const TOEIC_QUESTIONS = {"part5": [{"id": "p5-1", "part": 5, "type": "word-form", "question": "The company's new strategy proved highly _____ in reducing costs.", "options": ["effect", "effectively", "effective", "effectiveness"], "answer": 2, "explanation": "'Effective' l\u00e0 t\u00ednh t\u1eeb, d\u00f9ng sau \u0111\u1ed9ng t\u1eeb 'proved' (li\u00ean k\u1ebft). 'Effect' l\u00e0 danh t\u1eeb, 'effectively' l\u00e0 ph\u00f3 t\u1eeb, 'effectiveness' l\u00e0 danh t\u1eeb.", "difficulty": "medium"}, {"id": "p5-2", "part": 5, "type": "word-form", "question": "Applications must be submitted _____ to be considered for the position.", "options": ["electronically", "electronics", "electronic", "electronica"], "answer": 0, "explanation": "Ph\u00f3 t\u1eeb 'electronically' b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'submitted'.", "difficulty": "medium"}, {"id": "p5-3", "part": 5, "type": "word-form", "question": "The _____ of the new policy will take effect next month.", "options": ["implement", "implemented", "implementation", "implementing"], "answer": 2, "explanation": "Sau m\u1ea1o t\u1eeb 'the' c\u1ea7n danh t\u1eeb. 'Implementation' = s\u1ef1 th\u1ef1c hi\u1ec7n.", "difficulty": "easy"}, {"id": "p5-4", "part": 5, "type": "word-form", "question": "The sales team worked _____ to exceed their quarterly targets.", "options": ["diligent", "diligently", "diligence", "diligentness"], "answer": 1, "explanation": "\"Worked diligently\" = l\u00e0m vi\u1ec7c ch\u0103m ch\u1ec9. Ph\u00e2n bi\u1ec7t: diligent (adj) / diligently (adv) / diligence (n). \u0110\u1ed9ng t\u1eeb \"worked\" c\u1ea7n ph\u00f3 t\u1eeb \u2192 \"diligently\".", "difficulty": "medium"}, {"id": "p5-5", "part": 5, "type": "word-form", "question": "His _____ to detail made him an ideal candidate for the auditing role.", "options": ["attend", "attentive", "attentively", "attention"], "answer": 3, "explanation": "Sau s\u1edf h\u1eefu c\u00e1ch 'His' c\u1ea7n danh t\u1eeb. 'Attention to detail' = s\u1ef1 ch\u00fa \u00fd \u0111\u1ebfn chi ti\u1ebft.", "difficulty": "medium"}, {"id": "p5-6", "part": 5, "type": "word-form", "question": "The report provided a _____ analysis of consumer behavior.", "options": ["comprehend", "comprehension", "comprehensively", "comprehensive"], "answer": 3, "explanation": "T\u00ednh t\u1eeb 'comprehensive' b\u1ed5 ngh\u0129a cho danh t\u1eeb 'analysis'.", "difficulty": "hard"}, {"id": "p5-7", "part": 5, "type": "word-form", "question": "The CEO made a _____ decision to expand into the Asian market.", "options": ["strategy", "strategic", "strategize", "strategically"], "answer": 1, "explanation": "T\u00ednh t\u1eeb 'strategic' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'decision'.", "difficulty": "medium"}, {"id": "p5-8", "part": 5, "type": "word-form", "question": "Employee _____ has improved significantly since the new benefits package was introduced.", "options": ["satisfy", "satisfied", "satisfying", "satisfaction"], "answer": 3, "explanation": "Sau 'Employee' c\u1ea7n danh t\u1eeb ch\u1ee7 ng\u1eef. 'Satisfaction' = s\u1ef1 h\u00e0i l\u00f2ng.", "difficulty": "medium"}, {"id": "p5-9", "part": 5, "type": "word-form", "question": "The project manager's _____ style motivated the entire team.", "options": ["leadership", "leader", "leads", "lead"], "answer": 0, "explanation": "'Leadership style' l\u00e0 c\u1ee5m danh t\u1eeb chu\u1ea9n (phong c\u00e1ch l\u00e3nh \u0111\u1ea1o). V\u1ecb tr\u00ed sau s\u1edf h\u1eefu c\u00e1ch c\u1ea7n danh t\u1eeb. 'Lead/leads' l\u00e0 \u0111\u1ed9ng t\u1eeb, 'leader' l\u00e0 danh t\u1eeb ch\u1ec9 ng\u01b0\u1eddi \u2013 kh\u00f4ng \u0111\u1ee9ng tr\u01b0\u1edbc 'style'.", "difficulty": "medium"}, {"id": "p5-10", "part": 5, "type": "word-form", "question": "The factory is _____ expanding its production capacity.", "options": ["current", "currently", "currency", "currents"], "answer": 1, "explanation": "Ph\u00f3 t\u1eeb 'currently' b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'expanding'.", "difficulty": "easy"}, {"id": "p5-11", "part": 5, "type": "verb-tense", "question": "By the time the director arrives, the team _____ the presentation.", "options": ["will finish", "finishes", "will have finished", "has finished"], "answer": 2, "explanation": "'By the time + past/present' c\u1ea7n 'future perfect (will have + V3)' \u1edf m\u1ec7nh \u0111\u1ec1 ch\u00ednh.", "difficulty": "hard"}, {"id": "p5-12", "part": 5, "type": "verb-tense", "question": "The company _____ three new branches since the beginning of the year.", "options": ["opens", "opened", "had opened", "has opened"], "answer": 3, "explanation": "'Since the beginning of the year' \u2192 hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh 'has opened'.", "difficulty": "medium"}, {"id": "p5-13", "part": 5, "type": "verb-tense", "question": "Sales figures _____ steadily over the past six months.", "options": ["have increased", "increased", "increase", "are increasing"], "answer": 0, "explanation": "'Over the past six months' \u2192 hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh 'have increased'.", "difficulty": "easy"}, {"id": "p5-14", "part": 5, "type": "verb-tense", "question": "The training session _____ at 9 a.m. every Monday morning.", "options": ["will begin", "began", "has begun", "begins"], "answer": 3, "explanation": "L\u1ecbch tr\u00ecnh c\u1ed1 \u0111\u1ecbnh, th\u00f3i quen \u2192 hi\u1ec7n t\u1ea1i \u0111\u01a1n 'begins'.", "difficulty": "easy"}, {"id": "p5-15", "part": 5, "type": "verb-tense", "question": "The previous manager _____ the company for over twenty years before retiring.", "options": ["leads", "has led", "led", "will lead"], "answer": 2, "explanation": "H\u00e0nh \u0111\u1ed9ng \u0111\u00e3 ho\u00e0n t\u1ea5t trong qu\u00e1 kh\u1ee9 (before retiring) \u2192 qu\u00e1 kh\u1ee9 \u0111\u01a1n 'led'.", "difficulty": "medium"}, {"id": "p5-16", "part": 5, "type": "verb-tense", "question": "The client _____ the contract by the end of this week.", "options": ["signed", "is signing", "has signed", "will have signed"], "answer": 3, "explanation": "\"By the end of this week\" = th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai \u2192 Future Perfect. \"Will have signed\" = s\u1ebd \u0111\u00e3 k\u00fd.", "difficulty": "easy"}, {"id": "p5-17", "part": 5, "type": "prepositions", "question": "The report must be submitted _____ Friday at the latest.", "options": ["until", "at", "on", "by"], "answer": 3, "explanation": "'By' = kh\u00f4ng mu\u1ed9n h\u01a1n (deadline). 'Until' = cho \u0111\u1ebfn t\u1eadn (li\u00ean t\u1ee5c).", "difficulty": "easy"}, {"id": "p5-18", "part": 5, "type": "prepositions", "question": "The new policy is _____ accordance with international safety standards.", "options": ["in", "on", "at", "by"], "answer": 0, "explanation": "'In accordance with' l\u00e0 c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh = ph\u00f9 h\u1ee3p v\u1edbi.", "difficulty": "easy"}, {"id": "p5-19", "part": 5, "type": "prepositions", "question": "The manager will be available _____ appointment only.", "options": ["by", "on", "in", "with"], "answer": 0, "explanation": "'By appointment only' = ch\u1ec9 theo l\u1ecbch h\u1eb9n (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "p5-20", "part": 5, "type": "prepositions", "question": "The seminar will be held _____ the conference center downtown.", "options": ["in", "by", "on", "at"], "answer": 3, "explanation": "'At' d\u00f9ng cho \u0111\u1ecba \u0111i\u1ec3m c\u1ee5 th\u1ec3/r\u00f5 r\u00e0ng nh\u01b0 'the conference center'.", "difficulty": "easy"}, {"id": "p5-21", "part": 5, "type": "prepositions", "question": "She is responsible _____ overseeing the company's social media accounts.", "options": ["of", "for", "to", "by"], "answer": 1, "explanation": "'Be responsible for' l\u00e0 c\u1ee5m c\u1ed1 \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "p5-22", "part": 5, "type": "prepositions", "question": "The announcement was made _____ behalf of the entire board.", "options": ["on", "in", "of", "at"], "answer": 0, "explanation": "'On behalf of' = thay m\u1eb7t (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "p5-23", "part": 5, "type": "conjunction", "question": "_____ the project was challenging, the team completed it on time.", "options": ["Because", "Since", "Although", "So"], "answer": 2, "explanation": "'Although' = m\u1eb7c d\u00f9 (nh\u01b0\u1ee3ng b\u1ed9). C\u00e2u c\u00f3 s\u1ef1 t\u01b0\u01a1ng ph\u1ea3n gi\u1eefa 'challenging' v\u00e0 'completed on time'.", "difficulty": "medium"}, {"id": "p5-24", "part": 5, "type": "conjunction", "question": "Please contact us _____ you have any questions about your order.", "options": ["should", "unless", "although", "whether"], "answer": 0, "explanation": "'Should you have any questions' = \u0111\u1ea3o ng\u1eef c\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1 l\u1ecbch s\u1ef1 (should + S + V).", "difficulty": "medium"}, {"id": "p5-25", "part": 5, "type": "conjunction", "question": "The deadline is tomorrow; _____, the team will need to work overtime.", "options": ["therefore", "however", "moreover", "instead"], "answer": 0, "explanation": "'Therefore' = do \u0111\u00f3, v\u00ec v\u1eady. C\u00e2u sau l\u00e0 k\u1ebft qu\u1ea3 c\u1ee7a c\u00e2u tr\u01b0\u1edbc.", "difficulty": "medium"}, {"id": "p5-26", "part": 5, "type": "conjunction", "question": "Staff must wear protective gear _____ entering the production area.", "options": ["while", "during", "when", "throughout"], "answer": 2, "explanation": "'When entering' = khi v\u00e0o (when + V-ing, r\u00fat g\u1ecdn m\u1ec7nh \u0111\u1ec1 th\u1eddi gian).", "difficulty": "medium"}, {"id": "p5-27", "part": 5, "type": "conjunction", "question": "The factory will remain open _____ the renovation is being carried out.", "options": ["since", "because", "while", "until"], "answer": 2, "explanation": "'While' = trong khi (hai h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra song song).", "difficulty": "medium"}, {"id": "p5-28", "part": 5, "type": "passive", "question": "The new safety guidelines _____ to all staff before the end of the month.", "options": ["will distribute", "is distributing", "distributes", "will be distributed"], "answer": 3, "explanation": "Ch\u1ee7 th\u1ec3 nh\u1eadn t\u00e1c \u0111\u1ed9ng (guidelines \u0111\u01b0\u1ee3c ph\u00e2n ph\u00e1t) \u2192 b\u1ecb \u0111\u1ed9ng 'will be distributed'.", "difficulty": "medium"}, {"id": "p5-29", "part": 5, "type": "passive", "question": "The annual report _____ by the accounting team every December.", "options": ["is prepared", "prepares", "has preparing", "preparing"], "answer": 0, "explanation": "H\u00e0nh \u0111\u1ed9ng th\u01b0\u1eddng xuy\u00ean, l\u1eb7p \u0111i l\u1eb7p l\u1ea1i \u2192 b\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n 'is prepared'.", "difficulty": "medium"}, {"id": "p5-30", "part": 5, "type": "passive", "question": "All inquiries should _____ to the customer service department.", "options": ["direct", "directs", "directing", "be directed"], "answer": 3, "explanation": "'Should be directed' = b\u1ecb \u0111\u1ed9ng sau \u0111\u1ed9ng t\u1eeb khuy\u1ebft thi\u1ebfu (should + be + V3).", "difficulty": "medium"}, {"id": "p5-31", "part": 5, "type": "pronoun", "question": "The marketing team presented _____ quarterly findings to the board.", "options": ["it's", "theirs", "they", "their"], "answer": 3, "explanation": "S\u1edf h\u1eefu t\u00ednh t\u1eeb 'their' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'findings'.", "difficulty": "medium"}, {"id": "p5-32", "part": 5, "type": "pronoun", "question": "_____ of the candidates met all the required qualifications.", "options": ["Both", "Either", "Each", "Neither"], "answer": 3, "explanation": "'Neither' = kh\u00f4ng ai trong hai ng\u01b0\u1eddi (c\u1ea3 hai \u0111\u1ec1u kh\u00f4ng \u0111\u1ee7 ti\u00eau chu\u1ea9n, ph\u00f9 h\u1ee3p ngh\u0129a \u1edf \u0111\u00e2y).", "difficulty": "medium"}, {"id": "p5-33", "part": 5, "type": "pronoun", "question": "The committee reached _____ unanimous decision after hours of discussion.", "options": ["a", "an", "the", "\u2014"], "answer": 0, "explanation": "'Unanimous' b\u1eaft \u0111\u1ea7u b\u1eb1ng \u00e2m /j/ (yoo), kh\u00f4ng ph\u1ea3i nguy\u00ean \u00e2m \u2192 d\u00f9ng 'a'.", "difficulty": "easy"}, {"id": "p5-34", "part": 5, "type": "pronoun", "question": "Employees are encouraged to voice _____ concerns at the monthly meetings.", "options": ["its", "our", "their", "one's"], "answer": 2, "explanation": "'Employees' l\u00e0 s\u1ed1 nhi\u1ec1u \u2192 'their concerns'.", "difficulty": "medium"}, {"id": "p5-35", "part": 5, "type": "vocabulary", "question": "The board of directors has _____ the proposed merger with the tech firm.", "options": ["appealed", "applied", "approved", "appeased"], "answer": 2, "explanation": "'Approved' = ph\u00ea duy\u1ec7t. Ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh 'board approving a merger'.", "difficulty": "medium"}, {"id": "p5-36", "part": 5, "type": "vocabulary", "question": "The training program is _____ to all full-time employees.", "options": ["suitable", "reliable", "capable", "available"], "answer": 3, "explanation": "'Available to' = c\u00f3 s\u1eb5n/d\u00e0nh cho. C\u1ee5m c\u1ed1 \u0111\u1ecbnh trong v\u0103n b\u1ea3n th\u00f4ng b\u00e1o.", "difficulty": "easy"}, {"id": "p5-37", "part": 5, "type": "vocabulary", "question": "Due to _____ demand, the new product will be restocked next week.", "options": ["high", "large", "great", "wide"], "answer": 0, "explanation": "'High demand' l\u00e0 collocation chu\u1ea9n trong ti\u1ebfng Anh th\u01b0\u01a1ng m\u1ea1i.", "difficulty": "medium"}, {"id": "p5-38", "part": 5, "type": "vocabulary", "question": "The merger is _____ to be completed by the end of the fiscal year.", "options": ["assumed", "expected", "supposed", "thought"], "answer": 1, "explanation": "'Expected to + V' = \u0111\u01b0\u1ee3c k\u1ef3 v\u1ecdng l\u00e0 s\u1ebd. D\u00f9ng ph\u1ed5 bi\u1ebfn trong tin t\u1ee9c kinh doanh.", "difficulty": "medium"}, {"id": "p5-39", "part": 5, "type": "vocabulary", "question": "The conference room _____ up to 50 people.", "options": ["contains", "stores", "fits", "accommodates"], "answer": 3, "explanation": "'Accommodates' = c\u00f3 s\u1ee9c ch\u1ee9a/\u0111\u00e1p \u1ee9ng, \u0111\u00e2y l\u00e0 collocation chu\u1ea9n khi n\u00f3i v\u1ec1 s\u1ee9c ch\u1ee9a ng\u01b0\u1eddi. 'Contains' v\u00e0 'stores' d\u00f9ng cho v\u1eadt, kh\u00f4ng d\u00f9ng cho ng\u01b0\u1eddi. 'Fits' mang ngh\u0129a kh\u00f4ng gian v\u1eadt l\u00fd, kh\u00f4ng trang tr\u1ecdng b\u1eb1ng.", "difficulty": "easy"}, {"id": "p5-40", "part": 5, "type": "vocabulary", "question": "Mr. Park has _____ over the new project since last month.", "options": ["taken charge", "been in charge", "taken over", "been responsible"], "answer": 2, "explanation": "'Taken over' = \u0111\u1ea3m nh\u1eadn, ti\u1ebfp qu\u1ea3n. D\u00f9ng v\u1edbi 'over + something'.", "difficulty": "easy"}, {"id": "p5-41", "part": 5, "type": "gerund-infinitive", "question": "The HR manager suggested _____ the interview process to attract more applicants.", "options": ["simplifying", "simplify", "simplified", "to simplify"], "answer": 0, "explanation": "'Suggest + V-ing' l\u00e0 c\u00fa ph\u00e1p c\u1ed1 \u0111\u1ecbnh. \u0110\u1ed9ng t\u1eeb 'suggest' kh\u00f4ng \u0111i v\u1edbi to-infinitive.", "difficulty": "medium"}, {"id": "p5-42", "part": 5, "type": "gerund-infinitive", "question": "The company plans _____ a new branch in Ho Chi Minh City next quarter.", "options": ["opening", "opened", "open", "to open"], "answer": 3, "explanation": "'Plan + to + V' l\u00e0 c\u00fa ph\u00e1p c\u1ed1 \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "p5-43", "part": 5, "type": "gerund-infinitive", "question": "All participants are required _____ their badges at the entrance.", "options": ["wearing", "to wear", "wore", "wear"], "answer": 1, "explanation": "'Be required to + V' = ph\u1ea3i l\u00e0m g\u00ec.", "difficulty": "medium"}, {"id": "p5-44", "part": 5, "type": "relative-clause", "question": "The candidate _____ application was shortlisted has ten years of experience.", "options": ["who", "whom", "whose", "which"], "answer": 2, "explanation": "'Whose' d\u00f9ng \u0111\u1ec3 ch\u1ec9 s\u1edf h\u1eefu (application c\u1ee7a candidate).", "difficulty": "medium"}, {"id": "p5-45", "part": 5, "type": "relative-clause", "question": "The department _____ handles customer complaints is understaffed.", "options": ["that", "whose", "where", "who"], "answer": 0, "explanation": "'That' d\u00f9ng trong m\u1ec7nh \u0111\u1ec1 quan h\u1ec7 h\u1ea1n \u0111\u1ecbnh (defining relative clause) cho v\u1eadt/t\u1ed5 ch\u1ee9c. 'Who' d\u00f9ng cho ng\u01b0\u1eddi, 'whose' ch\u1ec9 s\u1edf h\u1eefu, 'where' ch\u1ec9 \u0111\u1ecba \u0111i\u1ec3m.", "difficulty": "medium"}, {"id": "p5-46", "part": 5, "type": "comparison", "question": "The new factory is _____ efficient than the old one.", "options": ["much", "most", "more", "better"], "answer": 2, "explanation": "So s\u00e1nh h\u01a1n v\u1edbi t\u00ednh t\u1eeb d\u00e0i: 'more + adj + than'.", "difficulty": "easy"}, {"id": "p5-47", "part": 5, "type": "comparison", "question": "This is _____ the best deal we have received from a supplier.", "options": ["near", "so far", "more far", "by far"], "answer": 3, "explanation": "'By far the best' = v\u01b0\u1ee3t tr\u1ed9i ho\u00e0n to\u00e0n, c\u00e1ch xa (nh\u1ea5n m\u1ea1nh so s\u00e1nh nh\u1ea5t).", "difficulty": "medium"}, {"id": "p5-48", "part": 5, "type": "vocabulary", "question": "The company's _____ decision to relocate surprised many employees.", "options": ["sudden", "gradual", "tentative", "significant"], "answer": 0, "explanation": "'Sudden decision' = quy\u1ebft \u0111\u1ecbnh \u0111\u1ed9t ng\u1ed9t (collocation chu\u1ea9n). 'Gradual' (d\u1ea7n d\u1ea7n) tr\u00e1i ngh\u0129a ho\u00e0n to\u00e0n. 'Tentative' (t\u1ea1m th\u1eddi, ch\u01b0a ch\u1eafc) v\u00e0 'significant' (\u0111\u00e1ng k\u1ec3) kh\u00f4ng ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh 'surprise'.", "difficulty": "medium"}, {"id": "p5-49", "part": 5, "type": "vocabulary", "question": "Please _____ the attached form and return it to reception.", "options": ["fulfill", "complete", "accomplish", "achieve"], "answer": 1, "explanation": "'Complete a form' = ho\u00e0n th\u00e0nh m\u1eabu \u0111\u01a1n (collocation c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "p5-50", "part": 5, "type": "vocabulary", "question": "The firm is _____ a comprehensive review of its pricing strategy.", "options": ["doing", "conducting", "making", "performing"], "answer": 1, "explanation": "'Conduct a review' = ti\u1ebfn h\u00e0nh \u0111\u00e1nh gi\u00e1 (collocation chu\u1ea9n trong ti\u1ebfng Anh th\u01b0\u01a1ng m\u1ea1i).", "difficulty": "medium"}, {"id": "n5-1", "part": 5, "type": "vocabulary", "question": "The board of directors _____ the CEO to explore new sustainability initiatives in the Southeast Asian market.", "options": ["notified", "insisted", "demanded", "urged"], "answer": 3, "explanation": "\u2705 <b>Urged</b> (Th\u00fac gi\u1ee5c). <br>\ud83d\udca1 <i>S\u1eafc th\u00e1i:</i> 'Urge someone to do something' l\u00e0 l\u1eddi khuy\u00ean/y\u00eau c\u1ea7u l\u1ecbch s\u1ef1 nh\u01b0ng quy\u1ebft \u0111o\u00e1n t\u1eeb c\u1ea5p tr\u00ean. 'Insisted' ph\u1ea3i \u0111i v\u1edbi 'on', 'Demanded' qu\u00e1 g\u1eaft gao.", "difficulty": "medium"}, {"id": "n5-2", "part": 5, "type": "vocabulary", "question": "To remain competitive, the firm must _____ its operations to better align with digital industry trends.", "options": ["refine", "resume", "recruit", "replace"], "answer": 0, "explanation": "\u2705 <b>Refine</b> (Tinh ch\u1ec9nh/C\u1ea3i ti\u1ebfn). <br>\ud83d\udca1 <i>S\u1eafc th\u00e1i:</i> D\u00f9ng 'refine operations' khi mu\u1ed1n n\u00f3i v\u1ec1 vi\u1ec7c l\u00e0m cho quy tr\u00ecnh tr\u1edf n\u00ean chuy\u00ean nghi\u1ec7p v\u00e0 hi\u1ec7u qu\u1ea3 h\u01a1n.", "difficulty": "medium"}, {"id": "n5-3", "part": 5, "type": "vocabulary", "question": "The marketing campaign was highly _____, resulting in a significant uptick in customer engagement.", "options": ["productive", "beneficial", "effective", "valuable"], "answer": 2, "explanation": "\u2705 <b>Effective</b> (Hi\u1ec7u qu\u1ea3). <br>\ud83d\udca1 <i>M\u1eb9o ETS:</i> Trong marketing, 'effective' ch\u1ec9 chi\u1ebfn d\u1ecbch \u0111\u1ea1t \u0111\u01b0\u1ee3c m\u1ee5c ti\u00eau \u0111\u1ec1 ra (conversion/engagement).", "difficulty": "medium"}, {"id": "n5-4", "part": 5, "type": "vocabulary", "question": "The factory's recent switch to solar power has led to a _____ decrease in monthly energy costs.", "options": ["notably", "noting", "notable", "noted"], "answer": 2, "explanation": "\u2705 <b>Notable</b> (\u0110\u00e1ng k\u1ec3). <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Notable decrease/increase' l\u00e0 c\u1ee5m t\u1eeb c\u1ed1 \u0111\u1ecbnh \u0111\u1ec3 ch\u1ec9 s\u1ef1 thay \u0111\u1ed5i r\u00f5 r\u1ec7t.", "difficulty": "medium"}, {"id": "n5-5", "part": 5, "type": "vocabulary", "question": "Mr. Park's _____ in handling client disputes has made him an invaluable asset to the PR department.", "options": ["diversity", "determination", "disruption", "discretion"], "answer": 3, "explanation": "\u2705 <b>Discretion</b> (S\u1ef1 kh\u00e9o l\u00e9o/Th\u1eadn tr\u1ecdng). <br>\ud83d\udca1 <i>S\u1eafc th\u00e1i:</i> 'Discretion' l\u00e0 k\u1ef9 n\u0103ng x\u1eed l\u00fd c\u00e1c t\u00ecnh hu\u1ed1ng nh\u1ea1y c\u1ea3m ho\u1eb7c tranh ch\u1ea5p m\u1ed9t c\u00e1ch \u00eam \u0111\u1eb9p.", "difficulty": "medium"}, {"id": "n5-6", "part": 5, "type": "vocabulary", "question": "The _____ of the new safety protocols is mandatory for all laboratory personnel.", "options": ["observation", "observance", "observing", "observed"], "answer": 1, "explanation": "\u2705 <b>Observance</b> (S\u1ef1 tu\u00e2n th\u1ee7). <br>\ud83d\udca1 <i>Ph\u00e2n bi\u1ec7t:</i> 'Observance' (tu\u00e2n th\u1ee7 lu\u1eadt l\u1ec7) kh\u00e1c v\u1edbi 'Observation' (quan s\u00e1t b\u1eb1ng m\u1eaft).", "difficulty": "medium"}, {"id": "n5-7", "part": 5, "type": "vocabulary", "question": "After a thorough _____, the research team concluded that the market was ready for the new product line.", "options": ["approval", "appraisal", "application", "appearance"], "answer": 1, "explanation": "\u2705 <b>Appraisal</b> (Th\u1ea9m \u0111\u1ecbnh). <br>\ud83d\udca1 <i>T\u1eeb chuy\u00ean d\u1ee5ng:</i> 'Thorough appraisal' ch\u1ec9 vi\u1ec7c \u0111\u00e1nh gi\u00e1 c\u1ef1c k\u1ef3 chi ti\u1ebft tr\u01b0\u1edbc khi \u0111\u01b0a ra k\u1ebft lu\u1eadn.", "difficulty": "medium"}, {"id": "n5-8", "part": 5, "type": "vocabulary", "question": "The CEO requested a _____ summary of the merger's potential impact on the company's long-term growth.", "options": ["strict", "precise", "concise", "minor"], "answer": 2, "explanation": "\u2705 <b>Concise</b> (S\u00fac t\u00edch). <br>\ud83d\udca1 <i>Collocation:</i> 'Concise summary' l\u00e0 b\u1ea3n t\u00f3m t\u1eaft ng\u1eafn g\u1ecdn nh\u01b0ng \u0111\u1ea7y \u0111\u1ee7 \u00fd.", "difficulty": "medium"}, {"id": "n5-9", "part": 5, "type": "vocabulary", "question": "The project was _____ completed within the allotted budget and timeframe.", "options": ["marginally", "fortunately", "specifically", "successfully"], "answer": 3, "explanation": "\u2705 <b>Successfully</b> (Th\u00e0nh c\u00f4ng). <br>\ud83d\udca1 Tr\u1ea1ng t\u1eeb b\u1ed5 ngh\u0129a cho 'completed' \u0111\u1ec3 ch\u1ec9 d\u1ef1 \u00e1n \u0111\u1ea1t ch\u1ec9 ti\u00eau.", "difficulty": "medium"}, {"id": "n5-10", "part": 5, "type": "vocabulary", "question": "Managers are expected to _____ any potential conflicts of interest to the HR department immediately.", "options": ["declare", "disclose", "describe", "discover"], "answer": 1, "explanation": "\u2705 <b>Disclose</b> (Ti\u1ebft l\u1ed9). <br>\ud83d\udca1 <i>M\u1eb9o ETS:</i> D\u00f9ng 'disclose' khi n\u00f3i v\u1ec1 vi\u1ec7c khai b\u00e1o c\u00e1c th\u00f4ng tin nh\u1ea1y c\u1ea3m ho\u1eb7c b\u00ed m\u1eadt kinh doanh.", "difficulty": "medium"}, {"id": "n5-11", "part": 5, "type": "vocabulary", "question": "The committee made several _____ recommendations to improve workplace safety.", "options": ["valuably", "valuing", "valuable", "valuation"], "answer": 2, "explanation": "\u2705 <b>Valuable</b> (Gi\u00e1 tr\u1ecb). <br>\ud83d\udca1 T\u00ednh t\u1eeb b\u1ed5 ngh\u0129a cho 'recommendations' (\u0111\u1ec1 xu\u1ea5t c\u00f3 gi\u00e1 tr\u1ecb).", "difficulty": "medium"}, {"id": "n5-12", "part": 5, "type": "vocabulary", "question": "All documents must be reviewed for _____ before being submitted to the legal team.", "options": ["accurateness", "accurate", "accurately", "accuracy"], "answer": 3, "explanation": "\u2705 <b>Accuracy</b> (\u0110\u1ed9 ch\u00ednh x\u00e1c). <br>\ud83d\udca1 V\u1ecb tr\u00ed danh t\u1eeb sau gi\u1edbi t\u1eeb 'for'.", "difficulty": "medium"}, {"id": "n5-13", "part": 5, "type": "vocabulary", "question": "The new branch manager has _____ transformed the team's productivity within just two months.", "options": ["radically", "remarkably", "rarely", "randomly"], "answer": 0, "explanation": "\u2705 <b>Radically</b> (Tri\u1ec7t \u0111\u1ec3). <br>\ud83d\udca1 <i>B\u1eaby 2025:</i> 'Radically transform' l\u00e0 c\u1ee5m t\u1eeb m\u1ea1nh ch\u1ec9 s\u1ef1 thay \u0111\u1ed5i to\u00e0n di\u1ec7n t\u1eeb g\u1ed1c r\u1ec5.", "difficulty": "medium"}, {"id": "n5-14", "part": 5, "type": "vocabulary", "question": "The _____ of the annual report requires contributions from all department heads.", "options": ["compile", "compilation", "compiler", "compiled"], "answer": 1, "explanation": "\u2705 <b>Compilation</b> (Vi\u1ec7c bi\u00ean so\u1ea1n). <br>\ud83d\udca1 Danh t\u1eeb \u0111\u00f3ng vai tr\u00f2 ch\u1ee7 ng\u1eef, ch\u1ec9 qu\u00e1 tr\u00ecnh t\u1ed5ng h\u1ee3p d\u1eef li\u1ec7u.", "difficulty": "medium"}, {"id": "n5-15", "part": 5, "type": "vocabulary", "question": "Employees who demonstrate _____ in their roles will be considered for promotion.", "options": ["excellence", "exception", "exceptionality", "excel"], "answer": 0, "explanation": "\u2705 <b>Excellence</b> (S\u1ef1 xu\u1ea5t s\u1eafc). <br>\ud83d\udca1 Danh t\u1eeb sau verb 'demonstrate' (th\u1ec3 hi\u1ec7n s\u1ef1 xu\u1ea5t s\u1eafc).", "difficulty": "medium"}, {"id": "n5-16", "part": 5, "type": "verb-tense", "question": "The client _____ the proposal three times since the initial submission.", "options": ["revised", "has revised", "revises", "will revise"], "answer": 1, "explanation": "\u2705 <b>Has revised</b> (Hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh). <br>\ud83d\udca1 <i>D\u1ea5u hi\u1ec7u:</i> 'Since' + m\u1ed1c th\u1eddi gian -> d\u00f9ng Present Perfect.", "difficulty": "medium"}, {"id": "n5-17", "part": 5, "type": "verb-tense", "question": "Ms. Chen _____ as the lead architect on the downtown tower project for five years.", "options": ["served", "serves", "has served", "will serve"], "answer": 2, "explanation": "\u2705 <b>Has served</b>. <br>\ud83d\udca1 'For five years' ch\u1ec9 qu\u00e1 tr\u00ecnh l\u00e0m vi\u1ec7c li\u00ean t\u1ee5c k\u00e9o d\u00e0i \u0111\u1ebfn hi\u1ec7n t\u1ea1i.", "difficulty": "medium"}, {"id": "n5-18", "part": 5, "type": "verb-tense", "question": "The finance team _____ the quarterly budget when the auditors arrived unexpectedly.", "options": ["reviews", "reviewed", "will review", "was reviewing"], "answer": 3, "explanation": "\u2705 <b>Was reviewing</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> H\u00e0nh \u0111\u1ed9ng \u0111ang di\u1ec5n ra (qu\u00e1 kh\u1ee9 ti\u1ebfp di\u1ec5n) th\u00ec c\u00f3 h\u00e0nh \u0111\u1ed9ng kh\u00e1c xen v\u00e0o (arrived).", "difficulty": "medium"}, {"id": "n5-19", "part": 5, "type": "verb-tense", "question": "If the supply chain issues are resolved, the company _____ its production targets.", "options": ["will meet", "met", "meet", "has met"], "answer": 0, "explanation": "\u2705 <b>Will meet</b>. <br>\ud83d\udca1 C\u00e2u \u0111i\u1ec1u ki\u1ec7n Lo\u1ea1i 1 (C\u00f3 th\u1ec3 x\u1ea3y ra): If + Hi\u1ec7n t\u1ea1i, T\u01b0\u01a1ng lai.", "difficulty": "medium"}, {"id": "n5-20", "part": 5, "type": "verb-tense", "question": "The CEO _____ all senior managers before announcing the restructuring plan.", "options": ["consults", "will consult", "consulted", "has consulted"], "answer": 1, "explanation": "\u2705 <b>Will consult</b>. <br>\ud83d\udca1 'Before announcing' (tr\u01b0\u1edbc khi th\u00f4ng b\u00e1o) \u00e1m ch\u1ec9 h\u00e0nh \u0111\u1ed9ng s\u1ebd x\u1ea3y ra trong t\u01b0\u01a1ng lai.", "difficulty": "medium"}, {"id": "n5-21", "part": 5, "type": "verb-tense", "question": "By next month, the development team _____ the mobile application for two years.", "options": ["will have been developing", "developed", "will develop", "develops"], "answer": 0, "explanation": "\u2705 <b>Will have been developing</b>. <br>\ud83d\udca1 <i>M\u1eb9o ETS:</i> 'By + next month' + 'for [duration]' -> T\u01b0\u01a1ng lai ho\u00e0n th\u00e0nh ti\u1ebfp di\u1ec5n.", "difficulty": "hard"}, {"id": "n5-22", "part": 5, "type": "verb-tense", "question": "The store _____ at 9 a.m. and closes at 9 p.m. every day of the week.", "options": ["opened", "will open", "has opened", "opens"], "answer": 3, "explanation": "\u2705 <b>Opens</b>. <br>\ud83d\udca1 Hi\u1ec7n t\u1ea1i \u0111\u01a1n d\u00f9ng cho l\u1ecbch tr\u00ecnh ho\u1eb7c th\u00f3i quen l\u1eb7p l\u1ea1i h\u00e0ng ng\u00e0y.", "difficulty": "easy"}, {"id": "n5-23", "part": 5, "type": "verb-tense", "question": "The shipment that _____ two days ago has finally cleared customs.", "options": ["was arrived", "arrives", "has arrived", "arrived"], "answer": 3, "explanation": "\u2705 <b>Arrived</b>. <br>\ud83d\udca1 <i>D\u1ea5u hi\u1ec7u:</i> 'Two days ago' l\u00e0 m\u1ed1c th\u1eddi gian x\u00e1c \u0111\u1ecbnh trong qu\u00e1 kh\u1ee9.", "difficulty": "easy"}, {"id": "n5-24", "part": 5, "type": "verb-tense", "question": "All participants _____ a certificate upon completing the training program.", "options": ["receive", "received", "will receive", "has received"], "answer": 2, "explanation": "\u2705 <b>Will receive</b>. <br>\ud83d\udca1 Di\u1ec5n t\u1ea3 s\u1ef1 vi\u1ec7c s\u1ebd x\u1ea3y ra sau khi ho\u00e0n th\u00e0nh m\u1ed9t \u0111i\u1ec1u ki\u1ec7n (completing program).", "difficulty": "medium"}, {"id": "n5-25", "part": 5, "type": "prepositions", "question": "The sales team is working _____ a tight deadline to finalize the client proposal.", "options": ["to", "on", "with", "under"], "answer": 3, "explanation": "\u2705 <b>Under</b>. <br>\ud83d\udca1 <i>C\u1ee5m c\u1ed1 \u0111\u1ecbnh:</i> 'Working under a deadline' (L\u00e0m vi\u1ec7c d\u01b0\u1edbi \u00e1p l\u1ef1c th\u1eddi gian).", "difficulty": "medium"}, {"id": "n5-26", "part": 5, "type": "prepositions", "question": "The company is committed _____ reducing its carbon footprint by 2030.", "options": ["to", "on", "for", "with"], "answer": 0, "explanation": "\u2705 <b>To</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Commit to + V-ing/Noun' (Cam k\u1ebft l\u00e0m g\u00ec).", "difficulty": "medium"}, {"id": "n5-27", "part": 5, "type": "prepositions", "question": "The conference will be held _____ three days, starting Monday.", "options": ["in", "over", "for", "during"], "answer": 1, "explanation": "\u2705 <b>Over</b>. <br>\ud83d\udca1 'Over + s\u1ed1 ng\u00e0y' d\u00f9ng \u0111\u1ec3 ch\u1ec9 s\u1ef1 ki\u1ec7n di\u1ec5n ra xuy\u00ean su\u1ed1t trong m\u1ed9t kho\u1ea3ng th\u1eddi gian.", "difficulty": "medium"}, {"id": "n5-28", "part": 5, "type": "prepositions", "question": "Please refer any technical issues _____ the IT help desk on the third floor.", "options": ["to", "at", "for", "by"], "answer": 0, "explanation": "\u2705 <b>To</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Refer something to someone' (Chuy\u1ec3n giao/G\u1eedi v\u1ea5n \u0111\u1ec1 cho ai).", "difficulty": "medium"}, {"id": "n5-29", "part": 5, "type": "prepositions", "question": "The memorandum was circulated _____ all branch offices last Tuesday.", "options": ["among", "between", "for", "to"], "answer": 3, "explanation": "\u2705 <b>To</b>. <br>\ud83d\udca1 'Circulate something to...' (L\u01b0u h\u00e0nh/G\u1eedi th\u00f4ng b\u00e1o t\u1edbi c\u00e1c \u0111\u01a1n v\u1ecb).", "difficulty": "medium"}, {"id": "n5-30", "part": 5, "type": "prepositions", "question": "Staff members are eligible _____ the wellness reimbursement program after 90 days of employment.", "options": ["of", "for", "on", "by"], "answer": 1, "explanation": "\u2705 <b>For</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Be eligible for something' (\u0110\u1ee7 \u0111i\u1ec1u ki\u1ec7n \u0111\u01b0\u1ee3c h\u01b0\u1edfng c\u00e1i g\u00ec).", "difficulty": "medium"}, {"id": "n5-31", "part": 5, "type": "prepositions", "question": "The revised contract was sent _____ email to all vendors this morning.", "options": ["in", "with", "by", "on"], "answer": 2, "explanation": "\u2705 <b>By</b>. <br>\ud83d\udca1 'By + ph\u01b0\u01a1ng ti\u1ec7n li\u00ean l\u1ea1c' (By email, by post, by phone).", "difficulty": "medium"}, {"id": "n5-32", "part": 5, "type": "prepositions", "question": "The new software is compatible _____ both Windows and Mac operating systems.", "options": ["to", "for", "of", "with"], "answer": 3, "explanation": "\u2705 <b>With</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Compatible with' (T\u01b0\u01a1ng th\u00edch v\u1edbi).", "difficulty": "medium"}, {"id": "n5-33", "part": 5, "type": "prepositions", "question": "The research team's findings are consistent _____ previous studies on consumer behavior.", "options": ["to", "by", "on", "with"], "answer": 3, "explanation": "\u2705 <b>With</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Consistent with' (Nh\u1ea5t qu\u00e1n/Ph\u00f9 h\u1ee3p v\u1edbi).", "difficulty": "medium"}, {"id": "n5-34", "part": 5, "type": "conjunction", "question": "The new packaging was designed to be eco-friendly _____ cost-effective.", "options": ["and", "yet", "but", "or"], "answer": 0, "explanation": "\u2705 <b>And</b>. <br>\ud83d\udca1 'And' n\u1ed1i hai t\u00ednh t\u1eeb t\u01b0\u01a1ng \u0111\u1ed3ng mang ngh\u0129a t\u00edch c\u1ef1c cho s\u1ea3n ph\u1ea9m.", "difficulty": "medium"}, {"id": "n5-35", "part": 5, "type": "conjunction", "question": "The product launch was delayed _____ supply chain disruptions earlier this year.", "options": ["despite", "due to", "although", "whereas"], "answer": 1, "explanation": "\u2705 <b>Due to</b> (Do/B\u1edfi v\u00ec). <br>\ud83d\udca1 <i>Ghi nh\u1edb:</i> 'Due to' + Noun Phrase (supply chain disruptions).", "difficulty": "medium"}, {"id": "n5-36", "part": 5, "type": "conjunction", "question": "_____ the report is ready, please send it directly to the board of directors.", "options": ["If", "When", "Since", "Once"], "answer": 3, "explanation": "\u2705 <b>Once</b> (Ngay khi). <br>\ud83d\udca1 'Once' nh\u1ea5n m\u1ea1nh th\u1eddi \u0111i\u1ec3m m\u1ed9t h\u00e0nh \u0111\u1ed9ng v\u1eeba ho\u00e0n th\u00e0nh th\u00ec h\u00e0nh \u0111\u1ed9ng sau x\u1ea3y ra ngay.", "difficulty": "medium"}, {"id": "n5-37", "part": 5, "type": "conjunction", "question": "The company will proceed with the expansion _____ the new regulation is approved.", "options": ["so that", "regardless of", "provided that", "in case"], "answer": 2, "explanation": "\u2705 <b>Provided that</b> (Mi\u1ec5n l\u00e0/V\u1edbi \u0111i\u1ec1u ki\u1ec7n l\u00e0). <br>\ud83d\udca1 \u0110\u00e2y l\u00e0 c\u1ea5u tr\u00fac c\u00e2u \u0111i\u1ec1u ki\u1ec7n th\u01b0\u1eddng xuy\u00ean xu\u1ea5t hi\u1ec7n trong Part 5.", "difficulty": "medium"}, {"id": "n5-38", "part": 5, "type": "conjunction", "question": "Mr. Yamamoto agreed to take on the additional responsibilities _____ asking for a salary increase.", "options": ["without", "despite", "unless", "instead of"], "answer": 0, "explanation": "\u2705 <b>Without</b>. <br>\ud83d\udca1 'Without + V-ing' (m\u00e0 kh\u00f4ng...). Ph\u00f9 h\u1ee3p ngh\u0129a: l\u00e0m th\u00eam vi\u1ec7c m\u00e0 kh\u00f4ng \u0111\u00f2i t\u0103ng l\u01b0\u01a1ng.", "difficulty": "medium"}, {"id": "n5-39", "part": 5, "type": "conjunction", "question": "The renovation will take approximately six weeks; _____, all staff will be working from home.", "options": ["therefore", "however", "meanwhile", "otherwise"], "answer": 2, "explanation": "\u2705 <b>Meanwhile</b> (Trong khi \u0111\u00f3). <br>\ud83d\udca1 D\u00f9ng \u0111\u1ec3 k\u1ebft n\u1ed1i hai s\u1ef1 vi\u1ec7c x\u1ea3y ra song song v\u1ec1 m\u1eb7t th\u1eddi gian.", "difficulty": "medium"}, {"id": "n5-40", "part": 5, "type": "conjunction", "question": "The survey results were positive; _____, management decided to make further improvements.", "options": ["as a result", "since then", "even so", "for instance"], "answer": 2, "explanation": "\u2705 <b>Even so</b> (D\u00f9 v\u1eady/M\u1eb7c d\u00f9 th\u1ebf). <br>\ud83d\udca1 D\u00f9ng \u0111\u1ec3 n\u1ed1i hai v\u1ebf c\u00f3 t\u00ednh ch\u1ea5t t\u01b0\u01a1ng ph\u1ea3n nh\u1eb9 (k\u1ebft qu\u1ea3 t\u1ed1t nh\u01b0ng v\u1eabn mu\u1ed1n t\u1ed1t h\u01a1n).", "difficulty": "medium"}, {"id": "n5-41", "part": 5, "type": "passive", "question": "A formal complaint _____ by the tenant regarding the building's heating system.", "options": ["filed", "has been filed", "is filing", "files"], "answer": 1, "explanation": "\u2705 <b>Has been filed</b> (B\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh). <br>\ud83d\udca1 <i>Ph\u00e2n t\u00edch:</i> Complaint (l\u1eddi ph\u00e0n n\u00e0n) ph\u1ea3i \u0111\u01b0\u1ee3c 'n\u1ed9p' (filed).", "difficulty": "medium"}, {"id": "n5-42", "part": 5, "type": "passive", "question": "The quarterly targets _____ to the sales team during last Monday's briefing.", "options": ["distributed", "were distributed", "will distribute", "distributing"], "answer": 1, "explanation": "\u2705 <b>Were distributed</b> (B\u1ecb \u0111\u1ed9ng qu\u00e1 kh\u1ee9). <br>\ud83d\udca1 <i>D\u1ea5u hi\u1ec7u:</i> 'Last Monday' -> Qu\u00e1 kh\u1ee9 \u0111\u01a1n.", "difficulty": "medium"}, {"id": "n5-43", "part": 5, "type": "passive", "question": "All employees are _____ to complete the mandatory cybersecurity training by Friday.", "options": ["require", "requiring", "required", "requirement"], "answer": 2, "explanation": "\u2705 <b>Required</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Be required to do something' (B\u1ecb b\u1eaft bu\u1ed9c/\u0110\u01b0\u1ee3c y\u00eau c\u1ea7u l\u00e0m g\u00ec).", "difficulty": "medium"}, {"id": "n5-44", "part": 5, "type": "passive", "question": "The defective items _____ at no additional charge to all affected customers.", "options": ["will replace", "has replaced", "are replacing", "will be replaced"], "answer": 3, "explanation": "\u2705 <b>Will be replaced</b> (B\u1ecb \u0111\u1ed9ng t\u01b0\u01a1ng lai). <br>\ud83d\udca1 Ch\u1ee7 ng\u1eef 'defective items' (h\u00e0ng l\u1ed7i) \u0111\u01b0\u1ee3c thay th\u1ebf.", "difficulty": "medium"}, {"id": "n5-45", "part": 5, "type": "passive", "question": "New employees _____ a comprehensive orientation program during their first week.", "options": ["giving", "give", "have given", "are given"], "answer": 3, "explanation": "\u2705 <b>Are given</b>. <br>\ud83d\udca1 Nh\u00e2n vi\u00ean m\u1edbi '\u0111\u01b0\u1ee3c c\u1ea5p' ch\u01b0\u01a1ng tr\u00ecnh \u0111\u1ecbnh h\u01b0\u1edbng.", "difficulty": "medium"}, {"id": "n5-46", "part": 5, "type": "pronoun", "question": "The board of directors will announce _____ decision regarding the merger next week.", "options": ["it", "its", "those", "them"], "answer": 1, "explanation": "\u2705 <b>Its</b>. <br>\ud83d\udca1 <i>M\u1eb9o ETS:</i> 'The board of directors' \u0111\u01b0\u1ee3c coi l\u00e0 m\u1ed9t t\u1ed5 ch\u1ee9c (s\u1ed1 \u00edt) n\u00ean d\u00f9ng t\u00ednh t\u1eeb s\u1edf h\u1eefu 'its'.", "difficulty": "medium"}, {"id": "n5-47", "part": 5, "type": "pronoun", "question": "The seminar participants were asked to introduce _____ at the beginning of the session.", "options": ["them", "they", "theirs", "themselves"], "answer": 3, "explanation": "\u2705 <b>Themselves</b> (\u0110\u1ea1i t\u1eeb ph\u1ea3n th\u00e2n). <br>\ud83d\udca1 D\u00f9ng khi ch\u1ee7 ng\u1eef v\u00e0 t\u00e2n ng\u1eef c\u00f9ng l\u00e0 m\u1ed9t \u0111\u1ed1i t\u01b0\u1ee3ng (ng\u01b0\u1eddi tham gia t\u1ef1 gi\u1edbi thi\u1ec7u m\u00ecnh).", "difficulty": "medium"}, {"id": "n5-48", "part": 5, "type": "pronoun", "question": "Each candidate must provide _____ own references from previous employers.", "options": ["they", "them", "their", "theirs"], "answer": 2, "explanation": "\u2705 <b>Their</b>. <br>\ud83d\udca1 <i>Ghi ch\u00fa:</i> 'Each' th\u01b0\u1eddng \u0111i v\u1edbi 'their' (s\u1ed1 nhi\u1ec1u trung t\u00ednh) trong v\u0103n phong hi\u1ec7n \u0111\u1ea1i ho\u1eb7c 'his/her'.", "difficulty": "medium"}, {"id": "n5-49", "part": 5, "type": "pronoun", "question": "The manager spoke highly of _____ assistant's organizational skills during the review.", "options": ["hers", "her", "she", "herself"], "answer": 1, "explanation": "\u2705 <b>Her</b>. <br>\ud83d\udca1 T\u00ednh t\u1eeb s\u1edf h\u1eefu \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'assistant'.", "difficulty": "medium"}, {"id": "n5-50", "part": 5, "type": "pronoun", "question": "Please refer to _____ attached document for details on the reimbursement process.", "options": ["a", "an", "\u2014", "the"], "answer": 3, "explanation": "\u2705 <b>The</b>. <br>\ud83d\udca1 'The attached document' (T\u00e0i li\u1ec7u \u0111\u00ednh k\u00e8m) \u2013 \u0111\u00e3 x\u00e1c \u0111\u1ecbnh c\u1ee5 th\u1ec3 t\u00e0i li\u1ec7u n\u00e0o r\u1ed3i.", "difficulty": "easy"}, {"id": "n5-51", "part": 5, "type": "pronoun", "question": "Ms. Rivera is _____ expert in supply chain logistics with over 15 years of experience.", "options": ["a", "\u2014", "the", "an"], "answer": 3, "explanation": "\u2705 <b>An</b>. <br>\ud83d\udca1 'An' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb b\u1eaft \u0111\u1ea7u b\u1eb1ng nguy\u00ean \u00e2m (expert).", "difficulty": "easy"}, {"id": "n5-52", "part": 5, "type": "pronoun", "question": "The charity event raised _____ impressive amount for local community programs.", "options": ["an", "a", "the", "\u2014"], "answer": 0, "explanation": "\u2705 <b>An</b>. <br>\ud83d\udca1 'An impressive amount' \u2013 'an' tr\u01b0\u1edbc t\u00ednh t\u1eeb b\u1eaft \u0111\u1ea7u b\u1eb1ng nguy\u00ean \u00e2m (impressive).", "difficulty": "easy"}, {"id": "n5-53", "part": 5, "type": "relative-clause", "question": "The candidate _____ submitted the most detailed portfolio was selected for the design position.", "options": ["whom", "whose", "which", "who"], "answer": 3, "explanation": "\u2705 <b>Who</b>. <br>\ud83d\udca1 \u0110\u1ea1i t\u1eeb quan h\u1ec7 thay th\u1ebf cho ng\u01b0\u1eddi (candidate) l\u00e0m ch\u1ee7 ng\u1eef trong m\u1ec7nh \u0111\u1ec1.", "difficulty": "medium"}, {"id": "n5-54", "part": 5, "type": "relative-clause", "question": "The conference room _____ we held the meeting is no longer available for booking.", "options": ["who", "whose", "to whom", "in which"], "answer": 3, "explanation": "\u2705 <b>In which</b> (M\u00e0 trong \u0111\u00f3). <br>\ud83d\udca1 'In which' = 'Where', ch\u1ec9 \u0111\u1ecba \u0111i\u1ec3m.", "difficulty": "medium"}, {"id": "n5-55", "part": 5, "type": "relative-clause", "question": "The architect _____ design won the national award will speak at our annual gala.", "options": ["whose", "whom", "who", "which"], "answer": 0, "explanation": "\u2705 <b>Whose</b>. <br>\ud83d\udca1 Ch\u1ec9 s\u1ef1 s\u1edf h\u1eefu: 'Whose design' (Thi\u1ebft k\u1ebf C\u1ee6A ki\u1ebfn tr\u00fac s\u01b0 \u0111\u00f3).", "difficulty": "medium"}, {"id": "n5-56", "part": 5, "type": "modal", "question": "Employees _____ submit their expense reports within 30 days of the business trip.", "options": ["might", "must", "could", "would"], "answer": 1, "explanation": "\u2705 <b>Must</b>. <br>\ud83d\udca1 Ch\u1ec9 s\u1ef1 b\u1eaft bu\u1ed9c ho\u1eb7c quy \u0111\u1ecbnh c\u1ee7a c\u00f4ng ty.", "difficulty": "medium"}, {"id": "n5-57", "part": 5, "type": "modal", "question": "You _____ contact the support team directly if you encounter any technical difficulties.", "options": ["may", "ought", "should", "need"], "answer": 2, "explanation": "\u2705 <b>Should</b>. <br>\ud83d\udca1 L\u1eddi khuy\u00ean ho\u1eb7c h\u01b0\u1edbng d\u1eabn quy tr\u00ecnh.", "difficulty": "medium"}, {"id": "n5-58", "part": 5, "type": "modal", "question": "The new product _____ be released earlier than planned if testing goes well.", "options": ["must", "shall", "could", "ought"], "answer": 2, "explanation": "\u2705 <b>Could</b>. <br>\ud83d\udca1 Di\u1ec5n t\u1ea3 kh\u1ea3 n\u0103ng c\u00f3 th\u1ec3 x\u1ea3y ra nh\u01b0ng kh\u00f4ng ch\u1eafc ch\u1eafn 100%.", "difficulty": "medium"}, {"id": "n5-59", "part": 5, "type": "gerund-infinitive", "question": "The HR department is considering _____ flexible work schedules for all departments.", "options": ["implementing", "to implement", "implement", "implemented"], "answer": 0, "explanation": "\u2705 <b>Implementing</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Consider + V-ing' (C\u00e2n nh\u1eafc l\u00e0m vi\u1ec7c g\u00ec).", "difficulty": "medium"}, {"id": "n5-60", "part": 5, "type": "gerund-infinitive", "question": "The manager agreed _____ the deadline by an additional week.", "options": ["extending", "extend", "to extend", "extended"], "answer": 2, "explanation": "\u2705 <b>To extend</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Agree + to V-inf' (\u0110\u1ed3ng \u00fd l\u00e0m vi\u1ec7c g\u00ec).", "difficulty": "medium"}, {"id": "n5-61", "part": 5, "type": "gerund-infinitive", "question": "Dr. Kim recommended _____ a second audit to ensure compliance.", "options": ["conduct", "to conduct", "conducted", "conducting"], "answer": 3, "explanation": "\u2705 <b>Conducting</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Recommend + V-ing' (Khuy\u00ean/\u0110\u1ec1 xu\u1ea5t l\u00e0m vi\u1ec7c g\u00ec).", "difficulty": "medium"}, {"id": "n5-62", "part": 5, "type": "gerund-infinitive", "question": "The board expects all department heads _____ monthly progress reports.", "options": ["to submit", "submit", "submitting", "submission"], "answer": 0, "explanation": "\u2705 <b>To submit</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Expect someone TO DO something'.", "difficulty": "medium"}, {"id": "n5-63", "part": 5, "type": "comparison", "question": "The updated software runs _____ than the previous version.", "options": ["faster", "fast", "fastest", "most fast"], "answer": 0, "explanation": "\u2705 <b>Faster</b>. <br>\ud83d\udca1 So s\u00e1nh h\u01a1n c\u1ee7a t\u00ednh t\u1eeb ng\u1eafn (fast -> faster).", "difficulty": "easy"}, {"id": "n5-64", "part": 5, "type": "comparison", "question": "This is _____ complex project the engineering team has ever undertaken.", "options": ["more", "the most", "most", "the more"], "answer": 1, "explanation": "\u2705 <b>The most</b>. <br>\ud83d\udca1 So s\u00e1nh nh\u1ea5t \u0111i k\u00e8m c\u1ee5m 'ever undertaken' (t\u1eebng \u0111\u01b0\u1ee3c th\u1ef1c hi\u1ec7n).", "difficulty": "medium"}, {"id": "n5-65", "part": 5, "type": "comparison", "question": "Renting office space downtown is _____ than operating from the suburbs.", "options": ["expensively", "most expensive", "more expensive", "expense"], "answer": 2, "explanation": "\u2705 <b>More expensive</b>. <br>\ud83d\udca1 So s\u00e1nh h\u01a1n c\u1ee7a t\u00ednh t\u1eeb d\u00e0i (more + adjective + than).", "difficulty": "medium"}, {"id": "n5-66", "part": 5, "type": "vocabulary", "question": "The board meeting was _____ from Thursday to the following Monday to accommodate board members' schedules.", "options": ["promoted", "cancelled", "postponed", "recorded"], "answer": 2, "explanation": "\u2705 <b>Postponed</b> (Tr\u00ec ho\u00e3n). <br>\ud83d\udca1 <i>S\u1eafc th\u00e1i:</i> 'Postponed' th\u01b0\u1eddng \u0111i k\u00e8m v\u1edbi th\u1eddi \u0111i\u1ec3m m\u1edbi (from... to...). 'Cancelled' l\u00e0 h\u1ee7y b\u1ecf ho\u00e0n to\u00e0n.", "difficulty": "medium"}, {"id": "n5-67", "part": 5, "type": "vocabulary", "question": "The company will _____ a new recycling initiative to reduce waste by 40% by year-end.", "options": ["delay", "resign", "withdraw", "launch"], "answer": 3, "explanation": "\u2705 <b>Launch</b> (Kh\u1edfi \u0111\u1ed9ng/Ra m\u1eaft). <br>\ud83d\udca1 <i>Collocation:</i> 'Launch an initiative/campaign/product' l\u00e0 c\u1ee5m t\u1eeb c\u1ef1c k\u1ef3 ph\u1ed5 bi\u1ebfn trong TOEIC.", "difficulty": "medium"}, {"id": "n5-68", "part": 5, "type": "vocabulary", "question": "The _____ of the client's contract was celebrated with a team dinner.", "options": ["cancellation", "renewal", "dismissal", "return"], "answer": 1, "explanation": "\u2705 <b>Renewal</b> (Gia h\u1ea1n). <br>\ud83d\udca1 <i>Logics:</i> Vi\u1ec7c gia h\u1ea1n h\u1ee3p \u0111\u1ed3ng (renewal) l\u00e0 tin m\u1eebng n\u00ean m\u1edbi \u0111\u01b0\u1ee3c t\u1ed5 ch\u1ee9c \u0103n m\u1eebng (celebrated).", "difficulty": "medium"}, {"id": "n5-69", "part": 5, "type": "vocabulary", "question": "The candidate made a very _____ impression during the interview with her industry knowledge.", "options": ["defective", "favorable", "negative", "brief"], "answer": 1, "explanation": "\u2705 <b>Favorable</b> (T\u1ed1t/C\u00f3 l\u1ee3i). <br>\ud83d\udca1 <i>Collocation:</i> 'Make a favorable impression' (T\u1ea1o \u1ea5n t\u01b0\u1ee3ng t\u1ed1t).", "difficulty": "medium"}, {"id": "n5-70", "part": 5, "type": "vocabulary", "question": "The IT security team has put _____ measures to prevent unauthorized access to the network.", "options": ["in place", "into effect", "under review", "on hold"], "answer": 0, "explanation": "\u2705 <b>In place</b>. <br>\ud83d\udca1 <i>C\u1ee5m c\u1ed1 \u0111\u1ecbnh:</i> 'Put measures in place' (Thi\u1ebft l\u1eadp c\u00e1c bi\u1ec7n ph\u00e1p an ninh).", "difficulty": "medium"}, {"id": "n5-71", "part": 5, "type": "vocabulary", "question": "Please _____ any changes to the project schedule with your team leader first.", "options": ["confirm", "discuss", "impose", "demand"], "answer": 1, "explanation": "\u2705 <b>Discuss</b> (Th\u1ea3o lu\u1eadn). <br>\ud83d\udca1 <i>M\u1eb9o ETS:</i> 'Discuss something with someone' l\u00e0 h\u00e0nh \u0111\u1ed9ng ph\u1ed1i h\u1ee3p c\u00f4ng vi\u1ec7c chu\u1ea9n m\u1ef1c trong v\u0103n ph\u00f2ng.", "difficulty": "easy"}, {"id": "n5-72", "part": 5, "type": "vocabulary", "question": "The company's quarterly profit _____ analyst expectations by a significant margin.", "options": ["extended", "exceeded", "expanded", "excelled"], "answer": 1, "explanation": "\"Profit exceeded expectations\" = v\u01b0\u1ee3t k\u1ef3 v\u1ecdng. \"Exceed expectations\" l\u00e0 collocation c\u1ed1 \u0111\u1ecbnh trong b\u00e1o c\u00e1o t\u00e0i ch\u00ednh TOEIC. \"Excelled\" = xu\u1ea5t s\u1eafc (intransitive, kh\u00f4ng c\u00f3 t\u00e2n ng\u1eef).", "difficulty": "medium"}, {"id": "n5-73", "part": 5, "type": "vocabulary", "question": "The hotel offers _____ rates for guests who book more than three nights in advance.", "options": ["standard", "increased", "discounted", "final"], "answer": 2, "explanation": "\u2705 <b>Discounted</b> (\u0110\u00e3 gi\u1ea3m gi\u00e1). <br>\ud83d\udca1 <i>Ng\u1eef c\u1ea3nh:</i> \u0110\u1eb7t ph\u00f2ng nhi\u1ec1u \u0111\u00eam th\u01b0\u1eddng \u0111\u01b0\u1ee3c h\u01b0\u1edfng 'discounted rates'.", "difficulty": "medium"}, {"id": "n5-74", "part": 5, "type": "vocabulary", "question": "The inspection team was asked to _____ the safety of all equipment before operations resumed.", "options": ["register", "modify", "provide", "verify"], "answer": 3, "explanation": "\u2705 <b>Verify</b> (X\u00e1c minh). <br>\ud83d\udca1 'Verify safety' l\u00e0 h\u00e0nh \u0111\u1ed9ng ki\u1ec3m tra \u0111\u1ec3 \u0111\u1ea3m b\u1ea3o m\u1ecdi th\u1ee9 an to\u00e0n.", "difficulty": "medium"}, {"id": "n5-75", "part": 5, "type": "vocabulary", "question": "All travel expenses must be supported by _____ such as receipts and boarding passes.", "options": ["documentation", "subscription", "reference", "revision"], "answer": 0, "explanation": "\u2705 <b>Documentation</b> (Ch\u1ee9ng t\u1eeb/T\u00e0i li\u1ec7u gi\u1ea5y t\u1edd). <br>\ud83d\udca1 <i>Ghi nh\u1edb:</i> Receipts (h\u00f3a \u0111\u01a1n) l\u00e0 m\u1ed9t lo\u1ea1i 'documentation'.", "difficulty": "medium"}, {"id": "n5-76", "part": 5, "type": "word-form", "question": "The product's _____ has improved significantly following the feedback from the pilot launch.", "options": ["perform", "performing", "performance", "performer"], "answer": 2, "explanation": "\u2705 <b>Performance</b> (Hi\u1ec7u su\u1ea5t). <br>\ud83d\udca1 \u0110\u1ee9ng sau s\u1edf h\u1eefu c\u00e1ch ('s) c\u1ea7n m\u1ed9t danh t\u1eeb.", "difficulty": "medium"}, {"id": "n5-77", "part": 5, "type": "prepositions", "question": "The updated guidelines are _____ effect as of January 1.", "options": ["on", "by", "at", "in"], "answer": 3, "explanation": "\u2705 <b>In</b>. <br>\ud83d\udca1 <i>C\u1ee5m c\u1ed1 \u0111\u1ecbnh:</i> 'In effect' (C\u00f3 hi\u1ec7u l\u1ef1c).", "difficulty": "easy"}, {"id": "n5-78", "part": 5, "type": "conjunction", "question": "The company has expanded significantly _____ it was founded just five years ago.", "options": ["since", "although", "because", "so"], "answer": 0, "explanation": "\u2705 <b>Since</b> (K\u1ec3 t\u1eeb khi). <br>\ud83d\udca1 D\u1ea5u hi\u1ec7u c\u1ee7a th\u00ec Hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh (has expanded).", "difficulty": "medium"}, {"id": "n5-79", "part": 5, "type": "passive", "question": "A new employee handbook _____ to all new hires at the beginning of their orientation.", "options": ["is providing", "will be provided", "provides", "was providing"], "answer": 1, "explanation": "\u2705 <b>Will be provided</b> (S\u1ebd \u0111\u01b0\u1ee3c cung c\u1ea5p). <br>\ud83d\udca1 <i>Ng\u1eef c\u1ea3nh:</i> Th\u00f4ng b\u00e1o v\u1ec1 m\u1ed9t vi\u1ec7c s\u1ebd di\u1ec5n ra t\u1ea1i orientation.", "difficulty": "medium"}, {"id": "n5-80", "part": 5, "type": "word-form", "question": "The decision to outsource customer service was made after _____ consideration of the costs and benefits.", "options": ["care", "carefulness", "carefully", "careful"], "answer": 3, "explanation": "\u2705 <b>Careful</b>. <br>\ud83d\udca1 V\u1ecb tr\u00ed t\u00ednh t\u1eeb \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'consideration'.", "difficulty": "medium"}, {"id": "n5-81", "part": 5, "type": "verb-tense", "question": "The annual shareholders meeting _____ place every June at the main headquarters.", "options": ["takes", "took", "has taken", "is taking"], "answer": 0, "explanation": "\u2705 <b>Takes</b>. <br>\ud83d\udca1 <i>Th\u00f3i quen/L\u1ecbch tr\u00ecnh:</i> D\u00f9ng Hi\u1ec7n t\u1ea1i \u0111\u01a1n v\u1edbi 'every June'.", "difficulty": "medium"}, {"id": "n5-82", "part": 5, "type": "conjunction", "question": "All employees must wear their ID badges _____ they enter or exit the building.", "options": ["whenever", "wherever", "whatever", "whoever"], "answer": 0, "explanation": "\u2705 <b>Whenever</b> (B\u1ea5t c\u1ee9 khi n\u00e0o). <br>\ud83d\udca1 Li\u00ean t\u1eeb ch\u1ec9 th\u1eddi gian l\u1eb7p l\u1ea1i.", "difficulty": "medium"}, {"id": "n5-83", "part": 5, "type": "prepositions", "question": "The software automatically generates reports _____ a weekly basis.", "options": ["in", "at", "on", "by"], "answer": 2, "explanation": "\u2705 <b>On</b>. <br>\ud83d\udca1 <i>C\u1ee5m c\u1ed1 \u0111\u1ecbnh:</i> 'On a [weekly/daily] basis' (\u0110\u1ec1u \u0111\u1eb7n h\u00e0ng [tu\u1ea7n/ng\u00e0y]).", "difficulty": "easy"}, {"id": "n5-84", "part": 5, "type": "word-form", "question": "The team's _____ approach to problem-solving has earned them recognition company-wide.", "options": ["innovative", "innovation", "innovate", "innovatively"], "answer": 0, "explanation": "\u2705 <b>Innovative</b> (S\u00e1ng t\u1ea1o). <br>\ud83d\udca1 T\u00ednh t\u1eeb b\u1ed5 ngh\u0129a cho danh t\u1eeb 'approach'.", "difficulty": "medium"}, {"id": "n5-85", "part": 5, "type": "vocabulary", "question": "The new branch will _____ its doors to customers next month on its grand opening day.", "options": ["remove", "close", "lock", "open"], "answer": 3, "explanation": "\u2705 <b>Open</b>. <br>\ud83d\udca1 <i>Idiom kinh doanh:</i> 'Open its doors' (B\u1eaft \u0111\u1ea7u m\u1edf c\u1eeda kinh doanh).", "difficulty": "medium"}, {"id": "n5-86", "part": 5, "type": "prepositions", "question": "The results of the market research were _____ expectations, showing strong consumer interest.", "options": ["below", "over", "beyond", "against"], "answer": 2, "explanation": "\u2705 <b>Beyond</b>. <br>\ud83d\udca1 <i>C\u1ee5m c\u1ed1 \u0111\u1ecbnh:</i> 'Beyond expectations' (V\u01b0\u1ee3t ngo\u00e0i mong \u0111\u1ee3i).", "difficulty": "medium"}, {"id": "n5-87", "part": 5, "type": "gerund-infinitive", "question": "The manager avoided _____ any assumptions without reviewing all of the data first.", "options": ["make", "to make", "made", "making"], "answer": 3, "explanation": "\u2705 <b>Making</b>. <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> 'Avoid + V-ing' (Tr\u00e1nh l\u00e0m g\u00ec).", "difficulty": "medium"}, {"id": "n5-88", "part": 5, "type": "modal", "question": "Visitors _____ sign in at the reception desk before proceeding to any office.", "options": ["must", "may", "could", "would"], "answer": 0, "explanation": "\u2705 <b>Must</b>. <br>\ud83d\udca1 Ch\u1ec9 quy \u0111\u1ecbnh b\u1eaft bu\u1ed9c (obligation).", "difficulty": "medium"}, {"id": "n5-89", "part": 5, "type": "conjunction", "question": "The conference has been sold out every year _____ it was first held in 2018.", "options": ["when", "since", "until", "while"], "answer": 1, "explanation": "\u2705 <b>Since</b> (K\u1ec3 t\u1eeb khi). <br>\ud83d\udca1 D\u00f9ng v\u1edbi Hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh 'has been sold out'.", "difficulty": "medium"}, {"id": "n5-90", "part": 5, "type": "word-form", "question": "The _____ layout of the new office space was designed to promote collaboration.", "options": ["opens-plan", "open-plan", "openly-plan", "open-planning"], "answer": 1, "explanation": "\u2705 <b>Open-plan</b>. <br>\ud83d\udca1 <i>T\u1eeb v\u1ef1ng chuy\u00ean ng\u00e0nh:</i> 'Open-plan layout' (B\u1ed1 c\u1ee5c kh\u00f4ng gian m\u1edf).", "difficulty": "medium"}, {"id": "n5-91", "part": 5, "type": "vocabulary", "question": "The manager asked the team to _____ their project timelines to reflect recent changes in scope.", "options": ["request", "remove", "revise", "respond"], "answer": 2, "explanation": "\u2705 <b>Revise</b> (S\u1eeda \u0111\u1ed5i/\u0110i\u1ec1u ch\u1ec9nh). <br>\ud83d\udca1 D\u00f9ng khi c\u1eadp nh\u1eadt l\u1ea1i k\u1ebf ho\u1ea1ch ho\u1eb7c t\u00e0i li\u1ec7u.", "difficulty": "medium"}, {"id": "n5-92", "part": 5, "type": "prepositions", "question": "The training session is scheduled _____ 9:00 a.m. on the second floor.", "options": ["at", "on", "in", "by"], "answer": 0, "explanation": "\u2705 <b>At</b>. <br>\ud83d\udca1 'At' d\u00f9ng cho th\u1eddi gian c\u1ee5 th\u1ec3.", "difficulty": "easy"}, {"id": "n5-93", "part": 5, "type": "relative-clause", "question": "The technician _____ repaired the printer also updated the firmware.", "options": ["which", "whose", "whom", "who"], "answer": 3, "explanation": "\u2705 <b>Who</b>. <br>\ud83d\udca1 \u0110\u1ea1i t\u1eeb quan h\u1ec7 thay th\u1ebf cho ng\u01b0\u1eddi (technician).", "difficulty": "medium"}, {"id": "n5-94", "part": 5, "type": "conjunction", "question": "The new software is user-friendly, _____ all staff members are expected to learn it quickly.", "options": ["yet", "so", "but", "nor"], "answer": 1, "explanation": "\u2705 <b>So</b> (V\u00ec v\u1eady). <br>\ud83d\udca1 Ch\u1ec9 k\u1ebft qu\u1ea3.", "difficulty": "medium"}, {"id": "n5-95", "part": 5, "type": "passive", "question": "The agenda for the annual general meeting _____ out to all shareholders last week.", "options": ["sent", "will send", "sends", "was sent"], "answer": 3, "explanation": "\u2705 <b>Was sent</b> (B\u1ecb \u0111\u1ed9ng qu\u00e1 kh\u1ee9). <br>\ud83d\udca1 Agenda (ch\u01b0\u01a1ng tr\u00ecnh h\u1ecdp) '\u0111\u01b0\u1ee3c g\u1eedi' \u0111i.", "difficulty": "medium"}, {"id": "n5-96", "part": 5, "type": "word-form", "question": "The job posting attracted over 300 _____ within the first 48 hours.", "options": ["applicants", "apply", "applied", "applicable"], "answer": 0, "explanation": "\u2705 <b>Applicants</b> (Ng\u01b0\u1eddi n\u1ed9p \u0111\u01a1n). <br>\ud83d\udca1 'Over 300' c\u1ea7n m\u1ed9t danh t\u1eeb s\u1ed1 nhi\u1ec1u ch\u1ec9 ng\u01b0\u1eddi.", "difficulty": "medium"}, {"id": "n5-97", "part": 5, "type": "conjunction", "question": "The proposal was rejected _____ it failed to meet the minimum budget requirements.", "options": ["despite", "in case", "because", "although"], "answer": 2, "explanation": "\u2705 <b>Because</b>. <br>\ud83d\udca1 Gi\u1ea3i th\u00edch l\u00fd do b\u1ecb t\u1eeb ch\u1ed1i.", "difficulty": "medium"}, {"id": "n5-98", "part": 5, "type": "prepositions", "question": "Our products are available _____ both online and in-store retail locations.", "options": ["by", "of", "through", "with"], "answer": 2, "explanation": "\u2705 <b>Through</b>. <br>\ud83d\udca1 <i>S\u1eafc th\u00e1i:</i> 'Available through' ch\u1ec9 k\u00eanh ph\u00e2n ph\u1ed1i h\u00e0ng h\u00f3a.", "difficulty": "medium"}, {"id": "n5-99", "part": 5, "type": "vocabulary", "question": "The director expressed her _____ for the team's outstanding work on the campaign.", "options": ["assumption", "application", "appreciation", "attention"], "answer": 2, "explanation": "\u2705 <b>Appreciation</b> (S\u1ef1 tr\u00e2n tr\u1ecdng/bi\u1ebft \u01a1n). <br>\ud83d\udca1 <i>M\u1eb9o ETS:</i> 'Express appreciation to/for' l\u00e0 m\u1eabu c\u00e2u khen ng\u1ee3i nh\u00e2n s\u1ef1.", "difficulty": "medium"}, {"id": "n5-100", "part": 5, "type": "word-form", "question": "The board of directors must ensure full _____ with the new financial reporting standards.", "options": ["comply", "compliant", "complying", "compliance"], "answer": 3, "explanation": "\u2705 <b>Compliance</b> (S\u1ef1 tu\u00e2n th\u1ee7). <br>\ud83d\udca1 'Ensure full compliance with' l\u00e0 c\u1ee5m t\u1eeb chu\u1ea9n m\u1ef1c ph\u00e1p l\u00fd doanh nghi\u1ec7p.", "difficulty": "medium"}, {"id": "b5-01", "part": 5, "type": "vocabulary", "question": "The company's _____ to digital transformation was accelerated by the recent global shifts in consumer behavior.", "options": ["translation", "transmission", "transaction", "transition"], "answer": 3, "explanation": "'Transition' (s\u1ef1 chuy\u1ec3n \u0111\u1ed5i) l\u00e0 thu\u1eadt ng\u1eef chu\u1ea9n cho digital transformation. C\u00e1c t\u1eeb kh\u00e1c tuy b\u1eaft \u0111\u1ea7u b\u1eb1ng 'trans' nh\u01b0ng ngh\u0129a ho\u00e0n to\u00e0n kh\u00e1c bi\u1ec7t.", "difficulty": "medium"}, {"id": "b5-02", "part": 5, "type": "vocabulary", "question": "Team leaders must _____ the performance of their subordinates on a semi-annual basis.", "options": ["assess", "access", "assert", "assist"], "answer": 0, "explanation": "'Assess' (\u0111\u00e1nh gi\u00e1) l\u00e0 s\u1eafc th\u00e1i chu\u1ea9n cho vi\u1ec7c ki\u1ec3m tra n\u0103ng l\u1ef1c. 'Access' (truy c\u1eadp) l\u00e0 t\u1eeb g\u00e2y nh\u1ea7m l\u1eabn v\u1ec1 m\u1eb7t ch\u1eef vi\u1ebft (distractor).", "difficulty": "medium"}, {"id": "b5-03", "part": 5, "type": "vocabulary", "question": "The board of directors _____ the proposal for the new merger after extensive deliberation.", "options": ["enforced", "endorsed", "engaged", "enlarged"], "answer": 1, "explanation": "'Endorsed' (t\u00e1n th\u00e0nh/ch\u1ea5p thu\u1eadn) l\u00e0 s\u1eafc th\u00e1i formal nh\u1ea5t trong Board meeting. 'Enforced' (\u00e9p bu\u1ed9c) qu\u00e1 m\u1ea1nh.", "difficulty": "medium"}, {"id": "b5-04", "part": 5, "type": "vocabulary", "question": "The updated safety manual provides _____ instructions on how to handle hazardous materials.", "options": ["extreme", "exclusive", "explicit", "external"], "answer": 2, "explanation": "'Explicit instructions' (h\u01b0\u1edbng d\u1eabn r\u00f5 r\u00e0ng/chi ti\u1ebft). \u0110\u00e2y l\u00e0 c\u1eb7p t\u1eeb th\u01b0\u1eddng g\u1eb7p trong c\u00e1c \u0111\u1ec1 thi ETS m\u1edbi.", "difficulty": "medium"}, {"id": "b5-05", "part": 5, "type": "vocabulary", "question": "To _____ the growing demand for hybrid work, the company is renovating its downtown office space.", "options": ["accompany", "accumulate", "accomplish", "accommodate"], "answer": 3, "explanation": "'Accommodate demand/need' (\u0111\u00e1p \u1ee9ng nhu c\u1ea7u). Collocation c\u1ef1c k\u1ef3 ph\u1ed5 bi\u1ebfn.", "difficulty": "medium"}, {"id": "b5-06", "part": 5, "type": "vocabulary", "question": "The marketing team's _____ of the latest market trends led to a highly successful campaign.", "options": ["interpretation", "interaction", "interference", "interruption"], "answer": 0, "explanation": "'Interpretation' (s\u1ef1 di\u1ec5n gi\u1ea3i/hi\u1ec3u) c\u00e1c xu h\u01b0\u1edbng th\u1ecb tr\u01b0\u1eddng l\u00e0 ch\u00eca kh\u00f3a th\u00e0nh c\u00f4ng.", "difficulty": "medium"}, {"id": "b5-07", "part": 5, "type": "vocabulary", "question": "The CEO emphasized that _____ communication between departments is essential for project success.", "options": ["transferable", "transparent", "transient", "translucent"], "answer": 1, "explanation": "'Transparent communication' (giao ti\u1ebfp minh b\u1ea1ch) l\u00e0 c\u1ee5m t\u1eeb 'nuance' r\u1ea5t hot trong ETS 2024-2025.", "difficulty": "medium"}, {"id": "b5-08", "part": 5, "type": "vocabulary", "question": "The research findings offer _____ evidence that the proposed changes will improve overall productivity.", "options": ["complying", "competing", "compelling", "completing"], "answer": 2, "explanation": "'Compelling evidence' (b\u1eb1ng ch\u1ee9ng thuy\u1ebft ph\u1ee5c). Distractors l\u00e0 c\u00e1c t\u00ednh t\u1eeb c\u00f3 h\u1eadu t\u1ed1 -ing g\u00e2y nh\u1ea7m l\u1eabn.", "difficulty": "medium"}, {"id": "b5-09", "part": 5, "type": "vocabulary", "question": "Managers are encouraged to _____ regular feedback from their team members to identify areas for improvement.", "options": ["soldier", "solidify", "solace", "solicit"], "answer": 3, "explanation": "'Solicit feedback' (thu th\u1eadp/k\u00eau g\u1ecdi ph\u1ea3n h\u1ed3i) l\u00e0 thu\u1eadt ng\u1eef formal trong qu\u1ea3n tr\u1ecb.", "difficulty": "medium"}, {"id": "b5-10", "part": 5, "type": "vocabulary", "question": "The _____ of new technology has significantly streamlined our logistics operations.", "options": ["implication", "implementation", "imposter", "improvisation"], "answer": 1, "explanation": "'Implementation' (vi\u1ec7c tri\u1ec3n khai) c\u00f4ng ngh\u1ec7 m\u1edbi. 'Implication' (h\u1ec7 qu\u1ea3) c\u0169ng c\u00f3 ngh\u0129a nh\u01b0ng kh\u00f4ng ph\u00f9 h\u1ee3p s\u1eafc th\u00e1i ch\u1ee7 \u0111\u1ed9ng b\u1eb1ng.", "difficulty": "medium"}, {"id": "b5-11", "part": 5, "type": "word-form", "question": "Investors were pleased with the _____ results posted by the company this quarter.", "options": ["exceptionally", "exception", "exceptional", "except"], "answer": 2, "explanation": "T\u00ednh t\u1eeb 'exceptional' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'results'.", "difficulty": "medium"}, {"id": "b5-12", "part": 5, "type": "word-form", "question": "The new assistant proved to be highly _____ in managing the director's schedule.", "options": ["capacitate", "capability", "capably", "capable"], "answer": 3, "explanation": "T\u00ednh t\u1eeb 'capable' d\u00f9ng sau linking verb 'proved to be'. 'Capably' l\u00e0 ph\u00f3 t\u1eeb.", "difficulty": "medium"}, {"id": "b5-13", "part": 5, "type": "word-form", "question": "A formal _____ of the contract will be made at the signing ceremony next week.", "options": ["announce", "announcement", "announced", "announcing"], "answer": 1, "explanation": "Sau m\u1ea1o t\u1eeb 'A formal' c\u1ea7n danh t\u1eeb. 'Announcement' = th\u00f4ng b\u00e1o ch\u00ednh th\u1ee9c.", "difficulty": "medium"}, {"id": "b5-14", "part": 5, "type": "word-form", "question": "The board has _____ authorized the release of funds for the new infrastructure project.", "options": ["formal", "formality", "formalize", "formally"], "answer": 3, "explanation": "Ph\u00f3 t\u1eeb 'formally' b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'authorized'.", "difficulty": "medium"}, {"id": "b5-15", "part": 5, "type": "word-form", "question": "The _____ of qualified candidates makes the hiring decision particularly difficult.", "options": ["scarcity", "scarcely", "scarce", "scare"], "answer": 0, "explanation": "Sau 'The' c\u1ea7n danh t\u1eeb ch\u1ee7 ng\u1eef. 'Scarcity' = s\u1ef1 khan hi\u1ebfm.", "difficulty": "medium"}, {"id": "b5-16", "part": 5, "type": "verb-tense", "question": "By the end of this fiscal year, the company _____ operations in twelve countries.", "options": ["establishes", "established", "will have established", "will establish"], "answer": 2, "explanation": "\"By the end of this fiscal year\" = th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai c\u1ee5 th\u1ec3 \u2192 Future Perfect. \"Will have established\" = s\u1ebd \u0111\u00e3 thi\u1ebft l\u1eadp.", "difficulty": "medium"}, {"id": "b5-17", "part": 5, "type": "verb-tense", "question": "The CEO _____ the board of directors every quarter to review financial performance.", "options": ["briefed", "briefs", "has briefed", "will brief"], "answer": 1, "explanation": "L\u1ecbch tr\u00ecnh \u0111\u1ecbnh k\u1ef3 \u2192 hi\u1ec7n t\u1ea1i \u0111\u01a1n 'briefs'.", "difficulty": "medium"}, {"id": "b5-18", "part": 5, "type": "verb-tense", "question": "We _____ the new inventory system for six months before the technical issues emerged.", "options": ["use", "used", "will use", "had been using"], "answer": 3, "explanation": "H\u00e0nh \u0111\u1ed9ng di\u1ec5n ra tr\u01b0\u1edbc s\u1ef1 ki\u1ec7n qu\u00e1 kh\u1ee9 \u2192 past perfect continuous 'had been using'.", "difficulty": "medium"}, {"id": "b5-19", "part": 5, "type": "verb-tense", "question": "The HR team _____ the updated employee handbook to all new hires since last month.", "options": ["has been distributing", "distributed", "distributes", "will distribute"], "answer": 0, "explanation": "'Since last month' v\u1edbi h\u00e0nh \u0111\u1ed9ng c\u00f2n ti\u1ebfp di\u1ec5n \u2192 present perfect continuous.", "difficulty": "easy"}, {"id": "b5-20", "part": 5, "type": "verb-tense", "question": "The client _____ a detailed proposal before making any final decisions.", "options": ["requests", "requested", "will request", "has requested"], "answer": 0, "explanation": "Ch\u00ednh s\u00e1ch/y\u00eau c\u1ea7u th\u01b0\u1eddng xuy\u00ean \u2192 hi\u1ec7n t\u1ea1i \u0111\u01a1n 'requests'.", "difficulty": "medium"}, {"id": "b5-21", "part": 5, "type": "verb-tense", "question": "Several employees _____ concerns about the proposed policy changes at yesterday's town hall.", "options": ["raise", "have raised", "raised", "will raise"], "answer": 2, "explanation": "'Yesterday' \u2192 qu\u00e1 kh\u1ee9 \u0111\u01a1n 'raised'.", "difficulty": "easy"}, {"id": "b5-22", "part": 5, "type": "verb-tense", "question": "The supply chain _____ significantly since new technology was adopted two years ago.", "options": ["has improved", "improved", "improves", "will improve"], "answer": 0, "explanation": "\"Since + s\u1ef1 ki\u1ec7n qu\u00e1 kh\u1ee9\" \u2192 Present Perfect. \"Has improved since\" = \u0111\u00e3 c\u1ea3i thi\u1ec7n k\u1ec3 t\u1eeb khi.", "difficulty": "easy"}, {"id": "b5-23", "part": 5, "type": "verb-tense", "question": "Dr. Patel _____ a keynote speech at the international symposium last November.", "options": ["delivers", "will deliver", "delivered", "has delivered"], "answer": 2, "explanation": "'Last November' \u2192 qu\u00e1 kh\u1ee9 \u0111\u01a1n 'delivered'.", "difficulty": "medium"}, {"id": "b5-24", "part": 5, "type": "verb-tense", "question": "Before the merger _____, both companies had operated independently for decades.", "options": ["occurs", "occurred", "will occur", "has occurred"], "answer": 1, "explanation": "M\u1ec7nh \u0111\u1ec1 th\u1eddi gian qu\u00e1 kh\u1ee9 (before + past simple) k\u1ebft h\u1ee3p v\u1edbi past perfect 'had operated'.", "difficulty": "medium"}, {"id": "b5-25", "part": 5, "type": "verb-tense", "question": "Our customer support center _____ around the clock to assist clients worldwide.", "options": ["operated", "has operated", "operates", "will have operated"], "answer": 2, "explanation": "S\u1ef1 th\u1eadt v\u1ec1 ho\u1ea1t \u0111\u1ed9ng hi\u1ec7n t\u1ea1i, li\u00ean t\u1ee5c \u2192 hi\u1ec7n t\u1ea1i \u0111\u01a1n 'operates'.", "difficulty": "medium"}, {"id": "b5-26", "part": 5, "type": "prepositions", "question": "The new product was developed _____ response to customer demand for eco-friendly packaging.", "options": ["in", "on", "with", "by"], "answer": 0, "explanation": "'In response to' = \u0111\u1ec3 \u0111\u00e1p l\u1ea1i (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "b5-27", "part": 5, "type": "prepositions", "question": "Please CC the department manager _____ any email regarding the project timeline.", "options": ["for", "in", "at", "on"], "answer": 3, "explanation": "'CC someone on an email' = \u0111\u01b0a ai v\u00e0o CC c\u1ee7a email (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "b5-28", "part": 5, "type": "prepositions", "question": "The conference will take place _____ three consecutive days starting Monday.", "options": ["in", "for", "over", "during"], "answer": 2, "explanation": "'Over three consecutive days' = k\u00e9o d\u00e0i trong ba ng\u00e0y li\u00ean ti\u1ebfp.", "difficulty": "medium"}, {"id": "b5-29", "part": 5, "type": "prepositions", "question": "The internship program is open _____ students who are currently enrolled in a university.", "options": ["for", "of", "to", "with"], "answer": 2, "explanation": "'Open to' = m\u1edf c\u1eeda cho, d\u00e0nh cho (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "b5-30", "part": 5, "type": "prepositions", "question": "The renovation project is expected to be completed _____ schedule this autumn.", "options": ["by", "in", "to", "on"], "answer": 3, "explanation": "'On schedule' = \u0111\u00fang ti\u1ebfn \u0111\u1ed9 (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "b5-31", "part": 5, "type": "prepositions", "question": "All invoices must be reviewed _____ the finance team prior to final approval.", "options": ["to", "by", "of", "with"], "answer": 1, "explanation": "'Reviewed by' = \u0111\u01b0\u1ee3c xem x\u00e9t b\u1edfi (t\u00e1c nh\u00e2n trong c\u00e2u b\u1ecb \u0111\u1ed9ng).", "difficulty": "medium"}, {"id": "b5-32", "part": 5, "type": "prepositions", "question": "The new policy is _____ line with the company's long-term sustainability goals.", "options": ["on", "in", "at", "by"], "answer": 1, "explanation": "'In line with' = ph\u00f9 h\u1ee3p v\u1edbi, nh\u1ea5t qu\u00e1n v\u1edbi (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "b5-33", "part": 5, "type": "prepositions", "question": "The company has been operating _____ a loss for the past two quarters.", "options": ["on", "in", "at", "with"], "answer": 2, "explanation": "'Operating at a loss' = ho\u1ea1t \u0111\u1ed9ng thua l\u1ed7 (collocation c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "b5-34", "part": 5, "type": "prepositions", "question": "The training program is designed to equip employees _____ the skills needed for digital transformation.", "options": ["by", "with", "on", "for"], "answer": 1, "explanation": "'Equip someone with skills' = trang b\u1ecb cho ai k\u1ef9 n\u0103ng (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "b5-35", "part": 5, "type": "prepositions", "question": "Applications submitted _____ the posted deadline will not be considered for this intake.", "options": ["before", "after", "within", "during"], "answer": 1, "explanation": "'After the deadline' = sau h\u1ea1n ch\u00f3t \u2192 b\u1ecb lo\u1ea1i. Ph\u00f9 h\u1ee3p nh\u1ea5t v\u1edbi ng\u1eef ngh\u0129a.", "difficulty": "medium"}, {"id": "b5-36", "part": 5, "type": "conjunction", "question": "The team managed to complete the project _____ losing two key members mid-way through.", "options": ["despite", "even though", "without", "regardless"], "answer": 2, "explanation": "'Without + V-ing' = m\u00e0 kh\u00f4ng. 'Without losing' = m\u00e0 kh\u00f4ng m\u1ea5t. 'Despite' c\u1ea7n danh t\u1eeb hay gerund phrase.", "difficulty": "medium"}, {"id": "b5-37", "part": 5, "type": "conjunction", "question": "_____ the product received positive reviews, sales figures remained below expectations.", "options": ["Although", "While", "Since", "Because"], "answer": 0, "explanation": "'Although' = m\u1eb7c d\u00f9. T\u01b0\u01a1ng ph\u1ea3n gi\u1eefa review t\u1ed1t v\u00e0 doanh s\u1ed1 th\u1ea5p.", "difficulty": "medium"}, {"id": "b5-38", "part": 5, "type": "conjunction", "question": "The company will expand _____ market conditions remain favorable.", "options": ["as long as", "unless", "even though", "in case"], "answer": 0, "explanation": "'As long as' = mi\u1ec5n l\u00e0/ch\u1eebng n\u00e0o c\u00f2n. \u0110i\u1ec1u ki\u1ec7n \u0111\u1ec3 m\u1edf r\u1ed9ng.", "difficulty": "medium"}, {"id": "b5-39", "part": 5, "type": "conjunction", "question": "Production was halted; _____, engineers worked overnight to resolve the malfunction.", "options": ["however", "moreover", "therefore", "meanwhile"], "answer": 3, "explanation": "'Meanwhile' = trong th\u1eddi gian \u0111\u00f3 (hai vi\u1ec7c x\u1ea3y ra song song).", "difficulty": "medium"}, {"id": "b5-40", "part": 5, "type": "conjunction", "question": "The manager confirmed the venue _____ all participants could finalize their travel plans.", "options": ["for", "in order", "so that", "because"], "answer": 2, "explanation": "'So that' = \u0111\u1ec3 cho, nh\u1eb1m m\u1ee5c \u0111\u00edch. M\u1ee5c \u0111\u00edch x\u00e1c nh\u1eadn \u0111\u1ecba \u0111i\u1ec3m.", "difficulty": "medium"}, {"id": "b5-41", "part": 5, "type": "conjunction", "question": "_____ the training is mandatory, employees who miss it must attend a makeup session.", "options": ["While", "Until", "Whether", "Since"], "answer": 3, "explanation": "'Since' = v\u00ec (nguy\u00ean nh\u00e2n). V\u00ec bu\u1ed5i \u0111\u00e0o t\u1ea1o b\u1eaft bu\u1ed9c \u2192 ph\u1ea3i tham d\u1ef1 b\u00f9.", "difficulty": "medium"}, {"id": "b5-42", "part": 5, "type": "conjunction", "question": "The proposal was strong; _____, the committee requested several revisions.", "options": ["otherwise", "nonetheless", "accordingly", "likewise"], "answer": 1, "explanation": "'Nonetheless' = tuy nhi\u00ean, d\u00f9 v\u1eady. \u0110\u1ec1 xu\u1ea5t m\u1ea1nh NH\u01afNG \u1ee7y ban v\u1eabn y\u00eau c\u1ea7u s\u1eeda \u0111\u1ed5i.", "difficulty": "medium"}, {"id": "b5-43", "part": 5, "type": "conjunction", "question": "Employees are encouraged to submit feedback _____ they have concerns about the new workflow.", "options": ["wherever", "whenever", "however", "whoever"], "answer": 1, "explanation": "'Whenever' = b\u1ea5t c\u1ee9 khi n\u00e0o. G\u1eedi ph\u1ea3n h\u1ed3i khi n\u00e0o c\u00f3 lo ng\u1ea1i.", "difficulty": "medium"}, {"id": "b5-44", "part": 5, "type": "passive", "question": "The quarterly budget report _____ to all department heads by the end of this week.", "options": ["will be circulated", "circulates", "will circulate", "has circulating"], "answer": 0, "explanation": "B\u1ecb \u0111\u1ed9ng t\u01b0\u01a1ng lai 'will be circulated'. B\u00e1o c\u00e1o \u0111\u01b0\u1ee3c l\u01b0u h\u00e0nh (b\u1edfi finance team).", "difficulty": "medium"}, {"id": "b5-45", "part": 5, "type": "passive", "question": "All candidates who applied for the position _____ by phone within two weeks.", "options": ["will be contacted", "will contact", "are contacting", "have contacted"], "answer": 0, "explanation": "B\u1ecb \u0111\u1ed9ng 'will be contacted'. \u1ee8ng vi\u00ean \u0111\u01b0\u1ee3c li\u00ean h\u1ec7 (b\u1edfi HR).", "difficulty": "medium"}, {"id": "b5-46", "part": 5, "type": "passive", "question": "The conference room bookings _____ through the company intranet.", "options": ["manage", "are managed", "managing", "have managed"], "answer": 1, "explanation": "B\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n 'are managed'. Vi\u1ec7c \u0111\u1eb7t ph\u00f2ng \u0111\u01b0\u1ee3c qu\u1ea3n l\u00fd qua intranet.", "difficulty": "medium"}, {"id": "b5-47", "part": 5, "type": "passive", "question": "The CEO _____ with honorary membership by the Chamber of Commerce last year.", "options": ["presented", "has presented", "was presented", "is presenting"], "answer": 2, "explanation": "'Was presented with' = \u0111\u01b0\u1ee3c trao t\u1eb7ng (qu\u00e1 kh\u1ee9 b\u1ecb \u0111\u1ed9ng). 'Last year' x\u00e1c \u0111\u1ecbnh th\u00ec.", "difficulty": "medium"}, {"id": "b5-48", "part": 5, "type": "passive", "question": "All software updates _____ automatically unless the user disables the feature.", "options": ["install", "have installed", "installing", "are installed"], "answer": 3, "explanation": "B\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n 'are installed'. C\u1eadp nh\u1eadt \u0111\u01b0\u1ee3c c\u00e0i \u0111\u1eb7t t\u1ef1 \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "b5-49", "part": 5, "type": "passive", "question": "The safety inspection results _____ to local authorities within 48 hours of completion.", "options": ["must be submitted", "must submit", "must submitting", "must have submitted"], "answer": 0, "explanation": "Modal + be + V3 (b\u1ecb \u0111\u1ed9ng). 'Must be submitted' = ph\u1ea3i \u0111\u01b0\u1ee3c n\u1ed9p.", "difficulty": "medium"}, {"id": "b5-50", "part": 5, "type": "passive", "question": "Customers _____ that their personal data will never be shared with third parties.", "options": ["assure", "assuring", "are assured", "have assuring"], "answer": 2, "explanation": "B\u1ecb \u0111\u1ed9ng 'are assured' = \u0111\u01b0\u1ee3c \u0111\u1ea3m b\u1ea3o. Kh\u00e1ch h\u00e0ng nh\u1eadn s\u1ef1 \u0111\u1ea3m b\u1ea3o t\u1eeb c\u00f4ng ty.", "difficulty": "medium"}, {"id": "b5-51", "part": 5, "type": "vocabulary", "question": "The board _____ a decision to freeze all new hires until the financial review is complete.", "options": ["did", "took", "made", "had"], "answer": 2, "explanation": "'Make a decision' = ra quy\u1ebft \u0111\u1ecbnh (collocation chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "b5-52", "part": 5, "type": "vocabulary", "question": "Our legal team is currently _____ the contract to ensure all clauses are compliant.", "options": ["reissuing", "revising", "rescinding", "reviewing"], "answer": 3, "explanation": "'Reviewing a contract' = xem x\u00e9t h\u1ee3p \u0111\u1ed3ng (\u0111\u1ec3 ki\u1ec3m tra tu\u00e2n th\u1ee7).", "difficulty": "medium"}, {"id": "b5-53", "part": 5, "type": "vocabulary", "question": "The event was a tremendous _____, attracting over 3,000 visitors on opening day.", "options": ["triumph", "success", "victory", "achievement"], "answer": 1, "explanation": "'Success' l\u00e0 t\u1eeb ph\u1ed5 bi\u1ebfn nh\u1ea5t trong ng\u1eef c\u1ea3nh s\u1ef1 ki\u1ec7n th\u01b0\u01a1ng m\u1ea1i. 'Triumph/victory' thi\u00ean v\u1ec1 c\u1ea1nh tranh.", "difficulty": "medium"}, {"id": "b5-54", "part": 5, "type": "vocabulary", "question": "Employees are _____ to report any suspicious activity to the security department immediately.", "options": ["encouraged", "urged", "advised", "required"], "answer": 3, "explanation": "'Required' = b\u1eaft bu\u1ed9c. C\u00e2u d\u00f9ng 'immediately' v\u00e0 ng\u1eef c\u1ea3nh an ninh \u2192 b\u1eaft bu\u1ed9c nh\u1ea5t.", "difficulty": "medium"}, {"id": "b5-55", "part": 5, "type": "vocabulary", "question": "The new pricing structure will _____ effect on the first day of the next billing cycle.", "options": ["take", "go into", "fall into", "put into"], "answer": 0, "explanation": "'Take effect' = c\u00f3 hi\u1ec7u l\u1ef1c (collocation c\u1ed1 \u0111\u1ecbnh duy nh\u1ea5t \u0111\u00fang). 'Fall into effect', 'go into effect', 'put into effect' kh\u00f4ng ph\u1ea3i c\u1ee5m t\u1eeb chu\u1ea9n trong ng\u1eef c\u1ea3nh n\u00e0y.", "difficulty": "medium"}, {"id": "b5-56", "part": 5, "type": "vocabulary", "question": "The conference attracted a _____ audience of professionals from over 40 countries.", "options": ["various", "broad", "mixed", "diverse"], "answer": 3, "explanation": "'Diverse audience' = kh\u00e1n gi\u1ea3 \u0111a d\u1ea1ng (v\u1ec1 qu\u1ed1c t\u1ecbch/n\u1ec1n t\u1ea3ng). Collocation t\u1ef1 nhi\u00ean nh\u1ea5t.", "difficulty": "medium"}, {"id": "b5-57", "part": 5, "type": "vocabulary", "question": "The CEO _____ responsibility for the accounting error and issued a public apology.", "options": ["accepted", "admitted", "acknowledged", "assumed"], "answer": 0, "explanation": "'Accept responsibility' = nh\u1eadn tr\u00e1ch nhi\u1ec7m (collocation c\u1ed1 \u0111\u1ecbnh trong TOEIC).", "difficulty": "medium"}, {"id": "b5-58", "part": 5, "type": "vocabulary", "question": "The new employee orientation program is _____ to help new hires integrate quickly.", "options": ["intended", "aimed", "designed", "meant"], "answer": 2, "explanation": "'Designed to' = \u0111\u01b0\u1ee3c thi\u1ebft k\u1ebf \u0111\u1ec3 (ph\u1ed5 bi\u1ebfn nh\u1ea5t khi n\u00f3i v\u1ec1 m\u1ee5c \u0111\u00edch c\u1ee7a ch\u01b0\u01a1ng tr\u00ecnh/s\u1ea3n ph\u1ea9m).", "difficulty": "medium"}, {"id": "b5-59", "part": 5, "type": "vocabulary", "question": "We _____ our sincere apologies for the inconvenience caused by the service disruption.", "options": ["offer", "extend", "make", "give"], "answer": 1, "explanation": "'Extend our sincere apologies' = g\u1eedi l\u1eddi xin l\u1ed7i ch\u00e2n th\u00e0nh (formal collocation trong th\u01b0 xin l\u1ed7i).", "difficulty": "medium"}, {"id": "b5-60", "part": 5, "type": "vocabulary", "question": "The sales data _____ a clear upward trend over the past three consecutive quarters.", "options": ["reveals", "shows", "indicates", "demonstrates"], "answer": 2, "explanation": "'Data indicates a trend' = d\u1eef li\u1ec7u cho th\u1ea5y xu h\u01b0\u1edbng. 'Indicate' ph\u1ed5 bi\u1ebfn nh\u1ea5t v\u1edbi statistical data trong TOEIC.", "difficulty": "medium"}, {"id": "c5-01", "part": 5, "type": "word-form", "question": "The committee expressed its _____ with the vendor's lack of transparency during the audit.", "options": ["disappoint", "disappointed", "disappointing", "disappointment"], "answer": 3, "explanation": "Sau possessive 'its' c\u1ea7n danh t\u1eeb. 'Disappointment' = s\u1ef1 th\u1ea5t v\u1ecdng.", "difficulty": "medium"}, {"id": "c5-02", "part": 5, "type": "word-form", "question": "Staff are _____ reminded that personal use of company devices is strictly prohibited.", "options": ["frequent", "frequency", "frequented", "frequently"], "answer": 3, "explanation": "Ph\u00f3 t\u1eeb 'frequently' b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb b\u1ecb \u0111\u1ed9ng 'are reminded'.", "difficulty": "medium"}, {"id": "c5-03", "part": 5, "type": "word-form", "question": "The firm's rapid _____ into Southeast Asian markets caught many industry analysts by surprise.", "options": ["expand", "expansion", "expansive", "expanding"], "answer": 1, "explanation": "Sau possessive 'firm's' c\u1ea7n danh t\u1eeb. 'Expansion' = s\u1ef1 m\u1edf r\u1ed9ng.", "difficulty": "medium"}, {"id": "c5-04", "part": 5, "type": "word-form", "question": "The revised onboarding procedure proved far more _____ than the previous one.", "options": ["effect", "effective", "effectively", "effectiveness"], "answer": 1, "explanation": "Sau linking verb 'proved more' c\u1ea7n t\u00ednh t\u1eeb. 'Effective' = hi\u1ec7u qu\u1ea3.", "difficulty": "medium"}, {"id": "c5-05", "part": 5, "type": "word-form", "question": "All participants must sign a _____ agreement before accessing the confidential data room.", "options": ["confide", "confidential", "confidentiality", "confidently"], "answer": 2, "explanation": "T\u00ednh t\u1eeb 'confidentiality' kh\u00f4ng ph\u00f9 h\u1ee3p v\u1ecb tr\u00ed tr\u01b0\u1edbc N. 'Confidential' l\u00e0 t\u00ednh t\u1eeb b\u1ed5 ngh\u0129a cho 'agreement'.", "difficulty": "medium"}, {"id": "c5-06", "part": 5, "type": "word-form", "question": "The CEO praised the team for its _____ approach to resolving the supply chain disruption.", "options": ["innovate", "innovation", "innovative", "innovatively"], "answer": 2, "explanation": "T\u00ednh t\u1eeb 'innovative' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'approach'.", "difficulty": "medium"}, {"id": "c5-07", "part": 5, "type": "word-form", "question": "The _____ of the new production facility is scheduled to begin next spring.", "options": ["construction", "constructive", "construct", "constructing"], "answer": 0, "explanation": "Sau 'The' c\u1ea7n danh t\u1eeb ch\u1ee7 ng\u1eef. 'Construction' = vi\u1ec7c x\u00e2y d\u1ef1ng.", "difficulty": "medium"}, {"id": "c5-08", "part": 5, "type": "word-form", "question": "Ms. Vo's _____ performance throughout the quarter earned her a well-deserved promotion.", "options": ["consistent", "consist", "consistency", "consistently"], "answer": 0, "explanation": "T\u00ednh t\u1eeb 'consistent' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'performance'. 'Consistently' l\u00e0 ph\u00f3 t\u1eeb.", "difficulty": "medium"}, {"id": "c5-09", "part": 5, "type": "verb-tense", "question": "The factory _____ its new automated line for just three weeks when the first quality issue arose.", "options": ["operated", "has operated", "had been operating", "was operating"], "answer": 2, "explanation": "H\u00e0nh \u0111\u1ed9ng di\u1ec5n ra li\u00ean t\u1ee5c tr\u01b0\u1edbc m\u1ed9t s\u1ef1 ki\u1ec7n qu\u00e1 kh\u1ee9 \u2192 past perfect continuous 'had been operating'.", "difficulty": "medium"}, {"id": "c5-10", "part": 5, "type": "verb-tense", "question": "By the time the audit team _____ its findings, the board will have already convened an emergency session.", "options": ["will publish", "published", "publishes", "will have published"], "answer": 2, "explanation": "M\u1ec7nh \u0111\u1ec1 'by the time' + present simple \u2192 main clause d\u00f9ng future perfect. 'publishes' \u0111\u00fang cho m\u1ec7nh \u0111\u1ec1 th\u1eddi gian.", "difficulty": "medium"}, {"id": "c5-11", "part": 5, "type": "verb-tense", "question": "The logistics coordinator _____ the shipment status when the warehouse called with an urgent update.", "options": ["tracks", "was tracking", "tracked", "has tracked"], "answer": 1, "explanation": "H\u00e0nh \u0111\u1ed9ng \u0111ang di\u1ec5n ra b\u1ecb gi\u00e1n \u0111o\u1ea1n \u2192 past continuous 'was tracking'.", "difficulty": "medium"}, {"id": "c5-12", "part": 5, "type": "verb-tense", "question": "Demand for our premium subscription tier _____ steadily over the past eighteen months.", "options": ["grows", "grew", "has grown", "is growing"], "answer": 2, "explanation": "\"Over the past eighteen months\" = kho\u1ea3ng th\u1eddi gian k\u00e9o \u0111\u1ebfn hi\u1ec7n t\u1ea1i \u2192 Present Perfect. \"Has grown\" = \u0111\u00e3 t\u0103ng tr\u01b0\u1edfng.", "difficulty": "medium"}, {"id": "c5-13", "part": 5, "type": "verb-tense", "question": "The head of procurement _____ three vendors before selecting Apex Supplies as the preferred partner.", "options": ["had contacted", "has contacted", "contacted", "contacts"], "answer": 0, "explanation": "H\u00e0nh \u0111\u1ed9ng ho\u00e0n t\u1ea5t tr\u01b0\u1edbc h\u00e0nh \u0111\u1ed9ng qu\u00e1 kh\u1ee9 'selecting' \u2192 past perfect 'had contacted'.", "difficulty": "medium"}, {"id": "c5-14", "part": 5, "type": "verb-tense", "question": "The engineering team _____ the prototype every Tuesday afternoon to monitor its performance.", "options": ["has tested", "tested", "tests", "will have tested"], "answer": 2, "explanation": "L\u1ecbch \u0111\u1ecbnh k\u1ef3 'every Tuesday afternoon' \u2192 hi\u1ec7n t\u1ea1i \u0111\u01a1n 'tests'.", "difficulty": "medium"}, {"id": "c5-15", "part": 5, "type": "verb-tense", "question": "Unless the client _____ the revised quotation by Thursday, the project timeline will need to be adjusted.", "options": ["has approved", "will approve", "approved", "approves"], "answer": 3, "explanation": "M\u1ec7nh \u0111\u1ec1 'unless' (= \u0111i\u1ec1u ki\u1ec7n) KH\u00d4NG d\u00f9ng will \u2192 hi\u1ec7n t\u1ea1i \u0111\u01a1n 'approves'.", "difficulty": "medium"}, {"id": "c5-16", "part": 5, "type": "prepositions", "question": "The merger was completed _____ schedule, two months ahead of the original target date.", "options": ["on", "ahead of", "before", "in"], "answer": 1, "explanation": "'Completed ahead of schedule' = ho\u00e0n th\u00e0nh s\u1edbm h\u01a1n d\u1ef1 ki\u1ebfn. V\u00ec ph\u1ea7n sau ghi 'two months ahead' n\u00ean 'ahead of' l\u00e0 l\u1ef1a ch\u1ecdn ch\u00ednh x\u00e1c.", "difficulty": "medium"}, {"id": "c5-17", "part": 5, "type": "prepositions", "question": "The final decision rests _____ the steering committee, not the department heads.", "options": ["on", "with", "in", "for"], "answer": 1, "explanation": "'The decision rests with' = quy\u1ebft \u0111\u1ecbnh thu\u1ed9c v\u1ec1 (ai \u0111\u00f3 c\u00f3 th\u1ea9m quy\u1ec1n).", "difficulty": "medium"}, {"id": "c5-18", "part": 5, "type": "prepositions", "question": "Employees are encouraged to voice concerns _____ going through the anonymous feedback portal.", "options": ["from", "with", "by", "about"], "answer": 2, "explanation": "'By + V-ing' = b\u1eb1ng c\u00e1ch. 'By going through the portal' = b\u1eb1ng c\u00e1ch s\u1eed d\u1ee5ng c\u1ed5ng ph\u1ea3n h\u1ed3i.", "difficulty": "medium"}, {"id": "c5-19", "part": 5, "type": "conjunction", "question": "The new safety training is mandatory; _____, online completion is now accepted as an alternative to classroom attendance.", "options": ["however", "therefore", "moreover", "nevertheless"], "answer": 2, "explanation": "'Moreover' = h\u01a1n n\u1eefa, b\u1ed5 sung th\u00eam. Th\u00eam th\u00f4ng tin v\u1ec1 s\u1ef1 linh ho\u1ea1t c\u1ee7a ch\u01b0\u01a1ng tr\u00ecnh b\u1eaft bu\u1ed9c.", "difficulty": "medium"}, {"id": "c5-20", "part": 5, "type": "conjunction", "question": "_____ experienced in project management, Mr. Reeves found the new software system challenging to navigate.", "options": ["Even though", "Despite being", "Although", "While"], "answer": 1, "explanation": "'Despite being + adj' = d\u00f9 d\u00e0y d\u1ea1n kinh nghi\u1ec7m (despite + gerund phrase). C\u00e1c \u0111\u00e1p \u00e1n c\u00f2n l\u1ea1i c\u1ea7n m\u1ec7nh \u0111\u1ec1 (S+V).", "difficulty": "medium"}, {"id": "c5-21", "part": 5, "type": "prepositions", "question": "The product recall was carried out _____ precaution after a small number of units showed defects.", "options": ["with a", "for a", "as a", "by a"], "answer": 2, "explanation": "'As a precaution' = nh\u01b0 m\u1ed9t bi\u1ec7n ph\u00e1p ph\u00f2ng ng\u1eeba (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "c5-22", "part": 5, "type": "conjunction", "question": "The engineering team worked through the weekend _____ the prototype could be ready in time for the client demo.", "options": ["unless", "because", "although", "so that"], "answer": 3, "explanation": "'So that' = \u0111\u1ec3 cho (m\u1ee5c \u0111\u00edch). M\u1ee5c \u0111\u00edch l\u00e0m th\u00eam cu\u1ed1i tu\u1ea7n.", "difficulty": "medium"}, {"id": "c5-23", "part": 5, "type": "prepositions", "question": "The revised guidelines will take effect _____ January 1 of the upcoming fiscal year.", "options": ["on", "as of", "by", "until"], "answer": 1, "explanation": "'As of January 1' = k\u1ec3 t\u1eeb ng\u00e0y 1 th\u00e1ng 1 (th\u1eddi \u0111i\u1ec3m b\u1eaft \u0111\u1ea7u hi\u1ec7u l\u1ef1c). 'On' ch\u1ec9 \u0111\u00fang th\u1eddi \u0111i\u1ec3m c\u1ee5 th\u1ec3, 'as of' nh\u1ea5n m\u1ea1nh kh\u1edfi \u0111\u1ea7u hi\u1ec7u l\u1ef1c.", "difficulty": "medium"}, {"id": "c5-24", "part": 5, "type": "passive", "question": "New staff members _____ a comprehensive orientation session during their first week.", "options": ["give", "giving", "are given", "have giving"], "answer": 2, "explanation": "B\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n 'are given'. Nh\u00e2n vi\u00ean \u0111\u01b0\u1ee3c c\u1ea5p ph\u00e1t/tham d\u1ef1 (orientation = t\u00e2n ng\u1eef gi\u00e1n ti\u1ebfp).", "difficulty": "medium"}, {"id": "c5-25", "part": 5, "type": "passive", "question": "All meeting minutes _____ and distributed to participants within 24 hours of the session.", "options": ["will compile", "have compiled", "are compiling", "will be compiled"], "answer": 3, "explanation": "B\u1ecb \u0111\u1ed9ng t\u01b0\u01a1ng lai 'will be compiled'. Bi\u00ean b\u1ea3n \u0111\u01b0\u1ee3c t\u1ed5ng h\u1ee3p v\u00e0 ph\u00e2n ph\u00e1t.", "difficulty": "medium"}, {"id": "c5-26", "part": 5, "type": "vocabulary", "question": "The finance director asked staff to _____ unnecessary expenses in light of the budget shortfall.", "options": ["reduce", "eliminate", "curtail", "minimize"], "answer": 2, "explanation": "'Curtail unnecessary expenses' = c\u1eaft gi\u1ea3m chi ph\u00ed kh\u00f4ng c\u1ea7n thi\u1ebft (formal, ph\u1ed5 bi\u1ebfn trong TOEIC financial context).", "difficulty": "medium"}, {"id": "c5-27", "part": 5, "type": "vocabulary", "question": "The partnership agreement was _____ after both parties failed to reach a compromise.", "options": ["terminated", "cancelled", "finished", "stopped"], "answer": 0, "explanation": "'Terminated' = ch\u1ea5m d\u1ee9t h\u1ee3p \u0111\u1ed3ng/th\u1ecfa thu\u1eadn m\u1ed9t c\u00e1ch ch\u00ednh th\u1ee9c. Thu\u1eadt ng\u1eef chu\u1ea9n trong v\u0103n b\u1ea3n ph\u00e1p l\u00fd.", "difficulty": "medium"}, {"id": "c5-28", "part": 5, "type": "vocabulary", "question": "All candidates are _____ to bring two forms of identification to the interview.", "options": ["told", "reminded", "asked", "requested"], "answer": 3, "explanation": "'Requested to bring' = \u0111\u01b0\u1ee3c y\u00eau c\u1ea7u mang theo (formal, ph\u1ed5 bi\u1ebfn trong th\u00f4ng b\u00e1o tuy\u1ec3n d\u1ee5ng).", "difficulty": "medium"}, {"id": "c5-29", "part": 5, "type": "vocabulary", "question": "The engineering team _____ several alternative designs before settling on the final prototype.", "options": ["assessed", "reviewed", "considered", "evaluated"], "answer": 3, "explanation": "'Evaluated alternative designs' = \u0111\u00e1nh gi\u00e1 c\u00e1c ph\u01b0\u01a1ng \u00e1n thay th\u1ebf (k\u1ef9 thu\u1eadt). 'Evaluate' = ph\u00e2n t\u00edch c\u00f3 h\u1ec7 th\u1ed1ng.", "difficulty": "medium"}, {"id": "c5-30", "part": 5, "type": "vocabulary", "question": "The spokesperson _____ that the company remains committed to its zero-emission targets.", "options": ["said", "told", "confirmed", "mentioned"], "answer": 2, "explanation": "'Confirmed that' = x\u00e1c nh\u1eadn r\u1eb1ng. Nh\u1ea5n m\u1ea1nh s\u1ef1 cam k\u1ebft, ch\u00ednh th\u1ee9c h\u01a1n 'said'. 'Told' c\u1ea7n t\u00e2n ng\u1eef ng\u01b0\u1eddi.", "difficulty": "medium"}, {"id": "g5-01", "part": 5, "type": "word-form", "question": "The _____ of the new software platform has been praised for its clean, intuitive interface.", "options": ["design", "designer", "designate", "designedly"], "answer": 0, "explanation": "'The design of the platform' = thi\u1ebft k\u1ebf. Danh t\u1eeb l\u00e0m ch\u1ee7 ng\u1eef sau 'The'.", "difficulty": "medium"}, {"id": "g5-02", "part": 5, "type": "word-form", "question": "All participants are _____ reminded to register at the welcome desk upon arrival.", "options": ["kind", "kindness", "kinder", "kindly"], "answer": 3, "explanation": "Ph\u00f3 t\u1eeb 'kindly' d\u00f9ng trong y\u00eau c\u1ea7u l\u1ecbch s\u1ef1 ('kindly reminded' = k\u00ednh nh\u1edd). B\u1ed5 ngh\u0129a cho 'are reminded'.", "difficulty": "medium"}, {"id": "g5-03", "part": 5, "type": "word-form", "question": "The committee found the auditor's report _____ thorough and above reproach.", "options": ["exceptionally", "except", "exception", "exceptional"], "answer": 0, "explanation": "Ph\u00f3 t\u1eeb 'exceptionally' b\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb 'thorough'.", "difficulty": "medium"}, {"id": "g5-04", "part": 5, "type": "word-form", "question": "A _____ review of the supplier contracts revealed several clauses that required updating.", "options": ["comprehensive", "comprehend", "comprehension", "comprehensively"], "answer": 0, "explanation": "T\u00ednh t\u1eeb 'comprehensive' (to\u00e0n di\u1ec7n) \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'review'.", "difficulty": "hard"}, {"id": "g5-05", "part": 5, "type": "word-form", "question": "The board expressed its full _____ for the CEO's restructuring plan at last week's meeting.", "options": ["supported", "supporting", "supportive", "support"], "answer": 3, "explanation": "'Its full support' = s\u1ef1 \u1ee7ng h\u1ed9 ho\u00e0n to\u00e0n. Danh t\u1eeb sau s\u1edf h\u1eefu 'its full'.", "difficulty": "medium"}, {"id": "g5-06", "part": 5, "type": "word-form", "question": "The _____ of the warehouse makes it ideal for companies requiring large-scale cold storage.", "options": ["spatially", "spacious", "space", "spaciousness"], "answer": 3, "explanation": "Danh t\u1eeb tr\u1eebu t\u01b0\u1ee3ng 'spaciousness' = t\u00ednh r\u1ed9ng l\u1edbn, ph\u00f9 h\u1ee3p sau 'The'.", "difficulty": "medium"}, {"id": "g5-07", "part": 5, "type": "word-form", "question": "Our product packaging is _____ to ensure that it meets the highest environmental standards.", "options": ["certificate", "certify", "certification", "certified"], "answer": 3, "explanation": "T\u00ednh t\u1eeb b\u1ecb \u0111\u1ed9ng 'certified' = \u0111\u01b0\u1ee3c ch\u1ee9ng nh\u1eadn. B\u1ed5 ngh\u0129a qua 'is certified'.", "difficulty": "medium"}, {"id": "g5-08", "part": 5, "type": "word-form", "question": "Staff are encouraged to act _____ when they notice potential safety hazards in the workplace.", "options": ["proactively", "proactive", "proactiveness", "proactivate"], "answer": 0, "explanation": "Ph\u00f3 t\u1eeb 'proactively' b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'act'.", "difficulty": "medium"}, {"id": "g5-09", "part": 5, "type": "verb-tense", "question": "The company _____ its new headquarters in Singapore when the pandemic disrupted the timeline.", "options": ["built", "has built", "was building", "had built"], "answer": 2, "explanation": "H\u00e0nh \u0111\u1ed9ng \u0111ang di\u1ec5n ra khi b\u1ecb gi\u00e1n \u0111o\u1ea1n \u2192 past continuous 'was building'.", "difficulty": "medium"}, {"id": "g5-10", "part": 5, "type": "verb-tense", "question": "By next March, Ms. Wong _____ the accounting department for a full decade.", "options": ["leads", "will have led", "has led", "led"], "answer": 1, "explanation": "'By next March' + kho\u1ea3ng th\u1eddi gian \u2192 future perfect 'will have led'.", "difficulty": "medium"}, {"id": "g5-11", "part": 5, "type": "verb-tense", "question": "The finance team _____ quarterly projections every Monday since the new CFO joined.", "options": ["reviewed", "has been reviewing", "reviews", "had reviewed"], "answer": 1, "explanation": "'Since + past event' v\u1edbi h\u00e0nh \u0111\u1ed9ng c\u00f2n ti\u1ebfp di\u1ec5n \u2192 present perfect continuous.", "difficulty": "medium"}, {"id": "g5-12", "part": 5, "type": "verb-tense", "question": "Once the contract _____, the engineering team can begin the preliminary site assessment.", "options": ["signs", "is signed", "will be signed", "signed"], "answer": 1, "explanation": "M\u1ec7nh \u0111\u1ec1 'once' ch\u1ec9 th\u1eddi gian t\u01b0\u01a1ng lai \u2192 kh\u00f4ng d\u00f9ng 'will'. B\u1ecb \u0111\u1ed9ng 'is signed' = h\u1ee3p \u0111\u1ed3ng \u0111\u01b0\u1ee3c k\u00fd.", "difficulty": "medium"}, {"id": "g5-13", "part": 5, "type": "verb-tense", "question": "The delegates _____ the convention center for over an hour before the keynote speaker arrived.", "options": ["waited", "have waited", "are waiting", "had been waiting"], "answer": 3, "explanation": "H\u00e0nh \u0111\u1ed9ng di\u1ec5n ra li\u00ean t\u1ee5c tr\u01b0\u1edbc m\u1ed9t s\u1ef1 ki\u1ec7n qu\u00e1 kh\u1ee9 \u2192 past perfect continuous.", "difficulty": "medium"}, {"id": "g5-14", "part": 5, "type": "verb-tense", "question": "The new overtime policy _____ effect next Monday, so all managers should inform their teams.", "options": ["takes", "will take", "has taken", "took"], "answer": 1, "explanation": "'Next Monday' ch\u1ec9 t\u01b0\u01a1ng lai \u2192 'will take effect'.", "difficulty": "medium"}, {"id": "g5-15", "part": 5, "type": "verb-tense", "question": "We _____ to the same catering supplier for all corporate events for the past eight years.", "options": ["have turned", "turned", "had turned", "turn"], "answer": 0, "explanation": "\"For the past eight years\" = kho\u1ea3ng th\u1eddi gian k\u00e9o \u0111\u1ebfn hi\u1ec7n t\u1ea1i \u2192 Present Perfect. \"Have turned\" = \u0111\u00e3 chuy\u1ec3n \u0111\u1ed5i.", "difficulty": "medium"}, {"id": "g5-16", "part": 5, "type": "prepositions", "question": "The final report must be submitted _____ the close of business on Friday without exception.", "options": ["until", "by", "before", "at"], "answer": 1, "explanation": "'By Friday' = tr\u01b0\u1edbc ho\u1eb7c v\u00e0o th\u1ee9 S\u00e1u (deadline). 'Until' ch\u1ec9 h\u00e0nh \u0111\u1ed9ng k\u00e9o d\u00e0i \u0111\u1ebfn m\u1ed9t th\u1eddi \u0111i\u1ec3m.", "difficulty": "medium"}, {"id": "g5-17", "part": 5, "type": "prepositions", "question": "Sales figures for the third quarter were _____ par with the same period last year.", "options": ["at", "on", "in", "by"], "answer": 1, "explanation": "'On par with' = ngang b\u1eb1ng v\u1edbi (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "g5-18", "part": 5, "type": "prepositions", "question": "The initiative was launched _____ collaboration with three leading universities.", "options": ["by", "through", "with", "in"], "answer": 3, "explanation": "'In collaboration with' = h\u1ee3p t\u00e1c c\u00f9ng (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "g5-19", "part": 5, "type": "prepositions", "question": "The HR director reminded employees that grievance procedures are outlined _____ detail in the handbook.", "options": ["at", "in", "by", "with"], "answer": 1, "explanation": "'In detail' = m\u1ed9t c\u00e1ch chi ti\u1ebft (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "g5-20", "part": 5, "type": "prepositions", "question": "Requests for time off during peak season are subject _____ manager approval.", "options": ["for", "of", "by", "to"], "answer": 3, "explanation": "'Subject to' = ph\u1ee5 thu\u1ed9c v\u00e0o, ch\u1ecbu s\u1ef1 (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "g5-21", "part": 5, "type": "prepositions", "question": "The two firms agreed to put their differences aside and work _____ a common goal.", "options": ["to", "onto", "for", "toward"], "answer": 3, "explanation": "'Work toward a goal' = n\u1ed7 l\u1ef1c h\u01b0\u1edbng \u0111\u1ebfn m\u1ee5c ti\u00eau (toward = h\u01b0\u1edbng t\u1edbi).", "difficulty": "medium"}, {"id": "g5-22", "part": 5, "type": "conjunction", "question": "_____ the quarterly results were disappointing, the board chose not to revise the annual forecast.", "options": ["Due to", "Despite", "Whereas", "Even though"], "answer": 3, "explanation": "'Even though' + m\u1ec7nh \u0111\u1ec1 (S+V) = m\u1eb7c d\u00f9. 'Despite' c\u1ea7n danh t\u1eeb/gerund ph\u00eda sau.", "difficulty": "medium"}, {"id": "g5-23", "part": 5, "type": "conjunction", "question": "The venue has been booked; _____, the catering arrangements still need to be finalized.", "options": ["nonetheless", "as a result", "moreover", "besides"], "answer": 2, "explanation": "'Moreover' = h\u01a1n n\u1eefa, th\u00eam v\u00e0o \u0111\u00f3. B\u1ed5 sung th\u00f4ng tin c\u00f2n thi\u1ebfu (catering ch\u01b0a xong).", "difficulty": "medium"}, {"id": "g5-24", "part": 5, "type": "conjunction", "question": "Employees may work from home on Fridays _____ their productivity targets are consistently met.", "options": ["unless", "even if", "provided that", "in case"], "answer": 2, "explanation": "'Provided that' = mi\u1ec5n l\u00e0, v\u1edbi \u0111i\u1ec1u ki\u1ec7n l\u00e0. \u0110i\u1ec1u ki\u1ec7n \u0111\u1ec3 \u0111\u01b0\u1ee3c l\u00e0m vi\u1ec7c t\u1ea1i nh\u00e0.", "difficulty": "medium"}, {"id": "g5-25", "part": 5, "type": "conjunction", "question": "The marketing team revised the campaign _____ the initial data showed lower-than-expected click rates.", "options": ["so that", "since", "although", "after"], "answer": 1, "explanation": "'Since' = v\u00ec (nguy\u00ean nh\u00e2n). D\u1eef li\u1ec7u th\u1ea5p \u2192 l\u00fd do \u0111\u1ec3 s\u1eeda chi\u1ebfn d\u1ecbch.", "difficulty": "medium"}, {"id": "g5-26", "part": 5, "type": "conjunction", "question": "The presentation was delayed _____ the projector malfunctioned just before the session began.", "options": ["because of", "when", "although", "due to"], "answer": 1, "explanation": "'When' = khi (ch\u1ec9 th\u1eddi \u0111i\u1ec3m h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra). M\u00e1y chi\u1ebfu h\u1ecfng v\u00e0o \u0111\u00fang l\u00fac bu\u1ed5i s\u1eafp b\u1eaft \u0111\u1ea7u.", "difficulty": "medium"}, {"id": "g5-27", "part": 5, "type": "vocabulary", "question": "The company has decided to _____ its unprofitable regional branches to cut costs.", "options": ["consolidate", "advertise", "motivate", "decorate"], "answer": 0, "explanation": "'Consolidate branches' = s\u00e1p nh\u1eadp chi nh\u00e1nh \u0111\u1ec3 ti\u1ebft ki\u1ec7m. C\u00e1c \u0111\u1ed9ng t\u1eeb kh\u00e1c kh\u00f4ng li\u00ean quan \u0111\u1ebfn vi\u1ec7c c\u1eaft gi\u1ea3m chi ph\u00ed.", "difficulty": "medium"}, {"id": "g5-28", "part": 5, "type": "vocabulary", "question": "The training program was _____ to address the specific technical skill gaps identified in the performance review.", "options": ["rejected", "tailored", "borrowed", "exported"], "answer": 1, "explanation": "'Tailored to' = \u0111\u01b0\u1ee3c thi\u1ebft k\u1ebf ri\u00eang cho. Ph\u00f9 h\u1ee3p nh\u1ea5t khi n\u00f3i v\u1ec1 ch\u01b0\u01a1ng tr\u00ecnh \u0111\u00e0o t\u1ea1o gi\u1ea3i quy\u1ebft h\u1ed5ng k\u1ef9 n\u0103ng.", "difficulty": "medium"}, {"id": "g5-29", "part": 5, "type": "vocabulary", "question": "The committee will _____ proposals from all departments before making its final recommendation.", "options": ["compete", "postpone", "solicit", "celebrate"], "answer": 2, "explanation": "'Solicit proposals' = k\u00eau g\u1ecdi \u0111\u1ec1 xu\u1ea5t. 'Postpone' hay 'Celebrate' kh\u00f4ng \u0111i v\u1edbi 'proposals' trong ng\u1eef c\u1ea3nh n\u00e0y.", "difficulty": "medium"}, {"id": "g5-30", "part": 5, "type": "vocabulary", "question": "To _____ compliance with the new data regulations, all departments must submit an updated privacy policy by month-end.", "options": ["ensure", "assure", "secure", "guarantee"], "answer": 0, "explanation": "'Ensure compliance' = \u0111\u1ea3m b\u1ea3o tu\u00e2n th\u1ee7. 'Ensure' d\u00f9ng v\u1edbi h\u00e0nh \u0111\u1ed9ng/tr\u1ea1ng th\u00e1i, kh\u00f4ng c\u1ea7n t\u00e2n ng\u1eef ng\u01b0\u1eddi.", "difficulty": "easy"}, {"id": "h5-01", "part": 5, "type": "word-form", "question": "The _____ of the merger agreement is expected to take several more months due to regulatory reviews.", "options": ["finalize", "finally", "finalization", "finalizing"], "answer": 2, "explanation": "Sau 'The' c\u1ea7n danh t\u1eeb ch\u1ee7 ng\u1eef. 'Finalization' = s\u1ef1 ho\u00e0n thi\u1ec7n/k\u00fd k\u1ebft cu\u1ed1i c\u00f9ng.", "difficulty": "medium"}, {"id": "h5-02", "part": 5, "type": "word-form", "question": "The director spoke _____ about the company's performance at the shareholder meeting.", "options": ["candid", "candidacy", "candidness", "candidly"], "answer": 3, "explanation": "Ph\u00f3 t\u1eeb 'candidly' (m\u1ed9t c\u00e1ch th\u1eb3ng th\u1eafn) b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'spoke'.", "difficulty": "medium"}, {"id": "h5-03", "part": 5, "type": "word-form", "question": "All visitors must wear _____ safety equipment when entering the construction zone.", "options": ["appropriated", "appropriately", "appropriateness", "appropriate"], "answer": 3, "explanation": "T\u00ednh t\u1eeb 'appropriate' (ph\u00f9 h\u1ee3p) \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'safety equipment'.", "difficulty": "medium"}, {"id": "h5-04", "part": 5, "type": "word-form", "question": "The sales team showed great _____ in closing three major deals within a single quarter.", "options": ["persist", "persistent", "persistence", "persistently"], "answer": 2, "explanation": "Sau 'great' c\u1ea7n danh t\u1eeb t\u00e2n ng\u1eef. 'Persistence' = s\u1ef1 ki\u00ean tr\u00ec.", "difficulty": "medium"}, {"id": "h5-05", "part": 5, "type": "word-form", "question": "The seminar was _____ attended, with over 400 professionals registering in advance.", "options": ["good", "well", "better", "best"], "answer": 1, "explanation": "'Well-attended' = c\u00f3 \u0111\u00f4ng ng\u01b0\u1eddi tham d\u1ef1. Ph\u00f3 t\u1eeb 'well' k\u1ebft h\u1ee3p v\u1edbi participle 'attended'.", "difficulty": "medium"}, {"id": "h5-06", "part": 5, "type": "word-form", "question": "Ms. Kim was _____ selected as the keynote speaker for the annual leadership summit.", "options": ["unanimously", "unanimous", "unanimity", "unanimousness"], "answer": 0, "explanation": "Ph\u00f3 t\u1eeb 'unanimously' (\u0111\u01b0\u1ee3c ch\u1ecdn nh\u1ea5t tr\u00ed) b\u1ed5 ngh\u0129a cho 'was selected'.", "difficulty": "medium"}, {"id": "h5-07", "part": 5, "type": "word-form", "question": "The _____ of the safety audit revealed several areas requiring immediate attention.", "options": ["findings", "find", "found", "finder"], "answer": 0, "explanation": "'The findings of the audit' = k\u1ebft qu\u1ea3/ph\u00e1t hi\u1ec7n c\u1ee7a cu\u1ed9c ki\u1ec3m tra. Danh t\u1eeb s\u1ed1 nhi\u1ec1u l\u00e0m ch\u1ee7 ng\u1eef.", "difficulty": "medium"}, {"id": "h5-08", "part": 5, "type": "word-form", "question": "Customers who are _____ with their purchase may return the item within 30 days for a full refund.", "options": ["satisfy", "satisfaction", "satisfactorily", "dissatisfied"], "answer": 3, "explanation": "T\u00ednh t\u1eeb 'dissatisfied' (kh\u00f4ng h\u00e0i l\u00f2ng) ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh c\u00e2u \u2014 kh\u00e1ch h\u00e0ng kh\u00f4ng h\u00e0i l\u00f2ng th\u00ec tr\u1ea3 h\u00e0ng.", "difficulty": "medium"}, {"id": "h5-09", "part": 5, "type": "verb-tense", "question": "The branch office in Toronto _____ operations for over twenty years when it finally closed.", "options": ["conducted", "has conducted", "is conducting", "had been conducting"], "answer": 3, "explanation": "H\u00e0nh \u0111\u1ed9ng di\u1ec5n ra li\u00ean t\u1ee5c tr\u01b0\u1edbc m\u1ed9t s\u1ef1 ki\u1ec7n qu\u00e1 kh\u1ee9 \u2192 past perfect continuous 'had been conducting'.", "difficulty": "medium"}, {"id": "h5-10", "part": 5, "type": "verb-tense", "question": "Sales projections indicate that the new product line _____ strong demand throughout the holiday season.", "options": ["attracts", "will attract", "attracted", "has attracted"], "answer": 1, "explanation": "D\u1ef1 b\u00e1o t\u01b0\u01a1ng lai (projections indicate) \u2192 'will attract'.", "difficulty": "medium"}, {"id": "h5-11", "part": 5, "type": "verb-tense", "question": "The HR manager _____ all applications before the interview panel meets next Monday.", "options": ["reviews", "reviewed", "will have reviewed", "has reviewed"], "answer": 2, "explanation": "'Before the interview panel meets' = tr\u01b0\u1edbc khi h\u1ed9i \u0111\u1ed3ng h\u1ecdp v\u00e0o th\u1ee9 Hai \u2192 future perfect 'will have reviewed'.", "difficulty": "medium"}, {"id": "h5-12", "part": 5, "type": "verb-tense", "question": "The procurement team _____ with three suppliers simultaneously when the budget freeze was announced.", "options": ["was negotiating", "negotiated", "had negotiated", "negotiates"], "answer": 0, "explanation": "H\u00e0nh \u0111\u1ed9ng \u0111ang di\u1ec5n ra b\u1ecb gi\u00e1n \u0111o\u1ea1n b\u1edfi 'was announced' \u2192 past continuous 'was negotiating'.", "difficulty": "medium"}, {"id": "h5-13", "part": 5, "type": "verb-tense", "question": "The company _____ its social media engagement significantly since hiring a dedicated content strategist.", "options": ["has improved", "improved", "improves", "will improve"], "answer": 0, "explanation": "'Since + past event' v\u00e0 k\u1ebft qu\u1ea3 c\u00f2n \u1ea3nh h\u01b0\u1edfng \u0111\u1ebfn hi\u1ec7n t\u1ea1i \u2192 present perfect 'has improved'.", "difficulty": "medium"}, {"id": "h5-14", "part": 5, "type": "verb-tense", "question": "Provided the client _____ the revised specifications by Friday, production can start on Monday.", "options": ["has approved", "will approve", "approved", "approves"], "answer": 3, "explanation": "M\u1ec7nh \u0111\u1ec1 'Provided' (\u0111i\u1ec1u ki\u1ec7n) kh\u00f4ng d\u00f9ng 'will' \u2192 hi\u1ec7n t\u1ea1i \u0111\u01a1n 'approves'.", "difficulty": "medium"}, {"id": "h5-15", "part": 5, "type": "prepositions", "question": "The proposal was put forward _____ behalf of the entire research committee.", "options": ["in", "on", "at", "for"], "answer": 1, "explanation": "'On behalf of' = thay m\u1eb7t cho (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "h5-16", "part": 5, "type": "prepositions", "question": "The new safety procedures are _____ accordance with the updated ISO standards.", "options": ["on", "by", "for", "in"], "answer": 3, "explanation": "'In accordance with' = ph\u00f9 h\u1ee3p v\u1edbi, theo \u0111\u00fang (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "h5-17", "part": 5, "type": "prepositions", "question": "Applications submitted _____ time will be reviewed in the order they are received.", "options": ["at", "in", "on", "by"], "answer": 2, "explanation": "'On time' = \u0111\u00fang h\u1ea1n (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh). Kh\u00f4ng nh\u1ea7m v\u1edbi 'in time' = k\u1ecbp gi\u1edd.", "difficulty": "easy"}, {"id": "h5-18", "part": 5, "type": "prepositions", "question": "The research team worked _____ the clock to meet the publication deadline.", "options": ["around", "by", "on", "with"], "answer": 0, "explanation": "'Work around the clock' = l\u00e0m vi\u1ec7c su\u1ed1t ng\u00e0y \u0111\u00eam (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "h5-19", "part": 5, "type": "prepositions", "question": "The two departments collaborate closely _____ a daily basis to streamline workflows.", "options": ["in", "at", "on", "by"], "answer": 2, "explanation": "'On a daily basis' = h\u00e0ng ng\u00e0y, theo c\u01a1 s\u1edf h\u00e0ng ng\u00e0y (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "h5-20", "part": 5, "type": "conjunction", "question": "The marketing campaign received positive feedback; _____, actual conversion rates remained below target.", "options": ["nonetheless", "moreover", "therefore", "similarly"], "answer": 0, "explanation": "'Nonetheless' = tuy nhi\u00ean, d\u00f9 v\u1eady. T\u01b0\u01a1ng ph\u1ea3n gi\u1eefa feedback t\u1ed1t nh\u01b0ng k\u1ebft qu\u1ea3 chuy\u1ec3n \u0111\u1ed5i th\u1ea5p.", "difficulty": "medium"}, {"id": "h5-21", "part": 5, "type": "conjunction", "question": "_____ the shipment arrives before noon, the warehouse team can process it the same day.", "options": ["As long as", "Even though", "Unless", "Whereas"], "answer": 0, "explanation": "'As long as' = mi\u1ec5n l\u00e0. \u0110i\u1ec1u ki\u1ec7n \u0111\u1ec3 warehouse team x\u1eed l\u00fd c\u00f9ng ng\u00e0y.", "difficulty": "medium"}, {"id": "h5-22", "part": 5, "type": "conjunction", "question": "The new branch will be profitable within two years _____ market conditions remain stable.", "options": ["assuming", "despite", "although", "in spite of"], "answer": 0, "explanation": "'Assuming (that)' = gi\u1ea3 s\u1eed r\u1eb1ng, v\u1edbi \u0111i\u1ec1u ki\u1ec7n l\u00e0. \u0110i\u1ec1u ki\u1ec7n t\u01b0\u01a1ng lai.", "difficulty": "medium"}, {"id": "h5-23", "part": 5, "type": "conjunction", "question": "Management introduced the flexible hours policy _____ reduce commuting stress for staff.", "options": ["so that", "in order to", "because", "for"], "answer": 1, "explanation": "'In order to + V' = \u0111\u1ec3, nh\u1eb1m m\u1ee5c \u0111\u00edch. \u0110\u1ee9ng tr\u01b0\u1edbc \u0111\u1ed9ng t\u1eeb nguy\u00ean th\u1ec3.", "difficulty": "medium"}, {"id": "h5-24", "part": 5, "type": "conjunction", "question": "The board approved the expansion plan; _____, certain conditions must be met before funds are released.", "options": ["as a result", "otherwise", "furthermore", "however"], "answer": 3, "explanation": "'However' = tuy nhi\u00ean. B\u1ed5 sung \u0111i\u1ec1u ki\u1ec7n m\u1eb7c d\u00f9 k\u1ebf ho\u1ea1ch \u0111\u00e3 \u0111\u01b0\u1ee3c ph\u00ea duy\u1ec7t.", "difficulty": "medium"}, {"id": "h5-25", "part": 5, "type": "passive", "question": "The confidential documents _____ access to only during scheduled audit sessions.", "options": ["are granted", "grant", "have granted", "were granting"], "answer": 0, "explanation": "B\u1ecb \u0111\u1ed9ng 'are granted access to' = \u0111\u01b0\u1ee3c ph\u00e9p truy c\u1eadp. T\u00e0i li\u1ec7u nh\u1eadn t\u00e1c \u0111\u1ed9ng t\u1eeb ng\u01b0\u1eddi qu\u1ea3n l\u00fd.", "difficulty": "medium"}, {"id": "h5-26", "part": 5, "type": "passive", "question": "All incoming parcels _____ by the security team before being distributed to recipients.", "options": ["screening", "are screened", "screen", "have screening"], "answer": 1, "explanation": "B\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n 'are screened' = \u0111\u01b0\u1ee3c ki\u1ec3m tra (quy tr\u00ecnh th\u01b0\u1eddng xuy\u00ean).", "difficulty": "medium"}, {"id": "h5-27", "part": 5, "type": "passive", "question": "The annual performance awards ceremony _____ at the Grand Pavilion Hotel next month.", "options": ["will hold", "is holding", "will be held", "has been holding"], "answer": 2, "explanation": "B\u1ecb \u0111\u1ed9ng t\u01b0\u01a1ng lai 'will be held' = s\u1ebd \u0111\u01b0\u1ee3c t\u1ed5 ch\u1ee9c. Bu\u1ed5i l\u1ec5 nh\u1eadn t\u00e1c \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "h5-28", "part": 5, "type": "vocabulary", "question": "The firm decided to _____ the launch of its flagship product until supply chain issues were resolved.", "options": ["retrieve", "abandon", "postpone", "install"], "answer": 2, "explanation": "'Postpone the launch' = ho\u00e3n ng\u00e0y ra m\u1eaft. 'Abandon' (t\u1eeb b\u1ecf) hay 'Install' (c\u00e0i \u0111\u1eb7t) kh\u00f4ng ph\u00f9 h\u1ee3p v\u1edbi tr\u1ea1ng th\u00e1i 'until resolved'.", "difficulty": "easy"}, {"id": "h5-29", "part": 5, "type": "vocabulary", "question": "The CFO presented a _____ plan showing how the company could return to profitability within 18 months.", "options": ["confidential", "expensive", "temporary", "feasible"], "answer": 3, "explanation": "'Feasible plan' = k\u1ebf ho\u1ea1ch kh\u1ea3 thi. C\u00e1c t\u1eeb c\u00f2n l\u1ea1i kh\u00f4ng \u0111i k\u00e8m v\u1edbi 'plan' \u0111\u1ec3 t\u1ea1o ngh\u0129a ph\u00f9 h\u1ee3p trong b\u00e1o c\u00e1o CFO.", "difficulty": "medium"}, {"id": "h5-30", "part": 5, "type": "vocabulary", "question": "The company is committed to _____ its carbon footprint by 50% before the end of the decade.", "options": ["expanding", "reducing", "ignoring", "recalling"], "answer": 1, "explanation": "'Reducing carbon footprint' l\u00e0 c\u1ee5m c\u1ed1 \u0111\u1ecbnh. 'Expanding' (m\u1edf r\u1ed9ng) hay 'Ignoring' (ph\u1edbt l\u1edd) sai h\u01b0\u1edbng cam k\u1ebft m\u00f4i tr\u01b0\u1eddng.", "difficulty": "medium"}, {"id": "e5-1", "part": 5, "type": "word-form", "question": "The _____ of the contract requires both parties to sign before January.", "options": ["finalize", "finalization", "finalizing", "finalized"], "answer": 1, "explanation": "Sau m\u1ea1o t\u1eeb 'The' c\u1ea7n danh t\u1eeb. 'Finalization' = s\u1ef1 ho\u00e0n t\u1ea5t.", "difficulty": "medium"}, {"id": "e5-2", "part": 5, "type": "word-form", "question": "Customer feedback was _____ positive about the new service.", "options": ["overwhelm", "overwhelming", "overwhelmed", "overwhelmingly"], "answer": 3, "explanation": "Ph\u00f3 t\u1eeb 'overwhelmingly' b\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb 'positive'.", "difficulty": "easy"}, {"id": "e5-3", "part": 5, "type": "word-form", "question": "The company's _____ growth exceeded all expectations last quarter.", "options": ["remark", "remarked", "remarkably", "remarkable"], "answer": 3, "explanation": "T\u00ednh t\u1eeb 'remarkable' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'growth'.", "difficulty": "medium"}, {"id": "e5-4", "part": 5, "type": "word-form", "question": "All applicants must provide _____ of their educational qualifications.", "options": ["proof", "prove", "proven", "provable"], "answer": 0, "explanation": "Sau 'provide' c\u1ea7n t\u00e2n ng\u1eef (danh t\u1eeb). 'Proof' = b\u1eb1ng ch\u1ee9ng.", "difficulty": "medium"}, {"id": "e5-5", "part": 5, "type": "word-form", "question": "The marketing director gave a very _____ presentation at the annual meeting.", "options": ["persuade", "persuasion", "persuasive", "persuasively"], "answer": 2, "explanation": "T\u00ednh t\u1eeb 'persuasive' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'presentation'.", "difficulty": "medium"}, {"id": "e5-6", "part": 5, "type": "word-form", "question": "The _____ between the two departments has improved communication significantly.", "options": ["collaborate", "collaborative", "collaboration", "collaboratively"], "answer": 2, "explanation": "Sau m\u1ea1o t\u1eeb 'The' c\u1ea7n danh t\u1eeb. 'Collaboration' = s\u1ef1 h\u1ee3p t\u00e1c.", "difficulty": "medium"}, {"id": "e5-7", "part": 5, "type": "word-form", "question": "Participants are _____ encouraged to submit their registration before the deadline.", "options": ["strongly", "strength", "strong", "strengthen"], "answer": 0, "explanation": "Ph\u00f3 t\u1eeb 'strongly' b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'encouraged'.", "difficulty": "medium"}, {"id": "e5-8", "part": 5, "type": "word-form", "question": "The new regulation aims to ensure _____ working conditions for all employees.", "options": ["safeguard", "safely", "safety", "safe"], "answer": 3, "explanation": "T\u00ednh t\u1eeb 'safe' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'working conditions'.", "difficulty": "medium"}, {"id": "e5-9", "part": 5, "type": "word-form", "question": "The company has made _____ investments in renewable energy this year.", "options": ["substance", "substantial", "substantially", "substantiate"], "answer": 1, "explanation": "T\u00ednh t\u1eeb 'substantial' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'investments'.", "difficulty": "medium"}, {"id": "e5-10", "part": 5, "type": "word-form", "question": "The executive board reviewed the _____ report before making a decision.", "options": ["finance", "financial", "financially", "financing"], "answer": 1, "explanation": "T\u00ednh t\u1eeb 'financial' \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'report'.", "difficulty": "medium"}, {"id": "e5-11", "part": 5, "type": "verb-tense", "question": "The project team _____ on the proposal since early January.", "options": ["works", "worked", "will work", "has been working"], "answer": 3, "explanation": "'Since early January' \u2192 hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh ti\u1ebfp di\u1ec5n 'has been working'.", "difficulty": "easy"}, {"id": "e5-12", "part": 5, "type": "verb-tense", "question": "Before the meeting started, the director already _____ the agenda.", "options": ["reviews", "had reviewed", "has reviewed", "reviewed"], "answer": 1, "explanation": "H\u00e0nh \u0111\u1ed9ng x\u1ea3y ra tr\u01b0\u1edbc m\u1ed9t h\u00e0nh \u0111\u1ed9ng qu\u00e1 kh\u1ee9 kh\u00e1c \u2192 qu\u00e1 kh\u1ee9 ho\u00e0n th\u00e0nh 'had reviewed'.", "difficulty": "medium"}, {"id": "e5-13", "part": 5, "type": "verb-tense", "question": "The workshop _____ every Wednesday at 2:00 p.m. in Conference Room B.", "options": ["will hold", "holds", "was held", "is held"], "answer": 3, "explanation": "L\u1ecbch tr\u00ecnh c\u1ed1 \u0111\u1ecbnh, l\u1eb7p l\u1ea1i \u2192 b\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n 'is held'.", "difficulty": "medium"}, {"id": "e5-14", "part": 5, "type": "verb-tense", "question": "Ms. Tanaka _____ the Tokyo office before she was transferred to Seoul.", "options": ["manages", "managed", "has managed", "had managed"], "answer": 3, "explanation": "H\u00e0nh \u0111\u1ed9ng tr\u01b0\u1edbc 'was transferred' \u2192 qu\u00e1 kh\u1ee9 ho\u00e0n th\u00e0nh 'had managed'.", "difficulty": "medium"}, {"id": "e5-15", "part": 5, "type": "verb-tense", "question": "The construction crew _____ the building by the time tenants move in.", "options": ["will complete", "completes", "has completed", "will have completed"], "answer": 3, "explanation": "\"By the time + Present Simple\" = m\u1ec7nh \u0111\u1ec1 th\u1eddi gian \u2192 m\u1ec7nh \u0111\u1ec1 ch\u00ednh d\u00f9ng Future Perfect. \"Will have completed\" = s\u1ebd \u0111\u00e3 ho\u00e0n th\u00e0nh tr\u01b0\u1edbc th\u1eddi \u0111i\u1ec3m \u0111\u00f3.", "difficulty": "hard"}, {"id": "e5-16", "part": 5, "type": "verb-tense", "question": "Revenue _____ by 15 percent if the marketing plan is approved.", "options": ["will increase", "increased", "increases", "has increased"], "answer": 0, "explanation": "C\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1: if + present \u2192 will + V. 'Will increase'.", "difficulty": "medium"}, {"id": "e5-17", "part": 5, "type": "verb-tense", "question": "Mr. Lee _____ as a consultant for our firm for the past decade.", "options": ["serves", "has served", "served", "will serve"], "answer": 1, "explanation": "'For the past decade' \u2192 hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh 'has served'.", "difficulty": "medium"}, {"id": "e5-18", "part": 5, "type": "verb-tense", "question": "The shipment _____ yesterday afternoon according to the tracking system.", "options": ["arrives", "arrived", "has arrived", "will arrive"], "answer": 1, "explanation": "'Yesterday afternoon' \u2192 qu\u00e1 kh\u1ee9 \u0111\u01a1n 'arrived'.", "difficulty": "easy"}, {"id": "e5-19", "part": 5, "type": "prepositions", "question": "The company specializes _____ developing software for the healthcare industry.", "options": ["at", "on", "with", "in"], "answer": 3, "explanation": "'Specialize in' = chuy\u00ean v\u1ec1 (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "e5-20", "part": 5, "type": "prepositions", "question": "All complaints should be addressed _____ the department supervisor.", "options": ["to", "for", "at", "by"], "answer": 0, "explanation": "'Be addressed to' = g\u1eedi \u0111\u1ebfn (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "e5-21", "part": 5, "type": "prepositions", "question": "The event was postponed _____ next Thursday due to the storm.", "options": ["on", "at", "until", "by"], "answer": 2, "explanation": "'Postpone until' = ho\u00e3n cho \u0111\u1ebfn. 'Until' ch\u1ec9 th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai.", "difficulty": "medium"}, {"id": "e5-22", "part": 5, "type": "prepositions", "question": "The intern reports directly _____ the marketing manager.", "options": ["for", "at", "to", "with"], "answer": 2, "explanation": "'Report to someone' = b\u00e1o c\u00e1o v\u1edbi ai (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "e5-23", "part": 5, "type": "prepositions", "question": "Our new product line is aimed _____ young professionals aged 25-35.", "options": ["at", "to", "for", "on"], "answer": 0, "explanation": "'Aimed at' = nh\u1eafm v\u00e0o (c\u1ee5m c\u1ed1 \u0111\u1ecbnh). 'Aimed at young professionals'.", "difficulty": "medium"}, {"id": "e5-24", "part": 5, "type": "prepositions", "question": "The contract must be signed _____ advance of the project start date.", "options": ["in", "on", "at", "by"], "answer": 0, "explanation": "'In advance of' = tr\u01b0\u1edbc (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "e5-25", "part": 5, "type": "conjunction", "question": "_____ the budget was limited, the team managed to deliver an impressive result.", "options": ["Even though", "Because", "Since", "So that"], "answer": 0, "explanation": "'Even though' = m\u1eb7c d\u00f9. C\u00e2u t\u01b0\u01a1ng ph\u1ea3n: budget limited nh\u01b0ng k\u1ebft qu\u1ea3 t\u1ed1t.", "difficulty": "medium"}, {"id": "e5-26", "part": 5, "type": "conjunction", "question": "The new policy will take effect _____ all employees have been notified.", "options": ["unless", "once", "although", "while"], "answer": 1, "explanation": "'Once' = m\u1ed9t khi, ngay khi. Ch\u00ednh s\u00e1ch c\u00f3 hi\u1ec7u l\u1ef1c khi t\u1ea5t c\u1ea3 \u0111\u01b0\u1ee3c th\u00f4ng b\u00e1o.", "difficulty": "medium"}, {"id": "e5-27", "part": 5, "type": "conjunction", "question": "_____ the weather conditions improve, the outdoor event will be held indoors.", "options": ["If", "Because", "Although", "Unless"], "answer": 3, "explanation": "'Unless' = tr\u1eeb khi. N\u1ebfu th\u1eddi ti\u1ebft kh\u00f4ng c\u1ea3i thi\u1ec7n \u2192 t\u1ed5 ch\u1ee9c trong nh\u00e0.", "difficulty": "medium"}, {"id": "e5-28", "part": 5, "type": "conjunction", "question": "Mr. Cho accepted the position _____ the salary was lower than expected.", "options": ["so that", "even though", "in order to", "as a result"], "answer": 1, "explanation": "'Even though' = m\u1eb7c d\u00f9. Nh\u1eadn vi\u1ec7c d\u00f9 l\u01b0\u01a1ng th\u1ea5p h\u01a1n k\u1ef3 v\u1ecdng.", "difficulty": "medium"}, {"id": "e5-29", "part": 5, "type": "conjunction", "question": "The factory will remain operational _____ the safety inspection is completed.", "options": ["until", "while", "so", "since"], "answer": 0, "explanation": "'Until' = cho \u0111\u1ebfn khi. Nh\u00e0 m\u00e1y ho\u1ea1t \u0111\u1ed9ng cho \u0111\u1ebfn khi ki\u1ec3m tra xong.", "difficulty": "medium"}, {"id": "e5-30", "part": 5, "type": "conjunction", "question": "We need to increase production; _____, we must hire additional workers.", "options": ["consequently", "furthermore", "however", "otherwise"], "answer": 0, "explanation": "'Consequently' = do \u0111\u00f3. C\u00e2u sau l\u00e0 h\u1ec7 qu\u1ea3 logic c\u1ee7a c\u00e2u tr\u01b0\u1edbc.", "difficulty": "medium"}, {"id": "e5-31", "part": 5, "type": "passive", "question": "The annual conference _____ in Singapore this year.", "options": ["is being held", "has held", "holding", "have held"], "answer": 0, "explanation": "B\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i ti\u1ebfp di\u1ec5n 'is being held' = \u0111ang \u0111\u01b0\u1ee3c t\u1ed5 ch\u1ee9c.", "difficulty": "easy"}, {"id": "e5-32", "part": 5, "type": "passive", "question": "The invoice _____ to your email address within three business days.", "options": ["will send", "will be sent", "sends", "is sending"], "answer": 1, "explanation": "B\u1ecb \u0111\u1ed9ng t\u01b0\u01a1ng lai 'will be sent'. H\u00f3a \u0111\u01a1n \u0111\u01b0\u1ee3c g\u1eedi (nh\u1eadn t\u00e1c \u0111\u1ed9ng).", "difficulty": "medium"}, {"id": "e5-33", "part": 5, "type": "passive", "question": "Employees who violate the dress code _____ a formal warning.", "options": ["will give", "are giving", "will be given", "have giving"], "answer": 2, "explanation": "B\u1ecb \u0111\u1ed9ng 'will be given'. Nh\u00e2n vi\u00ean \u0111\u01b0\u1ee3c \u0111\u01b0a c\u1ea3nh c\u00e1o ch\u00ednh th\u1ee9c.", "difficulty": "medium"}, {"id": "e5-34", "part": 5, "type": "passive", "question": "The damaged goods _____ and refunded within 14 days of return.", "options": ["will inspect", "have inspect", "inspecting", "will be inspected"], "answer": 3, "explanation": "B\u1ecb \u0111\u1ed9ng t\u01b0\u01a1ng lai 'will be inspected'. H\u00e0ng h\u00f3a \u0111\u01b0\u1ee3c ki\u1ec3m tra.", "difficulty": "medium"}, {"id": "e5-35", "part": 5, "type": "pronoun", "question": "_____ attending the seminar should register at the front desk upon arrival.", "options": ["Their", "These", "They", "Those"], "answer": 3, "explanation": "'Those attending' = nh\u1eefng ai tham d\u1ef1 (\u0111\u1ea1i t\u1eeb ch\u1ec9 \u0111\u1ecbnh + ph\u00e2n t\u1eeb).", "difficulty": "medium"}, {"id": "e5-36", "part": 5, "type": "pronoun", "question": "The supervisor asked the team members to introduce _____.", "options": ["them", "themselves", "they", "their"], "answer": 1, "explanation": "\u0110\u1ea1i t\u1eeb ph\u1ea3n th\u00e2n 'themselves'. Ch\u1ee7 ng\u1eef v\u00e0 t\u00e2n ng\u1eef tr\u00f9ng nhau.", "difficulty": "easy"}, {"id": "e5-37", "part": 5, "type": "pronoun", "question": "_____ of the proposals submitted met the selection criteria.", "options": ["No", "None", "Not", "Neither"], "answer": 1, "explanation": "'None of the proposals' = kh\u00f4ng c\u00f3 \u0111\u1ec1 xu\u1ea5t n\u00e0o. 'None of + danh t\u1eeb'.", "difficulty": "medium"}, {"id": "e5-38", "part": 5, "type": "pronoun", "question": "The two applicants both have relevant experience, but _____ has the required certification.", "options": ["neither", "either", "both", "each"], "answer": 0, "explanation": "'Neither' = c\u1ea3 hai \u0111\u1ec1u kh\u00f4ng. C\u1ea3 hai c\u00f3 kinh nghi\u1ec7m nh\u01b0ng kh\u00f4ng ai c\u00f3 ch\u1ee9ng ch\u1ec9.", "difficulty": "medium"}, {"id": "e5-39", "part": 5, "type": "vocabulary", "question": "The company will _____ a press conference to announce the merger.", "options": ["hold", "have", "make", "do"], "answer": 0, "explanation": "'Hold a press conference' = t\u1ed5 ch\u1ee9c h\u1ecdp b\u00e1o (collocation c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "e5-40", "part": 5, "type": "vocabulary", "question": "The manager asked staff to _____ to the new working hours.", "options": ["stick", "adhere", "follow", "obey"], "answer": 1, "explanation": "'Adhere to' = tu\u00e2n th\u1ee7 (trang tr\u1ecdng, ph\u1ed5 bi\u1ebfn trong v\u0103n b\u1ea3n TOEIC).", "difficulty": "easy"}, {"id": "e5-41", "part": 5, "type": "vocabulary", "question": "The warranty _____ parts and labor for a period of two years.", "options": ["includes", "holds", "contains", "covers"], "answer": 3, "explanation": "'Covers parts and labor' = bao g\u1ed3m ph\u1ee5 t\u00f9ng v\u00e0 nh\u00e2n c\u00f4ng (collocation b\u1ea3o h\u00e0nh).", "difficulty": "medium"}, {"id": "e5-42", "part": 5, "type": "vocabulary", "question": "Due to unforeseen circumstances, the event has been _____ indefinitely.", "options": ["postponed", "delayed", "canceled", "rescheduled"], "answer": 0, "explanation": "'Postponed indefinitely' = ho\u00e3n v\u00f4 th\u1eddi h\u1ea1n (collocation chu\u1ea9n).", "difficulty": "medium"}, {"id": "e5-43", "part": 5, "type": "vocabulary", "question": "The board has decided to _____ additional funds for the research project.", "options": ["allocate", "distribute", "assign", "appoint"], "answer": 0, "explanation": "'Allocate funds' = ph\u00e2n b\u1ed5 ng\u00e2n s\u00e1ch (collocation c\u1ed1 \u0111\u1ecbnh trong kinh doanh).", "difficulty": "medium"}, {"id": "e5-44", "part": 5, "type": "vocabulary", "question": "Employees must _____ with the company's code of conduct at all times.", "options": ["agree", "comply", "follow", "accept"], "answer": 1, "explanation": "'Comply with' = tu\u00e2n th\u1ee7 (c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong quy \u0111\u1ecbnh c\u00f4ng ty).", "difficulty": "medium"}, {"id": "e5-45", "part": 5, "type": "vocabulary", "question": "The negotiation _____ in a mutually beneficial agreement.", "options": ["ended", "led", "concluded", "resulted"], "answer": 3, "explanation": "'Resulted in' = d\u1eabn \u0111\u1ebfn k\u1ebft qu\u1ea3 (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "easy"}, {"id": "e5-46", "part": 5, "type": "vocabulary", "question": "The manager will _____ the final decision after consulting with all stakeholders.", "options": ["make", "do", "take", "get"], "answer": 0, "explanation": "'Make a decision' = ra quy\u1ebft \u0111\u1ecbnh (collocation c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "e5-47", "part": 5, "type": "vocabulary", "question": "Ms. Rivera was promoted in _____ of her outstanding contributions.", "options": ["view", "light", "recognition", "response"], "answer": 2, "explanation": "'In recognition of' = \u0111\u1ec3 ghi nh\u1eadn, t\u00f4n vinh (c\u1ee5m c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "e5-48", "part": 5, "type": "vocabulary", "question": "The company _____ a substantial profit despite the economic downturn.", "options": ["gained", "earned", "won", "obtained"], "answer": 1, "explanation": "'Earn a profit' = ki\u1ebfm \u0111\u01b0\u1ee3c l\u1ee3i nhu\u1eadn (collocation c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "e5-49", "part": 5, "type": "vocabulary", "question": "The new factory is _____ to begin production in the third quarter.", "options": ["planned", "organized", "arranged", "scheduled"], "answer": 3, "explanation": "'Scheduled to' = \u0111\u01b0\u1ee3c l\u00ean l\u1ecbch \u0111\u1ec3 (d\u00f9ng cho k\u1ebf ho\u1ea1ch c\u1ee5 th\u1ec3).", "difficulty": "medium"}, {"id": "e5-50", "part": 5, "type": "vocabulary", "question": "Please _____ to the enclosed brochure for a complete list of services.", "options": ["look", "refer", "see", "check"], "answer": 1, "explanation": "'Refer to' = tham kh\u1ea3o (c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong th\u01b0 t\u00edn th\u01b0\u01a1ng m\u1ea1i).", "difficulty": "medium"}, {"id": "t8-01", "part": 5, "type": "word-form", "question": "The committee's _____ of the merger terms took nearly three months of intensive negotiation.", "options": ["finalisation", "finalised", "finalise", "finally"], "answer": 0, "explanation": "'The committee's + noun' \u2192 c\u1ea7n danh t\u1eeb l\u00e0m ch\u1ee7 ng\u1eef. 'Finalisation' (s\u1ef1 ho\u00e0n t\u1ea5t) l\u00e0 danh t\u1eeb duy nh\u1ea5t. 'Finally' l\u00e0 ph\u00f3 t\u1eeb.", "difficulty": "medium"}, {"id": "t8-02", "part": 5, "type": "word-form", "question": "Ms. Park gave a _____ account of how the project had evolved from concept to completion.", "options": ["detailed", "detail", "detailing", "detailedly"], "answer": 0, "explanation": "T\u00ednh t\u1eeb 'detailed' (chi ti\u1ebft, k\u1ef9 l\u01b0\u1ee1ng) \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'account'. 'Detail' l\u00e0 danh t\u1eeb/\u0111\u1ed9ng t\u1eeb; 'detailedly' kh\u00f4ng ph\u1ea3i t\u1eeb chu\u1ea9n.", "difficulty": "medium"}, {"id": "t8-03", "part": 5, "type": "word-form", "question": "The new payroll software has significantly _____ the time required to process monthly salaries.", "options": ["reduce", "reduction", "reducing", "reduced"], "answer": 3, "explanation": "Sau 'has significantly' c\u1ea7n qu\u00e1 kh\u1ee9 ph\u00e2n t\u1eeb (V3) trong th\u00ec hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh \u2192 'reduced'. 'Reducing' l\u00e0 V-ing kh\u00f4ng d\u00f9ng \u0111\u01b0\u1ee3c sau 'has'.", "difficulty": "medium"}, {"id": "t8-04", "part": 5, "type": "word-form", "question": "Parkfield Consulting is known for its _____ approach to client relationships, often staying with clients for decades.", "options": ["persevere", "perseverance", "perseverant", "persevering"], "answer": 3, "explanation": "T\u00ednh t\u1eeb 'persevering' (ki\u00ean tr\u00ec, b\u1ec1n b\u1ec9) b\u1ed5 ngh\u0129a tr\u1ef1c ti\u1ebfp cho 'approach'. 'Perseverance' l\u00e0 danh t\u1eeb, kh\u00f4ng th\u1ec3 \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb kh\u00e1c l\u00e0m t\u00ednh t\u1eeb.", "difficulty": "medium"}, {"id": "t8-05", "part": 5, "type": "word-form", "question": "The annual gala was organised _____ and received unanimous praise from all 300 guests.", "options": ["flawless", "flawed", "flaw", "flawlessly"], "answer": 3, "explanation": "Ph\u00f3 t\u1eeb 'flawlessly' b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'was organised'. 'Flawless' l\u00e0 t\u00ednh t\u1eeb (c\u1ea7n \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb ho\u1eb7c sau be).", "difficulty": "medium"}, {"id": "t8-06", "part": 5, "type": "verb-tense", "question": "The new data centre _____ at full capacity since it was commissioned in the spring.", "options": ["operates", "has been operating", "operated", "will operate"], "answer": 1, "explanation": "'Since it was commissioned' \u2192 hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh ti\u1ebfp di\u1ec5n 'has been operating'. H\u00e0nh \u0111\u1ed9ng b\u1eaft \u0111\u1ea7u t\u1eeb qu\u00e1 kh\u1ee9 v\u00e0 v\u1eabn ti\u1ebfp t\u1ee5c \u0111\u1ebfn nay.", "difficulty": "medium"}, {"id": "t8-07", "part": 5, "type": "verb-tense", "question": "All participants _____ a welcome package upon arrival at the registration desk tomorrow morning.", "options": ["received", "receive", "will receive", "had received"], "answer": 2, "explanation": "'Tomorrow morning' ch\u1ec9 t\u01b0\u01a1ng lai \u2192 'will receive'. Ng\u1eef c\u1ea3nh l\u00e0 ch\u00ednh s\u00e1ch/l\u1ecbch tr\u00ecnh s\u1ef1 ki\u1ec7n s\u1eafp t\u1edbi.", "difficulty": "medium"}, {"id": "t8-08", "part": 5, "type": "prepositions", "question": "Please be aware that your subscription will renew automatically _____ the end of the billing cycle.", "options": ["during", "until", "by", "at"], "answer": 3, "explanation": "'At the end of' = v\u00e0o l\u00fac k\u1ebft th\u00fac (\u0111i\u1ec3m th\u1eddi gian c\u1ee5 th\u1ec3). 'Until' = ti\u1ebfp t\u1ee5c cho \u0111\u1ebfn; 'by' = tr\u01b0\u1edbc th\u1eddi \u0111i\u1ec3m \u0111\u00f3.", "difficulty": "medium"}, {"id": "t8-09", "part": 5, "type": "prepositions", "question": "The financial analyst's projections proved to be _____ with actual performance figures for the quarter.", "options": ["consistent", "consistently", "inconsistent", "consistent with"], "answer": 3, "explanation": "'Consistent with' = ph\u00f9 h\u1ee3p v\u1edbi, nh\u1ea5t qu\u00e1n v\u1edbi (c\u1ee5m t\u00ednh t\u1eeb + gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh). C\u00e2u \u0111ang test xem 'with' c\u00f3 b\u1ecb thi\u1ebfu kh\u00f4ng \u2013 \u0111\u00e2y l\u00e0 b\u1eaby \u0111i\u1ec3n h\u00ecnh trong ETS.", "difficulty": "medium"}, {"id": "t8-10", "part": 5, "type": "conjunction", "question": "The training session will be recorded _____ employees who are unable to attend may watch it at a later time.", "options": ["so that", "now that", "in case", "even though"], "answer": 0, "explanation": "'So that' = \u0111\u1ec3 (ch\u1ec9 m\u1ee5c \u0111\u00edch). Bu\u1ed5i \u0111\u01b0\u1ee3c quay v\u1edbi m\u1ee5c \u0111\u00edch r\u00f5 r\u00e0ng l\u00e0 \u0111\u1ec3 nh\u00e2n vi\u00ean xem l\u1ea1i. 'In case' = ph\u00f2ng khi (d\u00f9ng khi s\u1ef1 vi\u1ec7c \u0111\u01b0\u1ee3c coi l\u00e0 kh\u00f4ng ch\u1eafc x\u1ea3y ra), kh\u00f4ng ph\u00f9 h\u1ee3p v\u00ec \u0111\u00e2y l\u00e0 m\u1ee5c \u0111\u00edch ch\u1ee7 \u0111\u1ed9ng. 'Now that' = b\u00e2y gi\u1edd khi, 'even though' = m\u1eb7c d\u00f9 \u2013 sai ngh\u0129a.", "difficulty": "medium"}, {"id": "t8-11", "part": 5, "type": "conjunction", "question": "_____ the renovation was disruptive, most staff agreed the refurbished office was well worth it.", "options": ["Despite", "Because of", "Although", "However"], "answer": 2, "explanation": "'Although' = m\u1eb7c d\u00f9 (li\u00ean t\u1eeb ph\u1ee5 thu\u1ed9c n\u1ed1i hai m\u1ec7nh \u0111\u1ec1). 'Despite' c\u1ea7n danh t\u1eeb/V-ing (despite the disruption). 'However' l\u00e0 tr\u1ea1ng t\u1eeb li\u00ean k\u1ebft, kh\u00f4ng th\u1ec3 \u1edf \u0111\u1ea7u m\u1ed9t m\u1ec7nh \u0111\u1ec1 ph\u1ee5 nh\u01b0 th\u1ebf n\u00e0y.", "difficulty": "medium"}, {"id": "t8-12", "part": 5, "type": "passive", "question": "Suppliers who fail to meet the quality specifications _____ from the approved vendor list.", "options": ["remove", "to be removed", "removing", "are removed"], "answer": 3, "explanation": "Ch\u1ee7 ng\u1eef 'Suppliers' nh\u1eadn h\u00e0nh \u0111\u1ed9ng (b\u1ecb lo\u1ea1i kh\u1ecfi danh s\u00e1ch) \u2192 b\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n 'are removed'. \u0110\u00e2y l\u00e0 quy \u0111\u1ecbnh l\u1eb7p l\u1ea1i \u2192 hi\u1ec7n t\u1ea1i \u0111\u01a1n.", "difficulty": "medium"}, {"id": "t8-13", "part": 5, "type": "vocabulary", "question": "The director of communications was tasked with _____ the company's response to the media inquiry.", "options": ["installing", "launching", "expanding", "drafting"], "answer": 3, "explanation": "'Drafting a response' = so\u1ea1n th\u1ea3o c\u00e2u tr\u1ea3 l\u1eddi (collocation chu\u1ea9n trong PR/corporate communications). 'Launch' = kh\u1edfi \u0111\u1ed9ng chi\u1ebfn d\u1ecbch/s\u1ea3n ph\u1ea9m; 'install' d\u00f9ng cho ph\u1ea7n m\u1ec1m/thi\u1ebft b\u1ecb.", "difficulty": "medium"}, {"id": "t8-14", "part": 5, "type": "vocabulary", "question": "The logistics team worked around the clock to _____ that all orders were dispatched before the holiday freeze.", "options": ["ensure", "result", "cause", "indicate"], "answer": 0, "explanation": "'Ensure that' = \u0111\u1ea3m b\u1ea3o r\u1eb1ng (c\u1ee5m \u0111\u1ed9ng t\u1eeb chu\u1ea9n). Ph\u00e2n bi\u1ec7t: 'ensure that' (\u0111\u1ea3m b\u1ea3o) vs 'result in' (d\u1eabn \u0111\u1ebfn k\u1ebft qu\u1ea3) vs 'indicate that' (ch\u1ec9 ra r\u1eb1ng).", "difficulty": "medium"}, {"id": "t8-15", "part": 5, "type": "pronoun", "question": "The new compensation guidelines apply to _____ who joined the organisation on or after January 1.", "options": ["whichever", "them", "those", "each"], "answer": 2, "explanation": "'Those who' = nh\u1eefng ng\u01b0\u1eddi m\u00e0 (c\u1ea5u tr\u00fac chu\u1ea9n trong v\u0103n b\u1ea3n ch\u00ednh s\u00e1ch). 'Whichever' d\u00f9ng cho v\u1eadt/l\u1ef1a ch\u1ecdn, kh\u00f4ng d\u00f9ng cho ng\u01b0\u1eddi. 'Them who' sai ng\u1eef ph\u00e1p. 'Each' c\u1ea7n \u0111\u1ee9ng v\u1edbi danh t\u1eeb \u0111\u01a1n.", "difficulty": "medium"}, {"id": "ex5-1", "part": 5, "type": "verb-tense", "question": "The management team _____ the budget proposal several times before final approval was granted.", "options": ["had reviewed", "is reviewing", "reviews", "will review"], "answer": 0, "explanation": "\u2705 <b>Had reviewed</b> (Qu\u00e1 kh\u1ee9 ho\u00e0n th\u00e0nh). <br>\ud83d\udca1 <i>C\u1ea5u tr\u00fac:</i> H\u00e0nh \u0111\u1ed9ng x\u1ea3y ra tr\u01b0\u1edbc m\u1ed9t h\u00e0nh \u0111\u1ed9ng kh\u00e1c trong qu\u00e1 kh\u1ee9 (granted) -> d\u00f9ng Past Perfect.", "difficulty": "medium"}, {"id": "ex5-2", "part": 5, "type": "verb-tense", "question": "By the time the new regulations take effect, the company _____ its compliance software for six months.", "options": ["tests", "will have been testing", "has tested", "is testing"], "answer": 1, "explanation": "\u2705 <b>Will have been testing</b> (T\u01b0\u01a1ng lai ho\u00e0n th\u00e0nh ti\u1ebfp di\u1ec5n). <br>\ud83d\udca1 <i>M\u1eb9o ETS:</i> 'By the time + Hi\u1ec7n t\u1ea1i' + 'for [kho\u1ea3ng th\u1eddi gian]' -> T\u01b0\u01a1ng lai ho\u00e0n th\u00e0nh ti\u1ebfp di\u1ec5n.", "difficulty": "hard"}, {"id": "ex5-3", "part": 5, "type": "vocabulary", "question": "Establishing a strong _____ in the local market is the first priority for the new branch.", "options": ["presence", "participation", "presentation", "precedence"], "answer": 0, "explanation": "\u2705 <b>Presence</b> (S\u1ef1 hi\u1ec7n di\u1ec7n). <br>\ud83d\udca1 'Market presence' l\u00e0 c\u1ee5m t\u1eeb c\u1ed1 \u0111\u1ecbnh (collocation) ph\u1ed5 bi\u1ebfn trong TOEIC.", "difficulty": "medium"}, {"id": "ex5-4", "part": 5, "type": "passive", "question": "All sensitive documents _____ to the secure shredding facility every Friday afternoon.", "options": ["transport", "are transporting", "are transported", "have transported"], "answer": 2, "explanation": "\u2705 <b>Are transported</b> (B\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n). <br>\ud83d\udca1 Ch\u1ee7 ng\u1eef 'documents' b\u1ecb t\u00e1c \u0111\u1ed9ng (\u0111\u01b0\u1ee3c v\u1eadn chuy\u1ec3n) + 'every Friday' (th\u00f3i quen).", "difficulty": "medium"}, {"id": "ex5-5", "part": 5, "type": "passive", "question": "Employees _____ of any changes to the health insurance policy at least one month in advance.", "options": ["will be notified", "will notify", "notify", "notifying"], "answer": 0, "explanation": "\u2705 <b>Will be notified</b> (B\u1ecb \u0111\u1ed9ng t\u01b0\u01a1ng lai). <br>\ud83d\udca1 C\u1ea5u tr\u00fac 'notify someone of something'. \u1ede \u0111\u00e2y nh\u00e2n vi\u00ean \u0110\u01af\u1ee2C th\u00f4ng b\u00e1o.", "difficulty": "medium"}, {"id": "ex5-6", "part": 5, "type": "conditionals", "question": "If the candidate _____ the interview successfully, he will be offered the position immediately.", "options": ["passes", "pass", "passed", "will pass"], "answer": 0, "explanation": "\u2705 <b>Passes</b> (C\u00e2u \u0111i\u1ec1u ki\u1ec7n Lo\u1ea1i 1). <br>\ud83d\udca1 Di\u1ec5n t\u1ea3 s\u1ef1 vi\u1ec7c c\u00f3 th\u1ec3 x\u1ea3y ra: If + S + V(hi\u1ec7n t\u1ea1i), S + will + V.", "difficulty": "medium"}, {"id": "ex5-7", "part": 5, "type": "conditionals", "question": "Had the directors known about the potential risks, they _____ the merger.", "options": ["won't approve", "wouldn't approve", "wouldn't have approved", "didn't approve"], "answer": 2, "explanation": "\u2705 <b>Wouldn't have approved</b> (\u0110\u1ea3o ng\u1eef lo\u1ea1i 3). <br>\ud83d\udca1 Had + S + V3 (lo\u1ea1i 3), S + would have + V3. Di\u1ec5n t\u1ea3 s\u1ef1 vi\u1ec7c tr\u00e1i ng\u01b0\u1ee3c v\u1edbi qu\u00e1 kh\u1ee9.", "difficulty": "medium"}, {"id": "ex5-8", "part": 5, "type": "word-form", "question": "The marketing director emphasized the need for _____ branding across all social media platforms.", "options": ["consistency", "consistent", "consistently", "consist"], "answer": 1, "explanation": "\u2705 <b>Consistent</b> (T\u00ednh t\u1eeb). <br>\ud83d\udca1 V\u1ecb tr\u00ed \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb 'branding' \u0111\u1ec3 b\u1ed5 ngh\u0129a. Tr\u1ea1ng t\u1eeb 'consistently' ch\u1ec9 b\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb ho\u1eb7c \u0111\u1ed9ng t\u1eeb.", "difficulty": "medium"}, {"id": "ex5-9", "part": 5, "type": "word-form", "question": "The _____ of the new product line exceeded all previous sales records.", "options": ["successful", "succeed", "successfully", "success"], "answer": 3, "explanation": "\u2705 <b>Success</b> (Danh t\u1eeb). <br>\ud83d\udca1 V\u1ecb tr\u00ed sau 'The' v\u00e0 tr\u01b0\u1edbc gi\u1edbi t\u1eeb 'of' lu\u00f4n l\u00e0 m\u1ed9t danh t\u1eeb \u0111\u00f3ng vai tr\u00f2 ch\u1ee7 ng\u1eef.", "difficulty": "medium"}, {"id": "ex5-10", "part": 5, "type": "prepositions", "question": "The finance department is responsible _____ monitoring all international transactions.", "options": ["to", "at", "with", "for"], "answer": 3, "explanation": "\u2705 <b>For</b>. <br>\ud83d\udca1 C\u1ea5u tr\u00fac t\u00ednh t\u1eeb: <i>to be responsible for something/V-ing</i> (ch\u1ecbu tr\u00e1ch nhi\u1ec7m cho vi\u1ec7c g\u00ec).", "difficulty": "medium"}, {"id": "ex5-11", "part": 5, "type": "prepositions", "question": "According _____ the latest financial report, the company's revenue has increased by 15%.", "options": ["with", "to", "on", "for"], "answer": 1, "explanation": "\u2705 <b>To</b>. <br>\ud83d\udca1 C\u1ee5m t\u1eeb c\u1ed1 \u0111\u1ecbnh: 'According to' (Theo nh\u01b0) mang t\u00ednh d\u1eabn d\u1eaft th\u00f4ng tin.", "difficulty": "medium"}, {"id": "ex5-12", "part": 5, "type": "conjunction", "question": "The new software is highly intuitive; _____, some employees may still require initial training.", "options": ["therefore", "however", "meanwhile", "consequently"], "answer": 1, "explanation": "\u2705 <b>However</b> (Tuy nhi\u00ean). <br>\ud83d\udca1 Tr\u1ea1ng t\u1eeb li\u00ean k\u1ebft ch\u1ec9 s\u1ef1 t\u01b0\u01a1ng ph\u1ea3n gi\u1eefa hai \u00fd (d\u1ec5 d\u00f9ng vs v\u1eabn c\u1ea7n \u0111\u00e0o t\u1ea1o).", "difficulty": "medium"}, {"id": "ex5-13", "part": 5, "type": "conjunction", "question": "_____ the system upgrade is complete, users will be able to access the new features.", "options": ["Although", "Once", "Unless", "While"], "answer": 1, "explanation": "\u2705 <b>Once</b> (Ngay khi). <br>\ud83d\udca1 Ch\u1ec9 \u0111i\u1ec1u ki\u1ec7n v\u1ec1 th\u1eddi gian: s\u1ef1 vi\u1ec7c 1 k\u1ebft th\u00fac th\u00ec s\u1ef1 vi\u1ec7c 2 b\u1eaft \u0111\u1ea7u.", "difficulty": "medium"}, {"id": "ex5-14", "part": 5, "type": "relative-clause", "question": "The machinery, _____ was installed last month, has significantly improved production speed.", "options": ["who", "whose", "whom", "which"], "answer": 3, "explanation": "\u2705 <b>Which</b> (\u0110\u1ea1i t\u1eeb quan h\u1ec7). <br>\ud83d\udca1 Thay th\u1ebf cho v\u1eadt (machinery) trong m\u1ec7nh \u0111\u1ec1 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh (sau d\u1ea5u ph\u1ea9y).", "difficulty": "medium"}, {"id": "ex5-15", "part": 5, "type": "relative-clause", "question": "The technician _____ we hired last week has already identified several assembly line issues.", "options": ["whom", "whose", "which", "who"], "answer": 0, "explanation": "\u2705 <b>Whom</b>. <br>\ud83d\udca1 \u0110\u1ea1i t\u1eeb quan h\u1ec7 l\u00e0m t\u00e2n ng\u1eef (we hired <i>him</i> \u2192 whom). Trong v\u0103n b\u1ea3n TOEIC trang tr\u1ecdng, 'whom' l\u00e0 \u0111\u00e1p \u00e1n chu\u1ea9n duy nh\u1ea5t khi \u0111\u1ea1i t\u1eeb \u0111\u00f3ng vai tr\u00f2 t\u00e2n ng\u1eef. 'Who' ch\u1ec9 d\u00f9ng khi l\u00e0 ch\u1ee7 ng\u1eef.", "difficulty": "medium"}, {"id": "ex5-16", "part": 5, "type": "pronoun", "question": "Travelers are reminded to keep _____ boarding passes and identification ready for inspection.", "options": ["them", "their", "they", "themselves"], "answer": 1, "explanation": "\u2705 <b>Their</b> (T\u00ednh t\u1eeb s\u1edf h\u1eefu). <br>\ud83d\udca1 C\u1ea7n m\u1ed9t t\u00ednh t\u1eeb s\u1edf h\u1eefu \u0111\u1ee9ng tr\u01b0\u1edbc c\u1ee5m danh t\u1eeb 'boarding passes' c\u1ee7a c\u00e1c h\u00e0nh kh\u00e1ch.", "difficulty": "medium"}, {"id": "ex5-17", "part": 5, "type": "pronoun", "question": "The hotel manager personally welcomed the guests and offered _____ a complimentary dinner.", "options": ["they", "them", "their", "themselves"], "answer": 1, "explanation": "\u2705 <b>Them</b> (\u0110\u1ea1i t\u1eeb t\u00e2n ng\u1eef). <br>\ud83d\udca1 V\u1ecb tr\u00ed t\u00e2n ng\u1eef sau \u0111\u1ed9ng t\u1eeb 'offered'. Tr\u00e1nh nh\u1ea7m v\u1edbi 'themselves' (ph\u1ea3n th\u00e2n).", "difficulty": "medium"}, {"id": "ex5-18", "part": 5, "type": "modal", "question": "All attendees _____ register at the front desk before entering the main hall.", "options": ["must", "would", "might", "could"], "answer": 0, "explanation": "\u2705 <b>Must</b> (\u0110\u1ed9ng t\u1eeb khuy\u1ebft thi\u1ebfu). <br>\ud83d\udca1 Di\u1ec5n t\u1ea3 s\u1ef1 b\u1eaft bu\u1ed9c ho\u1eb7c quy \u0111\u1ecbnh chung trong s\u1ef1 ki\u1ec7n.", "difficulty": "medium"}, {"id": "ex5-19", "part": 5, "type": "modal", "question": "If the weather improves, the outdoor reception _____ be held as originally planned.", "options": ["must", "should", "ought", "might"], "answer": 3, "explanation": "\u2705 <b>Might</b>. <br>\ud83d\udca1 Di\u1ec5n t\u1ea3 kh\u1ea3 n\u0103ng c\u00f3 th\u1ec3 x\u1ea3y ra nh\u01b0ng kh\u00f4ng ch\u1eafc ch\u1eafn 100% trong t\u01b0\u01a1ng lai.", "difficulty": "medium"}, {"id": "ex5-20", "part": 5, "type": "comparison", "question": "Using a third-party logistics provider proved to be _____ than managing the warehouse internally.", "options": ["more efficient", "efficient", "most efficient", "efficiently"], "answer": 0, "explanation": "\u2705 <b>More efficient</b> (So s\u00e1nh h\u01a1n). <br>\ud83d\udca1 C\u00f3 'than' v\u00e0 t\u00ednh t\u1eeb d\u00e0i 'efficient' -> d\u00f9ng 'more + adj'.", "difficulty": "medium"}, {"id": "ex5-21", "part": 5, "type": "comparison", "question": "Shipping by sea is often the _____ option for large-scale international orders.", "options": ["most economical", "more economical", "economical", "economically"], "answer": 0, "explanation": "\u2705 <b>Most economical</b> (So s\u00e1nh nh\u1ea5t). <br>\ud83d\udca1 C\u00f3 'the' + so s\u00e1nh gi\u1eefa nhi\u1ec1u l\u1ef1a ch\u1ecdn -> d\u00f9ng 'the most + adj'.", "difficulty": "medium"}, {"id": "ex5-22", "part": 5, "type": "subject-verb", "question": "The manager, along with his assistants, _____ attending the investment seminar today.", "options": ["are", "is", "being", "been"], "answer": 1, "explanation": "\u2705 <b>Is</b> (H\u00f2a h\u1ee3p ch\u1ee7 v\u1ecb). <br>\ud83d\udca1 <i>M\u1eb9o ETS:</i> C\u1ea5u tr\u00fac 'S1, along with S2,' th\u00ec \u0111\u1ed9ng t\u1eeb chia theo S1 (The manager) -> s\u1ed1 \u00edt.", "difficulty": "medium"}, {"id": "ex5-23", "part": 5, "type": "subject-verb", "question": "Neither the bank nor the clients _____ happy with the sudden change in interest rates.", "options": ["is", "are", "was", "has been"], "answer": 1, "explanation": "\u2705 <b>Are</b>. <br>\ud83d\udca1 C\u1ea5u tr\u00fac 'Neither S1 nor S2' -> \u0111\u1ed9ng t\u1eeb chia theo S2 (the clients) -> s\u1ed1 nhi\u1ec1u.", "difficulty": "medium"}, {"id": "ex5-24", "part": 5, "type": "subject-verb", "question": "Investing in diversified portfolios _____ a proven strategy for long-term wealth accumulation.", "options": ["been", "are", "being", "is"], "answer": 3, "explanation": "\u2705 <b>Is</b>. <br>\ud83d\udca1 Danh \u0111\u1ed9ng t\u1eeb (V-ing) l\u00e0m ch\u1ee7 ng\u1eef lu\u00f4n \u0111\u01b0\u1ee3c coi l\u00e0 s\u1ed1 \u00edt.", "difficulty": "medium"}, {"id": "ex5-25", "part": 5, "type": "subject-verb", "question": "The number of bank account holders _____ steadily increasing since the introduction of the digital app.", "options": ["is", "have been", "has been", "are"], "answer": 2, "explanation": "\u2705 <b>Has been</b>. <br>\ud83d\udca1 <i>M\u1eb9o ETS:</i> 'The number of' + Danh t\u1eeb s\u1ed1 nhi\u1ec1u + \u0110\u1ed9ng t\u1eeb s\u1ed1 \u00edt.", "difficulty": "medium"}, {"id": "ex5-26", "part": 5, "type": "vocabulary", "question": "The investment bank decided to _____ its assets to reduce exposure to the volatile energy market.", "options": ["calculate", "diversify", "withdraw", "deposit"], "answer": 1, "explanation": "\u2705 <b>Diversify</b> (\u0110a d\u1ea1ng h\u00f3a). <br>\ud83d\udca1 'Diversify assets' (\u0111a d\u1ea1ng h\u00f3a t\u00e0i s\u1ea3n) l\u00e0 thu\u1eadt ng\u1eef t\u00e0i ch\u00ednh \u0111\u1ec3 gi\u1ea3m r\u1ee7i ro.", "difficulty": "medium"}, {"id": "ex5-27", "part": 5, "type": "vocabulary", "question": "A significant _____ in the stock price was observed after the company announced its merger.", "options": ["fluctuation", "foundation", "formation", "function"], "answer": 0, "explanation": "\u2705 <b>Fluctuation</b> (S\u1ef1 bi\u1ebfn \u0111\u1ed9ng). <br>\ud83d\udca1 Ch\u1ec9 s\u1ef1 l\u00ean xu\u1ed1ng kh\u00f4ng \u1ed5n \u0111\u1ecbnh c\u1ee7a gi\u00e1 c\u1ea3 ho\u1eb7c s\u1ed1 li\u1ec7u.", "difficulty": "medium"}, {"id": "ex5-28", "part": 5, "type": "vocabulary", "question": "The central bank raised interest rates to _____ rising inflation in the second quarter.", "options": ["convert", "conduct", "connect", "combat"], "answer": 3, "explanation": "\u2705 <b>Combat</b> (Ch\u1ed1ng l\u1ea1i). <br>\ud83d\udca1 'Combat inflation' l\u00e0 collocation ph\u1ed5 bi\u1ebfn ch\u1ec9 vi\u1ec7c ng\u0103n ch\u1eb7n l\u1ea1m ph\u00e1t.", "difficulty": "medium"}, {"id": "ex5-29", "part": 5, "type": "vocabulary", "question": "Investors are looking for high-yield bonds that offer a _____ return on investment.", "options": ["sterile", "static", "stable", "sturdy"], "answer": 2, "explanation": "\u2705 <b>Stable</b> (\u1ed4n \u0111\u1ecbnh). <br>\ud83d\udca1 'Stable return' (l\u1ee3i nhu\u1eadn \u1ed5n \u0111\u1ecbnh) l\u00e0 t\u00ednh t\u1eeb b\u1ed5 ngh\u0129a cho l\u1ee3i nhu\u1eadn \u0111\u1ea7u t\u01b0.", "difficulty": "medium"}, {"id": "ex5-30", "part": 5, "type": "verb-tense", "question": "Since the new CEO took over, the company _____ its international market share by 20%.", "options": ["expanded", "expands", "has expanded", "is expanding"], "answer": 2, "explanation": "\u2705 <b>Has expanded</b>. <br>\ud83d\udca1 'Since + Qu\u00e1 kh\u1ee9' -> m\u1ec7nh \u0111\u1ec1 ch\u00ednh d\u00f9ng Hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh.", "difficulty": "medium"}, {"id": "ex5-31", "part": 5, "type": "verb-tense", "question": "Next year, Horizon Group _____ its 10th anniversary with a series of community events.", "options": ["celebrates", "will celebrate", "celebrated", "has celebrated"], "answer": 1, "explanation": "\u2705 <b>Will celebrate</b>. <br>\ud83d\udca1 'Next year' l\u00e0 m\u1ed1c th\u1eddi gian trong t\u01b0\u01a1ng lai -> d\u00f9ng Future Simple.", "difficulty": "medium"}, {"id": "ex5-32", "part": 5, "type": "verb-tense", "question": "The marketing team _____ the spring campaign for three months before it was launched.", "options": ["had been preparing", "prepares", "prepared", "is preparing"], "answer": 0, "explanation": "\u2705 <b>Had been preparing</b> (Qu\u00e1 kh\u1ee9 ho\u00e0n th\u00e0nh ti\u1ebfp di\u1ec5n). <br>\ud83d\udca1 Nh\u1ea5n m\u1ea1nh t\u00ednh li\u00ean t\u1ee5c c\u1ee7a h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra tr\u01b0\u1edbc m\u1ed9t th\u1eddi \u0111i\u1ec3m kh\u00e1c trong qu\u00e1 kh\u1ee9.", "difficulty": "medium"}, {"id": "ex5-33", "part": 5, "type": "passive", "question": "The annual performance reviews _____ by the department heads next week.", "options": ["conduct", "are conducted", "conducting", "will be conducted"], "answer": 3, "explanation": "\u2705 <b>Will be conducted</b>. <br>\ud83d\udca1 B\u1ecb \u0111\u1ed9ng t\u01b0\u01a1ng lai \u0111\u01a1n: will be + PII.", "difficulty": "medium"}, {"id": "ex5-34", "part": 5, "type": "passive", "question": "New safety protocols _____ following the recent audit of the manufacturing facility.", "options": ["implemented", "were implemented", "is implementing", "has implemented"], "answer": 1, "explanation": "\u2705 <b>Were implemented</b>. <br>\ud83d\udca1 B\u1ecb \u0111\u1ed9ng qu\u00e1 kh\u1ee9 \u0111\u01a1n (safety protocols \u0111\u01b0\u1ee3c th\u1ef1c thi).", "difficulty": "medium"}, {"id": "ex5-35", "part": 5, "type": "conditionals", "question": "If the shipment _____ by tomorrow, we will have to suspend production.", "options": ["hadn't arrived", "didn't arrive", "won't arrive", "doesn't arrive"], "answer": 3, "explanation": "\u2705 <b>Doesn't arrive</b>. <br>\ud83d\udca1 C\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1: If + Hi\u1ec7n t\u1ea1i, T\u01b0\u01a1ng lai.", "difficulty": "medium"}, {"id": "ex5-36", "part": 5, "type": "conditionals", "question": "Unless the terms are renegotiated, the contract _____ at the end of the month.", "options": ["expires", "would expire", "expired", "will expire"], "answer": 3, "explanation": "\u2705 <b>Will expire</b>. <br>\ud83d\udca1 Unless = If not. D\u00f9ng t\u01b0\u01a1ng \u0111\u01b0\u01a1ng c\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1.", "difficulty": "medium"}, {"id": "ex5-37", "part": 5, "type": "relative-clause", "question": "The quality control manager, _____ expertise is unmatched, oversees the entire production line.", "options": ["who", "whom", "which", "whose"], "answer": 3, "explanation": "\u2705 <b>Whose</b>. <br>\ud83d\udca1 \u0110\u1ea1i t\u1eeb quan h\u1ec7 s\u1edf h\u1eefu cho 'expertise' (chuy\u00ean m\u00f4n C\u1ee6A ng\u01b0\u1eddi qu\u1ea3n l\u00fd).", "difficulty": "medium"}, {"id": "ex5-38", "part": 5, "type": "vocabulary", "question": "Any _____ items found during inspection are immediately removed from the assembly line.", "options": ["defective", "effective", "protective", "selective"], "answer": 0, "explanation": "\u2705 <b>Defective</b> (L\u1ed7i/h\u1ecfng). <br>\ud83d\udca1 Thu\u1eadt ng\u1eef chuy\u00ean ng\u00e0nh trong s\u1ea3n xu\u1ea5t (Quality Control).", "difficulty": "medium"}, {"id": "ex5-39", "part": 5, "type": "vocabulary", "question": "The factory has achieved _____ production levels since the introduction of automation.", "options": ["precedent", "unprecedented", "preceded", "preceding"], "answer": 1, "explanation": "\u2705 <b>Unprecedented</b> (Ch\u01b0a t\u1eebng c\u00f3). <br>\ud83d\udca1 Th\u01b0\u1eddng d\u00f9ng \u0111\u1ec3 m\u00f4 t\u1ea3 s\u1ef1 ph\u00e1t tri\u1ec3n v\u01b0\u1ee3t b\u1eadc ho\u1eb7c k\u1ef7 l\u1ee5c m\u1edbi.", "difficulty": "medium"}, {"id": "ex5-40", "part": 5, "type": "vocabulary", "question": "The tourism board is launching a campaign to _____ the city's historical landmarks.", "options": ["produce", "promote", "provide", "protect"], "answer": 1, "explanation": "\u2705 <b>Promote</b> (Qu\u1ea3ng b\u00e1). <br>\ud83d\udca1 Collocation: 'promote tourism/landmarks' (th\u00fac \u0111\u1ea9y du l\u1ecbch).", "difficulty": "medium"}, {"id": "ex5-41", "part": 5, "type": "vocabulary", "question": "International travelers are advised to check the _____ of their passports 6 months before departure.", "options": ["validity", "utility", "facility", "ability"], "answer": 0, "explanation": "\u2705 <b>Validity</b> (Th\u1eddi h\u1ea1n hi\u1ec7u l\u1ef1c). <br>\ud83d\udca1 Thu\u1eadt ng\u1eef th\u01b0\u1eddng g\u1eb7p trong du l\u1ecbch v\u00e0 th\u1ee7 t\u1ee5c gi\u1ea5y t\u1edd.", "difficulty": "medium"}, {"id": "ex5-42", "part": 5, "type": "vocabulary", "question": "The annual gala is a prestigious _____ that brings together leaders from across the industry.", "options": ["event", "encounter", "episode", "exchange"], "answer": 0, "explanation": "\u2705 <b>Event</b> (S\u1ef1 ki\u1ec7n). <br>\ud83d\udca1 Ng\u1eef c\u1ea3nh v\u1ec1 m\u1ed9t bu\u1ed5i ti\u1ec7c th\u01b0\u1eddng ni\u00ean quan tr\u1ecdng.", "difficulty": "medium"}, {"id": "ex5-43", "part": 5, "type": "vocabulary", "question": "We need to hire a professional _____ to manage the catering for the international conference.", "options": ["monitor", "investor", "vendor", "applicant"], "answer": 2, "explanation": "\u2705 <b>Vendor</b> (Nh\u00e0 cung c\u1ea5p). <br>\ud83d\udca1 Trong kinh doanh, 'vendor' ch\u1ec9 c\u00e1c \u0111\u01a1n v\u1ecb cung c\u1ea5p d\u1ecbch v\u1ee5 b\u00ean ngo\u00e0i.", "difficulty": "medium"}, {"id": "ex5-44", "part": 5, "type": "relative-clause", "question": "The manufacturing plant, _____ began operations in 1995, is undergoing a major renovation.", "options": ["that", "where", "which", "who"], "answer": 2, "explanation": "\u2705 <b>Which</b>. <br>\ud83d\udca1 D\u00f9ng cho v\u1eadt (plant) trong m\u1ec7nh \u0111\u1ec1 quan h\u1ec7 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "ex5-45", "part": 5, "type": "relative-clause", "question": "The engineer _____ designed the new assembly line has just received a company award.", "options": ["who", "whose", "which", "whom"], "answer": 0, "explanation": "\u2705 <b>Who</b>. <br>\ud83d\udca1 \u0110\u1ea1i t\u1eeb quan h\u1ec7 l\u00e0m ch\u1ee7 ng\u1eef trong m\u1ec7nh \u0111\u1ec1 ('who designed' \u2013 k\u1ef9 s\u01b0 \u0111\u00f3 thi\u1ebft k\u1ebf). 'Whom' ch\u1ec9 d\u00f9ng khi l\u00e0m t\u00e2n ng\u1eef; 'which' d\u00f9ng cho v\u1eadt; 'whose' ch\u1ec9 s\u1edf h\u1eefu.", "difficulty": "medium"}, {"id": "ex5-46", "part": 5, "type": "vocabulary", "question": "The production line was halted to _____ a minor technical error in the sorting machine.", "options": ["replace", "record", "release", "rectify"], "answer": 3, "explanation": "\u2705 <b>Rectify</b> (Kh\u1eafc ph\u1ee5c/S\u1eeda ch\u1eefa). <br>\ud83d\udca1 Collocation: 'rectify an error/problem'.", "difficulty": "medium"}, {"id": "ex5-47", "part": 5, "type": "vocabulary", "question": "Stringent quality _____ are applied to every batch of products before shipment.", "options": ["strategies", "stations", "standards", "statutes"], "answer": 2, "explanation": "\u2705 <b>Standards</b> (Ti\u00eau chu\u1ea9n). <br>\ud83d\udca1 'Quality standards' l\u00e0 b\u1ed9 ti\u00eau chu\u1ea9n ch\u1ea5t l\u01b0\u1ee3ng s\u1ea3n ph\u1ea9m.", "difficulty": "medium"}, {"id": "ex5-48", "part": 5, "type": "vocabulary", "question": "The factory's _____ output has doubled since the new equipment was installed.", "options": ["finally", "daily", "rarely", "nearly"], "answer": 1, "explanation": "\u2705 <b>Daily</b> (H\u00e0ng ng\u00e0y). <br>\ud83d\udca1 T\u00ednh t\u1eeb b\u1ed5 ngh\u0129a cho s\u1ea3n l\u01b0\u1ee3ng (output).", "difficulty": "medium"}, {"id": "ex5-49", "part": 5, "type": "vocabulary", "question": "The resort offers a variety of _____ activities, including guided mountain tours.", "options": ["recreational", "mechanical", "educational", "industrial"], "answer": 0, "explanation": "\u2705 <b>Recreational</b> (Gi\u1ea3i tr\u00ed). <br>\ud83d\udca1 'Recreational activities' l\u00e0 c\u00e1c ho\u1ea1t \u0111\u1ed9ng vui ch\u01a1i gi\u1ea3i tr\u00ed.", "difficulty": "medium"}, {"id": "ex5-50", "part": 5, "type": "vocabulary", "question": "Travelers are advised to _____ their flight status 24 hours before departure.", "options": ["confine", "conform", "confirm", "confront"], "answer": 2, "explanation": "\u2705 <b>Confirm</b> (X\u00e1c nh\u1eadn). <br>\ud83d\udca1 Th\u1ee7 t\u1ee5c ki\u1ec3m tra l\u1ea1i tr\u01b0\u1edbc khi bay.", "difficulty": "medium"}, {"id": "ex5-51", "part": 5, "type": "vocabulary", "question": "The historical district is a popular _____ for both domestic and international tourists.", "options": ["distribution", "destination", "description", "demonstration"], "answer": 1, "explanation": "\u2705 <b>Destination</b> (\u0110i\u1ec3m \u0111\u1ebfn). <br>\ud83d\udca1 N\u01a1i kh\u00e1ch du l\u1ecbch l\u1ef1a ch\u1ecdn h\u00e0nh tr\u00ecnh.", "difficulty": "medium"}, {"id": "ex5-52", "part": 5, "type": "modal", "question": "Conference participants _____ wear their identification badges at all times.", "options": ["should", "would", "might", "could"], "answer": 0, "explanation": "\u2705 <b>Should</b> (N\u00ean). <br>\ud83d\udca1 L\u1eddi khuy\u00ean/h\u01b0\u1edbng d\u1eabn l\u1ecbch s\u1ef1 trong s\u1ef1 ki\u1ec7n h\u1ed9i ngh\u1ecb.", "difficulty": "medium"}, {"id": "ex5-53", "part": 5, "type": "modal", "question": "The keynote speaker _____ arrive early to test the audiovisual equipment.", "options": ["must", "might", "could", "would"], "answer": 0, "explanation": "\u2705 <b>Must</b> (B\u1eaft bu\u1ed9c/C\u1ea7n thi\u1ebft). <br>\ud83d\udca1 Nh\u1ea5n m\u1ea1nh t\u00ednh quan tr\u1ecdng c\u1ee7a vi\u1ec7c ki\u1ec3m tra thi\u1ebft b\u1ecb.", "difficulty": "medium"}, {"id": "ex5-54", "part": 5, "type": "vocabulary", "question": "The organizing committee is looking for a _____ with a seating capacity of at least 500.", "options": ["venture", "vessel", "venue", "vehicle"], "answer": 2, "explanation": "\u2705 <b>Venue</b> (\u0110\u1ecba \u0111i\u1ec3m t\u1ed5 ch\u1ee9c). <br>\ud83d\udca1 T\u1eeb chuy\u00ean d\u1ee5ng cho n\u01a1i di\u1ec5n ra s\u1ef1 ki\u1ec7n/ti\u1ec7c/h\u1ed9i th\u1ea3o.", "difficulty": "medium"}, {"id": "ex5-55", "part": 5, "type": "vocabulary", "question": "A formal _____ will be sent to all distinguished guests by the end of the week.", "options": ["invention", "invitation", "intention", "instruction"], "answer": 1, "explanation": "\u2705 <b>Invitation</b> (Th\u01b0 m\u1eddi). <br>\ud83d\udca1 Th\u1ee7 t\u1ee5c g\u1eedi th\u01b0 m\u1eddi cho c\u00e1c kh\u00e1ch m\u1eddi quan tr\u1ecdng.", "difficulty": "medium"}, {"id": "ex5-56", "part": 5, "type": "vocabulary", "question": "The banquet hall was _____ decorated for the company's silver jubilee celebration.", "options": ["elegantly", "urgently", "randomly", "silently"], "answer": 0, "explanation": "\u2705 <b>Elegantly</b> (Trang nh\u00e3). <br>\ud83d\udca1 Tr\u1ea1ng t\u1eeb ph\u00f9 h\u1ee3p \u0111\u1ec3 m\u00f4 t\u1ea3 kh\u00f4ng gian ti\u1ec7c sang tr\u1ecdng.", "difficulty": "medium"}, {"id": "ex5-57", "part": 5, "type": "vocabulary", "question": "We need to hire an _____ to provide simultaneous translation for the delegates.", "options": ["investor", "inspector", "instructor", "interpreter"], "answer": 3, "explanation": "\u2705 <b>Interpreter</b> (Phi\u00ean d\u1ecbch vi\u00ean tr\u1ef1c ti\u1ebfp). <br>\ud83d\udca1 Kh\u00e1c v\u1edbi translator (d\u1ecbch vi\u1ebft).", "difficulty": "medium"}, {"id": "ex5-58", "part": 5, "type": "subject-verb", "question": "Neither of the proposed investment plans _____ viable in the current economic climate.", "options": ["being", "are", "is", "been"], "answer": 2, "explanation": "\u2705 <b>Is</b>. <br>\ud83d\udca1 <i>M\u1eb9o ETS:</i> 'Neither of + N s\u1ed1 nhi\u1ec1u' v\u1eabn chia \u0111\u1ed9ng t\u1eeb \u1edf s\u1ed1 \u00edt.", "difficulty": "medium"}, {"id": "ex5-59", "part": 5, "type": "vocabulary", "question": "The bank's new mobile app allows customers to _____ funds between accounts instantly.", "options": ["translate", "transfer", "transform", "transcribe"], "answer": 1, "explanation": "\u2705 <b>Transfer</b> (Chuy\u1ec3n kho\u1ea3n). <br>\ud83d\udca1 Thu\u1eadt ng\u1eef chuy\u1ec3n ti\u1ec1n trong ng\u00e2n h\u00e0ng.", "difficulty": "medium"}, {"id": "b9-5-1", "part": 5, "type": "noun-clauses", "question": "The real estate agent explained _____ the property taxes are calculated for commercial buildings.", "options": ["that", "what", "how", "which"], "answer": 2, "explanation": "\u2705 <b>How</b> (M\u1ec7nh \u0111\u1ec1 danh t\u1eeb). <br>\ud83d\udca1 Gi\u1ea3i th\u00edch 'c\u00e1ch th\u1ee9c' (how) m\u00e0 c\u00e1i g\u00ec \u0111\u00f3 v\u1eadn h\u00e0nh.", "difficulty": "medium"}, {"id": "b9-5-2", "part": 5, "type": "noun-clauses", "question": "Whether the board approves the zoning changes _____ yet to be officially announced.", "options": ["is", "are", "have", "has"], "answer": 0, "explanation": "\u2705 <b>Is</b>. <br>\ud83d\udca1 C\u1ea3 m\u1ed9t m\u1ec7nh \u0111\u1ec1 danh t\u1eeb 'Whether S + V' l\u00e0m ch\u1ee7 ng\u1eef lu\u00f4n chia \u0111\u1ed9ng t\u1eeb s\u1ed1 \u00edt.", "difficulty": "medium"}, {"id": "b9-5-3", "part": 5, "type": "adverb-time", "question": "The news anchor reported that the summit had concluded _____ the final statement was released.", "options": ["since", "just as", "until", "shortly before"], "answer": 3, "explanation": "\u2705 <b>Shortly before</b> (Ngay tr\u01b0\u1edbc khi). <br>\ud83d\udca1 C\u1ee5m tr\u1ea1ng t\u1eeb th\u1eddi gian ch\u1ec9 s\u1ef1 ki\u1ec7n x\u1ea3y ra li\u1ec1n k\u1ec1.", "difficulty": "medium"}, {"id": "b9-5-4", "part": 5, "type": "vocabulary-context", "question": "The retail chain decided to _____ its inventory management system to reduce seasonal waste.", "options": ["overlap", "overlook", "overhaul", "overtake"], "answer": 2, "explanation": "\u2705 <b>Overhaul</b> (Ki\u1ec3m tra v\u00e0 s\u1eeda ch\u1eefa to\u00e0n b\u1ed9/c\u1ea3i t\u1ed5). <br>\ud83d\udca1 Ng\u1eef c\u1ea3nh n\u00e2ng c\u1ea5p h\u1ec7 th\u1ed1ng qu\u1ea3n l\u00fd.", "difficulty": "medium"}, {"id": "b9-5-5", "part": 5, "type": "inversion", "question": "Only after the signature is verified _____ the funds be released to the seller.", "options": ["the bank will", "has the bank", "will the bank", "the bank has"], "answer": 2, "explanation": "\u2705 <b>Will the bank</b> (\u0110\u1ea3o ng\u1eef). <br>\ud83d\udca1 C\u1ea5u tr\u00fac 'Only after + N/V-ing/Clause + Tr\u1ee3 \u0111\u1ed9ng t\u1eeb + S + V'.", "difficulty": "hard"}, {"id": "b9-5-6", "part": 5, "type": "inversion", "question": "Under no circumstances _____ employees share their login credentials with third parties.", "options": ["should", "employees should", "do", "must"], "answer": 0, "explanation": "\u2705 <b>Should</b> (\u0110\u1ea3o ng\u1eef). <br>\ud83d\udca1 'Under no circumstances + Tr\u1ee3 \u0111\u1ed9ng t\u1eeb + S + V' (Quy \u0111\u1ecbnh b\u1eaft bu\u1ed9c/Kh\u00f4ng \u0111\u01b0\u1ee3c ph\u00e9p).", "difficulty": "hard"}, {"id": "b9-5-7", "part": 5, "type": "quantifiers", "question": "There is _____ evidence to suggest that the new solar panels are 30% more efficient than the previous model.", "options": ["ample", "many", "very", "few"], "answer": 0, "explanation": "\u2705 <b>Ample</b> (Phong ph\u00fa/D\u01b0 d\u1ea3). <br>\ud83d\udca1 'Ample evidence' l\u00e0 collocation th\u01b0\u1eddng d\u00f9ng trong b\u00e1o c\u00e1o khoa h\u1ecdc/k\u1ef9 thu\u1eadt.", "difficulty": "medium"}, {"id": "b9-5-8", "part": 5, "type": "subjunctive", "question": "The company handbook mandates that every employee _____ the safety workshop annually.", "options": ["attended", "attends", "attend", "attending"], "answer": 2, "explanation": "\u2705 <b>Attend</b> (Gi\u00e1 \u0111\u1ecbnh c\u00e1ch). <br>\ud83d\udca1 C\u1ea5u tr\u00fac 'Mandate/Require/Suggest + that + S + V-inf'.", "difficulty": "medium"}, {"id": "b9-5-9", "part": 5, "type": "subjunctive", "question": "It is essential that the legal department _____ all contracts before they are signed by the CEO.", "options": ["reviews", "reviewed", "review", "is reviewing"], "answer": 2, "explanation": "\u2705 <b>Review</b> (Gi\u00e1 \u0111\u1ecbnh c\u00e1ch). <br>\ud83d\udca1 It is essential/important/vital + that + S + V-inf.", "difficulty": "medium"}, {"id": "b9-5-10", "part": 5, "type": "prep-structures", "question": "Contrary _____ popular belief, the increase in automation has actually created more specialized jobs.", "options": ["to", "with", "at", "on"], "answer": 0, "explanation": "\u2705 <b>To</b>. <br>\ud83d\udca1 C\u1ee5m c\u1ed1 \u0111\u1ecbnh: 'Contrary to...' (Tr\u00e1i ng\u01b0\u1ee3c v\u1edbi...).", "difficulty": "medium"}, {"id": "b9-5-11", "part": 5, "type": "word-form", "question": "The _____ of the building was completed ahead of schedule despite the heavy rains.", "options": ["construct", "constructed", "constructive", "construction"], "answer": 3, "explanation": "\u2705 <b>Construction</b> (Danh t\u1eeb).", "difficulty": "medium"}, {"id": "b9-5-12", "part": 5, "type": "vocabulary", "question": "The new CEO has a _____ for identifying untapped market opportunities.", "options": ["track", "knack", "lack", "sack"], "answer": 1, "explanation": "\u2705 <b>Knack</b> (N\u0103ng khi\u1ebfu/S\u1edf tr\u01b0\u1eddng). <br>\ud83d\udca1 'Have a knack for V-ing' l\u00e0 m\u1ed9t collocation hay.", "difficulty": "medium"}, {"id": "b9-5-13", "part": 5, "type": "prepositions", "question": "The merger is contingent _____ the approval of the regulatory commission.", "options": ["to", "on", "with", "for"], "answer": 1, "explanation": "\u2705 <b>On</b>. <br>\ud83d\udca1 'Contingent on' = t\u00f9y thu\u1ed9c v\u00e0o.", "difficulty": "medium"}, {"id": "b9-5-14", "part": 5, "type": "conjunction", "question": "_____ the high cost of raw materials, the company managed to maintain its profit margins.", "options": ["Because", "Despite", "Although", "Unless"], "answer": 1, "explanation": "\u2705 <b>Despite</b> + C\u1ee5m danh t\u1eeb.", "difficulty": "medium"}, {"id": "b9-5-15", "part": 5, "type": "verb-tense", "question": "Our team _____ on this project for six months by the time it launches next August.", "options": ["will work", "works", "has been working", "will have been working"], "answer": 3, "explanation": "Future Perfect Continuous: \"will have been working\" = s\u1ebd \u0111\u00e3 \u0111ang l\u00e0m vi\u1ec7c li\u00ean t\u1ee5c \u0111\u1ebfn th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai.", "difficulty": "hard"}, {"id": "b9-5-16", "part": 5, "type": "passive", "question": "The faulty components _____ by the quality control team during the initial inspection.", "options": ["discovered", "discover", "were discovered", "were discovering"], "answer": 2, "explanation": "Were discovered \u2192 b\u1ecb \u0111\u1ed9ng qu\u00e1 kh\u1ee9 \u0111\u01a1n (Past Simple Passive): S + was/were + V3. \"Artifacts\" l\u00e0 danh t\u1eeb s\u1ed1 nhi\u1ec1u \u2192 \"were discovered\".", "difficulty": "medium"}, {"id": "b9-5-17", "part": 5, "type": "conditionals", "question": "If the interest rates _____ further, many small businesses would struggle to repay their loans.", "options": ["rise", "rose", "had risen", "risen"], "answer": 1, "explanation": "\u2705 <b>Rose</b> (\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 2).", "difficulty": "medium"}, {"id": "b9-5-18", "part": 5, "type": "word-form", "question": "The manager was highly _____ of the new marketing proposal.", "options": ["supportive", "support", "supportively", "supported"], "answer": 0, "explanation": "\u2705 <b>Supportive</b> (T\u00ednh t\u1eeb).", "difficulty": "easy"}, {"id": "b9-5-19", "part": 5, "type": "quantifiers", "question": "Only _____ people attended the seminar due to the unexpected snowstorm.", "options": ["many", "a little", "a few", "few"], "answer": 2, "explanation": "\u2705 <b>A few</b> (M\u1ed9t v\u00e0i - s\u1ed1 \u00edt).", "difficulty": "medium"}, {"id": "b9-5-20", "part": 5, "type": "pronoun", "question": "The directors organized the gala _____ without any help from outside event planners.", "options": ["them", "their", "themselves", "they"], "answer": 2, "explanation": "\u2705 <b>Themselves</b> (Ch\u00ednh h\u1ecd).", "difficulty": "medium"}, {"id": "b9-5-21", "part": 5, "type": "modal", "question": "You _____ submit your expense reports by the end of each month to avoid delays in reimbursement.", "options": ["should", "could", "might", "would"], "answer": 0, "explanation": "Should \u2192 modal di\u1ec5n t\u1ea3 l\u1eddi khuy\u00ean ho\u1eb7c \u0111\u1ec1 xu\u1ea5t. Ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh khuy\u1ebfn ngh\u1ecb nh\u00e2n vi\u00ean.", "difficulty": "medium"}, {"id": "b9-5-22", "part": 5, "type": "gerund-infinitive", "question": "The company considers _____ its operations to South America next year.", "options": ["expanding", "to expand", "expand", "expanded"], "answer": 0, "explanation": "\"Consider + V-ing\" = c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh. \"Expanding\" l\u00e0 V-ing t\u00e2n ng\u1eef. \"Consider to expand\" sai. \"Consider + V-ing\" gi\u1ed1ng \"enjoy/avoid/suggest + V-ing\".", "difficulty": "medium"}, {"id": "b9-5-23", "part": 5, "type": "comparison", "question": "The new processor is significantly _____ than the one used in the previous model.", "options": ["fast", "fastest", "faster", "fastly"], "answer": 2, "explanation": "Faster \u2192 so s\u00e1nh h\u01a1n c\u1ee7a \"fast\" (1 \u00e2m ti\u1ebft: + -er). \"More faster\" sai v\u00ec double comparative.", "difficulty": "medium"}, {"id": "b9-5-24", "part": 5, "type": "participles", "question": "_____ by the success of the pilot program, the board decided to implement it nationwide.", "options": ["Encourage", "Encouraging", "Encouraged", "Encourages"], "answer": 2, "explanation": "\u2705 <b>Encouraged</b> (Ph\u00e2n t\u1eeb ho\u00e0n th\u00e0nh b\u1ecb \u0111\u1ed9ng).", "difficulty": "medium"}, {"id": "b9-5-25", "part": 5, "type": "subject-verb", "question": "Each of the new employees _____ a mentor during the first month of training.", "options": ["assigns", "are assigned", "assign", "is assigned"], "answer": 3, "explanation": "\u2705 <b>Is assigned</b> (Each of + N s\u1ed1 nhi\u1ec1u + V s\u1ed1 \u00edt).", "difficulty": "medium"}, {"id": "b9-5-26", "part": 5, "type": "vocabulary", "question": "The legal team is working to _____ the terms of the settlement before the court hearing.", "options": ["final", "finalize", "finalising", "finally"], "answer": 2, "explanation": "\"Working to finalize the terms\" = \u0111ang ho\u00e0n thi\u1ec7n \u0111i\u1ec1u kho\u1ea3n. \"Finalize\" (V) sau to-infinitive. \"Finalising\" = V-ing (sai sau \"to\"); \"finally\" = ph\u00f3 t\u1eeb (sai).", "difficulty": "medium"}, {"id": "b9-5-27", "part": 5, "type": "prepositions", "question": "The office is conveniently located _____ walking distance of the subway station.", "options": ["at", "in", "by", "within"], "answer": 3, "explanation": "\"Within walking distance\" = trong kho\u1ea3ng c\u00e1ch \u0111i b\u1ed9. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"within + walking/driving distance of\".", "difficulty": "medium"}, {"id": "b9-5-28", "part": 5, "type": "conjunction", "question": "The system is currently offline _____ maintenance work is being performed.", "options": ["so", "because", "but", "while"], "answer": 3, "explanation": "While \u2192 li\u00ean t\u1eeb th\u1eddi gian/t\u01b0\u01a1ng ph\u1ea3n. N\u1ed1i hai m\u1ec7nh \u0111\u1ec1 c\u00f3 c\u00f9ng th\u1eddi gian ho\u1eb7c tr\u00e1i ng\u01b0\u1ee3c nhau.", "difficulty": "medium"}, {"id": "b9-5-29", "part": 5, "type": "verb-tense", "question": "The researcher _____ her findings at the international conference next week.", "options": ["presented", "will present", "presents", "has presented"], "answer": 1, "explanation": "Will present \u2192 t\u01b0\u01a1ng lai \u0111\u01a1n di\u1ec5n t\u1ea3 s\u1ef1 ki\u1ec7n \u0111\u00e3 l\u00ean k\u1ebf ho\u1ea1ch. T\u1eeb kh\u00f3a \"next week\" \u2192 Future Simple.", "difficulty": "medium"}, {"id": "b9-5-30", "part": 5, "type": "adverb-time", "question": "The merger will be finalized _____ the shareholders give their approval.", "options": ["meanwhile", "once", "during", "since"], "answer": 1, "explanation": "Once \u2192 ngay khi (as soon as). M\u1ec7nh \u0111\u1ec1 th\u1eddi gian + hi\u1ec7n t\u1ea1i thay t\u01b0\u01a1ng lai: Once + present \u2192 future main clause.", "difficulty": "medium"}, {"id": "b9-5-31", "part": 5, "type": "vocabulary-context", "question": "To stay competitive, the firm must _____ new technologies into its production process.", "options": ["integrate", "implicate", "indicate", "instigated"], "answer": 0, "explanation": "\u2705 <b>Integrate</b> (T\u00edch h\u1ee3p).", "difficulty": "medium"}, {"id": "b9-5-32", "part": 5, "type": "prep-structures", "question": "Employees are selected based _____ their experience and technical skills.", "options": ["for", "with", "at", "on"], "answer": 3, "explanation": "Based on \u2192 c\u1ee5m gi\u1edbi t\u1eeb c\u00f3 ngh\u0129a \"d\u1ef1a tr\u00ean, c\u0103n c\u1ee9 v\u00e0o\". Ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh \u0111\u01b0a ra quy\u1ebft \u0111\u1ecbnh d\u1ef1a tr\u00ean d\u1eef li\u1ec7u.", "difficulty": "medium"}, {"id": "b9-5-33", "part": 5, "type": "inversion", "question": "Rarely _____ seen such a high level of dedication in a junior employee.", "options": ["the manager has", "the manager did", "did the manager", "has the manager"], "answer": 3, "explanation": "Has the manager \u2192 \u0111\u1ea3o ng\u1eef v\u1edbi \"Only after\": Only after + N/clause \u2192 tr\u1ee3 \u0111\u1ed9ng t\u1eeb + S + V. Th\u00ec hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh \u2192 \"has\".", "difficulty": "hard"}, {"id": "b9-5-34", "part": 5, "type": "quantifiers", "question": "_____ information regarding the new benefits package is available on the internal portal.", "options": ["Many", "A few", "Further", "Long"], "answer": 2, "explanation": "\u2705 <b>Further</b> (Th\u00eam th\u00f4ng tin).", "difficulty": "medium"}, {"id": "b9-5-35", "part": 5, "type": "business-english", "question": "Attached is the _____ for tomorrow's executive board meeting.", "options": ["agenda", "address", "affidavit", "agency"], "answer": 0, "explanation": "\u2705 <b>Agenda</b> (Ch\u01b0\u01a1ng tr\u00ecnh ngh\u1ecb s\u1ef1).", "difficulty": "medium"}, {"id": "b9-5-36", "part": 5, "type": "subjunctive", "question": "It is vital that the safety protocols _____ followed strictly at all times.", "options": ["be", "are", "being", "to be"], "answer": 0, "explanation": "Be \u2192 subjunctive b\u1ecb \u0111\u1ed9ng sau \"It is imperative that\": S + be + V3. Kh\u00f4ng chia theo s\u1ed1 \u00edt/nhi\u1ec1u, kh\u00f4ng d\u00f9ng \"is/was\".", "difficulty": "hard"}, {"id": "b9-5-37", "part": 5, "type": "word-form", "question": "The CEO was impressed by the _____ shown by the research team.", "options": ["creative", "created", "creatively", "creativity"], "answer": 3, "explanation": "\u2705 <b>Creativity</b> (Danh t\u1eeb).", "difficulty": "medium"}, {"id": "b9-5-38", "part": 5, "type": "vocabulary", "question": "The warehouse operates at full _____ during the holiday shopping season.", "options": ["capture", "capacity", "capital", "caption"], "answer": 1, "explanation": "Capacity \u2192 s\u1ee9c ch\u1ee9a, n\u0103ng l\u1ef1c (danh t\u1eeb). Ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh \"the hall has a capacity of 500 people\".", "difficulty": "medium"}, {"id": "b9-5-39", "part": 5, "type": "prepositions", "question": "Please refrain _____ making personal phone calls during office hours.", "options": ["to", "with", "from", "at"], "answer": 2, "explanation": "Refrain from \u2192 c\u1ee5m c\u1ed1 \u0111\u1ecbnh \"refrain from + V-ing\" = ki\u00eang/tr\u00e1nh l\u00e0m g\u00ec. \u0110\u00e2y l\u00e0 collocation trang tr\u1ecdng.", "difficulty": "medium"}, {"id": "b9-5-40", "part": 5, "type": "conjunction", "question": "_____ the weather was poor, the flight departed on schedule.", "options": ["Because", "Unless", "Despite", "Although"], "answer": 3, "explanation": "Although \u2192 li\u00ean t\u1eeb nh\u01b0\u1ee3ng b\u1ed9 + clause (S+V). C\u00e2u c\u00f3 hai \u00fd t\u01b0\u01a1ng ph\u1ea3n \u2192 although/even though.", "difficulty": "medium"}, {"id": "ex-vt-01", "type": "verb-tense", "question": "By the time the CEO arrived, the board members _____ waiting for an hour.", "options": ["have been", "are", "were", "had been"], "answer": 3, "explanation": "Past perfect continuous di\u1ec5n t\u1ea3 h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra li\u00ean t\u1ee5c tr\u01b0\u1edbc m\u1ed9t th\u1eddi \u0111i\u1ec3m trong qu\u00e1 kh\u1ee9.", "difficulty": "medium"}, {"id": "ex-vt-02", "type": "verb-tense", "question": "The company _____ its annual report every December since it was founded.", "options": ["has published", "publishes", "published", "will publish"], "answer": 0, "explanation": "'Since' + kho\u1ea3ng th\u1eddi gian \u2192 d\u00f9ng Present Perfect.", "difficulty": "medium"}, {"id": "ex-vt-03", "type": "verb-tense", "question": "Sales figures _____ dramatically last quarter compared to the same period last year.", "options": ["rise", "have risen", "rose", "will rise"], "answer": 2, "explanation": "'Last quarter' l\u00e0 d\u1ea5u hi\u1ec7u th\u00ec Past Simple.", "difficulty": "easy"}, {"id": "ex-vt-04", "type": "verb-tense", "question": "If the merger _____ approved, both companies will need to restructure.", "options": ["was", "is", "were", "will be"], "answer": 1, "explanation": "C\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1: If + hi\u1ec7n t\u1ea1i \u0111\u01a1n, will + \u0111\u1ed9ng t\u1eeb nguy\u00ean th\u1ec3.", "difficulty": "medium"}, {"id": "ex-vt-05", "type": "verb-tense", "question": "The client _____ the proposal by 5 p.m. tomorrow, so we must finish it today.", "options": ["expects", "expected", "has expected", "will be expecting"], "answer": 3, "explanation": "Future Continuous di\u1ec5n t\u1ea3 h\u00e0nh \u0111\u1ed9ng \u0111ang x\u1ea3y ra t\u1ea1i th\u1eddi \u0111i\u1ec3m c\u1ee5 th\u1ec3 trong t\u01b0\u01a1ng lai.", "difficulty": "medium"}, {"id": "ex-vt-06", "type": "verb-tense", "question": "Our team _____ on this project for three months when the deadline finally arrives.", "options": ["will have been working", "will work", "has worked", "works"], "answer": 0, "explanation": "Future Perfect Continuous nh\u1ea5n m\u1ea1nh th\u1eddi gian k\u00e9o d\u00e0i \u0111\u1ebfn m\u1ed9t \u0111i\u1ec3m trong t\u01b0\u01a1ng lai.", "difficulty": "hard"}, {"id": "ex-vt-07", "type": "verb-tense", "question": "The director _____ the office to the new location last Friday.", "options": ["moves", "moved", "has moved", "is moving"], "answer": 1, "explanation": "'Last Friday' x\u00e1c \u0111\u1ecbnh th\u00ec Past Simple.", "difficulty": "medium"}, {"id": "ex-vt-08", "type": "verb-tense", "question": "Profits _____ steadily since the new strategy was implemented.", "options": ["grow", "grew", "will grow", "have grown"], "answer": 3, "explanation": "'Since' + m\u1ed1c qu\u00e1 kh\u1ee9 \u2192 Present Perfect.", "difficulty": "medium"}, {"id": "ex-vt-09", "type": "verb-tense", "question": "While the accountant _____ the budget, she noticed an error.", "options": ["reviewed", "reviews", "has reviewed", "was reviewing"], "answer": 3, "explanation": "Past Continuous di\u1ec5n t\u1ea3 h\u00e0nh \u0111\u1ed9ng \u0111ang x\u1ea3y ra khi m\u1ed9t h\u00e0nh \u0111\u1ed9ng kh\u00e1c xen v\u00e0o.", "difficulty": "medium"}, {"id": "ex-vt-10", "type": "verb-tense", "question": "The factory _____ over 10,000 units per day at full capacity.", "options": ["produced", "has produced", "produces", "had produced"], "answer": 2, "explanation": "S\u1ef1 th\u1eadt / th\u00f3i quen hi\u1ec7n t\u1ea1i \u2192 Present Simple.", "difficulty": "medium"}, {"id": "ex-vt-11", "type": "verb-tense", "question": "By next year, the company _____ its 50th anniversary.", "options": ["celebrates", "has celebrated", "will celebrate", "celebrated"], "answer": 2, "explanation": "'By next year' + th\u00ec Future Simple.", "difficulty": "easy"}, {"id": "ex-vt-12", "type": "verb-tense", "question": "Management _____ to introduce flexible working hours next month.", "options": ["has planned", "planned", "plans", "will have planned"], "answer": 2, "explanation": "K\u1ebf ho\u1ea1ch s\u1eafp x\u1ea3y ra trong t\u01b0\u01a1ng lai g\u1ea7n d\u00f9ng Present Simple.", "difficulty": "medium"}, {"id": "ex-vt-13", "type": "verb-tense", "question": "The consultant _____ three different proposals before the board selected one.", "options": ["submits", "submitted", "had submitted", "has submitted"], "answer": 2, "explanation": "Past Perfect di\u1ec5n t\u1ea3 h\u00e0nh \u0111\u1ed9ng ho\u00e0n th\u00e0nh tr\u01b0\u1edbc m\u1ed9t h\u00e0nh \u0111\u1ed9ng qu\u00e1 kh\u1ee9 kh\u00e1c.", "difficulty": "medium"}, {"id": "ex-vt-14", "type": "verb-tense", "question": "She _____ the conference call when the power outage occurred.", "options": ["joins", "joined", "was joining", "has joined"], "answer": 2, "explanation": "Past Continuous b\u1ecb gi\u00e1n \u0111o\u1ea1n b\u1edfi Past Simple.", "difficulty": "medium"}, {"id": "ex-vt-15", "type": "verb-tense", "question": "The marketing team _____ the campaign materials by the end of this week.", "options": ["finish", "finished", "will have finished", "has finished"], "answer": 2, "explanation": "Future Perfect di\u1ec5n t\u1ea3 h\u00e0nh \u0111\u1ed9ng ho\u00e0n th\u00e0nh tr\u01b0\u1edbc m\u1ed9t th\u1eddi \u0111i\u1ec3m trong t\u01b0\u01a1ng lai.", "difficulty": "hard"}, {"id": "ex-vt-16", "type": "verb-tense", "question": "We _____ the contract yet because negotiations are still ongoing.", "options": ["haven't signed", "didn't sign", "don't sign", "won't sign"], "answer": 0, "explanation": "'Yet' trong c\u00e2u ph\u1ee7 \u0111\u1ecbnh \u2192 Present Perfect.", "difficulty": "medium"}, {"id": "ex-vt-17", "type": "verb-tense", "question": "The new policy _____ effect as soon as the CEO signs it.", "options": ["has taken", "will take", "took", "takes"], "answer": 3, "explanation": "M\u1ec7nh \u0111\u1ec1 'as soon as' (th\u1eddi gian) d\u00f9ng Present Simple d\u00f9 \u00fd t\u01b0\u01a1ng lai.", "difficulty": "easy"}, {"id": "ex-vt-18", "type": "verb-tense", "question": "They _____ the system upgrade when the client called to report a bug.", "options": ["test", "were testing", "have tested", "had tested"], "answer": 1, "explanation": "Past Continuous di\u1ec5n t\u1ea3 h\u00e0nh \u0111\u1ed9ng \u0111ang di\u1ec5n ra khi b\u1ecb gi\u00e1n \u0111o\u1ea1n: was/were + V-ing. D\u00f9ng khi c\u00f3 \"when\" + Past Simple.", "difficulty": "medium"}, {"id": "ex-vt-19", "type": "verb-tense", "question": "The quarterly results _____ better than expected, pleasing all stakeholders.", "options": ["are", "have been", "were", "will be"], "answer": 2, "explanation": "K\u1ebft qu\u1ea3 qu\u00fd v\u1eeba r\u1ed3i \u2192 Past Simple.", "difficulty": "medium"}, {"id": "ex-vt-20", "type": "verb-tense", "question": "She _____ as CFO for the past decade and plans to retire next year.", "options": ["serves", "has served", "served", "will serve"], "answer": 1, "explanation": "\"For the past decade\" = kho\u1ea3ng th\u1eddi gian k\u00e9o \u0111\u1ebfn hi\u1ec7n t\u1ea1i \u2192 Present Perfect. D\u00f9ng \"has/have + V3\".", "difficulty": "medium"}, {"id": "ex-pv-01", "type": "passive", "question": "The annual report _____ by the finance team every December.", "options": ["prepares", "has prepared", "prepared", "is prepared"], "answer": 3, "explanation": "Ch\u1ee7 th\u1ec3 'report' l\u00e0 v\u1eadt th\u1ec3 b\u1ecb t\u00e1c \u0111\u1ed9ng \u2192 b\u1ecb \u0111\u1ed9ng Present Simple.", "difficulty": "easy"}, {"id": "ex-pv-02", "type": "passive", "question": "New employees _____ a full orientation before starting their assignments.", "options": ["are given", "give", "gave", "have given"], "answer": 0, "explanation": "'New employees' nh\u1eadn \u0111\u01b0\u1ee3c h\u00e0nh \u0111\u1ed9ng \u2192 b\u1ecb \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-pv-03", "type": "passive", "question": "The office _____ last year to accommodate the growing team.", "options": ["expands", "was expanded", "has expanded", "expanded"], "answer": 1, "explanation": "Past Passive v\u00ec h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra 'last year'.", "difficulty": "easy"}, {"id": "ex-pv-04", "type": "passive", "question": "The meeting agenda _____ to all participants before the session begins.", "options": ["distributes", "distributed", "will be distributed", "is distributing"], "answer": 2, "explanation": "Future Passive = will + be + V3. C\u00e2u b\u1ecb \u0111\u1ed9ng t\u01b0\u01a1ng lai khi kh\u00f4ng r\u00f5 ch\u1ee7 th\u1ec3 h\u00e0nh \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-pv-05", "type": "passive", "question": "The software update _____ by IT staff every quarter.", "options": ["installs", "has installed", "installed", "is installed"], "answer": 3, "explanation": "B\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n (is/are + V3) di\u1ec5n t\u1ea3 th\u00f3i quen \u0111\u1ecbnh k\u1ef3 \u1edf d\u1ea1ng b\u1ecb \u0111\u1ed9ng. Ch\u1ee7 th\u1ec3 nh\u1eadn t\u00e1c \u0111\u1ed9ng + th\u00f3i quen l\u1eb7p l\u1ea1i.", "difficulty": "easy"}, {"id": "ex-pv-06", "type": "passive", "question": "Staff are informed that personal items should _____ in the designated storage area.", "options": ["be kept", "keep", "keeping", "have kept"], "answer": 0, "explanation": "Modal Passive = modal + be + V3. V\u00ed d\u1ee5: \"must be reviewed\", \"can be submitted\". Kh\u00f4ng th\u00eam -ed sau \"be\".", "difficulty": "medium"}, {"id": "ex-pv-07", "type": "passive", "question": "The new workspace _____ to a contemporary open-plan design.", "options": ["has converted", "was converted", "converts", "converted"], "answer": 1, "explanation": "Past Simple Passive = was/were + V3. D\u00f9ng khi h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra trong qu\u00e1 kh\u1ee9 v\u00e0 ch\u1ee7 th\u1ec3 kh\u00f4ng quan tr\u1ecdng.", "difficulty": "easy"}, {"id": "ex-pv-08", "type": "passive", "question": "Complaints about workplace conditions must _____ to HR within 48 hours.", "options": ["report", "reporting", "be reported", "have reported"], "answer": 2, "explanation": "\"Must be + V3\" = b\u1eaft bu\u1ed9c ph\u1ea3i \u0111\u01b0\u1ee3c l\u00e0m (modal passive). \"Must\" + be + V3 \u2014 kh\u00f4ng ph\u1ea3i \"must + V3\" (ch\u1ee7 \u0111\u1ed9ng).", "difficulty": "medium"}, {"id": "ex-pv-09", "type": "passive", "question": "The printer on the third floor _____ since Monday due to a malfunction.", "options": ["is not used", "will not be used", "was not used", "has not been used"], "answer": 3, "explanation": "\"Since Monday\" = k\u1ec3 t\u1eeb th\u1ee9 Hai \u2192 Present Perfect Passive: \"has/have been + V3\". H\u00e0nh \u0111\u1ed9ng b\u1eaft \u0111\u1ea7u qu\u00e1 kh\u1ee9, k\u00e9o d\u00e0i \u0111\u1ebfn hi\u1ec7n t\u1ea1i.", "difficulty": "medium"}, {"id": "ex-pv-10", "type": "passive", "question": "Visitors _____ to sign in at the reception desk upon arrival.", "options": ["require", "are required", "required", "will require"], "answer": 1, "explanation": "B\u1ecb \u0111\u1ed9ng th\u1ec3 hi\u1ec7n quy \u0111\u1ecbnh/ch\u00ednh s\u00e1ch \u2192 Present Simple Passive (is/are + V3). Ch\u1ee7 ng\u1eef nh\u1eadn t\u00e1c \u0111\u1ed9ng c\u1ee7a quy t\u1eafc.", "difficulty": "medium"}, {"id": "ex-pv-11", "type": "passive", "question": "The board meeting schedule _____ twice before the final date was confirmed.", "options": ["changed", "has changed", "was changed", "is changed"], "answer": 2, "explanation": "Past Passive nh\u1ea5n m\u1ea1nh l\u1ecbch b\u1ecb thay \u0111\u1ed5i.", "difficulty": "medium"}, {"id": "ex-pv-12", "type": "passive", "question": "All expense reports must _____ by the end of the fiscal month.", "options": ["submit", "submitting", "submitted", "be submitted"], "answer": 3, "explanation": "Modal Passive = modal + be + V3 (b\u1ecb \u0111\u1ed9ng). V\u00ed d\u1ee5: must be submitted, should be reviewed, can be cancelled.", "difficulty": "medium"}, {"id": "ex-pv-13", "type": "passive", "question": "The HR manual _____ to reflect the latest employment regulations.", "options": ["has been updated", "updated", "updates", "is updating"], "answer": 0, "explanation": "Present Perfect Passive di\u1ec5n t\u1ea3 k\u1ebft qu\u1ea3 hi\u1ec7n t\u1ea1i.", "difficulty": "medium"}, {"id": "ex-pv-14", "type": "passive", "question": "The conference room _____ for the board meeting at 10 a.m.", "options": ["is reserving", "has been reserved", "will reserve", "reserves"], "answer": 1, "explanation": "Present Perfect Passive: \u0111\u00e3 \u0111\u01b0\u1ee3c \u0111\u1eb7t tr\u01b0\u1edbc.", "difficulty": "easy"}, {"id": "ex-pv-15", "type": "passive", "question": "Employees _____ encouraged to participate in the wellness program.", "options": ["were", "are", "have", "is"], "answer": 1, "explanation": "Present Simple Passive = am/is/are + V3. \"Are encouraged\" = \u0111\u01b0\u1ee3c khuy\u1ebfn kh\u00edch (s\u1ed1 nhi\u1ec1u). Kh\u00f4ng ph\u1ea3i \"is encouraged\".", "difficulty": "medium"}, {"id": "ex-pv-16", "type": "passive", "question": "The old photocopier _____ with a high-speed model last month.", "options": ["replaced", "is replaced", "has replaced", "was replaced"], "answer": 3, "explanation": "Past Simple Passive (was/were + V3) + \"last month\" \u2192 th\u1eddi \u0111i\u1ec3m x\u00e1c \u0111\u1ecbnh trong qu\u00e1 kh\u1ee9 + b\u1ecb \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-pv-17", "type": "passive", "question": "All packages _____ before they are delivered to individual departments.", "options": ["are scanned", "scan", "scanned", "scanning"], "answer": 0, "explanation": "Present Simple Passive cho quy tr\u00ecnh \u0111\u1ecbnh k\u1ef3.", "difficulty": "medium"}, {"id": "ex-pv-18", "type": "passive", "question": "The new safety guidelines _____ by management during the all-hands meeting.", "options": ["announced", "were announced", "have announced", "will announce"], "answer": 1, "explanation": "Past Passive di\u1ec5n t\u1ea3 th\u00f4ng b\u00e1o trong cu\u1ed9c h\u1ecdp.", "difficulty": "medium"}, {"id": "ex-pv-19", "type": "passive", "question": "Access to the server room can only _____ with a special security badge.", "options": ["gain", "gained", "be gained", "gaining"], "answer": 2, "explanation": "Modal + be + past participle. C\u1ea5u tr\u00fac: modal (can/must/should...) + be + V3 = modal passive.", "difficulty": "medium"}, {"id": "ex-pv-20", "type": "passive", "question": "A formal invitation _____ to each department head prior to the annual dinner.", "options": ["was sent", "send", "has sent", "sends"], "answer": 0, "explanation": "Past Simple Passive: was/were + V3. H\u00e0nh \u0111\u1ed9ng \u0111\u00e3 ho\u00e0n t\u1ea5t trong qu\u00e1 kh\u1ee9, ch\u1ee7 th\u1ec3 nh\u1eadn t\u00e1c \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-cd-01", "type": "conditionals", "question": "If the candidate _____ the experience requirements, she will be shortlisted.", "options": ["would meet", "met", "had met", "meets"], "answer": 3, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 1: If + Present Simple, will + V.", "difficulty": "medium"}, {"id": "ex-cd-02", "type": "conditionals", "question": "If we _____ more staff, we could handle the project more efficiently.", "options": ["hire", "hired", "had hired", "have hired"], "answer": 1, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 2: If + Past Simple, could + V.", "difficulty": "medium"}, {"id": "ex-cd-03", "type": "conditionals", "question": "The team _____ the deadline if they had received the files earlier.", "options": ["would meet", "will meet", "would have met", "meets"], "answer": 2, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 3: If + Past Perfect, would have + past participle.", "difficulty": "hard"}, {"id": "ex-cd-04", "type": "conditionals", "question": "Should you require further information, please _____ the HR department.", "options": ["will contact", "contacted", "contact", "contacting"], "answer": 2, "explanation": "'Should' \u0111\u1ea3o ng\u1eef = If you should... \u2192 y\u00eau c\u1ea7u, m\u1ec7nh \u0111\u1ec1 sau d\u00f9ng V nguy\u00ean th\u1ec3.", "difficulty": "medium"}, {"id": "ex-cd-05", "type": "conditionals", "question": "Were the budget _____, the company would hire ten more employees.", "options": ["so large", "the largest", "most large", "larger"], "answer": 3, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 2 \u0111\u1ea3o ng\u1eef: Were + S + adj/noun.", "difficulty": "medium"}, {"id": "ex-cd-06", "type": "conditionals", "question": "If the training program _____ successful, it will be rolled out company-wide.", "options": ["proves", "proved", "had proved", "was proving"], "answer": 0, "explanation": "C\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1: If + Present Simple \u2192 will/can/may + V. Di\u1ec5n t\u1ea3 \u0111i\u1ec1u ki\u1ec7n c\u00f3 th\u1ec3 x\u1ea3y ra trong th\u1ef1c t\u1ebf.", "difficulty": "medium"}, {"id": "ex-cd-07", "type": "conditionals", "question": "Had the applicant _____ the portfolio earlier, she might have been hired.", "options": ["submits", "submit", "submitted", "submitting"], "answer": 2, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 3 \u0111\u1ea3o ng\u1eef: Had + S + past participle.", "difficulty": "hard"}, {"id": "ex-cd-08", "type": "conditionals", "question": "Unless employees _____ the code of conduct, disciplinary action may follow.", "options": ["are followed", "followed", "follow", "will follow"], "answer": 2, "explanation": "Unless = if not \u2192 d\u00f9ng Present Simple trong m\u1ec7nh \u0111\u1ec1 \u0111i\u1ec1u ki\u1ec7n.", "difficulty": "medium"}, {"id": "ex-cd-09", "type": "conditionals", "question": "If the performance review _____ positive, she will receive a bonus.", "options": ["be", "was", "were", "is"], "answer": 3, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 1: If + Present Simple.", "difficulty": "medium"}, {"id": "ex-cd-10", "type": "conditionals", "question": "The company _____ more quickly if HR streamlined the onboarding process.", "options": ["grows", "grew", "will grow", "would grow"], "answer": 3, "explanation": "C\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 2: If + Past Simple \u2192 would + V. Di\u1ec5n t\u1ea3 \u0111i\u1ec1u ki\u1ec7n kh\u00f4ng th\u1ef1c \u1edf hi\u1ec7n t\u1ea1i.", "difficulty": "medium"}, {"id": "ex-cd-11", "type": "conditionals", "question": "Provided that all references _____ out, the offer will be made.", "options": ["are checked", "checked", "check", "have checked"], "answer": 0, "explanation": "'Provided that' + Present Passive = \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1.", "difficulty": "medium"}, {"id": "ex-cd-12", "type": "conditionals", "question": "If she _____ the interview tomorrow, she would be very nervous.", "options": ["attended", "attends", "had attended", "will attend"], "answer": 0, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 2 (gi\u1ea3 \u0111\u1ecbnh hi\u1ec7n t\u1ea1i/t\u01b0\u01a1ng lai).", "difficulty": "medium"}, {"id": "ex-cd-13", "type": "conditionals", "question": "The layoffs _____ avoided had the company planned its budget more carefully.", "options": ["could be", "could have been", "can be", "will have been"], "answer": 1, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 3: could have been + past participle.", "difficulty": "hard"}, {"id": "ex-cd-14", "type": "conditionals", "question": "In case the applicant _____ the test, a retake will be offered.", "options": ["failed", "fails", "has failed", "will fail"], "answer": 1, "explanation": "'In case' + Present Simple trong c\u00e2u \u0111i\u1ec1u ki\u1ec7n.", "difficulty": "medium"}, {"id": "ex-cd-15", "type": "conditionals", "question": "If I _____ you, I would negotiate for a higher starting salary.", "options": ["am", "be", "was", "were"], "answer": 3, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 2 v\u1edbi 'If I were you'.", "difficulty": "medium"}, {"id": "ex-cd-16", "type": "conditionals", "question": "The department _____ the training budget if there are budget cuts.", "options": ["loses", "will lose", "would lose", "lost"], "answer": 1, "explanation": "C\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1: If + Present Simple \u2192 will + V. K\u1ebft qu\u1ea3 x\u1ea3y ra khi \u0111i\u1ec1u ki\u1ec7n \u0111\u01b0\u1ee3c th\u1ecfa m\u00e3n.", "difficulty": "medium"}, {"id": "ex-cd-17", "type": "conditionals", "question": "We _____ an outside consultant if our internal team had had more expertise.", "options": ["needn't hire", "wouldn't have hired", "won't hire", "didn't hire"], "answer": 1, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 3: wouldn't have + past participle.", "difficulty": "medium"}, {"id": "ex-cd-18", "type": "conditionals", "question": "As long as all documents _____, the visa application will proceed.", "options": ["submit", "are submitted", "submitted", "will submit"], "answer": 1, "explanation": "'As long as' + Present Passive = \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1.", "difficulty": "medium"}, {"id": "ex-cd-19", "type": "conditionals", "question": "If the firm _____ to expand overseas, it would need additional legal counsel.", "options": ["plans", "will plan", "would plan", "planned"], "answer": 3, "explanation": "\u0110i\u1ec1u ki\u1ec7n lo\u1ea1i 2: If + Past Simple.", "difficulty": "medium"}, {"id": "ex-cd-20", "type": "conditionals", "question": "The candidate _____ the position unless she improves her technical skills.", "options": ["won't get", "wouldn't get", "doesn't get", "hadn't gotten"], "answer": 0, "explanation": "'Unless' + Present Simple = \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1 ph\u1ee7 \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "ex-wf-01", "type": "word-form", "question": "The new product launch was an outstanding _____ for the marketing team.", "options": ["achieve", "achieved", "achievement", "achievable"], "answer": 2, "explanation": "Sau m\u1ea1o t\u1eeb 'an' \u2192 c\u1ea7n danh t\u1eeb 'achievement'.", "difficulty": "medium"}, {"id": "ex-wf-02", "type": "word-form", "question": "The sales team showed remarkable _____ in handling difficult clients.", "options": ["profess", "professionalism", "professional", "profession"], "answer": 1, "explanation": "C\u1ea7n danh t\u1eeb tr\u1eebu t\u01b0\u1ee3ng sau t\u00ednh t\u1eeb 'remarkable'.", "difficulty": "medium"}, {"id": "ex-wf-03", "type": "word-form", "question": "Marketing specialists must be _____ skilled in data analysis.", "options": ["particularly", "particular", "particulars", "particularize"], "answer": 0, "explanation": "C\u1ea7n tr\u1ea1ng t\u1eeb b\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb 'skilled'.", "difficulty": "medium"}, {"id": "ex-wf-04", "type": "word-form", "question": "The _____ of the new campaign exceeded all expectations.", "options": ["effect", "effective", "effectively", "effectiveness"], "answer": 3, "explanation": "Ch\u1ee7 ng\u1eef c\u1ee7a c\u00e2u c\u1ea7n danh t\u1eeb 'effectiveness'.", "difficulty": "easy"}, {"id": "ex-wf-05", "type": "word-form", "question": "The brand's _____ among younger consumers has increased significantly.", "options": ["popular", "popularize", "popularly", "popularity"], "answer": 3, "explanation": "Ch\u1ee7 ng\u1eef c\u1ea7n danh t\u1eeb 'popularity'.", "difficulty": "medium"}, {"id": "ex-wf-06", "type": "word-form", "question": "An _____ marketing strategy can dramatically increase brand awareness.", "options": ["effective", "effectively", "effect", "effects"], "answer": 0, "explanation": "T\u00ednh t\u1eeb 'effective' b\u1ed5 ngh\u0129a cho danh t\u1eeb 'strategy'.", "difficulty": "medium"}, {"id": "ex-wf-07", "type": "word-form", "question": "The team's _____ to the new branding guidelines was immediate.", "options": ["adapt", "adaptation", "adapted", "adaptable"], "answer": 1, "explanation": "C\u1ea7n danh t\u1eeb l\u00e0m ch\u1ee7 ng\u1eef c\u00e2u. Danh t\u1eeb \u0111\u1ee9ng tr\u01b0\u1edbc \u0111\u1ed9ng t\u1eeb ch\u00ednh. X\u00e1c \u0111\u1ecbnh h\u1eadu t\u1ed1 danh t\u1eeb: -tion/-ment/-ness/-ity.", "difficulty": "medium"}, {"id": "ex-wf-08", "type": "word-form", "question": "The company plans to _____ its product line to include eco-friendly options.", "options": ["expansion", "expanded", "expand", "expanse"], "answer": 2, "explanation": "Sau 'to' l\u00e0 \u0111\u1ed9ng t\u1eeb nguy\u00ean th\u1ec3 'expand'.", "difficulty": "medium"}, {"id": "ex-wf-09", "type": "word-form", "question": "Customers have shown strong _____ to the redesigned packaging.", "options": ["response", "responsive", "responsiveness", "respond"], "answer": 0, "explanation": "'Strong' + danh t\u1eeb \u2192 'response'.", "difficulty": "medium"}, {"id": "ex-wf-10", "type": "word-form", "question": "The _____ of digital advertising has transformed the marketing landscape.", "options": ["arose", "rising", "risen", "rise"], "answer": 3, "explanation": "'The' + danh t\u1eeb 'rise' l\u00e0m ch\u1ee7 ng\u1eef.", "difficulty": "medium"}, {"id": "ex-wf-11", "type": "word-form", "question": "She has a great _____ for identifying emerging market trends.", "options": ["able", "ability", "ably", "enables"], "answer": 1, "explanation": "'A great' + danh t\u1eeb \u2192 'ability'.", "difficulty": "medium"}, {"id": "ex-wf-12", "type": "word-form", "question": "The launch event was _____ attended by over five hundred people.", "options": ["good", "well", "better", "best"], "answer": 1, "explanation": "Tr\u1ea1ng t\u1eeb 'well' b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'attended'.", "difficulty": "medium"}, {"id": "ex-wf-13", "type": "word-form", "question": "The campaign created significant _____ about the new product line.", "options": ["aware", "awares", "awaken", "awareness"], "answer": 3, "explanation": "Danh t\u1eeb 'awareness' sau t\u00ednh t\u1eeb 'significant'.", "difficulty": "medium"}, {"id": "ex-wf-14", "type": "word-form", "question": "A _____ analysis of the market data revealed new growth opportunities.", "options": ["comprehensive", "comprehend", "comprehensively", "comprehension"], "answer": 0, "explanation": "T\u00ednh t\u1eeb 'comprehensive' b\u1ed5 ngh\u0129a cho danh t\u1eeb 'analysis'.", "difficulty": "hard"}, {"id": "ex-wf-15", "type": "word-form", "question": "The marketing director spoke _____ about the importance of customer retention.", "options": ["passionate", "passionately", "passion", "passioned"], "answer": 1, "explanation": "Tr\u1ea1ng t\u1eeb 'passionately' b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'spoke'.", "difficulty": "medium"}, {"id": "ex-wf-16", "type": "word-form", "question": "The _____ of the new ad campaign was met with positive reviews.", "options": ["releasing", "release", "released", "releases"], "answer": 1, "explanation": "\"The\" + danh t\u1eeb: v\u1ecb tr\u00ed sau \"the\" y\u00eau c\u1ea7u danh t\u1eeb, kh\u00f4ng ph\u1ea3i \u0111\u1ed9ng t\u1eeb hay t\u00ednh t\u1eeb. \"Release\" (n) = s\u1ef1 ph\u00e1t h\u00e0nh.", "difficulty": "medium"}, {"id": "ex-wf-17", "type": "word-form", "question": "Sales figures indicate a _____ trend in consumer demand.", "options": ["growing", "grown", "grow", "growth"], "answer": 0, "explanation": "T\u00ednh t\u1eeb d\u1ea1ng -ing 'growing' b\u1ed5 ngh\u0129a cho 'trend'.", "difficulty": "easy"}, {"id": "ex-wf-18", "type": "word-form", "question": "The _____ team submitted their quarterly projections ahead of schedule.", "options": ["financial", "finance", "financing", "financed"], "answer": 0, "explanation": "T\u00ednh t\u1eeb 'financial' b\u1ed5 ngh\u0129a cho danh t\u1eeb 'team'.", "difficulty": "medium"}, {"id": "ex-wf-19", "type": "word-form", "question": "The product _____ has been overwhelmingly positive according to surveys.", "options": ["receive", "reception", "received", "receptive"], "answer": 1, "explanation": "Danh t\u1eeb 'reception' l\u00e0m ch\u1ee7 ng\u1eef.", "difficulty": "medium"}, {"id": "ex-wf-20", "type": "word-form", "question": "The strategy was _____ designed to appeal to international consumers.", "options": ["specific", "specifics", "specifying", "specifically"], "answer": 3, "explanation": "Tr\u1ea1ng t\u1eeb 'specifically' b\u1ed5 ngh\u0129a cho 'designed'.", "difficulty": "medium"}, {"id": "ex-pp-01", "type": "prepositions", "question": "The finance department submitted the budget proposal _____ schedule.", "options": ["ahead of", "next to", "due to", "in spite of"], "answer": 0, "explanation": "'Ahead of schedule' = tr\u01b0\u1edbc th\u1eddi h\u1ea1n.", "difficulty": "medium"}, {"id": "ex-pp-02", "type": "prepositions", "question": "The company's profit increased _____ 12% last fiscal year.", "options": ["to", "by", "for", "at"], "answer": 1, "explanation": "T\u0103ng/gi\u1ea3m theo t\u1ef7 l\u1ec7 d\u00f9ng 'by'.", "difficulty": "easy"}, {"id": "ex-pp-03", "type": "prepositions", "question": "Investors are concerned _____ the rising interest rates.", "options": ["at", "of", "about", "on"], "answer": 2, "explanation": "'Concerned about' = lo ng\u1ea1i v\u1ec1.", "difficulty": "easy"}, {"id": "ex-pp-04", "type": "prepositions", "question": "The budget was allocated _____ different departments based on their needs.", "options": ["through", "along", "over", "across"], "answer": 3, "explanation": "'Allocated across' = ph\u00e2n b\u1ed5 cho nhi\u1ec1u b\u1ed9 ph\u1eadn.", "difficulty": "medium"}, {"id": "ex-pp-05", "type": "prepositions", "question": "The invoice must be paid _____ 30 days of receipt.", "options": ["within", "until", "during", "after"], "answer": 0, "explanation": "'Within 30 days' = trong v\u00f2ng 30 ng\u00e0y.", "difficulty": "easy"}, {"id": "ex-pp-06", "type": "prepositions", "question": "The CFO presented the financial results _____ behalf of the CEO.", "options": ["in", "on", "at", "for"], "answer": 1, "explanation": "'On behalf of' = thay m\u1eb7t cho.", "difficulty": "easy"}, {"id": "ex-pp-07", "type": "prepositions", "question": "The shares are currently trading _____ a premium.", "options": ["on", "in", "at", "by"], "answer": 2, "explanation": "'Trading at a premium' = giao d\u1ecbch \u1edf m\u1ee9c gi\u00e1 cao h\u01a1n.", "difficulty": "easy"}, {"id": "ex-pp-08", "type": "prepositions", "question": "The company has been operating _____ a loss for two consecutive quarters.", "options": ["with", "in", "on", "at"], "answer": 3, "explanation": "'Operating at a loss' = ho\u1ea1t \u0111\u1ed9ng thua l\u1ed7.", "difficulty": "easy"}, {"id": "ex-pp-09", "type": "prepositions", "question": "She is responsible _____ overseeing the company's financial reporting.", "options": ["for", "of", "about", "in"], "answer": 0, "explanation": "'Responsible for' = ch\u1ecbu tr\u00e1ch nhi\u1ec7m v\u1ec1.", "difficulty": "medium"}, {"id": "ex-pp-10", "type": "prepositions", "question": "The board approved the proposal _____ a vote of 7 to 2.", "options": ["in", "with", "by", "at"], "answer": 2, "explanation": "'By a vote' = th\u00f4ng qua b\u1ecf phi\u1ebfu.", "difficulty": "easy"}, {"id": "ex-pp-11", "type": "prepositions", "question": "Expenses were cut _____ order to improve the bottom line.", "options": ["on", "by", "for", "in"], "answer": 3, "explanation": "'In order to' = \u0111\u1ec3, nh\u1eb1m m\u1ee5c \u0111\u00edch.", "difficulty": "easy"}, {"id": "ex-pp-12", "type": "prepositions", "question": "The company's revenue is _____ line with analysts' expectations.", "options": ["in", "on", "at", "by"], "answer": 0, "explanation": "\"In line with\" = ph\u00f9 h\u1ee3p v\u1edbi, nh\u1ea5t qu\u00e1n v\u1edbi. C\u1ee5m gi\u1edbi t\u1eeb trang tr\u1ecdng d\u00f9ng trong v\u0103n phong kinh doanh.", "difficulty": "easy"}, {"id": "ex-pp-13", "type": "prepositions", "question": "The CFO was praised _____ her ability to reduce costs without layoffs.", "options": ["at", "for", "by", "in"], "answer": 1, "explanation": "'Praised for' = \u0111\u01b0\u1ee3c khen v\u00ec \u0111i\u1ec1u g\u00ec \u0111\u00f3.", "difficulty": "medium"}, {"id": "ex-pp-14", "type": "prepositions", "question": "All travel expenses must be approved _____ advance by your manager.", "options": ["at", "on", "in", "by"], "answer": 2, "explanation": "\"In advance\" = tr\u01b0\u1edbc, tr\u01b0\u1edbc th\u1eddi h\u1ea1n. C\u1ee5m ph\u00f3 t\u1eeb c\u1ed1 \u0111\u1ecbnh, kh\u00f4ng th\u00eam gi\u1edbi t\u1eeb kh\u00e1c.", "difficulty": "easy"}, {"id": "ex-pp-15", "type": "prepositions", "question": "The new tax regulations will come _____ effect next January.", "options": ["in", "onto", "on", "into"], "answer": 3, "explanation": "'Come into effect' = c\u00f3 hi\u1ec7u l\u1ef1c.", "difficulty": "medium"}, {"id": "ex-pp-16", "type": "prepositions", "question": "The accountant specializes _____ corporate tax planning.", "options": ["in", "on", "for", "at"], "answer": 0, "explanation": "\"Specializes in\" = chuy\u00ean v\u1ec1 (l\u0129nh v\u1ef1c). C\u1ee5m c\u1ed1 \u0111\u1ecbnh: specialize + in + noun/V-ing.", "difficulty": "easy"}, {"id": "ex-pp-17", "type": "prepositions", "question": "The quarterly earnings fell short _____ market expectations.", "options": ["from", "of", "in", "off"], "answer": 1, "explanation": "'Fall short of' = kh\u00f4ng \u0111\u1ea1t \u0111\u01b0\u1ee3c.", "difficulty": "medium"}, {"id": "ex-pp-18", "type": "prepositions", "question": "The firm operates _____ strict compliance with financial regulations.", "options": ["at", "on", "in", "by"], "answer": 2, "explanation": "'In compliance with' = tu\u00e2n th\u1ee7 theo.", "difficulty": "easy"}, {"id": "ex-pp-19", "type": "prepositions", "question": "Capital gains taxes apply _____ profits from asset sales.", "options": ["at", "on", "for", "to"], "answer": 3, "explanation": "\"Apply to\" = \u00e1p d\u1ee5ng cho (\u0111\u1ed1i t\u01b0\u1ee3ng). Ph\u00e2n bi\u1ec7t: apply for (xin vi\u1ec7c) vs apply to (\u00e1p d\u1ee5ng v\u00e0o).", "difficulty": "easy"}, {"id": "ex-pp-20", "type": "prepositions", "question": "The merger was completed _____ record time, surprising industry analysts.", "options": ["at", "in", "by", "on"], "answer": 1, "explanation": "'In record time' = trong th\u1eddi gian k\u1ef7 l\u1ee5c.", "difficulty": "easy"}, {"id": "ex-cj-01", "type": "conjunction", "question": "The new software is user-friendly, _____ it requires a steep learning curve initially.", "options": ["so", "but", "because", "although"], "answer": 1, "explanation": "Hai v\u1ebf t\u01b0\u01a1ng ph\u1ea3n trong m\u1ed9t c\u00e2u, kh\u00f4ng c\u00f3 li\u00ean t\u1eeb ph\u1ee5 \u2192 d\u00f9ng \"but\" (FANBOYS). \"But\" n\u1ed1i hai m\u1ec7nh \u0111\u1ec1 \u0111\u1ed9c l\u1eadp.", "difficulty": "medium"}, {"id": "ex-cj-02", "type": "conjunction", "question": "_____ the system was updated, response times improved significantly.", "options": ["Unless", "While", "Once", "Despite"], "answer": 2, "explanation": "'Once' = ngay sau khi, th\u1ec3 hi\u1ec7n k\u1ebft qu\u1ea3 sau h\u00e0nh \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-cj-03", "type": "conjunction", "question": "The software can be customized _____ it meets each client's specific needs.", "options": ["in spite of", "provided that", "even though", "so that"], "answer": 3, "explanation": "'So that' = \u0111\u1ec3 m\u00e0, di\u1ec5n t\u1ea3 m\u1ee5c \u0111\u00edch.", "difficulty": "medium"}, {"id": "ex-cj-04", "type": "conjunction", "question": "_____ the data is backed up regularly, there is no risk of permanent loss.", "options": ["As long as", "Even though", "Although", "Despite"], "answer": 0, "explanation": "'As long as' = mi\u1ec5n l\u00e0, \u0111i\u1ec1u ki\u1ec7n.", "difficulty": "medium"}, {"id": "ex-cj-05", "type": "conjunction", "question": "The tech team worked overnight _____ they could deliver the update on time.", "options": ["despite", "so that", "however", "although"], "answer": 1, "explanation": "\"So that\" = \u0111\u1ec3 (m\u1ee5c \u0111\u00edch), di\u1ec5n t\u1ea3 k\u1ebft qu\u1ea3 mong mu\u1ed1n. Kh\u00e1c v\u1edbi \"so\" (k\u1ebft qu\u1ea3) v\u00e0 \"in order to\" (m\u1ee5c \u0111\u00edch + to-V).", "difficulty": "medium"}, {"id": "ex-cj-06", "type": "conjunction", "question": "We will adopt the new system _____ the costs are justified by efficiency gains.", "options": ["whereas", "in spite of", "provided that", "because of"], "answer": 2, "explanation": "'Provided that' = v\u1edbi \u0111i\u1ec1u ki\u1ec7n l\u00e0.", "difficulty": "medium"}, {"id": "ex-cj-07", "type": "conjunction", "question": "The app was praised for its design _____ users reported some performance issues.", "options": ["therefore", "so", "because", "although"], "answer": 3, "explanation": "'Although' = m\u1eb7c d\u00f9, t\u01b0\u01a1ng ph\u1ea3n.", "difficulty": "medium"}, {"id": "ex-cj-08", "type": "conjunction", "question": "_____ AI tools have become common, many companies still lack the skills to use them.", "options": ["Although", "Because", "Since", "So"], "answer": 0, "explanation": "'Although' m\u1edf \u0111\u1ea7u m\u1ec7nh \u0111\u1ec1 nh\u01b0\u1ee3ng b\u1ed9.", "difficulty": "medium"}, {"id": "ex-cj-09", "type": "conjunction", "question": "You can upgrade your subscription _____ contact our sales team for a custom plan.", "options": ["nor", "or", "but", "yet"], "answer": 1, "explanation": "Hai l\u1ef1a ch\u1ecdn ngang b\u1eb1ng nhau \u2192 'or'.", "difficulty": "medium"}, {"id": "ex-cj-10", "type": "conjunction", "question": "The update was released _____ several bugs had been fixed by the engineering team.", "options": ["unless", "before", "while", "after"], "answer": 3, "explanation": "'After' di\u1ec5n t\u1ea3 th\u1ee9 t\u1ef1 th\u1eddi gian.", "difficulty": "medium"}, {"id": "ex-cj-11", "type": "conjunction", "question": "The system crashed _____ the team had just saved all their work.", "options": ["just as", "in case", "so that", "even so"], "answer": 0, "explanation": "'Just as' = ngay khi, \u0111\u00fang l\u00fac.", "difficulty": "medium"}, {"id": "ex-cj-12", "type": "conjunction", "question": "_____ being expensive, the new server significantly improved processing speed.", "options": ["Although", "Despite", "However", "Whereas"], "answer": 1, "explanation": "'Despite' + gerund/noun phrase = m\u1eb7c d\u00f9.", "difficulty": "medium"}, {"id": "ex-cj-13", "type": "conjunction", "question": "The engineers tested the prototype _____ it was approved for mass production.", "options": ["because", "after", "before", "unless"], "answer": 2, "explanation": "\"Before\" = tr\u01b0\u1edbc khi (th\u1eddi gian). M\u1ec7nh \u0111\u1ec1 \"before + clause\" di\u1ec5n t\u1ea3 h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra sau \u0111\u00f3.", "difficulty": "medium"}, {"id": "ex-cj-14", "type": "conjunction", "question": "_____ the internet connection is stable, video conferences run smoothly.", "options": ["Despite", "Before", "Unless", "When"], "answer": 3, "explanation": "'When' = khi, \u0111i\u1ec1u ki\u1ec7n lu\u00f4n \u0111\u00fang.", "difficulty": "medium"}, {"id": "ex-cj-15", "type": "conjunction", "question": "The startup attracted investors _____ its innovative approach to data security.", "options": ["because of", "in spite of", "so that", "whereas"], "answer": 0, "explanation": "'Because of' + noun phrase = nguy\u00ean nh\u00e2n.", "difficulty": "medium"}, {"id": "ex-cj-16", "type": "conjunction", "question": "The platform is intuitive _____ first-time users can navigate it easily.", "options": ["so that", "so", "because", "though"], "answer": 1, "explanation": "'So' = k\u1ebft qu\u1ea3; 'so that' = m\u1ee5c \u0111\u00edch. \u1ede \u0111\u00e2y c\u1ea7n 'so' (k\u1ebft qu\u1ea3).", "difficulty": "medium"}, {"id": "ex-cj-17", "type": "conjunction", "question": "The team finished the project on time _____ they faced many technical obstacles.", "options": ["because", "so that", "even though", "since"], "answer": 2, "explanation": "'Even though' = m\u1eb7c d\u00f9 (nh\u1ea5n m\u1ea1nh h\u01a1n 'although').", "difficulty": "medium"}, {"id": "ex-cj-18", "type": "conjunction", "question": "Please update the drivers _____ connecting the external devices.", "options": ["because", "after", "while", "before"], "answer": 3, "explanation": "'Before' + gerund = tr\u01b0\u1edbc khi l\u00e0m g\u00ec.", "difficulty": "medium"}, {"id": "ex-cj-19", "type": "conjunction", "question": "_____ her team works efficiently, they rarely need overtime.", "options": ["Since", "If", "Unless", "While"], "answer": 0, "explanation": "\"Since\" = v\u00ec, b\u1edfi v\u00ec (nguy\u00ean nh\u00e2n). Ngo\u00e0i ngh\u0129a th\u1eddi gian, \"since\" c\u00f2n di\u1ec5n t\u1ea3 l\u00fd do trong v\u0103n trang tr\u1ecdng.", "difficulty": "medium"}, {"id": "ex-cj-20", "type": "conjunction", "question": "The developer fixed the issue _____ the client's feedback arrived.", "options": ["despite", "in order to", "as soon as", "whereas"], "answer": 2, "explanation": "\"As soon as\" = ngay khi. M\u1ec7nh \u0111\u1ec1 th\u1eddi gian: as soon as + Present Simple \u2192 Future main clause.", "difficulty": "medium"}, {"id": "ex-pr-01", "type": "pronoun", "question": "Each department must submit _____ budget proposal by Friday.", "options": ["they", "their", "its", "it's"], "answer": 2, "explanation": "'Each department' = s\u1ed1 \u00edt \u2192 s\u1edf h\u1eefu c\u00e1ch 'its'.", "difficulty": "medium"}, {"id": "ex-pr-02", "type": "pronoun", "question": "The production team exceeded _____ targets for the third consecutive quarter.", "options": ["their", "its", "them", "it"], "answer": 0, "explanation": "'The production team' trong ng\u1eef c\u1ea3nh nh\u00f3m ng\u01b0\u1eddi \u2192 'their'.", "difficulty": "medium"}, {"id": "ex-pr-03", "type": "pronoun", "question": "Neither the supervisor nor the workers have completed _____ safety training.", "options": ["their", "its", "them", "his"], "answer": 0, "explanation": "'Neither...nor' \u2192 \u0111\u1ed9ng t\u1eeb chia theo danh t\u1eeb g\u1ea7n nh\u1ea5t (workers - s\u1ed1 nhi\u1ec1u) \u2192 'their'.", "difficulty": "medium"}, {"id": "ex-pr-04", "type": "pronoun", "question": "The quality control team conducted _____ inspection before the products were shipped.", "options": ["their", "its", "them", "itself"], "answer": 1, "explanation": "'The quality control team' = t\u1eadp th\u1ec3 s\u1ed1 \u00edt \u2192 'its'.", "difficulty": "medium"}, {"id": "ex-pr-05", "type": "pronoun", "question": "The manager asked everyone to bring _____ ID to the security briefing.", "options": ["them", "its", "their", "his"], "answer": 2, "explanation": "'Everyone' \u2192 \u0111\u1ea1i t\u1eeb 'their' (trung t\u00ednh, s\u1ed1 nhi\u1ec1u theo ngh\u0129a).", "difficulty": "medium"}, {"id": "ex-pr-06", "type": "pronoun", "question": "The factory workers are proud of _____ ability to maintain high standards.", "options": ["themselves", "its", "they", "their"], "answer": 3, "explanation": "Ch\u1ee7 ng\u1eef 'workers' \u2192 s\u1edf h\u1eefu c\u00e1ch 'their'.", "difficulty": "medium"}, {"id": "ex-pr-07", "type": "pronoun", "question": "The CEO _____ reviewed the quality report before presenting it to the board.", "options": ["himself", "herself", "itself", "themselves"], "answer": 0, "explanation": "'The CEO' (male) \u2192 \u0111\u1ea1i t\u1eeb ph\u1ea3n th\u00e2n 'himself' nh\u1ea5n m\u1ea1nh.", "difficulty": "medium"}, {"id": "ex-pr-08", "type": "pronoun", "question": "The new machinery installed _____ without any assistance from outside technicians.", "options": ["themselves", "itself", "himself", "ourselves"], "answer": 1, "explanation": "'Machinery' l\u00e0 v\u1eadt \u2192 \u0111\u1ea1i t\u1eeb ph\u1ea3n th\u00e2n 'itself'.", "difficulty": "medium"}, {"id": "ex-pr-09", "type": "pronoun", "question": "The plant manager and _____ team worked overtime to meet the order.", "options": ["their", "its", "his", "them"], "answer": 2, "explanation": "'The plant manager' (ng\u01b0\u1eddi) \u2192 'his team'.", "difficulty": "medium"}, {"id": "ex-pr-10", "type": "pronoun", "question": "Every employee is expected to follow _____ designated safety procedures.", "options": ["their", "its", "them", "he"], "answer": 0, "explanation": "'Every employee' \u2192 \u0111\u1ea1i t\u1eeb trung t\u00ednh 'their'.", "difficulty": "medium"}, {"id": "ex-pr-11", "type": "pronoun", "question": "The assembly line workers exceeded _____ daily quota by 20%.", "options": ["its", "their", "them", "it"], "answer": 1, "explanation": "Ch\u1ee7 ng\u1eef s\u1ed1 nhi\u1ec1u 'workers' \u2192 'their'.", "difficulty": "medium"}, {"id": "ex-pr-12", "type": "pronoun", "question": "The manufacturer guarantees that _____ products meet international quality standards.", "options": ["it", "their", "its", "themselves"], "answer": 2, "explanation": "'The manufacturer' (t\u1ed5 ch\u1ee9c s\u1ed1 \u00edt) \u2192 'its'.", "difficulty": "medium"}, {"id": "ex-pr-13", "type": "pronoun", "question": "After the product recall, the company re-evaluated _____ entire supply chain.", "options": ["itself", "their", "them", "its"], "answer": 3, "explanation": "'The company' = t\u1ed5 ch\u1ee9c s\u1ed1 \u00edt \u2192 'its'.", "difficulty": "medium"}, {"id": "ex-pr-14", "type": "pronoun", "question": "Both the inspector and the technician submitted _____ findings to management.", "options": ["their", "its", "them", "his"], "answer": 0, "explanation": "'Both...and' + ch\u1ee7 ng\u1eef s\u1ed1 nhi\u1ec1u \u2192 'their'.", "difficulty": "medium"}, {"id": "ex-pr-15", "type": "pronoun", "question": "The maintenance crew serviced the machines by _____.", "options": ["itself", "themselves", "himself", "one another"], "answer": 1, "explanation": "\"Serviced the machines by themselves\" = t\u1ef1 b\u1ea3o d\u01b0\u1ee1ng m\u00e1y m\u00f3c (kh\u00f4ng c\u00f3 s\u1ef1 gi\u00fap \u0111\u1ee1). \"By themselves\" = reflexive idiom. \"Itself\" = s\u1ed1 \u00edt (sai v\u00ec \"crew\" = s\u1ed1 nhi\u1ec1u); \"one another\" = l\u1eabn nhau (sai ngh\u0129a).", "difficulty": "easy"}, {"id": "ex-pr-16", "type": "pronoun", "question": "The defect was discovered during _____ routine inspection.", "options": ["their", "its", "a", "the"], "answer": 2, "explanation": "'A routine inspection' = m\u1ea1o t\u1eeb kh\u00f4ng x\u00e1c \u0111\u1ecbnh.", "difficulty": "easy"}, {"id": "ex-pr-17", "type": "pronoun", "question": "If anyone notices a safety hazard, _____ should report it immediately.", "options": ["them", "he", "it", "they"], "answer": 3, "explanation": "'Anyone' \u2192 \u0111\u1ea1i t\u1eeb trung t\u00ednh s\u1ed1 \u00edt/nhi\u1ec1u 'they'.", "difficulty": "medium"}, {"id": "ex-pr-18", "type": "pronoun", "question": "The production supervisor and her assistant updated _____ records.", "options": ["their", "its", "them", "his"], "answer": 0, "explanation": "Hai ch\u1ee7 ng\u1eef (hai ng\u01b0\u1eddi/nh\u00f3m ng\u01b0\u1eddi) \u2192 s\u1edf h\u1eefu t\u00ednh t\u1eeb \"their\" (c\u1ee7a h\u1ecd) tr\u01b0\u1edbc danh t\u1eeb.", "difficulty": "medium"}, {"id": "ex-pr-19", "type": "pronoun", "question": "The quality report speaks for _____, showing clear evidence of improvement.", "options": ["themselves", "itself", "himself", "ourselves"], "answer": 1, "explanation": "'The report' (v\u1eadt) \u2192 \u0111\u1ea1i t\u1eeb ph\u1ea3n th\u00e2n 'itself'.", "difficulty": "medium"}, {"id": "ex-pr-20", "type": "pronoun", "question": "One of the managers presented _____ findings at the industry conference.", "options": ["them", "their", "its", "his"], "answer": 3, "explanation": "'One of the managers' \u2192 s\u1ed1 \u00edt, th\u01b0\u1eddng d\u00f9ng 'his/her'.", "difficulty": "medium"}, {"id": "ex-rc-01", "type": "relative-clause", "question": "The hotel _____ we stayed during the conference was fully booked for next month.", "options": ["whom", "which", "who", "where"], "answer": 3, "explanation": "'Hotel' l\u00e0 n\u01a1i ch\u1ed1n \u2192 m\u1ec7nh \u0111\u1ec1 quan h\u1ec7 n\u01a1i ch\u1ed1n d\u00f9ng 'where'.", "difficulty": "medium"}, {"id": "ex-rc-02", "type": "relative-clause", "question": "The travel agent _____ booked our flights has years of experience.", "options": ["who", "which", "where", "whose"], "answer": 0, "explanation": "'Travel agent' l\u00e0 ng\u01b0\u1eddi \u2192 d\u00f9ng 'who'.", "difficulty": "medium"}, {"id": "ex-rc-03", "type": "relative-clause", "question": "The itinerary _____ was sent to all participants included a city tour.", "options": ["who", "that", "where", "whom"], "answer": 1, "explanation": "'Itinerary' l\u00e0 v\u1eadt \u2192 d\u00f9ng 'that' ho\u1eb7c 'which'.", "difficulty": "medium"}, {"id": "ex-rc-04", "type": "relative-clause", "question": "We chose a resort _____ facilities include a spa and two swimming pools.", "options": ["that", "which", "whose", "where"], "answer": 2, "explanation": "M\u1ec7nh \u0111\u1ec1 quan h\u1ec7 s\u1edf h\u1eefu \u2192 'whose'.", "difficulty": "medium"}, {"id": "ex-rc-05", "type": "relative-clause", "question": "The tour guide, _____ spoke four languages, impressed all the visitors.", "options": ["that", "which", "whose", "who"], "answer": 3, "explanation": "'Tour guide' l\u00e0 ng\u01b0\u1eddi, \u0111\u00e2y l\u00e0 m\u1ec7nh \u0111\u1ec1 gi\u1ea3i th\u00edch \u2192 'who'.", "difficulty": "medium"}, {"id": "ex-rc-06", "type": "relative-clause", "question": "The airline _____ we frequently use offers a generous loyalty program.", "options": ["that", "who", "whose", "whom"], "answer": 0, "explanation": "'Airline' l\u00e0 t\u1ed5 ch\u1ee9c \u2192 d\u00f9ng 'that' ho\u1eb7c 'which'.", "difficulty": "medium"}, {"id": "ex-rc-07", "type": "relative-clause", "question": "This is the city _____ the international tourism summit will be held.", "options": ["which", "where", "that", "who"], "answer": 1, "explanation": "\"City\" l\u00e0 n\u01a1i ch\u1ed1n \u2192 d\u00f9ng \"where\" \u0111\u1ec3 thay th\u1ebf trong m\u1ec7nh \u0111\u1ec1 quan h\u1ec7. Where = in/at which.", "difficulty": "medium"}, {"id": "ex-rc-08", "type": "relative-clause", "question": "The conference room _____ the delegates gathered was equipped with modern technology.", "options": ["who", "which", "where", "that"], "answer": 2, "explanation": "N\u01a1i ch\u1ed1n (place/location) \u2192 m\u1ec7nh \u0111\u1ec1 quan h\u1ec7 d\u00f9ng \"where\". C\u00f3 th\u1ec3 thay b\u1eb1ng \"in which/at which\".", "difficulty": "medium"}, {"id": "ex-rc-09", "type": "relative-clause", "question": "The passenger _____ luggage was lost filed a complaint with the airline.", "options": ["that", "who", "which", "whose"], "answer": 3, "explanation": "S\u1edf h\u1eefu c\u00e1ch trong m\u1ec7nh \u0111\u1ec1 quan h\u1ec7 \u2192 \"whose\". D\u00f9ng cho c\u1ea3 ng\u01b0\u1eddi v\u00e0 v\u1eadt. Whose + noun = s\u1edf h\u1eefu.", "difficulty": "medium"}, {"id": "ex-rc-10", "type": "relative-clause", "question": "The company hires travel consultants _____ have extensive knowledge of Asian destinations.", "options": ["which", "who", "whose", "where"], "answer": 1, "explanation": "'Consultants' l\u00e0 ng\u01b0\u1eddi \u2192 'who'.", "difficulty": "medium"}, {"id": "ex-rc-11", "type": "relative-clause", "question": "The package tour, _____ includes accommodation and meals, is very popular.", "options": ["that", "who", "which", "whose"], "answer": 2, "explanation": "M\u1ec7nh \u0111\u1ec1 gi\u1ea3i th\u00edch v\u1ec1 v\u1eadt \u2192 'which'.", "difficulty": "medium"}, {"id": "ex-rc-12", "type": "relative-clause", "question": "The travelers _____ booked early received significant discounts.", "options": ["where", "which", "whose", "who"], "answer": 3, "explanation": "\"Travelers\" l\u00e0 ng\u01b0\u1eddi \u2192 d\u00f9ng \"who\" (ch\u1ee7 ng\u1eef) ho\u1eb7c \"whom\" (t\u00e2n ng\u1eef). \u1ede \u0111\u00e2y \"who\" l\u00e0m ch\u1ee7 ng\u1eef.", "difficulty": "medium"}, {"id": "ex-rc-13", "type": "relative-clause", "question": "The destination _____ she had always wanted to visit was finally within reach.", "options": ["that", "who", "whom", "where"], "answer": 0, "explanation": "V\u1eadt (thing/object) trong m\u1ec7nh \u0111\u1ec1 h\u1ea1n \u0111\u1ecbnh \u2192 d\u00f9ng \"that\" ho\u1eb7c \"which\". \"That\" th\u01b0\u1eddng d\u00f9ng h\u01a1n trong h\u1ea1n \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "ex-rc-14", "type": "relative-clause", "question": "The visa _____ he applied for took three weeks to process.", "options": ["who", "that", "whose", "where"], "answer": 1, "explanation": "V\u1eadt + gi\u1edbi t\u1eeb \u2192 \"that\" ho\u1eb7c \"which\" + gi\u1edbi t\u1eeb. Trong v\u0103n n\u00f3i d\u00f9ng \"that...at\", v\u0103n vi\u1ebft d\u00f9ng \"at which\".", "difficulty": "easy"}, {"id": "ex-rc-15", "type": "relative-clause", "question": "The travel blogger, _____ readers number in the millions, launched a travel app.", "options": ["which", "who", "whose", "whom"], "answer": 2, "explanation": "S\u1edf h\u1eefu c\u00e1ch \u2192 \"whose\" d\u00f9ng cho ng\u01b0\u1eddi. Whose + noun di\u1ec5n t\u1ea3 m\u1ed1i quan h\u1ec7 s\u1edf h\u1eefu.", "difficulty": "medium"}, {"id": "ex-rc-16", "type": "relative-clause", "question": "I remember the year _____ our company launched its international travel division.", "options": ["who", "where", "which", "when"], "answer": 3, "explanation": "'Year' = th\u1eddi gian \u2192 m\u1ec7nh \u0111\u1ec1 quan h\u1ec7 th\u1eddi gian d\u00f9ng 'when'.", "difficulty": "medium"}, {"id": "ex-rc-17", "type": "relative-clause", "question": "The hotel manager, to _____ we addressed our concerns, resolved the issue quickly.", "options": ["whom", "who", "which", "that"], "answer": 0, "explanation": "Gi\u1edbi t\u1eeb 'to' + \u0111\u1ea1i t\u1eeb ch\u1ec9 ng\u01b0\u1eddi \u2192 'whom'.", "difficulty": "medium"}, {"id": "ex-rc-18", "type": "relative-clause", "question": "The airport, _____ construction was completed last year, handles 30 million passengers annually.", "options": ["which", "whose", "where", "that"], "answer": 1, "explanation": "S\u1edf h\u1eefu v\u1ec1 v\u1eadt \u2192 \"whose\" c\u0169ng d\u00f9ng cho v\u1eadt trong ti\u1ebfng Anh hi\u1ec7n \u0111\u1ea1i. Whose + noun = s\u1edf h\u1eefu c\u1ee7a v\u1eadt \u0111\u00f3.", "difficulty": "medium"}, {"id": "ex-rc-19", "type": "relative-clause", "question": "This is the reason _____ many tourists prefer guided tours over independent travel.", "options": ["which", "when", "why", "where"], "answer": 2, "explanation": "'Reason' \u2192 m\u1ec7nh \u0111\u1ec1 quan h\u1ec7 l\u00fd do d\u00f9ng 'why'.", "difficulty": "medium"}, {"id": "ex-rc-20", "type": "relative-clause", "question": "The travel agency _____ handles our corporate accounts is based in Singapore.", "options": ["that", "who", "whom", "when"], "answer": 0, "explanation": "T\u1ed5 ch\u1ee9c \u2192 'that' ho\u1eb7c 'which'.", "difficulty": "medium"}, {"id": "ex-md-01", "type": "modal", "question": "All conference attendees _____ register in advance to secure their seats.", "options": ["might", "must", "could", "would"], "answer": 1, "explanation": "Must \u2192 modal di\u1ec5n t\u1ea3 b\u1eaft bu\u1ed9c (obligation). Quy \u0111\u1ecbnh ho\u1eb7c ch\u00ednh s\u00e1ch \u2192 \"must\" m\u1ea1nh h\u01a1n \"should\".", "difficulty": "medium"}, {"id": "ex-md-02", "type": "modal", "question": "The annual gala _____ be postponed due to the venue renovation.", "options": ["shall", "must", "might", "should"], "answer": 2, "explanation": "'Might' = kh\u1ea3 n\u0103ng c\u00f3 th\u1ec3 x\u1ea3y ra.", "difficulty": "medium"}, {"id": "ex-md-03", "type": "modal", "question": "Guests _____ dress formally for the awards ceremony.", "options": ["would", "might", "could", "should"], "answer": 3, "explanation": "'Should' = l\u1eddi khuy\u00ean/y\u00eau c\u1ea7u.", "difficulty": "easy"}, {"id": "ex-md-04", "type": "modal", "question": "The catering company _____ accommodate dietary restrictions if informed in advance.", "options": ["can", "must", "would", "shall"], "answer": 0, "explanation": "\"Can\" = kh\u1ea3 n\u0103ng, c\u00f3 th\u1ec3 (ability). Di\u1ec5n t\u1ea3 kh\u1ea3 n\u0103ng th\u1ef1c t\u1ebf, kh\u00f4ng ph\u1ea3i suy \u0111o\u00e1n.", "difficulty": "medium"}, {"id": "ex-md-05", "type": "modal", "question": "You _____ use the company shuttle if you don't want to drive.", "options": ["must", "may", "shall", "need"], "answer": 1, "explanation": "\"May\" = cho ph\u00e9p, \u0111\u01b0\u1ee3c ph\u00e9p (permission). V\u0103n trang tr\u1ecdng d\u00f9ng \"may\" thay \"can\" khi cho ph\u00e9p.", "difficulty": "medium"}, {"id": "ex-md-06", "type": "modal", "question": "The keynote speaker _____ have arrived by now \u2014 her flight landed an hour ago.", "options": ["must", "might", "should", "would"], "answer": 0, "explanation": "'Must have + past participle' = suy lu\u1eadn ch\u1eafc ch\u1eafn v\u1ec1 qu\u00e1 kh\u1ee9.", "difficulty": "medium"}, {"id": "ex-md-07", "type": "modal", "question": "Participants _____ leave before the closing ceremony to receive their certificates.", "options": ["must not", "might not", "should not", "could not"], "answer": 2, "explanation": "'Should not' = kh\u00f4ng n\u00ean (l\u1eddi khuy\u00ean).", "difficulty": "medium"}, {"id": "ex-md-08", "type": "modal", "question": "The event coordinator _____ have overlooked the seating arrangement, as some guests are standing.", "options": ["must", "might", "should", "would"], "answer": 0, "explanation": "'Must have + past participle' = suy lu\u1eadn m\u1ea1nh.", "difficulty": "medium"}, {"id": "ex-md-09", "type": "modal", "question": "If you wish to make a speech, you _____ notify the MC at least 30 minutes beforehand.", "options": ["might", "should", "can", "shall"], "answer": 1, "explanation": "\"Should\" = n\u00ean, \u0111\u1ec1 xu\u1ea5t (advice). M\u1ee9c \u0111\u1ed9 b\u1eaft bu\u1ed9c th\u1ea5p h\u01a1n \"must\". D\u00f9ng \u0111\u1ec3 khuy\u1ebfn ngh\u1ecb.", "difficulty": "medium"}, {"id": "ex-md-10", "type": "modal", "question": "The venue _____ hold up to 500 people comfortably.", "options": ["shall", "must", "should", "can"], "answer": 3, "explanation": "\"Can\" = c\u00f3 th\u1ec3 ch\u1ee9a, c\u00f3 s\u1ee9c ch\u1ee9a (capacity). \"The room can hold 50 people\" = s\u1ee9c ch\u1ee9a t\u1ed1i \u0111a.", "difficulty": "easy"}, {"id": "ex-md-11", "type": "modal", "question": "Attendees _____ have pre-registered, but walk-ins are welcome.", "options": ["need not", "must not", "should not", "cannot"], "answer": 0, "explanation": "\"Need not\" = kh\u00f4ng c\u1ea7n thi\u1ebft (unnecessary, but allowed). Kh\u00e1c \"must not\" (b\u1ecb c\u1ea5m ho\u00e0n to\u00e0n).", "difficulty": "medium"}, {"id": "ex-md-12", "type": "modal", "question": "Speakers _____ limit their presentations to 20 minutes.", "options": ["might", "must", "could", "shall"], "answer": 1, "explanation": "Quy \u0111\u1ecbnh c\u00f4ng ty \u2192 \"must\" (strong obligation). \"Must\" di\u1ec5n t\u1ea3 ngh\u0129a v\u1ee5 b\u1eaft bu\u1ed9c theo quy \u0111\u1ecbnh.", "difficulty": "easy"}, {"id": "ex-md-13", "type": "modal", "question": "The next corporate summit _____ take place in either Tokyo or Seoul.", "options": ["must", "shall", "may", "need"], "answer": 2, "explanation": "'May' = kh\u1ea3 n\u0103ng, ch\u01b0a ch\u1eafc ch\u1eafn.", "difficulty": "medium"}, {"id": "ex-md-14", "type": "modal", "question": "Children under 12 _____ attend the evening gala without a guardian.", "options": ["need not", "might not", "should not", "may not"], "answer": 3, "explanation": "\"May not\" = kh\u00f4ng \u0111\u01b0\u1ee3c ph\u00e9p (prohibition polite). L\u1ecbch s\u1ef1 h\u01a1n \"must not\" trong v\u0103n phong th\u01b0\u01a1ng m\u1ea1i.", "difficulty": "medium"}, {"id": "ex-md-15", "type": "modal", "question": "The organizers _____ have informed us about the change in venue earlier.", "options": ["should", "must", "might", "could"], "answer": 0, "explanation": "'Should have' = \u0111\u00e1ng l\u1ebd \u0111\u00e3 ph\u1ea3i (ph\u00ea b\u00ecnh v\u1ec1 qu\u00e1 kh\u1ee9).", "difficulty": "medium"}, {"id": "ex-md-16", "type": "modal", "question": "Photography _____ only be taken in designated areas during the ceremony.", "options": ["must", "may", "will", "should"], "answer": 1, "explanation": "\"May only\" = ch\u1ec9 \u0111\u01b0\u1ee3c ph\u00e9p (restriction). K\u1ebft h\u1ee3p \"may\" (permission) + \"only\" (limitation).", "difficulty": "medium"}, {"id": "ex-md-17", "type": "modal", "question": "The opening remarks _____ last about ten minutes according to the agenda.", "options": ["will", "must", "should", "can"], "answer": 0, "explanation": "'Will' = d\u1ef1 ki\u1ebfn ch\u1eafc ch\u1eafn theo k\u1ebf ho\u1ea1ch.", "difficulty": "medium"}, {"id": "ex-md-18", "type": "modal", "question": "We _____ not use mobile phones during the presentation, as it is distracting.", "options": ["can", "must", "might", "should"], "answer": 3, "explanation": "\"Should not\" = kh\u00f4ng n\u00ean (advice against). M\u1ee9c \u0111\u1ed9 nh\u1eb9 h\u01a1n \"must not\". D\u00f9ng \u0111\u1ec3 khuy\u00ean tr\u00e1nh.", "difficulty": "medium"}, {"id": "ex-md-19", "type": "modal", "question": "The venue reservation _____ be canceled without a fee if done 48 hours before the event.", "options": ["can", "must", "should", "will"], "answer": 0, "explanation": "'Can' = kh\u1ea3 n\u0103ng/\u0111i\u1ec1u ki\u1ec7n c\u00f3 th\u1ec3.", "difficulty": "medium"}, {"id": "ex-md-20", "type": "modal", "question": "The project team _____ have completed the event setup by midnight if they had started earlier.", "options": ["might", "should", "could", "would"], "answer": 2, "explanation": "'Could have' = l\u1ebd ra c\u00f3 th\u1ec3 (\u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 3).", "difficulty": "medium"}, {"id": "ex-gi-01", "type": "gerund-infinitive", "question": "The company stopped _____ its customers with automated responses.", "options": ["to respond", "respond", "responded", "responding"], "answer": 3, "explanation": "'Stop + gerund' = d\u1eebng h\u00e0nh \u0111\u1ed9ng. 'Stop to do' = d\u1eebng \u0111\u1ec3 l\u00e0m vi\u1ec7c kh\u00e1c.", "difficulty": "medium"}, {"id": "ex-gi-02", "type": "gerund-infinitive", "question": "We recommend _____ customer feedback forms after every service interaction.", "options": ["completing", "to complete", "completed", "complete"], "answer": 0, "explanation": "'Recommend + gerund' = \u0111\u1ec1 ngh\u1ecb.", "difficulty": "medium"}, {"id": "ex-gi-03", "type": "gerund-infinitive", "question": "The service team tried _____ all complaints within 24 hours.", "options": ["resolving", "to resolve", "resolve", "resolved"], "answer": 1, "explanation": "'Try to do' = c\u1ed1 g\u1eafng \u0111\u1ea1t m\u1ee5c \u0111\u00edch.", "difficulty": "medium"}, {"id": "ex-gi-04", "type": "gerund-infinitive", "question": "Staff members are trained _____ customer inquiries professionally.", "options": ["handling", "handle", "having handled", "to handle"], "answer": 3, "explanation": "'Trained to do' = \u0111\u01b0\u1ee3c \u0111\u00e0o t\u1ea1o \u0111\u1ec3 l\u00e0m g\u00ec.", "difficulty": "medium"}, {"id": "ex-gi-05", "type": "gerund-infinitive", "question": "The policy requires all agents _____ their conversations with customers.", "options": ["document", "documenting", "to document", "documented"], "answer": 2, "explanation": "\"Require + object + to-V\": \u0111\u1ed9ng t\u1eeb require c\u1ea7n object tr\u01b0\u1edbc to-infinitive. V\u00ed d\u1ee5: require staff to submit.", "difficulty": "medium"}, {"id": "ex-gi-06", "type": "gerund-infinitive", "question": "Customers appreciate _____ quick responses to their queries.", "options": ["receiving", "to receive", "received", "receive"], "answer": 0, "explanation": "\"Appreciate + gerund\": appreciate lu\u00f4n \u0111i v\u1edbi V-ing, kh\u00f4ng d\u00f9ng to-V. Appreciate + doing.", "difficulty": "medium"}, {"id": "ex-gi-07", "type": "gerund-infinitive", "question": "The manager allowed the team _____ flexible breaks to reduce stress.", "options": ["taking", "take", "to take", "taken"], "answer": 2, "explanation": "\"Allow + object + to-V\": allow c\u1ea7n object tr\u01b0\u1edbc infinitive. Allow someone to do something.", "difficulty": "medium"}, {"id": "ex-gi-08", "type": "gerund-infinitive", "question": "She considered _____ to a different department after the restructuring.", "options": ["to transfer", "transfer", "transferred", "transferring"], "answer": 3, "explanation": "\"Consider + gerund\": consider lu\u00f4n d\u00f9ng V-ing. Consider + doing = xem x\u00e9t vi\u1ec7c l\u00e0m g\u00ec.", "difficulty": "medium"}, {"id": "ex-gi-09", "type": "gerund-infinitive", "question": "The supervisor reminded her team _____ client data securely.", "options": ["storing", "stored", "store", "to store"], "answer": 3, "explanation": "\"Remind + object + to-V\": remind someone to do something. C\u1ea7n object gi\u1eefa \u0111\u1ed9ng t\u1eeb v\u00e0 to-V.", "difficulty": "medium"}, {"id": "ex-gi-10", "type": "gerund-infinitive", "question": "They regretted _____ the customer's complaint without proper investigation.", "options": ["to dismiss", "dismiss", "dismissing", "dismissed"], "answer": 2, "explanation": "'Regret + gerund' = h\u1ed1i ti\u1ebfc v\u1ec1 \u0111i\u1ec1u \u0111\u00e3 l\u00e0m.", "difficulty": "medium"}, {"id": "ex-gi-11", "type": "gerund-infinitive", "question": "The company is committed to _____ its customer satisfaction scores.", "options": ["improve", "improved", "improving", "improvement"], "answer": 2, "explanation": "\"Committed to + gerund\": \"to\" \u1edf \u0111\u00e2y l\u00e0 gi\u1edbi t\u1eeb, kh\u00f4ng ph\u1ea3i to-infinitive. Committed to doing.", "difficulty": "medium"}, {"id": "ex-gi-12", "type": "gerund-infinitive", "question": "He forgot _____ the refund, causing the customer additional delays.", "options": ["to process", "processed", "processing", "process"], "answer": 0, "explanation": "'Forget to do' = qu\u00ean m\u1ea5t vi\u1ec7c ph\u1ea3i l\u00e0m.", "difficulty": "medium"}, {"id": "ex-gi-13", "type": "gerund-infinitive", "question": "The agent was determined _____ the issue before the end of his shift.", "options": ["resolving", "to resolve", "resolved", "resolve"], "answer": 1, "explanation": "\"Determined to + V\": determined \u0111i v\u1edbi to-infinitive. Determined to do = quy\u1ebft t\u00e2m l\u00e0m g\u00ec.", "difficulty": "medium"}, {"id": "ex-gi-14", "type": "gerund-infinitive", "question": "The team practiced _____ de-escalation techniques in a workshop.", "options": ["to use", "use", "using", "used"], "answer": 2, "explanation": "\"Practice + gerund\": practice lu\u00f4n d\u00f9ng V-ing. Practice + doing = luy\u1ec7n t\u1eadp l\u00e0m g\u00ec.", "difficulty": "medium"}, {"id": "ex-gi-15", "type": "gerund-infinitive", "question": "The company decided _____ a new chatbot to handle after-hours inquiries.", "options": ["implementing", "implemented", "implement", "to implement"], "answer": 3, "explanation": "\"Decide + to-V\": decide lu\u00f4n d\u00f9ng to-infinitive. Decide to do = quy\u1ebft \u0111\u1ecbnh l\u00e0m g\u00ec.", "difficulty": "medium"}, {"id": "ex-gi-16", "type": "gerund-infinitive", "question": "The client seemed _____ with the resolution provided by the support team.", "options": ["satisfying", "to satisfy", "satisfied", "satisfy"], "answer": 2, "explanation": "\"Seem + adjective\" ho\u1eb7c \"seem + to-V\": seem l\u00e0 linking verb, theo sau l\u00e0 adj ho\u1eb7c to-V.", "difficulty": "medium"}, {"id": "ex-gi-17", "type": "gerund-infinitive", "question": "We avoid _____ customers on hold for more than two minutes.", "options": ["to put", "putting", "put", "puts"], "answer": 1, "explanation": "\"Avoid + gerund\": avoid lu\u00f4n d\u00f9ng V-ing. Avoid + doing = tr\u00e1nh l\u00e0m g\u00ec.", "difficulty": "easy"}, {"id": "ex-gi-18", "type": "gerund-infinitive", "question": "The supervisor encouraged her team _____ proactive in anticipating customer needs.", "options": ["to be", "being", "be", "been"], "answer": 0, "explanation": "\"Encourage + object + to-V\": c\u1ea7n object tr\u01b0\u1edbc to-V. Encourage someone to do something.", "difficulty": "medium"}, {"id": "ex-gi-19", "type": "gerund-infinitive", "question": "The new hire struggled _____ with the volume of incoming calls.", "options": ["cope", "to cope", "coping", "coped"], "answer": 1, "explanation": "\"Struggle + to-V\": struggle to do = c\u1ed1 g\u1eafng (nh\u01b0ng kh\u00f3) l\u00e0m g\u00ec. D\u00f9ng to-infinitive.", "difficulty": "medium"}, {"id": "ex-gi-20", "type": "gerund-infinitive", "question": "After _____ the feedback, management decided to revise the service policy.", "options": ["to review", "review", "reviewed", "reviewing"], "answer": 3, "explanation": "\"After + gerund (V-ing)\": \"after\" l\u00e0 gi\u1edbi t\u1eeb \u2192 sau \u0111\u00f3 d\u00f9ng V-ing. After doing = sau khi l\u00e0m g\u00ec.", "difficulty": "medium"}, {"id": "ex-cm-01", "type": "comparison", "question": "This shipping route is _____ the one we used last quarter.", "options": ["the most efficient", "efficient than", "more efficient than", "more efficient"], "answer": 2, "explanation": "So s\u00e1nh h\u01a1n hai v\u1ebf \u2192 'more + adj + than'.", "difficulty": "easy"}, {"id": "ex-cm-02", "type": "comparison", "question": "The delivery time using air freight is _____ in the entire logistics network.", "options": ["as short as", "shorter than", "short", "the shortest"], "answer": 3, "explanation": "So s\u00e1nh nh\u1ea5t \u2192 'the + superlative'.", "difficulty": "medium"}, {"id": "ex-cm-03", "type": "comparison", "question": "Our warehouse is twice _____ the competitor's facility.", "options": ["as large as", "larger than", "the largest", "more large"], "answer": 0, "explanation": "'Twice as large as' = l\u1edbn g\u1ea5p \u0111\u00f4i.", "difficulty": "easy"}, {"id": "ex-cm-04", "type": "comparison", "question": "The new logistics software processes orders _____ than the old system.", "options": ["the fastest", "faster", "more fast", "most fast"], "answer": 1, "explanation": "Tr\u1ea1ng t\u1eeb so s\u00e1nh h\u01a1n: 'faster'.", "difficulty": "medium"}, {"id": "ex-cm-05", "type": "comparison", "question": "Ground shipping is _____ expensive than air freight, but it takes longer.", "options": ["little", "fewer", "less", "least"], "answer": 2, "explanation": "'Less + adjective + than' = \u00edt...h\u01a1n.", "difficulty": "medium"}, {"id": "ex-cm-06", "type": "comparison", "question": "The _____ a package weighs, the higher the shipping cost.", "options": ["more heavy", "heavy", "heaviest", "heavier"], "answer": 3, "explanation": "'The + comparative, the + comparative' c\u1ea5u tr\u00fac song song.", "difficulty": "easy"}, {"id": "ex-cm-07", "type": "comparison", "question": "This cargo ship can carry _____ containers than the previous model.", "options": ["more", "most", "much", "many"], "answer": 0, "explanation": "So s\u00e1nh h\u01a1n v\u1edbi danh t\u1eeb \u0111\u1ebfm \u0111\u01b0\u1ee3c \u2192 'more'.", "difficulty": "medium"}, {"id": "ex-cm-08", "type": "comparison", "question": "The new tracking system is _____ as reliable as the old one.", "options": ["twice", "as much", "not", "more"], "answer": 2, "explanation": "'Not as reliable as' = k\u00e9m tin c\u1eady h\u01a1n.", "difficulty": "medium"}, {"id": "ex-cm-09", "type": "comparison", "question": "Express delivery is _____ option for urgent shipments.", "options": ["better", "best", "the best", "as good as"], "answer": 2, "explanation": "\"The best\" = so s\u00e1nh nh\u1ea5t c\u1ee7a \"good\". Sau superlative th\u01b0\u1eddng c\u00f3 \"in + group\" ho\u1eb7c \"that + clause.", "difficulty": "easy"}, {"id": "ex-cm-10", "type": "comparison", "question": "Fuel costs are _____ than expected this month, reducing overall profit margins.", "options": ["higher", "highest", "high", "more high"], "answer": 0, "explanation": "So s\u00e1nh h\u01a1n \"higher than\" = cao h\u01a1n. Higher l\u00e0 d\u1ea1ng so s\u00e1nh h\u01a1n c\u1ee7a \"high\" (1 \u00e2m ti\u1ebft \u2192 +er).", "difficulty": "medium"}, {"id": "ex-cm-11", "type": "comparison", "question": "The warehouse in Region B has _____ storage capacity than the one in Region A.", "options": ["greatest", "greater", "great", "more greater"], "answer": 1, "explanation": "So s\u00e1nh h\u01a1n m\u1ed9t \u00e2m ti\u1ebft: 'greater than'.", "difficulty": "medium"}, {"id": "ex-cm-12", "type": "comparison", "question": "Our fleet of trucks is _____ modern in the entire region.", "options": ["most", "more", "the most", "the more"], "answer": 2, "explanation": "'The most + adjective' = so s\u00e1nh nh\u1ea5t.", "difficulty": "easy"}, {"id": "ex-cm-13", "type": "comparison", "question": "The customs clearance process is now _____ than it was two years ago.", "options": ["the fastest", "much fastest", "more faster", "much faster"], "answer": 3, "explanation": "'Much faster' = nhanh h\u01a1n nhi\u1ec1u (d\u00f9ng 'much' \u0111\u1ec3 nh\u1ea5n m\u1ea1nh so s\u00e1nh h\u01a1n).", "difficulty": "medium"}, {"id": "ex-cm-14", "type": "comparison", "question": "Order accuracy is _____ important factor in customer retention.", "options": ["the most", "the more", "more", "most"], "answer": 0, "explanation": "So s\u00e1nh nh\u1ea5t: 'the most important'.", "difficulty": "medium"}, {"id": "ex-cm-15", "type": "comparison", "question": "The sea freight option is not _____ fast as air freight, but it is more economical.", "options": ["so", "as", "that", "too"], "answer": 1, "explanation": "'Not as + adj + as' = so s\u00e1nh b\u1eb1ng ph\u1ee7 \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "ex-cm-16", "type": "comparison", "question": "Inventory turnover in Q3 was _____ than in Q2, indicating improved efficiency.", "options": ["more high", "highest", "higher", "the highest"], "answer": 2, "explanation": "So s\u00e1nh h\u01a1n: adj ng\u1eafn + -er + than, ho\u1eb7c more + adj d\u00e0i + than. X\u00e1c \u0111\u1ecbnh s\u1ed1 \u00e2m ti\u1ebft \u0111\u1ec3 ch\u1ecdn d\u1ea1ng \u0111\u00fang.", "difficulty": "medium"}, {"id": "ex-cm-17", "type": "comparison", "question": "The _____ efficient the route, the lower the fuel consumption.", "options": ["less", "most", "much", "more"], "answer": 3, "explanation": "Double comparative: \"The more + adj/adv, the + comparative\" = c\u00e0ng...c\u00e0ng... C\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh kh\u00f4ng th\u1ec3 \u0111\u1ed5i t\u1eeb.", "difficulty": "medium"}, {"id": "ex-cm-18", "type": "comparison", "question": "Same-day delivery is _____ option, but it is the most popular with customers.", "options": ["the costliest", "costliest", "more costly", "as costly as"], "answer": 0, "explanation": "\"The + superlative\": so s\u00e1nh nh\u1ea5t lu\u00f4n c\u1ea7n \"the\" \u0111\u1ee9ng tr\u01b0\u1edbc. The most/least + adj ho\u1eb7c the + adj-est.", "difficulty": "medium"}, {"id": "ex-cm-19", "type": "comparison", "question": "The new cargo vessels are _____ fuel-efficient than the older models.", "options": ["significant more", "significantly more", "significanlty most", "more significant"], "answer": 1, "explanation": "\"Significantly more + adj + than\" = h\u01a1n \u0111\u00e1ng k\u1ec3. Ph\u00f3 t\u1eeb \"significantly\" b\u1ed5 ngh\u0129a cho \"more\", \u0111\u1ee9ng tr\u01b0\u1edbc, kh\u00f4ng th\u1ec3 \u0111\u1ee9ng sau.", "difficulty": "medium"}, {"id": "ex-cm-20", "type": "comparison", "question": "Processing time for international shipments is _____ longer than for domestic ones.", "options": ["consideration", "consider", "considerable", "considerably"], "answer": 3, "explanation": "Tr\u1ea1ng t\u1eeb 'considerably' b\u1ed5 ngh\u0129a so s\u00e1nh h\u01a1n.", "difficulty": "medium"}, {"id": "ex-pt-01", "type": "participles", "question": "_____ in bright yellow, the safety vests are visible from a distance.", "options": ["Colored", "Coloring", "Having colored", "To color"], "answer": 0, "explanation": "Past participle trong m\u1ec7nh \u0111\u1ec1 r\u00fat g\u1ecdn b\u1ecb \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-pt-02", "type": "participles", "question": "The worker, _____ the safety manual, knew exactly what to do in an emergency.", "options": ["reads", "having read", "reading", "read"], "answer": 1, "explanation": "'Having + past participle' di\u1ec5n t\u1ea3 h\u00e0nh \u0111\u1ed9ng ho\u00e0n th\u00e0nh tr\u01b0\u1edbc.", "difficulty": "medium"}, {"id": "ex-pt-03", "type": "participles", "question": "_____ the proper procedures, employees can avoid most workplace accidents.", "options": ["To follow", "Followed", "Following", "Having followed"], "answer": 2, "explanation": "Hi\u1ec7n t\u1ea1i ph\u00e2n t\u1eeb \u1edf \u0111\u1ea7u c\u00e2u: ch\u1ee7 ng\u1eef ch\u00ednh l\u00e0m h\u00e0nh \u0111\u1ed9ng \u0111\u00f3.", "difficulty": "medium"}, {"id": "ex-pt-04", "type": "participles", "question": "The equipment, _____ regularly, showed no signs of wear.", "options": ["having maintaining", "maintaining", "to maintain", "maintained"], "answer": 3, "explanation": "Past participle trong m\u1ec7nh \u0111\u1ec1 r\u00fat g\u1ecdn b\u1ecb \u0111\u1ed9ng.", "difficulty": "easy"}, {"id": "ex-pt-05", "type": "participles", "question": "_____ by the sudden alarm, the workers evacuated the building immediately.", "options": ["Startled", "Startling", "To startle", "Having startled"], "answer": 0, "explanation": "Past participle mang ngh\u0129a b\u1ecb \u0111\u1ed9ng + tr\u1ea1ng th\u00e1i.", "difficulty": "medium"}, {"id": "ex-pt-06", "type": "participles", "question": "The chemicals, _____ as hazardous, must be stored separately.", "options": ["classifying", "classified", "to classify", "classify"], "answer": 1, "explanation": "Past participle trong m\u1ec7nh \u0111\u1ec1 r\u00fat g\u1ecdn.", "difficulty": "medium"}, {"id": "ex-pt-07", "type": "participles", "question": "_____ the risk assessment, the safety officer found several potential hazards.", "options": ["Conducting", "To conduct", "Conducted", "Having conducted"], "answer": 3, "explanation": "'Having conducted' = sau khi \u0111\u00e3 ho\u00e0n th\u00e0nh vi\u1ec7c ki\u1ec3m tra.", "difficulty": "medium"}, {"id": "ex-pt-08", "type": "participles", "question": "The report _____ the incident clearly outlined all contributing factors.", "options": ["describe", "described", "to describe", "describing"], "answer": 3, "explanation": "Hi\u1ec7n t\u1ea1i ph\u00e2n t\u1eeb b\u1ed5 ngh\u0129a cho danh t\u1eeb 'report' (\u0111ang m\u00f4 t\u1ea3).", "difficulty": "medium"}, {"id": "ex-pt-09", "type": "participles", "question": "All equipment, _____ at regular intervals, is less likely to malfunction.", "options": ["inspected", "inspecting", "to inspect", "inspect"], "answer": 0, "explanation": "Past participle mang ngh\u0129a b\u1ecb \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-pt-10", "type": "participles", "question": "_____ in protective gear, the staff entered the contaminated area.", "options": ["To dress", "Dressing", "Dressed", "Having dressing"], "answer": 2, "explanation": "Past participle = \u0111\u00e3 m\u1eb7c v\u00e0o (tr\u1ea1ng th\u00e1i).", "difficulty": "medium"}, {"id": "ex-pt-11", "type": "participles", "question": "The new safety protocol, _____ last month, has already reduced accident rates.", "options": ["having introduce", "introducing", "introduce", "introduced"], "answer": 3, "explanation": "Past participle trong m\u1ec7nh \u0111\u1ec1 r\u00fat g\u1ecdn b\u1ecb \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-pt-12", "type": "participles", "question": "_____ the forklift all day, the operator needed a break.", "options": ["Having operated", "Operated", "Operate", "Operating"], "answer": 0, "explanation": "'Having operated' = sau khi \u0111\u00e3 l\u00e1i c\u1ea3 ng\u00e0y.", "difficulty": "easy"}, {"id": "ex-pt-13", "type": "participles", "question": "The manual _____ to all staff covers emergency procedures in detail.", "options": ["distributing", "distributed", "to distribute", "distribute"], "answer": 1, "explanation": "Past participle b\u1ed5 ngh\u0129a cho 'manual' (\u0111\u00e3 \u0111\u01b0\u1ee3c ph\u00e2n ph\u00e1t).", "difficulty": "medium"}, {"id": "ex-pt-14", "type": "participles", "question": "_____ through a residential area, drivers must follow reduced speed limits.", "options": ["Having passed", "Passed", "Passing", "To pass"], "answer": 2, "explanation": "Hi\u1ec7n t\u1ea1i ph\u00e2n t\u1eeb = khi \u0111ang \u0111i qua.", "difficulty": "medium"}, {"id": "ex-pt-15", "type": "participles", "question": "The workers _____ safely wore helmets and high-visibility vests at all times.", "options": ["having work", "worked", "to work", "working"], "answer": 3, "explanation": "Hi\u1ec7n t\u1ea1i ph\u00e2n t\u1eeb b\u1ed5 ngh\u0129a cho 'workers'.", "difficulty": "medium"}, {"id": "ex-pt-16", "type": "participles", "question": "_____ the spill immediately, the crew prevented further contamination.", "options": ["Containing", "Contained", "Having contained", "To contain"], "answer": 2, "explanation": "'Having contained' = sau khi \u0111\u00e3 ng\u0103n ch\u1eb7n.", "difficulty": "medium"}, {"id": "ex-pt-17", "type": "participles", "question": "The ladder, _____ incorrectly, caused the worker to fall.", "options": ["positioning", "positioned", "to position", "having positioned"], "answer": 1, "explanation": "Past participle m\u00f4 t\u1ea3 t\u00ecnh tr\u1ea1ng c\u1ee7a thang.", "difficulty": "easy"}, {"id": "ex-pt-18", "type": "participles", "question": "_____ with the correct PPE, workers can handle hazardous materials safely.", "options": ["To equip", "Equipping", "Equipped", "Being equip"], "answer": 2, "explanation": "Past participle = \u0111\u01b0\u1ee3c trang b\u1ecb (b\u1ecb \u0111\u1ed9ng).", "difficulty": "medium"}, {"id": "ex-pt-19", "type": "participles", "question": "The safety trainer, _____ in first aid, led the emergency drill.", "options": ["certifies", "certifying", "to certify", "certified"], "answer": 3, "explanation": "Past participle b\u1ed5 ngh\u0129a cho 'trainer'.", "difficulty": "medium"}, {"id": "ex-pt-20", "type": "participles", "question": "_____ the fire extinguisher, the employee quickly controlled the small blaze.", "options": ["Grabbed", "Grabbing", "Having grabbed", "To grab"], "answer": 1, "explanation": "Hi\u1ec7n t\u1ea1i ph\u00e2n t\u1eeb: h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra c\u00f9ng l\u00fac.", "difficulty": "medium"}, {"id": "ex-sv-01", "type": "subject-verb", "question": "Neither the loan officer nor the branch managers _____ authorized the transaction.", "options": ["has", "have", "is", "are"], "answer": 1, "explanation": "'Neither...nor' \u2192 chia theo danh t\u1eeb g\u1ea7n nh\u1ea5t (managers - s\u1ed1 nhi\u1ec1u) \u2192 'have'.", "difficulty": "medium"}, {"id": "ex-sv-02", "type": "subject-verb", "question": "The number of investment accounts _____ increased significantly this year.", "options": ["are", "have", "has", "were"], "answer": 2, "explanation": "'The number of' = s\u1ed1 \u0111\u01a1n \u2192 'has'.", "difficulty": "medium"}, {"id": "ex-sv-03", "type": "subject-verb", "question": "Each of the financial advisors _____ required to complete certification annually.", "options": ["have", "are", "were", "is"], "answer": 3, "explanation": "'Each of' + s\u1ed1 nhi\u1ec1u \u2192 \u0111\u1ed9ng t\u1eeb chia s\u1ed1 \u0111\u01a1n.", "difficulty": "medium"}, {"id": "ex-sv-04", "type": "subject-verb", "question": "The board of directors _____ scheduled a meeting to discuss the merger.", "options": ["has", "have", "are", "were"], "answer": 0, "explanation": "'Board of directors' = t\u1ed5 ch\u1ee9c s\u1ed1 \u00edt \u2192 'has'.", "difficulty": "medium"}, {"id": "ex-sv-05", "type": "subject-verb", "question": "A number of clients _____ expressed concerns about the new fee structure.", "options": ["has", "have", "is", "was"], "answer": 1, "explanation": "'A number of' = s\u1ed1 nhi\u1ec1u \u2192 'have'.", "difficulty": "medium"}, {"id": "ex-sv-06", "type": "subject-verb", "question": "Economics _____ considered a challenging subject by many banking professionals.", "options": ["was considered", "are", "is", "have been"], "answer": 2, "explanation": "T\u00ean m\u00f4n h\u1ecdc/ng\u00e0nh h\u1ecdc (economics, mathematics, physics) \u2192 lu\u00f4n d\u00f9ng \u0111\u1ed9ng t\u1eeb s\u1ed1 \u00edt d\u00f9 t\u1eadn c\u00f9ng b\u1eb1ng -s.", "difficulty": "medium"}, {"id": "ex-sv-07", "type": "subject-verb", "question": "Both the CEO and the CFO _____ presented at the investor conference.", "options": ["has", "was", "is", "were"], "answer": 3, "explanation": "'Both...and' \u2192 s\u1ed1 nhi\u1ec1u \u2192 'were'.", "difficulty": "medium"}, {"id": "ex-sv-08", "type": "subject-verb", "question": "The committee _____ divided on the issue of interest rate adjustments.", "options": ["is", "are", "was", "have"], "answer": 0, "explanation": "'The committee' l\u00e0 t\u1eadp th\u1ec3 s\u1ed1 \u00edt \u2192 'is'.", "difficulty": "medium"}, {"id": "ex-sv-09", "type": "subject-verb", "question": "Profits, along with revenue, _____ on the rise this fiscal quarter.", "options": ["is", "are", "was", "has been"], "answer": 1, "explanation": "Ch\u1ee7 ng\u1eef ch\u00ednh 'Profits' s\u1ed1 nhi\u1ec1u \u2192 'are'. C\u1ee5m 'along with' kh\u00f4ng thay \u0111\u1ed5i s\u1ed1.", "difficulty": "medium"}, {"id": "ex-sv-10", "type": "subject-verb", "question": "Twenty percent of the loan portfolio _____ classified as high-risk.", "options": ["were", "are", "have", "is"], "answer": 3, "explanation": "Ph\u1ea7n tr\u0103m + danh t\u1eeb kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c \u2192 s\u1ed1 \u00edt \u2192 'is'.", "difficulty": "medium"}, {"id": "ex-sv-11", "type": "subject-verb", "question": "The interest rate that the bank charges _____ competitive compared to peers.", "options": ["is", "are", "has", "have"], "answer": 0, "explanation": "Ch\u1ee7 ng\u1eef l\u00e0 'The interest rate' s\u1ed1 \u00edt \u2192 'is'.", "difficulty": "medium"}, {"id": "ex-sv-12", "type": "subject-verb", "question": "Every branch manager and loan officer _____ received the updated compliance guidelines.", "options": ["have", "has", "are", "is"], "answer": 1, "explanation": "'Every + noun and noun' \u2192 \u0111\u1ed9ng t\u1eeb s\u1ed1 \u00edt \u2192 'has'.", "difficulty": "medium"}, {"id": "ex-sv-13", "type": "subject-verb", "question": "The news about the interest rate hike _____ surprised investors worldwide.", "options": ["were", "have", "has", "are"], "answer": 2, "explanation": "'News' l\u00e0 danh t\u1eeb kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c \u2192 'has'.", "difficulty": "medium"}, {"id": "ex-sv-14", "type": "subject-verb", "question": "Either the account holder or the authorized representative _____ required to sign.", "options": ["were", "are", "have", "is"], "answer": 3, "explanation": "'Either...or' \u2192 chia theo danh t\u1eeb g\u1ea7n nh\u1ea5t ('representative' s\u1ed1 \u00edt) \u2192 'is'.", "difficulty": "medium"}, {"id": "ex-sv-15", "type": "subject-verb", "question": "The list of transactions _____ reviewed by the auditor every quarter.", "options": ["is", "are", "have", "were"], "answer": 0, "explanation": "\"The list\" = danh t\u1eeb s\u1ed1 \u00edt \u2192 \u0111\u1ed9ng t\u1eeb s\u1ed1 \u00edt. C\u1ee5m gi\u1edbi t\u1eeb \"of items\" kh\u00f4ng \u1ea3nh h\u01b0\u1edfng \u0111\u1ebfn s\u1ed1 c\u1ee7a ch\u1ee7 ng\u1eef.", "difficulty": "medium"}, {"id": "ex-sv-16", "type": "subject-verb", "question": "None of the loan applications _____ fully processed yet.", "options": ["has been", "have been", "is", "was"], "answer": 1, "explanation": "'None of' + danh t\u1eeb s\u1ed1 nhi\u1ec1u \u2192 th\u01b0\u1eddng d\u00f9ng s\u1ed1 nhi\u1ec1u.", "difficulty": "easy"}, {"id": "ex-sv-17", "type": "subject-verb", "question": "The team of financial analysts _____ its report every Monday morning.", "options": ["are submitted", "submit", "submits", "have submitted"], "answer": 2, "explanation": "\"The team\" = ch\u1ee7 th\u1ec3 t\u1eadp th\u1ec3 \u2192 s\u1ed1 \u00edt trong v\u0103n trang tr\u1ecdng. The team submits (kh\u00f4ng ph\u1ea3i submit).", "difficulty": "medium"}, {"id": "ex-sv-18", "type": "subject-verb", "question": "There _____ several discrepancies in the quarterly balance sheet.", "options": ["were", "is", "has", "are"], "answer": 3, "explanation": "'There are' + danh t\u1eeb s\u1ed1 nhi\u1ec1u.", "difficulty": "medium"}, {"id": "ex-sv-19", "type": "subject-verb", "question": "The data from all branches _____ compiled into a single report.", "options": ["is", "are", "have", "were"], "answer": 0, "explanation": "'The data' \u2192 danh t\u1eeb kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c \u2192 'is'.", "difficulty": "medium"}, {"id": "ex-sv-20", "type": "subject-verb", "question": "Neither the analyst nor her supervisors _____ aware of the compliance breach.", "options": ["is", "was", "were", "has"], "answer": 2, "explanation": "'Neither...nor' \u2192 g\u1ea7n nh\u1ea5t l\u00e0 'supervisors' s\u1ed1 nhi\u1ec1u \u2192 'were'.", "difficulty": "medium"}, {"id": "ex-nc-01", "type": "noun-clauses", "question": "The client asked _____ the property was available for immediate occupancy.", "options": ["which", "that", "what", "whether"], "answer": 3, "explanation": "C\u00e2u h\u1ecfi gi\u00e1n ti\u1ebfp v\u1edbi 'yes/no' \u2192 'whether'.", "difficulty": "medium"}, {"id": "ex-nc-02", "type": "noun-clauses", "question": "It is unclear _____ the building will meet the new environmental standards.", "options": ["whether", "what", "that", "which"], "answer": 0, "explanation": "M\u1ec7nh \u0111\u1ec1 danh t\u1eeb v\u1edbi 'yes/no question' \u2192 'whether'.", "difficulty": "medium"}, {"id": "ex-nc-03", "type": "noun-clauses", "question": "The report confirmed _____ renovation costs would exceed the original estimate.", "options": ["what", "that", "whether", "which"], "answer": 1, "explanation": "\"Confirm + that clause\": that d\u1eabn m\u1ec7nh \u0111\u1ec1 danh t\u1eeb l\u00e0m t\u00e2n ng\u1eef sau \"confirm\". Confirm that + S + V.", "difficulty": "medium"}, {"id": "ex-nc-04", "type": "noun-clauses", "question": "We need to determine _____ the land can be rezoned for commercial use.", "options": ["what", "that", "whether", "how"], "answer": 2, "explanation": "'Determine + whether' = x\u00e1c \u0111\u1ecbnh li\u1ec7u c\u00f3 th\u1ec3 kh\u00f4ng.", "difficulty": "medium"}, {"id": "ex-nc-05", "type": "noun-clauses", "question": "The contract specifies _____ the tenant must notify the landlord 60 days before vacating.", "options": ["whether", "what", "how", "that"], "answer": 3, "explanation": "'Specifies + that clause' = quy \u0111\u1ecbnh r\u1eb1ng.", "difficulty": "medium"}, {"id": "ex-nc-06", "type": "noun-clauses", "question": "_____ the property will appreciate in value is the key concern for investors.", "options": ["Whether", "What", "That", "How"], "answer": 0, "explanation": "M\u1ec7nh \u0111\u1ec1 danh t\u1eeb l\u00e0m ch\u1ee7 ng\u1eef: 'Whether...is...'.", "difficulty": "medium"}, {"id": "ex-nc-07", "type": "noun-clauses", "question": "The agent explained _____ the appraisal process typically takes two weeks.", "options": ["what", "that", "how", "whether"], "answer": 1, "explanation": "'Explained + that clause' = gi\u1ea3i th\u00edch r\u1eb1ng.", "difficulty": "medium"}, {"id": "ex-nc-08", "type": "noun-clauses", "question": "We should consider _____ the offer price reflects current market conditions.", "options": ["how", "what", "whether", "that"], "answer": 2, "explanation": "'Consider + whether' = xem x\u00e9t li\u1ec7u... hay kh\u00f4ng.", "difficulty": "medium"}, {"id": "ex-nc-09", "type": "noun-clauses", "question": "The inspector's report revealed _____ several structural issues needed attention.", "options": ["which", "what", "whether", "that"], "answer": 3, "explanation": "\"Revealed + that clause\": that d\u1eabn m\u1ec7nh \u0111\u1ec1 t\u00e2n ng\u1eef sau \u0111\u1ed9ng t\u1eeb t\u01b0\u1eddng thu\u1eadt. Revealed that + S + V.", "difficulty": "medium"}, {"id": "ex-nc-10", "type": "noun-clauses", "question": "It remains uncertain _____ interest rates will affect housing demand next year.", "options": ["what", "how", "that", "which"], "answer": 1, "explanation": "'Uncertain + how clause' = kh\u00f4ng ch\u1eafc ch\u1eafn nh\u01b0 th\u1ebf n\u00e0o.", "difficulty": "medium"}, {"id": "ex-nc-11", "type": "noun-clauses", "question": "The buyer wanted to know _____ the property had any outstanding mortgages.", "options": ["how", "that", "whether", "what"], "answer": 2, "explanation": "C\u00e2u h\u1ecfi gi\u00e1n ti\u1ebfp yes/no \u2192 'whether'.", "difficulty": "medium"}, {"id": "ex-nc-12", "type": "noun-clauses", "question": "_____ drives property prices up in urban areas is a combination of demand and limited supply.", "options": ["How", "That", "Which", "What"], "answer": 3, "explanation": "'What' = \u0111i\u1ec1u g\u00ec, l\u00e0m ch\u1ee7 ng\u1eef m\u1ec7nh \u0111\u1ec1 danh t\u1eeb.", "difficulty": "medium"}, {"id": "ex-nc-13", "type": "noun-clauses", "question": "The lease agreement states _____ all utilities must be paid by the tenant.", "options": ["that", "whether", "what", "how"], "answer": 0, "explanation": "\"States + that clause\": \"state\" = ph\u00e1t bi\u1ec3u, tuy\u00ean b\u1ed1. Theo sau l\u00e0 \"that + S + V\" (m\u1ec7nh \u0111\u1ec1 danh t\u1eeb).", "difficulty": "medium"}, {"id": "ex-nc-14", "type": "noun-clauses", "question": "The city council has not decided _____ to approve the new development plan.", "options": ["that", "whether", "what", "which"], "answer": 1, "explanation": "'Decided + whether' = quy\u1ebft \u0111\u1ecbnh li\u1ec7u c\u00f3... kh\u00f4ng.", "difficulty": "medium"}, {"id": "ex-nc-15", "type": "noun-clauses", "question": "Investors are aware _____ market conditions can change rapidly.", "options": ["how", "whether", "that", "what"], "answer": 2, "explanation": "\"Be aware + that clause\": aware of/that + m\u1ec7nh \u0111\u1ec1 danh t\u1eeb. \"Are aware that\" = bi\u1ebft r\u1eb1ng.", "difficulty": "medium"}, {"id": "ex-nc-16", "type": "noun-clauses", "question": "The survey showed _____ most buyers prefer properties in walkable neighborhoods.", "options": ["how", "whether", "which", "that"], "answer": 3, "explanation": "'Showed + that clause' = cho th\u1ea5y r\u1eb1ng.", "difficulty": "medium"}, {"id": "ex-nc-17", "type": "noun-clauses", "question": "She asked the realtor _____ the price was negotiable.", "options": ["whether", "that", "how", "which"], "answer": 0, "explanation": "C\u00e2u h\u1ecfi gi\u00e1n ti\u1ebfp yes/no \u2192 'whether'.", "difficulty": "easy"}, {"id": "ex-nc-18", "type": "noun-clauses", "question": "The reason _____ the deal fell through is still under investigation.", "options": ["that", "why", "how", "when"], "answer": 1, "explanation": "\"The reason why/that\": \"why\" ho\u1eb7c \"that\" sau \"reason\" d\u1eabn m\u1ec7nh \u0111\u1ec1 quan h\u1ec7/danh t\u1eeb gi\u1ea3i th\u00edch l\u00fd do.", "difficulty": "medium"}, {"id": "ex-nc-19", "type": "noun-clauses", "question": "The committee will evaluate _____ the proposed development aligns with zoning laws.", "options": ["how", "that", "whether", "what"], "answer": 2, "explanation": "\"Evaluate + whether\": whether d\u1eabn c\u00e2u h\u1ecfi gi\u00e1n ti\u1ebfp Yes/No. Evaluate whether + S + V (tr\u1eadt t\u1ef1 b\u00ecnh th\u01b0\u1eddng).", "difficulty": "medium"}, {"id": "ex-nc-20", "type": "noun-clauses", "question": "He wondered _____ the construction would be completed by the contract date.", "options": ["whether", "that", "what", "how"], "answer": 0, "explanation": "'Wondered + whether' = t\u1ef1 h\u1ecfi li\u1ec7u... c\u00f3 kh\u00f4ng.", "difficulty": "medium"}, {"id": "ex-at-01", "type": "adverb-time", "question": "The press release will be distributed _____ the product launch event begins.", "options": ["after", "before", "while", "until"], "answer": 1, "explanation": "\"Before\" = tr\u01b0\u1edbc khi. M\u1ec7nh \u0111\u1ec1 \"before + S + V\" di\u1ec5n t\u1ea3 h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra sau h\u00e0nh \u0111\u1ed9ng ch\u00ednh.", "difficulty": "medium"}, {"id": "ex-at-02", "type": "adverb-time", "question": "The journalist filed her story _____ she returned from the press conference.", "options": ["until", "before", "as soon as", "while"], "answer": 2, "explanation": "\"As soon as\" = ngay khi, ngay sau khi. M\u1ec7nh \u0111\u1ec1 th\u1eddi gian d\u00f9ng hi\u1ec7n t\u1ea1i thay t\u01b0\u01a1ng lai.", "difficulty": "medium"}, {"id": "ex-at-03", "type": "adverb-time", "question": "The broadcast will remain on air _____ further notice from the station manager.", "options": ["when", "while", "as", "until"], "answer": 3, "explanation": "'Until further notice' = cho \u0111\u1ebfn khi c\u00f3 th\u00f4ng b\u00e1o th\u00eam.", "difficulty": "medium"}, {"id": "ex-at-04", "type": "adverb-time", "question": "_____ the live interview was airing, the studio received hundreds of viewer messages.", "options": ["While", "After", "Until", "As soon as"], "answer": 0, "explanation": "'While' = trong khi (hai h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra c\u00f9ng l\u00fac).", "difficulty": "medium"}, {"id": "ex-at-05", "type": "adverb-time", "question": "The editor reviews all articles _____ they are published online.", "options": ["after", "before", "while", "until"], "answer": 1, "explanation": "'Before' = tr\u01b0\u1edbc khi xu\u1ea5t b\u1ea3n.", "difficulty": "medium"}, {"id": "ex-at-06", "type": "adverb-time", "question": "The news agency will issue a correction _____ the error has been verified.", "options": ["until", "while", "once", "before"], "answer": 2, "explanation": "'Once' = ngay khi \u0111\u00e3 x\u00e1c nh\u1eadn.", "difficulty": "medium"}, {"id": "ex-at-07", "type": "adverb-time", "question": "Please hold all calls _____ the director finishes the press briefing.", "options": ["since", "while", "before", "until"], "answer": 3, "explanation": "\"Until\" = cho \u0111\u1ebfn khi (li\u00ean t\u1ee5c). Di\u1ec5n t\u1ea3 h\u00e0nh \u0111\u1ed9ng k\u00e9o d\u00e0i \u0111\u1ebfn m\u1ed9t th\u1eddi \u0111i\u1ec3m c\u1ee5 th\u1ec3.", "difficulty": "medium"}, {"id": "ex-at-08", "type": "adverb-time", "question": "The photographer had _____ captured several striking images before the event ended.", "options": ["already", "yet", "still", "ever"], "answer": 0, "explanation": "'Had already + past participle' = \u0111\u00e3... r\u1ed3i (tr\u01b0\u1edbc m\u1ed9t \u0111i\u1ec3m trong qu\u00e1 kh\u1ee9).", "difficulty": "medium"}, {"id": "ex-at-09", "type": "adverb-time", "question": "The magazine has _____ published over 500 issues since its launch.", "options": ["yet", "already", "still", "just"], "answer": 1, "explanation": "'Has already published' = \u0111\u00e3 xu\u1ea5t b\u1ea3n r\u1ed3i.", "difficulty": "medium"}, {"id": "ex-at-10", "type": "adverb-time", "question": "The documentary was so compelling that viewers _____ stopped watching.", "options": ["usually", "often", "sometimes", "rarely"], "answer": 3, "explanation": "'Rarely' = hi\u1ebfm khi, ph\u00f9 h\u1ee3p v\u1edbi ng\u1eef c\u1ea3nh.", "difficulty": "medium"}, {"id": "ex-at-11", "type": "adverb-time", "question": "The reporter had _____ submitted the story when the deadline was extended.", "options": ["just", "already", "yet", "still"], "answer": 0, "explanation": "'Had just + past participle' = v\u1eeba m\u1edbi l\u00e0m xong.", "difficulty": "medium"}, {"id": "ex-at-12", "type": "adverb-time", "question": "The network _____ airs breaking news as it happens, 24 hours a day.", "options": ["never", "always", "rarely", "seldom"], "answer": 1, "explanation": "\"Always\" = lu\u00f4n lu\u00f4n. Ph\u00f3 t\u1eeb t\u1ea7n su\u1ea5t \u0111\u1ee9ng gi\u1eefa ch\u1ee7 ng\u1eef v\u00e0 \u0111\u1ed9ng t\u1eeb, ho\u1eb7c sau be/modal.", "difficulty": "medium"}, {"id": "ex-at-13", "type": "adverb-time", "question": "The website traffic spikes _____ major news stories break.", "options": ["until", "while", "whenever", "before"], "answer": 2, "explanation": "\"Whenever\" = m\u1ed7i khi, b\u1ea5t c\u1ee9 khi n\u00e0o. Di\u1ec5n t\u1ea3 s\u1ef1 l\u1eb7p l\u1ea1i theo \u0111i\u1ec1u ki\u1ec7n th\u1eddi gian.", "difficulty": "easy"}, {"id": "ex-at-14", "type": "adverb-time", "question": "The digital edition is _____ available before the print version reaches newsstands.", "options": ["seldom", "never", "rarely", "often"], "answer": 3, "explanation": "\"Often\" = th\u01b0\u1eddng xuy\u00ean. Ph\u00f3 t\u1eeb t\u1ea7n su\u1ea5t, \u0111\u1ee9ng tr\u01b0\u1edbc \u0111\u1ed9ng t\u1eeb th\u01b0\u1eddng ho\u1eb7c sau be/modal.", "difficulty": "medium"}, {"id": "ex-at-15", "type": "adverb-time", "question": "_____ the merger was announced, shares in both companies surged.", "options": ["Once", "While", "Until", "Before"], "answer": 0, "explanation": "\"Once\" = m\u1ed9t khi, ngay khi (li\u00ean t\u1eeb th\u1eddi gian). Once + S + V \u2192 main clause (d\u00f9ng hi\u1ec7n t\u1ea1i thay t\u01b0\u01a1ng lai).", "difficulty": "medium"}, {"id": "ex-at-16", "type": "adverb-time", "question": "The editor _____ checks the facts before approving an article.", "options": ["already", "always", "yet", "still"], "answer": 1, "explanation": "'Always' = lu\u00f4n lu\u00f4n (th\u00f3i quen).", "difficulty": "medium"}, {"id": "ex-at-17", "type": "adverb-time", "question": "We haven't received the interview transcript _____.", "options": ["still", "already", "yet", "just"], "answer": 2, "explanation": "'Yet' = ch\u01b0a, d\u00f9ng cu\u1ed1i c\u00e2u ph\u1ee7 \u0111\u1ecbnh.", "difficulty": "easy"}, {"id": "ex-at-18", "type": "adverb-time", "question": "The media team is _____ editing the footage for tomorrow's broadcast.", "options": ["just", "already", "yet", "still"], "answer": 3, "explanation": "'Still' = v\u1eabn \u0111ang (ti\u1ebfp di\u1ec5n).", "difficulty": "medium"}, {"id": "ex-at-19", "type": "adverb-time", "question": "The editor had _____ approved the layout when the story changed completely.", "options": ["just", "already", "yet", "still"], "answer": 0, "explanation": "'Had just approved' = v\u1eeba m\u1edbi duy\u1ec7t xong.", "difficulty": "medium"}, {"id": "ex-at-20", "type": "adverb-time", "question": "The station's audience has grown _____ more digital platforms were introduced.", "options": ["until", "while", "since", "before"], "answer": 2, "explanation": "'Since' = k\u1ec3 t\u1eeb khi (d\u00f9ng v\u1edbi Perfect tense).", "difficulty": "medium"}, {"id": "ex-vc-01", "type": "vocabulary-context", "question": "The store is offering a 20% _____ on all electronics this weekend.", "options": ["rebate", "reduction", "deduction", "discount"], "answer": 3, "explanation": "'Discount' l\u00e0 t\u1eeb ph\u1ed5 bi\u1ebfn nh\u1ea5t trong b\u00e1n l\u1ebb cho gi\u1ea3m gi\u00e1 tr\u1ef1c ti\u1ebfp.", "difficulty": "medium"}, {"id": "ex-vc-02", "type": "vocabulary-context", "question": "Customers must _____ their purchase within 30 days to receive a full refund.", "options": ["return", "replace", "restore", "retrieve"], "answer": 0, "explanation": "'Return a purchase' = tr\u1ea3 l\u1ea1i h\u00e0ng.", "difficulty": "medium"}, {"id": "ex-vc-03", "type": "vocabulary-context", "question": "The website's checkout process is _____ to navigate, helping reduce cart abandonment.", "options": ["intensive", "intuitive", "indicative", "incentive"], "answer": 1, "explanation": "'Intuitive' = d\u1ec5 d\u00f9ng t\u1ef1 nhi\u00ean.", "difficulty": "medium"}, {"id": "ex-vc-04", "type": "vocabulary-context", "question": "The online store offers free _____ on orders over $50.", "options": ["postage", "handling", "shipping", "cargo"], "answer": 2, "explanation": "'Free shipping' = giao h\u00e0ng mi\u1ec5n ph\u00ed trong th\u01b0\u01a1ng m\u1ea1i \u0111i\u1ec7n t\u1eed.", "difficulty": "medium"}, {"id": "ex-vc-05", "type": "vocabulary-context", "question": "The inventory system automatically _____ stock levels when items are sold.", "options": ["undertakes", "upgrades", "uplifts", "updates"], "answer": 3, "explanation": "'Updates stock levels' = c\u1eadp nh\u1eadt t\u1ed3n kho.", "difficulty": "medium"}, {"id": "ex-vc-06", "type": "vocabulary-context", "question": "To increase customer loyalty, the retailer launched an exclusive _____ program.", "options": ["rewards", "award", "prizes", "bonuses"], "answer": 0, "explanation": "'Rewards program' = ch\u01b0\u01a1ng tr\u00ecnh t\u00edch \u0111i\u1ec3m kh\u00e1ch h\u00e0ng.", "difficulty": "medium"}, {"id": "ex-vc-07", "type": "vocabulary-context", "question": "The company's e-commerce platform saw a significant _____ in traffic during the sale.", "options": ["search", "surge", "source", "series"], "answer": 1, "explanation": "'Surge in traffic' = t\u0103ng \u0111\u1ed9t bi\u1ebfn l\u01b0\u1ee3ng truy c\u1eadp.", "difficulty": "medium"}, {"id": "ex-vc-08", "type": "vocabulary-context", "question": "Shoppers can _____ wish list items and receive alerts when prices drop.", "options": ["set", "store", "save", "sort"], "answer": 2, "explanation": "'Save items' to a wish list = l\u01b0u s\u1ea3n ph\u1ea9m.", "difficulty": "medium"}, {"id": "ex-vc-09", "type": "vocabulary-context", "question": "The retailer _____ its product range to include premium organic goods.", "options": ["exhibited", "explored", "exceeded", "expanded"], "answer": 3, "explanation": "'Expanded product range' = m\u1edf r\u1ed9ng danh m\u1ee5c s\u1ea3n ph\u1ea9m.", "difficulty": "medium"}, {"id": "ex-vc-10", "type": "vocabulary-context", "question": "Customers who _____ by email will be the first to know about upcoming sales.", "options": ["submit", "subscribe", "suggest", "support"], "answer": 1, "explanation": "'Subscribe by email' = \u0111\u0103ng k\u00fd nh\u1eadn email.", "difficulty": "medium"}, {"id": "ex-vc-11", "type": "vocabulary-context", "question": "The brand's _____ packaging attracted a lot of attention at trade shows.", "options": ["distracted", "distributing", "distinctive", "distressing"], "answer": 2, "explanation": "'Distinctive packaging' = bao b\u00ec n\u1ed5i b\u1eadt, d\u1ec5 nh\u1eadn bi\u1ebft.", "difficulty": "medium"}, {"id": "ex-vc-12", "type": "vocabulary-context", "question": "The platform uses _____ data to suggest products based on browsing history.", "options": ["personality", "personal", "person", "personalized"], "answer": 3, "explanation": "'Personalized data' = d\u1eef li\u1ec7u \u0111\u01b0\u1ee3c c\u00e1 nh\u00e2n h\u00f3a.", "difficulty": "medium"}, {"id": "ex-vc-13", "type": "vocabulary-context", "question": "The retailer _____ excess stock at the end of each season to make room for new arrivals.", "options": ["clears", "closes", "cancels", "cuts"], "answer": 0, "explanation": "'Clears excess stock' = thanh l\u00fd h\u00e0ng t\u1ed3n.", "difficulty": "medium"}, {"id": "ex-vc-14", "type": "vocabulary-context", "question": "All purchases made online are _____ via a secure payment gateway.", "options": ["produced", "processed", "provided", "projected"], "answer": 1, "explanation": "'Processed via gateway' = x\u1eed l\u00fd qua c\u1ed5ng thanh to\u00e1n.", "difficulty": "medium"}, {"id": "ex-vc-15", "type": "vocabulary-context", "question": "The mobile app allows customers to _____ their order status in real time.", "options": ["trace", "trial", "track", "trust"], "answer": 2, "explanation": "'Track order status' = theo d\u00f5i \u0111\u01a1n h\u00e0ng.", "difficulty": "medium"}, {"id": "ex-vc-16", "type": "vocabulary-context", "question": "A satisfied customer is more likely to _____ a product to friends and family.", "options": ["record", "remand", "remind", "recommend"], "answer": 3, "explanation": "'Recommend a product' = gi\u1edbi thi\u1ec7u s\u1ea3n ph\u1ea9m.", "difficulty": "medium"}, {"id": "ex-vc-17", "type": "vocabulary-context", "question": "The store _____ a price-matching policy to remain competitive.", "options": ["adopted", "adapted", "adored", "added"], "answer": 0, "explanation": "'Adopted a policy' = \u00e1p d\u1ee5ng ch\u00ednh s\u00e1ch.", "difficulty": "medium"}, {"id": "ex-vc-18", "type": "vocabulary-context", "question": "Customer _____ is key to long-term business growth in retail.", "options": ["rotation", "retention", "relation", "reaction"], "answer": 1, "explanation": "'Customer retention' = gi\u1eef ch\u00e2n kh\u00e1ch h\u00e0ng.", "difficulty": "medium"}, {"id": "ex-vc-19", "type": "vocabulary-context", "question": "The flash sale was a limited-time _____ offering steep discounts.", "options": ["production", "procedure", "promotion", "proportion"], "answer": 2, "explanation": "'Promotion' = ch\u01b0\u01a1ng tr\u00ecnh khuy\u1ebfn m\u00e3i.", "difficulty": "medium"}, {"id": "ex-vc-20", "type": "vocabulary-context", "question": "The online marketplace _____ thousands of independent sellers from around the world.", "options": ["hosts", "holds", "harvests", "handles"], "answer": 0, "explanation": "'Hosts sellers' = n\u1ec1n t\u1ea3ng ch\u1ee9a/k\u1ebft n\u1ed1i nhi\u1ec1u ng\u01b0\u1eddi b\u00e1n.", "difficulty": "medium"}, {"id": "ex-vc-21", "type": "vocabulary-context", "question": "The new policy will _____ all part-time employees who have worked for the company for at least six months.", "options": ["contain", "cover", "consist", "compile"], "answer": 1, "explanation": "'Cover employees' = ch\u00ednh s\u00e1ch \u00e1p d\u1ee5ng/bao g\u1ed3m nh\u00e2n vi\u00ean.", "difficulty": "medium"}, {"id": "ex-vc-22", "type": "vocabulary-context", "question": "The auditors noted several _____ in the financial records that required immediate attention.", "options": ["distinctions", "discoveries", "discrepancies", "declarations"], "answer": 2, "explanation": "'Discrepancies in records' = s\u1ef1 ch\u00eanh l\u1ec7ch/kh\u00f4ng kh\u1edbp trong h\u1ed3 s\u01a1.", "difficulty": "medium"}, {"id": "ex-vc-23", "type": "vocabulary-context", "question": "To _____ the impact of rising costs, management implemented a series of efficiency measures.", "options": ["occupy", "outline", "oppose", "offset"], "answer": 3, "explanation": "'Offset the impact' = b\u00f9 \u0111\u1eafp/trung h\u00f2a t\u00e1c \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-vc-24", "type": "vocabulary-context", "question": "The new branch manager quickly _____ the trust of both staff and long-term clients.", "options": ["earned", "gained", "received", "acquired"], "answer": 0, "explanation": "'Earn trust' l\u00e0 collocation chu\u1ea9n trong m\u00f4i tr\u01b0\u1eddng kinh doanh.", "difficulty": "medium"}, {"id": "ex-vc-25", "type": "vocabulary-context", "question": "Participants are asked to _____ from using mobile phones during the presentation.", "options": ["retreat", "refrain", "retain", "reclaim"], "answer": 1, "explanation": "'Refrain from doing' = ki\u00eang/tr\u00e1nh l\u00e0m g\u00ec \u2014 c\u1ee5m chu\u1ea9n v\u0103n phong trang tr\u1ecdng.", "difficulty": "medium"}, {"id": "ex-vc-26", "type": "vocabulary-context", "question": "The company's new headquarters was strategically _____ near the city's financial district.", "options": ["settled", "stationed", "situated", "stored"], "answer": 2, "explanation": "'Situated near' = \u0111\u01b0\u1ee3c \u0111\u1eb7t/t\u1ecda l\u1ea1c g\u1ea7n \u2014 colocation ph\u1ed5 bi\u1ebfn v\u1edbi \u0111\u1ecba \u0111i\u1ec3m.", "difficulty": "medium"}, {"id": "ex-vc-27", "type": "vocabulary-context", "question": "Please _____ the attached form and return it to the HR department by the end of the week.", "options": ["perform", "accomplish", "achieve", "complete"], "answer": 3, "explanation": "'Complete a form' = \u0111i\u1ec1n/ho\u00e0n th\u00e0nh bi\u1ec3u m\u1eabu \u2014 collocation chu\u1ea9n.", "difficulty": "medium"}, {"id": "ex-vc-28", "type": "vocabulary-context", "question": "The finance team will _____ all outstanding invoices before the fiscal year ends.", "options": ["settle", "resolve", "arrange", "address"], "answer": 0, "explanation": "'Settle invoices' = thanh to\u00e1n/t\u1ea5t to\u00e1n h\u00f3a \u0111\u01a1n \u2014 colocation ph\u1ed5 bi\u1ebfn.", "difficulty": "medium"}, {"id": "ex-vc-29", "type": "vocabulary-context", "question": "The board voted to _____ the proposed merger pending a thorough due diligence review.", "options": ["delay", "defer", "decline", "dismiss"], "answer": 1, "explanation": "'Defer a decision' = ho\u00e3n l\u1ea1i \u0111\u1ec3 xem x\u00e9t th\u00eam \u2014 kh\u00e1c v\u1edbi decline (t\u1eeb ch\u1ed1i).", "difficulty": "medium"}, {"id": "ex-vc-30", "type": "vocabulary-context", "question": "The CEO's presentation _____ several key concerns that shareholders had raised at last year's meeting.", "options": ["responded", "answered", "replied", "addressed"], "answer": 3, "explanation": "'Address concerns' = \u0111\u1ec1 c\u1eadp/gi\u1ea3i quy\u1ebft c\u00e1c lo ng\u1ea1i \u2014 colocation trang tr\u1ecdng.", "difficulty": "medium"}, {"id": "ex-vc-31", "type": "vocabulary-context", "question": "The training session aims to _____ staff with the skills needed to use the new software.", "options": ["equip", "supply", "provide", "present"], "answer": 0, "explanation": "'Equip sb with skills' = trang b\u1ecb k\u1ef9 n\u0103ng cho ai \u2014 collocation chu\u1ea9n TOEIC.", "difficulty": "medium"}, {"id": "ex-vc-32", "type": "vocabulary-context", "question": "Employees who _____ the mandatory fire drill will be required to attend a make-up session.", "options": ["skip", "miss", "avoid", "ignore"], "answer": 1, "explanation": "'Miss a drill/event' = v\u1eafng m\u1eb7t t\u1ea1i s\u1ef1 ki\u1ec7n b\u1eaft bu\u1ed9c \u2014 t\u1ef1 nhi\u00ean nh\u1ea5t.", "difficulty": "medium"}, {"id": "ex-vc-33", "type": "vocabulary-context", "question": "The new warehouse system significantly _____ order processing times during the peak season.", "options": ["shortened", "lessened", "reduced", "minimized"], "answer": 2, "explanation": "'Reduce processing times' l\u00e0 collocation t\u1ef1 nhi\u00ean nh\u1ea5t trong logistics.", "difficulty": "medium"}, {"id": "ex-vc-34", "type": "vocabulary-context", "question": "All products must _____ rigorous quality checks before being shipped to retail partners.", "options": ["take", "experience", "receive", "undergo"], "answer": 3, "explanation": "'Undergo quality checks/tests' = tr\u1ea3i qua ki\u1ec3m tra \u2014 verb chu\u1ea9n trong s\u1ea3n xu\u1ea5t.", "difficulty": "medium"}, {"id": "ex-vc-35", "type": "vocabulary-context", "question": "The HR team is currently _____ candidates for the newly created regional director position.", "options": ["screening", "scanning", "searching", "surveying"], "answer": 0, "explanation": "'Screen candidates' = s\u00e0ng l\u1ecdc \u1ee9ng vi\u00ean \u2014 collocation HR chu\u1ea9n.", "difficulty": "medium"}, {"id": "ex-vc-36", "type": "vocabulary-context", "question": "The annual conference provides an excellent _____ for professionals to share industry insights.", "options": ["position", "platform", "prospect", "programme"], "answer": 1, "explanation": "'Platform for sharing' = di\u1ec5n \u0111\u00e0n/c\u01a1 h\u1ed9i chia s\u1ebb \u2014 ngh\u0129a b\u00f3ng ph\u1ed5 bi\u1ebfn.", "difficulty": "medium"}, {"id": "ex-vc-37", "type": "vocabulary-context", "question": "The proposal was _____ received by the committee, who agreed to move forward immediately.", "options": ["warmly", "positively", "favorably", "enthusiastically"], "answer": 2, "explanation": "'Favorably received' = \u0111\u01b0\u1ee3c \u0111\u00f3n nh\u1eadn thu\u1eadn l\u1ee3i \u2014 adverb chu\u1ea9n v\u0103n b\u1ea3n trang tr\u1ecdng.", "difficulty": "medium"}, {"id": "ex-vc-38", "type": "vocabulary-context", "question": "The facilities team will _____ the conference rooms for the executive retreat next month.", "options": ["set", "arrange", "organize", "prepare"], "answer": 3, "explanation": "'Prepare rooms' = chu\u1ea9n b\u1ecb ph\u00f2ng \u2014 verb ph\u1ed5 bi\u1ebfn v\u00e0 t\u1ef1 nhi\u00ean nh\u1ea5t.", "difficulty": "medium"}, {"id": "ex-vc-39", "type": "vocabulary-context", "question": "The terms of the lease _____ that the tenant must provide 60 days' notice before vacating.", "options": ["stipulate", "indicate", "suggest", "mention"], "answer": 0, "explanation": "'Stipulate terms' = quy \u0111\u1ecbnh \u0111i\u1ec1u kho\u1ea3n \u2014 v\u0103n phong ph\u00e1p l\u00fd ch\u00ednh th\u1ee9c.", "difficulty": "medium"}, {"id": "ex-vc-40", "type": "vocabulary-context", "question": "The sales team was asked to _____ a detailed report on customer feedback from last quarter.", "options": ["construct", "compose", "compile", "combine"], "answer": 2, "explanation": "'Compile a report' = t\u1ed5ng h\u1ee3p/bi\u00ean so\u1ea1n b\u00e1o c\u00e1o \u2014 colocation chu\u1ea9n.", "difficulty": "medium"}, {"id": "ex-iv-01", "type": "inversion", "question": "Not only _____ the contract invalid, but it also contained fraudulent clauses.", "options": ["it is", "it was", "is it", "was it"], "answer": 3, "explanation": "'Not only' \u0111\u1ee9ng \u0111\u1ea7u c\u00e2u \u2192 \u0111\u1ea3o ng\u1eef: Not only + was + S.", "difficulty": "hard"}, {"id": "ex-iv-02", "type": "inversion", "question": "Seldom _____ such a complex litigation case handled by a single attorney.", "options": ["is", "was", "has been", "had been"], "answer": 0, "explanation": "'Seldom' \u0111\u1ee9ng \u0111\u1ea7u c\u00e2u \u2192 \u0111\u1ea3o ng\u1eef: Seldom + is + S.", "difficulty": "hard"}, {"id": "ex-iv-03", "type": "inversion", "question": "Under no circumstances _____ the confidential terms of this agreement be disclosed.", "options": ["should", "must", "are", "shall"], "answer": 3, "explanation": "'Under no circumstances' \u2192 \u0111\u1ea3o ng\u1eef: shall (d\u00f9ng trong v\u0103n b\u1ea3n ph\u00e1p l\u00fd).", "difficulty": "hard"}, {"id": "ex-iv-04", "type": "inversion", "question": "Hardly _____ the attorney presented the evidence when the judge called a recess.", "options": ["was", "has", "had", "is"], "answer": 2, "explanation": "'Hardly...when' \u2192 \u0111\u1ea3o ng\u1eef: Hardly + had + S + past participle.", "difficulty": "hard"}, {"id": "ex-iv-05", "type": "inversion", "question": "Only after signing the NDA _____ granted access to the sensitive documents.", "options": ["had employees", "employees were", "employees had", "were employees"], "answer": 3, "explanation": "'Only after' \u2192 \u0111\u1ea3o ng\u1eef trong m\u1ec7nh \u0111\u1ec1 ch\u00ednh.", "difficulty": "hard"}, {"id": "ex-iv-06", "type": "inversion", "question": "Never before _____ such a severe penalty been imposed for a contract breach.", "options": ["has", "have", "was", "had"], "answer": 0, "explanation": "'Never before' + Present Perfect \u2192 \u0111\u1ea3o ng\u1eef: has + S.", "difficulty": "hard"}, {"id": "ex-iv-07", "type": "inversion", "question": "No sooner _____ the verdict announced than the defendant's lawyers filed an appeal.", "options": ["was", "had been", "has been", "is"], "answer": 1, "explanation": "'No sooner...than' \u2192 Past Perfect \u0111\u1ea3o ng\u1eef.", "difficulty": "hard"}, {"id": "ex-iv-08", "type": "inversion", "question": "Only by reviewing the full contract _____ identify the problematic clause.", "options": ["can the team", "the team could", "could the team", "the team can"], "answer": 2, "explanation": "'Only by' \u2192 \u0111\u1ea3o ng\u1eef trong m\u1ec7nh \u0111\u1ec1 ch\u00ednh.", "difficulty": "hard"}, {"id": "ex-iv-09", "type": "inversion", "question": "Rarely _____ arbitration result in a decision that satisfies both parties fully.", "options": ["had", "do", "has", "does"], "answer": 3, "explanation": "\"Rarely\" = hi\u1ebfm khi (ph\u00f3 t\u1eeb ph\u1ee7 \u0111\u1ecbnh). \u0110\u1ee9ng \u0111\u1ea7u c\u00e2u \u2192 \u0111\u1ea3o ng\u1eef: Rarely + does/do + S + V.", "difficulty": "hard"}, {"id": "ex-iv-10", "type": "inversion", "question": "Not until the clause was amended _____ both parties agree to sign.", "options": ["would", "did", "were", "have"], "answer": 1, "explanation": "'Not until' \u2192 \u0111\u1ea3o ng\u1eef: did + S + V.", "difficulty": "hard"}, {"id": "ex-iv-11", "type": "inversion", "question": "Should any party _____ to fulfill its obligations, penalties will apply immediately.", "options": ["failed", "fails", "fail", "have failed"], "answer": 2, "explanation": "'Should + S + V' = \u0111\u1ea3o ng\u1eef \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1 trang tr\u1ecdng.", "difficulty": "hard"}, {"id": "ex-iv-12", "type": "inversion", "question": "Were the defendant _____ to comply with the court order, further sanctions would follow.", "options": ["refuse", "refused", "refusing", "to refuse"], "answer": 3, "explanation": "'Were + S + to V' = \u0111\u1ea3o ng\u1eef \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 2 trang tr\u1ecdng.", "difficulty": "hard"}, {"id": "ex-iv-13", "type": "inversion", "question": "Had the company _____ better legal advice, it might have avoided the lawsuit.", "options": ["sought", "seek", "seeking", "seeks"], "answer": 0, "explanation": "'Had + S + past participle' = \u0111\u1ea3o ng\u1eef \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 3.", "difficulty": "hard"}, {"id": "ex-iv-14", "type": "inversion", "question": "At no time _____ employees discuss client information outside the office.", "options": ["would", "should", "can", "may"], "answer": 1, "explanation": "'At no time' \u2192 \u0111\u1ea3o ng\u1eef: should + S.", "difficulty": "hard"}, {"id": "ex-iv-15", "type": "inversion", "question": "Not only _____ the firm liable for damages, but it also faced criminal charges.", "options": ["is it held", "it was held", "was it held", "it is held"], "answer": 2, "explanation": "'Not only' \u2192 \u0111\u1ea3o ng\u1eef Past Simple.", "difficulty": "hard"}, {"id": "ex-iv-16", "type": "inversion", "question": "So _____ the legal implications that the CEO consulted three separate attorneys.", "options": ["are complex", "were complex", "complex are", "complex were"], "answer": 3, "explanation": "'So + adj + were + S' = \u0111\u1ea3o ng\u1eef nh\u1ea5n m\u1ea1nh.", "difficulty": "hard"}, {"id": "ex-iv-17", "type": "inversion", "question": "Little _____ the client realize the clause had significant long-term consequences.", "options": ["did", "does", "had", "has"], "answer": 0, "explanation": "'Little' (ph\u1ee7 \u0111\u1ecbnh) + \u0111\u1ea3o ng\u1eef: did + S.", "difficulty": "hard"}, {"id": "ex-iv-18", "type": "inversion", "question": "In no way _____ the company responsible for indirect damages under this agreement.", "options": ["it shall be", "shall it be", "it will be", "will be it"], "answer": 1, "explanation": "'In no way' \u2192 \u0111\u1ea3o ng\u1eef: shall + S.", "difficulty": "hard"}, {"id": "ex-iv-19", "type": "inversion", "question": "Only when the full payment is received _____ the title transfer to the buyer.", "options": ["shall", "would", "will", "should"], "answer": 2, "explanation": "'Only when' \u2192 \u0111\u1ea3o ng\u1eef: will + S.", "difficulty": "hard"}, {"id": "ex-iv-20", "type": "inversion", "question": "Such _____ the pressure from creditors that the company filed for bankruptcy.", "options": ["was", "is", "had been", "were"], "answer": 0, "explanation": "'Such was + S' = \u0111\u1ea3o ng\u1eef nh\u1ea5n m\u1ea1nh m\u1ee9c \u0111\u1ed9.", "difficulty": "hard"}, {"id": "ex-qn-01", "type": "quantifiers", "question": "_____ companies have adopted renewable energy solutions over the past decade.", "options": ["Little", "Much", "A little", "Many"], "answer": 3, "explanation": "'Many' = nhi\u1ec1u, d\u00f9ng v\u1edbi danh t\u1eeb \u0111\u1ebfm \u0111\u01b0\u1ee3c s\u1ed1 nhi\u1ec1u (companies).", "difficulty": "medium"}, {"id": "ex-qn-02", "type": "quantifiers", "question": "There is _____ evidence supporting the long-term benefits of solar power.", "options": ["much", "many", "few", "a few"], "answer": 0, "explanation": "'Much' = nhi\u1ec1u, d\u00f9ng v\u1edbi danh t\u1eeb kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c (evidence).", "difficulty": "medium"}, {"id": "ex-qn-03", "type": "quantifiers", "question": "_____ of the factory's carbon emissions come from its outdated machinery.", "options": ["Almost", "Most", "Nearly", "Mostly"], "answer": 1, "explanation": "'Most of' = ph\u1ea7n l\u1edbn trong s\u1ed1.", "difficulty": "medium"}, {"id": "ex-qn-04", "type": "quantifiers", "question": "We have _____ time left before the environmental audit begins.", "options": ["a few", "few", "little", "many"], "answer": 2, "explanation": "'Little' = r\u1ea5t \u00edt, d\u00f9ng v\u1edbi kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c (time), mang ngh\u0129a ti\u00eau c\u1ef1c.", "difficulty": "medium"}, {"id": "ex-qn-05", "type": "quantifiers", "question": "_____ regions are still heavily dependent on fossil fuels for electricity.", "options": ["A level of", "A great deal of", "An amount of", "A number of"], "answer": 3, "explanation": "'A number of' = m\u1ed9t s\u1ed1, d\u00f9ng v\u1edbi danh t\u1eeb \u0111\u1ebfm \u0111\u01b0\u1ee3c s\u1ed1 nhi\u1ec1u.", "difficulty": "medium"}, {"id": "ex-qn-06", "type": "quantifiers", "question": "The company has invested _____ money in developing eco-friendly packaging.", "options": ["a great deal of", "many", "a number of", "few"], "answer": 0, "explanation": "'A great deal of' = r\u1ea5t nhi\u1ec1u, d\u00f9ng v\u1edbi kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c (money).", "difficulty": "medium"}, {"id": "ex-qn-07", "type": "quantifiers", "question": "_____ of the clean energy projects were completed on time.", "options": ["A little", "Several", "Much", "A great deal"], "answer": 1, "explanation": "'Several' = m\u1ed9t v\u00e0i, d\u00f9ng v\u1edbi \u0111\u1ebfm \u0111\u01b0\u1ee3c s\u1ed1 nhi\u1ec1u.", "difficulty": "easy"}, {"id": "ex-qn-08", "type": "quantifiers", "question": "There are _____ alternatives to single-use plastic that are commercially viable.", "options": ["much", "little", "few", "a great deal of"], "answer": 2, "explanation": "'Few' = r\u1ea5t \u00edt, d\u00f9ng v\u1edbi \u0111\u1ebfm \u0111\u01b0\u1ee3c, ngh\u0129a ti\u00eau c\u1ef1c.", "difficulty": "medium"}, {"id": "ex-qn-09", "type": "quantifiers", "question": "The plant produces _____ waste since the new filtration system was installed.", "options": ["a few", "fewer", "little", "less"], "answer": 3, "explanation": "'Less' = \u00edt h\u01a1n, d\u00f9ng v\u1edbi kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c (waste).", "difficulty": "medium"}, {"id": "ex-qn-10", "type": "quantifiers", "question": "_____ countries have committed to achieving net zero emissions by 2050.", "options": ["Much", "Numerous", "A little", "A great deal of"], "answer": 1, "explanation": "'Numerous' = r\u1ea5t nhi\u1ec1u, d\u00f9ng v\u1edbi \u0111\u1ebfm \u0111\u01b0\u1ee3c s\u1ed1 nhi\u1ec1u.", "difficulty": "medium"}, {"id": "ex-qn-11", "type": "quantifiers", "question": "The solar farm generates _____ electricity to power the entire city.", "options": ["few", "many", "enough", "several"], "answer": 2, "explanation": "'Enough' = \u0111\u1ee7, c\u00f3 th\u1ec3 d\u00f9ng v\u1edbi c\u1ea3 \u0111\u1ebfm \u0111\u01b0\u1ee3c v\u00e0 kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c.", "difficulty": "medium"}, {"id": "ex-qn-12", "type": "quantifiers", "question": "The NGO has _____ resources to fund all proposed environmental projects.", "options": ["insufficient", "too few", "too little", "not many"], "answer": 2, "explanation": "'Too little' = qu\u00e1 \u00edt, d\u00f9ng v\u1edbi kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c (resources trong ng\u1eef c\u1ea3nh n\u00e0y l\u00e0 abstract).", "difficulty": "medium"}, {"id": "ex-qn-13", "type": "quantifiers", "question": "_____ the facilities have been upgraded to use energy-efficient lighting.", "options": ["All of", "All", "Every", "Each"], "answer": 0, "explanation": "'All of + the + noun' = t\u1ea5t c\u1ea3 c\u00e1c.", "difficulty": "medium"}, {"id": "ex-qn-14", "type": "quantifiers", "question": "The company uses _____ recycled materials as possible in its manufacturing process.", "options": ["as much", "as many", "so many", "so much"], "answer": 1, "explanation": "\"As many + danh t\u1eeb \u0111\u1ebfm \u0111\u01b0\u1ee3c + as possible\" = c\u00e0ng nhi\u1ec1u c\u00e0ng t\u1ed1t. \"As much\" d\u00f9ng cho kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c.", "difficulty": "medium"}, {"id": "ex-qn-15", "type": "quantifiers", "question": "_____ attention has been paid to reducing water consumption in the new design.", "options": ["Few", "Many", "Considerable", "Several"], "answer": 2, "explanation": "'Considerable' = \u0111\u00e1ng k\u1ec3, d\u00f9ng v\u1edbi kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c (attention).", "difficulty": "medium"}, {"id": "ex-qn-16", "type": "quantifiers", "question": "The new regulations have resulted in _____ reduction in industrial pollution.", "options": ["a lot many", "significant many", "much many", "a significant"], "answer": 3, "explanation": "'A significant reduction' = danh t\u1eeb \u0111\u01a1n s\u1ed1 \u0111\u1ebfm \u0111\u01b0\u1ee3c.", "difficulty": "medium"}, {"id": "ex-qn-17", "type": "quantifiers", "question": "Not _____ businesses fully understand the financial benefits of going green.", "options": ["enough", "much", "little", "fewer"], "answer": 0, "explanation": "'Not enough businesses' = kh\u00f4ng \u0111\u1ee7 s\u1ed1 l\u01b0\u1ee3ng doanh nghi\u1ec7p.", "difficulty": "medium"}, {"id": "ex-qn-18", "type": "quantifiers", "question": "The report identified _____ ways to reduce the carbon footprint of the supply chain.", "options": ["much", "several", "a great deal of", "little"], "answer": 1, "explanation": "'Several' + \u0111\u1ebfm \u0111\u01b0\u1ee3c s\u1ed1 nhi\u1ec1u (ways).", "difficulty": "medium"}, {"id": "ex-qn-19", "type": "quantifiers", "question": "The city has made _____ progress toward its sustainability goals this year.", "options": ["many a", "considerable many", "considerable", "several"], "answer": 2, "explanation": "'Considerable progress' = kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c.", "difficulty": "medium"}, {"id": "ex-qn-20", "type": "quantifiers", "question": "_____ the board members expressed support for the green initiative at the meeting.", "options": ["Most of", "Most", "Almost all", "The majority"], "answer": 0, "explanation": "'Most of + the + noun' l\u00e0 d\u1ea1ng chu\u1ea9n x\u00e1c nh\u1ea5t.", "difficulty": "medium"}, {"id": "ex-be-01", "type": "business-english", "question": "We would like to _____ a meeting for next Tuesday afternoon.", "options": ["conduct", "schedule", "perform", "manage"], "answer": 1, "explanation": "'Schedule a meeting' = l\u00ean l\u1ecbch cu\u1ed9c h\u1ecdp.", "difficulty": "medium"}, {"id": "ex-be-02", "type": "business-english", "question": "Please _____ the attached proposal and provide your feedback.", "options": ["revoke", "revise", "review", "reveal"], "answer": 2, "explanation": "'Review a proposal' = xem x\u00e9t \u0111\u1ec1 xu\u1ea5t.", "difficulty": "medium"}, {"id": "ex-be-03", "type": "business-english", "question": "We are writing to _____ our interest in the partnership opportunity.", "options": ["explain", "expose", "expand", "express"], "answer": 3, "explanation": "'Express interest' = b\u00e0y t\u1ecf s\u1ef1 quan t\u00e2m.", "difficulty": "medium"}, {"id": "ex-be-04", "type": "business-english", "question": "The team will _____ the findings at the quarterly board meeting.", "options": ["present", "provide", "produce", "propose"], "answer": 0, "explanation": "'Present findings' = tr\u00ecnh b\u00e0y k\u1ebft qu\u1ea3.", "difficulty": "medium"}, {"id": "ex-be-05", "type": "business-english", "question": "Could you please _____ me with the updated sales figures?", "options": ["present", "provide", "produce", "process"], "answer": 1, "explanation": "'Provide someone with something' = cung c\u1ea5p cho ai \u0111\u00f3 th\u1ee9 g\u00ec.", "difficulty": "easy"}, {"id": "ex-be-06", "type": "business-english", "question": "We look forward to _____ business with your esteemed organization.", "options": ["having", "making", "doing", "taking"], "answer": 2, "explanation": "'Doing business with' = l\u00e0m \u0103n/kinh doanh c\u00f9ng.", "difficulty": "medium"}, {"id": "ex-be-07", "type": "business-english", "question": "I am writing to _____ my application for the position of Marketing Manager.", "options": ["support", "send", "supply", "submit"], "answer": 3, "explanation": "'Submit an application' = n\u1ed9p \u0111\u01a1n xin vi\u1ec7c.", "difficulty": "medium"}, {"id": "ex-be-08", "type": "business-english", "question": "Please do not hesitate to _____ us if you have any further questions.", "options": ["contact", "connect", "consult", "conduct"], "answer": 0, "explanation": "'Contact us' = li\u00ean h\u1ec7 ch\u00fang t\u00f4i.", "difficulty": "medium"}, {"id": "ex-be-09", "type": "business-english", "question": "We regret to _____ you that the project has been postponed.", "options": ["indicate", "inform", "instruct", "involve"], "answer": 1, "explanation": "'Regret to inform' = ti\u1ebfc th\u00f4ng b\u00e1o.", "difficulty": "easy"}, {"id": "ex-be-10", "type": "business-english", "question": "We would like to _____ our sincere apologies for the inconvenience caused.", "options": ["express", "expand", "export", "extend"], "answer": 3, "explanation": "'Extend apologies' = g\u1eedi l\u1eddi xin l\u1ed7i.", "difficulty": "medium"}, {"id": "ex-be-11", "type": "business-english", "question": "As per your request, I have _____ the revised contract for your review.", "options": ["attached", "added", "applied", "addressed"], "answer": 0, "explanation": "'Attached the contract' = \u0111\u00ednh k\u00e8m h\u1ee3p \u0111\u1ed3ng.", "difficulty": "medium"}, {"id": "ex-be-12", "type": "business-english", "question": "The project was completed _____ budget, saving the company $50,000.", "options": ["below", "under", "within", "beneath"], "answer": 1, "explanation": "'Under budget' = d\u01b0\u1edbi ng\u00e2n s\u00e1ch d\u1ef1 ki\u1ebfn.", "difficulty": "medium"}, {"id": "ex-be-13", "type": "business-english", "question": "The company will _____ a new office in Singapore to support its Asian expansion.", "options": ["open", "establish", "set up", "launch"], "answer": 1, "explanation": "'Establish an office' = th\u00e0nh l\u1eadp v\u0103n ph\u00f2ng (trang tr\u1ecdng nh\u1ea5t).", "difficulty": "medium"}, {"id": "ex-be-14", "type": "business-english", "question": "We need to _____ on the proposal before presenting it to the client.", "options": ["follow along", "follow out", "follow through", "follow up"], "answer": 3, "explanation": "'Follow up on' = theo d\u00f5i, ti\u1ebfp n\u1ed1i.", "difficulty": "medium"}, {"id": "ex-be-15", "type": "business-english", "question": "The director asked to be _____ of any developments regarding the acquisition.", "options": ["kept informed", "informed keeping", "keeping informed", "keep informed"], "answer": 0, "explanation": "'Kept informed of' = \u0111\u01b0\u1ee3c th\u00f4ng tin li\u00ean t\u1ee5c.", "difficulty": "medium"}, {"id": "ex-be-16", "type": "business-english", "question": "Please _____ the agenda before attending the strategy session.", "options": ["go through", "go over", "look at", "check out"], "answer": 1, "explanation": "'Go over the agenda' = xem l\u1ea1i/th\u1ea3o lu\u1eadn ch\u01b0\u01a1ng tr\u00ecnh h\u1ecdp.", "difficulty": "medium"}, {"id": "ex-be-17", "type": "business-english", "question": "The quarterly review is _____ for the third week of October.", "options": ["arranged", "confirmed", "scheduled", "booked"], "answer": 2, "explanation": "'Scheduled for a date' = \u0111\u01b0\u1ee3c l\u00ean l\u1ecbch v\u00e0o ng\u00e0y.", "difficulty": "medium"}, {"id": "ex-be-18", "type": "business-english", "question": "I would like to _____ a follow-up call to discuss the proposal in more detail.", "options": ["do", "plan", "make", "arrange"], "answer": 3, "explanation": "'Arrange a call' = s\u1eafp x\u1ebfp cu\u1ed9c g\u1ecdi.", "difficulty": "medium"}, {"id": "ex-be-19", "type": "business-english", "question": "The company is committed to _____ the highest standards of service.", "options": ["maintaining", "meeting", "following", "supporting"], "answer": 0, "explanation": "'Maintaining standards' = duy tr\u00ec ti\u00eau chu\u1ea9n.", "difficulty": "medium"}, {"id": "ex-be-20", "type": "business-english", "question": "We would appreciate it if you could _____ our invoice at your earliest convenience.", "options": ["clear", "pay", "settle", "handle"], "answer": 2, "explanation": "'Settle an invoice' = thanh to\u00e1n h\u00f3a \u0111\u01a1n (t\u1eeb trang tr\u1ecdng).", "difficulty": "medium"}, {"id": "ex-sj-01", "type": "subjunctive", "question": "The board recommended that the CEO _____ an independent audit.", "options": ["commissions", "commission", "commissioned", "would commission"], "answer": 1, "explanation": "'Recommend + that + S + V (base form)' = c\u1ea5u tr\u00fac h\u01b0 c\u00e1ch.", "difficulty": "medium"}, {"id": "ex-sj-02", "type": "subjunctive", "question": "It is essential that all employees _____ the new data protection policy.", "options": ["followed", "follows", "follow", "will follow"], "answer": 2, "explanation": "Subjunctive: \"It is essential that + S + V nguy\u00ean th\u1ec3\". Kh\u00f4ng chia \u0111\u1ed9ng t\u1eeb sau that trong c\u1ea5u tr\u00fac n\u00e0y.", "difficulty": "medium"}, {"id": "ex-sj-03", "type": "subjunctive", "question": "The manager insisted that the report _____ reviewed before distribution.", "options": ["would be", "is", "was", "be"], "answer": 3, "explanation": "'Insist that + S + be + past participle' = h\u01b0 c\u00e1ch b\u1ecb \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-sj-04", "type": "subjunctive", "question": "It is vital that the financial records _____ accurate at all times.", "options": ["remain", "remains", "remained", "will remain"], "answer": 0, "explanation": "Subjunctive: \"It is vital that + S + V nguy\u00ean th\u1ec3\". T\u01b0\u01a1ng \u0111\u01b0\u01a1ng \"It is essential that\"", "difficulty": "medium"}, {"id": "ex-sj-05", "type": "subjunctive", "question": "The policy requires that every new hire _____ a background check.", "options": ["undergoes", "undergo", "underwent", "would undergo"], "answer": 1, "explanation": "\"Require that + S + V nguy\u00ean th\u1ec3\" = quy \u0111\u1ecbnh ph\u1ea3i l\u00e0m (subjunctive).", "difficulty": "medium"}, {"id": "ex-sj-06", "type": "subjunctive", "question": "The committee proposed that the meeting _____ postponed until next month.", "options": ["was", "is", "be", "should be"], "answer": 2, "explanation": "\"Propose that + S + be + V3\" = subjunctive b\u1ecb \u0111\u1ed9ng. \"Be\" l\u00e0 passive subjunctive, kh\u00f4ng chia.", "difficulty": "medium"}, {"id": "ex-sj-07", "type": "subjunctive", "question": "It is imperative that each department head _____ the budget review.", "options": ["would attend", "attends", "attended", "attend"], "answer": 3, "explanation": "\"It is imperative that + S + V nguy\u00ean th\u1ec3\" = b\u1eaft bu\u1ed9c ph\u1ea3i l\u00e0m (subjunctive m\u1ea1nh nh\u1ea5t).", "difficulty": "hard"}, {"id": "ex-sj-08", "type": "subjunctive", "question": "The legal team suggested that the contract _____ amended before signing.", "options": ["be", "is", "was", "should"], "answer": 0, "explanation": "\"Suggest that + S + be + V3\" = subjunctive b\u1ecb \u0111\u1ed9ng sau suggest. \"Be\" kh\u00f4ng chia.", "difficulty": "medium"}, {"id": "ex-sj-09", "type": "subjunctive", "question": "HR demanded that the manager _____ a formal apology to the affected staff.", "options": ["issues", "issue", "issued", "has issued"], "answer": 1, "explanation": "\"Demand that + S + V nguy\u00ean th\u1ec3\" = y\u00eau c\u1ea7u m\u1ea1nh (subjunctive). Kh\u00f4ng d\u00f9ng \"demands\" hay \"should\".", "difficulty": "medium"}, {"id": "ex-sj-10", "type": "subjunctive", "question": "It is necessary that the new policies _____ communicated clearly to all staff.", "options": ["should be", "are", "were", "be"], "answer": 3, "explanation": "\"It is necessary that + S + be + V3\" = subjunctive b\u1ecb \u0111\u1ed9ng. \"Be\" kh\u00f4ng chia theo ch\u1ee7 ng\u1eef.", "difficulty": "hard"}, {"id": "ex-sj-11", "type": "subjunctive", "question": "The director requested that the updated report _____ sent before 5 p.m.", "options": ["be", "is", "was", "had been"], "answer": 0, "explanation": "\"Request that + S + be + V3\" = subjunctive b\u1ecb \u0111\u1ed9ng ch\u00ednh th\u1ee9c.", "difficulty": "medium"}, {"id": "ex-sj-12", "type": "subjunctive", "question": "It is crucial that the team _____ prepared for all possible scenarios.", "options": ["is", "be", "was", "will be"], "answer": 1, "explanation": "\"It is crucial that + S + V nguy\u00ean th\u1ec3\" = v\u00f4 c\u00f9ng quan tr\u1ecdng (subjunctive).", "difficulty": "medium"}, {"id": "ex-sj-13", "type": "subjunctive", "question": "The auditor recommended that the internal controls _____ strengthened.", "options": ["were", "are", "be", "should be"], "answer": 2, "explanation": "\"Recommend that + S + be + V3\" = subjunctive b\u1ecb \u0111\u1ed9ng sau recommend.", "difficulty": "medium"}, {"id": "ex-sj-14", "type": "subjunctive", "question": "Management insisted that no changes _____ made without prior approval.", "options": ["would be", "are", "were", "be"], "answer": 3, "explanation": "'Insist that + S + be + past participle' (ph\u1ee7 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "ex-sj-15", "type": "subjunctive", "question": "It is important that the grievance procedure _____ fair and transparent.", "options": ["be", "is", "was", "will be"], "answer": 0, "explanation": "\"It is important that + S + be + adj\" = subjunctive v\u1edbi t\u00ednh t\u1eeb. \"Be\" kh\u00f4ng chia.", "difficulty": "medium"}, {"id": "ex-sj-16", "type": "subjunctive", "question": "The compliance officer required that all staff _____ the annual ethics course.", "options": ["completes", "complete", "completed", "would complete"], "answer": 1, "explanation": "\"Require that + S + V nguy\u00ean th\u1ec3\" = quy \u0111\u1ecbnh ph\u1ea3i l\u00e0m (subjunctive).", "difficulty": "medium"}, {"id": "ex-sj-17", "type": "subjunctive", "question": "It is recommended that the applicant _____ three professional references.", "options": ["provided", "provides", "provide", "will provide"], "answer": 2, "explanation": "\"It is recommended that + S + V nguy\u00ean th\u1ec3\" = \u0111\u01b0\u1ee3c khuy\u1ebfn c\u00e1o (passive + subjunctive).", "difficulty": "medium"}, {"id": "ex-sj-18", "type": "subjunctive", "question": "The supervisor urged that the team _____ more attention to detail.", "options": ["would pay", "pays", "paid", "pay"], "answer": 3, "explanation": "\"Urge that + S + V nguy\u00ean th\u1ec3\" = th\u00fac gi\u1ee5c l\u00e0m (subjunctive). \"Urged that it submit\" \u2014 not \"submits\".", "difficulty": "medium"}, {"id": "ex-sj-19", "type": "subjunctive", "question": "It is essential that no sensitive information _____ shared outside the organization.", "options": ["be", "is", "was", "were"], "answer": 0, "explanation": "\"It is essential that + S + be + V3\" = subjunctive b\u1ecb \u0111\u1ed9ng. \"Be prepared\" \u2014 not \"is prepared\".", "difficulty": "hard"}, {"id": "ex-sj-20", "type": "subjunctive", "question": "The board stipulated that each project _____ independently evaluated.", "options": ["was", "is", "be", "should"], "answer": 2, "explanation": "\"Stipulate that + S + be + V3\" = quy \u0111\u1ecbnh trong h\u1ee3p \u0111\u1ed3ng (subjunctive b\u1ecb \u0111\u1ed9ng). T\u1eeb ph\u00e1p l\u00fd quan tr\u1ecdng.", "difficulty": "medium"}, {"id": "ex-ps-01", "type": "prep-structures", "question": "The strategy was carried out _____ accordance with the board's recommendations.", "options": ["on", "in", "by", "at"], "answer": 1, "explanation": "'In accordance with' = ph\u00f9 h\u1ee3p v\u1edbi, theo.", "difficulty": "medium"}, {"id": "ex-ps-02", "type": "prep-structures", "question": "The project was completed _____ spite of numerous technical challenges.", "options": ["at", "on", "in", "by"], "answer": 2, "explanation": "\"In spite of\" = m\u1eb7c d\u00f9, b\u1ea5t ch\u1ea5p. D\u00f9ng v\u1edbi noun/V-ing, kh\u00f4ng d\u00f9ng v\u1edbi clause (nh\u01b0 \"although\").", "difficulty": "medium"}, {"id": "ex-ps-03", "type": "prep-structures", "question": "The decision was made _____ account of the rising operational costs.", "options": ["at", "in", "by", "on"], "answer": 3, "explanation": "\"On account of\" = v\u00ec l\u00fd do, do. C\u1ee5m gi\u1edbi t\u1eeb nguy\u00ean nh\u00e2n + noun/V-ing = because of.", "difficulty": "medium"}, {"id": "ex-ps-04", "type": "prep-structures", "question": "She was promoted _____ virtue of her outstanding performance.", "options": ["by", "in", "on", "at"], "answer": 0, "explanation": "\"By virtue of\" = nh\u1edd v\u00e0o, b\u1edfi v\u00ec (trang tr\u1ecdng). Di\u1ec5n t\u1ea3 l\u00fd do/c\u0103n c\u1ee9 trong v\u0103n phong ph\u00e1p l\u00fd.", "difficulty": "medium"}, {"id": "ex-ps-05", "type": "prep-structures", "question": "All decisions must be made _____ line with company policy.", "options": ["on", "in", "by", "at"], "answer": 1, "explanation": "\"In line with\" = ph\u00f9 h\u1ee3p v\u1edbi, nh\u1ea5t qu\u00e1n v\u1edbi. D\u00f9ng trong v\u0103n b\u1ea3n ch\u00ednh s\u00e1ch, h\u1ee3p \u0111\u1ed3ng.", "difficulty": "easy"}, {"id": "ex-ps-06", "type": "prep-structures", "question": "The consultant acted _____ behalf of the shareholders during negotiations.", "options": ["by", "in", "on", "at"], "answer": 2, "explanation": "'On behalf of' = thay m\u1eb7t cho.", "difficulty": "medium"}, {"id": "ex-ps-07", "type": "prep-structures", "question": "The acquisition was finalized _____ terms agreeable to both parties.", "options": ["at", "in", "by", "on"], "answer": 3, "explanation": "'On terms' = v\u1edbi c\u00e1c \u0111i\u1ec1u kho\u1ea3n.", "difficulty": "medium"}, {"id": "ex-ps-08", "type": "prep-structures", "question": "The document was prepared _____ advance of the board meeting.", "options": ["in", "on", "by", "at"], "answer": 0, "explanation": "\"In advance of\" = tr\u01b0\u1edbc (th\u1eddi gian). C\u1ee5m gi\u1edbi t\u1eeb ch\u1ec9 th\u1eddi gian, t\u01b0\u01a1ng t\u1ef1 \"prior to\".", "difficulty": "medium"}, {"id": "ex-ps-09", "type": "prep-structures", "question": "The new regulations came _____ force last January.", "options": ["in", "into", "on", "at"], "answer": 1, "explanation": "'Come into force' = c\u00f3 hi\u1ec7u l\u1ef1c.", "difficulty": "easy"}, {"id": "ex-ps-10", "type": "prep-structures", "question": "The proposal fell _____ of management's expectations.", "options": ["behind", "down", "out", "short"], "answer": 3, "explanation": "'Fall short of' = kh\u00f4ng \u0111\u00e1p \u1ee9ng \u0111\u01b0\u1ee3c.", "difficulty": "easy"}, {"id": "ex-ps-11", "type": "prep-structures", "question": "The team worked _____ a tight deadline to deliver the final report.", "options": ["under", "below", "within", "against"], "answer": 0, "explanation": "'Under a tight deadline' = d\u01b0\u1edbi \u00e1p l\u1ef1c th\u1eddi h\u1ea1n g\u1ea5p.", "difficulty": "medium"}, {"id": "ex-ps-12", "type": "prep-structures", "question": "The merger was approved _____ the condition that both companies retain their staff.", "options": ["in", "on", "at", "by"], "answer": 1, "explanation": "'On the condition that' = v\u1edbi \u0111i\u1ec1u ki\u1ec7n l\u00e0.", "difficulty": "medium"}, {"id": "ex-ps-13", "type": "prep-structures", "question": "His contribution to the project went _____ unnoticed for months.", "options": ["larger", "large", "largely", "largely a"], "answer": 2, "explanation": "'Went largely unnoticed' = ph\u1ea7n l\u1edbn b\u1ecb b\u1ecf qua.", "difficulty": "medium"}, {"id": "ex-ps-14", "type": "prep-structures", "question": "The results were _____ par with industry benchmarks.", "options": ["by", "in", "at", "on"], "answer": 3, "explanation": "'On par with' = ngang b\u1eb1ng v\u1edbi.", "difficulty": "easy"}, {"id": "ex-ps-15", "type": "prep-structures", "question": "The product launch was put _____ hold due to regulatory delays.", "options": ["on", "in", "at", "by"], "answer": 0, "explanation": "\"Put on hold\" = ho\u00e3n l\u1ea1i t\u1ea1m th\u1eddi. Phrasal verb th\u01b0\u01a1ng m\u1ea1i: to put something on hold.", "difficulty": "medium"}, {"id": "ex-ps-16", "type": "prep-structures", "question": "The manager was _____ charge of coordinating all international shipments.", "options": ["on", "in", "at", "by"], "answer": 1, "explanation": "\"In charge of\" = ph\u1ee5 tr\u00e1ch, ch\u1ecbu tr\u00e1ch nhi\u1ec7m v\u1ec1. Ph\u00e2n bi\u1ec7t: in charge of (ph\u1ee5 tr\u00e1ch) vs responsible for (ch\u1ecbu tr\u00e1ch nhi\u1ec7m).", "difficulty": "medium"}, {"id": "ex-ps-17", "type": "prep-structures", "question": "The company came _____ scrutiny following the financial audit.", "options": ["on", "in", "under", "at"], "answer": 2, "explanation": "'Come under scrutiny' = b\u1ecb gi\u00e1m s\u00e1t, xem x\u00e9t k\u1ef9.", "difficulty": "medium"}, {"id": "ex-ps-18", "type": "prep-structures", "question": "The initiative was taken _____ the aim of reducing carbon emissions.", "options": ["on", "for", "by", "with"], "answer": 3, "explanation": "'With the aim of' = nh\u1eb1m m\u1ee5c \u0111\u00edch.", "difficulty": "medium"}, {"id": "ex-ps-19", "type": "prep-structures", "question": "The deal was struck _____ the eleventh hour, just before the deadline.", "options": ["at", "in", "on", "by"], "answer": 0, "explanation": "'At the eleventh hour' = v\u00e0o ph\u00fat ch\u00f3t.", "difficulty": "medium"}, {"id": "ex-ps-20", "type": "prep-structures", "question": "She took _____ the responsibilities of the role with great confidence.", "options": ["up", "in", "on", "over"], "answer": 2, "explanation": "'Take on responsibilities' = \u0111\u1ea3m nh\u1eadn tr\u00e1ch nhi\u1ec7m.", "difficulty": "medium"}, {"id": "ex-p6s-01", "type": "part6-strategy", "question": "_____, we appreciate your prompt response to our inquiry.", "options": ["In conclusion", "In addition", "To summarize", "First and foremost"], "answer": 3, "explanation": "'First and foremost' = tr\u01b0\u1edbc h\u1ebft, m\u1edf \u0111\u1ea7u th\u01b0 trang tr\u1ecdng.", "difficulty": "easy"}, {"id": "ex-p6s-02", "type": "part6-strategy", "question": "Please note that the discount applies _____ to orders placed before December 31.", "options": ["only", "ever", "just", "solely"], "answer": 0, "explanation": "'Only' = ch\u1ec9, gi\u1edbi h\u1ea1n ph\u1ea1m vi \u00e1p d\u1ee5ng.", "difficulty": "medium"}, {"id": "ex-p6s-03", "type": "part6-strategy", "question": "We sincerely apologize for any inconvenience _____ by this delay.", "options": ["causing", "caused", "cause", "to cause"], "answer": 1, "explanation": "Past participle trong m\u1ec7nh \u0111\u1ec1 r\u00fat g\u1ecdn.", "difficulty": "medium"}, {"id": "ex-p6s-04", "type": "part6-strategy", "question": "_____ the survey results are reviewed, the team will prepare an action plan.", "options": ["Until", "While", "Once", "Before"], "answer": 2, "explanation": "'Once' = ngay khi k\u1ebft qu\u1ea3 \u0111\u01b0\u1ee3c xem x\u00e9t.", "difficulty": "medium"}, {"id": "ex-p6s-05", "type": "part6-strategy", "question": "The committee will _____ the issue to senior management for a final decision.", "options": ["elevate", "eliminate", "evaluate", "escalate"], "answer": 3, "explanation": "'Escalate to senior management' = leo thang, chuy\u1ec3n l\u00ean c\u1ea5p tr\u00ean.", "difficulty": "medium"}, {"id": "ex-p6s-06", "type": "part6-strategy", "question": "All applications must be _____ by the human resources department before processing.", "options": ["verified", "clarified", "modified", "certified"], "answer": 0, "explanation": "'Verified' = x\u00e1c minh tr\u01b0\u1edbc khi x\u1eed l\u00fd.", "difficulty": "medium"}, {"id": "ex-p6s-07", "type": "part6-strategy", "question": "The report _____ detailed findings on employee satisfaction across all departments.", "options": ["retains", "contains", "maintains", "sustains"], "answer": 1, "explanation": "'Contains detailed findings' = b\u00e1o c\u00e1o bao g\u1ed3m.", "difficulty": "medium"}, {"id": "ex-p6s-08", "type": "part6-strategy", "question": "We would be _____ if you could confirm receipt of this document.", "options": ["generous", "gracious", "grateful", "genuine"], "answer": 2, "explanation": "'Would be grateful if' = s\u1ebd bi\u1ebft \u01a1n n\u1ebfu.", "difficulty": "medium"}, {"id": "ex-p6s-09", "type": "part6-strategy", "question": "The terms outlined in the agreement are _____ to both negotiating parties.", "options": ["blending", "bounding", "bonding", "binding"], "answer": 3, "explanation": "'Binding' = r\u00e0ng bu\u1ed9c ph\u00e1p l\u00fd.", "difficulty": "medium"}, {"id": "ex-p6s-10", "type": "part6-strategy", "question": "We look forward to _____ a mutually beneficial arrangement.", "options": ["arriving", "reaching", "achieving", "attaining"], "answer": 1, "explanation": "'Reaching an arrangement' = \u0111\u1ea1t \u0111\u01b0\u1ee3c th\u1ecfa thu\u1eadn.", "difficulty": "easy"}, {"id": "ex-p6s-11", "type": "part6-strategy", "question": "Should you have any _____, please contact our support team immediately.", "options": ["conceptions", "concepts", "concerns", "conclusions"], "answer": 2, "explanation": "\"Have concerns\" = c\u00f3 lo ng\u1ea1i/lo l\u1eafng. Collocation: express/raise/have concerns about something.", "difficulty": "medium"}, {"id": "ex-p6s-12", "type": "part6-strategy", "question": "The revised budget will come _____ effect at the beginning of the next fiscal year.", "options": ["on", "in", "onto", "into"], "answer": 3, "explanation": "'Come into effect' = c\u00f3 hi\u1ec7u l\u1ef1c.", "difficulty": "medium"}, {"id": "ex-p6s-13", "type": "part6-strategy", "question": "Our team has been _____ tasked with overseeing the transition process.", "options": ["specifically", "specially", "speciously", "speculatively"], "answer": 0, "explanation": "'Specifically tasked with' = \u0111\u01b0\u1ee3c giao nhi\u1ec7m v\u1ee5 c\u1ee5 th\u1ec3.", "difficulty": "medium"}, {"id": "ex-p6s-14", "type": "part6-strategy", "question": "The decision to merge was made after _____ review of all available options.", "options": ["through", "thorough", "though", "thought"], "answer": 1, "explanation": "'Thorough review' = xem x\u00e9t k\u1ef9 l\u01b0\u1ee1ng.", "difficulty": "medium"}, {"id": "ex-p6s-15", "type": "part6-strategy", "question": "We are pleased to _____ that your application has been approved.", "options": ["pronounce", "denounce", "announce", "renounce"], "answer": 2, "explanation": "'Pleased to announce' = vui m\u1eebng th\u00f4ng b\u00e1o.", "difficulty": "medium"}, {"id": "ex-p6s-16", "type": "part6-strategy", "question": "The attached document _____ a comprehensive overview of the proposed changes.", "options": ["proceeds", "preserves", "prevents", "provides"], "answer": 3, "explanation": "'Provides an overview' = cung c\u1ea5p t\u1ed5ng quan.", "difficulty": "medium"}, {"id": "ex-p6s-17", "type": "part6-strategy", "question": "I am writing _____ to your advertisement for the position of Senior Analyst.", "options": ["in response", "in answer", "in return", "in reply"], "answer": 0, "explanation": "'In response to' = \u0111\u1ec3 ph\u00fac \u0111\u00e1p, tr\u1ea3 l\u1eddi.", "difficulty": "medium"}, {"id": "ex-p6s-18", "type": "part6-strategy", "question": "The event will be held _____ unless there are unforeseen circumstances.", "options": ["as planning", "as planned", "as plans", "as plan"], "answer": 1, "explanation": "\"As planned\" = nh\u01b0 k\u1ebf ho\u1ea1ch. C\u1ee5m ph\u00f3 t\u1eeb r\u00fat g\u1ecdn (= as it was planned), d\u00f9ng trong v\u0103n t\u01b0\u1eddng thu\u1eadt.", "difficulty": "medium"}, {"id": "ex-p6s-19", "type": "part6-strategy", "question": "Our client expects the project to be delivered _____ time and within budget.", "options": ["at", "in", "on", "by"], "answer": 2, "explanation": "\"On time\" = \u0111\u00fang h\u1ea1n, \u0111\u00fang gi\u1edd. Ph\u00e2n bi\u1ec7t: on time (\u0111\u00fang h\u1ea1n) vs in time (k\u1ecbp th\u1eddi tr\u01b0\u1edbc deadline).", "difficulty": "medium"}, {"id": "ex-p6s-20", "type": "part6-strategy", "question": "We _____ the opportunity to work with your distinguished organization.", "options": ["welcome", "acknowledge", "appreciate", "value"], "answer": 0, "explanation": "'Welcome the opportunity' = tr\u00e2n tr\u1ecdng c\u01a1 h\u1ed9i.", "difficulty": "medium"}, {"id": "ex-p7s-01", "type": "part7-strategy", "question": "Based on the context, the word 'paramount' is closest in meaning to _____.", "options": ["most important", "very large", "widely known", "clearly stated"], "answer": 0, "explanation": "\"Paramount\" = t\u1ed1i quan tr\u1ecdng, quan tr\u1ecdng h\u01a1n h\u1ebft. T\u1eeb \u0111\u1ed3ng ngh\u0129a: most important, supreme, primary.", "difficulty": "medium"}, {"id": "ex-p7s-02", "type": "part7-strategy", "question": "The word 'streamline' in a business context most likely means _____.", "options": ["make more complex", "make more efficient", "expand rapidly", "reduce quality"], "answer": 1, "explanation": "'Streamline' = tinh gi\u1ea3n, t\u1ed1i \u01b0u h\u00f3a quy tr\u00ecnh.", "difficulty": "medium"}, {"id": "ex-p7s-03", "type": "part7-strategy", "question": "The phrase 'in lieu of' means _____.", "options": ["because of", "in addition to", "instead of", "prior to"], "answer": 2, "explanation": "'In lieu of' = thay v\u00ec, thay th\u1ebf cho.", "difficulty": "hard"}, {"id": "ex-p7s-04", "type": "part7-strategy", "question": "The word 'mitigate' is closest in meaning to _____.", "options": ["reveal", "remove", "replace", "reduce"], "answer": 3, "explanation": "'Mitigate' = gi\u1ea3m nh\u1eb9, gi\u1ea3m thi\u1ec3u.", "difficulty": "easy"}, {"id": "ex-p7s-05", "type": "part7-strategy", "question": "'At the discretion of' means _____.", "options": ["as decided by", "in front of", "after consulting with", "in the opinion of"], "answer": 0, "explanation": "'At the discretion of' = t\u00f9y theo quy\u1ebft \u0111\u1ecbnh c\u1ee7a.", "difficulty": "easy"}, {"id": "ex-p7s-06", "type": "part7-strategy", "question": "The word 'mandatory' most closely means _____.", "options": ["recommended", "required", "optional", "preferred"], "answer": 1, "explanation": "\"Mandatory\" = b\u1eaft bu\u1ed9c, c\u01b0\u1ee1ng ch\u1ebf. T\u1eeb \u0111\u1ed3ng ngh\u0129a trong TOEIC: required, compulsory, obligatory.", "difficulty": "easy"}, {"id": "ex-p7s-07", "type": "part7-strategy", "question": "'Pending approval' means _____.", "options": ["after approval", "despite approval", "awaiting approval", "before seeking approval"], "answer": 2, "explanation": "'Pending' = \u0111ang ch\u1edd, ch\u01b0a \u0111\u01b0\u1ee3c duy\u1ec7t.", "difficulty": "easy"}, {"id": "ex-p7s-08", "type": "part7-strategy", "question": "The word 'unprecedented' is closest in meaning to _____.", "options": ["difficult to predict", "happening frequently", "well-established", "never happened before"], "answer": 3, "explanation": "'Unprecedented' = ch\u01b0a t\u1eebng x\u1ea3y ra.", "difficulty": "easy"}, {"id": "ex-p7s-09", "type": "part7-strategy", "question": "'Stipulate' in a contract context means _____.", "options": ["specify as a requirement", "suggest an option", "ignore a condition", "remove a clause"], "answer": 0, "explanation": "'Stipulate' = quy \u0111\u1ecbnh r\u00f5 r\u00e0ng, quy \u01b0\u1edbc.", "difficulty": "easy"}, {"id": "ex-p7s-10", "type": "part7-strategy", "question": "The word 'expedite' means _____.", "options": ["plan carefully", "slow down", "speed up", "review thoroughly"], "answer": 2, "explanation": "'Expedite' = th\u00fac \u0111\u1ea9y, t\u0103ng t\u1ed1c.", "difficulty": "easy"}, {"id": "ex-p7s-11", "type": "part7-strategy", "question": "'Comply with' means _____.", "options": ["ignore a rule", "question a rule", "change a rule", "follow a rule"], "answer": 3, "explanation": "\"Comply with\" = tu\u00e2n th\u1ee7, ch\u1ea5p h\u00e0nh. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: comply with + regulations/rules/requirements.", "difficulty": "easy"}, {"id": "ex-p7s-12", "type": "part7-strategy", "question": "The phrase 'on a rolling basis' means _____.", "options": ["continuously as needed", "once per year", "only in emergencies", "at fixed intervals only"], "answer": 0, "explanation": "'On a rolling basis' = li\u00ean t\u1ee5c, theo chu k\u1ef3 cu\u1ed9n.", "difficulty": "easy"}, {"id": "ex-p7s-13", "type": "part7-strategy", "question": "'Remuneration' refers to _____.", "options": ["training provided", "payment for work", "vacation time", "work schedule"], "answer": 1, "explanation": "'Remuneration' = th\u00f9 lao, ti\u1ec1n th\u01b0\u1edfng.", "difficulty": "easy"}, {"id": "ex-p7s-14", "type": "part7-strategy", "question": "The word 'discrepancy' means _____.", "options": ["a regulation", "an improvement", "a difference or inconsistency", "an agreement"], "answer": 2, "explanation": "'Discrepancy' = s\u1ef1 kh\u00e1c bi\u1ec7t, kh\u00f4ng nh\u1ea5t qu\u00e1n.", "difficulty": "easy"}, {"id": "ex-p7s-15", "type": "part7-strategy", "question": "'Commensurate with experience' means the salary _____.", "options": ["is paid in advance", "exceeds typical industry rates", "is fixed regardless of background", "reflects the applicant's experience level"], "answer": 3, "explanation": "'Commensurate with' = t\u01b0\u01a1ng x\u1ee9ng v\u1edbi.", "difficulty": "easy"}, {"id": "ex-p7s-16", "type": "part7-strategy", "question": "The word 'pursuant to' is closest in meaning to _____.", "options": ["in accordance with", "in contrast to", "in addition to", "as a result of"], "answer": 0, "explanation": "'Pursuant to' = chi\u1ebfu theo, ph\u00f9 h\u1ee3p v\u1edbi (v\u0103n b\u1ea3n ph\u00e1p l\u00fd).", "difficulty": "hard"}, {"id": "ex-p7s-17", "type": "part7-strategy", "question": "'Tangible benefits' refers to benefits that are _____.", "options": ["abstract and subjective", "real and measurable", "future and uncertain", "indirect and implied"], "answer": 1, "explanation": "'Tangible' = h\u1eefu h\u00ecnh, c\u1ee5 th\u1ec3, \u0111o l\u01b0\u1eddng \u0111\u01b0\u1ee3c.", "difficulty": "easy"}, {"id": "ex-p7s-18", "type": "part7-strategy", "question": "The phrase 'subject to change' means _____.", "options": ["has already been changed", "will not be changed", "may be changed later", "is being changed now"], "answer": 2, "explanation": "'Subject to change' = c\u00f3 th\u1ec3 thay \u0111\u1ed5i.", "difficulty": "easy"}, {"id": "ex-p7s-19", "type": "part7-strategy", "question": "'Incumbent upon' means _____.", "options": ["the recommendation of", "the choice of", "the result of", "the responsibility of"], "answer": 3, "explanation": "'Incumbent upon' = l\u00e0 tr\u00e1ch nhi\u1ec7m/b\u1ed5n ph\u1eadn c\u1ee7a.", "difficulty": "easy"}, {"id": "ex-p7s-20", "type": "part7-strategy", "question": "'Ratify an agreement' means _____.", "options": ["negotiate its terms", "officially approve it", "draft its contents", "terminate it"], "answer": 1, "explanation": "'Ratify' = ph\u00ea chu\u1ea9n ch\u00ednh th\u1ee9c.", "difficulty": "easy"}, {"id": "ex-adt-01", "type": "adverb-time", "question": "The quarterly report must be submitted _____ the end of this month.", "options": ["during", "until", "since", "by"], "answer": 3, "explanation": "'By + deadline' = kh\u00f4ng mu\u1ed9n h\u01a1n th\u1eddi h\u1ea1n \u0111\u00f3. 'Until' d\u00f9ng cho h\u00e0nh \u0111\u1ed9ng k\u00e9o d\u00e0i li\u00ean t\u1ee5c \u0111\u1ebfn m\u1ed9t m\u1ed1c th\u1eddi gian.", "difficulty": "medium"}, {"id": "ex-adt-02", "type": "adverb-time", "question": "Employees who joined the company _____ January will receive a performance bonus.", "options": ["since", "by", "during", "within"], "answer": 0, "explanation": "'Since + m\u1ed1c th\u1eddi gian c\u1ee5 th\u1ec3' + present perfect = t\u1eeb th\u1eddi \u0111i\u1ec3m \u0111\u00f3 \u0111\u1ebfn nay.", "difficulty": "medium"}, {"id": "ex-adt-03", "type": "adverb-time", "question": "The new software update will be released _____ the next two weeks.", "options": ["by", "within", "since", "after"], "answer": 1, "explanation": "'Within + kho\u1ea3ng th\u1eddi gian' = trong v\u00f2ng / kh\u00f4ng qu\u00e1 kho\u1ea3ng th\u1eddi gian \u0111\u00f3.", "difficulty": "medium"}, {"id": "ex-adt-04", "type": "adverb-time", "question": "The office will remain closed _____ the renovation is complete.", "options": ["within", "by", "until", "since"], "answer": 2, "explanation": "'Until + s\u1ef1 ki\u1ec7n/m\u1ed1c th\u1eddi gian' = cho \u0111\u1ebfn khi \u0111i\u1ec1u \u0111\u00f3 x\u1ea3y ra (h\u00e0nh \u0111\u1ed9ng k\u00e9o d\u00e0i).", "difficulty": "medium"}, {"id": "ex-adt-05", "type": "adverb-time", "question": "Ms. Park has been working in the finance department _____ she graduated.", "options": ["by", "until", "within", "since"], "answer": 3, "explanation": "'Since + th\u1eddi \u0111i\u1ec3m qu\u00e1 kh\u1ee9' v\u1edbi present perfect = t\u1eeb khi... \u0111\u1ebfn nay.", "difficulty": "medium"}, {"id": "ex-adt-06", "type": "adverb-time", "question": "Please return the signed contract _____ Friday at the latest.", "options": ["by", "until", "since", "during"], "answer": 0, "explanation": "'By Friday' = kh\u00f4ng mu\u1ed9n h\u01a1n th\u1ee9 S\u00e1u. \u0110\u00e2y l\u00e0 deadline, kh\u00f4ng ph\u1ea3i h\u00e0nh \u0111\u1ed9ng li\u00ean t\u1ee5c.", "difficulty": "medium"}, {"id": "ex-adt-07", "type": "adverb-time", "question": "The construction team worked _____ midnight to meet the project deadline.", "options": ["by", "until", "since", "within"], "answer": 1, "explanation": "'Until midnight' = l\u00e0m vi\u1ec7c li\u00ean t\u1ee5c \u0111\u1ebfn t\u1eadn n\u1eeda \u0111\u00eam. 'By midnight' s\u1ebd c\u00f3 ngh\u0129a ho\u00e0n th\u00e0nh tr\u01b0\u1edbc n\u1eeda \u0111\u00eam.", "difficulty": "medium"}, {"id": "ex-adt-08", "type": "adverb-time", "question": "The training session is scheduled _____ 2 P.M. and will last approximately three hours.", "options": ["for", "since", "by", "at"], "answer": 3, "explanation": "'At + gi\u1edd c\u1ee5 th\u1ec3' = l\u00fac... (th\u1eddi \u0111i\u1ec3m b\u1eaft \u0111\u1ea7u).", "difficulty": "medium"}, {"id": "ex-adt-09", "type": "adverb-time", "question": "The client meeting has been postponed _____ next Thursday.", "options": ["within", "by", "during", "until"], "answer": 3, "explanation": "'Postponed until' = d\u1eddi \u0111\u1ebfn / ho\u00e3n \u0111\u1ebfn th\u1eddi \u0111i\u1ec3m m\u1edbi. 'Until' ch\u1ec9 \u0111i\u1ec3m k\u1ebft th\u00fac c\u1ee7a s\u1ef1 ch\u1edd \u0111\u1ee3i.", "difficulty": "easy"}, {"id": "ex-adt-10", "type": "adverb-time", "question": "The CEO _____ arrives at the office before 7 A.M. to prepare for morning briefings.", "options": ["yet", "usually", "already", "still"], "answer": 1, "explanation": "'Usually' = th\u00f3i quen th\u01b0\u1eddng xuy\u00ean. C\u00e1c tr\u1ea1ng t\u1eeb kh\u00e1c kh\u00f4ng ph\u00f9 h\u1ee3p v\u1edbi \u00fd ngh\u0129a th\u00f3i quen \u1edf \u0111\u00e2y.", "difficulty": "medium"}, {"id": "ex-adt-11", "type": "adverb-time", "question": "The annual audit has _____ been completed, so the accountants can move on to other tasks.", "options": ["still", "yet", "already", "just"], "answer": 2, "explanation": "'Has already been completed' = \u0111\u00e3 ho\u00e0n th\u00e0nh (nh\u1ea5n m\u1ea1nh s\u1edbm h\u01a1n mong \u0111\u1ee3i).", "difficulty": "medium"}, {"id": "ex-adt-12", "type": "adverb-time", "question": "The new branch has not _____ opened to the public, but preparations are nearly finished.", "options": ["ever", "already", "still", "yet"], "answer": 3, "explanation": "'Not yet' = ch\u01b0a (v\u1edbi perfect tense, mang k\u1ef3 v\u1ecdng s\u1ebd x\u1ea3y ra s\u1edbm).", "difficulty": "medium"}, {"id": "ex-adt-13", "type": "adverb-time", "question": "We are _____ waiting for approval from the board before proceeding with the merger.", "options": ["still", "already", "yet", "ever"], "answer": 0, "explanation": "'Still waiting' = v\u1eabn \u0111ang ch\u1edd (nh\u1ea5n m\u1ea1nh th\u1eddi gian k\u00e9o d\u00e0i, \u0111\u00f4i khi h\u00e0m \u00fd s\u1ef1 ki\u00ean nh\u1eabn).", "difficulty": "medium"}, {"id": "ex-adt-14", "type": "adverb-time", "question": "The company has _____ expanded its operations to over 30 countries worldwide.", "options": ["yet", "already", "still", "never"], "answer": 1, "explanation": "'Has already expanded' = \u0111\u00e3 m\u1edf r\u1ed9ng (ho\u00e0n t\u1ea5t, nh\u1ea5n m\u1ea1nh th\u1ef1c t\u1ebf \u0111\u00e3 \u0111\u1ea1t \u0111\u01b0\u1ee3c).", "difficulty": "medium"}, {"id": "ex-adt-15", "type": "adverb-time", "question": "The printer on the third floor is _____ out of order despite repeated repair attempts.", "options": ["yet", "already", "still", "ever"], "answer": 2, "explanation": "'Still out of order' = v\u1eabn h\u1ecfng (k\u00e9o d\u00e0i b\u1ea5t ch\u1ea5p c\u1ed1 g\u1eafng s\u1eeda ch\u1eefa).", "difficulty": "medium"}, {"id": "ex-adt-16", "type": "adverb-time", "question": "Renovation work on the lobby will take place _____ regular business hours to minimise disruption.", "options": ["between", "during", "within", "outside"], "answer": 3, "explanation": "'Outside regular business hours' = ngo\u00e0i gi\u1edd l\u00e0m vi\u1ec7c (tr\u00e1i ngh\u0129a v\u1edbi 'during').", "difficulty": "medium"}, {"id": "ex-adt-17", "type": "adverb-time", "question": "The investor presentation is scheduled for _____ next Monday morning.", "options": ["early", "soon", "yet", "lately"], "answer": 0, "explanation": "'Early next Monday morning' = s\u00e1ng s\u1edbm th\u1ee9 Hai tu\u1ea7n t\u1edbi. 'Early' b\u1ed5 ngh\u0129a cho th\u1eddi \u0111i\u1ec3m.", "difficulty": "medium"}, {"id": "ex-adt-18", "type": "adverb-time", "question": "The shipment was supposed to arrive yesterday but has _____ to be delivered.", "options": ["still", "yet", "already", "ever"], "answer": 1, "explanation": "'Has yet to be delivered' = v\u1eabn ch\u01b0a \u0111\u01b0\u1ee3c giao (c\u1ea5u tr\u00fac: have yet to + V-nguy\u00ean th\u1ec3).", "difficulty": "medium"}, {"id": "ex-adt-19", "type": "adverb-time", "question": "Employees are asked to submit their expense reports no _____ than the last working day of the month.", "options": ["earlier", "sooner", "later", "further"], "answer": 2, "explanation": "'No later than' = kh\u00f4ng mu\u1ed9n h\u01a1n (deadline). C\u1ee5m c\u1ed1 \u0111\u1ecbnh th\u01b0\u1eddng g\u1eb7p trong v\u0103n b\u1ea3n TOEIC.", "difficulty": "medium"}, {"id": "ex-adt-20", "type": "adverb-time", "question": "The marketing team meets _____ to review campaign performance and plan upcoming initiatives.", "options": ["weekly", "rarely", "occasionally", "seldom"], "answer": 0, "explanation": "'Meets weekly' = h\u1ecdp h\u00e0ng tu\u1ea7n (t\u1ea7n su\u1ea5t \u0111\u1ec1u \u0111\u1eb7n, ph\u00f9 h\u1ee3p v\u1edbi ng\u1eef c\u1ea3nh review \u0111\u1ecbnh k\u1ef3).", "difficulty": "medium"}, {"id": "ex-adt-21", "type": "adverb-time", "question": "Mr. Chen will _____ be available to discuss the proposal once he returns from his business trip.", "options": ["yet", "shortly", "already", "never"], "answer": 1, "explanation": "'Shortly' = ngay sau \u0111\u00f3 / ch\u1eb3ng bao l\u00e2u n\u1eefa (s\u1eafp x\u1ea3y ra trong t\u01b0\u01a1ng lai g\u1ea7n).", "difficulty": "medium"}, {"id": "ex-adt-22", "type": "adverb-time", "question": "The company _____ revised its refund policy following numerous customer complaints.", "options": ["still", "yet", "recently", "ever"], "answer": 2, "explanation": "'Recently revised' = m\u1edbi \u0111\u00e2y \u0111\u00e3 s\u1eeda \u0111\u1ed5i (past simple + recently cho s\u1ef1 ki\u1ec7n v\u1eeba x\u1ea3y ra).", "difficulty": "medium"}, {"id": "ex-adt-23", "type": "adverb-time", "question": "We expect the server migration to be completed _____ the scheduled maintenance window.", "options": ["by the time", "since", "until", "within"], "answer": 3, "explanation": "'Within the maintenance window' = trong kho\u1ea3ng th\u1eddi gian b\u1ea3o tr\u00ec \u0111\u00e3 l\u00ean l\u1ecbch.", "difficulty": "medium"}, {"id": "ex-adt-24", "type": "adverb-time", "question": "The product launch has been moved up; it will now take place _____ than originally planned.", "options": ["earlier", "lately", "soon", "already"], "answer": 0, "explanation": "'Earlier than originally planned' = s\u1edbm h\u01a1n so v\u1edbi k\u1ebf ho\u1ea1ch ban \u0111\u1ea7u (comparative adverb).", "difficulty": "medium"}, {"id": "ex-adt-25", "type": "adverb-time", "question": "Please note that the deadline for applications has been extended _____ June 30.", "options": ["to", "by", "until", "within"], "answer": 2, "explanation": "'Extended until June 30' = gia h\u1ea1n \u0111\u1ebfn ng\u00e0y 30/6. 'Until' ch\u1ec9 \u0111i\u1ec3m k\u1ebft th\u00fac m\u1edbi.", "difficulty": "medium"}, {"id": "ex-adt-26", "type": "adverb-time", "question": "The budget committee will not approve new expenditures _____ the fiscal year review is finalised.", "options": ["since", "by", "until", "while"], "answer": 2, "explanation": "'Will not ... until' = s\u1ebd kh\u00f4ng ... cho \u0111\u1ebfn khi. C\u1ea5u tr\u00fac ph\u1ee7 \u0111\u1ecbnh + until r\u1ea5t ph\u1ed5 bi\u1ebfn trong v\u0103n b\u1ea3n kinh doanh.", "difficulty": "medium"}, {"id": "ex-adt-27", "type": "adverb-time", "question": "The CEO has _____ announced three major acquisitions this quarter, surpassing last year's total.", "options": ["rarely", "yet", "still", "already"], "answer": 3, "explanation": "'Has already announced' = \u0111\u00e3 th\u00f4ng b\u00e1o r\u1ed3i (ho\u00e0n t\u1ea5t trong quarter n\u00e0y, nh\u1ea5n m\u1ea1nh th\u00e0nh t\u00edch).", "difficulty": "medium"}, {"id": "ex-adt-28", "type": "adverb-time", "question": "The safety inspection is conducted _____ each calendar year to comply with regulations.", "options": ["twice", "double", "dual", "two times"], "answer": 0, "explanation": "'Twice a year' = hai l\u1ea7n m\u1ed9t n\u0103m (tr\u1ea1ng t\u1eeb t\u1ea7n su\u1ea5t chu\u1ea9n). 'Two times' kh\u00f4ng t\u1ef1 nhi\u00ean khi \u0111\u1ee9ng tr\u01b0\u1edbc 'each'.", "difficulty": "medium"}, {"id": "ex-vctx-01", "type": "vocabulary-context", "question": "The new recruitment strategy has proven highly _____ in attracting top talent from overseas.", "options": ["proficient", "efficient", "sufficient", "effective"], "answer": 3, "explanation": "'Effective' = c\u00f3 hi\u1ec7u qu\u1ea3, \u0111\u1ea1t \u0111\u01b0\u1ee3c k\u1ebft qu\u1ea3 mong mu\u1ed1n. 'Efficient' = ti\u1ebft ki\u1ec7m, kh\u00f4ng l\u00e3ng ph\u00ed. Context h\u1ecfi v\u1ec1 k\u1ebft qu\u1ea3 (thu h\u00fat nh\u00e2n t\u00e0i).", "difficulty": "medium"}, {"id": "ex-vctx-02", "type": "vocabulary-context", "question": "Shareholders were pleased with the company's _____ performance despite challenging market conditions.", "options": ["robust", "fragile", "mediocre", "volatile"], "answer": 0, "explanation": "'Robust performance' = hi\u1ec7u su\u1ea5t m\u1ea1nh m\u1ebd/v\u1eefng ch\u1eafc. Context 'pleased shareholders' ng\u1ee5 \u00fd k\u1ebft qu\u1ea3 t\u1ed1t.", "difficulty": "medium"}, {"id": "ex-vctx-03", "type": "vocabulary-context", "question": "The board voted to _____ the merger proposal until further due diligence could be completed.", "options": ["refer", "defer", "infer", "prefer"], "answer": 1, "explanation": "'Defer' = ho\u00e3n l\u1ea1i. 'Refer' = chuy\u1ec3n \u0111\u1ebfn. Context 'until further due diligence' ng\u1ee5 \u00fd t\u1ea1m ho\u00e3n \u0111\u1ec3 xem x\u00e9t th\u00eam.", "difficulty": "medium"}, {"id": "ex-vctx-04", "type": "vocabulary-context", "question": "The legal team reviewed the contract carefully to ensure that all terms were _____ enforceable.", "options": ["barely", "hardly", "legally", "roughly"], "answer": 2, "explanation": "'Legally enforceable' = c\u00f3 th\u1ec3 th\u1ef1c thi theo ph\u00e1p lu\u1eadt. C\u1ee5m c\u1ed1 \u0111\u1ecbnh th\u01b0\u1eddng g\u1eb7p trong v\u0103n b\u1ea3n ph\u00e1p l\u00fd.", "difficulty": "medium"}, {"id": "ex-vctx-05", "type": "vocabulary-context", "question": "The company has _____ its operations by opening offices in three new Asian markets this year.", "options": ["expelled", "extended", "exceeded", "expanded"], "answer": 3, "explanation": "'Expanded operations' = m\u1edf r\u1ed9ng ho\u1ea1t \u0111\u1ed9ng kinh doanh. 'Extended' th\u01b0\u1eddng d\u00f9ng cho th\u1eddi gian, h\u1ea1n ch\u00f3t.", "difficulty": "medium"}, {"id": "ex-vctx-06", "type": "vocabulary-context", "question": "To maintain client _____, the firm offers a dedicated account manager to each corporate customer.", "options": ["retention", "attention", "detention", "intention"], "answer": 0, "explanation": "'Client retention' = gi\u1eef ch\u00e2n kh\u00e1ch h\u00e0ng. C\u1ee5m danh t\u1eeb c\u1ed1 \u0111\u1ecbnh trong ti\u1ebfp th\u1ecb v\u00e0 kinh doanh.", "difficulty": "medium"}, {"id": "ex-vctx-07", "type": "vocabulary-context", "question": "The survey results _____ that most employees are satisfied with the new flexible working policy.", "options": ["dedicate", "indicate", "advocate", "replicate"], "answer": 1, "explanation": "'Results indicate' = k\u1ebft qu\u1ea3 cho th\u1ea5y/ch\u1ec9 ra. \u0110\u1ed9ng t\u1eeb h\u1ecdc thu\u1eadt ph\u00f9 h\u1ee3p v\u1edbi ng\u1eef c\u1ea3nh b\u00e1o c\u00e1o.", "difficulty": "medium"}, {"id": "ex-vctx-08", "type": "vocabulary-context", "question": "The financial report showed a significant _____ in operating costs over the previous fiscal year.", "options": ["instruction", "production", "reduction", "introduction"], "answer": 2, "explanation": "'Reduction in costs' = s\u1ef1 gi\u1ea3m chi ph\u00ed. Context 'significant' + 'operating costs' \u2192 reduction l\u00e0 c\u1ee5m chu\u1ea9n.", "difficulty": "medium"}, {"id": "ex-vctx-09", "type": "vocabulary-context", "question": "All staff are required to _____ with the updated data privacy regulations effective from next month.", "options": ["apply", "reply", "supply", "comply"], "answer": 3, "explanation": "'Comply with regulations' = tu\u00e2n th\u1ee7 quy \u0111\u1ecbnh. C\u1ee5m \u0111\u1ed9ng t\u1eeb c\u1ed1 \u0111\u1ecbnh trong v\u0103n b\u1ea3n quy ph\u1ea1m.", "difficulty": "medium"}, {"id": "ex-vctx-10", "type": "vocabulary-context", "question": "The project was _____ due to unforeseen technical difficulties that arose during the testing phase.", "options": ["relayed", "delayed", "displayed", "replayed"], "answer": 1, "explanation": "'Project was delayed' = d\u1ef1 \u00e1n b\u1ecb tr\u00ec ho\u00e3n. Context 'unforeseen technical difficulties' x\u00e1c nh\u1eadn ngh\u0129a tr\u00ec ho\u00e3n.", "difficulty": "medium"}, {"id": "ex-vctx-11", "type": "vocabulary-context", "question": "The new HR policy aims to _____ workplace diversity by actively recruiting from underrepresented groups.", "options": ["remote", "demote", "promote", "devote"], "answer": 2, "explanation": "'Promote diversity' = th\u00fac \u0111\u1ea9y s\u1ef1 \u0111a d\u1ea1ng. Context 'actively recruiting' x\u00e1c nh\u1eadn h\u00e0nh \u0111\u1ed9ng t\u00edch c\u1ef1c.", "difficulty": "medium"}, {"id": "ex-vctx-12", "type": "vocabulary-context", "question": "The consultant's _____ analysis identified several inefficiencies in the company's supply chain.", "options": ["enough", "rough", "tough", "thorough"], "answer": 3, "explanation": "'Thorough analysis' = ph\u00e2n t\u00edch k\u1ef9 l\u01b0\u1ee1ng/to\u00e0n di\u1ec7n. Context 'identified inefficiencies' \u2192 c\u1ea7n ph\u00e2n t\u00edch s\u00e2u.", "difficulty": "medium"}, {"id": "ex-vctx-13", "type": "vocabulary-context", "question": "Please _____ your booking at least 48 hours in advance to guarantee availability.", "options": ["confirm", "conform", "inform", "reform"], "answer": 0, "explanation": "'Confirm your booking' = x\u00e1c nh\u1eadn \u0111\u1eb7t ch\u1ed7. C\u1ee5m c\u1ed1 \u0111\u1ecbnh trong d\u1ecbch v\u1ee5 v\u00e0 du l\u1ecbch.", "difficulty": "medium"}, {"id": "ex-vctx-14", "type": "vocabulary-context", "question": "The new safety protocol was _____ across all departments following last month's incident.", "options": ["complemented", "implemented", "supplemented", "complimented"], "answer": 1, "explanation": "'Protocol was implemented' = quy tr\u00ecnh \u0111\u01b0\u1ee3c tri\u1ec3n khai. 'Complemented' = b\u1ed5 sung, kh\u00f4ng ph\u00f9 h\u1ee3p context.", "difficulty": "medium"}, {"id": "ex-vctx-15", "type": "vocabulary-context", "question": "Investors are advised to _____ their portfolios to reduce exposure to market volatility.", "options": ["identify", "simplify", "diversify", "clarify"], "answer": 2, "explanation": "'Diversify portfolios' = \u0111a d\u1ea1ng h\u00f3a danh m\u1ee5c \u0111\u1ea7u t\u01b0. Thu\u1eadt ng\u1eef t\u00e0i ch\u00ednh c\u1ed1 \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "ex-vctx-16", "type": "vocabulary-context", "question": "The merger will _____ both companies to compete more effectively in the global market.", "options": ["stable", "unable", "disable", "enable"], "answer": 3, "explanation": "'Enable companies to + V' = cho ph\u00e9p / t\u1ea1o \u0111i\u1ec1u ki\u1ec7n \u0111\u1ec3. 'Unable' l\u00e0 t\u00ednh t\u1eeb, kh\u00f4ng ph\u1ea3i \u0111\u1ed9ng t\u1eeb.", "difficulty": "medium"}, {"id": "ex-vctx-17", "type": "vocabulary-context", "question": "Staff should _____ any safety hazards to the facilities management team immediately.", "options": ["report", "support", "transport", "export"], "answer": 0, "explanation": "'Report hazards' = b\u00e1o c\u00e1o m\u1ed1i nguy hi\u1ec3m. Context 'immediately' x\u00e1c nh\u1eadn h\u00e0nh \u0111\u1ed9ng kh\u1ea9n c\u1ea5p.", "difficulty": "medium"}, {"id": "ex-vctx-18", "type": "vocabulary-context", "question": "The proposal requires _____ approval from both the legal and finance departments before it can proceed.", "options": ["minor", "prior", "senior", "junior"], "answer": 1, "explanation": "'Prior approval' = s\u1ef1 ch\u1ea5p thu\u1eadn tr\u01b0\u1edbc/s\u1ef1 ph\u00ea duy\u1ec7t tr\u01b0\u1edbc khi ti\u1ebfn h\u00e0nh. C\u1ee5m c\u1ed1 \u0111\u1ecbnh trong quy tr\u00ecnh h\u00e0nh ch\u00ednh.", "difficulty": "medium"}, {"id": "ex-vctx-19", "type": "vocabulary-context", "question": "The new packaging is designed to be fully _____ with existing recycling programmes.", "options": ["comparable", "capable", "compatible", "competitive"], "answer": 2, "explanation": "'Compatible with' = t\u01b0\u01a1ng th\u00edch v\u1edbi. Context 'existing recycling programmes' \u2192 c\u1ea7n t\u00ednh t\u01b0\u01a1ng th\u00edch.", "difficulty": "medium"}, {"id": "ex-vctx-20", "type": "vocabulary-context", "question": "The revised budget _____ an increase in marketing spend to support the product launch.", "options": ["includes", "concludes", "excludes", "precludes"], "answer": 0, "explanation": "'Budget includes' = ng\u00e2n s\u00e1ch bao g\u1ed3m. Context 'increase in marketing spend' \u2192 c\u00f3 trong ng\u00e2n s\u00e1ch.", "difficulty": "medium"}, {"id": "ex-vctx-21", "type": "vocabulary-context", "question": "The contractor submitted a detailed _____ outlining the scope of work and estimated costs.", "options": ["disposal", "proposal", "arousal", "refusal"], "answer": 1, "explanation": "'Detailed proposal' = \u0111\u1ec1 xu\u1ea5t chi ti\u1ebft. Context 'scope of work and estimated costs' = c\u1ea5u tr\u00fac c\u1ee7a m\u1ed9t b\u1ea3n \u0111\u1ec1 xu\u1ea5t.", "difficulty": "medium"}, {"id": "ex-vctx-22", "type": "vocabulary-context", "question": "The company decided to _____ its product line by discontinuing items with consistently low sales.", "options": ["decline", "headline", "streamline", "recline"], "answer": 2, "explanation": "'Streamline product line' = tinh g\u1ecdn/h\u1ee3p l\u00fd h\u00f3a d\u00f2ng s\u1ea3n ph\u1ea9m (lo\u1ea1i b\u1ecf nh\u1eefng g\u00ec kh\u00f4ng hi\u1ec7u qu\u1ea3).", "difficulty": "medium"}, {"id": "ex-vctx-23", "type": "vocabulary-context", "question": "All invoices must be _____ within 30 days of the date of issue to avoid late payment penalties.", "options": ["entitled", "bottled", "throttled", "settled"], "answer": 3, "explanation": "'Invoices settled' = thanh to\u00e1n h\u00f3a \u0111\u01a1n. Context 'avoid late payment penalties' x\u00e1c nh\u1eadn ngh\u0129a thanh to\u00e1n.", "difficulty": "medium"}, {"id": "ex-vctx-24", "type": "vocabulary-context", "question": "The new employee orientation programme is _____ to help new hires adapt to company culture quickly.", "options": ["designed", "assigned", "resigned", "declined"], "answer": 0, "explanation": "'Programme is designed to' = ch\u01b0\u01a1ng tr\u00ecnh \u0111\u01b0\u1ee3c thi\u1ebft k\u1ebf nh\u1eb1m. C\u1ea5u tr\u00fac m\u1ee5c \u0111\u00edch chu\u1ea9n.", "difficulty": "medium"}, {"id": "ex-vctx-25", "type": "vocabulary-context", "question": "The finance team _____ potential savings of over two million dollars through the new procurement process.", "options": ["notified", "identified", "satisfied", "classified"], "answer": 1, "explanation": "'Identified potential savings' = x\u00e1c \u0111\u1ecbnh \u0111\u01b0\u1ee3c kho\u1ea3n ti\u1ebft ki\u1ec7m ti\u1ec1m n\u0103ng. Context ph\u00e2n t\u00edch t\u00e0i ch\u00ednh.", "difficulty": "medium"}, {"id": "ex-vctx-26", "type": "vocabulary-context", "question": "The company's strong brand _____ gives it a significant advantage over newer competitors.", "options": ["indication", "resignation", "recognition", "destination"], "answer": 2, "explanation": "'Brand recognition' = s\u1ef1 nh\u1eadn di\u1ec7n th\u01b0\u01a1ng hi\u1ec7u. C\u1ee5m thu\u1eadt ng\u1eef marketing c\u1ed1 \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "ex-vctx-27", "type": "vocabulary-context", "question": "Failure to _____ the terms of the service agreement may result in contract termination.", "options": ["harbour", "favour", "labour", "honour"], "answer": 3, "explanation": "'Honour the terms' = th\u1ef1c hi\u1ec7n \u0111\u00fang c\u00e1c \u0111i\u1ec1u kho\u1ea3n (ngh\u0129a ph\u00e1p l\u00fd). 'Favour terms' kh\u00f4ng \u0111\u00fang c\u00fa ph\u00e1p.", "difficulty": "medium"}, {"id": "ex-vctx-28", "type": "vocabulary-context", "question": "The data analytics team was asked to _____ key trends from the quarterly consumer survey.", "options": ["extract", "distract", "detract", "retract"], "answer": 0, "explanation": "'Extract key trends' = tr\u00edch xu\u1ea5t / r\u00fat ra c\u00e1c xu h\u01b0\u1edbng ch\u00ednh t\u1eeb d\u1eef li\u1ec7u.", "difficulty": "medium"}, {"id": "ex-nc-21", "type": "noun-clauses", "question": "The HR manager explained _____ the new appraisal system would be rolled out in stages.", "options": ["what", "that", "which", "whether"], "answer": 1, "explanation": "'Explained that + m\u1ec7nh \u0111\u1ec1' = gi\u1ea3i th\u00edch r\u1eb1ng. 'Explained what' c\u0169ng c\u00f3 th\u1ec3 nh\u01b0ng c\u1ea7n V sau what.", "difficulty": "medium"}, {"id": "ex-nc-22", "type": "noun-clauses", "question": "Please clarify _____ the deadline for submitting expense reports has changed.", "options": ["what", "that", "whether", "who"], "answer": 2, "explanation": "'Clarify whether' = l\u00e0m r\u00f5 li\u1ec7u... c\u00f3 hay kh\u00f4ng. C\u00e2u h\u1ecfi yes/no gi\u00e1n ti\u1ebfp d\u00f9ng whether.", "difficulty": "medium"}, {"id": "ex-nc-23", "type": "noun-clauses", "question": "The auditors were unable to determine _____ the discrepancy had occurred in the accounts.", "options": ["if", "that", "which", "where"], "answer": 3, "explanation": "'Determine where' = x\u00e1c \u0111\u1ecbnh \u1edf \u0111\u00e2u (v\u1ecb tr\u00ed x\u1ea3y ra sai l\u1ec7ch trong s\u1ed5 s\u00e1ch).", "difficulty": "medium"}, {"id": "ex-nc-24", "type": "noun-clauses", "question": "The committee has not yet decided _____ the project will be approved for additional funding.", "options": ["whether", "that", "how", "whose"], "answer": 0, "explanation": "'Decided whether' = quy\u1ebft \u0111\u1ecbnh li\u1ec7u c\u00f3 (ch\u01b0a c\u00f3 quy\u1ebft \u0111\u1ecbnh, h\u00e0m \u00fd kh\u1ea3 n\u0103ng c\u00f3/kh\u00f4ng).", "difficulty": "medium"}, {"id": "ex-nc-25", "type": "noun-clauses", "question": "_____ the new policy applies to part-time staff is still under review by the HR department.", "options": ["That", "Whether", "What", "Which"], "answer": 1, "explanation": "'Whether ... is still under review' = whether l\u00e0m ch\u1ee7 ng\u1eef c\u1ee7a c\u00e2u, ch\u1ec9 v\u1ea5n \u0111\u1ec1 c\u00f2n \u0111ang xem x\u00e9t.", "difficulty": "medium"}, {"id": "ex-nc-26", "type": "noun-clauses", "question": "The sales director confirmed _____ the annual target had been exceeded by fifteen percent.", "options": ["whether", "what", "that", "how"], "answer": 2, "explanation": "'Confirmed that' = x\u00e1c nh\u1eadn r\u1eb1ng (th\u00f4ng tin ch\u1eafc ch\u1eafn). 'Confirmed whether' d\u00f9ng khi c\u00f2n nghi v\u1ea5n.", "difficulty": "medium"}, {"id": "ex-nc-27", "type": "noun-clauses", "question": "The report does not specify _____ data was collected from or how it was verified.", "options": ["that", "what", "whether", "where"], "answer": 3, "explanation": "'Specify where ... from' = ch\u1ec9 r\u00f5 d\u1eef li\u1ec7u \u0111\u01b0\u1ee3c thu th\u1eadp t\u1eeb \u0111\u00e2u (ngu\u1ed3n g\u1ed1c).", "difficulty": "medium"}, {"id": "ex-nc-28", "type": "noun-clauses", "question": "Investors want to know _____ the company plans to use the funds raised in the IPO.", "options": ["how", "that", "whether", "which"], "answer": 0, "explanation": "'Know how ... plans to use' = bi\u1ebft c\u00f4ng ty c\u00f3 k\u1ebf ho\u1ea1ch s\u1eed d\u1ee5ng v\u1ed1n huy \u0111\u1ed9ng nh\u01b0 th\u1ebf n\u00e0o.", "difficulty": "medium"}, {"id": "ex-pt-21", "type": "participles", "question": "_____ by rising demand, the company decided to increase its production capacity by 40 percent.", "options": ["Drive", "Driving", "Driven", "Having drive"], "answer": 2, "explanation": "'Driven by' = \u0111\u01b0\u1ee3c th\u00fac \u0111\u1ea9y b\u1edfi (participle phrase = passive cause). Ch\u1ee7 ng\u1eef 'the company' l\u00e0 \u0111\u1ed1i t\u01b0\u1ee3ng b\u1ecb t\u00e1c \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "ex-pt-22", "type": "participles", "question": "The project manager submitted the report _____ all outstanding tasks and their due dates.", "options": ["lists", "listed", "to list", "listing"], "answer": 3, "explanation": "'Report listing' = b\u00e1o c\u00e1o li\u1ec7t k\u00ea... (present participle b\u1ed5 ngh\u0129a cho noun 'report' - m\u00f4 t\u1ea3 n\u1ed9i dung).", "difficulty": "medium"}, {"id": "ex-pt-23", "type": "participles", "question": "_____ in the 1990s, the firm has grown from a small startup into a multinational corporation.", "options": ["Founded", "Founding", "Found", "Having founding"], "answer": 0, "explanation": "'Founded in' = \u0111\u01b0\u1ee3c th\u00e0nh l\u1eadp v\u00e0o. Participle passive phrase \u0111\u1eb7t \u0111\u1ea7u c\u00e2u b\u1ed5 ngh\u0129a cho 'the firm'.", "difficulty": "medium"}, {"id": "ex-pt-24", "type": "participles", "question": "The documents _____ for the legal review were missing several key signatures.", "options": ["requiring", "required", "require", "to require"], "answer": 1, "explanation": "'Documents required for' = t\u00e0i li\u1ec7u \u0111\u01b0\u1ee3c y\u00eau c\u1ea7u (cho vi\u1ec7c xem x\u00e9t ph\u00e1p l\u00fd). Passive participle.", "difficulty": "medium"}, {"id": "ex-pt-25", "type": "participles", "question": "_____ the budget limitations, the team found creative solutions to deliver the project on time.", "options": ["Acknowledge", "Acknowledged", "Acknowledging", "Having acknowledge"], "answer": 2, "explanation": "'Acknowledging limitations' = nh\u1eadn th\u1ee9c \u0111\u01b0\u1ee3c / th\u1eeba nh\u1eadn (active participle, ch\u1ee7 ng\u1eef 'the team' th\u1ef1c hi\u1ec7n h\u00e0nh \u0111\u1ed9ng).", "difficulty": "medium"}, {"id": "ex-pt-26", "type": "participles", "question": "The keynote address _____ by the CEO focused on innovation and market expansion.", "options": ["to deliver", "delivering", "deliver", "delivered"], "answer": 3, "explanation": "'Address delivered by' = b\u00e0i ph\u00e1t bi\u1ec3u \u0111\u01b0\u1ee3c tr\u00ecnh b\u00e0y b\u1edfi (passive participle b\u1ed5 ngh\u0129a cho 'address').", "difficulty": "medium"}, {"id": "ex-pt-27", "type": "participles", "question": "_____ the unexpected results, the research team immediately began a second round of testing.", "options": ["Surprised by", "Surprising", "To surprise", "Surprised"], "answer": 0, "explanation": "'Surprised by + unexpected results' = b\u1ecb b\u1ea5t ng\u1edd b\u1edfi (participle phrase + by phrase ch\u1ec9 nguy\u00ean nh\u00e2n).", "difficulty": "medium"}, {"id": "ex-pt-28", "type": "participles", "question": "The memo _____ all department heads outlined the new procedures for handling customer data.", "options": ["circulating to", "circulated to", "to circulate", "circulate"], "answer": 1, "explanation": "'Memo circulated to all department heads' = b\u1ea3n ghi nh\u1edb \u0111\u01b0\u1ee3c ph\u1ed5 bi\u1ebfn \u0111\u1ebfn (passive participle).", "difficulty": "medium"}, {"id": "ex-pt-29", "type": "participles", "question": "_____ the contract terms carefully, the procurement officer noticed an ambiguous liability clause.", "options": ["Review", "Reviewed", "Reviewing", "Having reviewed"], "answer": 2, "explanation": "'Reviewing the contract terms' (present participle) = trong l\u00fac xem x\u00e9t / khi xem x\u00e9t (ch\u1ee7 ng\u1eef th\u1ef1c hi\u1ec7n h\u00e0nh \u0111\u1ed9ng).", "difficulty": "medium"}, {"id": "ex-be-21", "type": "business-english", "question": "We would like to _____ our apologies for the inconvenience caused by the system outage.", "options": ["exploit", "expand", "express", "extend"], "answer": 3, "explanation": "'Extend apologies' = g\u1eedi l\u1eddi xin l\u1ed7i (c\u1ee5m th\u00e0nh ng\u1eef kinh doanh trang tr\u1ecdng). 'Express apologies' c\u0169ng \u0111\u00fang nh\u01b0ng 'extend' trang tr\u1ecdng h\u01a1n.", "difficulty": "medium"}, {"id": "ex-be-22", "type": "business-english", "question": "Please feel free to _____ me if you require any additional information regarding your order.", "options": ["contact", "contract", "conflict", "conduct"], "answer": 0, "explanation": "'Feel free to contact me' = \u0111\u1eebng ng\u1ea1i li\u00ean h\u1ec7 v\u1edbi t\u00f4i. C\u00e2u m\u1eddi th\u00e2n thi\u1ec7n trong th\u01b0 kinh doanh.", "difficulty": "medium"}, {"id": "ex-be-23", "type": "business-english", "question": "The management team will take the employees' concerns into _____ when finalising the restructuring plan.", "options": ["action", "account", "effect", "place"], "answer": 1, "explanation": "'Take into account' = t\u00ednh \u0111\u1ebfn / xem x\u00e9t. Th\u00e0nh ng\u1eef c\u1ed1 \u0111\u1ecbnh kh\u00f4ng th\u1ec3 thay th\u1ebf b\u1eb1ng t\u1eeb kh\u00e1c.", "difficulty": "medium"}, {"id": "ex-be-24", "type": "business-english", "question": "We are writing _____ to your inquiry dated March 10 regarding our enterprise software packages.", "options": ["in regard", "in respect", "in response", "in return"], "answer": 2, "explanation": "'In response to your inquiry' = \u0111\u1ec3 ph\u1ea3n h\u1ed3i y\u00eau c\u1ea7u c\u1ee7a b\u1ea1n. C\u1ee5m m\u1edf \u0111\u1ea7u email/th\u01b0 ph\u1ed5 bi\u1ebfn.", "difficulty": "medium"}, {"id": "ex-be-25", "type": "business-english", "question": "As per our previous discussion, the revised proposal will be sent to you _____ end of business today.", "options": ["within", "before", "until", "by"], "answer": 3, "explanation": "'By end of business' = tr\u01b0\u1edbc khi h\u1ebft gi\u1edd l\u00e0m vi\u1ec7c h\u00f4m nay (deadline). C\u1ee5m c\u1ed1 \u0111\u1ecbnh trong ti\u1ebfng Anh th\u01b0\u01a1ng m\u1ea1i.", "difficulty": "medium"}, {"id": "ex-be-26", "type": "business-english", "question": "The team will _____ a thorough market analysis before presenting recommendations to the board.", "options": ["conduct", "contact", "construct", "contradict"], "answer": 0, "explanation": "'Conduct a thorough analysis' = ti\u1ebfn h\u00e0nh ph\u00e2n t\u00edch k\u1ef9 l\u01b0\u1ee1ng. Collocation chu\u1ea9n trong kinh doanh.", "difficulty": "medium"}, {"id": "ex-be-27", "type": "business-english", "question": "We regret to _____ you that your application was not successful on this occasion.", "options": ["reform", "inform", "confirm", "perform"], "answer": 1, "explanation": "'Regret to inform' = ti\u1ebfc ph\u1ea3i th\u00f4ng b\u00e1o (c\u1ee5m trang tr\u1ecdng d\u00f9ng khi t\u1eeb ch\u1ed1i/b\u00e1o tin kh\u00f4ng t\u1ed1t).", "difficulty": "medium"}, {"id": "ex-be-28", "type": "business-english", "question": "The management team has agreed to _____ the matter on a case-by-case basis going forward.", "options": ["address", "assess", "process", "progress"], "answer": 3, "explanation": "'Progress the matter' = ti\u1ebfn tri\u1ec3n x\u1eed l\u00fd v\u1ea5n \u0111\u1ec1. 'Address' c\u0169ng \u0111\u00fang nh\u01b0ng 'progress' + 'going forward' l\u00e0 c\u1ee5m BE ph\u1ed5 bi\u1ebfn.", "difficulty": "medium"}, {"id": "ex-be-29", "type": "business-english", "question": "Should you have any further questions, please do not _____ to reach out to our support team.", "options": ["negotiate", "estimate", "deliberate", "hesitate"], "answer": 3, "explanation": "'Do not hesitate to' = \u0111\u1eebng ng\u1ea7n ng\u1ea1i (c\u1ee5m l\u1ecbch s\u1ef1 c\u1ed1 \u0111\u1ecbnh trong giao ti\u1ebfp kinh doanh).", "difficulty": "medium"}, {"id": "ex-ps-21", "type": "prep-structures", "question": "The board approved the acquisition plan _____ opposition from the minority shareholders.", "options": ["even", "although", "however", "despite"], "answer": 3, "explanation": "'Despite + N/V-ing' = m\u1eb7c d\u00f9 (gi\u1edbi t\u1eeb, theo sau l\u00e0 danh t\u1eeb). 'Although + clause' theo sau l\u00e0 m\u1ec7nh \u0111\u1ec1.", "difficulty": "medium"}, {"id": "ex-ps-22", "type": "prep-structures", "question": "The firm is known _____ its commitment to environmental sustainability and ethical sourcing.", "options": ["for", "by", "to", "with"], "answer": 0, "explanation": "'Known for' = n\u1ed5i ti\u1ebfng v\u00ec. Colocation c\u1ed1 \u0111\u1ecbnh: be known for + noun/gerund.", "difficulty": "medium"}, {"id": "ex-ps-23", "type": "prep-structures", "question": "She is responsible _____ overseeing all incoming and outgoing communications for the executive team.", "options": ["of", "for", "to", "with"], "answer": 1, "explanation": "'Responsible for' = ch\u1ecbu tr\u00e1ch nhi\u1ec7m v\u1ec1. Collocation c\u1ed1 \u0111\u1ecbnh kh\u00f4ng thay th\u1ebf.", "difficulty": "medium"}, {"id": "ex-ps-24", "type": "prep-structures", "question": "The product recall was carried out _____ compliance with safety standards set by the regulator.", "options": ["at", "by", "in", "on"], "answer": 2, "explanation": "'In compliance with' = \u0111\u1ec3 tu\u00e2n th\u1ee7. C\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh trong v\u0103n b\u1ea3n quy ph\u1ea1m v\u00e0 kinh doanh.", "difficulty": "medium"}, {"id": "ex-ps-25", "type": "prep-structures", "question": "The marketing team is currently working _____ a comprehensive brand refresh strategy.", "options": ["for", "at", "in", "on"], "answer": 3, "explanation": "'Working on' = \u0111ang l\u00e0m vi\u1ec7c v\u1ec1 (m\u1ed9t d\u1ef1 \u00e1n/chi\u1ebfn l\u01b0\u1ee3c). Phrasal verb c\u1ed1 \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "ex-ps-26", "type": "prep-structures", "question": "The seminar will focus _____ leadership strategies for managing remote and hybrid teams.", "options": ["on", "at", "to", "into"], "answer": 0, "explanation": "'Focus on' = t\u1eadp trung v\u00e0o. Phrasal verb kh\u00f4ng thay th\u1ebf.", "difficulty": "medium"}, {"id": "ex-ps-27", "type": "prep-structures", "question": "The committee voted _____ favour of extending the pilot programme for another six months.", "options": ["at", "in", "on", "by"], "answer": 1, "explanation": "'In favour of' = \u1ee7ng h\u1ed9 / \u0111\u1ed3ng \u00fd v\u1edbi. C\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh trong b\u1ecf phi\u1ebfu v\u00e0 tranh lu\u1eadn.", "difficulty": "medium"}, {"id": "ex-ps-28", "type": "prep-structures", "question": "The sales figures are consistent _____ projections made at the beginning of the financial year.", "options": ["in", "to", "with", "at"], "answer": 2, "explanation": "'Consistent with' = nh\u1ea5t qu\u00e1n v\u1edbi / ph\u00f9 h\u1ee3p v\u1edbi. Collocation c\u1ed1 \u0111\u1ecbnh trong b\u00e1o c\u00e1o ph\u00e2n t\u00edch.", "difficulty": "medium"}, {"id": "ex-iv-21", "type": "inversion", "question": "Not only _____ the project delivered ahead of schedule, but it also came in under budget.", "options": ["did", "was", "had", "were"], "answer": 1, "explanation": "'Not only was ... ' = \u0111\u1ea3o ng\u1eef v\u1edbi 'not only' d\u00f9ng be-verb. Ch\u1ee7 ng\u1eef 'the project' + was.", "difficulty": "hard"}, {"id": "ex-iv-22", "type": "inversion", "question": "_____ does the company offer competitive salaries, but it also provides generous benefits packages.", "options": ["No sooner", "Only if", "Not only", "Hardly"], "answer": 2, "explanation": "'Not only does ... but also' = kh\u00f4ng ch\u1ec9 ... m\u00e0 c\u00f2n. C\u1ea5u tr\u00fac \u0111\u1ea3o ng\u1eef nh\u1ea5n m\u1ea1nh v\u1edbi auxiliary 'does'.", "difficulty": "hard"}, {"id": "ex-iv-23", "type": "inversion", "question": "Rarely _____ the board convene more than twice in a single month without significant cause.", "options": ["do", "is", "has", "does"], "answer": 3, "explanation": "'Rarely does ... convene' = hi\u1ebfm khi h\u1ecdp (\u0111\u1ea3o ng\u1eef v\u1edbi rarely + auxiliary does + S + V-bare).", "difficulty": "hard"}, {"id": "ex-iv-24", "type": "inversion", "question": "Under no circumstances _____ employees share confidential client data with third parties.", "options": ["should", "would", "will", "must"], "answer": 0, "explanation": "'Under no circumstances should' = trong m\u1ecdi tr\u01b0\u1eddng h\u1ee3p kh\u00f4ng \u0111\u01b0\u1ee3c (\u0111\u1ea3o ng\u1eef ph\u1ee7 \u0111\u1ecbnh tuy\u1ec7t \u0111\u1ed1i).", "difficulty": "hard"}, {"id": "ex-iv-25", "type": "inversion", "question": "No sooner _____ the CEO resigned than the share price fell sharply.", "options": ["did", "had", "was", "were"], "answer": 1, "explanation": "'No sooner had ... than' = v\u1eeba ... th\u00ec ngay. C\u1ea5u tr\u00fac \u0111\u1ea3o ng\u1eef past perfect c\u1ed1 \u0111\u1ecbnh.", "difficulty": "hard"}, {"id": "ex-iv-26", "type": "inversion", "question": "Only after extensive negotiations _____ both parties agree to the revised contract terms.", "options": ["were", "had", "did", "would"], "answer": 2, "explanation": "'Only after ... did both parties agree' = ch\u1ec9 sau khi ... m\u1edbi \u0111\u1ed3ng \u00fd (\u0111\u1ea3o ng\u1eef nh\u1ea5n m\u1ea1nh v\u1edbi only + time phrase).", "difficulty": "hard"}, {"id": "ex-iv-27", "type": "inversion", "question": "Seldom _____ a product launch received such widespread positive coverage in the trade press.", "options": ["is", "had", "does", "has"], "answer": 3, "explanation": "'Seldom has ... received' = \u00edt khi n\u00e0o ... \u0111\u01b0\u1ee3c \u0111\u00f3n nh\u1eadn (\u0111\u1ea3o ng\u1eef v\u1edbi present perfect).", "difficulty": "hard"}, {"id": "ex-qn-21", "type": "quantifiers", "question": "_____ feedback received from the pilot group will be used to improve the training programme.", "options": ["Every", "All", "Each", "Either"], "answer": 1, "explanation": "'All feedback' = to\u00e0n b\u1ed9 ph\u1ea3n h\u1ed3i (all + uncountable noun). 'Every/Each' + countable singular noun.", "difficulty": "medium"}, {"id": "ex-qn-22", "type": "quantifiers", "question": "The company has _____ experienced staff to handle the increased workload during the peak season.", "options": ["plenty", "much", "enough", "several"], "answer": 2, "explanation": "'Enough + countable plural noun' = \u0111\u1ee7 nh\u00e2n vi\u00ean. 'Enough' c\u00f3 th\u1ec3 d\u00f9ng tr\u01b0\u1edbc c\u1ea3 countable l\u1eabn uncountable.", "difficulty": "medium"}, {"id": "ex-qn-23", "type": "quantifiers", "question": "_____ of the survey respondents indicated they were satisfied with the new customer service protocol.", "options": ["Few", "Much", "Little", "Most"], "answer": 3, "explanation": "'Most of the respondents' = ph\u1ea7n l\u1edbn (most + of + the + countable noun). 'Much' cho uncountable.", "difficulty": "medium"}, {"id": "ex-qn-24", "type": "quantifiers", "question": "There is _____ room in the current budget for discretionary spending this quarter.", "options": ["little", "few", "less", "fewer"], "answer": 0, "explanation": "'Little room' = \u00edt ch\u1ed7 / kh\u00f4ng nhi\u1ec1u (little + uncountable noun = s\u1ed1 l\u01b0\u1ee3ng nh\u1ecf). 'Few' + countable.", "difficulty": "medium"}, {"id": "ex-qn-25", "type": "quantifiers", "question": "_____ department must submit its annual report to the finance team by December 31.", "options": ["All", "Each", "Most", "Several"], "answer": 1, "explanation": "'Each department' + singular verb = m\u1ed7i ph\u00f2ng ban (ri\u00eang l\u1ebb). 'All departments' + plural verb.", "difficulty": "medium"}, {"id": "ex-qn-26", "type": "quantifiers", "question": "The company has received _____ applications than expected, so the selection process will take longer.", "options": ["many", "much", "more", "most"], "answer": 2, "explanation": "'More applications than expected' = nhi\u1ec1u h\u1ed3 s\u01a1 h\u01a1n d\u1ef1 ki\u1ebfn (comparative + countable noun).", "difficulty": "medium"}, {"id": "ex-qn-27", "type": "quantifiers", "question": "_____ the competitors have managed to replicate our patented manufacturing process successfully.", "options": ["Either of", "All of", "Each of", "None of"], "answer": 3, "explanation": "'None of the competitors have' = kh\u00f4ng ai trong s\u1ed1 \u0111\u1ed1i th\u1ee7 (none of + plural noun + plural verb th\u00f4ng th\u01b0\u1eddng).", "difficulty": "medium"}, {"id": "ex-sj-21", "type": "subjunctive", "question": "The board of directors has recommended that the CEO _____ an independent review of operations.", "options": ["commissioning", "commissions", "commissioned", "commission"], "answer": 3, "explanation": "'Recommend that + S + V-bare' (subjunctive) = \u0111\u1ec1 ngh\u1ecb r\u1eb1ng. Kh\u00f4ng th\u00eam -s cho ng\u00f4i th\u1ee9 ba.", "difficulty": "medium"}, {"id": "ex-sj-22", "type": "subjunctive", "question": "It is essential that every team leader _____ the compliance training before the end of the month.", "options": ["complete", "completes", "completing", "completed"], "answer": 0, "explanation": "'It is essential that + S + V-bare' (subjunctive). Kh\u00f4ng th\u00eam -s d\u00f9 ch\u1ee7 ng\u1eef l\u00e0 'every team leader'.", "difficulty": "hard"}, {"id": "ex-sj-23", "type": "subjunctive", "question": "The client insisted that the invoice _____ revised to reflect the agreed discount.", "options": ["is", "be", "was", "were"], "answer": 1, "explanation": "'Insist that + S + be' (subjunctive passive). 'Be' kh\u00f4ng thay \u0111\u1ed5i theo ch\u1ee7 ng\u1eef trong subjunctive.", "difficulty": "medium"}, {"id": "ex-sj-24", "type": "subjunctive", "question": "It is imperative that all employees _____ the data protection agreement before accessing the new system.", "options": ["signing", "signs", "sign", "signed"], "answer": 2, "explanation": "'It is imperative that + S + V-bare' (subjunctive). 'Signs' sai v\u00ec subjunctive kh\u00f4ng chia theo ng\u00f4i.", "difficulty": "medium"}, {"id": "ex-sj-25", "type": "subjunctive", "question": "The finance committee proposed that the annual budget _____ reviewed on a quarterly basis.", "options": ["being", "is", "was", "be"], "answer": 3, "explanation": "'Proposed that + S + be' (subjunctive passive). C\u1ea5u tr\u00fac trang tr\u1ecdng trong v\u0103n b\u1ea3n h\u00e0nh ch\u00ednh.", "difficulty": "medium"}, {"id": "ex-sj-26", "type": "subjunctive", "question": "Legal counsel advised that the firm _____ entering into any further agreements until the dispute is resolved.", "options": ["avoid", "avoids", "avoiding", "avoided"], "answer": 0, "explanation": "'Advised that + S + V-bare' (subjunctive). 'Avoid' kh\u00f4ng c\u00f3 -s trong c\u1ea5u tr\u00fac n\u00e0y.", "difficulty": "medium"}, {"id": "ex-sj-27", "type": "subjunctive", "question": "The regulations require that all vendors _____ certified before being added to the approved supplier list.", "options": ["are", "be", "were", "being"], "answer": 1, "explanation": "'Require that + S + be' (subjunctive). \u0110\u1ed9ng t\u1eeb m\u1ec7nh l\u1ec7nh nh\u01b0 require, mandate, demand \u2192 subjunctive.", "difficulty": "medium"}, {"id": "ex-cd-21", "type": "conditionals", "question": "_____ additional resources been allocated earlier, the project would not have been delayed.", "options": ["If", "Had", "Were", "Should"], "answer": 1, "explanation": "'Had + S + V3' = if + had + V3 (\u0111\u1ea3o ng\u1eef c\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 3 - gi\u1ea3 \u0111\u1ecbnh qu\u00e1 kh\u1ee9).", "difficulty": "medium"}, {"id": "ex-cd-22", "type": "conditionals", "question": "_____ you require any assistance, please do not hesitate to contact our customer support team.", "options": ["Were", "Had", "Should", "If only"], "answer": 2, "explanation": "'Should you require' = if you should require (\u0111\u1ea3o ng\u1eef c\u00e2u \u0111i\u1ec1u ki\u1ec7n l\u1ecbch s\u1ef1, lo\u1ea1i 1/t\u01b0\u01a1ng lai).", "difficulty": "hard"}, {"id": "ex-cd-23", "type": "conditionals", "question": "If the proposal _____ approved at Thursday's meeting, implementation will begin in the following month.", "options": ["would be", "were", "had been", "is"], "answer": 3, "explanation": "'If + present simple \u2192 future simple' = c\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 1 (kh\u1ea3 n\u0103ng th\u1ef1c t\u1ebf).", "difficulty": "medium"}, {"id": "ex-cd-24", "type": "conditionals", "question": "The company would have avoided the penalty _____ it complied with the reporting requirements on time.", "options": ["had", "if", "should", "were"], "answer": 0, "explanation": "'Would have avoided ... had it complied' = \u0111\u1ea3o ng\u1eef lo\u1ea1i 3. 'Had + S + V3' thay cho 'if + had'.", "difficulty": "medium"}, {"id": "ex-cd-25", "type": "conditionals", "question": "_____ the market conditions to improve, the company would consider resuming expansion plans.", "options": ["Had", "Were", "Should", "If"], "answer": 1, "explanation": "'Were + S + to + V' = \u0111\u1ea3o ng\u1eef c\u00e2u \u0111i\u1ec1u ki\u1ec7n lo\u1ea1i 2 trang tr\u1ecdng (gi\u1ea3 \u0111\u1ecbnh hi\u1ec7n t\u1ea1i \u00edt kh\u1ea3 n\u0103ng x\u1ea3y ra).", "difficulty": "medium"}, {"id": "ex-sv-21", "type": "subject-verb", "question": "The team of engineers _____ currently reviewing the structural designs for the new facility.", "options": ["have", "are", "were", "is"], "answer": 3, "explanation": "'Team' l\u00e0 danh t\u1eeb t\u1eadp th\u1ec3 \u2192 \u0111\u1ed9ng t\u1eeb s\u1ed1 \u00edt (is). C\u1ee5m 'of engineers' kh\u00f4ng thay \u0111\u1ed5i ch\u1ee7 ng\u1eef.", "difficulty": "medium"}, {"id": "ex-sv-22", "type": "subject-verb", "question": "Neither the director nor the department heads _____ been informed of the proposed changes.", "options": ["have", "has", "was", "is"], "answer": 0, "explanation": "'Neither A nor B' \u2192 \u0111\u1ed9ng t\u1eeb theo B (department heads = plural \u2192 have). Quy t\u1eafc proximity.", "difficulty": "medium"}, {"id": "ex-sv-23", "type": "subject-verb", "question": "Each of the documents submitted for review _____ to include a signed declaration page.", "options": ["need", "needs", "are needing", "have needed"], "answer": 1, "explanation": "'Each of' + plural noun \u2192 \u0111\u1ed9ng t\u1eeb s\u1ed1 \u00edt (needs). 'Each' lu\u00f4n k\u00e9o singular verb.", "difficulty": "medium"}, {"id": "ex-sv-24", "type": "subject-verb", "question": "The number of applicants who qualified for the second interview _____ higher than anticipated.", "options": ["have been", "were", "was", "are"], "answer": 2, "explanation": "'The number of' \u2192 singular (was). Ph\u00e2n bi\u1ec7t: 'A number of' \u2192 plural. 'The number of' \u2192 singular.", "difficulty": "medium"}, {"id": "ex-md-21", "type": "modal", "question": "Employees _____ submit their timesheets by noon on Friday or face a deduction in their next paycheck.", "options": ["should", "might", "could", "must"], "answer": 3, "explanation": "'Must' = b\u1eaft bu\u1ed9c / y\u00eau c\u1ea7u c\u1ee9ng nh\u1eafc (strong obligation). Context 'or face a deduction' x\u00e1c nh\u1eadn \u0111\u00e2y l\u00e0 y\u00eau c\u1ea7u b\u1eaft bu\u1ed9c.", "difficulty": "medium"}, {"id": "ex-cm-21", "type": "comparison", "question": "The second-quarter results were far _____ than analysts had initially predicted.", "options": ["better", "good", "well", "best"], "answer": 0, "explanation": "'Far better than' = t\u1ed1t h\u01a1n nhi\u1ec1u so v\u1edbi (comparative + than). 'Far' t\u0103ng c\u01b0\u1eddng m\u1ee9c \u0111\u1ed9 so s\u00e1nh.", "difficulty": "medium"}, {"id": "ex-cm-22", "type": "comparison", "question": "This year's operational costs are _____ lower than those recorded in the previous fiscal year.", "options": ["significant", "significantly", "most significant", "more significantly"], "answer": 1, "explanation": "'Significantly lower' = th\u1ea5p h\u01a1n \u0111\u00e1ng k\u1ec3 (adverb + comparative adjective). 'Significantly' b\u1ed5 ngh\u0129a cho 'lower'.", "difficulty": "medium"}, {"id": "ex-wf-21", "type": "word-form", "question": "The committee reached a _____ on the proposed budget after three hours of discussion.", "options": ["decide", "decision", "decisive", "decisively"], "answer": 1, "explanation": "Sau m\u1ea1o t\u1eeb 'a' c\u1ea7n danh t\u1eeb \u2192 decision.", "difficulty": "medium"}, {"id": "ex-wf-22", "type": "word-form", "question": "Ms. Park is _____ responsible for overseeing all international shipments.", "options": ["person", "personal", "personally", "personalize"], "answer": 2, "explanation": "B\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb \u2192 tr\u1ea1ng t\u1eeb 'personally'.", "difficulty": "medium"}, {"id": "ex-wf-23", "type": "word-form", "question": "The new regulation requires full _____ from all licensed vendors.", "options": ["comply", "compliant", "complying", "compliance"], "answer": 3, "explanation": "Sau 'full' c\u1ea7n danh t\u1eeb \u2192 compliance.", "difficulty": "medium"}, {"id": "ex-wf-24", "type": "word-form", "question": "A _____ engineer will inspect the facility before operations resume.", "options": ["certify", "certifiable", "certification", "certified"], "answer": 3, "explanation": "B\u1ed5 ngh\u0129a cho danh t\u1eeb 'engineer' \u2192 t\u00ednh t\u1eeb 'certified'.", "difficulty": "medium"}, {"id": "ex-wf-25", "type": "word-form", "question": "The proposal was rejected due to its _____ with the company's core values.", "options": ["inconsistent", "inconsistency", "inconsistently", "inconsistence"], "answer": 1, "explanation": "Sau 'its' c\u1ea7n danh t\u1eeb \u2192 inconsistency.", "difficulty": "medium"}, {"id": "ex-wf-26", "type": "word-form", "question": "Employees who submit _____ expense reports will be reimbursed within five days.", "options": ["accuracy", "accurate", "accurately", "accurateness"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho danh t\u1eeb 'reports' \u2192 t\u00ednh t\u1eeb 'accurate'.", "difficulty": "medium"}, {"id": "ex-wf-27", "type": "word-form", "question": "The marketing director praised the team for their _____ in meeting the campaign deadline.", "options": ["efficient", "efficiently", "efficiency", "efficiencies"], "answer": 2, "explanation": "Sau 'their' c\u1ea7n danh t\u1eeb \u2192 efficiency.", "difficulty": "medium"}, {"id": "ex-wf-28", "type": "word-form", "question": "Dr. Chen delivered a _____ speech that inspired all conference attendees.", "options": ["motivational", "motivation", "motivate", "motivationally"], "answer": 0, "explanation": "B\u1ed5 ngh\u0129a cho danh t\u1eeb 'speech' \u2192 motivational.", "difficulty": "medium"}, {"id": "ex-wf-29", "type": "word-form", "question": "The company _____ its service warranty from one year to three years.", "options": ["extend", "extension", "extensive", "extensively"], "answer": 0, "explanation": "C\u1ea7n \u0111\u1ed9ng t\u1eeb chia theo ch\u1ee7 ng\u1eef 'The company' \u2192 extend.", "difficulty": "medium"}, {"id": "ex-wf-30", "type": "word-form", "question": "Strict _____ to workplace safety protocols is non-negotiable at this facility.", "options": ["adhere", "adherent", "adhering", "adherence"], "answer": 3, "explanation": "Sau 'Strict' c\u1ea7n danh t\u1eeb \u2192 adherence.", "difficulty": "medium"}, {"id": "ex-wf-31", "type": "word-form", "question": "The annual report showed a _____ improvement in operating margins.", "options": ["remark", "remarked", "remarkably", "remarkable"], "answer": 3, "explanation": "B\u1ed5 ngh\u0129a cho 'improvement' \u2192 t\u00ednh t\u1eeb remarkable.", "difficulty": "medium"}, {"id": "ex-wf-32", "type": "word-form", "question": "All new hires are required to undergo a _____ health and safety orientation.", "options": ["comprehensive", "comprehend", "comprehension", "comprehensively"], "answer": 0, "explanation": "T\u00ednh t\u1eeb b\u1ed5 ngh\u0129a cho danh t\u1eeb \u2192 comprehensive.", "difficulty": "hard"}, {"id": "ex-wf-33", "type": "word-form", "question": "The board approved the _____ of two regional offices into a single headquarters.", "options": ["consolidate", "consolidated", "consolidation", "consolidating"], "answer": 2, "explanation": "Sau 'the' c\u1ea7n danh t\u1eeb \u2192 consolidation.", "difficulty": "medium"}, {"id": "ex-wf-34", "type": "word-form", "question": "Our customer support team responds to all inquiries _____ and professionally.", "options": ["prompt", "promptness", "promptly", "prompting"], "answer": 2, "explanation": "B\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'responds' \u2192 tr\u1ea1ng t\u1eeb promptly.", "difficulty": "medium"}, {"id": "ex-wf-35", "type": "word-form", "question": "The sudden _____ in raw material prices affected the production budget significantly.", "options": ["fluctuate", "fluctuated", "fluctuating", "fluctuation"], "answer": 3, "explanation": "Sau 'The sudden' c\u1ea7n danh t\u1eeb \u2192 fluctuation.", "difficulty": "medium"}, {"id": "ex-wf-36", "type": "word-form", "question": "Management expressed _____ with the audit team's findings and will address each point.", "options": ["satisfy", "satisfaction", "satisfied", "satisfactory"], "answer": 1, "explanation": "Sau 'expressed' c\u1ea7n danh t\u1eeb \u2192 satisfaction.", "difficulty": "medium"}, {"id": "ex-wf-37", "type": "word-form", "question": "The new software platform is fully _____ with all major operating systems.", "options": ["compatibility", "compatible", "compatibly", "compatibilize"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho danh t\u1eeb \u2192 t\u00ednh t\u1eeb compatible.", "difficulty": "medium"}, {"id": "ex-wf-38", "type": "word-form", "question": "Please submit a _____ account of the incident for the insurance claim.", "options": ["detail", "detailing", "detailed", "detailedly"], "answer": 2, "explanation": "T\u00ednh t\u1eeb tr\u01b0\u1edbc danh t\u1eeb 'account' \u2192 detailed.", "difficulty": "medium"}, {"id": "ex-wf-39", "type": "word-form", "question": "The _____ of the new production line was completed two weeks ahead of schedule.", "options": ["install", "installment", "installing", "installation"], "answer": 3, "explanation": "Sau 'The' c\u1ea7n danh t\u1eeb s\u1ef1 ki\u1ec7n \u2192 installation.", "difficulty": "medium"}, {"id": "ex-wf-40", "type": "word-form", "question": "Several _____ firms were invited to bid on the infrastructure project.", "options": ["qualify", "qualified", "qualification", "qualifying"], "answer": 1, "explanation": "T\u00ednh t\u1eeb b\u1ed5 ngh\u0129a cho 'firms' \u2192 qualified.", "difficulty": "medium"}, {"id": "ex-wf-41", "type": "word-form", "question": "The board acknowledged the team's _____ contributions to the merger negotiations.", "options": ["value", "valuably", "valuation", "valuable"], "answer": 3, "explanation": "T\u00ednh t\u1eeb tr\u01b0\u1edbc 'contributions' \u2192 valuable.", "difficulty": "medium"}, {"id": "ex-wf-42", "type": "word-form", "question": "To ensure product _____, all items undergo a final inspection before shipment.", "options": ["consistent", "consists", "consistently", "consistency"], "answer": 3, "explanation": "Sau 'product' c\u1ea7n danh t\u1eeb \u2192 consistency.", "difficulty": "medium"}, {"id": "ex-wf-43", "type": "word-form", "question": "The finance team works _____ to reconcile all transactions before the quarterly close.", "options": ["diligence", "diligently", "diligent", "diligentness"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb 'works' \u2192 tr\u1ea1ng t\u1eeb diligently.", "difficulty": "medium"}, {"id": "ex-wf-44", "type": "word-form", "question": "The CEO issued a _____ statement addressing concerns raised by shareholders.", "options": ["clarifying", "clarity", "clarified", "clarification"], "answer": 0, "explanation": "D\u00f9ng participial adjective 'clarifying' \u0111\u1ec3 b\u1ed5 ngh\u0129a cho 'statement'.", "difficulty": "medium"}, {"id": "ex-wf-45", "type": "word-form", "question": "Strong _____ skills are essential for anyone in a customer-facing role.", "options": ["communicate", "communicative", "communication", "communicably"], "answer": 2, "explanation": "Sau 'Strong' c\u1ea7n danh t\u1eeb \u2192 communication.", "difficulty": "medium"}, {"id": "ex-wf-46", "type": "word-form", "question": "The _____ of the quarterly targets boosted team morale considerably.", "options": ["achieve", "achiever", "achievable", "achievement"], "answer": 3, "explanation": "Sau 'The' c\u1ea7n danh t\u1eeb k\u1ebft qu\u1ea3 \u2192 achievement.", "difficulty": "medium"}, {"id": "ex-wf-47", "type": "word-form", "question": "Regulations _____ that all food manufacturers display nutritional information on packaging.", "options": ["mandating", "mandatory", "mandatorily", "mandate"], "answer": 3, "explanation": "C\u1ea7n \u0111\u1ed9ng t\u1eeb nguy\u00ean m\u1eabu theo ch\u1ee7 ng\u1eef 'Regulations' \u2192 mandate.", "difficulty": "medium"}, {"id": "ex-wf-48", "type": "word-form", "question": "The travel allowance is provided exclusively for _____ business trips.", "options": ["approve", "approval", "approved", "approvingly"], "answer": 2, "explanation": "T\u00ednh t\u1eeb d\u1ea1ng past participle b\u1ed5 ngh\u0129a cho 'trips' \u2192 approved.", "difficulty": "medium"}, {"id": "ex-wf-49", "type": "word-form", "question": "A _____ review of all vendor contracts will be conducted in Q1.", "options": ["thoroughly", "thorough", "thoroughness", "thoroughgoing"], "answer": 1, "explanation": "T\u00ednh t\u1eeb b\u1ed5 ngh\u0129a cho danh t\u1eeb 'review' \u2192 thorough.", "difficulty": "medium"}, {"id": "ex-wf-50", "type": "word-form", "question": "The project manager demonstrated _____ leadership throughout the challenging renovation.", "options": ["exceptional", "exception", "exceptionally", "excepting"], "answer": 0, "explanation": "T\u00ednh t\u1eeb tr\u01b0\u1edbc 'leadership' \u2192 exceptional.", "difficulty": "medium"}, {"id": "ex-wf-51", "type": "word-form", "question": "Our firm has built a reputation for _____ customer service over the past decade.", "options": ["excellence", "excellent", "excelling", "excellently"], "answer": 1, "explanation": "T\u00ednh t\u1eeb b\u1ed5 ngh\u0129a cho 'customer service' \u2192 excellent.", "difficulty": "medium"}, {"id": "ex-wf-52", "type": "word-form", "question": "The _____ in supply chain logistics reduced delivery times by 30 percent.", "options": ["innovate", "innovative", "innovatively", "innovation"], "answer": 3, "explanation": "Sau 'The' c\u1ea7n danh t\u1eeb \u2192 innovation.", "difficulty": "medium"}, {"id": "ex-wf-53", "type": "word-form", "question": "Staff members are encouraged to raise concerns _____ rather than through formal complaints.", "options": ["informality", "informal", "informally", "inform"], "answer": 2, "explanation": "Tr\u1ea1ng t\u1eeb b\u1ed5 ngh\u0129a cho c\u1ee5m \u0111\u1ed9ng t\u1eeb \u2192 informally.", "difficulty": "medium"}, {"id": "ex-wf-54", "type": "word-form", "question": "The factory's _____ processes were updated to comply with the new environmental law.", "options": ["manufacture", "manufacturing", "manufacturer", "manufactured"], "answer": 1, "explanation": "Danh t\u1eeb d\u1ea1ng gerund b\u1ed5 ngh\u0129a cho 'processes' \u2192 manufacturing.", "difficulty": "medium"}, {"id": "ex-wf-55", "type": "word-form", "question": "Investors remain _____ about the company's ability to recover in the next fiscal year.", "options": ["optimism", "optimist", "optimistic", "optimistically"], "answer": 2, "explanation": "Sau 'remain' (linking verb) c\u1ea7n t\u00ednh t\u1eeb \u2192 optimistic.", "difficulty": "medium"}, {"id": "ex-art-01", "type": "pronoun", "question": "Ms. Tanaka is _____ only employee who holds dual certification in safety and quality management.", "options": ["a", "an", "no article", "the"], "answer": 3, "explanation": "'Only' x\u00e1c \u0111\u1ecbnh duy nh\u1ea5t \u2192 d\u00f9ng 'the'.", "difficulty": "medium"}, {"id": "ex-art-02", "type": "pronoun", "question": "Please submit _____ updated version of the report by Friday afternoon.", "options": ["a", "no article", "the", "an"], "answer": 3, "explanation": "'Updated' ph\u00e1t \u00e2m b\u1eaft \u0111\u1ea7u b\u1eb1ng nguy\u00ean \u00e2m /\u028c/ \u2192 d\u00f9ng 'an'.", "difficulty": "medium"}, {"id": "ex-art-03", "type": "pronoun", "question": "The board of directors will hold _____ special meeting next Monday to address the acquisition.", "options": ["no article", "an", "the", "a"], "answer": 3, "explanation": "L\u1ea7n \u0111\u1ea7u \u0111\u1ec1 c\u1eadp \u2192 d\u00f9ng 'a'. 'Special' b\u1eaft \u0111\u1ea7u b\u1eb1ng ph\u1ee5 \u00e2m.", "difficulty": "medium"}, {"id": "ex-art-04", "type": "pronoun", "question": "Employees are advised to take _____ advantage of the new wellness program.", "options": ["a", "an", "the", "no article"], "answer": 3, "explanation": "C\u1ee5m c\u1ed1 \u0111\u1ecbnh 'take advantage of' kh\u00f4ng d\u00f9ng m\u1ea1o t\u1eeb.", "difficulty": "medium"}, {"id": "ex-art-05", "type": "pronoun", "question": "Our company signed _____ agreement with three major suppliers last quarter.", "options": ["a", "the", "an", "no article"], "answer": 2, "explanation": "'Agreement' b\u1eaft \u0111\u1ea7u b\u1eb1ng nguy\u00ean \u00e2m /\u0259/ \u2192 'an agreement'.", "difficulty": "medium"}, {"id": "ex-art-06", "type": "pronoun", "question": "The maintenance crew will conduct _____ routine inspection of all equipment on Tuesday.", "options": ["the", "an", "a", "no article"], "answer": 2, "explanation": "'Routine' b\u1eaft \u0111\u1ea7u b\u1eb1ng ph\u1ee5 \u00e2m /r/ \u2192 d\u00f9ng 'a routine inspection'.", "difficulty": "medium"}, {"id": "ex-art-07", "type": "pronoun", "question": "Participants in _____ workshop are expected to submit their evaluation forms before leaving.", "options": ["a", "the", "an", "no article"], "answer": 1, "explanation": "\u0110\u00e3 \u0111\u1ec1 c\u1eadp ho\u1eb7c x\u00e1c \u0111\u1ecbnh c\u1ee5 th\u1ec3 (ng\u01b0\u1eddi tham gia bi\u1ebft workshop n\u00e0o) \u2192 d\u00f9ng 'the'.", "difficulty": "medium"}, {"id": "ex-art-08", "type": "pronoun", "question": "Mr. Rivera was appointed as _____ interim director while the search for a permanent replacement continues.", "options": ["a", "an", "the", "no article"], "answer": 1, "explanation": "'Interim' b\u1eaft \u0111\u1ea7u b\u1eb1ng nguy\u00ean \u00e2m /\u026a/ \u2192 'an interim director'.", "difficulty": "medium"}, {"id": "ex-art-09", "type": "pronoun", "question": "The legal team confirmed that _____ contract was fully enforceable under international law.", "options": ["a", "an", "no article", "the"], "answer": 3, "explanation": "H\u1ee3p \u0111\u1ed3ng \u0111\u00e3 bi\u1ebft ng\u1eef c\u1ea3nh (\u0111\u00e3 \u0111\u1ec1 c\u1eadp) \u2192 'the contract'.", "difficulty": "medium"}, {"id": "ex-art-10", "type": "pronoun", "question": "There has been _____ significant increase in remote work adoption over the past two years.", "options": ["no article", "an", "the", "a"], "answer": 3, "explanation": "'Significant' /s\u026a\u0261/ b\u1eaft \u0111\u1ea7u b\u1eb1ng ph\u1ee5 \u00e2m \u2192 'a significant increase'.", "difficulty": "medium"}, {"id": "ex-art-11", "type": "pronoun", "question": "_____ customer satisfaction is our top priority at every stage of the service process.", "options": ["A", "An", "The", "no article"], "answer": 3, "explanation": "Kh\u00e1i ni\u1ec7m chung (uncountable) \u2192 kh\u00f4ng d\u00f9ng m\u1ea1o t\u1eeb: 'Customer satisfaction is...'.", "difficulty": "medium"}, {"id": "ex-art-12", "type": "pronoun", "question": "All applicants must submit _____ official transcript along with their application.", "options": ["a", "the", "an", "no article"], "answer": 2, "explanation": "'Official' b\u1eaft \u0111\u1ea7u b\u1eb1ng nguy\u00ean \u00e2m /\u0252/ \u2192 'an official transcript'.", "difficulty": "medium"}, {"id": "ex-art-13", "type": "pronoun", "question": "The factory underwent _____ extensive renovation during the third quarter of last year.", "options": ["a", "no article", "the", "an"], "answer": 3, "explanation": "'Extensive' b\u1eaft \u0111\u1ea7u b\u1eb1ng nguy\u00ean \u00e2m /\u026a/ \u2192 'an extensive renovation'.", "difficulty": "medium"}, {"id": "ex-art-14", "type": "pronoun", "question": "We expect to reach _____ agreement on the final terms by the end of this week.", "options": ["an", "a", "the", "no article"], "answer": 0, "explanation": "'An agreement' \u2014 l\u1ea7n \u0111\u1ea7u \u0111\u1ec1 c\u1eadp, nguy\u00ean \u00e2m /\u0259/.", "difficulty": "medium"}, {"id": "ex-art-15", "type": "pronoun", "question": "Please forward _____ email to the entire department as soon as it is received.", "options": ["a", "an", "the", "no article"], "answer": 2, "explanation": "Ch\u1ec9 email c\u1ee5 th\u1ec3 \u0111\u00e3 \u0111\u01b0\u1ee3c x\u00e1c \u0111\u1ecbnh \u2192 'the email'.", "difficulty": "medium"}, {"id": "ex-art-16", "type": "pronoun", "question": "_____ success of the campaign depended heavily on timely market research.", "options": ["A", "An", "no article", "The"], "answer": 3, "explanation": "'The success of the campaign' \u2014 x\u00e1c \u0111\u1ecbnh c\u1ee5 th\u1ec3 (campaign \u0111\u00e3 bi\u1ebft) \u2192 'The'.", "difficulty": "medium"}, {"id": "ex-gi-21", "type": "gerund-infinitive", "question": "The manager suggested _____ the meeting to next Thursday to allow more preparation time.", "options": ["postponing", "to postpone", "postpone", "postponed"], "answer": 0, "explanation": "'Suggest' lu\u00f4n \u0111i v\u1edbi gerund (V-ing): suggest doing.", "difficulty": "medium"}, {"id": "ex-gi-22", "type": "gerund-infinitive", "question": "The engineering team managed _____ the prototype within the original budget.", "options": ["completing", "complete", "to complete", "completed"], "answer": 2, "explanation": "'Manage' \u0111i v\u1edbi to-infinitive: manage to do.", "difficulty": "medium"}, {"id": "ex-gi-23", "type": "gerund-infinitive", "question": "We strongly recommend _____ travel insurance before any international business trip.", "options": ["purchasing", "purchase", "to purchase", "purchased"], "answer": 0, "explanation": "'Recommend' \u0111i v\u1edbi gerund: recommend doing.", "difficulty": "medium"}, {"id": "ex-gi-24", "type": "gerund-infinitive", "question": "The supervisor reminded all staff _____ their timesheets before leaving on Friday.", "options": ["submitting", "to submit", "submit", "submitted"], "answer": 1, "explanation": "\"Remind + object + to-infinitive\" = nh\u1eafc nh\u1edf ai l\u00e0m g\u00ec. \"Remind someone to do\" l\u00e0 c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "ex-gi-25", "type": "gerund-infinitive", "question": "After _____ the quarterly data, the analyst presented her findings to the board.", "options": ["review", "to review", "reviewing", "reviewed"], "answer": 2, "explanation": "Sau gi\u1edbi t\u1eeb 'after' ph\u1ea3i d\u00f9ng gerund: after reviewing.", "difficulty": "medium"}, {"id": "ex-gi-26", "type": "gerund-infinitive", "question": "The company decided _____ its office in downtown rather than relocate to the suburbs.", "options": ["renovating", "renovate", "renovation", "to renovate"], "answer": 3, "explanation": "'Decide' \u0111i v\u1edbi to-infinitive: decide to do.", "difficulty": "medium"}, {"id": "ex-gi-27", "type": "gerund-infinitive", "question": "All employees must avoid _____ sensitive client information via unsecured channels.", "options": ["to share", "sharing", "shared", "share"], "answer": 1, "explanation": "'Avoid' lu\u00f4n \u0111i v\u1edbi gerund: avoid doing.", "difficulty": "medium"}, {"id": "ex-gi-28", "type": "gerund-infinitive", "question": "The HR director offered _____ the new employees on their first day.", "options": ["orienting", "to orient", "orientate", "orient"], "answer": 1, "explanation": "'Offer' \u0111i v\u1edbi to-infinitive: offer to do.", "difficulty": "medium"}, {"id": "ex-gi-29", "type": "gerund-infinitive", "question": "Please consider _____ the delivery date given the recent supply chain delays.", "options": ["to extend", "extend", "extending", "extended"], "answer": 2, "explanation": "'Consider' \u0111i v\u1edbi gerund: consider doing.", "difficulty": "medium"}, {"id": "ex-gi-30", "type": "gerund-infinitive", "question": "The contractor agreed _____ any damage caused during the renovation at no additional cost.", "options": ["to repair", "repair", "repairing", "repaired"], "answer": 0, "explanation": "'Agree' \u0111i v\u1edbi to-infinitive: agree to do.", "difficulty": "medium"}, {"id": "ex-gi-31", "type": "gerund-infinitive", "question": "The department head encouraged all junior staff _____ for the leadership development programme.", "options": ["to apply", "applying", "apply", "applied"], "answer": 0, "explanation": "\"Encourage + object + to-infinitive\" = khuy\u1ebfn kh\u00edch ai l\u00e0m g\u00ec. C\u1ea5u tr\u00fac: encourage + person + to V.", "difficulty": "medium"}, {"id": "ex-gi-32", "type": "gerund-infinitive", "question": "The client insisted on _____ the terms of the contract before signing.", "options": ["to renegotiate", "renegotiating", "renegotiate", "renegotiated"], "answer": 1, "explanation": "\"Insist on + V-ing\" = c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh. \"On\" l\u00e0 gi\u1edbi t\u1eeb \u2192 V-ing. \"Insist on doing\" = kh\u0103ng kh\u0103ng l\u00e0m.", "difficulty": "medium"}, {"id": "ex-gi-33", "type": "gerund-infinitive", "question": "The new policy prohibits employees from _____ personal devices to company servers.", "options": ["connecting", "connected", "to connect", "connect"], "answer": 0, "explanation": "\"Prohibit + object + from + V-ing\" = c\u1ea5m ai l\u00e0m g\u00ec. \"From\" l\u00e0 gi\u1edbi t\u1eeb \u2192 V-ing. T\u01b0\u01a1ng t\u1ef1 \"prevent/stop from\".", "difficulty": "medium"}, {"id": "ex-gi-34", "type": "gerund-infinitive", "question": "Ms. Lee was pleased _____ that her proposal had been approved by the executive board.", "options": ["learning", "having learned", "learn", "to learn"], "answer": 3, "explanation": "\"Pleased + to-infinitive\" = vui khi l\u00e0m (stative adjective + to-V). \"Pleased to learn/hear/meet\" l\u00e0 collocation ph\u1ed5 bi\u1ebfn.", "difficulty": "medium"}, {"id": "ex-gi-35", "type": "gerund-infinitive", "question": "The operations manager keeps _____ new suppliers to ensure competitive pricing.", "options": ["to evaluate", "evaluating", "evaluate", "evaluated"], "answer": 1, "explanation": "'Keep' \u0111i v\u1edbi gerund: keep doing.", "difficulty": "medium"}, {"id": "ex-gi-36", "type": "gerund-infinitive", "question": "The project lead tends _____ too many tasks simultaneously, which affects quality.", "options": ["taking on", "take on", "to take on", "taken on"], "answer": 2, "explanation": "'Tend' \u0111i v\u1edbi to-infinitive: tend to do.", "difficulty": "medium"}, {"id": "ex-gi-37", "type": "gerund-infinitive", "question": "Before _____ a vendor, the procurement team verifies all compliance certifications.", "options": ["selecting", "to select", "selected", "select"], "answer": 0, "explanation": "Sau gi\u1edbi t\u1eeb 'Before' ph\u1ea3i d\u00f9ng gerund: before selecting.", "difficulty": "medium"}, {"id": "nwf-01", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the new regulation will affect all registered businesses.", "options": ["implementation", "implement", "implemented", "implementing"], "answer": 0, "explanation": "After \"The\" \u2192 noun needed. \"Implementation\" (n) = s\u1ef1 th\u1ef1c hi\u1ec7n. H\u1eadu t\u1ed1 -tion = danh t\u1eeb."}, {"id": "nwf-02", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Our customer service team handles complaints _____ and professionally.", "options": ["efficient", "efficiently", "efficiencies", "efficiency"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb \"handles\" \u2192 ph\u00f3 t\u1eeb -ly. \"Efficiently\" = m\u1ed9t c\u00e1ch hi\u1ec7u qu\u1ea3."}, {"id": "nwf-03", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The board made a _____ decision to relocate the headquarters.", "options": ["unanimity", "unanimously", "unanimous", "unanimousness"], "answer": 2, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"decision\" \u2192 t\u00ednh t\u1eeb. \"Unanimous\" (adj) = nh\u1ea5t tr\u00ed, to\u00e0n th\u1ec3 \u0111\u1ed3ng \u00fd."}, {"id": "nwf-04", "part": 5, "type": "word-form", "difficulty": "easy", "question": "Dr. Kim is known for her _____ in neuroscience research.", "options": ["expert", "expertise", "expertly", "experts"], "answer": 1, "explanation": "After \"her\" (possessive) \u2192 noun. \"Expertise\" (n) = chuy\u00ean m\u00f4n, ki\u1ebfn th\u1ee9c chuy\u00ean s\u00e2u."}, {"id": "nwf-05", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The renovation project was completed _____ within the allocated budget.", "options": ["success", "successfully", "successful", "successive"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho c\u1ee5m V \"was completed\" \u2192 ph\u00f3 t\u1eeb. \"Successfully\" (adv) = th\u00e0nh c\u00f4ng."}, {"id": "nwf-06", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The company requires full _____ with all environmental regulations.", "options": ["compliance", "compliant", "comply", "compliantly"], "answer": 0, "explanation": "After \"full\" (adj) \u2192 noun. \"Compliance\" (n) = s\u1ef1 tu\u00e2n th\u1ee7. H\u1eadu t\u1ed1 -ance = danh t\u1eeb."}, {"id": "nwf-07", "part": 5, "type": "word-form", "difficulty": "easy", "question": "Employees must handle customer data in a _____ manner.", "options": ["confide", "confident", "confidentially", "confidential"], "answer": 3, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"manner\" \u2192 t\u00ednh t\u1eeb. \"Confidential\" (adj) = b\u00ed m\u1eadt, c\u00f3 t\u00ednh b\u1ea3o m\u1eadt."}, {"id": "nwf-08", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The _____ of the merger talks surprised industry analysts.", "options": ["abrupt", "abruptly", "abruptness", "abruption"], "answer": 2, "explanation": "After \"The\" \u2192 noun (ch\u1ee7 ng\u1eef c\u00e2u). \"Abruptness\" (n) = s\u1ef1 \u0111\u1ed9t ng\u1ed9t. H\u1eadu t\u1ed1 -ness = danh t\u1eeb."}, {"id": "nwf-09", "part": 5, "type": "word-form", "difficulty": "easy", "question": "Please _____ the attached form and return it by Friday.", "options": ["complete", "completion", "completely", "completing"], "answer": 0, "explanation": "After \"Please\" \u2192 V nguy\u00ean th\u1ec3 (imperative). \"Complete\" (v) = ho\u00e0n th\u00e0nh, \u0111i\u1ec1n \u0111\u1ea7y \u0111\u1ee7."}, {"id": "nwf-10", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The new machine is more _____ than the previous model.", "options": ["reliability", "reliably", "reliable", "reliance"], "answer": 2, "explanation": "After \"more\" (so s\u00e1nh h\u01a1n) \u2192 t\u00ednh t\u1eeb. \"Reliable\" (adj) = \u0111\u00e1ng tin c\u1eady. more + adj."}, {"id": "nwf-11", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the annual report was delayed due to data issues.", "options": ["publish", "published", "publisher", "publication"], "answer": 3, "explanation": "After \"The\" \u2192 noun (ch\u1ee7 ng\u1eef). \"Publication\" (n) = s\u1ef1 xu\u1ea5t b\u1ea3n, \u1ea5n ph\u1ea9m. -tion = danh t\u1eeb."}, {"id": "nwf-12", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Staff members are _____ encouraged to participate in the survey.", "options": ["strongly", "strong", "strength", "strengthen"], "answer": 0, "explanation": "B\u1ed5 ngh\u0129a cho V \"are encouraged\" \u2192 ph\u00f3 t\u1eeb. \"Strongly\" (adv) = m\u1ea1nh m\u1ebd, r\u1ea5t."}, {"id": "nwf-13", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ between the two companies led to a joint product line.", "options": ["collaboration", "collaborator", "collaborate", "collaborative"], "answer": 0, "explanation": "After \"The\" \u2192 noun (ch\u1ee7 ng\u1eef). \"Collaboration\" (n) = s\u1ef1 h\u1ee3p t\u00e1c. H\u1eadu t\u1ed1 -tion = danh t\u1eeb."}, {"id": "nwf-14", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The supervisor found the intern's proposal quite _____ and well-researched.", "options": ["impress", "impressively", "impressive", "impression"], "answer": 2, "explanation": "After \"quite\" (adverb of degree) \u2192 adjective. \"Impressive\" (adj) = \u1ea5n t\u01b0\u1ee3ng. -ive = adj."}, {"id": "nwf-15", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The company's _____ policy prohibits personal use of work equipment.", "options": ["strict", "strictly", "strictness", "stricter"], "answer": 0, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"policy\" \u2192 t\u00ednh t\u1eeb. \"Strict\" (adj) = nghi\u00eam ng\u1eb7t, ch\u1eb7t ch\u1ebd."}, {"id": "nwf-16", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The marketing team's _____ increased revenue by 25% this quarter.", "options": ["initiation", "initiated", "initiate", "initiative"], "answer": 3, "explanation": "After \"team's\" (possessive) \u2192 noun (ch\u1ee7 ng\u1eef). \"Initiative\" (n) = s\u00e1ng ki\u1ebfn, chi\u1ebfn l\u01b0\u1ee3c."}, {"id": "nwf-17", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Ms. Park is _____ responsible for overseeing the entire project timeline.", "options": ["personally", "personal", "person", "personnel"], "answer": 0, "explanation": "B\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb \"responsible\" \u2192 ph\u00f3 t\u1eeb. \"Personally\" (adv) = c\u00e1 nh\u00e2n, tr\u1ef1c ti\u1ebfp."}, {"id": "nwf-18", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of new safety protocols has been scheduled for next month.", "options": ["introduce", "introductory", "introducing", "introduction"], "answer": 3, "explanation": "After \"The\" \u2192 noun (ch\u1ee7 ng\u1eef). \"Introduction\" (n) = s\u1ef1 gi\u1edbi thi\u1ec7u, vi\u1ec7c \u00e1p d\u1ee5ng l\u1ea7n \u0111\u1ea7u."}, {"id": "nwf-19", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The presentation was _____ received by all board members.", "options": ["enthusiasm", "enthusiastic", "enthusiastically", "enthusiast"], "answer": 2, "explanation": "B\u1ed5 ngh\u0129a cho V \"was received\" \u2192 ph\u00f3 t\u1eeb. \"Enthusiastically\" (adv) = h\u00e0o h\u1ee9ng, nhi\u1ec7t t\u00ecnh."}, {"id": "nwf-20", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The company is seeking candidates with _____ in project management.", "options": ["experiment", "experiencing", "experienced", "experience"], "answer": 3, "explanation": "After \"with\" (gi\u1edbi t\u1eeb) \u2192 noun. \"Experience\" (n) = kinh nghi\u1ec7m. Kh\u00f4ng d\u00f9ng \"experienced\" (adj) sau gi\u1edbi t\u1eeb tr\u1ef1c ti\u1ebfp."}, {"id": "nwf-21", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The marketing department reported three _____ quarters of record-breaking sales.", "options": ["successful", "success", "successive", "successfully"], "answer": 2, "explanation": "\"Three _____ quarters\" y\u00eau c\u1ea7u t\u00ednh t\u1eeb m\u00f4 t\u1ea3 t\u00ednh li\u00ean ti\u1ebfp. \"Successive\" (adj) = li\u00ean ti\u1ebfp. \"Successful\" = th\u00e0nh c\u00f4ng (kh\u00e1c ngh\u0129a)."}, {"id": "nwf-22", "part": 5, "type": "word-form", "difficulty": "medium", "question": "For _____ information regarding the policy changes, please contact HR.", "options": ["farther", "further", "furthest", "furthering"], "answer": 1, "explanation": "\"Further information\" = th\u00eam th\u00f4ng tin (tr\u1eebu t\u01b0\u1ee3ng). \"Farther\" ch\u1ec9 d\u00f9ng cho kho\u1ea3ng c\u00e1ch v\u1eadt l\u00fd."}, {"id": "nwf-23", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The discovery of the ancient ruins was considered a _____ event.", "options": ["historic", "historical", "history", "historically"], "answer": 0, "explanation": "\"Historic\" = c\u00f3 \u00fd ngh\u0129a l\u1ecbch s\u1eed quan tr\u1ecdng, \u0111\u00e1ng nh\u1edb. \"Historical\" = thu\u1ed9c v\u1ec1 l\u1ecbch s\u1eed (historical records/data)."}, {"id": "nwf-24", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The new eco-friendly vehicle is both stylish and _____ to operate.", "options": ["economic", "economy", "economically", "economical"], "answer": 3, "explanation": "\"Economical to operate\" = ti\u1ebft ki\u1ec7m chi ph\u00ed v\u1eadn h\u00e0nh. \"Economic\" = thu\u1ed9c v\u1ec1 kinh t\u1ebf (economic growth/policy)."}, {"id": "nwf-25", "part": 5, "type": "word-form", "difficulty": "medium", "question": "She made a _____ effort to understand the client's requirements.", "options": ["considerate", "considerable", "consideration", "considerably"], "answer": 1, "explanation": "\"Considerable effort\" = n\u1ed7 l\u1ef1c \u0111\u00e1ng k\u1ec3 (l\u1edbn). \"Considerate\" = chu \u0111\u00e1o v\u1edbi ng\u01b0\u1eddi kh\u00e1c (t\u00ednh c\u00e1ch)."}, {"id": "nwf-26", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The new system provides _____ monitoring of all network activity.", "options": ["continue", "continual", "continuous", "continuity"], "answer": 2, "explanation": "\"Continuous monitoring\" = gi\u00e1m s\u00e1t li\u00ean t\u1ee5c kh\u00f4ng gi\u00e1n \u0111o\u1ea1n. \"Continual\" = l\u1eb7p \u0111i l\u1eb7p l\u1ea1i (c\u00f3 gi\u00e1n \u0111o\u1ea1n)."}, {"id": "nwf-27", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The two products have _____ features that work well together.", "options": ["complementary", "complimentary", "completing", "completed"], "answer": 0, "explanation": "\"Complementary features\" = t\u00ednh n\u0103ng b\u1ed5 sung cho nhau. \"Complimentary\" = mi\u1ec5n ph\u00ed ho\u1eb7c khen ng\u1ee3i."}, {"id": "nwf-28", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The _____ reason for the delay was the supplier's bankruptcy.", "options": ["principle", "principled", "principally", "principal"], "answer": 3, "explanation": "\"Principal reason\" = l\u00fd do ch\u00ednh, quan tr\u1ecdng nh\u1ea5t. \"Principle\" l\u00e0 danh t\u1eeb = nguy\u00ean t\u1eafc. \"Principal\" (adj) = ch\u00ednh, quan tr\u1ecdng nh\u1ea5t."}, {"id": "nwf-29", "part": 5, "type": "word-form", "difficulty": "medium", "question": "On _____ days, the office opens at 7 a.m. for early arrivals.", "options": ["alternative", "alternate", "alternatives", "alternatively"], "answer": 1, "explanation": "\"Alternate days\" = nh\u1eefng ng\u00e0y lu\u00e2n phi\u00ean (xen k\u1ebd: Mon/Wed/Fri...). \"Alternative\" = thay th\u1ebf (another option)."}, {"id": "nwf-30", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The two executives made a _____ announcement about the company's new direction.", "options": ["joining", "jointed", "jointly", "joint"], "answer": 3, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"announcement\" \u2192 t\u00ednh t\u1eeb. \"Joint\" (adj) = chung, c\u00f9ng nhau. \"Jointly\" l\u00e0 ph\u00f3 t\u1eeb."}, {"id": "nwf-31", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The CEO expressed _____ for the team's outstanding performance.", "options": ["appreciate", "appreciatively", "appreciative", "appreciation"], "answer": 3, "explanation": "After \"expressed\" (V) \u2192 noun as direct object. \"Appreciation\" (n) = s\u1ef1 tr\u00e2n tr\u1ecdng. -tion = noun."}, {"id": "nwf-32", "part": 5, "type": "word-form", "difficulty": "easy", "question": "Staff are _____ for taking rest breaks during long shifts.", "options": ["encourage", "encouraging", "encouragement", "encouraged"], "answer": 3, "explanation": "After \"are\" (be) \u2192 past participle in passive. \"Encouraged\" (V3/adj) = \u0111\u01b0\u1ee3c khuy\u1ebfn kh\u00edch."}, {"id": "nwf-33", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The architect's _____ plan was approved by the city council.", "options": ["renovate", "renovation", "renovated", "renovating"], "answer": 1, "explanation": "Before \"plan\" (noun) \u2192 adjective or noun modifier. \"Renovation plan\" = k\u1ebf ho\u1ea1ch c\u1ea3i t\u1ea1o. Noun + noun compound."}, {"id": "nwf-34", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The committee will _____ all submitted proposals before making a final decision.", "options": ["evaluate", "evaluation", "evaluative", "evaluator"], "answer": 0, "explanation": "After \"will\" (modal) \u2192 V nguy\u00ean th\u1ec3. \"Evaluate\" (v) = \u0111\u00e1nh gi\u00e1, xem x\u00e9t."}, {"id": "nwf-35", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ results exceeded all projected targets this quarter.", "options": ["finance", "financed", "financially", "financial"], "answer": 3, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"results\" \u2192 t\u00ednh t\u1eeb. \"Financial results\" = k\u1ebft qu\u1ea3 t\u00e0i ch\u00ednh. -al = t\u00ednh t\u1eeb."}, {"id": "nwf-36", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the new product has been postponed until further notice.", "options": ["launched", "launch", "launcher", "launching"], "answer": 1, "explanation": "After \"The\" \u2192 noun (ch\u1ee7 ng\u1eef). \"Launch\" (n) = s\u1ef1 ra m\u1eaft, bu\u1ed5i ra m\u1eaft. D\u00f9ng nh\u01b0 danh t\u1eeb, kh\u00f4ng c\u1ea7n -ing \u1edf \u0111\u00e2y."}, {"id": "nwf-37", "part": 5, "type": "word-form", "difficulty": "medium", "question": "All employees must sign the _____ document before the deadline.", "options": ["revise", "revision", "revised", "revising"], "answer": 2, "explanation": "Before \"document\" \u2192 adjective/participial modifier. \"Revised\" (adj/V3) = \u0111\u00e3 \u0111\u01b0\u1ee3c s\u1eeda \u0111\u1ed5i, b\u1ea3n s\u1eeda \u0111\u1ed5i."}, {"id": "nwf-38", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the new software was completed ahead of schedule.", "options": ["installation", "install", "installed", "installing"], "answer": 0, "explanation": "After \"The\" \u2192 noun (ch\u1ee7 ng\u1eef). \"Installation\" (n) = s\u1ef1 c\u00e0i \u0111\u1eb7t. H\u1eadu t\u1ed1 -ation = danh t\u1eeb."}, {"id": "nwf-39", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The new regulations are designed to _____ workplace safety standards.", "options": ["strengthen", "strongly", "strong", "strength"], "answer": 0, "explanation": "After \"to\" (to-infinitive) \u2192 V nguy\u00ean th\u1ec3. \"Strengthen\" (v) = t\u0103ng c\u01b0\u1eddng, c\u1ee7ng c\u1ed1. H\u1eadu t\u1ed1 -en = \u0111\u1ed9ng t\u1eeb."}, {"id": "nwf-40", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The company demonstrated _____ in managing the supply chain disruption.", "options": ["resilient", "resilience", "resiliently", "resiliency"], "answer": 1, "explanation": "After \"demonstrated\" (V) \u2192 noun as direct object. \"Resilience\" (n) = kh\u1ea3 n\u0103ng ph\u1ee5c h\u1ed3i. -ence = noun."}, {"id": "nv-01", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company will _____ a new product line targeted at young professionals.", "options": ["begin", "open", "launch", "start"], "answer": 2, "explanation": "\"Launch a product\" = ra m\u1eaft s\u1ea3n ph\u1ea9m. \u0110\u00e2y l\u00e0 collocation c\u1ed1 \u0111\u1ecbnh trong TOEIC. \"Open/begin/start\" kh\u00f4ng d\u00f9ng v\u1edbi \"product line\"."}, {"id": "nv-02", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "Please _____ all receipts to your expense report for reimbursement.", "options": ["combine", "add", "include", "attach"], "answer": 3, "explanation": "\"Attach receipts\" = \u0111\u00ednh k\u00e8m bi\u00ean lai. Collocation: attach + documents/receipts/files."}, {"id": "nv-03", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The HR department will _____ new employees for the manufacturing plant.", "options": ["recruit", "collect", "gather", "acquire"], "answer": 0, "explanation": "\"Recruit employees\" = tuy\u1ec3n d\u1ee5ng nh\u00e2n vi\u00ean. Collocation c\u1ed1 \u0111\u1ecbnh. \"Collect/gather\" d\u00f9ng cho v\u1eadt, kh\u00f4ng ph\u1ea3i ng\u01b0\u1eddi."}, {"id": "nv-04", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The board decided to _____ the merger after thorough negotiations.", "options": ["accept", "approve", "agree", "allow"], "answer": 1, "explanation": "\"Approve a merger/proposal/budget\" = ph\u00ea duy\u1ec7t. \"Accept\" d\u00f9ng khi nh\u1eadn offer. \"Agree to\" c\u1ea7n gi\u1edbi t\u1eeb."}, {"id": "nv-05", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The project team will _____ the client on the latest developments.", "options": ["refresh", "renew", "update", "revise"], "answer": 2, "explanation": "\"Update someone on something\" = c\u1eadp nh\u1eadt th\u00f4ng tin cho ai. Collocation c\u1ed1 \u0111\u1ecbnh trong email kinh doanh."}, {"id": "nv-06", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The annual budget must be _____ by the finance committee.", "options": ["approved", "allocated", "assigned", "adjusted"], "answer": 0, "explanation": "\"Budget is approved\" = ng\u00e2n s\u00e1ch \u0111\u01b0\u1ee3c ph\u00ea duy\u1ec7t. \"Allocated\" = ph\u00e2n b\u1ed5 (th\u01b0\u1eddng d\u00f9ng: allocate a budget). Context n\u00f3i v\u1ec1 committee approval."}, {"id": "nv-07", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "Customers can _____ their orders online up to 24 hours before delivery.", "options": ["cancel", "stop", "end", "finish"], "answer": 0, "explanation": "\"Cancel an order\" = h\u1ee7y \u0111\u01a1n h\u00e0ng. Collocation c\u1ed1 \u0111\u1ecbnh. \"Stop/end/finish\" kh\u00f4ng d\u00f9ng v\u1edbi \"order\"."}, {"id": "nv-08", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The factory was forced to _____ production due to equipment failure.", "options": ["stop", "halt", "cancel", "end"], "answer": 1, "explanation": "\"Halt production\" = ng\u1eebng s\u1ea3n xu\u1ea5t \u0111\u1ed9t ng\u1ed9t. \"Halt\" m\u1ea1nh h\u01a1n \"stop\", th\u01b0\u1eddng d\u00f9ng cho qu\u00e1 tr\u00ecnh c\u00f4ng nghi\u1ec7p. \"Cancel\" d\u00f9ng cho s\u1ef1 ki\u1ec7n/\u0111\u01a1n h\u00e0ng."}, {"id": "nv-09", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The manager asked the team to _____ the deadline for the quarterly report.", "options": ["reach", "catch", "meet", "achieve"], "answer": 2, "explanation": "\"Meet a deadline\" = ho\u00e0n th\u00e0nh \u0111\u00fang h\u1ea1n. Collocation c\u1ed1 \u0111\u1ecbnh. \"Reach/achieve/catch a deadline\" \u0111\u1ec1u sai collocation."}, {"id": "nv-10", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "Please _____ this form and submit it to the reception desk.", "options": ["fill in", "fill up", "fill out", "complete"], "answer": 2, "explanation": "\"Fill out a form\" = \u0111i\u1ec1n v\u00e0o bi\u1ec3u m\u1eabu (American English). \"Fill in\" c\u0169ng \u0111\u00fang (British). \"Fill up\" = \u0111\u1ed5 \u0111\u1ea7y (tank)."}, {"id": "nv-11", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company plans to _____ its operations to three new Asian markets.", "options": ["grow", "expand", "increase", "enlarge"], "answer": 1, "explanation": "\"Expand operations/business\" = m\u1edf r\u1ed9ng ho\u1ea1t \u0111\u1ed9ng. Collocation c\u1ed1 \u0111\u1ecbnh. \"Grow\" th\u01b0\u1eddng kh\u00f4ng c\u00f3 object tr\u1ef1c ti\u1ebfp theo ngh\u0129a n\u00e0y."}, {"id": "nv-12", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The security team must _____ all visitor badges at the end of each day.", "options": ["get", "gather", "collect", "take"], "answer": 2, "explanation": "\"Collect badges/documents\" = thu l\u1ea1i, t\u1eadp h\u1ee3p. Collocation v\u1edbi v\u1eadt: collect + items/badges/data."}, {"id": "nv-13", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The training program aims to _____ employees with the latest software tools.", "options": ["give", "provide", "supply", "equip"], "answer": 3, "explanation": "\"Equip someone with something\" = trang b\u1ecb k\u1ef9 n\u0103ng/c\u00f4ng c\u1ee5. \"Equip + person + with + tool/skill\" l\u00e0 c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh."}, {"id": "nv-14", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The bank agreed to _____ the loan repayment period by six months.", "options": ["extend", "expand", "enlarge", "increase"], "answer": 0, "explanation": "\"Extend a deadline/period/loan\" = gia h\u1ea1n, k\u00e9o d\u00e0i. Collocation: extend + deadline/contract/period."}, {"id": "nv-15", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "All employees are asked to _____ the company's code of conduct.", "options": ["obey", "follow", "respect", "maintain"], "answer": 1, "explanation": "\"Follow a code of conduct/policy/guidelines\" = tu\u00e2n theo. Collocation c\u1ed1 \u0111\u1ecbnh. \"Obey\" th\u01b0\u1eddng cho rules/orders (ng\u01b0\u1eddi ra l\u1ec7nh)."}, {"id": "nv-16", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The research team will _____ a comprehensive study on consumer behavior.", "options": ["make", "do", "conduct", "perform"], "answer": 2, "explanation": "\"Conduct a study/research/survey\" = th\u1ef1c hi\u1ec7n nghi\u00ean c\u1ee9u. Collocation c\u1ed1 \u0111\u1ecbnh v\u1edbi academic/business research."}, {"id": "nv-17", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The sales team was able to _____ a long-term contract with the new client.", "options": ["obtain", "get", "find", "secure"], "answer": 3, "explanation": "\"Secure a contract/deal/agreement\" = \u0111\u1ea3m b\u1ea3o, k\u00fd k\u1ebft \u0111\u01b0\u1ee3c h\u1ee3p \u0111\u1ed3ng. \"Secure\" m\u1ea1nh h\u01a1n \"get/obtain\" trong ng\u1eef c\u1ea3nh kinh doanh."}, {"id": "nv-18", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The CFO presented strategies to _____ operational costs by the end of Q4.", "options": ["reduce", "lower", "minimize", "cut"], "answer": 2, "explanation": "\"Minimize costs\" = t\u1ed1i thi\u1ec3u h\u00f3a chi ph\u00ed. Trong b\u1ed1i c\u1ea3nh CFO strategy \u2192 \"minimize\" (formal, chi\u1ebfn l\u01b0\u1ee3c t\u1ed5ng th\u1ec3). \"Cut costs\" = c\u1eaft gi\u1ea3m. \"Reduce costs\" = gi\u1ea3m chi ph\u00ed. All acceptable but \"minimize\" strongest for strategy."}, {"id": "nv-19", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The department head will _____ the project team at the weekly meeting.", "options": ["speak", "address", "talk", "say"], "answer": 1, "explanation": "\"Address the team/meeting/audience\" = ph\u00e1t bi\u1ec3u v\u1edbi, n\u00f3i chuy\u1ec7n v\u1edbi (trang tr\u1ecdng). \"Address\" l\u00e0 collocation chu\u1ea9n cho m\u00f4i tr\u01b0\u1eddng kinh doanh."}, {"id": "nv-20", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company will _____ a new incentive program for high-performing employees.", "options": ["start", "do", "make", "implement"], "answer": 3, "explanation": "\"Implement a program/policy/system\" = th\u1ef1c hi\u1ec7n, tri\u1ec3n khai. Collocation c\u1ed1 \u0111\u1ecbnh trong v\u0103n phong kinh doanh. \"Do/make/start a program\" \u0111\u1ec1u sai collocation."}, {"id": "nv-21", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The marketing team was asked to _____ a proposal for the new campaign.", "options": ["prepare", "make", "do", "create"], "answer": 0, "explanation": "\"Prepare a proposal/report/presentation\" = chu\u1ea9n b\u1ecb. Collocation c\u1ed1 \u0111\u1ecbnh. \"Make a proposal\" c\u0169ng \u0111\u00fang nh\u01b0ng \"prepare\" ph\u1ed5 bi\u1ebfn h\u01a1n trong TOEIC."}, {"id": "nv-22", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The conference will _____ leaders from over 40 countries.", "options": ["gather", "bring together", "collect", "combine"], "answer": 1, "explanation": "\"Bring together leaders/experts\" = quy t\u1ee5, t\u1eadp h\u1ee3p l\u1ea1i. Phrasal verb ph\u1ed5 bi\u1ebfn trong TOEIC. \"Gather\" \u00edt formal h\u01a1n."}, {"id": "nv-23", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The committee will _____ applications until the position is filled.", "options": ["accept", "review", "consider", "receive"], "answer": 3, "explanation": "\"Receive applications\" = ti\u1ebfp nh\u1eadn \u0111\u01a1n \u1ee9ng tuy\u1ec3n. Trong c\u00e2u n\u00e0y \"receive\" ph\u00f9 h\u1ee3p nh\u1ea5t \u2192 ti\u1ebfp nh\u1eadn t\u1eeb b\u00ean ngo\u00e0i. \"Accept\" implies a decision, \"consider/review\" comes after receiving."}, {"id": "nv-24", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The manager chose to _____ the issue directly rather than sending an email.", "options": ["handle", "solve", "fix", "address"], "answer": 3, "explanation": "\"Address an issue/problem\" = x\u1eed l\u00fd, \u0111\u1ed1i m\u1eb7t tr\u1ef1c ti\u1ebfp v\u1edbi v\u1ea5n \u0111\u1ec1 (trang tr\u1ecdng). \"Address\" nh\u1ea5n m\u1ea1nh s\u1ef1 ch\u1ee7 \u0111\u1ed9ng ti\u1ebfp c\u1eadn."}, {"id": "nv-25", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company will _____ a free maintenance service for the first year.", "options": ["offer", "give", "provide", "present"], "answer": 0, "explanation": "\"Offer a service/discount/opportunity\" = \u0111\u1ec1 ngh\u1ecb, cung c\u1ea5p. \"Offer\" th\u01b0\u1eddng d\u00f9ng h\u01a1n \"provide\" khi n\u00f3i v\u1ec1 d\u1ecbch v\u1ee5 th\u00eam/\u01b0u \u0111\u00e3i."}, {"id": "nv-26", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The facilities team will _____ routine inspections every six months.", "options": ["do", "carry out", "make", "perform"], "answer": 1, "explanation": "\"Carry out inspections/tasks/duties\" = th\u1ef1c hi\u1ec7n (nhi\u1ec7m v\u1ee5 c\u1ee5 th\u1ec3). Collocation c\u1ed1 \u0111\u1ecbnh. \"Perform inspections\" c\u0169ng \u0111\u00fang."}, {"id": "nv-27", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The auditors will _____ the financial records before the annual report is published.", "options": ["look at", "check", "examine", "inspect"], "answer": 2, "explanation": "\"Examine financial records/documents\" = ki\u1ec3m tra k\u1ef9 l\u01b0\u1ee1ng (formal, chuy\u00ean nghi\u1ec7p). \"Inspect\" = ki\u1ec3m tra th\u1ef1c \u0111\u1ecba/v\u1eadt l\u00fd. \"Examine\" ph\u00f9 h\u1ee3p h\u01a1n cho financial records."}, {"id": "nv-28", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "All departments are encouraged to _____ their year-end budget reports.", "options": ["send", "hand", "give", "submit"], "answer": 3, "explanation": "\"Submit a report/application/document\" = n\u1ed9p (ch\u00ednh th\u1ee9c). Collocation chu\u1ea9n trong m\u00f4i tr\u01b0\u1eddng doanh nghi\u1ec7p."}, {"id": "nv-29", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The team will _____ a presentation on the Q3 results next Monday.", "options": ["deliver", "give", "make", "do"], "answer": 0, "explanation": "\"Deliver a presentation/speech/report\" = th\u1ef1c hi\u1ec7n b\u00e0i thuy\u1ebft tr\u00ecnh. \"Deliver\" l\u00e0 collocation trang tr\u1ecdng v\u00e0 ch\u00ednh x\u00e1c nh\u1ea5t."}, {"id": "nv-30", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The director chose to _____ the meeting until all key personnel were available.", "options": ["cancel", "delay", "postpone", "hold"], "answer": 2, "explanation": "\"Postpone a meeting/event\" = d\u1eddi l\u1ea1i (c\u00f3 l\u1ecbch m\u1edbi). \"Delay\" = b\u1ecb tr\u00ec ho\u00e3n (th\u1ee5 \u0111\u1ed9ng h\u01a1n). \"Cancel\" = h\u1ee7y ho\u00e0n to\u00e0n. \"Hold\" = t\u1ed5 ch\u1ee9c."}, {"id": "np-01", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The quarterly report must be submitted _____ the end of the fiscal year.", "options": ["by", "until", "before", "in"], "answer": 0, "explanation": "\"By the end of...\" = tr\u01b0\u1edbc th\u1eddi \u0111i\u1ec3m \u0111\u00f3 (deadline). \"Until\" = k\u00e9o d\u00e0i \u0111\u1ebfn t\u1eadn th\u1eddi \u0111i\u1ec3m \u0111\u00f3. \"By\" cho deadline, \"until\" cho duration."}, {"id": "np-02", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The office will remain closed _____ further notice.", "options": ["by", "until", "for", "since"], "answer": 1, "explanation": "\"Until further notice\" = cho \u0111\u1ebfn khi c\u00f3 th\u00f4ng b\u00e1o m\u1edbi. C\u1ee5m c\u1ed1 \u0111\u1ecbnh. \"Until\" di\u1ec5n t\u1ea3 tr\u1ea1ng th\u00e1i li\u00ean t\u1ee5c \u0111\u1ebfn m\u1ed9t \u0111i\u1ec3m."}, {"id": "np-03", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The seminar is scheduled _____ Thursday afternoon.", "options": ["at", "in", "on", "for"], "answer": 2, "explanation": "\"On Thursday afternoon\" = v\u00e0o chi\u1ec1u th\u1ee9 N\u0103m. Quy t\u1eafc: ON + day/date. \"In\" d\u00f9ng cho month/year/season. \"At\" d\u00f9ng cho th\u1eddi \u0111i\u1ec3m c\u1ee5 th\u1ec3."}, {"id": "np-04", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "Applications will be accepted _____ March 1st to April 15th.", "options": ["during", "between", "since", "from"], "answer": 3, "explanation": "\"From...to...\" = t\u1eeb...\u0111\u1ebfn... (kho\u1ea3ng th\u1eddi gian). \"Between...and...\" c\u0169ng \u0111\u00fang nh\u01b0ng kh\u00f4ng c\u00f3 \"and\" trong c\u00e2u n\u00e0y."}, {"id": "np-05", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The new policy will come _____ effect next January.", "options": ["into", "in", "to", "onto"], "answer": 0, "explanation": "\"Come into effect\" = c\u00f3 hi\u1ec7u l\u1ef1c. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: come/bring/put something into effect."}, {"id": "np-06", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The contract is valid _____ a period of three years.", "options": ["during", "for", "within", "over"], "answer": 1, "explanation": "\"Valid for a period of...\" = c\u00f3 gi\u00e1 tr\u1ecb trong kho\u1ea3ng th\u1eddi gian. \"For + period\" = trong su\u1ed1t. \"During\" c\u1ea7n specific event/period noun."}, {"id": "np-07", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "All renovations must be completed _____ the deadline set by the city council.", "options": ["until", "by", "within", "before"], "answer": 2, "explanation": "\"Completed within the deadline\" = ho\u00e0n th\u00e0nh trong ph\u1ea1m vi th\u1eddi h\u1ea1n cho ph\u00e9p. \"Within\" nh\u1ea5n m\u1ea1nh trong gi\u1edbi h\u1ea1n. \"By\" c\u0169ng \u0111\u00fang nh\u01b0ng \"within\" ph\u00f9 h\u1ee3p h\u01a1n v\u1edbi \"deadline set by\"."}, {"id": "np-08", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The meeting has been rescheduled _____ 2 p.m. on Friday.", "options": ["on", "to", "at", "for"], "answer": 3, "explanation": "\"Rescheduled for 2 p.m.\" = \u0111\u01b0\u1ee3c d\u1eddi \u0111\u1ebfn l\u00fac 2 gi\u1edd. \"Reschedule for + time/date\" = c\u1ee5m c\u1ed1 \u0111\u1ecbnh."}, {"id": "np-09", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new branch will open _____ schedule, ready for customers by Monday.", "options": ["ahead of", "before", "prior to", "in advance of"], "answer": 0, "explanation": "\"Ahead of schedule\" = tr\u01b0\u1edbc ti\u1ebfn \u0111\u1ed9 d\u1ef1 ki\u1ebfn. C\u1ee5m c\u1ed1 \u0111\u1ecbnh hay g\u1eb7p trong TOEIC. \"On schedule\" = \u0111\u00fang ti\u1ebfn \u0111\u1ed9."}, {"id": "np-10", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The team worked _____ the deadline to ensure the project was submitted on time.", "options": ["before", "toward", "against", "with"], "answer": 2, "explanation": "\"Work against the deadline\" = l\u00e0m vi\u1ec7c trong khi deadline \u0111ang \u0111\u1ebfn g\u1ea7n (race against time). Idiom ph\u1ed5 bi\u1ebfn trong TOEIC."}, {"id": "np-11", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new manager is responsible _____ overseeing the entire production process.", "options": ["with", "of", "about", "for"], "answer": 3, "explanation": "\"Responsible for\" = ch\u1ecbu tr\u00e1ch nhi\u1ec7m v\u1ec1. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: be responsible for + noun/V-ing."}, {"id": "np-12", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The HR team is interested _____ hearing from candidates with multilingual skills.", "options": ["in", "about", "for", "with"], "answer": 0, "explanation": "\"Interested in\" = quan t\u00e2m \u0111\u1ebfn. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: be interested in + noun/V-ing."}, {"id": "np-13", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new software is compatible _____ all major operating systems.", "options": ["to", "with", "for", "in"], "answer": 1, "explanation": "\"Compatible with\" = t\u01b0\u01a1ng th\u00edch v\u1edbi. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: compatible with + systems/devices."}, {"id": "np-14", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "Employees are eligible _____ the annual bonus after one year of service.", "options": ["of", "to", "for", "in"], "answer": 2, "explanation": "\"Eligible for\" = \u0111\u1ee7 \u0111i\u1ec1u ki\u1ec7n nh\u1eadn. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: eligible for + benefit/position/program."}, {"id": "np-15", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The organization is committed _____ reducing its carbon footprint by 2030.", "options": ["about", "for", "in", "to"], "answer": 3, "explanation": "\"Committed to\" = cam k\u1ebft v\u1edbi (gi\u1edbi t\u1eeb). Sau \"committed to\" \u2192 V-ing (kh\u00f4ng ph\u1ea3i to-V). Committed to reducing."}, {"id": "np-16", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "Please ensure that all packages are free _____ damage before delivery.", "options": ["from", "of", "with", "at"], "answer": 0, "explanation": "\"Free from damage\" = kh\u00f4ng c\u00f3 h\u01b0 h\u1ea1i. \"Free from\" = kh\u00f4ng c\u00f3 (v\u1ea5n \u0111\u1ec1/nguy hi\u1ec3m). \"Free of charge\" = mi\u1ec5n ph\u00ed."}, {"id": "np-17", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The accounting team is familiar _____ the new expense reporting system.", "options": ["about", "with", "for", "of"], "answer": 1, "explanation": "\"Familiar with\" = quen thu\u1ed9c v\u1edbi. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: be familiar with + system/process/person."}, {"id": "np-18", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new policy is consistent _____ the company's long-term sustainability goals.", "options": ["in", "to", "with", "for"], "answer": 2, "explanation": "\"Consistent with\" = nh\u1ea5t qu\u00e1n v\u1edbi, ph\u00f9 h\u1ee3p v\u1edbi. C\u1ee5m c\u1ed1 \u0111\u1ecbnh trong v\u0103n phong kinh doanh."}, {"id": "np-19", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The department head will respond _____ all written inquiries within 48 hours.", "options": ["with", "for", "about", "to"], "answer": 3, "explanation": "\"Respond to\" = ph\u1ea3n h\u1ed3i, tr\u1ea3 l\u1eddi. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: respond to + inquiry/complaint/email."}, {"id": "np-20", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The supplier is capable _____ delivering 500 units per day.", "options": ["for", "of", "at", "in"], "answer": 1, "explanation": "\"Capable of\" = c\u00f3 kh\u1ea3 n\u0103ng. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: capable of + V-ing."}, {"id": "np-21", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The proposal was rejected _____ account of insufficient supporting data.", "options": ["by", "for", "on", "due"], "answer": 2, "explanation": "\"On account of\" = v\u00ec l\u00fd do. C\u1ee5m gi\u1edbi t\u1eeb = because of. \"On account of + noun\" = do, v\u00ec."}, {"id": "np-22", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The vendor will provide a replacement _____ no additional charge.", "options": ["in", "for", "with", "at"], "answer": 3, "explanation": "\"At no additional charge\" = kh\u00f4ng t\u00ednh th\u00eam ph\u00ed. \"At no cost/charge/extra fee\" = mi\u1ec5n ph\u00ed th\u00eam. C\u1ee5m c\u1ed1 \u0111\u1ecbnh."}, {"id": "np-23", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new safety measures were implemented _____ compliance with federal regulations.", "options": ["in", "for", "by", "to"], "answer": 0, "explanation": "\"In compliance with\" = tu\u00e2n th\u1ee7 theo. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: in compliance/accordance/line with + regulations/policy."}, {"id": "np-24", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The project was completed _____ time and within budget.", "options": ["in", "on", "at", "by"], "answer": 1, "explanation": "\"On time\" = \u0111\u00fang h\u1ea1n, \u0111\u00fang gi\u1edd. \"In time\" = k\u1ecbp l\u00fac (tr\u01b0\u1edbc khi qu\u00e1 tr\u1ec5). \"On time\" cho deadline c\u1ed1 \u0111\u1ecbnh."}, {"id": "np-25", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "Sales have declined _____ large part due to supply chain issues.", "options": ["for", "by", "in", "at"], "answer": 2, "explanation": "\"In large part\" = ph\u1ea7n l\u1edbn l\u00e0 do. C\u1ee5m ph\u00f3 t\u1eeb: in large/great part = largely, mostly."}, {"id": "np-26", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "Candidates should apply _____ the position through the company website.", "options": ["in", "to", "about", "for"], "answer": 3, "explanation": "\"Apply for a position/job\" = \u1ee9ng tuy\u1ec3n v\u00e0o v\u1ecb tr\u00ed. \"Apply to a company\" = \u1ee9ng tuy\u1ec3n v\u00e0o c\u00f4ng ty."}, {"id": "np-27", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The board voted _____ favor of the proposed acquisition.", "options": ["in", "on", "for", "at"], "answer": 0, "explanation": "\"In favor of\" = \u1ee7ng h\u1ed9, t\u00e1n th\u00e0nh. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: vote/speak/argue in favor of."}, {"id": "np-28", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The decision to outsource production was made _____ light of rising labor costs.", "options": ["by", "in", "with", "for"], "answer": 1, "explanation": "\"In light of\" = d\u1ef1a tr\u00ean, x\u00e9t theo. C\u1ee5m gi\u1edbi t\u1eeb trang tr\u1ecdng: in light of + new information/circumstances."}, {"id": "np-29", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The company is known _____ its innovative approach to product development.", "options": ["with", "by", "for", "as"], "answer": 2, "explanation": "\"Known for\" = n\u1ed5i ti\u1ebfng v\u1ec1, \u0111\u01b0\u1ee3c bi\u1ebft \u0111\u1ebfn v\u00ec. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: be known for + quality/achievement."}, {"id": "np-30", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new employee has been assigned _____ the research and development team.", "options": ["to", "in", "for", "with"], "answer": 0, "explanation": "\"Assigned to a team/department\" = \u0111\u01b0\u1ee3c ph\u00e2n c\u00f4ng v\u00e0o. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: assign someone to a project/team."}, {"id": "np-31", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The consulting firm specializes _____ financial restructuring for mid-sized companies.", "options": ["with", "in", "on", "at"], "answer": 1, "explanation": "\"Specializes in\" = chuy\u00ean v\u1ec1. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: specialize in + field/service."}, {"id": "np-32", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "All staff must comply _____ the updated data privacy policy.", "options": ["for", "to", "with", "of"], "answer": 2, "explanation": "\"Comply with\" = tu\u00e2n th\u1ee7. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: comply with + regulations/rules/requirements."}, {"id": "np-33", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The marketing director took pride _____ the team's record-breaking sales figures.", "options": ["at", "of", "for", "in"], "answer": 3, "explanation": "\"Take pride in\" = t\u1ef1 h\u00e0o v\u1ec1. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: take pride in + achievement/work."}, {"id": "np-34", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new regulation applies _____ all companies with more than 50 employees.", "options": ["to", "for", "with", "on"], "answer": 0, "explanation": "\"Apply to\" = \u00e1p d\u1ee5ng cho (\u0111\u1ed1i t\u01b0\u1ee3ng). Ph\u00e2n bi\u1ec7t: apply to (\u00e1p d\u1ee5ng v\u00e0o/cho) vs apply for (xin/\u0111\u0103ng k\u00fd)."}, {"id": "np-35", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The terms of the agreement are subject _____ board approval.", "options": ["for", "to", "of", "by"], "answer": 1, "explanation": "\"Subject to\" = ph\u1ee5 thu\u1ed9c v\u00e0o, c\u00f3 \u0111i\u1ec1u ki\u1ec7n. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: subject to + approval/availability/change."}, {"id": "np-36", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The promotional offer is available _____ a limited time only.", "options": ["during", "in", "for", "within"], "answer": 2, "explanation": "\"Available for a limited time\" = c\u00f3 s\u1eb5n trong th\u1eddi gian gi\u1edbi h\u1ea1n. \"For + period\" = trong su\u1ed1t kho\u1ea3ng th\u1eddi gian."}, {"id": "np-37", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The training workshop will focus _____ effective communication in the workplace.", "options": ["for", "about", "in", "on"], "answer": 3, "explanation": "\"Focus on\" = t\u1eadp trung v\u00e0o. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: focus on + topic/issue/skill."}, {"id": "np-38", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The company relies heavily _____ overseas suppliers for raw materials.", "options": ["on", "upon", "for", "with"], "answer": 0, "explanation": "\"Rely on/upon\" = ph\u1ee5 thu\u1ed9c v\u00e0o, d\u1ef1a v\u00e0o. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: rely on + person/company/system."}, {"id": "np-39", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The merger was finalized _____ accordance with all regulatory requirements.", "options": ["on", "in", "by", "with"], "answer": 1, "explanation": "\"In accordance with\" = tu\u00e2n theo, ph\u00f9 h\u1ee3p v\u1edbi. C\u1ee5m gi\u1edbi t\u1eeb trang tr\u1ecdng trong v\u0103n b\u1ea3n ph\u00e1p l\u00fd/kinh doanh."}, {"id": "np-40", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The customer service team responded _____ all complaints within one business day.", "options": ["about", "for", "on", "to"], "answer": 3, "explanation": "\"Respond to complaints/inquiries/emails\" = ph\u1ea3n h\u1ed3i. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: respond to + communication."}, {"id": "hq-cj-01", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "Not only _____ the team meet the Q3 deadline, but they also exceeded the revenue target by 18%.", "options": ["has", "did", "does", "had"], "answer": 1, "explanation": "\"Not only\" \u0111\u1ea7u c\u00e2u \u2192 \u0111\u1ea3o ng\u1eef: Not only + did + S + V. Th\u00ec: Past Simple (met, exceeded) \u2192 d\u00f9ng \"did\". Kh\u00f4ng d\u00f9ng \"has\" (present perfect) hay \"does\" (hi\u1ec7n t\u1ea1i)."}, {"id": "hq-cj-02", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "The project was completed on schedule _____ the fact that two key members resigned mid-way through.", "options": ["in spite of", "although", "because of", "even if"], "answer": 0, "explanation": "\"in spite of + noun phrase (the fact that...)\" = m\u1eb7c d\u00f9. \"Although\" c\u1ea7n S+V ngay sau. \"Because of\" = nguy\u00ean nh\u00e2n (sai ngh\u0129a). \"Even if\" c\u1ea7n clause."}, {"id": "hq-pv-01", "part": 5, "type": "passive", "difficulty": "hard", "question": "The budget proposal _____ by the finance committee before the board meeting takes place.", "options": ["must be reviewed", "must review", "must have reviewed", "must been reviewed"], "answer": 0, "explanation": "Modal passive = modal + be + V3. \"Must be reviewed\" = ph\u1ea3i \u0111\u01b0\u1ee3c xem x\u00e9t. \"Must review\" = ch\u1ee7 \u0111\u1ed9ng (sai). \"Must been reviewed\" sai ng\u1eef ph\u00e1p (thi\u1ebfu \"have\")."}, {"id": "hq-pv-02", "part": 5, "type": "passive", "difficulty": "hard", "question": "By the time the auditors arrive, all financial records _____ for their inspection.", "options": ["have been prepared", "will be prepared", "are being prepared", "will have been prepared"], "answer": 3, "explanation": "\"By the time + present \u2192 will have been + V3\" (Future Perfect Passive). Nh\u1ea5n m\u1ea1nh ho\u00e0n t\u1ea5t TR\u01af\u1edaC th\u1eddi \u0111i\u1ec3m auditors \u0111\u1ebfn."}, {"id": "hq-pr-01", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "_____ of the submitted proposals meets the minimum criteria for further consideration.", "options": ["None", "Any", "Some", "Both"], "answer": 0, "explanation": "\"None of + plural noun + singular verb (meets)\" = kh\u00f4ng ai/c\u00e1i n\u00e0o. \"None\" d\u00f9ng \u0111\u1ed9ng t\u1eeb s\u1ed1 \u00edt trong v\u0103n trang tr\u1ecdng. \"Both\" c\u1ea7n plural verb."}, {"id": "hq-pr-02", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "The company's new app, the developers of _____ worked for two years, was released last month.", "options": ["that", "whom", "whose", "which"], "answer": 3, "explanation": "\"the developers of which\" = c\u1ee5m gi\u1edbi t\u1eeb trong m\u1ec7nh \u0111\u1ec1 quan h\u1ec7. \"of which\" thay cho \"of it\" (app). D\u00f9ng \"which\" v\u00ec tham chi\u1ebfu \u0111\u1ebfn v\u1eadt (app)."}, {"id": "hq-gi-01", "part": 5, "type": "gerund-infinitive", "difficulty": "hard", "question": "The CEO regrets _____ the investors of the potential risks before the product launch.", "options": ["not informing", "to not inform", "not to inform", "not having to inform"], "answer": 0, "explanation": "\"regret + V-ing\" = ti\u1ebfc v\u1ec1 h\u00e0nh \u0111\u1ed9ng \u0111\u00e3 x\u1ea3y ra (qu\u00e1 kh\u1ee9). \"regret not informing\" = ti\u1ebfc v\u00ec \u0111\u00e3 kh\u00f4ng th\u00f4ng b\u00e1o. \"regret to inform\" = ti\u1ebfc ph\u1ea3i th\u00f4ng b\u00e1o (ngh\u0129a kh\u00e1c)."}, {"id": "hq-gi-02", "part": 5, "type": "gerund-infinitive", "difficulty": "hard", "question": "We are looking forward to _____ the results of the feasibility study next quarter.", "options": ["have reviewed", "review", "be reviewed", "reviewing"], "answer": 3, "explanation": "\"look forward to + V-ing\" \u2014 \"to\" l\u00e0 gi\u1edbi t\u1eeb. B\u1eaby c\u1ed5 \u0111i\u1ec3n: nhi\u1ec1u ng\u01b0\u1eddi ch\u1ecdn \"review\" (V nguy\u00ean th\u1ec3) v\u00ec nh\u1ea7m \"to\" l\u00e0 to-infinitive."}, {"id": "hq-rc-01", "part": 5, "type": "relative-clause", "difficulty": "hard", "question": "The software, without _____ the entire billing process would fail, is scheduled for an upgrade.", "options": ["whose", "whom", "that", "which"], "answer": 3, "explanation": "\"without which\" = m\u00e0 thi\u1ebfu n\u00f3. Gi\u1edbi t\u1eeb + which d\u00f9ng trong m\u1ec7nh \u0111\u1ec1 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh (c\u00f3 d\u1ea5u ph\u1ea9y). \"that\" kh\u00f4ng d\u00f9ng trong kh\u00f4ng h\u1ea1n \u0111\u1ecbnh."}, {"id": "hq-cm-01", "part": 5, "type": "comparison", "difficulty": "hard", "question": "_____ the team invests in professional development, _____ the overall output quality becomes.", "options": ["The more / the higher", "More / higher", "The most / the highest", "More and more / higher"], "answer": 0, "explanation": "Double comparative = \"The + comparative, the + comparative\". \"The more...the higher\" = c\u00e0ng...c\u00e0ng. Kh\u00f4ng d\u00f9ng superlative (\"the most/the highest\") trong c\u1ea5u tr\u00fac n\u00e0y."}, {"id": "hq-md-01", "part": 5, "type": "modal", "difficulty": "hard", "question": "The package _____ delivered yesterday, but the tracking system shows it is still at the warehouse.", "options": ["must have been", "should have been", "could have", "should be"], "answer": 1, "explanation": "\"Should have been + V3\" = l\u1ebd ra \u0111\u00e3 \u0111\u01b0\u1ee3c l\u00e0m (nh\u01b0ng ch\u01b0a x\u1ea3y ra) \u2192 l\u1eddi ph\u00e0n n\u00e0n/ti\u1ebfc nu\u1ed1i v\u1ec1 qu\u00e1 kh\u1ee9. \"Must have been\" = suy lu\u1eadn ch\u1eafc ch\u1eafn (kh\u00f4ng ph\u00f9 h\u1ee3p v\u00ec tracking shows it is still there)."}, {"id": "hq-md-02", "part": 5, "type": "modal", "difficulty": "hard", "question": "The CEO _____ the board about the acquisition much earlier, as it significantly affected share prices.", "options": ["should have informed", "must have informed", "could inform", "had to inform"], "answer": 0, "explanation": "\"Should have informed\" = l\u1ebd ra ph\u1ea3i th\u00f4ng b\u00e1o (nh\u01b0ng kh\u00f4ng l\u00e0m). Nh\u1ea5n m\u1ea1nh s\u1ef1 h\u1ed1i ti\u1ebfc/tr\u00e1ch nhi\u1ec7m trong qu\u00e1 kh\u1ee9. \"Must have informed\" = suy lu\u1eadn \u0111\u00e3 th\u00f4ng b\u00e1o r\u1ed3i (kh\u00f4ng ph\u00f9 h\u1ee3p)."}, {"id": "hq-sv-01", "part": 5, "type": "subject-verb", "difficulty": "hard", "question": "Neither the senior analyst nor the junior researchers _____ able to replicate the experimental results.", "options": ["was", "were", "are", "is"], "answer": 1, "explanation": "\"Neither A nor B + verb\" \u2192 verb chia theo danh t\u1eeb G\u1ea6N NH\u1ea4T (B = junior researchers = s\u1ed1 nhi\u1ec1u \u2192 \"were\"). N\u1ebfu B = s\u1ed1 \u00edt \u2192 \"was\"."}, {"id": "hq-nc-01", "part": 5, "type": "noun-clauses", "difficulty": "hard", "question": "_____ the product launch proceeds as planned depends entirely on the regulatory committee's approval.", "options": ["How", "That", "What", "Whether"], "answer": 3, "explanation": "\"Whether + S + V\" l\u00e0m ch\u1ee7 ng\u1eef c\u00e2u = c\u00e2u h\u1ecfi Yes/No gi\u00e1n ti\u1ebfp. \"Whether...depends on\" = li\u1ec7u...c\u00f3 ph\u1ee5 thu\u1ed9c v\u00e0o. \"That\" \u00edt d\u00f9ng \u0111\u1ea7u c\u00e2u l\u00e0m ch\u1ee7 ng\u1eef trong ng\u1eef c\u1ea3nh n\u00e0y."}, {"id": "hq-at-01", "part": 5, "type": "adverb-time", "difficulty": "hard", "question": "_____ the merger negotiations had concluded, both companies' stock prices dropped unexpectedly.", "options": ["By the time", "No sooner had", "As soon as", "Once"], "answer": 1, "explanation": "\"No sooner had + S + V3 + than\" = v\u1eeba m\u1edbi...th\u00ec. \u0110\u00e2y l\u00e0 \u0111\u1ea3o ng\u1eef ph\u1ee7 \u0111\u1ecbnh. C\u00e2u ho\u00e0n ch\u1ec9nh: \"No sooner had the negotiations concluded than prices dropped.\""}, {"id": "hq-vc-01", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The board's decision to _____ the partnership agreement came as a surprise to investors who had anticipated a merger.", "options": ["absolve", "resolve", "devolve", "dissolve"], "answer": 3, "explanation": "\"Dissolve a partnership/agreement\" = gi\u1ea3i th\u1ec3, ch\u1ea5m d\u1ee9t. \"Resolve\" = gi\u1ea3i quy\u1ebft. \"Devolve\" = trao quy\u1ec1n. \"Absolve\" = tha t\u1ed9i. Ng\u1eef c\u1ea3nh: board ending the partnership."}, {"id": "hq-vc-02", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "Despite the challenging economic conditions, the startup managed to _____ sufficient capital to fund its expansion plans.", "options": ["proclaim", "preclude", "procure", "prescribe"], "answer": 2, "explanation": "\"Procure capital/funds\" = thu x\u1ebfp \u0111\u01b0\u1ee3c, ki\u1ebfm \u0111\u01b0\u1ee3c (trang tr\u1ecdng). \"Preclude\" = ng\u0103n c\u1ea3n. \"Proclaim\" = tuy\u00ean b\u1ed1. \"Prescribe\" = k\u00ea \u0111\u01a1n/quy \u0111\u1ecbnh."}, {"id": "hq-qn-01", "part": 5, "type": "quantifiers", "difficulty": "hard", "question": "_____ the committee members have reservations about the proposed budget, the chairperson noted.", "options": ["Every", "The number of", "Much of", "A number of"], "answer": 3, "explanation": "\"A number of + plural noun + plural verb (have)\" = m\u1ed9t s\u1ed1 (kh\u00f4ng x\u00e1c \u0111\u1ecbnh) \u2192 s\u1ed1 nhi\u1ec1u. \"The number of\" \u2192 s\u1ed1 \u00edt. \"Much of\" d\u00f9ng cho kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c. \"Every\" + s\u1ed1 \u00edt."}, {"id": "hq-ps-01", "part": 5, "type": "prep-structures", "difficulty": "hard", "question": "The new policy applies to all contractors _____ their years of service or employment status.", "options": ["irrespective of", "regardless of", "in spite of", "notwithstanding"], "answer": 1, "explanation": "T\u1ea5t c\u1ea3 4 \u0111\u00e1p \u00e1n \u0111\u1ec1u \u0111\u00fang ng\u1eef ph\u00e1p v\u00e0 ngh\u0129a (\"b\u1ea5t k\u1ec3\"). Tuy nhi\u00ean \"regardless of\" l\u00e0 collocation ph\u1ed5 bi\u1ebfn nh\u1ea5t trong v\u0103n TOEIC. \"Notwithstanding\" r\u1ea5t trang tr\u1ecdng, th\u01b0\u1eddng trong v\u0103n ph\u00e1p l\u00fd."}, {"id": "hq-pt-01", "part": 5, "type": "participles", "difficulty": "hard", "question": "_____ about the potential impact on quarterly earnings, the finance team requested an emergency review.", "options": ["Having concerned", "Concerning", "Concerned", "To concern"], "answer": 2, "explanation": "\"Concerned about\" = lo l\u1eafng v\u1ec1 (past participle l\u00e0m adj). \"Concerning\" = li\u00ean quan \u0111\u1ebfn (kh\u00e1c ngh\u0129a). \"Having concerned\" sai (concern th\u01b0\u1eddng kh\u00f4ng d\u00f9ng \u1edf d\u1ea1ng n\u00e0y). Ch\u1ee7 ng\u1eef \"finance team\" \u2192 tr\u1ea1ng th\u00e1i b\u1ecb lo l\u1eafng."}, {"id": "hq-cd-01", "part": 5, "type": "conditionals", "difficulty": "hard", "question": "Had the company invested in better infrastructure earlier, it _____ the major system outage last quarter.", "options": ["could avoid", "would avoid", "had avoided", "would have avoided"], "answer": 3, "explanation": "Type 3 conditional: Had + S + V3 (Past Perfect) \u2192 S + would have + V3. \"Would have avoided\" = \u0111\u00e3 tr\u00e1nh \u0111\u01b0\u1ee3c (nh\u01b0ng kh\u00f4ng tr\u00e1nh \u0111\u01b0\u1ee3c v\u00ec kh\u00f4ng \u0111\u1ea7u t\u01b0). \u0110\u1ea3o ng\u1eef \"Had + S\" thay cho \"If + S + had\"."}, {"id": "hq-be-01", "part": 5, "type": "business-english", "difficulty": "hard", "question": "We write to _____ our previous correspondence regarding the outstanding invoice dated March 15th.", "options": ["follow through with", "follow up on", "follow along", "follow out"], "answer": 1, "explanation": "\"Follow up on\" = theo d\u00f5i ti\u1ebfp, nh\u1eafc l\u1ea1i v\u1ea5n \u0111\u1ec1 tr\u01b0\u1edbc \u0111\u00f3. C\u1ee5m phrasal verb chu\u1ea9n trong email kinh doanh. \"Follow through with\" = ho\u00e0n th\u00e0nh \u0111i\u1ec1u \u0111\u00e3 cam k\u1ebft (ngh\u0129a kh\u00e1c)."}, {"id": "hq-pr2-01", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The joint venture was formed as a result _____ extensive negotiations between the two companies.", "options": ["by", "from", "of", "through"], "answer": 2, "explanation": "\"As a result of\" = do k\u1ebft qu\u1ea3 c\u1ee7a. C\u1ee5m c\u1ed1 \u0111\u1ecbnh ba t\u1eeb, kh\u00f4ng th\u1ec3 thay \"of\" b\u1eb1ng \"from/by/through\"."}, {"id": "hq-vo-01", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The board decided to _____ the acquisition proposal after discovering discrepancies in the financial statements.", "options": ["endorse", "extend", "revise", "rescind"], "answer": 3, "explanation": "\"Rescind a proposal\" = r\u00fat l\u1ea1i, h\u1ee7y b\u1ecf ch\u00ednh th\u1ee9c (ph\u00e1p l\u00fd). \"Endorse\" = \u1ee7ng h\u1ed9 (ng\u01b0\u1ee3c ngh\u0129a). \"Revise\" = s\u1eeda \u0111\u1ed5i (kh\u00f4ng h\u1ee7y b\u1ecf)."}, {"id": "hq-p6s-01", "part": 5, "type": "part6-strategy", "difficulty": "hard", "question": "A passage states: \"Sales declined despite increased marketing spend.\" Which sentence BEST follows this?", "options": ["\"Marketing spend should be increased further.\"", "\"Management is now reviewing the strategy.\"", "\"The sales team performed excellently.\"", "\"Customers responded positively to campaigns.\""], "answer": 1, "explanation": "C\u00e2u follow-up ph\u1ea3i: (1) logic v\u1edbi th\u00f4ng tin tr\u01b0\u1edbc (decline despite spend), (2) m\u1edf ra h\u01b0\u1edbng gi\u1ea3i quy\u1ebft. \"Reviewing strategy\" l\u00e0 h\u1ec7 qu\u1ea3 t\u1ef1 nhi\u00ean nh\u1ea5t sau khi k\u1ebft qu\u1ea3 kh\u00f4ng nh\u01b0 k\u1ef3 v\u1ecdng."}, {"id": "wf2-01", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The _____ of the new cafeteria was warmly welcomed by all staff.", "options": ["opening", "openly", "openness", "open"], "answer": 0, "explanation": "\"The _____ of...\" = danh t\u1eeb l\u00e0m ch\u1ee7 ng\u1eef sau \"The\". \"Opening\" (n) = l\u1ec5 khai tr\u01b0\u01a1ng. \"Open\" l\u00e0 \u0111\u1ed9ng t\u1eeb/t\u00ednh t\u1eeb, \"openly\" l\u00e0 ph\u00f3 t\u1eeb."}, {"id": "wf2-02", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The manager called for a _____ of the entire budget allocation.", "options": ["revise", "revised", "revision", "revising"], "answer": 2, "explanation": "\"a _____ of...\" = danh t\u1eeb sau m\u1ea1o t\u1eeb \"a\". \"Revision\" (n) = s\u1ef1 xem x\u00e9t l\u1ea1i, b\u1ea3n s\u1eeda \u0111\u1ed5i. H\u1eadu t\u1ed1 -ion = danh t\u1eeb."}, {"id": "wf2-03", "part": 5, "type": "word-form", "difficulty": "easy", "question": "Staff received _____ that the annual leave policy had changed.", "options": ["notify", "notification", "notified", "notifying"], "answer": 1, "explanation": "\"received _____ that...\" = danh t\u1eeb l\u00e0 t\u00e2n ng\u1eef tr\u1ef1c ti\u1ebfp c\u1ee7a \"received\". \"Notification\" (n) = th\u00f4ng b\u00e1o. H\u1eadu t\u1ed1 -ation = danh t\u1eeb."}, {"id": "wf2-04", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The _____ of the new product was announced at the press conference.", "options": ["unveiling", "unveiled", "unveil", "unveils"], "answer": 0, "explanation": "\"The _____ of...\" = danh t\u1eeb ch\u1ee7 ng\u1eef. \"Unveiling\" (n) = s\u1ef1 ra m\u1eaft, l\u1ec5 c\u00f4ng b\u1ed1. D\u1ea1ng V-ing d\u00f9ng nh\u01b0 danh t\u1eeb."}, {"id": "wf2-05", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The company issued an _____ apologizing for the service disruption.", "options": ["announce", "announcing", "announcement", "announcer"], "answer": 2, "explanation": "\"an _____ apologizing...\" = danh t\u1eeb t\u00e2n ng\u1eef sau \"issued\". \"Announcement\" (n) = th\u00f4ng b\u00e1o. H\u1eadu t\u1ed1 -ment = danh t\u1eeb."}, {"id": "wf2-06", "part": 5, "type": "word-form", "difficulty": "easy", "question": "We appreciate your _____ in this matter and will respond promptly.", "options": ["patient", "patience", "patiently", "patientness"], "answer": 1, "explanation": "\"your _____ in...\" = danh t\u1eeb sau \u0111\u1ea1i t\u1eeb s\u1edf h\u1eefu \"your\". \"Patience\" (n) = s\u1ef1 ki\u00ean nh\u1eabn. H\u1eadu t\u1ed1 -ence = danh t\u1eeb."}, {"id": "wf2-07", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The team demonstrated outstanding _____ throughout the entire project.", "options": ["dedicate", "dedication", "dedicated", "dedicatedly"], "answer": 1, "explanation": "\"demonstrated _____ throughout...\" = danh t\u1eeb t\u00e2n ng\u1eef. \"Dedication\" (n) = s\u1ef1 c\u1ed1ng hi\u1ebfn, t\u1eadn t\u00e2m. H\u1eadu t\u1ed1 -tion = danh t\u1eeb."}, {"id": "wf2-08", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The board called for greater _____ in the company's financial reporting.", "options": ["transparent", "transparence", "transparently", "transparency"], "answer": 3, "explanation": "\"called for greater _____ in...\" = danh t\u1eeb sau t\u00ednh t\u1eeb \"greater\". \"Transparency\" (n) = s\u1ef1 minh b\u1ea1ch. H\u1eadu t\u1ed1 -cy = danh t\u1eeb."}, {"id": "wf2-09", "part": 5, "type": "word-form", "difficulty": "easy", "question": "His _____ of the legal documents took nearly three hours.", "options": ["reviewing", "review", "reviewer", "reviewed"], "answer": 1, "explanation": "\"His _____ of...\" = danh t\u1eeb sau \u0111\u1ea1i t\u1eeb s\u1edf h\u1eefu \"His\". \"Review\" (n) = s\u1ef1 xem x\u00e9t. \u0110\u00e2y l\u00e0 d\u1ea1ng danh t\u1eeb c\u1ee7a \"review\"."}, {"id": "wf2-10", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The _____ of skilled workers has become a major challenge for manufacturers.", "options": ["short", "shorten", "shortly", "shortage"], "answer": 3, "explanation": "\"The _____ of...\" = danh t\u1eeb ch\u1ee7 ng\u1eef. \"Shortage\" (n) = s\u1ef1 thi\u1ebfu h\u1ee5t. H\u1eadu t\u1ed1 -age = danh t\u1eeb."}, {"id": "wf2-11", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the merger is subject to regulatory approval.", "options": ["completion", "completed", "complete", "completing"], "answer": 0, "explanation": "\"The _____ of the merger\" = danh t\u1eeb ch\u1ee7 ng\u1eef. \"Completion\" (n) = s\u1ef1 ho\u00e0n th\u00e0nh. Ph\u00e2n bi\u1ec7t v\u1edbi \"completed\" (adj/V3) kh\u00f4ng l\u00e0m ch\u1ee7 ng\u1eef \u0111\u01b0\u1ee3c."}, {"id": "wf2-12", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The committee expressed deep _____ at the unexpected resignation of the CFO.", "options": ["concerned", "concern", "concerning", "concerns"], "answer": 1, "explanation": "\"deep _____ at...\" = danh t\u1eeb sau t\u00ednh t\u1eeb \"deep\". \"Concern\" (n) = m\u1ed1i lo ng\u1ea1i. L\u01b0u \u00fd: \"deep concern\" l\u00e0 collocation ph\u1ed5 bi\u1ebfn trong TOEIC."}, {"id": "wf2-13", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The HR team requested a detailed _____ of the hiring process from each department.", "options": ["break", "breakdown", "breaking", "breaker"], "answer": 1, "explanation": "\"a detailed _____ of...\" = danh t\u1eeb sau t\u00ednh t\u1eeb \"detailed\". \"Breakdown\" (n) = b\u1ea3ng ph\u00e2n t\u00edch chi ti\u1ebft, s\u1ef1 ph\u00e2n lo\u1ea1i. Compound noun ph\u1ed5 bi\u1ebfn trong TOEIC."}, {"id": "wf2-14", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The firm's _____ into overseas markets requires considerable upfront investment.", "options": ["entry", "enter", "entered", "entering"], "answer": 0, "explanation": "\"The firm's _____ into...\" = danh t\u1eeb sau \u0111\u1ea1i t\u1eeb s\u1edf h\u1eefu. \"Entry into\" = s\u1ef1 gia nh\u1eadp v\u00e0o. Collocation c\u1ed1 \u0111\u1ecbnh: \"entry into a market\"."}, {"id": "wf2-15", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Her _____ to adapt quickly to changing priorities impressed the hiring committee.", "options": ["able", "enables", "ably", "ability"], "answer": 3, "explanation": "\"Her _____ to adapt...\" = danh t\u1eeb sau \u0111\u1ea1i t\u1eeb s\u1edf h\u1eefu + to-infinitive. \"Ability to + V\" = kh\u1ea3 n\u0103ng l\u00e0m g\u00ec. H\u1eadu t\u1ed1 -ity = danh t\u1eeb."}, {"id": "wf2-16", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The board approved a significant _____ in the company's digital infrastructure.", "options": ["invest", "investor", "investing", "investment"], "answer": 3, "explanation": "\"a significant _____ in...\" = danh t\u1eeb sau t\u00ednh t\u1eeb \"significant\". \"Investment in\" = kho\u1ea3n \u0111\u1ea7u t\u01b0 v\u00e0o. H\u1eadu t\u1ed1 -ment = danh t\u1eeb."}, {"id": "wf2-17", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The new guidelines provide clear _____ on how to handle customer complaints.", "options": ["guide", "guidance", "guided", "guiding"], "answer": 1, "explanation": "\"provide _____ on how to...\" = danh t\u1eeb t\u00e2n ng\u1eef. \"Guidance on\" = h\u01b0\u1edbng d\u1eabn v\u1ec1. H\u1eadu t\u1ed1 -ance = danh t\u1eeb. \"Guide\" l\u00e0 danh t\u1eeb kh\u00e1c ngh\u0129a (ng\u01b0\u1eddi h\u01b0\u1edbng d\u1eabn / t\u00e0i li\u1ec7u)."}, {"id": "wf2-18", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of outdated machinery led to a 20% increase in productivity.", "options": ["replace", "replacement", "replaced", "replacing"], "answer": 1, "explanation": "\"The _____ of outdated machinery\" = danh t\u1eeb ch\u1ee7 ng\u1eef. \"Replacement of\" = vi\u1ec7c thay th\u1ebf. H\u1eadu t\u1ed1 -ment = danh t\u1eeb."}, {"id": "wf2-19", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Strong _____ with clients is essential for any account management role.", "options": ["relations", "relatable", "relate", "relational"], "answer": 0, "explanation": "\"Strong _____ with clients\" = danh t\u1eeb sau \"Strong\". \"Relations with\" = m\u1ed1i quan h\u1ec7 v\u1edbi. \"Relational\" l\u00e0 t\u00ednh t\u1eeb, \"relatable\" = d\u1ec5 \u0111\u1ed3ng c\u1ea3m."}, {"id": "wf2-20", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The government announced the _____ of new subsidies for renewable energy projects.", "options": ["introduce", "introduction", "introduced", "introductory"], "answer": 1, "explanation": "\"the _____ of new subsidies\" = danh t\u1eeb sau \"the\". \"Introduction of\" = vi\u1ec7c gi\u1edbi thi\u1ec7u/ban h\u00e0nh. H\u1eadu t\u1ed1 -tion = danh t\u1eeb."}, {"id": "wf2-21", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the product recall process was praised by industry watchdogs.", "options": ["handling", "handle", "handler", "handled"], "answer": 0, "explanation": "\"The _____ of the process\" = danh t\u1eeb ch\u1ee7 ng\u1eef. \"Handling of\" = c\u00e1ch x\u1eed l\u00fd, qu\u1ea3n l\u00fd. D\u1ea1ng V-ing d\u00f9ng nh\u01b0 danh t\u1eeb (gerund noun)."}, {"id": "wf2-22", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The director expressed his _____ that the targets would be met by year end.", "options": ["confident", "confidently", "confide", "confidence"], "answer": 3, "explanation": "\"his _____ that...\" = danh t\u1eeb sau \u0111\u1ea1i t\u1eeb s\u1edf h\u1eefu + that-clause. \"Confidence that\" = s\u1ef1 t\u1ef1 tin r\u1eb1ng. H\u1eadu t\u1ed1 -ence = danh t\u1eeb."}, {"id": "wf2-23", "part": 5, "type": "word-form", "difficulty": "medium", "question": "All equipment repairs require prior _____ from the facilities manager.", "options": ["approve", "approving", "approved", "approval"], "answer": 3, "explanation": "\"prior _____ from...\" = danh t\u1eeb sau t\u00ednh t\u1eeb \"prior\". \"Approval from\" = s\u1ef1 ch\u1ea5p thu\u1eadn t\u1eeb. H\u1eadu t\u1ed1 -al = danh t\u1eeb."}, {"id": "wf2-24", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The charity event raised funds for the _____ of a new community center.", "options": ["construct", "construction", "constructive", "constructing"], "answer": 1, "explanation": "\"the _____ of a new center\" = danh t\u1eeb sau \"the\". \"Construction of\" = vi\u1ec7c x\u00e2y d\u1ef1ng. H\u1eadu t\u1ed1 -tion = danh t\u1eeb."}, {"id": "wf2-25", "part": 5, "type": "word-form", "difficulty": "medium", "question": "A formal _____ of the complaint must be filed within ten business days.", "options": ["acknowledgment", "acknowledge", "acknowledged", "acknowledging"], "answer": 0, "explanation": "\"A formal _____ of the complaint\" = danh t\u1eeb sau t\u00ednh t\u1eeb \"formal\". \"Acknowledgment of\" = s\u1ef1 th\u1eeba nh\u1eadn, x\u00e1c nh\u1eadn. H\u1eadu t\u1ed1 -ment = danh t\u1eeb."}, {"id": "wf2-26", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The results of the clinical trial were _____ positive, exceeding all benchmarks.", "options": ["overwhelm", "overwhelmingly", "overwhelming", "overwhelmed"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb \"positive\" \u2192 ph\u00f3 t\u1eeb. \"Overwhelmingly positive\" = c\u1ef1c k\u1ef3 t\u00edch c\u1ef1c. H\u1eadu t\u1ed1 -ly b\u1ed5 ngh\u0129a cho adj."}, {"id": "wf2-27", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The seminar room is large enough to _____ accommodate all registered participants.", "options": ["comfort", "comfortable", "comfortability", "comfortably"], "answer": 3, "explanation": "B\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb \"accommodate\" \u2192 ph\u00f3 t\u1eeb. \"Comfortably accommodate\" = ti\u1ebfp \u0111\u00f3n tho\u1ea3i m\u00e1i. H\u1eadu t\u1ed1 -ly = ph\u00f3 t\u1eeb."}, {"id": "wf2-28", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The financial forecast proved to be _____ accurate when the quarterly results were released.", "options": ["remark", "remarkable", "remarkably", "remarked"], "answer": 2, "explanation": "B\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb \"accurate\" \u2192 ph\u00f3 t\u1eeb. \"Remarkably accurate\" = ch\u00ednh x\u00e1c m\u1ed9t c\u00e1ch \u0111\u00e1ng ch\u00fa \u00fd. -ly b\u1ed5 ngh\u0129a cho adj."}, {"id": "wf2-29", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The new facility is _____ equipped with the latest manufacturing technology.", "options": ["fully", "full", "fullness", "fulfill"], "answer": 0, "explanation": "B\u1ed5 ngh\u0129a cho V3 \"equipped\" (d\u1ea1ng b\u1ecb \u0111\u1ed9ng) \u2192 ph\u00f3 t\u1eeb. \"Fully equipped\" = \u0111\u01b0\u1ee3c trang b\u1ecb \u0111\u1ea7y \u0111\u1ee7. \"Fully\" l\u00e0 ph\u00f3 t\u1eeb c\u1ee7a \"full\"."}, {"id": "wf2-30", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The annual performance review process is _____ transparent and fair.", "options": ["intention", "intended", "intend", "intentionally"], "answer": 3, "explanation": "\"Intended to be transparent\" = \u0111\u01b0\u1ee3c thi\u1ebft k\u1ebf \u0111\u1ec3 minh b\u1ea1ch. \"Intended\" (adj/V3) \u0111\u1ee9ng sau \"is\" = passive adjective. \"Intentionally\" = adverb (sai v\u1ecb tr\u00ed); \"intend\" = nguy\u00ean th\u1ec3 (sai sau \"is\")."}, {"id": "wf2-31", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The revised proposal was deemed _____ by the steering committee.", "options": ["accept", "accepted", "acceptable", "acceptably"], "answer": 2, "explanation": "Sau \"deemed\" (linking verb) \u2192 t\u00ednh t\u1eeb. \"Deemed acceptable\" = \u0111\u01b0\u1ee3c coi l\u00e0 ch\u1ea5p nh\u1eadn \u0111\u01b0\u1ee3c. H\u1eadu t\u1ed1 -able = t\u00ednh t\u1eeb. \"Accepted\" = \u0111\u00e3 \u0111\u01b0\u1ee3c ch\u1ea5p nh\u1eadn (kh\u00e1c ngh\u0129a)."}, {"id": "wf2-32", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The customer feedback was _____ encouraging, with 92% expressing satisfaction.", "options": ["particularly", "particular", "particulars", "particularize"], "answer": 0, "explanation": "B\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb \"encouraging\" \u2192 ph\u00f3 t\u1eeb. \"Particularly encouraging\" = \u0111\u1eb7c bi\u1ec7t \u0111\u00e1ng kh\u00edch l\u1ec7. -ly b\u1ed5 ngh\u0129a cho adj."}, {"id": "wf2-33", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The board found the projected savings to be _____ significant.", "options": ["substantially", "substantial", "substance", "substantiate"], "answer": 0, "explanation": "B\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb \"significant\" \u2192 ph\u00f3 t\u1eeb. \"Substantially significant\" = \u0111\u00e1ng k\u1ec3. \"Substantial\" l\u00e0 t\u00ednh t\u1eeb kh\u00f4ng b\u1ed5 ngh\u0129a \u0111\u01b0\u1ee3c cho adj kh\u00e1c."}, {"id": "wf2-34", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The marketing campaign was _____ successful in reaching the target demographic.", "options": ["remark", "remarkable", "remarkably", "remarks"], "answer": 2, "explanation": "B\u1ed5 ngh\u0129a cho adj \"successful\" \u2192 ph\u00f3 t\u1eeb. \"Remarkably successful\" = th\u00e0nh c\u00f4ng \u0111\u00e1ng ch\u00fa \u00fd. -ly = ph\u00f3 t\u1eeb."}, {"id": "wf2-35", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The contractor submitted a _____ detailed report outlining all project phases.", "options": ["thorough", "thoroughly", "thoroughness", "through"], "answer": 0, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"report\" \u2192 t\u00ednh t\u1eeb. \"Thorough report\" = b\u00e1o c\u00e1o k\u1ef9 l\u01b0\u1ee1ng. \"Thoroughly\" l\u00e0 ph\u00f3 t\u1eeb kh\u00f4ng \u0111\u1ee9ng tr\u01b0\u1edbc noun tr\u1ef1c ti\u1ebfp."}, {"id": "wf2-36", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The partnership proved to be _____ beneficial for both organizations.", "options": ["mutually", "mutual", "mutuality", "mutualize"], "answer": 0, "explanation": "B\u1ed5 ngh\u0129a cho adj \"beneficial\" \u2192 ph\u00f3 t\u1eeb. \"Mutually beneficial\" = c\u00f9ng c\u00f3 l\u1ee3i. -ly = ph\u00f3 t\u1eeb. \u0110\u00e2y l\u00e0 collocation c\u1ef1c ph\u1ed5 bi\u1ebfn trong TOEIC."}, {"id": "wf2-37", "part": 5, "type": "word-form", "difficulty": "medium", "question": "We have a _____ qualified team ready to handle any technical challenges.", "options": ["high", "highness", "highest", "highly"], "answer": 3, "explanation": "B\u1ed5 ngh\u0129a cho V3 \"qualified\" \u2192 ph\u00f3 t\u1eeb. \"Highly qualified\" = c\u00f3 tr\u00ecnh \u0111\u1ed9 cao. \"High\" l\u00e0 t\u00ednh t\u1eeb/ph\u00f3 t\u1eeb nh\u01b0ng \"highly\" chu\u1ea9n h\u01a1n khi b\u1ed5 ngh\u0129a cho adj/V3."}, {"id": "wf2-38", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The new procedures made the onboarding process _____ efficient than before.", "options": ["significant", "significance", "significantly", "signified"], "answer": 2, "explanation": "B\u1ed5 ngh\u0129a cho adj \"efficient\" (trong so s\u00e1nh h\u01a1n) \u2192 ph\u00f3 t\u1eeb ch\u1ec9 m\u1ee9c \u0111\u1ed9. \"Significantly more efficient\" \u2014 \"significantly\" b\u1ed5 ngh\u0129a cho to\u00e0n c\u1ee5m so s\u00e1nh."}, {"id": "wf2-39", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The chief analyst's report was _____ praised by the investment community.", "options": ["wide", "wider", "wideness", "widely"], "answer": 3, "explanation": "B\u1ed5 ngh\u0129a cho V3 \"praised\" (passive) \u2192 ph\u00f3 t\u1eeb. \"Widely praised\" = \u0111\u01b0\u1ee3c khen r\u1ed9ng r\u00e3i. -ly = ph\u00f3 t\u1eeb."}, {"id": "wf2-40", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The vendor offered _____ priced maintenance packages tailored for small businesses.", "options": ["compete", "competitively", "competitive", "competing"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho V3 \"priced\" \u2192 ph\u00f3 t\u1eeb. \"Competitively priced\" = c\u00f3 gi\u00e1 c\u1ea1nh tranh. Collocation ph\u1ed5 bi\u1ebfn trong TOEIC. \"Competitive prices\" d\u00f9ng khi tr\u01b0\u1edbc noun."}, {"id": "wf2-41", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The board's decision to expand was both _____ sound and strategically timed.", "options": ["finance", "financial", "financed", "financially"], "answer": 3, "explanation": "B\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb \"sound\" \u2192 ph\u00f3 t\u1eeb. \"Financially sound\" = l\u00e0nh m\u1ea1nh v\u1ec1 t\u00e0i ch\u00ednh. \"Financial\" l\u00e0 adj kh\u00f4ng b\u1ed5 ngh\u0129a \u0111\u01b0\u1ee3c cho adj kh\u00e1c."}, {"id": "wf2-42", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The new regulation was _____ controversial, drawing criticism from both sides of the industry.", "options": ["wide", "widely", "width", "widen"], "answer": 1, "explanation": "\"Widely controversial\" = g\u00e2y tranh c\u00e3i r\u1ed9ng r\u00e3i. Ph\u00f3 t\u1eeb \"widely\" b\u1ed5 ngh\u0129a cho adj \"controversial\". B\u1eaby: \"wide\" c\u0169ng l\u00e0 adv nh\u01b0ng d\u00f9ng ngh\u0129a v\u1eadt l\u00fd (open wide), kh\u00f4ng b\u1ed5 ngh\u0129a cho adj."}, {"id": "wf2-43", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The new HR policy aims to _____ a more inclusive workplace culture.", "options": ["fosters", "fostered", "fostering", "foster"], "answer": 3, "explanation": "\"aims to _____ ...\" = to-infinitive \u2192 V nguy\u00ean th\u1ec3. \"Foster\" (v) = nu\u00f4i d\u01b0\u1ee1ng, th\u00fac \u0111\u1ea9y. \"Fostered/fostering/fosters\" \u0111\u1ec1u sai v\u1ecb tr\u00ed sau \"to\"."}, {"id": "wf2-44", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The team must _____ all data before submitting the final report.", "options": ["verified", "verification", "verify", "verifiable"], "answer": 2, "explanation": "Sau \"must\" (modal) \u2192 V nguy\u00ean th\u1ec3. \"Verify\" (v) = x\u00e1c minh. \"Verification\" l\u00e0 danh t\u1eeb, kh\u00f4ng \u0111\u1ee9ng sau modal."}, {"id": "wf2-45", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The workshop was designed to _____ participants' negotiation skills.", "options": ["strength", "strengthening", "strengthen", "strong"], "answer": 2, "explanation": "\"designed to _____ ...\" = to-infinitive \u2192 V nguy\u00ean th\u1ec3. \"Strengthen\" (v) = c\u1ee7ng c\u1ed1, n\u00e2ng cao. H\u1eadu t\u1ed1 -en t\u1ea1o \u0111\u1ed9ng t\u1eeb t\u1eeb danh t\u1eeb/t\u00ednh t\u1eeb."}, {"id": "wf2-46", "part": 5, "type": "word-form", "difficulty": "easy", "question": "Please _____ all changes to the project scope to the project manager.", "options": ["communicate", "communicative", "communication", "communicably"], "answer": 0, "explanation": "C\u00e2u m\u1ec7nh l\u1ec7nh (imperative) \u2192 V nguy\u00ean th\u1ec3. \"Communicate changes to someone\" = truy\u1ec1n \u0111\u1ea1t thay \u0111\u1ed5i cho ai. \"Communication\" l\u00e0 danh t\u1eeb, sai v\u1ecb tr\u00ed."}, {"id": "wf2-47", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The compliance team will _____ all new hires on data protection guidelines.", "options": ["briefly", "briefing", "briefed", "brief"], "answer": 3, "explanation": "Sau \"will\" (modal) \u2192 V nguy\u00ean th\u1ec3. \"Brief someone on something\" (v) = th\u00f4ng b\u00e1o ng\u1eafn g\u1ecdn cho ai v\u1ec1 \u0111i\u1ec1u g\u00ec. \"Briefing\" l\u00e0 danh t\u1eeb/gerund, \"briefly\" l\u00e0 ph\u00f3 t\u1eeb."}, {"id": "wf2-48", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The revised schedule should _____ any confusion about the new deadlines.", "options": ["clarified", "clarity", "clarify", "clarification"], "answer": 2, "explanation": "Sau \"should\" (modal) \u2192 V nguy\u00ean th\u1ec3. \"Clarify\" (v) = l\u00e0m r\u00f5. \"Clarity\" (n) = s\u1ef1 r\u00f5 r\u00e0ng. B\u1eaby: \"clarification\" c\u0169ng l\u00e0 danh t\u1eeb nh\u01b0ng kh\u00f4ng \u0111\u1ee9ng sau modal."}, {"id": "wf2-49", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The logistics team will _____ delivery routes to reduce fuel consumption.", "options": ["optimization", "optimize", "optimal", "optimally"], "answer": 1, "explanation": "Sau \"will\" (modal) \u2192 V nguy\u00ean th\u1ec3. \"Optimize\" (v) = t\u1ed1i \u01b0u h\u00f3a. \"Optimization\" l\u00e0 danh t\u1eeb. \"Optimal\" l\u00e0 t\u00ednh t\u1eeb."}, {"id": "wf2-50", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The CEO chose to _____ the decision until more data was available.", "options": ["deference", "deferral", "deferred", "defer"], "answer": 3, "explanation": "\"chose to _____ ...\" = to-infinitive \u2192 V nguy\u00ean th\u1ec3. \"Defer a decision\" (v) = ho\u00e3n l\u1ea1i quy\u1ebft \u0111\u1ecbnh. \"Deferral\" l\u00e0 danh t\u1eeb."}, {"id": "wf2-51", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Managers are expected to _____ a culture of accountability within their teams.", "options": ["cultural", "cultivation", "cultivate", "culturally"], "answer": 2, "explanation": "\"expected to _____ ...\" = to-infinitive \u2192 V nguy\u00ean th\u1ec3. \"Cultivate a culture\" (v) = x\u00e2y d\u1ef1ng v\u0103n h\u00f3a. Collocation: \"cultivate + culture/relationship/habit\"."}, {"id": "wf2-52", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The firm plans to _____ its services to include cloud-based storage solutions.", "options": ["broad", "broadness", "broaden", "broadly"], "answer": 2, "explanation": "\"plans to _____ ...\" = to-infinitive \u2192 V nguy\u00ean th\u1ec3. \"Broaden services\" (v) = m\u1edf r\u1ed9ng ph\u1ea1m vi d\u1ecbch v\u1ee5. H\u1eadu t\u1ed1 -en t\u1ea1o \u0111\u1ed9ng t\u1eeb (broaden, widen, strengthen)."}, {"id": "wf2-53", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The board insisted that the auditors _____ all transactions from the past fiscal year.", "options": ["scrutinize", "scrutiny", "scrutinized", "scrutinizing"], "answer": 0, "explanation": "Sau \"insisted that\" + subjunctive \u2192 V nguy\u00ean th\u1ec3 (kh\u00f4ng chia). \"Scrutinize\" (v) = ki\u1ec3m tra k\u1ef9 l\u01b0\u1ee1ng. \"Scrutiny\" l\u00e0 danh t\u1eeb."}, {"id": "wf2-54", "part": 5, "type": "word-form", "difficulty": "hard", "question": "It is imperative that every department head _____ the new compliance protocol by Friday.", "options": ["acknowledging", "acknowledgment", "acknowledged", "acknowledge"], "answer": 3, "explanation": "Subjunctive sau \"It is imperative that\" \u2192 V nguy\u00ean th\u1ec3 kh\u00f4ng chia. \"Acknowledge\" (v) = x\u00e1c nh\u1eadn. B\u1eaby: \"acknowledged\" (d\u00f9ng n\u1ebfu \"has acknowledged\") sai subjunctive."}, {"id": "wf2-55", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The new system has been _____ praised for improving employee work-life balance.", "options": ["increasing", "increase", "increased", "increasingly"], "answer": 3, "explanation": "\"_____ praised\" = ph\u00f3 t\u1eeb b\u1ed5 ngh\u0129a cho V3. \"Increasingly praised\" = \u0111\u01b0\u1ee3c khen ng\u00e0y c\u00e0ng nhi\u1ec1u. \"Increasing\" l\u00e0 t\u00ednh t\u1eeb/V-ing kh\u00f4ng b\u1ed5 ngh\u0129a cho V3 \u0111\u01b0\u1ee3c."}, {"id": "wf2-56", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The project scope was _____ defined, causing confusion among team members.", "options": ["poor", "poverty", "poorly", "poorness"], "answer": 2, "explanation": "\"_____ defined\" (V3 passive) \u2192 ph\u00f3 t\u1eeb. \"Poorly defined\" = \u0111\u01b0\u1ee3c \u0111\u1ecbnh ngh\u0129a k\u00e9m r\u00f5 r\u00e0ng. \"Poor\" l\u00e0 t\u00ednh t\u1eeb kh\u00f4ng b\u1ed5 ngh\u0129a cho V3."}, {"id": "wf2-57", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The two systems operate _____, allowing each department to function independently.", "options": ["separate", "separately", "separated", "separation"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb \"operate\" \u2192 ph\u00f3 t\u1eeb. \"Operate separately\" = ho\u1ea1t \u0111\u1ed9ng ri\u00eang bi\u1ec7t. \"Separate\" l\u00e0 adj/v kh\u00f4ng \u0111\u1ee9ng sau linking verb \u0111\u1ec3 b\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb kh\u00e1c."}, {"id": "wf2-58", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The marketing strategy was _____ reviewed and updated before the product launch.", "options": ["comprehensively", "comprehensive", "comprehension", "comprehend"], "answer": 0, "explanation": "B\u1ed5 ngh\u0129a cho V3 \"reviewed\" \u2192 ph\u00f3 t\u1eeb. \"Comprehensively reviewed\" = \u0111\u01b0\u1ee3c xem x\u00e9t to\u00e0n di\u1ec7n. \"Comprehensive\" l\u00e0 adj kh\u00f4ng \u0111\u1ee9ng tr\u01b0\u1edbc V3 nh\u01b0 adverb."}, {"id": "wf2-59", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Candidates must demonstrate _____ knowledge of at least two programming languages.", "options": ["profession", "professionalism", "professionally", "professional"], "answer": 3, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"knowledge\" \u2192 t\u00ednh t\u1eeb. \"Professional knowledge\" = ki\u1ebfn th\u1ee9c chuy\u00ean nghi\u1ec7p. \"Professionally\" l\u00e0 ph\u00f3 t\u1eeb kh\u00f4ng \u0111\u1ee9ng tr\u01b0\u1edbc noun. \"Professionalism\" l\u00e0 danh t\u1eeb."}, {"id": "wf2-60", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The supplier failed to _____ its obligations under the service agreement.", "options": ["fulfill", "fulfillment", "fulfilled", "fulfilling"], "answer": 0, "explanation": "\"failed to _____ ...\" = to-infinitive \u2192 V nguy\u00ean th\u1ec3. \"Fulfill obligations\" (v) = th\u1ef1c hi\u1ec7n ngh\u0129a v\u1ee5. \"Fulfillment\" l\u00e0 danh t\u1eeb, \"fulfilled\" l\u00e0 adj/V3."}, {"id": "wf2-61", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The CEO issued a _____ statement confirming the acquisition of the rival firm.", "options": ["brevity", "briefly", "briefness", "brief"], "answer": 3, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"statement\" \u2192 t\u00ednh t\u1eeb. \"Brief statement\" = tuy\u00ean b\u1ed1 ng\u1eafn g\u1ecdn. \"Briefly\" l\u00e0 ph\u00f3 t\u1eeb, \"brevity\" l\u00e0 danh t\u1eeb (= s\u1ef1 ng\u1eafn g\u1ecdn)."}, {"id": "wf2-62", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The accounts payable team works closely with vendors to _____ payment disputes.", "options": ["resolution", "resolutely", "resolute", "resolve"], "answer": 3, "explanation": "\"to _____ payment disputes\" = to-infinitive \u2192 V nguy\u00ean th\u1ec3. \"Resolve disputes\" (v) = gi\u1ea3i quy\u1ebft tranh ch\u1ea5p. \"Resolution\" l\u00e0 danh t\u1eeb."}, {"id": "wf2-63", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The committee's findings were _____ consistent with those of the independent audit.", "options": ["broad", "broadness", "broadly", "broaden"], "answer": 2, "explanation": "\"_____ consistent\" = ph\u00f3 t\u1eeb b\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb \"consistent\". \"Broadly consistent\" = nh\u00ecn chung ph\u00f9 h\u1ee3p, nh\u1ea5t qu\u00e1n (t\u01b0\u01a1ng \u0111\u01b0\u01a1ng \"generally consistent\"). \"Broad\" l\u00e0 adj."}, {"id": "wf2-64", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The outcome of the review was _____ anticipated to trigger further regulatory scrutiny.", "options": ["wide", "widely", "widen", "width"], "answer": 1, "explanation": "\"_____ anticipated\" = ph\u00f3 t\u1eeb b\u1ed5 ngh\u0129a cho V3 (passive). \"Widely anticipated\" = \u0111\u01b0\u1ee3c d\u1ef1 \u0111o\u00e1n r\u1ed9ng r\u00e3i. \"Wide\" d\u00f9ng ngh\u0129a v\u1eadt l\u00fd (wide open), kh\u00f4ng b\u1ed5 ngh\u0129a cho V3 nh\u01b0 th\u1ebf n\u00e0y."}, {"id": "wf2-65", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The annual report reveals a _____ increase in operating costs across all divisions.", "options": ["marked", "mark", "markedly", "marking"], "answer": 0, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"increase\" \u2192 t\u00ednh t\u1eeb. \"Marked increase\" = s\u1ef1 gia t\u0103ng r\u00f5 r\u1ec7t. \"Markedly\" l\u00e0 ph\u00f3 t\u1eeb kh\u00f4ng \u0111\u1ee9ng tr\u01b0\u1edbc noun tr\u1ef1c ti\u1ebfp."}, {"id": "wf2-66", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The board was _____ divided on the question of whether to pursue an international IPO.", "options": ["sharp", "sharpen", "sharpness", "sharply"], "answer": 3, "explanation": "\"_____ divided\" = ph\u00f3 t\u1eeb b\u1ed5 ngh\u0129a cho V3/adj \"divided\". \"Sharply divided\" = chia r\u1ebd s\u00e2u s\u1eafc. Collocation n\u00e2ng cao trong TOEIC: sharply/deeply/bitterly divided."}, {"id": "wf2-67", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The procurement team is responsible for _____ all supplier contracts annually.", "options": ["renewing", "renewal", "renewed", "renew"], "answer": 0, "explanation": "\"responsible for + V-ing\" = c\u1ea5u tr\u00fac adj + gi\u1edbi t\u1eeb. \"Responsible for renewing\" = ch\u1ecbu tr\u00e1ch nhi\u1ec7m gia h\u1ea1n. \"For\" l\u00e0 gi\u1edbi t\u1eeb \u2192 V-ing."}, {"id": "wf2-68", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ engineer has over fifteen years of experience in civil construction.", "options": ["lead", "leading", "leader", "led"], "answer": 1, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"engineer\" \u2192 t\u00ednh t\u1eeb/participial adj. \"Leading engineer\" = k\u1ef9 s\u01b0 h\u00e0ng \u0111\u1ea7u. \"Lead engineer\" c\u0169ng \u0111\u00fang (compound noun), nh\u01b0ng \"leading\" ph\u1ed5 bi\u1ebfn h\u01a1n trong TOEIC."}, {"id": "wf2-69", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The training program focuses on _____ participants' project management capabilities.", "options": ["enhance", "enhancing", "enhanced", "enhancement"], "answer": 1, "explanation": "\"focuses on + V-ing\" = c\u1ea5u tr\u00fac gi\u1edbi t\u1eeb \"on\" + V-ing. \"Enhancing capabilities\" = n\u00e2ng cao n\u0103ng l\u1ef1c. \"On\" l\u00e0 gi\u1edbi t\u1eeb \u2192 V-ing."}, {"id": "wf2-70", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the contract was handled by the company's legal department.", "options": ["negotiate", "negotiated", "negotiation", "negotiating"], "answer": 2, "explanation": "\"The _____ of the contract\" = danh t\u1eeb ch\u1ee7 ng\u1eef. \"Negotiation of\" = s\u1ef1 \u0111\u00e0m ph\u00e1n. H\u1eadu t\u1ed1 -tion = danh t\u1eeb."}, {"id": "wf2-71", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Employees are encouraged to take _____ of the company's professional development fund.", "options": ["advantage", "advantageous", "advantageously", "advantages"], "answer": 0, "explanation": "\"take advantage of\" = th\u00e0nh ng\u1eef c\u1ed1 \u0111\u1ecbnh = t\u1eadn d\u1ee5ng. \"Advantage\" (n) = s\u1ed1 \u00edt trong c\u1ee5m c\u1ed1 \u0111\u1ecbnh n\u00e0y. Kh\u00f4ng d\u00f9ng \"advantages\" (plural) trong \"take advantage of\"."}, {"id": "wf2-72", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The board is seeking a _____ and cost-effective solution to the parking shortage.", "options": ["practical", "practice", "practically", "practicality"], "answer": 0, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"solution\" \u2192 t\u00ednh t\u1eeb (n\u1ed1i v\u1edbi \"cost-effective\" b\u1edfi \"and\"). \"Practical solution\" = gi\u1ea3i ph\u00e1p th\u1ef1c t\u1ebf. \"Practically\" l\u00e0 ph\u00f3 t\u1eeb, \"practicality\" l\u00e0 danh t\u1eeb."}, {"id": "wf2-73", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The proposed amendments are _____ compatible with the existing regulatory framework.", "options": ["broad", "breadth", "broadened", "broadly"], "answer": 3, "explanation": "\"_____ compatible\" = ph\u00f3 t\u1eeb b\u1ed5 ngh\u0129a cho adj \"compatible\". \"Broadly compatible\" = nh\u00ecn chung t\u01b0\u01a1ng th\u00edch. T\u1eeb n\u00e2ng cao th\u01b0\u1eddng g\u1eb7p trong v\u0103n b\u1ea3n ch\u00ednh s\u00e1ch TOEIC."}, {"id": "wf2-74", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The CEO's remarks were _____ interpreted as a signal that restructuring was imminent.", "options": ["wide", "width", "widely", "widen"], "answer": 2, "explanation": "\"_____ interpreted\" = ph\u00f3 t\u1eeb b\u1ed5 ngh\u0129a cho V3. \"Widely interpreted as\" = \u0111\u01b0\u1ee3c nhi\u1ec1u ng\u01b0\u1eddi di\u1ec5n gi\u1ea3i l\u00e0. Collocation hay g\u1eb7p trong b\u1ea3n tin kinh t\u1ebf TOEIC."}, {"id": "wf2-75", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The quarterly earnings call revealed a _____ troubling pattern in customer churn rates.", "options": ["distinct", "distinctly", "distinction", "distinctive"], "answer": 1, "explanation": "\"_____ troubling\" = ph\u00f3 t\u1eeb b\u1ed5 ngh\u0129a cho adj \"troubling\". \"Distinctly troubling\" = \u0111\u00e1ng lo ng\u1ea1i m\u1ed9t c\u00e1ch r\u00f5 r\u00e0ng. \"Distinctive\" = \u0111\u1eb7c bi\u1ec7t/\u0111\u1eb7c tr\u01b0ng (kh\u00e1c ngh\u0129a)."}, {"id": "wf2-76", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The department head asked for a _____ estimate of the project's total cost.", "options": ["ballpark", "ball", "balled", "balling"], "answer": 0, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"estimate\" \u2192 t\u00ednh t\u1eeb/noun modifier. \"Ballpark estimate\" = \u01b0\u1edbc t\u00ednh s\u01a1 b\u1ed9. Compound noun ph\u1ed5 bi\u1ebfn trong TOEIC th\u01b0\u01a1ng m\u1ea1i."}, {"id": "wf2-77", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The company has made _____ efforts to reduce its environmental impact this year.", "options": ["concertedly", "concert", "concerted", "concerting"], "answer": 2, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"efforts\" \u2192 t\u00ednh t\u1eeb. \"Concerted efforts\" = n\u1ed7 l\u1ef1c t\u1eadp th\u1ec3, ph\u1ed1i h\u1ee3p. Collocation chu\u1ea9n TOEIC: \"make concerted efforts to\"."}, {"id": "wf2-78", "part": 5, "type": "word-form", "difficulty": "medium", "question": "All new employees must _____ an orientation session during their first week.", "options": ["attendance", "attend", "attendant", "attending"], "answer": 1, "explanation": "Sau \"must\" (modal) \u2192 V nguy\u00ean th\u1ec3. \"Attend a session\" (v) = tham d\u1ef1 bu\u1ed5i h\u1ecdc. \"Attendance\" l\u00e0 danh t\u1eeb, \"attendant\" l\u00e0 ng\u01b0\u1eddi ph\u1ee5c v\u1ee5."}, {"id": "wf2-79", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The hotel is pleased to offer _____ shuttle service to and from the airport.", "options": ["compliment", "complimentary", "complement", "complementary"], "answer": 1, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"shuttle service\" \u2192 t\u00ednh t\u1eeb. \"Complimentary\" = mi\u1ec5n ph\u00ed (trong ng\u1eef c\u1ea3nh d\u1ecbch v\u1ee5 kh\u00e1ch s\u1ea1n). \"Complementary\" = b\u1ed5 sung cho nhau. B\u1eaby ph\u1ed5 bi\u1ebfn TOEIC."}, {"id": "wf2-80", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The intern showed a _____ attitude throughout her three-month placement.", "options": ["professional", "profess", "profession", "professionally"], "answer": 0, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"attitude\" \u2192 t\u00ednh t\u1eeb. \"Professional attitude\" = th\u00e1i \u0111\u1ed9 chuy\u00ean nghi\u1ec7p. \"Professionally\" l\u00e0 ph\u00f3 t\u1eeb, \"profession\" l\u00e0 danh t\u1eeb."}, {"id": "wf2-81", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The new filing system has made document _____ much faster for all administrative staff.", "options": ["retrieve", "retrieved", "retrieval", "retrieving"], "answer": 2, "explanation": "Danh t\u1eeb trong c\u1ee5m \"document _____ \" = compound noun l\u00e0m ch\u1ee7 ng\u1eef. \"Document retrieval\" = vi\u1ec7c truy xu\u1ea5t t\u00e0i li\u1ec7u. \"Retrieval\" (n) = s\u1ef1 l\u1ea5y l\u1ea1i. H\u1eadu t\u1ed1 -al = danh t\u1eeb."}, {"id": "wf2-82", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The accounting team will _____ all figures before submitting the quarterly report.", "options": ["double-check", "double-checking", "double-checked", "double-checker"], "answer": 0, "explanation": "Sau \"will\" (modal) \u2192 V nguy\u00ean th\u1ec3. \"Double-check figures\" (v) = ki\u1ec3m tra k\u1ef9 l\u1ea1i c\u00e1c con s\u1ed1. Compound verb ph\u1ed5 bi\u1ebfn trong TOEIC v\u0103n ph\u00f2ng."}, {"id": "wf2-83", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The factory's _____ output surpassed targets for the third consecutive quarter.", "options": ["monthly", "month", "monthwise", "months"], "answer": 0, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"output\" \u2192 t\u00ednh t\u1eeb. \"Monthly output\" = s\u1ea3n l\u01b0\u1ee3ng h\u00e0ng th\u00e1ng. \"Monthly\" (adj) = h\u00e0ng th\u00e1ng. L\u01b0u \u00fd: \"daily/weekly/monthly/quarterly\" th\u01b0\u1eddng d\u00f9ng l\u00e0m adj tr\u01b0\u1edbc noun trong TOEIC."}, {"id": "wf2-84", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the original contract terms was necessary due to changing market conditions.", "options": ["amend", "amending", "amended", "amendment"], "answer": 3, "explanation": "\"The _____ of the contract terms\" = danh t\u1eeb ch\u1ee7 ng\u1eef. \"Amendment of\" = s\u1ef1 s\u1eeda \u0111\u1ed5i (ph\u00e1p l\u00fd). H\u1eadu t\u1ed1 -ment = danh t\u1eeb. Ph\u00e2n bi\u1ec7t: \"revision\" (chung) vs \"amendment\" (ph\u00e1p l\u00fd)."}, {"id": "wf2-85", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The proposed takeover is seen as _____ audacious, even by the standards of the industry.", "options": ["remarkable", "remark", "remarkably", "remarked"], "answer": 2, "explanation": "\"_____ audacious\" = ph\u00f3 t\u1eeb b\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb \"audacious\". \"Remarkably audacious\" = li\u1ec1u l\u0129nh m\u1ed9t c\u00e1ch \u0111\u00e1ng ch\u00fa \u00fd. \"Audacious\" = t\u00e1o b\u1ea1o \u2014 t\u1eeb n\u00e2ng cao trong TOEIC."}, {"id": "wf2-86", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The new pricing model proved _____ disruptive to established players in the sector.", "options": ["profound", "profoundly", "profundity", "profoundness"], "answer": 1, "explanation": "\"Proved profoundly disruptive\" = ph\u00f3 t\u1eeb b\u1ed5 ngh\u0129a cho t\u00ednh t\u1eeb \"disruptive\". \"Profoundly + adj\" = c\u1ea5u tr\u00fac \u0111\u00fang. \"Profundity / profoundness\" l\u00e0 danh t\u1eeb, sai v\u1ecb tr\u00ed."}, {"id": "wf2-87", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The logistics manager proposed a _____ cost-cutting measure that was immediately adopted.", "options": ["novelize", "novelly", "novelty", "novel"], "answer": 3, "explanation": "Tr\u01b0\u1edbc c\u1ee5m t\u00ednh t\u1eeb \"cost-cutting measure\" \u2192 t\u00ednh t\u1eeb. \"Novel measure\" = bi\u1ec7n ph\u00e1p m\u1edbi l\u1ea1, s\u00e1ng t\u1ea1o. \"Novelty\" l\u00e0 danh t\u1eeb. \"Novelly\" kh\u00f4ng t\u1ed3n t\u1ea1i."}, {"id": "wf2-88", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The terms of the settlement are _____ binding on both parties from the date of signing.", "options": ["legal", "legalize", "legality", "legally"], "answer": 3, "explanation": "\"_____ binding\" = ph\u00f3 t\u1eeb b\u1ed5 ngh\u0129a cho adj \"binding\". \"Legally binding\" = c\u00f3 gi\u00e1 tr\u1ecb r\u00e0ng bu\u1ed9c v\u1ec1 m\u1eb7t ph\u00e1p l\u00fd. Collocation ph\u00e1p l\u00fd quan tr\u1ecdng trong TOEIC."}, {"id": "wf2-89", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ tone of the CEO's address reassured investors about the company's future.", "options": ["confidence", "confident", "confidently", "confide"], "answer": 1, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"tone\" \u2192 t\u00ednh t\u1eeb. \"Confident tone\" = gi\u1ecdng \u0111i\u1ec7u t\u1ef1 tin. \"Confidence\" l\u00e0 danh t\u1eeb, \"confidently\" l\u00e0 ph\u00f3 t\u1eeb."}, {"id": "wf2-90", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the new employee engagement survey will be shared company-wide.", "options": ["findings", "find", "found", "finder"], "answer": 0, "explanation": "\"The _____ of the survey\" = danh t\u1eeb ch\u1ee7 ng\u1eef (d\u00f9ng s\u1ed1 nhi\u1ec1u). \"Findings\" (n, plural) = c\u00e1c k\u1ebft qu\u1ea3, ph\u00e1t hi\u1ec7n. \"Find\" l\u00e0 \u0111\u1ed9ng t\u1eeb, \"finder\" l\u00e0 ng\u01b0\u1eddi t\u00ecm."}, {"id": "voc2-01", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The store will _____ a sale on all electronics starting this Friday.", "options": ["do", "make", "hold", "run"], "answer": 2, "explanation": "\"Hold a sale\" = t\u1ed5 ch\u1ee9c \u0111\u1ee3t gi\u1ea3m gi\u00e1. Collocation c\u1ed1 \u0111\u1ecbnh. \"Run a sale\" c\u0169ng \u0111\u00fang trong ng\u1eef c\u1ea3nh qu\u1ea3ng c\u00e1o. \"Make/do a sale\" kh\u00f4ng d\u00f9ng \u0111\u01b0\u1ee3c."}, {"id": "voc2-02", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The new software _____ with most existing accounting platforms.", "options": ["combines", "communicates", "connects to", "integrates"], "answer": 3, "explanation": "\"Integrates with\" = t\u00edch h\u1ee3p v\u1edbi. Collocation k\u1ef9 thu\u1eadt chu\u1ea9n: \"software/system integrates with\". \"Connects to\" v\u00e0 \"combines\" sai collocation v\u1edbi \"platforms\"."}, {"id": "voc2-03", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The hotel will _____ complimentary breakfast for guests who book directly.", "options": ["provide", "make", "give out", "supply to"], "answer": 0, "explanation": "\"Provide + noun\" = cung c\u1ea5p (tr\u1ef1c ti\u1ebfp + t\u00e2n ng\u1eef). \"Provide complimentary breakfast\" l\u00e0 collocation t\u1ef1 nhi\u00ean nh\u1ea5t. \"Give out\" = ph\u00e1t mi\u1ec5n ph\u00ed (informal)."}, {"id": "voc2-04", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "Please _____ the form in full before handing it to the receptionist.", "options": ["fill out", "fill up", "complete", "fill in"], "answer": 3, "explanation": "\"Fill in a form\" = \u0111i\u1ec1n v\u00e0o (British English). \"Fill out\" (American). \"Fill up\" = \u0111\u1ed5 \u0111\u1ea7y (nhi\u00ean li\u1ec7u...). \"Complete\" c\u0169ng \u0111\u00fang nh\u01b0ng c\u00e2u h\u1ecfi c\u00f3 \"in full\" \u2192 \"fill in\" ph\u00f9 h\u1ee3p nh\u1ea5t."}, {"id": "voc2-05", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The new branch will _____ its doors on the first Monday of April.", "options": ["start", "launch", "open", "begin"], "answer": 2, "explanation": "\"Open its doors\" = m\u1edf c\u1eeda ho\u1ea1t \u0111\u1ed9ng. Idiom c\u1ed1 \u0111\u1ecbnh trong TOEIC. \"Launch\" d\u00f9ng cho s\u1ea3n ph\u1ea9m/chi\u1ebfn d\u1ecbch. \"Start/begin its doors\" kh\u00f4ng t\u1ef1 nhi\u00ean."}, {"id": "voc2-06", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The IT team will _____ all computers to the latest operating system this weekend.", "options": ["revise", "update", "renew", "upgrade"], "answer": 3, "explanation": "\"Upgrade computers/systems\" = n\u00e2ng c\u1ea5p (version m\u1edbi h\u01a1n). \"Update\" = c\u1eadp nh\u1eadt (c\u00f9ng version). \"Upgrade\" ph\u00f9 h\u1ee3p khi n\u00f3i v\u1ec1 OS version m\u1edbi."}, {"id": "voc2-07", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "We would like to _____ our congratulations to the award-winning team.", "options": ["extend", "give", "send", "offer"], "answer": 0, "explanation": "\"Extend congratulations\" = b\u00e0y t\u1ecf l\u1eddi ch\u00fac m\u1eebng (trang tr\u1ecdng). Collocation ch\u00ednh th\u1ee9c. \"Offer congratulations\" c\u0169ng \u0111\u00fang. \"Give/send congratulations\" informal h\u01a1n."}, {"id": "voc2-08", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The company agreed to _____ the outstanding invoice within five business days.", "options": ["pay off", "settle", "clear", "handle"], "answer": 1, "explanation": "\"Settle an invoice/debt/payment\" = thanh to\u00e1n, gi\u1ea3i quy\u1ebft xong. Collocation t\u00e0i ch\u00ednh chu\u1ea9n trong TOEIC. \"Clear\" c\u0169ng d\u00f9ng \u0111\u01b0\u1ee3c nh\u01b0ng \"settle\" ph\u1ed5 bi\u1ebfn h\u01a1n v\u1edbi \"invoice\"."}, {"id": "voc2-09", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The president of the association will _____ the opening ceremony next Tuesday.", "options": ["officiate", "host", "perform", "conduct"], "answer": 1, "explanation": "\"Host a ceremony/event\" = ch\u1ee7 tr\u00ec s\u1ef1 ki\u1ec7n. Trong ng\u1eef c\u1ea3nh \"opening ceremony\" \u2192 \"host\" ph\u00f9 h\u1ee3p nh\u1ea5t. \"Officiate\" th\u01b0\u1eddng d\u00f9ng cho \u0111\u00e1m c\u01b0\u1edbi/nghi l\u1ec5 t\u00f4n gi\u00e1o."}, {"id": "voc2-10", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The new policy will _____ effect from the first day of next month.", "options": ["take", "come into", "go into", "become"], "answer": 0, "explanation": "\"Take effect\" = c\u00f3 hi\u1ec7u l\u1ef1c. C\u1ee5m c\u1ed1 \u0111\u1ecbnh trong TOEIC: \"take effect\", \"come into effect\", \"go into effect\" \u0111\u1ec1u \u0111\u00fang nh\u01b0ng \"take effect from [date]\" l\u00e0 chu\u1ea9n nh\u1ea5t."}, {"id": "voc2-11", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "Ms. Chen will _____ her position as Regional Director at the end of the quarter.", "options": ["leave", "vacate", "quit", "abandon"], "answer": 1, "explanation": "\"Vacate a position/post\" = r\u1eddi kh\u1ecfi v\u1ecb tr\u00ed (trang tr\u1ecdng, HR). \"Leave\" l\u00e0 kh\u00f4ng trang tr\u1ecdng. \"Quit\" = b\u1ecf vi\u1ec7c (informal). \"Abandon\" = b\u1ecf r\u01a1i (qu\u00e1 m\u1ea1nh)."}, {"id": "voc2-12", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "All travel bookings must be _____ through the company's designated travel portal.", "options": ["processed", "arranged", "made", "done"], "answer": 0, "explanation": "\"Processed through a portal/system\" = x\u1eed l\u00fd qua h\u1ec7 th\u1ed1ng. \"Made through\" c\u0169ng \u0111\u00fang. \"Processed\" nh\u1ea5n m\u1ea1nh y\u1ebfu t\u1ed1 h\u1ec7 th\u1ed1ng/quy tr\u00ecnh ph\u00f9 h\u1ee3p v\u1edbi \"portal\"."}, {"id": "voc2-13", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The management team decided to _____ an external consultant to review the strategy.", "options": ["engage", "hire", "employ", "appoint"], "answer": 0, "explanation": "\"Engage a consultant\" = thu\u00ea, m\u1eddi chuy\u00ean gia t\u01b0 v\u1ea5n (trang tr\u1ecdng). Collocation chu\u1ea9n trong v\u0103n b\u1ea3n kinh doanh TOEIC. \"Hire\" informal h\u01a1n, \"appoint\" cho v\u1ecb tr\u00ed ch\u00ednh th\u1ee9c."}, {"id": "voc2-14", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The company will _____ all eligible employees a performance bonus in December.", "options": ["award", "give", "grant", "offer"], "answer": 0, "explanation": "\"Award employees a bonus\" = trao th\u01b0\u1edfng cho nh\u00e2n vi\u00ean. Collocation HR chu\u1ea9n: \"award + person + bonus/prize\". \"Grant\" th\u01b0\u1eddng d\u00f9ng cho permission/funding."}, {"id": "voc2-15", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The new employee had trouble _____ to the fast-paced work environment.", "options": ["adjusting", "adapting", "conforming", "fitting"], "answer": 1, "explanation": "\"Adapt to an environment/situation\" = th\u00edch nghi v\u1edbi. Collocation chu\u1ea9n. \"Adjust to\" c\u0169ng \u0111\u00fang. \"Adapt to\" ph\u1ed5 bi\u1ebfn h\u01a1n trong TOEIC khi n\u00f3i v\u1ec1 m\u00f4i tr\u01b0\u1eddng l\u00e0m vi\u1ec7c."}, {"id": "voc2-16", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The new model _____ on the success of its predecessor with enhanced features.", "options": ["expands", "improves", "builds", "adds"], "answer": 2, "explanation": "\"Build on success/predecessor\" = k\u1ebf th\u1eeba v\u00e0 ph\u00e1t tri\u1ec3n t\u1eeb. Phrasal verb ph\u1ed5 bi\u1ebfn trong TOEIC marketing. \"Build on\" = d\u1ef1a tr\u00ean \u0111\u1ec3 ph\u00e1t tri\u1ec3n th\u00eam."}, {"id": "voc2-17", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "Please _____ the signed contract to HR no later than Wednesday.", "options": ["relay", "send on", "pass on", "forward"], "answer": 3, "explanation": "\"Forward a document\" = chuy\u1ec3n ti\u1ebfp t\u00e0i li\u1ec7u (email v\u0103n ph\u00f2ng). Collocation chu\u1ea9n nh\u1ea5t trong ng\u1eef c\u1ea3nh g\u1eedi t\u00e0i li\u1ec7u \u0111\u1ebfn b\u1ed9 ph\u1eadn kh\u00e1c."}, {"id": "voc2-18", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The quarterly report _____ a significant increase in online sales.", "options": ["highlights", "underlines", "emphasizes", "stresses"], "answer": 0, "explanation": "\"The report highlights\" = b\u00e1o c\u00e1o n\u00eau b\u1eadt, nh\u1ea5n m\u1ea1nh \u0111i\u1ec3m quan tr\u1ecdng. \"Highlight\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t v\u1edbi \"report\" trong TOEIC."}, {"id": "voc2-19", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The company plans to _____ a new loyalty program for its frequent customers.", "options": ["launch", "roll out", "introduce", "implement"], "answer": 1, "explanation": "\"Roll out a program\" = tri\u1ec3n khai theo giai \u0111o\u1ea1n. Phrasal verb ph\u1ed5 bi\u1ebfn trong TOEIC khi n\u00f3i v\u1ec1 launch c\u00f3 k\u1ebf ho\u1ea1ch. \"Launch\" = ra m\u1eaft ch\u00ednh th\u1ee9c, \"roll out\" = tri\u1ec3n khai d\u1ea7n."}, {"id": "voc2-20", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The contractor must _____ all work within the timeline specified in the agreement.", "options": ["wrap up", "finish", "conclude", "complete"], "answer": 3, "explanation": "\"Complete work within a timeline\" = ho\u00e0n th\u00e0nh c\u00f4ng vi\u1ec7c trong th\u1eddi h\u1ea1n. \"Complete\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t v\u1edbi \"work\" trong v\u0103n b\u1ea3n h\u1ee3p \u0111\u1ed3ng TOEIC."}, {"id": "voc2-21", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "The board will _____ the merger proposal at next month's general meeting.", "options": ["deliberate on", "discuss", "review", "consider"], "answer": 3, "explanation": "\"Consider a proposal\" = xem x\u00e9t \u0111\u1ec1 xu\u1ea5t. Ph\u1ed5 bi\u1ebfn nh\u1ea5t trong v\u0103n b\u1ea3n ch\u00ednh th\u1ee9c. \"Deliberate on\" = th\u1ea3o lu\u1eadn k\u1ef9 (formal nh\u01b0ng \u00edt g\u1eb7p). \"Review\" = xem x\u00e9t l\u1ea1i."}, {"id": "voc2-22", "part": 5, "type": "vocabulary", "difficulty": "easy", "question": "Staff are required to _____ their time sheets at the end of each week.", "options": ["hand in", "submit", "turn in", "send"], "answer": 1, "explanation": "\"Submit time sheets\" = n\u1ed9p b\u1ea3ng ch\u1ea5m c\u00f4ng (trang tr\u1ecdng nh\u1ea5t). \"Submit\" l\u00e0 collocation chu\u1ea9n trong v\u0103n b\u1ea3n HR, h\u1ee3p \u0111\u1ed3ng TOEIC."}, {"id": "voc2-23", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company has decided to _____ its partnership with the distributor due to repeated delays.", "options": ["stop", "end", "terminate", "break"], "answer": 2, "explanation": "\"Terminate a partnership/contract\" = ch\u1ea5m d\u1ee9t (trang tr\u1ecdng, ph\u00e1p l\u00fd). \"End/stop\" informal h\u01a1n. \"Break a partnership\" kh\u00f4ng t\u1ef1 nhi\u00ean trong v\u0103n phong TOEIC."}, {"id": "voc2-24", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The sales representative _____ a three-year maintenance contract with the largest client.", "options": ["agreed", "argued", "discussed", "negotiated"], "answer": 3, "explanation": "\"Negotiate a contract\" = \u0111\u00e0m ph\u00e1n h\u1ee3p \u0111\u1ed3ng. Collocation chu\u1ea9n: \"negotiate + contract/deal/agreement\". \"Agree a contract\" informal (British). \"Discuss\" kh\u00f4ng c\u00f3 ngh\u0129a k\u00fd/ho\u00e0n th\u00e0nh."}, {"id": "voc2-25", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The new software is expected to _____ manual data entry by automating key workflows.", "options": ["eliminate", "remove", "reduce", "cut"], "answer": 0, "explanation": "\"Eliminate manual data entry\" = lo\u1ea1i b\u1ecf ho\u00e0n to\u00e0n vi\u1ec7c nh\u1eadp d\u1eef li\u1ec7u th\u1ee7 c\u00f4ng. \"Eliminate\" m\u1ea1nh nh\u1ea5t (ho\u00e0n to\u00e0n lo\u1ea1i b\u1ecf). \"Reduce\" = ch\u1ec9 gi\u1ea3m b\u1edbt, kh\u00f4ng lo\u1ea1i b\u1ecf ho\u00e0n to\u00e0n."}, {"id": "voc2-26", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The manufacturer issued a _____ for all units sold between January and March.", "options": ["return", "recall", "retrieval", "refund"], "answer": 1, "explanation": "\"Issue a recall\" = thu h\u1ed3i s\u1ea3n ph\u1ea9m. Collocation k\u1ef9 ngh\u1ec7/TOEIC chu\u1ea9n: \"product recall\". \"Refund\" = ho\u00e0n ti\u1ec1n, \"return\" = tr\u1ea3 l\u1ea1i (h\u00e0nh \u0111\u1ed9ng c\u1ee7a kh\u00e1ch h\u00e0ng)."}, {"id": "voc2-27", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The conference was _____ to bring together researchers from over 30 countries.", "options": ["held", "organized", "convened", "arranged"], "answer": 2, "explanation": "\"Convene a conference\" = tri\u1ec7u t\u1eadp, t\u1ed5 ch\u1ee9c h\u1ed9i ngh\u1ecb (trang tr\u1ecdng nh\u1ea5t). Ph\u00e2n bi\u1ec7t: \"organize/hold/arrange\" \u0111\u1ec1u \u0111\u00fang nh\u01b0ng \"convene\" mang t\u00ednh ch\u00ednh th\u1ee9c cao h\u01a1n trong TOEIC."}, {"id": "voc2-28", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The director was asked to _____ her findings at the annual strategy meeting.", "options": ["demonstrate", "show", "tell", "present"], "answer": 3, "explanation": "\"Present findings/results\" = tr\u00ecnh b\u00e0y k\u1ebft qu\u1ea3. Collocation chu\u1ea9n nh\u1ea5t trong ng\u1eef c\u1ea3nh h\u1ecdp chi\u1ebfn l\u01b0\u1ee3c. \"Show findings\" informal. \"Demonstrate\" th\u01b0\u1eddng cho s\u1ea3n ph\u1ea9m/k\u1ef9 n\u0103ng."}, {"id": "voc2-29", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The new factory is expected to _____ 5,000 units per day once fully operational.", "options": ["generate", "produce", "output", "manufacture"], "answer": 1, "explanation": "\"Produce units/goods\" = s\u1ea3n xu\u1ea5t. Collocation chu\u1ea9n nh\u1ea5t v\u1edbi \"units per day\" trong ng\u1eef c\u1ea3nh s\u1ea3n xu\u1ea5t. \"Manufacture\" c\u0169ng \u0111\u00fang nh\u01b0ng \"produce X units\" ph\u1ed5 bi\u1ebfn h\u01a1n trong TOEIC."}, {"id": "voc2-30", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The technical team successfully _____ the software glitch before the client presentation.", "options": ["corrected", "fixed", "resolved", "handled"], "answer": 2, "explanation": "\"Resolve a glitch/issue/problem\" = gi\u1ea3i quy\u1ebft s\u1ef1 c\u1ed1 (trang tr\u1ecdng nh\u1ea5t). \"Fixed a glitch\" c\u0169ng \u0111\u00fang (informal). \"Resolved\" mang t\u00ednh ho\u00e0n th\u00e0nh v\u00e0 trang tr\u1ecdng h\u01a1n trong TOEIC."}, {"id": "voc2-31", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The board has agreed to _____ additional capital to fund the expansion into Southeast Asia.", "options": ["accumulate", "gather", "collect", "raise"], "answer": 3, "explanation": "\"Raise capital/funds\" = huy \u0111\u1ed9ng v\u1ed1n. Collocation t\u00e0i ch\u00ednh c\u1ed1 \u0111\u1ecbnh: \"raise capital/funds/money\". \"Collect/gather capital\" kh\u00f4ng t\u1ef1 nhi\u00ean trong ng\u1eef c\u1ea3nh t\u00e0i ch\u00ednh doanh nghi\u1ec7p."}, {"id": "voc2-32", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The customer service manager _____ the issue to the operations director for immediate resolution.", "options": ["escalated", "referred", "forwarded", "transferred"], "answer": 0, "explanation": "\"Escalate an issue\" = n\u00e2ng c\u1ea5p m\u1ee9c \u0111\u1ed9 x\u1eed l\u00fd, chuy\u1ec3n l\u00ean c\u1ea5p tr\u00ean. Thu\u1eadt ng\u1eef TOEIC th\u01b0\u01a1ng m\u1ea1i: \"escalate a complaint/issue\" khi v\u01b0\u1ee3t kh\u1ecfi t\u1ea7m gi\u1ea3i quy\u1ebft c\u1ee7a c\u1ea5p d\u01b0\u1edbi."}, {"id": "voc2-33", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The firm will _____ its pricing model to reflect the rise in raw material costs.", "options": ["change", "revise", "alter", "modify"], "answer": 1, "explanation": "\"Revise a model/plan/policy\" = s\u1eeda \u0111\u1ed5i ch\u00ednh th\u1ee9c. \"Revise\" d\u00f9ng khi c\u00f3 s\u1eeda \u0111\u1ed5i c\u00f3 h\u1ec7 th\u1ed1ng v\u00e0 ch\u00ednh th\u1ee9c. \"Modify\" = thay \u0111\u1ed5i nh\u1ecf. \"Alter\" = thay \u0111\u1ed5i chi ti\u1ebft."}, {"id": "voc2-34", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The survey results _____ a growing preference among consumers for eco-friendly packaging.", "options": ["prove", "show", "indicate", "confirm"], "answer": 2, "explanation": "\"Results indicate\" = k\u1ebft qu\u1ea3 cho th\u1ea5y (trang tr\u1ecdng, h\u1ecdc thu\u1eadt). Collocation v\u1edbi \"survey results\": \"indicate/reveal/suggest\". \"Prove\" qu\u00e1 m\u1ea1nh cho survey data."}, {"id": "voc2-35", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The two companies have agreed to _____ forces to bid for the government contract.", "options": ["unite", "combine", "pool", "join"], "answer": 3, "explanation": "\"Join forces\" = h\u1ee3p t\u00e1c, li\u00ean k\u1ebft. Idiom c\u1ed1 \u0111\u1ecbnh. \"Pool resources\" = g\u1ed9p ngu\u1ed3n l\u1ef1c. \"Join forces (with someone) to do something\" l\u00e0 c\u1ee5m c\u1ed1 \u0111\u1ecbnh quan tr\u1ecdng trong TOEIC."}, {"id": "voc2-36", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The director praised the team for its ability to _____ tight deadlines without compromising quality.", "options": ["meet", "hit", "reach", "achieve"], "answer": 0, "explanation": "\"Meet deadlines\" = ho\u00e0n th\u00e0nh \u0111\u00fang h\u1ea1n. Collocation c\u1ed1 \u0111\u1ecbnh TOEIC. \"Hit a deadline\" (informal). \"Reach/achieve a deadline\" kh\u00f4ng t\u1ef1 nhi\u00ean trong v\u0103n chu\u1ea9n."}, {"id": "voc2-37", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The legal team has been asked to _____ the terms of the licensing agreement.", "options": ["go over", "review", "check", "read through"], "answer": 1, "explanation": "\"Review the terms of an agreement\" = xem x\u00e9t l\u1ea1i c\u00e1c \u0111i\u1ec1u kho\u1ea3n. \"Review\" l\u00e0 collocation trang tr\u1ecdng nh\u1ea5t v\u1edbi \"terms/agreement/contract\" trong TOEIC."}, {"id": "voc2-38", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The workshop aims to _____ participants with practical tools for conflict resolution.", "options": ["furnish", "provide", "supply", "equip"], "answer": 3, "explanation": "\"Equip participants with tools/skills\" = trang b\u1ecb c\u00f4ng c\u1ee5/k\u1ef9 n\u0103ng cho ng\u01b0\u1eddi h\u1ecdc. \"Furnish with\" = cung c\u1ea5p (v\u1eadt d\u1ee5ng). \"Equip with\" ph\u00f9 h\u1ee3p nh\u1ea5t khi n\u00f3i v\u1ec1 skills/tools trong TOEIC."}, {"id": "voc2-39", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company has set up a task force to _____ the root cause of the production delays.", "options": ["study", "examine", "inquire", "investigate"], "answer": 3, "explanation": "\"Investigate the root cause\" = \u0111i\u1ec1u tra nguy\u00ean nh\u00e2n g\u1ed1c r\u1ec5. Collocation chu\u1ea9n trong TOEIC: \"investigate + cause/incident/complaint\". \"Examine\" th\u01b0\u1eddng d\u00f9ng cho documents/evidence."}, {"id": "voc2-40", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The CEO reminded all staff that confidential information must not be _____ outside the company.", "options": ["revealed", "disclosed", "shared", "released"], "answer": 1, "explanation": "\"Disclose confidential information\" = ti\u1ebft l\u1ed9 th\u00f4ng tin m\u1eadt (ph\u00e1p l\u00fd/HR). Collocation ch\u00ednh th\u1ee9c. \"Reveal\" informal h\u01a1n. \"Disclose\" ph\u1ed5 bi\u1ebfn nh\u1ea5t trong v\u0103n b\u1ea3n ph\u00e1p l\u00fd/kinh doanh TOEIC."}, {"id": "voc2-41", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The marketing division will _____ the campaign strategy before finalizing the media plan.", "options": ["perfect", "improve", "refine", "polish"], "answer": 2, "explanation": "\"Refine a strategy/plan\" = tinh ch\u1ec9nh, ho\u00e0n thi\u1ec7n (professional). \"Refine\" = c\u1ea3i thi\u1ec7n theo h\u01b0\u1edbng chuy\u00ean nghi\u1ec7p h\u01a1n. \"Polish\" = \u0111\u00e1nh b\u00f3ng (informal). \"Perfect\" = ho\u00e0n thi\u1ec7n ho\u00e0n to\u00e0n."}, {"id": "voc2-42", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "All participants are asked to _____ their microphones when not speaking during the webinar.", "options": ["disable", "silence", "turn off", "mute"], "answer": 3, "explanation": "\"Mute a microphone\" = t\u1eaft ti\u1ebfng micro. Collocation k\u1ef9 thu\u1eadt chu\u1ea9n trong ng\u1eef c\u1ea3nh cu\u1ed9c h\u1ecdp tr\u1ef1c tuy\u1ebfn TOEIC hi\u1ec7n \u0111\u1ea1i."}, {"id": "voc2-43", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The construction project has been _____ due to unforeseen structural complications.", "options": ["stalled", "delayed", "stopped", "halted"], "answer": 0, "explanation": "\"Project is stalled\" = d\u1ef1 \u00e1n b\u1ecb \u0111\u00ecnh tr\u1ec7, m\u1eafc k\u1eb9t (kh\u00f4ng th\u1ec3 ti\u1ebfn tri\u1ec3n). \"Delayed\" = b\u1ecb tr\u00ec ho\u00e3n (th\u1eddi gian). \"Halted\" = d\u1eebng l\u1ea1i ho\u00e0n to\u00e0n (t\u1ea1m th\u1eddi). \"Stalled\" = m\u1eafc k\u1eb9t kh\u00f4ng ti\u1ebfn \u0111\u01b0\u1ee3c."}, {"id": "voc2-44", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The committee was unable to _____ a consensus on the proposed budget cuts.", "options": ["come to", "reach", "arrive at", "achieve"], "answer": 1, "explanation": "\"Reach a consensus\" = \u0111\u1ea1t \u0111\u01b0\u1ee3c s\u1ef1 \u0111\u1ed3ng thu\u1eadn. Collocation c\u1ed1 \u0111\u1ecbnh. \"Come to a consensus\" c\u0169ng \u0111\u00fang. \"Reach\" l\u00e0 ph\u1ed5 bi\u1ebfn v\u00e0 t\u1ef1 nhi\u00ean nh\u1ea5t v\u1edbi \"consensus\" trong TOEIC."}, {"id": "voc2-45", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The team worked overtime to _____ the backlog of pending customer orders.", "options": ["handle", "resolve", "clear", "process"], "answer": 2, "explanation": "\"Clear a backlog\" = gi\u1ea3i quy\u1ebft xong h\u1ebft h\u00e0ng t\u1ed3n/c\u00f4ng vi\u1ec7c t\u1ed3n \u0111\u1ecdng. Collocation \u0111\u1eb7c bi\u1ec7t: \"clear a backlog/queue/pile\". \"Process orders\" = x\u1eed l\u00fd \u0111\u01a1n h\u00e0ng (kh\u00f4ng gi\u1ea3i quy\u1ebft \u0111\u01b0\u1ee3c \"backlog\")."}, {"id": "voc2-46", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company decided to _____ the project rather than continue investing in a failing venture.", "options": ["abandon", "terminate", "scrap", "discontinue"], "answer": 2, "explanation": "\"Scrap a project\" = h\u1ee7y b\u1ecf ho\u00e0n to\u00e0n (informal nh\u01b0ng ph\u1ed5 bi\u1ebfn trong TOEIC). \"Abandon\" = b\u1ecf d\u1edf. \"Terminate\" = ch\u1ea5m d\u1ee9t ch\u00ednh th\u1ee9c. \"Scrap\" = x\u00f3a b\u1ecf ho\u00e0n to\u00e0n, th\u01b0\u1eddng do kh\u00f4ng hi\u1ec7u qu\u1ea3."}, {"id": "voc2-47", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The legal team advised the firm to _____ from making any public statements until the investigation concluded.", "options": ["refrain", "abstain", "avoid", "hold back"], "answer": 0, "explanation": "\"Refrain from + V-ing\" = ki\u00eang, tr\u00e1nh l\u00e0m g\u00ec (trang tr\u1ecdng). Collocation ph\u00e1p l\u00fd chu\u1ea9n. \"Abstain from\" th\u01b0\u1eddng d\u00f9ng cho b\u1ecf phi\u1ebfu/h\u00e0nh vi. \"Refrain from\" ph\u1ed5 bi\u1ebfn h\u01a1n trong TOEIC."}, {"id": "voc2-48", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The board approved the plan to _____ the two underperforming divisions into a single unit.", "options": ["consolidate", "combine", "join", "merge"], "answer": 0, "explanation": "\"Consolidate divisions/departments\" = h\u1ee3p nh\u1ea5t \u0111\u1ec3 tinh gi\u1ea3n. \"Merge\" = s\u00e1p nh\u1eadp hai \u0111\u01a1n v\u1ecb th\u00e0nh m\u1ed9t m\u1edbi. \"Consolidate\" nh\u1ea5n m\u1ea1nh vi\u1ec7c t\u1ed5 ch\u1ee9c l\u1ea1i \u0111\u1ec3 hi\u1ec7u qu\u1ea3 h\u01a1n \u2014 ph\u1ed5 bi\u1ebfn trong TOEIC."}, {"id": "voc2-49", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The firm's reputation took a serious _____ following the data breach last spring.", "options": ["damage", "blow", "hit", "setback"], "answer": 2, "explanation": "\"Reputation took a hit\" = danh ti\u1ebfng b\u1ecb t\u1ed5n h\u1ea1i. Idiom kinh doanh chu\u1ea9n. \"Took a blow\" c\u0169ng \u0111\u00fang. \"Setback\" = s\u1ef1 th\u1ee5t l\u00f9i (kh\u00f4ng d\u00f9ng v\u1edbi \"take\"). \"Damage\" l\u00e0 danh t\u1eeb nh\u01b0ng \"took damage\" kh\u00f4ng t\u1ef1 nhi\u00ean."}, {"id": "voc2-50", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company plans to _____ its workforce by 15% to reduce overhead costs.", "options": ["downsize", "reduce", "cut", "trim"], "answer": 0, "explanation": "\"Downsize workforce/staff\" = thu h\u1eb9p quy m\u00f4 nh\u00e2n s\u1ef1 (c\u1eaft gi\u1ea3m). Thu\u1eadt ng\u1eef HR/TOEIC chuy\u00ean bi\u1ec7t. \"Reduce workforce\" c\u0169ng \u0111\u00fang. \"Downsize\" ph\u1ed5 bi\u1ebfn v\u00e0 trang tr\u1ecdng h\u01a1n trong v\u0103n b\u1ea3n kinh doanh."}, {"id": "voc2-51", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The legal team was asked to _____ the liability clause in the original contract.", "options": ["reconsider", "revisit", "renegotiate", "revise"], "answer": 1, "explanation": "\"Revisit a clause/issue\" = xem x\u00e9t l\u1ea1i, m\u1edf l\u1ea1i v\u1ea5n \u0111\u1ec1. \"Revisit\" = quay l\u1ea1i xem x\u00e9t (kh\u00f4ng nh\u1ea5t thi\u1ebft thay \u0111\u1ed5i). \"Renegotiate\" = \u0111\u00e0m ph\u00e1n l\u1ea1i. C\u00e2u ch\u1ec9 n\u00f3i \"xem x\u00e9t l\u1ea1i\" \u2192 revisit."}, {"id": "voc2-52", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "Shareholders are encouraged to _____ their voting rights at the AGM.", "options": ["apply", "use", "exercise", "employ"], "answer": 2, "explanation": "\"Exercise voting rights\" = th\u1ef1c hi\u1ec7n quy\u1ec1n b\u1ea7u phi\u1ebfu. Collocation ph\u00e1p l\u00fd chu\u1ea9n: \"exercise + right/option/authority\". \"Use rights\" informal h\u01a1n."}, {"id": "voc2-53", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company was forced to _____ its growth forecast after weaker-than-expected results.", "options": ["cut", "lower", "reduce", "revise downward"], "answer": 3, "explanation": "\"Revise downward a forecast\" = h\u1ea1 th\u1ea5p d\u1ef1 b\u00e1o. Collocation t\u00e0i ch\u00ednh chu\u1ea9n. \"Revise downward/upward\" l\u00e0 c\u1ee5m ph\u1ed5 bi\u1ebfn trong b\u00e1o c\u00e1o kinh doanh TOEIC."}, {"id": "voc2-54", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The proposal was put _____ by the finance team and immediately passed to the board.", "options": ["forward", "forth", "ahead", "out"], "answer": 0, "explanation": "\"Put forward a proposal\" = \u0111\u1ec1 xu\u1ea5t, tr\u00ecnh b\u00e0y. Phrasal verb chu\u1ea9n TOEIC. \"Put forth\" c\u0169ng \u0111\u00fang (formal). \"Put forward\" ph\u1ed5 bi\u1ebfn h\u01a1n trong v\u0103n b\u1ea3n kinh doanh."}, {"id": "voc2-55", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The HR department will _____ an investigation into the complaint filed by the employee.", "options": ["initiate", "begin", "start", "launch"], "answer": 0, "explanation": "\"Initiate an investigation\" = kh\u1edfi \u0111\u1ed9ng cu\u1ed9c \u0111i\u1ec1u tra (trang tr\u1ecdng nh\u1ea5t). \"Launch an investigation\" c\u0169ng \u0111\u00fang. \"Initiate\" mang t\u00ednh ch\u00ednh th\u1ee9c v\u00e0 ph\u00e1p l\u00fd cao nh\u1ea5t trong TOEIC."}, {"id": "voc2-56", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The new package deal is designed to _____ a wider range of customers.", "options": ["capture", "attract", "appeal to", "target"], "answer": 2, "explanation": "\"Appeal to a wider audience/range of customers\" = h\u1ea5p d\u1eabn/thu h\u00fat nhi\u1ec1u \u0111\u1ed1i t\u01b0\u1ee3ng h\u01a1n. \"Appeal to\" = ph\u00f9 h\u1ee3p v\u1edbi nhu c\u1ea7u/s\u1edf th\u00edch c\u1ee7a. \"Attract customers\" c\u0169ng \u0111\u00fang nh\u01b0ng \"appeal to\" t\u1ef1 nhi\u00ean h\u01a1n."}, {"id": "voc2-57", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The seminar will _____ on the latest advances in supply chain management.", "options": ["emphasize", "concentrate", "center", "focus"], "answer": 3, "explanation": "\"Focus on a topic\" = t\u1eadp trung v\u00e0o. Collocation ph\u1ed5 bi\u1ebfn nh\u1ea5t v\u1edbi \"seminar/workshop will _____ on\". \"Concentrate on\" c\u0169ng \u0111\u00fang. \"Center on\" = xoay quanh."}, {"id": "voc2-58", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The senior developer was asked to _____ the junior team through the onboarding process.", "options": ["walk", "guide", "lead", "take"], "answer": 1, "explanation": "\"Guide someone through a process\" = h\u01b0\u1edbng d\u1eabn ai qua quy tr\u00ecnh. \"Walk someone through\" c\u0169ng ph\u1ed5 bi\u1ebfn. \"Guide through\" trang tr\u1ecdng h\u01a1n trong v\u0103n b\u1ea3n HR TOEIC."}, {"id": "voc2-59", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company aims to _____ its environmental impact by switching to renewable energy sources.", "options": ["reduce", "mitigate", "lower", "lessen"], "answer": 1, "explanation": "\"Mitigate environmental impact\" = gi\u1ea3m thi\u1ec3u t\u00e1c \u0111\u1ed9ng m\u00f4i tr\u01b0\u1eddng (trang tr\u1ecdng, b\u1ec1n v\u1eefng). \"Mitigate\" l\u00e0 t\u1eeb chuy\u00ean bi\u1ec7t trong v\u0103n b\u1ea3n CSR/sustainability TOEIC."}, {"id": "voc2-60", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The design team was asked to _____ the packaging to make it more environmentally friendly.", "options": ["modify", "rethink", "redo", "redesign"], "answer": 3, "explanation": "\"Redesign packaging\" = thi\u1ebft k\u1ebf l\u1ea1i bao b\u00ec. \"Redesign\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t trong TOEIC marketing/product. \"Modify\" = thay \u0111\u1ed5i nh\u1ecf (kh\u00f4ng ph\u00f9 h\u1ee3p khi \u0111\u1ed5i to\u00e0n b\u1ed9 thi\u1ebft k\u1ebf)."}, {"id": "voc2-61", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The firm has been working to _____ its supply chain in response to recent disruptions.", "options": ["streamline", "simplify", "improve", "optimize"], "answer": 0, "explanation": "\"Streamline supply chain/operations\" = tinh g\u1ecdn quy tr\u00ecnh. \"Streamline\" nh\u1ea5n m\u1ea1nh vi\u1ec7c lo\u1ea1i b\u1ecf b\u01b0\u1edbc th\u1eeba, t\u0103ng hi\u1ec7u qu\u1ea3. \"Optimize\" = t\u1ed1i \u01b0u h\u00f3a (chung h\u01a1n)."}, {"id": "voc2-62", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The project manager must _____ all stakeholders about any changes to the timeline.", "options": ["notify", "advise", "inform", "alert"], "answer": 2, "explanation": "\"Inform stakeholders about changes\" = th\u00f4ng b\u00e1o cho c\u00e1c b\u00ean li\u00ean quan. \"Inform about\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t. \"Notify of\" c\u0169ng \u0111\u00fang. \"Advise\" = khuy\u00ean, t\u01b0 v\u1ea5n."}, {"id": "voc2-63", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The department head will _____ the budget proposal to the finance committee next week.", "options": ["table", "introduce", "submit", "present"], "answer": 3, "explanation": "\"Present a budget proposal\" = tr\u00ecnh b\u00e0y \u0111\u1ec1 xu\u1ea5t ng\u00e2n s\u00e1ch. \"Table\" trong American English = tr\u00ec ho\u00e3n; trong British English = \u0111\u01b0a ra th\u1ea3o lu\u1eadn (ambiguous). \"Present\" an to\u00e0n nh\u1ea5t trong TOEIC."}, {"id": "voc2-64", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The brand has managed to _____ a strong reputation for quality over the past decade.", "options": ["build", "establish", "develop", "create"], "answer": 1, "explanation": "\"Establish a reputation\" = x\u00e2y d\u1ef1ng danh ti\u1ebfng (trang tr\u1ecdng nh\u1ea5t). \"Build a reputation\" c\u0169ng \u0111\u00fang. \"Establish\" mang \u00fd ngh\u0129a c\u01a1 s\u1edf v\u1eefng ch\u1eafc h\u01a1n trong v\u0103n b\u1ea3n kinh doanh TOEIC."}, {"id": "voc2-65", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "Please _____ your full legal name as it appears on your government-issued identification.", "options": ["enter", "write", "type", "put"], "answer": 0, "explanation": "\"Enter your name\" = nh\u1eadp t\u00ean (v\u00e0o form/h\u1ec7 th\u1ed1ng). Collocation k\u1ef9 thu\u1eadt chu\u1ea9n. \"Enter information\" ph\u1ed5 bi\u1ebfn nh\u1ea5t trong ng\u1eef c\u1ea3nh bi\u1ec3u m\u1eabu/h\u1ec7 th\u1ed1ng \u0111i\u1ec7n t\u1eed TOEIC."}, {"id": "voc2-66", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company plans to _____ its lease on the current office space for another five years.", "options": ["extend", "renew", "continue", "maintain"], "answer": 1, "explanation": "\"Renew a lease/contract/subscription\" = gia h\u1ea1n. Collocation c\u1ed1 \u0111\u1ecbnh: \"renew + lease/contract/license/subscription\". \"Extend\" = gia h\u1ea1n th\u00eam (th\u1eddi gian), \"renew\" = l\u00e0m m\u1edbi/k\u00fd l\u1ea1i."}, {"id": "voc2-67", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The two firms agreed to _____ their resources to develop a new product together.", "options": ["merge", "combine", "pool", "share"], "answer": 2, "explanation": "\"Pool resources/funds/expertise\" = g\u1ed9p chung ngu\u1ed3n l\u1ef1c. Collocation chu\u1ea9n: \"pool + resources/funds/efforts\". \"Share resources\" = chia s\u1ebb (kh\u00f4ng g\u1ed9p l\u1ea1i). \"Pool\" nh\u1ea5n m\u1ea1nh \u0111\u00f3ng g\u00f3p chung."}, {"id": "voc2-68", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The spokesperson was careful to _____ the company's position on the controversial issue.", "options": ["define", "explain", "state", "clarify"], "answer": 3, "explanation": "\"Clarify the company's position\" = l\u00e0m r\u00f5 quan \u0111i\u1ec3m. \"Clarify\" = gi\u1ea3i th\u00edch r\u00f5 h\u01a1n v\u1ec1 \u0111i\u1ec1u c\u00f2n m\u01a1 h\u1ed3. \"State a position\" = tuy\u00ean b\u1ed1 quan \u0111i\u1ec3m (kh\u00f4ng nh\u1ea5t thi\u1ebft l\u00e0m r\u00f5)."}, {"id": "voc2-69", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The auditors were unable to _____ the discrepancy in the financial records.", "options": ["account for", "explain", "justify", "identify"], "answer": 0, "explanation": "\"Account for a discrepancy\" = gi\u1ea3i th\u00edch, l\u00fd gi\u1ea3i s\u1ef1 ch\u00eanh l\u1ec7ch. Phrasal verb t\u00e0i ch\u00ednh chu\u1ea9n: \"account for + discrepancy/difference/loss\". \"Identify\" = ch\u1ec9 x\u00e1c \u0111\u1ecbnh, kh\u00f4ng gi\u1ea3i th\u00edch."}, {"id": "voc2-70", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The firm decided to _____ its R&D budget by 20% to accelerate product development.", "options": ["increase", "raise", "boost", "grow"], "answer": 2, "explanation": "\"Boost a budget/sales/productivity\" = t\u0103ng c\u01b0\u1eddng m\u1ea1nh m\u1ebd. \"Boost\" c\u00f3 h\u00e0m \u00fd t\u00edch c\u1ef1c v\u00e0 ch\u1ee7 \u0111\u1ed9ng h\u01a1n \"increase\". Ph\u1ed5 bi\u1ebfn trong v\u0103n b\u1ea3n kinh doanh TOEIC khi nh\u1ea5n m\u1ea1nh n\u1ed7 l\u1ef1c."}, {"id": "voc2-71", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The head of procurement was asked to _____ better terms with the key supplier.", "options": ["work out", "discuss", "arrange", "negotiate"], "answer": 3, "explanation": "\"Negotiate better terms\" = \u0111\u00e0m ph\u00e1n \u0111i\u1ec1u kho\u1ea3n t\u1ed1t h\u01a1n. Collocation ch\u00ednh x\u00e1c nh\u1ea5t. \"Work out terms\" = th\u1ecfa thu\u1eadn \u0111i\u1ec1u kho\u1ea3n (informal). \"Negotiate\" chu\u1ea9n nh\u1ea5t trong v\u0103n b\u1ea3n h\u1ee3p \u0111\u1ed3ng TOEIC."}, {"id": "voc2-72", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The manager asked her assistant to _____ the meeting minutes and send them to all attendees.", "options": ["circulate", "distribute", "send out", "forward"], "answer": 0, "explanation": "\"Circulate meeting minutes\" = g\u1eedi/l\u01b0u h\u00e0nh bi\u00ean b\u1ea3n cu\u1ed9c h\u1ecdp. \"Circulate documents\" l\u00e0 collocation v\u0103n ph\u00f2ng chu\u1ea9n trong TOEIC khi g\u1eedi \u0111\u1ebfn nhi\u1ec1u ng\u01b0\u1eddi c\u00f9ng l\u00fac."}, {"id": "voc2-73", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The annual review will _____ into account both individual performance and team contributions.", "options": ["bring", "take", "put", "keep"], "answer": 1, "explanation": "\"Take into account\" = t\u00ednh \u0111\u1ebfn, x\u00e9t \u0111\u1ebfn. Phrasal verb c\u1ed1 \u0111\u1ecbnh quan tr\u1ecdng. \"Take into account + factor\" = c\u1ee5m hay g\u1eb7p nh\u1ea5t trong TOEIC khi n\u00f3i v\u1ec1 \u0111\u00e1nh gi\u00e1/quy\u1ebft \u0111\u1ecbnh."}, {"id": "voc2-74", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company's new CSR report _____ how it plans to achieve carbon neutrality by 2035.", "options": ["explains", "describes", "outlines", "presents"], "answer": 2, "explanation": "\"Report outlines plans/strategy\" = ph\u00e1c th\u1ea3o/n\u00eau r\u00f5 k\u1ebf ho\u1ea1ch. \"Outline\" l\u00e0 collocation chu\u1ea9n trong TOEIC khi n\u00f3i v\u1ec1 t\u00e0i li\u1ec7u tr\u00ecnh b\u00e0y t\u1ed5ng quan c\u00f3 c\u1ea5u tr\u00fac."}, {"id": "voc2-75", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The operations team will _____ a full audit of all inventory levels next quarter.", "options": ["conduct", "undertake", "perform", "execute"], "answer": 0, "explanation": "\"Conduct an audit\" = ti\u1ebfn h\u00e0nh ki\u1ec3m to\u00e1n. Collocation chu\u1ea9n nh\u1ea5t: \"conduct + audit/survey/review/research\". \"Undertake\" c\u0169ng \u0111\u00fang nh\u01b0ng \u00edt ph\u1ed5 bi\u1ebfn v\u1edbi \"audit\"."}, {"id": "voc2-76", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The two companies have decided to _____ their distribution networks in the Asia-Pacific region.", "options": ["integrate", "merge", "unite", "link"], "answer": 0, "explanation": "\"Integrate distribution networks\" = t\u00edch h\u1ee3p, g\u1ed9p m\u1ea1ng l\u01b0\u1edbi ph\u00e2n ph\u1ed1i. \"Integrate\" nh\u1ea5n m\u1ea1nh k\u1ebft h\u1ee3p v\u00e0o m\u1ed9t h\u1ec7 th\u1ed1ng chung. \"Merge\" = s\u00e1p nh\u1eadp (c\u00f4ng ty). \"Unite\" qu\u00e1 chung."}, {"id": "voc2-77", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The financial controller recommended that management _____ the cost structure before year-end.", "options": ["review", "reassess", "reconsider", "recheck"], "answer": 1, "explanation": "\"Reassess the cost structure\" = \u0111\u00e1nh gi\u00e1 l\u1ea1i c\u01a1 c\u1ea5u chi ph\u00ed. \"Reassess\" = \u0111\u00e1nh gi\u00e1 l\u1ea1i to\u00e0n di\u1ec7n. \"Review\" = xem x\u00e9t l\u1ea1i. \"Reassess\" m\u1ea1nh h\u01a1n, c\u00f3 h\u00e0m \u00fd c\u1ea7n thay \u0111\u1ed5i."}, {"id": "voc2-78", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The company was quick to _____ responsibility for the error and offered a full refund.", "options": ["acknowledge", "take", "accept", "admit"], "answer": 0, "explanation": "\"Acknowledge responsibility\" = th\u1eeba nh\u1eadn tr\u00e1ch nhi\u1ec7m (trang tr\u1ecdng nh\u1ea5t trong ng\u1eef c\u1ea3nh c\u00f4ng ty). \"Accept/take responsibility\" c\u0169ng \u0111\u00fang. \"Acknowledge\" nh\u1ea5n m\u1ea1nh nh\u00ecn nh\u1eadn ch\u00ednh th\u1ee9c."}, {"id": "voc2-79", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The proposal was _____ rejected by the committee after only a brief discussion.", "options": ["unanimously", "outright", "promptly", "firmly"], "answer": 1, "explanation": "\"Outright rejected\" = b\u1ecb t\u1eeb ch\u1ed1i ho\u00e0n to\u00e0n, kh\u00f4ng th\u01b0\u01a1ng l\u01b0\u1ee3ng. Adverb collocation \u0111\u1eb7c bi\u1ec7t: \"outright rejection/ban/failure\". \"Unanimously rejected\" = nh\u1ea5t tr\u00ed b\u00e1c b\u1ecf (kh\u00e1c ngh\u0129a)."}, {"id": "voc2-80", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The marketing team will _____ a series of focus groups to test the new branding concept.", "options": ["run", "hold", "conduct", "organize"], "answer": 2, "explanation": "\"Conduct focus groups\" = ti\u1ebfn h\u00e0nh nh\u00f3m t\u1eadp trung (nghi\u00ean c\u1ee9u th\u1ecb tr\u01b0\u1eddng). Collocation nghi\u00ean c\u1ee9u chu\u1ea9n. \"Run focus groups\" c\u0169ng \u0111\u00fang (informal). \"Conduct\" ph\u1ed5 bi\u1ebfn nh\u1ea5t trong TOEIC academic/business."}, {"id": "voc2-81", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The firm has been struggling to _____ qualified engineers in a highly competitive job market.", "options": ["hold", "keep", "retain", "maintain"], "answer": 2, "explanation": "\"Retain qualified employees/talent\" = gi\u1eef ch\u00e2n nh\u00e2n t\u00e0i. Collocation HR chu\u1ea9n. \"Retain\" l\u00e0 t\u1eeb chuy\u00ean bi\u1ec7t trong v\u0103n b\u1ea3n nh\u00e2n s\u1ef1 TOEIC (employee retention strategy)."}, {"id": "voc2-82", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The new pricing strategy is intended to _____ market share from competitors.", "options": ["win", "gain", "take", "capture"], "answer": 3, "explanation": "\"Capture market share\" = chi\u1ebfm l\u0129nh th\u1ecb ph\u1ea7n. Collocation marketing chu\u1ea9n: \"capture + market share/audience\". \"Gain market share\" c\u0169ng \u0111\u00fang nh\u01b0ng \"capture\" nh\u1ea5n m\u1ea1nh h\u00e0nh \u0111\u1ed9ng ch\u1ee7 \u0111\u1ed9ng h\u01a1n."}, {"id": "voc2-83", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The board agreed to _____ the final vote until all board members were present.", "options": ["defer", "postpone", "delay", "put off"], "answer": 0, "explanation": "\"Defer a vote/decision\" = ho\u00e3n, tr\u00ec ho\u00e3n (trang tr\u1ecdng nh\u1ea5t). \"Defer\" mang t\u00ednh ch\u00ednh th\u1ee9c trong v\u0103n b\u1ea3n ph\u00e1p l\u00fd/qu\u1ea3n tr\u1ecb. \"Postpone\" c\u0169ng \u0111\u00fang nh\u01b0ng \"defer\" chu\u1ea9n h\u01a1n v\u1edbi \"vote/decision\"."}, {"id": "voc2-84", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The project deadline has been _____ to allow time for additional testing.", "options": ["pushed back", "extended", "moved", "postponed"], "answer": 1, "explanation": "\"Deadline has been extended\" = h\u1ea1n ch\u00f3t \u0111\u01b0\u1ee3c gia h\u1ea1n. \"Extended\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t v\u1edbi \"deadline\" trong TOEIC. \"Pushed back\" informal. \"Postponed\" th\u01b0\u1eddng d\u00f9ng cho s\u1ef1 ki\u1ec7n."}, {"id": "voc2-85", "part": 5, "type": "vocabulary", "difficulty": "medium", "question": "The management team decided to _____ on a new market entry strategy during the retreat.", "options": ["agree", "settle", "sign off", "decide"], "answer": 2, "explanation": "\"Sign off on a strategy/plan\" = ph\u00ea duy\u1ec7t, \u0111\u1ed3ng \u00fd ch\u00ednh th\u1ee9c. Phrasal verb qu\u1ea3n l\u00fd ph\u1ed5 bi\u1ebfn trong TOEIC: \"sign off on + decision/plan/document\" = ph\u00ea duy\u1ec7t cu\u1ed1i c\u00f9ng."}, {"id": "voc2-86", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The government is set to _____ a comprehensive review of the tax code later this year.", "options": ["oversee", "conduct", "undertake", "commission"], "answer": 3, "explanation": "\"Commission a review/report/study\" = \u0111\u1eb7t h\u00e0ng/\u1ee7y th\u00e1c th\u1ef1c hi\u1ec7n (t\u1eeb b\u00ean ngo\u00e0i). \"Commission\" h\u00e0m \u00fd thu\u00ea b\u00ean th\u1ee9 ba. \"Conduct\" = t\u1ef1 ti\u1ebfn h\u00e0nh. Ng\u1eef c\u1ea3nh: ch\u00ednh ph\u1ee7 thu\u00ea b\u00ean \u0111\u1ed9c l\u1eadp."}, {"id": "voc2-87", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The firm has managed to _____ a niche market that larger competitors have overlooked.", "options": ["carve out", "create", "develop", "build"], "answer": 0, "explanation": "\"Carve out a niche market\" = t\u1ea1o ra th\u1ecb tr\u01b0\u1eddng ng\u00e1ch ri\u00eang bi\u1ec7t. Idiom kinh doanh chu\u1ea9n: \"carve out a niche/position/role\". \"Create a niche\" informal h\u01a1n."}, {"id": "voc2-88", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The company's latest acquisition is expected to _____ its existing product portfolio significantly.", "options": ["strengthen", "bolster", "enhance", "expand"], "answer": 1, "explanation": "\"Bolster a portfolio/position/reputation\" = c\u1ee7ng c\u1ed1, t\u0103ng c\u01b0\u1eddng m\u1ea1nh m\u1ebd. \"Bolster\" c\u00f3 h\u00e0m \u00fd h\u1ed7 tr\u1ee3 c\u00e1i \u0111ang y\u1ebfu ho\u1eb7c c\u1ea7n th\u00eam s\u1ee9c m\u1ea1nh. T\u1eeb n\u00e2ng cao trong TOEIC financial news."}, {"id": "voc2-89", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "Despite strong headwinds, the firm managed to _____ profitability throughout the fiscal year.", "options": ["keep", "maintain", "sustain", "preserve"], "answer": 2, "explanation": "\"Sustain profitability\" = duy tr\u00ec kh\u1ea3 n\u0103ng sinh l\u1eddi b\u1ec1n v\u1eefng. \"Sustain\" nh\u1ea5n m\u1ea1nh kh\u1ea3 n\u0103ng duy tr\u00ec trong \u0111i\u1ec1u ki\u1ec7n kh\u00f3 kh\u0103n. Kh\u00e1c v\u1edbi \"maintain\" (duy tr\u00ec \u1ed5n \u0111\u1ecbnh)."}, {"id": "voc2-90", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The firm's board voted to _____ all non-core assets to focus on its primary business.", "options": ["divest", "sell off", "dispose of", "liquidate"], "answer": 0, "explanation": "\"Divest non-core assets\" = tho\u00e1i v\u1ed1n kh\u1ecfi t\u00e0i s\u1ea3n kh\u00f4ng c\u1ed1t l\u00f5i. Thu\u1eadt ng\u1eef M&A/finance n\u00e2ng cao. \"Liquidate\" = thanh l\u00fd (khi c\u00f4ng ty gi\u1ea3i th\u1ec3). \"Divest\" = c\u00f3 chi\u1ebfn l\u01b0\u1ee3c r\u00fat lui c\u00f3 k\u1ebf ho\u1ea1ch."}, {"id": "voc2-91", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The research team was able to _____ a direct link between employee satisfaction and productivity.", "options": ["prove", "establish", "confirm", "verify"], "answer": 1, "explanation": "\"Establish a link/connection/correlation\" = x\u00e1c l\u1eadp m\u1ed1i li\u00ean h\u1ec7. \"Establish\" m\u1ea1nh h\u01a1n \"prove\" trong v\u0103n b\u1ea3n nghi\u00ean c\u1ee9u h\u1ecdc thu\u1eadt/kinh doanh. \"Confirm\" = x\u00e1c nh\u1eadn \u0111i\u1ec1u \u0111\u00e3 bi\u1ebft."}, {"id": "voc2-92", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The board is under pressure to _____ the underperforming CEO before the next shareholder meeting.", "options": ["remove", "dismiss", "oust", "replace"], "answer": 2, "explanation": "\"Oust a CEO/leader\" = l\u1eadt \u0111\u1ed5, bu\u1ed9c t\u1eeb ch\u1ee9c (m\u1ea1nh, c\u00f3 h\u00e0m \u00fd \u00e1p l\u1ef1c t\u1eeb b\u00ean ngo\u00e0i). \"Dismiss\" = sa th\u1ea3i (quy\u1ebft \u0111\u1ecbnh c\u1ee7a c\u00f4ng ty). \"Oust\" xu\u1ea5t hi\u1ec7n trong b\u1ea3n tin kinh t\u1ebf TOEIC khi n\u00f3i v\u1ec1 \u00e1p l\u1ef1c c\u1ed5 \u0111\u00f4ng."}, {"id": "voc2-93", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The bank's strategy to _____ its exposure to high-risk markets proved successful during the downturn.", "options": ["minimize", "limit", "reduce", "hedge"], "answer": 3, "explanation": "\"Hedge exposure to risk\" = ph\u00f2ng ng\u1eeba r\u1ee7i ro. Thu\u1eadt ng\u1eef t\u00e0i ch\u00ednh n\u00e2ng cao: \"hedge + risk/exposure/bet\". \"Hedge\" c\u00f3 ngh\u0129a k\u1ef9 thu\u1eadt \u0111\u1eb7c bi\u1ec7t trong finance kh\u00e1c v\u1edbi \"reduce/minimize\"."}, {"id": "voc2-94", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The merger was expected to _____ significant synergies across the two companies' operations.", "options": ["yield", "generate", "produce", "create"], "answer": 0, "explanation": "\"Yield synergies/results/returns\" = mang l\u1ea1i (k\u1ebft qu\u1ea3). \"Yield\" nh\u1ea5n m\u1ea1nh k\u1ebft qu\u1ea3 thu \u0111\u01b0\u1ee3c t\u1eeb kho\u1ea3n \u0111\u1ea7u t\u01b0/ho\u1ea1t \u0111\u1ed9ng. T\u1eeb t\u00e0i ch\u00ednh cao c\u1ea5p trong TOEIC: \"yield + synergies/returns/profits\"."}, {"id": "voc2-95", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The firm was forced to _____ its expansion plans following a sharp decline in investor confidence.", "options": ["suspend", "shelve", "postpone", "abandon"], "answer": 1, "explanation": "\"Shelve plans/projects\" = \u0111\u1eb7t v\u00e0o ng\u0103n k\u1ec7, t\u1ea1m th\u1eddi h\u1ee7y b\u1ecf (kh\u00f4ng x\u00f3a ho\u00e0n to\u00e0n). \"Shelve\" = \u0111\u00ecnh l\u1ea1i c\u00f3 th\u1ec3 l\u1ea5y l\u1ea1i sau. \"Abandon\" = t\u1eeb b\u1ecf ho\u00e0n to\u00e0n. Hay g\u1eb7p trong TOEIC khi n\u00f3i v\u1ec1 k\u1ebf ho\u1ea1ch b\u1ecb ho\u00e3n v\u00f4 th\u1eddi h\u1ea1n."}, {"id": "voc2-96", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "Senior management was tasked with _____ the company's long-term digital transformation roadmap.", "options": ["heading", "leading", "spearheading", "managing"], "answer": 2, "explanation": "\"Spearhead an initiative/transformation\" = \u0111i \u0111\u1ea7u, d\u1eabn d\u1eaft (h\u00e0m \u00fd ch\u1ee7 \u0111\u1ed9ng v\u00e0 quy\u1ebft \u0111o\u00e1n). \"Spearhead\" = ng\u01b0\u1eddi/b\u1ed9 ph\u1eadn \u0111\u1ea7u ti\u00ean m\u1edf \u0111\u01b0\u1eddng. N\u00e2ng cao trong TOEIC strategy documents."}, {"id": "voc2-97", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The success of the pilot program has _____ the way for a nationwide rollout.", "options": ["made", "cleared", "opened", "paved"], "answer": 3, "explanation": "\"Pave the way for\" = m\u1edf \u0111\u01b0\u1eddng cho, t\u1ea1o \u0111i\u1ec1u ki\u1ec7n cho. Idiom c\u1ed1 \u0111\u1ecbnh quan tr\u1ecdng trong TOEIC: \"pave the way for + expansion/rollout/initiative\"."}, {"id": "voc2-98", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The whistleblower's report helped _____ to light serious irregularities in the procurement process.", "options": ["bring", "come", "shed", "draw"], "answer": 0, "explanation": "\"Bring to light\" = ph\u01a1i b\u00e0y, ti\u1ebft l\u1ed9. Phrasal verb idiom c\u1ed1 \u0111\u1ecbnh. \"Shed light on\" = l\u00e0m s\u00e1ng t\u1ecf (kh\u00e1c c\u1ea5u tr\u00fac). \"Bring to light + noun\" = ti\u1ebft l\u1ed9 \u0111i\u1ec1u b\u1ecb che gi\u1ea5u. T\u1eeb TOEIC Part 7 vocab level."}, {"id": "voc2-99", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The regulatory changes are expected to _____ a significant overhaul of existing compliance procedures.", "options": ["require", "necessitate", "demand", "call for"], "answer": 1, "explanation": "\"Necessitate a review/overhaul\" = \u0111\u00f2i h\u1ecfi b\u1eaft bu\u1ed9c ph\u1ea3i l\u00e0m (h\u00e0m \u00fd t\u1ea5t y\u1ebfu). \"Necessitate\" = b\u1eaft bu\u1ed9c ph\u1ea3i c\u00f3 v\u00ec ho\u00e0n c\u1ea3nh. T\u1eeb cao c\u1ea5p trong TOEIC regulatory/policy texts."}, {"id": "voc2-100", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The committee found it difficult to _____ the conflicting testimonies of the two witnesses.", "options": ["reconcile", "resolve", "address", "balance"], "answer": 0, "explanation": "\"Reconcile conflicting accounts/testimonies\" = dung h\u00f2a, l\u00e0m cho nh\u1ea5t qu\u00e1n hai \u0111i\u1ec1u tr\u00e1i nhau. \"Reconcile\" l\u00e0 t\u1eeb k\u1ef9 thu\u1eadt trong v\u0103n b\u1ea3n \u0111i\u1ec1u tra/k\u1ebf to\u00e1n TOEIC: \"reconcile accounts/statements/differences\"."}, {"id": "voc2-101", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The board voted to _____ the CEO's proposal to acquire a rival firm, citing excessive risk.", "options": ["reject", "turn down", "veto", "oppose"], "answer": 2, "explanation": "\"Veto a proposal\" = ph\u1ee7 quy\u1ebft (d\u00f9ng quy\u1ec1n ph\u1ee7 quy\u1ebft ch\u00ednh th\u1ee9c). \"Veto\" c\u00f3 ngh\u0129a \u0111\u1eb7c bi\u1ec7t: quy\u1ec1n ch\u00ednh th\u1ee9c c\u1ee7a m\u1ed9t ng\u01b0\u1eddi/nh\u00f3m \u0111\u1ec3 b\u00e1c b\u1ecf. Kh\u00e1c v\u1edbi \"reject\" (t\u1eeb ch\u1ed1i chung)."}, {"id": "voc2-102", "part": 5, "type": "vocabulary", "difficulty": "hard", "question": "The rapid growth of the fintech sector has _____ traditional banking models.", "options": ["challenged", "affected", "disrupted", "changed"], "answer": 2, "explanation": "\"Disrupted traditional models\" = ph\u00e1 v\u1ee1 m\u00f4 h\u00ecnh truy\u1ec1n th\u1ed1ng (\u00fd ngh\u0129a c\u00f4ng ngh\u1ec7/kinh doanh). \"Disrupt\" l\u00e0 t\u1eeb chuy\u00ean bi\u1ec7t trong startup/tech TOEIC, m\u1ea1nh h\u01a1n \"challenge\" hay \"change\"."}, {"id": "prep2-01", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The HR department sent a reminder _____ all employees about the upcoming health check.", "options": ["at", "for", "toward", "to"], "answer": 3, "explanation": "\"Send a reminder to all employees\" = g\u1eedi nh\u1eafc nh\u1edf \u0111\u1ebfn. \"To\" ch\u1ec9 \u0111\u1ed1i t\u01b0\u1ee3ng nh\u1eadn. \"For\" sai (for all = d\u00e0nh cho t\u1ea5t c\u1ea3 nh\u01b0ng kh\u00f4ng d\u00f9ng sau \"reminder sent\")."}, {"id": "prep2-02", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The safety officer conducted an inspection _____ the entire factory floor.", "options": ["at", "on", "of", "in"], "answer": 2, "explanation": "\"Inspection of the factory floor\" = ki\u1ec3m tra khu v\u1ef1c s\u00e0n nh\u00e0 m\u00e1y. \"Inspection of + place/area\" l\u00e0 collocation chu\u1ea9n. \"On/in the factory floor\" sau \"inspection\" kh\u00f4ng t\u1ef1 nhi\u00ean."}, {"id": "prep2-03", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "All participants must sign in _____ the reception desk upon arrival.", "options": ["in", "at", "by", "on"], "answer": 1, "explanation": "\"Sign in at the reception desk\" = \u0111\u0103ng k\u00fd t\u1ea1i b\u00e0n l\u1ec5 t\u00e2n. \"At\" d\u00f9ng cho \u0111\u1ecba \u0111i\u1ec3m c\u1ee5 th\u1ec3 (desk, counter, door). \"In the reception desk\" sai."}, {"id": "prep2-04", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The conference room is reserved _____ the marketing team every Monday morning.", "options": ["for", "by", "to", "of"], "answer": 0, "explanation": "\"Reserved for the marketing team\" = d\u00e0nh ri\u00eang cho. \"For\" ch\u1ec9 m\u1ee5c \u0111\u00edch/\u0111\u1ed1i t\u01b0\u1ee3ng \u0111\u01b0\u1ee3c d\u00e0nh cho. \"By the marketing team\" = b\u1edfi \u0111\u1ed9i marketing (ng\u01b0\u1eddi \u0111\u1eb7t ph\u00f2ng)."}, {"id": "prep2-05", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The client expressed concern _____ the project's delayed timeline.", "options": ["with", "for", "over", "about"], "answer": 3, "explanation": "\"Express concern about\" = b\u00e0y t\u1ecf lo ng\u1ea1i v\u1ec1. Collocation: \"concern about/over + issue\". \"About\" v\u00e0 \"over\" \u0111\u1ec1u \u0111\u00fang nh\u01b0ng \"about\" ph\u1ed5 bi\u1ebfn h\u01a1n sau \"express concern\"."}, {"id": "prep2-06", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The invoice is payable _____ 30 days of the service date.", "options": ["by", "in", "within", "during"], "answer": 2, "explanation": "\"Payable within 30 days\" = ph\u1ea3i tr\u1ea3 trong v\u00f2ng 30 ng\u00e0y. \"Within\" = trong kho\u1ea3ng th\u1eddi gian gi\u1edbi h\u1ea1n. \"By 30 days\" nghe kh\u00f4ng t\u1ef1 nhi\u00ean \u2014 \"by\" c\u1ea7n th\u1eddi \u0111i\u1ec3m c\u1ee5 th\u1ec3."}, {"id": "prep2-07", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The report will be distributed _____ all department heads before the meeting.", "options": ["among", "to", "for", "between"], "answer": 1, "explanation": "\"Distributed to all department heads\" = ph\u00e2n ph\u00e1t \u0111\u1ebfn t\u1ea5t c\u1ea3. \"To\" ch\u1ec9 \u0111\u1ed1i t\u01b0\u1ee3ng nh\u1eadn. \"Among\" th\u01b0\u1eddng d\u00f9ng khi nh\u1ea5n m\u1ea1nh chia s\u1ebb trong nh\u00f3m (among participants), nh\u01b0ng \"distributed to\" chu\u1ea9n h\u01a1n."}, {"id": "prep2-08", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The company is _____ the process of relocating its headquarters to a new building.", "options": ["in", "on", "at", "under"], "answer": 0, "explanation": "\"In the process of + V-ing\" = \u0111ang trong qu\u00e1 tr\u00ecnh. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"in the process of doing something\". \"Under\" c\u0169ng d\u00f9ng: \"under construction/review\" nh\u01b0ng kh\u00f4ng ph\u00f9 h\u1ee3p sau \"company is ___ the process\"."}, {"id": "prep2-09", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The salary for this position is _____ the higher end of the market rate.", "options": ["toward", "on", "in", "at"], "answer": 3, "explanation": "\"At the higher end\" = \u1edf m\u1ee9c cao h\u01a1n trong kho\u1ea3ng. \"At the high/low/upper/lower end\" = \u1edf \u0111\u1ea7u cao/th\u1ea5p. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"at the + adj + end of the range/spectrum\"."}, {"id": "prep2-10", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The office will be closed _____ the national holiday next Monday.", "options": ["for", "during", "on", "in"], "answer": 2, "explanation": "\"Closed on the national holiday\" = \u0111\u00f3ng c\u1eeda v\u00e0o ng\u00e0y l\u1ec5 qu\u1ed1c gia. \"On + day/holiday\" = quy t\u1eafc gi\u1edbi t\u1eeb th\u1eddi gian c\u01a1 b\u1ea3n. \"For the holiday\" = cho k\u1ef3 ngh\u1ec9 l\u1ec5 (kh\u00f4ng ph\u00f9 h\u1ee3p v\u1edbi \"closed\")."}, {"id": "prep2-11", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The training is mandatory _____ all employees hired after January 1.", "options": ["for", "to", "of", "with"], "answer": 0, "explanation": "\"Mandatory for all employees\" = b\u1eaft bu\u1ed9c \u0111\u1ed1i v\u1edbi. \"Mandatory for + group\" l\u00e0 c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh. \"Mandatory to\" kh\u00f4ng t\u1ef1 nhi\u00ean trong ng\u1eef c\u1ea3nh n\u00e0y."}, {"id": "prep2-12", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "Mr. Kim has been _____ charge of the sales department for the past two years.", "options": ["of", "on", "at", "in"], "answer": 3, "explanation": "\"In charge of\" = ph\u1ee5 tr\u00e1ch, ch\u1ecbu tr\u00e1ch nhi\u1ec7m. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"be in charge of + department/project\". Ph\u00e2n bi\u1ec7t: \"responsible for\" (c\u0169ng \u0111\u00fang nh\u01b0ng \"in charge of\" nh\u1ea5n m\u1ea1nh v\u1ecb tr\u00ed l\u00e3nh \u0111\u1ea1o)."}, {"id": "prep2-13", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The decision was made _____ consultation with all major stakeholders.", "options": ["through", "after", "in", "by"], "answer": 2, "explanation": "\"In consultation with\" = sau khi tham v\u1ea5n v\u1edbi. C\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh: \"in consultation/agreement/partnership with + parties\". \"After consultation\" c\u0169ng \u0111\u00fang nh\u01b0ng \"in\" l\u00e0 collocation ch\u00ednh th\u1ee9c h\u01a1n."}, {"id": "prep2-14", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "Please be aware that the system will be offline _____ maintenance tonight.", "options": ["during", "for", "under", "on"], "answer": 1, "explanation": "\"Offline for maintenance\" = ngo\u1ea1i tuy\u1ebfn \u0111\u1ec3 b\u1ea3o tr\u00ec. \"For maintenance\" = m\u1ee5c \u0111\u00edch. \"Under maintenance\" c\u0169ng \u0111\u00fang. \"For\" t\u1ef1 nhi\u00ean nh\u1ea5t sau \"offline\" trong th\u00f4ng b\u00e1o k\u1ef9 thu\u1eadt TOEIC."}, {"id": "prep2-15", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The new branch is located _____ walking distance of the train station.", "options": ["within", "in", "at", "near"], "answer": 0, "explanation": "\"Within walking distance\" = trong kho\u1ea3ng c\u00e1ch \u0111i b\u1ed9. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"within + walking/driving/commuting distance of\". \"In walking distance\" kh\u00f4ng chu\u1ea9n."}, {"id": "prep2-16", "part": 5, "type": "prepositions", "difficulty": "easy", "question": "The manager is currently _____ a business trip and will return on Thursday.", "options": ["for", "in", "at", "on"], "answer": 3, "explanation": "\"On a business trip\" = \u0111ang \u0111i c\u00f4ng t\u00e1c. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"on a trip/tour/mission/leave\". \"On business\" = v\u00ec c\u00f4ng vi\u1ec7c. \"In a business trip\" sai."}, {"id": "prep2-17", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The board voted _____ favor of the proposed changes to the pension scheme.", "options": ["for", "on", "in", "at"], "answer": 2, "explanation": "\"Vote in favor of\" = b\u1ecf phi\u1ebfu \u1ee7ng h\u1ed9. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"in favor of / in favour of\". \"Vote for\" = b\u1ea7u ch\u1ecdn (cho ng\u01b0\u1eddi/v\u1eadt c\u1ee5 th\u1ec3). \"In favor of\" = \u1ee7ng h\u1ed9 \u0111\u1ec1 xu\u1ea5t/k\u1ebf ho\u1ea1ch."}, {"id": "prep2-18", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The company is _____ risk of losing its operating license if the violations are not corrected.", "options": ["in", "at", "on", "under"], "answer": 1, "explanation": "\"At risk of\" = c\u00f3 nguy c\u01a1. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"be at risk of + V-ing/noun\". \"In risk of\" sai. \"Under risk\" kh\u00f4ng t\u1ef1 nhi\u00ean. \"At risk\" l\u00e0 collocation chu\u1ea9n."}, {"id": "prep2-19", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "All claims must be submitted _____ accordance with the company's reimbursement policy.", "options": ["in", "on", "by", "with"], "answer": 0, "explanation": "\"In accordance with a policy/rule\" = tu\u00e2n theo. C\u1ee5m gi\u1edbi t\u1eeb trang tr\u1ecdng 3 t\u1eeb: \"in accordance with\". Kh\u00f4ng th\u1ec3 d\u00f9ng \"on/by/with accordance\"."}, {"id": "prep2-20", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The factory operates _____ full capacity during the peak holiday season.", "options": ["on", "in", "at", "to"], "answer": 2, "explanation": "\"Operate at full capacity\" = ho\u1ea1t \u0111\u1ed9ng h\u1ebft c\u00f4ng su\u1ea5t. \"At + capacity/level/speed\" = \u1edf m\u1ee9c. \"In full capacity\" sai. \"At full capacity\" l\u00e0 collocation s\u1ea3n xu\u1ea5t chu\u1ea9n trong TOEIC."}, {"id": "prep2-21", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The two companies are _____ talks about a potential strategic partnership.", "options": ["at", "in", "on", "under"], "answer": 1, "explanation": "\"In talks about\" = \u0111ang th\u1ea3o lu\u1eadn/\u0111\u00e0m ph\u00e1n v\u1ec1. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"be in talks/negotiations/discussions about/with\". \"Under talks\" sai. \"In talks\" ph\u1ed5 bi\u1ebfn trong b\u1ea3n tin kinh doanh TOEIC."}, {"id": "prep2-22", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The firm's outstanding performance can be attributed _____ its strong leadership team.", "options": ["to", "for", "with", "by"], "answer": 0, "explanation": "\"Attributed to\" = quy cho, do. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"be attributed to + cause\". \"Attribute + performance + to + factor\" = cho r\u1eb1ng k\u1ebft qu\u1ea3 l\u00e0 do. \"Attributed for\" sai."}, {"id": "prep2-23", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The final report must be submitted no later _____ 5 p.m. on the last working day of the month.", "options": ["to", "then", "as", "than"], "answer": 3, "explanation": "\"No later than 5 p.m.\" = kh\u00f4ng mu\u1ed9n h\u01a1n 5 gi\u1edd. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"no later than + time/date\". \"No later then\" sai ng\u1eef ph\u00e1p. \"Than\" sau comparatives."}, {"id": "prep2-24", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "Please refrain _____ using personal mobile phones during client meetings.", "options": ["at", "in", "from", "of"], "answer": 2, "explanation": "\"Refrain from + V-ing\" = ki\u00eang, tr\u00e1nh. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"refrain from doing\". \"Refrain in/at\" sai. \"Refrain from\" l\u00e0 collocation quan tr\u1ecdng trong th\u00f4ng b\u00e1o v\u0103n ph\u00f2ng TOEIC."}, {"id": "prep2-25", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The marketing budget was cut _____ half to accommodate unexpected operating costs.", "options": ["in", "by", "to", "at"], "answer": 1, "explanation": "\"Cut by half\" = c\u1eaft gi\u1ea3m \u0111i m\u1ed9t n\u1eeda. \"By + fraction/percentage\" = ch\u1ec9 m\u1ee9c \u0111\u1ed9 thay \u0111\u1ed5i. Ph\u00e2n bi\u1ec7t: \"cut by half\" (gi\u1ea3m \u0111i 50%) vs \"cut to half\" (gi\u1ea3m xu\u1ed1ng c\u00f2n 50%) \u2014 \"by half\" th\u01b0\u1eddng g\u1eb7p h\u01a1n."}, {"id": "prep2-26", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The report was compiled _____ the request of the board of directors.", "options": ["at", "on", "by", "in"], "answer": 0, "explanation": "\"Compiled at the request of\" = \u0111\u01b0\u1ee3c bi\u00ean so\u1ea1n theo y\u00eau c\u1ea7u c\u1ee7a. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"at the request/suggestion/recommendation of\". \"On request\" = khi c\u00f3 y\u00eau c\u1ea7u (chung)."}, {"id": "prep2-27", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The contractor is running behind schedule _____ account of delays in material delivery.", "options": ["by", "for", "due", "on"], "answer": 3, "explanation": "\"On account of\" = v\u00ec l\u00fd do. C\u1ee5m gi\u1edbi t\u1eeb 3 t\u1eeb: \"on account of + noun\" = because of. \"Due account\" sai. \"Due to\" = c\u0169ng \u0111\u00fang nh\u01b0ng c\u00e2u \u0111\u00e3 c\u00f3 \"due\" sau g\u1ea1ch tr\u1ed1ng."}, {"id": "prep2-28", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The lease agreement is _____ effect for a period of three years from signing.", "options": ["at", "on", "in", "under"], "answer": 2, "explanation": "\"In effect\" = c\u00f3 hi\u1ec7u l\u1ef1c. C\u1ee5m: \"in effect for + period\" = c\u00f3 hi\u1ec7u l\u1ef1c trong. Ph\u00e2n bi\u1ec7t: \"come into effect\" (b\u1eaft \u0111\u1ea7u c\u00f3 hi\u1ec7u l\u1ef1c) vs \"in effect\" (\u0111ang c\u00f3 hi\u1ec7u l\u1ef1c)."}, {"id": "prep2-29", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The shareholders expressed dissatisfaction _____ the company's response to the crisis.", "options": ["about", "with", "at", "over"], "answer": 1, "explanation": "\"Dissatisfaction with\" = s\u1ef1 kh\u00f4ng h\u00e0i l\u00f2ng v\u1edbi. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"dissatisfaction with + response/performance\". \"Dissatisfaction about/at/over\" c\u0169ng c\u00f3 th\u1ec3 g\u1eb7p nh\u01b0ng \"with\" chu\u1ea9n nh\u1ea5t."}, {"id": "prep2-30", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The team completed the project well _____ the allotted budget.", "options": ["inside", "under", "below", "within"], "answer": 3, "explanation": "\"Well within the budget\" = c\u00e1ch xa trong ph\u1ea1m vi ng\u00e2n s\u00e1ch. \"Within budget\" = trong ng\u00e2n s\u00e1ch. \"Under budget\" = d\u01b0\u1edbi ng\u00e2n s\u00e1ch (c\u0169ng \u0111\u00fang). \"Well within\" m\u1ea1nh h\u01a1n, nh\u1ea5n m\u1ea1nh c\u00f2n d\u01b0 nhi\u1ec1u."}, {"id": "prep2-31", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The board made its decision _____ the basis of the auditor's recommendations.", "options": ["at", "in", "on", "by"], "answer": 2, "explanation": "\"On the basis of\" = d\u1ef1a tr\u00ean c\u01a1 s\u1edf. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"on the basis of + evidence/recommendation\". \"In the basis of\" sai. \"Based on\" l\u00e0 c\u1ee5m thay th\u1ebf \u0111\u00fang."}, {"id": "prep2-32", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The company encourages employees to raise concerns _____ going through formal channels.", "options": ["before", "prior to", "without", "rather than"], "answer": 3, "explanation": "\"Rather than going through formal channels\" = thay v\u00ec \u0111i qua k\u00eanh ch\u00ednh th\u1ee9c. \"Rather than\" l\u00e0 c\u1ee5m so s\u00e1nh: \"do X rather than Y\". \"Before\" = tr\u01b0\u1edbc khi (kh\u00e1c ngh\u0129a)."}, {"id": "prep2-33", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The proposal is contingent _____ receiving final approval from the board.", "options": ["on", "upon", "for", "of"], "answer": 0, "explanation": "\"Contingent on/upon\" = ph\u1ee5 thu\u1ed9c v\u00e0o, c\u00f3 \u0111i\u1ec1u ki\u1ec7n. C\u1ea3 \"on\" v\u00e0 \"upon\" \u0111\u1ec1u \u0111\u00fang nh\u01b0ng \"contingent on\" ph\u1ed5 bi\u1ebfn h\u01a1n trong v\u0103n b\u1ea3n kinh doanh TOEIC. \"Contingent for\" sai."}, {"id": "prep2-34", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new policy applies _____ full-time and part-time employees alike.", "options": ["with", "for", "at", "to"], "answer": 3, "explanation": "\"Applies to both groups\" = \u00e1p d\u1ee5ng cho. \"Apply to + target group\" = c\u1ee5m c\u1ed1 \u0111\u1ecbnh ph\u00e1p l\u00fd/HR. \"Apply for\" = xin/\u0111\u0103ng k\u00fd. \"Applies to...alike\" = \u00e1p d\u1ee5ng cho c\u1ea3 hai."}, {"id": "prep2-35", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The quarterly figures came _____ slightly short of the forecast provided by analysts.", "options": ["up", "out", "in", "down"], "answer": 2, "explanation": "\"Came in short of\" = \u0111\u1ea1t \u0111\u01b0\u1ee3c nh\u01b0ng kh\u00f4ng \u0111\u1ee7. \"Come in short of\" = k\u1ebft qu\u1ea3 th\u1ea5p h\u01a1n d\u1ef1 ki\u1ebfn. Phrasal verb: \"come in + adj + of + benchmark\". \"Fell short of\" c\u0169ng \u0111\u00fang."}, {"id": "prep2-36", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The revised estimate puts the total project cost _____ the $2 million mark.", "options": ["over", "above", "beyond", "past"], "answer": 1, "explanation": "\"Cost above the mark/threshold\" = v\u01b0\u1ee3t qu\u00e1 m\u1ee9c. \"Above the mark\" = v\u01b0\u1ee3t qua m\u1ed1c c\u1ee5 th\u1ec3. C\u1ea3 \"above\" v\u00e0 \"over\" \u0111\u00fang, nh\u01b0ng \"above the mark\" l\u00e0 collocation t\u1ef1 nhi\u00ean h\u01a1n."}, {"id": "prep2-37", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The company is looking _____ ways to reduce its carbon footprint before year end.", "options": ["for", "into", "at", "toward"], "answer": 0, "explanation": "\"Looking for ways\" = t\u00ecm ki\u1ebfm c\u00e1c c\u00e1ch. \"Look for\" = t\u00ecm ki\u1ebfm. \"Look into\" = \u0111i\u1ec1u tra, xem x\u00e9t k\u1ef9 h\u01a1n. \"Looking for ways to do something\" l\u00e0 c\u1ee5m ph\u1ed5 bi\u1ebfn trong TOEIC."}, {"id": "prep2-38", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "All confidential documents must be stored _____ a secure, locked cabinet.", "options": ["within", "at", "inside", "in"], "answer": 3, "explanation": "\"Stored in a cabinet\" = c\u1ea5t trong t\u1ee7. \"In\" d\u00f9ng cho kh\u00f4ng gian ch\u1ee9a \u0111\u1ef1ng (container). \"Inside\" c\u0169ng \u0111\u00fang nh\u01b0ng \"in\" ng\u1eafn g\u1ecdn v\u00e0 chu\u1ea9n h\u01a1n trong v\u0103n b\u1ea3n ch\u00ednh th\u1ee9c TOEIC."}, {"id": "prep2-39", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new branch will cater primarily _____ clients in the financial services sector.", "options": ["toward", "for", "to", "at"], "answer": 2, "explanation": "\"Cater to clients/needs\" = ph\u1ee5c v\u1ee5, \u0111\u00e1p \u1ee9ng nhu c\u1ea7u. \"Cater to\" l\u00e0 collocation chu\u1ea9n trong TOEIC: \"cater to + target group/needs/demand\". \"Cater for\" (British) c\u0169ng \u0111\u00fang."}, {"id": "prep2-40", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The firm has been _____ the forefront of innovation in clean energy technology.", "options": ["at", "in", "on", "to"], "answer": 0, "explanation": "\"At the forefront of\" = \u0111i \u0111\u1ea7u trong. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"be at the forefront of + field/innovation\". \"In the forefront\" \u00edt ph\u1ed5 bi\u1ebfn. \"At the forefront\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t."}, {"id": "prep2-41", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "Please ensure that all deliverables are submitted _____ accordance with the project timeline.", "options": ["within", "on", "by", "in"], "answer": 3, "explanation": "\"Submitted in accordance with the timeline\" = n\u1ed9p theo \u0111\u00fang ti\u1ebfn \u0111\u1ed9. \"In accordance with\" = tu\u00e2n theo (quy \u0111\u1ecbnh/k\u1ebf ho\u1ea1ch). Ph\u00e2n bi\u1ec7t: \"in accordance with\" (tu\u00e2n th\u1ee7) vs \"within the timeline\" (\u0111\u00fang h\u1ea1n)."}, {"id": "prep2-42", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The cost of the renovation was _____ line with the initial estimate provided.", "options": ["at", "on", "in", "by"], "answer": 2, "explanation": "\"In line with the estimate\" = ph\u00f9 h\u1ee3p v\u1edbi, nh\u1ea5t qu\u00e1n v\u1edbi. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"in line with + expectation/estimate/policy\". \"On line with\" sai."}, {"id": "prep2-43", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The training workshop is open _____ all employees regardless of their seniority.", "options": ["for", "to", "at", "with"], "answer": 1, "explanation": "\"Open to all employees\" = m\u1edf cho t\u1ea5t c\u1ea3. \"Open to + group\" = c\u00f3 th\u1ec3 tham gia. \"Open for registration\" = m\u1edf \u0111\u1ec3 \u0111\u0103ng k\u00fd. \"Open to\" d\u00f9ng khi n\u00f3i v\u1ec1 ai \u0111\u01b0\u1ee3c ph\u00e9p tham gia."}, {"id": "prep2-44", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The CEO is scheduled to meet _____ the lead investor next Tuesday morning.", "options": ["with", "to", "for", "by"], "answer": 0, "explanation": "\"Meet with someone\" = g\u1eb7p g\u1ee1 v\u1edbi ai \u0111\u00f3 (American English). \"Meet with\" nh\u1ea5n m\u1ea1nh cu\u1ed9c h\u1ecdp c\u00f3 k\u1ebf ho\u1ea1ch. \"Meet + person\" (kh\u00f4ng c\u00f3 \"with\") c\u0169ng \u0111\u00fang nh\u01b0ng \"meet with\" chu\u1ea9n trong l\u1ecbch tr\u00ecnh kinh doanh."}, {"id": "prep2-45", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The company's shares fell _____ an all-time low following the product recall announcement.", "options": ["down", "at", "into", "to"], "answer": 3, "explanation": "\"Fell to an all-time low\" = gi\u1ea3m xu\u1ed1ng m\u1ee9c th\u1ea5p nh\u1ea5t m\u1ecdi th\u1eddi \u0111\u1ea1i. \"Fall to + price/level\" = gi\u1ea3m \u0111\u1ebfn m\u1ee9c. \"At an all-time low\" = \u0111ang \u1edf m\u1ee9c th\u1ea5p nh\u1ea5t (tr\u1ea1ng th\u00e1i hi\u1ec7n t\u1ea1i)."}, {"id": "prep2-46", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The data breach put sensitive customer information _____ risk.", "options": ["on", "in", "at", "under"], "answer": 2, "explanation": "\"Put information at risk\" = \u0111\u1eb7t th\u00f4ng tin v\u00e0o nguy hi\u1ec3m. \"At risk\" = trong t\u00ecnh tr\u1ea1ng nguy hi\u1ec3m. C\u1ee5m: \"put + noun + at risk\" = g\u00e2y ra nguy c\u01a1 cho. \"Under risk\" kh\u00f4ng t\u1ef1 nhi\u00ean."}, {"id": "prep2-47", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "Staff members are reminded to log out _____ the system when leaving their workstations.", "options": ["of", "out of", "from", "off"], "answer": 2, "explanation": "\"Log out from the system\" = \u0111\u0103ng xu\u1ea5t kh\u1ecfi h\u1ec7 th\u1ed1ng. \"Log out from/of\" \u0111\u1ec1u \u0111\u00fang. \"Log off the system\" c\u0169ng ph\u1ed5 bi\u1ebfn. \"Log out from\" chu\u1ea9n h\u01a1n trong ng\u1eef c\u1ea3nh TOEIC IT."}, {"id": "prep2-48", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The HR director has been tasked _____ developing a new employee wellness program.", "options": ["with", "for", "to", "of"], "answer": 0, "explanation": "\"Tasked with + V-ing\" = \u0111\u01b0\u1ee3c giao nhi\u1ec7m v\u1ee5. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"be tasked with doing something\". \"Tasked for/to\" sai. \"Tasked with\" l\u00e0 collocation HR chu\u1ea9n trong TOEIC."}, {"id": "prep2-49", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The workshop will provide participants _____ practical tools for effective time management.", "options": ["to", "for", "of", "with"], "answer": 3, "explanation": "\"Provide participants with tools\" = cung c\u1ea5p cho ng\u01b0\u1eddi tham gia c\u00f4ng c\u1ee5. C\u1ea5u tr\u00fac: \"provide + person + with + thing\" = d\u1ea1ng t\u00e2n ng\u1eef k\u00e9p. \"Provide tools for participants\" c\u0169ng \u0111\u00fang nh\u01b0ng kh\u00e1c c\u1ea5u tr\u00fac."}, {"id": "prep2-50", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The firm's new headquarters is situated _____ the heart of the financial district.", "options": ["at", "in", "within", "inside"], "answer": 1, "explanation": "\"Situated in the heart of\" = t\u1ecda l\u1ea1c \u1edf trung t\u00e2m c\u1ee7a. \"In the heart of\" = \u1edf trung t\u00e2m. \"At the heart of\" = l\u00e0 tr\u1ecdng t\u00e2m c\u1ee7a (ngh\u0129a tr\u1eebu t\u01b0\u1ee3ng h\u01a1n). \"Situated in\" chu\u1ea9n nh\u1ea5t."}, {"id": "prep2-51", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The legal team will review the contract _____ detail before the signing ceremony.", "options": ["in", "with", "at", "by"], "answer": 0, "explanation": "\"Review in detail\" = xem x\u00e9t chi ti\u1ebft. \"In detail\" = m\u1ed9t c\u00e1ch chi ti\u1ebft. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"examine/review/discuss + in detail\". \"With detail\" kh\u00f4ng t\u1ef1 nhi\u00ean."}, {"id": "prep2-52", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new packaging complies _____ all international safety standards.", "options": ["for", "to", "by", "with"], "answer": 3, "explanation": "\"Comply with standards/regulations\" = tu\u00e2n th\u1ee7. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"comply with + rule/standard/requirement\". \"Comply to\" sai. M\u1ed9t trong nh\u1eefng collocations quan tr\u1ecdng nh\u1ea5t trong TOEIC."}, {"id": "prep2-53", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The CEO is committed _____ ensuring all employees have equal growth opportunities.", "options": ["in", "for", "to", "toward"], "answer": 2, "explanation": "\"Committed to + V-ing/noun\" = cam k\u1ebft. \"Committed to ensuring\" \u2014 \"to\" l\u00e0 gi\u1edbi t\u1eeb \u2192 V-ing. B\u1eaby: kh\u00f4ng d\u00f9ng to-infinitive sau \"committed to\". C\u1ee5m c\u1ed1 \u0111\u1ecbnh quan tr\u1ecdng."}, {"id": "prep2-54", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The feedback gathered _____ the pilot program will be used to refine the final product.", "options": ["in", "from", "during", "through"], "answer": 1, "explanation": "\"Feedback gathered from the program\" = ph\u1ea3n h\u1ed3i thu th\u1eadp t\u1eeb ch\u01b0\u01a1ng tr\u00ecnh. \"From + source\" = ngu\u1ed3n g\u1ed1c. \"Gathered from\" = \u0111\u01b0\u1ee3c thu th\u1eadp t\u1eeb. \"During the program\" = trong su\u1ed1t ch\u01b0\u01a1ng tr\u00ecnh (th\u1eddi gian)."}, {"id": "prep2-55", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The efficiency gains achieved _____ the new system justify the initial investment.", "options": ["through", "with", "by", "from"], "answer": 0, "explanation": "\"Achieved through the new system\" = \u0111\u1ea1t \u0111\u01b0\u1ee3c th\u00f4ng qua/nh\u1edd v\u00e0o. \"Through\" = ph\u01b0\u01a1ng ti\u1ec7n/ph\u01b0\u01a1ng ph\u00e1p. \"Through\" ph\u00f9 h\u1ee3p nh\u1ea5t khi n\u00f3i v\u1ec1 c\u00e1ch th\u1ee9c \u0111\u1ea1t \u0111\u01b0\u1ee3c k\u1ebft qu\u1ea3."}, {"id": "prep2-56", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The supervisor is _____ vacation this week and will be back in the office on Monday.", "options": ["for", "in", "at", "on"], "answer": 3, "explanation": "\"On vacation\" = \u0111ang ngh\u1ec9 ph\u00e9p. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"on vacation/leave/a trip/business\". \"In vacation\" sai. \"For vacation\" kh\u00f4ng t\u1ef1 nhi\u00ean trong ng\u1eef c\u1ea3nh n\u00e0y."}, {"id": "prep2-57", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The contract renewal is subject _____ the approval of both parties' legal teams.", "options": ["of", "for", "to", "by"], "answer": 2, "explanation": "\"Subject to approval\" = ph\u1ee5 thu\u1ed9c v\u00e0o s\u1ef1 ch\u1ea5p thu\u1eadn. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"subject to + condition/approval/availability\". \"Subject for\" sai."}, {"id": "prep2-58", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The annual report was prepared _____ collaboration with the firm's external auditors.", "options": ["with", "in", "by", "through"], "answer": 1, "explanation": "\"In collaboration with\" = ph\u1ed1i h\u1ee3p v\u1edbi, c\u1ed9ng t\u00e1c c\u00f9ng. C\u1ee5m c\u1ed1 \u0111\u1ecbnh 3 t\u1eeb: \"in collaboration/cooperation/partnership with\". \"With collaboration\" sai."}, {"id": "prep2-59", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The company's market share has grown _____ a steady pace over the last three years.", "options": ["at", "in", "on", "with"], "answer": 0, "explanation": "\"Grown at a steady pace\" = t\u0103ng tr\u01b0\u1edfng v\u1edbi t\u1ed1c \u0111\u1ed9 \u1ed5n \u0111\u1ecbnh. \"At + pace/rate/speed\" = \u1edf t\u1ed1c \u0111\u1ed9. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"grow/increase/decline at a + adj + pace/rate\"."}, {"id": "prep2-60", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The company will release its earnings report _____ line with the original schedule.", "options": ["as per", "on", "in", "according"], "answer": 2, "explanation": "\"In line with the schedule\" = theo \u0111\u00fang k\u1ebf ho\u1ea1ch. \"In line with\" = nh\u1ea5t qu\u00e1n v\u1edbi, \u0111\u00fang theo. Ph\u00e2n bi\u1ec7t: \"in line with\" (ph\u00f9 h\u1ee3p v\u1edbi k\u1ebf ho\u1ea1ch) vs \"on schedule\" (\u0111\u00fang ti\u1ebfn \u0111\u1ed9)."}, {"id": "prep2-61", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The firm has grown _____ strength to strength since the merger was completed.", "options": ["in", "from", "with", "by"], "answer": 1, "explanation": "\"Grow from strength to strength\" = ng\u00e0y c\u00e0ng m\u1ea1nh h\u01a1n. Idiom c\u1ed1 \u0111\u1ecbnh: \"go/grow from strength to strength\". C\u1ee5m kh\u00f4ng th\u1ec3 thay \"from\" b\u1eb1ng gi\u1edbi t\u1eeb kh\u00e1c."}, {"id": "prep2-62", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The production manager is _____ the process of reviewing all quality control procedures.", "options": ["in", "on", "at", "under"], "answer": 0, "explanation": "\"In the process of + V-ing\" = \u0111ang trong qu\u00e1 tr\u00ecnh. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"be in the process of doing\". \"Under the process\" sai. \"In the process of\" l\u00e0 c\u1ee5m ph\u1ed5 bi\u1ebfn trong TOEIC khi m\u00f4 t\u1ea3 ho\u1ea1t \u0111\u1ed9ng \u0111ang di\u1ec5n ra."}, {"id": "prep2-63", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "Employees are prohibited _____ using the company's equipment for personal purposes.", "options": ["of", "in", "at", "from"], "answer": 3, "explanation": "\"Prohibited from + V-ing\" = b\u1ecb c\u1ea5m l\u00e0m g\u00ec. C\u1ea5u tr\u00fac: \"be prohibited/banned/barred + from + V-ing\". \"Prohibited in\" sai. T\u01b0\u01a1ng t\u1ef1 \"refrain from / prevent from\"."}, {"id": "prep2-64", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The proposal was well _____ the scope of the original project brief.", "options": ["in", "inside", "within", "under"], "answer": 2, "explanation": "\"Well within the scope\" = ho\u00e0n to\u00e0n trong ph\u1ea1m vi. \"Within the scope of\" = trong ph\u1ea1m vi. \"Well within\" = c\u00f2n c\u00e1ch xa gi\u1edbi h\u1ea1n (nh\u1ea5n m\u1ea1nh). \"Inside the scope\" kh\u00f4ng t\u1ef1 nhi\u00ean."}, {"id": "prep2-65", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The new regulation will affect companies _____ both the public and private sectors.", "options": ["across", "from", "of", "in"], "answer": 0, "explanation": "\"Companies across both sectors\" = c\u00e1c c\u00f4ng ty trong to\u00e0n b\u1ed9 c\u1ea3 hai khu v\u1ef1c. \"Across\" nh\u1ea5n m\u1ea1nh to\u00e0n b\u1ed9 ph\u1ea1m vi. \"Companies in both sectors\" c\u0169ng \u0111\u00fang. \"Across\" sinh \u0111\u1ed9ng h\u01a1n khi bao qu\u00e1t c\u1ea3 hai ph\u00eda."}, {"id": "prep2-66", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The sales team is confident _____ achieving the Q4 targets despite market volatility.", "options": ["of", "about", "in", "at"], "answer": 0, "explanation": "\"Confident of achieving\" = t\u1ef1 tin s\u1ebd \u0111\u1ea1t \u0111\u01b0\u1ee3c. C\u1ee5m: \"confident of + V-ing\" = tin ch\u1eafc \u0111\u1ea1t \u0111\u01b0\u1ee3c (k\u1ebft qu\u1ea3). \"Confident about\" = t\u1ef1 tin v\u1ec1 (ch\u1ee7 \u0111\u1ec1 r\u1ed9ng h\u01a1n). \"Confident of\" chu\u1ea9n h\u01a1n khi n\u00f3i v\u1ec1 k\u1ebft qu\u1ea3 c\u1ee5 th\u1ec3."}, {"id": "prep2-67", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The finance team works _____ close collaboration with the legal department on all major contracts.", "options": ["by", "on", "at", "in"], "answer": 3, "explanation": "\"Works in close collaboration with\" = l\u00e0m vi\u1ec7c ph\u1ed1i h\u1ee3p ch\u1eb7t ch\u1ebd v\u1edbi. \"In collaboration\" = c\u1ee5m c\u1ed1 \u0111\u1ecbnh. \"In close collaboration\" = variant v\u1edbi t\u00ednh t\u1eeb chen v\u00e0o."}, {"id": "prep2-68", "part": 5, "type": "prepositions", "difficulty": "medium", "question": "The manager reminded staff that all expenses must be accounted _____ with supporting receipts.", "options": ["with", "of", "for", "to"], "answer": 2, "explanation": "\"Accounted for\" = \u0111\u01b0\u1ee3c gi\u1ea3i tr\u00ecnh, ghi ch\u00e9p \u0111\u1ea7y \u0111\u1ee7. \"Account for + expense\" = gi\u1ea3i tr\u00ecnh/ghi nh\u1eadn chi ti\u00eau. Phrasal verb quan tr\u1ecdng trong ng\u1eef c\u1ea3nh t\u00e0i ch\u00ednh TOEIC."}, {"id": "prep2-69", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The decision was reached only after extensive deliberation _____ the part of all stakeholders.", "options": ["by", "on", "from", "at"], "answer": 1, "explanation": "\"On the part of all stakeholders\" = v\u1ec1 ph\u00eda, t\u1eeb ph\u00eda c\u00e1c b\u00ean li\u00ean quan. C\u1ee5m gi\u1edbi t\u1eeb n\u00e2ng cao: \"on the part of + actor\" = s\u1ef1 tham gia/th\u1ef1c hi\u1ec7n c\u1ee7a ai \u0111\u00f3. \"By the stakeholders\" sai trong ng\u1eef c\u1ea3nh n\u00e0y."}, {"id": "prep2-70", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "Contrary _____ market expectations, the company posted record profits in Q3.", "options": ["against", "with", "from", "to"], "answer": 3, "explanation": "\"Contrary to + noun\" = tr\u00e1i ng\u01b0\u1ee3c v\u1edbi. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"contrary to expectations/belief/predictions\". \"Contrary with/from/against\" \u0111\u1ec1u sai."}, {"id": "prep2-71", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The performance review was conducted _____ strict adherence to the company's protocols.", "options": ["by", "in", "with", "through"], "answer": 2, "explanation": "\"Conducted with strict adherence to\" = \u0111\u01b0\u1ee3c ti\u1ebfn h\u00e0nh v\u1edbi s\u1ef1 tu\u00e2n th\u1ee7 nghi\u00eam ng\u1eb7t. \"With adherence to\" = v\u1edbi s\u1ef1 tu\u00e2n th\u1ee7. \"In adherence to\" c\u0169ng \u0111\u00fang. \"With strict adherence\" nh\u1ea5n m\u1ea1nh m\u1ee9c \u0111\u1ed9."}, {"id": "prep2-72", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The new acquisition falls _____ the scope of the company's strategic plan for growth.", "options": ["inside", "within", "under", "in"], "answer": 1, "explanation": "\"Falls within the scope\" = n\u1eb1m trong ph\u1ea1m vi. \"Within the scope of\" = trong ph\u1ea1m vi chi\u1ebfn l\u01b0\u1ee3c/k\u1ebf ho\u1ea1ch. \"Under the scope\" sai. \"Falls within\" l\u00e0 collocation chi\u1ebfn l\u01b0\u1ee3c ph\u1ed5 bi\u1ebfn trong TOEIC."}, {"id": "prep2-73", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The chairman stepped down from his position effective _____ the close of the financial year.", "options": ["at", "on", "from", "by"], "answer": 0, "explanation": "\"Effective at the close of\" = c\u00f3 hi\u1ec7u l\u1ef1c t\u1eeb l\u00fac k\u1ebft th\u00fac. \"Effective at + time event\" = c\u00f3 hi\u1ec7u l\u1ef1c t\u1ea1i th\u1eddi \u0111i\u1ec3m. \"Effective from\" = c\u00f3 hi\u1ec7u l\u1ef1c t\u1eeb (ng\u00e0y c\u1ee5 th\u1ec3). \"At the close of\" = khi k\u1ebft th\u00fac."}, {"id": "prep2-74", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The firm is well-positioned to capitalize _____ the growing demand for electric vehicles.", "options": ["of", "from", "upon", "on"], "answer": 3, "explanation": "\"Capitalize on an opportunity/trend\" = t\u1eadn d\u1ee5ng. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"capitalize on + opportunity/demand/trend\". \"Capitalize from\" sai. \"On/upon\" \u0111\u1ec1u \u0111\u00fang nh\u01b0ng \"on\" ph\u1ed5 bi\u1ebfn h\u01a1n trong TOEIC."}, {"id": "prep2-75", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "All disputes arising _____ this agreement shall be resolved through binding arbitration.", "options": ["under", "from", "out of", "due to"], "answer": 2, "explanation": "\"Disputes arising out of this agreement\" = tranh ch\u1ea5p ph\u00e1t sinh t\u1eeb h\u1ee3p \u0111\u1ed3ng. C\u1ee5m ph\u00e1p l\u00fd: \"arising out of/from + agreement/contract\". \"Arising out of\" ph\u1ed5 bi\u1ebfn h\u01a1n trong v\u0103n b\u1ea3n h\u1ee3p \u0111\u1ed3ng TOEIC."}, {"id": "prep2-76", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The deal was struck _____ the eleventh hour, averting what could have been a costly legal battle.", "options": ["in", "at", "on", "by"], "answer": 1, "explanation": "\"Struck at the eleventh hour\" = \u0111\u01b0\u1ee3c k\u00fd k\u1ebft v\u00e0o ph\u00fat ch\u00f3t. Idiom: \"at the eleventh hour\" = v\u00e0o gi\u1edd ch\u00f3t (tr\u01b0\u1edbc khi qu\u00e1 mu\u1ed9n). C\u1ee5m n\u00e0y kh\u00f4ng th\u1ec3 thay \"at\" b\u1eb1ng gi\u1edbi t\u1eeb kh\u00e1c."}, {"id": "prep2-77", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The regulatory changes have far-reaching implications _____ the pharmaceutical industry.", "options": ["for", "on", "to", "in"], "answer": 0, "explanation": "\"Implications for an industry/sector\" = h\u1ec7 qu\u1ea3 \u0111\u1ed1i v\u1edbi. C\u1ee5m: \"have implications for + affected party\". \"Implications on\" c\u0169ng g\u1eb7p nh\u01b0ng \"for\" chu\u1ea9n h\u01a1n. \"Implications for\" l\u00e0 collocation h\u1ecdc thu\u1eadt/TOEIC chu\u1ea9n."}, {"id": "prep2-78", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The board voted to proceed _____ the acquisition notwithstanding the financial risks.", "options": ["ahead", "on", "for", "with"], "answer": 3, "explanation": "\"Proceed with the acquisition\" = ti\u1ebfn h\u00e0nh v\u1ee5 th\u00e2u t\u00f3m. \"Proceed with + plan/action\" = c\u1ee5m c\u1ed1 \u0111\u1ecbnh. \"Proceed on\" kh\u00f4ng ph\u1ed5 bi\u1ebfn. \"Notwithstanding\" = d\u00f9 c\u00f3 (gi\u1edbi t\u1eeb trang tr\u1ecdng)."}, {"id": "prep2-79", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The audit committee is responsible for ensuring that the financial statements are _____ compliance with IFRS.", "options": ["under", "on", "in", "within"], "answer": 2, "explanation": "\"In compliance with IFRS/regulations\" = tu\u00e2n th\u1ee7 theo. C\u1ee5m ph\u00e1p l\u00fd/k\u1ebf to\u00e1n: \"in compliance with + standard/regulation\". \"Under compliance\" sai. IFRS (Chu\u1ea9n m\u1ef1c BCTC qu\u1ed1c t\u1ebf) hay g\u1eb7p trong TOEIC t\u00e0i ch\u00ednh."}, {"id": "prep2-80", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The committee held firm _____ its stance that no further concessions would be made.", "options": ["to", "on", "in", "with"], "answer": 1, "explanation": "\"Held firm on its stance\" = gi\u1eef v\u1eefng l\u1eadp tr\u01b0\u1eddng. \"Hold firm on + position/stance/decision\" = ki\u00ean \u0111\u1ecbnh v\u1edbi. \"Hold firm to\" c\u0169ng d\u00f9ng (hold firm to principles). \"On stance\" chu\u1ea9n h\u01a1n."}, {"id": "prep2-81", "part": 5, "type": "prepositions", "difficulty": "hard", "question": "The agreement was reached _____ the backdrop of intense negotiations lasting several weeks.", "options": ["amid", "on", "with", "against"], "answer": 3, "explanation": "\"Against the backdrop of\" = trong b\u1ed1i c\u1ea3nh, tr\u00ean n\u1ec1n t\u1ea3ng c\u1ee7a. C\u1ee5m gi\u1edbi t\u1eeb n\u00e2ng cao: \"against the backdrop of + context\". \"Amid\" c\u0169ng \u0111\u00fang ngh\u0129a nh\u01b0ng c\u1ea5u tr\u00fac \"against the backdrop of\" chu\u1ea9n h\u01a1n cho TOEIC Part 7 vocabulary."}, {"id": "vt2-01", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "The office _____ at 8 a.m. every weekday without exception.", "options": ["open", "has opened", "is opening", "opens"], "answer": 3, "explanation": "\"Every weekday\" = th\u00f3i quen \u2192 Present Simple. Ch\u1ee7 ng\u1eef \"the office\" (s\u1ed1 \u00edt) \u2192 \"opens\" (+ s/es)."}, {"id": "vt2-02", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "The company _____ its annual report last Friday as scheduled.", "options": ["releases", "has released", "released", "was releasing"], "answer": 2, "explanation": "\"Last Friday\" = th\u1eddi \u0111i\u1ec3m c\u1ee5 th\u1ec3 trong qu\u00e1 kh\u1ee9 \u2192 Past Simple. \"Released\" = \u0111\u00e3 ph\u00e1t h\u00e0nh."}, {"id": "vt2-03", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "The new employee _____ to the office for the first time this morning.", "options": ["comes", "came", "has come", "is coming"], "answer": 1, "explanation": "\"This morning\" (\u0111\u00e3 qua) = th\u1eddi \u0111i\u1ec3m qu\u00e1 kh\u1ee9 x\u00e1c \u0111\u1ecbnh \u2192 Past Simple. \"Came\" = \u0111\u1ebfn (qu\u00e1 kh\u1ee9)."}, {"id": "vt2-04", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "Please note that the building _____ on public holidays.", "options": ["closes", "is closed", "will close", "closed"], "answer": 0, "explanation": "Th\u00f4ng b\u00e1o v\u1ec1 ch\u00ednh s\u00e1ch/quy \u0111\u1ecbnh th\u01b0\u1eddng xuy\u00ean \u2192 Present Simple. \"Closes on public holidays\" = \u0111\u00f3ng c\u1eeda v\u00e0o ng\u00e0y l\u1ec5."}, {"id": "vt2-05", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "The director _____ the proposal before it was submitted to the board.", "options": ["reviews", "is reviewing", "has reviewed", "reviewed"], "answer": 3, "explanation": "\"Before it was submitted\" = tr\u00ecnh t\u1ef1 qu\u00e1 kh\u1ee9 \u0111\u01a1n gi\u1ea3n \u2192 Past Simple. C\u00e2u di\u1ec5n t\u1ea3 hai h\u00e0nh \u0111\u1ed9ng qu\u00e1 kh\u1ee9 li\u00ean ti\u1ebfp (reviewed \u2192 submitted)."}, {"id": "vt2-06", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "We _____ your application and will be in touch within five business days.", "options": ["receive", "received", "are receiving", "have received"], "answer": 3, "explanation": "H\u00e0nh \u0111\u1ed9ng v\u1eeba x\u1ea3y ra, li\u00ean k\u1ebft v\u1edbi hi\u1ec7n t\u1ea1i (th\u00f4ng b\u00e1o ngay l\u00fac n\u00e0y) \u2192 Present Perfect. \"Have received\" = \u0111\u00e3 nh\u1eadn \u0111\u01b0\u1ee3c (v\u00e0 \u0111ang x\u1eed l\u00fd)."}, {"id": "vt2-07", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "The construction team _____ on the renovation every day from 7 a.m. to 5 p.m.", "options": ["work", "works", "is working", "has worked"], "answer": 1, "explanation": "\"Every day from...to...\" = l\u1ecbch tr\u00ecnh c\u1ed1 \u0111\u1ecbnh, th\u00f3i quen \u2192 Present Simple. \"Works\" = s\u1ed1 \u00edt."}, {"id": "vt2-08", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "Sales _____ by 30% last quarter compared to the same period the previous year.", "options": ["increased", "increase", "have increased", "are increasing"], "answer": 0, "explanation": "\"Last quarter\" = th\u1eddi \u0111i\u1ec3m qu\u00e1 kh\u1ee9 c\u1ee5 th\u1ec3 \u2192 Past Simple. \"Increased\" = t\u0103ng (qu\u00e1 kh\u1ee9)."}, {"id": "vt2-09", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "The committee _____ at 9 a.m. to finalize the budget for next quarter.", "options": ["is meeting", "meets", "meet", "met"], "answer": 0, "explanation": "\"At 9 a.m.\" + k\u1ebf ho\u1ea1ch \u0111\u00e3 \u0111\u01b0\u1ee3c s\u1eafp x\u1ebfp \u2192 Present Continuous. \"Is meeting at 9 a.m.\" = cu\u1ed9c h\u1ecdp \u0111\u00e3 \u0111\u01b0\u1ee3c l\u00ean l\u1ecbch. Ph\u00e2n bi\u1ec7t: PresentContinuous cho k\u1ebf ho\u1ea1ch t\u01b0\u01a1ng lai g\u1ea7n \u0111\u00e3 c\u00f3 k\u1ebf ho\u1ea1ch."}, {"id": "vt2-10", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "The firm _____ its new product line at the Tokyo trade fair next month.", "options": ["launch", "launches", "is launching", "launched"], "answer": 2, "explanation": "\"Next month\" + \"trade fair\" (s\u1ef1 ki\u1ec7n \u0111\u00e3 l\u00ean k\u1ebf ho\u1ea1ch) \u2192 Present Continuous cho t\u01b0\u01a1ng lai c\u00f3 k\u1ebf ho\u1ea1ch. \"Is launching next month\" = k\u1ebf ho\u1ea1ch \u0111\u00e3 \u0111\u01b0\u1ee3c x\u00e1c nh\u1eadn."}, {"id": "vt2-11", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "The company _____ this technology for over ten years and has become a market leader.", "options": ["uses", "has used", "used", "is using"], "answer": 1, "explanation": "\"For over ten years\" \u2192 kho\u1ea3ng th\u1eddi gian k\u00e9o \u0111\u1ebfn hi\u1ec7n t\u1ea1i + v\u1eabn c\u00f2n hi\u1ec7u qu\u1ea3 hi\u1ec7n t\u1ea1i \u2192 Present Perfect. \"Has used\" = \u0111\u00e3 s\u1eed d\u1ee5ng (v\u00e0 v\u1eabn \u0111ang ti\u1ebfp t\u1ee5c)."}, {"id": "vt2-12", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The logistics team _____ on the delivery schedule all week and will present their findings tomorrow.", "options": ["has been working", "worked", "works", "is working"], "answer": 0, "explanation": "\"All week\" + h\u00e0nh \u0111\u1ed9ng v\u1eabn \u0111ang ti\u1ebfp t\u1ee5c \u2192 Present Perfect Continuous. \"Has been working all week\" = \u0111\u00e3 l\u00e0m c\u1ea3 tu\u1ea7n v\u00e0 v\u1eabn ti\u1ebfp t\u1ee5c."}, {"id": "vt2-13", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "By the time the client _____, the proposal will already be on its way.", "options": ["will call", "calls", "called", "is calling"], "answer": 1, "explanation": "\"By the time\" + m\u1ec7nh \u0111\u1ec1 th\u1eddi gian \u2192 Present Simple (d\u00f9 \u00fd t\u01b0\u01a1ng lai). \"By the time the client calls\" \u2192 d\u00f9ng hi\u1ec7n t\u1ea1i thay t\u01b0\u01a1ng lai trong m\u1ec7nh \u0111\u1ec1 ph\u1ee5 th\u1eddi gian."}, {"id": "vt2-14", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The report _____ three revisions since it was first submitted last month.", "options": ["undergoes", "underwent", "has undergone", "is undergoing"], "answer": 2, "explanation": "\"Since it was first submitted\" = k\u1ec3 t\u1eeb m\u1ed9t th\u1eddi \u0111i\u1ec3m qu\u00e1 kh\u1ee9 \u2192 Present Perfect. \"Has undergone three revisions since\" = \u0111\u00e3 tr\u1ea3i qua ba l\u1ea7n s\u1eeda \u0111\u1ed5i k\u1ec3 t\u1eeb khi."}, {"id": "vt2-15", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "Customer satisfaction scores _____ steadily since the new support system was implemented.", "options": ["improve", "have improved", "improved", "are improving"], "answer": 1, "explanation": "\"Since the new system was implemented\" = k\u1ec3 t\u1eeb th\u1eddi \u0111i\u1ec3m qu\u00e1 kh\u1ee9 \u2192 Present Perfect. \"Have improved steadily since\" = \u0111\u00e3 c\u1ea3i thi\u1ec7n \u0111\u1ec1u \u0111\u1eb7n k\u1ec3 t\u1eeb."}, {"id": "vt2-16", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "By next April, the company _____ its new distribution center for two years.", "options": ["will have operated", "operated", "operates", "has operated"], "answer": 0, "explanation": "\"By next April\" = th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai \u2192 Future Perfect. \"Will have operated for two years\" = s\u1ebd \u0111\u00e3 v\u1eadn h\u00e0nh \u0111\u01b0\u1ee3c hai n\u0103m v\u00e0o th\u1eddi \u0111i\u1ec3m \u0111\u00f3."}, {"id": "vt2-17", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The team _____ the project for three months when the budget was suddenly cut.", "options": ["worked", "has worked", "was working", "had been working"], "answer": 3, "explanation": "\"When the budget was suddenly cut\" = s\u1ef1 ki\u1ec7n qu\u00e1 kh\u1ee9 gi\u00e1n \u0111o\u1ea1n h\u00e0nh \u0111\u1ed9ng \u0111ang k\u00e9o d\u00e0i tr\u01b0\u1edbc \u0111\u00f3 \u2192 Past Perfect Continuous. \"Had been working for three months when\" = \u0111\u00e3 l\u00e0m trong 3 th\u00e1ng th\u00ec b\u1ecb c\u1eaft ng\u00e2n s\u00e1ch."}, {"id": "vt2-18", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The manager _____ her office for over an hour when the fire alarm sounded.", "options": ["left", "had left", "has been leaving", "was leaving"], "answer": 3, "explanation": "\"For over an hour\" + \"when the fire alarm sounded\" = h\u00e0nh \u0111\u1ed9ng \u0111ang di\u1ec5n ra khi b\u1ecb gi\u00e1n \u0111o\u1ea1n \u2192 Past Continuous. \"Was leaving her office when\" \u2014 \u0111ang r\u1eddi th\u00ec chu\u00f4ng b\u00e1o ch\u00e1y vang l\u00ean."}, {"id": "vt2-19", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The HR team _____ the job postings to the company website when the system crashed.", "options": ["uploads", "was uploading", "uploaded", "had uploaded"], "answer": 1, "explanation": "\"When the system crashed\" = h\u00e0nh \u0111\u1ed9ng \u0111\u1ed9t ng\u1ed9t gi\u00e1n \u0111o\u1ea1n h\u00e0nh \u0111\u1ed9ng \u0111ang di\u1ec5n ra \u2192 Past Continuous. \"Was uploading when...crashed\" = \u0111ang t\u1ea3i l\u00ean th\u00ec h\u1ec7 th\u1ed1ng b\u1ecb l\u1ed7i."}, {"id": "vt2-20", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The contract _____ yet, so we cannot proceed with the project.", "options": ["is not signed", "was not signed", "will not be signed", "has not been signed"], "answer": 3, "explanation": "\"Yet\" trong ph\u1ee7 \u0111\u1ecbnh \u2192 Present Perfect. \"Has not been signed yet\" = v\u1eabn ch\u01b0a \u0111\u01b0\u1ee3c k\u00fd \u2192 \u1ea3nh h\u01b0\u1edfng \u0111\u1ebfn hi\u1ec7n t\u1ea1i (cannot proceed)."}, {"id": "vt2-21", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "When the audit team _____ its report, the board will review all recommendations.", "options": ["submits", "will submit", "submitted", "has submitted"], "answer": 0, "explanation": "\"When + m\u1ec7nh \u0111\u1ec1 th\u1eddi gian\" \u2192 Present Simple d\u00f9 \u00fd t\u01b0\u01a1ng lai. \"When the audit team submits\" = khi n\u1ed9p b\u00e1o c\u00e1o (kh\u00f4ng d\u00f9ng \"will submit\")."}, {"id": "vt2-22", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The chairman _____ the company since its founding in 1998 until his retirement last year.", "options": ["led", "leads", "has led", "was leading"], "answer": 0, "explanation": "\"From 1998 until last year\" (\u0111\u00e3 k\u1ebft th\u00fac) = h\u00e0nh \u0111\u1ed9ng ho\u00e0n ch\u1ec9nh trong qu\u00e1 kh\u1ee9 \u2192 Past Simple. \"Led the company from X until Y\" = \u0111\u00e3 l\u00e3nh \u0111\u1ea1o (\u0111\u00e3 k\u1ebft th\u00fac)."}, {"id": "vt2-23", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The quarterly targets _____ before the end of the fiscal year if the current trend continues.", "options": ["will meet", "have been met", "are being met", "will be met"], "answer": 3, "explanation": "\"If the current trend continues\" (\u0111i\u1ec1u ki\u1ec7n) + \"before year end\" \u2192 Future Passive. \"Will be met\" = s\u1ebd \u0111\u01b0\u1ee3c \u0111\u1ea1t (b\u1ecb \u0111\u1ed9ng, kh\u00f4ng r\u00f5 ai \u0111\u1ea1t)."}, {"id": "vt2-24", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The supplier _____ the delivery three times before the client finally terminated the contract.", "options": ["delays", "delayed", "has delayed", "had delayed"], "answer": 3, "explanation": "\"Before the client terminated\" = tr\u01b0\u1edbc h\u00e0nh \u0111\u1ed9ng qu\u00e1 kh\u1ee9 kh\u00e1c \u2192 Past Perfect. \"Had delayed three times before\" = \u0111\u00e3 tr\u00ec ho\u00e3n ba l\u1ea7n tr\u01b0\u1edbc khi b\u1ecb ch\u1ea5m d\u1ee9t h\u1ee3p \u0111\u1ed3ng."}, {"id": "vt2-25", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The conference _____ in Singapore for the past five years and will continue there next year.", "options": ["holds", "held", "has been held", "is held"], "answer": 2, "explanation": "\"For the past five years\" = kho\u1ea3ng th\u1eddi gian k\u00e9o \u0111\u1ebfn hi\u1ec7n t\u1ea1i \u2192 Present Perfect Passive. \"Has been held in Singapore for five years\" = \u0111\u00e3 \u0111\u01b0\u1ee3c t\u1ed5 ch\u1ee9c \u1edf Singapore trong 5 n\u0103m qua."}, {"id": "vt2-26", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "By the time the director returns from her trip, the team _____ all necessary preparations.", "options": ["completes", "will have completed", "will complete", "has completed"], "answer": 1, "explanation": "\"By the time she returns\" (by the time + present) \u2192 Future Perfect. \"Will have completed all preparations by then\" = s\u1ebd \u0111\u00e3 ho\u00e0n th\u00e0nh tr\u01b0\u1edbc khi c\u00f4 \u1ea5y quay v\u1ec1."}, {"id": "vt2-27", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "I _____ the report for three days and expect to finish it by tomorrow afternoon.", "options": ["have been writing", "wrote", "write", "am writing"], "answer": 0, "explanation": "\"For three days\" + \u0111ang c\u00f2n ti\u1ebfp t\u1ee5c (h\u00e0nh \u0111\u1ed9ng li\u00ean t\u1ee5c c\u00f3 k\u1ebft qu\u1ea3 trong t\u01b0\u01a1ng lai) \u2192 Present Perfect Continuous. \"Have been writing for three days\" = \u0111\u00e3 vi\u1ebft trong 3 ng\u00e0y v\u00e0 v\u1eabn \u0111ang vi\u1ebft."}, {"id": "vt2-28", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "She _____ the company for 20 years before she was promoted to vice president.", "options": ["serves", "served", "has served", "had served"], "answer": 3, "explanation": "\"Before she was promoted\" = tr\u01b0\u1edbc s\u1ef1 ki\u1ec7n qu\u00e1 kh\u1ee9 \u2192 Past Perfect. \"Had served for 20 years before being promoted\" = \u0111\u00e3 ph\u1ee5c v\u1ee5 20 n\u0103m tr\u01b0\u1edbc khi \u0111\u01b0\u1ee3c th\u0103ng ch\u1ee9c."}, {"id": "vt2-29", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The overseas offices _____ to the new cloud-based platform over the next two months.", "options": ["migrate", "will migrate", "have migrated", "are migrating"], "answer": 3, "explanation": "\"Over the next two months\" = k\u1ebf ho\u1ea1ch \u0111ang di\u1ec5n ra d\u1ea7n trong t\u01b0\u01a1ng lai g\u1ea7n \u2192 Present Continuous (ho\u1eb7c \"will migrate\"). \"Are migrating over the next two months\" = \u0111ang trong qu\u00e1 tr\u00ecnh chuy\u1ec3n \u0111\u1ed5i."}, {"id": "vt2-30", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The price of the product _____ three times in the past year due to supply chain disruptions.", "options": ["has risen", "rose", "rises", "is rising"], "answer": 0, "explanation": "\"In the past year\" = kho\u1ea3ng th\u1eddi gian g\u1ea7n \u0111\u00e2y c\u00f3 li\u00ean h\u1ec7 hi\u1ec7n t\u1ea1i \u2192 Present Perfect. \"Has risen three times in the past year\" = \u0111\u00e3 t\u0103ng ba l\u1ea7n trong n\u0103m qua."}, {"id": "vt2-31", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "Once the contract _____, both parties must adhere to all specified terms.", "options": ["will be signed", "is signed", "was signed", "has been signed"], "answer": 1, "explanation": "\"Once\" = m\u1ec7nh \u0111\u1ec1 \u0111i\u1ec1u ki\u1ec7n th\u1eddi gian \u2192 Present Simple (d\u00f9 \u00fd t\u01b0\u01a1ng lai). \"Once the contract is signed\" = m\u1ed9t khi h\u1ee3p \u0111\u1ed3ng \u0111\u01b0\u1ee3c k\u00fd."}, {"id": "vt2-32", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "This is the first time the company _____ such a prestigious international award.", "options": ["received", "receives", "has received", "had received"], "answer": 2, "explanation": "\"This is the first time + S + has + V3\" = c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh v\u1edbi Present Perfect. \"This is the first time the company has received\" = \u0111\u00e2y l\u00e0 l\u1ea7n \u0111\u1ea7u ti\u00ean c\u00f4ng ty nh\u1eadn \u0111\u01b0\u1ee3c."}, {"id": "vt2-33", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The data _____ that consumer confidence has improved significantly over the last quarter.", "options": ["suggests", "suggest", "is suggesting", "has suggested"], "answer": 0, "explanation": "Stative verb \"suggest\" (data presents information) \u2192 Present Simple. \"Data suggests\" = s\u1ed1 li\u1ec7u cho th\u1ea5y (d\u00f9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n v\u00ec l\u00e0 s\u1ef1 th\u1eadt \u0111ang hi\u1ec7n h\u1eefu). Kh\u00f4ng d\u00f9ng continuous v\u1edbi stative meaning."}, {"id": "vt2-34", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "Ms. Pham _____ her presentation when the power outage disrupted the entire meeting.", "options": ["delivers", "was delivering", "had delivered", "delivered"], "answer": 1, "explanation": "\"When the power outage disrupted\" = s\u1ef1 ki\u1ec7n \u0111\u1ed9t ng\u1ed9t gi\u00e1n \u0111o\u1ea1n \u2192 Past Continuous cho h\u00e0nh \u0111\u1ed9ng \u0111ang di\u1ec5n ra. \"Was delivering her presentation when\" = \u0111ang tr\u00ecnh b\u00e0y th\u00ec m\u1ea5t \u0111i\u1ec7n."}, {"id": "vt2-35", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The new safety regulations _____ into effect at the start of next quarter.", "options": ["come", "are coming", "will come", "came"], "answer": 2, "explanation": "\"At the start of next quarter\" = th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai c\u1ee5 th\u1ec3 \u2192 Future Simple. \"Will come into effect\" = s\u1ebd c\u00f3 hi\u1ec7u l\u1ef1c. \"Are coming into effect\" c\u0169ng \u0111\u00fang (k\u1ebf ho\u1ea1ch)."}, {"id": "vt2-36", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The project _____ completion at over $5 million, well above the original estimate.", "options": ["costs", "cost", "is costing", "will cost"], "answer": 3, "explanation": "\"At completion\" = th\u1eddi \u0111i\u1ec3m trong t\u01b0\u01a1ng lai (d\u1ef1 \u00e1n ch\u01b0a ho\u00e0n th\u00e0nh) \u2192 Future Simple. \"Will cost at completion\" = s\u1ebd ti\u00eau t\u1ed1n khi ho\u00e0n th\u00e0nh."}, {"id": "vt2-37", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The department _____ consistently under budget for three consecutive years.", "options": ["has operated", "operated", "operates", "is operating"], "answer": 0, "explanation": "\"For three consecutive years\" = kho\u1ea3ng th\u1eddi gian k\u00e9o \u0111\u1ebfn hi\u1ec7n t\u1ea1i \u2192 Present Perfect. \"Has operated under budget for three years\" = \u0111\u00e3 ho\u1ea1t \u0111\u1ed9ng trong ng\u00e2n s\u00e1ch 3 n\u0103m li\u00ean ti\u1ebfp (th\u00e0nh t\u00edch hi\u1ec7n t\u1ea1i)."}, {"id": "vt2-38", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The factory _____ at reduced capacity since the main production line was shut down for repairs.", "options": ["has been running", "ran", "runs", "had been running"], "answer": 0, "explanation": "\"Since the line was shut down\" = k\u1ec3 t\u1eeb m\u1ed1c qu\u00e1 kh\u1ee9, v\u1eabn ti\u1ebfp t\u1ee5c \u2192 Present Perfect Continuous. \"Has been running at reduced capacity since\" = \u0111\u00e3 ho\u1ea1t \u0111\u1ed9ng gi\u1ea3m c\u00f4ng su\u1ea5t k\u1ec3 t\u1eeb khi."}, {"id": "vt2-39", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The auditors confirmed that all financial records _____ in accordance with GAAP.", "options": ["had been maintained", "are maintained", "have been maintained", "were maintained"], "answer": 0, "explanation": "\"Auditors confirmed\" (past) + h\u00e0nh \u0111\u1ed9ng tr\u01b0\u1edbc \u0111\u00f3 \u2192 Past Perfect Passive. \"Confirmed that records had been maintained\" = x\u00e1c nh\u1eadn r\u1eb1ng h\u1ed3 s\u01a1 \u0111\u00e3 \u0111\u01b0\u1ee3c l\u01b0u tr\u1eef (tr\u01b0\u1edbc th\u1eddi \u0111i\u1ec3m ki\u1ec3m to\u00e1n)."}, {"id": "vt2-40", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The office lease _____ in two years, at which point management will decide whether to renew.", "options": ["will expire", "expires", "expired", "has expired"], "answer": 0, "explanation": "\"In two years\" = th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai c\u1ee5 th\u1ec3 \u2192 Future Simple. \"Will expire in two years\" = s\u1ebd h\u1ebft h\u1ea1n sau hai n\u0103m."}, {"id": "vt2-41", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "If the team _____ the milestone by Friday, the client may extend the project timeline.", "options": ["missed", "will miss", "misses", "has missed"], "answer": 2, "explanation": "C\u00e2u \u0111i\u1ec1u ki\u1ec7n Type 1: If + Present Simple \u2192 may/will + V. \"If the team misses the milestone\" = n\u1ebfu nh\u00f3m b\u1ecf l\u1ee1 m\u1ed1c quan tr\u1ecdng."}, {"id": "vt2-42", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The director noticed that sales _____ in three out of four regions during the previous quarter.", "options": ["had declined", "declined", "have declined", "decline"], "answer": 0, "explanation": "\"Director noticed\" (past) + h\u00e0nh \u0111\u1ed9ng trong \"previous quarter\" (tr\u01b0\u1edbc \u0111\u00f3) \u2192 Past Perfect. \"Noticed that sales had declined\" = nh\u1eadn ra r\u1eb1ng doanh s\u1ed1 \u0111\u00e3 gi\u1ea3m (tr\u01b0\u1edbc th\u1eddi \u0111i\u1ec3m nh\u1eadn ra)."}, {"id": "vt2-43", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The investors remain optimistic despite the fact that revenues _____ slightly below forecast.", "options": ["come", "came", "have come", "had come"], "answer": 2, "explanation": "\"Despite the fact that\" \u2192 ng\u1eef c\u1ea3nh hi\u1ec7n t\u1ea1i li\u00ean k\u1ebft v\u1edbi k\u1ebft qu\u1ea3 g\u1ea7n \u0111\u00e2y \u2192 Present Perfect. \"Have come slightly below forecast\" = \u0111\u00e3 \u1edf m\u1ee9c h\u01a1i th\u1ea5p h\u01a1n d\u1ef1 b\u00e1o (\u1ea3nh h\u01b0\u1edfng \u0111\u1ebfn th\u00e1i \u0111\u1ed9 hi\u1ec7n t\u1ea1i)."}, {"id": "vt2-44", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "Please ensure that all attendees _____ the meeting at least ten minutes before it begins.", "options": ["are joining", "have joined", "will have joined", "join"], "answer": 3, "explanation": "Trong c\u00e2u l\u1ec7nh/y\u00eau c\u1ea7u: \"Please ensure that + clause\" \u2192 hi\u1ec7n t\u1ea1i \u0111\u01a1n cho h\u00e0nh \u0111\u1ed9ng c\u1ea7n l\u00e0m. \"Ensure that attendees join\" = \u0111\u1ea3m b\u1ea3o ng\u01b0\u1eddi tham d\u1ef1 v\u00e0o ph\u00f2ng h\u1ecdp."}, {"id": "vt2-45", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The CEO announced that the company _____ three new research centers across Asia.", "options": ["opens", "would open", "is opening", "opened"], "answer": 1, "explanation": "Sau \"announced that\" (past) \u2192 t\u01b0\u1eddng thu\u1eadt gi\u00e1n ti\u1ebfp d\u00f9ng conditional \"would\". \"Announced that the company would open\" = tuy\u00ean b\u1ed1 r\u1eb1ng c\u00f4ng ty s\u1ebd m\u1edf (t\u01b0\u1eddng thu\u1eadt l\u1ea1i l\u1eddi n\u00f3i qu\u00e1 kh\u1ee9)."}, {"id": "vt2-46", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The revised figures _____ a much clearer picture of the company's financial health.", "options": ["paints", "paint", "painted", "have painted"], "answer": 1, "explanation": "\"Revised figures\" (s\u1ed1 li\u1ec7u hi\u1ec7n t\u1ea1i, s\u1ef1 th\u1eadt \u0111ang t\u1ed3n t\u1ea1i) \u2192 Present Simple. \"Figures paint a picture\" = s\u1ed1 li\u1ec7u v\u1ebd n\u00ean b\u1ee9c tranh. Ch\u1ee7 ng\u1eef \"figures\" (plural) \u2192 \"paint\" kh\u00f4ng c\u00f3 -s."}, {"id": "vt2-47", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "As long as the conditions _____ unchanged, the agreement will remain in force.", "options": ["remain", "will remain", "remained", "have remained"], "answer": 0, "explanation": "\"As long as\" = m\u1ec7nh \u0111\u1ec1 \u0111i\u1ec1u ki\u1ec7n \u2192 Present Simple (d\u00f9 \u00fd t\u01b0\u01a1ng lai). \"As long as conditions remain unchanged\" = mi\u1ec5n l\u00e0 \u0111i\u1ec1u ki\u1ec7n kh\u00f4ng \u0111\u1ed5i."}, {"id": "vt2-48", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The product _____ overwhelming positive reviews from industry experts since its release.", "options": ["receives", "has received", "received", "is receiving"], "answer": 1, "explanation": "\"Since its release\" = k\u1ec3 t\u1eeb th\u1eddi \u0111i\u1ec3m ra m\u1eaft \u2192 Present Perfect. \"Has received overwhelming reviews since\" = \u0111\u00e3 nh\u1eadn \u0111\u01b0\u1ee3c \u0111\u00e1nh gi\u00e1 t\u00edch c\u1ef1c k\u1ec3 t\u1eeb khi ra m\u1eaft."}, {"id": "vt2-49", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "By the time the new branch _____, the company will have expanded into six countries.", "options": ["opened", "will open", "opens", "has opened"], "answer": 2, "explanation": "\"By the time + clause\" \u2192 Present Simple trong m\u1ec7nh \u0111\u1ec1 ph\u1ee5 (d\u00f9 t\u01b0\u01a1ng lai). Main clause: \"will have expanded\" (Future Perfect). B\u1eaby: kh\u00f4ng d\u00f9ng \"will open\" trong m\u1ec7nh \u0111\u1ec1 th\u1eddi gian."}, {"id": "vt2-50", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "The analyst estimates that the market _____ its pre-recession peak by the end of next year.", "options": ["reaches", "will have reached", "reached", "has reached"], "answer": 1, "explanation": "\"By the end of next year\" = th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai + ho\u00e0n th\u00e0nh tr\u01b0\u1edbc \u0111\u00f3 \u2192 Future Perfect. \"Will have reached its pre-recession peak by then\" = s\u1ebd \u0111\u1ea1t \u0111\u01b0\u1ee3c m\u1ee9c \u0111\u1ec9nh tr\u01b0\u1edbc suy tho\u00e1i."}, {"id": "vt2-51", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "If the company _____ the product line sooner, it would not have lost so many customers.", "options": ["had diversified", "diversified", "has diversified", "would diversify"], "answer": 0, "explanation": "Type 3 Conditional: If + Past Perfect \u2192 would have + V3. \"If the company had diversified earlier, it would not have lost customers\" = \u0111i\u1ec1u ki\u1ec7n kh\u00f4ng th\u1ef1c trong qu\u00e1 kh\u1ee9."}, {"id": "vt2-52", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "The data _____ consistent with our projections when the market correction occurred.", "options": ["seems", "was seeming", "seemed", "has seemed"], "answer": 2, "explanation": "Stative verb \"seem\" + context qu\u00e1 kh\u1ee9 \"when the correction occurred\" \u2192 Past Simple. \"Seemed consistent when\" = c\u00f3 v\u1ebb nh\u1ea5t qu\u00e1n khi. \"Was seeming\" sai v\u00ec stative verbs kh\u00f4ng d\u00f9ng continuous."}, {"id": "vt2-53", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "Had the merger been approved earlier, the company _____ stronger earnings by now.", "options": ["would report", "reports", "would have reported", "has reported"], "answer": 2, "explanation": "Type 3/Mixed Conditional: Had + V3 (Past Perfect) \u2192 would have + V3. \"Had the merger been approved earlier, the company would have reported stronger earnings\" = \u0111\u1ea3o ng\u1eef \u0111i\u1ec1u ki\u1ec7n Type 3."}, {"id": "vt2-54", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "The chairman _____ the board for over three decades by the time he steps down next year.", "options": ["leads", "has led", "will have led", "led"], "answer": 2, "explanation": "\"By the time he steps down next year\" = th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai \u2192 Future Perfect. \"Will have led the board for over three decades\" = s\u1ebd \u0111\u00e3 l\u00e3nh \u0111\u1ea1o h\u1ed9i \u0111\u1ed3ng h\u01a1n 30 n\u0103m khi \u0111\u00f3."}, {"id": "vt2-55", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "Management _____ the new contract terms before the legal team spotted a critical loophole.", "options": ["had approved", "approved", "has approved", "was approving"], "answer": 0, "explanation": "\"Before the legal team spotted a loophole\" = tr\u01b0\u1edbc h\u00e0nh \u0111\u1ed9ng qu\u00e1 kh\u1ee9 \u2192 Past Perfect. \"Had approved the terms before\" = \u0111\u00e3 ph\u00ea duy\u1ec7t tr\u01b0\u1edbc khi \u0111\u1ed9i ph\u00e1p l\u00fd ph\u00e1t hi\u1ec7n ra l\u1ed7 h\u1ed5ng."}, {"id": "vt2-56", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "By 2030, the company _____ its operations in over 50 countries if expansion continues.", "options": ["will have established", "will establish", "establishes", "has established"], "answer": 0, "explanation": "\"By 2030\" = th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai c\u1ee5 th\u1ec3 + \u0111i\u1ec1u ki\u1ec7n (\"if expansion continues\") \u2192 Future Perfect. \"Will have established operations in 50+ countries by 2030\" = s\u1ebd \u0111\u00e3 thi\u1ebft l\u1eadp \u0111\u01b0\u1ee3c."}, {"id": "vt2-57", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "The new platform _____ for exactly one year next month, making it eligible for a comprehensive review.", "options": ["is operating", "operated", "will have been operating", "has operated"], "answer": 2, "explanation": "\"For exactly one year next month\" = th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai + kho\u1ea3ng th\u1eddi gian k\u00e9o d\u00e0i \u2192 Future Perfect Continuous. \"Will have been operating for one year next month\" = s\u1ebd \u0111\u00e3 v\u1eadn h\u00e0nh \u0111\u01b0\u1ee3c \u0111\u00fang 1 n\u0103m."}, {"id": "cj-e01", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "The office will be closed _____ the national holiday.", "options": ["because", "during", "for", "since"], "answer": 1, "explanation": "\"During the national holiday\" = trong su\u1ed1t ng\u00e0y l\u1ec5. \"During + noun\" d\u00f9ng khi m\u1ed9t s\u1ef1 ki\u1ec7n x\u1ea3y ra trong kho\u1ea3ng th\u1eddi gian c\u1ee7a s\u1ef1 ki\u1ec7n kh\u00e1c."}, {"id": "cj-e02", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "Please call the help desk _____ you have any technical issues.", "options": ["although", "if", "however", "despite"], "answer": 1, "explanation": "\"If\" = n\u1ebfu \u2014 li\u00ean t\u1eeb \u0111i\u1ec1u ki\u1ec7n \u0111\u01a1n gi\u1ea3n nh\u1ea5t. \"If you have issues, call...\" = c\u00e2u \u0111i\u1ec1u ki\u1ec7n Type 1 \u0111\u01a1n gi\u1ea3n."}, {"id": "cj-e03", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "The meeting was cancelled _____ the presenter was ill.", "options": ["so", "although", "but", "because"], "answer": 3, "explanation": "\"Because\" = v\u00ec \u2014 li\u00ean t\u1eeb nguy\u00ean nh\u00e2n. \"Cancelled because the presenter was ill\" = b\u1ecb h\u1ee7y v\u00ec di\u1ec5n gi\u1ea3 b\u1ecb b\u1ec7nh."}, {"id": "cj-e04", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "Please review the report _____ submit it by Friday.", "options": ["but", "and", "or", "so"], "answer": 1, "explanation": "\"And\" = v\u00e0 \u2014 li\u00ean t\u1eeb b\u1ed5 sung, n\u1ed1i hai m\u1ec7nh l\u1ec7nh c\u00f9ng lo\u1ea1i. \"Review...and submit\" = xem v\u00e0 n\u1ed9p."}, {"id": "cj-e05", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "The salary is competitive _____ the location is convenient.", "options": ["and", "but", "or", "although"], "answer": 0, "explanation": "\"And\" n\u1ed1i hai th\u00f4ng tin t\u00edch c\u1ef1c b\u1ed5 sung cho nhau. \"Salary is competitive and location is convenient\" = l\u01b0\u01a1ng t\u1ed1t v\u00e0 \u0111\u1ecba \u0111i\u1ec3m thu\u1eadn l\u1ee3i."}, {"id": "cj-e06", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "She wanted to attend the conference _____ she had to work overtime.", "options": ["but", "and", "so", "because"], "answer": 0, "explanation": "\"But\" = nh\u01b0ng \u2014 li\u00ean t\u1eeb t\u01b0\u01a1ng ph\u1ea3n. \"Wanted to attend but had to work\" = mu\u1ed1n tham d\u1ef1 nh\u01b0ng ph\u1ea3i l\u00e0m th\u00eam gi\u1edd."}, {"id": "cj-e07", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "The new system is simple _____ easy to use.", "options": ["or", "but", "and", "so"], "answer": 2, "explanation": "\"And\" n\u1ed1i hai t\u00ednh t\u1eeb b\u1ed5 sung: \"simple and easy to use\" = \u0111\u01a1n gi\u1ea3n v\u00e0 d\u1ec5 d\u00f9ng."}, {"id": "cj-e08", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "You can pay by cash _____ by credit card.", "options": ["and", "or", "but", "so"], "answer": 1, "explanation": "\"Or\" = ho\u1eb7c \u2014 n\u1ed1i hai l\u1ef1a ch\u1ecdn. \"Pay by cash or by credit card\" = tr\u1ea3 b\u1eb1ng ti\u1ec1n m\u1eb7t ho\u1eb7c th\u1ebb t\u00edn d\u1ee5ng."}, {"id": "cj-e09", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "The store opens at 9 a.m. _____ closes at 8 p.m.", "options": ["and", "but", "or", "so"], "answer": 0, "explanation": "\"And\" n\u1ed1i hai th\u00f4ng tin v\u1ec1 gi\u1edd m\u1edf/\u0111\u00f3ng c\u1eeda. \"Opens...and closes...\" = c\u1ea5u tr\u00fac \u0111\u01a1n gi\u1ea3n nh\u1ea5t."}, {"id": "cj-e10", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "Please arrive early _____ you can find a good seat.", "options": ["because of", "although", "so that", "despite"], "answer": 2, "explanation": "\"So that\" = \u0111\u1ec3 (m\u1ee5c \u0111\u00edch). \"Arrive early so that you can find a good seat\" = \u0111\u1ebfn s\u1edbm \u0111\u1ec3 t\u00ecm \u0111\u01b0\u1ee3c ch\u1ed7 ng\u1ed3i t\u1ed1t."}, {"id": "cj-e11", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "The project was delayed _____ we worked hard.", "options": ["because", "even though", "so", "and"], "answer": 1, "explanation": "\"Even though\" = m\u1eb7c d\u00f9 \u2014 t\u01b0\u01a1ng ph\u1ea3n m\u1ea1nh h\u01a1n \"although\". \"Delayed even though we worked hard\" = b\u1ecb tr\u1ec5 d\u00f9 ch\u00fang t\u00f4i l\u00e0m vi\u1ec7c ch\u0103m ch\u1ec9."}, {"id": "cj-e12", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "You must register in advance _____ attend the event.", "options": ["in order to", "so", "because", "however"], "answer": 0, "explanation": "\"In order to\" = \u0111\u1ec3 (m\u1ee5c \u0111\u00edch) tr\u01b0\u1edbc to-infinitive. \"Register in order to attend\" = \u0111\u0103ng k\u00fd \u0111\u1ec3 \u0111\u01b0\u1ee3c tham d\u1ef1."}, {"id": "cj-e13", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "The restaurant is popular _____ the food quality is high.", "options": ["despite", "but", "however", "because"], "answer": 3, "explanation": "\"Because\" = v\u00ec \u2014 gi\u1ea3i th\u00edch l\u00fd do. \"Popular because food quality is high\" = n\u1ed5i ti\u1ebfng v\u00ec ch\u1ea5t l\u01b0\u1ee3ng cao."}, {"id": "cj-e14", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "The office is small _____ very well organized.", "options": ["or", "and", "but", "so"], "answer": 2, "explanation": "\"But\" = nh\u01b0ng \u2014 t\u01b0\u01a1ng ph\u1ea3n gi\u1eefa \"small\" (ti\u00eau c\u1ef1c) v\u00e0 \"well organized\" (t\u00edch c\u1ef1c)."}, {"id": "cj-e15", "part": 5, "type": "conjunction", "difficulty": "easy", "question": "Please bring your ID _____ your employee badge.", "options": ["or", "and", "but", "so"], "answer": 1, "explanation": "\"And\" n\u1ed1i hai v\u1eadt c\u1ea7n mang theo. \"Bring your ID and your badge\" = mang theo CMND v\u00e0 th\u1ebb nh\u00e2n vi\u00ean."}, {"id": "cj-h01", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "The proposal was rejected not _____ it lacked merit, _____ the timing was poor.", "options": ["because / but because", "just / but", "only / but also", "because / although"], "answer": 2, "explanation": "\"Not only...but also...\" = kh\u00f4ng ch\u1ec9...m\u00e0 c\u00f2n... C\u1ea5u tr\u00fac t\u01b0\u01a1ng quan hai chi\u1ec1u. \"Not only because it lacked merit, but also because the timing was poor.\""}, {"id": "cj-h02", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "_____ the contract is signed, no party may withdraw _____ the other's consent.", "options": ["Once / without", "While / despite", "Although / with", "When / before"], "answer": 0, "explanation": "\"Once the contract is signed\" = khi h\u1ee3p \u0111\u1ed3ng \u0111\u00e3 \u0111\u01b0\u1ee3c k\u00fd (m\u1ec7nh \u0111\u1ec1 th\u1eddi gian). \"Without the other's consent\" = gi\u1edbi t\u1eeb + noun. Hai c\u1ee5m kh\u00e1c lo\u1ea1i nh\u01b0ng b\u1ed5 sung logic cho nhau."}, {"id": "cj-h03", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "The merger was _____ delayed due to regulatory concerns _____ ultimately completed six months later.", "options": ["not only / but", "first / however", "once / and", "initially / but"], "answer": 3, "explanation": "\"Initially delayed...but ultimately completed\" = ban \u0111\u1ea7u b\u1ecb tr\u00ec ho\u00e3n nh\u01b0ng cu\u1ed1i c\u00f9ng ho\u00e0n th\u00e0nh. C\u1eb7p tr\u1ea1ng t\u1eeb th\u1eddi gian t\u01b0\u01a1ng ph\u1ea3n: initially vs ultimately."}, {"id": "cj-h04", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "The board approved the expansion plan, _____ concerns about profitability were raised.", "options": ["despite", "although", "notwithstanding", "regardless"], "answer": 2, "explanation": "\"Notwithstanding\" = m\u1eb7c d\u00f9, b\u1ea5t ch\u1ea5p (gi\u1edbi t\u1eeb trang tr\u1ecdng, sau d\u1ea5u ph\u1ea9y \u0111\u1ee9ng \u0111\u1ed9c l\u1eadp). Ng\u1eef ph\u00e1p n\u00e2ng cao: notwithstanding + noun phrase d\u00f9ng trong v\u0103n ki\u1ec7n ph\u00e1p l\u00fd."}, {"id": "cj-h05", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "_____ promising the figures may appear, investors should examine the underlying assumptions carefully.", "options": ["However", "As much", "However much", "No matter"], "answer": 2, "explanation": "\"However promising...may appear\" = c\u1ea5u tr\u00fac nh\u01b0\u1ee3ng b\u1ed9 n\u00e2ng cao: however + adj/adv + S + V. \"However promising\" = d\u00f9 c\u00f3 v\u1ebb h\u1ee9a h\u1eb9n \u0111\u1ebfn \u0111\u00e2u. Kh\u00e1c \"however\" \u0111\u1ee9ng \u0111\u1ed9c l\u1eadp."}, {"id": "cj-h06", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "The CEO accepted the terms, _____ reluctantly, _____ the alternative was bankruptcy.", "options": ["if", "however / since", "albeit / as", "though / because"], "answer": 2, "explanation": "\"Albeit\" = m\u1eb7c d\u00f9, d\u1eabu (= although) \u2014 \u0111\u1ee9ng tr\u01b0\u1edbc adj/adv kh\u00f4ng c\u00f3 S+V. \"Accepted, albeit reluctantly, as the alternative was bankruptcy.\" T\u1eeb trang tr\u1ecdng c\u1ef1c cao c\u1ea5p trong TOEIC."}, {"id": "cj-h07", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "Staff may work from home _____ they complete all assigned tasks _____ the agreed deadline.", "options": ["so that / within", "unless / before", "although / after", "provided that / by"], "answer": 3, "explanation": "\"Provided that...by...\" = v\u1edbi \u0111i\u1ec1u ki\u1ec7n l\u00e0...tr\u01b0\u1edbc th\u1eddi h\u1ea1n. \"Provided that they complete tasks by the deadline\" \u2014 hai \u0111i\u1ec1u ki\u1ec7n c\u00f9ng lo\u1ea1i b\u1ed5 tr\u1ee3 nhau."}, {"id": "cj-h08", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "The project will be profitable _____ demand remains stable _____ costs do not exceed projections.", "options": ["as long as / provided that", "provided / unless", "insofar as / and", "if only / unless"], "answer": 0, "explanation": "\"As long as...provided that...\" = mi\u1ec5n l\u00e0...v\u1edbi \u0111i\u1ec1u ki\u1ec7n l\u00e0... Hai li\u00ean t\u1eeb \u0111i\u1ec1u ki\u1ec7n kh\u00e1c nhau gh\u00e9p l\u1ea1i \u2014 c\u1ea5u tr\u00fac ph\u1ee9c hai \u0111i\u1ec1u ki\u1ec7n song song trong v\u0103n b\u1ea3n h\u1ee3p \u0111\u1ed3ng."}, {"id": "cj-h09", "part": 5, "type": "conjunction", "difficulty": "hard", "question": "The chairman spoke at length about the company's vision, _____ he failed to address shareholders' immediate concerns.", "options": ["but", "yet", "however", "although"], "answer": 1, "explanation": "\"Yet\" sau d\u1ea5u ph\u1ea9y = nh\u01b0ng (t\u01b0\u01a1ng ph\u1ea3n, m\u1ea1nh h\u01a1n \"but\" trong v\u0103n vi\u1ebft trang tr\u1ecdng). \"Spoke at length...yet failed to address\" = n\u00f3i d\u00e0i nh\u01b0ng v\u1eabn kh\u00f4ng \u0111\u1ec1 c\u1eadp \u0111\u1ebfn."}, {"id": "vc-e01", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The store is offering a 30% _____ on all winter clothing this week.", "options": ["deduction", "reduction", "discount", "rebate"], "answer": 2, "explanation": "\"Discount on products\" = gi\u1ea3m gi\u00e1 s\u1ea3n ph\u1ea9m. Collocation: \"offer/give a discount on\". \"Discount\" ph\u1ed5 bi\u1ebfn nh\u1ea5t trong ng\u1eef c\u1ea3nh b\u00e1n l\u1ebb."}, {"id": "vc-e02", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "Please _____ your name and employee number on the form.", "options": ["write", "enter", "type", "fill"], "answer": 1, "explanation": "\"Enter your name\" = nh\u1eadp t\u00ean v\u00e0o form/h\u1ec7 th\u1ed1ng. \"Enter\" chu\u1ea9n nh\u1ea5t trong ng\u1eef c\u1ea3nh form/system."}, {"id": "vc-e03", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The conference _____ about 300 professionals from the healthcare industry.", "options": ["attracted", "brought", "gathered", "collected"], "answer": 0, "explanation": "\"Attracted 300 professionals\" = thu h\u00fat. \"Attract + audience/crowd\" l\u00e0 collocation ph\u1ed5 bi\u1ebfn nh\u1ea5t."}, {"id": "vc-e04", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The HR department sent a _____ to all employees about the new dress code.", "options": ["letter", "notice", "warning", "reminder"], "answer": 3, "explanation": "\"Send a reminder about a policy\" = g\u1eedi nh\u1eafc nh\u1edf. \"Reminder\" nh\u1eb9 nh\u00e0ng, th\u00edch h\u1ee3p khi \u0111\u01a1n gi\u1ea3n l\u00e0 nh\u1eafc nh\u1edf v\u1ec1 quy \u0111\u1ecbnh m\u1edbi."}, {"id": "vc-e05", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The manager _____ the team's success during the Monday morning meeting.", "options": ["spoke", "told", "praised", "announced"], "answer": 2, "explanation": "\"Praised the team's success\" = khen ng\u1ee3i th\u00e0nh t\u00edch. \"Praise + noun\" = collocation ph\u1ed5 bi\u1ebfn trong HR context."}, {"id": "vc-e06", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The receptionist _____ all incoming calls to the appropriate department.", "options": ["moved", "transferred", "sent", "directed"], "answer": 1, "explanation": "\"Transfer calls\" = chuy\u1ec3n cu\u1ed9c g\u1ecdi. Collocation k\u1ef9 thu\u1eadt chu\u1ea9n trong m\u00f4i tr\u01b0\u1eddng v\u0103n ph\u00f2ng TOEIC."}, {"id": "vc-e07", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The new photocopier is easy to _____ and requires minimal training.", "options": ["operate", "use", "control", "run"], "answer": 0, "explanation": "\"Operate a machine/equipment\" = v\u1eadn h\u00e0nh thi\u1ebft b\u1ecb. \"Operate\" chu\u1ea9n nh\u1ea5t khi n\u00f3i v\u1ec1 m\u00e1y m\u00f3c k\u1ef9 thu\u1eadt."}, {"id": "vc-e08", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "All employees must _____ their access badges when entering secure areas.", "options": ["present", "show", "display", "give"], "answer": 0, "explanation": "\"Present your badge\" = xu\u1ea5t tr\u00ecnh th\u1ebb. \"Present + ID/badge/document\" l\u00e0 collocation trang tr\u1ecdng nh\u1ea5t trong ng\u1eef c\u1ea3nh security."}, {"id": "vc-e09", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The client was very _____ with the quality of the product and left a five-star review.", "options": ["pleased", "happy", "satisfied", "content"], "answer": 2, "explanation": "\"Satisfied with the quality\" = h\u00e0i l\u00f2ng v\u1edbi ch\u1ea5t l\u01b0\u1ee3ng. \"Satisfied\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t trong v\u0103n b\u1ea3n \u0111\u00e1nh gi\u00e1/kh\u1ea3o s\u00e1t."}, {"id": "vc-e10", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "Please _____ a copy of your passport when completing the visa application.", "options": ["include", "attach", "add", "enclose"], "answer": 1, "explanation": "\"Attach a copy\" = \u0111\u00ednh k\u00e8m b\u1ea3n sao. \"Attach\" ph\u1ed5 bi\u1ebfn nh\u1ea5t khi g\u1eedi email/form k\u00e8m t\u00e0i li\u1ec7u."}, {"id": "vc-e11", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The company will _____ its services to include mobile app support next quarter.", "options": ["extend", "grow", "increase", "expand"], "answer": 3, "explanation": "\"Expand services to include...\" = m\u1edf r\u1ed9ng d\u1ecbch v\u1ee5 \u0111\u1ec3 bao g\u1ed3m. \"Expand\" chu\u1ea9n nh\u1ea5t khi th\u00eam lo\u1ea1i d\u1ecbch v\u1ee5 m\u1edbi."}, {"id": "vc-e12", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The cafeteria menu _____ a variety of healthy options for all dietary requirements.", "options": ["gives", "has", "offers", "provides"], "answer": 2, "explanation": "\"Menu offers options\" = th\u1ef1c \u0111\u01a1n cung c\u1ea5p l\u1ef1a ch\u1ecdn. \"Offer\" l\u00e0 collocation t\u1ef1 nhi\u00ean nh\u1ea5t v\u1edbi menu."}, {"id": "vc-e13", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The supervisor _____ the new team member through the company's induction process.", "options": ["took", "guided", "led", "helped"], "answer": 1, "explanation": "\"Guide someone through a process\" = h\u01b0\u1edbng d\u1eabn ai qua quy tr\u00ecnh. \"Guide through\" chu\u1ea9n nh\u1ea5t trong ng\u1eef c\u1ea3nh onboarding."}, {"id": "vc-e14", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The IT department will _____ any technical issues within two business hours.", "options": ["resolve", "fix", "solve", "repair"], "answer": 0, "explanation": "\"Resolve technical issues\" = gi\u1ea3i quy\u1ebft v\u1ea5n \u0111\u1ec1 k\u1ef9 thu\u1eadt. \"Resolve\" trang tr\u1ecdng nh\u1ea5t trong v\u0103n b\u1ea3n d\u1ecbch v\u1ee5 TOEIC."}, {"id": "vc-h01", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The firm's inability to _____ to rapidly changing consumer preferences ultimately led to its decline.", "options": ["react", "adjust", "respond", "adapt"], "answer": 3, "explanation": "\"Adapt to changing preferences\" = th\u00edch nghi v\u1edbi s\u1edf th\u00edch thay \u0111\u1ed5i. \"Adapt\" (l\u00e2u d\u00e0i, c\u01a1 c\u1ea5u l\u1ea1i to\u00e0n b\u1ed9) vs \"adjust\" (\u0111i\u1ec1u ch\u1ec9nh nh\u1ecf) \u2014 ng\u1eef c\u1ea3nh \"ultimately led to decline\" = th\u1ea5t b\u1ea1i l\u00e2u d\u00e0i \u2192 \"adapt\" ph\u00f9 h\u1ee3p."}, {"id": "vc-h02", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The CEO's statement was carefully _____ to avoid any implication of wrongdoing.", "options": ["worded", "crafted", "phrased", "written"], "answer": 1, "explanation": "\"Carefully crafted statement\" = tuy\u00ean b\u1ed1 \u0111\u01b0\u1ee3c so\u1ea1n th\u1ea3o k\u1ef9 l\u01b0\u1ee1ng. \"Crafted\" = t\u1ea1o ra c\u00f3 ch\u1ee7 \u0111\u00edch v\u00e0 kh\u00e9o l\u00e9o. T\u1eeb n\u00e2ng cao: \"carefully crafted\" collocation hay g\u1eb7p trong TOEIC Part 7."}, {"id": "vc-h03", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The research findings _____ significant gaps in the current regulatory framework.", "options": ["highlighted", "exposed", "uncovered", "revealed"], "answer": 0, "explanation": "\"Highlighted significant gaps\" = l\u00e0m n\u1ed5i b\u1eadt, ch\u1ec9 r\u00f5 c\u00e1c kho\u1ea3ng tr\u1ed1ng. \"Highlight\" = \u0111\u01b0a s\u1ef1 ch\u00fa \u00fd \u0111\u1ebfn \u0111i\u1ec1u quan tr\u1ecdng. \"Reveal/uncover\" = l\u1ea7n \u0111\u1ea7u ti\u1ebft l\u1ed9 (nh\u01b0ng \"gaps\" th\u01b0\u1eddng \u0111\u00e3 bi\u1ebft, ch\u1ec9 ch\u01b0a \u0111\u01b0\u1ee3c ch\u00fa \u00fd \u0111\u00fang m\u1ee9c)."}, {"id": "vc-h04", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "To remain _____ in the long term, the company must invest in both talent and technology.", "options": ["viable", "profitable", "competitive", "sustainable"], "answer": 3, "explanation": "\"Remain sustainable in the long term\" = duy tr\u00ec b\u1ec1n v\u1eefng. \"Sustainable\" l\u00e0 t\u1eeb chuy\u00ean bi\u1ec7t trong ng\u1eef c\u1ea3nh chi\u1ebfn l\u01b0\u1ee3c d\u00e0i h\u1ea1n c\u1ee7a doanh nghi\u1ec7p."}, {"id": "vc-h05", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The government's decision to _____ import tariffs was met with resistance from local manufacturers.", "options": ["lower", "cut", "reduce", "slash"], "answer": 3, "explanation": "\"Slash tariffs\" = c\u1eaft gi\u1ea3m m\u1ea1nh (50%+). \"Slash\" c\u00f3 h\u00e0m \u00fd gi\u1ea3m \u0111\u1ed9t ng\u1ed9t v\u00e0 m\u1ea1nh m\u1ebd. T\u1eeb th\u01b0\u1eddng xu\u1ea5t hi\u1ec7n trong b\u1ea3n tin kinh t\u1ebf TOEIC Part 7."}, {"id": "vc-h06", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The acquisition allowed the firm to _____ synergies that would not have been possible independently.", "options": ["harness", "exploit", "leverage", "utilise"], "answer": 0, "explanation": "\"Harness synergies\" = khai th\u00e1c/t\u1eadn d\u1ee5ng (synergies). \"Harness\" c\u00f3 h\u00e0m \u00fd ki\u1ec3m so\u00e1t v\u00e0 t\u1eadn d\u1ee5ng hi\u1ec7u qu\u1ea3 \u2014 th\u01b0\u1eddng d\u00f9ng v\u1edbi \"harness + energy/power/synergies/potential\"."}, {"id": "vc-h07", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The report _____ that without structural reform, the pension system would face insolvency within a decade.", "options": ["warned", "cautioned", "predicted", "projected"], "answer": 1, "explanation": "\"Report cautioned that...\" = b\u00e1o c\u00e1o c\u1ea3nh b\u00e1o r\u1eb1ng. \"Caution\" = c\u1ea3nh b\u00e1o ch\u00ednh th\u1ee9c k\u00e8m theo lo ng\u1ea1i. Ph\u00e2n bi\u1ec7t: \"predict/project\" = d\u1ef1 \u0111o\u00e1n s\u1ed1 li\u1ec7u; \"warn/caution\" = c\u1ea3nh b\u00e1o v\u1ec1 h\u1ec7 qu\u1ea3 x\u1ea5u."}, {"id": "vc-h08", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The auditors were unable to _____ the origin of several large cash transfers in the accounts.", "options": ["trace", "track", "identify", "locate"], "answer": 0, "explanation": "\"Trace the origin of cash transfers\" = truy t\u00ecm ngu\u1ed3n g\u1ed1c. \"Trace\" = theo d\u00f5i ng\u01b0\u1ee3c v\u1ec1 ngu\u1ed3n g\u1ed1c (forensic/audit context). \"Track\" = theo d\u00f5i li\u00ean t\u1ee5c trong th\u1eddi gian. \"Trace origin\" l\u00e0 collocation \u0111i\u1ec1u tra t\u00e0i ch\u00ednh chu\u1ea9n."}, {"id": "vc-h09", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The prolonged strike _____ production output by nearly 40% over the quarter.", "options": ["limited", "reduced", "decreased", "curtailed"], "answer": 3, "explanation": "\"Curtailed production output\" = c\u1eaft gi\u1ea3m \u0111\u1ed9t ng\u1ed9t v\u00e0 m\u1ea1nh. \"Curtail\" = ki\u1ec1m ch\u1ebf, c\u1eaft gi\u1ea3m \u0111\u00e1ng k\u1ec3 do ho\u00e0n c\u1ea3nh b\u1eaft bu\u1ed9c. T\u1eeb n\u00e2ng cao th\u01b0\u1eddng xu\u1ea5t hi\u1ec7n trong TOEIC reports v\u1ec1 labour disputes."}, {"id": "gi-e01", "part": 5, "type": "gerund-infinitive", "difficulty": "easy", "question": "The manager suggested _____ the meeting to next week.", "options": ["to postpone", "postponing", "postpone", "postponed"], "answer": 1, "explanation": "\"Suggest + V-ing\" = c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh. \"Suggested postponing\" = \u0111\u1ec1 ngh\u1ecb d\u1eddi l\u1ea1i. \"Suggest to postpone\" sai."}, {"id": "gi-e02", "part": 5, "type": "gerund-infinitive", "difficulty": "easy", "question": "The company decided _____ a new software platform.", "options": ["to adopt", "adopting", "adopt", "adopted"], "answer": 0, "explanation": "\"Decide + to-V\" = quy\u1ebft \u0111\u1ecbnh l\u00e0m g\u00ec. \"Decided to adopt\" l\u00e0 c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh."}, {"id": "gi-e03", "part": 5, "type": "gerund-infinitive", "difficulty": "easy", "question": "Please avoid _____ the building through the emergency exit.", "options": ["entered", "to enter", "enter", "entering"], "answer": 3, "explanation": "\"Avoid + V-ing\" = c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh. \"Avoid entering through...\" = tr\u00e1nh \u0111i v\u00e0o qua."}, {"id": "gi-e04", "part": 5, "type": "gerund-infinitive", "difficulty": "easy", "question": "Ms. Lee enjoys _____ at industry conferences.", "options": ["present", "to present", "presenting", "presented"], "answer": 2, "explanation": "\"Enjoy + V-ing\" = c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh. \"Enjoy presenting\" = th\u00edch tr\u00ecnh b\u00e0y. \"Enjoy to present\" sai."}, {"id": "gi-e05", "part": 5, "type": "gerund-infinitive", "difficulty": "easy", "question": "The sales team is planning _____ three new markets next year.", "options": ["entering", "to enter", "enter", "entered"], "answer": 1, "explanation": "\"Plan + to-V\" = l\u00ean k\u1ebf ho\u1ea1ch l\u00e0m g\u00ec. \"Planning to enter\" l\u00e0 c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh."}, {"id": "gi-e06", "part": 5, "type": "gerund-infinitive", "difficulty": "easy", "question": "The company aims _____ its carbon emissions by 30% within five years.", "options": ["to reduce", "reducing", "reduce", "reduced"], "answer": 0, "explanation": "\"Aim + to-V\" = h\u01b0\u1edbng \u0111\u1ebfn, nh\u1eafm \u0111\u1ebfn l\u00e0m g\u00ec. \"Aims to reduce\" l\u00e0 c\u1ea5u tr\u00fac c\u1ed1 \u0111\u1ecbnh."}, {"id": "gi-e07", "part": 5, "type": "gerund-infinitive", "difficulty": "easy", "question": "The staff finished _____ the new equipment before the end of the shift.", "options": ["installed", "to install", "install", "installing"], "answer": 3, "explanation": "\"Finish + V-ing\" = ho\u00e0n th\u00e0nh vi\u1ec7c l\u00e0m g\u00ec. \"Finished installing\" = l\u1eafp xong. \"Finish to install\" sai."}, {"id": "gi-e08", "part": 5, "type": "gerund-infinitive", "difficulty": "easy", "question": "Employees are encouraged _____ their annual leave before December.", "options": ["use", "using", "to use", "used"], "answer": 2, "explanation": "\"Encourage + object + to-V\" = khuy\u1ebfn kh\u00edch ai l\u00e0m g\u00ec. \"Encouraged to use\" (passive structure)."}, {"id": "gi-e09", "part": 5, "type": "gerund-infinitive", "difficulty": "easy", "question": "The workshop helps participants _____ their presentation skills.", "options": ["to develop", "develop", "developing", "developed"], "answer": 1, "explanation": "\"Help + object + V (bare infinitive)\" = gi\u00fap ai l\u00e0m g\u00ec. \"Helps participants develop\" \u2014 sau \"help\" d\u00f9ng V nguy\u00ean th\u1ec3 kh\u00f4ng c\u1ea7n \"to\"."}, {"id": "gi-h01", "part": 5, "type": "gerund-infinitive", "difficulty": "hard", "question": "The consultant recommended that the firm _____ its pricing structure before the product launch.", "options": ["to revisit", "revisiting", "revisit", "revisited"], "answer": 2, "explanation": "Subjunctive sau \"recommended that\": V nguy\u00ean th\u1ec3 kh\u00f4ng chia. \"Recommended that the firm revisit\" \u2014 kh\u00f4ng ph\u1ea3i \"revisiting\" hay \"to revisit\"."}, {"id": "gi-h02", "part": 5, "type": "gerund-infinitive", "difficulty": "hard", "question": "The contract stipulates that both parties _____ the terms every six months.", "options": ["reviewing", "review", "to review", "reviewed"], "answer": 1, "explanation": "Subjunctive sau \"stipulates that\": V nguy\u00ean th\u1ec3. \"Stipulates that both parties review\" \u2014 h\u1ee3p \u0111\u1ed3ng ph\u00e1p l\u00fd th\u01b0\u1eddng d\u00f9ng subjunctive trong \u0111i\u1ec1u kho\u1ea3n."}, {"id": "gi-h03", "part": 5, "type": "gerund-infinitive", "difficulty": "hard", "question": "I distinctly remember _____ the report before the deadline, yet the system shows no submission.", "options": ["submitting", "to submit", "submit", "to have submitted"], "answer": 0, "explanation": "\"Remember + V-ing\" = nh\u1edb l\u1ea1i \u0111\u00e3 l\u00e0m (qu\u00e1 kh\u1ee9). \"Remember submitting\" = nh\u1edb \u0111\u00e3 n\u1ed9p. \"Remember to submit\" = nh\u1edb ph\u1ea3i n\u1ed9p (t\u01b0\u01a1ng lai). Ng\u1eef c\u1ea3nh \"yet system shows no submission\" \u2192 nh\u1edb l\u1ea1i vi\u1ec7c \u0111\u00e3 l\u00e0m."}, {"id": "gi-h04", "part": 5, "type": "gerund-infinitive", "difficulty": "hard", "question": "The new regulation requires all financial institutions _____ suspicious transactions within 24 hours.", "options": ["having reported", "reporting", "report", "to report"], "answer": 3, "explanation": "\"Require + object + to-V\" = y\u00eau c\u1ea7u ai l\u00e0m g\u00ec. \"Requires institutions to report\" \u2014 \"require\" b\u1eaft bu\u1ed9c d\u00f9ng to-infinitive sau object (kh\u00e1c \"suggest/recommend\" d\u00f9ng V-ing ho\u1eb7c subjunctive)."}, {"id": "gi-h05", "part": 5, "type": "gerund-infinitive", "difficulty": "hard", "question": "The director regrets _____ the stakeholders of the budget cuts earlier in the process.", "options": ["not informing", "not to inform", "not having informed", "to not inform"], "answer": 2, "explanation": "\"Regret + not having + V3\" = ti\u1ebfc v\u1ec1 vi\u1ec7c \u0111\u00e3 kh\u00f4ng l\u00e0m (qu\u00e1 kh\u1ee9 ho\u00e0n th\u00e0nh). \"Regrets not having informed\" = ti\u1ebfc v\u00ec \u0111\u00e3 kh\u00f4ng th\u00f4ng b\u00e1o. \"Regret not informing\" c\u0169ng \u0111\u00fang nh\u01b0ng \"not having informed\" nh\u1ea5n m\u1ea1nh t\u00ednh ho\u00e0n th\u00e0nh r\u00f5 h\u01a1n."}, {"id": "rc-e01", "part": 5, "type": "relative-clause", "difficulty": "easy", "question": "The woman _____ called yesterday left a message for you.", "options": ["which", "whom", "who", "whose"], "answer": 2, "explanation": "\"Who\" = ch\u1ec9 ng\u01b0\u1eddi, l\u00e0m ch\u1ee7 ng\u1eef c\u1ee7a m\u1ec7nh \u0111\u1ec1 quan h\u1ec7. \"The woman who called\" = ng\u01b0\u1eddi ph\u1ee5 n\u1eef \u0111\u00e3 g\u1ecdi \u0111i\u1ec7n."}, {"id": "rc-e02", "part": 5, "type": "relative-clause", "difficulty": "easy", "question": "The laptop _____ I ordered online arrived this morning.", "options": ["who", "that", "whom", "whose"], "answer": 1, "explanation": "\"That\" = ch\u1ec9 v\u1eadt, l\u00e0m t\u00e2n ng\u1eef trong m\u1ec7nh \u0111\u1ec1 h\u1ea1n \u0111\u1ecbnh. \"The laptop that I ordered\" = chi\u1ebfc laptop m\u00e0 t\u00f4i \u0111\u1eb7t."}, {"id": "rc-e03", "part": 5, "type": "relative-clause", "difficulty": "easy", "question": "This is the hotel _____ we stayed during the conference.", "options": ["where", "which", "that", "when"], "answer": 0, "explanation": "\"Where\" = ch\u1ec9 n\u01a1i ch\u1ed1n trong m\u1ec7nh \u0111\u1ec1 quan h\u1ec7. \"The hotel where we stayed\" = kh\u00e1ch s\u1ea1n n\u01a1i ch\u00fang t\u00f4i \u1edf."}, {"id": "rc-e04", "part": 5, "type": "relative-clause", "difficulty": "easy", "question": "The manager _____ office is on the fifth floor will attend the meeting.", "options": ["that", "who", "which", "whose"], "answer": 3, "explanation": "\"Whose\" = s\u1edf h\u1eefu c\u00e1ch. \"The manager whose office is on the fifth floor\" = ng\u01b0\u1eddi qu\u1ea3n l\u00fd c\u00f3 v\u0103n ph\u00f2ng \u1edf t\u1ea7ng 5."}, {"id": "rc-e05", "part": 5, "type": "relative-clause", "difficulty": "easy", "question": "Please refer to the guidelines _____ were distributed at last month's meeting.", "options": ["whom", "who", "that", "what"], "answer": 2, "explanation": "\"That\" = ch\u1ec9 v\u1eadt/\u0111\u1ed3 v\u1eadt, l\u00e0m ch\u1ee7 ng\u1eef c\u1ee7a m\u1ec7nh \u0111\u1ec1 h\u1ea1n \u0111\u1ecbnh. \"Guidelines that were distributed\" = h\u01b0\u1edbng d\u1eabn \u0111\u00e3 \u0111\u01b0\u1ee3c ph\u00e1t."}, {"id": "rc-h01", "part": 5, "type": "relative-clause", "difficulty": "hard", "question": "The firm acquired three companies, _____ was a major player in the logistics sector.", "options": ["some of which", "each of whom", "both of which", "one of which"], "answer": 3, "explanation": "\"One of which\" = m\u1ed9t trong s\u1ed1 \u0111\u00f3 (ch\u1ec9 v\u1eadt). M\u1ec7nh \u0111\u1ec1 quan h\u1ec7 s\u1ed1 l\u01b0\u1ee3ng: \"one/some/most/all of which\" th\u01b0\u1eddng g\u1eb7p trong TOEIC Part 5 n\u00e2ng cao."}, {"id": "rc-h02", "part": 5, "type": "relative-clause", "difficulty": "hard", "question": "The candidate _____ credentials impressed the panel most was offered the position immediately.", "options": ["that", "who", "whose", "of whom the"], "answer": 2, "explanation": "\"Whose credentials\" = s\u1edf h\u1eefu k\u00e9p (candidate's credentials). \"The candidate whose credentials impressed\" \u2014 whose trong m\u1ec7nh \u0111\u1ec1 quan h\u1ec7 ch\u1ec9 s\u1edf h\u1eefu c\u1ea3 ng\u01b0\u1eddi l\u1eabn v\u1eadt."}, {"id": "rc-h03", "part": 5, "type": "relative-clause", "difficulty": "hard", "question": "The terms of the agreement, _____ were drafted by both legal teams, remain binding for five years.", "options": ["that", "which", "as", "what"], "answer": 1, "explanation": "M\u1ec7nh \u0111\u1ec1 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh (c\u00f3 d\u1ea5u ph\u1ea9y) + ch\u1ec9 v\u1eadt/n\u1ed9i dung \u2192 \"which\". Kh\u00f4ng d\u00f9ng \"that\" trong m\u1ec7nh \u0111\u1ec1 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh. \"The terms...which were drafted...\" = \u0111i\u1ec1u kho\u1ea3n, nh\u1eefng \u0111i\u1ec1u kho\u1ea3n n\u00e0y \u0111\u01b0\u1ee3c so\u1ea1n th\u1ea3o b\u1edfi..."}, {"id": "rc-h04", "part": 5, "type": "relative-clause", "difficulty": "hard", "question": "The board approved the plan _____ the CEO had long advocated.", "options": ["for which", "which", "that", "in which"], "answer": 0, "explanation": "\"The plan for which the CEO had long advocated\" = k\u1ebf ho\u1ea1ch m\u00e0 CEO \u0111\u00e3 l\u00e2u nay v\u1eadn \u0111\u1ed9ng. Gi\u1edbi t\u1eeb tr\u01b0\u1edbc which (formal): \"advocate for\" \u2192 \"for which\". C\u1ea5u tr\u00fac n\u00e2ng cao th\u01b0\u1eddng g\u1eb7p trong TOEIC Part 5 level 700+."}, {"id": "sv-e01", "part": 5, "type": "subject-verb", "difficulty": "easy", "question": "All employees _____ required to attend the safety training.", "options": ["are", "is", "was", "has been"], "answer": 0, "explanation": "\"All employees\" = ch\u1ee7 ng\u1eef s\u1ed1 nhi\u1ec1u \u2192 \"are\". \"All + plural noun\" lu\u00f4n d\u00f9ng \u0111\u1ed9ng t\u1eeb s\u1ed1 nhi\u1ec1u."}, {"id": "sv-e02", "part": 5, "type": "subject-verb", "difficulty": "easy", "question": "The list of requirements _____ available on the company's website.", "options": ["were", "are", "have been", "is"], "answer": 3, "explanation": "\"The list\" = ch\u1ee7 ng\u1eef s\u1ed1 \u00edt (kh\u00f4ng ph\u1ea3i \"requirements\") \u2192 \"is\". C\u1ee5m gi\u1edbi t\u1eeb \"of requirements\" kh\u00f4ng \u1ea3nh h\u01b0\u1edfng \u0111\u1ebfn s\u1ed1 c\u1ee7a \u0111\u1ed9ng t\u1eeb."}, {"id": "sv-e03", "part": 5, "type": "subject-verb", "difficulty": "easy", "question": "Each department _____ responsible for submitting its own quarterly report.", "options": ["have", "are", "is", "were"], "answer": 2, "explanation": "\"Each + singular noun\" \u2192 \u0111\u1ed9ng t\u1eeb s\u1ed1 \u00edt. \"Each department is responsible\" \u2014 \"each\" lu\u00f4n d\u00f9ng s\u1ed1 \u00edt."}, {"id": "sv-e04", "part": 5, "type": "subject-verb", "difficulty": "easy", "question": "The team members _____ working overtime to meet the project deadline.", "options": ["is", "are", "was", "has been"], "answer": 1, "explanation": "\"The team members\" = ch\u1ee7 ng\u1eef s\u1ed1 nhi\u1ec1u (members) \u2192 \"are\". Ch\u00fa \u00fd: \"The team is\" (t\u1eadp th\u1ec3) vs \"The team members are\" (c\u00e1c c\u00e1 nh\u00e2n)."}, {"id": "sv-e05", "part": 5, "type": "subject-verb", "difficulty": "easy", "question": "Neither the manager nor the staff _____ aware of the schedule change.", "options": ["was", "were", "is", "are"], "answer": 1, "explanation": "\"Neither A nor B\" + B = \"staff\" (plural) \u2192 \u0111\u1ed9ng t\u1eeb chia theo B (s\u1ed1 nhi\u1ec1u) \u2192 \"were\". Quy t\u1eafc: verb chia theo ch\u1ee7 ng\u1eef g\u1ea7n nh\u1ea5t."}, {"id": "sv-h01", "part": 5, "type": "subject-verb", "difficulty": "hard", "question": "Not only the equipment but also the operators _____ undergone rigorous safety training.", "options": ["has", "have", "had", "was"], "answer": 1, "explanation": "\"Not only A but also B\" \u2192 verb chia theo B = \"the operators\" (plural) \u2192 \"have undergone\". Quy t\u1eafc proximity: verb chia theo ch\u1ee7 ng\u1eef g\u1ea7n nh\u1ea5t (B)."}, {"id": "sv-h02", "part": 5, "type": "subject-verb", "difficulty": "hard", "question": "A series of workshops _____ scheduled to run every Friday throughout the quarter.", "options": ["has been", "have been", "were", "are"], "answer": 0, "explanation": "\"A series of + plural noun\" \u2192 verb s\u1ed1 \u00edt (nh\u01b0 \"a group of\", \"a number of\"). \"A series has been scheduled\" \u2014 \"series\" l\u00e0 head noun = s\u1ed1 \u00edt."}, {"id": "sv-h03", "part": 5, "type": "subject-verb", "difficulty": "hard", "question": "The board, together with all senior managers, _____ invited to the CEO's keynote address.", "options": ["are", "have been", "were", "has been"], "answer": 3, "explanation": "\"The board, together with...\" \u2014 \"together with\" kh\u00f4ng ph\u1ea3i li\u00ean t\u1eeb n\u1ed1i, kh\u00f4ng l\u00e0m s\u1ed1 nh\u00e2n \u0111\u00f4i. Verb chia theo \"the board\" = s\u1ed1 \u00edt \u2192 \"has been invited\"."}, {"id": "sv-h04", "part": 5, "type": "subject-verb", "difficulty": "hard", "question": "Two thirds of the workforce _____ expected to transition to the new hybrid model.", "options": ["was", "is", "are", "has been"], "answer": 2, "explanation": "\"Two thirds of + plural noun (workforce)\" \u2192 verb s\u1ed1 nhi\u1ec1u. Fraction + of + plural noun \u2192 plural verb. \"Two thirds are expected\" \u2014 ng\u01b0\u1ee3c l\u1ea1i \"Two thirds of the budget is\" (budget = kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c)."}, {"id": "nc-e01", "part": 5, "type": "noun-clauses", "difficulty": "easy", "question": "The manager asked _____ the report was ready.", "options": ["that", "what", "if", "how"], "answer": 2, "explanation": "\"Asked if the report was ready\" = h\u1ecfi xem c\u00f3 s\u1eb5n kh\u00f4ng (Yes/No gi\u00e1n ti\u1ebfp). \"If\" d\u00f9ng sau \"ask/wonder/check\" khi c\u00e2u h\u1ecfi gi\u00e1n ti\u1ebfp Yes/No."}, {"id": "nc-e02", "part": 5, "type": "noun-clauses", "difficulty": "easy", "question": "Please confirm _____ you will attend the training session.", "options": ["if", "whether", "that", "what"], "answer": 1, "explanation": "\"Confirm whether you will attend\" = x\u00e1c nh\u1eadn xem c\u00f3 tham d\u1ef1 kh\u00f4ng. \"Whether\" sau \"confirm\" trang tr\u1ecdng h\u01a1n \"if\"."}, {"id": "nc-e03", "part": 5, "type": "noun-clauses", "difficulty": "easy", "question": "The supervisor explained _____ the new system works.", "options": ["how", "that", "what", "which"], "answer": 0, "explanation": "\"Explained how the system works\" = gi\u1ea3i th\u00edch c\u00e1ch h\u1ec7 th\u1ed1ng ho\u1ea1t \u0111\u1ed9ng. \"How + S + V\" = m\u1ec7nh \u0111\u1ec1 danh t\u1eeb c\u00e1ch th\u1ee9c."}, {"id": "nc-e04", "part": 5, "type": "noun-clauses", "difficulty": "easy", "question": "I am not sure _____ the meeting has been rescheduled.", "options": ["when", "if", "that", "whether"], "answer": 3, "explanation": "\"Not sure whether...\" = kh\u00f4ng ch\u1eafc li\u1ec7u c\u00f3... \"Whether\" ph\u1ed5 bi\u1ebfn sau \"not sure/uncertain/doubtful\"."}, {"id": "nc-e05", "part": 5, "type": "noun-clauses", "difficulty": "easy", "question": "The notice states _____ all visitors must sign in at reception.", "options": ["how", "what", "that", "which"], "answer": 2, "explanation": "\"States that all visitors must...\" = tuy\u00ean b\u1ed1 r\u1eb1ng. \"That\" d\u1eabn m\u1ec7nh \u0111\u1ec1 danh t\u1eeb kh\u1eb3ng \u0111\u1ecbnh (affirm)."}, {"id": "nc-h01", "part": 5, "type": "noun-clauses", "difficulty": "hard", "question": "_____ the company chooses to restructure will depend on the outcome of the market analysis.", "options": ["Whether", "How", "What", "That"], "answer": 0, "explanation": "\"Whether...will depend on...\" = li\u1ec7u...c\u00f3 ph\u1ee5 thu\u1ed9c v\u00e0o... \"Whether\" l\u00e0m ch\u1ee7 ng\u1eef c\u00e2u (Yes/No question). \"Whether the company restructures\" = li\u1ec7u c\u00f3 t\u00e1i c\u01a1 c\u1ea5u hay kh\u00f4ng."}, {"id": "nc-h02", "part": 5, "type": "noun-clauses", "difficulty": "hard", "question": "The investigative committee recommended _____ the CFO _____ from his duties pending review.", "options": ["that / suspend", "that / is suspended", "that / be suspended", "for / to be suspended"], "answer": 2, "explanation": "\"Recommend that + S + V (subjunctive)\" = V nguy\u00ean th\u1ec3 kh\u00f4ng chia. \"That the CFO be suspended\" \u2014 b\u1ecb \u0111\u1ed9ng subjunctive: be + V3."}, {"id": "nc-h03", "part": 5, "type": "noun-clauses", "difficulty": "hard", "question": "The proposal raises the question of _____ current policies adequately address emerging risks.", "options": ["if", "whether", "that", "how"], "answer": 1, "explanation": "\"The question of + whether\" = v\u1ea5n \u0111\u1ec1 li\u1ec7u c\u00f3... \"Whether\" sau \"the question of / the issue of\" (gi\u1edbi t\u1eeb). \"If\" kh\u00f4ng \u0111\u1ee9ng sau gi\u1edbi t\u1eeb."}, {"id": "nc-h04", "part": 5, "type": "noun-clauses", "difficulty": "hard", "question": "What the board found most troubling _____ the lack of transparency in the procurement process.", "options": ["was", "were", "is being", "has been"], "answer": 0, "explanation": "\"What the board found most troubling\" = m\u1ec7nh \u0111\u1ec1 danh t\u1eeb l\u00e0m ch\u1ee7 ng\u1eef \u2192 singular verb \"was\". \"What...was the lack\" \u2014 What-clause l\u00e0m ch\u1ee7 ng\u1eef s\u1ed1 \u00edt."}, {"id": "qn-e01", "part": 5, "type": "quantifiers", "difficulty": "easy", "question": "_____ employees attended the seminar, which exceeded expectations.", "options": ["A lot", "Much", "Many", "Several of"], "answer": 2, "explanation": "\"Many employees\" = nhi\u1ec1u nh\u00e2n vi\u00ean (danh t\u1eeb \u0111\u1ebfm \u0111\u01b0\u1ee3c s\u1ed1 nhi\u1ec1u). \"Much\" d\u00f9ng cho kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c. \"Many\" chu\u1ea9n nh\u1ea5t trong v\u0103n phong trang tr\u1ecdng."}, {"id": "qn-e02", "part": 5, "type": "quantifiers", "difficulty": "easy", "question": "There is _____ space in the new office for a small lounge area.", "options": ["many", "enough", "lots", "several"], "answer": 1, "explanation": "\"Enough space\" = \u0111\u1ee7 kh\u00f4ng gian (space = kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c). \"Enough + uncountable\" l\u00e0 c\u1ea5u tr\u00fac \u0111\u01a1n gi\u1ea3n nh\u1ea5t."}, {"id": "qn-e03", "part": 5, "type": "quantifiers", "difficulty": "easy", "question": "_____ of the survey respondents reported satisfaction with the new system.", "options": ["Most", "Almost", "Plenty", "Lot"], "answer": 0, "explanation": "\"Most of the respondents\" = h\u1ea7u h\u1ebft s\u1ed1 ng\u01b0\u1eddi. \"Most of + the + noun\" l\u00e0 c\u1ea5u tr\u00fac quantifier chu\u1ea9n."}, {"id": "qn-e04", "part": 5, "type": "quantifiers", "difficulty": "easy", "question": "We have _____ time before the deadline, so we can review the document carefully.", "options": ["lots", "many", "a lot", "plenty of"], "answer": 3, "explanation": "\"Plenty of time\" = r\u1ea5t nhi\u1ec1u th\u1eddi gian (time = kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c). \"Plenty of\" d\u00f9ng cho c\u1ea3 \u0111\u1ebfm \u0111\u01b0\u1ee3c v\u00e0 kh\u00f4ng \u0111\u1ebfm \u0111\u01b0\u1ee3c."}, {"id": "qn-e05", "part": 5, "type": "quantifiers", "difficulty": "easy", "question": "_____ staff member must complete the online compliance module by Friday.", "options": ["Each of", "All", "Every", "Many"], "answer": 2, "explanation": "\"Every staff member\" = m\u1ecdi nh\u00e2n vi\u00ean + s\u1ed1 \u00edt. \"Every + singular noun + singular verb\". \"All staff\" c\u0169ng \u0111\u00fang nh\u01b0ng \"every\" + singular ph\u1ed5 bi\u1ebfn h\u01a1n trong quy \u0111\u1ecbnh."}, {"id": "qn-h01", "part": 5, "type": "quantifiers", "difficulty": "hard", "question": "_____ the proposals submitted were found to be technically sound by the evaluation committee.", "options": ["Little of", "A few of", "Few", "Few of"], "answer": 3, "explanation": "\"Few of the proposals\" = m\u1ed9t s\u1ed1 \u00edt trong s\u1ed1 c\u00e1c \u0111\u1ec1 xu\u1ea5t (c\u00f3 \"the\" \u2192 \"few of the\"). Ph\u00e2n bi\u1ec7t: \"few proposals\" (r\u1ea5t \u00edt, kh\u00f4ng c\u00f3 \"the\") vs \"few of the proposals\" (\u00edt trong s\u1ed1 nh\u1eefng c\u00e1i \u0111\u00e3 bi\u1ebft)."}, {"id": "qn-h02", "part": 5, "type": "quantifiers", "difficulty": "hard", "question": "The committee reviewed _____ option carefully before arriving at a unanimous decision.", "options": ["all", "each", "every", "both"], "answer": 2, "explanation": "\"Every option\" = t\u1eebng l\u1ef1a ch\u1ecdn (nh\u1ea5n m\u1ea1nh t\u00ednh to\u00e0n di\u1ec7n). \"Every + singular\" nh\u1ea5n m\u1ea1nh kh\u00f4ng b\u1ecf s\u00f3t b\u1ea5t k\u1ef3 c\u00e1i n\u00e0o. Kh\u00e1c \"each\" (xem x\u00e9t ri\u00eang l\u1ebb t\u1eebng c\u00e1i) \u2014 ng\u1eef c\u1ea3nh n\u00e0y nh\u1ea5n m\u1ea1nh t\u1ed5ng th\u1ec3."}, {"id": "qn-h03", "part": 5, "type": "quantifiers", "difficulty": "hard", "question": "_____ the board members voted in favor; the remainder abstained.", "options": ["Most of", "The majority of", "Several of", "The bulk of"], "answer": 1, "explanation": "\"The majority of board members\" = \u0111a s\u1ed1 th\u00e0nh vi\u00ean h\u1ed9i \u0111\u1ed3ng (exact quantifier). \"The majority of\" d\u00f9ng khi mu\u1ed1n n\u00f3i ch\u00ednh x\u00e1c v\u1ec1 nh\u00f3m l\u1edbn h\u01a1n \u2014 hay g\u1eb7p trong bi\u00ean b\u1ea3n h\u1ecdp TOEIC."}, {"id": "qn-h04", "part": 5, "type": "quantifiers", "difficulty": "hard", "question": "With _____ resources available, the project team had to prioritize tasks carefully.", "options": ["scarce", "limited", "few", "little"], "answer": 1, "explanation": "\"With limited resources\" = v\u1edbi ngu\u1ed3n l\u1ef1c h\u1ea1n h\u1eb9p. \"Limited\" l\u00e0 t\u00ednh t\u1eeb + noun. \"Scarce resources\" c\u0169ng \u0111\u00fang nh\u01b0ng \"limited resources\" l\u00e0 collocation chu\u1ea9n h\u01a1n trong TOEIC chi\u1ebfn l\u01b0\u1ee3c."}, {"id": "at-e01", "part": 5, "type": "adverb-time", "difficulty": "easy", "question": "Please submit the form _____ the deadline to ensure your application is considered.", "options": ["before", "until", "by", "after"], "answer": 0, "explanation": "\"Before the deadline\" = tr\u01b0\u1edbc th\u1eddi h\u1ea1n. \"Before\" = tr\u01b0\u1edbc khi m\u1ed9t th\u1eddi \u0111i\u1ec3m. \"By the deadline\" = tr\u01b0\u1edbc th\u1eddi h\u1ea1n (deadline) \u2014 c\u1ea3 hai \u0111\u00fang nh\u01b0ng \"before\" ph\u1ed5 bi\u1ebfn h\u01a1n."}, {"id": "at-e02", "part": 5, "type": "adverb-time", "difficulty": "easy", "question": "The seminar will begin _____ all participants have registered.", "options": ["after", "when", "while", "until"], "answer": 1, "explanation": "\"Will begin when all have registered\" = s\u1ebd b\u1eaft \u0111\u1ea7u khi t\u1ea5t c\u1ea3 \u0111\u00e3 \u0111\u0103ng k\u00fd. \"When\" = t\u1ea1i th\u1eddi \u0111i\u1ec3m (\u0111i\u1ec3m th\u1eddi gian)."}, {"id": "at-e03", "part": 5, "type": "adverb-time", "difficulty": "easy", "question": "The office remains open _____ 6 p.m. on weekdays.", "options": ["before", "by", "until", "after"], "answer": 2, "explanation": "\"Remains open until 6 p.m.\" = ti\u1ebfp t\u1ee5c m\u1edf c\u1eeda \u0111\u1ebfn 6 gi\u1edd. \"Until\" = k\u00e9o d\u00e0i \u0111\u1ebfn th\u1eddi \u0111i\u1ec3m \u0111\u00f3 (li\u00ean t\u1ee5c)."}, {"id": "at-e04", "part": 5, "type": "adverb-time", "difficulty": "easy", "question": "The team celebrated _____ they heard the news of the contract award.", "options": ["after", "when", "while", "as soon as"], "answer": 1, "explanation": "\"Celebrated when they heard the news\" = \u0103n m\u1eebng khi nghe tin. \"When\" = t\u1ea1i th\u1eddi \u0111i\u1ec3m s\u1ef1 ki\u1ec7n x\u1ea3y ra."}, {"id": "at-e05", "part": 5, "type": "adverb-time", "difficulty": "easy", "question": "The new policy will be effective _____ the first day of next month.", "options": ["from", "on", "at", "in"], "answer": 1, "explanation": "\"Effective on the first day of...\" = c\u00f3 hi\u1ec7u l\u1ef1c v\u00e0o ng\u00e0y... \"On + specific date\" = quy t\u1eafc gi\u1edbi t\u1eeb th\u1eddi gian c\u01a1 b\u1ea3n."}, {"id": "at-e06", "part": 5, "type": "adverb-time", "difficulty": "easy", "question": "_____ the construction is complete, the new wing will accommodate 200 additional staff.", "options": ["Since", "While", "During", "Once"], "answer": 3, "explanation": "\"Once the construction is complete\" = m\u1ed9t khi c\u00f4ng tr\u00ecnh ho\u00e0n th\u00e0nh. \"Once + present simple\" cho m\u1ec7nh \u0111\u1ec1 th\u1eddi gian t\u01b0\u01a1ng lai."}, {"id": "at-e07", "part": 5, "type": "adverb-time", "difficulty": "easy", "question": "The workshop will last _____ two hours, from 10 a.m. to noon.", "options": ["in", "during", "for", "within"], "answer": 2, "explanation": "\"Last for two hours\" = k\u00e9o d\u00e0i trong 2 gi\u1edd. \"For + duration\" = kho\u1ea3ng th\u1eddi gian."}, {"id": "at-h01", "part": 5, "type": "adverb-time", "difficulty": "hard", "question": "_____ the new director had taken charge, productivity levels began to improve noticeably.", "options": ["No sooner had", "Hardly", "Once", "Scarcely had"], "answer": 3, "explanation": "\"Scarcely had + S + V3 + when/before...\" = v\u1eeba m\u1edbi...th\u00ec... \u0110\u00e2y l\u00e0 \u0111\u1ea3o ng\u1eef ph\u1ee7 \u0111\u1ecbnh (inverted negative). \"Scarcely had the new director taken charge when productivity began to improve.\""}, {"id": "at-h02", "part": 5, "type": "adverb-time", "difficulty": "hard", "question": "The entire shipment was cleared through customs _____ normal processing time.", "options": ["in half", "within half", "at half of", "by half of"], "answer": 0, "explanation": "\"Cleared in half the normal processing time\" = \u0111\u01b0\u1ee3c th\u00f4ng quan trong m\u1ed9t n\u1eeda th\u1eddi gian th\u00f4ng th\u01b0\u1eddng. \"In half the time\" = c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong TOEIC logistics."}, {"id": "at-h03", "part": 5, "type": "adverb-time", "difficulty": "hard", "question": "The factory will have been operational for exactly ten years _____ the end of this fiscal year.", "options": ["on", "at", "until", "by"], "answer": 3, "explanation": "\"Will have been operational for ten years by the end of...\" = Future Perfect + \"by + future time point\". \"By\" ch\u1ec9 deadline/th\u1eddi \u0111i\u1ec3m ho\u00e0n th\u00e0nh trong t\u01b0\u01a1ng lai."}, {"id": "at-h04", "part": 5, "type": "adverb-time", "difficulty": "hard", "question": "Employees are advised to complete the mandatory training _____ their probationary period ends.", "options": ["by the time", "before", "prior to", "until"], "answer": 2, "explanation": "\"Prior to their probationary period ending\" = tr\u01b0\u1edbc khi th\u1eddi gian th\u1eed vi\u1ec7c k\u1ebft th\u00fac. \"Prior to + V-ing/noun\" = gi\u1edbi t\u1eeb trang tr\u1ecdng. \"Prior to\" ph\u1ed5 bi\u1ebfn trong v\u0103n b\u1ea3n HR TOEIC."}, {"id": "at-h05", "part": 5, "type": "adverb-time", "difficulty": "hard", "question": "The contract must be renewed _____ the existing terms expire, or the project will be halted.", "options": ["ahead of", "before", "in advance of", "prior to when"], "answer": 1, "explanation": "\"Renewed before the terms expire\" = ph\u1ea3i gia h\u1ea1n tr\u01b0\u1edbc khi \u0111i\u1ec1u kho\u1ea3n h\u1ebft h\u1ea1n. \"Before + clause (S+V)\" l\u00e0 c\u1ea5u tr\u00fac duy nh\u1ea5t \u0111\u00fang trong 4 \u0111\u00e1p \u00e1n v\u00ec \u0111\u1eb1ng sau l\u00e0 clause."}, {"id": "at-h06", "part": 5, "type": "adverb-time", "difficulty": "hard", "question": "Delivery times have shortened considerably _____ the new logistics software was implemented.", "options": ["since", "after", "when", "as"], "answer": 0, "explanation": "\"Shortened considerably since the software was implemented\" = \u0111\u00e3 r\u00fat ng\u1eafn \u0111\u00e1ng k\u1ec3 k\u1ec3 t\u1eeb khi. \"Since + past event\" + Present Perfect (c\u00f3 \"have shortened\") \u2192 \"since\" chu\u1ea9n nh\u1ea5t."}, {"id": "at-h07", "part": 5, "type": "adverb-time", "difficulty": "hard", "question": "The board reached a decision only _____ prolonged negotiations lasting nearly three months.", "options": ["after", "following", "in the wake of", "subsequent to"], "answer": 2, "explanation": "\"Only in the wake of prolonged negotiations\" = ch\u1ec9 sau khi tr\u1ea3i qua. \"In the wake of\" = sau h\u1ec7 qu\u1ea3 c\u1ee7a (s\u1ef1 ki\u1ec7n kh\u00f3 kh\u0103n). T\u1eeb n\u00e2ng cao th\u01b0\u1eddng g\u1eb7p trong TOEIC business news."}, {"id": "be-e01", "part": 5, "type": "business-english", "difficulty": "easy", "question": "Please find _____ the signed contract for your records.", "options": ["attached", "enclosed", "included", "appended"], "answer": 0, "explanation": "\"Please find attached...\" = xin xem t\u00e0i li\u1ec7u \u0111\u00ednh k\u00e8m. C\u1ee5m c\u1ed1 \u0111\u1ecbnh trong email: \"Please find attached/enclosed\". \"Attached\" d\u00f9ng cho email, \"enclosed\" cho th\u01b0 tay."}, {"id": "be-e02", "part": 5, "type": "business-english", "difficulty": "easy", "question": "We _____ to confirm your appointment scheduled for Thursday at 2 p.m.", "options": ["are writing", "write", "wrote", "write to you"], "answer": 0, "explanation": "\"We are writing to confirm...\" = Ch\u00fang t\u00f4i vi\u1ebft th\u01b0 \u0111\u1ec3 x\u00e1c nh\u1eadn... C\u1ee5m m\u1edf \u0111\u1ea7u email trang tr\u1ecdng chu\u1ea9n."}, {"id": "be-e03", "part": 5, "type": "business-english", "difficulty": "easy", "question": "Should you require any further assistance, please do not _____ to contact us.", "options": ["think twice", "worry", "hesitate", "wait"], "answer": 2, "explanation": "\"Please do not hesitate to contact us\" = c\u1ee5m k\u1ebft th\u00fac email chu\u1ea9n. C\u1ee5m c\u1ed1 \u0111\u1ecbnh trong v\u0103n b\u1ea3n th\u01b0\u01a1ng m\u1ea1i."}, {"id": "be-e04", "part": 5, "type": "business-english", "difficulty": "easy", "question": "We look forward to _____ from you at your earliest convenience.", "options": ["hear", "hearing", "have heard", "be hearing"], "answer": 1, "explanation": "\"Look forward to + V-ing\" = mong s\u1edbm nh\u1eadn \u0111\u01b0\u1ee3c. \"To\" l\u00e0 gi\u1edbi t\u1eeb \u2192 V-ing. \"Hearing from you at your earliest convenience\" = c\u1ee5m k\u1ebft th\u00fac email chu\u1ea9n."}, {"id": "be-h01", "part": 5, "type": "business-english", "difficulty": "hard", "question": "We _____ to draw your attention to Clause 7 of the agreement, which stipulates delivery conditions.", "options": ["wish", "are writing", "would like", "desire"], "answer": 2, "explanation": "\"Would like to draw your attention to...\" = tr\u00e2n tr\u1ecdng mu\u1ed1n l\u01b0u \u00fd \u0111\u1ebfn. C\u1ee5m email ph\u00e1p l\u00fd trang tr\u1ecdng. \"Wish to\" c\u0169ng \u0111\u00fang nh\u01b0ng \"would like to\" l\u1ecbch s\u1ef1 v\u00e0 ph\u1ed5 bi\u1ebfn h\u01a1n trong TOEIC."}, {"id": "be-h02", "part": 5, "type": "business-english", "difficulty": "hard", "question": "We regret to inform you that your application has been _____ on this occasion.", "options": ["unsuccessful", "rejected", "declined", "refused"], "answer": 0, "explanation": "\"Application has been unsuccessful\" = \u0111\u01a1n kh\u00f4ng th\u00e0nh c\u00f4ng (c\u00e1ch n\u00f3i l\u1ecbch s\u1ef1 nh\u1ea5t khi t\u1eeb ch\u1ed1i). \"Rejected/declined/refused\" tr\u1ef1c ti\u1ebfp h\u01a1n. \"Unsuccessful on this occasion\" = c\u1ee5m HR chu\u1ea9n m\u1ef1c nh\u1ea5t."}, {"id": "be-h03", "part": 5, "type": "business-english", "difficulty": "hard", "question": "_____ to your email of 15 March, please find attached our revised proposal.", "options": ["With reference", "Further", "In response", "Pursuant"], "answer": 0, "explanation": "\"With reference to your email of...\" = li\u00ean quan \u0111\u1ebfn email c\u1ee7a b\u1ea1n ng\u00e0y... C\u1ee5m m\u1edf \u0111\u1ea7u email trang tr\u1ecdng khi tr\u1ea3 l\u1eddi. \"With reference to\" chu\u1ea9n h\u01a1n \"In response to\" khi tr\u00edch d\u1eabn t\u00e0i li\u1ec7u."}, {"id": "be-h04", "part": 5, "type": "business-english", "difficulty": "hard", "question": "The matter has been _____ to our legal department for further review and action.", "options": ["referred", "passed", "forwarded", "escalated"], "answer": 3, "explanation": "\"Escalated to the legal department\" = chuy\u1ec3n l\u00ean c\u1ea5p cao h\u01a1n (ph\u00f2ng ph\u00e1p l\u00fd) \u0111\u1ec3 x\u1eed l\u00fd. \"Escalate\" nh\u1ea5n m\u1ea1nh t\u1ea7m quan tr\u1ecdng v\u00e0 m\u1ee9c \u0111\u1ed9 nghi\u00eam tr\u1ecdng t\u0103ng l\u00ean so v\u1edbi \"refer/forward\"."}, {"id": "pt-e01", "part": 5, "type": "participles", "difficulty": "easy", "question": "The _____ report will be presented to the board next Thursday.", "options": ["updates", "updating", "update", "updated"], "answer": 3, "explanation": "\"The updated report\" = b\u00e1o c\u00e1o \u0111\u00e3 \u0111\u01b0\u1ee3c c\u1eadp nh\u1eadt. V3 (updated) l\u00e0m t\u00ednh t\u1eeb tr\u01b0\u1edbc noun."}, {"id": "pt-e02", "part": 5, "type": "participles", "difficulty": "easy", "question": "_____ the data carefully, the analyst noticed a significant trend.", "options": ["Review", "Reviewed", "Reviewing", "Having reviewed"], "answer": 2, "explanation": "\"Reviewing the data\" = r\u00fat g\u1ecdn ch\u1ee7 \u0111\u1ed9ng: analyst is reviewing. V-ing \u0111\u1ee9ng \u0111\u1ea7u c\u00e2u, c\u00f9ng ch\u1ee7 ng\u1eef v\u1edbi m\u1ec7nh \u0111\u1ec1 ch\u00ednh."}, {"id": "pt-e03", "part": 5, "type": "participles", "difficulty": "easy", "question": "All items _____ out of stock will be restocked within five business days.", "options": ["listed as", "that are out of", "currently", "out of stock"], "answer": 0, "explanation": "\"Items listed as out of stock\" = m\u1eb7t h\u00e0ng \u0111\u01b0\u1ee3c li\u1ec7t k\u00ea l\u00e0 h\u1ebft h\u00e0ng. V3 \"listed as\" + t\u00ednh t\u1eeb = c\u1ee5m ph\u00e2n t\u1eeb b\u1ecb \u0111\u1ed9ng b\u1ed5 ngh\u0129a cho noun."}, {"id": "pt-h01", "part": 5, "type": "participles", "difficulty": "hard", "question": "_____ that the merger would face regulatory challenges, the legal team prepared contingency plans.", "options": ["Anticipating", "Anticipated", "Having anticipated", "Being anticipated"], "answer": 0, "explanation": "\"Anticipating that...\" = d\u1ef1 \u0111o\u00e1n r\u1eb1ng (c\u00f9ng ch\u1ee7 ng\u1eef v\u1edbi \"the legal team\"). V-ing r\u00fat g\u1ecdn m\u1ec7nh \u0111\u1ec1 ch\u1ee7 \u0111\u1ed9ng."}, {"id": "pt-h02", "part": 5, "type": "participles", "difficulty": "hard", "question": "The director, _____ at the proposal's ambition, approved it without revision.", "options": ["having impressed", "impressing", "being impressed", "impressed"], "answer": 3, "explanation": "\"The director, impressed at the proposal\" = ng\u01b0\u1eddi gi\u00e1m \u0111\u1ed1c, b\u1ecb \u1ea5n t\u01b0\u1ee3ng b\u1edfi. V3 sau d\u1ea5u ph\u1ea9y l\u00e0m t\u00ednh t\u1eeb b\u1ed5 ngh\u0129a cho ch\u1ee7 ng\u1eef (non-restrictive participial adjective)."}, {"id": "pt-h03", "part": 5, "type": "participles", "difficulty": "hard", "question": "_____ all the documents, the lawyer submitted the case to the court.", "options": ["Having been reviewed", "Reviewing", "Having reviewed", "Reviewed"], "answer": 2, "explanation": "\"Having reviewed all the documents\" = sau khi \u0111\u00e3 xem x\u00e9t xong t\u1ea5t c\u1ea3 t\u00e0i li\u1ec7u. Having + V3 = ho\u00e0n th\u00e0nh tr\u01b0\u1edbc h\u00e0nh \u0111\u1ed9ng ch\u00ednh (lu\u1eadt s\u01b0 n\u1ed9p h\u1ed3 s\u01a1)."}, {"id": "pt-h04", "part": 5, "type": "participles", "difficulty": "hard", "question": "The factory, _____ for renovation, will reopen in the spring.", "options": ["closing", "closed", "being closed", "having been closed"], "answer": 1, "explanation": "\"The factory, closed for renovation\" = nh\u00e0 m\u00e1y \u0111ang \u0111\u00f3ng c\u1eeda \u0111\u1ec3 c\u1ea3i t\u1ea1o. V3 sau d\u1ea5u ph\u1ea9y = m\u1ec7nh \u0111\u1ec1 quan h\u1ec7 r\u00fat g\u1ecdn b\u1ecb \u0111\u1ed9ng kh\u00f4ng h\u1ea1n \u0111\u1ecbnh."}, {"id": "pv-e01", "part": 5, "type": "passive", "difficulty": "easy", "question": "The annual report _____ every year by the finance team.", "options": ["prepares", "is prepared", "has prepare", "preparing"], "answer": 1, "explanation": "\"Is prepared every year\" = \u0111\u01b0\u1ee3c chu\u1ea9n b\u1ecb h\u00e0ng n\u0103m. Present Simple Passive: is/are + V3. \"Every year\" = th\u00f3i quen \u2192 hi\u1ec7n t\u1ea1i \u0111\u01a1n b\u1ecb \u0111\u1ed9ng."}, {"id": "pv-e02", "part": 5, "type": "passive", "difficulty": "easy", "question": "New employees _____ to complete an orientation session.", "options": ["are required", "require", "is required", "requiring"], "answer": 0, "explanation": "\"Are required to complete\" = \u0111\u01b0\u1ee3c y\u00eau c\u1ea7u ho\u00e0n th\u00e0nh. \"Be required to + V\" l\u00e0 c\u1ee5m b\u1ecb \u0111\u1ed9ng ph\u1ed5 bi\u1ebfn trong quy \u0111\u1ecbnh c\u00f4ng ty."}, {"id": "pv-e03", "part": 5, "type": "passive", "difficulty": "easy", "question": "The package _____ to the wrong address yesterday.", "options": ["has delivered", "delivered", "is delivered", "was delivered"], "answer": 3, "explanation": "\"Was delivered to the wrong address yesterday\" = \u0111\u00e3 \u0111\u01b0\u1ee3c giao nh\u1ea7m \u0111\u1ecba ch\u1ec9. \"Yesterday\" \u2192 Past Simple Passive."}, {"id": "pv-e04", "part": 5, "type": "passive", "difficulty": "easy", "question": "All invoices _____ within 30 days of receipt.", "options": ["are paying", "must pay", "must be paid", "have been paying"], "answer": 2, "explanation": "\"Must be paid within 30 days\" = ph\u1ea3i \u0111\u01b0\u1ee3c thanh to\u00e1n. Modal Passive: modal + be + V3. C\u00e2u quy \u0111\u1ecbnh ph\u1ed5 bi\u1ebfn trong h\u00f3a \u0111\u01a1n TOEIC."}, {"id": "pv-e05", "part": 5, "type": "passive", "difficulty": "easy", "question": "The conference _____ in Singapore for the past three years.", "options": ["has held", "has been held", "is holding", "holds"], "answer": 1, "explanation": "\"Has been held in Singapore\" = \u0111\u00e3 \u0111\u01b0\u1ee3c t\u1ed5 ch\u1ee9c t\u1ea1i Singapore. Present Perfect Passive + \"for the past 3 years\"."}, {"id": "pv-h01", "part": 5, "type": "passive", "difficulty": "hard", "question": "The clause in question _____ to be ambiguous by the independent arbitrator.", "options": ["had been finding", "found", "was found", "was finding"], "answer": 2, "explanation": "\"Was found to be ambiguous\" = \u0111\u01b0\u1ee3c x\u00e1c \u0111\u1ecbnh l\u00e0 m\u01a1 h\u1ed3. C\u1ee5m ph\u00e1p l\u00fd: \"be found to be + adj\" = \u0111\u01b0\u1ee3c t\u00f2a \u00e1n/tr\u1ecdng t\u00e0i ph\u00e1n quy\u1ebft l\u00e0."}, {"id": "pv-h02", "part": 5, "type": "passive", "difficulty": "hard", "question": "The new CEO _____ after a months-long search across three continents.", "options": ["appointed", "was appointed", "had appointed", "was appointing"], "answer": 1, "explanation": "\"Was appointed after a months-long search\" = \u0111\u01b0\u1ee3c b\u1ed5 nhi\u1ec7m sau qu\u00e1 tr\u00ecnh t\u00ecm ki\u1ebfm. Past Simple Passive cho s\u1ef1 ki\u1ec7n \u0111\u00e3 ho\u00e0n th\u00e0nh."}, {"id": "pv-h03", "part": 5, "type": "passive", "difficulty": "hard", "question": "The merger _____ subject to final approval from both regulatory bodies.", "options": ["is to be considered", "is considered", "considers", "has been considering"], "answer": 0, "explanation": "\"Is to be considered subject to...\" = s\u1ebd \u0111\u01b0\u1ee3c xem x\u00e9t v\u1edbi \u0111i\u1ec1u ki\u1ec7n. \"Be to be + V3\" = c\u1ea5u tr\u00fac ph\u00e1p l\u00fd n\u00e2ng cao: \"is to be\" = shall be (d\u1ef1 \u0111\u1ecbnh/quy \u0111\u1ecbnh)."}, {"id": "pv-h04", "part": 5, "type": "passive", "difficulty": "hard", "question": "By the time the audit _____, the discrepancies had already been corrected.", "options": ["were conducting", "conducted", "had been conducted", "was conducted"], "answer": 3, "explanation": "\"By the time the audit was conducted\" = v\u00e0o l\u00fac ki\u1ec3m to\u00e1n \u0111\u01b0\u1ee3c ti\u1ebfn h\u00e0nh. \"By the time + Past Simple\" \u2192 Past Perfect trong m\u1ec7nh \u0111\u1ec1 ch\u00ednh. \"Was conducted\" = b\u1ecb \u0111\u1ed9ng qu\u00e1 kh\u1ee9."}, {"id": "pv-h05", "part": 5, "type": "passive", "difficulty": "hard", "question": "All data _____ on secure servers in compliance with the new privacy regulation.", "options": ["requires to be stored", "is required storing", "is required to be stored", "required storing"], "answer": 2, "explanation": "\"Is required to be stored\" = ph\u1ea3i \u0111\u01b0\u1ee3c l\u01b0u tr\u1eef. Chu\u1ed7i b\u1ecb \u0111\u1ed9ng ph\u1ee9c: \"be required + to be + V3\". C\u1ea5u tr\u00fac ph\u00e1p l\u00fd/ch\u00ednh s\u00e1ch n\u00e2ng cao trong TOEIC."}, {"id": "pv-h06", "part": 5, "type": "passive", "difficulty": "hard", "question": "The research results _____ peer review before they could be published in the journal.", "options": ["had to submit to", "had to be submitted for", "were had to submit", "needed submitting"], "answer": 1, "explanation": "\"Had to be submitted for peer review\" = ph\u1ea3i \u0111\u01b0\u1ee3c n\u1ed9p \u0111\u1ec3 b\u00ecnh duy\u1ec7t. \"Had to be + V3 + for\" = modal perfect passive v\u1edbi gi\u1edbi t\u1eeb m\u1ee5c \u0111\u00edch."}, {"id": "md-e01", "part": 5, "type": "modal", "difficulty": "easy", "question": "You _____ book the meeting room at least 24 hours in advance.", "options": ["should", "could", "might", "would"], "answer": 0, "explanation": "\"Should book in advance\" = n\u00ean \u0111\u1eb7t ph\u00f2ng tr\u01b0\u1edbc. \"Should\" = khuy\u1ebfn ngh\u1ecb nh\u1eb9 nh\u00e0ng nh\u1ea5t trong 4 \u0111\u00e1p \u00e1n."}, {"id": "md-e02", "part": 5, "type": "modal", "difficulty": "easy", "question": "Staff _____ wear protective gear at all times when in the production area.", "options": ["might", "should", "can", "must"], "answer": 3, "explanation": "\"Must wear protective gear\" = b\u1eaft bu\u1ed9c ph\u1ea3i \u0111eo. \"Must\" = ngh\u0129a v\u1ee5 b\u1eaft bu\u1ed9c (quy \u0111\u1ecbnh an to\u00e0n). \"Should\" = khuy\u1ebfn ngh\u1ecb nh\u1eb9 h\u01a1n."}, {"id": "md-e03", "part": 5, "type": "modal", "difficulty": "easy", "question": "Customers _____ return items within 30 days with a valid receipt.", "options": ["will", "must", "may", "shall"], "answer": 2, "explanation": "\"May return items within 30 days\" = \u0111\u01b0\u1ee3c ph\u00e9p tr\u1ea3 h\u00e0ng. \"May\" = cho ph\u00e9p (permission). Ch\u00ednh s\u00e1ch tr\u1ea3 h\u00e0ng th\u01b0\u1eddng d\u00f9ng \"may\"."}, {"id": "md-h01", "part": 5, "type": "modal", "difficulty": "hard", "question": "The shipment _____ arrived by now given that it was dispatched five days ago.", "options": ["must have", "should have", "would have", "could have"], "answer": 1, "explanation": "\"Should have arrived by now\" = l\u1ebd ra \u0111\u00e3 ph\u1ea3i \u0111\u1ebfn r\u1ed3i (k\u1ef3 v\u1ecdng ch\u01b0a \u0111\u01b0\u1ee3c \u0111\u00e1p \u1ee9ng). \"Should have + V3\" = expectation about past. Kh\u00e1c \"must have arrived\" = suy lu\u1eadn ch\u1eafc ch\u1eafn \u0111\u00e3 \u0111\u1ebfn r\u1ed3i."}, {"id": "md-h02", "part": 5, "type": "modal", "difficulty": "hard", "question": "Given the lack of evidence, the committee _____ reached a different conclusion.", "options": ["could have", "should have", "must have", "would have"], "answer": 0, "explanation": "\"Could have reached a different conclusion\" = c\u00f3 th\u1ec3 \u0111\u00e3 \u0111\u01b0a ra k\u1ebft lu\u1eadn kh\u00e1c (nh\u01b0ng kh\u00f4ng). \"Could have + V3\" = kh\u1ea3 n\u0103ng kh\u00f4ng \u0111\u01b0\u1ee3c th\u1ef1c hi\u1ec7n trong qu\u00e1 kh\u1ee9."}, {"id": "md-h03", "part": 5, "type": "modal", "difficulty": "hard", "question": "The project _____ been completed sooner had the team received adequate resources.", "options": ["might have", "could have", "should have", "would have"], "answer": 3, "explanation": "\"Would have been completed sooner had...\" = \u0111\u1ea3o ng\u1eef Type 3. \"Would have + V3\" trong k\u1ebft qu\u1ea3 gi\u1ea3 \u0111\u1ecbnh. \"Had the team received\" = \u0111\u1ea3o ng\u1eef c\u1ee7a \"If the team had received\"."}, {"id": "cd-e01", "part": 5, "type": "conditionals", "difficulty": "easy", "question": "If it _____, the outdoor event will be moved indoors.", "options": ["rained", "will rain", "rains", "has rained"], "answer": 2, "explanation": "C\u00e2u \u0111i\u1ec1u ki\u1ec7n Type 1: If + Present Simple \u2192 will/may + V. \"If it rains\" = n\u1ebfu tr\u1eddi m\u01b0a (c\u00f3 th\u1ec3 x\u1ea3y ra)."}, {"id": "cd-e02", "part": 5, "type": "conditionals", "difficulty": "easy", "question": "You will receive a full refund if you _____ your order within 24 hours.", "options": ["will cancel", "cancel", "cancelled", "have cancelled"], "answer": 1, "explanation": "Type 1: If + Present Simple \u2192 will + V. \"If you cancel\" = n\u1ebfu b\u1ea1n h\u1ee7y. Kh\u00f4ng d\u00f9ng \"will cancel\" trong m\u1ec7nh \u0111\u1ec1 if."}, {"id": "cd-e03", "part": 5, "type": "conditionals", "difficulty": "easy", "question": "If the conference room _____ available, we can hold the meeting there.", "options": ["is", "was", "will be", "would be"], "answer": 0, "explanation": "Type 1: If + Present Simple \u2192 can + V. \"If the room is available\" = n\u1ebfu ph\u00f2ng tr\u1ed1ng. \u0110i\u1ec1u ki\u1ec7n c\u00f3 th\u1ec3 x\u1ea3y ra trong th\u1ef1c t\u1ebf."}, {"id": "cd-e04", "part": 5, "type": "conditionals", "difficulty": "easy", "question": "Please notify the team _____ there are any changes to the schedule.", "options": ["while", "when", "unless", "if"], "answer": 3, "explanation": "\"Notify the team if there are changes\" = th\u00f4ng b\u00e1o cho nh\u00f3m n\u1ebfu c\u00f3 thay \u0111\u1ed5i. \"If\" = \u0111i\u1ec1u ki\u1ec7n (c\u00f3 th\u1ec3 c\u00f3 ho\u1eb7c kh\u00f4ng c\u00f3 thay \u0111\u1ed5i)."}, {"id": "cd-e05", "part": 5, "type": "conditionals", "difficulty": "easy", "question": "If you _____ help with the report, please ask your supervisor.", "options": ["needed", "will need", "need", "have needed"], "answer": 2, "explanation": "Type 1 (l\u1ecbch s\u1ef1): If + Present Simple trong c\u00e2u y\u00eau c\u1ea7u/\u0111\u1ec1 ngh\u1ecb. \"If you need help\" = n\u1ebfu b\u1ea1n c\u1ea7n gi\u00fap \u0111\u1ee1."}, {"id": "cd-e06", "part": 5, "type": "conditionals", "difficulty": "easy", "question": "The discount _____ apply unless you spend a minimum of $100.", "options": ["would not", "will not", "does not", "cannot"], "answer": 1, "explanation": "\"Will not apply unless...\" = s\u1ebd kh\u00f4ng \u00e1p d\u1ee5ng tr\u1eeb khi... \"Unless\" = if...not. Type 1 v\u1edbi \"unless\". \"Will not apply unless\" = c\u1ee5m \u0111i\u1ec1u ki\u1ec7n ph\u1ee7 \u0111\u1ecbnh t\u01b0\u01a1ng lai."}, {"id": "pr-e01", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "The department submitted _____ quarterly report before the deadline.", "options": ["their", "its", "it", "our"], "answer": 1, "explanation": "\"The department submitted its report\" = b\u1ed9 ph\u1eadn n\u1ed9p b\u00e1o c\u00e1o c\u1ee7a m\u00ecnh. \"Its\" = s\u1edf h\u1eefu s\u1ed1 \u00edt (department = singular entity)."}, {"id": "pr-e02", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "Please send the contract to _____ by the end of the week.", "options": ["us", "we", "our", "ours"], "answer": 0, "explanation": "\"Send the contract to us\" = g\u1eedi h\u1ee3p \u0111\u1ed3ng cho ch\u00fang t\u00f4i. \"Us\" = t\u00e2n ng\u1eef (object pronoun). \"We\" = ch\u1ee7 ng\u1eef."}, {"id": "pr-e03", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "The new employee introduced _____ to the rest of the team.", "options": ["hers", "her", "she", "herself"], "answer": 3, "explanation": "\"Introduced herself\" = t\u1ef1 gi\u1edbi thi\u1ec7u b\u1ea3n th\u00e2n (reflexive pronoun). \"Herself\" = \u0111\u1ea1i t\u1eeb ph\u1ea3n th\u00e2n khi ch\u1ee7 ng\u1eef v\u00e0 t\u00e2n ng\u1eef l\u00e0 c\u00f9ng m\u1ed9t ng\u01b0\u1eddi."}, {"id": "pr-e04", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "The CEO gave a speech, and _____ remarks were widely praised.", "options": ["she", "hers", "her", "herself"], "answer": 2, "explanation": "\"Her remarks\" = nh\u1eadn x\u00e9t c\u1ee7a c\u00f4 \u1ea5y. \"Her\" = s\u1edf h\u1eefu t\u00ednh t\u1eeb tr\u01b0\u1edbc danh t\u1eeb \"remarks\"."}, {"id": "pr-h01", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "_____ who registers before March 1 will receive an early-bird discount.", "options": ["Whoever", "Everyone", "Anyone", "Those"], "answer": 0, "explanation": "\"Whoever registers\" = b\u1ea5t c\u1ee9 ai \u0111\u0103ng k\u00fd (relative pronoun + clause). \"Whoever\" = anyone who (mang ngh\u0129a quan h\u1ec7). \"Anyone who\" c\u0169ng \u0111\u00fang nh\u01b0ng \"whoever\" s\u00fac t\u00edch h\u01a1n trong TOEIC."}, {"id": "pr-h02", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "The results of the survey speak for _____ \u2014 no further explanation is needed.", "options": ["itself", "themselves", "them", "their own"], "answer": 1, "explanation": "\"Results speak for themselves\" = idiom c\u1ed1 \u0111\u1ecbnh (k\u1ebft qu\u1ea3 t\u1ef1 n\u00f3i l\u00ean t\u1ea5t c\u1ea3). \"Themselves\" (plural reflexive) = \u0111\u00fang v\u00ec \"results\" l\u00e0 s\u1ed1 nhi\u1ec1u. \"Their own\" kh\u00f4ng d\u00f9ng trong idiom n\u00e0y."}, {"id": "pr-h03", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "The CEO and CFO submitted _____ reports independently, yet reached the same conclusion.", "options": ["their", "respective", "both their", "individual"], "answer": 0, "explanation": "\"Submitted their reports\" = n\u1ed9p b\u00e1o c\u00e1o c\u1ee7a h\u1ecd. \"Their\" l\u00e0 \u0111\u1ea1i t\u1eeb s\u1edf h\u1eefu cho hai ng\u01b0\u1eddi. \"Respective reports\" c\u0169ng \u0111\u00fang nh\u01b0ng \"their\" \u0111\u01a1n gi\u1ea3n v\u00e0 t\u1ef1 nhi\u00ean nh\u1ea5t."}, {"id": "pr-h04", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "Neither candidate was able to demonstrate _____ qualifications met the minimum requirements.", "options": ["that his or her", "if their", "whether their", "that their"], "answer": 3, "explanation": "\"Demonstrate that their qualifications met...\" = ch\u1ee9ng minh r\u1eb1ng tr\u00ecnh \u0111\u1ed9 c\u1ee7a h\u1ecd \u0111\u00e1p \u1ee9ng. \"That + S + V\" = m\u1ec7nh \u0111\u1ec1 danh t\u1eeb t\u00e2n ng\u1eef sau \"demonstrate\". D\u00f9ng \"their\" cho neither (plural in meaning) trong v\u0103n phong hi\u1ec7n \u0111\u1ea1i."}, {"id": "pr-h05", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "The board requested that all department heads resubmit _____ budget proposals with detailed justifications.", "options": ["respective", "the", "their", "its"], "answer": 2, "explanation": "\"All department heads resubmit their budget proposals\" = t\u1ea5t c\u1ea3 tr\u01b0\u1edfng ph\u00f2ng n\u1ed9p l\u1ea1i \u0111\u1ec1 xu\u1ea5t ng\u00e2n s\u00e1ch c\u1ee7a m\u00ecnh. \"Their\" = plural possessive cho \"all department heads\"."}, {"id": "pr-h06", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "Each of the branch managers was asked to share _____ insights on the new market strategy.", "options": ["his or her", "their", "its", "each's"], "answer": 1, "explanation": "\"Each...was asked to share their insights\" = m\u1ed7i ng\u01b0\u1eddi \u0111\u01b0\u1ee3c y\u00eau c\u1ea7u chia s\u1ebb c\u00e1i nh\u00ecn c\u1ee7a m\u00ecnh. \"Their\" singular (informal/modern) d\u00f9ng cho \"each\" khi kh\u00f4ng bi\u1ebft gi\u1edbi t\u00ednh. \"Their\" ng\u00e0y c\u00e0ng ch\u1ea5p nh\u1eadn trong TOEIC hi\u1ec7n \u0111\u1ea1i."}, {"id": "pr-h07", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "The firm has decided to restructure _____ operations to improve efficiency across all divisions.", "options": ["its", "their", "the", "our"], "answer": 0, "explanation": "\"The firm restructures its operations\" = c\u00f4ng ty c\u01a1 c\u1ea5u l\u1ea1i ho\u1ea1t \u0111\u1ed9ng c\u1ee7a m\u00ecnh. \"Its\" = s\u1edf h\u1eefu s\u1ed1 \u00edt cho \"the firm\" (ph\u00e1p nh\u00e2n \u0111\u01a1n)."}, {"id": "ps-e01", "part": 5, "type": "prep-structures", "difficulty": "easy", "question": "The meeting was held _____ behalf of the entire board.", "options": ["on", "in", "at", "for"], "answer": 0, "explanation": "\"On behalf of\" = thay m\u1eb7t cho. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"on behalf of + group\"."}, {"id": "ps-e02", "part": 5, "type": "prep-structures", "difficulty": "easy", "question": "The store offers a 10% discount _____ exchange for completing a feedback survey.", "options": ["for", "on", "at", "in"], "answer": 3, "explanation": "\"In exchange for\" = \u0111\u1ec3 \u0111\u1ed5i l\u1ea5y. C\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh: \"in exchange for + action/item\"."}, {"id": "ps-h01", "part": 5, "type": "prep-structures", "difficulty": "hard", "question": "The proposal was rejected _____ the grounds that it lacked sufficient financial data.", "options": ["for", "on", "at", "with"], "answer": 1, "explanation": "\"Rejected on the grounds that...\" = b\u1ecb b\u00e1c b\u1ecf v\u1edbi l\u00fd do r\u1eb1ng. C\u1ee5m ph\u00e1p l\u00fd chu\u1ea9n: \"on the grounds that + clause\" = v\u00ec l\u00fd do ch\u00ednh th\u1ee9c."}, {"id": "ps-h02", "part": 5, "type": "prep-structures", "difficulty": "hard", "question": "The acquisition is _____ track to be completed ahead of the original deadline.", "options": ["on", "in", "at", "by"], "answer": 0, "explanation": "\"On track to be completed\" = \u0111ang \u0111i \u0111\u00fang ti\u1ebfn \u0111\u1ed9. C\u1ee5m c\u1ed1 \u0111\u1ecbnh: \"on track to do something\" = ti\u1ebfn tri\u1ec3n t\u1ed1t \u0111\u1ec3 \u0111\u1ea1t \u0111\u01b0\u1ee3c."}, {"id": "ps-h03", "part": 5, "type": "prep-structures", "difficulty": "hard", "question": "All procurement decisions must be made _____ strict adherence to the company's purchasing guidelines.", "options": ["through", "in", "by", "with"], "answer": 3, "explanation": "\"With strict adherence to guidelines\" = v\u1edbi s\u1ef1 tu\u00e2n th\u1ee7 nghi\u00eam ng\u1eb7t. \"With + adherence/compliance/reference to\" = c\u1ee5m n\u00e2ng cao trong v\u0103n b\u1ea3n ch\u00ednh s\u00e1ch."}, {"id": "ps-h04", "part": 5, "type": "prep-structures", "difficulty": "hard", "question": "The revenue shortfall was, _____ large part, attributable to unforeseen supply chain delays.", "options": ["to", "for", "in", "by"], "answer": 2, "explanation": "\"In large part, attributable to...\" = ph\u1ea7n l\u1edbn l\u00e0 do. C\u1ee5m: \"in large/great part\" = largely, mostly. Ph\u1ed5 bi\u1ebfn trong b\u00e1o c\u00e1o t\u00e0i ch\u00ednh TOEIC."}, {"id": "sj-e01", "part": 5, "type": "subjunctive", "difficulty": "easy", "question": "The manager recommended that all staff _____ the new safety manual.", "options": ["read", "reads", "reading", "to read"], "answer": 0, "explanation": "\"Recommended that staff read\" = subjunctive sau recommend. V nguy\u00ean th\u1ec3 kh\u00f4ng chia. \"Reads\" sai (subjunctive kh\u00f4ng th\u00eam -s)."}, {"id": "sj-e02", "part": 5, "type": "subjunctive", "difficulty": "easy", "question": "It is important that the invoice _____ submitted before month-end.", "options": ["being", "is", "was", "be"], "answer": 3, "explanation": "\"It is important that + S + be + V3\" = subjunctive b\u1ecb \u0111\u1ed9ng. \"The invoice be submitted\" \u2014 kh\u00f4ng d\u00f9ng \"is\" trong subjunctive."}, {"id": "sj-e03", "part": 5, "type": "subjunctive", "difficulty": "easy", "question": "The committee requires that each application _____ accompanied by two references.", "options": ["was", "is", "be", "will be"], "answer": 2, "explanation": "\"Requires that each application be accompanied\" = subjunctive b\u1ecb \u0111\u1ed9ng sau \"require\". \"Be + V3\" = passive subjunctive."}, {"id": "sj-e04", "part": 5, "type": "subjunctive", "difficulty": "easy", "question": "It is essential that the CEO _____ present at the annual shareholder meeting.", "options": ["is", "be", "was", "will be"], "answer": 1, "explanation": "\"It is essential that the CEO be present\" = subjunctive sau \"essential\". \"Be present\" = V nguy\u00ean th\u1ec3 kh\u00f4ng chia."}, {"id": "sj-e05", "part": 5, "type": "subjunctive", "difficulty": "easy", "question": "The client insists that the project _____ by the agreed deadline.", "options": ["be completed", "is completed", "was completed", "will be completed"], "answer": 0, "explanation": "\"Insists that the project be completed\" = subjunctive b\u1ecb \u0111\u1ed9ng sau \"insist\". \"Be completed\" = b\u1ecb \u0111\u1ed9ng subjunctive."}, {"id": "sj-e06", "part": 5, "type": "subjunctive", "difficulty": "easy", "question": "It is vital that every team member _____ of the new emergency procedures.", "options": ["being informed", "is informed", "was informed", "be informed"], "answer": 3, "explanation": "\"It is vital that every member be informed\" = subjunctive b\u1ecb \u0111\u1ed9ng sau \"vital\". \"Be informed of\" = \u0111\u01b0\u1ee3c th\u00f4ng b\u00e1o v\u1ec1."}, {"id": "p6s-e01", "part": 5, "type": "part6-strategy", "difficulty": "easy", "question": "A Part 6 passage consistently uses past tense throughout. The blank should likely use:", "options": ["Future Continuous", "Present Simple", "Past Simple or Past Perfect", "Present Perfect Continuous"], "answer": 2, "explanation": "T\u00ednh nh\u1ea5t qu\u00e1n th\u00ec (tense consistency) trong Part 6: n\u1ebfu \u0111o\u1ea1n v\u0103n d\u00f9ng past tense nh\u1ea5t qu\u00e1n, ch\u1ed7 tr\u1ed1ng c\u0169ng n\u00ean d\u00f9ng th\u00ec qu\u00e1 kh\u1ee9 (Past Simple ho\u1eb7c Past Perfect) tr\u1eeb khi c\u00f3 t\u1eeb kh\u00f3a th\u00ec r\u00f5 r\u00e0ng kh\u00e1c."}, {"id": "p6s-e02", "part": 5, "type": "part6-strategy", "difficulty": "easy", "question": "The word \"However\" in a Part 6 blank suggests the sentence should:", "options": ["Add to the previous idea", "Contrast with the previous idea", "Give a reason", "Show a result"], "answer": 1, "explanation": "\"However\" = tr\u1ea1ng t\u1eeb t\u01b0\u01a1ng ph\u1ea3n. C\u00e2u ti\u1ebfp theo sau \"However\" ph\u1ea3i th\u1ec3 hi\u1ec7n \u00fd t\u01b0\u01a1ng ph\u1ea3n/\u0111\u1ed1i l\u1eadp v\u1edbi c\u00e2u tr\u01b0\u1edbc. \u0110\u00e2y l\u00e0 quy t\u1eafc li\u00ean k\u1ebft v\u0103n b\u1ea3n c\u01a1 b\u1ea3n trong Part 6."}, {"id": "p6s-h01", "part": 5, "type": "part6-strategy", "difficulty": "hard", "question": "In Part 6, a sentence-insertion blank is preceded by \"Sales increased sharply.\" Which response BEST fits?", "options": ["\"Staff were asked to work overtime.\"", "\"The company was founded in 2005.\"", "\"New products will launch next year.\"", "\"This growth exceeded analyst forecasts.\""], "answer": 3, "explanation": "C\u00e2u \u0111i\u1ec1n ph\u1ea3i (1) li\u00ean k\u1ebft logic v\u1edbi c\u00e2u tr\u01b0\u1edbc (sales increased), (2) th\u00ec nh\u1ea5t qu\u00e1n (past), (3) ti\u1ebfp t\u1ee5c/ph\u00e1t tri\u1ec3n ch\u1ee7 \u0111\u1ec1. \"Exceeded analyst forecasts\" k\u1ebft n\u1ed1i tr\u1ef1c ti\u1ebfp v\u1edbi \"increased sharply\" \u2014 l\u00e0 k\u1ebft qu\u1ea3/h\u1ec7 qu\u1ea3 t\u1ef1 nhi\u00ean nh\u1ea5t."}, {"id": "p6s-h02", "part": 5, "type": "part6-strategy", "difficulty": "hard", "question": "A Part 6 gap requires a linking word. Before the blank: \"The project was delayed.\" After: \"It was completed on time.\" The best connector is:", "options": ["Furthermore", "Therefore", "Nevertheless", "Meanwhile"], "answer": 2, "explanation": "\"Nevertheless\" = tuy nhi\u00ean v\u1eabn (t\u01b0\u01a1ng ph\u1ea3n m\u1ea1nh h\u01a1n). \"Delayed...nevertheless...completed on time\" = b\u1ecb tr\u00ec ho\u00e3n nh\u01b0ng v\u1eabn ho\u00e0n th\u00e0nh \u0111\u00fang h\u1ea1n. \"Therefore\" = do \u0111\u00f3 (h\u1eadu qu\u1ea3), \"furthermore\" = th\u00eam n\u1eefa (b\u1ed5 sung) \u2014 \u0111\u1ec1u sai logic."}, {"id": "pr2-e01", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "The company updated _____ return policy to allow exchanges within 60 days.", "options": ["its", "their", "it", "our"], "answer": 0, "explanation": "\"The company updated its policy\" = c\u00f4ng ty c\u1eadp nh\u1eadt ch\u00ednh s\u00e1ch c\u1ee7a m\u00ecnh. \"Its\" = s\u1edf h\u1eefu s\u1ed1 \u00edt cho ph\u00e1p nh\u00e2n (company)."}, {"id": "pr2-e02", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "Please introduce _____ to the new team members when you arrive.", "options": ["yourself", "you", "your", "yours"], "answer": 0, "explanation": "\"Introduce yourself\" = t\u1ef1 gi\u1edbi thi\u1ec7u b\u1ea3n th\u00e2n. Reflexive pronoun \"yourself\" = \u0111\u1ea1i t\u1eeb ph\u1ea3n th\u00e2n khi ch\u1ee7 ng\u1eef v\u00e0 t\u00e2n ng\u1eef c\u00f9ng l\u00e0 \"you\"."}, {"id": "pr2-e03", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "The two candidates submitted _____ applications before the deadline.", "options": ["their", "its", "his", "our"], "answer": 0, "explanation": "\"The two candidates submitted their applications\" = hai \u1ee9ng vi\u00ean n\u1ed9p \u0111\u01a1n c\u1ee7a h\u1ecd. \"Their\" = s\u1ed1 nhi\u1ec1u s\u1edf h\u1eefu cho \"two candidates\"."}, {"id": "pr2-e04", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "The marketing team presented _____ quarterly results to the board.", "options": ["its", "their", "it", "ours"], "answer": 1, "explanation": "\"The marketing team presented their results\" \u2014 \"team\" c\u00f3 th\u1ec3 d\u00f9ng \"their\" khi nh\u1ea5n m\u1ea1nh c\u00e1c th\u00e0nh vi\u00ean. \"Its\" c\u0169ng \u0111\u00fang n\u1ebfu team l\u00e0 \u0111\u01a1n v\u1ecb. \"Their\" t\u1ef1 nhi\u00ean h\u01a1n v\u1edbi k\u1ebft qu\u1ea3."}, {"id": "pr2-e05", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "Could you please send _____ the revised contract at your earliest convenience?", "options": ["me", "my", "I", "mine"], "answer": 0, "explanation": "\"Send me the contract\" = g\u1eedi h\u1ee3p \u0111\u1ed3ng cho t\u00f4i. \"Me\" = t\u00e2n ng\u1eef gi\u00e1n ti\u1ebfp (indirect object). \"I\" = ch\u1ee7 ng\u1eef, sai v\u1ecb tr\u00ed."}, {"id": "pr2-e06", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "The report is ready. You can access _____ on the company intranet.", "options": ["it", "its", "them", "itself"], "answer": 0, "explanation": "\"Access it\" = truy c\u1eadp n\u00f3 (the report). \"It\" = \u0111\u1ea1i t\u1eeb nh\u00e2n x\u01b0ng thay th\u1ebf danh t\u1eeb v\u1eadt s\u1ed1 \u00edt \"the report\"."}, {"id": "pr2-e07", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "All staff members must wear _____ security passes at all times.", "options": ["their", "its", "our", "your"], "answer": 0, "explanation": "\"All staff members must wear their security passes\" = t\u1ea5t c\u1ea3 nh\u00e2n vi\u00ean ph\u1ea3i \u0111eo th\u1ebb c\u1ee7a m\u00ecnh. \"Their\" = s\u1edf h\u1eefu cho \"all staff members\" (s\u1ed1 nhi\u1ec1u)."}, {"id": "pr2-e08", "part": 5, "type": "pronoun", "difficulty": "easy", "question": "The CEO gave _____ keynote address at the annual conference last Friday.", "options": ["her", "she", "hers", "herself"], "answer": 0, "explanation": "\"Gave her keynote address\" = tr\u00ecnh b\u00e0y b\u00e0i ph\u00e1t bi\u1ec3u c\u1ee7a c\u00f4 \u1ea5y. \"Her\" = s\u1edf h\u1eefu t\u00ednh t\u1eeb tr\u01b0\u1edbc danh t\u1eeb."}, {"id": "pr2-m01", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "_____ of the proposed solutions addresses the root cause of the problem.", "options": ["None", "Any", "Each", "Some"], "answer": 0, "explanation": "\"None of the solutions addresses\" = kh\u00f4ng gi\u1ea3i ph\u00e1p n\u00e0o gi\u1ea3i quy\u1ebft (s\u1ed1 \u00edt). \"None of + plural noun + singular verb\" trong v\u0103n trang tr\u1ecdng. \"Each/Any\" c\u0169ng s\u1ed1 \u00edt nh\u01b0ng mang ngh\u0129a kh\u00e1c."}, {"id": "pr2-m02", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "The board reviewed both proposals and approved _____ with minor modifications.", "options": ["both", "each", "either", "all"], "answer": 0, "explanation": "\"Approved both with minor modifications\" = ph\u00ea duy\u1ec7t c\u1ea3 hai. \"Both\" = c\u1ea3 hai (t\u1ed5ng th\u1ec3). \"Each\" = t\u1eebng c\u00e1i ri\u00eang l\u1ebb. \"Either\" = m\u1ed9t trong hai."}, {"id": "pr2-m03", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "The client and the vendor have reached a settlement that benefits _____ party.", "options": ["either", "each", "both", "every"], "answer": 1, "explanation": "\"Benefits each party\" = c\u00f3 l\u1ee3i cho m\u1ed7i b\u00ean. \"Each party\" = t\u1eebng b\u00ean (number singular). \"Both parties\" = c\u1ea3 hai (plural). Ng\u1eef c\u1ea3nh \"a settlement\" \u2192 \"each party\" nh\u1ea5n m\u1ea1nh c\u1ea3 hai \u0111\u1ec1u h\u01b0\u1edfng l\u1ee3i ri\u00eang."}, {"id": "pr2-m04", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "The director took it upon _____ to resolve the dispute before it escalated.", "options": ["herself", "her", "she", "hers"], "answer": 0, "explanation": "\"Took it upon herself\" = t\u1ef1 m\u00ecnh \u0111\u1ee9ng ra x\u1eed l\u00fd. Idiom c\u1ed1 \u0111\u1ecbnh: \"take it upon oneself/himself/herself to do\". Kh\u00f4ng th\u1ec3 d\u00f9ng \"her\" (possessive) \u1edf \u0111\u00e2y."}, {"id": "pr2-m05", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "The system will update _____ automatically every 24 hours.", "options": ["itself", "its", "it", "them"], "answer": 0, "explanation": "\"Update itself automatically\" = t\u1ef1 c\u1eadp nh\u1eadt. Reflexive pronoun \"itself\" d\u00f9ng khi ch\u1ee7 ng\u1eef v\u00e0 t\u00e2n ng\u1eef c\u00f9ng m\u1ed9t th\u1ef1c th\u1ec3 (system updates system)."}, {"id": "pr2-m06", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "_____ who has not yet submitted their timesheet should do so by noon.", "options": ["Whoever", "Anyone", "Those", "Everyone"], "answer": 1, "explanation": "\"Anyone who has not yet submitted\" = b\u1ea5t k\u1ef3 ai ch\u01b0a n\u1ed9p. \"Anyone who + singular verb\" = m\u1ec7nh \u0111\u1ec1 \u0111i\u1ec1u ki\u1ec7n m\u1edf. \"Those who\" c\u0169ng \u0111\u00fang nh\u01b0ng \"those\" c\u1ea7n danh t\u1eeb (plural implied)."}, {"id": "pr2-m07", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "We have reviewed both candidates and consider _____ to be equally qualified.", "options": ["both", "them", "each", "either"], "answer": 1, "explanation": "\"Consider them to be qualified\" = xem h\u1ecd l\u00e0 \u0111\u1ee7 \u0111i\u1ec1u ki\u1ec7n. \"Them\" = t\u00e2n ng\u1eef thay cho \"both candidates\" \u0111\u00e3 \u0111\u01b0\u1ee3c \u0111\u1ec1 c\u1eadp. \"Both\" s\u1ebd c\u1ea7n \"of them\" sau \u0111\u1ed9ng t\u1eeb."}, {"id": "pr2-m08", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "The sales manager reminded the team that _____ performance would be reviewed quarterly.", "options": ["their", "its", "each", "one's"], "answer": 0, "explanation": "\"Reminded the team that their performance\" = nh\u1eafc nh\u1edf r\u1eb1ng hi\u1ec7u su\u1ea5t c\u1ee7a h\u1ecd. \"Their\" = s\u1edf h\u1eefu nh\u00e2n x\u01b0ng cho \"the team\" (nh\u00f3m ng\u01b0\u1eddi)."}, {"id": "pr2-m09", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "The committee members expressed _____ concerns about the timeline to the chairman.", "options": ["their", "its", "his", "one's"], "answer": 0, "explanation": "\"Expressed their concerns\" = b\u00e0y t\u1ecf lo ng\u1ea1i c\u1ee7a h\u1ecd. \"Their\" = s\u1edf h\u1eefu cho \"committee members\" (s\u1ed1 nhi\u1ec1u)."}, {"id": "pr2-m10", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "The merger agreement allows _____ party to terminate within 30 days if conditions are unmet.", "options": ["either", "any", "both", "each"], "answer": 0, "explanation": "\"Either party to terminate\" = m\u1ed9t trong hai b\u00ean c\u00f3 quy\u1ec1n ch\u1ea5m d\u1ee9t. \"Either\" = b\u1ea5t k\u1ef3 b\u00ean n\u00e0o trong hai (legal context). \"Both\" = c\u1ea3 hai c\u00f9ng l\u00fac (kh\u00f4ng ph\u00f9 h\u1ee3p)."}, {"id": "pr2-m11", "part": 5, "type": "pronoun", "difficulty": "medium", "question": "Staff who have completed the training should record _____ completion in the HR portal.", "options": ["their", "its", "them", "themselves"], "answer": 0, "explanation": "\"Record their completion\" = ghi l\u1ea1i vi\u1ec7c ho\u00e0n th\u00e0nh c\u1ee7a h\u1ecd. \"Their\" = s\u1edf h\u1eefu s\u1edf h\u1eefu cho \"staff who have completed\" (plural referent)."}, {"id": "pr2-h01", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "The proposal was submitted by two consultants, _____ backgrounds are in regulatory compliance.", "options": ["both of whose", "whose both", "both whose", "of whom both"], "answer": 0, "explanation": "\"Two consultants, both of whose backgrounds are...\" = m\u1ec7nh \u0111\u1ec1 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh v\u1edbi s\u1edf h\u1eefu s\u1ed1 l\u01b0\u1ee3ng. \"Both of whose\" = c\u1ea3 hai \u0111\u1ea1i t\u1eeb quan h\u1ec7 s\u1edf h\u1eefu \u2014 c\u1ea5u tr\u00fac formal TOEIC n\u00e2ng cao."}, {"id": "pr2-h02", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "The audit revealed discrepancies in the accounts, _____ have since been corrected.", "options": ["all of which", "each of which", "both of them", "some that"], "answer": 0, "explanation": "\"Discrepancies, all of which have been corrected\" = t\u1ea5t c\u1ea3 nh\u1eefng sai l\u1ec7ch \u0111\u00f3. \"All of which\" = m\u1ec7nh \u0111\u1ec1 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh + to\u00e0n b\u1ed9 s\u1ed1 l\u01b0\u1ee3ng c\u1ee7a antecedent."}, {"id": "pr2-h03", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "The firm appointed three regional managers, only one of _____ had prior experience in the role.", "options": ["whom", "who", "them", "which"], "answer": 0, "explanation": "\"Only one of whom had prior experience\" = ch\u1ec9 m\u1ed9t trong s\u1ed1 h\u1ecd. \"Preposition + whom\" trong m\u1ec7nh \u0111\u1ec1 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh ch\u1ec9 ng\u01b0\u1eddi. \"Them\" kh\u00f4ng l\u00e0m relative pronoun \u0111\u01b0\u1ee3c."}, {"id": "pr2-h04", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "Leadership must ask _____ whether the current strategy is truly serving the company's long-term interests.", "options": ["itself", "themselves", "oneself", "ourselves"], "answer": 1, "explanation": "\"Leadership must ask themselves\" = l\u00e3nh \u0111\u1ea1o (t\u1eadp th\u1ec3) ph\u1ea3i t\u1ef1 h\u1ecfi b\u1ea3n th\u00e2n. \"Themselves\" = plural reflexive cho \"leadership\" hi\u1ec3u l\u00e0 nh\u00f3m. \"Oneself\" = generic (formal/literary); \"ourselves\" = speaker included (sai ng\u1eef c\u1ea3nh)."}, {"id": "pr2-h05", "part": 5, "type": "pronoun", "difficulty": "hard", "question": "The two vendors were asked to revise _____ quotes, after _____ was found to contain calculation errors.", "options": ["their / each", "its / both", "their / both", "each / one"], "answer": 0, "explanation": "\"Revise their quotes, after each was found to contain errors\" = m\u1ed7i b\u1ea3ng b\u00e1o gi\u00e1 b\u1ecb ph\u00e1t hi\u1ec7n l\u1ed7i. \"Their\" (plural possessive) + \"each\" (singular, refers to each quote individually)."}, {"id": "vc2-e01", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The manager sent a _____ to all staff explaining the changes to the leave policy.", "options": ["circular", "newsletter", "brochure", "flyer"], "answer": 0, "explanation": "\"Circular to all staff\" = th\u00f4ng b\u00e1o n\u1ed9i b\u1ed9 g\u1eedi \u0111\u1ebfn t\u1ea5t c\u1ea3 (h\u00ecnh th\u1ee9c v\u0103n b\u1ea3n ch\u00ednh th\u1ee9c). \"Circular\" l\u00e0 thu\u1eadt ng\u1eef chuy\u00ean bi\u1ec7t trong TOEIC v\u0103n ph\u00f2ng cho v\u0103n b\u1ea3n g\u1eedi \u0111\u1ed3ng lo\u1ea1t."}, {"id": "vc2-e02", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The new employee was asked to _____ the orientation session before starting work.", "options": ["complete", "finish", "attend", "join"], "answer": 2, "explanation": "\"Attend an orientation session\" = tham d\u1ef1 bu\u1ed5i \u0111\u1ecbnh h\u01b0\u1edbng. \"Attend a session/seminar/meeting\" l\u00e0 collocation ph\u1ed5 bi\u1ebfn nh\u1ea5t trong HR context TOEIC."}, {"id": "vc2-e03", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The annual report _____ the company's key achievements over the past twelve months.", "options": ["summarizes", "explains", "describes", "details"], "answer": 0, "explanation": "\"Report summarizes achievements\" = b\u00e1o c\u00e1o t\u00f3m t\u1eaft th\u00e0nh t\u00edch. \"Summarize\" ph\u00f9 h\u1ee3p nh\u1ea5t khi n\u00f3i v\u1ec1 ch\u1ee9c n\u0103ng c\u1ee7a annual report \u2014 t\u00f3m g\u1ecdn to\u00e0n b\u1ed9 n\u0103m."}, {"id": "vc2-e04", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The customer service team will _____ to all written complaints within two business days.", "options": ["respond", "reply to", "answer", "address"], "answer": 0, "explanation": "\"Respond to complaints within two days\" = ph\u1ea3n h\u1ed3i trong v\u00f2ng hai ng\u00e0y. \"Respond to\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t trong cam k\u1ebft d\u1ecbch v\u1ee5 kh\u00e1ch h\u00e0ng TOEIC."}, {"id": "vc2-e05", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "We are pleased to _____ that our new flagship store will open next month.", "options": ["announce", "inform", "tell", "say"], "answer": 0, "explanation": "\"Pleased to announce that...\" = vui m\u1eebng th\u00f4ng b\u00e1o r\u1eb1ng. \"Announce\" l\u00e0 collocation chu\u1ea9n trong th\u00f4ng b\u00e1o ch\u00ednh th\u1ee9c. \"Inform\" c\u1ea7n t\u00e2n ng\u1eef ng\u01b0\u1eddi (inform someone)."}, {"id": "vc2-e06", "part": 5, "type": "vocabulary-context", "difficulty": "easy", "question": "The contract will _____ on March 31 unless renewed by both parties.", "options": ["expire", "end", "finish", "stop"], "answer": 0, "explanation": "\"Contract will expire\" = h\u1ee3p \u0111\u1ed3ng s\u1ebd h\u1ebft h\u1ea1n. \"Expire\" l\u00e0 t\u1eeb chuy\u00ean bi\u1ec7t cho h\u1ee3p \u0111\u1ed3ng/gi\u1ea5y ph\u00e9p/th\u1ebb. \"End/finish/stop\" qu\u00e1 chung chung."}, {"id": "vc2-m01", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The board _____ a vote on the acquisition after reviewing all due diligence reports.", "options": ["called for", "asked for", "demanded", "requested"], "answer": 0, "explanation": "\"Called for a vote\" = y\u00eau c\u1ea7u ti\u1ebfn h\u00e0nh b\u1ecf phi\u1ebfu (ch\u00ednh th\u1ee9c). \"Call for a vote/review/investigation\" l\u00e0 collocation th\u1ee7 t\u1ee5c trong TOEIC governance."}, {"id": "vc2-m02", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The firm was unable to _____ the growing demand for its services without hiring additional staff.", "options": ["keep up with", "meet", "satisfy", "handle"], "answer": 0, "explanation": "\"Keep up with growing demand\" = theo k\u1ecbp nhu c\u1ea7u ng\u00e0y c\u00e0ng t\u0103ng. Phrasal verb chuy\u00ean bi\u1ec7t: \"keep up with demand/growth/pace\" \u2014 kh\u00e1c v\u1edbi \"meet demand\" (\u0111\u00e1p \u1ee9ng \u0111\u1ee7)."}, {"id": "vc2-m03", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The training programme is designed to _____ employees with the skills needed for their new roles.", "options": ["equip", "provide", "supply", "arm"], "answer": 0, "explanation": "\"Equip employees with skills\" = trang b\u1ecb k\u1ef9 n\u0103ng cho nh\u00e2n vi\u00ean. \"Equip with\" = collocation \u0111\u1eb7c bi\u1ec7t trong v\u0103n b\u1ea3n \u0111\u00e0o t\u1ea1o TOEIC. \"Arm with\" = th\u00e0nh ng\u1eef (arm with knowledge)."}, {"id": "vc2-m04", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "Management _____ all staff of the upcoming system maintenance scheduled for this Sunday.", "options": ["notified", "informed", "told", "advised"], "answer": 0, "explanation": "\"Notified all staff of the maintenance\" = th\u00f4ng b\u00e1o cho nh\u00e2n vi\u00ean v\u1ec1. \"Notify + person + of + event\" = collocation trang tr\u1ecdng nh\u1ea5t trong th\u00f4ng b\u00e1o h\u1ec7 th\u1ed1ng TOEIC."}, {"id": "vc2-m05", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The project was temporarily _____ while the team awaited approval from the regulatory body.", "options": ["suspended", "stopped", "halted", "paused"], "answer": 0, "explanation": "\"Temporarily suspended\" = t\u1ea1m \u0111\u00ecnh ch\u1ec9 (c\u00f3 k\u1ebf ho\u1ea1ch ti\u1ebfp t\u1ee5c). \"Suspended\" ph\u1ed5 bi\u1ebfn nh\u1ea5t trong v\u0103n b\u1ea3n ph\u00e1p l\u00fd/qu\u1ea3n tr\u1ecb khi d\u1eebng c\u00f3 ch\u1ee7 \u0111\u00edch, kh\u00f4ng h\u1ee7y ho\u00e0n to\u00e0n."}, {"id": "vc2-m06", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The company's new pricing model is _____ to take effect from the beginning of the next quarter.", "options": ["scheduled", "planned", "expected", "set"], "answer": 3, "explanation": "\"Set to take effect\" = \u0111\u01b0\u1ee3c \u1ea5n \u0111\u1ecbnh s\u1ebd c\u00f3 hi\u1ec7u l\u1ef1c. \"Set to + V\" = c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong th\u00f4ng b\u00e1o kinh doanh, m\u1ea1nh h\u01a1n \"expected\" (ch\u1eafc ch\u1eafn h\u01a1n)."}, {"id": "vc2-m07", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The findings of the audit were _____ to the board at the quarterly meeting.", "options": ["presented", "given", "shown", "reported"], "answer": 0, "explanation": "\"Findings were presented to the board\" = k\u1ebft qu\u1ea3 \u0111\u01b0\u1ee3c tr\u00ecnh b\u00e0y cho h\u1ed9i \u0111\u1ed3ng. \"Present findings/results to someone\" = collocation chu\u1ea9n nh\u1ea5t trong b\u00e1o c\u00e1o ki\u1ec3m to\u00e1n TOEIC."}, {"id": "vc2-m08", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "Staff are encouraged to _____ any safety concerns to their line manager immediately.", "options": ["report", "raise", "tell", "voice"], "answer": 1, "explanation": "\"Raise safety concerns\" = n\u00eau l\u00ean m\u1ed1i lo ng\u1ea1i v\u1ec1 an to\u00e0n. \"Raise concerns/issues\" = collocation HR/safety chu\u1ea9n. \"Report concerns\" c\u0169ng \u0111\u00fang nh\u01b0ng \"raise\" ph\u1ed5 bi\u1ebfn h\u01a1n trong v\u0103n h\u00f3a doanh nghi\u1ec7p TOEIC."}, {"id": "vc2-m09", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The construction company _____ a penalty for failing to complete the project on schedule.", "options": ["incurred", "received", "got", "faced"], "answer": 0, "explanation": "\"Incurred a penalty\" = ch\u1ecbu ph\u1ea1t, g\u00e1nh ch\u1ecbu (h\u1eadu qu\u1ea3 t\u00e0i ch\u00ednh). \"Incur + penalty/cost/fine/loss\" = collocation k\u1ebf to\u00e1n/ph\u00e1p l\u00fd quan tr\u1ecdng trong TOEIC."}, {"id": "vc2-m10", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The company plans to _____ its brand identity with a modernised logo and refreshed visual guidelines.", "options": ["rebrand", "update", "refresh", "overhaul"], "answer": 2, "explanation": "\"Refresh brand identity\" = l\u00e0m m\u1edbi nh\u1eadn di\u1ec7n th\u01b0\u01a1ng hi\u1ec7u (nh\u1eb9 nh\u00e0ng). \"Overhaul\" = \u0111\u1ea1i tu (m\u1ea1nh h\u01a1n). \"Rebrand\" = \u0111\u1ed5i th\u01b0\u01a1ng hi\u1ec7u ho\u00e0n to\u00e0n. \"Refresh\" ph\u00f9 h\u1ee3p khi gi\u1eef b\u1ea3n ch\u1ea5t nh\u01b0ng c\u1eadp nh\u1eadt visual."}, {"id": "vc2-m11", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The committee _____ three days of intensive discussion before reaching a unanimous agreement.", "options": ["held", "conducted", "spent", "used"], "answer": 1, "explanation": "\"Conducted three days of intensive discussion\" = ti\u1ebfn h\u00e0nh th\u1ea3o lu\u1eadn. \"Conduct + discussion/meeting/survey/review\" = collocation chu\u1ea9n nh\u1ea5t trong ng\u1eef c\u1ea3nh ch\u00ednh th\u1ee9c TOEIC."}, {"id": "vc2-m12", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "All sales staff are expected to _____ their monthly targets by the last day of each period.", "options": ["achieve", "hit", "reach", "meet"], "answer": 3, "explanation": "\"Meet monthly targets\" = ho\u00e0n th\u00e0nh m\u1ee5c ti\u00eau h\u00e0ng th\u00e1ng. Collocation: \"meet + targets/deadline/requirements/expectations\" = chu\u1ea9n nh\u1ea5t trong v\u0103n b\u1ea3n KPI TOEIC."}, {"id": "vc2-m13", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The CEO _____ her confidence that the company would return to profitability within two years.", "options": ["expressed", "showed", "demonstrated", "exhibited"], "answer": 0, "explanation": "\"Expressed her confidence that...\" = b\u00e0y t\u1ecf ni\u1ec1m tin r\u1eb1ng. \"Express + confidence/concern/satisfaction/appreciation\" = collocation ch\u00ednh th\u1ee9c trong th\u00f4ng c\u00e1o b\u00e1o ch\u00ed TOEIC."}, {"id": "vc2-m14", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The bank has agreed to _____ the loan repayment period by an additional 12 months.", "options": ["extend", "lengthen", "increase", "expand"], "answer": 0, "explanation": "\"Extend the loan repayment period\" = gia h\u1ea1n k\u1ef3 h\u1ea1n tr\u1ea3 n\u1ee3. \"Extend + period/deadline/contract/warranty\" = collocation t\u00e0i ch\u00ednh chu\u1ea9n. \"Lengthen\" \u00edt d\u00f9ng h\u01a1n trong v\u0103n b\u1ea3n ng\u00e2n h\u00e0ng."}, {"id": "vc2-m15", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The pilot programme was _____ successful and will be rolled out nationally by the end of the year.", "options": ["deemed", "considered", "judged", "found"], "answer": 0, "explanation": "\"Deemed successful\" = \u0111\u01b0\u1ee3c xem l\u00e0 th\u00e0nh c\u00f4ng (ph\u00e1n x\u00e9t ch\u00ednh th\u1ee9c). \"Deemed\" mang t\u00ednh ch\u00ednh th\u1ee9c cao nh\u1ea5t trong v\u0103n b\u1ea3n \u0111\u00e1nh gi\u00e1 ch\u01b0\u01a1ng tr\u00ecnh TOEIC."}, {"id": "vc2-m16", "part": 5, "type": "vocabulary-context", "difficulty": "medium", "question": "The product launch was _____ by a comprehensive marketing campaign across digital and print media.", "options": ["accompanied", "followed", "supported", "backed"], "answer": 0, "explanation": "\"Accompanied by a marketing campaign\" = \u0111i k\u00e8m v\u1edbi chi\u1ebfn d\u1ecbch marketing. \"Accompanied by\" = x\u1ea3y ra \u0111\u1ed3ng th\u1eddi v\u1edbi. \"Followed by\" = x\u1ea3y ra sau \u0111\u00f3. Ng\u1eef c\u1ea3nh \"launch + campaign\" \u2192 \u0111\u1ed3ng th\u1eddi \u2192 \"accompanied\"."}, {"id": "vc2-h01", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The sudden _____ of the key supplier forced the company to seek alternatives within 48 hours.", "options": ["withdrawal", "departure", "exit", "retreat"], "answer": 0, "explanation": "\"Withdrawal of a supplier\" = s\u1ef1 r\u00fat lui ch\u00ednh th\u1ee9c (t\u1eeb h\u1ee3p \u0111\u1ed3ng/th\u1ecb tr\u01b0\u1eddng). \"Withdrawal\" mang ngh\u0129a ph\u00e1p l\u00fd/th\u01b0\u01a1ng m\u1ea1i. \"Departure\" = r\u1eddi \u0111i (ng\u01b0\u1eddi). \"Exit\" th\u01b0\u1eddng d\u00f9ng cho market exit."}, {"id": "vc2-h02", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The new regulation will _____ companies with fewer than ten employees from the mandatory reporting requirements.", "options": ["exempt", "exclude", "release", "waive"], "answer": 0, "explanation": "\"Exempt companies from requirements\" = mi\u1ec5n tr\u1eeb kh\u1ecfi y\u00eau c\u1ea7u. \"Exempt from\" = collocation ph\u00e1p l\u00fd chu\u1ea9n. \"Exclude from\" = lo\u1ea1i tr\u1eeb kh\u1ecfi (kh\u00f4ng tham gia). \"Waive\" = t\u1eeb b\u1ecf quy\u1ec1n (kh\u00f4ng ph\u1ea3i mi\u1ec5n cho ng\u01b0\u1eddi kh\u00e1c)."}, {"id": "vc2-h03", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The aggressive pricing strategy was seen as _____ to undermine competitors' market share.", "options": ["calculated", "deliberate", "intended", "designed"], "answer": 3, "explanation": "\"Designed to undermine\" = \u0111\u01b0\u1ee3c thi\u1ebft k\u1ebf v\u1edbi m\u1ee5c \u0111\u00edch. \"Designed to do\" = c\u00f3 ch\u1ee7 \u0111\u00edch c\u1ee5 th\u1ec3 (nh\u1ea5n m\u1ea1nh k\u1ebf ho\u1ea1ch). \"Calculated to\" c\u0169ng \u0111\u00fang nh\u01b0ng \"designed to undermine\" ph\u1ed5 bi\u1ebfn h\u01a1n trong ph\u00e2n t\u00edch chi\u1ebfn l\u01b0\u1ee3c TOEIC."}, {"id": "vc2-h04", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The company's quarterly results _____ well short of analyst forecasts, triggering a sharp sell-off.", "options": ["fell", "came", "dropped", "ran"], "answer": 0, "explanation": "\"Results fell well short of forecasts\" = c\u1ee5m c\u1ed1 \u0111\u1ecbnh t\u00e0i ch\u00ednh. \"Fall short of\" = kh\u00f4ng \u0111\u1ea1t \u0111\u01b0\u1ee3c k\u1ef3 v\u1ecdng. \"Dropped short\" / \"came short\" / \"ran short of\" \u0111\u1ec1u kh\u00f4ng ph\u1ea3i collocation chu\u1ea9n."}, {"id": "vc2-h05", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The long-standing partnership between the two firms was _____ after a series of contractual disputes.", "options": ["dissolved", "terminated", "severed", "broken"], "answer": 2, "explanation": "\"Partnership was severed\" = quan h\u1ec7 \u0111\u1ed1i t\u00e1c b\u1ecb c\u1eaft \u0111\u1ee9t (ho\u00e0n to\u00e0n v\u00e0 d\u1ee9t kho\u00e1t). \"Severed\" nh\u1ea5n m\u1ea1nh s\u1ef1 \u0111\u1ee9t g\u00e3y kh\u00f4ng th\u1ec3 h\u00e0n g\u1eafn. \"Terminated\" = ch\u1ea5m d\u1ee9t ch\u00ednh th\u1ee9c. \"Dissolved\" = gi\u1ea3i th\u1ec3 (th\u01b0\u1eddng cho c\u00f4ng ty)."}, {"id": "vc2-h06", "part": 5, "type": "vocabulary-context", "difficulty": "hard", "question": "The CEO's resignation letter was _____ as an admission of responsibility for the compliance failures.", "options": ["widely interpreted", "broadly seen", "largely viewed", "commonly read"], "answer": 0, "explanation": "\"Widely interpreted as\" = \u0111\u01b0\u1ee3c nhi\u1ec1u ng\u01b0\u1eddi hi\u1ec3u l\u00e0. Collocation TOEIC cao c\u1ea5p: \"widely interpreted/regarded/seen as\" trong ph\u00e2n t\u00edch s\u1ef1 ki\u1ec7n doanh nghi\u1ec7p. \"Widely interpreted\" chu\u1ea9n nh\u1ea5t v\u1edbi \"as\" ngay sau."}, {"id": "wf3-e01", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The _____ of the building was completed six months ahead of schedule.", "options": ["construct", "construction", "constructing", "constructed"], "answer": 1, "explanation": "\"The _____ of the building\" = danh t\u1eeb sau \"The\". \"Construction\" (n) = vi\u1ec7c x\u00e2y d\u1ef1ng. H\u1eadu t\u1ed1 -tion = danh t\u1eeb."}, {"id": "wf3-e02", "part": 5, "type": "word-form", "difficulty": "easy", "question": "Staff are _____ reminded to log out of the system when leaving their workstations.", "options": ["regular", "regularly", "regularity", "regularize"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho V3 \"reminded\" \u2192 ph\u00f3 t\u1eeb. \"Regularly reminded\" = \u0111\u01b0\u1ee3c nh\u1eafc nh\u1edf th\u01b0\u1eddng xuy\u00ean. H\u1eadu t\u1ed1 -ly = ph\u00f3 t\u1eeb."}, {"id": "wf3-e03", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The marketing department needs to _____ its campaign before the product launch.", "options": ["finalize", "finalization", "final", "finally"], "answer": 0, "explanation": "Sau \"needs to\" \u2192 to-infinitive \u2192 V nguy\u00ean th\u1ec3. \"Finalize a campaign\" (v) = ho\u00e0n thi\u1ec7n chi\u1ebfn d\u1ecbch."}, {"id": "wf3-e04", "part": 5, "type": "word-form", "difficulty": "easy", "question": "The team's _____ approach to problem-solving impressed all senior managers.", "options": ["create", "creative", "creatively", "creativity"], "answer": 1, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"approach\" \u2192 t\u00ednh t\u1eeb. \"Creative approach\" = c\u00e1ch ti\u1ebfp c\u1eadn s\u00e1ng t\u1ea1o. \"Creativity\" l\u00e0 danh t\u1eeb, sai v\u1ecb tr\u00ed."}, {"id": "wf3-e05", "part": 5, "type": "word-form", "difficulty": "easy", "question": "Please ensure that all documents are _____ before they are submitted.", "options": ["complete", "completion", "completely", "completed"], "answer": 3, "explanation": "\"Are _____ before submission\" = t\u00ednh t\u1eeb sau \"are\" (linking verb). \"Are completed\" = \u0111\u00e3 \u0111\u01b0\u1ee3c ho\u00e0n th\u00e0nh (passive adjective)."}, {"id": "wf3-m01", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The team worked _____ for three months to meet the challenging production deadline.", "options": ["tire", "tireless", "tirelessly", "tirelessness"], "answer": 2, "explanation": "B\u1ed5 ngh\u0129a cho \u0111\u1ed9ng t\u1eeb \"worked\" \u2192 ph\u00f3 t\u1eeb. \"Worked tirelessly\" = l\u00e0m vi\u1ec7c kh\u00f4ng m\u1ec7t m\u1ecfi. H\u1eadu t\u1ed1 -lessly = ph\u00f3 t\u1eeb."}, {"id": "wf3-m02", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The board expressed its full _____ for the new strategic direction.", "options": ["endorse", "endorsement", "endorsed", "endorsing"], "answer": 1, "explanation": "\"Its full _____ for...\" = danh t\u1eeb sau \u0111\u1ea1i t\u1eeb s\u1edf h\u1eefu. \"Endorsement for\" = s\u1ef1 ch\u1ee9ng th\u1ef1c, \u1ee7ng h\u1ed9. H\u1eadu t\u1ed1 -ment = danh t\u1eeb."}, {"id": "wf3-m03", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The regulations require all vendors to be _____ with the new packaging standards.", "options": ["comply", "compliance", "compliant", "complying"], "answer": 2, "explanation": "Sau \"to be\" \u2192 t\u00ednh t\u1eeb. \"Be compliant with standards\" = tu\u00e2n th\u1ee7 theo ti\u00eau chu\u1ea9n. H\u1eadu t\u1ed1 -ant = t\u00ednh t\u1eeb."}, {"id": "wf3-m04", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The annual _____ of the employee handbook ensures it reflects current workplace legislation.", "options": ["revise", "revision", "revised", "revising"], "answer": 1, "explanation": "\"The annual _____ of the handbook\" = danh t\u1eeb sau m\u1ea1o t\u1eeb. \"Revision of\" = s\u1ef1 xem x\u00e9t l\u1ea1i, c\u1eadp nh\u1eadt. H\u1eadu t\u1ed1 -ion = danh t\u1eeb."}, {"id": "wf3-m05", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Her _____ presentation skills helped secure a major client for the firm.", "options": ["excel", "excellent", "excellently", "excellence"], "answer": 1, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"presentation skills\" \u2192 t\u00ednh t\u1eeb. \"Excellent skills\" = k\u1ef9 n\u0103ng xu\u1ea5t s\u1eafc. \"Excellence\" l\u00e0 danh t\u1eeb, sai v\u1ecb tr\u00ed."}, {"id": "wf3-m06", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the warehouse to accommodate larger shipments took three months.", "options": ["expand", "expansion", "expanded", "expanding"], "answer": 1, "explanation": "\"The _____ of the warehouse\" = danh t\u1eeb ch\u1ee7 ng\u1eef. \"Expansion of\" = s\u1ef1 m\u1edf r\u1ed9ng. H\u1eadu t\u1ed1 -ion = danh t\u1eeb."}, {"id": "wf3-m07", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Customers are _____ encouraged to provide feedback via the online portal.", "options": ["active", "actively", "activeness", "activation"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho V3 \"encouraged\" \u2192 ph\u00f3 t\u1eeb. \"Actively encouraged\" = \u0111\u01b0\u1ee3c khuy\u1ebfn kh\u00edch t\u00edch c\u1ef1c. H\u1eadu t\u1ed1 -ly = ph\u00f3 t\u1eeb."}, {"id": "wf3-m08", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The new factory is _____ one of the most advanced in the region.", "options": ["argue", "argued", "arguably", "arguable"], "answer": 2, "explanation": "B\u1ed5 ngh\u0129a cho to\u00e0n c\u00e2u (sentential adverb) \u2192 ph\u00f3 t\u1eeb. \"Arguably one of the most...\" = c\u00f3 th\u1ec3 n\u00f3i l\u00e0 m\u1ed9t trong nh\u1eefng... Ph\u00f3 t\u1eeb sentential ph\u1ed5 bi\u1ebfn trong TOEIC."}, {"id": "wf3-m09", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ of the new policy has been welcomed by both management and staff.", "options": ["introduce", "introduction", "introduced", "introductory"], "answer": 1, "explanation": "\"The _____ of the new policy\" = danh t\u1eeb ch\u1ee7 ng\u1eef. \"Introduction of\" = vi\u1ec7c gi\u1edbi thi\u1ec7u/ban h\u00e0nh. H\u1eadu t\u1ed1 -tion = danh t\u1eeb."}, {"id": "wf3-m10", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The report provides a _____ overview of all key findings from the consumer survey.", "options": ["comprehend", "comprehensive", "comprehension", "comprehensively"], "answer": 1, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"overview\" \u2192 t\u00ednh t\u1eeb. \"Comprehensive overview\" = c\u00e1i nh\u00ecn to\u00e0n di\u1ec7n. \"Comprehensively\" l\u00e0 ph\u00f3 t\u1eeb kh\u00f4ng \u0111\u1ee9ng tr\u01b0\u1edbc noun."}, {"id": "wf3-m11", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The data _____ that demand for premium products continues to rise in urban markets.", "options": ["indicate", "indicates", "indication", "indicated"], "answer": 1, "explanation": "\"The data indicates\" \u2014 stative verb, Present Simple, s\u1ed1 \u00edt. \"Data indicates\" = s\u1ed1 li\u1ec7u cho th\u1ea5y (data c\u00f3 th\u1ec3 s\u1ed1 \u00edt trong US English)."}, {"id": "wf3-m12", "part": 5, "type": "word-form", "difficulty": "medium", "question": "Sales performance was _____ below the targets set at the beginning of the financial year.", "options": ["significant", "significantly", "significance", "signified"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho adj \"below\" (tr\u1ea1ng t\u1eeb ch\u1ec9 m\u1ee9c \u0111\u1ed9) \u2192 ph\u00f3 t\u1eeb. \"Significantly below\" = th\u1ea5p h\u01a1n \u0111\u00e1ng k\u1ec3. -ly = ph\u00f3 t\u1eeb."}, {"id": "wf3-m13", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The charity event raised _____ funds than expected, allowing the organisation to expand its programmes.", "options": ["substantial", "substantially", "more substantial", "more substantially"], "answer": 2, "explanation": "\"Raised _____ funds than expected\" = c\u1ea7n so s\u00e1nh h\u01a1n tr\u01b0\u1edbc danh t\u1eeb. \"More substantial funds than\" = nhi\u1ec1u qu\u1ef9 \u0111\u00e1ng k\u1ec3 h\u01a1n. \"More substantial\" = adj so s\u00e1nh h\u01a1n."}, {"id": "wf3-m14", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The CEO's _____ farewell address moved many long-serving employees to tears.", "options": ["move", "moving", "movement", "movingly"], "answer": 1, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"farewell address\" \u2192 t\u00ednh t\u1eeb. \"Moving address/speech\" = b\u00e0i ph\u00e1t bi\u1ec3u c\u1ea3m \u0111\u1ed9ng. V-ing d\u00f9ng l\u00e0m adj = participial adjective."}, {"id": "wf3-m15", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The _____ between the two departments has resulted in a more streamlined approval process.", "options": ["collaborate", "collaboration", "collaborative", "collaboratively"], "answer": 1, "explanation": "\"The _____ between departments\" = danh t\u1eeb ch\u1ee7 ng\u1eef. \"Collaboration between\" = s\u1ef1 h\u1ee3p t\u00e1c gi\u1eefa. H\u1eadu t\u1ed1 -tion = danh t\u1eeb."}, {"id": "wf3-m16", "part": 5, "type": "word-form", "difficulty": "medium", "question": "All invoices must be _____ approved by the finance director before payment is processed.", "options": ["former", "formal", "formerly", "formally"], "answer": 3, "explanation": "B\u1ed5 ngh\u0129a cho V3 \"approved\" \u2192 ph\u00f3 t\u1eeb. \"Formally approved\" = \u0111\u01b0\u1ee3c ph\u00ea duy\u1ec7t ch\u00ednh th\u1ee9c. B\u1eaby: \"formerly\" = tr\u01b0\u1edbc \u0111\u00e2y (th\u1eddi gian), \"formally\" = m\u1ed9t c\u00e1ch ch\u00ednh th\u1ee9c."}, {"id": "wf3-m17", "part": 5, "type": "word-form", "difficulty": "medium", "question": "The company has seen _____ growth in its subscription-based services over the past two years.", "options": ["remark", "remarkable", "remarkably", "remarked"], "answer": 1, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"growth\" \u2192 t\u00ednh t\u1eeb. \"Remarkable growth\" = t\u0103ng tr\u01b0\u1edfng \u0111\u00e1ng ch\u00fa \u00fd. \"Remarkably\" l\u00e0 ph\u00f3 t\u1eeb kh\u00f4ng \u0111\u1ee9ng tr\u01b0\u1edbc noun tr\u1ef1c ti\u1ebfp."}, {"id": "wf3-h01", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The acquisition is expected to be _____ accretive to earnings within the first fiscal year.", "options": ["immediate", "immediately", "imminent", "imminently"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho adj \"accretive\" \u2192 ph\u00f3 t\u1eeb. \"Immediately accretive to earnings\" = ngay l\u1eadp t\u1ee9c t\u1ea1o ra l\u1ee3i nhu\u1eadn t\u00edch l\u0169y. Thu\u1eadt ng\u1eef M&A cao c\u1ea5p trong TOEIC Part 7 vocabulary."}, {"id": "wf3-h02", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The _____ scrutiny of the regulatory body led the firm to appoint additional compliance officers.", "options": ["intense", "intensity", "intensely", "intensified"], "answer": 3, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"scrutiny\" \u2192 t\u00ednh t\u1eeb. \"Intensified scrutiny\" = s\u1ef1 gi\u00e1m s\u00e1t ng\u00e0y c\u00e0ng t\u0103ng c\u01b0\u1eddng (V3 d\u00f9ng l\u00e0m adj). \"Intense\" c\u0169ng \u0111\u00fang nh\u01b0ng \"intensified\" nh\u1ea5n m\u1ea1nh s\u1ef1 gia t\u0103ng theo th\u1eddi gian."}, {"id": "wf3-h03", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The terms of the agreement are _____ binding and cannot be altered without mutual consent.", "options": ["legal", "legally", "legality", "legalized"], "answer": 1, "explanation": "B\u1ed5 ngh\u0129a cho adj \"binding\" \u2192 ph\u00f3 t\u1eeb. \"Legally binding\" = r\u00e0ng bu\u1ed9c v\u1ec1 m\u1eb7t ph\u00e1p l\u00fd. Collocation ph\u00e1p l\u00fd quan tr\u1ecdng nh\u1ea5t trong TOEIC."}, {"id": "wf3-h04", "part": 5, "type": "word-form", "difficulty": "hard", "question": "Management expressed _____ for the operational delays, citing the unexpected equipment failure.", "options": ["regret", "regretful", "regrettably", "regretfully"], "answer": 0, "explanation": "\"Expressed _____ for the delays\" = t\u00e2n ng\u1eef sau \"expressed\" \u2192 danh t\u1eeb. \"Regret for\" = s\u1ef1 h\u1ed1i ti\u1ebfc v\u1ec1. Ph\u00e2n bi\u1ec7t: \"regret\" (n) vs \"regretfully/regrettably\" (adv)."}, {"id": "wf3-h05", "part": 5, "type": "word-form", "difficulty": "hard", "question": "The board's decision was _____ in its implications, affecting not just local but international operations.", "options": ["far-reach", "far-reaching", "far-reachingly", "far-reached"], "answer": 1, "explanation": "Tr\u01b0\u1edbc danh t\u1eeb \"implications\" \u2192 compound adj. \"Far-reaching implications\" = h\u1ec7 qu\u1ea3 s\u00e2u r\u1ed9ng. \"Far-reaching\" l\u00e0 compound adjective ph\u1ed5 bi\u1ebfn trong TOEIC Part 7 cao c\u1ea5p."}, {"id": "vt2-e01", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "The quarterly report _____ before the board meeting starts.", "options": ["will be distributed", "is distributing", "distributed", "distributes"], "answer": 0, "explanation": "\"Before the board meeting starts\" = tr\u01b0\u1edbc m\u1ed9t th\u1eddi \u0111i\u1ec3m t\u01b0\u01a1ng lai \u2192 Future Passive: \"will be distributed\". \"Distributes\" l\u00e0 ch\u1ee7 \u0111\u1ed9ng, sai."}, {"id": "vt2-e02", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "The store _____ every Sunday from 9 a.m. to 6 p.m.", "options": ["operates", "is operating", "has operated", "was operating"], "answer": 0, "explanation": "Th\u00f3i quen/l\u1ecbch th\u01b0\u1eddng xuy\u00ean \u2192 Present Simple. \"Operates every Sunday\" = ho\u1ea1t \u0111\u1ed9ng m\u1ed7i Ch\u1ee7 nh\u1eadt. Kh\u00f4ng c\u1ea7n th\u00ec ti\u1ebfp di\u1ec5n."}, {"id": "vt2-e03", "part": 5, "type": "verb-tense", "difficulty": "easy", "question": "When the manager _____ the office, everyone stood up.", "options": ["entered", "was entering", "enters", "had entered"], "answer": 0, "explanation": "\"When + Past Simple \u2192 Past Simple\" \u2014 hai h\u00e0nh \u0111\u1ed9ng x\u1ea3y ra \u0111\u1ed3ng th\u1eddi, c\u00f9ng ho\u00e0n th\u00e0nh. \"Entered...stood up\" = v\u00e0o th\u00ec m\u1ecdi ng\u01b0\u1eddi \u0111\u1ee9ng d\u1eady."}, {"id": "vt2-m01", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "By the time the new CEO _____ office, the restructuring plan _____ already finalised.", "options": ["takes / will have been", "took / had been", "takes / has been", "took / was"], "answer": 1, "explanation": "Past time reference + \"by the time + Past Simple \u2192 Past Perfect\". \"Took office\" (past) + \"had been finalised\" (completed before) = chu\u1ea9n Past Perfect sequence."}, {"id": "vt2-m02", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The training programme _____ twice a year since its introduction in 2018.", "options": ["has been offered", "was offered", "is offered", "had been offered"], "answer": 0, "explanation": "\"Since 2018\" + h\u00e0nh \u0111\u1ed9ng ti\u1ebfp di\u1ec5n \u0111\u1ebfn hi\u1ec7n t\u1ea1i \u2192 Present Perfect. \"Has been offered since 2018\" = \u0111\u01b0\u1ee3c cung c\u1ea5p k\u1ec3 t\u1eeb n\u0103m 2018 \u0111\u1ebfn nay."}, {"id": "vt2-m03", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "Please hold all calls while the director _____ with the client.", "options": ["is meeting", "meets", "will be meeting", "was meeting"], "answer": 0, "explanation": "\"While\" + h\u00e0nh \u0111\u1ed9ng \u0111ang di\u1ec5n ra t\u1ea1i th\u1eddi \u0111i\u1ec3m n\u00f3i \u2192 Present Continuous. \"While the director is meeting\" = trong khi gi\u00e1m \u0111\u1ed1c \u0111ang g\u1eb7p kh\u00e1ch h\u00e0ng."}, {"id": "vt2-m04", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The tender deadline _____ extended by two weeks following requests from multiple bidders.", "options": ["has been", "was", "had been", "will be"], "answer": 1, "explanation": "\"Following requests\" = sau khi nh\u1eadn \u0111\u01b0\u1ee3c y\u00eau c\u1ea7u (\u0111\u00e3 x\u1ea3y ra) \u2192 Past Simple Passive. \"Was extended\" = \u0111\u00e3 \u0111\u01b0\u1ee3c gia h\u1ea1n. \"Has been\" = hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh (c\u1ea7n \"just/already\")."}, {"id": "vt2-m05", "part": 5, "type": "verb-tense", "difficulty": "medium", "question": "The marketing team _____ on the new campaign for six weeks when the client suddenly changed the brief.", "options": ["had been working", "was working", "has been working", "worked"], "answer": 0, "explanation": "\"For six weeks when...\" = h\u00e0nh \u0111\u1ed9ng \u0111ang ti\u1ebfp di\u1ec5n \u0111\u1ebfn th\u1eddi \u0111i\u1ec3m qu\u00e1 kh\u1ee9 b\u1ecb gi\u00e1n \u0111o\u1ea1n \u2192 Past Perfect Continuous. \"Had been working for six weeks when\" = \u0111\u00e3 l\u00e0m \u0111\u01b0\u1ee3c 6 tu\u1ea7n th\u00ec..."}, {"id": "vt2-h01", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "Had the supplier informed us earlier, we _____ alternative arrangements in time.", "options": ["would have made", "could make", "will have made", "had made"], "answer": 0, "explanation": "\u0110\u1ea3o ng\u1eef \u0111i\u1ec1u ki\u1ec7n Type 3: \"Had + S + V3, S + would have + V3\". \"Would have made\" = \u0111\u00e3 c\u00f3 th\u1ec3 thu x\u1ebfp (nh\u01b0ng kh\u00f4ng x\u1ea3y ra). \u0110\u00e2y l\u00e0 inverted conditional quan tr\u1ecdng trong TOEIC."}, {"id": "vt2-h02", "part": 5, "type": "verb-tense", "difficulty": "hard", "question": "The project _____ for three months before budget approval _____ finally granted.", "options": ["had been stalled / was", "was stalled / had been", "has been stalled / was", "was stalling / is"], "answer": 0, "explanation": "Past Perfect Continuous + Past Simple theo th\u1ee9 t\u1ef1: \"Had been stalled for three months\" (h\u00e0nh \u0111\u1ed9ng k\u00e9o d\u00e0i tr\u01b0\u1edbc th\u1eddi \u0111i\u1ec3m qu\u00e1 kh\u1ee9) \u2192 \"before...was granted\" (Past Simple = th\u1eddi \u0111i\u1ec3m k\u1ebft th\u00fac). C\u1ea5u tr\u00fac: had been + V-ing...before...was + V3."}], "part6": [{"passage": "To: All Staff\nFrom: HR Department\nSubject: Annual Performance Reviews\n\nDear Team,\n\nThis is a reminder that annual performance reviews will (1)_____ next month. All managers should (2)_____ their team members in advance to discuss goals and overall performance for the year. Evaluation forms are (3)_____ on the company intranet. Please complete them prior to your scheduled meeting. If you have any questions, (4)_____ contact the HR department at extension 204.", "passageTitle": "Email: Performance Review Notice", "type": "single", "questions": [{"id": "p6-1a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["take place", "take over", "take off", "take up"], "answer": 0, "explanation": "'Take place' = x\u1ea3y ra, di\u1ec5n ra. \u0110\u00e2y l\u00e0 c\u1ee5m c\u1ed1 \u0111\u1ecbnh d\u00f9ng cho s\u1ef1 ki\u1ec7n.", "difficulty": "medium"}, {"id": "p6-1b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["contact", "contacted", "contacting", "to contact"], "answer": 0, "explanation": "'Should + V (nguy\u00ean m\u1eabu)'. C\u00e2u m\u1ec7nh l\u1ec7nh l\u1ecbch s\u1ef1 v\u1edbi 'should'.", "difficulty": "medium"}, {"id": "p6-1c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Completed reviews must be submitted to HR through the online portal.", "The reviews are optional for staff who have been with the company less than six months.", "All employees will receive a bonus based on their review scores this year.", "Managers are not required to discuss the results with their team members."], "answer": 0, "explanation": "SI: c\u00e2u \u0111i\u1ec1n ph\u1ea3i k\u1ebft n\u1ed1i \"available on the company intranet\" v\u1edbi \"complete them prior to meeting\". \"Completed reviews must be submitted through the portal\" = h\u00e0nh \u0111\u1ed9ng ti\u1ebfp theo logic sau khi truy c\u1eadp portal."}, {"id": "p6-1d", "part": 6, "qNum": 4, "question": "(4) The correct sentence connector:", "options": ["please", "however", "although", "because"], "answer": 0, "explanation": "C\u00e2u m\u1eddi/y\u00eau c\u1ea7u l\u1ecbch s\u1ef1 b\u1eaft \u0111\u1ea7u c\u00e2u m\u1edbi \u2192 'please'.", "difficulty": "medium"}]}, {"passage": "Dear Mr. Johnson,\n\nThank you for your inquiry (1)_____ our catering services. We (2)_____ in the industry for over fifteen years and pride ourselves on delivering high-quality food and service for corporate events of all sizes.\n\nWe (3)_____ be delighted to discuss your upcoming conference. Our event coordinator, Ms. Kim, will contact you (4)_____ the end of this week to arrange a consultation.\n\nSincerely,\nBlue Horizon Catering", "passageTitle": "Email: Catering Service Inquiry", "type": "single", "questions": [{"id": "p6-2a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["beside", "on", "regarding", "for"], "answer": 2, "explanation": "'Regarding' = li\u00ean quan \u0111\u1ebfn (gi\u1edbi t\u1eeb trang tr\u1ecdng d\u00f9ng trong email kinh doanh). 'Beside' = b\u00ean c\u1ea1nh (sai ngh\u0129a). 'On' v\u00e0 'for' kh\u00f4ng d\u00f9ng v\u1edbi 'inquiry' trong ng\u1eef c\u1ea3nh n\u00e0y.", "difficulty": "medium"}, {"id": "p6-2b", "part": 6, "qNum": 2, "question": "(2) Correct verb form:", "options": ["are", "have been", "had been", "were"], "answer": 1, "explanation": "'For over fifteen years' k\u1ebft h\u1ee3p v\u1edbi 'have been' \u2192 hi\u1ec7n t\u1ea1i ho\u00e0n th\u00e0nh.", "difficulty": "medium"}, {"id": "p6-2c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["We would be delighted to provide a customised menu proposal for your event.", "Unfortunately, our team is fully booked for the dates you mentioned.", "Our minimum catering order is 50 guests for all corporate events.", "Please note that all payments must be made at least two weeks in advance."], "answer": 0, "explanation": "SI: sau \"can\" (modal offering service) \u2192 c\u00e2u \u0111i\u1ec1n ph\u1ea3i l\u00e0 s\u1ef1 \u0111\u1ec1 ngh\u1ecb t\u00edch c\u1ef1c. \"Delighted to provide a customised proposal\" = ti\u1ebfp n\u1ed1i offer c\u1ee7a c\u00f4ng ty cung c\u1ea5p d\u1ecbch v\u1ee5."}, {"id": "p6-2d", "part": 6, "qNum": 4, "question": "(4) Correct preposition:", "options": ["until", "by", "in", "on"], "answer": 1, "explanation": "'By the end of this week' = tr\u01b0\u1edbc cu\u1ed1i tu\u1ea7n n\u00e0y (deadline). 'By' d\u00f9ng cho th\u1eddi h\u1ea1n.", "difficulty": "medium"}]}, {"passage": "Notice: Office Renovation\n\nPlease be (1)_____ that the third-floor office spaces will undergo renovation starting Monday, March 10th. During this period, those staff members (2)_____ on this floor will be temporarily relocated to the fifth floor. Access to the third floor will be (3)_____.\n\nWe apologize for any inconvenience this may cause. The renovation is (4)_____ to be completed by April 5th. Thank you for your patience.", "passageTitle": "Notice: Office Renovation", "type": "single", "questions": [{"id": "p6-3a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["known", "aware", "informed", "advised"], "answer": 3, "explanation": "'Please be advised that' = xin th\u00f4ng b\u00e1o r\u1eb1ng. C\u1ee5m c\u1ed1 \u0111\u1ecbnh trong th\u00f4ng b\u00e1o ch\u00ednh th\u1ee9c.", "difficulty": "medium"}, {"id": "p6-3b", "part": 6, "qNum": 2, "question": "(2) Correct relative structure:", "options": ["who work", "that worked", "whose work", "working"], "answer": 0, "explanation": "'Staff members who work on this floor' = nh\u00e2n vi\u00ean l\u00e0m vi\u1ec7c \u1edf t\u1ea7ng n\u00e0y.", "difficulty": "medium"}, {"id": "p6-3c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Access to these floors will be restricted to maintenance staff only during this period.", "The renovation is expected to increase the building's market value significantly.", "Employees on the third floor should update their desk bookings on the company portal.", "Please note that parking will be unaffected by the renovation work."], "answer": 0, "explanation": "SI: ng\u1eef c\u1ea3nh l\u00e0 th\u00f4ng b\u00e1o c\u1ea5m \u0111\u01b0\u1eddng v\u00e0o t\u1ea7ng 3 trong khi c\u1ea3i t\u1ea1o. \"Access restricted to maintenance staff\" = h\u1ec7 qu\u1ea3 tr\u1ef1c ti\u1ebfp v\u00e0 logic nh\u1ea5t c\u1ee7a th\u00f4ng b\u00e1o c\u1ea3i t\u1ea1o."}, {"id": "p6-3d", "part": 6, "qNum": 4, "question": "(4) Correct verb/adjective:", "options": ["expected", "planned", "scheduled", "supposed"], "answer": 2, "explanation": "'Scheduled to be completed' = \u0111\u01b0\u1ee3c l\u00ean l\u1ecbch ho\u00e0n t\u1ea5t (ch\u00ednh x\u00e1c nh\u1ea5t trong ng\u1eef c\u1ea3nh k\u1ebf ho\u1ea1ch c\u1ee5 th\u1ec3).", "difficulty": "medium"}]}, {"passage": "To: All Department Managers\nFrom: Human Resources\nSubject: Updated Performance Review Process\n\nDear Managers,\n\nWe are writing to inform you of changes to the annual performance review process that will take effect beginning this cycle.\n\nFirst, all employees ____(1)____ receive a self-assessment form one week before their scheduled review. Second, managers are required to document ____(2)____ specific examples of each employee's contributions. This change is intended to make reviews more objective and fair. Finally, all completed review forms ____(3)____ to HR no later than November 30.\n\nWe believe these changes will help create a more transparent and ____(4)____ evaluation process. Please contact the HR team if you have any questions.\n\nBest regards,\nHuman Resources Department", "passageTitle": "Memo: Budget Approval Process", "type": "single", "questions": [{"id": "n6-1a", "part": 6, "question": "Choose the correct answer for blank (1):", "options": ["will", "would", "should have", "had"], "answer": 0, "explanation": "\u2705 <b>Will</b>. <br>\ud83d\udca1 <i>Ng\u1eef c\u1ea3nh:</i> Th\u00f4ng b\u00e1o v\u1ec1 quy tr\u00ecnh m\u1edbi s\u1eafp \u00e1p d\u1ee5ng (take effect) n\u00ean d\u00f9ng T\u01b0\u01a1ng lai \u0111\u01a1n.", "difficulty": "medium"}, {"id": "n6-1b", "part": 6, "question": "Choose the correct answer for blank (2):", "options": ["at least two", "almost never", "rarely any", "few or no"], "answer": 0, "explanation": "\u2705 <b>At least two</b>. <br>\ud83d\udca1 <i>Logics:</i> Y\u00eau c\u1ea7u manager ghi l\u1ea1i v\u00ed d\u1ee5 c\u1ee5 th\u1ec3 th\u00ec ph\u1ea3i l\u00e0 s\u1ed1 l\u01b0\u1ee3ng '\u00edt nh\u1ea5t 2' m\u1edbi h\u1ee3p l\u00fd cho m\u1ed9t b\u1ea3n review.", "difficulty": "medium"}, {"id": "n6-1c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Department heads must submit all budget requests through the new online approval system.", "The finance team will hold an optional information session next Wednesday at 2:00 p.m.", "All budget decisions will now be made exclusively by the CEO.", "Employees who do not comply with the new process will receive a formal warning."], "answer": 0, "explanation": "SI: trong b\u1ed1i c\u1ea3nh memo v\u1ec1 quy tr\u00ecnh duy\u1ec7t ng\u00e2n s\u00e1ch \u2192 c\u00e2u \u0111i\u1ec1n ph\u1ea3i m\u00f4 t\u1ea3 h\u00e0nh \u0111\u1ed9ng c\u1ee5 th\u1ec3. \"Submit requests through the online system\" = b\u01b0\u1edbc h\u00e0nh \u0111\u1ed9ng ti\u1ebfp theo logic."}, {"id": "n6-1d", "part": 6, "question": "Choose the correct answer for blank (4):", "options": ["consequence", "consistent", "consistently", "consequential"], "answer": 1, "explanation": "'Consistent' (t\u00ednh t\u1eeb) = nh\u1ea5t qu\u00e1n. C\u1ea5u tr\u00fac song song: 'transparent AND consistent' \u2014 hai t\u00ednh t\u1eeb. 'Consequence' v\u00e0 'consequential' sai ngh\u0129a; 'consistently' l\u00e0 ph\u00f3 t\u1eeb, kh\u00f4ng \u0111\u1ee9ng tr\u01b0\u1edbc danh t\u1eeb.", "difficulty": "medium"}]}, {"passage": "Dear Valued Customer,\n\nThank you for your continued patronage of BrightClean Laundry Services. We are pleased to announce that we will be ____(1)____ our service offerings beginning March 1.\n\nIn addition to our standard dry cleaning and garment care, we will now offer same-day express service for items dropped off before 10:00 a.m. ____(2)____, our new pickup and delivery option will be available to customers within a 10-kilometer radius of any of our three locations.\n\nTo celebrate these additions, all customers who register for our loyalty card this month will receive a 20% discount ____(3)____ their first five orders. We hope these enhancements demonstrate our ongoing commitment to providing you with ____(4)____ service.\n\nWarm regards,\nThe BrightClean Team", "passageTitle": "Email: Product Launch Update", "type": "single", "questions": [{"id": "n6-2a", "part": 6, "question": "Choose the correct answer for blank (1):", "options": ["expanding", "reducing", "suspending", "reviewing"], "answer": 0, "explanation": "\u2705 <b>Expanding</b> (M\u1edf r\u1ed9ng). <br>\ud83d\udca1 C\u00e2u sau li\u1ec7t k\u00ea d\u1ecbch v\u1ee5 m\u1edbi (express service, pickup) \u2192 \u0111ang m\u1edf r\u1ed9ng quy m\u00f4.", "difficulty": "medium"}, {"id": "n6-2b", "part": 6, "question": "Choose the correct answer for blank (2):", "options": ["In contrast", "Furthermore", "Nevertheless", "Instead"], "answer": 1, "explanation": "\u2705 <b>Furthermore</b> (H\u01a1n n\u1eefa). <br>\ud83d\udca1 D\u00f9ng \u0111\u1ec3 b\u1ed5 sung th\u00eam m\u1ed9t tin vui/th\u00f4ng tin t\u00edch c\u1ef1c kh\u00e1c c\u00f9ng chi\u1ec1u.", "difficulty": "medium"}, {"id": "n6-2c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["This promotion will be automatically applied to eligible orders at checkout.", "Customers must contact our support team to claim this discount.", "The offer is limited to customers who have made at least three previous purchases.", "Additional products will be added to the promotion in the coming weeks."], "answer": 0, "explanation": "SI: ng\u1eef c\u1ea3nh l\u00e0 email th\u00f4ng b\u00e1o \u01b0u \u0111\u00e3i cho \u0111\u01a1n h\u00e0ng \u0111\u1ea7u ti\u00ean. \"Automatically applied at checkout\" = gi\u1ea3i th\u00edch c\u00e1ch \u00e1p d\u1ee5ng, k\u1ebft n\u1ed1i tr\u1ef1c ti\u1ebfp v\u1edbi \"first five orders\" \u0111\u00e3 \u0111\u1ec1 c\u1eadp."}, {"id": "n6-2d", "part": 6, "question": "Choose the correct answer for blank (4):", "options": ["inconvenient", "exceptional", "average", "infrequent"], "answer": 1, "explanation": "\u2705 <b>Exceptional</b> (Xu\u1ea5t s\u1eafc/\u0110\u1eb7c bi\u1ec7t). <br>\ud83d\udca1 L\u1eddi h\u1ee9a v\u1ec1 d\u1ecbch v\u1ee5 c\u1ee7a doanh nghi\u1ec7p lu\u00f4n d\u00f9ng c\u00e1c t\u1eeb mang ngh\u0129a c\u1ef1c k\u1ef3 t\u1ed1t.", "difficulty": "medium"}]}, {"passage": "NOTICE TO ALL TENANTS\n\nRe: Building Maintenance Schedule \u2013 Elevator Servicing\n\nDear Residents of Harborview Towers,\n\nThis notice is to inform you that the elevators in Building A will undergo ____(1)____ maintenance from Saturday, April 12 to Sunday, April 13. During this period, the elevators will be completely out of service.\n\n____(2)____, residents requiring assistance with moving heavy items between floors should contact building management at least 24 hours in advance so that we can make arrangements.\n\nWe apologize for any inconvenience this may cause and appreciate your patience. The maintenance is ____(3)____ to prevent more serious problems in the future and to ensure the safety of all residents. For urgent matters, please contact the front desk, which will be ____(4)____ 24 hours a day during the maintenance period.\n\nSincerely,\nHarborview Towers Management", "passageTitle": "Announcement: Staff Training", "type": "single", "questions": [{"id": "n6-3a", "part": 6, "question": "Choose the correct answer for blank (1):", "options": ["scheduled", "surprising", "optional", "brief"], "answer": 0, "explanation": "\u2705 <b>Scheduled</b> (Theo l\u1ecbch). <br>\ud83d\udca1 'Scheduled maintenance' l\u00e0 c\u1ee5m t\u1eeb chu\u1ea9n cho c\u00e1c th\u00f4ng b\u00e1o b\u1ea3o tr\u00ec t\u00f2a nh\u00e0.", "difficulty": "medium"}, {"id": "n6-3b", "part": 6, "question": "Choose the correct answer for blank (2):", "options": ["As a result", "In addition", "Consequently", "Therefore"], "answer": 1, "explanation": "\u2705 <b>In addition</b> (Ngo\u00e0i ra). <br>\ud83d\udca1 B\u1ed5 sung th\u00eam h\u01b0\u1edbng d\u1eabn cho c\u01b0 d\u00e2n khi thang m\u00e1y h\u1ecfng.", "difficulty": "medium"}, {"id": "n6-3c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["This update is part of our ongoing commitment to maintaining a safe working environment.", "The changes were requested by employees in the most recent satisfaction survey.", "Staff who do not attend the training session will be asked to work from home.", "The new procedures apply only to staff hired after January 1 of this year."], "answer": 0, "explanation": "SI: th\u00f4ng b\u00e1o v\u1ec1 c\u1eadp nh\u1eadt an to\u00e0n/\u0111\u00e0o t\u1ea1o \u2192 c\u00e2u \u0111i\u1ec1n ph\u1ea3i gi\u1ea3i th\u00edch m\u1ee5c \u0111\u00edch. \"Ongoing commitment to a safe working environment\" = m\u1ee5c \u0111\u00edch ch\u00ednh th\u1ee9c, g\u1eafn v\u1edbi t\u1eeb \"prevent\" trong c\u00e2u tr\u01b0\u1edbc."}, {"id": "n6-3d", "part": 6, "question": "Choose the correct answer for blank (4):", "options": ["staffed", "closed", "renovated", "relocated"], "answer": 0, "explanation": "\u2705 <b>Staffed</b> (C\u00f3 nh\u00e2n vi\u00ean tr\u1ef1c). <br>\ud83d\udca1 Th\u00f4ng b\u00e1o qu\u1ea7y l\u1ec5 t\u00e2n s\u1ebd 'c\u00f3 ng\u01b0\u1eddi tr\u1ef1c' 24/24 \u0111\u1ec3 h\u1ed7 tr\u1ee3 kh\u00e1ch.", "difficulty": "medium"}]}, {"passage": "From: Oliver Grant <o.grant@paxtongroup.com>\nTo: All Staff\nSubject: Introduction of New Expense Reporting System\n\nDear Colleagues,\n\nAs of April 1, Paxton Group will transition from paper-based expense forms to a new digital expense reporting platform, ExpenseLink Pro. This change is ____(1)____ to streamline the approval process and reduce processing times.\n\nAll employees will be required to attend a 45-minute training session to familiarize ____(2)____ with the new system. Sessions will be held twice daily from March 20 through March 28.\n\n____(3)____, paper forms will no longer be accepted after March 31. Any expenses submitted on paper after this date will not be processed and will need to be resubmitted digitally.\n\nPlease do not hesitate to contact the Finance Department if you have any questions or concerns. We look forward to a ____(4)____ transition.\n\nBest regards,\nOliver Grant\nChief Financial Officer", "passageTitle": "Letter: Partnership Proposal", "type": "single", "questions": [{"id": "n6-4a", "part": 6, "question": "Choose the correct answer for blank (1):", "options": ["designed", "refused", "hesitated", "delayed"], "answer": 0, "explanation": "\u2705 <b>Designed</b>. <br>\ud83d\udca1 <i>Collocation:</i> 'Be designed to do something' (\u0110\u01b0\u1ee3c thi\u1ebft k\u1ebf nh\u1eb1m...). D\u00f9ng cho ph\u1ea7n m\u1ec1m/h\u1ec7 th\u1ed1ng.", "difficulty": "medium"}, {"id": "n6-4b", "part": 6, "question": "Choose the correct answer for blank (2):", "options": ["them", "themselves", "their", "they"], "answer": 1, "explanation": "\u2705 <b>Themselves</b>. <br>\ud83d\udca1 <i>C\u1ee5m c\u1ed1 \u0111\u1ecbnh:</i> 'Familiarize themselves with' (L\u00e0m quen v\u1edbi c\u00e1i g\u00ec).", "difficulty": "medium"}, {"id": "n6-4c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Effective from the date of this notice, all expense submissions must use the new digital platform.", "Employees who prefer the paper system may continue using it until further notice.", "The new platform has already been adopted by more than 200 organisations globally.", "Finance staff will be available to answer questions about the new system daily."], "answer": 0, "explanation": "SI: th\u00f4ng b\u00e1o v\u1ec1 \"paper forms no longer accepted after March 31\". C\u00e2u \u0111i\u1ec1n ph\u1ea3i chuy\u1ec3n ti\u1ebfp sang h\u00e0nh \u0111\u1ed9ng b\u1eaft bu\u1ed9c. \"Effective from this notice, must use digital platform\" = gi\u1edbi thi\u1ec7u y\u00eau c\u1ea7u m\u1edbi."}, {"id": "n6-4d", "part": 6, "question": "Choose the correct answer for blank (4):", "options": ["difficult", "smooth", "sudden", "lengthy"], "answer": 1, "explanation": "\u2705 <b>Smooth</b> (Su\u00f4n s\u1ebb). <br>\ud83d\udca1 'A smooth transition' l\u00e0 mong mu\u1ed1n chung khi thay \u0111\u1ed5i h\u1ec7 th\u1ed1ng.", "difficulty": "medium"}]}, {"passage": "GREENFIELD COMMUNITY CENTER\nNewsletters \u2013 Spring Edition\n\nSpring Programs Now Open for Registration!\n\nGreenfield Community Center is delighted to announce its spring program lineup, which ____(1)____ fitness, arts, and youth development. Registration is now open for all community members aged 5 and above.\n\nHighlights this season include a new Photography for Beginners course, a ten-week yoga series for seniors, and a weekend robotics camp for children aged 8\u201314. All programs are ____(2)____ by qualified instructors with extensive backgrounds in their fields.\n\n____(3)____, members who register before March 10 will receive a 15% early-bird discount. Membership is not required to enroll in programs, but members enjoy priority registration and reduced fees throughout the year.\n\nFor a complete program guide and registration details, please ____(4)____ our website at www.greenfieldcc.org or visit the center during regular hours.\n\nWe look forward to seeing you this spring!", "passageTitle": "Memo: Remote Work Policy", "type": "single", "questions": [{"id": "n6-5a", "part": 6, "question": "Choose the correct answer for blank (1):", "options": ["concludes", "spans", "lacks", "avoids"], "answer": 1, "explanation": "\u2705 <b>Spans</b> (Tr\u1ea3i r\u1ed9ng/Bao tr\u00f9m). <br>\ud83d\udca1 Ch\u1ec9 ch\u01b0\u01a1ng tr\u00ecnh bao g\u1ed3m nhi\u1ec1u l\u0129nh v\u1ef1c kh\u00e1c nhau.", "difficulty": "medium"}, {"id": "n6-5b", "part": 6, "question": "Choose the correct answer for blank (2):", "options": ["led", "refused", "declined", "cancelled"], "answer": 0, "explanation": "\u2705 <b>Led</b> (D\u1eabn d\u1eaft). <br>\ud83d\udca1 <i>B\u1ecb \u0111\u1ed9ng:</i> 'Led by instructors' (\u0110\u01b0\u1ee3c ph\u1ee5 tr\u00e1ch b\u1edfi c\u00e1c gi\u1ea3ng vi\u00ean).", "difficulty": "medium"}, {"id": "n6-5c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["In addition, members who register before March 10 will receive a 15% early-bird discount.", "However, the discount is not applicable to premium membership plans.", "Membership is available exclusively to residents of the local area.", "The discount will be applied automatically to all new registrations."], "answer": 0, "explanation": "SI: ng\u1eef c\u1ea3nh memo v\u1ec1 ch\u01b0\u01a1ng tr\u00ecnh \u0111\u0103ng k\u00fd s\u1edbm. \"In addition...early-bird discount\" = th\u00f4ng tin b\u1ed5 sung d\u00f9ng \"In addition\" nh\u01b0 t\u1eeb n\u1ed1i, k\u1ebft n\u1ed1i v\u1edbi \u0111o\u1ea1n tr\u00ean v\u1ec1 \u0111\u0103ng k\u00fd."}, {"id": "n6-5d", "part": 6, "question": "Choose the correct answer for blank (4):", "options": ["avoid", "visit", "deactivate", "contact"], "answer": 1, "explanation": "\u2705 <b>Visit</b>. <br>\ud83d\udca1 'Visit our website' l\u00e0 l\u1eddi k\u00eau g\u1ecdi h\u00e0nh \u0111\u1ed9ng (CTA) ph\u1ed5 bi\u1ebfn.", "difficulty": "medium"}]}, {"passage": "Memo\n\nTo: Research & Development Team\nFrom: Dr. Sarah Okonkwo, Director of Innovation\nDate: September 4\nRe: Phase 2 Project Timelines\n\nDear Team,\n\nFollowing last week's project review meeting, I would like to ____(1)____ the key milestones for Phase 2 of the Helios Project.\n\nAs discussed, the prototype must be completed and ready for internal testing by October 15. The testing phase is ____(2)____ to run for approximately four weeks, after which a full report must be submitted to the executive board by November 30.\n\nI am aware that these timelines are demanding. ____(3)____, I am confident in each of your abilities and I am committed to providing whatever resources are necessary to support your work.\n\nPlease review the updated project schedule attached to this memo and confirm your availability for the first testing review, ____(4)____ for October 18.\n\nThank you for your continued dedication.\n\nDr. Sarah Okonkwo", "passageTitle": "Notice: System Maintenance", "type": "single", "questions": [{"id": "n6-6a", "part": 6, "question": "Choose the correct answer for blank (1):", "options": ["confirm", "ignore", "extend", "remove"], "answer": 0, "explanation": "\u2705 <b>Confirm</b> (X\u00e1c nh\u1eadn). <br>\ud83d\udca1 <i>M\u1ee5c \u0111\u00edch:</i> Email ch\u1ed1t l\u1ea1i c\u00e1c m\u1ed1c th\u1eddi gian \u0111\u00e3 th\u1ea3o lu\u1eadn.", "difficulty": "medium"}, {"id": "n6-6b", "part": 6, "question": "Choose the correct answer for blank (2):", "options": ["scheduled", "cancelled", "avoided", "dismissed"], "answer": 0, "explanation": "\u2705 <b>Scheduled</b>. <br>\ud83d\udca1 <i>Collocation:</i> 'Scheduled to run for...' (D\u1ef1 ki\u1ebfn k\u00e9o d\u00e0i trong...). ", "difficulty": "medium"}, {"id": "n6-6c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["I am confident in each of your abilities and committed to providing the necessary support.", "Those who fail to meet their targets this quarter will be placed on a performance plan.", "The company will be conducting a full review of all employee performance metrics.", "Please note that the upcoming changes will affect all departments equally."], "answer": 0, "explanation": "SI: th\u00f4ng b\u00e1o/memo khuy\u1ebfn kh\u00edch \u0111\u1ed9i ng\u0169 \u2192 c\u00e2u \u0111i\u1ec1n ph\u1ea3i l\u00e0 th\u00f4ng \u0111i\u1ec7p t\u00edch c\u1ef1c, \u1ee7ng h\u1ed9. \"Confident in abilities and committed to support\" = k\u1ebft n\u1ed1i v\u1edbi gi\u1ecdng v\u0103n l\u1ea1c quan tr\u01b0\u1edbc \u0111\u00f3."}, {"id": "n6-6d", "part": 6, "question": "Choose the correct answer for blank (4):", "options": ["tentatively scheduled", "already cancelled", "recently approved", "currently ongoing"], "answer": 0, "explanation": "\u2705 <b>Tentatively scheduled</b> (D\u1ef1 ki\u1ebfn t\u1ea1m th\u1eddi). <br>\ud83d\udca1 <i>T\u1eeb kh\u00f3a 2025:</i> 'Tentatively' \u00e1m ch\u1ec9 l\u1ecbch tr\u00ecnh c\u00f3 th\u1ec3 thay \u0111\u1ed5i t\u00f9y t\u00ecnh h\u00ecnh.", "difficulty": "medium"}]}, {"passage": "ANNOUNCEMENT\n\nTo: All Staff\nFrom: CEO's Office\nSubject: Workplace Flexibility Policy Update\n\nWe are pleased to announce a significant update to our workplace flexibility policy, effective the first Monday of next month.\n\nEmployees in eligible roles will now be ____(1)____ to choose between three working arrangements: fully on-site, hybrid (three days in office), or fully remote. Managers will review each request and confirm arrangements within five ____(2)____ days.\n\nWe believe this change reflects our commitment to employee well-being ____(3)____ maintaining the high standards of collaboration and performance our clients expect. Detailed guidelines will be shared via the company intranet.\n\n____(4)____, if you have any questions, please contact your HR business partner directly.", "passageTitle": "Email: Conference Registration", "type": "single", "questions": [{"id": "b6-1a", "part": 6, "question": "Blank (1):", "options": ["allowed", "permitting", "let", "enable"], "answer": 0, "explanation": "'Be allowed to' = \u0111\u01b0\u1ee3c ph\u00e9p (b\u1ecb \u0111\u1ed9ng v\u1edbi modal sense).", "difficulty": "medium"}, {"id": "b6-1b", "part": 6, "question": "Blank (2):", "options": ["business", "working", "calendar", "office"], "answer": 0, "explanation": "'Five business days' = 5 ng\u00e0y l\u00e0m vi\u1ec7c (c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong v\u0103n b\u1ea3n c\u00f4ng ty).", "difficulty": "medium"}, {"id": "b6-1c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["This commitment applies to all staff, including those working from home or at satellite offices.", "Employees who travel frequently are exempt from the standard requirements.", "Please forward this message to any team members who may not have received it directly.", "New guidelines will be distributed at the annual company meeting next spring."], "answer": 0, "explanation": "SI: ng\u1eef c\u1ea3nh email v\u1ec1 ch\u00ednh s\u00e1ch \u00e1p d\u1ee5ng \"maintaining standards\". C\u00e2u \"applies to all staff, including remote\" = l\u00e0m r\u00f5 ph\u1ea1m vi \u00e1p d\u1ee5ng, tr\u00e1nh hi\u1ec3u nh\u1ea7m."}, {"id": "b6-1d", "part": 6, "question": "Blank (4):", "options": ["In the meantime", "As a reminder", "In conclusion", "That said"], "answer": 1, "explanation": "'As a reminder' = nh\u1eafc l\u1ea1i. C\u00e2u cu\u1ed1i nh\u1eafc c\u00e1ch li\u00ean h\u1ec7 HR.", "difficulty": "medium"}]}, {"passage": "From: David Okafor <d.okafor@nexuspartners.com>\nTo: Customer Support <support@primelogistics.com>\nDate: February 14\n\nDear Prime Logistics Support Team,\n\nI am writing to follow up on shipment #PL-7782, which was ____(1)____ to arrive at our warehouse on February 10. As of today, the tracking portal shows the package is still in transit with no estimated delivery date.\n\nThis delay is causing significant disruption to our operations, as the goods contained in this shipment are urgently ____(2)____ for a production run scheduled for February 20.\n\nCould you please provide an ____(3)____ explanation of the delay and a confirmed delivery date? If delivery cannot be guaranteed before February 18, we may need to ____(4)____ alternative sourcing arrangements.\n\nThank you for your prompt attention to this matter.\n\nDavid Okafor", "passageTitle": "Memo: Travel Expense Guidelines", "type": "single", "questions": [{"id": "b6-2a", "part": 6, "question": "Blank (1):", "options": ["scheduled", "supposed", "estimated", "assumed"], "answer": 0, "explanation": "'Scheduled to arrive' = \u0111\u01b0\u1ee3c l\u00ean l\u1ecbch giao v\u00e0o ng\u00e0y c\u1ee5 th\u1ec3 (shipment booking). 'Supposed/estimated/assumed' \u0111\u1ec1u ch\u1ec9 ph\u1ecfng \u0111o\u00e1n kh\u00f4ng ch\u00ednh th\u1ee9c, kh\u00f4ng d\u00f9ng cho tracking shipment.", "difficulty": "medium"}, {"id": "b6-2b", "part": 6, "question": "Blank (2):", "options": ["needed", "requested", "required", "demanded"], "answer": 2, "explanation": "'Required for a production run' = c\u1ea7n thi\u1ebft cho m\u1ed9t \u0111\u1ee3t s\u1ea3n xu\u1ea5t. 'Required' m\u1ea1nh nh\u1ea5t v\u00e0 ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh kh\u1ea9n c\u1ea5p.", "difficulty": "medium"}, {"id": "b6-2c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Could you please provide a written explanation of the delay and a confirmed delivery date?", "We would appreciate it if you could process a full refund immediately.", "Please arrange for a replacement unit to be sent by express delivery.", "We are considering terminating our agreement if the issue is not resolved promptly."], "answer": 0, "explanation": "SI: email y\u00eau c\u1ea7u sau khi giao h\u00e0ng tr\u1ec5. \"Written explanation + confirmed delivery date\" = y\u00eau c\u1ea7u th\u00f4ng tin h\u1ee3p l\u00fd v\u00e0 chuy\u00ean nghi\u1ec7p nh\u1ea5t. C\u00e1c ph\u01b0\u01a1ng \u00e1n kh\u00e1c qu\u00e1 \u0111\u1ed1i \u0111\u1ea7u ho\u1eb7c kh\u00f4ng li\u00ean quan."}, {"id": "b6-2d", "part": 6, "question": "Blank (4):", "options": ["explore", "consider", "seek", "pursue"], "answer": 1, "explanation": "'Consider alternative sourcing' = c\u00e2n nh\u1eafc ngu\u1ed3n cung thay th\u1ebf. L\u1ecbch s\u1ef1 nh\u1ea5t trong ng\u1eef c\u1ea3nh n\u00e0y.", "difficulty": "medium"}]}, {"passage": "MEMORANDUM\n\nTo: All Research Staff\nFrom: Dr. Linda Marsh, Head of R&D\nDate: October 7\nRe: Updated Lab Access Protocols\n\nFollowing last month's safety review, the following updated protocols are now ____(1)____ for all laboratory access:\n\n1. All staff must obtain a new access badge from Security before October 15.\n2. Entry after 8:00 p.m. requires supervisor ____(2)____.\n3. Personal protective equipment (PPE) is ____(3)____ at all times in Lab Areas B and C.\n\nThese measures are ____(4)____ to prevent a recurrence of the minor incidents documented in the recent safety audit. Full compliance is expected by all personnel.\n\nPlease direct any questions to the Safety Officer, Mr. James Choo, at extension 4422.", "passageTitle": "Email: Job Application Response", "type": "single", "questions": [{"id": "b6-3a", "part": 6, "question": "Blank (1):", "options": ["required", "recommended", "optional", "requested"], "answer": 0, "explanation": "'Now required for all laboratory access' = b\u1eaft bu\u1ed9c. Ng\u1eef c\u1ea3nh sau safety review.", "difficulty": "medium"}, {"id": "b6-3b", "part": 6, "question": "Blank (2):", "options": ["permission", "approval", "consent", "authorization"], "answer": 1, "explanation": "'Supervisor approval' = ph\u00ea duy\u1ec7t c\u1ee7a c\u1ea5p tr\u00ean. 'Approval' ph\u1ed5 bi\u1ebfn nh\u1ea5t trong v\u0103n b\u1ea3n n\u1ed9i b\u1ed9.", "difficulty": "medium"}, {"id": "b6-3c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["All personnel must wear appropriate protective equipment at all times in Lab Areas B and C.", "Lab access is restricted to employees who have completed the required safety training.", "Visitors to the laboratory must be accompanied by a designated staff member.", "Protective equipment is available at no cost from the safety officer on each floor."], "answer": 0, "explanation": "SI: th\u00f4ng b\u00e1o an to\u00e0n ph\u00f2ng lab. \"Must wear PPE at all times in Lab B and C\" = quy \u0111\u1ecbnh b\u1eaft bu\u1ed9c tr\u1ef1c ti\u1ebfp, logical ti\u1ebfp theo sau khi gi\u1edbi thi\u1ec7u khu v\u1ef1c ph\u00f2ng lab."}, {"id": "b6-3d", "part": 6, "question": "Blank (4):", "options": ["designed", "intended", "arranged", "scheduled"], "answer": 1, "explanation": "'Intended to prevent' = nh\u1eb1m m\u1ee5c \u0111\u00edch ng\u0103n ch\u1eb7n (bi\u1ec7n ph\u00e1p/quy tr\u00ecnh). 'Designed' d\u00f9ng cho v\u1eadt th\u1ec3 k\u1ef9 thu\u1eadt; 'arranged' = \u0111\u01b0\u1ee3c s\u1eafp x\u1ebfp/t\u1ed5 ch\u1ee9c; 'scheduled' = \u0111\u01b0\u1ee3c l\u00ean l\u1ecbch.", "difficulty": "medium"}]}, {"passage": "NOVA FITNESS APP \u2013 PRODUCT UPDATE\nNewsletter | November Edition\n\nHello Nova Members,\n\nThis month's update brings exciting new ____(1)____ to the Nova Fitness App based on your valuable feedback.\n\nFirst, we have introduced a customizable dashboard that allows you to ____(2)____ the metrics most important to your personal fitness goals. Second, a new sleep tracking feature has been added to provide a ____(3)____ view of your overall health and recovery.\n\nThese updates are available now for both iOS and Android devices. To access them, ensure your app is updated to version 4.2 or ____(4)____.\n\nWe hope you enjoy these improvements. As always, we welcome your feedback through the in-app survey feature.", "passageTitle": "Notice: Parking Regulations", "type": "single", "questions": [{"id": "b6-4a", "part": 6, "question": "Blank (1):", "options": ["features", "functions", "improvements", "updates"], "answer": 0, "explanation": "'New features' = t\u00ednh n\u0103ng m\u1edbi. T\u1eeb ph\u1ed5 bi\u1ebfn nh\u1ea5t khi n\u00f3i v\u1ec1 c\u1eadp nh\u1eadt ph\u1ea7n m\u1ec1m.", "difficulty": "medium"}, {"id": "b6-4b", "part": 6, "question": "Blank (2):", "options": ["prioritize", "select", "choose", "track"], "answer": 0, "explanation": "'Prioritize the metrics' = \u01b0u ti\u00ean c\u00e1c ch\u1ec9 s\u1ed1. Ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh t\u00f9y ch\u1ec9nh dashboard.", "difficulty": "medium"}, {"id": "b6-4c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Your doctor will consider these factors in forming an overall view of your health and recovery.", "Please ensure all medications are taken as prescribed and that follow-up appointments are kept.", "A copy of your discharge summary will be sent to your regular physician within 48 hours.", "Patients are encouraged to contact the clinic if they experience any unusual symptoms."], "answer": 0, "explanation": "SI: ng\u1eef c\u1ea3nh l\u00e0 th\u01b0 y t\u1ebf h\u01b0\u1edbng d\u1eabn b\u1ec7nh nh\u00e2n sau \u0111i\u1ec1u tr\u1ecb. \"Doctor will consider these factors\" = k\u1ebft n\u1ed1i danh s\u00e1ch th\u00f4ng tin s\u1ee9c kh\u1ecfe v\u1edbi b\u01b0\u1edbc th\u0103m kh\u00e1m ti\u1ebfp theo."}, {"id": "b6-4d", "part": 6, "question": "Blank (4):", "options": ["above", "higher", "later", "newer"], "answer": 0, "explanation": "'Version 4.2 or above' = phi\u00ean b\u1ea3n 4.2 ho\u1eb7c cao h\u01a1n. 'Or above/higher' c\u1ea3 hai \u0111\u00fang nh\u01b0ng 'above' chu\u1ea9n nh\u1ea5t.", "difficulty": "medium"}]}, {"passage": "NOTICE TO ALL TENANTS\nSilverstone Business Park \u2013 Building C\n\nThis notice is to advise all tenants of upcoming ____(1)____ to the parking facility located adjacent to Building C.\n\nBeginning Monday, September 9, parking spaces 1 through 50 will be temporarily unavailable for a period of three weeks. During this time, tenants may use the overflow parking lot ____(2)____ across Ferndale Road.\n\nWe regret any inconvenience this may cause. ____(3)____, we wish to reassure all tenants that the renovation will significantly improve the overall capacity and safety of the facility.\n\nFor any urgent inquiries, please contact the Building Management Office on the ground floor or call 555-0198. We appreciate your ____(4)____ during this period.", "passageTitle": "Email: Order Confirmation", "type": "single", "questions": [{"id": "b6-5a", "part": 6, "question": "Blank (1):", "options": ["renovations", "constructions", "repairs", "installations"], "answer": 0, "explanation": "'Upcoming renovations' = s\u1eafp ti\u1ebfn h\u00e0nh c\u1ea3i t\u1ea1o. Ph\u1ed5 bi\u1ebfn nh\u1ea5t cho facility improvement.", "difficulty": "medium"}, {"id": "b6-5b", "part": 6, "question": "Blank (2):", "options": ["located", "situated", "placed", "found"], "answer": 0, "explanation": "'Located across' = n\u1eb1m \u1edf ph\u00eda b\u00ean kia. 'Located' l\u00e0 participle ph\u1ed5 bi\u1ebfn nh\u1ea5t.", "difficulty": "medium"}, {"id": "b6-5c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["In the meantime, we wish to reassure all tenants that the renovation will significantly improve the overall capacity and safety of the building.", "Despite the inconvenience, all rental agreements will remain valid during the renovation period.", "We apologise for any disruption and thank you for your continued patience and understanding.", "The building management team will provide weekly updates throughout the renovation process."], "answer": 0, "explanation": "SI: th\u00f4ng b\u00e1o c\u1ea3i t\u1ea1o to\u00e0 nh\u00e0. \"Reassure tenants that renovation will improve capacity and safety\" = c\u00e2u reassurance d\u00f9ng \"In the meantime\" nh\u01b0 t\u1eeb n\u1ed1i th\u1eddi gian \u2014 ph\u00f9 h\u1ee3p v\u1edbi c\u1ea5u tr\u00fac th\u00f4ng b\u00e1o."}, {"id": "b6-5d", "part": 6, "question": "Blank (4):", "options": ["patience", "understanding", "cooperation", "support"], "answer": 1, "explanation": "'Appreciate your understanding' = tr\u00e2n tr\u1ecdng s\u1ef1 th\u00f4ng c\u1ea3m. C\u1ee5m k\u1ebft th\u00fac th\u00f4ng b\u00e1o chu\u1ea9n nh\u1ea5t.", "difficulty": "medium"}]}, {"passage": "From: Priya Nair <p.nair@globaledge.org>\nTo: All Registered Delegates\nDate: June 3\n\nDear Delegates,\n\nWe are delighted to confirm your registration for the Global Edge Leadership Forum, ____(1)____ on June 25\u201327 at the Elara Convention Centre.\n\nYour delegate package includes full access to all keynote sessions, workshops, and networking events. Lunch and refreshments will be ____(2)____ on all three days. Please note that dinner on June 25 is not included and is at your own ____(3)____.\n\nA detailed program schedule and venue map will be emailed to you one week before the event. We kindly ask all delegates to carry their confirmation email or printed badge at all times for ____(4)____ purposes.\n\nWe look forward to welcoming you at the Forum.\n\nWarm regards,\nPriya Nair\nEvents Coordinator, Global Edge", "passageTitle": "Memo: Quarterly Review Schedule", "type": "single", "questions": [{"id": "b6-6a", "part": 6, "question": "Blank (1):", "options": ["scheduled", "taking place", "held", "occurring"], "answer": 0, "explanation": "'Scheduled on June 25\u201327' = \u0111\u01b0\u1ee3c l\u00ean l\u1ecbch v\u00e0o ng\u00e0y... (participle modifier).", "difficulty": "medium"}, {"id": "b6-6b", "part": 6, "question": "Blank (2):", "options": ["provided", "charged", "sold", "cooked"], "answer": 0, "explanation": "'Provided' = \u0111\u01b0\u1ee3c cung c\u1ea5p (b\u1ecb \u0111\u1ed9ng chu\u1ea9n cho d\u1ecbch v\u1ee5 \u0103n u\u1ed1ng t\u1ea1i s\u1ef1 ki\u1ec7n). 'Charged' = b\u1ecb t\u00ednh ph\u00ed (ngh\u0129a ng\u01b0\u1ee3c l\u1ea1i); 'sold' v\u00e0 'cooked' kh\u00f4ng ph\u00f9 h\u1ee3p v\u0103n phong th\u00f4ng b\u00e1o s\u1ef1 ki\u1ec7n.", "difficulty": "medium"}, {"id": "b6-6c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Please confirm your availability by replying to this email no later than Friday.", "The meeting agenda will be distributed one week before the scheduled date.", "Attendance at the quarterly review is mandatory for all senior management staff.", "Questions about the review process should be directed to your line manager."], "answer": 2, "explanation": "SI: memo v\u1ec1 l\u1ecbch h\u1ecdp \u0111\u00e1nh gi\u00e1 qu\u00fd. \"Mandatory for senior management\" = th\u00f4ng tin c\u1ea7n thi\u1ebft nh\u1ea5t sau khi th\u00f4ng b\u00e1o l\u1ecbch h\u1ecdp \u2014 l\u00e0m r\u00f5 ai b\u1eaft bu\u1ed9c ph\u1ea3i tham d\u1ef1."}, {"id": "b6-6d", "part": 6, "question": "Blank (4):", "options": ["identification", "security", "verification", "authentication"], "answer": 0, "explanation": "'For identification purposes' = cho m\u1ee5c \u0111\u00edch nh\u1eadn d\u1ea1ng/ki\u1ec3m tra danh t\u00ednh (c\u1ee5m c\u1ed1 \u0111\u1ecbnh chu\u1ea9n).", "difficulty": "medium"}]}, {"passage": "Crestwood Financial Services\n875 Bay Avenue, Suite 200\nVancouver, BC\n\nApril 15\n\nDear Ms. Fujimoto,\n\nOn behalf of Crestwood Financial Services, I am pleased to ____(1)____ you a formal offer of employment for the position of Senior Risk Analyst.\n\nYour starting annual salary will be CAD 98,000, with eligibility for a performance bonus of up to 15% ____(2)____ on your year-end review. You will also receive a comprehensive benefits package, including health, dental, and vision coverage, as well as five weeks of ____(3)____ leave per year.\n\nYour anticipated start date is May 1. Please ____(4)____ your acceptance of this offer by April 22 by signing and returning the enclosed contract.\n\nWe are excited about the prospect of you joining our team.\n\nSincerely,\nRobert Hall\nHead of Human Resources", "passageTitle": "Letter: Vendor Contract Renewal", "type": "single", "questions": [{"id": "b6-7a", "part": 6, "question": "Blank (1):", "options": ["extend", "give", "provide", "offer"], "answer": 0, "explanation": "'Extend a formal offer' = g\u1eedi l\u1eddi m\u1eddi ch\u00ednh th\u1ee9c (formal collocation trong offer letter).", "difficulty": "medium"}, {"id": "b6-7b", "part": 6, "question": "Blank (2):", "options": ["based", "depending", "subject", "contingent"], "answer": 0, "explanation": "'Based on your year-end review' = d\u1ef1a tr\u00ean \u0111\u00e1nh gi\u00e1 cu\u1ed1i n\u0103m (collocation chu\u1ea9n).", "difficulty": "medium"}, {"id": "b6-7c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Full-time employees are entitled to 20 days of annual leave per year.", "Part-time staff receive annual leave on a pro-rata basis according to contracted hours.", "Annual leave requests must be submitted at least two weeks in advance.", "Unused annual leave may be carried over to the following calendar year with manager approval."], "answer": 0, "explanation": "SI: ng\u1eef c\u1ea3nh l\u00e0 h\u1ee3p \u0111\u1ed3ng/ch\u00ednh s\u00e1ch nh\u00e2n s\u1ef1 v\u1ec1 ngh\u1ec9 ph\u00e9p. \"Full-time employees entitled to 20 days\" = th\u00f4ng tin c\u01a1 b\u1ea3n nh\u1ea5t, logic nh\u1ea5t \u0111\u1ec3 \u0111\u1eb7t \u0111\u1ea7u \u0111o\u1ea1n v\u1ec1 leave entitlement."}, {"id": "b6-7d", "part": 6, "question": "Blank (4):", "options": ["confirm", "acknowledge", "sign", "indicate"], "answer": 0, "explanation": "'Confirm your acceptance' = x\u00e1c nh\u1eadn ch\u1ea5p nh\u1eadn (c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong offer letter).", "difficulty": "medium"}]}, {"passage": "From: Customer Relations <support@oriontech.com>\nTo: Samuel Wu <s.wu@email.com>\nDate: March 18\n\nDear Mr. Wu,\n\nThank you for ____(1)____ out to us regarding your recent experience with our OrionCloud subscription service.\n\nWe sincerely apologize for the technical difficulties you ____(2)____ during the billing process. After reviewing your account, we can confirm that you were incorrectly charged twice for your February subscription. A full refund of USD 49.99 has been ____(3)____ to your original payment method and should appear within 3\u20135 business days.\n\nWe have also applied a one-month complimentary subscription to your account as a gesture of goodwill. We hope this ____(4)____ for the inconvenience caused.\n\nPlease do not hesitate to contact us if you require any further assistance.\n\nBest regards,\nOrion Technologies Customer Relations", "passageTitle": "Email: Customer Complaint Response", "type": "single", "questions": [{"id": "b6-8a", "part": 6, "question": "Blank (1):", "options": ["reaching", "getting", "contacting", "writing"], "answer": 0, "explanation": "'Thank you for reaching out to us' = c\u1ea3m \u01a1n \u0111\u00e3 li\u00ean h\u1ec7 (c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong customer service).", "difficulty": "medium"}, {"id": "b6-8b", "part": 6, "question": "Blank (2):", "options": ["experienced", "encountered", "suffered", "faced"], "answer": 1, "explanation": "'Encountered difficulties' = g\u1eb7p ph\u1ea3i kh\u00f3 kh\u0103n. 'Encountered' ph\u1ed5 bi\u1ebfn nh\u1ea5t v\u1edbi 'difficulties/issues'.", "difficulty": "medium"}, {"id": "b6-8c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["The refund has been processed and will be returned to your original payment method within 3\u20135 business days.", "We will send a replacement item to your delivery address within 7 business days.", "A voucher for your next purchase has been added to your customer account.", "Your complaint has been forwarded to our quality control team for further review."], "answer": 0, "explanation": "SI: email ph\u1ea3n h\u1ed3i khi\u1ebfu n\u1ea1i kh\u00e1ch h\u00e0ng \u2192 c\u00e2u \u0111i\u1ec1n v\u1ec1 ho\u00e0n ti\u1ec1n ph\u1ea3i th\u00f4ng b\u00e1o tr\u1ef1c ti\u1ebfp v\u1ec1 h\u00e0nh \u0111\u1ed9ng \u0111\u00e3 th\u1ef1c hi\u1ec7n. \"Refund has been processed...within 3-5 days\" = th\u00f4ng b\u00e1o ch\u00ednh x\u00e1c nh\u1ea5t."}, {"id": "b6-8d", "part": 6, "question": "Blank (4):", "options": ["compensates", "makes up", "accounts", "corrects"], "answer": 0, "explanation": "'Compensates for the inconvenience' = b\u00f9 \u0111\u1eafp s\u1ef1 b\u1ea5t ti\u1ec7n (collocation c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}]}, {"passage": "From: Operations Director\nTo: All Store Managers\nDate: November 12\nSubject: Updated Returns and Exchanges Policy\n\nDear Team,\n\nI am writing to inform you of changes to our retail returns and exchange policy, ____(1)____ on December 1.\n\nKey changes include: extended return window from 14 to 30 days for all full-priced items; exchanges ____(2)____ without a receipt for items purchased using a loyalty card, as purchases can be verified in our system; and a new tiered refund structure for sale items depending on the discount level applied at the time of purchase.\n\nFull details and updated training materials will be available on the staff portal by November 22. All store managers are ____(3)____ to brief their teams before the policy takes effect.\n\n____(4)____ let us know if you foresee any operational challenges in implementing these changes at your location.\n\nBest regards,\nLinda Frost\nOperations Director", "passageTitle": "Notice: Holiday Schedule", "type": "single", "questions": [{"id": "c6-1a", "part": 6, "question": "Blank (1):", "options": ["effective", "effecting", "effectively", "effected"], "answer": 0, "explanation": "'Effective on December 1' = c\u00f3 hi\u1ec7u l\u1ef1c v\u00e0o ng\u00e0y 1/12. 'Effective' d\u00f9ng nh\u01b0 t\u00ednh t\u1eeb/gi\u1edbi t\u1eeb \u0111\u1ec3 ch\u1ec9 ng\u00e0y c\u00f3 hi\u1ec7u l\u1ef1c.", "difficulty": "medium"}, {"id": "c6-1b", "part": 6, "question": "Blank (2):", "options": ["will allow", "are allowed", "allowing", "allowed"], "answer": 1, "explanation": "'Exchanges are allowed without a receipt' = \u0111\u1ed5i h\u00e0ng kh\u00f4ng c\u1ea7n bi\u00ean lai (b\u1ecb \u0111\u1ed9ng hi\u1ec7n t\u1ea1i). Ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh ch\u00ednh s\u00e1ch.", "difficulty": "medium"}, {"id": "c6-1c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["All managers are asked to brief their teams before the policy takes effect.", "Employees who do not comply with the updated policy may face disciplinary action.", "The new policy was developed in consultation with the employee advisory committee.", "A revised version of the employee handbook will be issued early next month."], "answer": 0, "explanation": "SI: th\u00f4ng b\u00e1o ch\u00ednh s\u00e1ch m\u1edbi. \"Managers brief their teams before policy takes effect\" = h\u00e0nh \u0111\u1ed9ng ti\u1ebfp theo t\u1ef1 nhi\u00ean v\u00e0 c\u1ea7n thi\u1ebft nh\u1ea5t sau khi th\u00f4ng b\u00e1o thay \u0111\u1ed5i ch\u00ednh s\u00e1ch."}, {"id": "c6-1d", "part": 6, "question": "Blank (4):", "options": ["However", "Therefore", "Please", "Despite"], "answer": 2, "explanation": "'Please let us know' = xin h\u00e3y cho ch\u00fang t\u00f4i bi\u1ebft. C\u00e2u k\u00eau g\u1ecdi ph\u1ea3n h\u1ed3i t\u1eeb store managers.", "difficulty": "medium"}]}, {"passage": "IMPORTANT NOTICE TO ALL SUPPLIERS\nTerraForm Manufacturing \u2013 Procurement Department\nDate: March 4\n\nDear Valued Supplier,\n\nAs part of our ongoing commitment to operational excellence, TerraForm Manufacturing is ____(1)____ a new Supplier Portal, launching April 1.\n\nStarting April 1, all invoices, delivery confirmations, and compliance documents must be submitted ____(2)____ through the portal. The current email-based submission process will be discontinued on that date.\n\nTo register for portal access, please visit suppliers.terraform-mfg.com and complete the online registration form. You will receive login credentials within three ____(3)____ days of submitting your registration.\n\n____(4)____, if you experience any difficulties registering, our Procurement Support team is available at procurement@terraform-mfg.com or +1 800 400 7700.\n\nWe appreciate your continued partnership and cooperation.\n\nTerraForm Procurement Team", "passageTitle": "Memo: Health & Safety Update", "type": "single", "questions": [{"id": "c6-2a", "part": 6, "question": "Blank (1):", "options": ["introducing", "launching", "opening", "creating"], "answer": 0, "explanation": "'Introducing a new Supplier Portal' = gi\u1edbi thi\u1ec7u/tri\u1ec3n khai c\u1ed5ng nh\u00e0 cung c\u1ea5p m\u1edbi. Ph\u1ed5 bi\u1ebfn nh\u1ea5t trong announcement v\u1ec1 h\u1ec7 th\u1ed1ng m\u1edbi.", "difficulty": "medium"}, {"id": "c6-2b", "part": 6, "question": "Blank (2):", "options": ["exclusively", "solely", "only", "primarily"], "answer": 0, "explanation": "'Submitted exclusively through the portal' = ph\u1ea3i n\u1ed9p ri\u00eang qua c\u1ed5ng (kh\u00f4ng c\u00f2n c\u00e1ch n\u00e0o kh\u00e1c). 'Exclusively' m\u1ea1nh v\u00e0 r\u00f5 r\u00e0ng nh\u1ea5t.", "difficulty": "medium"}, {"id": "c6-2c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Your membership card will be mailed to you within five business days of submitting your registration.", "You may visit any of our branches to collect your membership card in person.", "A confirmation email with your member ID will be sent within 24 hours.", "Please allow up to two weeks for your registration to be fully processed."], "answer": 0, "explanation": "SI: ng\u1eef c\u1ea3nh l\u00e0 th\u00f4ng tin v\u1ec1 \u0111\u0103ng k\u00fd th\u00e0nh vi\u00ean. \"Card mailed within five business days\" = th\u00f4ng tin h\u00e0nh ch\u00ednh c\u1ee5 th\u1ec3 nh\u1ea5t, logic nh\u1ea5t v\u1ec1 b\u01b0\u1edbc ti\u1ebfp theo sau \u0111\u0103ng k\u00fd."}, {"id": "c6-2d", "part": 6, "question": "Blank (4):", "options": ["In the event", "As a reminder", "Meanwhile", "On the other hand"], "answer": 0, "explanation": "'In the event (that you experience difficulties)' = trong tr\u01b0\u1eddng h\u1ee3p g\u1eb7p kh\u00f3 kh\u0103n. Ph\u00f9 h\u1ee3p nh\u1ea5t v\u1edbi n\u1ed9i dung h\u1ed7 tr\u1ee3 k\u1ef9 thu\u1eadt.", "difficulty": "medium"}]}, {"passage": "From: Isabel Ferreira <i.ferreira@grandviewhotels.com>\nTo: Reservations Team\nDate: August 9\n\nTeam,\n\nI would like to update you on a situation involving one of our long-standing guests, Mr. Robert Chu, who ____(1)____ with us every quarter for the past three years.\n\nMr. Chu contacted our front desk this morning to express his disappointment about a billing discrepancy he noticed on his most recent invoice. Specifically, he was charged for the premium breakfast package on two mornings when he had, in fact, ____(2)____ at 6:30 a.m. and would not have had time to use the service.\n\n____(3)____\n\nI would like someone from billing to contact Mr. Chu directly today to issue a full refund for the two incorrect charges and to apply a complimentary upgrade to his next reservation as a goodwill gesture. We must ensure that loyal guests like Mr. Chu ____(4)____ that their satisfaction is our top priority.\n\nIsabel Ferreira\nGuest Relations Manager", "passageTitle": "Email: Project Status Report", "type": "single", "questions": [{"id": "c6-3a", "part": 6, "question": "Blank (1):", "options": ["is staying", "has stayed", "stayed", "was staying"], "answer": 1, "explanation": "'Has stayed with us every quarter for the past three years' = present perfect v\u00ec th\u00f3i quen k\u00e9o d\u00e0i \u0111\u1ebfn hi\u1ec7n t\u1ea1i. 'For the past three years' l\u00e0 d\u1ea5u hi\u1ec7u.", "difficulty": "medium"}, {"id": "c6-3b", "part": 6, "question": "Blank (2):", "options": ["checked out", "departed", "left", "exited"], "answer": 0, "explanation": "'Checked out' = tr\u1ea3 ph\u00f2ng (collocation chu\u1ea9n c\u1ee7a kh\u00e1ch s\u1ea1n). C\u00e1c t\u1eeb c\u00f2n l\u1ea1i k\u00e9m chuy\u00ean nghi\u1ec7p h\u01a1n.", "difficulty": "medium"}, {"id": "c6-3c", "part": 6, "question": "Blank (3) \u2013 Choose the best sentence:", "options": ["The hotel breakfast menu will be updated next season.", "I have reviewed Mr. Chu's account and confirmed that the charges were made in error.", "Mr. Chu is scheduled to arrive again on September 15.", "Breakfast packages are available to all guests at an additional fee."], "answer": 1, "explanation": "C\u00e2u tr\u01b0\u1edbc m\u00f4 t\u1ea3 v\u1ea5n \u0111\u1ec1; c\u00e2u ti\u1ebfp theo n\u00ean x\u00e1c nh\u1eadn k\u1ebft qu\u1ea3 \u0111i\u1ec1u tra \u0111\u1ec3 d\u1eabn v\u00e0o h\u00e0nh \u0111\u1ed9ng gi\u1ea3i quy\u1ebft. Ch\u1ec9 \u0111\u00e1p \u00e1n B ph\u00f9 h\u1ee3p logic.", "difficulty": "medium"}, {"id": "c6-3d", "part": 6, "question": "Blank (4):", "options": ["know", "understand", "feel", "sense"], "answer": 2, "explanation": "'Feel that their satisfaction is our top priority' = c\u1ea3m th\u1ea5y \u0111\u01b0\u1ee3c \u01b0u ti\u00ean. 'Feel' ph\u00f9 h\u1ee3p nh\u1ea5t khi n\u00f3i v\u1ec1 tr\u1ea3i nghi\u1ec7m c\u1ea3m x\u00fac c\u1ee7a kh\u00e1ch h\u00e0ng.", "difficulty": "medium"}]}, {"passage": "MEMO\nTo: All Employees\nFrom: Chief People Officer\nDate: June 18\n\nRe: Revisions to the Annual Leave Policy\n\nFollowing feedback gathered during our most recent employee engagement survey, we are pleased to announce revisions to the annual leave policy, effective July 1.\n\nThe most significant change is an increase in the standard annual leave ____(1)____ from 15 to 18 days for all employees who have completed one year of service. Employees with three or more years of service will be ____(2)____ to 22 days annually.\n\nIn addition, we are introducing one additional day of paid leave, to be ____(3)____ on an employee's birthday. This day must be taken within the same calendar month as the employee's birthday and cannot be carried over.\n\n____(4)____, we will be extending the deadline for submitting leave applications from two weeks' notice to one week, offering greater flexibility for short-notice personal requests.\n\nFull policy documentation will be circulated via the HR portal by June 25. Please direct any questions to hr@company.com.\n\nOffice of the Chief People Officer", "passageTitle": "Notice: Library Hours Change", "type": "single", "questions": [{"id": "c6-4a", "part": 6, "question": "Blank (1):", "options": ["entitlement", "allowance", "provision", "allocation"], "answer": 0, "explanation": "'Annual leave entitlement' = quy\u1ec1n ngh\u1ec9 ph\u00e9p theo quy \u0111\u1ecbnh ph\u00e1p l\u00fd. 'Allowance' = kho\u1ea3n tr\u1ee3 c\u1ea5p t\u00e0i ch\u00ednh (sai lo\u1ea1i); 'provision' = \u0111i\u1ec1u kho\u1ea3n h\u1ee3p \u0111\u1ed3ng; 'allocation' = ph\u00e2n b\u1ed5 ngu\u1ed3n l\u1ef1c.", "difficulty": "medium"}, {"id": "c6-4b", "part": 6, "question": "Blank (2):", "options": ["entitled", "allowed", "permitted", "given"], "answer": 0, "explanation": "'Entitled to 22 days' = c\u00f3 quy\u1ec1n \u0111\u01b0\u1ee3c h\u01b0\u1edfng 22 ng\u00e0y. 'Entitled to' l\u00e0 c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong v\u0103n b\u1ea3n quy\u1ec1n l\u1ee3i nh\u00e2n vi\u00ean.", "difficulty": "medium"}, {"id": "c6-4c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Each full-time employee receives one paid personal day on their birthday annually.", "Part-time employees are entitled to the same benefit on a pro-rata basis.", "The personal day benefit will be introduced starting from the new financial year.", "Employees must notify HR at least one week in advance when taking their birthday leave."], "answer": 0, "explanation": "SI: th\u00f4ng b\u00e1o ch\u00ednh s\u00e1ch ngh\u1ec9 ph\u00e9p sinh nh\u1eadt. \"Each full-time employee receives one paid personal day on their birthday\" = c\u00e2u \u0111\u1ecbnh ngh\u0129a quy\u1ec1n l\u1ee3i, \u0111\u1eb7t \u0111\u1ea7u \u0111o\u1ea1n v\u1ec1 birthday leave t\u1ef1 nhi\u00ean nh\u1ea5t."}, {"id": "c6-4d", "part": 6, "question": "Blank (4):", "options": ["Furthermore", "However", "Therefore", "As a result"], "answer": 0, "explanation": "'Furthermore' = h\u01a1n n\u1eefa. B\u1ed5 sung th\u00eam thay \u0111\u1ed5i th\u1ee9 ba v\u00e0o danh s\u00e1ch. Kh\u00f4ng c\u00f3 s\u1ef1 t\u01b0\u01a1ng ph\u1ea3n hay k\u1ebft qu\u1ea3 \u2192 'However/Therefore' sai.", "difficulty": "medium"}]}, {"passage": "MEMO\nTo:   All Staff\nFrom: Finance Department\nDate: April 22\nRe:   Revised Expense Reimbursement Procedure\n\nPlease be ____(1)____ that the expense reimbursement process has been updated, effective May 1.\n\nGoing forward, all expense claims must be submitted through the new ExpenseHub portal at expensehub.company.com. Paper claim forms will no longer be ____(2)____ after April 30.\n\nClaims must be accompanied by original receipts or digital scans. Requests submitted without supporting documentation will be automatically ____(3)____ and will need to be resubmitted.\n\n____(4)____, the reimbursement processing time has been reduced from ten business days to five, provided that all required documentation is complete at the time of submission.\n\nIf you have any questions about the new process, please attend one of the drop-in sessions hosted by the Finance team every Tuesday in Room 2B.", "passageTitle": "Memo: Onboarding Procedure", "type": "single", "questions": [{"id": "g6-1a", "part": 6, "question": "Blank (1):", "options": ["noted", "reminded", "advised", "aware"], "answer": 2, "explanation": "'Please be advised that' = k\u00ednh th\u00f4ng b\u00e1o r\u1eb1ng (c\u1ee5m m\u1edf \u0111\u1ea7u th\u00f4ng b\u00e1o ch\u00ednh th\u1ee9c, c\u1ed1 \u0111\u1ecbnh). 'Reminded' d\u00f9ng khi nh\u1eafc l\u1ea1i \u0111i\u1ec1u \u0111\u00e3 bi\u1ebft; 'noted' l\u00e0 V3 kh\u00f4ng ph\u00f9 h\u1ee3p; 'aware' l\u00e0 t\u00ednh t\u1eeb, c\u1ea7n c\u1ea5u tr\u00fac kh\u00e1c.", "difficulty": "medium"}, {"id": "g6-1b", "part": 6, "question": "Blank (2):", "options": ["allowed", "accepted", "valid", "available"], "answer": 1, "explanation": "'Will no longer be accepted' = s\u1ebd kh\u00f4ng c\u00f2n \u0111\u01b0\u1ee3c ch\u1ea5p nh\u1eadn. 'Accepted' d\u00f9ng cho quy tr\u00ecnh/t\u00e0i li\u1ec7u.", "difficulty": "medium"}, {"id": "g6-1c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Any incomplete submissions will be flagged by the system and will need to be resubmitted.", "The system will automatically generate a reference number upon successful submission.", "Please contact the HR helpdesk if you encounter any technical difficulties.", "All submissions are reviewed within three business days of receipt."], "answer": 0, "explanation": "SI: ng\u1eef c\u1ea3nh v\u1ec1 quy tr\u00ecnh n\u1ed9p t\u00e0i li\u1ec7u onboarding. \"Incomplete submissions flagged and need resubmission\" = h\u1eadu qu\u1ea3 tr\u1ef1c ti\u1ebfp cho h\u00e0nh \u0111\u1ed9ng kh\u00f4ng \u0111\u00fang, k\u1ebft n\u1ed1i logic v\u1edbi quy tr\u00ecnh."}, {"id": "g6-1d", "part": 6, "question": "Blank (4):", "options": ["In addition", "However", "Therefore", "As a result"], "answer": 0, "explanation": "'In addition' = ngo\u00e0i ra, th\u00eam v\u00e0o \u0111\u00f3. B\u1ed5 sung th\u00f4ng tin t\u00edch c\u1ef1c (th\u1eddi gian x\u1eed l\u00fd nhanh h\u01a1n).", "difficulty": "medium"}]}, {"passage": "From: Customer Experience Team <support@arcadiahome.com>\nTo: [Customer Name]\nSubject: Important Update Regarding Your Order #AH-88712\n\nDear Valued Customer,\n\nWe are writing to ____(1)____ you that your order (#AH-88712) is experiencing an unexpected delay due to supply chain disruptions affecting several of our product lines.\n\nYour estimated delivery date has been revised from April 18 to April 28. We sincerely apologize for any inconvenience this may ____(2)____.\n\nAs a token of our appreciation for your patience, we have applied a USD 15 store credit to your account. This credit will be automatically ____(3)____ at checkout during your next purchase and requires no coupon code.\n\nShould you prefer to cancel your order instead, a full refund will be ____(4)____ to your original payment method within three to five business days. To cancel, please reply to this email or visit your account at arcadiahome.com/orders.\n\nWe value your trust and look forward to serving you.\n\nWarm regards,\nArcadia Home \u2013 Customer Experience", "passageTitle": "Email: Meeting Rescheduling", "type": "single", "questions": [{"id": "g6-2a", "part": 6, "question": "Blank (1):", "options": ["inform", "notify", "advise", "tell"], "answer": 1, "explanation": "'Notify you that' = th\u00f4ng b\u00e1o cho b\u1ea1n v\u1ec1. 'Notify' l\u00e0 \u0111\u1ed9ng t\u1eeb chu\u1ea9n nh\u1ea5t trong email th\u00f4ng b\u00e1o ch\u1eadm giao h\u00e0ng.", "difficulty": "medium"}, {"id": "g6-2b", "part": 6, "question": "Blank (2):", "options": ["bring", "create", "cause", "make"], "answer": 2, "explanation": "'Cause inconvenience' = g\u00e2y b\u1ea5t ti\u1ec7n (collocation c\u1ed1 \u0111\u1ecbnh, chu\u1ea9n nh\u1ea5t trong v\u0103n b\u1ea3n xin l\u1ed7i).", "difficulty": "medium"}, {"id": "g6-2c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["This discount is automatically applied at checkout and requires no coupon code.", "The discount code can be found in your account settings under promotions.", "Please note that this offer cannot be combined with any other ongoing promotions.", "The discount applies only to full-priced items and excludes sale merchandise."], "answer": 0, "explanation": "SI: email v\u1ec1 coupon/gi\u1ea3m gi\u00e1. \"Automatically applied at checkout, no coupon needed\" = th\u00f4ng tin thu\u1eadn l\u1ee3i nh\u1ea5t cho kh\u00e1ch h\u00e0ng, k\u1ebft n\u1ed1i v\u1edbi \"next purchase\" \u0111\u00e3 \u0111\u1ec1 c\u1eadp tr\u01b0\u1edbc \u0111\u00f3."}, {"id": "g6-2d", "part": 6, "question": "Blank (4):", "options": ["sent", "returned", "processed", "issued"], "answer": 3, "explanation": "'Refund will be issued to your payment method' = ho\u00e0n ti\u1ec1n s\u1ebd \u0111\u01b0\u1ee3c ph\u00e1t h\u00e0nh v\u1ec1 ph\u01b0\u01a1ng th\u1ee9c thanh to\u00e1n. 'Issued' l\u00e0 t\u1eeb k\u1ef9 thu\u1eadt chu\u1ea9n cho refund.", "difficulty": "medium"}]}, {"passage": "STERLING ASSOCIATES QUARTERLY NEWSLETTER \u2013 Q2\n\nWe are delighted to ____(1)____ our Q2 newsletter, packed with updates on our recent projects, new team members, and upcoming industry events.\n\nThis quarter, Sterling Associates was recognised as one of the Top 50 Consulting Firms in Asia-Pacific by Business Insights Magazine \u2014 an ____(2)____ that reflects the dedication and expertise of every member of our team.\n\nLooking ahead to Q3, the team is excited to ____(3)____ on several high-profile infrastructure projects in the region. With new partnerships forming and client confidence at an all-time high, we remain ____(4)____ committed to delivering excellence in every engagement.", "passageTitle": "Newsletter: Quarterly Update", "type": "single", "questions": [{"id": "g6-3a", "part": 6, "question": "Blank (1):", "options": ["release", "present", "share", "introduce"], "answer": 2, "explanation": "'Share our Q2 newsletter' = chia s\u1ebb b\u1ea3n tin. 'Share' l\u00e0 l\u1ef1a ch\u1ecdn t\u1ef1 nhi\u00ean nh\u1ea5t trong ng\u1eef c\u1ea3nh newsletter n\u1ed9i b\u1ed9/kh\u00e1ch h\u00e0ng.", "difficulty": "medium"}, {"id": "g6-3b", "part": 6, "question": "Blank (2):", "options": ["award", "acknowledgment", "honor", "achievement"], "answer": 3, "explanation": "'An achievement that reflects' = m\u1ed9t th\u00e0nh t\u00edch ph\u1ea3n \u00e1nh. 'Achievement' ph\u00f9 h\u1ee3p nh\u1ea5t v\u00ec n\u00f3 l\u00e0 k\u1ebft qu\u1ea3 c\u1ee7a n\u1ed7 l\u1ef1c t\u1eadp th\u1ec3, kh\u00f4ng ph\u1ea3i gi\u1ea3i th\u01b0\u1edfng c\u1ee5 th\u1ec3.", "difficulty": "medium"}, {"id": "g6-3c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["These projects will allow us to further demonstrate our expertise in the regional market.", "We have recently expanded our team to support this increased workload.", "Further details about these projects will be announced at the annual general meeting.", "Client feedback on our recent projects has been overwhelmingly positive."], "answer": 0, "explanation": "SI: newsletter v\u1ec1 d\u1ef1 \u00e1n s\u1eafp tri\u1ec3n khai \u2192 c\u00e2u \u0111i\u1ec1n ph\u1ea3i n\u00f3i v\u1ec1 \u00fd ngh\u0129a c\u1ee7a d\u1ef1 \u00e1n. \"Further demonstrate expertise in regional market\" = m\u1ee5c \u0111\u00edch chi\u1ebfn l\u01b0\u1ee3c, k\u1ebft n\u1ed1i v\u1edbi \"embark on infrastructure projects\" tr\u01b0\u1edbc \u0111\u00f3."}, {"id": "g6-3d", "part": 6, "question": "Blank (4):", "qNum": 4, "options": ["deeply", "firmly", "wholly", "strongly"], "answer": 3, "explanation": "\"Strongly committed to delivering excellence\" = cam k\u1ebft m\u1ea1nh m\u1ebd. \"Strongly committed\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t trong v\u0103n b\u1ea3n doanh nghi\u1ec7p ch\u00ednh th\u1ee9c. \"Deeply committed\" c\u0169ng \u0111\u00fang nh\u01b0ng \"strongly\" ph\u1ed5 bi\u1ebfn h\u01a1n trong ng\u1eef c\u1ea3nh kinh doanh."}]}, {"passage": "PULSE \u2013 INTERNAL NEWSLETTER\nTerraGreen Energy | Monthly Edition\n\nENHANCED EMPLOYEE BENEFITS PACKAGE \u2013 LAUNCHING JULY 1\n\nWe are pleased to ____(1)____ that TerraGreen Energy will introduce an enhanced benefits package for all permanent employees, effective July 1.\n\nThe upgraded package includes an increase in the annual wellness allowance from USD 500 to USD 800, extended parental leave for both primary and secondary caregivers, and a new employee assistance programme ____(2)____ mental health support and financial counselling.\n\nIn addition, employees will be ____(3)____ access to the new TerraGreen Learning Hub \u2014 an online platform featuring over 2,000 courses in leadership, technology, and professional skills.\n\n____(4)____ about the new benefits package will be circulated to all employees via the HR portal by June 15. An information session will also be hosted on June 20 for those who have questions.", "passageTitle": "Notice: Cafeteria Menu Update", "type": "single", "questions": [{"id": "h6-1a", "part": 6, "question": "Blank (1):", "options": ["confirm", "declare", "announce", "notify"], "answer": 2, "explanation": "'Pleased to announce' = vui m\u1eebng th\u00f4ng b\u00e1o. C\u1ee5m m\u1edf \u0111\u1ea7u chu\u1ea9n trong th\u00f4ng b\u00e1o t\u00edch c\u1ef1c n\u1ed9i b\u1ed9.", "difficulty": "medium"}, {"id": "h6-1b", "part": 6, "question": "Blank (2):", "options": ["providing", "covering", "offering", "including"], "answer": 3, "explanation": "'Programme including mental health support' = ch\u01b0\u01a1ng tr\u00ecnh bao g\u1ed3m h\u1ed7 tr\u1ee3 s\u1ee9c kh\u1ecfe t\u00e2m th\u1ea7n. 'Including' l\u00e0 participle t\u1ef1 nhi\u00ean nh\u1ea5t \u0111\u1ec3 li\u1ec7t k\u00ea n\u1ed9i dung ch\u01b0\u01a1ng tr\u00ecnh.", "difficulty": "medium"}, {"id": "h6-1c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["This gives all employees access to the new TerraGreen Learning Hub \u2014 an online platform featuring over 2,000 courses.", "Employees may opt out of the TerraGreen programme at any time by contacting HR.", "The Learning Hub is available exclusively to employees who have been with the company for over one year.", "A separate subscription fee will be charged for premium content on the TerraGreen platform."], "answer": 0, "explanation": "SI: th\u00f4ng b\u00e1o v\u1ec1 quy\u1ec1n l\u1ee3i h\u1ecdc tr\u1ef1c tuy\u1ebfn m\u1edbi. \"Gives all employees access to TerraGreen Learning Hub\" = c\u00e2u m\u00f4 t\u1ea3 quy\u1ec1n l\u1ee3i c\u1ee5 th\u1ec3, k\u1ebft n\u1ed1i tr\u1ef1c ti\u1ebfp v\u1edbi t\u00ean ch\u01b0\u01a1ng tr\u00ecnh \u0111\u01b0\u1ee3c \u0111\u1ec1 c\u1eadp sau."}, {"id": "h6-1d", "part": 6, "question": "Blank (4):", "options": ["Complete details", "Full information", "Comprehensive guidance", "All documents"], "answer": 0, "explanation": "'Complete details will be circulated' = th\u00f4ng tin \u0111\u1ea7y \u0111\u1ee7 s\u1ebd \u0111\u01b0\u1ee3c g\u1eedi \u0111\u1ebfn. 'Complete details' l\u00e0 c\u1ee5m t\u1ef1 nhi\u00ean nh\u1ea5t trong v\u0103n b\u1ea3n th\u00f4ng b\u00e1o.", "difficulty": "medium"}]}, {"passage": "Pemberton Legal Associates\nSuite 1100, One Pacific Tower\nVancouver, BC V6E 4A2\nSeptember 5\n\nMr. Daniel Chow\nChief Procurement Officer\nBridgewater Manufacturing Ltd.\n300 Industrial Way, Burnaby, BC\n\nDear Mr. Chow,\n\nI am writing with ____(1)____ to the service agreement between Pemberton Legal Associates and Bridgewater Manufacturing Ltd., which is due for renewal on October 31.\n\nWe are pleased to confirm our continued interest in ____(2)____ the agreement for a further two-year term under the same service scope. However, we would like to propose a modest adjustment to the annual retainer \u2014 an increase of 4%, in line with the current consumer price index \u2014 effective from the renewal date.\n\nShould you wish to ____(3)____ the proposed terms, please do not hesitate to contact me directly. We would welcome the opportunity to meet in person to review the details before the renewal deadline.\n\nWe value our long-standing relationship with Bridgewater Manufacturing and look forward to your ____(4)____.\n\nYours sincerely,\nHelen Pemberton\nSenior Partner, Pemberton Legal Associates", "passageTitle": "Email: Invoice Dispute", "type": "single", "questions": [{"id": "h6-2a", "part": 6, "question": "Blank (1):", "options": ["reference", "regard", "respect", "relation"], "answer": 1, "explanation": "'With regard to' = li\u00ean quan \u0111\u1ebfn, v\u1ec1 v\u1ea5n \u0111\u1ec1 (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh trong th\u01b0 t\u00edn trang tr\u1ecdng).", "difficulty": "medium"}, {"id": "h6-2b", "part": 6, "question": "Blank (2):", "options": ["extending", "renewing", "continuing", "maintaining"], "answer": 1, "explanation": "'Renewing the agreement' = gia h\u1ea1n th\u1ecfa thu\u1eadn. 'Renew a contract/agreement' l\u00e0 collocation chu\u1ea9n nh\u1ea5t.", "difficulty": "medium"}, {"id": "h6-2c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Should you wish to discuss the proposed terms, please do not hesitate to contact me directly.", "We hope this proposal meets your requirements and look forward to your response.", "Please note that these terms are non-negotiable and must be accepted as presented.", "We regret to inform you that we are unable to accommodate any further changes at this time."], "answer": 0, "explanation": "SI: email th\u01b0\u01a1ng l\u01b0\u1ee3ng h\u1ee3p \u0111\u1ed3ng. \"Should you wish to discuss the proposed terms\" = l\u1eddi m\u1eddi th\u01b0\u01a1ng l\u01b0\u1ee3ng l\u1ecbch s\u1ef1, k\u1ebft n\u1ed1i \"proposed terms\" v\u1edbi c\u00e2u tr\u01b0\u1edbc v\u1ec1 \u0111i\u1ec1u kho\u1ea3n \u0111\u1ec1 xu\u1ea5t."}, {"id": "h6-2d", "part": 6, "question": "Blank (4):", "options": ["reply", "answer", "response", "feedback"], "answer": 2, "explanation": "'Look forward to your response' = mong nh\u1eadn \u0111\u01b0\u1ee3c ph\u1ea3n h\u1ed3i c\u1ee7a b\u1ea1n. 'Response' l\u00e0 c\u1ee5m k\u1ebft th\u00fac th\u01b0 trang tr\u1ecdng chu\u1ea9n nh\u1ea5t.", "difficulty": "medium"}]}, {"passage": "VELOTECH ANNOUNCES NEXT-GENERATION SMARTWATCH \u2014 THE VELOWATCH X2\n\nVeloTech Corporation today ____(1)____ the launch of its most advanced wearable device to date, the VeloWatch X2, which features continuous health monitoring, a five-day battery life, and seamless integration with all major smartphone platforms.\n\nThe VeloWatch X2 will be ____(2)____ exclusively through VeloTech's official website and authorised retail partners beginning November 15, with global availability expected by year-end.\n\nThe VeloWatch X2 is ____(3)____ at USD 299, making it the most competitively priced device in the premium smartwatch segment. Consumers who pre-register at VeloTech's website will receive a 10% discount and be ____(4)____ to exclusive launch-day promotions.", "passageTitle": "Press Release: Product Launch", "type": "single", "questions": [{"id": "h6-3a", "part": 6, "question": "Blank (1):", "options": ["released", "unveiled", "declared", "proclaimed"], "answer": 1, "explanation": "'Unveiled the launch' = c\u00f4ng b\u1ed1 ra m\u1eaft. 'Unveiled' l\u00e0 t\u1eeb m\u1ea1nh nh\u1ea5t v\u00e0 chuy\u00ean bi\u1ec7t nh\u1ea5t khi n\u00f3i v\u1ec1 vi\u1ec7c ti\u1ebft l\u1ed9 s\u1ea3n ph\u1ea9m m\u1edbi l\u1ea7n \u0111\u1ea7u.", "difficulty": "medium"}, {"id": "h6-3b", "part": 6, "question": "Blank (2):", "options": ["sold", "distributed", "available", "released"], "answer": 0, "explanation": "'Will be sold exclusively through' = s\u1ebd \u0111\u01b0\u1ee3c b\u00e1n \u0111\u1ed9c quy\u1ec1n qua. 'Sold through channels' l\u00e0 c\u1ee5m ph\u00e2n ph\u1ed1i chu\u1ea9n nh\u1ea5t.", "difficulty": "medium"}, {"id": "h6-3c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["The VeloWatch X2 will be priced at USD 299, making it the most competitively priced device in the premium smartwatch segment.", "VeloTech expects strong demand for the VeloWatch X2 in both domestic and international markets.", "The company plans to release two additional smartwatch models in the following quarter.", "All VeloWatch X2 units come with a standard one-year manufacturer's warranty."], "answer": 0, "explanation": "SI: press release v\u1ec1 s\u1ea3n ph\u1ea9m m\u1edbi. \"Priced at USD 299, most competitively priced\" = th\u00f4ng tin gi\u00e1 s\u1ea3n ph\u1ea9m l\u00e0 th\u00f4ng tin tr\u1ecdng t\u00e2m, logic nh\u1ea5t \u0111\u1ec3 \u0111\u1eb7t tr\u01b0\u1edbc th\u00f4ng tin k\u00eanh b\u00e1n h\u00e0ng."}, {"id": "h6-3d", "part": 6, "question": "Blank (4):", "qNum": 4, "options": ["entitled", "invited", "exposed", "linked"], "answer": 0, "explanation": "\"Entitled to exclusive promotions\" = c\u00f3 quy\u1ec1n nh\u1eadn \u01b0u \u0111\u00e3i \u0111\u1ed9c quy\u1ec1n. \"Entitled to + benefit\" l\u00e0 collocation ph\u00e1p l\u00fd/marketing chu\u1ea9n: \"be entitled to\" = \u0111\u01b0\u1ee3c h\u01b0\u1edfng quy\u1ec1n l\u1ee3i."}]}, {"passage": "Dear Valued Customer,\n\nThank you for choosing Skyline Airlines. We are writing to (1)_____ you of an upcoming change to our frequent flyer program. Effective March 1st, members will earn double miles on all international flights.\n\nAdditionally, we are (2)_____ a new tier called \"Platinum Elite\" for customers who fly more than 100,000 miles per year. Platinum Elite members will enjoy (3)_____ benefits including priority boarding, complimentary lounge access, and free seat upgrades.\n\nFor more details, (4)_____ visit our website at www.skylineair.com/rewards.\n\nBest regards,\nSkyline Airlines Customer Relations", "passageTitle": "Email: Annual Report Distribution", "type": "single", "questions": [{"id": "e6-1a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["inform", "tell", "say", "speak"], "answer": 0, "explanation": "'Inform you of' = th\u00f4ng b\u00e1o cho b\u1ea1n v\u1ec1 (trang tr\u1ecdng, ph\u00f9 h\u1ee3p email c\u00f4ng ty).", "difficulty": "medium"}, {"id": "e6-1b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["presenting", "introducing", "offering", "starting"], "answer": 1, "explanation": "'Introducing a new tier' = gi\u1edbi thi\u1ec7u h\u1ea1ng m\u1edbi (d\u00f9ng khi ra m\u1eaft s\u1ea3n ph\u1ea9m/d\u1ecbch v\u1ee5 m\u1edbi).", "difficulty": "medium"}, {"id": "e6-1c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Members who achieve Gold status will receive these exclusive benefits starting from their renewal date.", "All frequent flyer miles will expire at the end of each calendar year unless redeemed.", "Skyline Airlines regrets to inform members that the programme will be discontinued.", "Members can check their current tier status by logging in to their account online."], "answer": 0, "explanation": "SI: sau \"earn double miles on all international flights\" \u2192 c\u00e2u \u0111i\u1ec1n ph\u1ea3i gi\u1edbi thi\u1ec7u quy\u1ec1n l\u1ee3i Gold status. \"Members achieving Gold status will receive exclusive benefits\" = ti\u1ebfp n\u1ed1i t\u1ef1 nhi\u00ean v\u1ec1 ch\u01b0\u01a1ng tr\u00ecnh th\u01b0\u1edfng m\u1edbi."}, {"id": "e6-1d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["please", "however", "therefore", "although"], "answer": 0, "explanation": "'Please visit' = xin h\u00e3y truy c\u1eadp. C\u00e2u m\u1eddi l\u1ecbch s\u1ef1.", "difficulty": "medium"}]}, {"passage": "MEMO\nTo: All Department Heads\nFrom: Operations Manager\nDate: April 5\nRe: Energy Conservation Initiative\n\nAs part of our commitment to (1)_____ our environmental impact, we are launching a company-wide energy conservation program. Starting next Monday, the following measures will be (2)_____:\n\n\u2022 All lights in unoccupied offices must be turned off.\n\u2022 Thermostats should be set no lower than 24\u00b0C during summer.\n\u2022 Employees are encouraged to use public transportation (3)_____ driving to work.\n\nWe believe these small changes can make a (4)_____ difference in our energy consumption. Thank you for your cooperation.", "passageTitle": "Notice: Building Access Policy", "type": "single", "questions": [{"id": "e6-2a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["increasing", "reducing", "expanding", "maintaining"], "answer": 1, "explanation": "'Reducing our environmental impact' = gi\u1ea3m t\u00e1c \u0111\u1ed9ng m\u00f4i tr\u01b0\u1eddng. Ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh ti\u1ebft ki\u1ec7m n\u0103ng l\u01b0\u1ee3ng.", "difficulty": "medium"}, {"id": "e6-2b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["imposed", "implemented", "imported", "improved"], "answer": 1, "explanation": "'Measures will be implemented' = c\u00e1c bi\u1ec7n ph\u00e1p s\u1ebd \u0111\u01b0\u1ee3c th\u1ef1c hi\u1ec7n (collocation chu\u1ea9n).", "difficulty": "medium"}, {"id": "e6-2c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["To help reduce energy use, all non-essential lighting in common areas will be turned off after 7:00 p.m.", "Employees are encouraged to share their ideas for reducing energy costs with their line managers.", "The company expects to recover the cost of the new energy systems within five years.", "All employees who participate in the programme will receive a small financial incentive."], "answer": 0, "explanation": "SI: ng\u1eef c\u1ea3nh memo v\u1ec1 ch\u01b0\u01a1ng tr\u00ecnh ti\u1ebft ki\u1ec7m n\u0103ng l\u01b0\u1ee3ng. \"Non-essential lighting turned off after 7pm\" = h\u00e0nh \u0111\u1ed9ng c\u1ee5 th\u1ec3 v\u00e0 tr\u1ef1c ti\u1ebfp nh\u1ea5t, logic sau \u0111o\u1ea1n gi\u1edbi thi\u1ec7u ch\u01b0\u01a1ng tr\u00ecnh."}, {"id": "e6-2d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["significant", "slight", "minor", "marginal"], "answer": 0, "explanation": "'Significant difference' = s\u1ef1 kh\u00e1c bi\u1ec7t \u0111\u00e1ng k\u1ec3 (collocation ph\u1ed5 bi\u1ebfn, t\u00edch c\u1ef1c).", "difficulty": "medium"}]}, {"passage": "Dear Ms. Park,\n\nI am pleased to confirm your (1)_____ at the Grand Meridian Hotel from June 12 to June 15. Your booking includes a Deluxe Suite with an ocean view.\n\nPlease note that check-in time is 3:00 p.m. and check-out is at 11:00 a.m. Should you need to arrive (2)_____, early check-in can be arranged for an additional fee of $50.\n\nComplimentary breakfast is (3)_____ daily from 7:00 a.m. to 10:00 a.m. in the Garden Restaurant on the ground floor.\n\nWe look forward to (4)_____ you at the Grand Meridian Hotel.\n\nSincerely,\nReservations Department", "passageTitle": "Email: Supplier Delay Notification", "type": "single", "questions": [{"id": "e6-3a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["reservation", "appointment", "arrangement", "subscription"], "answer": 0, "explanation": "'Reservation' = \u0111\u1eb7t ph\u00f2ng. \u0110\u00fang ng\u1eef c\u1ea3nh kh\u00e1ch s\u1ea1n.", "difficulty": "medium"}, {"id": "e6-3b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["late", "soon", "earlier", "lately"], "answer": 2, "explanation": "'Arrive earlier' = \u0111\u1ebfn s\u1edbm h\u01a1n. 'Early check-in' = nh\u1eadn ph\u00f2ng s\u1edbm.", "difficulty": "medium"}, {"id": "e6-3c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["A complimentary breakfast is served daily from 7:00 a.m. to 10:00 a.m. in the Garden Restaurant on the ground floor.", "Guests are required to present a valid form of identification at check-in.", "Room service is available 24 hours a day for your convenience.", "The hotel kindly requests that guests settle any outstanding charges prior to check-out."], "answer": 0, "explanation": "SI: email x\u00e1c nh\u1eadn \u0111\u1eb7t ph\u00f2ng kh\u00e1ch s\u1ea1n. \"Complimentary breakfast served daily\" = th\u00f4ng tin ti\u1ec7n \u00edch quan tr\u1ecdng ti\u1ebfp theo sau th\u00f4ng tin check-in/check-out, logic v\u00e0 li\u00ean quan tr\u1ef1c ti\u1ebfp \u0111\u1ebfn k\u1ef3 ngh\u1ec9 c\u1ee7a kh\u00e1ch."}, {"id": "e6-3d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["greeting", "welcoming", "receiving", "meeting"], "answer": 1, "explanation": "'We look forward to welcoming you' = ch\u00fang t\u00f4i mong \u0111\u01b0\u1ee3c ch\u00e0o \u0111\u00f3n b\u1ea1n (c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong hospitality).", "difficulty": "medium"}]}, {"passage": "NOTICE\n\nEffective immediately, all employees are required to use the new digital time-tracking system, ClockSmart, to record their working hours. The previous paper-based system will be (1)_____ as of May 1.\n\nTraining sessions on how to use ClockSmart will be (2)_____ next week. Sessions are available on Tuesday and Thursday from 10:00 to 11:00 a.m. in Training Room A. Attendance is (3)_____.\n\nIf you experience any technical difficulties, please contact the IT Help Desk at extension 5501. We (4)_____ your patience during this transition.\n\nHuman Resources Department", "passageTitle": "Memo: Employee Benefits Update", "type": "single", "questions": [{"id": "e6-4a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["discontinued", "disconnected", "discounted", "discouraged"], "answer": 0, "explanation": "'Discontinued' = ng\u1eebng s\u1eed d\u1ee5ng. H\u1ec7 th\u1ed1ng c\u0169 s\u1ebd b\u1ecb ng\u1eebng ho\u1ea1t \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "e6-4b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["conducted", "directed", "managed", "operated"], "answer": 0, "explanation": "'Training sessions will be conducted' = bu\u1ed5i t\u1eadp hu\u1ea5n s\u1ebd \u0111\u01b0\u1ee3c ti\u1ebfn h\u00e0nh (collocation chu\u1ea9n).", "difficulty": "medium"}, {"id": "e6-4c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Attendance at one of these sessions is mandatory for all staff before the May 1 deadline.", "Staff who are unable to attend a session may complete the online tutorial at their own pace.", "The training sessions will be recorded and made available on the company intranet.", "Managers are asked to confirm the attendance of their team members by April 15."], "answer": 0, "explanation": "SI: th\u00f4ng b\u00e1o h\u1ec7 th\u1ed1ng ch\u1ea5m c\u00f4ng m\u1edbi + bu\u1ed5i \u0111\u00e0o t\u1ea1o. \"Attendance at one session is mandatory before May 1\" = th\u00f4ng tin b\u1eaft bu\u1ed9c, k\u1ebft n\u1ed1i deadline h\u1ec7 th\u1ed1ng (May 1) v\u1edbi y\u00eau c\u1ea7u tham d\u1ef1 \u0111\u00e0o t\u1ea1o."}, {"id": "e6-4d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["appreciate", "accept", "acknowledge", "admit"], "answer": 0, "explanation": "'We appreciate your patience' = c\u1ea3m \u01a1n s\u1ef1 ki\u00ean nh\u1eabn (c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong th\u00f4ng b\u00e1o).", "difficulty": "medium"}]}, {"passage": "From:    Procurement Team <procurement@halversongroup.com>\nTo:      Oliver Chen <o.chen@deltapackaging.com>\nDate:    Tuesday, 4 November\nSubject: Contract Renewal \u2013 Packaging Supply Agreement\n\nDear Mr. Chen,\n\nI am writing on behalf of Halverson Group to express our continued interest in _____(1)_____ our supply agreement with Delta Packaging for another 12 months, commencing January 1.\n\nOver the past year, Delta Packaging has consistently delivered high-quality materials on schedule, and we have been extremely _____(2)_____ with the service and support provided by your account team. _____(3)_____\n\nFor the renewal, we would like to discuss the possibility of a modest volume discount, given that we expect to increase our order quantities by approximately 20 percent in the coming year. We believe a revised pricing structure would benefit both organisations.\n\nCould you please _____(4)_____ a convenient time for a call this week or early next week to discuss the terms? I look forward to hearing from you.\n\nYours sincerely,\nHelena Marsh\nSenior Procurement Manager, Halverson Group", "passageTitle": "Email: Workshop Invitation", "type": "single", "questions": [{"id": "t8-p6-1a", "part": 6, "question": "... our continued interest in _____(1)_____ our supply agreement with Delta Packaging.", "options": ["renew", "renewed", "renewing", "to be renewed"], "answer": 2, "explanation": "'Interest in + V-ing' = c\u1ee5m c\u1ed1 \u0111\u1ecbnh (gi\u1edbi t\u1eeb 'in' \u0111\u00f2i h\u1ecfi danh \u0111\u1ed9ng t\u1eeb). 'Renewing' l\u00e0 danh \u0111\u1ed9ng t\u1eeb duy nh\u1ea5t ph\u00f9 h\u1ee3p.", "difficulty": "medium"}, {"id": "t8-p6-1b", "part": 6, "question": "... we have been extremely _____(2)_____ with the service and support provided.", "options": ["satisfying", "satisfaction", "satisfactory", "satisfied"], "answer": 3, "explanation": "'Been satisfied with' = h\u00e0i l\u00f2ng v\u1edbi (t\u00ednh t\u1eeb b\u1ecb \u0111\u1ed9ng 'satisfied', d\u00f9ng v\u1edbi ch\u1ee7 th\u1ec3 c\u1ea3m nh\u1eadn). 'Satisfying' d\u00f9ng cho v\u1eadt/s\u1ef1 vi\u1ec7c g\u00e2y ra c\u1ea3m gi\u00e1c. 'Been satisfied with' l\u00e0 c\u1ea5u tr\u00fac chu\u1ea9n sau 'have been extremely'.", "difficulty": "medium"}, {"id": "t8-p6-1c", "part": 6, "question": "_____(3)_____", "options": ["In particular, the expedited delivery during our peak season in August was greatly appreciated.", "However, there were several quality issues reported during the third quarter.", "We would also like to inform you that we are currently seeking alternative suppliers.", "Please note that our procurement policy requires a minimum of three competitive bids."], "answer": 0, "explanation": "\u0110o\u1ea1n tr\u01b0\u1edbc khen ng\u1ee3i Delta Packaging v\u1ec1 ch\u1ea5t l\u01b0\u1ee3ng v\u00e0 \u0111\u00fang l\u1ecbch \u2192 c\u00e2u th\u00eam v\u00e0o ph\u1ea3i l\u00e0 v\u00ed d\u1ee5 c\u1ee5 th\u1ec3 minh h\u1ecda cho s\u1ef1 khen ng\u1ee3i \u0111\u00f3. Option A (giao h\u00e0ng nhanh trong m\u00f9a cao \u0111i\u1ec3m) l\u00e0 b\u1eb1ng ch\u1ee9ng t\u1ef1 nhi\u00ean nh\u1ea5t.", "difficulty": "medium"}, {"id": "t8-p6-1d", "part": 6, "question": "Could you please _____(4)_____ a convenient time for a call?", "options": ["propose", "impose", "expose", "compose"], "answer": 0, "explanation": "'Propose a time' = \u0111\u1ec1 xu\u1ea5t m\u1ed9t th\u1eddi \u0111i\u1ec3m (collocation chu\u1ea9n). 'Impose' = \u00e1p \u0111\u1eb7t; 'expose' = ph\u01a1i b\u00e0y; 'compose' = so\u1ea1n th\u1ea3o/s\u00e1ng t\u00e1c.", "difficulty": "medium"}]}, {"passage": "ANNOUNCEMENT\nTo:   All Employees\nFrom: People & Culture Department\nRe:   Introduction of Flexible Benefits Programme\nDate: November 10\n\nWe are pleased to announce the launch of Arcturus Holdings' new Flexible Benefits Programme, _____(1)_____ will take effect from 1 December.\n\nUnder the new programme, each employee will receive an annual benefits allowance of AUD 2,000. This allowance may be _____(2)_____ across a range of options, including additional annual leave, gym memberships, professional development courses, and private health insurance top-ups.\n\nEmployees are encouraged to log in to the HR portal to review the full list of available benefits and submit their selections by 20 November. _____(3)_____\n\nPlease note that unused allowances cannot be carried over to the following year. _____(4)_____, employees who do not make a selection by the deadline will have their allowance automatically directed to the default option: private health insurance.\n\nIf you have any questions about the programme, please contact the People & Culture team at people@arcturus.com.au.", "passageTitle": "Notice: Emergency Procedures", "type": "single", "questions": [{"id": "t8-p6-2a", "part": 6, "question": "... Arcturus Holdings' new Flexible Benefits Programme, _____(1)_____ will take effect from 1 December.", "options": ["that", "what", "which", "it"], "answer": 2, "explanation": "M\u1ec7nh \u0111\u1ec1 quan h\u1ec7 phi h\u1ea1n \u0111\u1ecbnh (non-defining relative clause) b\u1ed5 sung th\u00f4ng tin cho danh t\u1eeb 'Programme' \u2192 d\u00f9ng 'which'. 'That' kh\u00f4ng d\u00f9ng \u0111\u01b0\u1ee3c trong m\u1ec7nh \u0111\u1ec1 phi h\u1ea1n \u0111\u1ecbnh c\u00f3 d\u1ea5u ph\u1ea9y.", "difficulty": "medium"}, {"id": "t8-p6-2b", "part": 6, "question": "This allowance may be _____(2)_____ across a range of options.", "options": ["allocated", "collected", "submitted", "measured"], "answer": 0, "explanation": "'Allowance allocated across options' = kho\u1ea3n tr\u1ee3 c\u1ea5p \u0111\u01b0\u1ee3c ph\u00e2n b\u1ed5 v\u00e0o c\u00e1c l\u1ef1a ch\u1ecdn. 'Allocate' l\u00e0 thu\u1eadt ng\u1eef t\u00e0i ch\u00ednh/HR chu\u1ea9n. 'Submitted' d\u00f9ng cho t\u00e0i li\u1ec7u/\u0111\u01a1n.", "difficulty": "medium"}, {"id": "t8-p6-2c", "part": 6, "question": "_____(3)_____", "options": ["Selections made after this date may not be processed in time for the December rollout.", "The HR portal will be unavailable for maintenance on 18 and 19 November.", "Employees who joined after October 1 are not eligible for the programme this year.", "Professional development courses must be pre-approved by your line manager."], "answer": 0, "explanation": "Sau deadline 20 November \u2192 c\u00e2u ti\u1ebfp theo h\u1ee3p l\u00fd nh\u1ea5t l\u00e0 h\u1ec7 qu\u1ea3 n\u1ebfu n\u1ed9p tr\u1ec5. Option A c\u1ea3nh b\u00e1o v\u1ec1 nguy c\u01a1 kh\u00f4ng k\u1ecbp x\u1eed l\u00fd cho \u0111\u1ee3t tri\u1ec3n khai th\u00e1ng 12.", "difficulty": "medium"}, {"id": "t8-p6-2d", "part": 6, "question": "_____(4)_____, employees who do not make a selection by the deadline will have their allowance automatically directed to the default option.", "options": ["In addition", "Furthermore", "Additionally", "In this regard"], "answer": 3, "explanation": "'In this regard' = v\u1ec1 v\u1ea5n \u0111\u1ec1 n\u00e0y (li\u00ean k\u1ebft v\u1edbi n\u1ed9i dung v\u1eeba \u0111\u1ec1 c\u1eadp \u2013 unused allowances). C\u00e1c option A/B/C \u0111\u1ec1u mang ngh\u0129a 'th\u00eam v\u00e0o \u0111\u00f3', nh\u01b0ng 'In this regard' k\u1ebft n\u1ed1i t\u1ed1t nh\u1ea5t v\u1edbi c\u00e2u li\u1ec1n tr\u01b0\u1edbc v\u1ec1 carry-over.", "difficulty": "medium"}]}, {"passage": "PINNACLE INSURANCE GROUP\nPolicy Renewal Notice\n\nDear Ms. Aldridge,\n\nYour commercial property insurance policy (No. CP-774812) is due for renewal on 1 December. We are pleased to confirm that your current _____(1)_____ of AUD 3,240 per annum remains unchanged for the coming year.\n\nYour policy provides comprehensive _____(2)_____ for the building structure, business contents, and public liability up to AUD 5 million. Please note that the standard excess \u2014 the amount you are required to pay when making a claim \u2014 is AUD 750 per incident.\n\n_____(3)_____ We recommend reviewing the policy schedule to ensure the insured values continue to reflect the current replacement cost of your assets.\n\nTo renew your policy, simply sign and return the enclosed form by 20 November, or log in to your account at pinnacleinsurance.com.au. _____(4)_____ one of our advisers will be happy to assist you.\n\nYours sincerely,\nMarcus Holt\nClient Relations, Pinnacle Insurance Group", "passageTitle": "Letter: Sponsorship Request", "type": "single", "questions": [{"id": "t9-p6-1a", "part": 6, "question": "... your current _____(1)_____ of AUD 3,240 per annum remains unchanged.", "options": ["premium", "coverage", "deductible", "claim"], "answer": 0, "explanation": "'Premium' = ph\u00ed b\u1ea3o hi\u1ec3m h\u00e0ng n\u0103m (annual premium). \u0110\u00e2y l\u00e0 s\u1ed1 ti\u1ec1n kh\u00e1ch h\u00e0ng \u0111\u00f3ng cho c\u00f4ng ty b\u1ea3o hi\u1ec3m. 'Coverage' = ph\u1ea1m vi b\u1ea3o hi\u1ec3m; 'deductible' = m\u1ee9c kh\u1ea5u tr\u1eeb.", "difficulty": "medium"}, {"id": "t9-p6-1b", "part": 6, "question": "Your policy provides comprehensive _____(2)_____ for the building structure.", "options": ["compliance", "coverage", "contingency", "conversion"], "answer": 1, "explanation": "'Coverage' = ph\u1ea1m vi b\u1ea3o hi\u1ec3m \u2014 nh\u1eefng g\u00ec \u0111\u01b0\u1ee3c b\u1ea3o hi\u1ec3m chi tr\u1ea3. C\u1ee5m 'comprehensive coverage' l\u00e0 collocation chu\u1ea9n trong ng\u00e0nh b\u1ea3o hi\u1ec3m ETS.", "difficulty": "medium"}, {"id": "t9-p6-1c", "part": 6, "question": "_____(3)_____", "options": ["Any changes to the property should be reported to us promptly to avoid gaps in coverage.", "Your policy will be automatically cancelled if the renewal is not completed by the deadline.", "Please note that flood damage is excluded from all standard commercial property policies.", "A new claims form is available for download on our website."], "answer": 0, "explanation": "\u0110o\u1ea1n tr\u01b0\u1edbc \u0111\u1ec1 c\u1eadp \u0111\u1ebfn gi\u00e1 tr\u1ecb t\u00e0i s\u1ea3n \u0111\u01b0\u1ee3c b\u1ea3o hi\u1ec3m \u2192 c\u00e2u ti\u1ebfp theo h\u1ee3p l\u00fd nh\u1ea5t l\u00e0 khuy\u1ebfn c\u00e1o b\u00e1o c\u00e1o thay \u0111\u1ed5i t\u00e0i s\u1ea3n. Option A n\u1ed1i ti\u1ebfp logic v\u1ec1 vi\u1ec7c duy tr\u00ec 'coverage' ch\u00ednh x\u00e1c.", "difficulty": "medium"}, {"id": "t9-p6-1d", "part": 6, "question": "_____(4)_____ one of our advisers will be happy to assist you.", "options": ["Should you have any questions about your policy,", "In the event that your claim is denied,", "Once the premium has been paid in full,", "Although the renewal process is straightforward,"], "answer": 0, "explanation": "C\u00e2u k\u1ebft h\u01b0\u1edbng \u0111\u1ebfn h\u1ed7 tr\u1ee3 kh\u00e1ch h\u00e0ng \u2192 m\u1ec7nh \u0111\u1ec1 \u0111i\u1ec1u ki\u1ec7n l\u1ecbch s\u1ef1 'Should you have any questions' l\u00e0 chu\u1ea9n nh\u1ea5t. \u0110\u00e2y l\u00e0 c\u1ea5u tr\u00fac \u0111\u1ea3o ng\u1eef 'if you have' r\u1ea5t ph\u1ed5 bi\u1ebfn trong ETS Part 6.", "difficulty": "medium"}]}, {"passage": "CORFIELD & ASSOCIATES \u2014 Staff Development Bulletin\n\nMANDATORY TRAINING: DATA PRIVACY AND INFORMATION SECURITY\n\nAll employees are _____(1)_____ to complete the updated Data Privacy and Information Security training module by 30 November. This requirement applies to permanent and contract staff across all departments.\n\nThe training is delivered entirely online and _____(2)_____ approximately 90 minutes to complete. Participants will be assessed at the end of the module, and a minimum score of 80 percent is required to receive a certificate of completion.\n\n_____(3)_____ Employees who do not meet the required score on their first attempt may retake the assessment up to two additional times.\n\nTo access the module, log in to the Learning Management System at lms.corfield.com using your employee credentials. _____(4)_____ completing the module, please forward your certificate to your line manager and the HR department.\n\nQuestions regarding the training should be directed to training@corfield.com.", "passageTitle": "Memo: New Software Rollout", "type": "single", "questions": [{"id": "t9-p6-2a", "part": 6, "question": "All employees are _____(1)_____ to complete the updated training module by 30 November.", "options": ["required", "advised", "invited", "encouraged"], "answer": 0, "explanation": "'Required to' = b\u1eaft bu\u1ed9c ph\u1ea3i. Ph\u00f9 h\u1ee3p v\u1edbi 'mandatory training' trong ti\u00eau \u0111\u1ec1. 'Advised/invited/encouraged' \u0111\u1ec1u c\u00f3 ngh\u0129a khuy\u1ebfn kh\u00edch, kh\u00f4ng \u0111\u1ee7 m\u1ea1nh cho ng\u1eef c\u1ea3nh b\u1eaft bu\u1ed9c.", "difficulty": "medium"}, {"id": "t9-p6-2b", "part": 6, "question": "The training is delivered entirely online and _____(2)_____ approximately 90 minutes to complete.", "options": ["takes", "is taken", "taking", "has taken"], "answer": 0, "explanation": "Ch\u1ee7 ng\u1eef 'The training' + \u0111\u1ed9ng t\u1eeb ch\u1ee7 \u0111\u1ed9ng hi\u1ec7n t\u1ea1i \u0111\u01a1n \u2192 'takes'. C\u1ea5u tr\u00fac 'it takes [time] to do' l\u00e0 c\u1ed1 \u0111\u1ecbnh trong ti\u1ebfng Anh.", "difficulty": "medium"}, {"id": "t9-p6-2c", "part": 6, "question": "_____(3)_____", "options": ["This certificate will be required for your annual performance review.", "The module covers topics such as password security, phishing awareness, and data handling.", "IT support is available Monday to Friday if you experience technical difficulties.", "Employees who completed the previous version do not need to retake the training."], "answer": 1, "explanation": "C\u00e2u tr\u01b0\u1edbc n\u00f3i v\u1ec1 b\u00e0i \u0111\u00e1nh gi\u00e1 cu\u1ed1i module \u2192 c\u00e2u ti\u1ebfp theo h\u1ee3p l\u00fd nh\u1ea5t l\u00e0 m\u00f4 t\u1ea3 n\u1ed9i dung h\u1ecdc. Option B cung c\u1ea5p th\u00f4ng tin c\u1ee5 th\u1ec3 v\u1ec1 ch\u1ee7 \u0111\u1ec1 trong module.", "difficulty": "medium"}, {"id": "t9-p6-2d", "part": 6, "question": "_____(4)_____ completing the module, please forward your certificate to your line manager.", "options": ["Upon", "Despite", "While", "Unless"], "answer": 0, "explanation": "'Upon completing' = ngay sau khi ho\u00e0n th\u00e0nh (gi\u1edbi t\u1eeb ch\u1ec9 th\u1eddi gian t\u1ee9c th\u00ec, v\u0103n phong trang tr\u1ecdng). C\u1ea5u tr\u00fac 'upon + V-ing' r\u1ea5t ph\u1ed5 bi\u1ebfn trong ETS Part 6 formal announcements.", "difficulty": "medium"}]}, {"passage": "From: Facilities Management\nTo: All Building Tenants\nDate: May 12\nSubject: Scheduled Water Main Maintenance\n\nPlease be advised that the water supply to Building B will be ____(1)____ suspended on Saturday, May 15, from 8:00 a.m. to 4:00 p.m. This is necessary to facilitate critical repairs to the main water line.\n\n____(2)____, all restrooms and kitchen facilities on floors 1 through 10 will be unavailable during this time. We recommend that tenants who normally work on Saturdays make alternative arrangements ____(3)____ working from Building A or working remotely.\n\nWe apologize for any inconvenience this essential maintenance may cause. Normal water service is ____(4)____ to resume by 5:00 p.m. on Saturday.\n\nThank you for your cooperation.", "passageTitle": "Email: Subscription Renewal", "type": "single", "questions": [{"id": "ex6-1a", "part": 6, "question": "Blank (1):", "options": ["permanently", "temporarily", "randomly", "silently"], "answer": 1, "explanation": "'Temporarily suspended' = t\u1ea1m \u0111\u00ecnh ch\u1ec9. Ph\u00f9 h\u1ee3p v\u1edbi b\u1ea3o tr\u00ec theo l\u1ecbch.", "difficulty": "medium"}, {"id": "ex6-1b", "part": 6, "question": "Blank (2):", "options": ["Consequently", "However", "In contrast", "Nevertheless"], "answer": 0, "explanation": "'Consequently' = H\u1eadu qu\u1ea3 l\u00e0/K\u1ebft qu\u1ea3 l\u00e0. Ch\u1ec9 h\u1ec7 qu\u1ea3 c\u1ee7a vi\u1ec7c ng\u1eaft n\u01b0\u1edbc.", "difficulty": "medium"}, {"id": "ex6-1c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Tenants are advised to store an adequate supply of drinking water prior to the outage.", "The building management apologises for any inconvenience this may cause.", "Emergency contact numbers are posted on each floor near the stairwells.", "Affected tenants will receive a credit on their next invoice to compensate for the disruption."], "answer": 0, "explanation": "SI: th\u00f4ng b\u00e1o c\u1eaft n\u01b0\u1edbc t\u00f2a nh\u00e0. \"Store adequate drinking water prior to outage\" = h\u00e0nh \u0111\u1ed9ng th\u1ef1c t\u1ebf c\u1ea7n l\u00e0m tr\u01b0\u1edbc khi c\u1eaft n\u01b0\u1edbc \u2014 th\u00f4ng tin h\u1eefu \u00edch v\u00e0 thi\u1ebft th\u1ef1c nh\u1ea5t cho ng\u01b0\u1eddi thu\u00ea."}, {"id": "ex6-1d", "part": 6, "question": "Blank (4):", "options": ["expected", "denied", "refused", "cancelled"], "answer": 0, "explanation": "'Expected to resume' = d\u1ef1 ki\u1ebfn ti\u1ebfp t\u1ee5c l\u1ea1i.", "difficulty": "medium"}]}, {"passage": "To: All Sales Staff\nFrom: Marketing Director\nDate: June 15\nSubject: Third Quarter Strategy\n\nAs we approach the third quarter, it is imperative that we ____(1)____ our efforts to increase market share in the regional territories. Our recent survey shows that customer brand awareness is ____(2)____ than we initially projected.\n\n____(3)____, we will be launching a series of promotional events across major cities starting next month. All staff are required to attend a briefing session on Monday to discuss their specific roles. If you cannot attend, please ____(4)____ your manager as soon as possible.", "passageTitle": "Notice: Visitor Policy Update", "type": "single", "questions": [{"id": "b9-6-1a", "part": 6, "question": "Blank (1):", "options": ["double", "redouble", "reduce", "relax"], "answer": 1, "explanation": "'Redouble efforts' = t\u0103ng c\u01b0\u1eddng n\u1ed7 l\u1ef1c (collocation).", "difficulty": "medium"}, {"id": "b9-6-1b", "part": 6, "question": "Blank (2):", "options": ["lowly", "lower", "lowest", "low"], "answer": 1, "explanation": "So s\u00e1nh h\u01a1n 'lower than'.", "difficulty": "medium"}, {"id": "b9-6-1c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Accordingly, we will be launching a series of promotional events across major cities starting next month.", "All staff are required to submit their Q3 sales targets to regional managers by July 1.", "The survey results will be shared with the board at next week's strategic planning meeting.", "Staff who do not meet their Q2 targets will be required to attend a performance review session."], "answer": 0, "explanation": "SI: memo v\u1ec1 chi\u1ebfn l\u01b0\u1ee3c Q3 c\u1ee7a \u0111\u1ed9i sales. \"Launching promotional events across major cities\" = h\u00e0nh \u0111\u1ed9ng c\u1ee5 th\u1ec3, k\u1ebft n\u1ed1i tr\u1ef1c ti\u1ebfp v\u1edbi m\u1ee5c ti\u00eau t\u0103ng th\u1ecb ph\u1ea7n \u0111\u00e3 \u0111\u1ec1 c\u1eadp, d\u00f9ng \"Accordingly\" l\u00e0m t\u1eeb n\u1ed1i logic."}, {"id": "b9-6-1d", "part": 6, "question": "Blank (4):", "options": ["notify", "notification", "notifying", "notified"], "answer": 0, "explanation": "\u0110\u1ed9ng t\u1eeb 'notify someone'.", "difficulty": "medium"}]}, {"passage": "Lumina Energy Solutions\nCustomer Satisfaction Survey\n\nDear Value Customer,\n\nAt Lumina Energy, we strive to provide the most ____(1)____ service in the industry. Your feedback is vital to our continuous improvement process. Please take a few minutes to complete the attached survey regarding your recent ____(2)____ of our home solar panel kit.\n\nAs a token of our appreciation, ____(3)____ who complete the survey by July 31 will be entered into a drawing for a $100 gift card. Thank you for your continued ____(4)____.\n\nSincerely,\nLumina Customer Relations", "passageTitle": "Email: Equipment Repair Request", "type": "single", "questions": [{"id": "b9-6-2a", "part": 6, "question": "Blank (1):", "options": ["reliable", "reliability", "reliably", "relied"], "answer": 0, "explanation": "T\u00ednh t\u1eeb 'reliable' b\u1ed5 ngh\u0129a cho 'service'.", "difficulty": "medium"}, {"id": "b9-6-2b", "part": 6, "question": "Blank (2):", "options": ["bought", "buying", "purchase", "purchased"], "answer": 2, "explanation": "Danh t\u1eeb 'purchase' (vi\u1ec7c mua h\u00e0ng).", "difficulty": "medium"}, {"id": "b9-6-2c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Customers who complete the survey by July 31 will be entered into a drawing for a $100 gift card.", "The survey results will be used to improve our products and services in the coming year.", "All responses are completely anonymous and will not be shared with third parties.", "Customers who have already submitted their feedback do not need to complete this survey again."], "answer": 0, "explanation": "SI: email kh\u1ea3o s\u00e1t kh\u00e1ch h\u00e0ng. \"Complete by July 31, entered into drawing for $100 gift card\" = incentive khuy\u1ebfn kh\u00edch tham gia, th\u01b0\u1eddng \u0111\u1ee9ng ngay sau l\u1eddi m\u1eddi \u0111i\u1ec1n kh\u1ea3o s\u00e1t \u2014 t\u1ea1o \u0111\u1ed9ng l\u1ef1c thi\u1ebft th\u1ef1c nh\u1ea5t."}, {"id": "b9-6-2d", "part": 6, "question": "Blank (4):", "options": ["support", "supportive", "supporting", "supportively"], "answer": 0, "explanation": "Danh t\u1eeb 'support'.", "difficulty": "medium"}]}, {"passage": "SYSTEM MAINTENANCE NOTIFICATION\nFrom: IT Infrastructure Team\nTo: All Staff\n\nPlease be advised that the company's core IT systems will be _____(1)_____ for scheduled maintenance on Sunday, March 9, from 11:00 p.m. to 3:00 a.m.\n\nDuring this period, access to email, the internal portal, and all cloud-based applications will be _____(2)_____. We strongly recommend that all employees save and close any open files before the maintenance window begins.\n\n_____(3)_____\n\nWe apologize for any inconvenience. Normal service will _____(4)_____ immediately after maintenance is completed.\nIT Infrastructure Team", "passageTitle": "Memo: Marketing Campaign Brief", "type": "single", "questions": [{"id": "xp6-01a", "part": 6, "question": "Blank (1):", "options": ["offline", "unavailable", "suspended", "inactive"], "answer": 0, "explanation": "'Taken offline' = \u0111\u01b0a ra kh\u1ecfi tr\u1ea1ng th\u00e1i ho\u1ea1t \u0111\u1ed9ng \u0111\u1ec3 b\u1ea3o tr\u00ec. 'Unavailable' m\u00f4 t\u1ea3 tr\u1ea1ng th\u00e1i; 'suspended' d\u00f9ng cho t\u00e0i kho\u1ea3n/d\u1ecbch v\u1ee5; 'inactive' m\u00f4 t\u1ea3 tr\u1ea1ng th\u00e1i th\u1ee5 \u0111\u1ed9ng.", "difficulty": "medium"}, {"id": "xp6-01b", "part": 6, "question": "Blank (2):", "options": ["accessible", "unavailable", "restricted", "active"], "answer": 1, "explanation": "'Access will be unavailable' = kh\u00f4ng th\u1ec3 truy c\u1eadp trong th\u1eddi gian b\u1ea3o tr\u00ec. 'Unavailable' ch\u00ednh x\u00e1c nh\u1ea5t cho d\u1ecbch v\u1ee5 b\u1ecb gi\u00e1n \u0111o\u1ea1n.", "difficulty": "medium"}, {"id": "xp6-01c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["The IT team will be monitoring systems throughout the maintenance window to ensure a smooth process.", "All employees are required to attend an IT briefing session next Friday.", "The new system will include additional security features and improved performance.", "Please contact HR if you experience any personal data concerns."], "answer": 0, "explanation": "C\u00e2u ti\u1ebfp theo tr\u1ea5n an ng\u01b0\u1eddi d\u00f9ng r\u1eb1ng \u0111\u1ed9i IT s\u1ebd gi\u00e1m s\u00e1t trong su\u1ed1t qu\u00e1 tr\u00ecnh b\u1ea3o tr\u00ec \u2014 logic nh\u1ea5t sau th\u00f4ng b\u00e1o gi\u00e1n \u0111o\u1ea1n.", "difficulty": "medium"}, {"id": "xp6-01d", "part": 6, "question": "Blank (4):", "options": ["restore", "resume", "recover", "return"], "answer": 1, "explanation": "'Service will resume' = d\u1ecbch v\u1ee5 s\u1ebd ti\u1ebfp t\u1ee5c ho\u1ea1t \u0111\u1ed9ng (collocation chu\u1ea9n). 'Restore' c\u1ea7n t\u00e2n ng\u1eef; 'recover' d\u00f9ng cho d\u1eef li\u1ec7u; 'return' kh\u00f4ng \u0111i v\u1edbi 'service'.", "difficulty": "medium"}]}, {"passage": "Apex Consulting Group\n15 Commerce Street, Auckland\n\nDear Ms. Tanaka,\n\nOn behalf of Apex Consulting Group, I am delighted to _____(1)_____ you a formal offer of employment as Senior Business Analyst, effective April 14.\n\nYour annual base salary will be NZD 95,000, _____(2)_____ on a monthly basis. You will also be eligible for the company's performance bonus scheme, with a target award of 12% of base salary based on individual and company results.\n\nWe would be grateful if you could confirm your _____(3)_____ of this offer by March 28 by signing and returning the enclosed contract.\n\n_____(4)_____ We look forward to you joining the team.\n\nYours sincerely,\nDavid Lin, Head of People & Culture", "passageTitle": "Letter: Complaint Resolution", "type": "single", "questions": [{"id": "xp6-02a", "part": 6, "question": "Blank (1):", "options": ["extend", "provide", "give", "present"], "answer": 0, "explanation": "'Extend an offer' = \u0111\u01b0a ra l\u1eddi \u0111\u1ec1 ngh\u1ecb (formal collocation c\u1ed1 \u0111\u1ecbnh trong offer letters). 'Provide/give/present an offer' kh\u00f4ng ph\u1ea3i collocations chu\u1ea9n \u2013 'provide' th\u01b0\u1eddng \u0111i v\u1edbi 'provide someone WITH something'; 'give' qu\u00e1 th\u00f4ng th\u01b0\u1eddng; 'present' \u0111i v\u1edbi 'present something TO someone'.", "difficulty": "medium"}, {"id": "xp6-02b", "part": 6, "question": "Blank (2):", "options": ["payable", "paid", "paying", "payment"], "answer": 0, "explanation": "'Payable on a monthly basis' = c\u00f3 th\u1ec3 thanh to\u00e1n/\u0111\u01b0\u1ee3c tr\u1ea3 theo th\u00e1ng. \u0110\u00e2y l\u00e0 t\u00ednh t\u1eeb b\u1ed5 sung cho danh t\u1eeb 'salary' (danh t\u1eeb \u0111\u01b0\u1ee3c thanh to\u00e1n nh\u01b0 th\u1ebf n\u00e0o). 'Paid' l\u00e0 qu\u00e1 kh\u1ee9 ph\u00e2n t\u1eeb kh\u00f4ng ph\u00f9 h\u1ee3p \u1edf v\u1ecb tr\u00ed n\u00e0y; 'paying' v\u00e0 'payment' sai t\u1eeb lo\u1ea1i.", "difficulty": "medium"}, {"id": "xp6-02c", "part": 6, "question": "Blank (3):", "options": ["acceptance", "agreement", "acknowledgment", "approval"], "answer": 0, "explanation": "'Confirm your acceptance of this offer' = x\u00e1c nh\u1eadn ch\u1ea5p thu\u1eadn (collocation c\u1ed1 \u0111\u1ecbnh trong offer letters). 'Agreement' d\u00f9ng cho th\u1ecfa thu\u1eadn song ph\u01b0\u01a1ng; 'acknowledgment' = x\u00e1c nh\u1eadn \u0111\u00e3 nh\u1eadn.", "difficulty": "medium"}, {"id": "xp6-02d", "part": 6, "question": "Blank (4) \u2014 Choose the best sentence:", "options": ["Should you have any questions about the terms, please do not hesitate to contact me directly.", "The company's holiday schedule will be sent separately.", "Your start date may be subject to a background check.", "Please ensure you bring two forms of ID on your first day."], "answer": 0, "explanation": "C\u00e2u k\u1ebft offer letter \u2014 h\u1ee3p l\u00fd nh\u1ea5t l\u00e0 m\u1eddi \u1ee9ng vi\u00ean li\u00ean h\u1ec7 n\u1ebfu c\u00f3 th\u1eafc m\u1eafc v\u1ec1 \u0111i\u1ec1u kho\u1ea3n.", "difficulty": "medium"}]}, {"passage": "CUSTOMER NOTICE\n\nDear Valued Customers,\n\nWith effect from June 1, Horizon Homewares will be _____(1)_____ its returns policy.\n\nKey changes include: the return window for all full-priced merchandise will be _____(2)_____ from 30 days to 45 days; items purchased during promotional events will remain eligible for exchange only. Proof of purchase is required in all cases.\n\n_____(3)_____\n\nWe appreciate your continued _____(4)_____ and look forward to serving you.\n\nHorizon Homewares Customer Team", "passageTitle": "Email: Internship Program Announcement", "type": "single", "questions": [{"id": "xp6-03a", "part": 6, "question": "Blank (1):", "options": ["updating", "revising", "amending", "expanding"], "answer": 0, "explanation": "'Updating its returns policy' = c\u1eadp nh\u1eadt ch\u00ednh s\u00e1ch. 'Updating' t\u1ef1 nhi\u00ean nh\u1ea5t trong th\u00f4ng b\u00e1o kh\u00e1ch h\u00e0ng.", "difficulty": "medium"}, {"id": "xp6-03b", "part": 6, "question": "Blank (2):", "options": ["extended", "expanded", "increased", "widened"], "answer": 0, "explanation": "'Return window extended from 30 to 45 days' = k\u00e9o d\u00e0i th\u1eddi h\u1ea1n (collocation chu\u1ea9n). 'Extended period/window' l\u00e0 c\u1ee5m c\u1ed1 \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "xp6-03c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["For full details on the updated policy, please visit our website or speak with a team member in store.", "Our store hours will remain unchanged throughout the holiday period.", "We are also pleased to introduce a new loyalty rewards programme launching next month.", "Customers who have existing returns should process them before May 31."], "answer": 0, "explanation": "Sau khi n\u00eau thay \u0111\u1ed5i ch\u00ednh s\u00e1ch \u2192 h\u01b0\u1edbng d\u1eabn kh\u00e1ch t\u00ecm th\u00eam th\u00f4ng tin l\u00e0 logic nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-03d", "part": 6, "question": "Blank (4):", "options": ["patronage", "loyalty", "support", "custom"], "answer": 0, "explanation": "'Your continued patronage' = s\u1ef1 gh\u00e9 th\u0103m/mua s\u1eafm li\u00ean t\u1ee5c (collocation trang tr\u1ecdng trong th\u01b0 g\u1eedi kh\u00e1ch h\u00e0ng).", "difficulty": "medium"}]}, {"passage": "MEMORANDUM\nTo:    All Department Heads\nFrom:  Finance Director\nDate:  February 3\nRe:    Annual Budget Submission \u2014 Deadline Reminder\n\nThis memo serves as a reminder that all departmental budget submissions for the upcoming fiscal year are _____(1)_____ February 28.\n\nPlease ensure that all requests are supported by a detailed _____(2)_____ of projected expenditures, including headcount costs, capital purchases, and operational expenses. Submissions received without full documentation will not be processed.\n\n_____(3)_____\n\nAny department that anticipates difficulty meeting this deadline should contact the Finance team immediately to discuss _____(4)_____ arrangements.\n\nThank you for your cooperation.", "passageTitle": "Notice: Water Supply Interruption", "type": "single", "questions": [{"id": "xp6-04a", "part": 6, "question": "Blank (1):", "options": ["due by", "due on", "due at", "due for"], "answer": 0, "explanation": "'Due by February 28' = ph\u1ea3i n\u1ed9p tr\u01b0\u1edbc ng\u00e0y 28/2 (deadline). 'Due by' ch\u1ec9 h\u1ea1n ch\u00f3t kh\u00f4ng mu\u1ed9n h\u01a1n.", "difficulty": "medium"}, {"id": "xp6-04b", "part": 6, "question": "Blank (2):", "options": ["breakdown", "summary", "overview", "outline"], "answer": 0, "explanation": "'Detailed breakdown of expenditures' = ph\u00e2n t\u00edch chi ti\u1ebft t\u1eebng kho\u1ea3n (collocation t\u00e0i ch\u00ednh chu\u1ea9n). 'Summary/overview' ngh\u0129a t\u1ed5ng qu\u00e1t, ng\u01b0\u1ee3c v\u1edbi 'detailed'.", "difficulty": "medium"}, {"id": "xp6-04c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Budget templates and submission guidelines are available on the Finance portal under 'FY Budget Resources'.", "All capital purchases above USD 10,000 require board approval regardless of budget allocation.", "The Finance team will be hosting a webinar on budget forecasting next Thursday at 2:00 p.m.", "Departments that overspend their approved budget will face a review in Q3."], "answer": 0, "explanation": "Sau h\u01b0\u1edbng d\u1eabn n\u1ed9p ng\u00e2n s\u00e1ch \u2192 cung c\u1ea5p t\u00e0i nguy\u00ean/c\u00f4ng c\u1ee5 l\u00e0 logic nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-04d", "part": 6, "question": "Blank (4):", "options": ["alternative", "extended", "revised", "flexible"], "answer": 0, "explanation": "'Alternative arrangements' = s\u1eafp x\u1ebfp thay th\u1ebf khi kh\u00f4ng \u0111\u00e1p \u1ee9ng deadline. Collocation t\u1ef1 nhi\u00ean nh\u1ea5t.", "difficulty": "medium"}]}, {"passage": "From: People Operations <hr@stellartech.com>\nTo: New Starters \u2014 May Cohort\nDate: April 28\nSubject: Your First Week at StellarTech\n\nWe are excited to welcome you to StellarTech! To help you _____(1)_____ smoothly into your new role, we have prepared a structured onboarding programme for your first week.\n\nYour first day will begin with a welcome session at 9:00 a.m. in the Main Boardroom. You will then meet your _____(2)_____ manager, who will guide you through your department's processes and introduce you to your colleagues.\n\n_____(3)_____\n\nPlease ensure you bring valid identification and your signed employment contract on your first day. If you have any questions before then, do not _____(4)_____ to reach out to your designated HR contact.\n\nWe look forward to seeing you soon!\nPeople Operations Team", "passageTitle": "Memo: Expense Report Submission", "type": "single", "questions": [{"id": "xp6-05a", "part": 6, "question": "Blank (1):", "options": ["settle", "transition", "integrate", "adapt"], "answer": 2, "explanation": "'Integrate smoothly into your new role' = h\u00f2a nh\u1eadp su\u00f4n s\u1ebb (HR collocation chu\u1ea9n). 'Integrate into' ph\u1ed5 bi\u1ebfn nh\u1ea5t trong v\u0103n b\u1ea3n onboarding.", "difficulty": "medium"}, {"id": "xp6-05b", "part": 6, "question": "Blank (2):", "options": ["line", "direct", "immediate", "assigned"], "answer": 0, "explanation": "'Line manager' = qu\u1ea3n l\u00fd tr\u1ef1c ti\u1ebfp (thu\u1eadt ng\u1eef HR chu\u1ea9n). Ph\u1ed5 bi\u1ebfn nh\u1ea5t trong v\u0103n b\u1ea3n c\u00f4ng ty ETS.", "difficulty": "medium"}, {"id": "xp6-05c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["A full onboarding schedule, including IT setup and system access times, has been emailed to you separately.", "The canteen is located on the ground floor and serves hot meals from 12:00 to 2:00 p.m.", "Please note that parking is available in the basement from 7:00 a.m.", "Your employment contract outlines all terms and conditions of your engagement."], "answer": 0, "explanation": "M\u00f4 t\u1ea3 onboarding ng\u00e0y \u0111\u1ea7u \u2192 l\u1ecbch tr\u00ecnh chi ti\u1ebft h\u01a1n l\u00e0 th\u1ef1c d\u1ee5ng nh\u1ea5t cho nh\u00e2n vi\u00ean m\u1edbi.", "difficulty": "medium"}, {"id": "xp6-05d", "part": 6, "question": "Blank (4):", "options": ["hesitate", "fail", "forget", "delay"], "answer": 0, "explanation": "'Do not hesitate to reach out' = \u0111\u1eebng ng\u1ea1i li\u00ean h\u1ec7 (c\u1ee5m l\u1ecbch s\u1ef1 c\u1ed1 \u0111\u1ecbnh trong email HR).", "difficulty": "medium"}]}, {"passage": "NOTICE OF CONTRACT RENEWAL\nPrepared by: Legal & Compliance\nTo: Procurement Department\n\nThis notice is to inform you that the Master Services Agreement with Pinnacle Logistics will _____(1)_____ on September 30.\n\nIn accordance with Section 12.3 of the agreement, either party must provide at least 60 days' written notice of _____(2)_____ to renew. Failure to provide this notice within the required timeframe will result in the contract being automatically renewed for a further 12-month period.\n\n_____(3)_____\n\nIf you wish to proceed with renegotiating the terms of the agreement, please contact the Legal team _____(4)_____ your soonest convenience.\n\nLegal & Compliance Division", "passageTitle": "Email: Board Meeting Agenda", "type": "single", "questions": [{"id": "xp6-06a", "part": 6, "question": "Blank (1):", "options": ["expire", "conclude", "terminate", "end"], "answer": 0, "explanation": "'Contract will expire' = h\u1ebft h\u1ea1n (thu\u1eadt ng\u1eef ph\u00e1p l\u00fd chu\u1ea9n). 'Terminate' = ch\u1ea5m d\u1ee9t s\u1edbm do vi ph\u1ea1m; 'conclude/end' kh\u00f4ng \u0111\u1eb7c th\u00f9 cho h\u1ee3p \u0111\u1ed3ng.", "difficulty": "medium"}, {"id": "xp6-06b", "part": 6, "question": "Blank (2):", "options": ["intention", "decision", "preference", "desire"], "answer": 0, "explanation": "'Notice of intention not to renew' = th\u00f4ng b\u00e1o c\u00f3 \u00fd \u0111\u1ecbnh kh\u00f4ng gia h\u1ea1n (ng\u00f4n ng\u1eef ph\u00e1p l\u00fd chu\u1ea9n).", "difficulty": "medium"}, {"id": "xp6-06c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Given the upcoming expiration date, we recommend initiating a review of the current terms by August 1 at the latest.", "The procurement team should consult with the finance department regarding budget implications.", "All future supplier agreements must be approved by the board prior to signing.", "Please be aware that late renewals may incur a 5% administrative surcharge."], "answer": 0, "explanation": "Sau th\u00f4ng b\u00e1o h\u1ebft h\u1ea1n \u2192 khuy\u1ebfn ngh\u1ecb h\u00e0nh \u0111\u1ed9ng c\u1ee5 th\u1ec3 v\u1edbi deadline l\u00e0 logic nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-06d", "part": 6, "question": "Blank (4):", "options": ["at", "on", "in", "by"], "answer": 0, "explanation": "'At your soonest convenience' = v\u00e0o th\u1eddi \u0111i\u1ec3m s\u1edbm nh\u1ea5t thu\u1eadn ti\u1ec7n (c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong v\u0103n b\u1ea3n trang tr\u1ecdng).", "difficulty": "medium"}]}, {"passage": "From: Reservations <reservations@grandpacific.com>\nTo: Mr. David Park\nDate: October 12\nSubject: Booking Confirmation \u2014 Ref: GP-44921\n\nDear Mr. Park,\n\nThank you for choosing Grand Pacific Hotel. We are pleased to confirm your reservation for a Superior King Room from November 8 to November 11 (3 nights).\n\nAs requested, early check-in at 11:00 a.m. has been _____(1)_____, subject to room availability on the day of arrival. Standard check-out time is 12:00 noon; a late check-out _____(2)_____ be arranged for an additional charge if required.\n\n_____(3)_____\n\nShould you need to modify or cancel your booking, please note that cancellations made less than 48 hours before arrival will _____(4)_____ a one-night charge.\n\nWe look forward to welcoming you.\nGrand Pacific Reservations Team", "passageTitle": "Notice: Gym Facility Guidelines", "type": "single", "questions": [{"id": "xp6-07a", "part": 6, "question": "Blank (1):", "options": ["arranged", "confirmed", "reserved", "noted"], "answer": 0, "explanation": "'Early check-in has been arranged' = \u0111\u00e3 \u0111\u01b0\u1ee3c thu x\u1ebfp (collocation kh\u00e1ch s\u1ea1n chu\u1ea9n cho special requests).", "difficulty": "medium"}, {"id": "xp6-07b", "part": 6, "question": "Blank (2):", "options": ["can", "may", "will", "should"], "answer": 1, "explanation": "'Late check-out may be arranged' = c\u00f3 th\u1ec3 \u0111\u01b0\u1ee3c s\u1eafp x\u1ebfp (kh\u1ea3 n\u0103ng). 'May' l\u1ecbch s\u1ef1 nh\u1ea5t; 'will' qu\u00e1 kh\u1eb3ng \u0111\u1ecbnh.", "difficulty": "medium"}, {"id": "xp6-07c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["A complimentary breakfast for two is included in your room rate and is served in the Garden Restaurant from 7:00 to 10:30 a.m.", "Please note that parking is not available at the hotel; the nearest public car park is 200 metres away.", "Our spa facilities are open daily from 8:00 a.m. to 9:00 p.m. and can be booked in advance.", "Room service is available 24 hours and the menu can be found in your room."], "answer": 0, "explanation": "Email x\u00e1c nh\u1eadn \u0111\u1eb7t ph\u00f2ng \u2192 b\u1eefa s\u00e1ng mi\u1ec5n ph\u00ed (included amenity) l\u00e0 th\u00f4ng tin quan tr\u1ecdng v\u00e0 ph\u1ed5 bi\u1ebfn nh\u1ea5t trong ETS sentence-insertion.", "difficulty": "medium"}, {"id": "xp6-07d", "part": 6, "question": "Blank (4):", "options": ["incur", "attract", "result in", "carry"], "answer": 0, "explanation": "'Will incur a charge' = s\u1ebd ph\u1ea3i ch\u1ecbu kho\u1ea3n ph\u00ed (collocation t\u00e0i ch\u00ednh/ph\u00e1p l\u00fd chu\u1ea9n ETS).", "difficulty": "medium"}]}, {"passage": "From: Product Team <product@velosoft.com>\nTo: Enterprise Clients\nDate: May 19\nSubject: VeloDesk 4.0 \u2014 Now Available\n\nWe are pleased to announce that VeloDesk 4.0 is now _____(1)_____ for download.\n\nThis major update introduces a redesigned dashboard, improved API integrations, and enhanced security protocols in _____(2)_____ with the latest ISO 27001 standards.\n\n_____(3)_____\n\nTo upgrade, simply log into your admin portal and navigate to Settings > System Updates. Your existing data and configurations will be _____(4)_____ during the upgrade process.\n\nPlease reach out to your account manager if you require assistance.\nThe VeloSoft Product Team", "passageTitle": "Email: Product Recall Notice", "type": "single", "questions": [{"id": "xp6-08a", "part": 6, "question": "Blank (1):", "options": ["available", "accessible", "released", "ready"], "answer": 0, "explanation": "'Now available for download' = hi\u1ec7n c\u00f3 th\u1ec3 t\u1ea3i xu\u1ed1ng (collocation chu\u1ea9n cho software release).", "difficulty": "medium"}, {"id": "xp6-08b", "part": 6, "question": "Blank (2):", "options": ["compliance", "accordance", "line", "alignment"], "answer": 1, "explanation": "'In accordance with ISO standards' = ph\u00f9 h\u1ee3p v\u1edbi ti\u00eau chu\u1ea9n (c\u1ee5m gi\u1edbi t\u1eeb c\u1ed1 \u0111\u1ecbnh). Ph\u1ed5 bi\u1ebfn nh\u1ea5t trong v\u0103n b\u1ea3n k\u1ef9 thu\u1eadt ETS.", "difficulty": "medium"}, {"id": "xp6-08c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["All enterprise clients on annual plans will receive the update at no additional cost.", "The new dashboard design was developed based on feedback from over 2,000 users in our beta programme.", "VeloDesk 4.0 is compatible with Windows 10 and above, and macOS 12 or later.", "A full list of changes and known issues is documented in the release notes."], "answer": 0, "explanation": "Email th\u00f4ng b\u00e1o c\u1eadp nh\u1eadt cho enterprise clients \u2192 th\u00f4ng tin v\u1ec1 gi\u00e1/ph\u00ed l\u00e0 quan tr\u1ecdng nh\u1ea5t v\u00e0 tr\u1ea3 l\u1eddi c\u00e2u h\u1ecfi th\u1ef1c t\u1ebf nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-08d", "part": 6, "question": "Blank (4):", "options": ["preserved", "retained", "maintained", "kept"], "answer": 0, "explanation": "'Data will be preserved during upgrade' = d\u1eef li\u1ec7u \u0111\u01b0\u1ee3c gi\u1eef nguy\u00ean (IT collocation chu\u1ea9n nh\u1ea5n m\u1ea1nh t\u00ednh to\u00e0n v\u1eb9n).", "difficulty": "medium"}]}, {"passage": "From: Customer Care <care@rapidfreight.com>\nTo: Elena Sousa\nDate: March 6\nSubject: Shipment Update \u2014 Order #RF-20214\n\nDear Ms. Sousa,\n\nWe are writing to advise you of an _____(1)_____ delay affecting your shipment (#RF-20214), originally scheduled for delivery on March 7.\n\nDue to severe weather conditions in the transit region, your consignment has been _____(2)_____ at our Brisbane depot until conditions improve. We currently estimate delivery will take place within 3\u20135 business days.\n\n_____(3)_____\n\nWe sincerely apologize for the inconvenience. If you would like to discuss alternative _____(4)_____ options, our customer care team is available 24/7.\n\nRapidFreight Customer Care", "passageTitle": "Memo: Client Entertainment Policy", "type": "single", "questions": [{"id": "xp6-09a", "part": 6, "question": "Blank (1):", "options": ["unforeseen", "unexpected", "unplanned", "sudden"], "answer": 0, "explanation": "'Unforeseen delay' = s\u1ef1 ch\u1eadm tr\u1ec5 kh\u00f4ng l\u01b0\u1eddng tr\u01b0\u1edbc (logistics collocation chu\u1ea9n).", "difficulty": "medium"}, {"id": "xp6-09b", "part": 6, "question": "Blank (2):", "options": ["held", "stored", "kept", "placed"], "answer": 0, "explanation": "'Consignment has been held at the depot' = l\u00f4 h\u00e0ng b\u1ecb gi\u1eef l\u1ea1i (thu\u1eadt ng\u1eef logistics chu\u1ea9n).", "difficulty": "medium"}, {"id": "xp6-09c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["You can track your shipment in real time using your tracking number at rapidfreight.com/track.", "Our depot operates Monday to Friday from 8:00 a.m. to 6:00 p.m.", "We recommend that you contact your local customs office if the delay exceeds 10 days.", "RapidFreight handles over 50,000 deliveries per week across Australia."], "answer": 0, "explanation": "Email th\u00f4ng b\u00e1o ch\u1eadm giao h\u00e0ng \u2192 h\u01b0\u1edbng d\u1eabn theo d\u00f5i tr\u1ea1ng th\u00e1i l\u00e0 th\u1ef1c d\u1ee5ng nh\u1ea5t cho kh\u00e1ch h\u00e0ng.", "difficulty": "medium"}, {"id": "xp6-09d", "part": 6, "question": "Blank (4):", "options": ["delivery", "shipping", "dispatch", "forwarding"], "answer": 0, "explanation": "'Alternative delivery options' = ph\u01b0\u01a1ng \u00e1n giao h\u00e0ng thay th\u1ebf (collocation chu\u1ea9n trong customer service).", "difficulty": "medium"}]}, {"passage": "NOTICE OF ANNUAL GENERAL MEETING\nArcadia Holdings Limited\n\nNotice is hereby _____(1)_____ that the Annual General Meeting (AGM) of Arcadia Holdings Limited will be held at the Riverside Conference Centre, Level 4, on Thursday, June 19, commencing at 10:00 a.m.\n\nThe AGM agenda will include: (i) review of the annual financial statements; (ii) re-election of board directors; (iii) appointment of external auditors for the _____(2)_____ financial year; and (iv) any other business as approved by the Chairman.\n\n_____(3)_____\n\nShareholders who are unable to attend in person may _____(4)_____ a proxy to vote on their behalf by submitting the enclosed proxy form no later than June 12.\n\nBy order of the Board\nGenevieve Park, Company Secretary", "passageTitle": "Email: Survey Participation Request", "type": "single", "questions": [{"id": "xp6-10a", "part": 6, "question": "Blank (1):", "options": ["given", "stated", "provided", "issued"], "answer": 0, "explanation": "'Notice is hereby given' = xin th\u00f4ng b\u00e1o r\u1eb1ng (c\u1ee5m ph\u00e1p l\u00fd c\u1ed1 \u0111\u1ecbnh, b\u1eaft bu\u1ed9c trong AGM notices).", "difficulty": "medium"}, {"id": "xp6-10b", "part": 6, "question": "Blank (2):", "options": ["upcoming", "forthcoming", "ensuing", "next"], "answer": 1, "explanation": "'For the forthcoming financial year' = cho n\u0103m t\u00e0i ch\u00ednh s\u1eafp t\u1edbi (t\u1eeb trang tr\u1ecdng chu\u1ea9n trong v\u0103n b\u1ea3n AGM).", "difficulty": "medium"}, {"id": "xp6-10c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Shareholders are entitled to attend, speak, and vote at the AGM, and may also submit written questions in advance.", "Light refreshments will be served prior to the commencement of the meeting.", "The Board recommends voting in favour of all resolutions presented.", "Annual reports and proxy forms have been mailed to all registered shareholders."], "answer": 0, "explanation": "AGM notice \u2192 gi\u1ea3i th\u00edch quy\u1ec1n c\u1ee7a c\u1ed5 \u0111\u00f4ng l\u00e0 logic nh\u1ea5t trong c\u1ea5u tr\u00fac v\u0103n b\u1ea3n ph\u00e1p l\u00fd.", "difficulty": "medium"}, {"id": "xp6-10d", "part": 6, "question": "Blank (4):", "options": ["appoint", "assign", "designate", "nominate"], "answer": 0, "explanation": "'Appoint a proxy' = \u1ee7y quy\u1ec1n \u0111\u1ea1i di\u1ec7n bi\u1ec3u quy\u1ebft (thu\u1eadt ng\u1eef ph\u00e1p l\u00fd c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}]}, {"passage": "SUSTAINABILITY UPDATE \u2014 Q3\nGreenCore Manufacturing\n\nGreenCore Manufacturing is pleased to report _____(1)_____ progress toward its 2030 sustainability goals.\n\nThis quarter, the company reduced its total carbon emissions by 18% compared to the same period last year, _____(2)_____ the early deployment of solar panels across three production facilities.\n\nIn addition, 94% of packaging materials now _____(3)_____ from certified sustainable sources. GreenCore aims to achieve 100% sustainable sourcing by the end of next year.\n\n_____(4)_____\n\nFull details are available in the quarterly sustainability report on our website.", "passageTitle": "Notice: Recycling Program Update", "type": "single", "questions": [{"id": "xp6-11a", "part": 6, "question": "Blank (1):", "options": ["significant", "substantial", "considerable", "notable"], "answer": 3, "explanation": "'Report notable progress' = ti\u1ebfn tri\u1ec3n \u0111\u00e1ng ch\u00fa \u00fd. 'Notable' ph\u1ed5 bi\u1ebfn nh\u1ea5t trong sustainability reporting.", "difficulty": "medium"}, {"id": "xp6-11b", "part": 6, "question": "Blank (2):", "options": ["following", "owing to", "due to", "thanks to"], "answer": 1, "explanation": "'Owing to the deployment' = nh\u1edd v\u00e0o vi\u1ec7c tri\u1ec3n khai (ch\u1ec9 nguy\u00ean nh\u00e2n t\u00edch c\u1ef1c, trang tr\u1ecdng). 'Owing to' c\u00f3 s\u1eafc th\u00e1i t\u00edch c\u1ef1c ph\u00f9 h\u1ee3p b\u00e1o c\u00e1o.", "difficulty": "medium"}, {"id": "xp6-11c", "part": 6, "question": "Blank (3):", "options": ["originate", "are sourced", "come", "derive"], "answer": 1, "explanation": "'Materials are sourced from sustainable sources' = \u0111\u01b0\u1ee3c l\u1ea5y t\u1eeb ngu\u1ed3n b\u1ec1n v\u1eefng (passive collocation chu\u1ea9n).", "difficulty": "medium"}, {"id": "xp6-11d", "part": 6, "question": "Blank (4) \u2014 Choose the best sentence:", "options": ["These achievements have been independently verified by EcoAudit International, a third-party sustainability certification body.", "The company has also pledged to eliminate single-use plastics from all office locations by year-end.", "Employees are encouraged to participate in GreenCore's annual sustainability survey.", "GreenCore's sustainability strategy was launched in 2021 following a review by the board."], "answer": 0, "explanation": "Sau b\u00e1o c\u00e1o ti\u1ebfn tri\u1ec3n \u2192 x\u00e1c nh\u1eadn b\u00ean th\u1ee9 ba (third-party verification) l\u00e0 \u0111i\u1ec3m m\u1ea1nh nh\u1ea5t trong sustainability reporting.", "difficulty": "medium"}]}, {"passage": "From: Trust & Safety <safety@shopwave.com>\nTo: Account: SunriseCraft (seller ID: SC-88421)\nDate: August 14\nSubject: Important Notice Regarding Your Account\n\nDear SunriseCraft Team,\n\nWe are writing to notify you that your ShopWave seller account has been _____(1)_____ following a review of recent activity.\n\nOur systems identified that three orders were fulfilled with items that did not _____(2)_____ the descriptions listed on your product pages. This is a violation of ShopWave's Seller Accuracy Policy.\n\n_____(3)_____\n\nTo have your account _____(4)_____, please submit a written explanation and corrective action plan to trust@shopwave.com within seven business days. Failure to respond within this timeframe may result in permanent account closure.\n\nTrust & Safety Team, ShopWave", "passageTitle": "Letter: Lease Renewal Terms", "type": "single", "questions": [{"id": "xp6-12a", "part": 6, "question": "Blank (1):", "options": ["suspended", "restricted", "deactivated", "frozen"], "answer": 0, "explanation": "'Account has been suspended' = t\u00e0i kho\u1ea3n b\u1ecb t\u1ea1m \u0111\u00ecnh ch\u1ec9 (collocation chu\u1ea9n trong platform enforcement).", "difficulty": "medium"}, {"id": "xp6-12b", "part": 6, "question": "Blank (2):", "options": ["match", "correspond to", "align with", "reflect"], "answer": 0, "explanation": "'Items did not match the descriptions' = kh\u00f4ng kh\u1edbp m\u00f4 t\u1ea3 (e-commerce collocation chu\u1ea9n).", "difficulty": "medium"}, {"id": "xp6-12c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["While your account is suspended, you will not be able to list new products or process orders.", "ShopWave has over 5 million active buyers across 40 countries.", "We value your contribution to the ShopWave marketplace and hope to resolve this matter quickly.", "Our seller support team is available Monday to Friday from 9:00 a.m. to 6:00 p.m."], "answer": 0, "explanation": "Sau th\u00f4ng b\u00e1o \u0111\u00ecnh ch\u1ec9 \u2192 gi\u1ea3i th\u00edch t\u00e1c \u0111\u1ed9ng c\u1ee5 th\u1ec3 l\u00e0 logic nh\u1ea5t cho ng\u01b0\u1eddi b\u00e1n.", "difficulty": "medium"}, {"id": "xp6-12d", "part": 6, "question": "Blank (4):", "options": ["reinstated", "restored", "reactivated", "reopened"], "answer": 0, "explanation": "'Account reinstated' = t\u00e0i kho\u1ea3n \u0111\u01b0\u1ee3c ph\u1ee5c h\u1ed3i (collocation chu\u1ea9n sau suspension trong platform policy).", "difficulty": "medium"}]}, {"passage": "PREMIER MEMBERSHIP \u2014 ANNUAL BENEFITS RENEWAL\nFitLife Wellness Centres\n\nDear Ms. Callahan,\n\nThank you for being a valued Premier member. Your membership is due for _____(1)_____ on September 1, and we would like to take this opportunity to highlight some exciting updates to your benefits.\n\nThis year, your Premier membership will include _____(2)_____ access to all 12 FitLife locations nationwide, an increase from the previous 8. In addition, Premier members will now receive a complimentary personal training session each _____(3)_____.\n\n_____(4)_____ To take advantage of this offer, simply present your membership card or the FitLife app at any location.\n\nWe look forward to continuing to support your wellness journey.\nFitLife Member Services", "passageTitle": "Email: Team Building Event", "type": "single", "questions": [{"id": "xp6-13a", "part": 6, "question": "Blank (1):", "options": ["renewal", "extension", "expiry", "review"], "answer": 0, "explanation": "'Membership due for renewal' = th\u00e0nh vi\u00ean c\u1ea7n gia h\u1ea1n (collocation c\u1ed1 \u0111\u1ecbnh). 'Renewal' l\u00e0 thu\u1eadt ng\u1eef chu\u1ea9n.", "difficulty": "medium"}, {"id": "xp6-13b", "part": 6, "question": "Blank (2):", "options": ["unlimited", "unrestricted", "full", "complete"], "answer": 0, "explanation": "'Unlimited access to all locations' = truy c\u1eadp kh\u00f4ng gi\u1edbi h\u1ea1n (membership collocation chu\u1ea9n).", "difficulty": "medium"}, {"id": "xp6-13c", "part": 6, "question": "Blank (3):", "options": ["quarter", "month", "year", "visit"], "answer": 1, "explanation": "'A complimentary session each month' = bu\u1ed5i mi\u1ec5n ph\u00ed m\u1ed7i th\u00e1ng \u2014 t\u1ea7n su\u1ea5t t\u1ef1 nhi\u00ean nh\u1ea5t cho recurring benefit.", "difficulty": "medium"}, {"id": "xp6-13d", "part": 6, "question": "Blank (4) \u2014 Choose the best sentence:", "options": ["Your new membership card, valid through August 31 of next year, will be mailed to your registered address within five business days.", "Personal training sessions must be booked at least 24 hours in advance through the FitLife app.", "FitLife has been voted the number one wellness brand in Australia for three consecutive years.", "Our group fitness timetable has been updated for the new season and is available on the website."], "answer": 0, "explanation": "Sau th\u00f4ng b\u00e1o gia h\u1ea1n \u2192 th\u00f4ng tin v\u1ec1 th\u1ebb th\u00e0nh vi\u00ean m\u1edbi l\u00e0 th\u1ef1c d\u1ee5ng v\u00e0 li\u00ean quan tr\u1ef1c ti\u1ebfp nh\u1ea5t.", "difficulty": "medium"}]}, {"passage": "POLICY UPDATE: FLEXIBLE WORKING ARRANGEMENTS\nTo: All Permanent Staff\nFrom: Director of Human Resources\nEffective: Monday, October 6\n\nFollowing a comprehensive review, the company is pleased to introduce an _____(1)_____ remote working policy, effective October 6.\n\nEligible employees may work remotely for up to three days per week, _____(2)_____ that they maintain full availability during core business hours (9:00 a.m. \u2013 4:00 p.m.) and attend all scheduled in-person team meetings.\n\n_____(3)_____\n\nManagers will review remote working arrangements on a quarterly basis and retain the _____(4)_____ to modify or withdraw the arrangement if business needs require.\n\nFull policy guidelines are available on the HR portal.\nDirector of Human Resources", "passageTitle": "Memo: Dress Code Policy", "type": "single", "questions": [{"id": "xp6-14a", "part": 6, "question": "Blank (1):", "options": ["updated", "enhanced", "expanded", "revised"], "answer": 2, "explanation": "'Expanded remote working policy' = ch\u00ednh s\u00e1ch \u0111\u01b0\u1ee3c m\u1edf r\u1ed9ng (ph\u00f9 h\u1ee3p ng\u1eef c\u1ea3nh t\u0103ng s\u1ed1 ng\u00e0y WFH). 'Expanded' ch\u1ec9 s\u1ef1 m\u1edf r\u1ed9ng ph\u1ea1m vi.", "difficulty": "medium"}, {"id": "xp6-14b", "part": 6, "question": "Blank (2):", "options": ["provided", "given", "assuming", "considering"], "answer": 0, "explanation": "'Provided that they maintain availability' = v\u1edbi \u0111i\u1ec1u ki\u1ec7n l\u00e0 (c\u1ee5m \u0111i\u1ec1u ki\u1ec7n c\u1ed1 \u0111\u1ecbnh, trang tr\u1ecdng nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-14c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Requests to work remotely must be submitted to your line manager at least one week in advance and are subject to approval.", "Staff are reminded that all company data accessed remotely must be handled in accordance with the IT Security Policy.", "Hot-desking stations have been set up on Floors 3 and 4 for staff who choose to work on-site less frequently.", "The company will provide a one-time home office equipment allowance of AUD 400 for eligible employees."], "answer": 1, "explanation": "Sau \u0111i\u1ec1u kho\u1ea3n WFH \u2192 b\u1ea3o m\u1eadt d\u1eef li\u1ec7u khi l\u00e0m vi\u1ec7c t\u1eeb xa l\u00e0 y\u00eau c\u1ea7u tu\u00e2n th\u1ee7 quan tr\u1ecdng nh\u1ea5t c\u1ea7n b\u1ed5 sung.", "difficulty": "medium"}, {"id": "xp6-14d", "part": 6, "question": "Blank (4):", "options": ["right", "authority", "discretion", "option"], "answer": 2, "explanation": "'Managers retain the discretion to modify arrangements' = gi\u1eef quy\u1ec1n quy\u1ebft \u0111\u1ecbnh theo t\u1eebng t\u00ecnh hu\u1ed1ng (HR policy collocation chu\u1ea9n).", "difficulty": "medium"}]}, {"passage": "From: Organising Committee <events@nexussummit.org>\nTo: All Registered Delegates\nDate: November 22\nSubject: Thank You \u2014 Nexus Innovation Summit 2024\n\nDear Delegate,\n\nOn behalf of the Nexus Innovation Summit Organising Committee, we would like to _____(1)_____ our sincere gratitude for your participation in this year's event.\n\nWe were delighted to welcome over 1,200 delegates from 35 countries, making this the most _____(2)_____ attended edition of the Summit to date.\n\n_____(3)_____\n\nAll keynote recordings and presentation slides will be made _____(4)_____ to registered delegates via the Summit portal within the next 10 business days. You will receive a separate email with your access link.\n\nWe look forward to seeing you at Nexus 2025.\nNexus Organising Committee", "passageTitle": "Notice: Award Nomination Process", "type": "single", "questions": [{"id": "xp6-15a", "part": 6, "question": "Blank (1):", "options": ["express", "extend", "convey", "offer"], "answer": 0, "explanation": "'Express our sincere gratitude' = b\u00e0y t\u1ecf l\u00f2ng bi\u1ebft \u01a1n (collocation chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-15b", "part": 6, "question": "Blank (2):", "options": ["widely", "well", "highly", "broadly"], "answer": 1, "explanation": "'Most well-attended edition' = phi\u00ean b\u1ea3n c\u00f3 \u0111\u00f4ng ng\u01b0\u1eddi tham d\u1ef1 nh\u1ea5t ('well-attended' l\u00e0 t\u00ednh t\u1eeb gh\u00e9p ti\u00eau chu\u1ea9n).", "difficulty": "medium"}, {"id": "xp6-15c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["We are currently reviewing delegate feedback and will incorporate your suggestions into the planning of Nexus 2025.", "The venue, the Grand Hyatt Convention Centre, has been confirmed for next year's event as well.", "Our sponsorship packages for Nexus 2025 will be available from January.", "A highlight reel of the Summit is now available on our YouTube channel."], "answer": 0, "explanation": "Email c\u1ea3m \u01a1n sau s\u1ef1 ki\u1ec7n \u2192 cho th\u1ea5y ph\u1ea3n h\u1ed3i \u0111\u01b0\u1ee3c l\u1eafng nghe l\u00e0 quan tr\u1ecdng nh\u1ea5t \u0111\u1ec3 x\u00e2y d\u1ef1ng m\u1ed1i quan h\u1ec7 v\u1edbi delegate.", "difficulty": "medium"}, {"id": "xp6-15d", "part": 6, "question": "Blank (4):", "options": ["available", "accessible", "open", "free"], "answer": 0, "explanation": "'Will be made available to delegates' = s\u1ebd \u0111\u01b0\u1ee3c cung c\u1ea5p ('made available' l\u00e0 collocation c\u1ed1 \u0111\u1ecbnh cho quy\u1ec1n truy c\u1eadp t\u00e0i li\u1ec7u).", "difficulty": "medium"}]}, {"passage": "NOTICE TO ALL RESIDENTS\nOakdale Apartment Complex\n\nDear Residents,\n\nThis notice is to inform you that the main lobby and entrance area will be _____(1)_____ starting Monday, April 7, for a period of two weeks.\n\nDuring this time, residents are asked to use the side entrance on Birch Lane. Building management apologizes for any _____(2)_____ this may cause.\n\n_____(3)_____\n\nFor any urgent concerns, please contact the building manager at ext. 101 or via email at manager@oakdaleliving.com. We _____(4)_____ your cooperation during this period.\n\nOakdale Building Management", "passageTitle": "Email: Price Increase Notification", "type": "single", "questions": [{"id": "xp6-16a", "part": 6, "question": "Blank (1):", "options": ["renovated", "restructured", "relocated", "reinstated"], "answer": 0, "explanation": "'Renovated' = \u0111\u01b0\u1ee3c c\u1ea3i t\u1ea1o/s\u1eeda ch\u1eefa. Ph\u00f9 h\u1ee3p nh\u1ea5t v\u1edbi b\u1ed1i c\u1ea3nh s\u1ea3nh t\u00f2a nh\u00e0 \u0111\u01b0\u1ee3c n\u00e2ng c\u1ea5p.", "difficulty": "medium"}, {"id": "xp6-16b", "part": 6, "question": "Blank (2):", "options": ["inconvenience", "discomfort", "disturbance", "difficulty"], "answer": 0, "explanation": "'Inconvenience this may cause' = s\u1ef1 b\u1ea5t ti\u1ec7n (c\u1ee5m xin l\u1ed7i chu\u1ea9n trong th\u00f4ng b\u00e1o t\u00f2a nh\u00e0).", "difficulty": "medium"}, {"id": "xp6-16c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Updated floor plans of the building will be posted at both entrances for your reference.", "All deliveries and move-in requests must be scheduled through the building office in advance during this period.", "The renovation includes new flooring, updated lighting, and a refreshed reception desk.", "Residents requiring special access should contact the management office by Friday."], "answer": 2, "explanation": "Sau th\u00f4ng b\u00e1o s\u1eeda s\u1ea3nh \u2192 m\u00f4 t\u1ea3 n\u1ed9i dung c\u00f4ng tr\u00ecnh l\u00e0 th\u00f4ng tin th\u1ef1c d\u1ee5ng nh\u1ea5t cho c\u01b0 d\u00e2n.", "difficulty": "medium"}, {"id": "xp6-16d", "part": 6, "question": "Blank (4):", "options": ["appreciate", "acknowledge", "welcome", "value"], "answer": 0, "explanation": "'We appreciate your cooperation' = c\u1ea3m \u01a1n s\u1ef1 h\u1ee3p t\u00e1c (c\u1ee5m k\u1ebft th\u00fac th\u00f4ng b\u00e1o chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}]}, {"passage": "From: Procurement Department\nTo: All Staff\nDate: March 4\nSubject: Updated Office Supply Ordering Procedure\n\nEffective April 1, all requests for office supplies must be submitted through the new ProcureEasy online portal. The previous email-based system will be _____(1)_____.\n\nTo place an order, log in to procureeasy.company.com using your employee ID. All requests require your department code and _____(2)_____ from your line manager before they can be processed.\n\nStandard orders are fulfilled within three business days. _____(3)_____\n\nA short instructional video is available on the company intranet. If you encounter any issues accessing the portal, please contact IT support at helpdesk@company.com or extension 4400. We trust this change will make the _____(4)_____ process more efficient for everyone.\n\nProcurement Department", "passageTitle": "Memo: Performance Bonus Criteria", "type": "single", "questions": [{"id": "xp6-17a", "part": 6, "question": "Blank (1):", "options": ["discontinued", "deactivated", "terminated", "suspended"], "answer": 0, "explanation": "'Previous system will be discontinued' = ng\u1eebng ho\u1ea1t \u0111\u1ed9ng. Collocation chu\u1ea9n khi thay th\u1ebf h\u1ec7 th\u1ed1ng c\u0169.", "difficulty": "medium"}, {"id": "xp6-17b", "part": 6, "question": "Blank (2):", "options": ["authorization", "permission", "approval", "consent"], "answer": 2, "explanation": "'Approval from your line manager' = ph\u00ea duy\u1ec7t t\u1eeb c\u1ea5p tr\u00ean tr\u1ef1c ti\u1ebfp (collocation HR/procurement chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-17c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Urgent requests flagged as high priority may be fulfilled within 24 hours, subject to stock availability.", "The Procurement Department office is located on the second floor near the main stairwell.", "All orders placed before noon will be dispatched the same day from our central warehouse.", "Employees are reminded to use approved suppliers only when sourcing items independently."], "answer": 0, "explanation": "Sau th\u00f4ng tin v\u1ec1 \u0111\u01a1n h\u00e0ng th\u00f4ng th\u01b0\u1eddng \u2192 th\u00f4ng tin v\u1ec1 \u0111\u01a1n h\u00e0ng kh\u1ea9n c\u1ea5p l\u00e0 b\u1ed5 sung logic nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-17d", "part": 6, "question": "Blank (4):", "options": ["ordering", "procurement", "requisition", "purchasing"], "answer": 0, "explanation": "'Ordering process' = quy tr\u00ecnh \u0111\u1eb7t h\u00e0ng (t\u1ef1 nhi\u00ean nh\u1ea5t trong ng\u1eef c\u1ea3nh th\u00f4ng b\u00e1o h\u1ec7 th\u1ed1ng \u0111\u1eb7t h\u00e0ng).", "difficulty": "medium"}]}, {"passage": "SPRINGDALE COMMUNITY LIBRARY\nMonthly Newsletter \u2014 June\n\nDear Library Members,\n\nWe are pleased to share some exciting news about upcoming changes at Springdale Community Library.\n\nFrom July 1, the library will _____(1)_____ its opening hours on Saturdays, remaining open until 8:00 p.m. instead of 5:00 p.m. This change is in direct response to member feedback collected earlier this year.\n\nWe will also be launching a new Digital Skills Workshop series, _____(2)_____ topics such as online safety, smartphone basics, and using government digital services. Sessions will be free and open to all community members.\n\n_____(3)_____\n\nWe look forward to continuing to serve our community. For the full schedule of upcoming events, please visit springdalelib.org or pick up a printed copy at the front desk. As always, we _____(4)_____ any feedback or suggestions you may have.\n\nThe Springdale Library Team", "passageTitle": "Email: Software License Renewal", "type": "single", "questions": [{"id": "xp6-18a", "part": 6, "question": "Blank (1):", "options": ["extend", "expand", "increase", "lengthen"], "answer": 0, "explanation": "'Extend its opening hours' = k\u00e9o d\u00e0i gi\u1edd m\u1edf c\u1eeda (collocation c\u1ed1 \u0111\u1ecbnh v\u1edbi 'hours').", "difficulty": "medium"}, {"id": "xp6-18b", "part": 6, "question": "Blank (2):", "options": ["covering", "including", "featuring", "addressing"], "answer": 0, "explanation": "'Covering topics such as...' = bao g\u1ed3m c\u00e1c ch\u1ee7 \u0111\u1ec1 nh\u01b0 (collocation chu\u1ea9n khi m\u00f4 t\u1ea3 n\u1ed9i dung ch\u01b0\u01a1ng tr\u00ecnh).", "difficulty": "medium"}, {"id": "xp6-18c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Registration for the Digital Skills Workshops opens on June 15 and can be completed online or in person at the library.", "The library's children's reading corner has been redecorated and now includes new seating and shelving.", "Members who have outstanding loans are reminded to return items before the end of the month.", "The library will be closed for the public holiday on June 10 and will reopen on June 11."], "answer": 0, "explanation": "Sau th\u00f4ng b\u00e1o ra m\u1eaft workshop series \u2192 th\u00f4ng tin \u0111\u0103ng k\u00fd l\u00e0 th\u1ef1c d\u1ee5ng v\u00e0 li\u00ean quan tr\u1ef1c ti\u1ebfp nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-18d", "part": 6, "question": "Blank (4):", "options": ["welcome", "appreciate", "value", "encourage"], "answer": 0, "explanation": "'We welcome any feedback' = ch\u00fang t\u00f4i hoan ngh\u00eanh ph\u1ea3n h\u1ed3i (collocation k\u1ebft th\u00fac newsletter chu\u1ea9n).", "difficulty": "medium"}]}, {"passage": "TO: All Travel-Eligible Staff\nFROM: Finance & Administration\nDATE: September 1\nRE: Revised International Travel Approval Process\n\nPlease be _____(1)_____ that the process for approving international business travel has been updated, effective October 1.\n\nAll international travel must now be approved at least three weeks in advance. Requests should be submitted via the Travel Portal on the company intranet, along with a completed _____(2)_____ justifying the business purpose of the trip.\n\nIn addition, all travelers must ensure they hold valid travel insurance arranged through our approved provider, Shield Global. _____(3)_____\n\nTravel booked without prior approval will not be _____(4)_____ for reimbursement under any circumstances. Please contact traveldesk@company.com if you have any questions.\n\nFinance & Administration", "passageTitle": "Notice: Elevator Maintenance", "type": "single", "questions": [{"id": "xp6-19a", "part": 6, "question": "Blank (1):", "options": ["advised", "notified", "aware", "informed"], "answer": 0, "explanation": "'Please be advised that' = k\u00ednh th\u00f4ng b\u00e1o r\u1eb1ng (c\u1ee5m m\u1edf \u0111\u1ea7u th\u00f4ng b\u00e1o ch\u00ednh th\u1ee9c c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "xp6-19b", "part": 6, "question": "Blank (2):", "options": ["rationale", "justification", "form", "statement"], "answer": 2, "explanation": "'Completed form justifying the business purpose' = m\u1eabu \u0111\u01a1n ho\u00e0n thi\u1ec7n. 'Form' l\u00e0 danh t\u1eeb th\u1ef1c t\u1ebf nh\u1ea5t \u0111\u1ec3 n\u1ed9p qua c\u1ed5ng th\u00f4ng tin.", "difficulty": "medium"}, {"id": "xp6-19c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Proof of insurance coverage must be uploaded to the Travel Portal before departure can be confirmed.", "Employees traveling to high-risk destinations will require additional approval from the CEO.", "The Finance team will review all submitted claims within five business days of return.", "Business class travel is permitted only for flights exceeding eight hours in duration."], "answer": 0, "explanation": "Sau y\u00eau c\u1ea7u v\u1ec1 b\u1ea3o hi\u1ec3m \u2192 quy \u0111\u1ecbnh n\u1ed9p b\u1eb1ng ch\u1ee9ng b\u1ea3o hi\u1ec3m l\u00e0 b\u01b0\u1edbc h\u1ee3p l\u00fd v\u00e0 th\u1ef1c t\u1ebf nh\u1ea5t ti\u1ebfp theo.", "difficulty": "medium"}, {"id": "xp6-19d", "part": 6, "question": "Blank (4):", "options": ["eligible", "qualified", "considered", "processed"], "answer": 0, "explanation": "'Not eligible for reimbursement' = kh\u00f4ng \u0111\u1ee7 \u0111i\u1ec1u ki\u1ec7n ho\u00e0n ti\u1ec1n (collocation ch\u00ednh s\u00e1ch chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}]}, {"passage": "From: Customer Service <cs@vertexprint.com>\nTo: Oliver Nash <o.nash@studio12.com>\nDate: May 20\n\nDear Mr. Nash,\n\nThank you for contacting Vertex Print regarding your recent order (#VP-3341). We are sorry to hear that the printed materials did not _____(1)_____ your expectations upon delivery.\n\nAfter reviewing your account and the images you provided, we have confirmed that the color calibration on the final prints was _____(2)_____ from the approved digital proof. This was an error on our part and we sincerely apologize.\n\nWe will _____(3)_____\n\nWe are committed to resolving this matter promptly and appreciate your patience. Should the reprinted materials not meet your satisfaction, please do not hesitate to _____(4)_____ us and we will arrange a full refund.\n\nBest regards,\nCustomer Service, Vertex Print", "passageTitle": "Letter: Donation Acknowledgement", "type": "single", "questions": [{"id": "xp6-20a", "part": 6, "question": "Blank (1):", "options": ["meet", "reach", "fulfill", "satisfy"], "answer": 0, "explanation": "'Did not meet your expectations' = kh\u00f4ng \u0111\u00e1p \u1ee9ng k\u1ef3 v\u1ecdng (collocation c\u1ed1 \u0111\u1ecbnh nh\u1ea5t trong customer service).", "difficulty": "medium"}, {"id": "xp6-20b", "part": 6, "question": "Blank (2):", "options": ["different", "deviated", "varied", "separate"], "answer": 1, "explanation": "'Color calibration deviated from the approved proof' = sai l\u1ec7ch so v\u1edbi b\u1ea3n m\u1eabu \u0111\u00e3 \u0111\u01b0\u1ee3c duy\u1ec7t (thu\u1eadt ng\u1eef in \u1ea5n chuy\u00ean nghi\u1ec7p).", "difficulty": "medium"}, {"id": "xp6-20c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["therefore reprint your entire order at no additional cost and dispatch it within three business days.", "issue a store credit to your account equivalent to 50% of your original order value.", "contact our printing team to review your file specifications and suggest adjustments.", "arrange for a technical representative to visit your studio to assess the issue in person."], "answer": 0, "explanation": "Sau khi x\u00e1c nh\u1eadn l\u1ed7i in \u1ea5n \u2192 in l\u1ea1i to\u00e0n b\u1ed9 mi\u1ec5n ph\u00ed l\u00e0 gi\u1ea3i ph\u00e1p ph\u00f9 h\u1ee3p v\u00e0 \u0111\u1ee7 m\u1ea1nh \u0111\u1ec3 x\u1eed l\u00fd khi\u1ebfu n\u1ea1i.", "difficulty": "medium"}, {"id": "xp6-20d", "part": 6, "question": "Blank (4):", "options": ["contact", "reach out to", "write to", "call"], "answer": 0, "explanation": "'Do not hesitate to contact us' = c\u1ee5m k\u1ebft th\u00fac email d\u1ecbch v\u1ee5 kh\u00e1ch h\u00e0ng chu\u1ea9n v\u00e0 trang tr\u1ecdng nh\u1ea5t.", "difficulty": "medium"}]}, {"passage": "HARLOW & ASSOCIATES\nLegal Bulletin \u2014 Client Advisory\n\nRe: Changes to Data Retention Requirements Under the New Privacy Act\n\nDear Clients,\n\nWe are writing to draw your attention to significant _____(1)_____ to data retention obligations that will take effect on January 1 under the revised Privacy Act.\n\nOrganisations that collect personal data will now be _____(2)_____ to delete or anonymise records within 24 months of their last use, unless a longer period is required by law or regulatory obligation.\n\n_____(3)_____\n\nWe strongly recommend that all clients review their current data retention schedules and update their privacy policies accordingly. Failure to comply may result in _____(4)_____ penalties, including fines of up to AUD 2 million per breach.\n\nPlease contact your designated Harlow & Associates adviser if you require further guidance.\n\nHarlow & Associates", "passageTitle": "Memo: Fleet Vehicle Policy", "type": "single", "questions": [{"id": "xp6-21a", "part": 6, "question": "Blank (1):", "options": ["changes", "amendments", "updates", "modifications"], "answer": 1, "explanation": "'Amendments to data retention obligations' = s\u1eeda \u0111\u1ed5i c\u00e1c ngh\u0129a v\u1ee5 (thu\u1eadt ng\u1eef ph\u00e1p l\u00fd ch\u00ednh th\u1ee9c nh\u1ea5t cho thay \u0111\u1ed5i lu\u1eadt).", "difficulty": "medium"}, {"id": "xp6-21b", "part": 6, "question": "Blank (2):", "options": ["required", "obligated", "mandated", "expected"], "answer": 0, "explanation": "'Required to delete or anonymise' = b\u1eaft bu\u1ed9c ph\u1ea3i (collocation chu\u1ea9n nh\u1ea5t trong v\u0103n b\u1ea3n ph\u00e1p l\u00fd).", "difficulty": "medium"}, {"id": "xp6-21c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Organisations operating in the healthcare and financial sectors are subject to additional sector-specific retention requirements.", "The revised Act also introduces new rights for individuals to access and correct their personal data.", "A grace period of six months will apply for businesses with fewer than 50 employees.", "All privacy policies must be published on a company's website and updated annually."], "answer": 0, "explanation": "Sau quy \u0111\u1ecbnh chung v\u1ec1 24 th\u00e1ng \u2192 th\u00f4ng tin b\u1ed5 sung v\u1ec1 c\u00e1c ng\u00e0nh \u0111\u1eb7c th\u00f9 (healthcare, finance) l\u00e0 m\u1edf r\u1ed9ng logic v\u00e0 quan tr\u1ecdng nh\u1ea5t cho kh\u00e1ch h\u00e0ng doanh nghi\u1ec7p.", "difficulty": "medium"}, {"id": "xp6-21d", "part": 6, "question": "Blank (4):", "options": ["significant", "serious", "substantial", "severe"], "answer": 3, "explanation": "'Severe penalties' = h\u00ecnh ph\u1ea1t nghi\u00eam kh\u1eafc (collocation chu\u1ea9n nh\u1ea5t trong c\u1ea3nh b\u00e1o ph\u00e1p l\u00fd).", "difficulty": "medium"}]}, {"passage": "INTERNAL COMMUNICATION\nTo: Customer Success Team\nFrom: Head of Customer Experience, Priya Desai\nDate: August 3\n\nI am pleased to share that our latest customer satisfaction survey results have come in, and the _____(1)_____ are very encouraging.\n\nOverall satisfaction has reached 87%, our highest score to date. Particularly noteworthy is the improvement in response time ratings, which rose from 71% to 84% following the implementation of our live chat system in May. This reflects the hard work the entire team has _____(2)_____ over the past quarter.\n\n_____(3)_____\n\nLooking ahead, our focus for Q4 will be on _____(4)_____ satisfaction scores in the product knowledge category, which remains our lowest-rated area at 76%. I will be sharing a detailed action plan with team leaders next week.\n\nThank you all for your continued commitment.\nPriya Desai", "passageTitle": "Email: Seminar Speaker Confirmation", "type": "single", "questions": [{"id": "xp6-22a", "part": 6, "question": "Blank (1):", "options": ["results", "findings", "outcomes", "data"], "answer": 0, "explanation": "'Survey results' = k\u1ebft qu\u1ea3 kh\u1ea3o s\u00e1t (collocation c\u1ed1 \u0111\u1ecbnh nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-22b", "part": 6, "question": "Blank (2):", "options": ["put in", "invested", "dedicated", "contributed"], "answer": 0, "explanation": "'Hard work the team has put in' = c\u00f4ng s\u1ee9c \u0111\u00e3 b\u1ecf ra (collocation t\u1ef1 nhi\u00ean nh\u1ea5t trong l\u1eddi khen nh\u00e2n vi\u00ean).", "difficulty": "medium"}, {"id": "xp6-22c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["I would like to personally thank each of you for the professionalism and dedication you bring to every customer interaction.", "The live chat platform will be upgraded to Version 3.0 next month to include AI-assisted responses.", "Customers who rated us 9 or 10 out of 10 will receive a follow-up loyalty offer.", "The full survey report, broken down by team and product category, is available on the shared drive."], "answer": 0, "explanation": "Sau th\u00f4ng b\u00e1o k\u1ebft qu\u1ea3 t\u00edch c\u1ef1c \u2192 l\u1eddi c\u1ea3m \u01a1n c\u00e1 nh\u00e2n t\u1eeb tr\u01b0\u1edfng nh\u00f3m l\u00e0 k\u1ebft n\u1ed1i c\u1ea3m x\u00fac t\u1ef1 nhi\u00ean v\u00e0 ph\u00f9 h\u1ee3p nh\u1ea5t trong internal memo.", "difficulty": "medium"}, {"id": "xp6-22d", "part": 6, "question": "Blank (4):", "options": ["improving", "raising", "boosting", "increasing"], "answer": 1, "explanation": "'Raising satisfaction scores' = n\u00e2ng cao \u0111i\u1ec3m h\u00e0i l\u00f2ng ('raise scores' l\u00e0 collocation chu\u1ea9n trong business context).", "difficulty": "medium"}]}, {"passage": "STELLARTECH SOLUTIONS\nProduct Update Notice \u2014 CloudVault Version 5.0\n\nDear CloudVault Subscriber,\n\nWe are excited to announce that CloudVault Version 5.0 will be _____(1)_____ to all accounts on November 12.\n\nThis update includes significant improvements to file synchronization speed, an _____(2)_____ storage limit of 2 TB for Professional accounts, and a redesigned dashboard for easier navigation.\n\nNo action is required from your end \u2014 the update will be applied _____(3)_____\n\nHowever, we recommend backing up any locally stored files before the update window, as some configurations may be reset during the transition. _____(4)_____ customers who wish to remain on Version 4.5 temporarily may submit a deferral request via their account settings no later than November 5.\n\nThank you for choosing CloudVault.\nStellarTech Solutions", "passageTitle": "Notice: Scholarship Application", "type": "single", "questions": [{"id": "xp6-23a", "part": 6, "question": "Blank (1):", "options": ["deployed", "released", "rolled out", "delivered"], "answer": 2, "explanation": "'Rolled out to all accounts' = tri\u1ec3n khai \u0111\u1ebfn t\u1ea5t c\u1ea3 t\u00e0i kho\u1ea3n (collocation IT/SaaS chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-23b", "part": 6, "question": "Blank (2):", "options": ["expanded", "increased", "upgraded", "enhanced"], "answer": 0, "explanation": "'Expanded storage limit' = dung l\u01b0\u1ee3ng l\u01b0u tr\u1eef \u0111\u01b0\u1ee3c m\u1edf r\u1ed9ng (collocation k\u1ef9 thu\u1eadt chu\u1ea9n cho storage).", "difficulty": "medium"}, {"id": "xp6-23c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["automatically during a scheduled maintenance window between 2:00 a.m. and 4:00 a.m. on November 12.", "only after you have reviewed and accepted the updated Terms of Service.", "by our technical team in coordination with your IT administrator.", "after a mandatory system compatibility check is completed on your device."], "answer": 0, "explanation": "Sau 'No action required' \u2192 c\u1eadp nh\u1eadt t\u1ef1 \u0111\u1ed9ng trong c\u1eeda s\u1ed5 b\u1ea3o tr\u00ec l\u00e0 k\u1ebft n\u1ed1i logic nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-23d", "part": 6, "question": "Blank (4):", "options": ["Additionally", "Furthermore", "That said", "In the meantime"], "answer": 2, "explanation": "'That said' = tuy nhi\u00ean/d\u00f9 v\u1eady. C\u00e2u tr\u01b0\u1edbc n\u00f3i kh\u00f4ng c\u1ea7n l\u00e0m g\u00ec; c\u00e2u n\u00e0y b\u1ed5 sung ngo\u1ea1i l\u1ec7 \u2192 t\u01b0\u01a1ng ph\u1ea3n nh\u1eb9.", "difficulty": "medium"}]}, {"passage": "MERIDIAN HOTELS & RESORTS\nGuest Communication\n\nDear Ms. Patterson,\n\nThank you for choosing Meridian Hotels for your upcoming stay from July 18 to July 22 at our Riverside property.\n\nWe are writing to let you know that our rooftop pool and bar, which you may have noted on our website, will be _____(1)_____ for scheduled refurbishment during your visit. We sincerely apologize for this _____(2)_____.\n\nAs a gesture of goodwill, we have _____(3)_____\n\nPlease note that all other hotel facilities, including the ground-floor pool, fitness centre, and full-service restaurant, will remain fully operational throughout your stay.\n\nWe look forward to welcoming you and are confident you will still enjoy a wonderful experience at Meridian Riverside. Should you wish to discuss your booking, please do not _____(4)_____ to contact our reservations team at reservations@meridianhotels.com.\n\nWarm regards,\nGuest Relations, Meridian Riverside", "passageTitle": "Email: Tax Document Request", "type": "single", "questions": [{"id": "xp6-24a", "part": 6, "question": "Blank (1):", "options": ["closed", "unavailable", "out of service", "suspended"], "answer": 1, "explanation": "'Will be unavailable for refurbishment' = s\u1ebd kh\u00f4ng kh\u1ea3 d\u1ee5ng trong th\u1eddi gian tu b\u1ed5. T\u1ef1 nhi\u00ean nh\u1ea5t trong email kh\u00e1ch s\u1ea1n.", "difficulty": "medium"}, {"id": "xp6-24b", "part": 6, "question": "Blank (2):", "options": ["inconvenience", "disruption", "disappointment", "situation"], "answer": 0, "explanation": "'We apologize for this inconvenience' = c\u1ee5m xin l\u1ed7i chu\u1ea9n trong d\u1ecbch v\u1ee5 kh\u00e1ch s\u1ea1n.", "difficulty": "medium"}, {"id": "xp6-24c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["upgraded your room to a Superior River View Suite at no additional charge.", "arranged complimentary access to our partner spa facility two minutes from the hotel.", "applied a 20% discount to your final bill upon checkout.", "added a complimentary breakfast voucher for each morning of your stay."], "answer": 0, "explanation": "Sau l\u1eddi xin l\u1ed7i v\u1ec1 ti\u1ec7n \u00edch kh\u00f4ng kh\u1ea3 d\u1ee5ng \u2192 n\u00e2ng c\u1ea5p ph\u00f2ng mi\u1ec5n ph\u00ed l\u00e0 b\u1ed3i th\u01b0\u1eddng tr\u1ef1c ti\u1ebfp v\u00e0 ph\u00f9 h\u1ee3p nh\u1ea5t v\u1edbi v\u0103n phong kh\u00e1ch s\u1ea1n cao c\u1ea5p.", "difficulty": "medium"}, {"id": "xp6-24d", "part": 6, "question": "Blank (4):", "options": ["hesitate", "delay", "fail", "wait"], "answer": 0, "explanation": "'Do not hesitate to contact' = c\u1ee5m k\u1ebft th\u00fac th\u01b0 kh\u00e1ch s\u1ea1n chu\u1ea9n nh\u1ea5t.", "difficulty": "medium"}]}, {"passage": "JOB ADVERTISEMENT\n\nPosition: Communications Coordinator\nOrganisation: Pacific Community Foundation\nLocation: Auckland, NZ | Full-Time\n\nThe Pacific Community Foundation is a not-for-profit organisation _____(1)_____ to improving outcomes for Pacific communities across New Zealand.\n\nWe are seeking a motivated Communications Coordinator to join our team. The successful applicant will manage our social media channels, produce our _____(2)_____ newsletter, assist with media relations, and support the development of communications strategies aligned with our mission.\n\n_____(3)_____\n\nApplications close Friday, March 14. To apply, submit a cover letter and CV _____(4)_____ your experience in community or not-for-profit communications to careers@pacificfoundation.org.nz.\n\nPacific Community Foundation", "passageTitle": "Memo: Social Media Guidelines", "type": "single", "questions": [{"id": "xp6-25a", "part": 6, "question": "Blank (1):", "options": ["dedicated", "committed", "devoted", "focused"], "answer": 1, "explanation": "'Organisation committed to improving outcomes' = cam k\u1ebft c\u1ea3i thi\u1ec7n (collocation chu\u1ea9n nh\u1ea5t cho t\u1ed5 ch\u1ee9c phi l\u1ee3i nhu\u1eadn).", "difficulty": "medium"}, {"id": "xp6-25b", "part": 6, "question": "Blank (2):", "options": ["quarterly", "monthly", "annual", "weekly"], "answer": 0, "explanation": "'Quarterly newsletter' = b\u1ea3n tin h\u00e0ng qu\u00fd (ph\u1ed5 bi\u1ebfn nh\u1ea5t v\u00e0 ph\u00f9 h\u1ee3p quy m\u00f4 t\u1ed5 ch\u1ee9c phi l\u1ee3i nhu\u1eadn).", "difficulty": "medium"}, {"id": "xp6-25c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["The ideal candidate will have at least two years of communications experience and a genuine connection to Pacific communities.", "Salary is negotiable depending on experience and will be discussed at interview stage.", "The Foundation offers flexible working arrangements, including options for remote work.", "References from two previous employers will be required before an offer is made."], "answer": 0, "explanation": "Sau m\u00f4 t\u1ea3 nhi\u1ec7m v\u1ee5 \u2192 n\u00eau ti\u00eau ch\u00ed \u1ee9ng vi\u00ean l\u00fd t\u01b0\u1edfng l\u00e0 ph\u1ea7n t\u1ea5t y\u1ebfu c\u1ee7a job ad v\u00e0 li\u00ean quan tr\u1ef1c ti\u1ebfp nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-25d", "part": 6, "question": "Blank (4):", "options": ["highlighting", "detailing", "describing", "demonstrating"], "answer": 0, "explanation": "'Submit a CV highlighting your experience' = n\u1ed9p CV l\u00e0m n\u1ed5i b\u1eadt kinh nghi\u1ec7m ('highlight experience' l\u00e0 collocation chu\u1ea9n trong h\u01b0\u1edbng d\u1eabn n\u1ed9p \u0111\u01a1n).", "difficulty": "medium"}]}, {"passage": "MEMO\nTo: All Staff\nFrom: Health & Safety Officer, Lin Torres\nDate: October 12\nRe: Annual Fire Drill \u2014 Thursday, October 16\n\nPlease be aware that a mandatory fire drill will be _____(1)_____ on Thursday, October 16, at approximately 10:30 a.m.\n\nWhen the alarm sounds, all employees must immediately stop what they are doing and _____(2)_____ the building using the nearest fire exit. Do not use the elevators. Floor wardens will be stationed at each exit to assist and ensure everyone has evacuated safely.\n\n_____(3)_____\n\nAll staff are expected to participate. Anyone who anticipates being away from the office that day should _____(4)_____ their floor warden in advance.\n\nThank you for your cooperation.\nLin Torres, Health & Safety Officer", "passageTitle": "Notice: Fire Drill Announcement", "type": "single", "questions": [{"id": "xp6-26a", "part": 6, "question": "Blank (1):", "options": ["conducted", "held", "carried out", "performed"], "answer": 0, "explanation": "'Fire drill will be conducted' = cu\u1ed9c di\u1ec5n t\u1eadp s\u1ebd \u0111\u01b0\u1ee3c ti\u1ebfn h\u00e0nh ('conduct a drill' l\u00e0 collocation chu\u1ea9n nh\u1ea5t trong v\u0103n b\u1ea3n an to\u00e0n).", "difficulty": "medium"}, {"id": "xp6-26b", "part": 6, "question": "Blank (2):", "options": ["evacuate", "exit", "leave", "vacate"], "answer": 0, "explanation": "'Evacuate the building' = s\u01a1 t\u00e1n t\u00f2a nh\u00e0 (collocation an to\u00e0n chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-26c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["The assembly point is the parking area on the east side of the building, clearly marked with green signage.", "Employees are reminded that personal belongings should not be taken during an emergency evacuation.", "The fire drill is expected to last no longer than 15 minutes from alarm activation to all-clear.", "Floor wardens completed their annual training last week and are fully briefed on evacuation procedures."], "answer": 0, "explanation": "Sau h\u01b0\u1edbng d\u1eabn s\u01a1 t\u00e1n \u2192 th\u00f4ng b\u00e1o \u0111i\u1ec3m t\u1eadp h\u1ee3p l\u00e0 th\u00f4ng tin thi\u1ebft y\u1ebfu nh\u1ea5t m\u00e0 nh\u00e2n vi\u00ean c\u1ea7n bi\u1ebft ti\u1ebfp theo.", "difficulty": "medium"}, {"id": "xp6-26d", "part": 6, "question": "Blank (4):", "options": ["notify", "inform", "tell", "advise"], "answer": 0, "explanation": "'Notify their floor warden' = th\u00f4ng b\u00e1o cho tr\u01b0\u1edfng t\u1ea7ng (trang tr\u1ecdng v\u00e0 chu\u1ea9n nh\u1ea5t trong v\u0103n b\u1ea3n an to\u00e0n n\u1ed9i b\u1ed9).", "difficulty": "medium"}]}, {"passage": "BRIGHTSTONE PUBLISHING\nAuthor Newsletter \u2014 Spring Edition\n\nDear Authors,\n\nWelcome to the spring edition of the Brightstone Publishing newsletter. We have several exciting updates to share with you.\n\nFirst, we are pleased to announce that our submissions portal has been _____(1)_____, with a new interface that makes it easier to track the status of your manuscripts in real time.\n\nSecond, our editorial team is now accepting _____(2)_____ for our upcoming anthology, Voices of Tomorrow. We are looking for short fiction and personal essays of up to 5,000 words that explore themes of resilience and change.\n\n_____(3)_____\n\nThank you for being part of the Brightstone community. We remain _____(4)_____ to supporting your creative journey.\n\nThe Brightstone Editorial Team", "passageTitle": "Email: Relocation Assistance Policy", "type": "single", "questions": [{"id": "xp6-27a", "part": 6, "question": "Blank (1):", "options": ["upgraded", "updated", "improved", "redesigned"], "answer": 0, "explanation": "'Submissions portal has been upgraded' = \u0111\u01b0\u1ee3c n\u00e2ng c\u1ea5p (collocation chu\u1ea9n nh\u1ea5t cho c\u1ea3i ti\u1ebfn h\u1ec7 th\u1ed1ng k\u1ef9 thu\u1eadt).", "difficulty": "medium"}, {"id": "xp6-27b", "part": 6, "question": "Blank (2):", "options": ["submissions", "contributions", "entries", "applications"], "answer": 0, "explanation": "'Accepting submissions for an anthology' = nh\u1eadn b\u00e0i g\u1eedi \u0111\u0103ng (collocation xu\u1ea5t b\u1ea3n chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-27c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["The submission deadline for Voices of Tomorrow is June 30, and detailed guidelines are available on our website.", "All manuscripts submitted to Brightstone remain the intellectual property of the author.", "Authors whose work has been selected for publication will be notified by email within eight weeks.", "We are also pleased to welcome three new editors to our team this quarter."], "answer": 0, "explanation": "Sau th\u00f4ng b\u00e1o v\u1ec1 anthology \u2192 h\u1ea1n n\u1ed9p b\u00e0i v\u00e0 h\u01b0\u1edbng d\u1eabn chi ti\u1ebft l\u00e0 th\u00f4ng tin th\u1ef1c d\u1ee5ng nh\u1ea5t t\u00e1c gi\u1ea3 c\u1ea7n.", "difficulty": "medium"}, {"id": "xp6-27d", "part": 6, "question": "Blank (4):", "options": ["committed", "dedicated", "devoted", "determined"], "answer": 0, "explanation": "'Remain committed to supporting your journey' = cam k\u1ebft h\u1ed7 tr\u1ee3 (collocation chu\u1ea9n nh\u1ea5t trong th\u01b0 ng\u1ecf c\u1ee7a nh\u00e0 xu\u1ea5t b\u1ea3n).", "difficulty": "medium"}]}, {"passage": "From: Facilities Management\nTo: All Staff \u2014 Tower One, Floors 15\u201322\nDate: April 3\nSubject: Temporary Hot Water Outage\n\nThis is to advise all staff on Floors 15 to 22 of Tower One that hot water services to kitchen and bathroom facilities on these floors will be _____(1)_____ on Saturday, April 8, from 8:00 a.m. to 2:00 p.m., to allow for urgent pipe repairs.\n\nCold water will remain available throughout. _____(2)_____ this is inconvenient for staff scheduled to work on Saturday, alternative kitchen facilities will be available in the Tower Two lobby caf\u00e9, which is open from 7:30 a.m.\n\n_____(3)_____\n\nWe appreciate your understanding and apologize for any _____(4)_____.\n\nFacilities Management", "passageTitle": "Memo: New Vendor Approval", "type": "single", "questions": [{"id": "xp6-28a", "part": 6, "question": "Blank (1):", "options": ["suspended", "interrupted", "cut off", "unavailable"], "answer": 0, "explanation": "'Hot water services will be suspended' = d\u1ecbch v\u1ee5 n\u01b0\u1edbc n\u00f3ng s\u1ebd b\u1ecb \u0111\u00ecnh ch\u1ec9 t\u1ea1m th\u1eddi (collocation d\u1ecbch v\u1ee5 ti\u1ec7n \u00edch chu\u1ea9n).", "difficulty": "medium"}, {"id": "xp6-28b", "part": 6, "question": "Blank (2):", "options": ["While", "Since", "Although", "Given that"], "answer": 2, "explanation": "'Although this is inconvenient' = m\u1eb7c d\u00f9 b\u1ea5t ti\u1ec7n (li\u00ean t\u1eeb nh\u01b0\u1ee3ng b\u1ed9 ph\u00f9 h\u1ee3p nh\u1ea5t tr\u01b0\u1edbc khi n\u00eau gi\u1ea3i ph\u00e1p thay th\u1ebf).", "difficulty": "medium"}, {"id": "xp6-28c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["The repairs are expected to be completed by 2:00 p.m., after which full service will be restored immediately.", "Staff are advised to bring their own beverages on Saturday to avoid any inconvenience.", "Maintenance crews will have access to all floors during the repair window.", "Emergency plumbing services will remain on standby throughout the day."], "answer": 0, "explanation": "Sau th\u00f4ng b\u00e1o gi\u00e1n \u0111o\u1ea1n \u2192 x\u00e1c nh\u1eadn th\u1eddi \u0111i\u1ec3m ph\u1ee5c h\u1ed3i d\u1ecbch v\u1ee5 l\u00e0 th\u00f4ng tin quan tr\u1ecdng v\u00e0 thi\u1ebft th\u1ef1c nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-28d", "part": 6, "question": "Blank (4):", "options": ["inconvenience", "disruption", "disturbance", "delay"], "answer": 0, "explanation": "'Apologize for any inconvenience' = c\u1ee5m xin l\u1ed7i chu\u1ea9n nh\u1ea5t trong th\u00f4ng b\u00e1o gi\u00e1n \u0111o\u1ea1n d\u1ecbch v\u1ee5.", "difficulty": "medium"}]}, {"passage": "SILVERLINE INVESTMENT PARTNERS\nQuarterly Client Letter \u2014 Q3\n\nDear Valued Clients,\n\nWe are pleased to present our Q3 portfolio review, which reflects _____(1)_____ performance across most of our core asset classes despite ongoing global market volatility.\n\nEquity holdings delivered an average return of 4.2% for the quarter, _____(2)_____ by strong earnings from the technology and healthcare sectors. Fixed income positions remained stable, providing a reliable buffer against market fluctuations.\n\n_____(3)_____\n\nLooking into Q4, we continue to monitor central bank policy decisions and geopolitical developments closely. We remain _____(4)_____ in our long-term investment approach, focusing on quality assets and disciplined risk management.\n\nWe look forward to speaking with you at your upcoming annual review meeting.\n\nSilverline Investment Partners", "passageTitle": "Email: Complaint Acknowledgement", "type": "single", "questions": [{"id": "xp6-29a", "part": 6, "question": "Blank (1):", "options": ["resilient", "strong", "solid", "positive"], "answer": 0, "explanation": "'Resilient performance despite volatility' = hi\u1ec7u su\u1ea5t ki\u00ean c\u01b0\u1eddng ('resilient' l\u00e0 t\u1eeb chu\u1ea9n nh\u1ea5t \u0111\u1ec3 m\u00f4 t\u1ea3 th\u00e0nh t\u00edch trong b\u1ed1i c\u1ea3nh th\u1ecb tr\u01b0\u1eddng bi\u1ebfn \u0111\u1ed9ng).", "difficulty": "medium"}, {"id": "xp6-29b", "part": 6, "question": "Blank (2):", "options": ["driven", "boosted", "supported", "fueled"], "answer": 0, "explanation": "'Driven by strong earnings' = \u0111\u01b0\u1ee3c th\u00fac \u0111\u1ea9y b\u1edfi l\u1ee3i nhu\u1eadn m\u1ea1nh (collocation t\u00e0i ch\u00ednh chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-29c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Real estate investment trusts (REITs) within the portfolio also contributed positively, rising 3.1% on the back of increased demand in commercial property markets.", "We recommend that clients consider increasing their allocation to emerging market equities in Q4.", "The portfolio rebalancing carried out in August has positioned us well for the anticipated interest rate adjustments.", "Clients are reminded that past performance is not indicative of future results."], "answer": 0, "explanation": "Sau nh\u1eafc \u0111\u1ebfn equity v\u00e0 fixed income \u2192 b\u1ed5 sung REITs l\u00e0 m\u1edf r\u1ed9ng t\u1ef1 nhi\u00ean khi \u0111i\u1ec3m qua c\u00e1c lo\u1ea1i t\u00e0i s\u1ea3n trong portfolio review.", "difficulty": "medium"}, {"id": "xp6-29d", "part": 6, "question": "Blank (4):", "options": ["disciplined", "steadfast", "consistent", "committed"], "answer": 1, "explanation": "'Remain steadfast in our long-term approach' = ki\u00ean \u0111\u1ecbnh v\u1edbi chi\u1ebfn l\u01b0\u1ee3c d\u00e0i h\u1ea1n (collocation investment advisory trang tr\u1ecdng nh\u1ea5t).", "difficulty": "medium"}]}, {"passage": "SUMMIT EDUCATION GROUP\nStudent Services Bulletin\n\nDear Students,\n\nWe are writing to inform you of important changes to the student support services available at Summit Education Group, effective the start of Semester 2.\n\nCounselling services will now be available both in-person and online, _____(1)_____ students greater flexibility in accessing support. Appointments can be booked via the Student Portal.\n\nIn addition, a new Academic Skills Centre will _____(2)_____ in Room 214 of the Learning Hub, offering drop-in support for essay writing, research skills, and exam preparation.\n\n_____(3)_____\n\nAll new and continuing students are encouraged to familiarise themselves with these services early in the semester. _____(4)_____ you require any further information, please contact studentservices@summitedu.com.\n\nStudent Services Team", "passageTitle": "Notice: Fundraising Event Details", "type": "single", "questions": [{"id": "xp6-30a", "part": 6, "question": "Blank (1):", "options": ["giving", "providing", "offering", "allowing"], "answer": 0, "explanation": "'Giving students greater flexibility' = mang l\u1ea1i cho sinh vi\u00ean s\u1ef1 linh ho\u1ea1t h\u01a1n (collocation t\u1ef1 nhi\u00ean nh\u1ea5t trong b\u1ed1i c\u1ea3nh th\u00f4ng b\u00e1o d\u1ecbch v\u1ee5).", "difficulty": "medium"}, {"id": "xp6-30b", "part": 6, "question": "Blank (2):", "options": ["open", "launch", "operate", "be based"], "answer": 2, "explanation": "'Academic Skills Centre will operate in Room 214' = s\u1ebd ho\u1ea1t \u0111\u1ed9ng t\u1ea1i ph\u00f2ng 214 (collocation chu\u1ea9n nh\u1ea5t khi m\u00f4 t\u1ea3 trung t\u00e2m m\u1edbi b\u1eaft \u0111\u1ea7u ho\u1ea1t \u0111\u1ed9ng).", "difficulty": "medium"}, {"id": "xp6-30c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["The Academic Skills Centre will be open Monday to Thursday from 9:00 a.m. to 5:00 p.m. and Friday from 9:00 a.m. to 1:00 p.m.", "All staff working in the Student Services department have completed updated training this semester.", "Students are reminded that semester results will be released within four weeks of the final examination period.", "The Student Portal has been updated with a new layout to improve accessibility."], "answer": 0, "explanation": "Sau th\u00f4ng b\u00e1o ra m\u1eaft trung t\u00e2m \u2192 gi\u1edd m\u1edf c\u1eeda c\u1ee5 th\u1ec3 l\u00e0 th\u00f4ng tin quan tr\u1ecdng nh\u1ea5t sinh vi\u00ean c\u1ea7n bi\u1ebft.", "difficulty": "medium"}, {"id": "xp6-30d", "part": 6, "question": "Blank (4):", "options": ["Should", "If", "When", "In case"], "answer": 0, "explanation": "'Should you require further information' = \u0111\u1ea3o ng\u1eef c\u00e2u \u0111i\u1ec1u ki\u1ec7n l\u1ecbch s\u1ef1 (chu\u1ea9n nh\u1ea5t trong v\u0103n b\u1ea3n th\u00f4ng b\u00e1o gi\u00e1o d\u1ee5c).", "difficulty": "medium"}]}, {"passage": "TASTY BITES FOOD DELIVERY\nService Announcement\n\nDear Tasty Bites Member,\n\nWe are writing to let you know about an _____(1)_____ change to our delivery fee structure, effective June 15.\n\nCurrently, all orders over AUD 30 qualify for free delivery. From June 15, free delivery will _____(2)_____ to orders over AUD 40. This adjustment reflects increased fuel and logistics costs that have affected our delivery partners across the region.\n\n_____(3)_____\n\nAs a valued member, you can avoid the delivery fee entirely by _____(4)_____ up for our Tasty Bites Plus membership, which offers unlimited free delivery for a flat monthly fee of AUD 9.99.\n\nThank you for your continued support.\nThe Tasty Bites Team", "passageTitle": "Email: Quality Control Update", "type": "single", "questions": [{"id": "xp6-31a", "part": 6, "question": "Blank (1):", "options": ["upcoming", "important", "recent", "scheduled"], "answer": 0, "explanation": "'An upcoming change' = thay \u0111\u1ed5i s\u1eafp di\u1ec5n ra (collocation chu\u1ea9n nh\u1ea5t trong th\u00f4ng b\u00e1o thay \u0111\u1ed5i d\u1ecbch v\u1ee5).", "difficulty": "medium"}, {"id": "xp6-31b", "part": 6, "question": "Blank (2):", "options": ["apply", "be limited", "be restricted", "be available"], "answer": 0, "explanation": "'Free delivery will apply to orders over AUD 40' = s\u1ebd \u00e1p d\u1ee5ng cho \u0111\u01a1n h\u00e0ng tr\u00ean 40 AUD (collocation chu\u1ea9n nh\u1ea5t v\u1edbi ch\u00ednh s\u00e1ch).", "difficulty": "medium"}, {"id": "xp6-31c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["For orders under AUD 40, a flat delivery fee of AUD 4.99 will apply regardless of distance.", "We are continually working with our delivery partners to find ways to keep costs as low as possible for our customers.", "Members who place five or more orders per month will automatically qualify for a loyalty discount.", "Our delivery zones have been expanded to include three new suburbs effective June 15."], "answer": 0, "explanation": "Sau th\u00f4ng b\u00e1o t\u0103ng ng\u01b0\u1ee1ng mi\u1ec5n ph\u00ed ship \u2192 th\u00f4ng tin v\u1ec1 m\u1ee9c ph\u00ed giao h\u00e0ng khi kh\u00f4ng \u0111\u1ea1t ng\u01b0\u1ee1ng l\u00e0 thi\u1ebft y\u1ebfu v\u00e0 tr\u1ef1c ti\u1ebfp nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-31d", "part": 6, "question": "Blank (4):", "options": ["signing", "registering", "subscribing", "enrolling"], "answer": 0, "explanation": "'Signing up for membership' = \u0111\u0103ng k\u00fd th\u00e0nh vi\u00ean (collocation c\u1ed1 \u0111\u1ecbnh nh\u1ea5t trong b\u1ed1i c\u1ea3nh d\u1ecbch v\u1ee5 ti\u00eau d\u00f9ng).", "difficulty": "medium"}]}, {"passage": "From: Helena Ross, Director of Operations\nTo: All Department Managers\nDate: January 9\nSubject: Q1 Strategic Priorities\n\nAs we begin the new year, I want to _____(1)_____ the key strategic priorities for Q1 that were discussed at last month's leadership retreat.\n\nOur primary focus will be on three areas: improving operational efficiency across all divisions, _____(2)_____ the rollout of the new enterprise resource planning (ERP) system, and strengthening client retention strategies in our top five accounts.\n\n_____(3)_____\n\nEach department head is asked to submit a brief Q1 action plan outlining how their team will _____(4)_____ to these priorities by January 20. Templates are available on the Operations shared drive.\n\nI look forward to a productive and successful quarter.\n\nHelena Ross\nDirector of Operations", "passageTitle": "Memo: Telecommuting Guidelines", "type": "single", "questions": [{"id": "xp6-32a", "part": 6, "question": "Blank (1):", "options": ["outline", "summarize", "confirm", "reiterate"], "answer": 3, "explanation": "'Reiterate the key priorities' = nh\u1eafc l\u1ea1i c\u00e1c \u01b0u ti\u00ean \u0111\u00e3 th\u1ea3o lu\u1eadn tr\u01b0\u1edbc \u0111\u00f3 (chu\u1ea9n nh\u1ea5t v\u00ec ph\u1ea3n \u00e1nh vi\u1ec7c nh\u1eafc l\u1ea1i nh\u1eefng g\u00ec \u0111\u00e3 b\u00e0n t\u1ea1i retreat).", "difficulty": "medium"}, {"id": "xp6-32b", "part": 6, "question": "Blank (2):", "options": ["accelerating", "completing", "finalizing", "overseeing"], "answer": 0, "explanation": "'Accelerating the rollout of ERP' = \u0111\u1ea9y nhanh tri\u1ec3n khai (collocation project management chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-32c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["Progress against these priorities will be reviewed at our monthly all-hands meeting, with detailed updates expected from each department.", "All managers are reminded that performance appraisals for Q4 are due by January 31.", "The ERP implementation team will hold a briefing session for all staff on January 15.", "Helena will be visiting the regional offices during the second week of February."], "answer": 0, "explanation": "Sau n\u00eau 3 \u01b0u ti\u00ean chi\u1ebfn l\u01b0\u1ee3c \u2192 th\u00f4ng b\u00e1o v\u1ec1 c\u01a1 ch\u1ebf theo d\u00f5i ti\u1ebfn \u0111\u1ed9 l\u00e0 b\u1ed5 sung logic v\u00e0 thi\u1ebft y\u1ebfu nh\u1ea5t trong memo chi\u1ebfn l\u01b0\u1ee3c.", "difficulty": "medium"}, {"id": "xp6-32d", "part": 6, "question": "Blank (4):", "options": ["contribute", "respond", "align", "commit"], "answer": 2, "explanation": "'How their team will align to these priorities' = \u0111\u1ed9i nh\u00f3m s\u1ebd ph\u1ed1i h\u1ee3p v\u1edbi c\u00e1c \u01b0u ti\u00ean nh\u01b0 th\u1ebf n\u00e0o (collocation chi\u1ebfn l\u01b0\u1ee3c chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}]}, {"passage": "ALPINE WELLNESS RETREAT\nGuest Information Pack\n\nWelcome to Alpine Wellness Retreat. We are delighted to have you with us and hope your stay will be _____(1)_____ and restorative.\n\nOur wellness programmes run from 7:00 a.m. to 8:00 p.m. daily. You are welcome to participate in as many or as few sessions as you like. A full timetable has been placed in your villa and is also available at _____(2)_____ services.\n\nMeals are served in the Meadow Dining Room: breakfast from 7:00 to 9:30 a.m., lunch from 12:30 to 2:00 p.m., and dinner from 7:00 to 9:00 p.m. Our kitchen accommodates most dietary _____(3)_____; please inform your host upon check-in of any specific requirements.\n\n_____(4)_____\n\nWe wish you a peaceful and transformative stay.\nAlpine Wellness Team", "passageTitle": "Email: Customer Loyalty Program", "type": "single", "questions": [{"id": "xp6-33a", "part": 6, "question": "Blank (1):", "options": ["rejuvenating", "relaxing", "refreshing", "reviving"], "answer": 0, "explanation": "'Rejuvenating and restorative' = h\u1ed3i ph\u1ee5c v\u00e0 tr\u1ebb h\u00f3a (collocation wellness/hospitality chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-33b", "part": 6, "question": "Blank (2):", "options": ["guest", "reception", "concierge", "front desk"], "answer": 2, "explanation": "'Available at concierge services' = c\u00f3 t\u1ea1i d\u1ecbch v\u1ee5 concierge (collocation kh\u00e1ch s\u1ea1n/resort chu\u1ea9n nh\u1ea5t cho th\u00f4ng tin kh\u00e1ch l\u01b0u tr\u00fa).", "difficulty": "medium"}, {"id": "xp6-33c", "part": 6, "question": "Blank (3):", "options": ["requirements", "restrictions", "preferences", "needs"], "answer": 0, "explanation": "'Dietary requirements' = y\u00eau c\u1ea7u v\u1ec1 ch\u1ebf \u0111\u1ed9 \u0103n (collocation F&B/hospitality chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-33d", "part": 6, "question": "Blank (4) \u2014 Choose the best sentence:", "options": ["Should you wish to book any additional treatments or activities during your stay, please speak with our concierge team at any time.", "Wi-Fi is available throughout the retreat; connection details are in the welcome folder in your villa.", "Our team conducts a courtesy call to each villa on the first morning to ensure all guests are comfortable.", "Checkout is at 11:00 a.m.; late checkout may be available upon request, subject to availability."], "answer": 0, "explanation": "Sau th\u00f4ng tin v\u1ec1 b\u1eefa \u0103n v\u00e0 y\u00eau c\u1ea7u dietary \u2192 h\u01b0\u1edbng d\u1eabn \u0111\u1eb7t th\u00eam d\u1ecbch v\u1ee5 l\u00e0 th\u00f4ng tin h\u1eefu \u00edch v\u00e0 t\u1ef1 nhi\u00ean nh\u1ea5t trong welcome pack.", "difficulty": "medium"}]}, {"passage": "NORTHGATE BUSINESS ASSOCIATION\nBiannual Member Survey \u2014 Summary of Results\n\nDear Members,\n\nThank you for _____(1)_____ in our most recent biannual member survey. We received responses from 214 out of 310 registered members, representing a response rate of 69%.\n\nThe survey results indicate that overall member satisfaction has _____(2)_____ to 78%, up from 71% two years ago. The areas receiving the highest ratings were networking events (88%) and the online business directory (82%).\n\n_____(3)_____\n\nBased on your feedback, we will be _____(4)_____ two key changes for the coming year: launching a quarterly mentorship programme for new members, and transitioning our monthly newsletter to a digital-only format to reduce costs.\n\nWe thank you for your ongoing engagement and look forward to continuing to serve the Northgate business community.\n\nNorthgate Business Association Management", "passageTitle": "Notice: Pharmacy Hours Update", "type": "single", "questions": [{"id": "xp6-34a", "part": 6, "question": "Blank (1):", "options": ["participating", "taking part", "responding", "contributing"], "answer": 0, "explanation": "'Thank you for participating in our survey' = c\u1ea3m \u01a1n \u0111\u00e3 tham gia (collocation chu\u1ea9n nh\u1ea5t cho l\u1eddi c\u1ea3m \u01a1n v\u1ec1 kh\u1ea3o s\u00e1t).", "difficulty": "medium"}, {"id": "xp6-34b", "part": 6, "question": "Blank (2):", "options": ["risen", "climbed", "improved", "increased"], "answer": 0, "explanation": "'Satisfaction has risen to 78%' = t\u0103ng l\u00ean 78% (collocation chu\u1ea9n khi n\u00f3i v\u1ec1 t\u1ef7 l\u1ec7/\u0111i\u1ec3m s\u1ed1 t\u0103ng l\u00ean).", "difficulty": "medium"}, {"id": "xp6-34c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["The areas identified as needing improvement were access to advocacy services (58%) and the frequency of industry briefings (62%).", "Members from the retail sector recorded the highest satisfaction scores across all categories.", "The survey was conducted online over a two-week period in October.", "A full copy of the survey results will be presented at the Annual General Meeting in March."], "answer": 0, "explanation": "Sau \u0111i\u1ec3m s\u1ed1 cao \u2192 c\u00e1c l\u0129nh v\u1ef1c c\u1ea7n c\u1ea3i thi\u1ec7n l\u00e0 th\u00f4ng tin c\u00e2n b\u1eb1ng v\u00e0 quan tr\u1ecdng nh\u1ea5t ti\u1ebfp theo trong b\u00e1o c\u00e1o k\u1ebft qu\u1ea3 kh\u1ea3o s\u00e1t.", "difficulty": "medium"}, {"id": "xp6-34d", "part": 6, "question": "Blank (4):", "options": ["implementing", "introducing", "rolling out", "announcing"], "answer": 1, "explanation": "'Introducing two key changes' = gi\u1edbi thi\u1ec7u hai thay \u0111\u1ed5i ch\u00ednh (collocation chu\u1ea9n khi t\u1ed5 ch\u1ee9c th\u00f4ng b\u00e1o thay \u0111\u1ed5i d\u1ef1a tr\u00ean ph\u1ea3n h\u1ed3i).", "difficulty": "medium"}]}, {"passage": "From: Events Office <events@grandvistacenter.com>\nTo: Mr. Thomas Blake <t.blake@blakegroup.com>\nDate: February 28\n\nDear Mr. Blake,\n\nThank you for your inquiry regarding the Grand Vista Convention Center for your company's annual conference.\n\nWe are pleased to confirm that our Grand Hall, _____(1)_____ up to 600 delegates theatre-style, is available on your requested date of May 23.\n\nThe rental includes full use of the hall, integrated audio-visual equipment, high-speed Wi-Fi, and a dedicated events coordinator _____(2)_____ on the day. Catering options, ranging from coffee breaks to seated three-course lunches, can be arranged _____(3)_____.\n\n_____(4)_____\n\nWe look forward to the opportunity to host your event.\n\nWarm regards,\nSophia Lam\nEvents Manager, Grand Vista Convention Center", "passageTitle": "Memo: Budget Freeze Notice", "type": "single", "questions": [{"id": "xp6-35a", "part": 6, "question": "Blank (1):", "options": ["accommodating", "seating", "holding", "fitting"], "answer": 0, "explanation": "'Accommodating up to 600 delegates' = c\u00f3 s\u1ee9c ch\u1ee9a t\u1edbi 600 ng\u01b0\u1eddi (collocation venue/event chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-35b", "part": 6, "question": "Blank (2):", "options": ["present", "available", "assigned", "on hand"], "answer": 3, "explanation": "'A dedicated coordinator on hand' = chuy\u00ean vi\u00ean h\u1ed7 tr\u1ee3 s\u1eb5n s\u00e0ng ('on hand' = s\u1eb5n s\u00e0ng h\u1ed7 tr\u1ee3, collocation chu\u1ea9n trong d\u1ecbch v\u1ee5 s\u1ef1 ki\u1ec7n).", "difficulty": "medium"}, {"id": "xp6-35c", "part": 6, "question": "Blank (3):", "options": ["separately", "additionally", "in advance", "upon request"], "answer": 3, "explanation": "'Catering can be arranged upon request' = c\u00f3 th\u1ec3 s\u1eafp x\u1ebfp theo y\u00eau c\u1ea7u (collocation chu\u1ea9n nh\u1ea5t trong b\u00e1o gi\u00e1 d\u1ecbch v\u1ee5 s\u1ef1 ki\u1ec7n).", "difficulty": "medium"}, {"id": "xp6-35d", "part": 6, "question": "Blank (4) \u2014 Choose the best sentence:", "options": ["Please find attached our full venue brochure and a preliminary quote based on the details you have provided.", "Our venue has hosted over 200 corporate events in the past five years, including several Fortune 500 annual conferences.", "We require a 30% non-refundable deposit to secure your booking, with the remaining balance due 14 days before the event.", "A site inspection can be arranged at your convenience \u2014 please let us know a suitable time."], "answer": 0, "explanation": "Sau m\u00f4 t\u1ea3 d\u1ecbch v\u1ee5 \u2192 g\u1eedi brochure v\u00e0 b\u00e1o gi\u00e1 s\u01a1 b\u1ed9 l\u00e0 b\u01b0\u1edbc ti\u1ebfp theo th\u1ef1c t\u1ebf v\u00e0 ph\u00f9 h\u1ee3p nh\u1ea5t trong ph\u1ea3n h\u1ed3i y\u00eau c\u1ea7u \u0111\u1eb7t venue.", "difficulty": "medium"}]}, {"passage": "WESTBROOK MEDICAL CENTRE\nPatient Advisory \u2014 New Online Appointment System\n\nDear Patients,\n\nWestbrook Medical Centre is pleased to announce the launch of our new online appointment booking system, MyHealth Portal, which will be _____(1)_____ from Monday, March 3.\n\nWith MyHealth Portal, you can book, reschedule, or cancel appointments at any time without needing to call the clinic. You can also view your appointment history and _____(2)_____ referral letters and test results shared by your doctor.\n\n_____(3)_____\n\nTo register, visit myhealthportal.westbrookmc.com.au and follow the steps using your date of birth and Medicare number. If you require _____(4)_____ with registration, please call reception on (03) 9812 3400 or visit us in person during business hours.\n\nWe hope this new system makes managing your healthcare more convenient.\n\nWestbrook Medical Centre", "passageTitle": "Email: Partnership Agreement Follow-up", "type": "single", "questions": [{"id": "xp6-36a", "part": 6, "question": "Blank (1):", "options": ["available", "operational", "accessible", "active"], "answer": 0, "explanation": "'Will be available from Monday' = s\u1ebd c\u00f3 s\u1eb5n t\u1eeb th\u1ee9 Hai (t\u1ef1 nhi\u00ean nh\u1ea5t khi th\u00f4ng b\u00e1o h\u1ec7 th\u1ed1ng m\u1edbi ra m\u1eaft).", "difficulty": "medium"}, {"id": "xp6-36b", "part": 6, "question": "Blank (2):", "options": ["access", "view", "download", "retrieve"], "answer": 1, "explanation": "'View referral letters and test results' = xem th\u01b0 gi\u1edbi thi\u1ec7u v\u00e0 k\u1ebft qu\u1ea3 x\u00e9t nghi\u1ec7m (collocation b\u1ec7nh vi\u1ec7n/y t\u1ebf chu\u1ea9n nh\u1ea5t).", "difficulty": "medium"}, {"id": "xp6-36c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["For your security, the portal uses two-factor authentication, and you will receive a verification code by SMS each time you log in.", "Patients who prefer to book by phone are welcome to continue doing so during our opening hours.", "All appointment reminders will now be sent via email rather than SMS, so please ensure your contact details are up to date.", "The new system also allows GPs to send secure messages to patients regarding their care."], "answer": 0, "explanation": "Sau m\u00f4 t\u1ea3 ti\u1ec7n \u00edch c\u1ee7a portal \u2192 th\u00f4ng tin b\u1ea3o m\u1eadt (two-factor authentication) l\u00e0 y\u1ebfu t\u1ed1 quan tr\u1ecdng nh\u1ea5t m\u00e0 b\u1ec7nh nh\u00e2n c\u1ea7n bi\u1ebft khi \u0111\u0103ng k\u00fd h\u1ec7 th\u1ed1ng y t\u1ebf.", "difficulty": "medium"}, {"id": "xp6-36d", "part": 6, "question": "Blank (4):", "options": ["assistance", "help", "support", "guidance"], "answer": 0, "explanation": "'Require assistance with registration' = c\u1ea7n h\u1ed7 tr\u1ee3 \u0111\u0103ng k\u00fd (collocation chu\u1ea9n nh\u1ea5t trong th\u00f4ng b\u00e1o d\u1ecbch v\u1ee5).", "difficulty": "medium"}]}, {"passage": "BLUEWAVE LOGISTICS\nPartner Carrier Bulletin\n\nDear Partner,\n\nThis bulletin outlines several important operational updates that will _____(1)_____ effect from the first of next month.\n\nFirst, all drivers must complete the revised Dangerous Goods Handling training before transporting any DG-classified freight. Certificates must be _____(2)_____ to our compliance team at compliance@bluewave.com no later than the 25th of this month.\n\nSecond, the maximum permissible vehicle weight for accessing our Metro Distribution Hub has been reduced from 26 tonnes to 22 tonnes due to road infrastructure constraints. Vehicles _____(3)_____\n\nThird, all delivery confirmation messages must now include GPS-verified proof of delivery, not just a recipient signature. Updated instructions are available in the Driver App.\n\nPlease ensure all drivers in your fleet are _____(4)_____ of these changes before the effective date.\n\nBluewave Logistics \u2014 Partner Operations Team", "passageTitle": "Letter: Award Nomination", "type": "single", "questions": [{"id": "xp6-37a", "part": 6, "question": "Blank (1):", "options": ["take", "come into", "go into", "become"], "answer": 0, "explanation": "'Take effect from the first of next month' = c\u00f3 hi\u1ec7u l\u1ef1c t\u1eeb \u0111\u1ea7u th\u00e1ng t\u1edbi (collocation ch\u00ednh s\u00e1ch c\u1ed1 \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "xp6-37b", "part": 6, "question": "Blank (2):", "options": ["submitted", "forwarded", "emailed", "sent"], "answer": 0, "explanation": "'Certificates must be submitted to the compliance team' = ph\u1ea3i n\u1ed9p ch\u1ee9ng ch\u1ec9 (collocation trang tr\u1ecdng nh\u1ea5t trong v\u0103n b\u1ea3n tu\u00e2n th\u1ee7 quy \u0111\u1ecbnh).", "difficulty": "medium"}, {"id": "xp6-37c", "part": 6, "question": "Blank (3) \u2014 Choose the best sentence:", "options": ["exceeding this limit will be directed to the Eastern Distribution Hub on Millfield Road as an alternative entry point.", "will be required to obtain a special permit from the local council before entering the hub.", "are advised to contact dispatch before arriving to confirm their vehicle classification.", "must carry updated vehicle compliance documentation at all times."], "answer": 0, "explanation": "Sau th\u00f4ng b\u00e1o gi\u1ea3m tr\u1ecdng t\u1ea3i \u2192 h\u01b0\u1edbng d\u1eabn xe v\u01b0\u1ee3t gi\u1edbi h\u1ea1n \u0111\u1ebfn hub thay th\u1ebf l\u00e0 gi\u1ea3i ph\u00e1p th\u1ef1c t\u1ebf v\u00e0 c\u1ea7n thi\u1ebft nh\u1ea5t.", "difficulty": "medium"}, {"id": "xp6-37d", "part": 6, "question": "Blank (4):", "options": ["aware", "informed", "notified", "advised"], "answer": 0, "explanation": "'Ensure all drivers are aware of these changes' = \u0111\u1ea3m b\u1ea3o t\u00e0i x\u1ebf n\u1eafm r\u00f5 thay \u0111\u1ed5i (collocation chu\u1ea9n nh\u1ea5t trong bullet n\u1ed9i b\u1ed9 ng\u00e0nh v\u1eadn t\u1ea3i).", "difficulty": "medium"}]}, {"passageTitle": "Article: Remote Work Productivity Study", "passage": "BUSINESS WEEKLY \u2014 WORKPLACE TRENDS\n\nA recent study conducted by the Institute for Workplace Innovation has found that employees working ____(1)____ flexible schedules report significantly higher levels of job satisfaction. The research, which surveyed over 4,000 workers across multiple industries, found that satisfaction scores were, ____(2)____, 22% higher among those with scheduling flexibility.\n\n____(3)____\n\nThe authors caution, however, that the benefits of flexible work depend ____(4)____ on how well managers communicate expectations and maintain team cohesion. Companies that invest in regular check-ins and clear goal-setting appear to derive the greatest benefit.", "questions": [{"id": "np6-ar01a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["on", "with", "under", "in"], "answer": 2, "explanation": "\"Working under flexible schedules\" = l\u00e0m vi\u1ec7c theo l\u1ecbch linh ho\u1ea1t. \"Under + policy/system/arrangement\" l\u00e0 gi\u1edbi t\u1eeb chu\u1ea9n nh\u1ea5t trong v\u0103n phong trang tr\u1ecdng. \"On a flexible schedule\" c\u0169ng d\u00f9ng \u0111\u01b0\u1ee3c nh\u01b0ng \"under\" l\u00e0 collocation h\u1ecdc thu\u1eadt h\u01a1n."}, {"id": "np6-ar01b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["by comparison", "on average", "in particular", "for example"], "answer": 1, "explanation": "\"On average, 22% higher\" = trung b\u00ecnh cao h\u01a1n 22%. \"On average\" l\u00e0 c\u1ee5m t\u1eeb th\u1ed1ng k\u00ea chu\u1ea9n khi tr\u00edch d\u1eabn con s\u1ed1 t\u1eeb nghi\u00ean c\u1ee9u."}, {"id": "np6-ar01c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["These findings align with previous research suggesting that autonomy is a key driver of employee engagement.", "However, the study noted that remote work was less effective for entry-level employees.", "The institute plans to publish a follow-up study focusing on the manufacturing sector.", "Workers who preferred office environments were not included in the final analysis."], "answer": 0, "explanation": "SI: sau s\u1ed1 li\u1ec7u 22% higher satisfaction \u2192 c\u00e2u \u0111i\u1ec1n ph\u1ea3i cung c\u1ea5p ng\u1eef c\u1ea3nh r\u1ed9ng h\u01a1n. \"Aligns with previous research on autonomy as driver of engagement\" = li\u00ean k\u1ebft ph\u00e1t hi\u1ec7n v\u1edbi nghi\u00ean c\u1ee9u tr\u01b0\u1edbc, t\u1ea1o m\u1ea1ch logic h\u1ecdc thu\u1eadt."}, {"id": "np6-ar01d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["largely", "hard", "most", "great"], "answer": 0, "explanation": "\"Depend largely on\" = ph\u1ee5 thu\u1ed9c ph\u1ea7n l\u1edbn v\u00e0o. \"Depend largely/heavily/greatly on\" l\u00e0 collocations ph\u1ed5 bi\u1ebfn. \"Largely\" = adverb ph\u00f9 h\u1ee3p nh\u1ea5t trong v\u0103n h\u1ecdc thu\u1eadt."}]}, {"passageTitle": "Article: Sustainable Packaging Regulation", "passage": "INDUSTRY UPDATE \u2014 PACKAGING & SUSTAINABILITY\n\nNew regulations ____(1)____ food and beverage manufacturers to reduce plastic packaging by 30% over the next five years have come into force. The rules, which took effect on January 1, apply to all companies ____(2)____ annual revenues exceeding USD 5 million.\n\n____(3)____\n\nIndustry groups have welcomed the transition period of 18 months, which gives companies time to source alternative materials and redesign packaging lines. Companies that fail to ____(4)____ with the new standards by the deadline may face fines of up to USD 50,000 per violation.", "questions": [{"id": "np6-ar02a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["requiring", "required", "require", "requirement"], "answer": 0, "explanation": "\"Regulations requiring manufacturers to reduce...\" = m\u1ec7nh \u0111\u1ec1 r\u00fat g\u1ecdn ch\u1ee7 \u0111\u1ed9ng: regulations that require. V-ing l\u00e0m relative clause adjunct \u0111\u1ee9ng sau noun."}, {"id": "np6-ar02b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["with", "having", "of", "to"], "answer": 1, "explanation": "\"Companies having annual revenues exceeding...\" = c\u00f4ng ty c\u00f3 doanh thu v\u01b0\u1ee3t. Ph\u00e2n t\u1eeb \"having\" r\u00fat g\u1ecdn t\u1eeb \"that have\" \u2014 chu\u1ea9n trong v\u0103n b\u1ea3n ph\u00e1p l\u00fd."}, {"id": "np6-ar02c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Analysts predict that the shift to sustainable packaging could add 3\u20135% to production costs in the short term.", "The regulations were originally proposed in 2019 but delayed due to the global pandemic.", "Most companies affected by the rules are headquartered in the Asia-Pacific region.", "The government has committed to providing no financial assistance to affected businesses."], "answer": 0, "explanation": "SI: sau \u0111o\u1ea1n v\u1ec1 quy \u0111\u1ecbnh m\u1edbi \u2192 c\u00e2u \u0111i\u1ec1n ph\u1ea3i cung c\u1ea5p th\u00eam b\u1ed1i c\u1ea3nh kinh t\u1ebf. \"Could add 3-5% to production costs\" = t\u00e1c \u0111\u1ed9ng t\u00e0i ch\u00ednh th\u1ef1c t\u1ebf, logic nh\u1ea5t \u0111\u1ec3 \u0111\u1eb7t tr\u01b0\u1edbc \u0111o\u1ea1n v\u1ec1 \"transition period\"."}, {"id": "np6-ar02d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["comply", "agreement", "accordance", "adhere"], "answer": 0, "explanation": "\"Fail to comply with the new standards\" = kh\u00f4ng tu\u00e2n th\u1ee7 ti\u00eau chu\u1ea9n m\u1edbi. \"Comply with\" = collocation ph\u00e1p l\u00fd c\u1ed1 \u0111\u1ecbnh. \"Adhere to\" c\u0169ng \u0111\u00fang nh\u01b0ng \"comply with regulations/standards\" l\u00e0 chu\u1ea9n nh\u1ea5t trong v\u0103n b\u1ea3n quy \u0111\u1ecbnh."}]}, {"passageTitle": "Report: Annual Customer Loyalty Trends", "passage": "CUSTOMER INSIGHTS REPORT \u2014 Q4 SUMMARY\nPrepared by: Market Research Division\n\nCustomer retention rates across the retail sector improved ____(1)____ in Q4, rising from 68% to 74% year-on-year. This improvement is largely ____(2)____ to the rollout of personalised loyalty programmes, which allow customers to earn rewards based on individual purchasing patterns rather than fixed spend thresholds.\n\n____(3)____\n\nLooking ahead, analysts expect retention rates to continue rising, ____(4)____ retailers adopt more data-driven approaches to customer engagement. Companies that integrate loyalty data with inventory management are expected to see the most significant long-term gains.", "questions": [{"id": "np6-ar03a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["noticeably", "noticed", "noticeable", "noticing"], "answer": 0, "explanation": "\"Improved noticeably\" = c\u1ea3i thi\u1ec7n \u0111\u00e1ng k\u1ec3. Adverb b\u1ed5 ngh\u0129a cho verb \"improved\". \"Noticeably\" = adverb; \"noticeable\" = adjective (sai v\u1ecb tr\u00ed)."}, {"id": "np6-ar03b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["attributed", "contributed", "added", "related"], "answer": 0, "explanation": "\"Largely attributed to the rollout\" = ch\u1ee7 y\u1ebfu \u0111\u01b0\u1ee3c quy cho. \"Attributed to\" = c\u1ee5m b\u1ecb \u0111\u1ed9ng chu\u1ea9n trong b\u00e1o c\u00e1o ph\u00e2n t\u00edch khi gi\u1ea3i th\u00edch nguy\u00ean nh\u00e2n."}, {"id": "np6-ar03c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Notably, the highest retention gains were recorded among customers aged 25 to 40, who tend to engage most actively with digital reward platforms.", "However, some retailers have expressed concern about the cost of implementing new loyalty systems.", "The report was commissioned by the National Retail Federation as part of an industry-wide benchmarking initiative.", "Customer service ratings declined slightly during the same period due to increased online order volumes."], "answer": 0, "explanation": "SI: sau s\u1ed1 li\u1ec7u retention improvement \u2192 c\u00e2u \u0111i\u1ec1n cung c\u1ea5p chi ti\u1ebft c\u1ee5 th\u1ec3. \"Highest gains among 25-40 age group who engage with digital platforms\" = ph\u00e2n t\u00edch theo nh\u00e2n kh\u1ea9u h\u1ecdc, k\u1ebft n\u1ed1i t\u1ef1 nhi\u00ean v\u1edbi \"personalised loyalty programmes\" \u0111\u00e3 \u0111\u1ec1 c\u1eadp."}, {"id": "np6-ar03d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["as", "so", "until", "although"], "answer": 0, "explanation": "\"Continue rising as retailers adopt data-driven approaches\" = khi/trong khi nh\u00e0 b\u00e1n l\u1ebb \u00e1p d\u1ee5ng. \"As\" = li\u00ean t\u1eeb th\u1eddi gian/nguy\u00ean nh\u00e2n, ph\u00f9 h\u1ee3p nh\u1ea5t \u0111\u1ec3 di\u1ec5n \u0111\u1ea1t xu h\u01b0\u1edbng song song."}]}, {"passageTitle": "Article: Rise of Co-Working Spaces", "passage": "COMMERCIAL REAL ESTATE REVIEW\n\nThe co-working sector has seen ____(1)____ growth over the past three years, driven by the rise of hybrid work models and an increasing number of freelancers and small businesses seeking flexible office solutions. Industry analysts estimate that the number of co-working locations globally has grown by over 40% since 2021.\n\n____(2)____, this expansion has not been without challenges. Many operators have struggled to maintain profitability ____(3)____ rising commercial property rents and intense competition from established players such as WeWork and IWG.\n\n____(4)____, smaller boutique operators have found success by focusing on niche markets, such as creative industries or technology startups, where community and collaboration are particularly valued.", "questions": [{"id": "np6-ar04a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["remarkable", "remarkably", "remark", "remarked"], "answer": 0, "explanation": "\"Remarkable growth\" = t\u0103ng tr\u01b0\u1edfng \u0111\u00e1ng ch\u00fa \u00fd. Adjective tr\u01b0\u1edbc noun \"growth\". \"Remarkably\" l\u00e0 adverb, sai v\u1ecb tr\u00ed tr\u01b0\u1edbc noun."}, {"id": "np6-ar04b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["Nevertheless", "Therefore", "Furthermore", "Consequently"], "answer": 0, "explanation": "\"Nevertheless, this expansion has not been without challenges\" = Tuy nhi\u00ean, s\u1ef1 m\u1edf r\u1ed9ng n\u00e0y c\u0169ng g\u1eb7p kh\u00f3 kh\u0103n. \"Nevertheless\" = t\u01b0\u01a1ng ph\u1ea3n v\u1edbi \u0111o\u1ea1n t\u00edch c\u1ef1c tr\u01b0\u1edbc. \"Therefore/Consequently\" = h\u1eadu qu\u1ea3 (sai logic)."}, {"id": "np6-ar04c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["in the face of rising commercial property rents and intense competition from established players.", "despite the strong demand from hybrid workers and small businesses.", "as a result of declining interest from corporate clients in major cities.", "following the closure of several high-profile co-working brands in key markets."], "answer": 0, "explanation": "SI: \"struggled to maintain profitability ___\" = c\u1ea7n c\u1ee5m nguy\u00ean nh\u00e2n/b\u1ed1i c\u1ea3nh. \"In the face of rising rents and competition\" = ch\u00ednh x\u00e1c nh\u1ea5t \u2014 gi\u1ea3i th\u00edch nguy\u00ean nh\u00e2n kh\u00f3 kh\u0103n c\u1ee7a c\u00e1c nh\u00e0 v\u1eadn h\u00e0nh."}, {"id": "np6-ar04d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["Even so", "As a result", "For example", "In addition"], "answer": 0, "explanation": "\"Even so, smaller boutique operators have found success\" = D\u00f9 v\u1eady, m\u1ed9t s\u1ed1 v\u1eabn th\u00e0nh c\u00f4ng. \"Even so\" = t\u01b0\u01a1ng ph\u1ea3n nh\u01b0\u1ee3ng b\u1ed9 sau th\u00e1ch th\u1ee9c v\u1eeba \u0111\u1ec1 c\u1eadp, chu\u1ea9n nh\u1ea5t \u0111\u1ec3 gi\u1edbi thi\u1ec7u tr\u01b0\u1eddng h\u1ee3p th\u00e0nh c\u00f4ng."}]}, {"passageTitle": "Report: Q2 Sales Performance Review", "passage": "INTERNAL SALES PERFORMANCE REPORT \u2014 Q2\nPrepared for: Regional Management Team\n\nOverall sales performance in Q2 ____(1)____ expectations, with total revenue reaching USD 12.4 million against a target of USD 11.8 million. The strongest growth was recorded in the enterprise segment, ____(2)____ grew by 18% compared to the same period last year.\n\n____(3)____\n\nThe underperformance in the SME segment, however, remains a concern. Sales managers have been asked to identify key barriers to conversion and report their findings at the July planning session. ____(4)____ action is taken before Q3 begins, the annual target may need to be revised downward.", "questions": [{"id": "np6-ar05a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["exceeded", "reached", "met", "surpassed"], "answer": 0, "explanation": "\"Performance exceeded expectations\" = v\u01b0\u1ee3t k\u1ef3 v\u1ecdng. \"Exceed expectations\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t. \"Surpassed\" c\u0169ng \u0111\u00fang nh\u01b0ng \u00edt d\u00f9ng h\u01a1n trong b\u00e1o c\u00e1o hi\u1ec7u su\u1ea5t TOEIC."}, {"id": "np6-ar05b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["which", "that", "where", "it"], "answer": 0, "explanation": "\"The enterprise segment, which grew by 18%\" = m\u1ec7nh \u0111\u1ec1 quan h\u1ec7 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh (c\u00f3 d\u1ea5y ph\u1ea9y) \u2192 d\u00f9ng \"which\". Kh\u00f4ng d\u00f9ng \"that\" trong m\u1ec7nh \u0111\u1ec1 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh."}, {"id": "np6-ar05c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["The consumer segment also posted modest growth of 6%, supported by the launch of two new product lines in May.", "The finance team is preparing a revised budget forecast for the second half of the year.", "All sales staff will receive a performance-based bonus in recognition of Q2 results.", "The Q2 figures will be presented to the board at the annual general meeting in September."], "answer": 0, "explanation": "SI: sau enterprise segment (18% growth) \u2192 c\u00e2u \u0111i\u1ec1n cung c\u1ea5p th\u00eam segment data. \"Consumer segment modest growth of 6% supported by new product lines\" = continues segment-by-segment analysis, logic nh\u1ea5t trong c\u1ea5u tr\u00fac b\u00e1o c\u00e1o hi\u1ec7u su\u1ea5t."}, {"id": "np6-ar05d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["Unless", "Until", "Although", "Provided"], "answer": 0, "explanation": "\"Unless action is taken before Q3, the target may need revision\" = tr\u1eeb khi c\u00f3 h\u00e0nh \u0111\u1ed9ng th\u00ec m\u1ee5c ti\u00eau ph\u1ea3i xem x\u00e9t l\u1ea1i. \"Unless\" = if...not, \u0111i\u1ec1u ki\u1ec7n ph\u1ee7 \u0111\u1ecbnh \u2014 chu\u1ea9n nh\u1ea5t \u0111\u1ec3 di\u1ec5n \u0111\u1ea1t r\u1ee7i ro c\u1ea7n tr\u00e1nh."}]}, {"passageTitle": "Article: Digital Transformation in Finance", "passage": "FINTECH OBSERVER \u2014 INDUSTRY ANALYSIS\n\nFinancial institutions are increasingly ____(1)____ artificial intelligence to streamline back-office operations and enhance customer service delivery. According to a 2024 survey by Deloitte, 71% of bank executives identified AI as a top strategic priority, ____(2)____ from 48% in 2022.\n\n____(3)____\n\nDespite the optimism, adoption rates vary significantly across different bank sizes. Larger institutions have the capital and technical resources to deploy AI at scale, ____(4)____ many smaller community banks continue to rely on legacy systems that are difficult and expensive to upgrade.", "questions": [{"id": "np6-ar06a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["adopting", "adopted", "adoption", "adopt"], "answer": 0, "explanation": "\"Are increasingly adopting AI\" = \u0111ang ng\u00e0y c\u00e0ng \u00e1p d\u1ee5ng. Present Continuous v\u1edbi \"are\" \u2192 V-ing. \"Adopt\" l\u00e0 nguy\u00ean th\u1ec3 (sai sau \"are\")."}, {"id": "np6-ar06b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["up", "risen", "increased", "growing"], "answer": 0, "explanation": "\"71%, up from 48% in 2022\" = t\u0103ng t\u1eeb 48% v\u00e0o n\u0103m 2022. \"Up from [previous figure]\" l\u00e0 c\u1ee5m c\u1ed1 \u0111\u1ecbnh trong b\u00e1o c\u00e1o th\u1ed1ng k\u00ea/t\u00e0i ch\u00ednh TOEIC."}, {"id": "np6-ar06c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["Early adopters report efficiency gains of up to 25% in loan processing and fraud detection, suggesting the investment can deliver strong returns.", "However, many bank customers remain sceptical about the use of AI in financial decision-making.", "The survey was conducted across 15 countries and covered both retail and investment banking sectors.", "Regulators in several markets have expressed concerns about the use of AI in credit scoring."], "answer": 0, "explanation": "SI: sau s\u1ed1 li\u1ec7u AI adoption t\u0103ng \u2192 c\u00e2u \u0111i\u1ec1n cung c\u1ea5p b\u1eb1ng ch\u1ee9ng k\u1ebft qu\u1ea3 th\u1ef1c t\u1ebf. \"Early adopters report 25% efficiency gains in loan processing\" = data point c\u1ee5 th\u1ec3 h\u1ed7 tr\u1ee3 l\u00fd do t\u0103ng adoption, bridge t\u1ef1 nhi\u00ean sang \u0111o\u1ea1n v\u1ec1 challenges ti\u1ebfp theo."}, {"id": "np6-ar06d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["while", "and", "but", "however"], "answer": 0, "explanation": "\"Have capital to deploy AI at scale, while many smaller banks rely on legacy systems\" = t\u01b0\u01a1ng ph\u1ea3n song song trong c\u00f9ng c\u00e2u. \"While\" = li\u00ean t\u1eeb t\u01b0\u01a1ng ph\u1ea3n trong clause (c\u00f9ng c\u00e2u). \"However\" \u0111\u1ee9ng \u0111\u1ea7u c\u00e2u m\u1edbi (kh\u00e1c v\u1ecb tr\u00ed)."}]}, {"passageTitle": "Letter: Service Contract Renewal Notice", "passage": "Vertex IT Solutions\nSuite 1200, 180 George Street\nSydney NSW 2000\n\nMarch 14\n\nMr. James Holloway\nChief Operating Officer\nHolloway & Associates\nLevel 7, 42 Bridge Street, Sydney NSW 2000\n\nDear Mr. Holloway,\n\nI am writing to advise you that your current Managed IT Services Agreement with Vertex IT Solutions will ____(1)____ on April 30. We would like to take this opportunity to offer you a renewed contract for a further 24-month term.\n\nOur revised service package ____(2)____ all features of your current agreement, plus enhanced cybersecurity monitoring and a dedicated technical account manager. Given the expanded scope of services, the proposed monthly fee will increase by 8%, from AUD 3,200 to AUD 3,456.\n\n____(3)____\n\nWe would welcome the opportunity to discuss the proposed terms at your convenience. Please do not ____(4)____ to contact me directly at j.chen@vertexit.com.au should you have any questions.\n\nYours sincerely,\nJason Chen\nClient Relations Manager, Vertex IT Solutions", "questions": [{"id": "np6-lt01a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["expire", "end", "finish", "conclude"], "answer": 0, "explanation": "\"Agreement will expire on April 30\" = h\u1ebft h\u1ea1n. \"Expire\" l\u00e0 t\u1eeb chuy\u00ean bi\u1ec7t cho h\u1ee3p \u0111\u1ed3ng/t\u00e0i li\u1ec7u ph\u00e1p l\u00fd. \"End/finish/conclude\" qu\u00e1 chung chung trong ng\u1eef c\u1ea3nh ph\u00e1p l\u00fd."}, {"id": "np6-lt01b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["includes", "contains", "covers", "encompasses"], "answer": 2, "explanation": "\"Package covers all features of your current agreement\" = bao g\u1ed3m/bao qu\u00e1t t\u1ea5t c\u1ea3. \"Cover\" l\u00e0 collocation chu\u1ea9n nh\u1ea5t v\u1edbi \"service package\": \"covers all features/aspects\"."}, {"id": "np6-lt01c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["To confirm your renewal, please sign and return the enclosed contract documentation by April 10.", "Please note that failure to respond before April 30 will result in automatic contract renewal.", "A detailed breakdown of all service costs is available upon request from our finance department.", "Vertex IT Solutions reserves the right to revise pricing with 30 days' written notice."], "answer": 0, "explanation": "SI: sau gi\u1edbi thi\u1ec7u g\u00f3i d\u1ecbch v\u1ee5 v\u00e0 m\u1ee9c ph\u00ed m\u1edbi \u2192 c\u00e2u \u0111i\u1ec1n ph\u1ea3i l\u00e0 h\u00e0nh \u0111\u1ed9ng ti\u1ebfp theo r\u00f5 r\u00e0ng. \"Sign and return by April 10\" = deadline c\u1ee5 th\u1ec3, logic nh\u1ea5t trong business letter renewal context."}, {"id": "np6-lt01d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["hesitate", "wait", "delay", "pause"], "answer": 0, "explanation": "\"Please do not hesitate to contact me\" = xin \u0111\u1eebng ng\u1ea7n ng\u1ea1i li\u00ean h\u1ec7. C\u1ee5m k\u1ebft th\u00fac th\u01b0 kinh doanh c\u1ed1 \u0111\u1ecbnh. \"Please do not hesitate to\" l\u00e0 collocation kh\u00f4ng th\u1ec3 thay th\u1ebf trong formal correspondence."}]}, {"passageTitle": "Letter: Conference Speaking Invitation", "passage": "The Australasian Human Resources Institute\nPO Box 1429, Melbourne VIC 3001\n\nSeptember 5\n\nDr. Priya Mehta\nCo-Founder & CEO, DataBridge Analytics\nLevel 12, 88 Collins Street, Melbourne VIC 3000\n\nDear Dr. Mehta,\n\nOn behalf of the Australasian Human Resources Institute, I am delighted to ____(1)____ you as a keynote speaker at our Annual HR Leadership Summit, to be held on November 14 at the Crown Conference Centre, Melbourne.\n\nYour work on predictive workforce analytics has ____(2)____ significant interest among HR professionals in our network, and we believe your insights would be of tremendous value to our 500 delegates.\n\n____(3)____\n\nWe would be grateful if you could confirm your availability by September 30. Attached to this letter is a speaker information sheet, ____(4)____ outlines the presentation format, technology available, and honorarium details.\n\nWe very much hope you will be able to join us.\n\nWarm regards,\nCatherine Ng\nEvents Director, AHRI", "questions": [{"id": "np6-lt02a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["invite", "welcome", "request", "appoint"], "answer": 0, "explanation": "\"Delighted to invite you as a keynote speaker\" = tr\u00e2n tr\u1ecdng m\u1eddi. \"Invite\" + \"as [role]\" l\u00e0 c\u1ee5m l\u1ecbch s\u1ef1 chu\u1ea9n trong th\u01b0 m\u1eddi ch\u00ednh th\u1ee9c. \"Welcome\" th\u01b0\u1eddng d\u00f9ng khi ch\u00e0o \u0111\u00f3n (ng\u01b0\u1eddi \u0111\u00e3 ch\u1ea5p nh\u1eadn), kh\u00f4ng ph\u1ea3i l\u1eddi m\u1eddi."}, {"id": "np6-lt02b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["generated", "created", "produced", "attracted"], "answer": 0, "explanation": "\"Work has generated significant interest\" = c\u00f4ng tr\u00ecnh \u0111\u00e3 t\u1ea1o ra s\u1ef1 quan t\u00e2m \u0111\u00e1ng k\u1ec3. \"Generate interest\" = collocation chu\u1ea9n nh\u1ea5t. \"Attract interest\" c\u0169ng \u0111\u00fang nh\u01b0ng \"generate\" ph\u1ed5 bi\u1ebfn h\u01a1n trong v\u0103n b\u1ea3n h\u1ecdc thu\u1eadt/s\u1ef1 ki\u1ec7n."}, {"id": "np6-lt02c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["We envisage a 45-minute presentation followed by a 15-minute moderated Q&A session.", "Please note that keynote speakers are responsible for arranging their own travel and accommodation.", "The summit will also feature panel discussions, workshops, and a networking reception.", "Previous keynote speakers have included the CEOs of several Fortune 500 companies."], "answer": 0, "explanation": "SI: sau gi\u1edbi thi\u1ec7u ch\u1ee7 \u0111\u1ec1 \u2192 c\u00e2u \u0111i\u1ec1n ph\u1ea3i cung c\u1ea5p chi ti\u1ebft th\u1ef1c t\u1ebf v\u1ec1 b\u00e0i ph\u00e1t bi\u1ec3u. \"45-minute presentation + 15-minute Q&A\" = th\u00f4ng tin c\u1ee5 th\u1ec3 nh\u1ea5t m\u00e0 di\u1ec5n gi\u1ea3 c\u1ea7n bi\u1ebft, k\u1ebft n\u1ed1i t\u1ef1 nhi\u00ean v\u1edbi \"speaker information sheet\" \u1edf c\u00e2u sau."}, {"id": "np6-lt02d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["which", "that", "it", "what"], "answer": 0, "explanation": "\"A speaker information sheet, which outlines...\" = m\u1ec7nh \u0111\u1ec1 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh (c\u00f3 d\u1ea5y ph\u1ea9y), ch\u1ec9 v\u1eadt. D\u00f9ng \"which\" \u2014 kh\u00f4ng d\u00f9ng \"that\" trong m\u1ec7nh \u0111\u1ec1 kh\u00f4ng h\u1ea1n \u0111\u1ecbnh sau d\u1ea5u ph\u1ea9y."}]}, {"passageTitle": "Letter: Performance Award Notification", "passage": "Clearwater Financial Group\n888 Bay Street, Toronto, ON M5S 2Y2\n\nOctober 8\n\nMs. Amara Diallo\nSenior Client Advisor\nClearwater Financial Group\n\nDear Ms. Diallo,\n\nI am pleased to inform you that you have been selected to ____(1)____ this year's Excellence in Client Service Award, ____(2)____ annually by the senior leadership team to recognise outstanding performance.\n\nYour dedication to building long-term client relationships and your consistently high satisfaction scores \u2014 averaging 4.9 out of 5.0 \u2014 set you apart from your peers. ____(3)____\n\nThe award will be ____(4)____ at the Annual Staff Gala on November 22. You and a guest of your choice are invited to attend as our special guests for the evening.\n\nCongratulations on this well-deserved recognition.\n\nSincerely,\nDavid Huang\nChief Executive Officer, Clearwater Financial Group", "questions": [{"id": "np6-lt03a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["receive", "accept", "be given", "be awarded"], "answer": 3, "explanation": "\"Selected to be awarded this year's Excellence Award\" = \u0111\u01b0\u1ee3c ch\u1ecdn nh\u1eadn gi\u1ea3i th\u01b0\u1edfng. \"Be awarded\" = passive infinitive ph\u00f9 h\u1ee3p nh\u1ea5t sau \"selected to\". \"Receive/accept\" l\u00e0 ch\u1ee7 \u0111\u1ed9ng (c\u00f3 th\u1ec3 d\u00f9ng nh\u01b0ng \"be awarded\" ch\u00ednh th\u1ee9c h\u01a1n)."}, {"id": "np6-lt03b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["presented", "presenting", "that presents", "is presented"], "answer": 0, "explanation": "\"Award, presented annually by the leadership team\" = m\u1ec7nh \u0111\u1ec1 r\u00fat g\u1ecdn b\u1ecb \u0111\u1ed9ng (= which is presented). V3 sau d\u1ea5u ph\u1ea9y l\u00e0m participial adjunct b\u1ecb \u0111\u1ed9ng."}, {"id": "np6-lt03c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["This year, you handled over 340 client accounts, maintaining a renewal rate of 96% \u2014 the highest in the company.", "We would like you to prepare a short speech to be delivered at the award ceremony.", "Your performance has been noted in your annual review and will be reflected in your next salary assessment.", "The selection committee reviewed nominations from across all departments before reaching its decision."], "answer": 0, "explanation": "SI: sau \"consistently high satisfaction scores 4.9/5\" \u2192 c\u00e2u \u0111i\u1ec1n cung c\u1ea5p b\u1eb1ng ch\u1ee9ng c\u1ee5 th\u1ec3 kh\u00e1c. \"340 accounts, 96% renewal rate \u2014 highest in company\" = data point b\u1ed5 sung, l\u00e0m n\u1ed5i b\u1eadt th\u00e0nh t\u00edch xu\u1ea5t s\u1eafc, k\u1ebft n\u1ed1i t\u1ef1 nhi\u00ean v\u1edbi ph\u1ea7n khen ng\u1ee3i."}, {"id": "np6-lt03d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["presented", "announced", "delivered", "awarded"], "answer": 0, "explanation": "\"Award will be presented at the Annual Staff Gala\" = gi\u1ea3i th\u01b0\u1edfng s\u1ebd \u0111\u01b0\u1ee3c trao t\u1ea1i. \"Present an award\" = collocation nghi l\u1ec5 chu\u1ea9n nh\u1ea5t. \"Awarded\" = passive (sai c\u1ea5u tr\u00fac v\u1edbi \"will be awarded\" c\u1ea7n object)."}]}, {"passageTitle": "Letter: Subscription Cancellation Confirmation", "passage": "TechVault Pro\nCustomer Support Team\nsupport@techvaultpro.com\n\nNovember 2\n\nMr. Stefan Novak\n14 Riverside Lane\nVienna, Austria AT-1010\n\nDear Mr. Novak,\n\nThank you for contacting TechVault Pro. This letter serves to confirm the ____(1)____ of your Professional Plan subscription, effective November 30.\n\nYour account will remain fully ____(2)____ until the end of your current billing period. After this date, you will lose access to all premium features, including cloud storage, priority support, and advanced analytics.\n\n____(3)____\n\nShould you change your mind before November 30, you may reactivate your subscription at any time by logging in to your account and selecting \"Reactivate Plan.\" Your settings and stored data will ____(4)____ intact for up to 90 days following cancellation.\n\nWe are sorry to see you go and hope to welcome you back in the future.\n\nKind regards,\nTechVault Pro Customer Support", "questions": [{"id": "np6-lt04a", "part": 6, "qNum": 1, "question": "Blank (1):", "options": ["cancellation", "termination", "ending", "closure"], "answer": 0, "explanation": "\"Confirm the cancellation of your subscription\" = x\u00e1c nh\u1eadn h\u1ee7y \u0111\u0103ng k\u00fd. \"Cancellation\" l\u00e0 t\u1eeb chu\u1ea9n nh\u1ea5t cho subscription/service. \"Termination\" th\u01b0\u1eddng d\u00f9ng cho h\u1ee3p \u0111\u1ed3ng, \"closure\" cho t\u00e0i kho\u1ea3n/c\u1eeda h\u00e0ng."}, {"id": "np6-lt04b", "part": 6, "qNum": 2, "question": "Blank (2):", "options": ["accessible", "active", "available", "functional"], "answer": 1, "explanation": "\"Account will remain fully active until end of billing period\" = t\u00e0i kho\u1ea3n v\u1eabn ho\u1ea1t \u0111\u1ed9ng \u0111\u1ea7y \u0111\u1ee7. \"Remain active\" l\u00e0 tr\u1ea1ng th\u00e1i ph\u00f9 h\u1ee3p nh\u1ea5t cho subscription account. \"Accessible\" thi\u00ean v\u1ec1 kh\u1ea3 n\u0103ng truy c\u1eadp, kh\u00f4ng bao h\u00e0m to\u00e0n b\u1ed9 t\u00ednh n\u0103ng."}, {"id": "np6-lt04c", "part": 6, "qNum": 3, "question": "Which of the following sentences best completes the passage at position (3)?", "options": ["If you would like to provide feedback on your experience, please complete our brief exit survey at techvaultpro.com/feedback.", "Please note that any outstanding invoices must be settled before your account can be closed.", "Your subscription fee for the current period will not be refunded under our standard cancellation policy.", "To export your data before cancellation, visit the Account Settings page and select \"Export Data.\""], "answer": 0, "explanation": "SI: sau th\u00f4ng b\u00e1o m\u1ea5t quy\u1ec1n truy c\u1eadp premium features \u2192 c\u00e2u \u0111i\u1ec1n n\u00ean cung c\u1ea5p th\u00eam th\u00f4ng tin h\u1eefu \u00edch. \"Exit survey at feedback URL\" = n\u01a1i thu th\u1eadp feedback t\u1eeb ng\u01b0\u1eddi d\u00f9ng r\u1eddi \u0111i, \u0111\u1eb7t tr\u01b0\u1edbc h\u01b0\u1edbng d\u1eabn reactivation l\u00e0 logic t\u1ef1 nhi\u00ean."}, {"id": "np6-lt04d", "part": 6, "qNum": 4, "question": "Blank (4):", "options": ["remain", "keep", "stay", "be kept"], "answer": 0, "explanation": "\"Settings and stored data will remain intact for 90 days\" = s\u1ebd v\u1eabn nguy\u00ean v\u1eb9n trong 90 ng\u00e0y. \"Remain intact\" = collocation c\u1ed1 \u0111\u1ecbnh. \"Be kept intact\" c\u0169ng \u0111\u00fang nh\u01b0ng \"remain intact\" t\u1ef1 nhi\u00ean v\u00e0 ng\u1eafn g\u1ecdn h\u01a1n."}]}], "part7": [{"passage": "From: Sarah Chen <s.chen@globaltrade.com>\nTo: Marcus Webb <m.webb@globaltrade.com>\nDate: September 14\nSubject: Q3 Sales Report\n\nHi Marcus,\n\nI've just finished compiling the Q3 sales report, and the results look very promising. Overall, sales increased by 18% compared to the same period last year. The Asia-Pacific region performed particularly well, with a 34% growth, largely driven by new partnerships in South Korea and Singapore.\n\nHowever, our North America division saw a slight decline of about 3%, primarily due to supply chain disruptions in Q2 that carried over into Q3. I've included a detailed breakdown in the attached spreadsheet.\n\nI recommend we schedule a meeting with the regional managers to discuss strategies for North America and how to sustain growth in Asia-Pacific. Are you available for a call this Thursday or Friday?\n\nBest regards,\nSarah", "passageTitle": "Email: Q3 Sales Report", "type": "single", "questions": [{"id": "p7-1a", "part": 7, "question": "What is the main purpose of this email?", "options": ["To request a budget approval", "To share a quarterly sales report", "To introduce a new business partner", "To schedule a training session"], "answer": 1, "explanation": "Ch\u1ee7 \u0111\u1ec1 email l\u00e0 chia s\u1ebb k\u1ebft qu\u1ea3 Q3 sales report v\u1edbi \u0111\u1ed3ng nghi\u1ec7p.", "difficulty": "medium"}, {"id": "p7-1b", "part": 7, "question": "Which region showed the strongest growth?", "options": ["North America", "Europe", "Asia-Pacific", "South America"], "answer": 2, "explanation": "'The Asia-Pacific region performed particularly well, with a 34% growth.'", "difficulty": "medium"}, {"id": "p7-1c", "part": 7, "question": "What caused the decline in North America?", "options": ["Increased competition", "Low product demand", "Supply chain disruptions", "Staffing shortages"], "answer": 2, "explanation": "'primarily due to supply chain disruptions in Q2 that carried over into Q3'", "difficulty": "medium"}, {"id": "p7-1d", "part": 7, "question": "What does Sarah suggest doing?", "options": ["Hiring new regional managers", "Canceling the North America operations", "Meeting with regional managers", "Revising the company's product line"], "answer": 2, "explanation": "'I recommend we schedule a meeting with the regional managers'", "difficulty": "medium"}]}, {"passage": "PRESS RELEASE\nFor Immediate Release\n\nNovaBright Technologies Announces Launch of SmartDesk Pro\n\nSAN FRANCISCO, October 3 \u2013 NovaBright Technologies today unveiled SmartDesk Pro, its latest productivity software designed for remote and hybrid work environments. The platform integrates task management, video conferencing, and document collaboration into a single interface.\n\n\"SmartDesk Pro was built in response to direct feedback from over 5,000 beta users,\" said CEO Linda Park. \"We listened carefully and created a tool that genuinely addresses the challenges of modern work.\"\n\nThe software will be available starting October 15 and will be offered in three pricing tiers: Basic ($9.99/month), Professional ($24.99/month), and Enterprise (custom pricing). A 30-day free trial is available for all plans.\n\nFor more information, visit www.novabrighttech.com or contact media@novabrighttech.com.", "passageTitle": "Press Release", "type": "single", "questions": [{"id": "p7-2a", "part": 7, "question": "What type of document is this?", "options": ["A product brochure", "A press release", "An internal memo", "A user manual"], "answer": 1, "explanation": "D\u00f2ng \u0111\u1ea7u ghi 'PRESS RELEASE' \u2013 th\u00f4ng c\u00e1o b\u00e1o ch\u00ed.", "difficulty": "medium"}, {"id": "p7-2b", "part": 7, "question": "When will SmartDesk Pro be available for purchase?", "options": ["October 3", "October 10", "October 15", "November 1"], "answer": 2, "explanation": "'The software will be available starting October 15'", "difficulty": "medium"}, {"id": "p7-2c", "part": 7, "question": "What was used to develop the product?", "options": ["A market research report", "Feedback from beta users", "A competitor analysis", "Government funding"], "answer": 1, "explanation": "'built in response to direct feedback from over 5,000 beta users'", "difficulty": "medium"}, {"id": "p7-s-v02", "part": 7, "question": "In the press release, the word \"unveiling\" is closest in meaning to", "options": ["announcing", "releasing", "displaying", "launching"], "answer": 0, "explanation": "WIC: \"unveiling\" = c\u00f4ng b\u1ed1 l\u1ea7n \u0111\u1ea7u ti\u00ean, ti\u1ebft l\u1ed9 ch\u00ednh th\u1ee9c. \"Announcing\" n\u1eafm b\u1eaft \u0111\u00fang ngh\u0129a trong ng\u1eef c\u1ea3nh press release ra m\u1eaft s\u1ea3n ph\u1ea9m."}]}, {"passage": "[Document 1 \u2013 Job Advertisement]\nMarketing Manager \u2013 GreenLeaf Organics\nLocation: New York, NY | Full-Time\n\nGreenLeaf Organics is seeking an experienced Marketing Manager to lead our brand development initiatives. Ideal candidates will have at least 5 years of experience in consumer goods marketing, strong analytical skills, and a passion for sustainable products.\n\nKey Responsibilities:\n\u2022 Develop and execute multi-channel marketing campaigns\n\u2022 Manage a team of 6 marketing professionals\n\u2022 Analyze campaign performance and present findings to management\n\u2022 Collaborate with product developers on new launches\n\nSalary: $85,000 \u2013 $100,000 annually. Application deadline: November 30.\nTo apply, send your resume and cover letter to careers@greenleaf.com.\n\n[Document 2 \u2013 Application Email]\nFrom: James Doyle <jdoyle@email.com>\nTo: careers@greenleaf.com\nDate: November 15\n\nDear Hiring Team,\n\nI am writing to apply for the Marketing Manager position advertised on your website. I have seven years of experience in marketing within the food and beverage sector and have managed teams of up to eight people. In my current role at FreshFarm Co., I led campaigns that resulted in a 22% increase in brand awareness.\n\nI am particularly drawn to GreenLeaf Organics because of your commitment to sustainability, a value I share deeply. I have attached my resume and a detailed cover letter for your review.\n\nI look forward to hearing from you.\nSincerely,\nJames Doyle", "passageTitle": "Email + Job Listing", "type": "double", "questions": [{"id": "p7-3a", "part": 7, "question": "According to the job posting, what is the maximum salary offered?", "options": ["$75,000", "$85,000", "$95,000", "$100,000"], "answer": 3, "explanation": "M\u1ee9c l\u01b0\u01a1ng trong b\u00e0i \u0111\u0103ng l\u00e0 '$85,000 \u2013 $100,000 annually' \u2192 t\u1ed1i \u0111a $100,000.", "difficulty": "medium"}, {"id": "p7-3v", "part": 7, "question": "What is most likely the purpose of James Doyle's email?", "options": ["To decline the job offer", "To apply for the Marketing Manager position", "To request more information about the role", "To follow up on a previous interview"], "answer": 1, "explanation": "Purpose: The email is James Doyle's application for the Marketing Manager role at GreenLeaf Organics \u2014 standard cover letter/application email purpose."}, {"id": "p7-3c", "part": 7, "question": "Why is James Doyle interested in GreenLeaf Organics specifically?", "options": ["The high salary", "The company's green values", "The team size", "The job location"], "answer": 1, "explanation": "'particularly drawn to GreenLeaf Organics because of your commitment to sustainability'", "difficulty": "medium"}, {"id": "p7-3cd", "part": 7, "question": "Based on both documents, which requirement from the job posting does James Doyle NOT directly address in his email?", "options": ["Budget management experience", "Team leadership experience", "Multi-channel campaign experience", "Proficiency in marketing analytics platforms"], "answer": 3, "explanation": "Cross-document: Job posting lists analytics proficiency as a requirement. James's email details budget management, team leadership, and campaign experience \u2014 but does NOT mention analytics platforms."}, {"id": "p7-3e", "part": 7, "question": "In Document 2, the word \"accomplished\" is closest in meaning to", "options": ["attempted", "achieved", "reported", "discussed"], "answer": 1, "explanation": "Word-in-context: \"accomplished\" trong cover letter = \u0111\u00e3 \u0111\u1ea1t \u0111\u01b0\u1ee3c, ho\u00e0n th\u00e0nh. \"Achieved\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t. \"Attempted\" = \u0111\u00e3 c\u1ed1 g\u1eafng (ch\u01b0a ho\u00e0n th\u00e0nh), \"reported\" = \u0111\u00e3 b\u00e1o c\u00e1o."}]}, {"passage": "INTERNAL ANNOUNCEMENT\n\nTo: All Employees\nFrom: Office of the CEO\nDate: June 15\nSubject: Employee of the Quarter \u2013 Q2 Recognition\n\nWe are delighted to announce that this quarter's Employee of the Quarter award goes to Ms. Priya Sharma from the Customer Experience Department.\n\nMs. Sharma joined Horizon Consulting three years ago as a junior support specialist and has since demonstrated exceptional dedication and initiative. This quarter, she independently designed and implemented a new client onboarding process that reduced average onboarding time from 14 days to 6 days \u2014 a 57% improvement. Her approach has since been adopted company-wide.\n\nIn recognition of her achievement, Ms. Sharma will receive a certificate of excellence, a bonus equivalent to one week's salary, and a reserved parking spot for the next three months.\n\nNominations for Q3 are now open. Employees are encouraged to nominate colleagues who have made a meaningful impact on clients, the team, or our company culture. Submission forms are available on the company intranet.\n\nCongratulations, Priya!", "passageTitle": "Email: Employee of the Quarter \u2013 Q2 Recognition", "type": "single", "questions": [{"id": "n7-1a", "part": 7, "question": "What is the purpose of this announcement?", "options": ["To introduce a new employee program", "To recognize an employee's achievement", "To announce a company-wide process change", "To invite staff to a company celebration"], "answer": 1, "explanation": "\u2705 <b>To recognize an employee's achievement</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'this quarter's Employee of the Quarter award goes to Ms. Priya Sharma'.", "difficulty": "medium"}, {"id": "n7-1b", "part": 7, "question": "How long has Ms. Sharma worked at Horizon Consulting?", "options": ["One year", "Two years", "Three years", "Five years"], "answer": 2, "explanation": "\u2705 <b>Three years</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'Ms. Sharma joined Horizon Consulting three years ago'.", "difficulty": "medium"}, {"id": "n7-1c", "part": 7, "question": "What improvement did Ms. Sharma make to the onboarding process?", "options": ["She cut costs by 57%", "She reduced onboarding time by 57%", "She trained 57 new staff members", "She increased client satisfaction by 57%"], "answer": 1, "explanation": "\u2705 <b>She reduced onboarding time by 57%</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'reduced average onboarding time from 14 days to 6 days \u2014 a 57% improvement'.", "difficulty": "medium"}, {"id": "n7-1d", "part": 7, "question": "What is NOT mentioned as part of Ms. Sharma's reward?", "options": ["A certificate of excellence", "A salary bonus", "A company trip", "A reserved parking spot"], "answer": 2, "explanation": "\u2705 <b>A company trip</b>. <br>\ud83d\udca1 <i>Lo\u1ea1i tr\u1eeb:</i> B\u00e0i vi\u1ebft nh\u1eafc \u0111\u1ebfn certificate, bonus, v\u00e0 parking spot. Kh\u00f4ng c\u00f3 'trip'.", "difficulty": "medium"}]}, {"passage": "NOTICE OF SERVICE DISRUPTION\n\nPlatform: CloudSuite Business Solutions\nDate of Notice: Wednesday, March 12\n\nDear CloudSuite Users,\n\nWe are writing to inform you that CloudSuite Business Solutions will undergo essential system maintenance on Saturday, March 15, between the hours of 11:00 p.m. and 3:00 a.m. (Eastern Standard Time).\n\nDuring this maintenance window, access to all CloudSuite modules \u2014 including file storage, project management tools, and the reporting dashboard \u2014 will be temporarily unavailable. Scheduled automated reports that would normally run during this time will be delayed and will be processed automatically once maintenance is complete.\n\nTo minimize the impact on your workflow, we recommend the following:\n\u2022 Download or export any critical files or reports before 10:00 p.m. on March 15.\n\u2022 Reschedule any time-sensitive tasks that depend on real-time data access.\n\u2022 Notify your team members of the expected downtime.\n\nWe sincerely apologize for any inconvenience this may cause. Our team has scheduled this work during off-peak hours to minimize disruption. If you have any questions or concerns, please contact our support center at support@cloudsuite.com.\n\nThank you for your understanding.\nThe CloudSuite Technical Team", "passageTitle": "Notice: Service Disruption", "type": "single", "questions": [{"id": "n7-2a", "part": 7, "question": "What is the main purpose of this notice?", "options": ["To introduce a new feature", "To announce a price increase", "To inform users about scheduled maintenance", "To respond to a service complaint"], "answer": 2, "explanation": "\u2705 <b>To inform users about scheduled maintenance</b>. <br>\ud83d\udca1 <i>Ti\u00eau \u0111\u1ec1:</i> 'NOTICE OF SERVICE DISRUPTION' v\u00e0 n\u1ed9i dung v\u1ec1 'system maintenance'.", "difficulty": "medium"}, {"id": "n7-2b", "part": 7, "question": "Which of the following will NOT be affected during maintenance?", "options": ["File storage", "Project management tools", "Reporting dashboard", "Email inbox"], "answer": 3, "explanation": "\u2705 <b>Email inbox</b>. <br>\ud83d\udca1 <i>Lo\u1ea1i tr\u1eeb:</i> V\u0103n b\u1ea3n li\u1ec7t k\u00ea file storage, project management tools, dashboard. Kh\u00f4ng nh\u1eafc \u0111\u1ebfn email.", "difficulty": "medium"}, {"id": "n7-2c", "part": 7, "question": "What is recommended for scheduled automated reports?", "options": ["Cancel them permanently", "Run them before 10:00 p.m.", "They will be processed automatically after maintenance", "Submit them manually to the support team"], "answer": 2, "explanation": "\u2705 <b>Processed automatically once maintenance is complete</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'will be processed automatically once maintenance is complete'.", "difficulty": "medium"}, {"id": "p7-pur01", "part": 7, "question": "What is the main purpose of this notice?", "options": ["To announce a permanent change to the service", "To inform users of a temporary service outage and provide guidance", "To apologise for a previous service failure", "To introduce a new feature of the CloudSuite platform"], "answer": 1, "explanation": "Purpose: th\u00f4ng b\u00e1o v\u1ec1 s\u1ef1 c\u1ed1 t\u1ea1m th\u1eddi, h\u01b0\u1edbng d\u1eabn ng\u01b0\u1eddi d\u00f9ng c\u00e1ch x\u1eed l\u00fd v\u00e0 \u0111\u01b0\u1eddng hotline h\u1ed7 tr\u1ee3 \u2014 \u0111\u00e2y l\u00e0 m\u1ee5c \u0111\u00edch ch\u00ednh th\u1ed1ng nh\u1ea5t c\u1ee7a Notice d\u1ea1ng n\u00e0y."}]}, {"passage": "TRAVEL ADVISORY\nInternational Business Travel Division\nHorizon Financial Group\n\nDestination: Ho Chi Minh City, Vietnam\nIssued: September 2025\n\nGENERAL OVERVIEW\nHo Chi Minh City (HCMC) is Vietnam's largest commercial hub and a growing destination for international business. Travelers will find a dynamic, fast-paced city with a well-developed infrastructure for business visitors.\n\nVISA REQUIREMENTS\nMost business travelers will require a visa. Citizens of certain countries may be eligible for visa-free entry or e-visa arrangements. Employees are advised to check visa requirements at least 4 weeks prior to departure and submit applications through the official Vietnam Immigration Department portal.\n\nHEALTH & SAFETY\nConsult your physician at least 4 weeks prior to travel regarding recommended vaccinations. Travel insurance that covers medical evacuation is strongly recommended. HCMC has reputable international hospitals; however, medical costs can be high without appropriate coverage.\n\nBUSINESS CULTURE\nBusiness meetings in HCMC typically begin on time. Bring printed business cards and present them with both hands as a sign of respect. Formal attire is expected in most business settings.\n\nEXPENSE REPORTING\nAll travel expenses must be submitted within 14 days of returning to the home office using the standard expense form on the company intranet. Original receipts are required for any single expense over USD 50.\n\nFor assistance, contact the International Travel Desk at travel@horizonfg.com.", "passageTitle": "Travel Advisory", "type": "single", "questions": [{"id": "n7-3a", "part": 7, "question": "What is this document?", "options": ["A tourist guidebook", "A visa application form", "A company travel advisory", "A health and safety policy"], "answer": 2, "explanation": "\u2705 <b>Company travel advisory</b>. <br>\ud83d\udca1 <i>Ti\u00eau \u0111\u1ec1:</i> 'TRAVEL ADVISORY' t\u1eeb Horizon Financial Group.", "difficulty": "medium"}, {"id": "n7-3b", "part": 7, "question": "How far in advance should employees check visa requirements?", "options": ["1 week", "2 weeks", "4 weeks", "8 weeks"], "answer": 2, "explanation": "\u2705 <b>4 weeks</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'check visa requirements at least 4 weeks prior to departure'.", "difficulty": "medium"}, {"id": "n7-3c", "part": 7, "question": "What should employees do with business cards when meeting Vietnamese counterparts?", "options": ["Keep them in their wallet", "Present them with one hand", "Present them with both hands", "Decline to offer them in the first meeting"], "answer": 2, "explanation": "\u2705 <b>Present them with both hands</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'present them with both hands as a sign of respect'.", "difficulty": "medium"}, {"id": "p7-s-v04", "part": 7, "question": "What can be inferred about the purpose of the travel advisory?", "options": ["To discourage all travel to the destination", "To ensure employees are adequately prepared for the trip", "To announce a new corporate travel policy", "To introduce a new travel booking system"], "answer": 1, "explanation": "Inference: The advisory provides practical preparation information rather than discouraging travel \u2014 its purpose is to equip travellers with what they need to know."}]}, {"passage": "[Document 1 \u2013 Job Advertisement]\n\nVACANCY: Senior Financial Analyst\nCompany: Meridian Capital Partners\nLocation: Singapore (Hybrid \u2013 3 days on-site)\nSalary: SGD 90,000 \u2013 115,000 annually + performance bonus\n\nMeridian Capital Partners is a leading investment advisory firm with offices across Asia-Pacific. We are seeking a Senior Financial Analyst to join our Singapore team.\n\nKey Requirements:\n\u2022 Bachelor's degree in Finance, Accounting, or related field (MBA or CFA preferred)\n\u2022 Minimum 5 years of financial analysis experience\n\u2022 Proficiency in Excel, Bloomberg Terminal, and Python\n\u2022 Strong communication skills in English; Mandarin is an advantage\n\nResponsibilities include: conducting company valuations, preparing investment research reports, presenting findings to senior management, and monitoring portfolio performance.\n\nApplication deadline: October 20. Send your CV and cover letter to: careers@meridiancapital.sg\n\n[Document 2 \u2013 Cover Letter]\n\nFrom: Angela Yu <a.yu@email.com>\nTo: careers@meridiancapital.sg\nDate: October 14\n\nDear Hiring Manager,\n\nI am writing to apply for the Senior Financial Analyst role at Meridian Capital Partners. I hold an MBA from the National University of Singapore and have over six years of experience in equity research and portfolio analysis at DBS Bank.\n\nIn my current role, I regularly use Excel and Bloomberg Terminal, and I recently completed an online Python course to further strengthen my analytical toolkit. I am also fluent in both English and Mandarin, which I believe will be a valuable asset in your regional operations.\n\nI am particularly excited about Meridian's focus on Asia-Pacific markets, an area I have followed closely throughout my career. I would welcome the opportunity to contribute my expertise to your team.\n\nI look forward to hearing from you.\nSincerely,\nAngela Yu", "passageTitle": "Job Advertisement + Cover Letter", "type": "double", "questions": [{"id": "n7-4a", "part": 7, "question": "What is the maximum salary offered for the position?", "options": ["SGD 90,000", "SGD 100,000", "SGD 115,000", "SGD 120,000"], "answer": 2, "explanation": "\u2705 <b>SGD 115,000</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'Salary: SGD 90,000 \u2013 115,000 annually'.", "difficulty": "medium"}, {"id": "n7-4b", "part": 7, "question": "Which qualification listed as preferred does Angela Yu possess?", "options": ["CFA certification", "MBA degree", "Bachelor's in Accounting", "CPA designation"], "answer": 1, "explanation": "\u2705 <b>MBA degree</b>. <br>\ud83d\udca1 <i>K\u1ebft n\u1ed1i:</i> JD y\u00eau c\u1ea7u 'MBA or CFA preferred', Angela Yu c\u00f3 'MBA from the National University of Singapore'.", "difficulty": "medium"}, {"id": "n7-4c", "part": 7, "question": "How does Angela Yu's Python proficiency compare to the job requirements?", "options": ["She exceeds the requirement with a formal degree", "She meets it with years of experience", "She recently obtained the skill through a course", "She does not mention Python"], "answer": 2, "explanation": "\u2705 <b>Recently obtained via a course</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'I recently completed an online Python course'.", "difficulty": "medium"}, {"id": "n7-4d", "part": 7, "question": "What additional advantage does Angela Yu mention she has?", "options": ["Knowledge of financial regulations", "Fluency in Mandarin", "Prior experience at Meridian", "A network of regional clients"], "answer": 1, "explanation": "\u2705 <b>Fluency in Mandarin</b>. <br>\ud83d\udca1 <i>K\u1ebft n\u1ed1i:</i> JD n\u00f3i 'Mandarin is an advantage', Angela n\u00f3i 'I am also fluent in both English and Mandarin'.", "difficulty": "medium"}, {"id": "n7-4x", "part": 7, "question": "Based on both documents, does Angela Yu meet all the requirements listed as essential in the job advertisement?", "options": ["Yes, she meets all essential requirements", "No, she lacks the required Python proficiency", "No, she does not have experience in financial services", "Yes, but she does not meet the preferred qualification for CFA"], "answer": 0, "explanation": "Cross-document: Doc1 essential requirements = CFA/CPA + Python + financial modelling. Doc2: Angela states she has Python skills and relevant qualifications. \u2192 She meets all essential requirements (CFA is \"preferred, not essential\")."}]}, {"passage": "[Document 1 \u2013 Email]\n\nFrom: Diana Cho <d.cho@nordicretail.com>\nTo: Marcus Webb <m.webb@nordicretail.com>\nDate: April 25\nSubject: Customer Satisfaction Survey \u2013 Q1 Results\n\nHi Marcus,\n\nPlease find attached the Q1 customer satisfaction survey results. Overall, the numbers look promising, though I wanted to draw your attention to a few key findings.\n\nFirst, our average satisfaction score has risen to 4.2 out of 5, up from 3.8 last quarter. However, product variety received the lowest rating, scoring just 3.4. Several customers also commented that wait times during peak hours are too long.\n\nI recommend we discuss these findings at next week's operations meeting. I'll prepare a more detailed breakdown by category beforehand. In the meantime, could you look into whether the checkout staffing levels are adequate during peak periods?\n\nThanks,\nDiana\n\n[Document 2 \u2013 Survey Summary]\n\nNordic Retail \u2013 Customer Satisfaction Survey Q1\nTotal Respondents: 412\nSurvey Period: January 1 \u2013 March 31\n\nCategory Scores (out of 5):\n\u2022 Staff Friendliness: 4.7\n\u2022 Store Cleanliness: 4.5\n\u2022 Checkout Speed: 3.6\n\u2022 Product Variety: 3.4\n\u2022 Overall Experience: 4.2\n\nTop Customer Comments:\n\u2022 \"Staff are always helpful and welcoming.\"\n\u2022 \"I wish there were more options for plant-based products.\"\n\u2022 \"Lines at checkout are too long on Saturday mornings.\"\n\nNote: Compared to Q4 of last year, overall satisfaction has increased by 0.4 points.", "passageTitle": "Email + Survey Results", "type": "double", "questions": [{"id": "n7-5a", "part": 7, "question": "What was the overall satisfaction score in Q4 of the previous year?", "options": ["3.4", "3.6", "3.8", "4.2"], "answer": 2, "explanation": "\u2705 <b>3.8</b>. <br>\ud83d\udca1 <i>T\u00ednh to\u00e1n:</i> Hi\u1ec7n t\u1ea1i 4.2, t\u0103ng 0.4 so v\u1edbi qu\u00fd tr\u01b0\u1edbc \u2192 4.2 - 0.4 = 3.8.", "difficulty": "medium"}, {"id": "n7-5v", "part": 7, "question": "What does Diana Cho most likely want Marcus Webb to do as a result of the survey data?", "options": ["Publish the survey results to all customers", "Investigate the cause of declining satisfaction and propose solutions", "Hire additional staff for weekend shifts", "Redesign the customer feedback questionnaire"], "answer": 1, "explanation": "Inference: Diana asks Marcus to \"look into\" specific issues \u2014 implying she wants him to investigate and address them, not just acknowledge the data."}, {"id": "n7-5c", "part": 7, "question": "Based on the survey, what received the highest rating?", "options": ["Overall Experience", "Checkout Speed", "Staff Friendliness", "Product Variety"], "answer": 2, "explanation": "\u2705 <b>Staff Friendliness</b> (4.7). <br>\ud83d\udca1 <i>So s\u00e1nh:</i> Trong b\u1ea3ng \u0111i\u1ec3m, Staff Friendliness \u0111\u1ea1t 4.7, cao nh\u1ea5t.", "difficulty": "medium"}, {"id": "n7-5cd", "part": 7, "question": "Based on both documents, what does Diana Cho suggest is the relationship between Saturday morning staffing and survey scores?", "options": ["More staff on Saturdays directly caused the score increase", "Understaffing on Saturday mornings may be contributing to lower satisfaction", "Saturday morning customers are consistently more demanding than others", "The survey results do not provide enough data to draw conclusions about staffing"], "answer": 1, "explanation": "Cross-document: Survey shows lower scores + Diana's email asks Marcus to \"look into Saturday mornings\" \u2014 combining both implies she believes understaffing on Saturday mornings may explain the lower scores."}, {"id": "n7-5e", "part": 7, "question": "In Document 1, the word \"notable\" is closest in meaning to", "options": ["minor", "unusual", "significant", "expected"], "answer": 2, "explanation": "Word-in-context: \"notable\" = \u0111\u00e1ng ch\u00fa \u00fd, \u0111\u00e1ng k\u1ec3. \"Significant\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong v\u0103n b\u1ea3n kinh doanh. \"Minor\" = nh\u1ecf, ng\u01b0\u1ee3c ngh\u0129a."}]}, {"passage": "[Document 1 \u2013 Job Posting]\n\nPOSITION: Events Coordinator\nCompany: Apex Event Solutions\nLocation: Toronto, ON\nEmployment: Full-time, Permanent\nSalary: CAD 55,000 \u2013 65,000\n\nApex Event Solutions is a full-service event management company specializing in corporate conferences, product launches, and charity galas. We are looking for an organized, energetic Events Coordinator to join our team.\n\nRequirements:\n\u2022 Diploma or degree in Event Management, Hospitality, or related field\n\u2022 Minimum 2 years of event coordination experience\n\u2022 Proficiency in event management software (e.g., Cvent, Eventbrite)\n\u2022 Valid driver's license\n\u2022 Ability to work evenings and weekends as needed\n\nApplication Instructions:\nSend CV and cover letter to hr@apexevents.ca by August 15.\n\n[Document 2 \u2013 Application Email]\n\nFrom: Tyler Brooks <t.brooks@email.com>\nTo: hr@apexevents.ca\nDate: August 10\n\nDear HR Team,\n\nI am applying for the Events Coordinator position at Apex Event Solutions. I hold a diploma in Hospitality Management from Centennial College and have three years of experience coordinating events for a nonprofit organization in Toronto.\n\nI am highly proficient in Eventbrite and have recently begun training in Cvent. I hold a valid driver's license and am comfortable with weekend and evening work.\n\nI would be excited to bring my passion for event planning to Apex Event Solutions. Please find my CV attached.\n\nWarm regards,\nTyler Brooks\n\n[Document 3 \u2013 Interview Schedule]\n\nFrom: Sandra Lim <s.lim@apexevents.ca>\nTo: Tyler Brooks <t.brooks@email.com>\nDate: August 22\n\nDear Mr. Brooks,\n\nThank you for your application. We are pleased to invite you to an interview on Tuesday, September 3, at 10:00 a.m. at our office (200 Bay Street, Suite 1500, Toronto).\n\nThe interview will be conducted by our Events Director, Ms. Patricia Allen, and will last approximately one hour. You will be asked to complete a brief practical exercise related to event planning as part of the interview process.\n\nPlease confirm your availability by replying to this email by August 28.\n\nKind regards,\nSandra Lim\nHR Coordinator", "passageTitle": "Job Posting + Application Email + Interview Schedule", "type": "triple", "questions": [{"id": "n7-6a", "part": 7, "question": "What is the minimum salary for the Events Coordinator position?", "options": ["CAD 45,000", "CAD 55,000", "CAD 65,000", "CAD 75,000"], "answer": 1, "explanation": "\u2705 <b>CAD 55,000</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'Salary: CAD 55,000 \u2013 65,000'.", "difficulty": "medium"}, {"id": "n7-6b", "part": 7, "question": "How does Tyler Brooks' experience compare to the job requirements?", "options": ["He lacks the required qualification", "He meets the minimum experience requirement", "He has more experience than required", "He does not have a valid driver's license"], "answer": 2, "explanation": "\u2705 <b>More experience than required</b>. <br>\ud83d\udca1 <i>So s\u00e1nh:</i> JD y\u00eau c\u1ea7u 2 n\u0103m, Tyler c\u00f3 3 n\u0103m kinh nghi\u1ec7m.", "difficulty": "medium"}, {"id": "n7-6c", "part": 7, "question": "What does Tyler Brooks mention about Cvent?", "options": ["He has been using it for three years", "He is an expert in it", "He is currently being trained in it", "He does not know the software"], "answer": 2, "explanation": "\u2705 <b>Currently being trained</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'have recently begun training in Cvent'.", "difficulty": "medium"}, {"id": "n7-6d", "part": 7, "question": "What will Tyler Brooks be required to do during the interview?", "options": ["Give a 30-minute presentation", "Complete a written grammar test", "Participate in a practical event planning exercise", "Meet with three different managers"], "answer": 2, "explanation": "\u2705 <b>Practical event planning exercise</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'complete a brief practical exercise related to event planning'.", "difficulty": "medium"}, {"id": "n7-6e", "part": 7, "question": "By what date must Tyler Brooks confirm his availability?", "options": ["August 10", "August 15", "August 22", "August 28"], "answer": 3, "explanation": "\u2705 <b>August 28</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'confirm your availability by replying to this email by August 28'.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Website Notice]\n\nSTAR FITNESS APP \u2013 SERVICE UPDATE\nPosted: October 1\n\nDear Star Fitness Members,\n\nWe are excited to announce that Star Fitness will be launching its redesigned mobile application on October 15. The new app includes a personalized workout planner, nutrition tracker, and live class booking feature.\n\nExisting subscribers will be migrated to the new platform automatically. Please note that your existing workout history and preferences will be transferred to the new app. The legacy app will remain accessible until November 30, after which it will be retired.\n\nAll current memberships will continue under their existing terms. New annual subscriptions will be priced at $89/year (previously $79/year).\n\n[Document 2 \u2013 Member Email]\n\nFrom: Rachel Stone <r.stone@email.com>\nTo: support@starfitness.com\nDate: October 8\n\nHello,\n\nI recently saw the update on your website regarding the new app. I am an existing annual subscriber \u2014 my renewal is coming up in November.\n\nI have two questions:\n1. Will my November renewal be charged at the old rate ($79) or the new rate ($89)?\n2. My workout history goes back about two years \u2014 will all of it transfer?\n\nThank you for your assistance.\nRachel Stone\n\n[Document 3 \u2013 Support Response]\n\nFrom: Star Fitness Support <support@starfitness.com>\nTo: Rachel Stone <r.stone@email.com>\nDate: October 10\n\nDear Ms. Stone,\n\nThank you for reaching out.\n\nRegarding your renewal: since your subscription was active before October 15, your November renewal will be honored at the existing rate of $79. The new pricing applies only to subscriptions initiated after the launch date.\n\nAs for your workout history, we are pleased to confirm that all historical data \u2014 including sessions logged up to two years prior \u2014 will be transferred to the new app automatically. Any data older than two years may need to be manually imported; instructions will be included in the app's help section.\n\nPlease don't hesitate to contact us if you have any further questions.\n\nBest regards,\nStar Fitness Support Team", "passageTitle": "Notice + Customer Email + Company Response", "type": "triple", "questions": [{"id": "n7-7a", "part": 7, "question": "What is the price of a new annual Star Fitness subscription after October 15?", "options": ["$69/year", "$79/year", "$89/year", "$99/year"], "answer": 2, "explanation": "\u2705 <b>$89/year</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'New annual subscriptions will be priced at $89/year'.", "difficulty": "medium"}, {"id": "n7-7b", "part": 7, "question": "What is Rachel Stone concerned about?", "options": ["The quality of the new app's design", "Her subscription renewal price and workout data", "The retirement of the old app", "The new nutrition tracking feature"], "answer": 1, "explanation": "\u2705 <b>Renewal price and workout data</b>. <br>\ud83d\udca1 <i>Ph\u00e2n t\u00edch:</i> Email c\u1ee7a Rachel h\u1ecfi v\u1ec1 gi\u00e1 gia h\u1ea1n v\u00e0 l\u1ecbch s\u1eed t\u1eadp luy\u1ec7n.", "difficulty": "medium"}, {"id": "n7-7c", "part": 7, "question": "How much will Rachel Stone pay for her November renewal?", "options": ["$69", "$79", "$89", "$99"], "answer": 1, "explanation": "\u2705 <b>$79</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'your November renewal will be honored at the existing rate of $79'.", "difficulty": "medium"}, {"id": "n7-7d", "part": 7, "question": "What does the support response say about Rachel's two-year workout history?", "options": ["It will be lost during migration", "It can only be accessed on the old app", "It will be transferred automatically", "It must be exported by Rachel manually"], "answer": 2, "explanation": "\u2705 <b>Transferred automatically</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'sessions logged up to two years prior \u2014 will be transferred to the new app automatically'.", "difficulty": "medium"}, {"id": "n7-7e", "part": 7, "question": "What will happen to data older than two years?", "options": ["It will be deleted permanently", "It will transfer automatically like recent data", "It will require manual import with instructions provided", "It will be emailed to the user"], "answer": 2, "explanation": "\u2705 <b>Manual import with instructions</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'Any data older than two years may need to be manually imported'.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Product Brochure Excerpt]\n\nINTRODUCING THE LUMINO DESK LAMP \u2013 Model L300\nManufacturer: Solara Home Products\n\nThe Lumino L300 is our most advanced desk lamp, designed for home office and professional use.\n\nKey Features:\n\u2022 Three adjustable color temperature modes: Cool White, Neutral, Warm\n\u2022 5-level brightness control\n\u2022 USB-A charging port on base\n\u2022 Touch control panel\n\u2022 Energy-efficient LED \u2014 50,000-hour lifespan\n\u2022 2-year manufacturer's warranty\n\nRetail Price: $79.99\n\nFor warranty claims and support, visit www.solarahome.com/support or call 1-800-765-4321.\n\n[Document 2 \u2013 Online Customer Review]\n\nReviewer: T. Harrison | Rating: 3 out of 5 stars\nPosted: February 20\n\nI purchased the Lumino L300 about six months ago and overall it performs well for reading and working. The color temperature options are genuinely useful and the brightness range is excellent.\n\nHowever, I was disappointed to find that the USB charging port stopped working after only three months. I checked the product listing and it clearly states a 2-year warranty, but when I contacted customer service, I was initially told the USB port wasn't covered. I pushed back, and they eventually agreed to send a replacement unit, but the process took three weeks.\n\nThe product itself is good, but customer service needs improvement.\n\n[Document 3 \u2013 Company Response]\n\nPosted by Solara Home Products \u2013 February 25\n\nDear T. Harrison,\n\nThank you for your feedback. We sincerely apologize for the confusion regarding warranty coverage. To clarify, all components of the Lumino L300, including the USB charging port, are covered under the 2-year manufacturer's warranty. We are sorry that this was not communicated clearly during your initial contact with our team.\n\nWe have taken note of your experience and are retraining our customer support team to ensure consistent and accurate warranty information is provided from the outset.\n\nWe hope the replacement unit is serving you well. Should you experience any further issues, please do not hesitate to reach out to us directly.\n\nWarm regards,\nSolara Home Products Customer Relations", "passageTitle": "Product Brochure + Customer Review + Company Reply", "type": "triple", "questions": [{"id": "n7-8a", "part": 7, "question": "How many brightness levels does the Lumino L300 offer?", "options": ["3", "4", "5", "6"], "answer": 2, "explanation": "\u2705 <b>5</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> '5-level brightness control'.", "difficulty": "medium"}, {"id": "n7-8b", "part": 7, "question": "What issue did T. Harrison experience with the product?", "options": ["The touch panel stopped working", "The color temperature stopped changing", "The USB charging port failed", "The LED burned out early"], "answer": 2, "explanation": "\u2705 <b>USB charging port failed</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'the USB charging port stopped working after only three months'.", "difficulty": "medium"}, {"id": "n7-8c", "part": 7, "question": "What was T. Harrison initially told by customer service?", "options": ["The lamp was out of warranty", "The USB port was not covered by warranty", "A replacement would be sent immediately", "The product was discontinued"], "answer": 1, "explanation": "\u2705 <b>Not covered by warranty</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'I was initially told the USB port wasn't covered'.", "difficulty": "medium"}, {"id": "n7-8d", "part": 7, "question": "According to Solara's response, what action are they taking following this complaint?", "options": ["Redesigning the USB port", "Offering refunds to all customers", "Retraining their customer support team", "Extending the warranty to 3 years"], "answer": 2, "explanation": "\u2705 <b>Retraining customer support</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> 'we are retraining our customer support team'.", "difficulty": "medium"}, {"id": "n7-8e", "part": 7, "question": "What can be inferred about the USB port's warranty coverage?", "options": ["It was excluded from the original warranty", "It is covered under the 2-year warranty per company policy", "It requires a separate warranty purchase", "It is only covered if registered online"], "answer": 1, "explanation": "\u2705 <b>Covered under 2-year warranty</b>. <br>\ud83d\udca1 <i>D\u1eabn ch\u1ee9ng:</i> Solara kh\u1eb3ng \u0111\u1ecbnh 'all components... are covered under the 2-year manufacturer's warranty'.", "difficulty": "medium"}]}, {"passage": "JOB OPPORTUNITY\n\nPosition: Digital Marketing Specialist\nCompany: BrightPath Media Group\nLocation: Ho Chi Minh City, Vietnam (On-site)\nSalary: VND 25,000,000 \u2013 35,000,000/month\nEmployment Type: Full-Time, Permanent\n\nBrightPath Media Group is a leading digital marketing agency specializing in content strategy, social media management, and performance advertising. We are seeking a talented and results-driven Digital Marketing Specialist to join our growing team.\n\nKey Responsibilities:\n\u2022 Develop and execute multi-channel digital marketing campaigns\n\u2022 Manage paid advertising campaigns (Google Ads, Meta Ads)\n\u2022 Analyze campaign performance using Google Analytics and prepare weekly reports\n\u2022 Collaborate with the creative team on content development\n\nRequirements:\n\u2022 Minimum 2 years of experience in digital marketing\n\u2022 Google Ads certification preferred\n\u2022 Strong analytical skills and proficiency in Excel\n\u2022 Excellent written and verbal communication skills in English and Vietnamese\n\nBenefits: 13th month salary, health insurance, annual performance review, and 15 days of paid leave.\n\nTo apply, send your CV and portfolio to careers@brightpathmedia.vn by August 30.\nOnly shortlisted candidates will be notified.", "passageTitle": "Job Posting: Digital Marketing Specialist", "type": "single", "questions": [{"id": "b7-s1a", "part": 7, "question": "What type of company is BrightPath Media Group?", "options": ["A technology startup", "A digital marketing agency", "A television production house", "A financial consulting firm"], "answer": 1, "explanation": "'BrightPath Media Group is a leading digital marketing agency'.", "difficulty": "medium"}, {"id": "b7-s1b", "part": 7, "question": "Which skill is listed as preferred but not required?", "options": ["Proficiency in Excel", "Communication skills in Vietnamese", "Google Ads certification", "Experience in content development"], "answer": 2, "explanation": "'Google Ads certification preferred' = \u01b0u ti\u00ean nh\u01b0ng kh\u00f4ng b\u1eaft bu\u1ed9c.", "difficulty": "medium"}, {"id": "b7-s1c", "part": 7, "question": "How many days of paid leave are offered?", "options": ["10 days", "12 days", "13 days", "15 days"], "answer": 3, "explanation": "'15 days of paid leave' n\u00eau trong ph\u1ea7n Benefits.", "difficulty": "medium"}, {"id": "p7-s-v05", "part": 7, "question": "Which of the following is NOT mentioned as a job requirement?", "options": ["Experience with social media platforms", "A university degree in marketing", "Proficiency in data analysis tools", "Knowledge of digital advertising platforms"], "answer": 1, "explanation": "NOT TRUE: Review the job requirements listed. A specific university degree is typically NOT listed as a hard requirement in this posting \u2014 experience and skills are prioritised."}]}, {"passage": "From: Rachel Moore <r.moore@cedarwoodshops.com>\nTo: Kevin Tanaka <k.tanaka@email.com>\nDate: September 16\nSubject: RE: Order #CW-44821 \u2013 Delayed Delivery\n\nDear Mr. Tanaka,\n\nThank you for bringing this matter to our attention. I sincerely apologize for the delay in delivering your order, which was originally estimated to arrive on September 10.\n\nAfter conducting a thorough investigation, we have determined that the delay was caused by an unexpected inventory error at our distribution center in Melbourne, which resulted in your items being held for an additional five business days.\n\nI am pleased to inform you that your order has now been dispatched and is currently in transit. Based on the updated tracking information, delivery is expected by September 19.\n\nAs an apology for the inconvenience, we have added a store credit of AUD 25 to your account, which can be applied to any future purchase. Additionally, shipping fees for this order have been fully waived.\n\nWe value your patronage and appreciate your patience. Should you have any further concerns, please do not hesitate to contact our support team.\n\nWarm regards,\nRachel Moore\nCustomer Relations Manager, Cedarwood Shops", "passageTitle": "Email: RE: Order #CW-44821 \u2013 Delayed Delivery", "type": "single", "questions": [{"id": "b7-s2a", "part": 7, "question": "Why was Mr. Tanaka's order delayed?", "options": ["A courier service problem", "An inventory error at the distribution center", "A delay in payment processing", "A public holiday in Melbourne"], "answer": 1, "explanation": "'delay was caused by an unexpected inventory error at our distribution center in Melbourne'.", "difficulty": "medium"}, {"id": "b7-s2b", "part": 7, "question": "When is the order now expected to arrive?", "options": ["September 10", "September 14", "September 16", "September 19"], "answer": 3, "explanation": "'delivery is expected by September 19'.", "difficulty": "medium"}, {"id": "b7-s2c", "part": 7, "question": "What compensation did the company offer?", "options": ["A full refund", "A replacement item and a discount", "Store credit and free shipping", "A gift card and priority delivery"], "answer": 2, "explanation": "'store credit of AUD 25' v\u00e0 'shipping fees for this order have been fully waived'.", "difficulty": "medium"}, {"id": "b7-s2d", "part": 7, "question": "What can be inferred about Cedarwood Shops?", "options": ["It only sells products online", "It has a distribution center outside Australia", "It is based in Melbourne", "It has store credit programs for customers"], "answer": 3, "explanation": "C\u00f4ng ty \u0111\u00e3 c\u1ed9ng store credit v\u00e0o t\u00e0i kho\u1ea3n \u2192 c\u00f3 ch\u01b0\u01a1ng tr\u00ecnh store credit.", "difficulty": "medium"}]}, {"passage": "FOR IMMEDIATE RELEASE\n\nVertexLink Acquires CloudNest Analytics to Strengthen Data Intelligence Capabilities\n\nSAN JOSE, October 22 \u2013 VertexLink Corporation (NASDAQ: VTLK) today announced the acquisition of CloudNest Analytics, a leading provider of real-time business intelligence solutions, for approximately USD 420 million in cash and stock.\n\nCloudNest Analytics serves more than 800 enterprise clients across North America and Europe, including five Fortune 500 companies. Its flagship product, DataPulse, provides organizations with real-time dashboards and predictive analytics capabilities.\n\n\"This acquisition accelerates our vision of delivering end-to-end data intelligence solutions to our global enterprise customers,\" said Marcus Chen, CEO of VertexLink. \"CloudNest's technology and talent are a perfect strategic fit.\"\n\nThe transaction is subject to regulatory approvals and is expected to close in the first quarter of the coming year. CloudNest Analytics will continue to operate under its own brand until integration is complete.\n\nAbout VertexLink Corporation: VertexLink is a global technology company headquartered in San Jose, California, providing enterprise software solutions to over 3,500 clients in 40 countries.\n\nMedia Contact: press@vertexlink.com", "passageTitle": "Press Release", "type": "single", "questions": [{"id": "b7-s3a", "part": 7, "question": "What is the purpose of this press release?", "options": ["To announce a new product launch", "To report quarterly earnings results", "To announce the acquisition of a company", "To introduce a new CEO"], "answer": 2, "explanation": "Press release th\u00f4ng b\u00e1o VertexLink mua l\u1ea1i CloudNest Analytics.", "difficulty": "medium"}, {"id": "b7-s3b", "part": 7, "question": "What is DataPulse?", "options": ["A new VertexLink product", "CloudNest's flagship product", "A Fortune 500 company client", "A financial analytics platform"], "answer": 1, "explanation": "'Its flagship product, DataPulse, provides...' \u2013 'Its' refers to CloudNest Analytics.", "difficulty": "medium"}, {"id": "b7-s3c", "part": 7, "question": "When is the transaction expected to be finalized?", "options": ["By the end of October", "In the first quarter of next year", "After regulatory approvals in six months", "Immediately following the announcement"], "answer": 1, "explanation": "'expected to close in the first quarter of the coming year'.", "difficulty": "medium"}, {"id": "p7-s-v26", "part": 7, "question": "What can be inferred about DataPulse's position in the market?", "options": ["It is a market leader that acquired a smaller competitor", "It is a startup seeking to establish itself through acquisition", "It is expanding its capabilities to enter the data analytics space", "It is merging with CloudNest to reduce competition"], "answer": 2, "explanation": "Inference: The press release describes DataPulse acquiring CloudNest Analytics \u2014 suggesting DataPulse is strengthening/expanding into analytics, implying it is growing its capabilities in that space."}]}, {"passage": "NOTICE\n\nLibrary Services \u2013 Temporary Closure of Reference Section\n\nThe Reference Section of the Westgate City Library will be closed for refurbishment from Monday, April 7 through Friday, April 18. All other areas of the library, including the general lending floors, the digital resource room, and the children's section, will remain open during normal hours.\n\nDuring the closure, patrons requiring access to reference materials may use the Eastdale Branch Library, located at 1245 Eastdale Drive, which is open Monday through Saturday, 9:00 a.m. to 7:00 p.m.\n\nOnline access to e-books, academic journals, and digital databases will continue without interruption and is available 24 hours a day at library.westgatecity.org.\n\nAll items currently on loan from the Reference Section are due to be returned by April 5. Late returns will not incur fines during the closure period.\n\nWe apologize for any inconvenience this may cause and look forward to welcoming you to an improved Reference Section when it reopens on April 21.\n\nWestgate City Library Management", "passageTitle": "Notice: Library Services \u2013 Temporary Closure of", "type": "single", "questions": [{"id": "b7-s4a", "part": 7, "question": "Which part of the library will be temporarily closed?", "options": ["The children's section", "The digital resource room", "The general lending floors", "The Reference Section"], "answer": 3, "explanation": "'The Reference Section of the Westgate City Library will be closed for refurbishment'.", "difficulty": "medium"}, {"id": "b7-s4b", "part": 7, "question": "Where can patrons go for reference materials during the closure?", "options": ["The Westgate City Library digital portal", "The Eastdale Branch Library", "The downtown community center", "An affiliated university library"], "answer": 1, "explanation": "'patrons requiring access to reference materials may use the Eastdale Branch Library'.", "difficulty": "medium"}, {"id": "b7-s4c", "part": 7, "question": "What happens to late returns during the closure period?", "options": ["Fines are doubled", "Fines are charged at the standard rate", "No fines will be charged", "Items must be returned before the closure begins"], "answer": 2, "explanation": "'Late returns will not incur fines during the closure period'.", "difficulty": "medium"}, {"id": "p7-s-v27", "part": 7, "question": "Which of the following is NOT stated in the closure notice?", "options": ["The reason for the closure", "The duration of the closure", "The location of temporary reference services", "The hours of operation during the closure"], "answer": 3, "explanation": "NOT TRUE: The notice states the reason (refurbishment), duration, and temporary service location. Operating hours during the closure are NOT mentioned in the notice."}]}, {"passage": "EMPLOYEE WELLNESS SURVEY \u2013 SUMMARY REPORT\nIsland Pacific Group | Prepared by: People & Culture Team\nSurvey Period: August 1\u201315 | Total Respondents: 287 (out of 312 staff)\n\nKEY FINDINGS\n\nOverall Job Satisfaction: 74% of respondents reported feeling satisfied or very satisfied with their roles, a 6-point increase compared to last year's survey.\n\nWork-Life Balance: 61% of employees reported that their current workload allows for adequate personal time. However, 38% indicated they regularly work beyond their contracted hours, with this figure highest among staff in the Finance and Operations departments.\n\nProfessional Development: 82% expressed a desire for more structured training and career development opportunities. The top requested programs were leadership development (48%), technical skills training (35%), and language learning (17%).\n\nWorkplace Environment: The canteen facilities and the open-plan office layout were rated as the top two areas for improvement. Conversely, team collaboration and management support received the highest satisfaction scores.\n\nRECOMMENDATIONS\nBased on these results, the People & Culture Team recommends: (1) introducing a capped overtime policy for Finance and Operations staff; (2) launching a structured development program with quarterly workshops; and (3) initiating a canteen upgrade in Q1 next year.", "passageTitle": "Employee Survey Report", "type": "single", "questions": [{"id": "b7-s5a", "part": 7, "question": "What percentage of staff responded to the survey?", "options": ["61%", "74%", "82%", "The majority of the 312 staff"], "answer": 3, "explanation": "287 out of 312 responded. 287/312 \u2248 92% \u2192 'the majority'. Kh\u00f4ng c\u00f3 con s\u1ed1 92% n\u00e0o trong \u0111\u00e1p \u00e1n \u2192 ch\u1ecdn 'The majority'.", "difficulty": "medium"}, {"id": "b7-s5b", "part": 7, "question": "Which departments had the highest rate of overtime work?", "options": ["Marketing and Sales", "HR and Legal", "Finance and Operations", "IT and Communications"], "answer": 2, "explanation": "'this figure highest among staff in the Finance and Operations departments'.", "difficulty": "medium"}, {"id": "b7-s5c", "part": 7, "question": "What was the most requested type of professional development?", "options": ["Technical skills training", "Language learning", "Leadership development", "Project management"], "answer": 2, "explanation": "'leadership development (48%)' = t\u1ec9 l\u1ec7 cao nh\u1ea5t trong ba l\u1ef1a ch\u1ecdn.", "difficulty": "medium"}, {"id": "p7-s-v06", "part": 7, "question": "In the report, the word \"predominantly\" is closest in meaning to", "options": ["consistently", "largely", "occasionally", "significantly"], "answer": 1, "explanation": "WIC: \"predominantly\" = ch\u1ee7 y\u1ebfu, ph\u1ea7n l\u1edbn. \"Largely\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t. \"Consistently\" = \u0111\u1ec1u \u0111\u1eb7n (kh\u00e1c ngh\u0129a), \"significantly\" = \u0111\u00e1ng k\u1ec3."}]}, {"passage": "DISCOVER SONOVA ISLAND\nA Premier Luxury Eco-Resort Experience\n\nNestled among the pristine coral reefs of the Andaman Sea, Sonova Island Resort offers an unrivaled escape for discerning travelers who seek both luxury and environmental responsibility.\n\nOur 42 overwater villas and beachfront suites are designed with locally sourced materials and feature panoramic ocean views, private infinity pools, and 24-hour butler service. Each villa is powered entirely by solar energy.\n\nGUEST EXPERIENCES:\n\u2022 Guided snorkeling and scuba diving excursions led by certified marine biologists\n\u2022 Farm-to-table dining at our award-winning Coral Table restaurant\n\u2022 Daily yoga and wellness retreats with resident instructors\n\u2022 Cultural tours of the neighboring fishing villages\n\nSUSTAINABILITY PLEDGE:\nSonova Island is proud to hold the Global Eco-Certification Platinum designation, the highest rating available. We employ over 80% of our staff from local communities and donate 5% of all revenue to coral reef restoration programs.\n\nRATES & AVAILABILITY:\nRates start from USD 850 per night. A minimum stay of three nights is required during peak season (December\u2013February). Early booking discounts of 15% are available for reservations made more than 90 days in advance.\n\nBook now: www.sonovaisland.com | +66 76 521 9900", "passageTitle": "Resort Advertisement", "type": "single", "questions": [{"id": "b7-s6a", "part": 7, "question": "What is unique about the energy source for the villas?", "options": ["They use wind turbines", "They are powered by solar energy", "They rely on the local power grid", "They use hydroelectric power"], "answer": 1, "explanation": "'Each villa is powered entirely by solar energy'.", "difficulty": "medium"}, {"id": "b7-s6b", "part": 7, "question": "What certification does Sonova Island hold?", "options": ["ISO 14001 Environmental Management", "Green Globe Standard", "Global Eco-Certification Platinum", "UNESCO World Heritage Eco-Status"], "answer": 2, "explanation": "'Sonova Island is proud to hold the Global Eco-Certification Platinum designation'.", "difficulty": "medium"}, {"id": "b7-s6c", "part": 7, "question": "During which months is a minimum three-night stay required?", "options": ["June through August", "September through November", "December through February", "March through May"], "answer": 2, "explanation": "'minimum stay of three nights is required during peak season (December\u2013February)'.", "difficulty": "medium"}, {"id": "p7-s-v28", "part": 7, "question": "In the advertisement, the word \"pristine\" is closest in meaning to", "options": ["untouched", "tropical", "remote", "scenic"], "answer": 0, "explanation": "WIC: \"pristine coral reefs\" = san h\u00f4 nguy\u00ean s\u01a1, ch\u01b0a b\u1ecb t\u00e1c \u0111\u1ed9ng. \"Untouched\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t, nh\u1ea5n m\u1ea1nh s\u1ef1 trong l\u00e0nh, ch\u01b0a b\u1ecb \u00f4 nhi\u1ec5m."}]}, {"passage": "EMPLOYEE BENEFITS GUIDE\nKaleidoscope Consulting Group\nEffective January 1, Current Year\n\nHEALTH & WELLNESS\nAll full-time employees are enrolled in the company's Premier Health Plan from their first day of employment. This plan covers 100% of inpatient hospital costs and 80% of outpatient services, including specialist consultations. Dental and vision coverage is optional and can be added during the annual enrollment window (November 1\u201315) or within 30 days of a qualifying life event.\n\nRETIREMENT SAVINGS\nKaleidoscope offers a matching contribution to the company's registered pension scheme. The company matches employee contributions up to 5% of gross annual salary. Employees become fully vested after 36 months of continuous employment.\n\nPROFESSIONAL DEVELOPMENT\nEach employee receives an annual learning allowance of USD 1,500 for approved courses, certifications, or conferences. Unused allowances cannot be carried over to the following year. Requests for learning activities must be submitted at least 30 days before the event.\n\nPARENTAL LEAVE\nPrimary caregivers are entitled to 18 weeks of fully paid parental leave. Secondary caregivers receive 4 weeks of paid leave. Leave may be taken at any point within the first 12 months following the birth or adoption of a child.\n\nFor full policy details, visit the HR portal at hr.kaleidoscopecg.com.", "passageTitle": "Employee Benefits Guide", "type": "single", "questions": [{"id": "b7-s7a", "part": 7, "question": "What percentage of outpatient services is covered by the Premier Health Plan?", "options": ["50%", "80%", "100%", "It depends on the service type"], "answer": 1, "explanation": "'80% of outpatient services, including specialist consultations'.", "difficulty": "medium"}, {"id": "b7-s7b", "part": 7, "question": "When can employees add dental and vision coverage?", "options": ["Only during their first week of employment", "Only during the annual enrollment window", "During the annual enrollment window or within 30 days of a life event", "At any time of year"], "answer": 2, "explanation": "'can be added during the annual enrollment window (November 1\u201315) or within 30 days of a qualifying life event'.", "difficulty": "medium"}, {"id": "b7-s7c", "part": 7, "question": "What happens to unused learning allowances at year-end?", "options": ["They roll over to the following year", "They are added to the employee's salary", "They cannot be carried over", "They can be donated to a colleague"], "answer": 2, "explanation": "'Unused allowances cannot be carried over to the following year'.", "difficulty": "medium"}, {"id": "p7-s-v07", "part": 7, "question": "What can be inferred about the company's approach to employee wellness?", "options": ["It is mandatory for all employees to use wellness benefits", "It values employee wellbeing as part of its broader HR strategy", "It recently introduced wellness benefits for the first time", "It provides wellness benefits only to full-time staff"], "answer": 1, "explanation": "Inference: The comprehensive benefits guide suggests wellness is an intentional part of HR strategy, not a new or limited offering \u2014 inferred from the breadth and detail of coverage."}]}, {"passage": "PROFESSIONAL CERTIFICATION PROGRAM\nProject Management for Business Leaders\nOffered by: Harmon Institute of Business Excellence\n\nProgram Overview:\nThis intensive six-week online program is designed for mid-to-senior level managers seeking to formalize their project management expertise and earn internationally recognized certification.\n\nProgram Structure:\nThe course consists of four modules, each running for ten days. Participants will learn to apply agile and traditional project management frameworks, manage cross-functional teams, and use industry-standard tools including MS Project and Trello.\n\nAdmission Requirements:\n\u2022 Minimum 3 years of managerial experience\n\u2022 Bachelor's degree in any field\n\u2022 Submission of a 500-word professional statement\n\nSchedule & Fees:\nCohorts begin on the first Monday of each month. Program fee: USD 2,400, which includes all learning materials and the final certification exam. A payment plan option is available upon request.\n\nUpon successful completion, participants receive the Harmon Certified Project Manager (HCPM) designation, recognized in over 65 countries.\n\nApplication deadline: Applications must be submitted at least two weeks before the cohort start date.\n\nFor more information: admissions@harmonibe.org | +1 212 884 0031", "passageTitle": "Certification Programme", "type": "single", "questions": [{"id": "b7-s8a", "part": 7, "question": "Who is this program primarily designed for?", "options": ["Recent university graduates", "Entry-level employees", "Mid-to-senior level managers", "IT project coordinators only"], "answer": 2, "explanation": "'designed for mid-to-senior level managers seeking to formalize their project management expertise'.", "difficulty": "medium"}, {"id": "b7-s8b", "part": 7, "question": "How many modules does the course contain?", "options": ["3", "4", "5", "6"], "answer": 1, "explanation": "'The course consists of four modules, each running for ten days'.", "difficulty": "medium"}, {"id": "b7-s8c", "part": 7, "question": "What does the program fee include?", "options": ["Accommodation and meals", "Learning materials and the certification exam", "One-on-one mentoring sessions", "MS Project software license"], "answer": 1, "explanation": "'Program fee: USD 2,400, which includes all learning materials and the final certification exam'.", "difficulty": "medium"}, {"id": "p7-s-v08", "part": 7, "question": "In the programme description, the word \"rigorous\" is closest in meaning to", "options": ["challenging", "lengthy", "practical", "comprehensive"], "answer": 0, "explanation": "WIC: \"rigorous\" = nghi\u00eam ng\u1eb7t, \u0111\u00f2i h\u1ecfi cao. \"Challenging\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh m\u00f4 t\u1ea3 ch\u01b0\u01a1ng tr\u00ecnh \u0111\u00e0o t\u1ea1o chuy\u00ean nghi\u1ec7p."}]}, {"passage": "[Document 1 \u2013 Internal Memo]\n\nTo: Sales Department\nFrom: Marcus Webb, Regional Sales Director\nDate: March 5\n\nEffective April 1, our team's sales performance will be evaluated using a new Key Performance Indicator (KPI) framework. Under this system, each sales representative will be assessed across three dimensions: monthly revenue generation, client retention rate, and new business acquisition.\n\nThe minimum acceptable score for each dimension is 70 out of 100. Representatives who score below 70 in any dimension for two consecutive months will be placed on a Performance Improvement Plan (PIP).\n\nI will hold individual briefing sessions with each of you during the week of March 20 to explain the full details. Please come prepared with any questions you may have.\n\nMarcus Webb\nRegional Sales Director\n\n[Document 2 \u2013 Reply Email]\n\nFrom: Nina Park <n.park@company.com>\nTo: Marcus Webb <m.webb@company.com>\nDate: March 8\n\nDear Marcus,\n\nThank you for the advance notice regarding the new KPI framework. I appreciate the transparency.\n\nI do have a few preliminary questions that I hope we can discuss during our individual session. My main concern relates to the new business acquisition dimension, as our territory has seen limited inbound leads over the past quarter due to the economic slowdown. I want to ensure that contextual factors like this are taken into account during evaluations.\n\nAdditionally, I would like to understand whether the 70-point minimum threshold will apply uniformly across all regions, or whether regional adjustments will be made.\n\nLooking forward to our meeting during the week of March 20.\n\nBest regards,\nNina Park\nSenior Sales Representative", "passageTitle": "Internal Memo + Reply Email", "type": "double", "questions": [{"id": "b7-d1a", "part": 7, "question": "How many dimensions will sales representatives be evaluated on?", "options": ["Two", "Three", "Four", "Five"], "answer": 1, "explanation": "'three dimensions: monthly revenue generation, client retention rate, and new business acquisition'.", "difficulty": "medium"}, {"id": "b7-d1b", "part": 7, "question": "What triggers a Performance Improvement Plan?", "options": ["Missing one monthly target by more than 20%", "Scoring below 70 in all dimensions", "Scoring below 70 in any dimension for two consecutive months", "Failing to attend the individual briefing session"], "answer": 2, "explanation": "'Representatives who score below 70 in any dimension for two consecutive months will be placed on a PIP'.", "difficulty": "medium"}, {"id": "b7-d1c", "part": 7, "question": "What is Nina Park's primary concern about the new framework?", "options": ["The timing of the implementation", "Whether client retention will be weighted fairly", "That external market conditions might not be considered", "The frequency of performance evaluations"], "answer": 2, "explanation": "'I want to ensure that contextual factors like this are taken into account' \u2013 referring to limited leads due to economic slowdown.", "difficulty": "medium"}, {"id": "b7-d1x", "part": 7, "question": "Based on both documents, what aspect of the new performance framework does Nina Park find unclear as it relates to her own situation?", "options": ["Whether her current sales figures qualify her for a bonus", "How the 70-point threshold applies to part-time employees", "Whether client satisfaction scores are weighted differently for senior staff", "How the new criteria compare to the previous framework"], "answer": 1, "explanation": "Cross-document: Memo sets 70-point threshold. Nina's email asks specifically about how this threshold applies to part-time employees \u2014 combining info from both documents to identify her specific concern."}, {"id": "b7-d1e", "part": 7, "question": "When are the individual briefing sessions scheduled?", "options": ["During the week of March 5", "During the week of March 8", "During the week of March 20", "On April 1"], "answer": 2, "explanation": "'I will hold individual briefing sessions...during the week of March 20'.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Workshop Announcement]\n\nFINANCIAL LITERACY FOR ENTREPRENEURS\nA Half-Day Workshop\n\nDate: Saturday, November 9\nTime: 9:00 a.m. \u2013 1:00 p.m.\nVenue: The Business Hub, Level 3, 320 Collins Street, Melbourne\nFacilitator: Ms. Diane Pearce, CPA \u2013 Senior Financial Advisor, Clearview Group\n\nWho Should Attend: Small business owners and entrepreneurs who want to strengthen their understanding of financial statements, cash flow management, and tax planning strategies.\n\nSession Outline:\n\u2022 9:00 \u2013 9:30: Financial Statements Demystified\n\u2022 9:30 \u2013 10:30: Cash Flow Management in Practice\n\u2022 10:30 \u2013 10:45: Break\n\u2022 10:45 \u2013 12:00: Tax Planning for Business Owners\n\u2022 12:00 \u2013 1:00: Networking Lunch\n\nRegistration Fee: AUD 95 per person (includes workbook and lunch)\nEarly Bird Rate: AUD 75 (register before October 25)\n\nPlaces are limited to 30 participants. Register at: www.thebusinesshub.com.au/events\n\n[Document 2 \u2013 Registration Email]\n\nFrom: Jamie Reyes <j.reyes@email.com>\nTo: events@thebusinesshub.com.au\nDate: October 20\n\nHello,\n\nI would like to register for the Financial Literacy for Entrepreneurs workshop on November 9. I am a sole trader who recently started a caf\u00e9 business and I am particularly keen to attend the session on cash flow management.\n\nCould you please confirm whether the early bird rate is still available for registrations submitted today? I would also like to know whether the workbook can be accessed digitally, as I prefer to read on my tablet.\n\nFinally, are there any dietary options available at the networking lunch? I follow a vegetarian diet.\n\nThank you for your assistance.\n\nJamie Reyes", "passageTitle": "Workshop Flyer + Registration Email", "type": "double", "questions": [{"id": "b7-d2a", "part": 7, "question": "Who is the facilitator of the workshop?", "options": ["A tax lawyer from Clearview Group", "A senior financial advisor with a CPA qualification", "A small business consultant", "An entrepreneur and business owner"], "answer": 1, "explanation": "'Ms. Diane Pearce, CPA \u2013 Senior Financial Advisor, Clearview Group'.", "difficulty": "medium"}, {"id": "b7-d2b", "part": 7, "question": "Which session is Jamie Reyes most interested in attending?", "options": ["Tax Planning for Business Owners", "Financial Statements Demystified", "Cash Flow Management in Practice", "The Networking Lunch"], "answer": 2, "explanation": "'I am particularly keen to attend the session on cash flow management'.", "difficulty": "medium"}, {"id": "b7-d2c", "part": 7, "question": "If Jamie Reyes qualifies for the early bird rate, how much will the registration cost?", "options": ["AUD 75", "AUD 95", "AUD 85", "AUD 65"], "answer": 0, "explanation": "'Early Bird Rate: AUD 75 (register before October 25)'. Jamie sent the email on October 20 \u2192 qualifies.", "difficulty": "medium"}, {"id": "b7-d2x", "part": 7, "question": "Based on both documents, if Jamie Reyes registered on October 20 and qualifies for the early bird rate, how much would the registration fee be?", "options": ["AUD 45", "AUD 65", "AUD 75", "AUD 90"], "answer": 1, "explanation": "Cross-document: Flyer states early bird price. Jamie's email date is Oct 20 \u2014 need to check against early bird deadline in flyer. The combined reading gives: AUD 65 (early bird rate for members)."}, {"id": "b7-d2e", "part": 7, "question": "What additional information does Jamie Reyes request?", "options": ["The facilitator's contact information", "Whether the event will be recorded", "Dietary accommodations at lunch and digital workbook access", "The exact room number at the venue"], "answer": 2, "explanation": "Jamie h\u1ecfi hai \u0111i\u1ec1u: digital workbook v\u00e0 vegetarian options at the networking lunch.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Corporate Travel Policy Update]\n\nHorizon Dynamics \u2013 UPDATED CORPORATE TRAVEL POLICY\nEffective Date: February 1\n\nThe following changes have been made to the corporate travel policy:\n\n1. Airline Bookings: All domestic flights must be booked at least 14 days in advance unless approved as an emergency by a Vice President or above. International flights require 21 days advance booking.\n\n2. Hotel Accommodation: The standard allowance for hotel accommodation is USD 180 per night for domestic travel and USD 250 per night for international travel. Any hotel exceeding these limits requires pre-approval via the travel request portal.\n\n3. Meals and Incidentals: The daily per diem rate is USD 60 for domestic and USD 90 for international travel. Receipts are required for any single expense over USD 25.\n\n4. Expense Reports: All expense reports must be submitted within 10 business days of return from travel. Late submissions will require a written explanation to the Finance Director.\n\n[Document 2 \u2013 Employee Email]\n\nFrom: Carlos Mendoza <c.mendoza@horizondynamics.com>\nTo: Finance Department <finance@horizondynamics.com>\nDate: February 17\n\nHi,\n\nI returned from the Toronto client visit on February 14 and wanted to clarify a few points before submitting my expense report.\n\nDuring my stay, I was unable to find a hotel within the USD 180 domestic limit in the downtown area near the client's office. I ended up staying at a hotel for USD 215 per night for three nights. I believe I did obtain pre-approval from the VP of Sales before booking \u2013 can you confirm this was processed?\n\nAlso, I had a client dinner on February 12 that came to USD 148. Does this fall under the per diem, or is it classified separately as a client entertainment expense?\n\nFinally, I want to make sure my expense report submission deadline is correct. I believe it should be submitted by February 28 \u2013 is that accurate?\n\nThank you.\nCarlos Mendoza", "passageTitle": "Travel Policy Update + Employee Inquiry", "type": "double", "questions": [{"id": "b7-d3a", "part": 7, "question": "How far in advance must domestic flights typically be booked?", "options": ["7 days", "10 days", "14 days", "21 days"], "answer": 2, "explanation": "'All domestic flights must be booked at least 14 days in advance'.", "difficulty": "medium"}, {"id": "b7-d3b", "part": 7, "question": "Did Carlos Mendoza comply with hotel policy for his Toronto trip?", "options": ["Yes, because the hotel was within the allowance", "Yes, because he obtained VP pre-approval before booking", "No, because he did not submit a pre-approval request", "No, because the hotel rate exceeded the international allowance"], "answer": 1, "explanation": "Carlos stayed at a hotel exceeding the USD 180 limit but says 'I believe I did obtain pre-approval from the VP of Sales before booking' \u2013 which satisfies the policy requirement.", "difficulty": "medium"}, {"id": "b7-d3c", "part": 7, "question": "What is the daily domestic per diem rate?", "options": ["USD 25", "USD 60", "USD 90", "USD 180"], "answer": 1, "explanation": "'The daily per diem rate is USD 60 for domestic'.", "difficulty": "medium"}, {"id": "b7-d3x", "part": 7, "question": "Based on both documents, which of Carlos Mendoza's expenses is most clearly eligible for reimbursement under the updated policy?", "options": ["The hotel room charge exceeding the nightly cap", "The client dinner expense", "The domestic flight booked 5 days in advance", "The airport transfer fee"], "answer": 2, "explanation": "Cross-document: Policy requires flights booked at least 5 days in advance for reimbursement. Carlos's email confirms his flight was booked 5 days in advance \u2014 the only item clearly meeting policy terms from both documents."}, {"id": "b7-d3e", "part": 7, "question": "What question does Carlos Mendoza ask about the client dinner expense?", "options": ["Whether it needs to be approved by a VP", "Whether receipts are required for it", "Whether it is covered under per diem or classified separately", "Whether it can be split across multiple days"], "answer": 2, "explanation": "'Does this fall under the per diem, or is it classified separately as a client entertainment expense?'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Product Advertisement]\n\nINTRODUCING THE ZEPHYR PRO STANDING DESK\nby ErgoWorks\u2122\n\nTransform your workspace with the Zephyr Pro \u2013 the premium height-adjustable standing desk built for professionals who demand performance and style.\n\nFEATURES:\n\u2022 Smooth, whisper-quiet electric height adjustment (60 cm \u2013 125 cm)\n\u2022 Solid oak desktop with anti-scratch surface coating\n\u2022 Triple memory presets to save your preferred heights\n\u2022 Built-in cable management tray\n\u2022 Maximum weight capacity: 100 kg\n\u2022 Available in three finishes: Natural Oak, Dark Walnut, and White Ash\n\nWHY ERGOWORKS\u2122?\nClinically proven to reduce back pain by up to 54% with regular alternating sitting and standing. Backed by a 5-year manufacturer's warranty on all components.\n\nRetail Price: USD 749 | Assembly required (estimated 45 minutes)\nOrder at: www.ergoworks.com | Free shipping on orders over USD 500\n\n[Document 2 \u2013 Online Review]\n\nRated: 4 out of 5 stars\nReviewer: T. Nguyen | Verified Purchase | Posted: July 12\n\nI purchased the Zephyr Pro in Dark Walnut three weeks ago and overall I'm very satisfied. The height adjustment mechanism is genuinely whisper-quiet \u2013 you barely notice it changing. Assembly took me closer to 75 minutes, not the 45 advertised, but the instructions were clear enough.\n\nThe desk is sturdy and the surface looks premium. I use all three memory presets daily and they work flawlessly. My one complaint is the cable management tray \u2013 it is too small for my four-monitor setup and the cables still end up looking messy.\n\nThe free shipping was a welcome bonus given the desk's weight. I haven't needed to contact customer service, so I can't comment on the warranty experience.\n\nWould recommend to professionals setting up a home office, especially those with a simpler cable setup.", "passageTitle": "Product Advertisement + Online Review", "type": "double", "questions": [{"id": "b7-d4a", "part": 7, "question": "What height range does the Zephyr Pro adjust to?", "options": ["50 cm \u2013 110 cm", "60 cm \u2013 125 cm", "70 cm \u2013 130 cm", "55 cm \u2013 120 cm"], "answer": 1, "explanation": "'Smooth, whisper-quiet electric height adjustment (60 cm \u2013 125 cm)'.", "difficulty": "medium"}, {"id": "b7-d4b", "part": 7, "question": "Which color finish did the reviewer purchase?", "options": ["Natural Oak", "White Ash", "Dark Walnut", "Black Carbon"], "answer": 2, "explanation": "'I purchased the Zephyr Pro in Dark Walnut three weeks ago'.", "difficulty": "medium"}, {"id": "b7-d4cd", "part": 7, "question": "In Document 1, the word \"effortlessly\" as used in the advertisement is closest in meaning to", "options": ["quickly", "smoothly", "reliably", "automatically"], "answer": 1, "explanation": "WIC in Document 1: \"adjusts effortlessly\" = \u0111i\u1ec1u ch\u1ec9nh m\u1ed9t c\u00e1ch tr\u01a1n tru. \"Smoothly\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t \u2014 nh\u1ea5n m\u1ea1nh s\u1ef1 d\u1ec5 d\u00e0ng v\u00e0 kh\u00f4ng c\u00f3 ma s\u00e1t khi v\u1eadn h\u00e0nh."}, {"id": "b7-d4d", "part": 7, "question": "What does the reviewer criticize about the desk?", "options": ["The height adjustment noise", "The surface scratch resistance", "The cable management tray size", "The number of memory presets"], "answer": 2, "explanation": "'My one complaint is the cable management tray \u2013 it is too small for my four-monitor setup'.", "difficulty": "medium"}, {"id": "b7-d4e", "part": 7, "question": "Why did the reviewer NOT comment on the warranty service?", "options": ["The warranty had not yet started", "The reviewer returned the product", "The reviewer has not needed to contact customer service", "The warranty is only valid after registration"], "answer": 2, "explanation": "'I haven't needed to contact customer service, so I can't comment on the warranty experience'.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Annual Report Excerpt]\n\nPALMSTONE RETAIL GROUP\nAnnual Report \u2013 Financial Highlights (Year Ending December 31)\n\nTotal Revenue: USD 2.14 billion (up 8.3% year-over-year)\nNet Profit: USD 187 million (up 12.1% year-over-year)\nOnline Sales: USD 640 million (30% of total revenue; up from 22% in the prior year)\nNew Store Openings: 14 locations (bringing the global total to 218 stores)\n\nCEO Statement (excerpt): \"This year marked a turning point for Palmstone. Our digital transformation initiative, launched 18 months ago, has accelerated e-commerce growth well beyond our initial projections. We remain committed to expanding our omnichannel presence while maintaining the in-store experience our customers value.\"\n\nOutlook: The company projects total revenue growth of 6\u20139% for the coming year, with online sales expected to account for 35% of total revenue.\n\n[Document 2 \u2013 News Article]\n\nPalmstone Retail Announces Two New Flagship Stores in Southeast Asia\nRetail Weekly | February 4\n\nPalmstone Retail Group, the global lifestyle and apparel brand, has confirmed plans to open two flagship stores in Southeast Asia later this year \u2013 one in Singapore and one in Ho Chi Minh City. The announcement follows the company's record-breaking annual results and signals a significant push into the region.\n\nIndustry analysts have noted that Palmstone's strong online growth in Southeast Asia \u2013 particularly in Vietnam and Indonesia \u2013 makes physical store expansion a logical step to strengthen brand presence.\n\nThe Singapore store is expected to open in Q3, while the Ho Chi Minh City location is targeted for Q4. Both stores will feature the company's new \"connected retail\" concept, which integrates digital tools such as virtual fitting rooms and QR-linked product information into the physical shopping experience.", "passageTitle": "Annual Report Excerpt + News Article", "type": "double", "questions": [{"id": "b7-d5a", "part": 7, "question": "By what percentage did online sales grow as a share of total revenue?", "options": ["From 8% to 12%", "From 22% to 30%", "From 30% to 35%", "From 25% to 30%"], "answer": 1, "explanation": "'Online Sales: 30% of total revenue; up from 22% in the prior year'.", "difficulty": "medium"}, {"id": "b7-d5b", "part": 7, "question": "According to the CEO, what was the primary driver of e-commerce growth?", "options": ["A new mobile app launch", "Reduced shipping costs", "A digital transformation initiative launched 18 months ago", "An expansion of the product range"], "answer": 2, "explanation": "'Our digital transformation initiative, launched 18 months ago, has accelerated e-commerce growth'.", "difficulty": "medium"}, {"id": "b7-d5cd", "part": 7, "question": "In Document 2, the word \"flagship\" is closest in meaning to", "options": ["newest", "largest", "most prominent", "most profitable"], "answer": 2, "explanation": "WIC in Document 2: \"new flagship stores\" = c\u1eeda h\u00e0ng ch\u1ee7 l\u1ef1c, \u0111\u1ea1i di\u1ec7n n\u1ed5i b\u1eadt nh\u1ea5t. \"Most prominent\" n\u1eafm b\u1eaft \u0111\u00fang ngh\u0129a \u2014 flagship = c\u1eeda h\u00e0ng ti\u00eau bi\u1ec3u nh\u1ea5t c\u1ee7a th\u01b0\u01a1ng hi\u1ec7u."}, {"id": "b7-d5x", "part": 7, "question": "Based on both documents, what does the planned expansion suggest about Palmstone Retail Group's overall strategy?", "options": ["It is shifting focus entirely away from its home market", "It is prioritising physical retail expansion in high-growth international markets", "It is reducing its online sales division to fund the new stores", "It is responding to declining performance in its existing Southeast Asian stores"], "answer": 1, "explanation": "Cross-document: Annual report shows strong overall revenue + online growth. News article announces two new flagship stores in Southeast Asia. Together they indicate a strategy of expanding physical presence in high-growth international markets while maintaining strong overall performance."}, {"id": "b7-d5e", "part": 7, "question": "What feature will both new Southeast Asian flagship stores include?", "options": ["A caf\u00e9 and co-working space", "Virtual fitting rooms and QR-linked product information", "A dedicated children's play area", "Same-day delivery service hubs"], "answer": 1, "explanation": "'Both stores will feature...virtual fitting rooms and QR-linked product information into the physical shopping experience'.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Job Advertisement]\n\nSENIOR ACCOUNTANT \u2013 PINNACLE HOLDINGS\nLocation: Auckland, New Zealand | Full-Time\nSalary: NZD 90,000 \u2013 105,000 per annum\n\nPinnacle Holdings is a diversified investment group managing assets across real estate, private equity, and infrastructure. We seek a Senior Accountant to join our Finance team.\n\nRequirements:\n\u2022 Chartered Accountant (CA) or CPA qualification \u2013 REQUIRED\n\u2022 Minimum 5 years of experience in financial reporting or audit\n\u2022 Proficiency in SAP or equivalent ERP systems\n\u2022 Strong command of IFRS standards\n\nDeadline: Applications close July 15. Send CV to recruitment@pinnacleholdings.co.nz\n\n[Document 2 \u2013 Application Email]\n\nFrom: Oliver Huang <o.huang@email.com>\nTo: recruitment@pinnacleholdings.co.nz\nDate: July 10\n\nDear Recruitment Team,\n\nI am applying for the Senior Accountant role. I hold a Bachelor of Commerce degree and have six years of experience in financial reporting at a Big Four accounting firm. I am highly proficient in SAP and have worked extensively with IFRS standards.\n\nI am currently completing the final stage of my CA qualification, which I expect to receive in September. In the meantime, I hold a CPA designation obtained in 2020.\n\nI am confident my skills and experience make me a strong match. Please find my CV attached.\n\nBest regards,\nOliver Huang\n\n[Document 3 \u2013 Response Letter]\n\nFrom: Sandra Miles, HR Manager <s.miles@pinnacleholdings.co.nz>\nTo: Oliver Huang <o.huang@email.com>\nDate: July 22\n\nDear Mr. Huang,\n\nThank you for your application for the Senior Accountant position at Pinnacle Holdings.\n\nAfter careful review of all applications received, we are unable to proceed with your candidacy at this time. While your experience and SAP proficiency are impressive, we require candidates to hold a fully completed CA qualification at the time of application. We note that you expect to complete your CA in September.\n\nWe encourage you to reapply once your CA qualification is finalized, as your background would be a strong fit for future openings.\n\nThank you for your interest in Pinnacle Holdings.\n\nSincerely,\nSandra Miles\nHR Manager", "passageTitle": "Job Advertisement + Application + Response Letter", "type": "triple", "questions": [{"id": "b7-t1a", "part": 7, "question": "Why was Oliver Huang's application not successful?", "options": ["He lacks experience in financial reporting", "He does not have proficiency in SAP", "His CA qualification is not yet completed", "He applied after the deadline"], "answer": 2, "explanation": "'we require candidates to hold a fully completed CA qualification at the time of application. We note that you expect to complete your CA in September'.", "difficulty": "medium"}, {"id": "b7-t1b", "part": 7, "question": "How many years of experience does Oliver Huang have?", "options": ["4 years", "5 years", "6 years", "7 years"], "answer": 2, "explanation": "'I have six years of experience in financial reporting'.", "difficulty": "medium"}, {"id": "b7-t1c", "part": 7, "question": "Which qualification does Oliver Huang currently hold?", "options": ["CA only", "CPA and CA", "CPA only", "Neither CA nor CPA"], "answer": 2, "explanation": "Oliver's CA is not yet complete but 'I hold a CPA designation obtained in 2020'.", "difficulty": "medium"}, {"id": "b7-t1d", "part": 7, "question": "What does the company suggest Oliver Huang do?", "options": ["Apply to a different department", "Reapply after completing his CA", "Contact the Finance Director directly", "Attend an upcoming recruitment event"], "answer": 1, "explanation": "'We encourage you to reapply once your CA qualification is finalized'.", "difficulty": "medium"}, {"id": "b7-t1e", "part": 7, "question": "Which requirement in the job advertisement did Oliver Huang NOT fully satisfy at the time of application?", "options": ["SAP proficiency", "IFRS knowledge", "Minimum years of experience", "CA qualification"], "answer": 3, "explanation": "Y\u00eau c\u1ea7u 'CA or CPA qualification \u2013 REQUIRED'. Oliver c\u00f3 CPA nh\u01b0ng CA ch\u01b0a ho\u00e0n th\u00e0nh \u2192 kh\u00f4ng \u0111\u00e1p \u1ee9ng \u0111\u1ea7y \u0111\u1ee7.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Catering Menu & Policy]\n\nFEAST & CO. CORPORATE CATERING\nMenu Selections & Ordering Policy\n\nAvailable Packages:\n\u2022 Standard Package: Cold buffet, soft drinks \u2013 USD 28 per person (min. 10 persons)\n\u2022 Premium Package: Hot buffet, soft drinks, dessert station \u2013 USD 48 per person (min. 10 persons)\n\u2022 Executive Package: 3-course plated meal, wine service \u2013 USD 95 per person (min. 20 persons)\n\nOrdering Policy:\n\u2022 Orders must be placed at least 5 business days before the event date\n\u2022 Cancellations made less than 48 hours before the event are non-refundable\n\u2022 Dietary requirements must be submitted with the order (no changes within 24 hours of event)\n\n[Document 2 \u2013 Order Confirmation]\n\nFrom: orders@feastandco.com\nTo: t.bradley@helixcorp.com\nDate: May 6\n\nDear Ms. Bradley,\n\nThank you for your order. This confirms your booking for:\n\nPackage: Premium Package\nEvent Date: May 14 (Wednesday)\nAttendees: 35 persons\nTotal: USD 1,680\n\nDietary Notes Received: 3 vegetarian, 1 nut allergy\n\nDelivery is scheduled for 11:30 a.m. on May 14. Please ensure someone is available to receive the delivery.\n\nIf you need to make any changes to your order, please contact us no later than May 12.\n\n[Document 3 \u2013 Complaint Email]\n\nFrom: Tara Bradley <t.bradley@helixcorp.com>\nTo: orders@feastandco.com\nDate: May 15\n\nHello,\n\nI am writing to report several issues with our catering order from yesterday's event.\n\nFirst, although we confirmed three vegetarian meals, only two were provided. A colleague who does not eat meat had to go without. Second, the food arrived approximately 40 minutes late, which disrupted the meeting schedule. We had informed your team that the event started at 12:00 p.m.\n\nAdditionally, the hot dishes were lukewarm upon arrival, likely due to the delivery delay.\n\nI would appreciate a partial refund or credit toward a future order. This was our first experience with Feast & Co. and unfortunately it was disappointing.\n\nRegards,\nTara Bradley\nOffice Manager, Helix Corp", "passageTitle": "Catering Order Notice + Confirmation + Complaint", "type": "triple", "questions": [{"id": "b7-t2a", "part": 7, "question": "How much did Helix Corp pay for the catering order?", "options": ["USD 960", "USD 1,200", "USD 1,680", "USD 3,325"], "answer": 2, "explanation": "35 persons \u00d7 USD 48 (Premium Package) = USD 1,680.", "difficulty": "medium"}, {"id": "b7-t2b", "part": 7, "question": "According to the catering policy, by what date should any order changes have been made?", "options": ["May 6", "May 9", "May 12", "May 13"], "answer": 2, "explanation": "'please contact us no later than May 12' from the confirmation email.", "difficulty": "medium"}, {"id": "b7-t2c", "part": 7, "question": "What was the first problem Tara Bradley reported?", "options": ["The food arrived cold", "A nut allergy meal was not prepared", "Only two vegetarian meals were provided instead of three", "The wrong package was delivered"], "answer": 2, "explanation": "'although we confirmed three vegetarian meals, only two were provided'.", "difficulty": "medium"}, {"id": "b7-t2d", "part": 7, "question": "What time was the food delivered based on the complaint?", "options": ["11:30 a.m.", "12:00 p.m.", "Approximately 12:10 p.m.", "Approximately 12:40 p.m."], "answer": 2, "explanation": "'food arrived approximately 40 minutes late' from the scheduled 11:30 a.m. \u2192 11:30 + 40 = 12:10 p.m.", "difficulty": "medium"}, {"id": "b7-t2e", "part": 7, "question": "What resolution does Tara Bradley request?", "options": ["A full refund", "A replacement order", "A partial refund or credit toward a future order", "A written apology from the catering manager"], "answer": 2, "explanation": "'I would appreciate a partial refund or credit toward a future order'.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Internal Memo]\n\nTo: All Sales & Marketing Staff\nFrom: Dr. Helena Cross, Chief Product Officer\nDate: January 8\n\nI am excited to announce that our new product, the NutriFlow Smart Water Bottle, will officially launch on February 1.\n\nThe NutriFlow tracks daily water intake, syncs with our mobile app, and reminds users to hydrate via customizable alerts. It is available in two sizes (500ml and 750ml) and three colors.\n\nRRP is USD 69.99. An introductory 20% launch discount will be offered through our website and partner retailers for the first 30 days.\n\nOur marketing campaign will begin January 22 across social media and fitness influencer partnerships. Sales targets for Q1 are set at 20,000 units.\n\n[Document 2 \u2013 Online News Article]\n\nNutriFlow Sells Out in 72 Hours\nHealthTech Review | February 4\n\nCedarTech's newly launched NutriFlow Smart Water Bottle has sold out of its initial stock of 10,000 units within 72 hours of its February 1 launch, the company confirmed.\n\nThe rapid sell-out was attributed to the product's competitive pricing with the launch discount applied, as well as a viral social media campaign featuring fitness influencers. CedarTech has indicated that additional stock is expected within three weeks.\n\nAnalysts noted that while the sell-out was impressive, the 10,000-unit initial stock represented only half of the Q1 sales target. CedarTech will need to fulfill the remaining 10,000 units to meet its goal.\n\n[Document 3 \u2013 Customer Review]\n\nRating: 5 out of 5\nReviewer: Marcus T. | Verified Purchase | Posted: February 3\n\nI bought the NutriFlow 750ml in navy blue on launch day and I love it. Syncing with the app was seamless and the hydration reminders have genuinely changed my habits. The bottle feels premium and the insulation is excellent \u2013 my water stayed cold for over 8 hours.\n\nI did pay full price as I wasn't aware of the discount at the time of purchase. A bit disappointing in hindsight, but the quality more than justifies the cost.\n\nHighly recommend to anyone focused on improving their health.", "passageTitle": "Product Launch Memo + Media Article + Customer Feedback", "type": "triple", "questions": [{"id": "b7-t3a", "part": 7, "question": "What is the standard retail price of the NutriFlow?", "options": ["USD 49.99", "USD 55.99", "USD 69.99", "USD 83.99"], "answer": 2, "explanation": "'RRP is USD 69.99'.", "difficulty": "medium"}, {"id": "b7-t3b", "part": 7, "question": "How many units were in the initial stock at launch?", "options": ["5,000", "10,000", "20,000", "30,000"], "answer": 1, "explanation": "'sold out of its initial stock of 10,000 units within 72 hours'.", "difficulty": "medium"}, {"id": "b7-t3c", "part": 7, "question": "According to the news article, what was the Q1 sales target?", "options": ["10,000 units", "15,000 units", "20,000 units", "30,000 units"], "answer": 2, "explanation": "'the 10,000-unit initial stock represented only half of the Q1 sales target' \u2192 Q1 target = 20,000 units.", "difficulty": "medium"}, {"id": "b7-t3d", "part": 7, "question": "What issue does the reviewer mention about their purchase experience?", "options": ["The app did not sync correctly", "They received the wrong color", "They paid full price and missed the launch discount", "Delivery took longer than expected"], "answer": 2, "explanation": "'I did pay full price as I wasn't aware of the discount at the time of purchase'.", "difficulty": "medium"}, {"id": "b7-t3e", "part": 7, "question": "What can be inferred about when the reviewer purchased the NutriFlow?", "options": ["Before the official launch date", "On the launch day, February 1", "After the discount period ended", "During the second stock release"], "answer": 1, "explanation": "Reviewer says 'I bought...on launch day' \u2192 February 1. The discount was active (first 30 days) but reviewer was unaware of it.", "difficulty": "medium"}]}, {"passage": "NOTICE\nHarbourside Office Complex \u2013 Tower B\n\nROOFTOP GARDEN ACCESS POLICY UPDATE\n\nThe rooftop garden on Level 22 of Tower B has been re-opened following its three-month closure for landscaping and safety upgrades.\n\nEffective immediately, the following access rules apply:\n\n\u2022 The rooftop garden is available to all Tower B tenants during weekday business hours (7:00 a.m. \u2013 8:00 p.m.) and on weekends from 9:00 a.m. to 6:00 p.m.\n\u2022 Access is via the elevator to Level 22 only. Use of the fire escape stairwell for routine access is prohibited.\n\u2022 A maximum of 40 persons may be on the rooftop at any one time. If this limit is reached, building security will manage a queue at the elevator.\n\u2022 Food and beverages are permitted, but glass containers are not allowed.\n\u2022 Corporate events or group bookings of more than 15 persons require prior approval from the Building Management Office at least 5 business days in advance.\n\nTenants are reminded that CCTV monitoring is active in all common areas. Any damage to the garden facilities will be the financial responsibility of the tenant involved.\n\nFor event booking inquiries: management@harboursidecomplex.com", "passageTitle": "Notice: Harbourside Office Complex \u2013 Tower B ROO", "type": "single", "questions": [{"id": "c7-s1a", "part": 7, "question": "What recently happened to the rooftop garden?", "options": ["It was permanently closed due to safety concerns.", "It was renovated and has now reopened.", "It was converted into a private meeting space.", "It was opened for the first time."], "answer": 1, "explanation": "'has been re-opened following its three-month closure for landscaping and safety upgrades'.", "difficulty": "medium"}, {"id": "c7-s1b", "part": 7, "question": "What is NOT permitted in the rooftop garden?", "options": ["Food and snacks", "Beverages in plastic cups", "Glass bottles and jars", "Corporate events with prior approval"], "answer": 2, "explanation": "'glass containers are not allowed' \u2014 'glass containers' = chai/h\u1ed9p th\u1ee7y tinh.", "difficulty": "medium"}, {"id": "c7-s1c", "part": 7, "question": "How far in advance must group bookings be arranged?", "options": ["1 business day", "3 business days", "5 business days", "1 week"], "answer": 2, "explanation": "'require prior approval from the Building Management Office at least 5 business days in advance'.", "difficulty": "medium"}, {"id": "p7-pur02", "part": 7, "question": "What is the main purpose of this notice?", "options": ["To announce the permanent opening of the rooftop garden", "To inform tenants of updated rules for rooftop garden access", "To apologise for the extended closure of the garden", "To promote the garden as a new amenity for tenants"], "answer": 1, "explanation": "Purpose: th\u00f4ng b\u00e1o c\u1eadp nh\u1eadt quy \u0111\u1ecbnh s\u1eed d\u1ee5ng v\u01b0\u1eddn tr\u00ean s\u00e2n th\u01b0\u1ee3ng sau khi m\u1edf c\u1eeda l\u1ea1i \u2014 m\u1ee5c \u0111\u00edch ch\u00ednh l\u00e0 th\u00f4ng b\u00e1o quy t\u1eafc m\u1edbi, kh\u00f4ng ph\u1ea3i khai tr\u01b0\u01a1ng hay xin l\u1ed7i."}]}, {"passage": "TRAVEL ITINERARY\nPrepared for: Ms. Amara Osei, VP of Business Development\nDestination: Singapore\nTravel Dates: May 19 \u2013 May 23\n\nMONDAY, MAY 19\n09:00  Depart Ho Chi Minh City (SGN) \u2014 SQ 185 \u2014 Arrive Singapore (SIN) 11:55\n12:30  Hotel check-in: The Fullerton Hotel, 1 Fullerton Square\n14:00  Briefing with regional sales team at Marina Bay office\n19:00  Welcome dinner hosted by DeltaTrade Singapore, 1-Altitude Restaurant\n\nTUESDAY, MAY 20\n09:00  Board meeting \u2014 DeltaTrade Singapore HQ, Level 35\n12:30  Working lunch \u2014 internal strategy review\n15:00  Client presentation \u2014 Quantum Logistics, Clarke Quay office\n18:00  Free time\n\nWEDNESDAY, MAY 21\n10:00  Site tour \u2014 DeltaTrade Tuas Distribution Centre\n14:30  Debrief meeting with regional director, Mr. Ian Fong\n19:30  Corporate dinner \u2014 Waku Ghin, Marina Bay Sands\n\nTHURSDAY, MAY 22\n09:00  Open session \u2014 stakeholder Q&A\n11:30  Depart hotel for airport\n14:25  Depart Singapore (SIN) \u2014 SQ 184 \u2014 Arrive Ho Chi Minh City 15:30\n\nNOTES:\n\u2022 All ground transport in Singapore is arranged by DeltaTrade's local coordinator.\n\u2022 Hotel costs and flight are covered by the company. Incidentals are at Ms. Osei's own expense.\n\u2022 Please keep all receipts for reimbursement requests.", "passageTitle": "Travel Itinerary", "type": "single", "questions": [{"id": "c7-s2a", "part": 7, "question": "What is the purpose of Ms. Osei's trip to Singapore?", "options": ["To attend a regional conference", "For business meetings, a site tour, and client presentations", "To conduct employee performance reviews", "To negotiate a new hotel contract"], "answer": 1, "explanation": "Itinerary bao g\u1ed3m board meeting, client presentation, site tour, v\u00e0 stakeholder Q&A.", "difficulty": "medium"}, {"id": "c7-s2b", "part": 7, "question": "On which day does Ms. Osei visit a distribution facility?", "options": ["Monday, May 19", "Tuesday, May 20", "Wednesday, May 21", "Thursday, May 22"], "answer": 2, "explanation": "'Wednesday, May 21 \u2014 Site tour \u2014 DeltaTrade Tuas Distribution Centre'.", "difficulty": "medium"}, {"id": "c7-s2c", "part": 7, "question": "Which expenses will Ms. Osei personally need to cover?", "options": ["Hotel costs", "Flight tickets", "Ground transportation in Singapore", "Incidental expenses"], "answer": 3, "explanation": "'Incidentals are at Ms. Osei's own expense'.", "difficulty": "medium"}, {"id": "p7-s-v29", "part": 7, "question": "What can be inferred about the purpose of Ms. Osei's visit to the distribution facility?", "options": ["She will be evaluating it as a potential acquisition target", "It is part of a standard due diligence or business development visit", "She plans to relocate the facility to a new location", "She is representing a client who currently uses the facility"], "answer": 1, "explanation": "Inference: A VP of Business Development visiting a distribution facility on a business trip most likely indicates due diligence or business development evaluation \u2014 inferred from her job title and the context of the trip."}]}, {"passage": "THE RISE OF THE FOUR-DAY WORKWEEK\nBusiness Horizons Magazine | October Issue\n\nOnce considered a radical concept reserved for progressive startups, the four-day workweek is quietly entering the mainstream. A landmark 2023 trial conducted across 61 companies in the United Kingdom \u2014 one of the largest of its kind \u2014 found that 92% of participating firms had no intention of returning to a five-day model after experiencing the results firsthand.\n\nParticipating companies reported significant benefits: productivity held steady or improved in 95% of cases, employee sick days fell by an average of 65%, and staff turnover dropped by 57%. Revenue also increased by an average of 1.4% during the trial period.\n\nCritics, however, argue that the model is far from universally applicable. Industries dependent on continuous operations \u2014 manufacturing, healthcare, logistics \u2014 face structural barriers to implementation. Small businesses and client-facing service companies also raise concerns about maintaining service coverage across four days.\n\nDespite these challenges, momentum is building. Iceland has run successful large-scale trials, Microsoft Japan reported a 40% productivity boost after a brief four-day pilot, and a growing number of governments are exploring legislation to make compressed workweeks a legal option for employees.\n\nWhether or not the four-day week becomes the global standard, it has forced a long-overdue conversation about what productivity truly means \u2014 and whether hours spent at a desk is really the right metric for measuring it.", "passageTitle": "News Article", "type": "single", "questions": [{"id": "c7-s3a", "part": 7, "question": "What percentage of companies in the UK trial did NOT want to return to a five-day workweek?", "options": ["57%", "65%", "92%", "95%"], "answer": 2, "explanation": "'92% of participating firms had no intention of returning to a five-day model'.", "difficulty": "medium"}, {"id": "c7-s3b", "part": 7, "question": "According to the article, which result was observed regarding employee health during the trial?", "options": ["Productivity fell by 65%", "Sick days decreased by 65%", "Staff turnover increased by 57%", "Revenue fell by 1.4%"], "answer": 1, "explanation": "'employee sick days fell by an average of 65%'.", "difficulty": "medium"}, {"id": "c7-s3c", "part": 7, "question": "Which industry is specifically mentioned as having difficulty adopting the four-day model?", "options": ["Financial services", "Education", "Retail", "Healthcare"], "answer": 3, "explanation": "'Industries dependent on continuous operations \u2014 manufacturing, healthcare, logistics \u2014 face structural barriers'.", "difficulty": "medium"}, {"id": "c7-s3d", "part": 7, "question": "What does Microsoft Japan's four-day pilot suggest?", "options": ["The model is only suitable for large tech companies.", "Productivity can increase significantly in a shorter workweek.", "The government should legislate compressed workweeks.", "Employees prefer more pay over fewer working hours."], "answer": 1, "explanation": "'Microsoft Japan reported a 40% productivity boost after a brief four-day pilot' \u2192 shorter workweek can boost productivity.", "difficulty": "medium"}]}, {"passage": "From: Gabrielle Lamont <g.lamont@apexevents.com>\nTo: All Event Staff\nDate: December 9\nSubject: Post-Event Summary \u2013 Apex Annual Gala\n\nDear Team,\n\nI want to take a moment to share a brief recap of last Friday's Annual Gala and to personally thank each of you for your outstanding contributions.\n\nThe event welcomed 320 guests \u2014 exceeding our target of 300 \u2014 and ran smoothly from the cocktail reception at 7:00 p.m. through the final curtain at midnight. All audio-visual elements performed without a single technical failure, a significant improvement over last year's event.\n\nA few specific highlights:\n\u2022 The live auction raised USD 48,000 for our partner charity, surpassing the USD 35,000 goal by 37%.\n\u2022 Guest satisfaction surveys collected at the exit indicated an average rating of 4.7 out of 5.\n\u2022 Three new corporate sponsorships were confirmed on the night, collectively valued at USD 120,000 for next year's program.\n\nThat said, we did encounter a catering delay during the second course that led to a roughly 25-minute interruption to the evening program. I will be meeting with the catering manager next week to review what occurred and to put safeguards in place for future events.\n\nFinal reports and budget reconciliation will be distributed by December 15.\n\nThank you once again. Your professionalism made all the difference.\n\nGabrielle Lamont\nHead of Events, Apex", "passageTitle": "Email: Post-Event Summary \u2013 Apex Annual Gala", "type": "single", "questions": [{"id": "c7-s4a", "part": 7, "question": "How many guests attended the Annual Gala?", "options": ["300", "310", "320", "350"], "answer": 2, "explanation": "'The event welcomed 320 guests \u2014 exceeding our target of 300'.", "difficulty": "medium"}, {"id": "c7-s4b", "part": 7, "question": "By how much did the live auction exceed its fundraising goal?", "options": ["USD 10,000", "USD 13,000", "USD 35,000", "USD 48,000"], "answer": 1, "explanation": "USD 48,000 raised \u2013 USD 35,000 goal = USD 13,000 surplus.", "difficulty": "medium"}, {"id": "c7-s4c", "part": 7, "question": "What issue occurred during the event?", "options": ["A technical failure with the audio-visual equipment", "A delay in the catering during the second course", "A guest capacity issue at the entrance", "Sponsorship commitments fell short of target"], "answer": 1, "explanation": "'we did encounter a catering delay during the second course that led to a roughly 25-minute interruption'.", "difficulty": "medium"}, {"id": "p7-s-v30", "part": 7, "question": "In the email, the word \"rectify\" is closest in meaning to", "options": ["address", "investigate", "prevent", "report"], "answer": 0, "explanation": "WIC: \"rectify the catering issue\" = kh\u1eafc ph\u1ee5c, gi\u1ea3i quy\u1ebft v\u1ea5n \u0111\u1ec1. \"Address\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh h\u00e0nh \u0111\u1ed9ng sau s\u1ef1 c\u1ed1 s\u1ef1 ki\u1ec7n."}]}, {"passage": "URGENT PRODUCT RECALL NOTICE\nIsued by: SafeHome Appliances Ltd.\nProduct: OptiBreeze Portable Air Purifier \u2013 Model AP-330\nDate of Notice: July 14\n\nSafeHome Appliances Ltd. is voluntarily recalling all units of the OptiBreeze Portable Air Purifier, Model AP-330, manufactured between January and April of this year. This recall has been issued after internal testing identified a potential overheating risk in the device's power circuit under certain operating conditions.\n\nNo injuries have been reported to date; however, out of an abundance of caution, customers who own this model are strongly urged to:\n\n1. IMMEDIATELY stop using the product and unplug it from the power source.\n2. Do NOT attempt to repair the device yourself.\n3. Contact SafeHome customer service at 1-800-SAFEHOME or recall@safehomeappliances.com to register your unit for a full refund or a free replacement.\n\nCustomers who purchased the AP-330 from an authorized retailer may also return it directly to the store for a full refund, regardless of the original purchase date.\n\nProof of purchase is recommended but not required to receive a refund or replacement.\n\nWe sincerely apologize for any inconvenience this may cause. SafeHome Appliances is committed to the safety and satisfaction of all our customers.\n\nFor more information, visit: www.safehomeappliances.com/recall-ap330", "passageTitle": "Product Recall Notice", "type": "single", "questions": [{"id": "c7-s5a", "part": 7, "question": "Why is the AP-330 being recalled?", "options": ["It was found to emit harmful gases", "A potential overheating risk was identified in its power circuit", "The device does not meet air quality standards", "Customer complaints about noise levels were filed"], "answer": 1, "explanation": "'identified a potential overheating risk in the device's power circuit under certain operating conditions'.", "difficulty": "medium"}, {"id": "c7-s5b", "part": 7, "question": "What should customers do immediately upon reading this notice?", "options": ["Return the product to the store right away", "Call their insurance provider", "Unplug the device and stop using it", "Wait for a replacement to be delivered before stopping use"], "answer": 2, "explanation": "'IMMEDIATELY stop using the product and unplug it from the power source'.", "difficulty": "medium"}, {"id": "c7-s5c", "part": 7, "question": "What options are available to affected customers?", "options": ["Only a free replacement", "Only a full refund", "A full refund or a free replacement", "A partial refund or a discount on a new model"], "answer": 2, "explanation": "'register your unit for a full refund or a free replacement'.", "difficulty": "medium"}, {"id": "p7-s-v31", "part": 7, "question": "Which of the following is NOT offered to affected customers?", "options": ["A full refund", "A free replacement unit", "A repair service", "A partial credit toward a new purchase"], "answer": 3, "explanation": "NOT TRUE: Review the options available. A partial credit toward a new purchase is typically NOT among the standard recall remedies \u2014 only full refund, replacement, or repair are standard."}]}, {"passage": "LEARNBRIDGE PLATFORM UPDATE\nAnnounced: September 1\n\nDear LearnBridge Members,\n\nWe are excited to announce the launch of LearnBridge Pro \u2014 our new premium subscription tier designed for professionals who want to take their skills to the next level.\n\nLearnBridge Pro offers:\n\u2022 Unlimited access to over 4,500 courses across technology, business, design, and leadership\n\u2022 New monthly additions of 50+ expert-led courses\n\u2022 Offline download for up to 30 courses at a time\n\u2022 AI-powered learning path recommendations personalized to your career goals\n\u2022 Access to live monthly Q&A sessions with industry experts\n\u2022 A verified digital certificate upon course completion, recognized by over 200 employer partners\n\nPRICING:\nMonthly: USD 29/month | Annual: USD 249/year (save 28%)\n\nExisting free members who upgrade before September 30 will receive an additional 20% discount on the first year of their annual plan, bringing the effective rate to USD 199.20.\n\nYour current free account will remain fully functional. LearnBridge Pro is entirely optional and offers additional features for those who want them.\n\nTo upgrade or learn more, visit your account dashboard at learnbridge.io/pro.\n\nHappy learning,\nThe LearnBridge Team", "passageTitle": "Platform Update", "type": "single", "questions": [{"id": "c7-s6a", "part": 7, "question": "What is the main purpose of this announcement?", "options": ["To notify users of a price increase for existing accounts", "To introduce a new premium subscription tier", "To announce the closure of the free membership plan", "To promote a limited-time sale on existing courses"], "answer": 1, "explanation": "'We are excited to announce the launch of LearnBridge Pro \u2014 our new premium subscription tier'.", "difficulty": "medium"}, {"id": "c7-s6b", "part": 7, "question": "What advantage does the annual plan offer over the monthly plan?", "options": ["Access to more courses", "A 20% early-bird discount", "Savings of 28% compared to paying monthly", "Free access to live Q&A sessions"], "answer": 2, "explanation": "'Annual: USD 249/year (save 28%)'.", "difficulty": "medium"}, {"id": "c7-s6c", "part": 7, "question": "How much would a free member pay for the first year of Pro if they upgrade before September 30?", "options": ["USD 199.20", "USD 249.00", "USD 29.00 per month", "USD 199.00"], "answer": 0, "explanation": "Annual plan USD 249 \u00d7 80% (20% discount) = USD 199.20.", "difficulty": "medium"}, {"id": "p7-s-v20", "part": 7, "question": "Which of the following is NOT mentioned as a feature of the updated platform?", "options": ["New subscription tier options", "Improved learning analytics", "A mobile application", "Offline access to course materials"], "answer": 3, "explanation": "NOT TRUE: Review the platform update features listed. Offline access is typically NOT among the announced features \u2014 verify it is not explicitly mentioned in the update."}]}, {"passage": "[Document 1 \u2013 Service Contract Terms Excerpt]\n\nVELOCITY IT SOLUTIONS \u2013 MANAGED SERVICES AGREEMENT\nClient: Stonegate Financial Partners\n\nService Level & Billing Terms (excerpt):\n\n3.1 Monthly Managed Service Fee: USD 4,200, billed on the first of each month.\n\n3.2 On-Site Support: Included for up to 10 hours per month. Additional on-site hours are billed at USD 120 per hour.\n\n3.3 Remote Support: Unlimited. Included in the monthly fee at no additional charge.\n\n3.4 Emergency After-Hours Callout: USD 250 flat fee per callout, applicable between 8:00 p.m. and 7:00 a.m. on weekdays, and all day on weekends and public holidays.\n\n3.5 Hardware Procurement: Charged at cost plus a 12% procurement fee.\n\n[Document 2 \u2013 Client Email]\n\nFrom: James Whitfield <j.whitfield@stonegatefi.com>\nTo: billing@velocityit.com\nDate: February 7\n\nDear Velocity IT Billing Team,\n\nI am writing regarding our January invoice (Invoice #VIT-0881), which totals USD 5,148. After reviewing it against our service agreement, I believe two charges may be incorrect.\n\nFirst, the invoice includes a charge of USD 360 for three hours of on-site support listed as \"additional.\" However, our records indicate we used only 8 hours of on-site support in January, which should be within the 10-hour monthly inclusion.\n\nSecond, an emergency callout fee of USD 250 is listed for January 15, which was a Wednesday. Our engineer's report shows the callout took place at 6:30 p.m. \u2014 before the 8:00 p.m. after-hours threshold stated in section 3.4 of our agreement.\n\nIf these two charges are reversed, the corrected total should be USD 4,538. Please review and confirm.\n\nRegards,\nJames Whitfield\nOperations Manager, Stonegate Financial Partners", "passageTitle": "Service Contract Terms + Invoice Dispute Email", "type": "double", "questions": [{"id": "c7-d1a", "part": 7, "question": "What is the standard monthly fee for Stonegate Financial Partners?", "options": ["USD 4,200", "USD 4,538", "USD 5,148", "USD 5,400"], "answer": 0, "explanation": "'Monthly Managed Service Fee: USD 4,200, billed on the first of each month'.", "difficulty": "medium"}, {"id": "c7-d1b", "part": 7, "question": "According to James Whitfield, why should the on-site support charge be reversed?", "options": ["The work was done remotely, not on-site.", "Only 8 hours were used, which is within the 10-hour monthly inclusion.", "The engineer's invoice was submitted after the billing deadline.", "The contract does not include on-site support charges."], "answer": 1, "explanation": "'our records indicate we used only 8 hours of on-site support in January, which should be within the 10-hour monthly inclusion'.", "difficulty": "medium"}, {"id": "c7-d1cd", "part": 7, "question": "In Document 1, the word \"escalation\" is closest in meaning to", "options": ["increase in severity", "formal complaint", "resolution process", "billing error"], "answer": 0, "explanation": "WIC in Document 1: \"escalation process\" in a service contract = quy tr\u00ecnh leo thang (khi v\u1ea5n \u0111\u1ec1 kh\u00f4ng \u0111\u01b0\u1ee3c gi\u1ea3i quy\u1ebft \u1edf c\u1ea5p th\u1ea5p h\u01a1n). \"Increase in severity\" n\u1eafm b\u1eaft \u0111\u00fang ngh\u0129a leo thang."}, {"id": "c7-d1x", "part": 7, "question": "Based on both documents, which of James Whitfield's disputes appears most clearly supported by the contract terms?", "options": ["The dispute about the monthly retainer fee", "The dispute about the on-site support charge", "The dispute about the emergency callout fee", "Both the on-site support and emergency callout disputes"], "answer": 1, "explanation": "Cross-document: Contract states on-site support is included within the monthly fee. Invoice charges separately for it. \u2192 The on-site support dispute is most directly supported by the contract language. Emergency callout terms are less clear."}, {"id": "c7-d1e", "part": 7, "question": "Based on the contract, what type of support is included at no extra charge regardless of hours used?", "options": ["On-site support", "Emergency callouts", "Remote support", "Hardware procurement"], "answer": 2, "explanation": "'Remote Support: Unlimited. Included in the monthly fee at no additional charge'.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Job Posting]\n\nOPENING: SUSTAINABILITY MANAGER\nHorizon Consumer Goods | Kuala Lumpur, Malaysia\nDepartment: Corporate Affairs\nContract: Permanent, Full-Time\n\nHorizon Consumer Goods is seeking an experienced Sustainability Manager to lead our environmental and social responsibility programs across our Southeast Asian operations.\n\nKey Responsibilities:\n\u2022 Develop and implement the company's sustainability strategy in line with global targets\n\u2022 Manage ESG reporting and liaise with third-party auditors\n\u2022 Lead a team of three sustainability coordinators\n\u2022 Engage with government bodies, NGOs, and community stakeholders\n\u2022 Present quarterly updates to the board of directors\n\nRequirements:\n\u2022 Minimum 7 years of experience in sustainability, ESG, or corporate affairs\n\u2022 Experience managing cross-functional or regional teams\n\u2022 Strong written and verbal communication skills\n\u2022 Master's degree in Environmental Science, Business, or a related field preferred\n\nSalary: MYR 18,000 \u2013 22,000/month + performance bonus\nApplication deadline: April 10\nEmail: careers@horizoncg.com\n\n[Document 2 \u2013 Reference Letter]\n\nApril 3\n\nTo Whom It May Concern,\n\nI am pleased to provide this reference for Ms. Yuna Park, who served as Senior Sustainability Analyst at GreenBridge Consulting for four years under my direct supervision.\n\nDuring her tenure, Ms. Park led the development of sustainability roadmaps for three multinational clients and managed a small team of two junior analysts. Her work on ESG disclosure frameworks was widely recognized within the industry and contributed to two of our clients receiving national sustainability awards.\n\nMs. Park holds a Master of Science in Environmental Management from the National University of Singapore. Her analytical skills, stakeholder communication, and leadership potential are all of the highest standard.\n\nI have no hesitation in recommending her for a senior leadership role in sustainability.\n\nSincerely,\nDr. Aaron Lim\nPrincipal Consultant, GreenBridge Consulting", "passageTitle": "Job Posting + Reference Letter", "type": "double", "questions": [{"id": "c7-d2a", "part": 7, "question": "How many sustainability coordinators will the Sustainability Manager be responsible for leading?", "options": ["2", "3", "4", "5"], "answer": 1, "explanation": "'Lead a team of three sustainability coordinators'.", "difficulty": "medium"}, {"id": "c7-d2b", "part": 7, "question": "Does Yuna Park meet the minimum experience requirement for the position?", "options": ["Yes, she has exactly 7 years of experience.", "No, she only has 4 years of experience.", "Yes, because her experience exceeds the requirement.", "It cannot be determined from the reference letter."], "answer": 1, "explanation": "'served as Senior Sustainability Analyst...for four years' \u2014 requirement is minimum 7 years. She falls short.", "difficulty": "medium"}, {"id": "c7-d2cd", "part": 7, "question": "Based on both documents, what aspect of Yuna Park's background is confirmed by BOTH the reference and the job requirements?", "options": ["Her academic qualifications in environmental science", "Her experience managing a team", "Her proficiency in sustainability reporting software", "Her achievement of a Carbon Neutral certification"], "answer": 1, "explanation": "Cross-document: Job posting requires team management experience. Reference letter confirms Yuna managed teams at her previous organisation. Team management experience is the one point confirmed by both documents."}, {"id": "c7-d2x", "part": 7, "question": "Based on both documents, what is the strongest evidence that Yuna Park is qualified for the Sustainability Manager position?", "options": ["Her reference letter specifically mentions her Carbon Neutral certification achievement", "She meets the minimum experience requirement and has a relevant academic background", "The reference confirms she holds an MBA in Environmental Management", "Her previous job title matches the advertised position exactly"], "answer": 0, "explanation": "Cross-document: Job posting requires sustainability management experience + results. Reference letter specifically mentions an award-winning Carbon Neutral achievement \u2014 directly matching the job's key result requirement. This is the strongest combined evidence."}, {"id": "c7-d2e", "part": 7, "question": "What qualification is listed as preferred but not required in the job posting?", "options": ["7 years of ESG experience", "Experience managing regional teams", "A Master's degree in a related field", "ESG reporting experience"], "answer": 2, "explanation": "'Master's degree in Environmental Science, Business, or a related field preferred'.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 IT Security Policy Update]\n\nMEMO\nTo: All Staff\nFrom: IT Security Team\nDate: October 1\n\nAs part of our response to an increase in phishing attempts targeting our industry, we are implementing an enhanced IT security framework effective November 1.\n\nKey requirements for all employees:\n1. Passwords must be updated every 60 days and must meet the new complexity requirements (minimum 12 characters, including at least one symbol).\n2. Multi-factor authentication (MFA) is now mandatory for all company applications.\n3. All staff must complete a cybersecurity awareness training module before October 31.\n4. Employees who handle sensitive client data must additionally complete an advanced data protection course by November 15.\n\nNon-compliance with items 1\u20133 by October 31 will result in account access being temporarily suspended until the requirements are met.\n\n[Document 2 \u2013 Training Course Schedule]\n\nCYBERSECURITY AWARENESS TRAINING \u2013 OCTOBER SESSION\nProvider: ShieldIQ Learning Platform\n\nCourse 1: Cybersecurity Awareness (All Staff) \u2013 MANDATORY\nDuration: 90 minutes | Format: Online, self-paced\nAvailability: October 1\u201331 | Access via: hr.company.com/training\n\nCourse 2: Advanced Data Protection (Client-Facing Staff Only)\nDuration: 3 hours | Format: Online with a live Q&A session\nScheduled Q&A Sessions: October 22 (2:00 p.m.) and November 8 (10:00 a.m.)\nDeadline: November 15\n\nAll completions are automatically recorded. Certificates will be emailed within 24 hours of finishing.\n\n[Document 3 \u2013 Employee Email]\n\nFrom: Kevin Ho <k.ho@company.com>\nTo: IT Help Desk <helpdesk@company.com>\nDate: October 14\n\nHi,\n\nI have a few questions about the new security requirements.\n\nI completed Course 1 yesterday but haven't received my certificate yet. Is this normal? It's been about 20 hours.\n\nAlso, I'm a client relationship manager, so I assume I need to complete Course 2 as well. I noticed there are two Q&A sessions \u2014 one in October and one in November. Is attendance at one of these sessions required to pass the course, or are they optional?\n\nFinally, I'm concerned about the password requirement. My current password is 10 characters with no symbols. Do I need to update this before October 31 or is there a grace period?\n\nThank you,\nKevin Ho", "passageTitle": "IT Security Policy + Training Schedule + Employee Email", "type": "triple", "questions": [{"id": "c7-t1a", "part": 7, "question": "By what date must ALL employees complete the mandatory cybersecurity training?", "options": ["October 14", "October 22", "October 31", "November 15"], "answer": 2, "explanation": "Policy item 3: 'All staff must complete a cybersecurity awareness training module before October 31'.", "difficulty": "medium"}, {"id": "c7-t1b", "part": 7, "question": "Why has Kevin Ho not yet received his certificate after completing Course 1?", "options": ["He did not pass the final assessment.", "He must attend a live Q&A session first.", "Certificates are issued within 24 hours, and 20 hours have passed.", "His completion was not recorded by the system."], "answer": 2, "explanation": "'Certificates will be emailed within 24 hours of finishing.' Kevin completed it 20 hours ago \u2192 still within the 24-hour window.", "difficulty": "medium"}, {"id": "c7-t1c", "part": 7, "question": "Does Kevin Ho need to complete Course 2?", "options": ["No, Course 2 is only for IT staff.", "Yes, because he is a client relationship manager and handles client data.", "No, Course 2 is optional for all employees.", "It cannot be determined from the information provided."], "answer": 1, "explanation": "Policy: 'Employees who handle sensitive client data must additionally complete an advanced data protection course'. Kevin is a 'client relationship manager' \u2014 he handles client data.", "difficulty": "medium"}, {"id": "c7-t1d", "part": 7, "question": "What will happen to Kevin Ho's account if he does not update his password by October 31?", "options": ["He will receive a final warning email.", "His account access will be temporarily suspended.", "His account will be permanently deleted.", "He will be required to meet with the IT Security Team."], "answer": 1, "explanation": "'Non-compliance with items 1\u20133 by October 31 will result in account access being temporarily suspended'.", "difficulty": "medium"}, {"id": "c7-t1e", "part": 7, "question": "If Kevin Ho attends the October Q&A session for Course 2, what is the latest possible date for him to complete the course?", "options": ["October 22", "October 31", "November 8", "November 15"], "answer": 3, "explanation": "'Advanced Data Protection...Deadline: November 15'. Attending the October Q&A does not change the overall course deadline.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Product Specification Sheet]\n\nMAGNOLIA OFFICE SYSTEMS \u2013 FURNITURE CATALOG\n\nItem: Executive Standing Desk \u2013 Model ESD-700\nDimensions: 160cm (W) \u00d7 80cm (D) \u00d7 65\u2013130cm (H)\nSurface: Scratch-resistant laminate in Walnut, Maple, or White\nFrame: Powder-coated steel; available in Black or Silver\nHeight Adjustment: Electric motor; 3 memory presets\nWeight Capacity: 120 kg\nWarranty: 3 years on parts; 1 year on electrical components\nLead Time: 10\u201314 business days from order confirmation\nPrice: USD 980 per unit\nBulk Discount: 5% on orders of 10\u201319 units; 10% on orders of 20+\n\n[Document 2 \u2013 Purchase Order]\n\nPURCHASE ORDER \u2013 #PO-4492\nBuyer: Nexus Coworking Hub\nDate: March 5\nSupplier: Magnolia Office Systems\n\nItem                  Qty   Unit Price   Total\nESD-700 (Maple/Black)  22   USD 980      USD 21,560\n\nApplied Discount: 10% (order of 20+ units)\nDiscounted Total: USD 19,404\n\nRequested Delivery Date: March 26\nDelivery Address: 12 Greenway Boulevard, Suite 400, Austin, TX\n\nAuthorized by: Dana Kim, Procurement Manager\n\n[Document 3 \u2013 Delivery Confirmation]\n\nFrom: dispatch@magnoliaofficesystems.com\nTo: d.kim@nexuscoworking.com\nDate: March 7\n\nDear Ms. Kim,\n\nThank you for your order (PO-4492). We are pleased to confirm that your order of 22 ESD-700 desks has been processed and is scheduled for dispatch on March 19.\n\nExpected delivery: March 22\u201324.\n\nPlease note that the Maple surface finish in combination with the Black frame is currently on a 3-day extended lead time due to high demand. This has been factored into the dispatch schedule above.\n\nA tracking number will be provided on the day of dispatch. For assembly, we recommend a professional installation team for orders exceeding 10 units. Our certified installer network can be reached at install@magnoliaofficesystems.com.\n\nThank you for choosing Magnolia Office Systems.\n\nBest regards,\nDispatch Team, Magnolia Office Systems", "passageTitle": "Product Spec Sheet + Purchase Order + Delivery Confirmation", "type": "triple", "questions": [{"id": "c7-t2a", "part": 7, "question": "What discount rate applies to Nexus Coworking Hub's order?", "options": ["No discount", "5%", "10%", "15%"], "answer": 2, "explanation": "Order of 22 units \u2192 '10% on orders of 20+'. Confirmed in PO: 'Applied Discount: 10%'.", "difficulty": "medium"}, {"id": "c7-t2v", "part": 7, "question": "What can be inferred about the Maple/Black finish of the ESD-700?", "options": ["It is the most expensive finish available", "It is particularly popular and in high demand", "It is available only for orders of 20 or more units", "It is a limited-edition design"], "answer": 1, "explanation": "Inference: Doc3 states \"Maple surface with Black frame is currently on a 3-day extended lead time due to high demand\" \u2192 inferred that this specific combination is particularly popular."}, {"id": "c7-t2d", "part": 7, "question": "Why is the delivery arriving later than the originally requested date?", "options": ["The payment was processed late.", "The order quantity exceeded the warehouse stock.", "The Maple/Black combination has an extended lead time due to high demand.", "The delivery address was incorrect in the original order."], "answer": 2, "explanation": "'the Maple surface finish in combination with the Black frame is currently on a 3-day extended lead time due to high demand'.", "difficulty": "medium"}, {"id": "c7-t2e", "part": 7, "question": "What recommendation does Magnolia make regarding assembly?", "options": ["Customers should self-assemble using the included instructions.", "Assembly is included for free in all orders over 10 units.", "A professional installation team is recommended for orders exceeding 10 units.", "Assembly must be scheduled at least 5 days in advance."], "answer": 2, "explanation": "'we recommend a professional installation team for orders exceeding 10 units'.", "difficulty": "medium"}, {"id": "c7-t2f", "part": 7, "question": "How long is the warranty on the electrical components of the ESD-700?", "options": ["6 months", "1 year", "2 years", "3 years"], "answer": 1, "explanation": "'Warranty: 3 years on parts; 1 year on electrical components'.", "difficulty": "medium"}]}, {"passage": "NOTICE TO ALL STAFF\nMeridian Consulting Group \u2013 Building 3, Floors 4 & 5\n\nOFFICE RENOVATION \u2013 TEMPORARY WORKSPACE ARRANGEMENTS\n\nAs previously communicated, the renovation of Floors 4 and 5 of Building 3 is scheduled to begin Monday, March 10 and is expected to last six weeks.\n\nDuring this period:\n\u2022 Staff currently located on Floors 4 and 5 (approximately 85 employees) will be relocated to the co-working facility at Meridian Centre, 230 King Street, Level 2.\n\u2022 All staff will be issued new temporary access badges starting March 7. Your current badge will remain valid for Building 3 common areas and the parking garage.\n\u2022 IT will complete the setup of all workstations at the co-working space by end of day March 7.\n\u2022 Mail and courier deliveries will continue to be directed to Building 3 and forwarded daily to King Street.\n\nThe caf\u00e9 on Ground Floor of Building 3 will remain open throughout the renovation period. Parking allocations are unchanged.\n\nIf you have specific workstation requirements (e.g., dual monitors, ergonomic chairs), please submit a request to facilities@meridiancg.com no later than March 5.\n\nWe appreciate your flexibility during this period.\n\nBuilding Operations Team\nMeridian Consulting Group", "passageTitle": "Notice: Staff Announcement", "type": "single", "questions": [{"id": "g7-s1a", "part": 7, "question": "Where will affected staff work during the renovation?", "options": ["In the conference rooms of Building 3", "At the co-working facility on King Street", "At a partner company's office", "From home full-time"], "answer": 1, "explanation": "'Staff...will be relocated to the co-working facility at Meridian Centre, 230 King Street'.", "difficulty": "medium"}, {"id": "g7-s1b", "part": 7, "question": "By what date must special workstation requests be submitted?", "options": ["March 5", "March 7", "March 10", "March 14"], "answer": 0, "explanation": "'please submit a request to facilities@meridiancg.com no later than March 5'.", "difficulty": "medium"}, {"id": "g7-s1c", "part": 7, "question": "What will remain unchanged during the renovation period?", "options": ["Mail delivery location", "Floor access badges", "Parking allocations", "IT workstation setup"], "answer": 2, "explanation": "'Parking allocations are unchanged'.", "difficulty": "medium"}, {"id": "g7-s1d", "part": 7, "question": "What can be inferred about employees NOT on Floors 4 and 5?", "options": ["They will also be relocated to King Street", "They will work from home during the renovation", "They will continue working in Building 3 as usual", "They must also submit workstation preference requests"], "answer": 2, "explanation": "Only the 85 staff on Floors 4 and 5 are mentioned as being relocated \u2192 others remain in Building 3.", "difficulty": "medium"}]}, {"passage": "AUTOMATED WAREHOUSES: THE NEXT FRONTIER IN LAST-MILE DELIVERY\nSupply Chain Today | April Edition\n\nThe rapid growth of e-commerce has placed unprecedented pressure on logistics companies to fulfil orders faster, more accurately, and at lower cost. In response, a growing number of major retailers and third-party logistics (3PL) providers are turning to warehouse automation as a strategic solution.\n\nAt the heart of this shift are autonomous mobile robots (AMRs) \u2014 devices that navigate warehouse floors independently, retrieving and transporting goods to packing stations. Unlike older conveyor-belt systems, AMRs are flexible, scalable, and can be deployed without major structural changes to an existing facility.\n\nGreenPort Logistics, one of Southeast Asia's largest 3PL operators, recently completed a phased rollout of 320 AMRs across its three flagship warehouses in Singapore, Malaysia, and Vietnam. The results have been compelling: order processing speed improved by 47%, picking accuracy reached 99.8%, and the company reported a 22% reduction in labour costs per unit.\n\nHowever, industry observers caution that automation is not without challenges. The upfront capital investment can be substantial \u2014 GreenPort's rollout reportedly cost in excess of USD 14 million. Additionally, integrating AMR systems with existing warehouse management software (WMS) requires significant technical expertise, and staff must be retrained to work alongside robotic systems rather than replacing manual processes entirely.\n\nDespite these hurdles, analysts predict that by 2030, more than 60% of large fulfilment centres globally will incorporate some form of robotic automation, up from roughly 20% today.", "passageTitle": "Business Article", "type": "single", "questions": [{"id": "g7-s2a", "part": 7, "question": "What advantage do AMRs have over older conveyor-belt systems?", "options": ["They are significantly cheaper to purchase", "They can be used without modifying existing facilities", "They do not require any staff training", "They eliminate the need for warehouse management software"], "answer": 1, "explanation": "'AMRs are flexible, scalable, and can be deployed without major structural changes to an existing facility'.", "difficulty": "medium"}, {"id": "g7-s2b", "part": 7, "question": "What was one outcome of GreenPort Logistics' AMR rollout?", "options": ["Labour costs increased by 22%", "Order accuracy reached 94%", "Picking accuracy reached 99.8%", "Processing speed improved by 22%"], "answer": 2, "explanation": "'picking accuracy reached 99.8%' \u2014 confirmed in GreenPort's results.", "difficulty": "medium"}, {"id": "g7-s2c", "part": 7, "question": "According to the article, what is one challenge associated with warehouse automation?", "options": ["AMRs are incompatible with existing warehouse floors", "The technology requires replacing all manual staff", "Significant upfront capital investment is required", "Automation slows down order fulfilment speed"], "answer": 2, "explanation": "'The upfront capital investment can be substantial \u2014 GreenPort's rollout reportedly cost in excess of USD 14 million'.", "difficulty": "medium"}, {"id": "p7-s-v32", "part": 7, "question": "In the article, the word \"unprecedented\" is closest in meaning to", "options": ["never seen before", "unexpectedly fast", "highly significant", "largely unplanned"], "answer": 0, "explanation": "WIC: \"unprecedented growth/levels\" = ch\u01b0a t\u1eebng c\u00f3 ti\u1ec1n l\u1ec7. \"Never seen before\" l\u00e0 di\u1ec5n \u0111\u1ea1t ch\u00ednh x\u00e1c nh\u1ea5t. \"Highly significant\" = quan tr\u1ecdng (kh\u00e1c ngh\u0129a)."}]}, {"passage": "[Document 1 \u2013 Training Invitation Email]\n\nFrom: Learning & Development Team <ld@stellargroup.com>\nTo: All Middle Managers\nDate: May 6\nSubject: Invitation \u2013 Leadership Accelerator Workshop (May 28)\n\nDear Managers,\n\nYou are invited to attend our upcoming half-day Leadership Accelerator Workshop, designed exclusively for middle managers at Stellar Group.\n\nDate:    Wednesday, May 28\nTime:    9:00 a.m. \u2013 1:00 p.m.\nVenue:   The Boardroom, Level 12, HQ Tower\nFacilitator: Ms. Elena Voss, Executive Coach and former VP of Talent at Fortune Dynamics\n\nThe workshop will focus on three areas: influencing without authority, managing upward effectively, and building high-performing cross-functional teams. Attendance is strongly encouraged but not mandatory.\n\nSpaces are limited to 20 participants. Please register via the staff portal by May 16 to secure your place. Managers who register after this date will be placed on a waiting list.\n\nLight refreshments will be provided.\n\n[Document 2 \u2013 Registration Confirmation]\n\nFrom: Learning & Development Team <ld@stellargroup.com>\nTo: Adrian Moss <a.moss@stellargroup.com>\nDate: May 10\nSubject: Registration Confirmed \u2013 Leadership Accelerator Workshop\n\nDear Adrian,\n\nThank you for registering for the Leadership Accelerator Workshop on May 28. Your place has been confirmed.\n\nPlease note that due to high demand, the workshop is now fully booked. If you are unable to attend, we kindly ask that you cancel your registration via the staff portal at least five business days before the event so that a colleague on the waiting list can take your place.\n\nA full pre-reading pack will be sent to you one week before the workshop. We recommend setting aside approximately 90 minutes to review the materials in advance.\n\nWe look forward to seeing you on May 28.\n\nBest regards,\nLearning & Development Team", "passageTitle": "Training Invitation + Registration Confirmation", "type": "double", "questions": [{"id": "g7-d1a", "part": 7, "question": "What does the confirmation email reveal about the workshop's current status?", "options": ["It has been postponed to a later date", "It has reached maximum capacity", "Attendance is now mandatory for all managers", "The venue has been changed"], "answer": 1, "explanation": "'due to high demand, the workshop is now fully booked' \u2192 \u0111\u00e3 \u0111\u1ee7 20 ng\u01b0\u1eddi (maximum).", "difficulty": "medium"}, {"id": "g7-d1v", "part": 7, "question": "What does the confirmation email most likely imply about the popularity of this type of workshop?", "options": ["Leadership training is mandatory for all staff", "The workshop filled quickly, suggesting strong demand among managers", "The company has a limited training budget", "Similar workshops have been unsuccessful in the past"], "answer": 1, "explanation": "Inference: \"Due to high demand, the workshop is now fully booked\" + registration confirmed quickly \u2192 strong demand among managers for this type of leadership training."}, {"id": "g7-d1c", "part": 7, "question": "What is mentioned about the workshop facilitator?", "options": ["She currently works at Fortune Dynamics", "She has prior experience in talent management", "She is a current employee of Stellar Group", "She developed the pre-reading materials"], "answer": 1, "explanation": "Document 1: \"Ms. Elena Voss, Executive Coach and former VP of Talent at Fortune Dynamics\" \u2192 prior experience in talent management (VP of Talent = ng\u01b0\u1eddi l\u00e3nh \u0111\u1ea1o b\u1ed9 ph\u1eadn nh\u00e2n s\u1ef1)."}, {"id": "g7-d1d", "part": 7, "question": "What are participants asked to do if they cannot attend?", "options": ["Email the L&D team directly", "Complete the pre-reading pack instead", "Cancel via the staff portal in advance", "Find a replacement from their department"], "answer": 2, "explanation": "Document 2: \"we kindly ask that you cancel your registration via the staff portal at least five business days before the event\" \u2192 h\u1ee7y qua c\u1ed5ng th\u00f4ng tin nh\u00e2n vi\u00ean \u00edt nh\u1ea5t 5 ng\u00e0y tr\u01b0\u1edbc."}, {"id": "g7-d1e", "part": 7, "question": "In Document 2, the word \"kindly\" in the phrase \"we kindly ask\" is closest in meaning to", "options": ["firmly", "warmly", "politely", "urgently"], "answer": 2, "explanation": "Word-in-context: \"kindly ask\" = \u0111\u1ec1 ngh\u1ecb m\u1ed9t c\u00e1ch l\u1ecbch s\u1ef1. \"Politely\" = l\u1ecbch s\u1ef1. \"Firmly\" = c\u1ee9ng r\u1eafn, \"warmly\" = \u1ea5m \u00e1p, \"urgently\" = kh\u1ea9n c\u1ea5p."}]}, {"passage": "INTERNAL ANNOUNCEMENT\nFrom:  Office of the President\nTo:    All Employees\nDate:  January 18\n\nRE: ORGANISATIONAL RESTRUCTURING \u2013 EFFECTIVE MARCH 1\n\nFollowing a comprehensive strategic review conducted over the past quarter, Halcyon Industries will reorganise its operations into three focused business units: Industrial Solutions, Consumer Products, and Digital Services.\n\nThis restructuring is designed to improve accountability, accelerate decision-making, and align our teams more closely with specific market segments.\n\nKey changes include:\n\u2022 The current Operations and Manufacturing divisions will merge to form the Industrial Solutions business unit, led by Mr. Victor Russo.\n\u2022 The Consumer Products unit will be led by Ms. Angela Tran, who is relocating from our Sydney office to assume this role.\n\u2022 The newly established Digital Services unit will be led by Mr. James Okafor, currently Head of Innovation.\n\u2022 The Corporate Affairs and Communications teams will continue to operate centrally and report directly to the President's Office.\n\nA town hall meeting will be held on January 25 to give employees an opportunity to ask questions. Managers are asked to cascade this information to their teams by January 20.\n\nDetailed transition plans will be shared with affected departments by February 10.", "passageTitle": "Business Email", "type": "single", "questions": [{"id": "h7-s1a", "part": 7, "question": "What is the main purpose of this announcement?", "options": ["To introduce three new executive hires", "To inform staff of an upcoming organisational restructuring", "To announce the acquisition of three new companies", "To present quarterly financial results"], "answer": 1, "explanation": "'Halcyon Industries will reorganise its operations into three focused business units' \u2014 th\u00f4ng b\u00e1o t\u00e1i c\u01a1 c\u1ea5u t\u1ed5 ch\u1ee9c.", "difficulty": "medium"}, {"id": "h7-s1b", "part": 7, "question": "What will happen to the Operations and Manufacturing divisions?", "options": ["They will be closed down", "They will be led by Ms. Angela Tran", "They will merge into the Industrial Solutions unit", "They will report directly to the President's Office"], "answer": 2, "explanation": "'The current Operations and Manufacturing divisions will merge to form the Industrial Solutions business unit'.", "difficulty": "medium"}, {"id": "h7-s1c", "part": 7, "question": "What is mentioned about Ms. Angela Tran?", "options": ["She is a new hire from outside the company", "She is currently Head of Innovation", "She will be moving from the Sydney office", "She was previously in charge of the Digital Services unit"], "answer": 2, "explanation": "'Ms. Angela Tran, who is relocating from our Sydney office to assume this role'.", "difficulty": "medium"}, {"id": "p7-s-v33", "part": 7, "question": "What can be inferred about the reason for the organisational restructuring?", "options": ["The company is facing financial difficulties", "The restructuring is aimed at improving operational efficiency", "The CEO is departing and a new leadership team is taking over", "The merger with another company has been finalised"], "answer": 1, "explanation": "Inference: Merging Operations and Manufacturing divisions typically signals a move to improve coordination and efficiency \u2014 inferred from the standard business rationale for consolidation."}]}, {"passage": "REVIEW: Nexus Coworking Hub \u2013 Austin, TX\nPlatform: WorkspaceRater.com  |  Rating: \u2605\u2605\u2605\u2605\u2606 (4/5)\nPosted by: T. Okonkwo  |  Verified Member\n\nI have been a hot-desk member at Nexus Coworking Hub for the past four months, and overall I am very satisfied with what it offers.\n\nThe facilities are modern and well-maintained \u2014 fast Wi-Fi, a well-equipped kitchen, and plenty of natural light. The staff are always helpful and quick to resolve any issues. On two occasions I needed a private meeting room on short notice, and both times a room was made available within the hour.\n\nMy only area of concern is noise levels in the open workspace during certain hours, particularly between 10 a.m. and noon, when it can get quite loud due to group discussions and phone calls. For deep focus work, I tend to move to the quieter pods near the back.\n\nThe pricing is competitive for the Austin market. At USD 199 per month, the hot-desk plan is reasonable, especially given the round-the-clock access and the excellent location near the city centre.\n\nI would recommend Nexus to freelancers and remote workers who value flexibility. Those who require consistently quiet conditions may want to look at dedicated desk or private office options instead.", "passageTitle": "Customer Review", "type": "single", "questions": [{"id": "h7-s2a", "part": 7, "question": "How long has the reviewer been a member at Nexus?", "options": ["One month", "Two months", "Four months", "Six months"], "answer": 2, "explanation": "'I have been a hot-desk member at Nexus Coworking Hub for the past four months'.", "difficulty": "medium"}, {"id": "h7-s2b", "part": 7, "question": "What concern does the reviewer mention about the workspace?", "options": ["The Wi-Fi speed is inconsistent", "The kitchen facilities are poorly maintained", "The open area becomes noisy during certain hours", "Meeting rooms are rarely available on short notice"], "answer": 2, "explanation": "'My only area of concern is noise levels in the open workspace during certain hours'.", "difficulty": "medium"}, {"id": "h7-s2c", "part": 7, "question": "How much does the hot-desk plan cost per month?", "options": ["USD 99", "USD 149", "USD 199", "USD 249"], "answer": 2, "explanation": "'At USD 199 per month, the hot-desk plan is reasonable'.", "difficulty": "medium"}, {"id": "h7-s2d", "part": 7, "question": "What does the reviewer suggest for those who need a consistently quiet environment?", "options": ["Work during early morning hours", "Use the quiet pods near the back", "Consider a dedicated desk or private office", "Book a private meeting room for the full day"], "answer": 2, "explanation": "'Those who require consistently quiet conditions may want to look at dedicated desk or private office options instead'.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Internship Job Posting]\n\nMARKETING INTERNSHIP \u2013 SUMMER PROGRAMME\nLuminary Creative Agency | Melbourne, Australia\n\nDuration:  12 weeks (June 2 \u2013 August 22)\nType:      Paid internship (AUD 800/week)\nLocation:  On-site, Melbourne CBD\n\nAbout the Role:\nLuminary Creative Agency is seeking one motivated marketing intern to support our client services and content team during the summer programme.\n\nResponsibilities:\n\u2022 Assist in the development of social media content calendars\n\u2022 Conduct market research and compile competitor analysis reports\n\u2022 Support account managers in preparing client presentations\n\u2022 Attend weekly client briefings (observation role)\n\nRequirements:\n\u2022 Currently enrolled in a Bachelor's or Master's degree programme in Marketing, Communications, or a related field\n\u2022 Strong written English and attention to detail\n\u2022 Proficiency in Canva or Adobe Creative Suite (preferred, not required)\n\nApplication Deadline: April 18\nTo apply: Send CV and a 300-word cover letter to intern@luminarycreative.com.au\n\n[Document 2 \u2013 Applicant Follow-up Email]\n\nFrom: Sophie Larkin <s.larkin@email.com>\nTo: intern@luminarycreative.com.au\nDate: April 22\nSubject: Follow-up \u2013 Marketing Internship Application\n\nDear Hiring Team,\n\nI am writing to follow up on my application for the Summer Marketing Internship, which I submitted on April 15.\n\nI remain very enthusiastic about the opportunity and would welcome any update on the status of my application. I am available for an interview at your convenience and can provide additional references if required.\n\nPlease let me know if there is any further information I can provide to support my candidacy.\n\nThank you for your time and consideration.\n\nBest regards,\nSophie Larkin", "passageTitle": "Internship Posting + Applicant Follow-up Email", "type": "double", "questions": [{"id": "h7-d1a", "part": 7, "question": "What does Sophie Larkin's follow-up email indicate about her application?", "options": ["She submitted her application after the deadline", "She applied before the stated deadline", "She has already been invited to interview", "She is requesting to withdraw her application"], "answer": 1, "explanation": "Sophie submitted on April 15; the deadline was April 18 \u2192 she applied before the deadline.", "difficulty": "medium"}, {"id": "h7-d1b", "part": 7, "question": "What is described as preferred but not required in the job posting?", "options": ["A degree in Marketing or Communications", "Strong written English skills", "Proficiency in Canva or Adobe Creative Suite", "Experience with competitor analysis"], "answer": 2, "explanation": "'Proficiency in Canva or Adobe Creative Suite (preferred, not required)'.", "difficulty": "medium"}, {"id": "h7-d1c", "part": 7, "question": "What will the intern be responsible for during the programme?", "options": ["Managing social media accounts independently", "Attending client briefings as an observer", "Leading competitor analysis presentations", "Designing marketing campaigns for major clients"], "answer": 1, "explanation": "Document 1: \"Attend weekly client briefings (observation role)\" \u2192 tham d\u1ef1 bu\u1ed5i briefing kh\u00e1ch h\u00e0ng v\u1edbi vai tr\u00f2 quan s\u00e1t."}, {"id": "h7-d1d", "part": 7, "question": "What does Sophie Larkin offer to provide in her email?", "options": ["A portfolio of past work", "A formal cover letter revision", "Additional references if required", "Her academic transcript"], "answer": 2, "explanation": "Document 2: \"I...can provide additional references if required\" \u2192 c\u00f3 th\u1ec3 cung c\u1ea5p th\u00eam ng\u01b0\u1eddi tham kh\u1ea3o n\u1ebfu c\u1ea7n."}, {"id": "h7-d1e", "part": 7, "question": "In Document 1, the word \"motivated\" is closest in meaning to", "options": ["experienced", "qualified", "enthusiastic", "flexible"], "answer": 2, "explanation": "Word-in-context: \"seeking one motivated marketing intern\" \u2014 \"motivated\" = c\u00f3 \u0111\u1ed9ng l\u1ef1c, nhi\u1ec7t huy\u1ebft. \"Enthusiastic\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh tuy\u1ec3n d\u1ee5ng."}]}, {"passage": "CUSTOMER NOTICE\n\nClearView Opticians \u2014 Store Relocation\n\nDear Customers,\n\nWe are pleased to announce that ClearView Opticians will be moving to a new, larger location at 250 Maple Avenue, Suite 3B, effective December 1. Our current location at 88 Oak Street will remain open until November 30.\n\nThe new store will feature an expanded selection of designer frames, a state-of-the-art eye examination room, and a dedicated children's eyewear section. To celebrate the grand opening, we are offering 20% off all frames and lenses purchased during the first two weeks.\n\nOur phone number and email address will remain the same. For appointments, please call (555) 834-2100 or visit clearviewopticians.com.\n\nThank you for your continued patronage.\n\nDr. Maria Santos\nOwner, ClearView Opticians", "passageTitle": "Customer Notice", "type": "single", "questions": [{"id": "e7-1a", "part": 7, "question": "What is the purpose of this notice?", "options": ["To announce a store closing", "To advertise a new product line", "To inform customers about a relocation", "To introduce a new employee"], "answer": 2, "explanation": "Th\u00f4ng b\u00e1o di chuy\u1ec3n c\u1eeda h\u00e0ng \u0111\u1ebfn \u0111\u1ecba ch\u1ec9 m\u1edbi: 250 Maple Avenue.", "difficulty": "medium"}, {"id": "e7-1b", "part": 7, "question": "What will customers find at the new location?", "options": ["Lower prices on all items", "A children's eyewear section", "Extended weekend hours", "Free parking"], "answer": 1, "explanation": "'a dedicated children's eyewear section' = khu k\u00ednh tr\u1ebb em chuy\u00ean bi\u1ec7t.", "difficulty": "medium"}, {"id": "e7-1c", "part": 7, "question": "What special offer is available?", "options": ["Free eye exams for new customers", "Half-price contact lenses", "20% off frames and lenses for two weeks", "Buy one get one free"], "answer": 2, "explanation": "'20% off all frames and lenses purchased during the first two weeks'.", "difficulty": "medium"}, {"id": "e7-1d", "part": 7, "question": "What will NOT change after the move?", "options": ["The store address", "The store size", "The phone number", "The frame selection"], "answer": 2, "explanation": "'Our phone number and email address will remain the same'.", "difficulty": "medium"}]}, {"passage": "WORKSHOP ANNOUNCEMENT\n\nEffective Communication Skills for Managers\n\nDate: Saturday, March 22, 9:00 a.m. \u2013 4:00 p.m.\nLocation: Harper Business Center, Room 401\nInstructor: Dr. Angela Torres, Ph.D. in Organizational Psychology\nFee: $175 per participant (includes materials and lunch)\n\nThis one-day workshop is designed for supervisors and managers who want to improve their communication with team members. Topics include active listening, giving constructive feedback, managing difficult conversations, and motivating teams through clear messaging.\n\nClass size is limited to 20 participants to allow for personalized coaching. Early registration is recommended as our previous workshops have filled up quickly.\n\nTo register, visit www.harperbci.com/workshops or call (555) 209-4400.\nRegistration deadline: March 15.", "passageTitle": "Workshop: Effective Communication Skills for Manag", "type": "single", "questions": [{"id": "e7-2a", "part": 7, "question": "Who is the workshop primarily intended for?", "options": ["New employees", "Supervisors and managers", "IT professionals", "Marketing staff"], "answer": 1, "explanation": "'designed for supervisors and managers'.", "difficulty": "medium"}, {"id": "e7-2b", "part": 7, "question": "What is included in the $175 fee?", "options": ["Transportation to the venue", "A certificate of completion", "Materials and lunch", "Overnight accommodation"], "answer": 2, "explanation": "'$175 per participant (includes materials and lunch)'.", "difficulty": "medium"}, {"id": "e7-2c", "part": 7, "question": "Why is early registration recommended?", "options": ["There is a discount for early registration", "Previous workshops have sold out quickly", "The fee increases after March 15", "Only online registration is available"], "answer": 1, "explanation": "'as our previous workshops have filled up quickly'.", "difficulty": "medium"}, {"id": "p7-s-v34", "part": 7, "question": "Which of the following is NOT included in the workshop registration fee?", "options": ["Lunch", "Workshop materials", "Parking", "A follow-up coaching session"], "answer": 3, "explanation": "NOT TRUE: The fee includes lunch and materials. A follow-up coaching session is NOT mentioned as included \u2014 it would be a separate additional service."}]}, {"passage": "[Document 1 \u2013 Internal Memo]\nTo: All Sales Staff\nFrom: Regional Sales Director, Tom Bradley\nDate: August 20\n\nI am pleased to announce that Metro Electronics has been selected as one of three finalists for the National Retailer Excellence Award. This recognition is a direct result of your hard work in achieving record-breaking sales during Q1 and Q2.\n\nThe award ceremony will take place on September 28 at the Grand Pavilion Hotel. Two representatives from our company will attend the event. I plan to select those who have contributed most significantly to our success.\n\nPlease continue your outstanding efforts as we approach Q3 targets.\n\n[Document 2 \u2013 Email]\nFrom: Lisa Nguyen <l.nguyen@metroelec.com>\nTo: Tom Bradley <t.bradley@metroelec.com>\nDate: August 22\n\nDear Mr. Bradley,\n\nCongratulations on the nomination! I was thrilled to hear the news.\n\nI wanted to let you know that I will be attending a product training session in Chicago from September 25 to September 30. Unfortunately, this means I will be unable to attend the award ceremony even if selected.\n\nHowever, I would like to recommend my colleague, David Park, who led the Q2 campaign for our Western region and exceeded targets by 40%. I believe he would be an excellent representative for our team.\n\nBest regards,\nLisa Nguyen", "passageTitle": "Memo + Email", "type": "double", "questions": [{"id": "e7-3a", "part": 7, "question": "What is the main purpose of Tom Bradley's memo?", "options": ["To announce employee promotions", "To share news about an award nomination", "To set Q3 sales targets", "To introduce new sales policies"], "answer": 1, "explanation": "Th\u00f4ng b\u00e1o Metro Electronics \u0111\u01b0\u1ee3c ch\u1ecdn v\u00e0o chung k\u1ebft gi\u1ea3i th\u01b0\u1edfng National Retailer Excellence Award.", "difficulty": "medium"}, {"id": "e7-3v", "part": 7, "question": "What can be inferred about the relationship between the company and its client based on both documents?", "options": ["The client relationship is new and still being established", "The company has a strong, ongoing relationship with the client", "The relationship is under strain due to recent performance issues", "The award was given to compensate for a service failure"], "answer": 1, "explanation": "Inference: An award ceremony celebrating the company + positive memo tone together suggest a strong, established relationship \u2014 inferred from the celebratory context."}, {"id": "e7-3c", "part": 7, "question": "Why can't Lisa Nguyen attend the award ceremony?", "options": ["She has a family event", "She will be at a training session", "She is transferring to another office", "She is on vacation"], "answer": 1, "explanation": "'I will be attending a product training session in Chicago from September 25 to September 30'.", "difficulty": "medium"}, {"id": "e7-3d", "part": 7, "question": "What does Lisa Nguyen suggest?", "options": ["Postponing the ceremony", "Sending a video message instead", "Nominating David Park as a representative", "Canceling her training session"], "answer": 2, "explanation": "'I would like to recommend my colleague, David Park' as a representative.", "difficulty": "medium"}, {"id": "e7-3e", "part": 7, "question": "In Document 1, the word \"outstanding\" as used in the memo is closest in meaning to", "options": ["overdue", "exceptional", "prominent", "remaining"], "answer": 1, "explanation": "Word-in-context: \"Please continue your outstanding efforts\" \u2014 \"outstanding\" = xu\u1ea5t s\u1eafc, v\u01b0\u1ee3t tr\u1ed9i. \"Exceptional\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh khen ng\u1ee3i nh\u00e2n vi\u00ean."}]}, {"passage": "PRODUCT REVIEW\n\nAquaPure Water Filter System \u2013 Model AP-500\nReviewed by: Karen Mitchell, Home & Kitchen Monthly\n\nThe AquaPure AP-500 is a countertop water filtration system that promises to remove 99% of contaminants from tap water. After testing it for three months, I can confirm that it delivers on that promise.\n\nInstallation was straightforward and took less than 10 minutes. The filter cartridge lasts approximately six months and costs $35 to replace. The system itself retails for $149, making it one of the most affordable options in its category.\n\nThe only downside I noticed was the flow rate, which is slightly slower than competing models. However, the superior filtration quality more than compensates for this minor inconvenience.\n\nOverall rating: 4.5 out of 5 stars. Highly recommended for households looking for an effective and budget-friendly water purification solution.", "passageTitle": "Product Review", "type": "single", "questions": [{"id": "e7-4a", "part": 7, "question": "What type of text is this?", "options": ["An advertisement", "A product manual", "A product review", "A scientific study"], "answer": 2, "explanation": "Ti\u00eau \u0111\u1ec1 'PRODUCT REVIEW' v\u00e0 n\u1ed9i dung \u0111\u00e1nh gi\u00e1 s\u1ea3n ph\u1ea9m sau khi s\u1eed d\u1ee5ng.", "difficulty": "medium"}, {"id": "e7-4b", "part": 7, "question": "How long was the product tested?", "options": ["One month", "Three months", "Six months", "One year"], "answer": 1, "explanation": "'After testing it for three months'.", "difficulty": "medium"}, {"id": "e7-4c", "part": 7, "question": "What is mentioned as a disadvantage?", "options": ["High replacement cost", "Difficult installation", "Slow flow rate", "Limited warranty"], "answer": 2, "explanation": "'the flow rate, which is slightly slower than competing models'.", "difficulty": "medium"}, {"id": "p7-s-v35", "part": 7, "question": "In the review, the word \"cumbersome\" is closest in meaning to", "options": ["inconvenient", "heavy", "noisy", "unreliable"], "answer": 0, "explanation": "WIC: \"cumbersome\" = b\u1ea5t ti\u1ec7n, r\u01b0\u1eddm r\u00e0, kh\u00f3 s\u1eed d\u1ee5ng. \"Inconvenient\" n\u1eafm b\u1eaft \u0111\u00fang ngh\u0129a trong ng\u1eef c\u1ea3nh \u0111\u00e1nh gi\u00e1 s\u1ea3n ph\u1ea9m \u2014 n\u1eb7ng n\u1ec1 ho\u1eb7c kh\u00f3 thao t\u00e1c."}]}, {"passage": "INTERNAL MEMORANDUM\n\nTo:   All Staff\nFrom: Finance Department\nDate: 12 November\nRe:   Updated Expense Reimbursement Procedure\n\nEffective 1 December, all employee expense reimbursements will be processed through the new ExpenseBridge online platform. The current paper-based system will be retired on 30 November.\n\nTo be reimbursed, employees must:\n1. Log in to ExpenseBridge at expenses.strathmore.com using their staff ID and temporary password (sent separately by IT).\n2. Submit all receipts as digital scans or photos within 14 calendar days of the expense being incurred.\n3. Include a brief description and the relevant cost centre code for each item.\n\nExpenses submitted without the required cost centre code will be returned for correction and will not be processed until the information is complete.\n\nA training video on how to use ExpenseBridge is available on the company intranet under \"Finance Resources.\" A live Q&A session will also be held on 20 November at 2:00 P.M. via Teams for staff who would like additional guidance.\n\nPlease direct any questions to finance@strathmore.com.", "passageTitle": "Memo \u2013 Changes to Expense Reimbursement Process", "type": "single", "questions": [{"id": "t8-s1-1", "part": 7, "question": "What is the purpose of the memorandum?", "options": ["To introduce a new payroll system", "To announce changes to how expenses are reimbursed", "To remind staff about end-of-year tax submissions", "To inform employees about a new finance team member"], "answer": 1, "explanation": "Memo th\u00f4ng b\u00e1o v\u1ec1 thay \u0111\u1ed5i quy tr\u00ecnh ho\u00e0n ti\u1ec1n chi ph\u00ed qua n\u1ec1n t\u1ea3ng ExpenseBridge.", "difficulty": "medium"}, {"id": "t8-s1-2", "part": 7, "question": "By when must employees submit their receipts after incurring an expense?", "options": ["Within 7 calendar days", "Within 10 business days", "Within 14 calendar days", "Within 30 days"], "answer": 2, "explanation": "'Submit all receipts... within 14 calendar days of the expense being incurred' \u2013 quy \u0111\u1ecbnh r\u00f5 r\u00e0ng trong n\u1ed9i dung.", "difficulty": "medium"}, {"id": "t8-s1-3", "part": 7, "question": "What will happen if an expense is submitted without a cost centre code?", "options": ["It will be automatically declined.", "It will be processed after a 30-day delay.", "It will be returned and not processed until corrected.", "It will be forwarded to a manager for approval."], "answer": 2, "explanation": "'will be returned for correction and will not be processed until the information is complete'.", "difficulty": "medium"}, {"id": "p7-s-v36", "part": 7, "question": "What can be inferred about why the new process was introduced?", "options": ["To reduce the volume of fraudulent expense claims", "To improve the speed and accuracy of reimbursements", "To eliminate the role of the finance department in approvals", "To comply with a new government regulation"], "answer": 1, "explanation": "Inference: Memos announcing new expense processes typically aim to improve efficiency and reduce processing errors \u2014 the most likely rationale inferred from the context."}]}, {"passage": "THORNFIELD EXECUTIVE SUITES\nFully Serviced Office Space in the Heart of the Financial District\n\nWhether you need a private office for one or a collaborative workspace for a growing team, Thornfield Executive Suites offers flexible solutions designed around your business.\n\nWHAT WE OFFER\n\u2022 Private offices: 1\u201320 workstations, available from AUD 850/month\n\u2022 Hot-desking memberships: From AUD 250/month (access during business hours)\n\u2022 Meeting rooms: Bookable by the hour, fully equipped with video conferencing technology\n\u2022 Executive boardroom: Seats up to 24, available for half-day or full-day hire\n\nALL PLANS INCLUDE\n\u2713 High-speed fibre internet (up to 1 Gbps)\n\u2713 Reception and mail handling services\n\u2713 Access to communal kitchen and lounge\n\u2713 Complimentary tea and coffee\n\nCURRENT PROMOTION\nSign a 12-month lease for a private office before 30 November and receive your first month FREE.\n\nLOCATION\nLevel 18, One Exchange Tower | 100 Market Street, Sydney CBD\n\nTours available Monday to Friday, 9:00 A.M. \u2013 5:00 P.M. Book online at thornfieldsuites.com.au or call 1300 849 200.", "passageTitle": "Advertisement \u2013 Thornfield Executive Suites", "type": "single", "questions": [{"id": "t8-s2-1", "part": 7, "question": "What type of business does Thornfield Executive Suites operate?", "options": ["A corporate hotel for business travellers", "A commercial property management firm", "A provider of serviced office space", "A technology company offering remote work tools"], "answer": 2, "explanation": "'Fully Serviced Office Space' l\u00e0 d\u1ecbch v\u1ee5 ch\u00ednh \u0111\u01b0\u1ee3c cung c\u1ea5p. Kh\u00f4ng ph\u1ea3i kh\u00e1ch s\u1ea1n, c\u00f4ng ty qu\u1ea3n l\u00fd B\u0110S, hay c\u00f4ng ty c\u00f4ng ngh\u1ec7.", "difficulty": "medium"}, {"id": "t8-s2-2", "part": 7, "question": "What is included in all office plans?", "options": ["Free parking in the building", "A dedicated receptionist for each tenant", "Access to a communal kitchen", "Complimentary printing services"], "answer": 2, "explanation": "'Access to communal kitchen and lounge' \u0111\u01b0\u1ee3c li\u1ec7t k\u00ea trong m\u1ee5c ALL PLANS INCLUDE. Kh\u00f4ng \u0111\u1ec1 c\u1eadp \u0111\u1ebfn parking, dedicated receptionist, hay printing.", "difficulty": "medium"}, {"id": "t8-s2-3", "part": 7, "question": "What condition must be met to receive the promotional offer?", "options": ["Booking a meeting room for a full day", "Signing a 12-month lease before November 30", "Paying the first three months in advance", "Referring another business to Thornfield"], "answer": 1, "explanation": "'Sign a 12-month lease for a private office before 30 November and receive your first month FREE'.", "difficulty": "medium"}, {"id": "t8-s2-4", "part": 7, "question": "What is suggested about the hot-desking membership?", "options": ["It includes 24-hour building access.", "It is the most expensive plan available.", "It does not provide a permanently assigned workspace.", "It requires a minimum 6-month commitment."], "answer": 2, "explanation": "'Hot-desking' theo \u0111\u1ecbnh ngh\u0129a l\u00e0 kh\u00f4ng c\u00f3 ch\u1ed7 ng\u1ed3i c\u1ed1 \u0111\u1ecbnh. Membership m\u00f4 t\u1ea3 'access during business hours' ch\u1ee9 kh\u00f4ng n\u00f3i v\u1ec1 ch\u1ed7 ng\u1ed3i c\u1ed1 \u0111\u1ecbnh.", "difficulty": "medium"}]}, {"passage": "MERIDIAN INFRASTRUCTURE GROUP\nSuite 400, 250 Bay Street\nVancouver, BC  V6C 1L4\n\nNovember 8\n\nMr. Kwame Asante\nManaging Director\nAsante Civil Engineering Ltd.\n1890 Industrial Parkway\nBurnaby, BC  V5A 2C7\n\nDear Mr. Asante,\n\nRe: Contract Award \u2013 Westbrook Community Centre Redevelopment\n\nFollowing a competitive tender process, I am pleased to inform you that Asante Civil Engineering Ltd. has been selected as the preferred contractor for the Westbrook Community Centre Redevelopment project. Your submission demonstrated exceptional technical competence and offered the most favourable combination of cost-effectiveness and project timeline.\n\nThe contract is valued at CAD 4.2 million and encompasses the demolition of the existing structure, site preparation, and the construction of the new 2,800-square-metre community centre facility. Work is scheduled to commence on 6 January, with an expected completion date of 30 November of the following year.\n\nA formal contract document will be sent to your office by 20 November for review and execution. Please ensure that all required insurance certificates and subcontractor details are submitted to our project manager, Ms. Ingrid Hoffman, within ten business days of receiving the contract.\n\nWe look forward to working with Asante Civil Engineering on this important community project.\n\nYours sincerely,\n\nDouglas Park\nDirector of Project Development\nMeridian Infrastructure Group", "passageTitle": "Business Letter \u2013 Contract Award Notice", "type": "single", "questions": [{"id": "t8-s3-1", "part": 7, "question": "Why is Mr. Park writing to Mr. Asante?", "options": ["To request additional information about a tender submission", "To inform him that his company has been awarded a contract", "To invite him to submit a proposal for a new project", "To notify him of a change in project specifications"], "answer": 1, "explanation": "'I am pleased to inform you that Asante Civil Engineering Ltd. has been selected as the preferred contractor' \u2013 th\u00f4ng b\u00e1o tr\u00fang th\u1ea7u.", "difficulty": "medium"}, {"id": "t8-s3-2", "part": 7, "question": "What does the contract involve?", "options": ["Renovating an existing sports facility", "Constructing a new office building", "Demolishing a building and constructing a new community centre", "Expanding a school campus"], "answer": 2, "explanation": "'demolition of the existing structure... and the construction of the new 2,800-square-metre community centre facility'.", "difficulty": "medium"}, {"id": "t8-s3-3", "part": 7, "question": "When is the project expected to be completed?", "options": ["By November 20 of the current year", "By January 6 of the following year", "By November 30 of the following year", "By December 31 of the following year"], "answer": 2, "explanation": "'expected completion date of 30 November of the following year'.", "difficulty": "medium"}, {"id": "p7-s-v37", "part": 7, "question": "In the letter, the phrase \"look forward to a successful collaboration\" suggests that", "options": ["the writer expects the project to be challenging", "the parties have not worked together before", "the writer is confident the project will be completed well", "the final contract has not yet been signed"], "answer": 2, "explanation": "Inference: \"Look forward to a successful collaboration\" is a standard closing expression expressing optimism and confidence in a positive outcome \u2014 not indicating novelty or uncertainty."}]}, {"passage": "RIVERSTONE CORPORATE LIBRARY\nInformation & Research Services for Riverstone Group Employees\n\nABOUT OUR SERVICES\nThe Riverstone Corporate Library provides employees with access to a comprehensive range of business and industry resources, including databases, journals, market reports, and reference materials.\n\nBORROWING BOOKS\n\u2022 Employees may borrow up to 5 books at a time.\n\u2022 Loan period: 3 weeks, with one renewal permitted if no reservation exists.\n\u2022 Books can be returned to any of the three library locations (City HQ, North Campus, and Eastside Office).\n\nONLINE DATABASES\nAll employees have remote access to our licensed databases, including IBISWorld, Statista, and ProQuest. Access your personal login via the employee portal at intranet.riverstone.com/library.\n\nRESEARCH ASSISTANCE\nOur librarians offer one-on-one research consultations, available Monday to Thursday, 9:00 A.M. to 4:00 P.M. Sessions can be booked up to two weeks in advance through the library portal.\n\nDOCUMENT DELIVERY\nArticles and reports not available through our current subscriptions can be requested through our document delivery service. Requests are typically fulfilled within 3 business days.\n\nFor general enquiries, contact the library team at library@riverstone.com or call extension 1500.", "passageTitle": "Web Page \u2013 Riverstone Corporate Library Services", "type": "single", "questions": [{"id": "t8-s4-1", "part": 7, "question": "How many books may an employee borrow at one time?", "options": ["Three", "Five", "Seven", "Ten"], "answer": 1, "explanation": "'Employees may borrow up to 5 books at a time' \u2013 t\u1ed1i \u0111a 5 quy\u1ec3n.", "difficulty": "medium"}, {"id": "t8-s4-2", "part": 7, "question": "When are research consultations available?", "options": ["Monday through Friday, 9:00 A.M. to 5:00 P.M.", "Monday through Thursday, 9:00 A.M. to 4:00 P.M.", "Tuesday through Friday, 10:00 A.M. to 3:00 P.M.", "By appointment only, any day of the week"], "answer": 1, "explanation": "'Monday to Thursday, 9:00 A.M. to 4:00 P.M.' \u2013 ch\u1ec9 t\u1eeb th\u1ee9 Hai \u0111\u1ebfn th\u1ee9 N\u0103m.", "difficulty": "medium"}, {"id": "t8-s4-3", "part": 7, "question": "What is suggested about the document delivery service?", "options": ["It is free for all employees.", "It is limited to books only.", "It can be used to obtain materials not in the library's current collection.", "It requires manager approval."], "answer": 2, "explanation": "'Articles and reports not available through our current subscriptions can be requested through our document delivery service' \u2013 d\u00f9ng khi t\u00e0i li\u1ec7u kh\u00f4ng c\u00f3 trong kho hi\u1ec7n t\u1ea1i.", "difficulty": "medium"}, {"id": "p7-pur03", "part": 7, "question": "What is the primary purpose of this web page?", "options": ["To promote the library's new digital collection", "To provide staff with information about available library services and how to access them", "To announce changes to library opening hours", "To recruit new members for the corporate library programme"], "answer": 1, "explanation": "Purpose: web page m\u00f4 t\u1ea3 c\u00e1c d\u1ecbch v\u1ee5 th\u01b0 vi\u1ec7n v\u00e0 c\u00e1ch \u0111\u1eb7t ch\u1ed7/truy c\u1eadp \u2014 m\u1ee5c \u0111\u00edch l\u00e0 th\u00f4ng tin v\u00e0 h\u01b0\u1edbng d\u1eabn s\u1eed d\u1ee5ng d\u1ecbch v\u1ee5 cho nh\u00e2n vi\u00ean."}]}, {"passage": "[Document 1 \u2013 E-mail]\n\nFrom:    Stefan Volkov <s.volkov@magnoliaevents.com>\nTo:      sales@luminaraudio.com\nDate:    November 6\nSubject: Product Enquiry \u2013 Wireless Microphone Systems\n\nDear Lumin Audio Sales Team,\n\nI am the technical coordinator for Magnolia Events, a corporate event production company based in Melbourne. We are currently upgrading our audio equipment and are interested in purchasing wireless microphone systems for use at large-format conferences of up to 800 attendees.\n\nAfter reviewing your website, I have some questions about the ProLink 900 system:\n\n1. What is the maximum number of simultaneous channels the ProLink 900 can support?\n2. Does the system include a rackmount receiver, or is that sold separately?\n3. Can the system be operated in environments with significant radio frequency interference \u2014 we often work in venues with multiple Wi-Fi networks?\n\nWe are looking to purchase between 8 and 12 units initially, with potential to expand. Please advise on pricing for this quantity, and whether volume discounts apply.\n\nThank you,\nStefan Volkov\nTechnical Coordinator, Magnolia Events\n\n---\n\n[Document 2 \u2013 Product Specification Sheet]\n\nLUMIN AUDIO \u2014 ProLink 900 Wireless Microphone System\nProfessional Grade | UHF Band | Ideal for Large Venues\n\nSPECIFICATIONS\nFrequency Range:     620\u2013698 MHz (UHF Band, 78 MHz bandwidth)\nSimultaneous Channels: Up to 20 in standard configuration; expandable to 32 with upgrade module\nOperating Range:     Up to 120 metres (line of sight)\nBattery Life:        Transmitter: up to 10 hours (2 \u00d7 AA batteries)\n                     Receiver: Powered via included 12V DC adapter\n\nWHAT'S INCLUDED\n\u2022 1 \u00d7 Handheld transmitter\n\u2022 1 \u00d7 Bodypack transmitter (clip-on lapel mic included)\n\u2022 1 \u00d7 Half-rack single-channel receiver (rackmount ears included)\n\u2022 1 \u00d7 Carrying case\n\u2022 User manual and warranty card\n\nINTERFERENCE RESISTANCE\nThe ProLink 900 features advanced frequency scanning technology that automatically identifies and avoids occupied frequencies, making it suitable for RF-dense environments including venues with multiple active Wi-Fi networks and other wireless devices.\n\nPRICING (AUD, ex GST)\nSingle unit:        AUD 1,190\n6\u201311 units:         AUD 1,090 per unit\n12+ units:          AUD 990 per unit\n\nWarranty: 2 years parts and labour. Extended warranty available.\nFor sales enquiries: sales@luminaraudio.com | 1800 LUM AUDIO", "passageTitle": "Enquiry E-mail and Product Specification Sheet", "type": "double", "questions": [{"id": "t8-d1-1", "part": 7, "question": "Why is Mr. Volkov contacting Lumin Audio?", "options": ["To report a fault with an existing product", "To enquire about wireless microphone equipment", "To request a product demonstration at his office", "To negotiate a service maintenance contract"], "answer": 1, "explanation": "'interested in purchasing wireless microphone systems' \u2013 li\u00ean h\u1ec7 \u0111\u1ec3 h\u1ecfi v\u1ec1 s\u1ea3n ph\u1ea9m microphone kh\u00f4ng d\u00e2y.", "difficulty": "medium"}, {"id": "t8-d1-2", "part": 7, "question": "According to the specification sheet, what does the ProLink 900 include?", "options": ["A full-rack receiver", "Two handheld transmitters", "A bodypack transmitter with a lapel microphone", "A wireless charging case"], "answer": 2, "explanation": "'1 \u00d7 Bodypack transmitter (clip-on lapel mic included)' \u2013 b\u1ed9 truy\u1ec1n \u0111eo ng\u01b0\u1eddi k\u00e8m micro c\u00e0i ve \u00e1o.", "difficulty": "medium"}, {"id": "t8-d1cd", "part": 7, "question": "Based on both documents, which of Mr. Volkov's stated requirements is fully confirmed by the specification sheet?", "options": ["Support for at least 6 simultaneous microphone channels", "A wireless range exceeding 100 metres", "Compatibility with standard audio interfaces", "A battery life of more than 10 hours per charge"], "answer": 0, "explanation": "Cross-document: Mr. Volkov requests 6+ simultaneous channels. Spec sheet confirms the ProLink 900 supports up to 8 simultaneous channels \u2014 directly and fully meeting his stated requirement."}, {"id": "t8-d1x", "part": 7, "question": "Based on both documents, which of Mr. Volkov's specific requirements is the ProLink 900 LEAST suited to meet?", "options": ["A wireless range sufficient for an outdoor venue", "Compatibility with an existing mixing board", "Support for simultaneous use of multiple microphones", "A rechargeable battery lasting at least 8 hours"], "answer": 0, "explanation": "Cross-document: Mr. Volkov's email mentions an outdoor venue. The spec sheet lists the ProLink 900 as \"ideal for large indoor venues\" \u2014 the outdoor requirement is the least well-matched based on combining both documents."}, {"id": "t8-d1-5", "part": 7, "question": "Which of Mr. Volkov's questions is directly answered by the specification sheet?", "options": ["Whether volume discounts are available", "Whether the receiver is sold separately", "The maximum number of simultaneous channels", "Whether training support is provided"], "answer": 2, "explanation": "Mr. Volkov h\u1ecfi v\u1ec1 s\u1ed1 k\u00eanh \u0111\u1ed3ng th\u1eddi t\u1ed1i \u0111a \u2192 Spec sheet tr\u1ea3 l\u1eddi: 'Up to 20 in standard configuration; expandable to 32 with upgrade module'.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Job Posting]\n\nOPERATIONS MANAGER \u2013 VANTAGE DISTRIBUTION SERVICES\nFull-Time | Brisbane, QLD\n\nVantage Distribution Services is seeking a motivated and experienced Operations Manager to oversee its Brisbane warehouse and logistics hub. The successful candidate will be responsible for a team of 35 staff and will report directly to the National Operations Director.\n\nKEY RESPONSIBILITIES\n\u2022 Manage daily warehouse operations including receiving, storage, and outbound dispatch\n\u2022 Develop and implement process improvements to increase efficiency and reduce costs\n\u2022 Ensure compliance with workplace health and safety regulations\n\u2022 Prepare weekly performance reports for senior management\n\u2022 Liaise with transport carriers and third-party logistics providers\n\nREQUIREMENTS\n\u2022 Minimum 5 years of operations management experience in a logistics or distribution environment\n\u2022 Proven track record of team leadership and performance management\n\u2022 Proficiency in warehouse management systems (WMS); Fishbowl or SAP preferred\n\u2022 Certificate IV in Logistics or Supply Chain (desirable)\n\u2022 Strong written and verbal communication skills\n\nSALARY: AUD 110,000\u2013125,000 + superannuation\nTO APPLY: Send CV and cover letter to hr@vantagedist.com.au by 5:00 P.M., Friday 22 November.\n\n---\n\n[Document 2 \u2013 Application E-mail]\n\nFrom:    Nadia Osei <n.osei@personalmail.com>\nTo:      hr@vantagedist.com.au\nDate:    November 19\nSubject: Application for Operations Manager \u2013 Vantage Distribution Services\n\nDear Hiring Team,\n\nPlease find attached my CV and cover letter in application for the Operations Manager position advertised on the Vantage Distribution Services website.\n\nI have seven years of experience managing warehouse and distribution operations, most recently as a Senior Operations Supervisor at Blueshore Freight in Townsville, where I led a team of 28 staff and oversaw a network of three regional depots. During my time at Blueshore Freight, I implemented a new inventory tracking system that reduced picking errors by 31 percent and cut operational costs by approximately AUD 180,000 annually.\n\nI hold a Certificate IV in Logistics and have extensive experience with SAP Warehouse Management. I am confident that my background aligns well with the requirements of this role and the strategic goals of Vantage Distribution Services.\n\nI would welcome the opportunity to discuss my application further and am available for an interview at your earliest convenience.\n\nKind regards,\nNadia Osei\n\n---\n\n[Document 3 \u2013 Reference Letter]\n\nBlueshore Freight Solutions\n25 Harbour View Drive, Townsville QLD 4810\n\nNovember 15\n\nTo Whom It May Concern,\n\nI am writing to provide a professional reference for Ms. Nadia Osei, who served as Senior Operations Supervisor at Blueshore Freight Solutions from March 2018 until October 2024.\n\nDuring her six and a half years with our organisation, Ms. Osei consistently demonstrated exceptional leadership and operational expertise. She managed a high-performing team and was directly responsible for several key process improvements that delivered measurable results across our depot network.\n\nMs. Osei's professional approach, sound judgement, and ability to manage complex logistics challenges make her an outstanding candidate for any senior operations role. I recommend her without reservation.\n\nIf you have any further questions, please do not hesitate to contact me at d.mcallister@blueshorefr.com.\n\nYours sincerely,\nDuncan McAllister\nGeneral Manager, Blueshore Freight Solutions", "passageTitle": "Job Posting, Application E-mail, and Reference Letter", "type": "triple", "questions": [{"id": "t8-t1-2", "part": 7, "question": "What did Ms. Osei accomplish at her previous employer?", "options": ["She expanded the company's operations to three new cities.", "She reduced picking errors and cut operational costs significantly.", "She introduced a new transport carrier partnership.", "She increased the workforce from 20 to 35 staff."], "answer": 1, "explanation": "'implemented a new inventory tracking system that reduced picking errors by 31 percent and cut operational costs by approximately AUD 180,000 annually'.", "difficulty": "medium"}, {"id": "t8-t1v", "part": 7, "question": "What is most likely the reason the application deadline is at 5:00 P.M. on Friday, November 22?", "options": ["The hiring team will be unavailable after that time", "Applications received later will not be considered", "The position may be filled before the deadline", "The company has a policy of weekly application processing"], "answer": 1, "explanation": "Purpose: Hard deadlines in job postings establish a clear cut-off \u2014 applications received after 5:00 P.M. on the deadline date will not be reviewed. This is standard recruiting practice."}, {"id": "t8-t1-4", "part": 7, "question": "How long did Ms. Osei work at Blueshore Freight, according to the reference letter?", "options": ["Four years", "Five years", "Six and a half years", "Seven years"], "answer": 2, "explanation": "'from March 2018 until October 2024' \u2013 Reference letter ghi 'six and a half years'.", "difficulty": "medium"}, {"id": "t8-t1-5", "part": 7, "question": "What does Mr. McAllister suggest about Ms. Osei in the reference letter?", "options": ["She may require additional training in logistics software.", "She is well suited for senior operations positions.", "She is currently seeking international opportunities.", "She prefers working in smaller team environments."], "answer": 1, "explanation": "'an outstanding candidate for any senior operations role. I recommend her without reservation' \u2013 \u0111\u00e1nh gi\u00e1 r\u1ea5t t\u00edch c\u1ef1c v\u00e0 ph\u00f9 h\u1ee3p v\u1edbi vai tr\u00f2 qu\u1ea3n l\u00fd c\u1ea5p cao.", "difficulty": "medium"}, {"id": "t8-t1-6", "part": 7, "question": "What information in Ms. Osei's application cannot be verified by the reference letter?", "options": ["Her previous job title", "The duration of her employment at Blueshore Freight", "The AUD 180,000 cost reduction she claims to have achieved", "Her professional approach and leadership ability"], "answer": 2, "explanation": "Reference letter \u0111\u1ec1 c\u1eadp \u0111\u1ebfn 'measurable results' chung chung nh\u01b0ng KH\u00d4NG x\u00e1c nh\u1eadn con s\u1ed1 c\u1ee5 th\u1ec3 AUD 180,000. \u0110\u00e2y l\u00e0 th\u00f4ng tin ch\u1ec9 c\u00f3 trong email \u1ee9ng tuy\u1ec3n.", "difficulty": "medium"}]}, {"passage": "CARTIFY \u2014 GROW YOUR BUSINESS ONLINE\nEverything you need to sell smarter\n\nABOUT CARTIFY\nCartify is Australia's fastest-growing e-commerce marketplace, connecting over 4 million active shoppers with small and medium-sized businesses nationwide. Whether you sell handmade goods, electronics, or apparel, Cartify provides the tools to reach your customers.\n\nSELLER PLANS\n\nSTARTER (Free)\n\u2022 List up to 50 products\n\u2022 Standard search visibility\n\u2022 Basic sales analytics\n\u2022 Cartify-managed fulfillment available at AUD 3.50 per order\n\nPROFESSIONAL (AUD 49/month)\n\u2022 Unlimited product listings\n\u2022 Priority search placement\n\u2022 Advanced analytics including conversion rate tracking\n\u2022 Dedicated seller support (Mon\u2013Fri, 9 A.M.\u20136 P.M.)\n\u2022 Fulfillment fee reduced to AUD 2.80 per order\n\nPREMIUM (AUD 120/month)\n\u2022 All Professional features\n\u2022 Featured placement on homepage and category pages\n\u2022 Same-day fulfillment for metro areas (orders placed before 11 A.M.)\n\u2022 Quarterly business review with a Cartify growth consultant\n\nHOW TO JOIN\nRegister at cartify.com.au/sellers. Approval typically takes one to two business days. Once approved, you can begin listing products immediately.\n\nCurrent promotion: New sellers who subscribe to a Professional or Premium plan before 30 November receive their first month at no charge.", "passageTitle": "Web Page \u2013 Cartify Seller Platform", "type": "single", "questions": [{"id": "t9-s1-1", "part": 7, "question": "What is Cartify?", "options": ["A logistics company specialising in same-day delivery", "An online marketplace connecting sellers and shoppers", "A software provider for retail inventory management", "A financial services firm for small businesses"], "answer": 1, "explanation": "'Cartify is Australia's fastest-growing e-commerce marketplace, connecting over 4 million active shoppers with small and medium-sized businesses' \u2013 s\u00e0n th\u01b0\u01a1ng m\u1ea1i \u0111i\u1ec7n t\u1eed.", "difficulty": "medium"}, {"id": "t9-s1-2", "part": 7, "question": "What feature is available ONLY to Premium subscribers?", "options": ["Unlimited product listings", "Advanced analytics with conversion rate tracking", "Same-day fulfillment for metro areas", "Priority search placement"], "answer": 2, "explanation": "'Same-day fulfillment for metro areas' ch\u1ec9 \u0111\u01b0\u1ee3c li\u1ec7t k\u00ea trong g\u00f3i Premium. Unlimited listings v\u00e0 analytics c\u00f3 \u1edf Professional; priority placement c\u0169ng t\u1eeb Professional.", "difficulty": "medium"}, {"id": "t9-s1-3", "part": 7, "question": "How long does seller approval typically take?", "options": ["A few hours", "One to two business days", "Up to five business days", "One week"], "answer": 1, "explanation": "'Approval typically takes one to two business days' \u2013 quy tr\u00ecnh ph\u00ea duy\u1ec7t th\u01b0\u1eddng m\u1ea5t 1-2 ng\u00e0y l\u00e0m vi\u1ec7c.", "difficulty": "medium"}, {"id": "p7-s-v38", "part": 7, "question": "Which of the following is NOT mentioned as a benefit of the Premium plan?", "options": ["Advanced analytics", "Priority customer support", "Unlimited product listings", "A dedicated account manager"], "answer": 3, "explanation": "NOT TRUE: Review the Premium plan features. A dedicated account manager is NOT listed among the Premium plan benefits on the web page."}]}, {"passage": "INTERNAL MEMORANDUM\n\nTo:   Executive Steering Committee\nFrom: Priya Mehta, Project Manager \u2013 CRM Implementation\nDate: November 14\nRe:   Halcyon CRM Project \u2013 Week 18 Status Update\n\nPROJECT STATUS: AMBER\n\nSUMMARY\nThe Halcyon CRM implementation project reached its third major milestone last week with the successful completion of data migration from the legacy system. However, the project is currently tracking approximately two weeks behind the revised timeline due to delays in third-party API integration.\n\nKEY UPDATES\n\u2022 Data migration: Complete \u2713\n\u2022 User interface customisation: 85% complete, on track\n\u2022 API integration with billing system: 40% complete \u2014 delayed due to a technical bottleneck identified by the vendor's development team\n\u2022 Staff training: Scheduled to commence 2 December (pending API completion)\n\nRISK & CONTINGENCY\nThe project team has identified two risk scenarios. In the first, the API integration is resolved within the next ten days, allowing the overall timeline to be recovered with minimal impact on the go-live date of 15 January. In the second scenario, a contingency plan has been prepared that would allow a partial go-live on 15 January, with full functionality to follow in February.\n\nNEXT STEPS\nThe vendor has committed to providing a resolution update by 21 November. A revised project plan will be circulated to all stakeholders once this update is received.", "passageTitle": "Memo \u2013 Halcyon CRM Project Status Update", "type": "single", "questions": [{"id": "t9-s2-1", "part": 7, "question": "What is the current status of the Halcyon CRM project?", "options": ["It is ahead of schedule and fully on track.", "It is on schedule with no issues reported.", "It is behind schedule due to an integration problem.", "It has been placed on hold pending executive approval."], "answer": 2, "explanation": "'tracking approximately two weeks behind the revised timeline due to delays in third-party API integration' \u2013 tr\u1ec5 2 tu\u1ea7n v\u00ec v\u1ea5n \u0111\u1ec1 t\u00edch h\u1ee3p API.", "difficulty": "medium"}, {"id": "t9-s2-2", "part": 7, "question": "What caused the delay in the project?", "options": ["A shortage of trained staff", "A technical bottleneck in the API integration", "Incomplete data migration from the legacy system", "A change in the project scope"], "answer": 1, "explanation": "'a technical bottleneck identified by the vendor's development team' l\u00e0m tr\u1ec5 ph\u1ea7n API integration v\u1edbi billing system.", "difficulty": "medium"}, {"id": "t9-s2-3", "part": 7, "question": "What has been prepared in case the timeline cannot be fully recovered?", "options": ["A request to postpone the go-live date indefinitely", "A proposal to reduce the project scope", "A contingency plan for a partial go-live on January 15", "A plan to replace the third-party vendor"], "answer": 2, "explanation": "'a contingency plan has been prepared that would allow a partial go-live on 15 January' \u2013 k\u1ebf ho\u1ea1ch d\u1ef1 ph\u00f2ng cho ph\u00e9p tri\u1ec3n khai m\u1ed9t ph\u1ea7n v\u00e0o ng\u00e0y \u0111\u00e3 \u0111\u1ecbnh.", "difficulty": "medium"}]}, {"passage": "NORTHBRIDGE INSURANCE\nBusiness Travel Insurance \u2014 Plan Comparison\n\nProtect your team wherever business takes them. Northbridge offers three levels of corporate travel coverage, designed for companies of all sizes.\n\nPLAN OVERVIEW\n\n                    STANDARD        PLUS            EXECUTIVE\nAnnual Premium*     AUD 380/person  AUD 590/person  AUD 890/person\nMedical Cover       AUD 500,000     AUD 2,000,000   Unlimited\nTrip Cancellation   AUD 5,000       AUD 10,000      AUD 20,000\nBaggage Loss        AUD 2,000       AUD 4,000       AUD 6,000\nTravel Delay        AUD 500         AUD 1,000       AUD 2,000\n24/7 Assistance     Yes             Yes             Yes\nDeductible          AUD 250         AUD 150         NIL\n\n*Per person, per year. Minimum 5 employees to qualify for corporate pricing.\n\nMAKING A CLAIM\nAll claims must be submitted within 60 days of the incident. Policyholders can lodge claims online at northbridgeinsurance.com.au/claims or by calling 1800 673 400. Supporting documentation \u2014 including receipts, medical reports, or police reports where applicable \u2014 must accompany all claims.\n\nIMPORTANT NOTES\n\u2022 Pre-existing medical conditions are not covered under any plan unless disclosed and approved at the time of enrolment.\n\u2022 Coverage applies to business-related travel only. Personal side trips during a business journey may not be covered.\n\u2022 Group discounts of 10% apply to companies enrolling 20 or more employees.\n\nFor a tailored quote, contact our corporate team at corporate@northbridge.com.au.", "passageTitle": "Web Page \u2013 Northbridge Business Travel Insurance", "type": "single", "questions": [{"id": "t9-s3-1", "part": 7, "question": "What is the deductible for the Plus plan?", "options": ["NIL", "AUD 150", "AUD 250", "AUD 500"], "answer": 1, "explanation": "B\u1ea3ng so s\u00e1nh: Plus plan \u2014 Deductible = AUD 150. Standard = AUD 250, Executive = NIL.", "difficulty": "medium"}, {"id": "t9-s3-2", "part": 7, "question": "What must policyholders do when submitting a claim?", "options": ["Visit a Northbridge office in person", "Submit the claim within 30 days", "Provide supporting documentation with the claim", "Obtain approval from their employer first"], "answer": 2, "explanation": "'Supporting documentation... must accompany all claims' \u2014 t\u00e0i li\u1ec7u h\u1ed7 tr\u1ee3 ph\u1ea3i n\u1ed9p k\u00e8m theo y\u00eau c\u1ea7u b\u1ed3i th\u01b0\u1eddng.", "difficulty": "medium"}, {"id": "t9-s3-3", "part": 7, "question": "What condition must be met for a pre-existing medical condition to be covered?", "options": ["The employee must hold an Executive plan.", "The condition must be disclosed and approved at enrolment.", "A doctor's certificate must be submitted each year.", "The claim must be filed within 30 days of travel."], "answer": 1, "explanation": "'Pre-existing medical conditions are not covered unless disclosed and approved at the time of enrolment' \u2014 ph\u1ea3i khai b\u00e1o v\u00e0 \u0111\u01b0\u1ee3c ch\u1ea5p thu\u1eadn khi \u0111\u0103ng k\u00fd.", "difficulty": "medium"}, {"id": "p7-s-v39", "part": 7, "question": "In the policy description, the word \"reimburse\" is closest in meaning to", "options": ["pay back", "cover in advance", "negotiate", "waive"], "answer": 0, "explanation": "WIC: \"reimburse\" = ho\u00e0n tr\u1ea3 (ti\u1ec1n \u0111\u00e3 chi). \"Pay back\" l\u00e0 di\u1ec5n \u0111\u1ea1t t\u01b0\u01a1ng \u0111\u01b0\u01a1ng nh\u1ea5t trong ng\u1eef c\u1ea3nh b\u1ea3o hi\u1ec3m chi tr\u1ea3 cho chi ph\u00ed ph\u00e1t sinh."}]}, {"passage": "LAKESIDE PROFESSIONAL SUITES\nConference Room Rental Rates\n\nRoom Name | Capacity | Hourly Rate | Full-Day Rate\n----------------------------------------------------\nBoardroom | 12 people| $50         | $350\nTraining B| 30 people| $80         | $550\nAuditorium| 100 people| $150        | $1,000\n\nAll rentals include:\n- High-speed Wi-Fi\n- Digital projector and screen\n- Filtered water and coffee/tea service\n\nOptional Add-ons:\n- Catering (Lunch Buffet): $25 per person\n- On-site IT Support: $40 per hour\n- Video conferencing setup: $75 flat fee\n\nBooking Policy: A 20% non-refundable deposit is required at the time of booking. Cancellations made less than 48 hours before the event will forfeit the full rental fee.\n\nTo book, visit www.lakesidesuites.com/rentals.", "passageTitle": "Venue Rental Information", "type": "single", "questions": [{"id": "ex7-1a", "part": 7, "question": "What is the hourly rate for the largest room?", "options": ["$50", "$80", "$150", "$350"], "answer": 2, "explanation": "Largest room l\u00e0 Auditorium (100 people), hourly rate l\u00e0 $150.", "difficulty": "medium"}, {"id": "ex7-1b", "part": 7, "question": "What is included in the base rental fee?", "options": ["Lunch buffet", "IT support", "Coffee and tea service", "Video conferencing"], "answer": 2, "explanation": "Trong 'All rentals include' c\u00f3 'coffee/tea service'.", "difficulty": "medium"}, {"id": "p7-s-v49", "part": 7, "question": "What can be inferred about the most popular room at the venue?", "options": ["The Grand Hall, because it can host the largest events", "The Boardroom, because it is the most affordable", "The Garden Terrace, because it offers the most flexibility", "The Conference Suite, because it has the best technology"], "answer": 0, "explanation": "Inference: The Grand Hall having the highest capacity suggests it serves the largest events \u2014 making it most likely the most in-demand for large corporate or social gatherings."}]}, {"passage": "[Email 1]\nFrom: Marcus Thorne <m.thorne@tech-solutions.com>\nTo: info@lakesidesuites.com\nDate: Oct 5\nSubject: Room Rental for Training Workshop\n\nDear Lakeside Team,\n\nI am interested in booking your 'Training B' room for a full day on Friday, November 12. We expect around 25 participants for our software workshop. \n\nWe will also require on-site IT support for the first two hours of the event to ensure all participants can connect their laptops to our server. Additionally, we would like the lunch buffet for 25 people.\n\nCould you please send me a quote including these add-ons?\n\nBest regards,\nMarcus Thorne\n\n[Email 2]\nFrom: Lakeside Suites Info <info@lakesidesuites.com>\nTo: Marcus Thorne <m.thorne@tech-solutions.com>\nDate: Oct 6\nSubject: Re: Room Rental for Training Workshop\n\nDear Mr. Thorne,\n\nThank you for your interest. I have calculated the quote for November 12 as requested:\n- Training B (Full-Day Rate): $550\n- IT Support (2 hours): $80\n- Catering (25 people): $625\nTOTAL: $1,255\n\nTo confirm this booking, please pay the 20% deposit ($251) by the end of this week. Please note that the IT support technician, Mr. Jenkins, will be available starting at 8:30 a.m. for your setup.\n\nSincerely,\nLakeside Suites Management", "passageTitle": "Inquiry Email + Response", "type": "double", "questions": [{"id": "ex7-2a", "part": 7, "question": "How many people are expected at the workshop?", "options": ["12", "20", "25", "30"], "answer": 2, "explanation": "Marcus Thorne n\u00f3i 'around 25 participants'.", "difficulty": "medium"}, {"id": "ex7-2b", "part": 7, "question": "What is the cost per person for the lunch buffet?", "options": ["$20", "$25", "$40", "$50"], "answer": 1, "explanation": "T\u1eeb b\u1ea3ng gi\u00e1 g\u1ed1c ho\u1eb7c t\u00ednh to\u00e1n: $625 / 25 = $25.", "difficulty": "medium"}, {"id": "ex7-2c", "part": 7, "question": "How much deposit is required to confirm the booking?", "options": ["$50", "$251", "$550", "$1,255"], "answer": 1, "explanation": "Email 2 ghi r\u00f5 '20% deposit ($251)'.", "difficulty": "medium"}, {"id": "ex7-2d", "part": 7, "question": "Who is Mr. Jenkins?", "options": ["A training participant", "The office manager", "A catering staff member", "An IT technician"], "answer": 3, "explanation": "Email 2 n\u00f3i 'the IT support technician, Mr. Jenkins'.", "difficulty": "medium"}, {"id": "ex7-2x", "part": 7, "question": "Based on both documents, which of Mr. Thorne's original requirements is confirmed as available by the response email?", "options": ["A room for exactly 30 participants with AV equipment included", "Lunch catering within his stated budget", "A half-day morning booking on October 15", "Both AV equipment and lunch catering within budget"], "answer": 2, "explanation": "Cross-document: Mr. Thorne's email requests a half-day morning booking on Oct 15. Response confirms availability for that date and time. AV and catering need separate confirmation that doesn't fully align \u2014 the morning booking is the clearest match."}]}, {"passage": "[Document 1: Job Posting]\nSENIOR GRAPHIC DESIGNER\nStudio Pixel is looking for a creative Senior Graphic Designer with at least 5 years of experience in digital marketing. Candidates must be proficient in Adobe Creative Suite and have a strong portfolio.\nResponsibilities:\n- Design social media campaigns\n- Collaborate with the marketing team\n- Mentor junior designers\nDeadline: August 20\n\n[Document 2: Email Application]\nFrom: Elena Rossi <e.rossi@email.com>\nTo: hr@studiopixel.com\nDate: August 15\nSubject: Application for Senior Graphic Designer\n\nDear HR Manager,\nI am writing to express my interest in the Senior Graphic Designer position advertised. I have 7 years of experience at Creative Lab, where I led several successful digital campaigns. I have attached my portfolio and CV. I am particularly interested in the mentoring aspect of the role.\n\n[Document 3: Interview Invitation]\nFrom: Studio Pixel HR <hr@studiopixel.com>\nTo: Elena Rossi <e.rossi@email.com>\nDate: August 18\nSubject: Interview Invitation\n\nDear Ms. Rossi,\nThank you for your application. We were impressed by your work at Creative Lab. We would like to invite you for an in-person interview on August 25 at 10:00 a.m. at our downtown office. Please let us know if this time works for you.", "passageTitle": "Job Posting + Email Application + Interview Invitation", "type": "triple", "questions": [{"id": "b9-7-1a", "part": 7, "question": "What is a requirement for the job?", "options": ["University degree in art", "5 years of digital marketing experience", "Fluency in three languages", "Ability to code websites"], "answer": 1, "explanation": "Doc 1 ghi 'at least 5 years of experience'.", "difficulty": "medium"}, {"id": "b9-7-1b", "part": 7, "question": "Why is Ms. Rossi interested in the position?", "options": ["The salary is higher", "She wants to move downtown", "She likes the mentoring responsibility", "She uses Adobe Creative Suite"], "answer": 2, "explanation": "Doc 2 ghi 'I am particularly interested in the mentoring aspect'.", "difficulty": "medium"}, {"id": "b9-7-1c", "part": 7, "question": "When will the interview take place?", "options": ["August 15", "August 18", "August 20", "August 25"], "answer": 3, "explanation": "Doc 3 ghi 'on August 25'.", "difficulty": "medium"}, {"id": "b9-7-1d", "part": 7, "question": "Where did Ms. Rossi previously work?", "options": ["Studio Pixel", "Creative Lab", "HR Department", "Downtown Office"], "answer": 1, "explanation": "Doc 2 ghi 'at Creative Lab'.", "difficulty": "medium"}, {"id": "b9-7-1e", "part": 7, "question": "Did Ms. Rossi apply before the deadline?", "options": ["Yes, 5 days early", "Yes, on the day of deadline", "No, for late application", "The deadline was not mentioned"], "answer": 0, "explanation": "Deadline 20/8, c\u00f4 \u1ea5y n\u1ed9p 15/8 -> S\u1edbm 5 ng\u00e0y.", "difficulty": "medium"}]}, {"passage": "[Review]\n\u2b50\u2b50\u2b50\u2b50\nProduct: Swift-Charge Power Bank (Model 500)\nReviewer: Alex P.\nDate: Sept 10\n\nI bought this power bank for a business trip. It is compact and charges my phone very quickly. However, the included USB-C cable started fraying after only two uses. The device itself is great, but the accessories are disappointing for the price.\n\n[Response]\nDear Alex,\nThank you for your feedback. We are sorry to hear about the cable issue. We take quality control seriously. Please contact our support team with your order number, and we will ship you a premium replacement cable free of charge. We are currently reviewing our accessory suppliers to ensure this doesn't happen again.\n- Swift-Charge Customer Care", "passageTitle": "Product Review + Company Response", "type": "double", "questions": [{"id": "b9-7-2a", "part": 7, "question": "What did the reviewer like about the product?", "options": ["The color", "The price", "The charging speed", "The cable quality"], "answer": 2, "explanation": "Reviewer n\u00f3i 'charges my phone very quickly'.", "difficulty": "medium"}, {"id": "b9-7-2v", "part": 7, "question": "In Document 1, the word \"intermittently\" is closest in meaning to", "options": ["occasionally", "continuously", "severely", "unexpectedly"], "answer": 0, "explanation": "WIC: \"intermittently\" = kh\u00f4ng li\u00ean t\u1ee5c, l\u00fac c\u00f3 l\u00fac kh\u00f4ng. \"Occasionally\" n\u1eafm b\u1eaft \u0111\u00fang ngh\u0129a trong ng\u1eef c\u1ea3nh m\u00f4 t\u1ea3 l\u1ed7i s\u1ea3n ph\u1ea9m xu\u1ea5t hi\u1ec7n kh\u00f4ng \u0111\u1ec1u."}, {"id": "b9-7-2c", "part": 7, "question": "What is the company offering the reviewer?", "options": ["A full refund", "A new power bank", "A free replacement cable", "A discount code"], "answer": 2, "explanation": "C\u00f4ng ty n\u00f3i 'ship you a premium replacement cable free of charge'.", "difficulty": "medium"}, {"id": "b9-7-2d", "part": 7, "question": "What is the company doing about the issue?", "options": ["Closing the factory", "Changing their phone numbers", "Reviewing their suppliers", "Discontinuing the product"], "answer": 2, "explanation": "C\u00f4ng ty n\u00f3i 'currently reviewing our accessory suppliers'.", "difficulty": "medium"}, {"id": "b9-7-2e", "part": 7, "question": "In Document 2, the word \"promptly\" is closest in meaning to", "options": ["carefully", "immediately", "directly", "publicly"], "answer": 1, "explanation": "Word-in-context: \"promptly\" = ngay l\u1eadp t\u1ee9c, kh\u00f4ng ch\u1eadm tr\u1ec5. \"Immediately\" l\u00e0 t\u1eeb \u0111\u1ed3ng ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh ph\u1ea3n h\u1ed3i kh\u00e1ch h\u00e0ng."}]}, {"passage": "PROPERTY LISTING\n\nPineview Business Park \u2014 Unit 14B\nAddress: 88 Pineview Drive, Melbourne VIC 3004\nType: Commercial Office Space\nSize: 320 sqm (net lettable area)\nLease Term: 3\u20135 years preferred; shorter terms considered\nAnnual Rent: AUD 128,000 + outgoings\nParking: 6 allocated spaces included\n\nFEATURES:\n\u2022 Fully fitted-out with open-plan workstations for 30 staff\n\u2022 Two enclosed meeting rooms (8 and 12 seats)\n\u2022 Server room with UPS backup\n\u2022 End-of-trip facilities (showers, lockers, bike storage)\n\u2022 Direct tram access from Collins Street\n\u2022 24/7 secure access\n\nInspections by appointment only.\nContact: Alex Gould, Pineview Commercial Real Estate\nPhone: 03 9812 4400 | alex.gould@pineviewre.com.au", "passageTitle": "Property Listing", "type": "single", "questions": [{"id": "xp7-s01a", "part": 7, "question": "What type of property is advertised?", "options": ["A residential apartment", "A retail shopfront", "A commercial office space", "A warehouse facility"], "answer": 2, "explanation": "'Commercial Office Space' is stated in the listing type.", "difficulty": "medium"}, {"id": "xp7-s01b", "part": 7, "question": "How many parking spaces are included?", "options": ["3", "4", "6", "8"], "answer": 2, "explanation": "'6 allocated spaces included'", "difficulty": "medium"}, {"id": "xp7-s01c", "part": 7, "question": "How must prospective tenants arrange to view the property?", "options": ["Submit a formal application", "Call during business hours only", "Book an appointment in advance", "Register on the Pineview website"], "answer": 2, "explanation": "'Inspections by appointment only.'", "difficulty": "medium"}, {"id": "p7-s-v09", "part": 7, "question": "Which of the following is NOT mentioned as a feature of the property?", "options": ["Air conditioning", "Parking facilities", "A dedicated reception area", "High-speed internet access"], "answer": 2, "explanation": "NOT TRUE: Review the listed property features. A dedicated reception area is the feature NOT explicitly listed in this commercial property description."}]}, {"passage": "MERIDIAN HEALTH NETWORK\nPatient Information Leaflet\n\nPREPARING FOR YOUR MRI SCAN\n\nThank you for scheduling your MRI scan at Meridian Health Network. Please read the following information carefully before your appointment.\n\nBEFORE YOUR SCAN\n\u2022 Do not eat or drink anything for 4 hours prior to your appointment, unless instructed otherwise by your doctor.\n\u2022 Leave all metal objects at home or in a locker: jewellery, watches, hairpins, and belt buckles can interfere with the scan.\n\u2022 Inform our staff if you have any implanted medical devices (e.g., pacemakers, cochlear implants), as these may be affected by the magnetic field.\n\u2022 Wear comfortable, loose-fitting clothing with no metal zippers or buttons.\n\nDURING YOUR SCAN\nThe scan typically takes 30\u201345 minutes. You will be asked to remain completely still. Some patients find the enclosed environment of the scanner uncomfortable; please notify staff in advance if you experience claustrophobia.\n\nAFTER YOUR SCAN\nYour results will be sent to your referring doctor within 3 business days. Meridian Health does not provide results directly to patients.", "passageTitle": "Healthcare Notice", "type": "single", "questions": [{"id": "xp7-s02a", "part": 7, "question": "What must patients avoid for 4 hours before the appointment?", "options": ["Wearing metal jewellery", "Taking any medication", "Eating or drinking", "Using electronic devices"], "answer": 2, "explanation": "'Do not eat or drink anything for 4 hours prior.'", "difficulty": "medium"}, {"id": "xp7-s02b", "part": 7, "question": "Who should patients inform about a pacemaker?", "options": ["Their referring doctor", "The hospital receptionist", "The MRI staff", "Meridian Health administration"], "answer": 2, "explanation": "'Inform our staff if you have any implanted medical devices.'", "difficulty": "medium"}, {"id": "xp7-s02c", "part": 7, "question": "How will patients receive their results?", "options": ["Directly from Meridian Health after the scan", "Via email within 24 hours", "Through their referring doctor", "At a follow-up appointment"], "answer": 2, "explanation": "'Your results will be sent to your referring doctor... Meridian Health does not provide results directly to patients.'", "difficulty": "medium"}, {"id": "p7-s-v10", "part": 7, "question": "What can be inferred about why the notice was sent to patients?", "options": ["To reschedule all upcoming appointments", "To inform patients of changes that affect their visit", "To announce a new healthcare service", "To request that patients update their medical records"], "answer": 1, "explanation": "Inference: Healthcare notices are sent when operational changes affect patients' experience \u2014 the content implies patients need this information before their visit."}]}, {"passage": "STELLARBANK ONLINE BANKING \u2014 SECURITY ALERT\n\nDear Valued Customer,\n\nWe have detected unusual login activity on your StellarBank online account from an unrecognised device in a different location from your usual access point.\n\nAs a precautionary measure, we have temporarily restricted access to your account. No funds have been transferred and your balance remains secure.\n\nTo restore full access, please verify your identity by:\n1. Visiting stellarbank.com/verify\n2. Entering your date of birth and the last 4 digits of your registered mobile number\n3. Resetting your password using a secure, unique combination\n\nIMPORTANT: StellarBank will never ask for your full password, PIN, or one-time passcode by phone or email. If you receive any such request, please report it immediately to 1800 STELLAR.\n\nIf you did not attempt to log in from a new device, this alert may indicate an unauthorised access attempt. In that case, please contact us immediately.\n\nStellarBank Security Team", "passageTitle": "Security Alert", "type": "single", "questions": [{"id": "xp7-s03a", "part": 7, "question": "Why was the customer's account access restricted?", "options": ["The customer failed to pay a fee", "Unusual login activity was detected", "The account had not been used for 90 days", "A fraud complaint was submitted"], "answer": 1, "explanation": "'We have detected unusual login activity... As a precautionary measure, we have temporarily restricted access.'", "difficulty": "medium"}, {"id": "xp7-s03b", "part": 7, "question": "What must the customer provide to verify identity?", "options": ["Their full password and PIN", "Date of birth and last 4 digits of mobile number", "A copy of government-issued ID", "Account number and branch code"], "answer": 1, "explanation": "Step 2: 'Entering your date of birth and the last 4 digits of your registered mobile number.'", "difficulty": "medium"}, {"id": "xp7-s03c", "part": 7, "question": "What does StellarBank warn customers about?", "options": ["Using public Wi-Fi for banking", "Sharing account details with family", "Being asked for passwords or PINs via phone or email", "Accessing the account from overseas"], "answer": 2, "explanation": "'StellarBank will never ask for your full password, PIN, or one-time passcode by phone or email.'", "difficulty": "medium"}, {"id": "xp7-s03d", "part": 7, "question": "What should the customer do if they did NOT attempt to log in from a new device?", "options": ["Wait for a follow-up email", "Change their password without contacting the bank", "Contact StellarBank immediately", "File a police report"], "answer": 2, "explanation": "'If you did not attempt to log in from a new device... please contact us immediately.'", "difficulty": "medium"}]}, {"passage": "HARBRIDGE UNIVERSITY \u2014 CONTINUING EDUCATION\nCertificate in Project Management\n\nCourse Overview\nThis 16-week online programme is designed for working professionals seeking to develop structured project management skills. The curriculum covers the full project lifecycle, from initiation and planning through to execution, monitoring, and closure.\n\nDelivery & Format\n\u2022 100% online; self-paced with weekly live sessions (Tuesdays, 7:00\u20139:00 p.m.)\n\u2022 Each module includes readings, video lectures, and a practical assignment\n\u2022 Peer review and instructor feedback provided throughout\n\nAdmission Requirements\n\u2022 No formal prerequisites; open to all professionals\n\u2022 Applicants must be currently employed or recently employed (within 12 months)\n\nCertification\nUpon successful completion (minimum 70% overall grade), students receive a Harbridge Certificate in Project Management, which carries 3 Continuing Education Units (CEUs) recognised by major professional bodies.\n\nFees: USD 1,850 (payment plans available)\nNext Intake: September 8\nApplication Deadline: August 25\n\nEnrol: ce.harbridge.edu/project-management", "passageTitle": "Certification Programme", "type": "single", "questions": [{"id": "xp7-s04a", "part": 7, "question": "How long is the programme?", "options": ["8 weeks", "12 weeks", "16 weeks", "20 weeks"], "answer": 2, "explanation": "'This 16-week online programme.'", "difficulty": "medium"}, {"id": "xp7-s04b", "part": 7, "question": "When do live sessions take place?", "options": ["Mondays 6:00\u20138:00 p.m.", "Tuesdays 7:00\u20139:00 p.m.", "Wednesdays 5:00\u20137:00 p.m.", "Fridays 7:00\u20139:00 p.m."], "answer": 1, "explanation": "'Weekly live sessions (Tuesdays, 7:00\u20139:00 p.m.)'", "difficulty": "medium"}, {"id": "xp7-s04c", "part": 7, "question": "What minimum grade is required to receive the certificate?", "options": ["60%", "65%", "70%", "75%"], "answer": 2, "explanation": "'Minimum 70% overall grade.'", "difficulty": "medium"}, {"id": "p7-s-v40", "part": 7, "question": "What can be inferred about the live sessions in the programme?", "options": ["They are optional and can be missed without penalty", "They are required for students who fall behind schedule", "They allow interaction between students and instructors", "They replace the written assignments for that week"], "answer": 2, "explanation": "Inference: Live sessions in online programmes are designed for real-time Q&A and interaction \u2014 the most standard purpose inferred from an online professional programme format."}]}, {"passage": "BLOOM & GROVE FLORAL STUDIO\nCustom Event Florals \u2014 Service Information\n\nBloom & Grove specialises in bespoke floral design for corporate events, weddings, and private functions. Each arrangement is handcrafted using seasonal and sustainably sourced flowers.\n\nSERVICE PACKAGES\n\u2022 Consultation Package (AUD 150): Includes a 60-minute in-person or virtual consultation, mood board creation, and a written quote. The fee is fully credited toward your final booking.\n\u2022 Installation Only (from AUD 800): Delivery and installation of pre-agreed floral designs. Suitable for clients who have completed the consultation process.\n\u2022 Full Event Package (custom pricing): End-to-end service from initial consultation through to installation and post-event removal.\n\nBOOKING TERMS\nA 30% deposit is required to secure your booking date. Cancellations made more than 30 days before the event will receive a full refund of the deposit. Cancellations within 30 days will forfeit the deposit.\n\nTo enquire, email hello@bloomandgrove.com.au or call 03 9311 7700.", "passageTitle": "Business Advertisement", "type": "single", "questions": [{"id": "xp7-s05a", "part": 7, "question": "What does the Consultation Package include?", "options": ["Flower delivery to the venue", "A mood board and written quote", "Installation of floral arrangements", "Post-event removal of flowers"], "answer": 1, "explanation": "'Includes a 60-minute consultation, mood board creation, and a written quote.'", "difficulty": "medium"}, {"id": "xp7-s05b", "part": 7, "question": "What happens to the consultation fee if the client makes a full booking?", "options": ["It is refunded after the event", "It is non-refundable", "It is credited toward the final booking", "It is applied as a future discount"], "answer": 2, "explanation": "'The fee is fully credited toward your final booking.'", "difficulty": "medium"}, {"id": "xp7-s05c", "part": 7, "question": "What percentage deposit is required to secure a booking?", "options": ["20%", "25%", "30%", "50%"], "answer": 2, "explanation": "'A 30% deposit is required to secure your booking date.'", "difficulty": "medium"}, {"id": "xp7-s05d", "part": 7, "question": "When will a client NOT receive a refund of their deposit?", "options": ["If they cancel more than 60 days in advance", "If the event is relocated", "If the cancellation is within 30 days of the event", "If the client requests a design change"], "answer": 2, "explanation": "'Cancellations within 30 days will forfeit the deposit.'", "difficulty": "medium"}]}, {"passage": "CITY TRANSIT AUTHORITY\nAdvisory Notice \u2014 Line 7 Service Changes\n\nEffective Monday, April 14, temporary changes will be made to Line 7 (Riverside\u2013Central) services to accommodate track upgrade works between Oakfield and Milford stations.\n\nKEY CHANGES:\n\u2022 Trains on Line 7 will not stop at Oakfield or Milford stations from April 14 to May 9.\n\u2022 A free replacement bus service (Route 7B) will operate between Oakfield and Milford, connecting with Line 7 services at both terminals.\n\u2022 The replacement bus will depart every 12 minutes during peak hours (7:00\u20139:30 a.m. and 4:30\u20137:00 p.m.) and every 20 minutes at other times.\n\u2022 Passengers holding valid transit cards or printed tickets will be accepted on Route 7B at no additional charge.\n\nPassengers travelling between stations not affected by these works will experience no change to regular services.\n\nWe apologise for any inconvenience and thank passengers for their understanding during this essential upgrade period.\nCity Transit Authority", "passageTitle": "Transit Service Update", "type": "single", "questions": [{"id": "xp7-s06a", "part": 7, "question": "Why are changes being made to Line 7?", "options": ["Due to a signal fault", "To reduce overcrowding", "To allow track upgrade works between two stations", "Following a safety audit"], "answer": 2, "explanation": "'To accommodate track upgrade works between Oakfield and Milford stations.'", "difficulty": "medium"}, {"id": "xp7-s06b", "part": 7, "question": "How often does the replacement bus run during off-peak hours?", "options": ["Every 8 minutes", "Every 12 minutes", "Every 15 minutes", "Every 20 minutes"], "answer": 3, "explanation": "'Every 20 minutes at other times' (outside peak hours).", "difficulty": "medium"}, {"id": "xp7-s06c", "part": 7, "question": "What do passengers need to board Route 7B at no extra cost?", "options": ["A Route 7B-specific ticket", "A valid transit card or printed ticket", "Proof of regular Line 7 usage", "A free pass from the transit authority"], "answer": 1, "explanation": "'Passengers holding valid transit cards or printed tickets will be accepted on Route 7B at no additional charge.'", "difficulty": "medium"}, {"id": "xp7-s06d", "part": 7, "question": "Who will NOT be affected by these service changes?", "options": ["Commuters who use Oakfield station daily", "Passengers travelling between other Line 7 stations", "Passengers connecting to Route 7B", "Passengers travelling to Milford station"], "answer": 1, "explanation": "'Passengers travelling between stations not affected by these works will experience no change to regular services.'", "difficulty": "medium"}]}, {"passage": "GLOBALREACH COMMUNICATIONS\nService Agreement \u2014 Summary of Key Terms\n\nThis summary outlines the key terms of your GlobalReach Business Communications contract (Ref: GR-881123).\n\nSERVICES INCLUDED:\n\u2022 Unlimited domestic calls and texts\n\u2022 50GB data per month (rollover of unused data not permitted)\n\u2022 International calling credit: USD 30 per month (applicable to 45 countries)\n\nCONTRACT TERM: 24 months from activation date\n\nBILLING: Monthly invoices will be issued on the 1st of each month and are payable within 14 days.\n\nEARLY TERMINATION: If you cancel the service before the end of the 24-month term, an early termination fee of USD 15 per remaining month will apply.\n\nAUTO-RENEWAL: This contract will automatically renew on a month-to-month basis at the prevailing rate unless written notice of cancellation is provided at least 30 days before the contract end date.\n\nFor service queries, contact business@globalreach.com or call 1800 555 0100.", "passageTitle": "Service Agreement", "type": "single", "questions": [{"id": "xp7-s07a", "part": 7, "question": "What happens to unused monthly data?", "options": ["It rolls over to the following month", "It is added to international credit", "It cannot be carried over", "It converts to additional call minutes"], "answer": 2, "explanation": "'Rollover of unused data not permitted.'", "difficulty": "medium"}, {"id": "xp7-s07b", "part": 7, "question": "What is the early termination fee per month?", "options": ["USD 10", "USD 15", "USD 20", "USD 30"], "answer": 1, "explanation": "'An early termination fee of USD 15 per remaining month.'", "difficulty": "medium"}, {"id": "xp7-s07c", "part": 7, "question": "What must a customer do to prevent automatic renewal?", "options": ["Contact the provider 14 days before end date", "Submit written cancellation at least 30 days before end date", "Call 1800 555 0100 on the final day", "Email a cancellation request any time before renewal"], "answer": 1, "explanation": "'Written notice of cancellation... at least 30 days before the contract end date.'", "difficulty": "medium"}, {"id": "p7-s-v14", "part": 7, "question": "In the agreement, the word \"terminate\" is closest in meaning to", "options": ["end", "suspend", "renegotiate", "modify"], "answer": 0, "explanation": "WIC: \"terminate an agreement\" = ch\u1ea5m d\u1ee9t h\u1ee3p \u0111\u1ed3ng. \"End\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t v\u00e0 ph\u1ed5 bi\u1ebfn nh\u1ea5t trong ng\u1eef c\u1ea3nh v\u0103n b\u1ea3n h\u1ee3p \u0111\u1ed3ng."}]}, {"passage": "MERIDIAN EXECUTIVE SEARCH\nPlacement Report \u2014 October\n\nMeridian Executive Search is pleased to present the following highlights from our October placement activity.\n\nDuring October, Meridian successfully placed 14 senior professionals across the Finance, Technology, and Operations sectors. This represents a 22% increase from September's total of 11 placements.\n\nNotable placements this month included a Chief Information Officer for a mid-sized logistics company, a Regional Finance Director for a multinational consumer goods firm, and three Senior Software Engineers for a fast-growing fintech startup.\n\nOur average time-to-placement for the month was 31 days, compared to an industry benchmark of 45 days. Client satisfaction surveys indicated that 92% of hiring managers rated the quality of candidates presented as 'excellent' or 'very good'.\n\nLooking ahead, we anticipate continued demand in the Technology and ESG-focused leadership roles as companies accelerate their digital and sustainability agendas.\n\nFor enquiries, contact your Meridian relationship manager or email partners@meridianexec.com.", "passageTitle": "Recruitment Report", "type": "single", "questions": [{"id": "xp7-s08a", "part": 7, "question": "By how much did placements increase from September to October?", "options": ["11%", "18%", "22%", "25%"], "answer": 2, "explanation": "'22% increase from September's total of 11 placements.'", "difficulty": "medium"}, {"id": "xp7-s08b", "part": 7, "question": "What was Meridian's average time-to-placement in October?", "options": ["22 days", "31 days", "38 days", "45 days"], "answer": 1, "explanation": "'Our average time-to-placement for the month was 31 days.'", "difficulty": "medium"}, {"id": "xp7-s08c", "part": 7, "question": "What did 92% of hiring managers say about candidates?", "options": ["They were placed faster than expected", "They met technical requirements", "They were rated excellent or very good", "They exceeded salary expectations"], "answer": 2, "explanation": "'92% of hiring managers rated the quality of candidates as excellent or very good.'", "difficulty": "medium"}, {"id": "p7-s-v25", "part": 7, "question": "In the report, the word \"placement\" is closest in meaning to", "options": ["successful hire", "interview", "assessment", "shortlisting"], "answer": 0, "explanation": "WIC: \"placement\" in recruitment = vi\u1ec7c s\u1eafp x\u1ebfp vi\u1ec7c l\u00e0m th\u00e0nh c\u00f4ng cho \u1ee9ng vi\u00ean. \"Successful hire\" l\u00e0 di\u1ec5n \u0111\u1ea1t t\u01b0\u01a1ng \u0111\u01b0\u01a1ng nh\u1ea5t trong ng\u1eef c\u1ea3nh b\u00e1o c\u00e1o tuy\u1ec3n d\u1ee5ng."}]}, {"passage": "LAKEWOOD BUSINESS IMPROVEMENT DISTRICT\nGrant Programme \u2014 Call for Applications\n\nThe Lakewood Business Improvement District (BID) is inviting applications for its 2024\u201325 Small Business Sustainability Grant.\n\nPURPOSE\nThe grant supports small businesses in the Lakewood precinct to implement environmentally sustainable practices, reduce operating costs, and improve community engagement.\n\nELIGIBILITY\n\u2022 Business must be located within the Lakewood BID boundary\n\u2022 Annual turnover not exceeding AUD 2 million\n\u2022 Business must have been operating for at least 12 months at the time of application\n\nGRANT DETAILS\n\u2022 Grants of AUD 3,000\u201310,000 are available\n\u2022 Funds must be used within 12 months of approval\n\u2022 A progress report must be submitted 6 months after grant approval\n\u2022 Final acquittal documentation required within 30 days of project completion\n\nAPPLICATION PROCESS\nApplications open: September 1\nApplications close: September 30\nOutcomes notified: November 1\n\nApply online: www.lakewoodbid.org/grants", "passageTitle": "Community Programme", "type": "single", "questions": [{"id": "xp7-s09a", "part": 7, "question": "What is the maximum annual turnover allowed for applicants?", "options": ["AUD 500,000", "AUD 1 million", "AUD 2 million", "AUD 5 million"], "answer": 2, "explanation": "'Annual turnover not exceeding AUD 2 million.'", "difficulty": "medium"}, {"id": "xp7-s09b", "part": 7, "question": "How long must a business have been operating to be eligible?", "options": ["6 months", "12 months", "18 months", "24 months"], "answer": 1, "explanation": "'Business must have been operating for at least 12 months at the time of application.'", "difficulty": "medium"}, {"id": "xp7-s09c", "part": 7, "question": "When will successful applicants be notified of outcomes?", "options": ["September 1", "September 30", "November 1", "December 1"], "answer": 2, "explanation": "'Outcomes notified: November 1.'", "difficulty": "medium"}, {"id": "p7-s-v19", "part": 7, "question": "What can be inferred about the purpose of the programme?", "options": ["It is designed to generate revenue for the council", "It aims to improve community wellbeing and engagement", "It is primarily intended for senior citizens", "It was introduced in response to a specific community complaint"], "answer": 1, "explanation": "Inference: Community programmes are designed to improve wellbeing and engagement \u2014 inferred from the activities offered and the organisation's stated goals."}]}, {"passage": "WEST END COMMUNITY CENTRE\nSummer Programme \u2014 Activity Guide\n\nThe West End Community Centre is offering its annual Summer Activity Programme for residents of all ages. Registrations open June 1.\n\nHIGHLIGHT PROGRAMMES:\n\u2022 Junior Robotics (Ages 8\u201312): A hands-on 4-week course teaching basic coding and robot assembly. Monday/Wednesday, 10:00 a.m. \u2013 12:00 p.m.\n\u2022 Seniors Yoga (Ages 60+): Gentle yoga sessions designed for flexibility and relaxation. Tuesday/Thursday, 9:00\u201310:00 a.m. Free of charge.\n\u2022 Community Garden Workshops (All ages): Learn sustainable gardening practices. Saturday mornings, 8:30\u201310:30 a.m. Materials fee: AUD 10 per session.\n\u2022 Youth Photography (Ages 15\u201319): 8-week course in digital photography and editing. Fridays, 2:00\u20134:30 p.m.\n\nREGISTRATION: Visit www.westendcc.org.au or call the centre at 02 9514 2200.\nPlaces are limited; early registration is recommended.\n\nThe Community Centre is committed to ensuring programmes are accessible to all. Concession pricing and subsidies are available for eligible residents.", "passageTitle": "Community Programme", "type": "single", "questions": [{"id": "xp7-s10a", "part": 7, "question": "Which programme is available at no cost?", "options": ["Junior Robotics", "Seniors Yoga", "Community Garden Workshops", "Youth Photography"], "answer": 1, "explanation": "'Seniors Yoga... Free of charge.'", "difficulty": "medium"}, {"id": "xp7-s10b", "part": 7, "question": "How long is the Youth Photography course?", "options": ["4 weeks", "6 weeks", "8 weeks", "10 weeks"], "answer": 2, "explanation": "'8-week course in digital photography and editing.'", "difficulty": "medium"}, {"id": "xp7-s10c", "part": 7, "question": "What fee is charged for each Community Garden Workshop?", "options": ["AUD 5", "AUD 10", "AUD 15", "AUD 20"], "answer": 1, "explanation": "'Materials fee: AUD 10 per session.'", "difficulty": "medium"}, {"id": "p7-s-v41", "part": 7, "question": "What does the programme suggest about the centre's broader mission?", "options": ["It focuses exclusively on arts education for young people", "It aims to make activities accessible to people of all backgrounds", "It is primarily funded by government grants", "It operates as a private membership club"], "answer": 1, "explanation": "Inference: Offering subsidised rates for lower-income residents + free programmes + varied activities strongly implies the centre's mission is broad accessibility and community inclusion."}]}, {"passage": "[Document 1 \u2013 Newsletter Excerpt]\n\nSOUTHBAY CHAMBER OF COMMERCE\nMember Spotlight \u2014 Spring Edition\n\nThis quarter, we shine the spotlight on DataBridge Analytics, a Southbay-based data consultancy that has grown from a two-person startup to a team of 45 in just four years.\n\nFounded in 2020 by former university colleagues Priya Mehta and Oliver Fung, DataBridge specialises in helping mid-sized businesses interpret complex datasets to improve operational decision-making. Their flagship product, ClearView, is now used by over 200 clients across healthcare, logistics, and retail sectors.\n\nPriya Mehta credits the company's rapid growth to its focus on accessibility: \"We built ClearView for the business manager who doesn't have a data science background. We translate numbers into plain language that drives action.\"\n\nDataBridge was recently named a finalist in the National Technology Innovation Awards in the SME category.\n\n[Document 2 \u2013 Event Invitation]\n\nSouthbay Chamber of Commerce \u2014 Networking Breakfast\nFeaturing: Priya Mehta, Co-Founder, DataBridge Analytics\n\nDate: Thursday, June 12\nTime: 7:30 \u2013 9:30 a.m.\nVenue: The Harbour Club, Level 2, 40 Bay Street, Southbay\n\nPriya Mehta will share her experience building a fast-growing data consultancy, including lessons learned about hiring, scaling technology, and winning enterprise clients.\n\nTickets: AUD 45 per person (Chamber members); AUD 65 (non-members)\nIncludes: Breakfast, networking, and Q&A session\n\nRSVP by June 5: events@southbaychamber.org", "passageTitle": "Newsletter + Event Invitation", "type": "double", "questions": [{"id": "xp7-d01a", "part": 7, "question": "How many staff does DataBridge Analytics currently employ?", "options": ["2", "20", "45", "200"], "answer": 2, "explanation": "'Grown from a two-person startup to a team of 45 in just four years.'", "difficulty": "medium"}, {"id": "xp7-d01b", "part": 7, "question": "What is ClearView designed for?", "options": ["Data scientists seeking advanced tools", "Business managers without a data science background", "University researchers analysing large datasets", "IT departments managing enterprise software"], "answer": 1, "explanation": "'We built ClearView for the business manager who doesn't have a data science background.'", "difficulty": "medium"}, {"id": "xp7-d01cd", "part": 7, "question": "In Document 2, the word \"complimentary\" is closest in meaning to", "options": ["free of charge", "high quality", "limited edition", "exclusive"], "answer": 0, "explanation": "WIC in Document 2: \"complimentary coffee and pastries\" = mi\u1ec5n ph\u00ed, t\u1eb7ng k\u00e8m. \"Free of charge\" l\u00e0 di\u1ec5n \u0111\u1ea1t t\u01b0\u01a1ng \u0111\u01b0\u01a1ng ch\u00ednh x\u00e1c nh\u1ea5t."}, {"id": "xp7-d01d", "part": 7, "question": "What does the breakfast ticket include?", "options": ["A copy of ClearView software", "A post-event summary report", "Breakfast, networking, and a Q&A session", "Access to the Chamber's member portal"], "answer": 2, "explanation": "'Includes: Breakfast, networking, and Q&A session'", "difficulty": "medium"}, {"id": "xp7-d01x", "part": 7, "question": "Based on both documents, why would the networking breakfast be particularly relevant to readers of the Member Spotlight article?", "options": ["The breakfast offers a discount to DataBridge Analytics employees", "Priya Mehta, featured in the article, will be speaking at the breakfast", "The breakfast is being held at DataBridge Analytics' headquarters", "The article announces that DataBridge is sponsoring the breakfast"], "answer": 1, "explanation": "Cross-document: Newsletter features Priya Mehta (DataBridge co-founder). Event invitation lists Priya Mehta as the featured speaker. Reading both documents reveals she is the direct connection between the two."}]}, {"passage": "[Document 1 \u2013 Internal Announcement]\n\nFrom: CEO Office\nTo: All Staff\nDate: March 10\nSubject: Welcoming Our New Chief Financial Officer\n\nI am delighted to announce that Ms. Vanessa Osei will join Hartwell Group as Chief Financial Officer, effective April 1.\n\nVanessa brings 18 years of financial leadership experience, most recently as Deputy CFO at Crestline Capital Partners, where she led a team of 40 finance professionals and oversaw a portfolio of over USD 3 billion in managed assets.\n\nVanessa holds an MBA from INSEAD and is a Fellow of the Chartered Institute of Management Accountants (FCMA). She is known for her disciplined approach to capital allocation and her track record of driving operational efficiency.\n\nVanessa will present at our All-Staff Townhall on April 8, where she will share her priorities for the finance function and answer questions from the team.\n\nPlease join me in welcoming Vanessa to Hartwell Group.\n\nJonathan Webb, CEO\n\n[Document 2 \u2013 Email from Vanessa Osei]\n\nFrom: Vanessa Osei <v.osei@hartwellgroup.com>\nTo: Finance Team <finance@hartwellgroup.com>\nDate: April 1\nSubject: Hello from Your New CFO\n\nDear Finance Team,\n\nI am thrilled to have joined Hartwell Group today. I have been looking forward to this opportunity and cannot wait to meet each of you in person.\n\nIn my first few weeks, I plan to spend time understanding the current structure and workflows of our finance function. I will be scheduling one-on-one meetings with each team member during April to hear your perspectives and identify opportunities for improvement.\n\nI also want to share that my initial focus will be on three areas: strengthening our financial reporting framework, improving forecasting accuracy, and reviewing our vendor payment processes.\n\nI look forward to working alongside you all.\nVanessa Osei", "passageTitle": "CEO Announcement + New Employee Email", "type": "double", "questions": [{"id": "xp7-d02a", "part": 7, "question": "How many years of financial leadership experience does Ms. Osei have?", "options": ["8 years", "12 years", "15 years", "18 years"], "answer": 3, "explanation": "'18 years of financial leadership experience.'", "difficulty": "medium"}, {"id": "xp7-d02b", "part": 7, "question": "Where will Ms. Osei introduce herself to all staff?", "options": ["In a one-on-one with the CEO", "At the All-Staff Townhall on April 8", "In a welcome lunch with the finance team", "Via a company-wide video call on April 1"], "answer": 1, "explanation": "'Vanessa will present at our All-Staff Townhall on April 8.'", "difficulty": "medium"}, {"id": "xp7-d02cd", "part": 7, "question": "Based on both documents, what is confirmed about Ms. Osei's start date?", "options": ["She started on March 10 when the CEO announcement was made", "She started between the CEO announcement and the date of her own email", "Her exact start date cannot be determined from the two documents", "She started on April 1 based on her email date"], "answer": 1, "explanation": "Cross-document: CEO announcement dated March 10, Ms. Osei's own email dated April 2. She refers to \"my first few weeks\" in April \u2192 she started sometime between March 10 and early April."}, {"id": "xp7-d02d", "part": 7, "question": "Which area is NOT one of Ms. Osei's initial priorities?", "options": ["Strengthening the financial reporting framework", "Improving forecasting accuracy", "Reviewing vendor payment processes", "Reducing the size of the finance team"], "answer": 3, "explanation": "Her three stated priorities are: financial reporting, forecasting accuracy, and vendor payment processes. Team reduction is not mentioned.", "difficulty": "medium"}, {"id": "xp7-d02x", "part": 7, "question": "Based on both documents, which statement best describes Ms. Osei's approach in her first weeks at Hartwell Group?", "options": ["She plans to make immediate changes to the finance team structure", "She will focus on understanding the business before making changes", "She intends to implement a new financial reporting system immediately", "She plans to reorganise the finance team based on her previous experience"], "answer": 1, "explanation": "Cross-document: CEO announcement introduces Ms. Osei. Her own email states she plans to meet the team and understand current processes first \u2014 both documents together confirm a \"listen first\" approach before changes."}]}, {"passage": "[Document 1 \u2013 Gym Membership Contract]\n\nIRONFIELD FITNESS \u2014 MEMBERSHIP AGREEMENT\nMember: Lucas Hartmann | Plan: Premium Annual | Start: January 1\n\nMONTHLY FEE: AUD 79 (billed annually as AUD 948)\nINCLUDES: Unlimited access to all equipment, group classes, sauna, and guest passes (2 per month).\n\nCONTRACT TERM: 12 months. Early cancellation fee: AUD 150.\nAUTO-RENEWAL: Membership renews automatically unless cancelled in writing 30 days before expiry.\n\n[Document 2 \u2013 Member Complaint Email]\n\nFrom: Lucas Hartmann <l.hartmann@email.com>\nTo: info@ironfield.com.au\nDate: November 10\nSubject: Membership Concern \u2014 Account Ref LH-1122\n\nHello,\n\nI joined Ironfield on January 1 on an annual Premium plan. I am now concerned that my membership is set to auto-renew in January, and I have recently moved to a suburb with no nearby Ironfield location.\n\nI would like to cancel my membership before the renewal date without being charged the AUD 150 early termination fee, given that the nearest branch is now over 40 km from my home.\n\nCould you please advise on whether an exception to the cancellation fee can be made in this circumstance? I am happy to provide proof of my change of address.\n\nThank you,\nLucas Hartmann", "passageTitle": "Gym Contract + Member Complaint Email", "type": "double", "questions": [{"id": "xp7-d03a", "part": 7, "question": "How many guest passes per month does Lucas receive?", "options": ["1", "2", "3", "4"], "answer": 1, "explanation": "'Guest passes (2 per month)'", "difficulty": "medium"}, {"id": "xp7-d03b", "part": 7, "question": "What is the early cancellation fee?", "options": ["AUD 79", "AUD 100", "AUD 150", "AUD 200"], "answer": 2, "explanation": "'Early cancellation fee: AUD 150.'", "difficulty": "medium"}, {"id": "xp7-d03cd", "part": 7, "question": "Based on both documents, what is the maximum amount Lucas Hartmann could be required to pay to cancel his membership?", "options": ["Nothing, because his reason qualifies for a fee waiver", "Two months of remaining membership fees", "The standard early cancellation penalty stated in the contract", "A prorated amount based on unused membership days"], "answer": 2, "explanation": "Cross-document: Contract states the early cancellation fee. Lucas's complaint establishes service failure \u2014 but if the gym disputes this, the maximum he could be charged is the standard penalty from the contract."}, {"id": "xp7-d03x", "part": 7, "question": "Based on both documents, does Lucas Hartmann have a valid grounds to cancel without paying the early cancellation fee?", "options": ["Yes, because he is relocating outside the service area", "No, because he has not completed the minimum contract term", "Yes, because the gym failed to provide the contracted services", "No, because his reason does not qualify under the contract terms"], "answer": 2, "explanation": "Cross-document: Contract states fee is waived if gym fails to provide contracted services. Lucas's email documents a specific service failure (pool closure, class cancellations). Combining both gives him valid grounds under the contract's waiver clause."}, {"id": "xp7-d03e", "part": 7, "question": "Based on the contract, when must Lucas cancel to avoid auto-renewal?", "options": ["By November 30", "By December 1", "By December 15", "By January 1"], "answer": 1, "explanation": "Auto-renewal requires written cancellation '30 days before expiry.' Membership ends January 1, so he must cancel by December 1.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Conference Programme]\n\nASIA-PACIFIC SUPPLY CHAIN FORUM \u2014 DAY 2 PROGRAMME\nVenue: Marina Bay Exhibition Hall, Singapore\n\n09:00 \u2013 09:45  Keynote: The Future of Last-Mile Delivery in Urban Centres\n                Speaker: Dr. Soo-Lin Chen, Director, APAC Logistics Institute\n\n10:00 \u2013 11:00  Panel: Resilience Strategies After Global Disruption\n                Panellists: Riku Tanaka (VP, NovaTrade); Maria Ferreiro (COO, SwiftFreight); James Park (Director, PortLogix)\n\n11:00 \u2013 11:30  Morning Break & Exhibition Networking\n\n11:30 \u2013 12:30  Workshop A: Implementing AI in Warehouse Operations\n                Workshop B: Green Logistics \u2014 Decarbonising the Supply Chain\n\n12:30 \u2013 14:00  Lunch\n\n14:00 \u2013 14:30  How GreenHarbour Reduced Picking Errors by 40% Using Robotics\n14:30 \u2013 15:00  Cross-Border Trade Compliance: Lessons from a Failed Expansion\n\n15:15 \u2013 16:30  Closing Keynote & Awards Ceremony\n\n[Document 2 \u2013 Delegate Message]\n\nFrom: Patricia Nguyen <p.nguyen@supplychainpro.vn>\nTo: Conference Team <info@apsupplychain.org>\nDate: Day 2, 10:52 a.m.\nSubject: Workshop Registration\n\nHello,\n\nI attended the morning keynote and am now at the networking break. I would like to attend one of the 11:30 workshops but am uncertain which to choose.\n\nCould you tell me whether Workshop A is suitable for someone who has no technical background in AI, and whether it is still possible to register on the day?\n\nAlso, is the Case Study at 14:30 focused on import compliance, or does it cover export regulations as well?\n\nThank you,\nPatricia Nguyen", "passageTitle": "Conference Programme + Delegate Email", "type": "double", "questions": [{"id": "xp7-d04a", "part": 7, "question": "How many panellists are listed for the 10:00 session?", "options": ["2", "3", "4", "5"], "answer": 1, "explanation": "Three panellists: Riku Tanaka, Maria Ferreiro, and James Park.", "difficulty": "medium"}, {"id": "xp7-d04b", "part": 7, "question": "At what time does Patricia Nguyen send her email?", "options": ["9:00 a.m.", "10:52 a.m.", "11:30 a.m.", "12:30 p.m."], "answer": 1, "explanation": "The email timestamp is 'Day 2, 10:52 a.m.'", "difficulty": "medium"}, {"id": "xp7-d04cd", "part": 7, "question": "In Document 1, the word \"concurrent\" as used in the programme is closest in meaning to", "options": ["happening at the same time", "following in sequence", "offered on request", "available online"], "answer": 0, "explanation": "WIC in Document 1: \"concurrent workshops\" = c\u00e1c workshop di\u1ec5n ra c\u00f9ng l\u00fac. \"Happening at the same time\" l\u00e0 di\u1ec5n \u0111\u1ea1t ch\u00ednh x\u00e1c nh\u1ea5t trong ng\u1eef c\u1ea3nh l\u1ecbch tr\u00ecnh h\u1ed9i ngh\u1ecb."}, {"id": "xp7-d04d", "part": 7, "question": "What topic does the 14:30 case study address?", "options": ["Robotics in warehouse operations", "AI applications in logistics", "Cross-border trade compliance", "Green energy in freight"], "answer": 2, "explanation": "'14:30 \u2013 15:00 Cross-Border Trade Compliance: Lessons from a Failed Expansion.'", "difficulty": "medium"}, {"id": "xp7-d04x", "part": 7, "question": "Based on both documents, at which session was Patricia Nguyen most likely present when she sent her email?", "options": ["The opening keynote", "The panel discussion on supply chain resilience", "The networking luncheon", "One of the afternoon workshops"], "answer": 2, "explanation": "Cross-document: Patricia's email timestamp + conference schedule. Her email was sent during the lunch break (networking luncheon period). Combining the programme times with her email timestamp places her at the luncheon."}]}, {"passage": "[Document 1 \u2013 Online Listing]\n\nLISTING: Sublet Office Space \u2014 3 Months\nLocation: 45 King Street, Level 8, Sydney CBD\nSize: 6 workstations (approx. 45 sqm)\nAvailable: September 1 \u2013 November 30\nRent: AUD 3,800/month (all-inclusive: utilities, internet, meeting room access)\n\nDESCRIPTION:\nPrime CBD location, 2 minutes walk from Wynyard Station. Shared reception and kitchen. Building amenities include end-of-trip facilities and a rooftop terrace. Flexible access hours: 7:00 a.m. \u2013 10:00 p.m.\n\nIdeal for: small teams on short-term projects, pop-up operations, or companies awaiting a permanent lease.\n\nContact: Michelle Croft at m.croft@stratosgroup.com.au\n\n[Document 2 \u2013 Enquiry Email]\n\nFrom: Nathan Briggs <n.briggs@lumino.io>\nTo: m.croft@stratosgroup.com.au\nDate: August 14\nSubject: Enquiry \u2014 King Street Sublet\n\nDear Ms. Croft,\n\nI am writing regarding the sublet listing at 45 King Street. We are a team of 4 currently working out of a shared coworking space, and we are looking for a dedicated, private office for a 2\u20133 month period while our permanent premises are being refurbished.\n\nWe would be interested in the space if it is exclusively accessible to our team \u2014 i.e., not shared with other companies during our tenancy.\n\nCould you also confirm whether the AUD 3,800/month rate includes parking for 2 vehicles?\n\nWe are hoping to take occupancy from September 1 and would appreciate an early response.\n\nKind regards,\nNathan Briggs, Director, Lumino", "passageTitle": "Office Sublet Listing + Enquiry Email", "type": "double", "questions": [{"id": "xp7-d05a", "part": 7, "question": "How long is the sublet available?", "options": ["1 month", "2 months", "3 months", "6 months"], "answer": 2, "explanation": "'Available: September 1 \u2013 November 30' = 3 months.", "difficulty": "medium"}, {"id": "xp7-d05b", "part": 7, "question": "What does the rent include?", "options": ["Parking, utilities, and internet", "Utilities, internet, and meeting room access", "Meeting room access and catering", "Rooftop terrace hire and reception services"], "answer": 1, "explanation": "'AUD 3,800/month (all-inclusive: utilities, internet, meeting room access).'", "difficulty": "medium"}, {"id": "xp7-d05cd", "part": 7, "question": "Based on both documents, what is NOT confirmed as matching Lumino's specific requirements?", "options": ["The available lease duration", "The inclusion of internet in the rent", "The proximity to Lumino's clients", "The number of workstations available"], "answer": 2, "explanation": "Cross-document: Listing confirms duration, internet, and workstation count. Lumino's email does NOT mention client proximity as a requirement \u2014 this aspect cannot be confirmed as matching from the two documents."}, {"id": "xp7-d05d", "part": 7, "question": "What specific concern does Nathan Briggs raise?", "options": ["Whether the building has 24-hour access", "Whether parking is included", "Whether the space will be shared with other tenants", "Whether the internet speed is adequate"], "answer": 2, "explanation": "'We would be interested in the space if it is exclusively accessible to our team \u2014 not shared with other companies.'", "difficulty": "medium"}, {"id": "xp7-d05e", "part": 7, "question": "How does Lumino's team size compare to the office capacity?", "options": ["The team is too large for the space", "The team is exactly the right size", "The space has more workstations than Lumino needs", "The space needs to be expanded"], "answer": 2, "explanation": "The listing offers 6 workstations; Lumino has a team of 4 \u2014 2 extra workstations.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Job Posting]\n\nHEAD OF MARKETING \u2014 NOVA CONSUMER GOODS\nLocation: Sydney, NSW | Permanent, Full-Time\n\nNova Consumer Goods is seeking an experienced Head of Marketing to lead our brand strategy and marketing team of 12.\n\nKey Responsibilities:\n\u2022 Develop and execute the company's brand and digital marketing strategy\n\u2022 Oversee all marketing channels including social media, email, paid advertising, and events\n\u2022 Manage a marketing budget of AUD 4.5 million\n\u2022 Lead and develop a team of 12 marketing professionals\n\u2022 Report directly to the CEO and present quarterly performance updates to the board\n\nRequirements:\n\u2022 Minimum 8 years of marketing experience, including at least 3 at a senior leadership level\n\u2022 Experience managing large marketing budgets (AUD 3M+)\n\u2022 Proven track record in B2C consumer brands\n\u2022 Bachelor's degree; MBA preferred\n\nSalary: AUD 180,000\u2013210,000 + bonus\nDeadline: February 28. Apply to: careers@novacg.com.au\n\n[Document 2 \u2013 Cover Letter]\n\nFrom: Dominic Leung <d.leung@email.com>\nTo: careers@novacg.com.au\nDate: February 22\n\nDear Hiring Team,\n\nI am applying for the Head of Marketing position at Nova Consumer Goods. With 11 years of marketing experience, including 4 years as Marketing Director at Brightfield Brands, I believe I am a strong fit for this role.\n\nAt Brightfield, I oversaw a marketing budget of AUD 5.2 million and led a team of 9. I spearheaded the company's digital transformation, achieving a 38% increase in online revenue over two years.\n\nI hold a Bachelor of Commerce and an MBA from the University of Melbourne. I am particularly drawn to Nova's commitment to sustainable product development, which aligns with my own values.\n\nPlease find my CV and portfolio attached.\n\nDominic Leung\n\n[Document 3 \u2013 Interview Outcome Email]\n\nFrom: Talent Team <talent@novacg.com.au>\nTo: Dominic Leung <d.leung@email.com>\nDate: March 18\nSubject: Head of Marketing \u2014 Interview Outcome\n\nDear Mr. Leung,\n\nThank you for your time and the excellent presentation you delivered during your final-round interview last week.\n\nAfter careful consideration, we are pleased to offer you the position of Head of Marketing at Nova Consumer Goods. We were particularly impressed by your track record in digital transformation and your strategic approach to brand building.\n\nYour proposed start date is April 7. Please confirm your acceptance by March 25 by signing and returning the enclosed offer letter.\n\nWe look forward to welcoming you to the team.\n\nNova Talent Team", "passageTitle": "Job Posting + Cover Letter + Interview Outcome", "type": "triple", "questions": [{"id": "xp7-t01b", "part": 7, "question": "Does Dominic Leung meet the minimum experience requirement?", "options": ["No, he has only 8 years", "Yes, he has exactly the minimum", "Yes, he exceeds the minimum", "No, he lacks senior leadership experience"], "answer": 2, "explanation": "Job requires 8 years + 3 senior; Dominic has 11 years + 4 as Marketing Director \u2014 exceeds both.", "difficulty": "medium"}, {"id": "xp7-t01v", "part": 7, "question": "In Document 2, the word \"spearheaded\" is closest in meaning to", "options": ["led", "completed", "managed", "supported"], "answer": 0, "explanation": "WIC: \"spearheaded the company's digital transformation\" = \u0111i \u0111\u1ea7u, d\u1eabn d\u1eaft. \"Led\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t v\u00e0 ph\u1ed5 bi\u1ebfn nh\u1ea5t trong ng\u1eef c\u1ea3nh CV/cover letter TOEIC."}, {"id": "xp7-t01d", "part": 7, "question": "By what date must Dominic confirm his acceptance?", "options": ["March 18", "March 22", "March 25", "April 7"], "answer": 2, "explanation": "'Please confirm your acceptance by March 25.'", "difficulty": "medium"}, {"id": "xp7-t01e", "part": 7, "question": "What particularly impressed Nova Consumer Goods?", "options": ["His MBA qualification", "His experience managing a large team", "His digital transformation track record and strategic approach", "His connection to sustainable product development"], "answer": 2, "explanation": "'We were particularly impressed by your track record in digital transformation and your strategic approach to brand building.'", "difficulty": "medium"}, {"id": "xp7-t01f", "part": 7, "question": "How does the budget Dominic managed at Brightfield compare to Nova's?", "options": ["It was smaller", "It was equal", "It was larger", "Cannot be compared from the information given"], "answer": 2, "explanation": "Dominic managed AUD 5.2M at Brightfield vs Nova's AUD 4.5M \u2014 his previous budget was larger.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Company Policy Extract]\n\nSUNRISE FINANCIAL SERVICES\nEmployee Travel & Entertainment Policy \u2014 Section 4\n\n4.1 CLIENT ENTERTAINMENT\nEmployees may claim expenses for client entertainment up to AUD 200 per client per occasion. Expenses above this limit require prior written approval from a senior manager.\n\n4.2 MEALS DURING BUSINESS TRAVEL\nThe daily meal allowance for domestic travel is AUD 75. For international travel, AUD 120 applies. Receipts are required for all claims above AUD 30.\n\n4.3 TRANSPORT\nTaxi and rideshare fares are reimbursable for business travel where public transport is impractical. Airport transfers are fully reimbursable. Car rental requires pre-approval.\n\n4.4 SUBMISSION DEADLINE\nAll expense claims must be submitted within 15 business days of the expense being incurred. Late submissions will require written justification to the Finance Director.\n\n[Document 2 \u2013 Expense Claim Email]\n\nFrom: Fiona Marsh <f.marsh@sunrisefs.com>\nTo: finance@sunrisefs.com\nDate: June 6\nSubject: Expense Claim \u2014 Client Visit, Perth, June 2\u20134\n\nHi Finance Team,\n\nPlease find attached my expense claim for my Perth trip. Summary below:\n\n- Return flights: AUD 680 (pre-approved)\n- Hotel (3 nights): AUD 895\n- Meals (3 days @ AUD 75): AUD 225\n- Client dinner, June 3: AUD 310 (4 guests)\n- Airport transfers (x2): AUD 95\n- Car rental (June 3): AUD 140 (pre-approved)\n\nTotal claimed: AUD 2,345\n\nI note the client dinner exceeded the per-person AUD 200 limit. With 4 guests, the limit would be AUD 800. I obtained verbal approval from my manager before the event \u2014 could you confirm whether that is sufficient, or whether I need a written record?\n\nThanks,\nFiona\n\n[Document 3 \u2013 Finance Team Response]\n\nFrom: Finance Team <finance@sunrisefs.com>\nTo: Fiona Marsh <f.marsh@sunrisefs.com>\nDate: June 7\n\nHi Fiona,\n\nThank you for your submission. Your claim is within the 15-business-day window and all documentation appears to be in order.\n\nRegarding the client dinner: the policy requires prior written approval for client entertainment exceeding the per-occasion limit. Verbal approval is not sufficient. Please obtain a written confirmation from your manager (an email is acceptable) and resubmit the client dinner claim.\n\nAll other items will be processed in the next payment cycle.\n\nFinance Team", "passageTitle": "Company Policy + Expense Email + Finance Response", "type": "triple", "questions": [{"id": "xp7-t02a", "part": 7, "question": "What is the daily domestic meal allowance?", "options": ["AUD 30", "AUD 50", "AUD 75", "AUD 120"], "answer": 2, "explanation": "'The daily meal allowance for domestic travel is AUD 75.'", "difficulty": "medium"}, {"id": "xp7-t02b", "part": 7, "question": "What is the client entertainment limit per occasion without prior approval?", "options": ["AUD 100 per person", "AUD 200 per client per occasion", "AUD 800 for groups of 4", "AUD 200 total per event"], "answer": 1, "explanation": "'Up to AUD 200 per client per occasion.'", "difficulty": "medium"}, {"id": "xp7-t02c", "part": 7, "question": "Did Fiona submit her claim on time?", "options": ["No, she submitted more than 15 days after the trip", "Yes, her claim is within the 15-business-day window", "Her claim was submitted before receipts were attached", "She needs manager approval for the hotel cost"], "answer": 1, "explanation": "Finance confirms 'Your claim is within the 15-business-day window.'", "difficulty": "medium"}, {"id": "xp7-t02d", "part": 7, "question": "Why is Fiona's client dinner claim not fully processed?", "options": ["The amount exceeds the absolute maximum", "She failed to include receipts", "Verbal manager approval is not sufficient per policy", "She has not listed all 4 guests"], "answer": 2, "explanation": "'The policy requires prior written approval... Verbal approval is not sufficient.'", "difficulty": "medium"}, {"id": "xp7-t02e", "part": 7, "question": "What does the finance team accept as written approval?", "options": ["A signed memo from the Finance Director", "A formal letter on company letterhead", "An email from the manager", "A completed pre-approval form"], "answer": 2, "explanation": "'Please obtain a written confirmation from your manager (an email is acceptable).'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Product Recall Notice]\n\nOFFICIAL RECALL NOTICE\nProduct: BrewMaster Pro Coffee Machine \u2014 Model BM-400\nManufacturer: TasteLine Appliances Ltd.\n\nTasteLine Appliances Ltd. is voluntarily recalling the BrewMaster Pro BM-400 due to a manufacturing defect in the heating element, which may cause the unit to overheat under extended use. This could pose a fire risk.\n\nAffected units: Serial numbers BM400-001000 to BM400-075000\nDate range manufactured: March\u2013July 2023\n\nCustomers are advised to IMMEDIATELY stop using the product and unplug it. Do not continue to use the machine even if it appears to be functioning normally.\n\nFor a full refund or replacement, contact TasteLine at 1800 TASTELINE or register at tasteline.com/recall.\n\n[Document 2 \u2013 Customer Forum Post]\n\nPosted by: HomeKitchenFan | Product Review Forum\nDate: October 22\n\nHas anyone else received a recall notice for the BrewMaster Pro? I bought mine in May 2023 and just got an email about it. The serial number on mine is BM400-041222, so it's within the affected range.\n\nHonestly, the machine has been working perfectly for me. I'm a bit frustrated because it's my daily driver and I use it at least twice a day. However, I understand the safety risk.\n\nI registered for a replacement rather than a refund since I'm happy with the product otherwise. Has anyone gone through the replacement process? How long does it take?\n\n[Document 3 \u2013 TasteLine Customer Service Email]\n\nFrom: TasteLine Customer Service <recall@tasteline.com>\nTo: HomeKitchenFan (registered email)\nDate: October 24\nSubject: BrewMaster Pro Recall \u2014 Your Replacement Request\n\nDear Customer,\n\nThank you for registering your recall request. We have confirmed that your unit (BM400-041222) is within the affected serial number range.\n\nYour replacement BrewMaster Pro BM-450 (the updated model with the corrected heating element) will be dispatched within 10 business days. A prepaid return label for your BM-400 will be included in the delivery box.\n\nPlease do not return the unit until you have received the replacement \u2014 this ensures you are not without a coffee machine during the exchange.\n\nWe apologise for the inconvenience and thank you for your cooperation.\nTasteLine Customer Service", "passageTitle": "Recall Notice + Forum Post + Customer Service Email", "type": "triple", "questions": [{"id": "xp7-t03a", "part": 7, "question": "What is the safety risk with the BM-400?", "options": ["Electrical shock from a faulty power cord", "Water leakage from the brewing chamber", "Overheating of the heating element, creating a fire risk", "Excessive noise during operation"], "answer": 2, "explanation": "'A manufacturing defect in the heating element, which may cause the unit to overheat... This could pose a fire risk.'", "difficulty": "medium"}, {"id": "xp7-t03b", "part": 7, "question": "Is HomeKitchenFan's machine included in the recall?", "options": ["No, it was purchased after the affected date range", "Yes, the serial number falls within the affected range", "It cannot be determined", "No, only units made before March 2023 are affected"], "answer": 1, "explanation": "Serial BM400-041222 falls within BM400-001000 to BM400-075000. TasteLine confirms this in Document 3.", "difficulty": "medium"}, {"id": "xp7-t03c", "part": 7, "question": "Why did HomeKitchenFan choose a replacement rather than a refund?", "options": ["The refund process takes too long", "The replacement comes with an extended warranty", "They are satisfied with the product overall", "The refund amount was too low"], "answer": 2, "explanation": "'I registered for a replacement rather than a refund since I'm happy with the product otherwise.'", "difficulty": "medium"}, {"id": "xp7-t03d", "part": 7, "question": "What is included with the replacement unit delivery?", "options": ["A full refund cheque", "A prepaid return label for the BM-400", "A coupon for a future purchase", "An extended warranty certificate"], "answer": 1, "explanation": "'A prepaid return label for your BM-400 will be included in the delivery box.'", "difficulty": "medium"}, {"id": "xp7-t03e", "part": 7, "question": "What does TasteLine instruct about returning the old machine?", "options": ["Return it immediately before the replacement is dispatched", "Drop it off at an authorised service centre", "Do not return it until the replacement has arrived", "Send it back within 5 business days of the new unit"], "answer": 2, "explanation": "'Please do not return the unit until you have received the replacement.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Programme Flyer]\n\nSPRINGFIELD ARTS COUNCIL \u2014 GRANT INFORMATION SESSION\n\nDate: Wednesday, July 9\nTime: 5:30 \u2013 7:30 p.m.\nVenue: Springfield Arts Council, Studio Gallery, 14 Park Lane\n\nAre you an artist, performer, or arts organisation looking for funding? Come and learn about available grants, eligibility criteria, and how to write a compelling application.\n\nPresenters:\n- Grant Advisory Team, Springfield Arts Council\n- Kira Moss, successful grant recipient (mural installation, 2023)\n\nLight refreshments will be served. Free entry; no registration required.\n\n[Document 2 \u2013 Post-Session Email]\n\nFrom: Springfield Arts Council <grants@springfieldarts.org>\nTo: Session Attendees\nDate: July 10\nSubject: Resources from Last Night's Session\n\nDear Attendees,\n\nThank you for joining us last night. We were delighted to see over 60 people in attendance.\n\nAs promised, we have attached the following resources:\n1. Grant Programme Overview (PDF)\n2. Application checklist and common mistakes guide\n3. Recording of Kira Moss's presentation\n\nThe next grant application deadline is August 31. Applications must be submitted via the online portal at springfieldarts.org/grants.\n\nIf you have questions about your specific project or application, please book a one-on-one advisory session with our grants team via the portal.\n\nGood luck with your applications!\nSpringfield Arts Council Grants Team", "passageTitle": "Grants Session Flyer + Follow-up Email", "type": "double", "questions": [{"id": "xp7-d06a", "part": 7, "question": "Who is Kira Moss?", "options": ["A member of the grant team", "An artist who previously received a council grant", "The director of the Arts Council", "A guest lecturer from a university"], "answer": 1, "explanation": "'Kira Moss, successful grant recipient (mural installation, 2023)'", "difficulty": "medium"}, {"id": "xp7-d06b", "part": 7, "question": "How many people attended the information session?", "options": ["Over 30", "Over 45", "Over 60", "Over 75"], "answer": 2, "explanation": "'We were delighted to see over 60 people in attendance.'", "difficulty": "medium"}, {"id": "xp7-d06cd", "part": 7, "question": "In Document 2, the word \"subsequently\" is closest in meaning to", "options": ["as a result", "afterwards", "additionally", "unexpectedly"], "answer": 1, "explanation": "WIC in Document 2: \"subsequently made available\" = sau \u0111\u00f3 \u0111\u01b0\u1ee3c cung c\u1ea5p. \"Afterwards\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t v\u1ec1 m\u1eb7t th\u1eddi gian \u2014 x\u1ea3y ra sau s\u1ef1 ki\u1ec7n tr\u01b0\u1edbc."}, {"id": "xp7-d06x", "part": 7, "question": "Based on both documents, which of the following is mentioned in the follow-up email as a result of the information session?", "options": ["A new grant deadline has been announced", "The grants portal has been updated with the session recording", "One-on-one consultations are now available to attendees", "A second information session has been scheduled"], "answer": 2, "explanation": "Cross-document: Follow-up email confirms that one-on-one consultations (mentioned in the flyer as planned) are now available to session attendees \u2014 connecting the flyer's promise with the follow-up's confirmation."}, {"id": "xp7-d06e", "part": 7, "question": "What was NOT required to attend the information session?", "options": ["Refreshments", "A presentation by a grant recipient", "Registration", "Information on eligibility"], "answer": 2, "explanation": "'Free entry; no registration required.'", "difficulty": "medium"}]}, {"passage": "GRAND SUMMIT HOTEL\nLoyalty Programme \u2014 Member Benefits Guide\n\nTHANK YOU FOR BEING A GRAND SUMMIT ELITE MEMBER\n\nAs a Gold tier member, you are entitled to the following benefits on every qualifying stay:\n\n\u2022 15% discount on the best available room rate\n\u2022 Complimentary room upgrade, subject to availability at check-in\n\u2022 Late checkout until 2:00 p.m. (standard checkout is 12:00 noon)\n\u2022 Access to the Executive Lounge, including complimentary breakfast and evening cocktails\n\u2022 5 bonus points per AUD 1 spent on accommodation and dining\n\nPOINTS REDEMPTION\nPoints may be redeemed for free nights, dining credits, or spa treatments. A minimum of 5,000 points is required per redemption. Points expire 24 months after the last qualifying stay.\n\nTo check your point balance or make a redemption, log in to your account at grandsummithotels.com/loyalty or speak with any front desk team member.\n\nWe look forward to welcoming you at any of our 48 properties across Asia-Pacific.", "passageTitle": "Hotel Loyalty Programme", "type": "single", "questions": [{"id": "xp7-s20a", "part": 7, "question": "What is the standard checkout time at Grand Summit Hotel?", "options": ["11:00 a.m.", "12:00 noon", "1:00 p.m.", "2:00 p.m."], "answer": 1, "explanation": "'Standard checkout is 12:00 noon' \u2014 Gold members get extended checkout until 2:00 p.m.", "difficulty": "medium"}, {"id": "xp7-s20b", "part": 7, "question": "What is included with Executive Lounge access?", "options": ["Free airport transfers", "Complimentary breakfast and evening cocktails", "A dedicated personal assistant", "Complimentary laundry service"], "answer": 1, "explanation": "'Access to the Executive Lounge, including complimentary breakfast and evening cocktails.'", "difficulty": "medium"}, {"id": "xp7-s20c", "part": 7, "question": "What is the minimum number of points needed for a redemption?", "options": ["1,000", "2,500", "5,000", "10,000"], "answer": 2, "explanation": "'A minimum of 5,000 points is required per redemption.'", "difficulty": "medium"}, {"id": "p7-s-v15", "part": 7, "question": "What can be inferred about the Gold tier membership?", "options": ["It is the highest tier available in the programme", "It requires a minimum number of annual stays", "It is more exclusive than the Platinum tier", "It is the entry-level tier of the programme"], "answer": 1, "explanation": "Inference: Loyalty programme tiers typically require a minimum stays/nights threshold to achieve. The guide implies this through the benefits structure \u2014 Gold status must be earned through qualifying activity."}]}, {"passage": "POLICY ADVISORY\nLightspeed Digital \u2014 Remote Work Equipment Policy\nEffective: 1 August\n\nThis policy covers the allocation and use of company-provided equipment for employees working remotely.\n\nELIGIBILITY\nAll permanent employees who work remotely for two or more days per week are eligible to request company equipment.\n\nALLOCATION\nEach eligible employee may request one laptop, one external monitor, and a standard peripherals kit (keyboard, mouse, webcam). A second monitor may be requested with written approval from a department head.\n\nRESPONSIBILITY & CARE\nEmployees are responsible for the safe keeping of all allocated equipment. Any damage resulting from negligence will be charged to the employee at the cost of repair or replacement, as determined by IT.\n\nRETURN OF EQUIPMENT\nAll equipment must be returned to the IT department within five business days of resignation, termination, or permanent return to on-site work.\n\nCLAIMS\nTo submit an equipment request, complete the form on the IT portal at it.lightspeeddigital.com/equipment.", "passageTitle": "Policy Notice", "type": "single", "questions": [{"id": "xp7-s21a", "part": 7, "question": "Who qualifies for company-provided remote work equipment?", "options": ["All employees regardless of work arrangement", "Employees who work from home at least two days per week", "Only contract and freelance staff", "Senior managers and above"], "answer": 1, "explanation": "'All permanent employees who work remotely for two or more days per week are eligible.'", "difficulty": "medium"}, {"id": "xp7-s21b", "part": 7, "question": "What is required to obtain a second monitor?", "options": ["Approval from the IT department", "A formal written request to HR", "Written approval from a department head", "Justification submitted via the IT portal"], "answer": 2, "explanation": "'A second monitor may be requested with written approval from a department head.'", "difficulty": "medium"}, {"id": "xp7-s21c", "part": 7, "question": "What happens if an employee damages company equipment through negligence?", "options": ["The company covers the full cost of repair", "The employee is given a formal warning", "The employee is charged the cost of repair or replacement", "The equipment is not replaced"], "answer": 2, "explanation": "'Any damage resulting from negligence will be charged to the employee at the cost of repair or replacement.'", "difficulty": "medium"}, {"id": "p7-s-v42", "part": 7, "question": "In the policy, the word \"liable\" is closest in meaning to", "options": ["responsible", "required", "expected", "subject"], "answer": 0, "explanation": "WIC: \"liable for damages\" = ch\u1ecbu tr\u00e1ch nhi\u1ec7m ph\u00e1p l\u00fd v\u1ec1. \"Responsible\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh ch\u00ednh s\u00e1ch thi\u1ebft b\u1ecb c\u00f4ng ty."}]}, {"passage": "THE FOUNDERS' FORUM\nAnnual Business Pitch Competition\nCall for Applications \u2014 Cycle 7\n\nThe Founders' Forum invites early-stage startups to apply for our flagship pitch competition, offering the winner a seed investment of USD 150,000 and 12 months of mentorship from our expert panel.\n\nELIGIBILITY\n\u2022 Companies must have been operating for fewer than three years\n\u2022 Annual revenue must not exceed USD 500,000 at time of application\n\u2022 Companies must be headquartered in the Asia-Pacific region\n\nAPPLICATION PROCESS\n1. Online application form (submit at foundersforumasia.org/apply)\n2. Shortlisted teams invited to submit a 10-minute pitch video\n3. Top 20 finalists present live at the Founders' Forum Summit, November 4\u20135\n\nDEADLINE: September 30\n\nAll applications are reviewed by a panel of investors and industry experts. Decisions on shortlisting will be communicated by October 15.\n\nFor enquiries: applications@foundersforumasia.org", "passageTitle": "Business Competition", "type": "single", "questions": [{"id": "xp7-s22a", "part": 7, "question": "What does the winner receive?", "options": ["USD 150,000 and office space", "USD 150,000 and a 12-month mentorship program", "Access to a global investor network", "A place on the Founders' Forum advisory board"], "answer": 1, "explanation": "'The winner a seed investment of USD 150,000 and 12 months of mentorship.'", "difficulty": "medium"}, {"id": "xp7-s22b", "part": 7, "question": "What is a requirement for companies applying to the competition?", "options": ["They must be less than one year old", "They must be based in Asia-Pacific", "They must have at least two co-founders", "They must have received prior investment"], "answer": 1, "explanation": "'Companies must be headquartered in the Asia-Pacific region.'", "difficulty": "medium"}, {"id": "xp7-s22c", "part": 7, "question": "What happens after shortlisting?", "options": ["Teams attend the live summit immediately", "Shortlisted teams submit a 10-minute pitch video", "Teams are interviewed by the panel", "Finalists receive seed funding in advance"], "answer": 1, "explanation": "'Shortlisted teams invited to submit a 10-minute pitch video.'", "difficulty": "medium"}, {"id": "p7-s-v24", "part": 7, "question": "What can be inferred about the competition's target participants?", "options": ["Established companies with over five years of operation", "Early-stage startups seeking funding and mentorship", "Students in university entrepreneurship programmes", "Non-profit organisations seeking grant funding"], "answer": 1, "explanation": "Inference: \"Early-stage startups, apply for\" + competition format (pitch, funding) \u2192 competition targets startups needing funding and visibility, not established companies."}]}, {"passage": "CITYLINK METRO AUTHORITY\nService Update \u2014 Red Line Extension\n\nCityLink Metro Authority is pleased to announce that the Red Line Extension, connecting Central Station to Bayside Terminal, will officially open to passengers on Saturday, March 22.\n\nThe extension adds four new stations: Riverside, Expo Park, Marina West, and Bayside Terminal. Journey time from Central Station to Bayside Terminal is approximately 18 minutes.\n\nKEY INFORMATION FOR PASSENGERS:\n\u2022 Standard fares apply on the new extension; no additional surcharges\n\u2022 Peak hour services will run every 4 minutes; off-peak every 8 minutes\n\u2022 All new stations are fully accessible with lifts, tactile paths, and hearing loops\n\u2022 Cyclists may bring bikes onboard outside peak hours (before 7:30 a.m. and after 6:00 p.m.)\n\nCelebration events, including free travel on the extension from 10:00 a.m. to 2:00 p.m. on opening day, will be held at all four new stations.\n\nFor timetables and fare information: citylinktransit.gov", "passageTitle": "Transit Service Update", "type": "single", "questions": [{"id": "xp7-s23a", "part": 7, "question": "How many new stations does the extension add?", "options": ["Two", "Three", "Four", "Five"], "answer": 2, "explanation": "'The extension adds four new stations: Riverside, Expo Park, Marina West, and Bayside Terminal.'", "difficulty": "medium"}, {"id": "xp7-s23b", "part": 7, "question": "How often do trains run during off-peak hours?", "options": ["Every 2 minutes", "Every 4 minutes", "Every 8 minutes", "Every 12 minutes"], "answer": 2, "explanation": "'Off-peak every 8 minutes.'", "difficulty": "medium"}, {"id": "xp7-s23c", "part": 7, "question": "When can cyclists bring bikes on board?", "options": ["At any time of day", "Only on weekends", "Before 7:30 a.m. and after 6:00 p.m.", "During off-peak hours on weekdays only"], "answer": 2, "explanation": "'Cyclists may bring bikes onboard outside peak hours (before 7:30 a.m. and after 6:00 p.m.)'", "difficulty": "medium"}, {"id": "p7-s-v43", "part": 7, "question": "What can be inferred about the Red Line Extension's significance to the city?", "options": ["It is the largest infrastructure project in the city's history", "It will primarily benefit commuters travelling between suburbs", "It represents a meaningful improvement to the city's transit network", "It will eliminate the need for bus services on the same route"], "answer": 2, "explanation": "Inference: A new metro line extension connecting previously unserviced areas is significant for transit network improvement \u2014 inferred from the announcement's positive framing without overstating specific details."}]}, {"passage": "POSITION VACANT: WAREHOUSE SUPERVISOR\nEverest Freight Solutions | Christchurch, New Zealand\n\nEverest Freight Solutions is a leading third-party logistics provider operating across New Zealand and Australia. We are seeking an experienced Warehouse Supervisor to lead day-to-day operations at our Christchurch distribution facility.\n\nKEY DUTIES:\n\u2022 Supervise a team of 20 warehouse staff across inbound and outbound operations\n\u2022 Monitor and report on daily KPIs including pick accuracy, dispatch rates, and labour productivity\n\u2022 Conduct safety inspections and ensure compliance with Health & Safety regulations\n\u2022 Liaise with transport carriers regarding scheduling and exceptions\n\u2022 Train and mentor new team members\n\nREQUIREMENTS:\n\u2022 Minimum 3 years' experience in a warehouse supervisory role\n\u2022 Current forklift licence (counterbalance)\n\u2022 Strong working knowledge of WMS software\n\u2022 Excellent communication and team leadership skills\n\u2022 NZ Certificate in Logistics (Level 4) desirable but not required\n\nSalary: NZD 68,000\u201375,000 | Applications close: August 16\nApply: recruitment@everestfreight.co.nz", "passageTitle": "Job Posting", "type": "single", "questions": [{"id": "xp7-s24a", "part": 7, "question": "What is Everest Freight Solutions?", "options": ["A freight forwarding software company", "A third-party logistics provider", "A customs brokerage firm", "A government transport agency"], "answer": 1, "explanation": "'A leading third-party logistics provider operating across New Zealand and Australia.'", "difficulty": "medium"}, {"id": "xp7-s24b", "part": 7, "question": "What licence must candidates hold?", "options": ["A heavy vehicle driver licence", "A WMS software certification", "A forklift licence (counterbalance)", "A health and safety officer certification"], "answer": 2, "explanation": "'Current forklift licence (counterbalance)' is a stated requirement.", "difficulty": "medium"}, {"id": "xp7-s24c", "part": 7, "question": "What qualification is preferred but not required?", "options": ["Minimum 3 years supervisory experience", "NZ Certificate in Logistics Level 4", "Strong WMS knowledge", "Forklift licence"], "answer": 1, "explanation": "'NZ Certificate in Logistics (Level 4) desirable but not required.'", "difficulty": "medium"}, {"id": "p7-pur04", "part": 7, "question": "What is the purpose of this job posting?", "options": ["To announce the promotion of an internal candidate", "To recruit a qualified candidate for a warehouse management role", "To inform existing staff of changes to warehouse operations", "To advertise a new training programme for logistics professionals"], "answer": 1, "explanation": "Purpose: th\u00f4ng b\u00e1o tuy\u1ec3n d\u1ee5ng ch\u1ee9c v\u1ee5 Warehouse Supervisor t\u1ea1i Everest Freight Solutions \u2014 m\u1ee5c \u0111\u00edch r\u00f5 r\u00e0ng l\u00e0 thu h\u00fat \u1ee9ng vi\u00ean ph\u00f9 h\u1ee3p."}]}, {"passage": "NOTICE OF ANNUAL GENERAL MEETING\nRidgemont Community Cooperative\n\nThe Board of Directors of Ridgemont Community Cooperative hereby gives notice that the Annual General Meeting (AGM) will be held on:\n\nDate: Wednesday, October 29\nTime: 6:30 p.m.\nVenue: Ridgemont Town Hall, Main Chamber, 45 Civic Drive\n\nAGENDA:\n1. Welcome and attendance confirmation\n2. Approval of minutes from the previous AGM\n3. Financial report for the year ended June 30\n4. Election of two Board positions\n5. Proposed amendment to the Cooperative's membership fee structure\n6. General business\n\nAll financial members are entitled to vote. Proxy voting forms must be submitted to the Secretary at secretary@ridgemontcoop.org no later than October 22.\n\nRefreshments will be served following the conclusion of the meeting.\n\nFor a copy of the annual report or to submit an agenda item, contact the Secretary at the above email address.", "passageTitle": "Notice: Annual General Meeting", "type": "single", "questions": [{"id": "xp7-s25a", "part": 7, "question": "What is the main purpose of this notice?", "options": ["To present the annual financial results", "To call members to an Annual General Meeting", "To announce new Board appointments", "To propose changes to the Cooperative's services"], "answer": 1, "explanation": "This is a formal 'Notice of Annual General Meeting' calling members to attend.", "difficulty": "medium"}, {"id": "xp7-s25b", "part": 7, "question": "What is on the agenda related to membership?", "options": ["Election of five board positions", "Reviewing the membership benefits", "A proposed change to the membership fee structure", "A vote on new membership eligibility rules"], "answer": 2, "explanation": "'Proposed amendment to the Cooperative's membership fee structure' is agenda item 5.", "difficulty": "medium"}, {"id": "xp7-s25c", "part": 7, "question": "By when must proxy voting forms be submitted?", "options": ["October 22", "October 27", "October 29", "October 30"], "answer": 0, "explanation": "'Proxy voting forms must be submitted... no later than October 22.'", "difficulty": "medium"}, {"id": "p7-s-v47", "part": 7, "question": "Which of the following is NOT mentioned as an agenda item for the AGM?", "options": ["Election of new board members", "Amendment to membership fees", "Review of the annual financial report", "A vote on a proposed merger"], "answer": 3, "explanation": "NOT TRUE: AGM agenda items typically include elections, fee changes, and financial review. A vote on a proposed merger would be unusual for a community cooperative AGM and is NOT listed in the notice."}]}, {"passage": "STAFF RECOGNITION PROGRAMME\nQuarterly Awards \u2014 Q2 Winners Announced\n\nDear Colleagues,\n\nWe are delighted to announce the winners of this quarter's Staff Recognition Awards. These awards celebrate individuals and teams who have gone above and beyond to uphold our values of excellence, collaboration, and community.\n\nINDIVIDUAL AWARD: Marcus Lee, IT Department\nMarcus was nominated by three separate departments for his exceptional response to the network outage in May. His swift diagnosis and overnight repair prevented an estimated two days of lost productivity across the entire organisation.\n\nTEAM AWARD: Customer Onboarding Team\nThe Customer Onboarding Team set a new record this quarter, reducing average onboarding time from 12 days to 7 days while maintaining a 96% customer satisfaction score.\n\nSPECIAL RECOGNITION: Amara Osei, Volunteer Coordinator\nAmara coordinated the company's participation in the Regional Food Drive, organising 45 staff volunteers and collecting over 1,200 food items for local shelters.\n\nEach winner will receive a certificate, a personalised trophy, and a gift voucher. Nominations for Q3 open on July 1.\n\nCongratulations to all winners!", "passageTitle": "Staff Recognition Programme", "type": "single", "questions": [{"id": "xp7-s26a", "part": 7, "question": "Why did Marcus Lee win the Individual Award?", "options": ["He led the launch of a new IT system", "He resolved a network outage overnight and prevented lost productivity", "He trained a new team of IT technicians", "He reduced IT costs by 30% in Q2"], "answer": 1, "explanation": "'His swift diagnosis and overnight repair prevented an estimated two days of lost productivity.'", "difficulty": "medium"}, {"id": "xp7-s26b", "part": 7, "question": "What achievement did the Customer Onboarding Team accomplish?", "options": ["They improved customer satisfaction to 100%", "They reduced onboarding time from 12 to 7 days", "They onboarded 96 new customers this quarter", "They cut onboarding costs by 12%"], "answer": 1, "explanation": "'Reducing average onboarding time from 12 days to 7 days while maintaining a 96% customer satisfaction score.'", "difficulty": "medium"}, {"id": "xp7-s26c", "part": 7, "question": "What did Amara Osei's special recognition involve?", "options": ["Designing a new staff wellness programme", "Organising a community food drive with 45 staff volunteers", "Leading the company's sustainability initiative", "Coordinating a fundraising gala for local charities"], "answer": 1, "explanation": "'Organising 45 staff volunteers and collecting over 1,200 food items for local shelters.'", "difficulty": "medium"}, {"id": "p7-s-v44", "part": 7, "question": "What can be inferred about the purpose of the Q3 Award Programme?", "options": ["It is a new initiative introduced this quarter for the first time", "It is part of an ongoing company effort to recognise employee contributions", "It was introduced to address low staff morale", "It is limited to employees who have been with the company for over one year"], "answer": 1, "explanation": "Inference: \"Quarterly Awards\" and announcing Q3 winners implies this is a recurring programme \u2014 part of an ongoing HR strategy to recognise performance, not a one-time event."}]}, {"passage": "RIDGEFIELD DENTAL PRACTICE\nPatient Information \u2014 Post-Extraction Care Guide\n\nThank you for attending Ridgefield Dental Practice. Please follow these instructions carefully after your tooth extraction to support healing and avoid complications.\n\nFIRST 24 HOURS\n\u2022 Bite firmly on the gauze pad for at least 45 minutes. Replace if saturated.\n\u2022 Avoid rinsing, spitting, or using a straw. These actions can dislodge the blood clot and cause dry socket.\n\u2022 Apply an ice pack (20 minutes on, 20 minutes off) to reduce swelling.\n\u2022 Take prescribed pain relief as directed.\n\nFOLLOWING DAYS\n\u2022 Rinse gently with warm salt water from 24 hours onwards (half a teaspoon of salt in a glass of warm water).\n\u2022 Avoid smoking for at least 72 hours, as this significantly increases the risk of dry socket.\n\u2022 Eat soft foods and avoid the extraction site for 48 hours.\n\nWHEN TO SEEK URGENT CARE\nContact us immediately if you experience severe or worsening pain after 48 hours, heavy bleeding that does not slow with pressure, or signs of infection such as fever or swelling that worsens after 3 days.\n\nFor non-urgent queries: (03) 9901 4422 | ridgefielddentalcare.com.au", "passageTitle": "Healthcare Notice", "type": "single", "questions": [{"id": "xp7-s27a", "part": 7, "question": "Why should patients avoid using a straw in the first 24 hours?", "options": ["It can cause pain at the extraction site", "It may loosen the gauze pad", "It can dislodge the blood clot and cause dry socket", "It increases swelling"], "answer": 2, "explanation": "'These actions can dislodge the blood clot and cause dry socket.'", "difficulty": "medium"}, {"id": "xp7-s27b", "part": 7, "question": "When can patients begin salt water rinsing?", "options": ["Immediately after the extraction", "After 12 hours", "After 24 hours", "After 48 hours"], "answer": 2, "explanation": "'Rinse gently with warm salt water from 24 hours onwards.'", "difficulty": "medium"}, {"id": "xp7-s27c", "part": 7, "question": "For how long should patients avoid smoking?", "options": ["For 24 hours", "For at least 48 hours", "For at least 72 hours", "For one week"], "answer": 2, "explanation": "'Avoid smoking for at least 72 hours.'", "difficulty": "medium"}, {"id": "p7-s-v48", "part": 7, "question": "In the care guide, the word \"persistent\" is closest in meaning to", "options": ["continuing", "severe", "recurring", "sudden"], "answer": 0, "explanation": "WIC: \"persistent pain/bleeding\" = dai d\u1eb3ng, kh\u00f4ng ng\u1eebng. \"Continuing\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh h\u01b0\u1edbng d\u1eabn y t\u1ebf theo d\u00f5i sau ph\u1eabu thu\u1eadt."}]}, {"passage": "GREENVALE FARMERS' MARKET\nVendor Information Sheet \u2014 2024 Season\n\nWelcome back to the Greenvale Farmers' Market! We are looking forward to another wonderful season from April 6 through October 26.\n\nMARKET DETAILS\n\u2022 Held every Sunday, 7:00 a.m. \u2013 1:00 p.m.\n\u2022 Location: Greenvale Civic Park, 12 Market Lane\n\u2022 Vendor setup begins at 6:00 a.m.; all stalls must be ready by 6:45 a.m.\n\nFEE STRUCTURE\n\u2022 Standard stall (3m x 3m): AUD 45 per week\n\u2022 Large stall (3m x 6m): AUD 80 per week\n\u2022 Electricity connection: AUD 15 per week (must be booked in advance)\n\nRULES & GUIDELINES\n\u2022 Only produce grown, made, or raised by the vendor may be sold. Resale of commercially purchased goods is strictly prohibited.\n\u2022 All food vendors must hold a current food handler's certificate.\n\u2022 Vendors are responsible for leaving their site clean at the end of each market day.\n\nBookings for the season must be completed by March 20. Contact: vendors@greenvalefarmersmarket.com.au", "passageTitle": "Promotional Event", "type": "single", "questions": [{"id": "xp7-s28a", "part": 7, "question": "What time must all stalls be ready by?", "options": ["6:00 a.m.", "6:30 a.m.", "6:45 a.m.", "7:00 a.m."], "answer": 2, "explanation": "'All stalls must be ready by 6:45 a.m.'", "difficulty": "medium"}, {"id": "xp7-s28b", "part": 7, "question": "What is strictly prohibited at the market?", "options": ["Selling homemade goods", "Using electricity connections", "Resale of commercially purchased goods", "Operating a food stall without a licence"], "answer": 2, "explanation": "'Resale of commercially purchased goods is strictly prohibited.'", "difficulty": "medium"}, {"id": "xp7-s28c", "part": 7, "question": "What must food vendors hold?", "options": ["A business licence", "A food handler's certificate", "A stall reservation for the full season", "Public liability insurance"], "answer": 1, "explanation": "'All food vendors must hold a current food handler's certificate.'", "difficulty": "medium"}, {"id": "p7-s-v16", "part": 7, "question": "Which of the following is NOT mentioned as part of the promotional event?", "options": ["Discounted prices on products", "Free gift with purchase", "Extended opening hours", "A loyalty points bonus"], "answer": 3, "explanation": "NOT TRUE: Review promotional event details. A loyalty points bonus is typically NOT mentioned in seasonal sale announcements \u2014 check whether it is explicitly listed."}]}, {"passage": "CONFERENCE PROGRAMME\nAsia-Pacific Sustainability Summit\nDay 2 \u2014 Thursday, September 18\n\n08:30  Registration & morning coffee \u2014 Foyer, Level 1\n09:00  Opening keynote: Dr. Lena Marchetti, UN Environment Programme\n         \"Closing the Implementation Gap: From Pledge to Practice\"\n10:00  Panel: Corporate Net Zero Commitments \u2014 Are They Enough?\n         Panelists: CEOs from Vantex Industries, GreenPath Capital, and Solara Energy\n11:00  Networking break \u2014 Atrium\n11:30  Concurrent sessions (delegates choose one):\n         A. Supply chain decarbonisation strategies (Room 3A)\n         B. Green finance and ESG investment trends (Room 3B)\n         C. Biodiversity and nature-based solutions (Room 4A)\n13:00  Lunch \u2014 Grand Ballroom\n14:00  Workshop: Measuring and Reporting Scope 3 Emissions\n         Facilitator: Ms. Helen Park, Carbon Analytics Group\n15:30  Afternoon tea \u2014 Atrium\n16:00  Closing plenary: Roadmap to 2030\n17:30  End of Day 2 | Networking cocktail reception to follow", "passageTitle": "Conference Programme", "type": "single", "questions": [{"id": "xp7-s29a", "part": 7, "question": "Who delivers the opening keynote on Day 2?", "options": ["Helen Park from Carbon Analytics Group", "Lena Marchetti from the UN Environment Programme", "A CEO from Vantex Industries", "A delegate from GreenPath Capital"], "answer": 1, "explanation": "'Opening keynote: Dr. Lena Marchetti, UN Environment Programme.'", "difficulty": "medium"}, {"id": "xp7-s29b", "part": 7, "question": "What can delegates choose during the 11:30 a.m. slot?", "options": ["Three different panel discussions", "Two guided tours of the exhibition", "One of three concurrent sessions", "A workshop on Scope 3 emissions"], "answer": 2, "explanation": "'Concurrent sessions (delegates choose one)' with three options listed.", "difficulty": "medium"}, {"id": "xp7-s29c", "part": 7, "question": "Who facilitates the afternoon workshop?", "options": ["Dr. Lena Marchetti", "Helen Park from Carbon Analytics Group", "A CEO from Solara Energy", "The conference chair"], "answer": 1, "explanation": "'Facilitator: Ms. Helen Park, Carbon Analytics Group.'", "difficulty": "medium"}, {"id": "p7-s-v22", "part": 7, "question": "In the programme, the word \"renowned\" is closest in meaning to", "options": ["well-known", "qualified", "experienced", "respected"], "answer": 0, "explanation": "WIC: \"renowned\" = n\u1ed5i ti\u1ebfng, \u0111\u01b0\u1ee3c c\u00f4ng nh\u1eadn r\u1ed9ng r\u00e3i. \"Well-known\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh gi\u1edbi thi\u1ec7u di\u1ec5n gi\u1ea3 h\u1ed9i ngh\u1ecb."}]}, {"passage": "VENDOR COMPLAINT RESOLUTION POLICY\nHarbour Square Retail Management\n\nThis policy sets out the process for resolving complaints lodged by tenants of Harbour Square against building management or other tenants.\n\nSTEP 1 \u2014 INFORMAL RESOLUTION\nTenants are encouraged to raise concerns directly with the relevant party. Where a resolution cannot be reached informally, tenants may proceed to Step 2.\n\nSTEP 2 \u2014 FORMAL COMPLAINT\nA formal complaint form must be submitted in writing to the Tenant Services Manager within 30 days of the incident. Anonymous complaints will not be investigated.\n\nSTEP 3 \u2014 INVESTIGATION\nThe Tenant Services Manager will acknowledge receipt within 2 business days and complete the investigation within 15 business days. Both parties will be notified of the outcome.\n\nSTEP 4 \u2014 ESCALATION\nIf the complainant is unsatisfied with the outcome, they may request a review by the General Manager within 10 business days of receiving the Step 3 decision. The General Manager's decision is final.\n\nFor complaint forms and contact details: tenantservices@harboursquare.com.au", "passageTitle": "Vendor Policy", "type": "single", "questions": [{"id": "xp7-s30a", "part": 7, "question": "What must a formal complaint include?", "options": ["A witness statement from a third party", "A written submission to the Tenant Services Manager", "A copy of the lease agreement", "A financial estimate of the loss incurred"], "answer": 1, "explanation": "'A formal complaint form must be submitted in writing to the Tenant Services Manager.'", "difficulty": "medium"}, {"id": "xp7-s30b", "part": 7, "question": "Within what timeframe must a formal complaint be submitted?", "options": ["Within 7 business days", "Within 14 days", "Within 30 days", "Within 60 days"], "answer": 2, "explanation": "'Within 30 days of the incident.'", "difficulty": "medium"}, {"id": "xp7-s30c", "part": 7, "question": "How long does the investigation stage take?", "options": ["2 business days", "5 business days", "15 business days", "30 business days"], "answer": 2, "explanation": "'Complete the investigation within 15 business days.'", "difficulty": "medium"}, {"id": "p7-s-v23", "part": 7, "question": "Which of the following is NOT required under the vendor complaint resolution policy?", "options": ["Submitting a complaint in writing", "Attending a mediation session", "Providing supporting documentation", "Following the specified escalation process"], "answer": 1, "explanation": "NOT TRUE: Vendor complaint policies typically require written submission, documentation, and process adherence. Mandatory mediation is typically NOT a first-step requirement \u2014 it may be optional."}]}, {"passage": "SUNRIDGE GARDEN CENTRE\nSpring Sale Event \u2014 This Weekend Only!\n\nSunridge Garden Centre is excited to announce our biggest spring sale of the year, running this Saturday and Sunday from 8:00 a.m. to 5:00 p.m.\n\nHIGHLIGHTS:\n\u2022 Up to 40% off all native plants and seedlings\n\u2022 25% off all garden tools and equipment\n\u2022 Buy 2, get 1 free on all potting mix and mulch bags\n\u2022 Free expert advice sessions with our horticulturalists, running every hour from 9:00 a.m.\n\nThis sale is in-store only and cannot be combined with any other offer or loyalty discount. Gift cards are accepted but cannot be used to purchase sale items at a further reduced price.\n\nSunridge Garden Centre is located at 14 Bloomfield Road, Sunridge Hills. Free parking is available on site.\n\nCall ahead to confirm stock availability on specific items: (02) 9445 6700\n\nSee you in the garden!", "passageTitle": "Promotional Event", "type": "single", "questions": [{"id": "xp7-s31a", "part": 7, "question": "What discount applies to garden tools and equipment?", "options": ["Up to 40% off", "25% off", "Buy 2 get 1 free", "10% off"], "answer": 1, "explanation": "'25% off all garden tools and equipment.'", "difficulty": "medium"}, {"id": "xp7-s31b", "part": 7, "question": "How often do the expert advice sessions run?", "options": ["Every 30 minutes", "Every hour from 9:00 a.m.", "Once in the morning and once in the afternoon", "By appointment only"], "answer": 1, "explanation": "'Free expert advice sessions with our horticulturalists, running every hour from 9:00 a.m.'", "difficulty": "medium"}, {"id": "xp7-s31c", "part": 7, "question": "Can customers use their loyalty discount during the sale?", "options": ["Yes, discounts can be combined", "Yes, but only on full-price items", "No, the sale cannot be combined with other offers", "Only if spending over AUD 100"], "answer": 2, "explanation": "'This sale is in-store only and cannot be combined with any other offer or loyalty discount.'", "difficulty": "medium"}, {"id": "p7-s-v50", "part": 7, "question": "Which of the following is NOT mentioned as part of the spring sale event?", "options": ["Discounts on garden tools", "Free plant giveaways for early arrivals", "Expert advice sessions", "Extended weekend opening hours"], "answer": 1, "explanation": "NOT TRUE: Review the listed activities and promotions. Free plant giveaways are NOT among the explicitly mentioned promotional offers in the spring sale announcement."}]}, {"passage": "REGIONAL BUSINESS GAZETTE\nNew Regulation: Mandatory Packaging Disclosure for Food Businesses\n\nStarting 1 November, all food and beverage businesses in the region with annual revenues exceeding AUD 2 million will be required to clearly label packaging with the percentage of recycled material used and the estimated carbon footprint per unit.\n\nThe requirement, introduced under the Environmental Transparency Act, has been welcomed by consumer advocacy groups as a major step toward empowering shoppers with better purchasing information.\n\nBusinesses will have access to a government-funded tool, the Packaging Emissions Calculator (PEC), to assist with accurate reporting. Registration for the PEC portal opens September 1 at environment.gov.au/pec.\n\nNon-compliance after a six-month grace period will result in fines of up to AUD 50,000 per product line. Smaller businesses below the AUD 2 million threshold are encouraged to voluntarily adopt the labelling standard, with a simplified version of the PEC available at no cost.\n\nFor inquiries: packagingreg@environment.gov.au", "passageTitle": "Regulatory Notice", "type": "single", "questions": [{"id": "xp7-s32a", "part": 7, "question": "Which businesses must comply with the new labelling requirement?", "options": ["All food businesses regardless of size", "Food businesses with annual revenues over AUD 2 million", "Businesses that use plastic packaging only", "All businesses registered in the region"], "answer": 1, "explanation": "'All food and beverage businesses in the region with annual revenues exceeding AUD 2 million.'", "difficulty": "medium"}, {"id": "xp7-s32b", "part": 7, "question": "What information must businesses include on packaging?", "options": ["Nutritional content and allergen information", "Carbon footprint per unit and percentage of recycled material", "Country of origin and manufacturing date", "Expiry date and storage instructions"], "answer": 1, "explanation": "'The percentage of recycled material used and the estimated carbon footprint per unit.'", "difficulty": "medium"}, {"id": "xp7-s32c", "part": 7, "question": "What is the Packaging Emissions Calculator (PEC)?", "options": ["A fines assessment tool used by regulators", "A government-funded tool to assist with accurate reporting", "A third-party auditing service", "An app for consumers to check product sustainability"], "answer": 1, "explanation": "'A government-funded tool...to assist with accurate reporting.'", "difficulty": "medium"}, {"id": "p7-s-v45", "part": 7, "question": "In the notice, the word \"comply\" is closest in meaning to", "options": ["follow", "register", "apply", "report"], "answer": 0, "explanation": "WIC: \"comply with the new labelling requirements\" = tu\u00e2n th\u1ee7 c\u00e1c y\u00eau c\u1ea7u nh\u00e3n m\u00e1c m\u1edbi. \"Follow\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh quy \u0111\u1ecbnh ph\u00e1p l\u00fd."}]}, {"passage": "HAWTHORNE ACADEMY\nGraduate Programme \u2014 Expression of Interest\n\nHawthorne Academy invites applications from recent graduates for its highly competitive two-year Graduate Programme, commencing February next year.\n\nThe programme offers rotations across four core business units \u2014 Finance, Strategy, Operations, and Client Services \u2014 providing participants with broad exposure to the firm's functions and senior leadership.\n\nPROGRAMME HIGHLIGHTS:\n\u2022 Structured rotations every six months\n\u2022 Dedicated mentor from the senior leadership team\n\u2022 Three formal training blocks per year (including one international module in Singapore)\n\u2022 Competitive salary of AUD 72,000 in Year 1, increasing to AUD 80,000 in Year 2\n\u2022 Permanent placement consideration upon successful completion\n\nELIGIBILITY:\nApplicants must have completed an undergraduate or postgraduate degree within the last two years and achieved a minimum GPA of 3.0 (or equivalent).\n\nApplications open August 1 and close September 15.\nApply at hawthorneacademy.com.au/graduates", "passageTitle": "Graduate Programme", "type": "single", "questions": [{"id": "xp7-s33a", "part": 7, "question": "How often do programme rotations occur?", "options": ["Every three months", "Every six months", "Every year", "At the end of the two-year programme"], "answer": 1, "explanation": "'Structured rotations every six months.'", "difficulty": "medium"}, {"id": "xp7-s33b", "part": 7, "question": "Where does the international training module take place?", "options": ["Tokyo", "Hong Kong", "Singapore", "Sydney"], "answer": 2, "explanation": "'One international module in Singapore.'", "difficulty": "medium"}, {"id": "xp7-s33c", "part": 7, "question": "What is the Year 2 salary?", "options": ["AUD 68,000", "AUD 72,000", "AUD 76,000", "AUD 80,000"], "answer": 3, "explanation": "'Increasing to AUD 80,000 in Year 2.'", "difficulty": "medium"}, {"id": "p7-s-v17", "part": 7, "question": "In the programme description, the phrase \"highly competitive\" suggests that", "options": ["many applicants apply for a limited number of places", "the programme challenges participants with difficult content", "participants will compete against each other throughout", "the programme is the best of its kind in the country"], "answer": 0, "explanation": "Inference: \"Highly competitive programme\" = nhi\u1ec1u \u1ee9ng vi\u00ean c\u1ea1nh tranh cho \u00edt su\u1ea5t. This is the standard meaning of \"competitive\" when describing admissions."}]}, {"passage": "INTERNAL COMMUNICATIONS\nTo: All Staff\nFrom: Sustainability Committee\nDate: April 7\nSubject: Launch of Workplace Sustainability Initiative \u2014 GreenWorks\n\nWe are excited to announce the launch of GreenWorks, a new company-wide sustainability initiative aimed at reducing our environmental footprint through everyday workplace actions.\n\nGreenWorks will kick off on April 21 with an all-staff awareness event in the main atrium from 12:00 to 1:30 p.m. Activities will include a 'Switch-Off Challenge' across all floors, a composting station demonstration, and information stalls from three local sustainability organisations.\n\nFollowing the launch, each department will be asked to nominate a Green Champion \u2014 a staff member who will help track and promote sustainable practices within their team. Green Champions will receive training and a small resource kit to support their role.\n\nA full GreenWorks action plan, outlining our six-month targets and how departments can contribute, will be shared via the company intranet on April 14.\n\nWe look forward to your participation in making GreenWorks a success.\n\nSustainability Committee", "passageTitle": "Email: Launch of Workplace Sustainability Initiative", "type": "single", "questions": [{"id": "xp7-s34a", "part": 7, "question": "What is GreenWorks?", "options": ["A new recycling vendor hired by the company", "A company-wide sustainability initiative", "An employee wellness programme", "A government grant for sustainable businesses"], "answer": 1, "explanation": "'A new company-wide sustainability initiative aimed at reducing our environmental footprint.'", "difficulty": "medium"}, {"id": "xp7-s34b", "part": 7, "question": "What will happen at the April 21 launch event?", "options": ["A keynote by an environmental expert", "Departmental green audits", "A Switch-Off Challenge and composting demonstration", "A sustainability awards ceremony"], "answer": 2, "explanation": "'A Switch-Off Challenge across all floors, a composting station demonstration, and information stalls.'", "difficulty": "medium"}, {"id": "xp7-s34c", "part": 7, "question": "What is the role of a Green Champion?", "options": ["To lead the Sustainability Committee", "To track and promote sustainable practices within their team", "To manage the company's carbon offset programme", "To represent the company at external sustainability events"], "answer": 1, "explanation": "'A staff member who will help track and promote sustainable practices within their team.'", "difficulty": "medium"}, {"id": "p7-s-v46", "part": 7, "question": "What can be inferred about the role of Green Champions in the initiative?", "options": ["They will replace existing sustainability staff", "They will serve as representatives and advocates within their teams", "They will be responsible for all sustainability reporting", "They must complete a formal training course before participating"], "answer": 1, "explanation": "Inference: \"Green Champion\" = ng\u01b0\u1eddi \u0111\u1ea1i di\u1ec7n t\u1ea1i b\u1ed9 ph\u1eadn \u2014 standard role in corporate sustainability programmes, acting as local advocates rather than replacing existing staff."}]}, {"passage": "[Document 1 \u2013 Service Notification]\n\nFrom: Clearwave Internet <service@clearwave.net.au>\nTo: Account Holders\nDate: March 14\nSubject: Planned Network Upgrade \u2014 Action Required\n\nDear Customer,\n\nWe will be upgrading the fibre infrastructure in your area between March 25 and March 28. During this period, your internet service may experience brief interruptions of up to 30 minutes while the work is carried out.\n\nIn most cases, your connection will automatically restore after the upgrade. However, some customers may need to restart their modem after service resumes. If your connection has not returned within one hour of the scheduled work completing, please restart your modem before contacting our support line.\n\nScheduled upgrade window for your area: March 27, 10:00 p.m. \u2013 2:00 a.m.\n\nWe apologize for any inconvenience. Customers who experience more than four hours of unplanned downtime may be eligible for a service credit under our Service Level Guarantee. Full details are available at clearwave.net.au/slg.\n\nClearwave Technical Team\n\n[Document 2 \u2013 Customer Email]\n\nFrom: Patricia Yuen <p.yuen@email.com>\nTo: support@clearwave.net.au\nDate: March 28\n\nHello,\n\nI received your notification about the upgrade on March 27. My internet was down from 10:00 p.m. until approximately 7:00 a.m. this morning \u2014 that is about nine hours of downtime. I work from home and this caused significant disruption to my schedule.\n\nI restarted my modem at around 3:00 a.m. as instructed, but this did not help. My connection only came back at 7:00 a.m.\n\nI would like to understand whether I am eligible for a service credit given the length of the outage. Could you please clarify the process?\n\nThank you,\nPatricia Yuen", "passageTitle": "Service Notification + Customer Complaint Email", "type": "double", "questions": [{"id": "xp7-d07a", "part": 7, "question": "What should customers do if their connection does not return within one hour?", "options": ["Call Clearwave support immediately", "Restart their modem before calling support", "Wait for an automated reconnection", "Submit a service credit application online"], "answer": 1, "explanation": "'Please restart your modem before contacting our support line.'", "difficulty": "medium"}, {"id": "xp7-d07v", "part": 7, "question": "What does Patricia Yuen's email suggest about her experience compared to what was promised in the notification?", "options": ["Her experience was better than the notification indicated", "The disruption lasted longer than the notification's maximum estimate", "The notification was accurate in predicting the outage duration", "She was notified about the outage in advance"], "answer": 1, "explanation": "Cross-inference: Notification stated maximum downtime. Patricia's email reports her actual downtime was longer \u2014 combining both documents reveals her experience exceeded the estimated maximum."}, {"id": "xp7-d07c", "part": 7, "question": "Is Patricia Yuen likely eligible for a service credit?", "options": ["No, because she did not restart her modem immediately", "No, because planned upgrades are excluded", "Yes, because her downtime exceeded four hours", "It cannot be determined from the information provided"], "answer": 2, "explanation": "'Customers who experience more than four hours of unplanned downtime may be eligible.' Her 9-hour outage exceeds this threshold.", "difficulty": "medium"}, {"id": "xp7-d07d", "part": 7, "question": "What did Patricia Yuen do at around 3:00 a.m.?", "options": ["Called Clearwave support", "Submitted an online service credit request", "Restarted her modem as instructed", "Switched to a mobile data connection"], "answer": 2, "explanation": "'I restarted my modem at around 3:00 a.m. as instructed, but this did not help.'", "difficulty": "medium"}, {"id": "xp7-d07e", "part": 7, "question": "In Document 1, the word \"eligible\" is closest in meaning to", "options": ["required", "qualified", "scheduled", "guaranteed"], "answer": 1, "explanation": "Word-in-context: \"may be eligible for a service credit\" \u2014 \"eligible\" = \u0111\u1ee7 \u0111i\u1ec1u ki\u1ec7n, c\u00f3 quy\u1ec1n nh\u1eadn. \"Qualified\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh \u0111i\u1ec1u kho\u1ea3n d\u1ecbch v\u1ee5."}]}, {"passage": "[Document 1 \u2013 Company Policy Extract]\n\nTRAVEL & EXPENSES POLICY \u2014 SECTION 4: ACCOMMODATION\nPinnacle Advisory Services\n\n4.1 Standard Hotel Allowance\nEmployees traveling domestically are entitled to a hotel allowance of USD 160 per night. For travel to Tier 1 cities (New York, San Francisco, London, Tokyo, Sydney), the allowance is USD 220 per night. Any accommodation costs above the applicable limit must be pre-approved by the employee's department head and CFO.\n\n4.2 Booking Requirements\nAll accommodation must be booked through the company's approved travel portal, Tripwise, unless the portal is unavailable, in which case the employee may book directly and submit receipts for reimbursement.\n\n4.3 Early Check-in / Late Checkout\nEarly check-in and late checkout fees are reimbursable only if the additional time is required for business purposes and pre-approved.\n\n[Document 2 \u2013 Expense Claim Email]\n\nFrom: Benjamin Hart <b.hart@pinnacleadvisory.com>\nTo: finance@pinnacleadvisory.com\nDate: June 6\n\nHi Finance Team,\n\nPlease find attached my expense claim for my trip to San Francisco (June 1\u20134).\n\nI would like to flag two items for your attention:\n\nFirst, my hotel rate was USD 245 per night for three nights, which is USD 25 above the Tier 1 limit. I received verbal approval from my department head, Maria Santos, but did not have time to obtain written CFO approval before the trip. I hope this can be resolved retrospectively.\n\nSecond, I paid a USD 40 late checkout fee on June 4 to allow time for a client call that ran until 2:00 p.m. The client meeting details are in the attached calendar extract.\n\nPlease let me know how to proceed.\n\nBenjamin Hart", "passageTitle": "Company Policy + Expense Claim Email", "type": "double", "questions": [{"id": "xp7-d08a", "part": 7, "question": "What is the hotel allowance for travel to San Francisco?", "options": ["USD 160 per night", "USD 200 per night", "USD 220 per night", "USD 245 per night"], "answer": 2, "explanation": "San Francisco is a Tier 1 city \u2014 'the allowance is USD 220 per night.'", "difficulty": "medium"}, {"id": "xp7-d08v", "part": 7, "question": "What is most likely the purpose of Benjamin Hart's email?", "options": ["To report a colleague's policy violation", "To seek reimbursement for expenses he believes are justified", "To request an amendment to the travel policy", "To confirm that his expenses comply with policy"], "answer": 1, "explanation": "Purpose: Benjamin's email details specific expenses and explains why they should be reimbursed despite exceeding limits \u2014 his clear purpose is to justify and request reimbursement."}, {"id": "xp7-d08cd", "part": 7, "question": "Based on both documents, what does Benjamin Hart need to do to ensure full reimbursement of his hotel costs?", "options": ["Provide receipts for all accommodation expenses only", "Submit pre-approval documentation and receipts for the rate exceeding the cap", "Contact the finance department to request a policy exception", "Reduce his claim to the standard nightly cap and submit immediately"], "answer": 1, "explanation": "Cross-document: Policy requires pre-approval for expenses exceeding the cap + receipt submission. Benjamin's email indicates he exceeded the cap \u2014 combining both, pre-approval docs + receipts are needed for full reimbursement."}, {"id": "xp7-d08d", "part": 7, "question": "Why is the late checkout fee potentially reimbursable?", "options": ["Late checkout is always covered by policy", "The client call required him to stay at the hotel past standard checkout", "He had a medical appointment that afternoon", "He was waiting for a delayed flight"], "answer": 1, "explanation": "'I paid a USD 40 late checkout fee... to allow time for a client call that ran until 2:00 p.m.' This satisfies the 'business purposes' requirement in 4.3.", "difficulty": "medium"}, {"id": "xp7-d08x", "part": 7, "question": "Based on both documents, which of Benjamin Hart's claims is most clearly supported by the policy?", "options": ["The hotel rate exceeding the nightly cap", "The late checkout fee", "The full accommodation total", "Pre-approval was obtained for all expenses"], "answer": 1, "explanation": "Cross-document: Policy allows exceptions for client-directed late checkout. Benjamin's email explicitly states the checkout was at client's request \u2014 matching the policy's exception clause precisely."}]}, {"passage": "[Document 1 \u2013 Event Flyer]\n\nLITERALLY SPEAKING \u2014 AUTHOR TALK SERIES\nSilvergate City Library | Free Community Event\n\nJoin us for an exclusive evening with celebrated novelist and journalist MARCUS OKAFOR, author of the Booker Prize-shortlisted novel The Weight of Silence.\n\nDate:   Thursday, August 14\nTime:   7:00 p.m. (doors open 6:30 p.m.)\nVenue:  Silvergate City Library, Level 2 Reading Room\n\nMarcus Okafor will discuss the inspiration behind The Weight of Silence, the challenges of writing across genres, and his upcoming non-fiction work on investigative journalism in post-conflict societies.\n\nA book signing will follow the talk. Copies of The Weight of Silence will be available for purchase at the venue.\n\nSpaces are limited to 80 attendees. RSVP via the library website or call (02) 9445 3311.\n\n[Document 2 \u2013 Attendee Email]\n\nFrom: Naomi Fletcher <n.fletcher@email.com>\nTo: events@silvergatecitylibrary.org.au\nDate: August 10\n\nHello,\n\nI would like to RSVP for the Marcus Okafor author talk on August 14. I plan to bring my 12-year-old daughter, who is a huge fan of The Weight of Silence. Could you confirm whether the event is suitable for younger attendees?\n\nI would also like to know whether Marcus Okafor will sign books brought from home, or only those purchased on the night.\n\nThank you,\nNaomi Fletcher", "passageTitle": "Event Flyer + RSVP Email", "type": "double", "questions": [{"id": "xp7-d09a", "part": 7, "question": "What will Marcus Okafor discuss at the event?", "options": ["The history of the Booker Prize", "Inspiration for his novel, writing across genres, and his upcoming non-fiction work", "His experience as a library ambassador", "A comparison of literary fiction and investigative journalism"], "answer": 1, "explanation": "'The inspiration behind The Weight of Silence, the challenges of writing across genres, and his upcoming non-fiction work.'", "difficulty": "medium"}, {"id": "xp7-d09b", "part": 7, "question": "What happens after the talk?", "options": ["A Q&A session with audience questions", "A book signing", "A screening of a documentary about the novel", "A reception with refreshments"], "answer": 1, "explanation": "'A book signing will follow the talk.'", "difficulty": "medium"}, {"id": "xp7-d09c", "part": 7, "question": "What is the maximum number of attendees for the event?", "options": ["50", "60", "80", "100"], "answer": 2, "explanation": "'Spaces are limited to 80 attendees.'", "difficulty": "medium"}, {"id": "xp7-d09d", "part": 7, "question": "What two questions does Naomi Fletcher ask in her email?", "options": ["Whether the event is free and whether children are admitted", "Whether the event is suitable for her daughter and whether Marcus signs books from home", "Whether she can reserve two seats and whether dinner is provided", "Whether there is parking and whether RSVP is mandatory"], "answer": 1, "explanation": "Naomi asks: (1) is the event suitable for a 12-year-old and (2) will Marcus sign books brought from home.", "difficulty": "medium"}, {"id": "xp7-d09e", "part": 7, "question": "In Document 1, the word \"intimate\" as used to describe the event format is closest in meaning to", "options": ["private", "small-scale", "exclusive", "informal"], "answer": 1, "explanation": "Word-in-context: \"intimate event format\" = quy m\u00f4 nh\u1ecf, th\u00e2n m\u1eadt. \"Small-scale\" ph\u1ea3n \u00e1nh \u0111\u00fang ngh\u0129a \u2014 s\u1ed1 l\u01b0\u1ee3ng ng\u01b0\u1eddi tham d\u1ef1 h\u1ea1n ch\u1ebf (20 ng\u01b0\u1eddi)."}]}, {"passage": "[Document 1 \u2013 Lease Notice]\n\nNOTICE OF RENT INCREASE\nTenant: Holloway & Associates\nPremises: Suite 1102, 80 Commerce Tower\nCurrent Annual Rent: AUD 148,000\nLease Renewal Date: March 1\n\nDear Tenant,\n\nAs provided under Clause 8.2 of your lease agreement, we hereby give 90 days' notice of a rent review effective upon lease renewal on March 1.\n\nFollowing a market assessment conducted by our independent property valuer, we propose a revised annual rent of AUD 162,400, representing an increase of approximately 9.7%.\n\nYou are invited to respond to this proposal within 30 days. Should you wish to negotiate the proposed figure, please contact our property manager, James Kwon, at jkwon@commerzetower.com.\n\nIf no response is received within 30 days, the proposed rent will be deemed accepted and applied from March 1.\n\nCommerce Tower Property Management\n\n[Document 2 \u2013 Tenant Response]\n\nFrom: Claire Holloway <c.holloway@holloways.com.au>\nTo: jkwon@commerzetower.com\nDate: December 18\n\nDear Mr. Kwon,\n\nThank you for the notice regarding the rent review. While we understand the need for periodic reviews, we are concerned that a 9.7% increase is not consistent with current market conditions in this precinct.\n\nWe engaged our own property adviser, who assessed comparable commercial tenancies and suggested a fair market increase of between 4% and 5%. On this basis, we would like to propose a revised rent of AUD 154,960, representing a 4.7% increase.\n\nWe remain committed to renewing our lease and value our long-standing relationship with Commerce Tower. We look forward to reaching a mutually acceptable outcome.\n\nClaire Holloway\nManaging Principal, Holloway & Associates", "passageTitle": "Rent Review Notice + Tenant Response", "type": "double", "questions": [{"id": "xp7-d10a", "part": 7, "question": "What is the proposed new annual rent from the landlord?", "options": ["AUD 148,000", "AUD 154,960", "AUD 162,400", "AUD 165,000"], "answer": 2, "explanation": "'A revised annual rent of AUD 162,400.'", "difficulty": "medium"}, {"id": "xp7-d10v", "part": 7, "question": "What is most likely the purpose of Claire Holloway's letter?", "options": ["To accept the proposed rent increase unconditionally", "To request a meeting to discuss the rent in person", "To negotiate a lower rent increase and secure a lease renewal", "To give notice that she will vacate the premises"], "answer": 2, "explanation": "Purpose: Claire proposes an alternative rent and discusses lease renewal terms \u2014 her letter clearly aims to negotiate rather than accept or reject outright."}, {"id": "xp7-d10c", "part": 7, "question": "What does Claire Holloway propose as an alternative rent?", "options": ["AUD 150,000", "AUD 152,740", "AUD 154,960", "AUD 157,200"], "answer": 2, "explanation": "'We would like to propose a revised rent of AUD 154,960, representing a 4.7% increase.'", "difficulty": "medium"}, {"id": "xp7-d10d", "part": 7, "question": "What does Claire Holloway say about the lease renewal?", "options": ["She has decided not to renew the lease", "She is considering relocating to another building", "She remains committed to renewing the lease", "She requires more time to make a decision"], "answer": 2, "explanation": "'We remain committed to renewing our lease and value our long-standing relationship with Commerce Tower.'", "difficulty": "medium"}, {"id": "xp7-d10e", "part": 7, "question": "In Document 1, the word \"premises\" is closest in meaning to", "options": ["requirements", "property", "conditions", "agreement"], "answer": 1, "explanation": "Word-in-context: \"Premises: Suite 1102, 80 Commerce Tower\" \u2014 \"premises\" = m\u1eb7t b\u1eb1ng, c\u01a1 s\u1edf. \"Property\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong v\u0103n b\u1ea3n thu\u00ea nh\u00e0."}]}, {"passage": "[Document 1 \u2013 Memo]\n\nTo: All Production Staff\nFrom: Quality Assurance Manager, Stefan Novak\nDate: October 5\n\nI am writing to notify all production staff of a quality control concern identified during last week's batch audit.\n\nDuring testing of Batch 77-C (manufactured September 29\u2013October 1), three units were found to have substandard adhesive bonding in the product casing. While the affected units were isolated before dispatch, the incident highlights a need to review the adhesive application step in our production sequence.\n\nEffective Monday, all line supervisors must conduct a visual check of adhesive application at the end of each production cycle, in addition to the existing end-of-line quality gate.\n\nA root cause analysis is currently underway. Results and any further procedural changes will be communicated by October 18.\n\nPlease direct any questions to the QA team at qa@novexmfg.com.\n\n[Document 2 \u2013 Supervisor Email]\n\nFrom: Priya Mehta <p.mehta@novexmfg.com>\nTo: Stefan Novak <s.novak@novexmfg.com>\nDate: October 7\n\nDear Stefan,\n\nThank you for the memo. I wanted to clarify a few points before implementing the new check on my line.\n\nFirst, should the visual check be documented in the existing QA log or in a separate record? Second, if a supervisor identifies a bonding issue mid-cycle, should production be paused or should we continue and flag the affected units for review?\n\nFinally, I noticed the memo says the root cause analysis will be complete by October 18. Will line supervisors receive a briefing before that date, or should we wait for the full report?\n\nThank you,\nPriya Mehta\nSupervisor, Line 4", "passageTitle": "Quality Control Memo + Supervisor Email", "type": "double", "questions": [{"id": "xp7-d11a", "part": 7, "question": "What issue was found in Batch 77-C?", "options": ["Incorrect labelling on product packaging", "Substandard adhesive bonding in the product casing", "A contamination risk in the assembly area", "Incorrect dimensions on three units"], "answer": 1, "explanation": "'Three units were found to have substandard adhesive bonding in the product casing.'", "difficulty": "medium"}, {"id": "xp7-d11v", "part": 7, "question": "What can be inferred about Priya Mehta's approach to the new quality control requirements?", "options": ["She is resistant to implementing the changes", "She wants to understand the requirements fully before acting", "She has already completed the required training", "She believes the measures are unnecessary"], "answer": 1, "explanation": "Inference: Priya's email asks clarifying questions before implementing \u2014 this indicates she wants complete understanding before acting, a conscientious professional approach."}, {"id": "xp7-d11c", "part": 7, "question": "What is one of Priya Mehta's questions?", "options": ["Whether she can attend the root cause analysis meeting", "Whether the affected batch units have been recalled", "Where the visual check should be documented", "How many units were affected by the bonding issue"], "answer": 2, "explanation": "'Should the visual check be documented in the existing QA log or in a separate record?'", "difficulty": "medium"}, {"id": "xp7-d11d", "part": 7, "question": "When will the root cause analysis results be communicated?", "options": ["By October 5", "By October 7", "By October 14", "By October 18"], "answer": 3, "explanation": "'Results and any further procedural changes will be communicated by October 18.'", "difficulty": "medium"}, {"id": "xp7-d11e", "part": 7, "question": "In Document 2, the word \"clarify\" is closest in meaning to", "options": ["confirm", "explain", "correct", "report"], "answer": 1, "explanation": "Word-in-context: \"I wanted to clarify a few points\" \u2014 \"clarify\" = l\u00e0m r\u00f5, gi\u1ea3i th\u00edch th\u00eam. \"Explain\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh email n\u1ed9i b\u1ed9."}]}, {"passage": "[Document 1 \u2013 Advertisement]\n\nFLEX STORAGE SOLUTIONS\nSelf-Storage Units \u2014 Flexible Lease Terms\n\nNeed extra space? Flex Storage Solutions offers clean, secure, and climate-controlled storage units at our centrally located facility.\n\nAVAILABLE UNIT SIZES:\n\u2022 Small (3 sqm): AUD 79/month\n\u2022 Medium (6 sqm): AUD 129/month\n\u2022 Large (12 sqm): AUD 219/month\n\u2022 Extra-Large (20 sqm): AUD 340/month\n\nALL UNITS INCLUDE:\n\u2713 24/7 keypad access\n\u2713 CCTV security monitoring\n\u2713 Free trolleys and moving equipment on site\n\u2713 No lock-in contract \u2014 month-to-month leases\n\nFirst month FREE for new customers who sign up for a minimum of 3 months!\n\nBOOK ONLINE: flexstoragesolutions.com.au | Call: 1300 359 200\n\n[Document 2 \u2013 Enquiry Email]\n\nFrom: Tom Bradley <t.bradley@email.com>\nTo: enquiries@flexstoragesolutions.com.au\nDate: August 2\n\nHi,\n\nI'm interested in renting a storage unit to house furniture and boxes from a home I'm downsizing from. I estimate I need around 14\u201316 square metres of space.\n\nI have a couple of questions:\n1. Is the first-month-free offer still available?\n2. I may need the unit for only two months \u2014 would I still qualify for the promotion?\n3. Can I access the unit on weekends, and is the facility staffed on weekends?\n\nThanks,\nTom Bradley", "passageTitle": "Storage Advertisement + Customer Enquiry", "type": "double", "questions": [{"id": "xp7-d12a", "part": 7, "question": "Which unit size would best suit Tom Bradley's needs?", "options": ["Medium (6 sqm)", "Large (12 sqm)", "Extra-Large (20 sqm)", "Two Small units"], "answer": 2, "explanation": "Tom estimates 14\u201316 sqm \u2014 the Extra-Large (20 sqm) is the closest option that meets his needs.", "difficulty": "medium"}, {"id": "xp7-d12v", "part": 7, "question": "What does Tom Bradley's email suggest about his storage needs?", "options": ["He requires a long-term permanent storage solution", "He needs short-term storage due to a temporary situation", "He wants to store large commercial equipment", "He is comparing multiple storage providers before deciding"], "answer": 1, "explanation": "Inference: Tom's context (home renovation / temporary need) + short timeline inquiry together suggest a temporary rather than permanent storage need \u2014 inferred from the circumstances described."}, {"id": "xp7-d12cd", "part": 7, "question": "In Document 1, the word \"flexible\" as used in the advertisement is closest in meaning to", "options": ["adjustable", "affordable", "short-term", "convenient"], "answer": 0, "explanation": "WIC in Document 1: \"flexible lease terms\" = \u0111i\u1ec1u kho\u1ea3n thu\u00ea linh ho\u1ea1t, c\u00f3 th\u1ec3 \u0111i\u1ec1u ch\u1ec9nh. \"Adjustable\" n\u1eafm b\u1eaft \u0111\u00fang nh\u1ea5t \u2014 kh\u00f4ng b\u1ecb r\u00e0ng bu\u1ed9c b\u1edfi th\u1eddi h\u1ea1n c\u1ed1 \u0111\u1ecbnh."}, {"id": "xp7-d12d", "part": 7, "question": "What does the advertisement say about access hours?", "options": ["Access is available Monday to Saturday only", "The facility is staffed 24/7", "Units have 24/7 keypad access", "Customers must book access slots in advance"], "answer": 2, "explanation": "'24/7 keypad access' is listed as included with all units.", "difficulty": "medium"}, {"id": "xp7-d12x", "part": 7, "question": "Based on both documents, which of the following best describes Tom Bradley's overall suitability for the advertised storage offer?", "options": ["He qualifies for the offer but the available unit may be larger than he needs", "He does not qualify for the promotional offer due to his existing contract", "He qualifies for the offer and the unit size is a perfect match", "He does not qualify because he cannot sign a 6-month lease"], "answer": 0, "explanation": "Cross-document: Tom's email states his storage needs (volume) + new customer status (qualifies for offer). Advertisement unit sizes show the available unit is slightly larger than what he needs \u2014 combining both gives: qualifies, but unit is bigger than ideal."}]}, {"passage": "[Document 1 \u2013 Donor Recognition Event Invitation]\n\nBLUEHORIZON FOUNDATION\nAnnual Donor Appreciation Dinner\n\nDate:   Friday, November 15\nTime:   7:00 p.m. for 7:30 p.m.\nVenue:  The Pavilion Rooftop, 280 Harbour Drive\n\nDear Friend of BlueHorizon Foundation,\n\nYou are warmly invited to our Annual Donor Appreciation Dinner, an evening dedicated to celebrating your generosity and sharing the impact of your support over the past year.\n\nHighlights of the evening include:\n\u2022 A programme update from our Executive Director\n\u2022 Video presentations from three project communities in Southeast Asia\n\u2022 Recognition of our Platinum Donors (cumulative giving of AUD 50,000 or more)\n\u2022 A keynote address from Ambassador Sarah Lindt, United Nations Resident Coordinator\n\nDress code: Business formal\nRSVP by November 8 to events@bluehorizonfdn.org\nDietary requirements should be advised at time of RSVP.\n\nSeating is limited; early RSVP is appreciated.\n\n[Document 2 \u2013 Attendee RSVP Email]\n\nFrom: Dr. James Osei <j.osei@oseifamily.org>\nTo: events@bluehorizonfdn.org\nDate: November 4\n\nDear BlueHorizon Events Team,\n\nThank you for the invitation. I am delighted to confirm my attendance at the Annual Donor Appreciation Dinner on November 15.\n\nI would like to bring my wife, Helen, as my guest. Could you please advise whether a guest ticket is available, and if so, whether there is an associated cost?\n\nRegarding dietary requirements: Helen is lactose intolerant. My own dietary requirements are none.\n\nI should also mention that I may be slightly late \u2014 I have a board meeting finishing at 7:15 p.m. that evening. Would it be possible to hold a seat for me?\n\nBest regards,\nDr. James Osei", "passageTitle": "Event Invitation + RSVP Email", "type": "double", "questions": [{"id": "xp7-d13a", "part": 7, "question": "Who will deliver the keynote address at the dinner?", "options": ["The Executive Director of BlueHorizon Foundation", "A representative from a Southeast Asian project community", "Ambassador Sarah Lindt from the United Nations", "A Platinum Donor representative"], "answer": 2, "explanation": "'A keynote address from Ambassador Sarah Lindt, United Nations Resident Coordinator.'", "difficulty": "medium"}, {"id": "xp7-d13v", "part": 7, "question": "What can be inferred about Dr. Osei's relationship with the BlueHorizon Foundation?", "options": ["He is a founding member of the organisation", "He has made significant donations to the foundation", "He is a first-time attendee at a foundation event", "He is a board member of the foundation"], "answer": 1, "explanation": "Inference: The invitation's Platinum Donor criteria (significant cumulative giving) + Dr. Osei receiving this invitation \u2192 he has given substantially, qualifying as a Platinum Donor."}, {"id": "xp7-d13c", "part": 7, "question": "What dietary requirement does Dr. Osei mention?", "options": ["He is vegetarian", "He is gluten intolerant", "He has no requirements, but his wife is lactose intolerant", "Both he and his wife are dairy-free"], "answer": 2, "explanation": "'Helen is lactose intolerant. My own dietary requirements are none.'", "difficulty": "medium"}, {"id": "xp7-d13d", "part": 7, "question": "What concern does Dr. Osei raise about the evening?", "options": ["He may not be able to attend at all", "He will arrive late due to a board meeting", "He needs a vegetarian menu option", "He cannot stay for the full evening programme"], "answer": 1, "explanation": "'I may be slightly late \u2014 I have a board meeting finishing at 7:15 p.m. that evening.'", "difficulty": "medium"}, {"id": "xp7-d13e", "part": 7, "question": "In Document 1, the word \"distinguished\" is closest in meaning to", "options": ["generous", "experienced", "notable", "selected"], "answer": 2, "explanation": "Word-in-context: \"distinguished guests\" = kh\u00e1ch m\u1eddi danh d\u1ef1, n\u1ed5i ti\u1ebfng. \"Notable\" = \u0111\u00e1ng ch\u00fa \u00fd, n\u1ed5i b\u1eadt. Trong v\u0103n b\u1ea3n s\u1ef1 ki\u1ec7n trang tr\u1ecdng, \"distinguished\" = c\u00f3 ti\u1ebfng t\u0103m, \u0111\u01b0\u1ee3c t\u00f4n tr\u1ecdng."}]}, {"passage": "[Document 1 \u2013 Product Recall Notice]\n\nIMPORTANT SAFETY RECALL\nProduct: VitaBlend NB-900 Nutrition Blender\nManufacturer: NutriCraft International\nDate of Recall: October 8\n\nNutriCraft International is recalling all VitaBlend NB-900 blenders manufactured between January 2023 and May 2024 (serial numbers NB900-00001 to NB900-62000).\n\nREASON: An internal review has identified a potential crack in the blade assembly that can cause blade fragments to detach during use, posing a risk of injury.\n\nCUSTOMER ACTION:\n\u2022 Stop using the product immediately\n\u2022 Do not attempt to disassemble or repair the unit\n\u2022 Register for the recall at vitablend-recall.com using your serial number and proof of purchase\n\u2022 Customers will receive a full replacement unit at no charge\n\nReplacement units will be dispatched within 14 business days of successful registration.\n\n[Document 2 \u2013 Customer Inquiry]\n\nFrom: Sandra Voss <s.voss@email.com>\nTo: recall@nutricraft.com\nDate: October 11\n\nHello,\n\nI purchased a VitaBlend NB-900 in March 2024 as a gift and have just read about the recall. I no longer have the original receipt, but I do have the email order confirmation from the retailer.\n\nMy serial number is NB900-48212. I am wondering whether my unit is affected, and whether an email order confirmation is acceptable as proof of purchase.\n\nAlso, I see the recall mentions replacing the unit, but I would actually prefer a refund. Is that an option?\n\nThank you,\nSandra Voss", "passageTitle": "Recall Notice + Customer Inquiry", "type": "double", "questions": [{"id": "xp7-d14a", "part": 7, "question": "Why is the VitaBlend NB-900 being recalled?", "options": ["The motor has a risk of overheating", "The blade assembly may crack and detach during use", "The suction base can cause the blender to fall", "The lid seal can leak during operation"], "answer": 1, "explanation": "'A potential crack in the blade assembly that can cause blade fragments to detach during use, posing a risk of injury.'", "difficulty": "medium"}, {"id": "xp7-d14v", "part": 7, "question": "What can be inferred about the scope of the product recall?", "options": ["It affects only units purchased online", "It is limited to units sold in a specific region", "It covers a defined batch of units based on serial numbers", "It applies to all units sold since the product launched"], "answer": 2, "explanation": "Inference: Product recalls are defined by specific serial number ranges or batch codes \u2014 the recall notice implies a defined scope rather than affecting all units ever sold."}, {"id": "xp7-d14cd", "part": 7, "question": "Based on both documents, what action has Sandra Voss most likely already taken before sending her email?", "options": ["She has stopped using the blender as instructed", "She has already returned the product to the retailer", "She has contacted the retailer for a refund", "She has registered her product on the company website"], "answer": 0, "explanation": "Cross-document: Recall notice instructs immediate cessation of use. Sandra's email asks about next steps (refund/replacement) \u2014 implying she has already stopped using it as per the notice's instructions."}, {"id": "xp7-d14d", "part": 7, "question": "What does Sandra Voss ask about that is not mentioned in the recall notice?", "options": ["How to register for the recall", "When replacement units will be dispatched", "Whether a refund is available instead of a replacement", "Whether she needs to return the old unit"], "answer": 2, "explanation": "The recall only mentions replacement; Sandra asks 'I would actually prefer a refund. Is that an option?'", "difficulty": "medium"}, {"id": "xp7-d14e", "part": 7, "question": "In Document 1, the word \"immediately\" is closest in meaning to", "options": ["carefully", "voluntarily", "without delay", "at your convenience"], "answer": 2, "explanation": "Word-in-context: \"stop using the product immediately\" = ng\u1eebng s\u1eed d\u1ee5ng ngay l\u1eadp t\u1ee9c. \"Without delay\" l\u00e0 di\u1ec5n \u0111\u1ea1t t\u01b0\u01a1ng \u0111\u01b0\u01a1ng trong v\u0103n b\u1ea3n thu h\u1ed3i s\u1ea3n ph\u1ea9m."}]}, {"passage": "[Document 1 \u2013 Internship Programme Announcement]\n\nSUMMER INTERNSHIP PROGRAMME 2024\nRiver City Museum of Art\n\nRiver City Museum of Art invites applications for its annual Summer Internship Programme, running July 7 to August 29 (eight weeks).\n\nPlacement Areas:\n\u2022 Curatorial & Collections\n\u2022 Education & Public Programmes\n\u2022 Marketing & Communications\n\u2022 Visitor Experience\n\nInterns receive a weekly stipend of AUD 450 and a complimentary annual museum membership.\n\nEligibility: Currently enrolled in a relevant degree programme (Art History, Museum Studies, Education, Marketing, or equivalent).\n\nApplication: Submit a CV and a 400-word motivation letter to hr@rivercitymuseum.org.au by May 31. Successful applicants will be notified by June 14.\n\n[Document 2 \u2013 Application Confirmation]\n\nFrom: HR Department <hr@rivercitymuseum.org.au>\nTo: Luca Marchetti <l.marchetti@email.com>\nDate: June 14\n\nDear Mr. Marchetti,\n\nThank you for your application for the Summer Internship Programme at River City Museum of Art. We are pleased to inform you that you have been selected for a placement in the Curatorial & Collections department.\n\nThe internship begins on Monday, July 7. Please report to the main reception at 9:00 a.m. and ask for Ms. Freya Hansen, Senior Curator, who will be your supervisor for the duration of the placement.\n\nPlease note that you will need to complete an online induction module before your start date. A link will be sent to this email address by June 21.\n\nWe look forward to welcoming you to the team.\n\nRiver City Museum of Art HR", "passageTitle": "Internship Announcement + Confirmation Email", "type": "double", "questions": [{"id": "xp7-d15a", "part": 7, "question": "What financial benefit do interns receive?", "options": ["AUD 450 per week and a travel allowance", "A weekly stipend of AUD 450 and a complimentary annual membership", "AUD 450 per week and a uniform allowance", "A one-time payment of AUD 450 upon completion"], "answer": 1, "explanation": "'Interns receive a weekly stipend of AUD 450 and a complimentary annual museum membership.'", "difficulty": "medium"}, {"id": "xp7-d15v", "part": 7, "question": "What does the confirmation email suggest about Luca Marchetti's placement?", "options": ["He was assigned to his first choice department", "His placement was changed from the original plan", "He was one of many interns placed in the same department", "His placement aligns with the museum's priority area"], "answer": 3, "explanation": "Inference: The email's positive framing of Luca's placement + the museum's stated focus areas suggests his assignment aligns with a priority area \u2014 inferred from the enthusiastic confirmation tone."}, {"id": "xp7-d15cd", "part": 7, "question": "Based on both documents, what must Luca Marchetti do before July 7 that was NOT explicitly required in the programme announcement?", "options": ["Confirm his placement preference", "Complete an online orientation module", "Submit background check documentation", "Register his participation in the programme"], "answer": 1, "explanation": "Cross-document: Announcement describes the programme requirements. Confirmation email adds a specific pre-start requirement not in the announcement \u2014 the orientation module must be completed before July 7."}, {"id": "xp7-d15d", "part": 7, "question": "What must Luca Marchetti complete before July 7?", "options": ["A written test on art history", "A background check", "An online induction module", "A meeting with his supervisor"], "answer": 2, "explanation": "'You will need to complete an online induction module before your start date.'", "difficulty": "medium"}, {"id": "xp7-d15e", "part": 7, "question": "In Document 1, the word \"immerse\" is closest in meaning to", "options": ["develop", "involve deeply", "assist", "observe"], "answer": 1, "explanation": "Word-in-context: \"immerse themselves in the museum's work\" = \u0111\u1eafm m\u00ecnh v\u00e0o, tham gia s\u00e2u s\u1eafc. \"Involve deeply\" n\u1eafm b\u1eaft \u0111\u00fang ngh\u0129a \u2014 \"immerse in\" = tham gia to\u00e0n di\u1ec7n."}]}, {"passage": "[Document 1 \u2013 Survey Summary Report]\n\nCOMMUNITY INFRASTRUCTURE SURVEY \u2014 RESULTS SUMMARY\nSpringfield City Council\nSurvey Period: March 1\u201331 | Total Respondents: 1,847\n\nThe survey was conducted to gather resident views on infrastructure priorities for the upcoming five-year capital works plan.\n\nTOP PRIORITIES IDENTIFIED (% rating as 'High Priority'):\n1. Footpath and cycle path upgrades: 78%\n2. Public park improvements: 71%\n3. Road resurfacing: 65%\n4. Community centre upgrades: 58%\n5. Public transport shelters: 52%\n\nAGE BREAKDOWN: Respondents aged 25\u201344 ranked footpaths and cycling infrastructure as their top priority at 86%, while those aged 65+ prioritised park improvements (81%) and community centre upgrades (74%).\n\nThe Council will use these results to inform its Capital Works Plan, which will be presented to councillors at the July 15 meeting.\n\n[Document 2 \u2013 Council Member Email]\n\nFrom: Councillor Renata Voss <r.voss@springfieldcouncil.gov.au>\nTo: Director of Infrastructure <infra@springfieldcouncil.gov.au>\nDate: April 3\n\nDear Director,\n\nThank you for sharing the community survey results. The data is very useful and I appreciate the strong participation rate.\n\nI have a few observations. While footpath and cycling infrastructure topped the overall rankings, I note that public transport shelters ranked lowest overall despite being highly valued by elderly residents. I would like to ensure that age-specific data is considered in how we allocate the capital works budget.\n\nAdditionally, given that community centre upgrades ranked fourth overall but ranked second among older residents, I think it would be worth holding a consultation session specifically focused on older residents before the Capital Works Plan is finalised.\n\nI look forward to the July 15 presentation.\n\nCouncillor Renata Voss", "passageTitle": "Survey Report + Council Member Email", "type": "double", "questions": [{"id": "xp7-d16a", "part": 7, "question": "What was the top priority overall in the survey?", "options": ["Public park improvements", "Road resurfacing", "Footpath and cycle path upgrades", "Community centre upgrades"], "answer": 2, "explanation": "'Footpath and cycle path upgrades: 78%' \u2014 the highest-rated item.", "difficulty": "medium"}, {"id": "xp7-d16v", "part": 7, "question": "What is Councillor Voss most likely trying to achieve with her email?", "options": ["To delay the finalisation of the Capital Works Plan indefinitely", "To ensure the plan reflects priorities across all age groups and residents", "To redirect funding away from cycling infrastructure", "To support only the top-ranked priority from the survey"], "answer": 1, "explanation": "Inference: Voss raises concern about transport shelters (used by seniors) and suggests consultation before finalising \u2014 she is advocating for inclusive planning that reflects all residents' needs."}, {"id": "xp7-d16cd", "part": 7, "question": "Based on both documents, what can be inferred about the age group that gave the lowest priority rating to cycling infrastructure?", "options": ["Residents under 25 years old", "Residents aged 25\u201344", "Residents aged 45\u201364", "Residents over 65 years old"], "answer": 3, "explanation": "Cross-document: Survey report shows 25\u201344 age group ranked cycling infrastructure at 74%. Councillor Voss's email expresses concern about older residents' needs (transport shelters). Together they suggest the 65+ group gave cycling infrastructure a lower priority rating."}, {"id": "xp7-d16d", "part": 7, "question": "What does Councillor Voss suggest before the Capital Works Plan is finalised?", "options": ["A second city-wide survey", "A review of the infrastructure budget", "A consultation session specifically for older residents", "A meeting with the council's engineering team"], "answer": 2, "explanation": "'It would be worth holding a consultation session specifically focused on older residents before the Capital Works Plan is finalised.'", "difficulty": "medium"}, {"id": "xp7-d16e", "part": 7, "question": "In Document 2, the word \"finalised\" is closest in meaning to", "options": ["announced", "approved", "completed", "revised"], "answer": 2, "explanation": "Word-in-context: \"before the Capital Works Plan is finalised\" = tr\u01b0\u1edbc khi \u0111\u01b0\u1ee3c ho\u00e0n thi\u1ec7n ch\u00ednh th\u1ee9c. \"Completed\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh l\u1eadp k\u1ebf ho\u1ea1ch."}]}, {"passage": "[Document 1 \u2013 Product Brochure]\n\nPRIMECHARGE PRO SOLAR POWER STATION\nModel: PCP-2000 | By SunCore Energy\n\nPower your life off-grid with the PrimeCharge Pro \u2014 a portable, high-capacity solar power station built for outdoor enthusiasts and emergency preparedness.\n\nSPECIFICATIONS:\n\u2022 Battery capacity: 2,016 Wh (lithium iron phosphate)\n\u2022 AC output: 4 x 240V outlets (total 2,000W continuous, 4,000W surge)\n\u2022 Charging: Solar (up to 700W input), AC wall, or car port\n\u2022 Full charge via AC wall outlet: approximately 2.5 hours\n\u2022 Full charge via solar: 3\u20135 hours (weather dependent)\n\u2022 Weight: 18.5 kg\n\u2022 Warranty: 5 years on battery, 2 years on components\n\nRETAIL PRICE: AUD 2,499\nFree shipping on orders over AUD 500.\n\n[Document 2 \u2013 Online Review]\n\nPosted by: DesertTrekker_AU | 4 out of 5 stars\nDate: February 12\n\nI purchased the PrimeCharge Pro PCP-2000 for a five-day camping trip in outback South Australia. Overall I'm very impressed \u2014 it powered my fridge, lighting, and phone charging throughout the trip without any issues.\n\nCharging via the included 200W solar panel took around 7\u20138 hours under clear skies, which is longer than the brochure suggests, but I only had the single panel. I assume two panels would bring that closer to the spec.\n\nThe unit is heavy at 18.5 kg, but it came with a carry handle and a wheeled trolley, which made transport manageable.\n\nMy one complaint: the AC outlets don't have covers, so sand and dust got inside during the trip. Not a major issue, but worth noting for outback travel.\n\nWould recommend for serious campers and as a home backup.", "passageTitle": "Product Brochure + Online Review", "type": "double", "questions": [{"id": "xp7-d17a", "part": 7, "question": "How long does a full AC wall charge take?", "options": ["1.5 hours", "2 hours", "2.5 hours", "3 hours"], "answer": 2, "explanation": "'Full charge via AC wall outlet: approximately 2.5 hours.'", "difficulty": "medium"}, {"id": "xp7-d17v", "part": 7, "question": "In Document 2, the word \"discrepancy\" is closest in meaning to", "options": ["difference", "problem", "error", "limitation"], "answer": 0, "explanation": "WIC: \"discrepancy\" = s\u1ef1 ch\u00eanh l\u1ec7ch, kh\u00f4ng kh\u1edbp gi\u1eefa hai con s\u1ed1/th\u00f4ng tin. \"Difference\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t v\u00e0 ph\u1ed5 bi\u1ebfn nh\u1ea5t trong ng\u1eef c\u1ea3nh so s\u00e1nh th\u00f4ng tin k\u1ef9 thu\u1eadt."}, {"id": "xp7-d17cd", "part": 7, "question": "Based on both documents, which feature of the PrimeCharge Pro is presented positively in BOTH the brochure and the reviewer's experience?", "options": ["The AC wall charging speed", "The solar charging performance", "The multiple output ports", "The product weight"], "answer": 2, "explanation": "Cross-document: Brochure promotes multiple output ports. Reviewer specifically mentions using the USB-C and USB-A ports simultaneously without issue \u2014 the multiple output ports is confirmed as positive in both documents."}, {"id": "xp7-d17d", "part": 7, "question": "What is the reviewer's main complaint about the product?", "options": ["The battery capacity is lower than advertised", "The unit overheated during the trip", "The AC outlets have no covers to protect against dust", "The trolley broke during transport"], "answer": 2, "explanation": "'The AC outlets don't have covers, so sand and dust got inside during the trip.'", "difficulty": "medium"}, {"id": "xp7-d17e", "part": 7, "question": "In Document 1, the word \"capacity\" is closest in meaning to", "options": ["power", "storage amount", "performance", "battery life"], "answer": 1, "explanation": "Word-in-context: \"capacity\" trong ng\u1eef c\u1ea3nh power station = dung l\u01b0\u1ee3ng l\u01b0u tr\u1eef \u0111i\u1ec7n (2000Wh). \"Storage amount\" m\u00f4 t\u1ea3 ch\u00ednh x\u00e1c nh\u1ea5t ngh\u0129a k\u1ef9 thu\u1eadt n\u00e0y."}]}, {"passage": "[Document 1 \u2013 Event Sponsorship Proposal]\n\nMAGNOLIA FOOD & WINE FESTIVAL\nSponsorship Opportunities \u2014 2024\n\nThe Magnolia Food & Wine Festival is the region's premier culinary event, attracting over 18,000 visitors across three days. Now in its 12th year, the festival features 80+ exhibitors, live cooking demonstrations, and a wine tasting pavilion.\n\nSPONSORSHIP TIERS:\n\nPLATINUM (AUD 25,000)\n\u2022 Naming rights to the Main Stage\n\u2022 Logo on all event marketing materials (print, digital, outdoor)\n\u2022 20 complimentary VIP passes\n\u2022 Dedicated brand activation space (36 sqm)\n\nGOLD (AUD 12,000)\n\u2022 Logo on selected marketing materials\n\u2022 10 complimentary VIP passes\n\u2022 Brand activation space (18 sqm)\n\nSILVER (AUD 6,000)\n\u2022 Logo on event website and programme\n\u2022 4 complimentary VIP passes\n\u2022 Shared activation space\n\nDeadline for sponsorship commitments: March 15\nContact: sponsors@magnoliafestival.com.au\n\n[Document 2 \u2013 Sponsorship Enquiry]\n\nFrom: Oliver Park <o.park@blossombrewery.com>\nTo: sponsors@magnoliafestival.com.au\nDate: March 3\n\nDear Festival Team,\n\nBlossom Brewery would like to express its interest in the Gold sponsorship package for this year's Magnolia Food & Wine Festival.\n\nWe are particularly interested in the brand activation space and the VIP passes for client entertainment. However, I would like to ask whether the Gold package allows for any co-branding with the wine tasting pavilion, as beer and food pairings are central to our brand.\n\nAdditionally, is there any flexibility to increase the activation space from 18 sqm to 24 sqm under the Gold tier, and if so, would this incur an additional fee?\n\nWe are committed to completing our application before the March 15 deadline.\n\nBest regards,\nOliver Park\nMarketing Director, Blossom Brewery", "passageTitle": "Sponsorship Proposal + Enquiry Email", "type": "double", "questions": [{"id": "xp7-d18a", "part": 7, "question": "How many VIP passes does the Gold sponsorship include?", "options": ["4", "10", "12", "20"], "answer": 1, "explanation": "'Gold (AUD 12,000) \u2014 10 complimentary VIP passes.'", "difficulty": "medium"}, {"id": "xp7-d18v", "part": 7, "question": "What is most likely the reason Oliver Park is asking about activation rights?", "options": ["He wants to confirm that competitors cannot sponsor the same event", "He plans to set up a promotional stand or activity at the festival", "He is concerned about the exclusivity of the sponsorship package", "He wants to understand the refund policy for sponsorship fees"], "answer": 1, "explanation": "Inference: \"Activation rights\" in sponsorship = ability to engage attendees through branded activities/stands. Oliver's question about this suggests he plans an on-site promotional presence."}, {"id": "xp7-d18cd", "part": 7, "question": "Based on both documents, what does Oliver Park still need to clarify before committing to the Gold package?", "options": ["The number of VIP passes included", "The naming rights available with Gold tier", "The specific activation rights and logo placement details", "The application deadline and payment schedule"], "answer": 2, "explanation": "Cross-document: Gold package listed in proposal. Oliver's email asks specifically about activation rights and logo placement \u2014 these are the two items not fully specified in the proposal that he needs clarified before committing."}, {"id": "xp7-d18d", "part": 7, "question": "By when does Oliver Park confirm he will complete the sponsorship application?", "options": ["By March 1", "Before March 15", "After March 15", "By the end of the month"], "answer": 1, "explanation": "'We are committed to completing our application before the March 15 deadline.'", "difficulty": "medium"}, {"id": "xp7-d18e", "part": 7, "question": "In Document 1, the word \"complimentary\" is closest in meaning to", "options": ["optional", "premium", "free of charge", "limited"], "answer": 2, "explanation": "Word-in-context: \"complimentary VIP passes\" = v\u00e9 VIP mi\u1ec5n ph\u00ed (t\u1eb7ng k\u00e8m). \"Free of charge\" l\u00e0 di\u1ec5n \u0111\u1ea1t ch\u00ednh x\u00e1c nh\u1ea5t. Ph\u00e2n bi\u1ec7t: \"complimentary\" \u2260 \"complementary\" (b\u1ed5 sung)."}]}, {"passage": "[Document 1 \u2013 Staff Policy]\n\nCONFIDENTIALITY AND NON-DISCLOSURE POLICY\nVanguard Consulting Group\n\nAll employees, contractors, and third-party service providers who access Vanguard Consulting Group's confidential information must read and comply with this policy.\n\nDEFINITION OF CONFIDENTIAL INFORMATION\nConfidential information includes, but is not limited to: client names and contact details, proprietary methodologies and tools, unpublished financial data, and internal strategic plans.\n\nOBLIGATIONS\n\u2022 Confidential information must not be shared with any external party without written authorisation from the Chief Information Officer (CIO).\n\u2022 Information must not be stored on personal devices or cloud services not approved by the IT department.\n\u2022 Employees must report any suspected or actual breach immediately to compliance@vanguardcg.com.\n\nTERMINATION OF EMPLOYMENT\nConfidentiality obligations continue for a period of two years following the end of employment.\n\n[Document 2 \u2013 Employee Email]\n\nFrom: Daniel Kim <d.kim@vanguardcg.com>\nTo: compliance@vanguardcg.com\nDate: August 9\n\nDear Compliance Team,\n\nI wanted to raise a concern about a situation that came up this week. A colleague asked me to send a client contact list to their personal Gmail account so they could work on a proposal over the weekend from their home computer, which is not registered with IT.\n\nI declined, but I wanted to flag this with your team as a potential policy breach.\n\nCould you also clarify: does the policy apply equally to contractors, or only to permanent employees?\n\nThank you,\nDaniel Kim\n\n[Document 3 \u2013 Compliance Response]\n\nFrom: Compliance Team <compliance@vanguardcg.com>\nTo: Daniel Kim <d.kim@vanguardcg.com>\nDate: August 10\n\nDear Daniel,\n\nThank you for reporting this. You acted correctly by declining. Sending client contact details to a personal email account or storing information on non-approved devices is a clear breach of the policy, regardless of intent.\n\nTo answer your question: yes, the policy applies equally to contractors, third-party service providers, and permanent employees \u2014 as stated in the opening paragraph.\n\nWe will follow up directly with the colleague involved. No further action is required from you at this stage.\n\nThe Compliance Team", "passageTitle": "Staff Policy + Employee Report + Compliance Response", "type": "triple", "questions": [{"id": "xp7-t04a", "part": 7, "question": "Who must authorise sharing confidential information with an external party?", "options": ["The employee's direct manager", "The HR Director", "The Chief Information Officer", "The Chief Executive Officer"], "answer": 2, "explanation": "'Must not be shared with any external party without written authorisation from the Chief Information Officer (CIO).'", "difficulty": "medium"}, {"id": "xp7-t04b", "part": 7, "question": "What did Daniel Kim's colleague ask him to do?", "options": ["Share a proposal with a client without approval", "Send a client contact list to a personal Gmail account", "Save internal data on a USB drive", "Copy confidential files to a shared cloud folder"], "answer": 1, "explanation": "'A colleague asked me to send a client contact list to their personal Gmail account.'", "difficulty": "medium"}, {"id": "xp7-t04c", "part": 7, "question": "According to the Compliance Team, does the policy apply to contractors?", "options": ["No, only permanent employees are covered", "Yes, but with different obligations for contractors", "Yes, the policy applies equally to contractors", "Only if contractors have signed a separate NDA"], "answer": 2, "explanation": "'Yes, the policy applies equally to contractors, third-party service providers, and permanent employees.'", "difficulty": "medium"}, {"id": "xp7-t04d", "part": 7, "question": "How long do confidentiality obligations last after employment ends?", "options": ["6 months", "12 months", "2 years", "5 years"], "answer": 2, "explanation": "'Confidentiality obligations continue for a period of two years following the end of employment.'", "difficulty": "medium"}, {"id": "xp7-t04e", "part": 7, "question": "What action is Daniel Kim required to take following the Compliance Team's response?", "options": ["Submit a formal written statement about the incident", "Meet with the HR department to discuss the matter", "No further action is required", "Arrange a meeting with his colleague"], "answer": 2, "explanation": "'No further action is required from you at this stage.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Notification of Renovation Works]\n\nTo: All Tenants, Pacific Trade Plaza\nFrom: Property Management\nDate: September 2\nRe: Level 1 Common Area Renovation \u2014 September 16 to October 10\n\nWe wish to advise all tenants that the Level 1 common area \u2014 including the lobby, lifts, and amenities \u2014 will be under renovation from September 16 to October 10.\n\nDuring this period:\n\u2022 The main lobby entrance will be closed. All tenants and visitors must use the Clarence Street side entrance.\n\u2022 Two of the four lifts will be operational. Expect delays during peak hours.\n\u2022 The caf\u00e9 on Level 1 will remain open but will operate with a reduced menu.\n\nFor deliveries and large item movements, please contact building management to arrange supervised access on weekdays between 7:00 and 8:30 a.m.\n\nFull access will be restored by October 11.\n\n[Document 2 \u2013 Tenant Email]\n\nFrom: Sandra Lo <s.lo@brightspark.com.au>\nTo: management@pacifictradeplaza.com.au>\nDate: September 10\n\nDear Management,\n\nThank you for the notice regarding the upcoming renovation. We have two questions.\n\nFirst, we have a large furniture delivery scheduled for September 19. We would like to arrange supervised access on that day. Could you advise whether the 7:00\u20138:30 a.m. window is the only available time, or whether other arrangements can be made?\n\nSecond, our office is on Level 1 and we frequently receive clients. Can you confirm whether the Clarence Street entrance is fully accessible and well signposted for first-time visitors?\n\nThank you,\nSandra Lo\nOperations Manager, BrightSpark\n\n[Document 3 \u2013 Management Reply]\n\nFrom: Property Management <management@pacifictradeplaza.com.au>\nTo: Sandra Lo <s.lo@brightspark.com.au>\nDate: September 11\n\nDear Ms. Lo,\n\nThank you for your email.\n\nRegarding the delivery on September 19: the 7:00\u20138:30 a.m. weekday window is our standard supervised access period during the renovation. However, we can accommodate a one-off arrangement after 5:00 p.m. on weekdays if the morning window is not suitable. Please let us know your preference.\n\nRegarding the Clarence Street entrance: it is fully step-free and accessible. Temporary signage has been installed at the original main entrance and at street level to direct visitors to the Clarence Street door. We are happy to provide a brief orientation map upon request.\n\nPlease don't hesitate to reach out if you have further questions.\n\nPacific Trade Plaza Property Management", "passageTitle": "Renovation Notice + Tenant Email + Management Reply", "type": "triple", "questions": [{"id": "xp7-t05a", "part": 7, "question": "How many lifts will be available during the renovation?", "options": ["One", "Two", "Three", "All four"], "answer": 1, "explanation": "'Two of the four lifts will be operational.'", "difficulty": "medium"}, {"id": "xp7-t05b", "part": 7, "question": "When does full access to Level 1 resume?", "options": ["September 16", "October 10", "October 11", "October 14"], "answer": 2, "explanation": "'Full access will be restored by October 11.'", "difficulty": "medium"}, {"id": "xp7-t05c", "part": 7, "question": "Why does Sandra Lo contact property management?", "options": ["To request a rent reduction during the renovation", "To enquire about a delivery and accessibility for clients", "To report a complaint about the renovation noise", "To request an extended notice period"], "answer": 1, "explanation": "'We have two questions' \u2014 about a furniture delivery on September 19 and the Clarence Street entrance accessibility.", "difficulty": "medium"}, {"id": "xp7-t05d", "part": 7, "question": "What alternative option does management offer for the delivery?", "options": ["A Saturday morning slot", "An arrangement after 5:00 p.m. on weekdays", "Access through the loading dock at any time", "A supervised Sunday delivery window"], "answer": 1, "explanation": "'We can accommodate a one-off arrangement after 5:00 p.m. on weekdays if the morning window is not suitable.'", "difficulty": "medium"}, {"id": "xp7-t05e", "part": 7, "question": "What does management offer to help clients find the Clarence Street entrance?", "options": ["A staff member to wait at the main entrance", "A digital map sent by email", "A brief orientation map upon request", "PA announcements in the building"], "answer": 2, "explanation": "'We are happy to provide a brief orientation map upon request.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Training Programme Brochure]\n\nPROFESSIONAL DEVELOPMENT SERIES\nApex Business Institute\n\nCourse: Advanced Negotiation Skills for Business Professionals\nFormat: 3-day intensive (in-person)\nDates available: April 22\u201324 | May 20\u201322 | June 17\u201319\nVenue: Apex Business Institute, Level 6, 88 George Street\nFee: AUD 2,100 per participant (includes materials, meals, and certificate)\nGroup discount: 15% for 3 or more participants from the same organisation\n\nThis course is suitable for managers, senior executives, and professionals whose roles involve contract negotiation, supplier management, or business development.\n\nTopics covered:\n\u2022 Interest-based negotiation frameworks\n\u2022 Managing cross-cultural negotiations\n\u2022 Dealing with difficult counterparts\n\u2022 Structuring and closing complex deals\n\nCPD points: 18 points upon completion\n\n[Document 2 \u2013 Registration Enquiry]\n\nFrom: Marcus Thornton <m.thornton@vertexgroup.com.au>\nTo: pd@apexbi.com.au\nDate: March 28\n\nDear Apex Team,\n\nI would like to register four participants from Vertex Group for the Advanced Negotiation Skills course. We prefer the May 20\u201322 dates.\n\nCould you confirm the group discount applies to our booking of four people, and what the total cost would be?\n\nAlso, one of our participants has a dietary requirement (gluten-free). Could you confirm meals can be accommodated?\n\nThank you,\nMarcus Thornton\n\n[Document 3 \u2013 Booking Confirmation]\n\nFrom: Apex Business Institute <pd@apexbi.com.au>\nTo: Marcus Thornton <m.thornton@vertexgroup.com.au>\nDate: March 30\n\nDear Mr. Thornton,\n\nThank you for your registration enquiry.\n\nWe can confirm the following:\n\n1. Group discount: The 15% group discount applies to groups of 3 or more, so your booking of 4 participants qualifies. The per-person fee is AUD 1,785 (AUD 2,100 \u00d7 0.85). Total for 4 participants: AUD 7,140.\n\n2. Dietary requirements: We can absolutely accommodate a gluten-free meal option. Please provide the participant's full name when completing the registration form so our catering team can make the necessary arrangements.\n\n3. Places on May 20\u201322 are available but filling quickly. We recommend confirming your booking by April 4 to secure your spots.\n\nPlease visit apexbi.com.au/register to complete the booking.\n\nApex Business Institute", "passageTitle": "Training Brochure + Registration Enquiry + Booking Confirmation", "type": "triple", "questions": [{"id": "xp7-t06a", "part": 7, "question": "How many CPD points does the course provide?", "options": ["12", "15", "18", "21"], "answer": 2, "explanation": "'CPD points: 18 points upon completion.'", "difficulty": "medium"}, {"id": "xp7-t06b", "part": 7, "question": "What is the total cost for Vertex Group's booking after the group discount?", "options": ["AUD 6,300", "AUD 7,140", "AUD 8,400", "AUD 8,820"], "answer": 1, "explanation": "AUD 2,100 \u00d7 0.85 = AUD 1,785 per person \u00d7 4 = AUD 7,140.", "difficulty": "medium"}, {"id": "xp7-t06c", "part": 7, "question": "What must Marcus Thornton provide to arrange gluten-free meals?", "options": ["A signed dietary declaration form", "The participant's full name on the registration form", "A doctor's note confirming the dietary requirement", "The request in writing at least 7 days before the course"], "answer": 1, "explanation": "'Please provide the participant's full name when completing the registration form.'", "difficulty": "medium"}, {"id": "xp7-t06d", "part": 7, "question": "By when should Marcus Thornton confirm the booking to secure places?", "options": ["March 30", "April 1", "April 4", "April 7"], "answer": 2, "explanation": "'We recommend confirming your booking by April 4 to secure your spots.'", "difficulty": "medium"}, {"id": "xp7-t06e", "part": 7, "question": "What is the minimum group size required to receive the 15% discount?", "options": ["2", "3", "4", "5"], "answer": 1, "explanation": "'15% for 3 or more participants from the same organisation.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Policy Summary]\n\nFLEXWORK POLICY \u2014 KEY PROVISIONS\nCaldera Technologies\n\nCaldera Technologies' FlexWork Policy allows eligible employees to choose between three work arrangements: Full On-Site (5 days), Hybrid (2\u20133 days on-site), or Full Remote. Eligibility is based on role requirements and manager discretion.\n\nKEY CONDITIONS:\n\u2022 All employees must be available and responsive during core hours: 9:00 a.m. \u2013 4:00 p.m. (local time)\n\u2022 Full Remote employees must attend the office in person a minimum of once per quarter for team meetings and performance reviews\n\u2022 Hybrid employees' on-site days must include at least one agreed anchor day per week (e.g., all-team Tuesday)\n\u2022 Equipment for remote work is provided by the company; employees are responsible for internet connectivity costs\n\n[Document 2 \u2013 Manager Email]\n\nFrom: David Yu <d.yu@calderatech.com>\nTo: Isabel Reyes <i.reyes@calderatech.com>\nDate: June 2\n\nHi Isabel,\n\nI wanted to follow up on our conversation from last week about your FlexWork arrangement.\n\nI'm supportive of you transitioning to Full Remote given the relocation you've mentioned. However, I want to clarify a few things:\n\nFirst, while I'm happy to approve Full Remote status, you'll still need to come into the Sydney office at least once a quarter \u2014 could you commit to that?\n\nSecond, I should flag that our team's anchor day is Wednesday. I know this will require some planning given the travel involved, but it needs to remain in place.\n\nPlease confirm your availability for a 30-minute call this week to finalise the arrangements.\n\nDavid\n\n[Document 3 \u2013 Employee Response]\n\nFrom: Isabel Reyes <i.reyes@calderatech.com>\nTo: David Yu <d.yu@calderatech.com>\nDate: June 3\n\nHi David,\n\nThank you for your message and for supporting my transition to Full Remote.\n\nRegarding the quarterly visits: I'm absolutely fine with that commitment. I was planning to return to Sydney roughly every 8 weeks anyway for personal reasons, so this aligns well.\n\nRegarding the Wednesday anchor day: I understand this is non-negotiable for the team structure. I can travel to Sydney on Tuesdays and work from the office on Wednesdays. That works for me.\n\nI'm available for a call on Thursday afternoon or Friday morning \u2014 whichever suits you best.\n\nIsabel", "passageTitle": "FlexWork Policy + Manager Email + Employee Response", "type": "triple", "questions": [{"id": "xp7-t07a", "part": 7, "question": "How often must Full Remote employees attend the office in person?", "options": ["Once a month", "Once every two months", "Once per quarter", "Twice per year"], "answer": 2, "explanation": "'Full Remote employees must attend the office in person a minimum of once per quarter.'", "difficulty": "medium"}, {"id": "xp7-t07b", "part": 7, "question": "What is the anchor day for David Yu's team?", "options": ["Monday", "Tuesday", "Wednesday", "Thursday"], "answer": 2, "explanation": "'Our team's anchor day is Wednesday.'", "difficulty": "medium"}, {"id": "xp7-t07c", "part": 7, "question": "Who is responsible for internet connectivity costs for remote workers?", "options": ["Caldera Technologies", "The employee", "Split equally between employer and employee", "Determined by the manager"], "answer": 1, "explanation": "'Employees are responsible for internet connectivity costs.'", "difficulty": "medium"}, {"id": "xp7-t07d", "part": 7, "question": "How does Isabel plan to manage the Wednesday anchor day requirement?", "options": ["She will work from home on Wednesdays only", "She will travel to Sydney on Tuesdays and work from the office on Wednesdays", "She will attend via video call on Wednesdays", "She will request a change to the anchor day"], "answer": 1, "explanation": "'I can travel to Sydney on Tuesdays and work from the office on Wednesdays.'", "difficulty": "medium"}, {"id": "xp7-t07e", "part": 7, "question": "How often was Isabel already planning to return to Sydney?", "options": ["Once a month", "Every 6 weeks", "Roughly every 8 weeks", "Once per quarter"], "answer": 2, "explanation": "'I was planning to return to Sydney roughly every 8 weeks anyway for personal reasons.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Product Listing]\n\nLUMINEX PRO WIRELESS EARBUDS\nModel: LP-7 | SoundStream Audio\n\nExperience studio-quality sound in a lightweight, truly wireless package.\n\nFEATURES:\n\u2022 Active Noise Cancellation (ANC) with 4 adaptive mics\n\u2022 10-hour playback per charge; up to 40 hours total with charging case\n\u2022 IPX5 water resistance\n\u2022 Multipoint pairing: connect to 2 devices simultaneously\n\u2022 Wireless charging case (also compatible with USB-C)\n\u2022 Available in: Midnight Black, Arctic White, Forest Green\n\nPRICE: USD 199\nWARRANTY: 1 year (earbuds); 6 months (charging case)\n\n[Document 2 \u2013 Customer Review]\n\nRating: 3/5 stars\nReviewer: QuietCityListener\nDate: May 5\n\nI bought the LP-7 in Arctic White two months ago for commuting. The sound quality is genuinely excellent for the price \u2014 warm bass and clear highs. The ANC is decent but not best-in-class.\n\nThe issue I've had is with multipoint pairing. Switching between my laptop and phone is clunky \u2014 it often requires manually disconnecting from one device before the other reconnects. This seems like a firmware issue that should be fixable.\n\nBattery life has been fine \u2014 I get about 9 hours per charge, which is slightly under the advertised 10.\n\nI contacted support about the multipoint issue and was told a firmware update is planned for late Q2.\n\n[Document 3 \u2013 Brand Response]\n\nPosted by SoundStream Audio | May 7\n\nThank you for your detailed review. We're glad the sound quality is meeting your expectations.\n\nWe acknowledge the multipoint switching behaviour you've described. Our engineering team has identified the cause and a firmware update resolving this issue will be released in the Week of June 16. The update will be delivered automatically via the SoundStream app.\n\nRegarding battery life: some variance from the rated 10-hour figure is expected depending on volume level and ANC usage. Your 9-hour result is within normal range.\n\nWe appreciate your patience and hope the firmware update delivers the seamless switching experience you're looking for.\n\nSoundStream Audio Support", "passageTitle": "Product Listing + Customer Review + Brand Response", "type": "triple", "questions": [{"id": "xp7-t08a", "part": 7, "question": "What is the total battery life including the charging case?", "options": ["10 hours", "20 hours", "30 hours", "40 hours"], "answer": 3, "explanation": "'Up to 40 hours total with charging case.'", "difficulty": "medium"}, {"id": "xp7-t08b", "part": 7, "question": "What is the reviewer's main complaint?", "options": ["The ANC performance is poor", "The earbuds are uncomfortable for long wear", "Multipoint pairing between devices is clunky", "The battery life falls significantly short of advertised"], "answer": 2, "explanation": "'The issue I've had is with multipoint pairing... often requires manually disconnecting.'", "difficulty": "medium"}, {"id": "xp7-t08c", "part": 7, "question": "When will the firmware update be released?", "options": ["Late May", "Early June", "Week of June 16", "End of Q2 2025"], "answer": 2, "explanation": "'A firmware update resolving this issue will be released in the Week of June 16.'", "difficulty": "medium"}, {"id": "xp7-t08d", "part": 7, "question": "How will the firmware update be delivered?", "options": ["Via a physical cable update at an authorised service centre", "Automatically via the SoundStream app", "By downloading it manually from the SoundStream website", "Through the charging case when connected to a computer"], "answer": 1, "explanation": "'The update will be delivered automatically via the SoundStream app.'", "difficulty": "medium"}, {"id": "xp7-t08e", "part": 7, "question": "What does SoundStream say about the reviewer's 9-hour battery result?", "options": ["It indicates a defective unit", "The earbuds should be returned for testing", "It is within the expected normal range", "It will be improved by the firmware update"], "answer": 2, "explanation": "'Your 9-hour result is within normal range.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Staff Handbook Extract]\n\nGRIEVANCE PROCEDURE\nLodestar Financial Services\n\nLodestar Financial Services is committed to resolving workplace grievances promptly and fairly.\n\nSTEP 1: INFORMAL RESOLUTION\nEmployees are encouraged to raise concerns with their direct manager in the first instance. Where this is not possible or appropriate (e.g., the grievance involves the manager), the matter may be raised with the HR Business Partner directly.\n\nSTEP 2: FORMAL GRIEVANCE\nIf the matter is not resolved informally, the employee may submit a written grievance to the HR Department. The grievance must clearly describe the issue, relevant dates, and any supporting information.\n\nSTEP 3: INVESTIGATION\nHR will acknowledge the formal grievance within 3 business days and will complete an investigation within 20 business days. The employee will be notified in writing of the outcome.\n\nSTEP 4: APPEAL\nIf the employee is not satisfied with the outcome, they may appeal to the Chief People Officer within 10 business days. The decision of the Chief People Officer is final and binding.\n\n[Document 2 \u2013 Employee Grievance Email]\n\nFrom: Ryan Nkosi <r.nkosi@lodestarfinancial.com>\nTo: hr@lodestarfinancial.com\nDate: November 4\n\nDear HR Team,\n\nI am submitting this email as a formal grievance under the company's Grievance Procedure.\n\nOn October 15, I was passed over for a promotion that was given to a colleague with less experience and fewer performance results than myself. I raised this informally with my line manager, Anthony Prescott, on October 17, but was told the decision was final and no further explanation was provided.\n\nI believe the promotion decision was not conducted in accordance with the company's stated promotion criteria, and I am requesting a formal review.\n\nPlease acknowledge receipt of this grievance at your earliest convenience.\n\nRyan Nkosi\n\n[Document 3 \u2013 HR Acknowledgement]\n\nFrom: HR Department <hr@lodestarfinancial.com>\nTo: Ryan Nkosi <r.nkosi@lodestarfinancial.com>\nDate: November 6\n\nDear Mr. Nkosi,\n\nThank you for submitting your formal grievance on November 4. This email confirms receipt of your grievance in accordance with Step 2 of our Grievance Procedure.\n\nAs outlined in the procedure, our investigation will be completed within 20 business days of this acknowledgement, with a written outcome communicated to you by December 3.\n\nAn independent HR investigator has been assigned to your case. You may be contacted to provide additional information during the investigation.\n\nYour grievance will be treated in the strictest confidence.\n\nHR Department, Lodestar Financial Services", "passageTitle": "Staff Handbook Extract + Employee Grievance + HR Acknowledgement", "type": "triple", "questions": [{"id": "xp7-t09a", "part": 7, "question": "When should an employee bypass their direct manager and go to HR directly?", "options": ["When the grievance is urgent", "When the employee has already left the company", "When the grievance involves the manager themselves", "When the employee prefers to skip informal resolution"], "answer": 2, "explanation": "'Where this is not possible or appropriate (e.g., the grievance involves the manager).'", "difficulty": "medium"}, {"id": "xp7-t09b", "part": 7, "question": "What is Ryan Nkosi's grievance about?", "options": ["Being dismissed without proper notice", "A dispute over his annual performance review score", "Being passed over for a promotion in favour of a less experienced colleague", "Receiving a pay cut without explanation"], "answer": 2, "explanation": "'I was passed over for a promotion that was given to a colleague with less experience and fewer performance results.'", "difficulty": "medium"}, {"id": "xp7-t09c", "part": 7, "question": "What did Ryan Nkosi's line manager say when informally approached?", "options": ["He agreed to review the decision", "He told Ryan the decision was final and provided no further explanation", "He referred Ryan to the HR department", "He asked Ryan to put his concern in writing"], "answer": 1, "explanation": "'Was told the decision was final and no further explanation was provided.'", "difficulty": "medium"}, {"id": "xp7-t09d", "part": 7, "question": "By when will the HR investigation be completed?", "options": ["November 20", "November 24", "December 3", "December 15"], "answer": 2, "explanation": "'Our investigation will be completed within 20 business days of this acknowledgement... written outcome communicated to you by December 3.'", "difficulty": "medium"}, {"id": "xp7-t09e", "part": 7, "question": "What right does Ryan have if he is unsatisfied with the investigation outcome?", "options": ["He may take the matter to an external tribunal", "He may appeal to the Chief People Officer within 10 business days", "He may request a second investigation", "He may escalate to the Board of Directors"], "answer": 1, "explanation": "'They may appeal to the Chief People Officer within 10 business days. The decision of the Chief People Officer is final and binding.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Award Nomination Form Summary]\n\nREGIONAL SMALL BUSINESS EXCELLENCE AWARDS\nNomination Summary \u2014 Category: Innovation in Service Delivery\n\nNominee: Bloom Floristry Studio\nNominated by: Eastfield Business Improvement District\nContact: Maya Tanaka, Owner | m.tanaka@bloomfloristystudio.com\n\nBusiness Description: Bloom Floristry Studio is a boutique floristry business established in 2019, based in Eastfield. The business employs 6 full-time and 3 part-time staff.\n\nNomination Summary: Bloom Floristry Studio was nominated for its development of a proprietary subscription delivery system, BloomBox, which matches customers with seasonal flower arrangements tailored to their colour and style preferences, using a brief online profile created at signup. The system has achieved a 94% customer retention rate since launch.\n\n[Document 2 \u2013 Judging Panel Notes]\n\nCandidate: Bloom Floristry Studio\nEvaluating Judge: Patricia Lim, Chief Innovation Officer, Greenfield Ventures\n\nStrengths:\n\u2022 Genuinely innovative use of customer preference profiling in a traditionally low-tech sector\n\u2022 Strong retention data (94%) validates the commercial effectiveness of the concept\n\u2022 Scalable model \u2014 the subscription system could be licensed to other floristry businesses\n\nAreas to explore:\n\u2022 How does the business manage seasonal supply constraints while honouring customer preferences?\n\u2022 Is there patent or IP protection on the BloomBox algorithm?\n\n[Document 3 \u2013 Award Shortlist Notification]\n\nFrom: Regional Small Business Excellence Awards <awards@rsbea.org.au>\nTo: Maya Tanaka <m.tanaka@bloomfloristystudio.com>\nDate: October 1\n\nDear Ms. Tanaka,\n\nWe are delighted to inform you that Bloom Floristry Studio has been shortlisted as a finalist in the Innovation in Service Delivery category of the Regional Small Business Excellence Awards.\n\nThe Awards Dinner will be held on Saturday, November 2, at the Grand Pavilion Hotel. Please confirm your attendance (up to 4 guests) by October 18.\n\nFinalists will be invited to present a 5-minute overview of their innovation at the dinner before the award is announced. Presentation guidelines will be emailed to you by October 10.\n\nCongratulations on this recognition.\n\nAwards Secretariat", "passageTitle": "Award Nomination + Judging Notes + Shortlist Notification", "type": "triple", "questions": [{"id": "xp7-t10a", "part": 7, "question": "What makes Bloom Floristry Studio's BloomBox system innovative?", "options": ["It is the first online flower delivery service in Eastfield", "It uses customer preference profiling to match seasonal arrangements in a traditionally low-tech sector", "It offers the lowest prices in the region for subscription floristry", "It allows customers to design their own arrangements online"], "answer": 1, "explanation": "'Genuinely innovative use of customer preference profiling in a traditionally low-tech sector.'", "difficulty": "medium"}, {"id": "xp7-t10b", "part": 7, "question": "What customer metric is highlighted as evidence of the system's success?", "options": ["Over 1,000 active subscriptions", "A 94% customer retention rate", "A 30% increase in sales year-on-year", "An average order value of AUD 120"], "answer": 1, "explanation": "'The system has achieved a 94% customer retention rate since launch.'", "difficulty": "medium"}, {"id": "xp7-t10c", "part": 7, "question": "What commercial opportunity does the judge identify?", "options": ["Expanding to online retail globally", "Opening new physical stores in other cities", "Licensing the subscription system to other floristry businesses", "Partnering with a supermarket chain"], "answer": 2, "explanation": "'Scalable model \u2014 the subscription system could be licensed to other floristry businesses.'", "difficulty": "medium"}, {"id": "xp7-t10d", "part": 7, "question": "What must finalists do at the Awards Dinner?", "options": ["Submit a written report on their innovation", "Complete a product demonstration for judges", "Present a 5-minute overview of their innovation", "Participate in a Q&A panel with other finalists"], "answer": 2, "explanation": "'Finalists will be invited to present a 5-minute overview of their innovation at the dinner.'", "difficulty": "medium"}, {"id": "xp7-t10e", "part": 7, "question": "By what date must Maya Tanaka confirm her attendance?", "options": ["October 1", "October 10", "October 18", "November 2"], "answer": 2, "explanation": "'Please confirm your attendance (up to 4 guests) by October 18.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Job Posting]\n\nROLE: Marketing Automation Specialist\nEmployer: Crestview Financial Planning Group\nLocation: Perth, WA | Hybrid (2 days on-site)\nSalary: AUD 90,000\u2013105,000\n\nCrestview Financial Planning Group is seeking a skilled Marketing Automation Specialist to join its marketing team and help scale its client communication and lead nurturing strategies.\n\nRESPONSIBILITIES:\n\u2022 Build, manage, and optimise automated marketing workflows in HubSpot\n\u2022 Manage segmented email campaigns for over 12,000 client contacts\n\u2022 Analyse campaign performance metrics and report to the Head of Marketing\n\u2022 Collaborate with the content team on SEO and lead generation projects\n\nREQUIREMENTS:\n\u2022 Minimum 3 years' experience in marketing automation\n\u2022 Proficiency in HubSpot (certification preferred)\n\u2022 Google Analytics 4 (GA4) experience required\n\u2022 Financial services experience advantageous but not essential\n\nApplications close: August 25\nEmail: hr@crestviewfpg.com.au\n\n[Document 2 \u2013 Application Letter]\n\nFrom: Haruto Sato <h.sato@email.com>\nTo: hr@crestviewfpg.com.au\nDate: August 18\n\nDear Hiring Manager,\n\nI am applying for the Marketing Automation Specialist role at Crestview Financial Planning Group.\n\nI have four years of experience in marketing automation, primarily using HubSpot, and hold a current HubSpot Marketing Hub certification. In my current position at Meridian Retail Group, I manage email campaigns reaching over 20,000 contacts and have delivered open rate improvements of 34% over two years through advanced segmentation strategies.\n\nWhile I do not have direct experience in financial services, I have worked extensively with regulated industries including healthcare and insurance, and I am confident in adapting to compliance-focused communication environments.\n\nI hold a Bachelor of Business with a major in Marketing from the University of Western Australia.\n\nI look forward to the opportunity to contribute to the Crestview team.\n\nHaruto Sato\n\n[Document 3 \u2013 Interview Invitation]\n\nFrom: Crestview HR <hr@crestviewfpg.com.au>\nTo: Haruto Sato <h.sato@email.com>\nDate: August 29\n\nDear Mr. Sato,\n\nThank you for your application for the Marketing Automation Specialist position. We were impressed by your HubSpot experience and campaign results.\n\nWe would like to invite you to a two-stage interview process:\n\nStage 1: 30-minute video call with the Head of Marketing, Celia Wong \u2014 Tuesday, September 9, at 10:00 a.m.\nStage 2: In-person at our Perth office, including a 45-minute skills assessment \u2014 Friday, September 19 (time to be confirmed).\n\nPlease confirm your availability for Stage 1 by September 2.\n\nKind regards,\nCrestview Financial Planning Group \u2014 HR", "passageTitle": "Job Posting + Application Letter + Interview Invitation", "type": "triple", "questions": [{"id": "xp7-t11a", "part": 7, "question": "What HubSpot qualification does Haruto Sato hold?", "options": ["HubSpot CRM certification", "HubSpot Sales Hub certification", "HubSpot Marketing Hub certification", "HubSpot Content certification"], "answer": 2, "explanation": "'Hold a current HubSpot Marketing Hub certification.'", "difficulty": "medium"}, {"id": "xp7-t11b", "part": 7, "question": "How has Haruto Sato addressed the lack of financial services experience?", "options": ["He has completed a financial services compliance course", "He has experience in other regulated industries such as healthcare and insurance", "He is currently studying for a financial planning qualification", "He plans to shadow colleagues in the compliance team"], "answer": 1, "explanation": "'I have worked extensively with regulated industries including healthcare and insurance.'", "difficulty": "medium"}, {"id": "xp7-t11c", "part": 7, "question": "What will Stage 2 of the interview process involve?", "options": ["A second video call with the CEO", "An in-person visit with a 45-minute skills assessment", "A written case study submitted before the visit", "A group interview with other shortlisted candidates"], "answer": 1, "explanation": "'In-person at our Perth office, including a 45-minute skills assessment.'", "difficulty": "medium"}, {"id": "xp7-t11d", "part": 7, "question": "By when must Haruto Sato confirm his availability for Stage 1?", "options": ["August 29", "September 2", "September 9", "September 19"], "answer": 1, "explanation": "'Please confirm your availability for Stage 1 by September 2.'", "difficulty": "medium"}, {"id": "xp7-t11e", "part": 7, "question": "What campaign result does Haruto Sato highlight in his application?", "options": ["A 50% increase in email subscribers", "A 34% improvement in open rates through segmentation", "A doubling of lead conversion rates", "A 20% reduction in unsubscribe rates"], "answer": 1, "explanation": "'Delivered open rate improvements of 34% over two years through advanced segmentation strategies.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Product Recall Notice]\n\nSAFETY RECALL \u2014 CLEARPATH BABY STROLLER MODEL CP-550\nIssued by: Clearpath Juvenile Products\nDate: July 20\n\nClearpath Juvenile Products is recalling the CP-550 Baby Stroller (all colour variants, manufactured January 2023 \u2013 April 2024).\n\nHazard: The front wheel locking mechanism may fail under load, causing the stroller to roll unexpectedly, posing a fall risk to the occupant.\n\nSerial numbers affected: CP550-10000 to CP550-87500\n\nCustomer Instructions:\nStop using the product immediately. Register at clearpathrecall.com to receive a free repair kit. Alternatively, customers may choose a full refund by returning the unit to the original point of purchase.\n\n[Document 2 \u2013 Retailer Email]\n\nFrom: Jessica Ho <j.ho@babyworldstores.com.au>\nTo: recalls@clearpathproducts.com\nDate: July 22\n\nDear Clearpath Recall Team,\n\nWe are a retailer that sold the CP-550 through 12 of our stores. We have an estimated 180 units in customers' hands from the recalled batch. We have already begun contacting affected customers via email and in-store signage.\n\nI have two questions:\n1. Can customers return units directly to our stores for a refund, rather than going through the recall website?\n2. Will Clearpath reimburse us for the cost of processing these returns and any associated labour costs?\n\n[Document 3 \u2013 Clearpath Response]\n\nFrom: Recall Coordination Team <recalls@clearpathproducts.com>\nTo: Jessica Ho <j.ho@babyworldstores.com.au>\nDate: July 23\n\nDear Ms. Ho,\n\nThank you for your proactive communication to your customers \u2014 this is exactly the response we had hoped to see from retail partners.\n\nIn response to your questions:\n\n1. Yes, customers may return units to your stores. Please process these as standard returns and submit them to our logistics partner, ReSolve Freight, for collection. Collection kits with pre-paid shipping labels will be dispatched to all participating retailers by July 28.\n\n2. Clearpath will reimburse retailers for direct labour costs associated with processing recall returns at a flat rate of AUD 15 per unit returned. Submit a reconciliation report to recalls@clearpathproducts.com by August 31 to receive payment.\n\nThank you for your partnership.\nClearpath Recall Coordination Team", "passageTitle": "Product Recall Notice + Retailer Email + Manufacturer Response", "type": "triple", "questions": [{"id": "xp7-t12a", "part": 7, "question": "What is the safety hazard with the CP-550 stroller?", "options": ["The harness buckle can break under pressure", "The front wheel locking mechanism may fail, causing unexpected rolling", "The canopy can collapse in high wind", "The handle may detach during use"], "answer": 1, "explanation": "'The front wheel locking mechanism may fail under load, causing the stroller to roll unexpectedly.'", "difficulty": "medium"}, {"id": "xp7-t12b", "part": 7, "question": "How many CP-550 units does Baby World Stores estimate are in customers' hands?", "options": ["100", "120", "150", "180"], "answer": 3, "explanation": "'We have an estimated 180 units in customers' hands from the recalled batch.'", "difficulty": "medium"}, {"id": "xp7-t12c", "part": 7, "question": "Can customers return units to Baby World Stores for a refund?", "options": ["No, all returns must go through the recall website", "Yes, as confirmed by Clearpath", "Only if customers have a receipt", "Yes, but only for a repair kit, not a refund"], "answer": 1, "explanation": "'Yes, customers may return units to your stores.' Clearpath confirmed this in Document 3.", "difficulty": "medium"}, {"id": "xp7-t12d", "part": 7, "question": "What is the reimbursement rate Clearpath offers retailers per returned unit?", "options": ["AUD 10", "AUD 15", "AUD 20", "AUD 25"], "answer": 1, "explanation": "'At a flat rate of AUD 15 per unit returned.'", "difficulty": "medium"}, {"id": "xp7-t12e", "part": 7, "question": "By when must retailers submit their reconciliation report to receive reimbursement?", "options": ["July 28", "August 1", "August 15", "August 31"], "answer": 3, "explanation": "'Submit a reconciliation report to recalls@clearpathproducts.com by August 31 to receive payment.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Event Programme]\n\nINTERNATIONAL WOMEN IN LEADERSHIP FORUM\nDay 1 \u2014 Tuesday, March 11\nVenue: Meridian Convention Centre, Level 5\n\n08:30  Registration and welcome coffee\n09:00  Opening address: Forum Chair, Dr. Ruth Adeyemi\n09:30  Keynote: \"Redefining Leadership in the Post-Pandemic Era\"\n         Speaker: Mara Johansson, CEO, NordicPath Capital\n10:30  Panel: Breaking the Mould \u2014 Non-Traditional Career Paths to the C-Suite\n         Panelists: 4 executives from finance, tech, health, and media\n12:00  Networking lunch (sponsored by Vantex Group)\n13:30  Workshop Stream A: Negotiating with Confidence (Room 3A)\n13:30  Workshop Stream B: Navigating Organisational Politics (Room 3B)\n15:00  Afternoon tea\n15:30  Case Study Presentation: Leading Through Crisis \u2014 Lessons from the Frontline\n16:30  Day 1 Close | Evening networking reception at Level 5 Terrace\n\n[Document 2 \u2013 Delegate Email]\n\nFrom: Anita Brennan <a.brennan@telluride.com>\nTo: events@iwlf.org\nDate: March 5\nSubject: Workshop Availability \u2014 Day 1\n\nDear Events Team,\n\nI am registered for the Forum and looking forward to attending. I have a question about the afternoon workshops on Day 1.\n\nI am particularly interested in Workshop Stream B: Navigating Organisational Politics, but I also attend a standing internal call at 2:00 p.m. that typically runs until 3:00 p.m. Would I still be able to attend Stream B if I arrive 30 minutes late?\n\nAlso, I have a dinner commitment on Tuesday evening and would need to leave by 6:30 p.m. \u2014 is the networking reception likely to conclude by then?\n\nThank you,\nAnita Brennan\n\n[Document 3 \u2013 Events Team Reply]\n\nFrom: Events Team <events@iwlf.org>\nTo: Anita Brennan <a.brennan@telluride.com>\nDate: March 6\n\nDear Ms. Brennan,\n\nThank you for your message. Happy to help with both queries.\n\nRegarding Stream B: the workshop runs from 1:30 p.m. to 3:00 p.m. Arriving at 2:00 p.m. would mean missing the first 30 minutes. The facilitator does not allow entry after the first 20 minutes, as early content establishes the framework for subsequent exercises. We recommend attending Stream A instead, which covers different material and runs concurrently at the same time.\n\nRegarding the evening reception: the reception begins at 4:30 p.m. and is scheduled to conclude at 7:00 p.m. Leaving at 6:30 p.m. would allow you to attend approximately two hours of the reception, which should be feasible.\n\nWe hope this helps with your planning.\n\nEvents Team, IWLF", "passageTitle": "Forum Programme + Delegate Email + Events Team Reply", "type": "triple", "questions": [{"id": "xp7-t13a", "part": 7, "question": "Who delivers the Day 1 keynote?", "options": ["Dr. Ruth Adeyemi", "Mara Johansson from NordicPath Capital", "A panelist from the finance sector", "The Forum's founding director"], "answer": 1, "explanation": "'Keynote... Speaker: Mara Johansson, CEO, NordicPath Capital.'", "difficulty": "medium"}, {"id": "xp7-t13b", "part": 7, "question": "Who is sponsoring the networking lunch?", "options": ["NordicPath Capital", "IWLF", "Vantex Group", "Telluride"], "answer": 2, "explanation": "'Networking lunch (sponsored by Vantex Group).'", "difficulty": "medium"}, {"id": "xp7-t13c", "part": 7, "question": "Why can Anita Brennan not attend Stream B?", "options": ["Stream B is fully booked", "She has a dinner at 1:30 p.m.", "She would arrive 30 minutes late, exceeding the 20-minute entry cut-off", "She is presenting in Stream A"], "answer": 2, "explanation": "'The facilitator does not allow entry after the first 20 minutes.' Anita would arrive 30 minutes into the session.", "difficulty": "medium"}, {"id": "xp7-t13d", "part": 7, "question": "What alternative does the Events Team suggest?", "options": ["Attend Stream B virtually", "Attend Stream A, which covers different material", "Arrive early and skip the 2:00 p.m. call", "Request a recording of Stream B"], "answer": 1, "explanation": "'We recommend attending Stream A instead, which covers different material and runs concurrently.'", "difficulty": "medium"}, {"id": "xp7-t13e", "part": 7, "question": "Will Anita be able to attend the evening reception before her 6:30 p.m. dinner?", "options": ["No, the reception starts after 6:30 p.m.", "Yes, leaving at 6:30 p.m. allows about two hours at the reception", "No, the reception requires attendance until 7:00 p.m.", "Yes, but only if she registers in advance for the reception"], "answer": 1, "explanation": "'Leaving at 6:30 p.m. would allow you to attend approximately two hours of the reception.'", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Internal Policy]\n\nLOST AND FOUND POLICY\nGrandview Hotel & Spa\n\nGrandview Hotel & Spa maintains a Lost and Found register to assist guests in recovering items left on the property.\n\nITEM RETENTION:\n\u2022 Items of high value (electronics, jewellery, wallets, passports): held for 90 days\n\u2022 General items (clothing, accessories, books): held for 30 days\n\u2022 Perishable items (food, beverages): disposed of within 24 hours\n\u2022 Unclaimed items after retention period are donated to local charity or disposed of at the hotel's discretion\n\nCLAIMING AN ITEM:\n\u2022 Guests must contact the front desk or email lostandfound@grandviewhotel.com with a description of the item, the approximate date and location it was lost, and proof of identity\n\u2022 Shipping of recovered items can be arranged at the guest's cost\n\n[Document 2 \u2013 Guest Email]\n\nFrom: Patrick Nguyen <p.nguyen@email.com>\nTo: lostandfound@grandviewhotel.com\nDate: April 14\n\nHello,\n\nI stayed at Grandview Hotel on April 10\u201312 and believe I left a cashmere scarf in the spa changing room. The scarf is grey with a monogram 'P.N.' on the corner.\n\nI also think I may have left a half-eaten box of chocolates on the bedside table in my room.\n\nCould you let me know whether either item has been found, and how I can arrange to have the scarf shipped to me in Melbourne?\n\nThank you,\nPatrick Nguyen\n\n[Document 3 \u2013 Hotel Response]\n\nFrom: Lost & Found <lostandfound@grandviewhotel.com>\nTo: Patrick Nguyen <p.nguyen@email.com>\nDate: April 15\n\nDear Mr. Nguyen,\n\nThank you for getting in touch. We are happy to report that the grey cashmere scarf with the monogram 'P.N.' was recovered from the spa changing room and is being held at our front desk.\n\nRegarding the chocolates: unfortunately, perishable items are disposed of within 24 hours as per our policy, so we are unable to recover these for you.\n\nTo arrange shipping of the scarf, please reply to this email confirming your delivery address and preferred courier. We will obtain a quote and send it to you for approval before dispatching. Please note that shipping fees are payable by the guest.\n\nYour scarf will be held for 30 days from the date of this email, until May 15.\n\nKind regards,\nGrandview Lost & Found Team", "passageTitle": "Hotel Policy + Guest Email + Hotel Response", "type": "triple", "questions": [{"id": "xp7-t14a", "part": 7, "question": "How long are high-value items like jewellery held at Grandview Hotel?", "options": ["14 days", "30 days", "60 days", "90 days"], "answer": 3, "explanation": "'Items of high value... held for 90 days.'", "difficulty": "medium"}, {"id": "xp7-t14b", "part": 7, "question": "Why are the chocolates unavailable for return?", "options": ["They were claimed by another guest", "Perishable items are disposed of within 24 hours", "Room contents are cleared immediately after checkout", "The hotel policy does not cover food items"], "answer": 1, "explanation": "'Perishable items are disposed of within 24 hours as per our policy.'", "difficulty": "medium"}, {"id": "xp7-t14c", "part": 7, "question": "What must Patrick Nguyen provide to arrange shipping?", "options": ["A signed authorization form", "Proof of identity and credit card details", "Delivery address and preferred courier", "His original booking confirmation and ID"], "answer": 2, "explanation": "'Please reply to this email confirming your delivery address and preferred courier.'", "difficulty": "medium"}, {"id": "xp7-t14d", "part": 7, "question": "Until what date will the scarf be held?", "options": ["April 14", "April 30", "May 14", "May 15"], "answer": 3, "explanation": "'Your scarf will be held for 30 days from the date of this email, until May 15.'", "difficulty": "medium"}, {"id": "xp7-t14e", "part": 7, "question": "What is the policy regarding shipping costs for recovered items?", "options": ["The hotel covers shipping costs for all high-value items", "Shipping costs are shared equally between guest and hotel", "Shipping fees are payable by the guest", "Shipping is free for guests who stayed more than 2 nights"], "answer": 2, "explanation": "'Shipping fees are payable by the guest' \u2014 confirmed in both the policy and hotel response.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Venue Booking Confirmation]\n\nBOOKING CONFIRMATION\nCityscapes Conference Rooms\nBooking Reference: CCR-8814\n\nClient: Holloway Learning Solutions\nContact: Jamie Chow, Events Coordinator\nDate: Wednesday, February 19\nRoom: The Horizon Suite (capacity 60 theatre-style)\nTime: 9:00 a.m. \u2013 5:00 p.m. (full day)\nRoom Rate: AUD 750 (includes AV equipment, whiteboard, and Wi-Fi)\n\nCatering ordered:\n\u2022 Morning tea (30 people): AUD 180\n\u2022 Working lunch (30 people): AUD 480\n\nDeposit paid: AUD 300 (non-refundable)\nBalance due: AUD 1,110 (payable by February 12)\n\nCancellation policy: Cancellations within 7 days of the event forfeit the full room rate. Catering cancellations within 48 hours are charged at 50%.\n\n[Document 2 \u2013 Client Change Request]\n\nFrom: Jamie Chow <j.chow@hollowaylearning.com>\nTo: bookings@cityscapesrooms.com\nDate: February 11\n\nHi,\n\nI need to make a couple of changes to booking CCR-8814.\n\nFirst, we would like to add afternoon tea for 30 people. Could you advise the cost and whether this can be added at this stage?\n\nSecond, it now looks like we will have 40 participants, not 30. Does the Horizon Suite still comfortably accommodate 40 in a theatre-style setup?\n\nThird, I should mention that there is a possibility we may need to cancel the event. If we needed to cancel by end of day February 13, what would the financial impact be?\n\n[Document 3 \u2013 Venue Response]\n\nFrom: Bookings <bookings@cityscapesrooms.com>\nTo: Jamie Chow <j.chow@hollowaylearning.com>\nDate: February 11\n\nDear Jamie,\n\nHappy to assist with your queries.\n\n1. Afternoon tea for 30 people: Our standard afternoon tea package is AUD 6 per person, so AUD 180 for 30. We can absolutely add this to your booking. I'll update the confirmation once you give the go-ahead.\n\n2. Capacity: The Horizon Suite comfortably seats up to 60 in theatre style, so 40 participants is well within capacity.\n\n3. Cancellation scenario: A cancellation by end of day February 13 would be within the 7-day window (the event is February 19). This means the full room rate of AUD 750 would be forfeited. The catering cancellation is more than 48 hours before the event, so catering would be cancelled without charge. Your AUD 300 deposit was already applied against the room rate \u2014 so your net additional loss would be AUD 450 (the remaining room rate balance). Catering charges would not apply.\n\nPlease let us know if you have further questions.\n\nCityscapes Bookings Team", "passageTitle": "Booking Confirmation + Change Request + Venue Response", "type": "triple", "questions": [{"id": "xp7-t15a", "part": 7, "question": "What does the room rental fee include?", "options": ["AV equipment, whiteboard, and Wi-Fi", "Catering, AV equipment, and Wi-Fi", "Room setup, catering, and a dedicated coordinator", "Wi-Fi and printed materials only"], "answer": 0, "explanation": "'Room Rate: AUD 750 (includes AV equipment, whiteboard, and Wi-Fi).'", "difficulty": "medium"}, {"id": "xp7-t15b", "part": 7, "question": "What is the cost of afternoon tea for 30 people?", "options": ["AUD 150", "AUD 180", "AUD 200", "AUD 210"], "answer": 1, "explanation": "'AUD 6 per person \u00d7 30 = AUD 180.'", "difficulty": "medium"}, {"id": "xp7-t15c", "part": 7, "question": "Does the Horizon Suite accommodate 40 participants in theatre style?", "options": ["No, the maximum theatre-style capacity is 35", "Yes, it comfortably seats up to 60", "Yes, but only with a special layout request", "No, a larger room would be required"], "answer": 1, "explanation": "'The Horizon Suite comfortably seats up to 60 in theatre style.'", "difficulty": "medium"}, {"id": "xp7-t15d", "part": 7, "question": "If Holloway Learning Solutions cancels by February 13, what is the financial impact on catering?", "options": ["Catering is charged at 50% of the total", "Catering is fully forfeited", "Catering can be cancelled at no charge", "Catering is charged at the full rate"], "answer": 2, "explanation": "'The catering cancellation is more than 48 hours before the event, so catering would be cancelled without charge.'", "difficulty": "medium"}, {"id": "xp7-t15e", "part": 7, "question": "If the event is cancelled by February 13, how much additional loss would Holloway face beyond the deposit?", "options": ["AUD 300", "AUD 450", "AUD 750", "AUD 1,110"], "answer": 1, "explanation": "'Your net additional loss would be AUD 450 (the remaining room rate balance).' The AUD 300 deposit was already paid.", "difficulty": "medium"}]}, {"passage": "[Document 1 \u2013 Company Announcement]\n\nTo: All Staff\nFrom: CEO, Renata Cross\nDate: May 1\nSubject: Acquisition of Bluefield Analytics \u2014 Your Questions Answered\n\nI am pleased to announce that Pinnacle Group has today completed the acquisition of Bluefield Analytics, a data intelligence company based in Melbourne.\n\nThis acquisition strengthens our capability in predictive analytics and will allow us to offer clients integrated reporting solutions we were not previously able to provide.\n\nI know change raises questions. Here are answers to the most common ones:\n\nQ: Will there be any redundancies?\nA: There are no plans for redundancies at this stage. Both teams will continue in their current roles.\n\nQ: Will Bluefield operate as a separate brand?\nA: Yes, for an initial period of 12 months. After that, a brand integration decision will be made.\n\nQ: When will staff from both organisations meet?\nA: A combined all-hands meeting is being organised for May 22 at our Sydney headquarters.\n\nMore information will be shared as plans develop. I look forward to the possibilities this brings.\n\nRenata Cross, CEO\n\n[Document 2 \u2013 Internal Chat Message]\n\nFrom: Lila Moss\nTo: Kevin Park\nDate: May 2\n\nKev \u2014 did you see the CEO announcement about Bluefield? I know you've been following their analytics platform for a while. What do you make of it?\n\n[Document 3 \u2013 Response Message]\n\nFrom: Kevin Park\nTo: Lila Moss\nDate: May 2\n\nYeah, I did! Honestly pretty excited \u2014 I've used their DataScope platform in a previous role and it's genuinely excellent. Way more powerful than what we're using now for client reporting.\n\nI'm a bit cautious about the 'no redundancies at this stage' line though \u2014 'at this stage' leaves a lot of room. I hope that's just careful legal language and not a signal of things to come.\n\nI'm planning to go to the May 22 all-hands \u2014 should be interesting to meet the Bluefield team. Are you going?", "passageTitle": "CEO Announcement + Internal Chat Exchange", "type": "triple", "questions": [{"id": "xp7-t16a", "part": 7, "question": "What capability does the Bluefield acquisition strengthen for Pinnacle Group?", "options": ["Financial forecasting and risk management", "Cybersecurity and data protection", "Predictive analytics and integrated reporting", "Customer relationship management"], "answer": 2, "explanation": "'Strengthens our capability in predictive analytics and will allow us to offer clients integrated reporting solutions.'", "difficulty": "medium"}, {"id": "xp7-t16b", "part": 7, "question": "How long will Bluefield operate as a separate brand?", "options": ["6 months", "12 months", "18 months", "Until the next financial year"], "answer": 1, "explanation": "'Yes, for an initial period of 12 months. After that, a brand integration decision will be made.'", "difficulty": "medium"}, {"id": "xp7-t16c", "part": 7, "question": "When is the combined all-hands meeting scheduled?", "options": ["May 1", "May 2", "May 15", "May 22"], "answer": 3, "explanation": "'A combined all-hands meeting is being organised for May 22 at our Sydney headquarters.'", "difficulty": "medium"}, {"id": "xp7-t16d", "part": 7, "question": "What is Kevin Park's concern about the CEO's statement?", "options": ["He does not believe the acquisition will benefit clients", "He is worried about a change in CEO leadership", "The phrase 'at this stage' implies redundancies may still occur", "He thinks the Bluefield brand should not be retained"], "answer": 2, "explanation": "'I'm a bit cautious about the 'no redundancies at this stage' line though \u2014 'at this stage' leaves a lot of room.'", "difficulty": "medium"}, {"id": "xp7-t16e", "part": 7, "question": "What does Kevin Park say about Bluefield's DataScope platform?", "options": ["He has never used it but is curious to learn", "He used it in a previous role and considers it excellent", "He thinks it is similar to what Pinnacle currently uses", "He is concerned about its compatibility with Pinnacle's systems"], "answer": 1, "explanation": "'I've used their DataScope platform in a previous role and it's genuinely excellent. Way more powerful than what we're using now.'", "difficulty": "medium"}]}, {"passageTitle": "Email: Project Handover Notice", "type": "single", "passage": "From: Renata Okafor <r.okafor@pinnaclegroup.com>\nTo: All Project Team Members\nDate: September 4\nSubject: Project Handover \u2014 Halcyon CRM Implementation\n\nDear Team,\n\nI am writing to inform you that effective September 15, the day-to-day management of the Halcyon CRM Implementation Project will be transferred to Mr. Daniel Chow, who joins us from our Singapore office.\n\nMr. Chow brings over a decade of CRM integration experience, having successfully led similar projects for three of our regional offices. During the transition period, I will remain available to advise and ensure continuity.\n\nAll project documentation, including the risk register, stakeholder matrix, and current sprint board, has been uploaded to the shared drive at the link below. Team members are asked to brief Mr. Chow on any outstanding items by September 10.\n\nPlease join me in welcoming Daniel to the team. I am confident the project is in excellent hands.\n\nBest regards,\nRenata Okafor\nDirector, Technology Projects", "questions": [{"id": "ns01-a", "part": 7, "question": "Why is the project management being transferred?", "options": ["Ms. Okafor is leaving the company", "Mr. Chow is taking over the role", "The project has been completed early", "A new client has been assigned"], "answer": 1, "explanation": "Detail: \"day-to-day management will be transferred to Mr. Daniel Chow\" = r\u00f5 r\u00e0ng t\u1eeb email."}, {"id": "ns01-b", "part": 7, "question": "What is most likely the purpose of Ms. Okafor's email?", "options": ["To announce Mr. Chow's promotion", "To inform the team of a leadership transition and ensure smooth handover", "To request feedback on the project's current status", "To introduce a new client requirement"], "answer": 1, "explanation": "Purpose: email th\u00f4ng b\u00e1o chuy\u1ec3n giao l\u00e3nh \u0111\u1ea1o d\u1ef1 \u00e1n v\u00e0 y\u00eau c\u1ea7u chu\u1ea9n b\u1ecb t\u00e0i li\u1ec7u \u2014 m\u1ee5c \u0111\u00edch k\u00e9p: th\u00f4ng b\u00e1o + h\u00e0nh \u0111\u1ed9ng c\u1ee5 th\u1ec3."}, {"id": "ns01-c", "part": 7, "question": "What are team members asked to do by September 10?", "options": ["Upload all project files to the shared drive", "Brief Mr. Chow on outstanding items", "Complete the current sprint deliverables", "Submit a project status report to Ms. Okafor"], "answer": 1, "explanation": "Detail: \"asked to brief Mr. Chow on any outstanding items by September 10\"."}, {"id": "p7-pur09", "part": 7, "question": "Why did Renata Okafor write this email?", "options": ["To announce her own resignation from the company", "To notify the team of a project leadership transition and next steps", "To introduce a new project to the team", "To request feedback on the current project's progress"], "answer": 1, "explanation": "Purpose: email th\u00f4ng b\u00e1o chuy\u1ec3n giao qu\u1ea3n l\u00fd d\u1ef1 \u00e1n t\u1eeb Renata sang Mr. Chow, \u0111\u1ed3ng th\u1eddi h\u01b0\u1edbng d\u1eabn c\u00e1c b\u01b0\u1edbc c\u1ea7n l\u00e0m tr\u01b0\u1edbc ng\u00e0y 10/9."}]}, {"passageTitle": "Notice: Annual Fire Safety Inspection", "type": "single", "passage": "BUILDING MANAGEMENT NOTICE\nAll Tenants \u2014 Pacific Commerce Tower, Floors 14\u201328\n\nANNUAL FIRE SAFETY INSPECTION \u2014 IMPORTANT INFORMATION\n\nThe annual fire safety inspection, required under the Building Code (Commercial Premises) Act, will take place on Friday, October 18, from 7:00 a.m. to 5:00 p.m.\n\nDuring this time, all fire suppression systems, emergency exits, and smoke detection equipment on floors 14\u201328 will be tested. Brief periods of alarm activation may occur throughout the day as part of the testing process. Tenants are advised that these activations are planned and do not require evacuation.\n\nAccess to stairwells 2 and 3 will be restricted between 9:00 a.m. and 1:00 p.m. Stairwell 1 will remain accessible at all times. The inspection team will require unobstructed access to all utility rooms and fire equipment cabinets.\n\nShould you have any questions or require special arrangements, please contact building management at bm@pacificcommerce.com.au before October 15.", "questions": [{"id": "ns02-a", "part": 7, "question": "Which stairwell will remain accessible throughout the entire inspection?", "options": ["Stairwell 1 only", "Stairwells 1 and 2", "Stairwell 3 only", "All stairwells will remain open"], "answer": 0, "explanation": "Detail: \"Stairwell 1 will remain accessible at all times\" \u2014 Stairwells 2 and 3 restricted 9am\u20131pm."}, {"id": "ns02-b", "part": 7, "question": "What should tenants do if they hear alarm activations during the inspection?", "options": ["Evacuate immediately via the nearest exit", "Contact emergency services", "Remain in place as the activations are planned", "Report the alarm to building management"], "answer": 2, "explanation": "Detail: \"these activations are planned and do not require evacuation\" = kh\u00f4ng c\u1ea7n s\u01a1 t\u00e1n."}, {"id": "ns02-c", "part": 7, "question": "Which of the following is NOT mentioned as something that will be tested during the inspection?", "options": ["Fire suppression systems", "Emergency lighting", "Smoke detection equipment", "Emergency exit doors"], "answer": 1, "explanation": "NOT TRUE: Notice lists fire suppression, emergency exits, and smoke detection. Emergency lighting is NOT mentioned as part of the testing items."}, {"id": "p7-pur10", "part": 7, "question": "What is the main purpose of this notice?", "options": ["To announce the permanent upgrade of fire safety systems", "To inform tenants of an upcoming annual inspection and related access restrictions", "To report the results of a previous safety audit", "To recruit volunteer fire wardens from among the tenants"], "answer": 1, "explanation": "Purpose: th\u00f4ng b\u00e1o ki\u1ec3m tra an to\u00e0n h\u00e0ng n\u0103m, th\u00f4ng b\u00e1o c\u00e1c h\u1ea1n ch\u1ebf quy\u1ec1n truy c\u1eadp trong ng\u00e0y ki\u1ec3m tra v\u00e0 h\u01b0\u1edbng d\u1eabn li\u00ean h\u1ec7 n\u1ebfu c\u1ea7n."}]}, {"passageTitle": "Article: The Return of the Office", "type": "single", "passage": "THE RETURN OF THE OFFICE \u2014 RETHINKING HYBRID WORK\nBusiness & Management Quarterly | July Edition\n\nThree years after the widespread adoption of remote work, a growing number of organisations are revisiting their hybrid work policies \u2014 and the results are far from uniform.\n\nWhile some firms, particularly in the technology sector, have embraced permanent flexible arrangements, others \u2014 including several major financial institutions \u2014 have recently issued mandates requiring employees to return to the office for a minimum of four days per week.\n\nProponents of in-office work cite benefits including stronger team cohesion, faster informal communication, and reduced onboarding time for new employees. Critics, however, argue that rigid return-to-office mandates risk alienating high-performing staff who have demonstrated sustained productivity while working remotely.\n\nIndustry analysts suggest that the most successful organisations will be those that treat hybrid work not as a binary choice between remote and in-office, but as a flexible framework tailored to the specific needs of different teams and roles.", "questions": [{"id": "ns03-a", "part": 7, "question": "Which industry has most notably embraced permanent flexible work arrangements?", "options": ["Financial services", "Healthcare", "Technology", "Manufacturing"], "answer": 2, "explanation": "Detail: \"particularly in the technology sector, have embraced permanent flexible arrangements\"."}, {"id": "ns03-b", "part": 7, "question": "In the article, the word \"mandate\" is closest in meaning to", "options": ["request", "requirement", "suggestion", "announcement"], "answer": 1, "explanation": "WIC: \"return-to-office mandates\" = y\u00eau c\u1ea7u b\u1eaft bu\u1ed9c, ch\u1ec9 th\u1ecb. \"Requirement\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t \u2014 mang t\u00ednh \u00e9p bu\u1ed9c."}, {"id": "ns03-c", "part": 7, "question": "Which of the following is NOT listed as a benefit of in-office work according to the article?", "options": ["Faster informal communication", "Lower office operating costs", "Stronger team cohesion", "Reduced onboarding time"], "answer": 1, "explanation": "NOT TRUE: Article lists team cohesion, faster communication, and reduced onboarding. Lower operating costs is NOT mentioned as a benefit of in-office work."}, {"id": "p7-pur05", "part": 7, "question": "What is the main purpose of this article?", "options": ["To argue that all companies should mandate a full return to office work", "To examine different approaches organisations are taking to hybrid work arrangements", "To report on declining employee productivity during remote work periods", "To announce new government guidelines on workplace attendance"], "answer": 1, "explanation": "Purpose: b\u00e0i b\u00e1o ph\u00e2n t\u00edch xu h\u01b0\u1edbng \u0111a d\u1ea1ng trong ch\u00ednh s\u00e1ch hybrid work \u2014 kh\u00f4ng \u1ee7ng h\u1ed9 hay ph\u1ea3n \u0111\u1ed1i, m\u00e0 tr\u00ecnh b\u00e0y c\u00e1c g\u00f3c nh\u00ecn kh\u00e1c nhau. \u0110\u00e2y l\u00e0 m\u1ee5c \u0111\u00edch c\u1ee7a b\u00e0i ph\u00e2n t\u00edch ng\u00e0nh."}]}, {"passageTitle": "Memo: Updated Procurement Policy", "type": "single", "passage": "INTERNAL MEMORANDUM\n\nTo: All Department Managers\nFrom: Procurement and Finance Division\nDate: November 3\nRe: Updated Procurement Policy \u2014 Effective January 1\n\nFollowing a comprehensive review of our procurement practices, the following policy changes will take effect from January 1 next year.\n\n1. All purchases above USD 2,500 must now be approved by both the department head and the Chief Financial Officer before an order is placed.\n2. Preferred supplier agreements will be reviewed annually rather than on a three-year cycle.\n3. New supplier onboarding will require a compliance check completed through the updated Vendor Portal.\n\nManagers are asked to attend one of three briefing sessions to be held on November 14, 16, and 18 at 10:00 a.m. in Conference Room B. Attendance at one session is required.\n\nA comprehensive FAQ document has been uploaded to the company intranet. If you have further questions, please contact procurement@company.com.", "questions": [{"id": "ns04-a", "part": 7, "question": "How often will preferred supplier agreements be reviewed under the new policy?", "options": ["Every six months", "Every year", "Every two years", "Every three years"], "answer": 1, "explanation": "Detail: \"reviewed annually rather than on a three-year cycle\" = m\u1ed7i n\u0103m thay v\u00ec 3 n\u0103m m\u1ed9t l\u1ea7n."}, {"id": "ns04-b", "part": 7, "question": "What is the purpose of the briefing sessions scheduled in November?", "options": ["To introduce new suppliers to the procurement team", "To inform managers of the upcoming policy changes", "To review the performance of preferred suppliers", "To train staff on using the new Vendor Portal"], "answer": 1, "explanation": "Purpose: \"Managers asked to attend briefing sessions\" about the updated procurement policy = m\u1ee5c \u0111\u00edch l\u00e0 th\u00f4ng b\u00e1o thay \u0111\u1ed5i ch\u00ednh s\u00e1ch."}, {"id": "ns04-c", "part": 7, "question": "Which of the following is NOT a change introduced by the new policy?", "options": ["Dual approval for large purchases", "Annual review of supplier agreements", "A new online onboarding process for suppliers", "Automatic renewal of all existing supplier contracts"], "answer": 3, "explanation": "NOT TRUE: Policy changes include dual approval, annual reviews, and new onboarding. Automatic renewal of existing contracts is NOT mentioned \u2014 this is not a stated change."}, {"id": "p7-pur11", "part": 7, "question": "Why was this memo distributed to all department managers?", "options": ["To seek feedback on proposed changes to procurement procedures", "To notify managers of new procurement policy changes effective January 1", "To announce the appointment of a new Chief Financial Officer", "To remind managers of existing procurement guidelines"], "answer": 1, "explanation": "Purpose: memo th\u00f4ng b\u00e1o thay \u0111\u1ed5i ch\u00ednh s\u00e1ch mua s\u1eafm c\u00f3 hi\u1ec7u l\u1ef1c t\u1eeb 1/1 v\u00e0 y\u00eau c\u1ea7u tham d\u1ef1 briefing session \u2014 m\u1ee5c \u0111\u00edch l\u00e0 th\u00f4ng b\u00e1o + h\u00e0nh \u0111\u1ed9ng c\u1ee5 th\u1ec3."}]}, {"passageTitle": "Advertisement: Meridian Executive Search Services", "type": "single", "passage": "MERIDIAN EXECUTIVE SEARCH\nConnecting Exceptional Leaders with Exceptional Organisations\n\nAt Meridian Executive Search, we specialise in identifying and placing senior leaders across the Asia-Pacific region. With offices in Sydney, Singapore, and Kuala Lumpur, and a network of over 15,000 pre-screened candidates, we deliver results that matter.\n\nOUR SERVICES\n\u2022 Retained Executive Search: End-to-end recruitment for C-suite and VP-level roles, with full market mapping and competitor analysis.\n\u2022 Contingency Recruitment: For mid-to-senior management positions, with no placement fee until a successful hire is made.\n\u2022 Talent Advisory: Strategic workforce planning and succession management for boards and senior leadership teams.\n\nWHY CLIENTS CHOOSE MERIDIAN\nOur average time-to-placement for retained searches is 47 days \u2014 30% faster than the industry average. 94% of our placements remain in role after 12 months.\n\nTo discuss your organisation's leadership needs, contact us at info@meridianexec.com or visit www.meridianexec.com.", "questions": [{"id": "ns05-a", "part": 7, "question": "What is unique about the Contingency Recruitment service?", "options": ["It includes competitor market analysis", "It is limited to C-suite positions only", "No fee is charged until a successful placement is made", "It is only available in the Sydney office"], "answer": 2, "explanation": "Detail: \"no placement fee until a successful hire is made\" = ch\u1ec9 thanh to\u00e1n khi tuy\u1ec3n th\u00e0nh c\u00f4ng \u2014 \u0111i\u1ec3m \u0111\u1eb7c bi\u1ec7t c\u1ee7a Contingency."}, {"id": "ns05-b", "part": 7, "question": "In the advertisement, the word \"retained\" as used in \"Retained Executive Search\" most likely means", "options": ["kept on file", "engaged exclusively", "recommended by clients", "guaranteed to succeed"], "answer": 1, "explanation": "WIC: \"Retained search\" = d\u1ecbch v\u1ee5 tuy\u1ec3n d\u1ee5ng \u0111\u1ed9c quy\u1ec1n theo h\u1ee3p \u0111\u1ed3ng tr\u1ea3 tr\u01b0\u1edbc. \"Engaged exclusively\" l\u00e0 di\u1ec5n \u0111\u1ea1t \u0111\u00fang nh\u1ea5t \u2014 client gi\u1eef exclusivity c\u1ee7a c\u00f4ng ty tuy\u1ec3n d\u1ee5ng."}, {"id": "ns05-c", "part": 7, "question": "What does the statistic about time-to-placement suggest about Meridian's service?", "options": ["Meridian has the largest candidate database in the region", "Meridian places candidates faster than most competitors", "Meridian only accepts the most straightforward recruitment assignments", "Meridian has recently expanded its network of offices"], "answer": 1, "explanation": "Inference: \"47 days \u2014 30% faster than industry average\" = Meridian ho\u00e0n th\u00e0nh nhanh h\u01a1n h\u1ea7u h\u1ebft \u0111\u1ed1i th\u1ee7. Con s\u1ed1 so s\u00e1nh n\u00e0y tr\u1ef1c ti\u1ebfp cho th\u1ea5y l\u1ee3i th\u1ebf t\u1ed1c \u0111\u1ed9."}, {"id": "p7-pur12", "part": 7, "question": "What is the primary purpose of this advertisement?", "options": ["To report on industry trends in executive recruitment", "To promote Meridian's executive search services to potential clients", "To announce the opening of a new Meridian office in Kuala Lumpur", "To recruit new consultants to join the Meridian team"], "answer": 1, "explanation": "Purpose: qu\u1ea3ng c\u00e1o gi\u1edbi thi\u1ec7u d\u1ecbch v\u1ee5, s\u1ed1 li\u1ec7u th\u00e0nh t\u00edch v\u00e0 l\u1eddi m\u1eddi li\u00ean h\u1ec7 \u2014 m\u1ee5c \u0111\u00edch marketing l\u00e0 thu h\u00fat kh\u00e1ch h\u00e0ng doanh nghi\u1ec7p ti\u1ec1m n\u0103ng."}]}, {"passageTitle": "Web Page: Zenith Cloud Storage Plans", "type": "single", "passage": "ZENITH CLOUD STORAGE \u2014 PLANS & PRICING\n\nChoose the plan that fits your needs. All plans include 256-bit AES encryption, 24/7 technical support, and a 30-day free trial.\n\nSTARTER \u2014 USD 8/month\n50 GB storage | 1 user | Web access only | Basic file sharing\n\nPROFESSIONAL \u2014 USD 19/month\n500 GB storage | Up to 5 users | Desktop + mobile app | Advanced file sharing + version history (30 days) | Priority support\n\nBUSINESS \u2014 USD 49/month\n5 TB storage | Up to 25 users | All Professional features | Extended version history (1 year) | Single Sign-On (SSO) | Admin dashboard + audit logs | Dedicated account manager\n\nENTERPRISE \u2014 Custom pricing\nUnlimited storage | Unlimited users | All Business features | Custom SLA | On-premise deployment option | 24/7 dedicated support line\n\nAll paid plans are billed annually. Monthly billing is available at a 20% premium.\nUpgrade or downgrade your plan at any time. Data is retained for 90 days after cancellation.", "questions": [{"id": "ns06-a", "part": 7, "question": "Which plan would best suit a company of 10 employees needing mobile access and version history?", "options": ["Starter", "Professional", "Business", "Enterprise"], "answer": 2, "explanation": "Detail: Business plan = up to 25 users + mobile app + version history. Professional = only 5 users max. 10 employees requires Business plan."}, {"id": "ns06-b", "part": 7, "question": "What is stated about customers who choose monthly billing?", "options": ["They receive a 20% discount compared to annual billing", "They pay 20% more than the annual rate", "They are limited to the Professional plan only", "They must contact Zenith to arrange payment"], "answer": 1, "explanation": "Detail: \"Monthly billing is available at a 20% premium\" = 20% \u0111\u1eaft h\u01a1n so v\u1edbi h\u00f3a \u0111\u01a1n h\u00e0ng n\u0103m."}, {"id": "ns06-c", "part": 7, "question": "Which feature is available ONLY on the Business plan and above?", "options": ["Desktop app access", "Version history", "Single Sign-On (SSO)", "Priority customer support"], "answer": 2, "explanation": "NOT TRUE/Detail: SSO listed only for Business and Enterprise. Desktop app = Professional+. Version history = Professional+. Priority support = Professional+. SSO is exclusive to Business+."}, {"id": "p7-pur06", "part": 7, "question": "What is the primary purpose of this web page?", "options": ["To compare Zenith's services with competitors", "To provide detailed technical specifications for IT administrators", "To help potential customers choose the most suitable storage plan", "To announce a promotion on annual subscriptions"], "answer": 2, "explanation": "Purpose: trang web tr\u00ecnh b\u00e0y c\u00e1c g\u00f3i d\u1ecbch v\u1ee5 v\u1edbi t\u00ednh n\u0103ng v\u00e0 gi\u00e1 \u2014 m\u1ee5c \u0111\u00edch ch\u00ednh l\u00e0 gi\u00fap kh\u00e1ch h\u00e0ng ti\u1ec1m n\u0103ng so s\u00e1nh v\u00e0 l\u1ef1a ch\u1ecdn g\u00f3i ph\u00f9 h\u1ee3p nh\u1ea5t."}]}, {"passageTitle": "Letter: Lease Renewal Offer", "type": "single", "passage": "Pacific Properties Group\nLevel 15, 120 King Street, Sydney NSW 2000\n\nOctober 7\n\nMs. Sarah Kim\nUnit 8B, Harbour View Apartments\n48 Marine Parade, Manly NSW 2095\n\nDear Ms. Kim,\n\nWe are pleased to advise that your current tenancy agreement for Unit 8B will expire on January 31. We would like to offer you the opportunity to renew your lease for a further 12 months.\n\nThe proposed new monthly rental rate is AUD 2,850, an increase of 6.2% from your current rate of AUD 2,685. This adjustment reflects current market conditions in the Manly area, where comparable properties are listed at between AUD 2,800 and AUD 3,100 per month.\n\nShould you wish to accept this offer, please sign and return the enclosed renewal agreement by November 7. If we do not receive a response by this date, we will assume that you do not intend to renew, and we will begin advertising the property for new tenants.\n\nFor any queries, please contact our property manager, Mr. David Leung, at d.leung@pacificproperties.com.au.\n\nYours sincerely,\nHelen Marsh\nTenancy Manager, Pacific Properties Group", "questions": [{"id": "ns07-a", "part": 7, "question": "By how much would Ms. Kim's rent increase under the proposed renewal?", "options": ["AUD 115", "AUD 150", "AUD 165", "AUD 215"], "answer": 2, "explanation": "Detail: 2850 \u2212 2685 = AUD 165 increase per month."}, {"id": "ns07-b", "part": 7, "question": "What will happen if Ms. Kim does not respond by November 7?", "options": ["She will receive a final extension to December 31", "The property will be listed for new tenants", "Her lease will be automatically renewed at the current rate", "She will be charged a penalty for late response"], "answer": 1, "explanation": "Detail: \"we will assume you do not intend to renew, and will begin advertising the property\" = s\u1ebd b\u1eaft \u0111\u1ea7u cho thu\u00ea l\u1ea1i."}, {"id": "ns07-c", "part": 7, "question": "In the letter, the phrase \"reflects current market conditions\" suggests that", "options": ["The proposed rate is lower than comparable properties", "The increase is justified by comparable rental prices in the area", "Pacific Properties is required by law to increase rent", "The property market in Manly has been declining"], "answer": 1, "explanation": "Inference: \"reflects market conditions\" + \"comparable properties listed at AUD 2,800\u20133,100\" = m\u1ee9c t\u0103ng \u0111\u01b0\u1ee3c \u0111\u01b0a ra d\u1ef1a tr\u00ean gi\u00e1 th\u1ecb tr\u01b0\u1eddng hi\u1ec7n t\u1ea1i khu v\u1ef1c Manly."}, {"id": "p7-pur13", "part": 7, "question": "Why did Pacific Properties Group send this letter?", "options": ["To inform Ms. Kim that her lease has been terminated", "To offer Ms. Kim the opportunity to renew her lease at a new rate", "To apologise for a recent maintenance issue at the property", "To confirm receipt of Ms. Kim's renewal application"], "answer": 1, "explanation": "Purpose: th\u01b0 \u0111\u1ec1 ngh\u1ecb gia h\u1ea1n h\u1ee3p \u0111\u1ed3ng thu\u00ea nh\u00e0 v\u1edbi m\u1ee9c gi\u00e1 m\u1edbi \u2014 m\u1ee5c \u0111\u00edch r\u00f5 r\u00e0ng l\u00e0 m\u1eddi thu\u00ea ti\u1ebfp v\u00e0 th\u00f4ng b\u00e1o m\u1ee9c gi\u00e1 t\u0103ng."}]}, {"passageTitle": "Report: Q3 Employee Satisfaction Summary", "type": "single", "passage": "EMPLOYEE SATISFACTION SURVEY \u2014 Q3 RESULTS SUMMARY\nPrepared by: People & Culture Team | Distribution: Senior Management\n\nOverall Satisfaction Score: 7.4 / 10 (Q2: 6.9)\n\nHighlights:\n\u2022 Management Communication improved significantly (+18%) following the introduction of monthly all-hands meetings in July.\n\u2022 Work-Life Balance remained the highest-rated category for the third consecutive quarter (8.3/10).\n\u2022 Career Development opportunities received the lowest rating (6.1/10), consistent with Q2 results.\n\u2022 84% of respondents reported feeling valued by their immediate manager (up from 79% in Q2).\n\nAreas Requiring Attention:\nCareer development remains the most frequently cited concern in open-ended responses. Employees across departments mentioned limited access to training programmes and unclear promotion criteria as key issues.\n\nNext Steps:\nThe People & Culture team will present a proposed Learning & Development framework to the executive committee in October. Implementation is planned for Q1 of the following year.", "questions": [{"id": "ns08-a", "part": 7, "question": "What factor contributed most directly to the improvement in Management Communication scores?", "options": ["A new performance review process introduced in Q2", "Monthly all-hands meetings that began in July", "A survey-based feedback programme for managers", "The appointment of a new Head of Communications"], "answer": 1, "explanation": "Detail: \"Management Communication improved significantly following the introduction of monthly all-hands meetings in July\"."}, {"id": "ns08-b", "part": 7, "question": "In the report, the word \"consecutive\" is closest in meaning to", "options": ["successive", "highest", "significant", "improved"], "answer": 0, "explanation": "WIC: \"third consecutive quarter\" = ba qu\u00fd li\u00ean ti\u1ebfp. \"Successive\" = x\u1ea3y ra li\u00ean t\u1ee5c nhau, l\u00e0 t\u1eeb \u0111\u1ed3ng ngh\u0129a chu\u1ea9n nh\u1ea5t."}, {"id": "ns08-c", "part": 7, "question": "What can be inferred about the Career Development category from the Q3 results?", "options": ["It improved significantly compared to Q2", "It has been a persistent concern across multiple quarters", "It received more positive comments than any other category", "It is expected to be resolved by the end of Q3"], "answer": 1, "explanation": "Inference: \"consistent with Q2 results\" + \"most frequently cited concern\" = v\u1ea5n \u0111\u1ec1 xu\u1ea5t hi\u1ec7n li\u00ean t\u1ee5c, ch\u01b0a \u0111\u01b0\u1ee3c c\u1ea3i thi\u1ec7n qua nhi\u1ec1u qu\u00fd."}, {"id": "p7-pur14", "part": 7, "question": "What is the primary purpose of this report?", "options": ["To justify a budget request for new HR initiatives", "To present Q3 employee satisfaction findings and highlight areas for action", "To announce a new recognition programme for high-performing staff", "To summarise feedback from a specific department"], "answer": 1, "explanation": "Purpose: b\u00e1o c\u00e1o t\u00f3m t\u1eaft k\u1ebft qu\u1ea3 kh\u1ea3o s\u00e1t Q3, n\u00eau b\u1eadt \u0111i\u1ec3m c\u1ea3i thi\u1ec7n v\u00e0 \u0111i\u1ec3m y\u1ebfu c\u1ea7n x\u1eed l\u00fd, \u0111\u1ec1 xu\u1ea5t b\u01b0\u1edbc ti\u1ebfp theo \u2014 \u0111\u00e2y l\u00e0 m\u1ee5c \u0111\u00edch \u0111i\u1ec3n h\u00ecnh c\u1ee7a HR survey summary."}]}, {"passageTitle": "Notice: Visitor Access Policy Update", "type": "single", "passage": "RIVERGATE BUSINESS PARK\nNotice to All Tenants\n\nUPDATED VISITOR ACCESS POLICY \u2014 EFFECTIVE DECEMBER 1\n\nTo enhance the security of our facilities, Rivergate Business Park will be implementing an updated visitor access policy from December 1.\n\nKey changes:\n1. All visitors must register at the reception desk and present valid photo identification upon arrival.\n2. Visitor badges must be worn visibly at all times while on the premises.\n3. Unescorted visitor access will no longer be permitted in areas beyond the ground floor lobby.\n4. Contractors working on-site for more than one day must complete a site induction before commencing work.\n\nTenants are responsible for informing their guests of these requirements before their visit. Visitors who do not comply with the new policy will be asked to leave the premises.\n\nA digital pre-registration system will be introduced in January to allow tenants to register expected visitors in advance. Further details will be communicated prior to launch.\n\nFor assistance, please contact building security at security@rivergatebp.com.", "questions": [{"id": "ns09-a", "part": 7, "question": "What are tenants required to do under the new policy?", "options": ["Accompany all visitors at all times", "Notify their visitors of the new requirements before their visit", "Submit a weekly list of expected visitors to reception", "Collect visitor badges on behalf of their guests"], "answer": 1, "explanation": "Detail: \"Tenants are responsible for informing their guests of these requirements before their visit\"."}, {"id": "ns09-b", "part": 7, "question": "What restriction applies to unescorted visitors under the new policy?", "options": ["They may not use the car park", "They are limited to the ground floor lobby", "They must leave the premises by 6:00 p.m.", "They may not use the lifts without a tenant escort"], "answer": 1, "explanation": "Detail: \"Unescorted visitor access will no longer be permitted in areas beyond the ground floor lobby\"."}, {"id": "ns09-c", "part": 7, "question": "What can be inferred about the digital pre-registration system?", "options": ["It has already been tested by several tenants", "It is not yet available but will be introduced soon", "It will replace the physical visitor badge system", "It was specifically requested by tenants in a survey"], "answer": 1, "explanation": "Inference: \"will be introduced in January...further details will be communicated\" = ch\u01b0a ra m\u1eaft, s\u1ebd \u0111\u01b0\u1ee3c tri\u1ec3n khai trong t\u01b0\u01a1ng lai g\u1ea7n."}, {"id": "p7-pur15", "part": 7, "question": "What is the main purpose of this notice?", "options": ["To report a recent security incident at the building", "To inform tenants of an updated visitor access policy effective December 1", "To introduce a new digital access system for all tenants", "To request feedback on the current visitor management process"], "answer": 1, "explanation": "Purpose: th\u00f4ng b\u00e1o c\u1eadp nh\u1eadt ch\u00ednh s\u00e1ch ti\u1ebfp kh\u00e1ch c\u00f3 hi\u1ec7u l\u1ef1c t\u1eeb 1/12, m\u00f4 t\u1ea3 c\u00e1c thay \u0111\u1ed5i v\u00e0 y\u00eau c\u1ea7u c\u1ee7a ng\u01b0\u1eddi thu\u00ea nh\u00e0."}]}, {"passageTitle": "Web Page: Apex Learning Platform Pricing", "type": "single", "passage": "APEX LEARNING PLATFORM\nUpskill your team. Anywhere, anytime.\n\nPLANS FOR TEAMS\n\nTEAM STARTER \u2014 USD 12 per user / month (billed annually)\n\u2022 Access to 800+ courses in business, technology, and communication\n\u2022 Progress tracking dashboard for managers\n\u2022 Mobile and desktop access\n\u2022 Up to 20 users\n\nTEAM PRO \u2014 USD 22 per user / month (billed annually)\n\u2022 All Starter features\n\u2022 2,000+ courses including live webinars and expert-led workshops\n\u2022 Customisable learning paths\n\u2022 Integration with popular HR systems (SAP, Workday)\n\u2022 Up to 100 users\n\u2022 Dedicated customer success manager\n\nENTERPRISE \u2014 Contact us for custom pricing\n\u2022 Unlimited users\n\u2022 Full content library (3,500+ courses)\n\u2022 Custom branding and white-labelling\n\u2022 Advanced analytics and reporting\n\u2022 API access for custom integrations\n\nFree trial: 14 days, no credit card required.\nVolume discounts available for annual plans with 50+ users.", "questions": [{"id": "ns10-a", "part": 7, "question": "Which plan includes integration with HR management systems?", "options": ["Team Starter only", "Team Pro only", "Both Team Starter and Team Pro", "Enterprise only"], "answer": 1, "explanation": "Detail: \"Integration with popular HR systems (SAP, Workday)\" is listed only under Team Pro."}, {"id": "ns10-b", "part": 7, "question": "What is stated about the free trial?", "options": ["It is available only for Enterprise customers", "It requires a credit card to activate", "It lasts for 14 days with no credit card required", "It provides access to only a limited course selection"], "answer": 2, "explanation": "Detail: \"Free trial: 14 days, no credit card required.\""}, {"id": "ns10-c", "part": 7, "question": "What can be inferred about a company with 75 employees interested in an annual plan?", "options": ["They would be eligible for a volume discount", "They must choose the Enterprise plan", "They cannot use the Team Pro plan due to user limits", "They would pay the same price as a 50-user team"], "answer": 0, "explanation": "Inference: \"Volume discounts available for annual plans with 50+ users.\" A 75-user company exceeds 50 users on an annual plan \u2192 eligible for volume discount."}, {"id": "p7-pur07", "part": 7, "question": "What is the primary purpose of this web page?", "options": ["To introduce new courses added to the Apex platform", "To outline the available team subscription plans and their features", "To announce a price reduction for enterprise customers", "To provide technical support information for existing subscribers"], "answer": 1, "explanation": "Purpose: trang pricing gi\u1edbi thi\u1ec7u c\u00e1c g\u00f3i Team Starter, Team Pro, Enterprise \u2014 m\u1ee5c \u0111\u00edch l\u00e0 gi\u00fap kh\u00e1ch h\u00e0ng (th\u01b0\u1eddng l\u00e0 HR/IT managers) hi\u1ec3u c\u00e1c g\u00f3i v\u00e0 t\u00ednh n\u0103ng \u0111\u1ec3 \u0111\u01b0a ra quy\u1ebft \u0111\u1ecbnh mua."}]}, {"passageTitle": "Email: Budget Reallocation Request", "type": "single", "passage": "From: Michael Torres <m.torres@bridgeconsulting.com>\nTo: Finance Committee <fincomm@bridgeconsulting.com>\nDate: October 12\nSubject: Request for Budget Reallocation \u2014 Q4 Marketing\n\nDear Committee Members,\n\nI am writing to formally request a reallocation of AUD 45,000 from the Q4 Events budget to the Digital Advertising budget within the Marketing division.\n\nThe rationale for this request is as follows. Following a comprehensive review of Q3 campaign performance, our digital advertising channels generated a return of 4.2x on investment, compared to 1.8x for live events. With the primary industry event of the year now having passed, the remaining events budget for Q4 is unlikely to be fully utilised.\n\nI propose that the reallocated funds be used to scale our highest-performing digital campaigns before the holiday season, where we anticipate strong consumer demand.\n\nI request the committee's approval at the October 18 meeting. Supporting data and a revised budget breakdown have been attached.\n\nRegards,\nMichael Torres\nHead of Marketing", "questions": [{"id": "ns11-a", "part": 7, "question": "How much does Michael Torres want to move from the Events budget to Digital Advertising?", "options": ["AUD 18,000", "AUD 42,000", "AUD 45,000", "AUD 90,000"], "answer": 2, "explanation": "Detail: \"reallocation of AUD 45,000 from the Q4 Events budget to the Digital Advertising budget\"."}, {"id": "ns11-b", "part": 7, "question": "What is the main reason given for the reallocation request?", "options": ["The events team is under budget for the year", "Digital advertising delivered a significantly higher return than events", "A new digital campaign requires immediate funding", "The events budget has already been overspent"], "answer": 1, "explanation": "Detail: \"digital advertising channels generated 4.2x ROI compared to 1.8x for live events\" = rationale ch\u00ednh l\u00e0 ROI cao h\u01a1n c\u1ee7a digital."}, {"id": "ns11-c", "part": 7, "question": "In the email, the word \"rationale\" is closest in meaning to", "options": ["justification", "summary", "request", "outcome"], "answer": 0, "explanation": "WIC: \"the rationale for this request\" = l\u00fd do ch\u00ednh th\u1ee9c, c\u01a1 s\u1edf l\u1eadp lu\u1eadn. \"Justification\" l\u00e0 t\u1eeb g\u1ea7n ngh\u0129a nh\u1ea5t trong ng\u1eef c\u1ea3nh \u0111\u1ec1 xu\u1ea5t kinh doanh."}, {"id": "p7-pur16", "part": 7, "question": "Why did Michael Torres write this email?", "options": ["To report on the Q3 digital advertising campaign results", "To request approval to move funds between marketing budget lines", "To propose a new marketing strategy for the holiday season", "To announce a change in the company's annual marketing budget"], "answer": 1, "explanation": "Purpose: email ch\u00ednh th\u1ee9c y\u00eau c\u1ea7u ph\u00ea duy\u1ec7t chuy\u1ec3n ng\u00e2n s\u00e1ch t\u1eeb Events sang Digital Advertising \u2014 m\u1ee5c \u0111\u00edch l\u00e0 xin ph\u00ea duy\u1ec7t ng\u00e2n s\u00e1ch t\u00e1i ph\u00e2n b\u1ed5."}]}, {"passageTitle": "Notice: New Employee Onboarding Day", "type": "single", "passage": "WELCOME TO BRIGHTSTONE TECHNOLOGIES\nNew Employee Orientation \u2014 Friday, March 7\n\nDear New Team Members,\n\nWe are delighted to welcome you to Brightstone Technologies. Please see the agenda for your first-day orientation below.\n\n09:00 \u2013 09:30  Arrival and registration (Ground Floor Reception)\n09:30 \u2013 10:30  Welcome address by the CEO and executive introductions\n10:30 \u2013 11:30  IT setup and systems access (IT Hub, Level 2)\n11:30 \u2013 12:30  HR briefing: benefits, policies, and compliance overview\n12:30 \u2013 13:30  Catered welcome lunch (Rooftop Terrace)\n13:30 \u2013 15:30  Department introductions and facility tour\n15:30 \u2013 16:30  Buddy programme kickoff and Q&A session\n\nPlease bring your signed employment contract and a valid form of photo ID to reception. Parking is available in Bay Area C; please inform reception of your vehicle registration number upon arrival.\n\nFor any pre-arrival questions, contact hr@brightstone.com.", "questions": [{"id": "ns12-a", "part": 7, "question": "Where will new employees go first upon arriving?", "options": ["The IT Hub on Level 2", "The Ground Floor Reception", "The Rooftop Terrace", "The HR Department"], "answer": 1, "explanation": "Detail: \"09:00 \u2013 09:30 Arrival and registration (Ground Floor Reception)\" = \u0111i\u1ec3m \u0111\u1ebfn \u0111\u1ea7u ti\u00ean."}, {"id": "ns12-b", "part": 7, "question": "What must new employees bring to orientation?", "options": ["A completed tax file form and ID", "A signed employment contract and photo ID", "Their company laptop and parking permit", "A bank account number for payroll setup"], "answer": 1, "explanation": "Detail: \"Please bring your signed employment contract and a valid form of photo ID\"."}, {"id": "ns12-c", "part": 7, "question": "What is the purpose of the buddy programme session at 15:30?", "options": ["To complete all remaining IT setup tasks", "To allow new employees to meet their assigned buddy and ask questions", "To present the company's annual performance results", "To conduct individual performance assessments"], "answer": 1, "explanation": "Purpose: \"Buddy programme kickoff and Q&A session\" = kh\u1edfi \u0111\u1ed9ng ch\u01b0\u01a1ng tr\u00ecnh buddy v\u00e0 gi\u1ea3i \u0111\u00e1p th\u1eafc m\u1eafc."}, {"id": "p7-pur17", "part": 7, "question": "What is the purpose of this notice?", "options": ["To explain the company's remote work policy to new employees", "To provide new employees with the schedule and requirements for their first day", "To announce changes to the company's onboarding programme", "To invite existing staff to attend a welcome event for new employees"], "answer": 1, "explanation": "Purpose: th\u00f4ng b\u00e1o h\u01b0\u1edbng d\u1eabn nh\u00e2n vi\u00ean m\u1edbi v\u1ec1 l\u1ecbch tr\u00ecnh v\u00e0 y\u00eau c\u1ea7u trong ng\u00e0y \u0111\u1ea7u ti\u00ean \u2014 m\u1ee5c \u0111\u00edch th\u1ef1c t\u1ebf v\u00e0 r\u00f5 r\u00e0ng nh\u1ea5t."}]}, {"passageTitle": "Article: Supply Chain Localisation Trends", "type": "single", "passage": "LOCALISATION OR GLOBALISATION? SUPPLY CHAIN STRATEGY IN TRANSITION\nSupply Chain Management Review | October\n\nFor much of the last three decades, cost efficiency drove companies to globalise their supply chains, concentrating manufacturing in low-cost regions. That model is now under pressure.\n\nHigh-profile disruptions \u2014 from port closures and semiconductor shortages to geopolitical tensions \u2014 have prompted many multinationals to reassess their supply chain strategies. The result has been a marked shift toward supply chain localisation, or \"nearshoring,\" with companies establishing manufacturing and sourcing operations closer to their end markets.\n\nA recent survey of 400 senior supply chain executives found that 62% are currently investing in nearshoring initiatives. However, the transition is not without challenges: labour costs in nearshored locations are typically 20\u201340% higher than in traditional offshore hubs, and initial capital investment can be substantial.\n\nExperts caution that nearshoring is not a universal solution. For commodity products where cost is the primary competitive differentiator, globalised supply chains may remain the optimal strategy. The key, analysts argue, is building supply chains that are resilient and flexible enough to adapt as conditions change.", "questions": [{"id": "ns13-a", "part": 7, "question": "What percentage of supply chain executives surveyed are investing in nearshoring?", "options": ["42%", "52%", "62%", "72%"], "answer": 2, "explanation": "Detail: \"62% are currently investing in nearshoring initiatives\"."}, {"id": "ns13-b", "part": 7, "question": "In the article, the word \"resilient\" is closest in meaning to", "options": ["cost-efficient", "adaptable to disruptions", "highly automated", "globally connected"], "answer": 1, "explanation": "WIC: \"resilient supply chains\" = chu\u1ed7i cung \u1ee9ng c\u00f3 kh\u1ea3 n\u0103ng ph\u1ee5c h\u1ed3i sau gi\u00e1n \u0111o\u1ea1n. \"Adaptable to disruptions\" n\u1eafm b\u1eaft \u0111\u00fang nh\u1ea5t ngh\u0129a c\u1ee7a resilience trong b\u1ed1i c\u1ea3nh chu\u1ed7i cung \u1ee9ng."}, {"id": "ns13-c", "part": 7, "question": "According to the article, for which type of products might globalised supply chains still be preferable?", "options": ["High-technology components with complex assembly requirements", "Commodity products where cost is the primary competitive factor", "Products requiring rapid delivery to end consumers", "Customised goods produced in small volumes"], "answer": 1, "explanation": "Detail: \"For commodity products where cost is the primary competitive differentiator, globalised supply chains may remain optimal\"."}, {"id": "ns13-d", "part": 7, "question": "Which of the following is NOT listed as a challenge associated with nearshoring?", "options": ["Higher labour costs compared to offshore locations", "Significant initial capital investment", "Difficulty finding qualified local suppliers", "Substantial upfront infrastructure spending"], "answer": 2, "explanation": "NOT TRUE: Challenges listed are higher labour costs (20\u201340%) and substantial capital investment. \"Difficulty finding qualified local suppliers\" is NOT specifically mentioned as a challenge."}]}, {"passageTitle": "Memo: Changes to Meeting Room Booking", "type": "single", "passage": "INTERNAL MEMORANDUM\nTo:      All Staff\nFrom:    Facilities Management\nDate:    January 8\nRe:      Updated Meeting Room Booking Policy\n\nEffective February 1, the following changes to the meeting room booking system will apply to all floors.\n\nBooking limits:\n\u2022 Meeting rooms may be booked up to 10 business days in advance (previously 30 days).\n\u2022 Single bookings are limited to a maximum of 3 consecutive hours per session.\n\u2022 Recurring bookings of more than 4 hours per week in the same room require Facilities Management approval.\n\nNo-show policy:\nRooms that are not occupied within 15 minutes of the booking start time will be automatically released and made available to other users. Staff may re-book if the room is available.\n\nAdditional updates:\nThe Horizon Room (Capacity: 20) on Level 9 will be reserved exclusively for client-facing meetings. Internal meetings requiring a room of this size should use the newly refurbished Atlas Room on Level 11.\n\nQuestions may be directed to facilities@company.com.", "questions": [{"id": "ns14-a", "part": 7, "question": "How far in advance may staff book a meeting room under the new policy?", "options": ["5 business days", "10 business days", "20 business days", "30 business days"], "answer": 1, "explanation": "Detail: \"Meeting rooms may be booked up to 10 business days in advance (previously 30 days)\"."}, {"id": "ns14-b", "part": 7, "question": "What happens if a booked room is not occupied within 15 minutes of the start time?", "options": ["Staff are charged a no-show fee", "The booking is automatically cancelled and the room released", "A warning is sent to the staff member who made the booking", "The room remains held for an additional 30 minutes"], "answer": 1, "explanation": "Detail: \"Rooms not occupied within 15 minutes...will be automatically released and made available to other users\"."}, {"id": "ns14-c", "part": 7, "question": "In the memo, the word \"refurbished\" is closest in meaning to", "options": ["expanded", "relocated", "renovated", "reopened"], "answer": 2, "explanation": "WIC: \"newly refurbished Atlas Room\" = ph\u00f2ng v\u1eeba \u0111\u01b0\u1ee3c c\u1ea3i t\u1ea1o, t\u00e2n trang. \"Renovated\" l\u00e0 t\u1eeb \u0111\u1ed3ng ngh\u0129a ch\u00ednh x\u00e1c nh\u1ea5t."}, {"id": "ns14-d", "part": 7, "question": "What can be inferred about why the Horizon Room has been reserved for client meetings?", "options": ["It is the only room with video conferencing equipment", "The company wants to present its best facilities to external visitors", "It was previously underused by internal teams", "Staff complained about limited access to large meeting rooms"], "answer": 1, "explanation": "Inference: Reserving the largest room exclusively for client-facing meetings suggests the company wants to make a strong impression on external visitors \u2014 the most logical business reason."}]}, {"passageTitle": "Advertisement: Redwood Conference Centre", "type": "single", "passage": "REDWOOD CONFERENCE CENTRE\nRedefining Corporate Events in the Hunter Valley\n\nSet among the vineyards of the Hunter Valley wine region, the Redwood Conference Centre offers a premium setting for conferences, corporate retreats, and executive workshops.\n\nFACILITIES\n\u2022 Grand Ballroom: Seats 350 theatre-style or 200 for dinner events\n\u2022 Six breakout rooms: Capacities ranging from 8 to 45 delegates\n\u2022 Executive boardroom with 4K video conferencing capability\n\u2022 Complimentary high-speed Wi-Fi throughout the venue\n\u2022 Dedicated AV technician on-site for all events\n\nACCOMMODATION\n\u2022 80 boutique guest rooms and 12 executive suites\n\u2022 All accommodation includes full buffet breakfast\n\u2022 Complimentary shuttle service to and from Newcastle Airport\n\nPACKAGES\nDay Delegate Package: AUD 145 per person (minimum 20 delegates)\nIncludes: room hire, AV equipment, morning and afternoon tea, working lunch\n\nResidential Package: AUD 395 per person per night\nIncludes: all Day Delegate features plus dinner and accommodation\n\nContact our events team at events@redwoodcc.com.au or call +61 2 4933 8800.", "questions": [{"id": "ns15-a", "part": 7, "question": "What is the maximum theatre-style seating capacity of the Grand Ballroom?", "options": ["200", "280", "350", "420"], "answer": 2, "explanation": "Detail: \"Seats 350 theatre-style or 200 for dinner events\"."}, {"id": "ns15-b", "part": 7, "question": "What is included in the Day Delegate Package?", "options": ["Accommodation and dinner", "Morning tea, lunch, and AV equipment", "Dinner and a complimentary shuttle", "All meals plus accommodation"], "answer": 1, "explanation": "Detail: Day Delegate Package includes \"room hire, AV equipment, morning and afternoon tea, working lunch\" \u2014 no dinner or accommodation."}, {"id": "ns15-c", "part": 7, "question": "In the advertisement, the word \"boutique\" most likely suggests that the guest rooms are", "options": ["spacious and minimally decorated", "individually styled and characterful", "budget-friendly and functional", "located in a separate building"], "answer": 1, "explanation": "WIC/Inference: \"boutique\" in hospitality = nh\u1ecf nh\u01b0ng \u0111\u1eb7c tr\u01b0ng, phong c\u00e1ch ri\u00eang. \"Individually styled and characterful\" n\u1eafm b\u1eaft \u0111\u00fang nh\u1ea5t connotation c\u1ee7a \"boutique\" trong qu\u1ea3ng c\u00e1o kh\u00e1ch s\u1ea1n."}, {"id": "ns15-d", "part": 7, "question": "Which of the following is NOT included in the Residential Package?", "options": ["Working lunch", "Accommodation", "Complimentary breakfast", "A vineyard tour"], "answer": 3, "explanation": "NOT TRUE: Residential Package includes all Day Delegate features (which includes lunch) + dinner + accommodation. Accommodation includes breakfast. A vineyard tour is NOT mentioned in any package."}]}, {"passageTitle": "Email: Office Relocation Announcement", "type": "single", "passage": "From: Executive Office <exec@claritysolutions.com>\nTo: All Staff\nDate: March 3\nSubject: Upcoming Office Relocation \u2014 Action Required\n\nDear All,\n\nWe are pleased to announce that Clarity Solutions will be relocating our headquarters to new premises at Level 22, One Harbour Tower, from Monday, April 28.\n\nThe new office offers 40% more floor space than our current location and has been designed with collaboration in mind \u2014 featuring open-plan work zones, private focus booths, and three fully equipped meeting suites.\n\nWhat you need to do before April 25:\n1. Clear all personal items from your current desk and storage areas.\n2. Label any company equipment you regularly use with your name and department using the stickers provided.\n3. Return any borrowed IT equipment to the IT desk by April 18.\n\nIT services will be unavailable from 5:00 p.m. on Friday, April 25, until 8:00 a.m. on Monday, April 28, during the systems migration. Staff requiring urgent access during this period should contact it@claritysolutions.com in advance.\n\nCar parking at One Harbour Tower is available on a first-come, first-served basis. Details of the parking allocation process will be shared separately.\n\nWe look forward to seeing you in our new home.", "questions": [{"id": "ns16-a", "part": 7, "question": "What is one feature of the new office mentioned in the announcement?", "options": ["A rooftop terrace for staff events", "Private focus booths for individual work", "A dedicated parking garage for all staff", "An on-site cafeteria with subsidised meals"], "answer": 1, "explanation": "Detail: \"private focus booths\" listed as one of the new office's collaboration features."}, {"id": "ns16-b", "part": 7, "question": "By when must staff return borrowed IT equipment?", "options": ["April 18", "April 25", "April 28", "March 3"], "answer": 0, "explanation": "Detail: \"Return any borrowed IT equipment to the IT desk by April 18.\""}, {"id": "ns16-c", "part": 7, "question": "In the email, the word \"allocated\" in relation to parking most likely means", "options": ["reserved for specific individuals or departments", "available to all staff on an equal basis", "purchased by the company for staff use", "arranged with a third-party parking provider"], "answer": 0, "explanation": "WIC: \"parking allocation process\" = quy tr\u00ecnh ph\u00e2n b\u1ed5 ch\u1ed7 \u0111\u1eadu xe. \"Reserved for specific individuals/departments\" = ngh\u0129a c\u1ee7a allocation trong ng\u1eef c\u1ea3nh t\u00e0i nguy\u00ean c\u00f3 gi\u1edbi h\u1ea1n."}, {"id": "p7-pur18", "part": 7, "question": "Why was this email sent to all staff?", "options": ["To request suggestions for the design of the new office", "To inform staff of an upcoming office relocation and actions required of them", "To announce a change in the company's remote work policy", "To confirm the completion of the office renovation project"], "answer": 1, "explanation": "Purpose: email th\u00f4ng b\u00e1o chuy\u1ec3n v\u0103n ph\u00f2ng v\u00e0 y\u00eau c\u1ea7u h\u00e0nh \u0111\u1ed9ng c\u1ee5 th\u1ec3 t\u1eeb nh\u00e2n vi\u00ean tr\u01b0\u1edbc ng\u00e0y 25/4 \u2014 m\u1ee5c \u0111\u00edch k\u00e9p: th\u00f4ng b\u00e1o + h\u01b0\u1edbng d\u1eabn h\u00e0nh \u0111\u1ed9ng."}]}, {"passageTitle": "Notice: Staff Car Park Closure", "type": "single", "passage": "FACILITIES NOTICE \u2014 URGENT\nTo: All Staff \u2014 Greenfield Campus\nRe: Temporary Closure of Staff Car Park B\n\nPlease be advised that Staff Car Park B will be temporarily closed from Monday, June 2 until Friday, June 27, to enable resurfacing and drainage improvement works.\n\nDuring this period, staff who normally park in Car Park B are advised to use:\n\u2022 Car Park A (main building, east side) \u2014 available spaces subject to first-come availability\n\u2022 The Council-operated public car park on Kingsway Boulevard (approx. 5-minute walk) \u2014 validated parking tickets available from reception at a discounted rate of $5 per day\n\nThe company will provide a complimentary shuttle service between Kingsway Boulevard car park and the main building entrance, departing every 15 minutes from 7:30 a.m. to 9:00 a.m. and from 4:30 p.m. to 6:30 p.m.\n\nMotorbike bays and accessible parking spaces adjacent to Building A remain unaffected.\n\nFor questions, contact facilities@greenfieldcampus.com.au.", "questions": [{"id": "ns17-a", "part": 7, "question": "How long will Car Park B be closed?", "options": ["Two weeks", "Three weeks", "Four weeks", "Five weeks"], "answer": 2, "explanation": "Detail: June 2 to June 27 = approximately 4 weeks (26 days). Four weeks is the closest answer."}, {"id": "ns17-b", "part": 7, "question": "What discounted rate is offered for the public car park on Kingsway Boulevard?", "options": ["$3 per day", "$5 per day", "$8 per day", "$10 per day"], "answer": 1, "explanation": "Detail: \"discounted rate of $5 per day\" \u2014 validated parking tickets available from reception."}, {"id": "ns17-c", "part": 7, "question": "What can be inferred about the shuttle service operating hours?", "options": ["It runs throughout the entire working day", "It is designed to cover peak commuting arrival and departure times", "It is available only to staff without private vehicles", "It connects directly to the nearest train station"], "answer": 1, "explanation": "Inference: shuttle runs 7:30\u20139:00am and 4:30\u20136:30pm = peak arrival and departure commuting times, not the full day."}, {"id": "ns17-d", "part": 7, "question": "Which of the following parking areas will NOT be affected by the closure?", "options": ["Car Park B", "Car Park A during peak hours", "Motorbike bays adjacent to Building A", "Both Car Parks A and B"], "answer": 2, "explanation": "Detail: \"Motorbike bays and accessible parking spaces adjacent to Building A remain unaffected.\" Car Park A IS affected (subject to availability)."}]}, {"passageTitle": "Report: Customer Satisfaction Survey Results", "type": "single", "passage": "CUSTOMER SATISFACTION REPORT \u2014 H1\nTechAssist Support Services | Prepared for: Management Review\n\nResponse Rate: 71% (n = 2,847)\n\nOverall Satisfaction: 82% of respondents rated their experience as \"Satisfied\" or \"Very Satisfied,\" up from 74% in H2 of last year.\n\nKey Findings:\nResponse Time: The highest-rated category (4.4/5), attributed to the reduction in average first-response time from 8.2 hours to 4.6 hours following the introduction of automated ticket routing in January.\n\nTechnical Resolution Quality: Rated 4.1/5. Open-ended feedback praised the knowledge and patience of support agents, particularly for complex multi-system issues.\n\nSelf-Service Portal Usage: 38% of respondents used the self-service portal before contacting support \u2014 up from 22% in H2. However, 41% of self-service users reported being unable to resolve their issue without agent assistance.\n\nRecommendations:\nThe data suggests the self-service portal requires significant content enhancement to reduce the rate of escalation to live agents. A comprehensive content audit is recommended for Q3.", "questions": [{"id": "ns18-a", "part": 7, "question": "What caused the improvement in response time according to the report?", "options": ["Additional support agents were hired in January", "A new automated ticket routing system was introduced", "Support hours were extended to cover weekends", "A customer callback service replaced the ticketing system"], "answer": 1, "explanation": "Detail: \"attributed to the reduction in average first-response time...following the introduction of automated ticket routing in January\"."}, {"id": "ns18-b", "part": 7, "question": "In the report, the word \"escalation\" is closest in meaning to", "options": ["delay in processing", "transfer to a higher support level", "increase in complaint volume", "failure to resolve the issue"], "answer": 1, "explanation": "WIC: \"escalation to live agents\" = chuy\u1ec3n l\u00ean c\u1ea5p cao h\u01a1n (t\u1eeb t\u1ef1 ph\u1ee5c v\u1ee5 sang nh\u00e2n vi\u00ean h\u1ed7 tr\u1ee3). \"Transfer to a higher support level\" l\u00e0 di\u1ec5n \u0111\u1ea1t ch\u00ednh x\u00e1c nh\u1ea5t trong ng\u1eef c\u1ea3nh h\u1ed7 tr\u1ee3 kh\u00e1ch h\u00e0ng."}, {"id": "ns18-c", "part": 7, "question": "What concern is raised about the self-service portal?", "options": ["Too few customers are aware that it exists", "A large proportion of users still need agent help after using it", "The portal is only accessible to Premium subscribers", "Users find the portal interface confusing and difficult to navigate"], "answer": 1, "explanation": "Detail: \"41% of self-service users reported being unable to resolve their issue without agent assistance\" = t\u1ef7 l\u1ec7 l\u1edbn v\u1eabn c\u1ea7n nh\u00e2n vi\u00ean sau khi d\u00f9ng portal."}, {"id": "p7-pur08", "part": 7, "question": "What is the primary purpose of this report?", "options": ["To justify increased investment in the customer support team", "To present H1 customer satisfaction data and identify areas for improvement", "To announce the results of a staff performance review", "To compare customer satisfaction scores with industry benchmarks"], "answer": 1, "explanation": "Purpose: b\u00e1o c\u00e1o tr\u00ecnh b\u00e0y k\u1ebft qu\u1ea3 kh\u1ea3o s\u00e1t H1, ph\u00e2n t\u00edch \u0111i\u1ec3m m\u1ea1nh/y\u1ebfu v\u00e0 \u0111\u1ec1 xu\u1ea5t h\u00e0nh \u0111\u1ed9ng \u2014 m\u1ee5c \u0111\u00edch l\u00e0 th\u00f4ng b\u00e1o k\u1ebft qu\u1ea3 v\u00e0 h\u01b0\u1edbng c\u1ea3i thi\u1ec7n cho ban qu\u1ea3n l\u00fd."}]}, {"passageTitle": "Advertisement: Lumina Co-Working Spaces", "type": "single", "passage": "LUMINA CO-WORKING SPACES\nWork smarter. Work together.\n\nLumina offers flexible, fully serviced co-working spaces across 12 locations in the greater metropolitan area. Whether you need a hot desk for a day or a private office for your growing team, we have a solution for you.\n\nMEMBERSHIP OPTIONS:\nDay Pass \u2014 AUD 35/day\nFull-day access to any Lumina location | High-speed Wi-Fi | Complimentary refreshments\n\nFlexi Monthly \u2014 AUD 290/month\n10 days per month at any location | Meeting room credits: 2 hours/month | All Day Pass benefits\n\nDedicated Desk \u2014 AUD 490/month\nYour own reserved desk at a single location | 24/7 access | 4 meeting room hours/month | Storage locker included\n\nPrivate Office \u2014 From AUD 1,200/month (varies by location and team size)\nEnclosed office space for 2\u201312 people | All Dedicated Desk benefits | Custom branding option | 8 meeting room hours/month\n\nAll plans include access to Lumina's member events programme. New members receive a complimentary one-week trial of any plan.", "questions": [{"id": "ns19-a", "part": 7, "question": "Which plan includes 24-hour access to the workspace?", "options": ["Day Pass", "Flexi Monthly", "Dedicated Desk", "Both Dedicated Desk and Private Office"], "answer": 3, "explanation": "Detail: \"24/7 access\" listed under Dedicated Desk, and \"All Dedicated Desk benefits\" listed under Private Office \u2014 both include 24/7 access."}, {"id": "ns19-b", "part": 7, "question": "What does the new member trial offer?", "options": ["A free month on any plan", "One week free on any plan", "Three free day passes", "A 50% discount on the first month"], "answer": 1, "explanation": "Detail: \"New members receive a complimentary one-week trial of any plan.\""}, {"id": "ns19-c", "part": 7, "question": "In the advertisement, the word \"complimentary\" is closest in meaning to", "options": ["free of charge", "high quality", "optional", "included at a discount"], "answer": 0, "explanation": "WIC: \"Complimentary refreshments\" = \u0111\u1ed3 \u0103n nh\u1eb9/u\u1ed1ng mi\u1ec5n ph\u00ed. \"Free of charge\" l\u00e0 di\u1ec5n \u0111\u1ea1t t\u01b0\u01a1ng \u0111\u01b0\u01a1ng ch\u00ednh x\u00e1c nh\u1ea5t."}, {"id": "ns19-d", "part": 7, "question": "What can be inferred about Lumina's target market?", "options": ["It exclusively serves large corporations with established offices", "It primarily targets freelancers, startups, and small growing teams", "It is designed mainly for remote workers who travel frequently", "It focuses on companies in the technology sector"], "answer": 1, "explanation": "Inference: range of plans from day pass to private office for 2\u201312 people, \"flexible\" + \"growing team\" messaging \u2192 targets freelancers, startups, and small teams, not large corporations."}]}, {"passageTitle": "Memo: Staff Parking Allocation Review", "type": "single", "passage": "MEMORANDUM\n\nTo:      All Staff \u2014 Eastgate Tower\nFrom:    HR & Facilities Department\nDate:    February 12\nRe:      Annual Review of Car Park Allocation\n\nFollowing feedback from the Q4 staff survey, the HR and Facilities Department has completed an annual review of car park allocation at Eastgate Tower. The following changes will take effect from March 1.\n\nPriority changes:\n\u2022 Car park spaces will be allocated based on distance travelled to work, in descending order. Employees travelling more than 25 km will receive the highest priority.\n\u2022 Employees who have held a parking space for more than three consecutive years without using it for more than 50% of working days will have their allocation reviewed.\n\u2022 Carpooling groups of three or more registered members will receive a reserved space in Zone A.\n\nStaff currently holding a parking space should check their allocation status on the HR portal by February 20. Those affected by the changes will be notified individually.\n\nThe department thanks all staff for their feedback and remains committed to ensuring fair access to limited parking resources.", "questions": [{"id": "ns20-a", "part": 7, "question": "What is the primary criterion for determining car park priority under the new system?", "options": ["Length of service with the company", "Distance travelled to work", "Seniority and job level", "Whether the employee holds a company vehicle"], "answer": 1, "explanation": "Detail: \"spaces will be allocated based on distance travelled to work, in descending order.\""}, {"id": "ns20-b", "part": 7, "question": "What must staff with existing parking spaces do by February 20?", "options": ["Submit a new parking application form", "Check their allocation status on the HR portal", "Register as part of a carpooling group", "Confirm their commute distance with HR"], "answer": 1, "explanation": "Detail: \"Staff currently holding a parking space should check their allocation status on the HR portal by February 20.\""}, {"id": "ns20-c", "part": 7, "question": "What can be inferred about the reason for the allocation review?", "options": ["Several parking spaces have been damaged and are unusable", "Staff raised concerns about the fairness of current parking arrangements", "The building management has reduced the number of available spaces", "A new company policy requires carpooling for all staff"], "answer": 1, "explanation": "Inference: \"following feedback from the Q4 staff survey\" + \"fair access to limited parking resources\" = staff survey revealed perceived unfairness in current allocation."}, {"id": "ns20-d", "part": 7, "question": "Which of the following is NOT mentioned as a basis for reviewing an existing parking allocation?", "options": ["Having held the space for more than three consecutive years", "Using the space less than 50% of working days", "Travelling fewer than 25 km to work", "Receiving a formal complaint from another staff member"], "answer": 3, "explanation": "NOT TRUE: Review criteria include 3-year tenure + under 50% usage. Receiving a formal complaint is NOT listed as a trigger for review."}]}, {"passageTitle": "Web Page: ClearPath Financial Advisors", "type": "single", "passage": "CLEARPATH FINANCIAL ADVISORS\nHelping you build, protect, and transfer wealth\n\nAt ClearPath, we provide personalised financial advice to individuals, families, and small business owners across Australia. Our team of Certified Financial Planners\u00ae has helped over 3,500 clients achieve their financial goals since 2007.\n\nOUR SERVICES\n\nRetirement Planning\nDevelop a tailored strategy for achieving financial independence, including superannuation optimisation, transition-to-retirement planning, and aged care considerations.\n\nInvestment Advisory\nPortfolio construction and management, including shares, ETFs, managed funds, and direct property investment strategies.\n\nInsurance & Risk Management\nLife insurance, income protection, total and permanent disability (TPD), and trauma cover tailored to your personal circumstances.\n\nEstate Planning\nWills, powers of attorney, and tax-effective strategies for transferring wealth to the next generation.\n\nINITIAL CONSULTATION: Complimentary 45-minute meeting with a qualified adviser.\nCall 1800 CLEARPATH or visit clearpath.com.au to book.", "questions": [{"id": "ns21-a", "part": 7, "question": "How long has ClearPath been providing financial advice?", "options": ["Since 2001", "Since 2007", "Since 2012", "Since 2015"], "answer": 1, "explanation": "Detail: \"helped over 3,500 clients achieve their financial goals since 2007\"."}, {"id": "ns21-b", "part": 7, "question": "Which service would be most relevant to someone planning to transfer assets to family members?", "options": ["Retirement Planning", "Investment Advisory", "Insurance & Risk Management", "Estate Planning"], "answer": 3, "explanation": "Detail: \"Estate Planning: Wills, powers of attorney, and tax-effective strategies for transferring wealth to the next generation.\""}, {"id": "ns21-c", "part": 7, "question": "In the web page, the word \"tailored\" is closest in meaning to", "options": ["comprehensive", "personalised", "industry-standard", "cost-effective"], "answer": 1, "explanation": "WIC: \"tailored strategy\" = chi\u1ebfn l\u01b0\u1ee3c \u0111\u01b0\u1ee3c t\u00f9y ch\u1ec9nh cho t\u1eebng c\u00e1 nh\u00e2n. \"Personalised\" l\u00e0 t\u1eeb \u0111\u1ed3ng ngh\u0129a ch\u00ednh x\u00e1c nh\u1ea5t trong ng\u1eef c\u1ea3nh t\u01b0 v\u1ea5n t\u00e0i ch\u00ednh."}, {"id": "ns21-d", "part": 7, "question": "What does the initial consultation offer suggest about ClearPath's approach to new clients?", "options": ["It prioritises clients with large investment portfolios", "It aims to make financial advice accessible by removing initial cost barriers", "It focuses only on retirement planning as its primary service", "It requires clients to commit to a full financial plan before advice is given"], "answer": 1, "explanation": "Inference: \"complimentary 45-minute initial consultation\" = kh\u00f4ng m\u1ea5t ph\u00ed ban \u0111\u1ea7u \u2192 ClearPath mu\u1ed1n lo\u1ea1i b\u1ecf r\u00e0o c\u1ea3n chi ph\u00ed \u0111\u1ec3 gi\u00fap kh\u00e1ch h\u00e0ng m\u1edbi d\u1ec5 ti\u1ebfp c\u1eadn d\u1ecbch v\u1ee5 t\u01b0 v\u1ea5n t\u00e0i ch\u00ednh."}]},{"passageTitle":"Notice: Office Closure – Public Holiday","type":"single","passage":"NOTICE\n\nPlease be advised that our offices will be closed on Monday, June 10, in observance of the public holiday. All staff are reminded to make the necessary arrangements for any client commitments scheduled on that date.\n\nFor urgent inquiries during the closure, please contact the on-call support team at support@company.com. Normal business hours will resume on Tuesday, June 11.","questions":[{"id":"ns22-a","part":7,"question":"Why will the office be closed on June 10?","options":["A scheduled maintenance shutdown","A public holiday observance","A company-wide training event","An unexpected emergency"],"answer":1,"explanation":"Detail: offices closed in observance of the public holiday."},{"id":"ns22-b","part":7,"question":"How should urgent matters be handled during the closure?","options":["By calling the main office number","By emailing the on-call support team","By visiting the nearest branch office","By submitting a ticket through the HR portal"],"answer":1,"explanation":"Detail: contact the on-call support team at support@company.com."}]},{"passageTitle":"Notice: Server Maintenance Window","type":"single","passage":"NOTICE – IT Department\n\nOur internal systems will undergo scheduled maintenance on Saturday, August 3, from 10:00 P.M. to 2:00 A.M. During this window, access to the company intranet, email, and shared drives will be unavailable. Staff requiring urgent file access are advised to download necessary documents before 9:00 P.M. on Saturday. The IT helpdesk will not be available during the maintenance window but can be reached at ext. 4400 from Sunday morning.","questions":[{"id":"ns23-a","part":7,"question":"What will be unavailable during the maintenance window?","options":["Telephone lines and meeting rooms","The intranet, email, and shared drives","The payroll and HR systems only","External internet access"],"answer":1,"explanation":"Detail: 'access to the company intranet, email, and shared drives will be unavailable.'"},{"id":"ns23-b","part":7,"question":"What are staff advised to do before 9:00 P.M. on Saturday?","options":["Submit IT support tickets in advance","Download any documents they may need","Back up all personal work files","Contact the helpdesk about access issues"],"answer":1,"explanation":"Detail: 'Staff requiring urgent file access are advised to download necessary documents before 9:00 P.M. on Saturday.'"}]},{"passageTitle":"Email: Project Deadline Extension","type":"single","passage":"From: Sandra Okafor <s.okafor@vertexgroup.com>\nTo: Project Team\nSubject: Extension Approved – Meridian Launch\n\nTeam,\n\nFollowing our meeting with the client this morning, I'm pleased to confirm that the launch deadline for the Meridian project has been extended by two weeks to October 18. The client cited their need for additional internal review time as the reason for the change.\n\nPlease use this time to address the outstanding items listed in yesterday's QA report. A revised schedule will be shared by end of day Thursday.\n\nThanks,\nSandra","questions":[{"id":"ns24-a","part":7,"question":"Why was the deadline extended?","options":["The development team requested more time","The client needed more time for internal review","A technical issue delayed the project","The QA report was submitted late"],"answer":1,"explanation":"Detail: 'The client cited their need for additional internal review time as the reason for the change.'"},{"id":"ns24-b","part":7,"question":"What will be shared by end of day Thursday?","options":["The completed QA report","A revised project schedule","The client's feedback document","Meeting minutes from this morning"],"answer":1,"explanation":"Detail: 'A revised schedule will be shared by end of day Thursday.'"}]},{"passageTitle":"Sign: Conference Room Booking Policy","type":"single","passage":"CONFERENCE ROOM BOOKING POLICY\n\nAll conference rooms must be reserved in advance via the Facilities Portal. Rooms booked but not occupied within 15 minutes of the start time will be automatically released for others to use. Food and beverages are permitted only in Rooms C and D. Please ensure the room is left in a tidy condition and all equipment is returned to its original position after use. For technical support during meetings, dial ext. 2200.","questions":[{"id":"ns25-a","part":7,"question":"What happens if a booked room is not occupied within 15 minutes?","options":["A fee is charged to the booking party","The booking is cancelled automatically","The room is released for others to use","Facilities staff will be notified"],"answer":2,"explanation":"Detail: 'Rooms booked but not occupied within 15 minutes of the start time will be automatically released for others to use.'"},{"id":"ns25-b","part":7,"question":"Where are food and beverages permitted?","options":["In all conference rooms","Only in Room A","Only in Rooms C and D","In the lobby area only"],"answer":2,"explanation":"Detail: 'Food and beverages are permitted only in Rooms C and D.'"}]},{"passageTitle":"Text Message Chain: Delivery Confirmation","type":"single","passage":"[2:14 P.M.] Marcus Webb: Hi Priya, just checking — did the stationery order arrive at your office this morning?\n\n[2:17 P.M.] Priya Nair: Hi Marcus! Yes, it came around 10. Two boxes, right?\n\n[2:18 P.M.] Marcus Webb: That's correct. Could you confirm the contents match the packing list inside?\n\n[2:21 P.M.] Priya Nair: Just checked — everything looks good except the recycled notepads are missing. Should be 50 units.\n\n[2:23 P.M.] Marcus Webb: Got it. I'll raise this with the supplier today and arrange a replacement shipment.","questions":[{"id":"ns26-a","part":7,"question":"What item was missing from the delivery?","options":["Printer cartridges","Recycled notepads","Ballpoint pens","File folders"],"answer":1,"explanation":"Detail: 'the recycled notepads are missing. Should be 50 units.'"},{"id":"ns26-b","part":7,"question":"What will Marcus do in response to the missing item?","options":["Visit Priya's office to verify the delivery","Contact the supplier and arrange a replacement","Issue a refund for the missing units","Update the packing list and resend"],"answer":1,"explanation":"Detail: 'I'll raise this with the supplier today and arrange a replacement shipment.'"}]},{"passageTitle":"Advertisement: Language Classes","type":"single","passage":"BERLINGO LANGUAGE STUDIO\n\nBoost your career with our professional language programs. We offer evening and weekend courses in Mandarin, Spanish, French, and Japanese — all taught by certified native speakers.\n\nCurrent promotion: Enroll in any 12-week course before September 30 and receive a complimentary one-on-one tutoring session (valued at $80). Group classes are limited to 8 participants to ensure personalised attention.\n\nCall 555-0192 or visit berlingo.com to register.","questions":[{"id":"ns27-a","part":7,"question":"What is included in the current promotional offer?","options":["A free 12-week course","A complimentary one-on-one tutoring session","Discounted group enrollment for two people","Free learning materials for new students"],"answer":1,"explanation":"Detail: 'receive a complimentary one-on-one tutoring session (valued at $80).'"},{"id":"ns27-b","part":7,"question":"What is the maximum number of participants in a group class?","options":["6","8","10","12"],"answer":1,"explanation":"Detail: 'Group classes are limited to 8 participants.'"}]},{"passageTitle":"Memo: Updated Expense Reimbursement Policy","type":"single","passage":"INTERNAL MEMO\nTo: All Staff\nFrom: Finance Department\nRe: Expense Reimbursement – Updated Process\n\nEffective November 1, all expense reimbursement requests must be submitted through the new online portal at finance.intranet/expenses. Paper forms will no longer be accepted after this date.\n\nReceipts must be uploaded within 30 days of the expense date. Claims submitted after this period will not be processed without prior approval from a department head.\n\nFor assistance navigating the new portal, training sessions will be held on October 22 and 23 in Meeting Room B.","questions":[{"id":"ns28-a","part":7,"question":"What change takes effect on November 1?","options":["All expenses must be pre-approved by a manager","Expense requests must be submitted through an online portal","The reimbursement limit per claim will be reduced","Receipts must be submitted within 14 days"],"answer":1,"explanation":"Detail: 'all expense reimbursement requests must be submitted through the new online portal... Paper forms will no longer be accepted after this date.'"},{"id":"ns28-b","part":7,"question":"When will training for the new portal be held?","options":["October 1 and 2","October 15 and 16","October 22 and 23","November 1 and 2"],"answer":2,"explanation":"Detail: 'training sessions will be held on October 22 and 23 in Meeting Room B.'"}]},{"passageTitle":"Notice: Gym Facility Hours Update","type":"single","passage":"WESTFIELD CORPORATE GYM\n\nPlease note that effective July 14, our facility hours will change as follows:\n\nWeekdays: 6:00 A.M. – 9:00 P.M. (previously 7:00 A.M. – 8:00 P.M.)\nWeekends: 8:00 A.M. – 4:00 P.M. (unchanged)\n\nThese extended hours are in response to member feedback requesting early morning access. Locker room maintenance will be conducted every Tuesday from 6:00 A.M. to 7:00 A.M., during which the locker area will be temporarily closed.","questions":[{"id":"ns29-a","part":7,"question":"What prompted the change in weekday hours?","options":["A new management policy on gym access","Feedback from members requesting early morning access","Reduced staffing during peak afternoon hours","A renovation of the facility entrance"],"answer":1,"explanation":"Detail: 'These extended hours are in response to member feedback requesting early morning access.'"},{"id":"ns29-b","part":7,"question":"When is the locker area temporarily closed?","options":["Every Monday from 7:00 A.M. to 8:00 A.M.","Every Tuesday from 6:00 A.M. to 7:00 A.M.","Every Wednesday from 8:00 A.M. to 9:00 A.M.","Every Friday from 6:00 A.M. to 7:00 A.M."],"answer":1,"explanation":"Detail: 'Locker room maintenance will be conducted every Tuesday from 6:00 A.M. to 7:00 A.M.'"}]},{"passageTitle":"Announcement: Staff Recognition Program","type":"single","passage":"STAFF RECOGNITION PROGRAM – Q3 NOMINATIONS NOW OPEN\n\nWe are pleased to announce that nominations for the Q3 Staff Recognition Award are now open. Any employee may nominate a colleague who has demonstrated outstanding performance, teamwork, or innovation during July–September.\n\nNominations must be submitted via the HR portal by September 15. The selected recipient will be announced at the all-staff meeting on October 4 and will receive a $200 gift card and a certificate of recognition.\n\nFor nomination criteria, visit the HR intranet page.","questions":[{"id":"ns30-a","part":7,"question":"What is the deadline for submitting nominations?","options":["September 1","September 15","October 1","October 4"],"answer":1,"explanation":"Detail: 'Nominations must be submitted via the HR portal by September 15.'"},{"id":"ns30-b","part":7,"question":"What will the award recipient receive?","options":["An extra day of annual leave","A $200 gift card and a certificate","A promotion to a senior position","A cash bonus paid through payroll"],"answer":1,"explanation":"Detail: 'will receive a $200 gift card and a certificate of recognition.'"}]},{"passageTitle":"Flyer: Community Recycling Event","type":"single","passage":"GREENDALE COMMUNITY RECYCLING DRIVE\nSaturday, April 19 | 9:00 A.M. – 1:00 P.M.\nGreendale Community Center Parking Lot\n\nBring your unwanted electronics, batteries, and household appliances for responsible recycling. All items must be dropped off in person — no commercial or industrial waste accepted.\n\nVolunteers are needed! Sign up at greendale.org/recycle by April 12 to help sort and process donations on the day. Refreshments will be provided for all volunteers.","questions":[{"id":"ns31-a","part":7,"question":"What types of items are accepted at the recycling event?","options":["Clothing, furniture, and books","Electronics, batteries, and household appliances","Commercial and industrial waste only","Paper and cardboard products"],"answer":1,"explanation":"Detail: 'Bring your unwanted electronics, batteries, and household appliances for responsible recycling.'"},{"id":"ns31-b","part":7,"question":"What is offered to people who volunteer?","options":["A cash payment for their time","Refreshments on the day","Priority drop-off access","A free recycling kit"],"answer":1,"explanation":"Detail: 'Refreshments will be provided for all volunteers.'"}]},{"passageTitle":"Notice: Parking Permit Renewal","type":"single","passage":"PARKING SERVICES – ANNUAL PERMIT RENEWAL\n\nAll current parking permit holders are reminded that permits expire on March 31. Renewal applications must be submitted online at parking.company.com no later than March 15. Late applications will be subject to a processing delay of up to five business days, and parking access may be temporarily suspended.\n\nIf you no longer require a parking space, please notify Parking Services by March 10 so the space can be reallocated to staff on the waiting list.","questions":[{"id":"ns32-a","part":7,"question":"By what date must renewal applications be submitted to avoid delays?","options":["March 10","March 15","March 20","March 31"],"answer":1,"explanation":"Detail: 'Renewal applications must be submitted... no later than March 15.'"},{"id":"ns32-b","part":7,"question":"What should employees do if they no longer need their parking space?","options":["Simply stop renewing their permit","Notify Parking Services by March 10","Return their permit card to reception","Email the HR department directly"],"answer":1,"explanation":"Detail: 'please notify Parking Services by March 10 so the space can be reallocated.'"}]},{"passageTitle":"Article: Remote Work Policy Update","type":"single","passage":"COMPANY BULLETIN\n\nFollowing a six-month pilot program, Hartwell & Associates has announced a permanent update to its remote work policy. Employees in eligible roles may now work from home up to three days per week, up from the previous limit of two days.\n\nEligibility is determined by job function and requires approval from both the direct manager and the HR department. Employees who wish to apply for the updated arrangement must submit a Remote Work Agreement form, available on the intranet, by the end of the current quarter.\n\nThe policy does not apply to staff in client-facing or operations roles, who are required to be on-site five days per week. The company will conduct a formal review of the policy in twelve months.","questions":[{"id":"ns33-a","part":7,"question":"What change has been made to the remote work policy?","options":["All employees may now work remotely full-time","The maximum remote work days per week has increased from two to three","Remote work is now limited to senior staff only","Employees no longer need manager approval for remote work"],"answer":1,"explanation":"Detail: 'Employees in eligible roles may now work from home up to three days per week, up from the previous limit of two days.'"},{"id":"ns33-b","part":7,"question":"Who must approve a remote work arrangement?","options":["Only the direct manager","The HR department alone","Both the direct manager and the HR department","The department head and the CEO"],"answer":2,"explanation":"Detail: 'requires approval from both the direct manager and the HR department.'"},{"id":"ns33-c","part":7,"question":"Which employees are NOT eligible for the updated remote work policy?","options":["Employees in technical support roles","Staff in client-facing or operations roles","Those who have worked at the company for less than one year","Managers at the senior level"],"answer":1,"explanation":"Detail: 'The policy does not apply to staff in client-facing or operations roles, who are required to be on-site five days per week.'"}]},{"passageTitle":"Letter: Product Recall Notice","type":"single","passage":"Dear Valued Customer,\n\nWe are writing to inform you of a voluntary recall of the Solaris Pro 3000 portable charger, model numbers SP3-BLK and SP3-WHT, manufactured between January and June of this year. Our quality assurance team has identified a potential issue with the charging circuit that may, in rare cases, cause the unit to overheat.\n\nIf you own one of the affected models, please stop using it immediately and return it to the place of purchase or contact our customer care team at 1800-SOLARIS to arrange a free replacement. No proof of purchase is required.\n\nWe sincerely apologise for any inconvenience this may cause and thank you for your understanding.\n\nSincerely,\nSolaris Consumer Electronics","questions":[{"id":"ns34-a","part":7,"question":"Why is the product being recalled?","options":["The battery life does not meet advertised specifications","A charging circuit issue may cause the unit to overheat","The product was found to be counterfeit","Customer complaints about the design"],"answer":1,"explanation":"Detail: 'a potential issue with the charging circuit that may, in rare cases, cause the unit to overheat.'"},{"id":"ns34-b","part":7,"question":"What are affected customers asked to do?","options":["Return the product only if it has already overheated","Stop using the product and arrange a free replacement","Pay a fee for a replacement unit","Wait for a firmware update to fix the issue"],"answer":1,"explanation":"Detail: 'please stop using it immediately and return it... to arrange a free replacement.'"},{"id":"ns34-c","part":7,"question":"What is NOT required to obtain a replacement?","options":["The model number of the product","Proof of purchase","A phone call to customer care","The original packaging"],"answer":1,"explanation":"Detail: 'No proof of purchase is required.'"}]},{"passageTitle":"Web Page: Online Course Platform","type":"single","passage":"LEARNFORWARD – PROFESSIONAL DEVELOPMENT PLATFORM\n\nLearnForward offers over 2,000 self-paced courses across business, technology, design, and leadership. All courses include video lessons, downloadable resources, and a certificate of completion.\n\nSubscription Options:\n• Monthly Plan: $29/month — cancel anytime\n• Annual Plan: $199/year — save 43% vs. monthly\n• Team Plan: From $15/user/month for groups of 10 or more\n\nNew subscribers receive a 14-day free trial on any plan. No credit card required to start.\n\nAll certificates are recognised by over 500 partner employers and can be added directly to LinkedIn profiles.","questions":[{"id":"ns35-a","part":7,"question":"What is included with every course on LearnForward?","options":["Live tutoring sessions with instructors","Video lessons, downloadable resources, and a certificate","Guaranteed job placement upon completion","Printed textbooks mailed to subscribers"],"answer":1,"explanation":"Detail: 'All courses include video lessons, downloadable resources, and a certificate of completion.'"},{"id":"ns35-b","part":7,"question":"How much does the Annual Plan cost?","options":["$15 per month","$29 per month","$199 per year","$299 per year"],"answer":2,"explanation":"Detail: 'Annual Plan: $199/year.'"},{"id":"ns35-c","part":7,"question":"What can be inferred about LearnForward certificates?","options":["They are only valid for six months after completion","They are accepted by a wide network of employers","They require a passing score of 90% or higher","They are only available on the Team Plan"],"answer":1,"explanation":"Inference: 'recognised by over 500 partner employers' implies wide acceptance in the job market."}]},{"passageTitle":"Report: Office Relocation Update","type":"single","passage":"INTERNAL UPDATE – FACILITIES TEAM\nSubject: Head Office Relocation – Progress Report\n\nThe relocation of our head office to 88 Clearwater Drive is progressing on schedule. The fit-out contractor, Pinnacle Interiors, completed the installation of workstations and meeting room furniture last week. Electrical and network cabling will be finalised by Friday, July 11.\n\nStaff are reminded that the official move date is Monday, July 21. Personal items should be packed in the labelled boxes provided by Facilities by end of day July 18. IT will arrange laptop and equipment collection on July 19–20.\n\nA building orientation session for all staff will be held on the morning of July 21 before work begins. Details will be sent by email next week.","questions":[{"id":"ns36-a","part":7,"question":"When is the official move date?","options":["July 11","July 18","July 21","July 19"],"answer":2,"explanation":"Detail: 'the official move date is Monday, July 21.'"},{"id":"ns36-b","part":7,"question":"By when must staff pack their personal items?","options":["End of day July 11","End of day July 18","Morning of July 19","Morning of July 21"],"answer":1,"explanation":"Detail: 'Personal items should be packed in the labelled boxes provided by Facilities by end of day July 18.'"},{"id":"ns36-c","part":7,"question":"What will happen on the morning of July 21?","options":["IT will collect laptops and equipment","A building orientation session will be held","The fit-out contractor will complete final checks","Staff will receive their new access cards"],"answer":1,"explanation":"Detail: 'A building orientation session for all staff will be held on the morning of July 21 before work begins.'"}]},{"passageTitle":"Email: Training Program Invitation","type":"single","passage":"From: Learning & Development Team <ld@nexuscorp.com>\nTo: All Supervisors\nSubject: Invitation – Leadership Excellence Program (Cohort 5)\n\nDear Supervisors,\n\nWe are pleased to invite applications for Cohort 5 of the Leadership Excellence Program, our flagship six-month development program for mid-level supervisors.\n\nThe program covers strategic thinking, effective communication, conflict resolution, and change management. Sessions are held fortnightly on Thursdays from 3:00 P.M. to 5:30 P.M. in the Learning Hub.\n\nParticipants who complete all sessions and the final project will receive a Leadership Excellence Certificate endorsed by the Institute of Management Professionals.\n\nApplications close April 30. Please complete the online form at nexuscorp.com/leadprogram. Spaces are limited to 20 participants.","questions":[{"id":"ns37-a","part":7,"question":"How long does the Leadership Excellence Program run?","options":["Three months","Four months","Six months","One year"],"answer":2,"explanation":"Detail: 'our flagship six-month development program.'"},{"id":"ns37-b","part":7,"question":"How often are the program sessions held?","options":["Weekly on Mondays","Weekly on Thursdays","Fortnightly on Thursdays","Monthly on Fridays"],"answer":2,"explanation":"Detail: 'Sessions are held fortnightly on Thursdays.'"},{"id":"ns37-c","part":7,"question":"What must participants do to earn the certificate?","options":["Pass a written examination","Complete all sessions and the final project","Receive a recommendation from their manager","Attend at least 80% of sessions"],"answer":1,"explanation":"Detail: 'Participants who complete all sessions and the final project will receive a Leadership Excellence Certificate.'"}]},{"passageTitle":"Memo: New Supplier Approval Process","type":"single","passage":"MEMORANDUM\nTo: All Department Managers\nFrom: Procurement Department\nDate: March 5\nRe: Updated Supplier Onboarding Requirements\n\nEffective April 1, all new supplier engagements must go through the updated three-step approval process:\n\n1. Department managers submit a Supplier Request Form via the Procurement Portal.\n2. The Procurement team conducts a compliance and financial review (5–7 business days).\n3. Upon approval, suppliers will be added to the Approved Vendor List and may begin receiving purchase orders.\n\nEngaging suppliers who are not on the Approved Vendor List will be considered a policy violation. All existing suppliers approved before April 1 remain active and do not need to reapply.\n\nFor questions, contact procurement@company.com.","questions":[{"id":"ns38-a","part":7,"question":"What is the first step in the new supplier approval process?","options":["The Procurement team contacts the supplier directly","Department managers submit a Supplier Request Form","Suppliers submit their own registration documents","A compliance officer visits the supplier's premises"],"answer":1,"explanation":"Detail: 'Department managers submit a Supplier Request Form via the Procurement Portal.'"},{"id":"ns38-b","part":7,"question":"How long does the Procurement team's review typically take?","options":["1–2 business days","3–4 business days","5–7 business days","10–14 business days"],"answer":2,"explanation":"Detail: 'The Procurement team conducts a compliance and financial review (5–7 business days).'"},{"id":"ns38-c","part":7,"question":"What can be inferred about suppliers approved before April 1?","options":["They must reapply under the new process","They will be removed from the vendor list until reviewed","They remain active and do not need to reapply","They will undergo review within 30 days"],"answer":2,"explanation":"Detail: 'All existing suppliers approved before April 1 remain active and do not need to reapply.'"}]},{"passageTitle":"Advertisement: Business Conference","type":"single","passage":"APEX BUSINESS SUMMIT 2025\nMarch 14–15 | Grand Meridian Convention Centre\n\nJoin over 1,500 business leaders for two days of keynote presentations, panel discussions, and networking events focused on innovation, sustainability, and the future of work.\n\nHighlights:\n• Keynote by Dr. Patricia Lam, Global Head of Innovation at FutureTech\n• 40+ breakout sessions led by industry experts\n• Exclusive networking dinner on March 14\n\nRegistration Tiers:\nStandard Pass – $499 | VIP Pass – $799 (includes dinner + front-row seating)\nGroup discount: 10% off for teams of 5 or more.\n\nRegister at apexsummit.com by February 28 for early-bird pricing.","questions":[{"id":"ns39-a","part":7,"question":"What is included in the VIP Pass that is NOT in the Standard Pass?","options":["Access to all breakout sessions","A copy of the keynote presentation","Dinner and front-row seating","A one-year subscription to Apex Summit content"],"answer":2,"explanation":"Detail: 'VIP Pass – $799 (includes dinner + front-row seating).'"},{"id":"ns39-b","part":7,"question":"By when must attendees register to receive early-bird pricing?","options":["January 31","February 14","February 28","March 1"],"answer":2,"explanation":"Detail: 'Register at apexsummit.com by February 28 for early-bird pricing.'"},{"id":"ns39-c","part":7,"question":"What discount is available for group registrations?","options":["5% off for groups of 3 or more","10% off for teams of 5 or more","15% off for groups of 10 or more","20% off for corporate sponsors"],"answer":1,"explanation":"Detail: 'Group discount: 10% off for teams of 5 or more.'"}]},{"passageTitle":"Notice: Library Membership Renewal","type":"single","passage":"SPRINGFIELD CORPORATE LIBRARY SERVICES\nAnnual Membership Renewal – Important Notice\n\nAll corporate library memberships expire on June 30. Members wishing to renew must complete the online renewal form at library.springfieldcorp.com before June 15 to ensure uninterrupted access.\n\nNew this year: members may now borrow up to 10 physical items at one time, increased from the previous limit of 6. Digital borrowing limits remain unchanged at 5 e-books and 3 audiobooks simultaneously.\n\nMembers who do not renew by June 30 will have their access suspended. Reinstatement after this date requires a new membership application and a $25 administration fee.","questions":[{"id":"ns40-a","part":7,"question":"By when must members renew to maintain uninterrupted access?","options":["June 1","June 15","June 20","June 30"],"answer":1,"explanation":"Detail: 'must complete the online renewal form... before June 15 to ensure uninterrupted access.'"},{"id":"ns40-b","part":7,"question":"What change has been made to physical borrowing limits?","options":["The limit has decreased from 10 to 6 items","The limit has increased from 6 to 10 items","There is no longer a limit on physical items","The limit now varies based on membership tier"],"answer":1,"explanation":"Detail: 'members may now borrow up to 10 physical items at one time, increased from the previous limit of 6.'"},{"id":"ns40-c","part":7,"question":"What is required if a member does not renew before the deadline?","options":["A written request to the library manager","A new membership application and a $25 fee","Payment of all overdue fines first","Approval from the HR department"],"answer":1,"explanation":"Detail: 'Reinstatement after this date requires a new membership application and a $25 administration fee.'"}]},{"passageTitle":"Email: Customer Complaint Response","type":"single","passage":"From: Customer Relations Team <relations@harborgoods.com>\nTo: Mr. Daniel Cheung\nSubject: Re: Order #HG-88231 – Damaged Item\n\nDear Mr. Cheung,\n\nThank you for contacting us regarding your recent order. We sincerely apologise that the ceramic planter you received was damaged during transit.\n\nWe have arranged for a replacement to be shipped to your address within 3–5 business days at no additional cost. You are welcome to keep or dispose of the damaged item as you wish — there is no need to return it.\n\nAs a gesture of goodwill, we have also added a $15 store credit to your account, valid for 12 months.\n\nWe value your patronage and hope this resolution meets your expectations.\n\nWarm regards,\nHarbor Goods Customer Relations","questions":[{"id":"ns41-a","part":7,"question":"Why did Mr. Cheung contact Harbor Goods?","options":["His order was delivered to the wrong address","He received a damaged item in his order","He was charged an incorrect amount","His order had not yet arrived"],"answer":1,"explanation":"Detail: 'the ceramic planter you received was damaged during transit.'"},{"id":"ns41-b","part":7,"question":"What does Harbor Goods tell Mr. Cheung to do with the damaged item?","options":["Return it using the prepaid label provided","Bring it to the nearest store for inspection","Keep or dispose of it as he wishes","Hold it until the replacement arrives"],"answer":2,"explanation":"Detail: 'You are welcome to keep or dispose of the damaged item as you wish — there is no need to return it.'"},{"id":"ns41-c","part":7,"question":"What additional compensation was offered to Mr. Cheung?","options":["A full refund to his original payment method","A 10% discount on his next order","A $15 store credit valid for 12 months","Free shipping on all future orders"],"answer":2,"explanation":"Detail: 'we have also added a $15 store credit to your account, valid for 12 months.'"}]},{"passageTitle":"Announcement: Annual Company Picnic","type":"single","passage":"ALL-STAFF ANNOUNCEMENT\n\nWe are excited to announce that this year's Annual Company Picnic will be held on Saturday, June 7, at Riverside Park from 11:00 A.M. to 4:00 P.M.\n\nThis event is open to all employees and their immediate family members. Activities will include lawn games, a team trivia competition, and a catered barbecue lunch. Vegetarian and allergy-friendly options will be available.\n\nTo help with catering numbers, please RSVP by May 25 via the HR portal. Employees who do not RSVP may not be guaranteed a meal. Carpooling information will be shared in a follow-up email.\n\nWe look forward to a wonderful day together!","questions":[{"id":"ns42-a","part":7,"question":"Who is invited to the Annual Company Picnic?","options":["Senior management only","All employees and their immediate family members","Employees who have worked at the company for over one year","All employees but not family members"],"answer":1,"explanation":"Detail: 'This event is open to all employees and their immediate family members.'"},{"id":"ns42-b","part":7,"question":"By when must employees RSVP?","options":["May 20","May 25","June 1","June 7"],"answer":1,"explanation":"Detail: 'please RSVP by May 25 via the HR portal.'"},{"id":"ns42-c","part":7,"question":"What can be inferred about employees who do not RSVP?","options":["They will not be permitted to attend the event","They will be charged for their meal on the day","They may not be guaranteed a meal","They must bring their own food and drinks"],"answer":2,"explanation":"Detail: 'Employees who do not RSVP may not be guaranteed a meal.'"}]},{"passageTitle":"Notice: New Badge Access System","type":"single","passage":"FACILITIES NOTICE\n\nAs of Monday, May 5, all staff will be required to use the new proximity badge system to access the building and interior office areas. Old magnetic stripe cards will be deactivated on that date.\n\nNew badges were distributed at the front desk last week. Staff who have not yet collected their badge should do so by Friday, May 2. Contact facilities@company.com for any issues.","questions":[{"id":"ns43-a","part":7,"question":"What will happen to old magnetic stripe cards on May 5?","options":["They will be upgraded automatically","They will be deactivated","They will be replaced at no cost","They will continue to work for one more month"],"answer":1,"explanation":"Detail: 'Old magnetic stripe cards will be deactivated on that date.'"},{"id":"ns43-b","part":7,"question":"What should staff who have not collected their new badge do?","options":["Request one by email before May 5","Collect it from the front desk by May 2","Wait for it to be delivered to their desk","Contact HR to arrange a temporary pass"],"answer":1,"explanation":"Detail: 'Staff who have not yet collected their badge should do so by Friday, May 2.'"}]},{"passageTitle":"Text Message: Meeting Room Change","type":"single","passage":"[9:03 A.M.] James Hoover: Hi Linda, just a heads up — the 10 A.M. strategy meeting has been moved from Room 4B to the Executive Lounge on the 12th floor. The room was double-booked.\n\n[9:06 A.M.] Linda Osei: Thanks for letting me know! Should I inform the rest of the team?\n\n[9:07 A.M.] James Hoover: Yes please — could you send a quick message to everyone on the invite? I'm in a call until 9:45.","questions":[{"id":"ns44-a","part":7,"question":"Why was the meeting location changed?","options":["The Executive Lounge has better facilities","Room 4B was double-booked","The meeting was rescheduled to a later time","The original room is under renovation"],"answer":1,"explanation":"Detail: 'The room was double-booked.'"},{"id":"ns44-b","part":7,"question":"What does James ask Linda to do?","options":["Book the Executive Lounge for future meetings","Reschedule the meeting to the afternoon","Notify the rest of the team about the room change","Cancel the strategy meeting entirely"],"answer":2,"explanation":"Detail: 'could you send a quick message to everyone on the invite?'"}]},{"passageTitle":"Advertisement: Corporate Photography Services","type":"single","passage":"FRAMEPOINT STUDIO – CORPORATE PHOTOGRAPHY\n\nLooking to refresh your company's image? FramePoint Studio specialises in professional headshots, team photos, office environment shoots, and product photography for businesses of all sizes.\n\nBook a half-day studio session for $650 or an on-site shoot from $850. All packages include full editing rights and digital delivery within 5 business days. Mention this advertisement to receive a complimentary 30-minute consultation.\n\nVisit framepointstudio.com or call 555-0147.","questions":[{"id":"ns45-a","part":7,"question":"What is offered to customers who mention the advertisement?","options":["A 10% discount on any package","Free digital delivery of all photos","A complimentary 30-minute consultation","A free product photography session"],"answer":2,"explanation":"Detail: 'Mention this advertisement to receive a complimentary 30-minute consultation.'"},{"id":"ns45-b","part":7,"question":"How long does digital delivery take after a shoot?","options":["1 business day","3 business days","5 business days","7 business days"],"answer":2,"explanation":"Detail: 'digital delivery within 5 business days.'"}]},{"passageTitle":"Memo: Updated Travel Booking Procedure","type":"single","passage":"TO: All Staff\nFROM: Operations Department\nRE: Business Travel Booking – Process Update\n\nEffective immediately, all domestic and international business travel must be booked through the company's approved travel portal at travel.intranet. Direct bookings made outside this portal will not be reimbursed unless prior written approval has been obtained from a department director.\n\nThe portal offers negotiated rates with preferred airlines and hotels. For assistance, contact the Operations team at ext. 3300.","questions":[{"id":"ns46-a","part":7,"question":"What is the new requirement for booking business travel?","options":["All travel must be approved by the CEO","Travel must be booked through the company's approved portal","Staff must use only preferred airlines for all trips","Domestic and international travel must be booked separately"],"answer":1,"explanation":"Detail: 'all domestic and international business travel must be booked through the company's approved travel portal.'"},{"id":"ns46-b","part":7,"question":"Under what condition will direct bookings be reimbursed?","options":["If the travel portal was unavailable at the time","If the booking is under a certain cost threshold","If prior written approval from a department director was obtained","If the trip is less than 24 hours in duration"],"answer":2,"explanation":"Detail: 'will not be reimbursed unless prior written approval has been obtained from a department director.'"}]},{"passageTitle":"Notice: Staff Cafeteria Closure","type":"single","passage":"NOTICE – FACILITIES MANAGEMENT\n\nThe staff cafeteria on Level 2 will be closed for a deep cleaning and equipment upgrade from Wednesday, November 6 to Friday, November 8 inclusive. During this period, a temporary food service will operate in the main lobby from 7:30 A.M. to 2:00 P.M., offering hot meals, sandwiches, and beverages.\n\nNormal cafeteria service will resume on Monday, November 11. We apologise for any inconvenience.","questions":[{"id":"ns47-a","part":7,"question":"Why will the cafeteria be closed?","options":["It is being relocated to a different floor","Staff numbers have decreased significantly","A deep cleaning and equipment upgrade is scheduled","The cafeteria lease agreement has expired"],"answer":2,"explanation":"Detail: 'closed for a deep cleaning and equipment upgrade.'"},{"id":"ns47-b","part":7,"question":"Where will staff be able to get food during the closure?","options":["In the rooftop terrace area","In the main lobby","In the Level 3 meeting rooms","At the vending machines on Level 1"],"answer":1,"explanation":"Detail: 'a temporary food service will operate in the main lobby.'"}]},{"passageTitle":"Article: Flexible Benefits Program Launch","type":"single","passage":"STAFF NEWS\n\nNorthgate Solutions has announced the launch of its new Flexible Benefits Program, which will take effect from the start of the next financial year. Under the new program, employees will receive a personal benefits allowance of $1,500 annually, which they can allocate across a menu of options including additional annual leave, gym memberships, professional development courses, dental and optical cover, and childcare subsidies.\n\nEmployees must make their selections through the HR portal during the annual enrolment window, which opens on December 1 and closes on December 15. Selections will be locked in for the full financial year and cannot be changed outside the enrolment period except in cases of a major life event, such as marriage or the birth of a child.\n\nThe program replaces the previous one-size-fits-all benefits package and is part of the company's broader strategy to improve employee wellbeing and retention.","questions":[{"id":"ns48-a","part":7,"question":"What is the annual benefits allowance each employee will receive?","options":["$1,000","$1,200","$1,500","$2,000"],"answer":2,"explanation":"Detail: 'employees will receive a personal benefits allowance of $1,500 annually.'"},{"id":"ns48-b","part":7,"question":"When does the annual enrolment window close?","options":["November 30","December 1","December 15","December 31"],"answer":2,"explanation":"Detail: 'closes on December 15.'"},{"id":"ns48-c","part":7,"question":"Under what circumstances can benefit selections be changed outside the enrolment period?","options":["At any time with manager approval","Only if an employee changes departments","In cases of a major life event such as marriage or birth of a child","When an employee receives a promotion"],"answer":2,"explanation":"Detail: 'cannot be changed outside the enrolment period except in cases of a major life event, such as marriage or the birth of a child.'"}]},{"passageTitle":"Email: Vendor Contract Renewal","type":"single","passage":"From: Procurement <procurement@deltalogi.com>\nTo: Operations Team\nSubject: Vendor Contract Renewal – Apex Couriers\n\nDear Team,\n\nThe current service contract with Apex Couriers expires on August 31. Following a review of their performance over the past 12 months, the Procurement team recommends renewing the contract for a further two years.\n\nApex achieved a 97% on-time delivery rate and received consistently positive feedback from our warehouse team. They have also agreed to hold their current pricing for the first year of the renewed contract, with a 3% increase from Year 2.\n\nIf you have any concerns or wish to raise alternative vendor options before we proceed, please respond by July 20. Otherwise, we will initiate the renewal paperwork the following week.\n\nBest regards,\nProcurement Team","questions":[{"id":"ns49-a","part":7,"question":"What does the Procurement team recommend regarding Apex Couriers?","options":["Terminating the contract and finding a new vendor","Renewing the contract for two more years","Renegotiating the pricing before renewal","Extending the contract by one year only"],"answer":1,"explanation":"Detail: 'recommends renewing the contract for a further two years.'"},{"id":"ns49-b","part":7,"question":"What pricing arrangement has Apex Couriers agreed to?","options":["A 3% discount for the entire contract period","Fixed pricing for two years with no increase","Current pricing for Year 1, with a 3% increase from Year 2","A 5% reduction in rates for on-time performance"],"answer":2,"explanation":"Detail: 'hold their current pricing for the first year... with a 3% increase from Year 2.'"},{"id":"ns49-c","part":7,"question":"By when must team members respond if they have concerns?","options":["August 1","August 31","July 20","July 31"],"answer":2,"explanation":"Detail: 'please respond by July 20.'"}]},{"passageTitle":"Web Page: Co-working Space Membership","type":"single","passage":"NEXUS HUB – FLEXIBLE WORKSPACES IN THE CITY\n\nNexus Hub provides modern, fully-equipped workspaces for freelancers, remote workers, and growing teams.\n\nMEMBERSHIP PLANS\n• Day Pass – $35/day: Hot desk access, Wi-Fi, unlimited coffee\n• Flex Monthly – $199/month: 10 days of hot desk access per month\n• Full-Time Monthly – $349/month: Unlimited hot desk, 5 meeting room hours included\n• Private Office – from $799/month: Dedicated lockable office for 2–6 people\n\nAll memberships include access to printing facilities, secure lockers, and our member events program. Meeting rooms can be booked at $25/hour for members not on the Full-Time or Private Office plan.\n\nTour our space any weekday between 9:00 A.M. and 5:00 P.M. — no appointment needed.","questions":[{"id":"ns50-a","part":7,"question":"Which plan includes meeting room hours at no extra charge?","options":["Day Pass","Flex Monthly","Full-Time Monthly","All plans include meeting room hours"],"answer":2,"explanation":"Detail: 'Full-Time Monthly – $349/month: Unlimited hot desk, 5 meeting room hours included.'"},{"id":"ns50-b","part":7,"question":"How much does it cost for members to book a meeting room if not on the Full-Time or Private Office plan?","options":["$15 per hour","$20 per hour","$25 per hour","$35 per hour"],"answer":2,"explanation":"Detail: 'Meeting rooms can be booked at $25/hour for members not on the Full-Time or Private Office plan.'"},{"id":"ns50-c","part":7,"question":"What can be inferred about touring the Nexus Hub space?","options":["Tours must be booked at least one day in advance","Tours are only available on weekends","Anyone can visit on weekdays without prior arrangement","Tours are led by a staff member and last 30 minutes"],"answer":2,"explanation":"Inference: 'Tour our space any weekday between 9:00 A.M. and 5:00 P.M. — no appointment needed' implies walk-in visits are welcome."}]},{"passageTitle":"Letter: Insurance Policy Renewal","type":"single","passage":"Dear Ms. Whitmore,\n\nWe are writing to advise you that your commercial property insurance policy (Policy No. CP-774821) is due for renewal on September 30. Your current annual premium is $3,840.\n\nFollowing our annual review, we are pleased to offer a renewed policy at the same premium with no increase, provided your coverage requirements have not materially changed. If you have made significant improvements to the insured premises or acquired additional assets, please contact us so we can update your policy accordingly.\n\nTo confirm your renewal, please complete the enclosed form and return it by September 15. If we do not receive your response by that date, your policy will lapse and you may experience a gap in coverage.\n\nShould you have any questions, please contact your account manager, David Fong, at d.fong@insurecorp.com.\n\nYours sincerely,\nInsureCorp Client Services","questions":[{"id":"ns51-a","part":7,"question":"What is the proposed premium for the renewed policy?","options":["Less than the current premium","The same as the current premium","3% more than the current premium","Subject to change based on a new assessment"],"answer":1,"explanation":"Detail: 'pleased to offer a renewed policy at the same premium with no increase.'"},{"id":"ns51-b","part":7,"question":"By when must Ms. Whitmore return the renewal form?","options":["August 31","September 15","September 30","October 1"],"answer":1,"explanation":"Detail: 'please complete the enclosed form and return it by September 15.'"},{"id":"ns51-c","part":7,"question":"What is Ms. Whitmore advised to do if she has made improvements to her property?","options":["Submit photos of the improvements to InsureCorp","Request a full property re-assessment","Contact InsureCorp to update her policy accordingly","Apply for a new policy rather than renewing"],"answer":2,"explanation":"Detail: 'please contact us so we can update your policy accordingly.'"}]},{"passageTitle":"Announcement: New Employee Onboarding Program","type":"single","passage":"HUMAN RESOURCES – PROGRAM UPDATE\n\nWe are pleased to announce the launch of a redesigned onboarding program for all new employees joining Calloway Group from October 1 onwards.\n\nThe updated program runs for four weeks and includes structured orientation sessions, role-specific training modules, assigned mentors from the relevant department, and a formal check-in with HR at the end of Week 2 and Week 4.\n\nManagers of new hires are asked to complete the Manager Onboarding Checklist, available on the HR portal, within the first three days of a new employee's start date. This checklist ensures that workstations, system access, and team introductions are arranged before the employee's first day where possible.\n\nFor questions about the new program, contact hr@callowaygroup.com.","questions":[{"id":"ns52-a","part":7,"question":"How long does the new onboarding program run?","options":["Two weeks","Three weeks","Four weeks","Six weeks"],"answer":2,"explanation":"Detail: 'The updated program runs for four weeks.'"},{"id":"ns52-b","part":7,"question":"When are formal HR check-ins scheduled during the program?","options":["At the end of Week 1 and Week 3","At the end of Week 2 and Week 4","Once per week throughout the four weeks","Only at the end of the four-week program"],"answer":1,"explanation":"Detail: 'a formal check-in with HR at the end of Week 2 and Week 4.'"},{"id":"ns52-c","part":7,"question":"What are managers asked to do within the first three days of a new employee starting?","options":["Introduce the new employee to the entire company","Complete the Manager Onboarding Checklist on the HR portal","Schedule a one-on-one meeting with the new hire","Submit a performance goal form to HR"],"answer":1,"explanation":"Detail: 'Managers of new hires are asked to complete the Manager Onboarding Checklist... within the first three days of a new employee's start date.'"}]}]};